window.QZ_DATA = {"meta": {"gerado": "questoes.json — SEDES-DF 2026 (validado cruzado em 2026-05-26)", "total": 1978, "disciplinas": {"psicologia": {"nome": "Psicologia", "com_gabarito": 1384, "total_banco": 1384}, "servico_social": {"nome": "Serviço Social (SUAS/LOAS)", "com_gabarito": 204, "total_banco": 204}, "direito_constitucional": {"nome": "Direito Constitucional", "com_gabarito": 319, "total_banco": 319}, "portugues": {"nome": "Português", "com_gabarito": 71, "total_banco": 71}}}, "questoes": [{"id": "3772157", "d": "psicologia", "a": ["Teorias da Personalidade"], "ano": "2025", "org": "CORE", "t": "", "e": "Quando um colaborador é digno de confiança, organizado,\nperseverante, autodisciplinado e íntegro, é correto afirmar\nque ele manifesta uma dimensão da personalidade dita", "alt": {"A": "ajustamento emocional.", "B": "afabilidade.", "C": "senso de responsabilidade.", "D": "extroversão.", "E": "abertura e interesse."}, "g": "C", "j": "Os descritores organizado, perseverante, autodisciplinado, integro e confiavel correspondem ao fator conscienciosidade/senso de responsabilidade nos Cinco Grandes."}, {"id": "3749287", "d": "psicologia", "a": ["Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A Política Nacional de Saúde Mental no Brasil, estabelecida\npela Lei nº 10.216/2001, tem como um de seus objetivos\nfundamentais", "alt": {"A": "garantir a internação a longo prazo exclusiva em\nhospitais psiquiátricos para pessoas com transtornos\nmentais.", "B": "ampliar o número de instituições psiquiátricas no país\npara aumentar a capacidade de internação.", "C": "privar as pessoas com transtornos mentais das suas\ndecisões para garantir a segurança pública.", "D": "priorizar o cuidado em liberdade, promovendo a\nautonomia e a inclusão social dos usuários, com\nênfase em serviços comunitários de saúde mental.", "E": "substituir totalmente os serviços comunitários de\nsaúde mental por práticas de internação compulsória."}, "g": "D", "j": "A Lei 10.216/2001 orienta protecao de direitos, tratamento em ambiente menos invasivo e reinsercao social, o que se alinha ao cuidado em liberdade e comunitario."}, {"id": "3749285", "d": "psicologia", "a": ["Psicologia e Organizações"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Considerando o impacto estratégico das ações de\nqualidade de vida no trabalho, assinale a opção que reflete\nde forma abrangente os benefícios dessas iniciativas para\numa organização.", "alt": {"A": "aumentar a satisfação dos colaboradores, sem\nimpacto na estratégia organizacional", "B": "reduzir custos operacionais ao estimular maior\nsobrecarga de trabalho dos funcionários", "C": "criar um ambiente organizacional equilibrado,\nreduzindo estresse e absenteísmo, promovendo\nengajamento, elevando o desempenho individual e\norganizacional, além de atrair e reter talentos", "D": "simplificar processos internos, dispensando\ntreinamentos contínuos e investindo menos em\ndesenvolvimento", "E": "desenvolver ações focadas apenas nos líderes como\nestratégia central para melhorar os resultados\nda organização"}, "g": "C", "j": "Qualidade de vida no trabalho envolve reducao de estresse/absenteismo, engajamento, desempenho e retencao; as demais alternativas sao restritivas ou contraproducentes."}, {"id": "3749281", "d": "psicologia", "a": ["Psicologia e Organizações"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta corretamente a principal\ncausa da síndrome de burnout.", "alt": {"A": "a realização de atividades físicas intensas sem\nacompanhamento profissional adequado", "B": "a competitividade e a pressão excessivas em\nambientes de trabalho, levando ao esgotamento\nemocional e físico", "C": "situações de lazer prolongado e falta de desafios\nprofissionais", "D": "problemas de relacionamento interpessoal fora do\nambiente de trabalho", "E": "doenças genéticas a afetar o comportamento\nemocional do profissional"}, "g": "B", "j": "Burnout e fenomeno associado ao contexto ocupacional, especialmente pressao cronica, demanda excessiva e esgotamento emocional/fisico."}, {"id": "3749278", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Educação"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta corretamente uma\ncaracterística dos distúrbios de aprendizagem.", "alt": {"A": "Os distúrbios de aprendizagem afetam todas as\nfunções cognitivas, incluindo habilidades intelectuais\nglobais.", "B": "Os distúrbios de aprendizagem são especificamente\nassociados a anomalias em funções básicas,\ncomo compreensão ou uso de linguagem, leitura\ne matemática.", "C": "Crianças com distúrbios de aprendizagem apresentam\ndificuldades apenas devido a problemas visuais\nou auditivos.", "D": "Meninas são diagnosticadas com distúrbios de\naprendizagem mais frequentemente do que meninos,\ndevido à prevalência desse problema ser mais alta\nem meninas.", "E": "Crianças com distúrbios de aprendizagem não têm\ncapacidade de apresentar nenhum desempenho\nelevado em atividades acadêmicas."}, "g": "B", "j": "Transtornos especificos de aprendizagem envolvem prejuizos persistentes em leitura, escrita, matematica ou linguagem, sem equivaler a incapacidade cognitiva global."}, {"id": "3749277", "d": "psicologia", "a": ["Psicopatologia"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "De acordo com os critérios de classificação de transtornos\nmentais do DSM‑5, assinale a opção que apresenta\ncorretamente um transtorno pertencente à categoria de\ntranstornos do neurodesenvolvimento.", "alt": {"A": "esquizofrenia", "B": "transtorno de personalidade borderline", "C": "transtorno do déficit de atenção/hiperatividade (TDAH)", "D": "transtorno do pânico", "E": "depressão maior"}, "g": "C", "j": "TDAH integra os transtornos do neurodesenvolvimento no DSM-5; as demais alternativas pertencem a outras categorias diagnosticas."}, {"id": "3749276", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Teorias e Técnicas Psicoterápicas"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta corretamente uma\nhabilidade essencial para o psicólogo, ao conduzir uma\nentrevista clínica de forma eficaz.", "alt": {"A": "ser totalmente objetivo, evitando qualquer\nenvolvimento emocional ou empático com o\nentrevistado", "B": "confrontar o entrevistado de forma direta e incisiva,\nsem sutilezas, para evitar esquivas ou contradições", "C": "assumir a postura de ouvinte passivo, respeitando o\nritmo do entrevistado, sem intervir ou direcionar", "D": "evitar a aplicação de técnicas estruturadas, focando\napenas na interação interpessoal espontânea durante\na entrevista", "E": "demonstrar a capacidade de estar presente, ouvindo\no outro sem interferências pessoais, e ajudar a criar\numa aliança de trabalho"}, "g": "E", "j": "Entrevista clinica eficaz requer presenca, escuta qualificada, manejo de interferencias pessoais e construcao de alianca de trabalho."}, {"id": "3749275", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta corretamente o papel e a\ndefinição da entrevista psicológica.", "alt": {"A": "A entrevista psicológica é exclusivamente um meio\nde coleta de dados padronizado e fechado, no qual o\nprofissional delimita todas as respostas possíveis do\ncliente para um diagnóstico mais objetivo e rápido.", "B": "A entrevista psicológica é um método de coleta\nde informações limitado em termos de aplicação\ncientífica, pois não permite integração com a prática\nclínica nem adaptação às demandas contextuais.", "C": "A entrevista psicológica é caracterizada por ser\numa técnica que permite ao psicólogo integrar\nconhecimentos científicos com as particularidades\ndo contexto pessoal e único de cada cliente,\npossibilitando um processo dinâmico e adaptável.", "D": "A entrevista psicológica é entendida como uma\ncomunicação vocal estruturada que utiliza protocolos\nfixos, impedindo variações no discurso do cliente\ne dificultando a compreensão de particularidades\nindividuais.", "E": "A entrevista psicológica é descrita como um processo\nunilateral, no qual o psicólogo assume total controle\nda fala do cliente, limitando‑se à obtenção mecânica\nde respostas e excluindo‑se os processos de interação."}, "g": "C", "j": "A entrevista psicologica e tecnica flexivel e contextualizada que integra conhecimento cientifico e singularidade do caso; nao e procedimento fechado, unilateral ou meramente mecanico."}, {"id": "3749274", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "O questionário NEO‑PI é amplamente utilizado para a\nmedição dos traços de personalidade e está estruturado\ncom base em cinco fatores principais. Considerando essa\ninformação, assinale a opção que apresenta corretamente\numa característica do NEO‑PI.", "alt": {"A": "O NEO‑PI contém 120 itens que medem exclusivamente\nos fatores de neuroticismo e extroversão.", "B": "Foi inicialmente desenvolvido para avaliar todos os\ncinco traços principais de personalidade.", "C": "O questionário NEO‑PI utiliza escalas projetivas para\ninferir traços de personalidade.", "D": "O NEO‑PI é composto de 240 itens, avaliando cinco\nfatores principais e suas facetas.", "E": "A validade psicométrica do NEO‑PI foi comprovada\napenas nos Estados Unidos."}, "g": "D", "j": "O NEO-PI-R e conhecido por ter 240 itens e avaliar os cinco fatores e suas facetas; as alternativas confundem quantidade, escopo ou metodo projetivo."}, {"id": "3749273", "d": "psicologia", "a": ["Teorias da Personalidade"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A teoria dos cinco grandes fatores de personalidade,\ntambém conhecida como FFM (Five‑Factor Model),\npropõe que existem cinco dimensões fundamentais que\ncaracterizam a personalidade humana, que são", "alt": {"A": "motivação, emoção, atenção, inteligência e memória.", "B": "neuroticismo, extroversão, abertura, cordialidade e\nresponsabilidade.", "C": "ansiedade, criatividade, assertividade, simpatia e\nprodutividade.", "D": "reflexão, sociabilidade, estabilidade, generosidade e\nresiliência.", "E": "autonomia, carinho, iniciativa, flexibilidade e\ndeterminação."}, "g": "B", "j": "O Five-Factor Model descreve neuroticismo, extroversao, abertura, cordialidade/amabilidade e responsabilidade/conscienciosidade."}, {"id": "3748816", "d": "psicologia", "a": ["Psicologia e Organizações", "Teorias da Personalidade"], "ano": "2025", "org": "CORE", "t": "", "e": "Quando um colaborador é focado em dados, analítico e\ncurioso, com aptidão para resolver problemas complexos\ne introvertido, é correto afirmar que, precipuamente, seu\nperfil de personalidade é", "alt": {"A": "social.", "B": "criativo.", "C": "empreendedor.", "D": "mediador.", "E": "analítico."}, "g": "E", "j": "O conjunto focado em dados, analitico, curioso e orientado a problemas complexos corresponde diretamente ao perfil analitico."}, {"id": "3469498", "d": "psicologia", "a": ["Psicologia e Organizações", "Teorias da Personalidade"], "ano": "2024", "org": "CRN", "t": "", "e": "Existem alguns atributos de personalidade que influenciam\nno comportamento organizacional. Conforme um deles, as\npessoas acreditam que são donas de seu próprio destino, ao\npasso que outras acreditam que tudo o que lhes acontece\né obra da sorte ou do acaso. Com base nessas informações,\nassinale a alternativa que apresenta esse tipo de atributo\nde personalidade.", "alt": {"A": "maquiavelismo", "B": "autoestima", "C": "automonitoramento", "D": "centro de controle", "E": "propensão para correr riscos"}, "g": "D", "j": "A crenca de controlar o proprio destino ou atribui-lo a sorte/acaso e o atributo classico locus/centro de controle."}, {"id": "3468946", "d": "psicologia", "a": ["Teorias da Personalidade"], "ano": "2024", "org": "CRN", "t": "", "e": "Um grande número de pesquisas indica que cinco\ndimensões básicas dão a base para todas as outras e\nenglobam as variações mais latentes na personalidade\nhumana. Uma dessas dimensões refere‑se à propensão\nque um indivíduo tem em acatar as ideias dos outros.\nConsiderando essa informação, assinale a alternativa que\napresenta essa dimensão.", "alt": {"A": "extroversão", "B": "amabilidade", "C": "consciência", "D": "estabilidade emocional", "E": "abertura para experiências"}, "g": "B", "j": "A propensao a acatar ideias dos outros e cooperar corresponde a amabilidade/agreeableness nos Cinco Grandes."}, {"id": "3468945", "d": "psicologia", "a": ["Teorias da Personalidade"], "ano": "2024", "org": "CRN", "t": "", "e": "Em relação ao tema personalidade e relacionamento,\nassinale a alternativa correta.", "alt": {"A": "A personalidade é a soma total dos modos como uma\npessoa reage e interage com as demais.", "B": "A personalidade também é descrita como os traços\nnão mensuráveis apresentados por um indivíduo.", "C": "A personalidade é resultado apenas da\nhereditariedade.", "D": "A hereditariedade refere‑se aos fatores culturais que\nexercem pressão na formação das pessoas.", "E": "A abordagem hereditária não tem relação com os\npais da pessoa, ou seja, por seus perfis biológico,\nfisiológico e psicológico."}, "g": "A", "j": "A definicao de personalidade como soma dos modos pelos quais a pessoa reage e interage e formula classica em comportamento organizacional; as demais alternativas distorcem hereditariedade ou mensuracao."}, {"id": "3465864", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2024", "org": "CRP", "t": "", "e": "De acordo com o artigo 27 da Resolução nº 40/2013 do\nCFP, os trabalhos nas sessões ordinárias recebem uma\nordem específica. Com base nessa informação, assinale\na alternativa que apresenta a primeira pauta de uma\nsessão ordinária.", "alt": {"A": "comunicações", "B": "leitura e conhecimento do expediente", "C": "ordem do dia", "D": "discussão, aprovação e assinatura da reunião anterior", "E": "leitura e discussão da reunião subsequente"}, "g": "D", "j": "O art. 27 da Resolucao CFP 40/2013 inicia a ordem dos trabalhos pela discussao, aprovacao e assinatura da ata da reuniao anterior."}, {"id": "3465863", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2024", "org": "CRP", "t": "", "e": "O plenário do CRP‑23 é formado por todos os conselheiros\ntitulares, os quais podem ser substituídos pelos suplentes\nconforme as disposições legais. Esse órgão é responsável\npelas deliberações do Conselho. Com base nessas\ninformações, assinale a alternativa que apresenta uma\natribuição do plenário.", "alt": {"A": "eleger, entre os diretores efetivos, aqueles que\ncomporão o Conselho", "B": "restringir‑se apenas a orientar o exercício da profissão\nem sua jurisdição", "C": "impor sanções previstas nesse Regimento Interno e no\nCódigo de Processamento Disciplinar editado pelo CFP", "D": "delegar a decisão sobre os pedidos de inscrição dos\npsicólogos, das pessoas jurídicas e da concessão\ndo título de especialista de acordo com a legislação\nvigente ao CFP", "E": "arrecadar anuidades, taxas, emolumentos e multas,\nimplementando as medidas necessárias para garantir\nsua receita e a do CFP, para fins de doação"}, "g": "C", "j": "O regimento do CRP-23 atribui ao Plenario impor sancoes previstas no Regimento Interno e no Codigo de Processamento Disciplinar do CFP."}, {"id": "3465861", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "De acordo com o artigo 4 da Resolução nº 40/2013 do\nCFP, assinale a alternativa que apresenta a composição de\nconselheiros e suplentes do CRP‑23.", "alt": {"A": "20 ao todo, entre conselheiros e suplentes", "B": "18 ao todo, entre conselheiros e suplentes", "C": "10 conselheiros e 5 suplentes", "D": "5 conselheiros e 10 suplentes", "E": "5 conselheiros e 5 suplentes"}, "g": "B", "j": "A Resolucao CFP 40/2013 fixa o CRP-23 com nove conselheiros efetivos e nove suplentes, totalizando dezoito membros."}, {"id": "3465860", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "Conforme o artigo 3º da Resolução nº 40/2012, compete\nao CRP‑23", "alt": {"A": "realizar unicamente a elaboração de seu regimento\ne submetê‑lo à aprovação do Conselho Federal de\nPsicologia (CFP).", "B": "adotar medidas para orientar, disciplinar, fiscalizar e\nsupervisionar o exercício da profissão dentro de sua\nárea de competência e de adjacentes.", "C": "exercer as funções de Tribunal Regional do Trabalho.", "D": "propor ao CFP as medidas necessárias para orientação\ne fiscalização do exercício profissional.", "E": "enviar semestralmente um relatório ao CFP, que deve\nincluir listas atualizadas dos profissionais inscritos,\ncancelados e suspensos."}, "g": "D", "j": "Entre as competencias do CRP-23 esta sugerir/propor ao CFP medidas necessarias a orientacao e fiscalizacao do exercicio profissional; as demais alternativas restringem ou adulteram a competencia."}, {"id": "3459220", "d": "psicologia", "a": ["Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2024", "org": "CRP", "t": "", "e": "Conforme a resolução do Conselho Federal de Psicologia,\nque institui normas e procedimentos para a perícia\npsicológica no contexto do trânsito, assinale a alternativa\nque apresenta aspectos cognitivos que devem ser avaliados\nnos candidatos à carteira nacional de habilitação e\ncondutores de veículos automotores.", "alt": {"A": "aptidão física, força muscular e coordenação motora", "B": "conhecimento sobre leis de trânsito, regras de\nestacionamento e manutenção de veículos", "C": "atenção concentrada, atenção dividida, atenção\nalternada, memória visual e inteligência", "D": "habilidades de navegação, uso de GPS e planejamento\nde rotas", "E": "conhecimento sobre primeiros socorros, técnicas de\nresgate e atendimento a acidentes"}, "g": "C", "j": "A pericia psicologica de transito avalia funcoes cognitivas como atencao concentrada/dividida/alternada, memoria visual e inteligencia, conforme diretrizes do CFP e Resolucao CONTRAN; demais alternativas referem-se a aspectos motores, juridicos ou de saude geral."}, {"id": "3459219", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "De acordo com o Art. 4º da Lei nº 4.119/1962, as funções\ndo psicólogo no uso de métodos e técnicas psicológicas são", "alt": {"A": "diagnóstico psicológico, orientação e seleção\nprofissional, orientação psicopedagógica e solução de\nproblemas de ajustamento.", "B": "administração de medicamentos para o tratamento de\ntranstornos mentais.", "C": "desenvolvimento de programas de exercícios físicos\npara a reabilitação.", "D": "realização de pesquisas científicas em laboratórios\nde biologia.", "E": "realização de cirurgias para a correção de problemas\npsicológicos."}, "g": "A", "j": "A Lei 4.119/1962 define como funcoes do psicologo o diagnostico psicologico, orientacao e selecao profissional, orientacao psicopedagogica e solucao de problemas de ajustamento; demais alternativas sao incompativeis com a profissao."}, {"id": "3459218", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "Para o exercício profissional do psicólogo, além de\ncumprir os requisitos de formação estabelecidos pela\nLei nº 4.119/1962, é obrigatório o registro dos diplomas\nem um órgão competente, que garanta a legalidade e\no reconhecimento da atuação profissional na área de\nPsicologia, denominado", "alt": {"A": "Ministério da Saúde.", "B": "Ministério da Educação e Cultura.", "C": "Associação Brasileira de Psicologia.", "D": "Ministério do Trabalho.", "E": "Conselho Nacional de Desenvolvimento Científico\ne Tecnológico."}, "g": "B", "j": "O registro do diploma de graduacao em psicologia compete ao Ministerio da Educacao (MEC); apos esse registro o profissional se inscreve no Conselho Regional para exercicio profissional."}, {"id": "3459217", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "De acordo com o artigo 5º da Lei nº 4.119/1962, que dispõe\nsobre os cursos de formação em psicologia e regulamenta a\nprofissão de psicólogo, assinale a alternativa que apresenta\nos requisitos básicos para o candidato à matrícula.", "alt": {"A": "idade mínima de 18 anos, certificado de conclusão do\n2º grau e aprovação em exames vestibulares", "B": "idade mínima de 18 anos e experiência profissional na\nárea de saúde mental", "C": "idade mínima de 18 anos e aprovação em um curso\ntécnico de psicologia", "D": "idade mínima de 21 anos e diploma de qualquer\ncurso superior", "E": "idade mínima de 21 anos e aprovação em um curso\npreparatório de psicologia"}, "g": "A", "j": "O art. 5 da Lei 4.119/1962 exige idade minima de 18 anos, certificado de conclusao do segundo grau e aprovacao em exames vestibulares para matricula no curso de psicologia."}, {"id": "3459215", "d": "psicologia", "a": ["Psicologia e Organizações"], "ano": "2024", "org": "CRP", "t": "", "e": "Existem diversos estilos de avaliação de desempenho,\nque variam conforme a maturidade da empresa e suas\nnecessidades específicas. Um método amplamente\nutilizado é a avaliação 360°. Acerca desse método, assinale\na alternativa que descreve o estilo de avaliação 360°.", "alt": {"A": "avaliação realizada, exclusivamente, pelo supervisor\ndireto do funcionário", "B": "avaliação que utiliza apenas métricas de produtividade\ne resultados financeiros", "C": "avaliação que considera feedback de supervisores,\ncolegas de trabalho, subordinados e autoavaliação do\nfuncionário", "D": "avaliação fundamentada, exclusivamente, em testes\npadronizados de habilidades técnicas", "E": "avaliação realizada por meio de autoavaliação,\nignorando o feedback de colegas e de subordinados"}, "g": "C", "j": "A avaliacao 360 graus integra feedback de supervisores, pares/colegas, subordinados e autoavaliacao, fornecendo perspectiva multidirecional do desempenho; demais opcoes reduzem o metodo a uma unica fonte."}, {"id": "3459214", "d": "psicologia", "a": ["Psicologia e Organizações"], "ano": "2024", "org": "CRP", "t": "", "e": "Entre as diversas atribuições do psicólogo no contexto\norganizacional, uma delas é a utilização da avaliação\nde desempenho como ferramenta. Com base nessa\ninformação, assinale a alternativa que apresenta o principal\nobjetivo dessa avaliação.", "alt": {"A": "promover o desenvolvimento profissional e pessoal\ndos funcionários, identificando os pontos fortes e as\náreas de melhoria", "B": "promover e dar méritos aos funcionários", "C": "identificar os funcionários que devem ser demitidos", "D": "melhorar a comunicação interna da organização por\nmeio de eventos sociais", "E": "implementar um sistema de recompensas\nfundamentado apenas no tempo de serviço dos\nfuncionários"}, "g": "A", "j": "O objetivo principal da avaliacao de desempenho e promover o desenvolvimento profissional e pessoal, identificando pontos fortes e oportunidades de melhoria; demais alternativas reducionistas distorcem a finalidade tecnica."}, {"id": "3459212", "d": "psicologia", "a": ["Psicologia e Organizações"], "ano": "2024", "org": "CRP", "t": "", "e": "O psicólogo do trabalho atua sozinho ou em equipe\nmultiprofissional em diversas organizações, aplicando\nconhecimentos de psicologia para entender, intervir e\ndesenvolver relações, considerando as dimensões política,\neconômica, social e cultural. Com base no contexto\norganizacional, assinale a alternativa que apresenta uma\nresponsabilidade do psicólogo do trabalho.", "alt": {"A": "promover estudos para a identificação das\nnecessidades humanas diante da construção de\nprojetos e de equipamentos de trabalho (ergonomia)", "B": "fornecer consultoria jurídica ou representação legal\nem questões corporativas", "C": "gerenciar aspectos financeiros ou contábeis da\norganização", "D": "realizar pesquisas visando à construção e à ampliação\ndo conhecimento teórico e aplicado, no campo da\nsaúde mental", "E": "implementar políticas de segurança ocupacional e\ngestão de riscos, sem análise psicossocial"}, "g": "A", "j": "Entre as responsabilidades do psicologo do trabalho descritas no CBO esta promover estudos para identificacao das necessidades humanas em projetos e equipamentos (ergonomia); demais opcoes pertencem a outras areas profissionais."}, {"id": "3459211", "d": "psicologia", "a": ["Psicologia da Saúde"], "ano": "2024", "org": "CRP", "t": "", "e": "O psicólogo clínico atua especificamente na área da saúde,\ncontribuindo para a compreensão dos processos intra e\ninterpessoais. O trabalho desse profissional pode ter um\nenfoque preventivo ou curativo, e ele pode atuar de forma\nisolada ou em equipe multiprofissional em instituições\nformais e informais. Com base nessas informações, assinale\na alternativa que apresenta uma das responsabilidades do\npsicólogo clínico.", "alt": {"A": "desenvolver, na esfera de sua competência, estudos e\nprojetos de educação de trânsito", "B": "supervisionar, orientar e executar trabalhos na área de\npsicologia educacional", "C": "criar, coordenar e acompanhar, individualmente ou\nem equipe multiprofissional, tecnologias próprias ao\ntreinamento em saúde, particularmente em saúde\nmental, com o objetivo de qualificar o desempenho de\nvárias equipes", "D": "colaborar na formulação e na implantação das\npolíticas de cidadania e direitos humanos", "E": "realizar atendimento psicológico por meio de trabalho\nacessível e comprometido com a busca de decisões\npróprias na organização familiar dos que recorrem às\nvaras de família para a resolução de questões"}, "g": "C", "j": "Conforme o CBO do psicologo clinico, esta sob suas responsabilidades criar, coordenar e acompanhar tecnologias proprias ao treinamento em saude, especialmente saude mental; demais opcoes correspondem a transito, educacional, direitos humanos e juridico."}, {"id": "3459201", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2024", "org": "CRP", "t": "", "e": "A Resolução nº 22/2024 do CRP regula a emissão de\npassagens, a reserva de hospedagens e a concessão de\nverbas para representações institucionais de interesse\ndo Conselho Regional de Psicologia da 23ª Região. Em\nconformidade com o princípio da economicidade, assinale\na alternativa que apresenta por quais meios a viagem a\nserviço poderá ser substituída.", "alt": {"A": "team building presenciais", "B": "workshops síncronos e presenciais", "C": "videoconferência", "D": "por meio de correspondência", "E": "por meio de deslocamento físico custeado pelo\ncolaborador"}, "g": "C", "j": "Pelo principio da economicidade, viagens a servico podem ser substituidas por videoconferencia, que dispensa custos de deslocamento e hospedagem; demais alternativas exigem presencialidade ou meios incompativeis."}, {"id": "3459199", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "A Câmara de Mediação do CRP‑23 é responsável por\nconduzir atividades como notificação, orientação e\nresolução consensual de conflitos relacionados a denúncias,\nrepresentações ou procedimentos investigativos e éticos na\nárea da psicologia. Com base nessa informação, assinale\na alternativa que apresenta o encarregado de conduzir as\naudiências de mediação, conciliação e ajuste de conduta,\nalém de assinar todos os documentos da comissão por\nmeio de assinatura digital.", "alt": {"A": "presidente do Conselho Federal de Psicologia", "B": "presidente do Conselho Regional", "C": "presidente da Câmara de Mediação", "D": "diretor do plenário do Conselho Regional", "E": "tesoureiro do Conselho Regional"}, "g": "C", "j": "Por logica institucional, o encarregado de conduzir audiencias da Camara de Mediacao e seu proprio presidente; presidentes do CFP, CRP ou diretor do plenario nao tem essa atribuicao especifica."}, {"id": "3459198", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "A respeito das atribuições do presidente do Conselho\nRegional de Psicologia da 23ª Região, assinale a\nalternativa correta.", "alt": {"A": "elaborar e assegurar o cumprimento do Regimento\nInterno", "B": "assinar, de forma autônoma e exclusiva, as resoluções,\nas instruções normativas, as portarias e outros atos\nnormativos do Conselho Regional de Psicologia da\n23ª Região", "C": "representar, exceto criminalmente, contra qualquer\npessoa que violar disposições legais relacionadas ao\nexercício da profissão de psicólogo", "D": "assinar as carteiras de identidade profissional, as\ncédulas e outros documentos, como os livros da\nsecretaria e da tesouraria", "E": "elaborar e aprovar o projeto de orçamento anual e os\nrelatórios de prestação de contas para apresentação\nao plenário e envio ao Conselho Federal de Psicologia"}, "g": "D", "j": "E atribuicao tipica do presidente do CRP assinar carteiras de identidade profissional, cedulas e livros da secretaria/tesouraria. B (assinatura autonoma de resolucoes) e C (excecao criminal) descrevem competencias incorretas."}, {"id": "3459197", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2024", "org": "CRP", "t": "", "e": "Os trabalhos no plenário começam com o quórum mínimo\nde metade mais um dos conselheiros, salvo para assuntos\nque requerem quórum especial, conforme o Regimento\nInterno. De acordo com o artigo 27, as sessões seguem\numa ordem de pauta. Com base nessa informação, assinale\na alternativa que apresenta o primeiro tema, por ordem de\nprioridade, nas sessões de plenária.", "alt": {"A": "discussão, aprovação e assinatura da ata da reunião\nanterior", "B": "leitura e conhecimento do expediente", "C": "comunicações", "D": "ordem do dia", "E": "outros assuntos"}, "g": "A", "j": "Conforme art. 27 do regimento do CRP-23 (confirmado tambem em validacao anterior ID 3465864), as sessoes plenarias iniciam pela discussao, aprovacao e assinatura da ata da reuniao anterior."}, {"id": "3459196", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2024", "org": "CRP", "t": "", "e": "Os membros do Conselho Regional de Psicologia 23ª Região\nsão eleitos por maioria de votos, em escrutínio secreto, dos\nprofissionais inscritos na respectiva área e jurisdição. Com\nbase nessa informação, assinale a alternativa que apresenta\no período do mandato do conselheiro regional.", "alt": {"A": "1 ano", "B": "2 anos", "C": "3 anos", "D": "5 anos", "E": "10 anos"}, "g": "C", "j": "A Lei 5.766/1971, que cria os Conselhos de Psicologia, estabelece mandato de 3 anos para os conselheiros regionais; norma classica nas resolucoes de eleicao."}, {"id": "2665319", "d": "psicologia", "a": ["Conflito nas Organizações", "Qualidade de Vida", "Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2024", "org": "CREFITO", "t": "", "e": "No que diz respeito aos fatores positivos do relacionamento,\ndo comportamento receptivo e defensivo, da empatia e da\ncompreensão mútua, julgue os itens a seguir.\n      I No comportamento defensivo, as pessoas buscam\nse defender inconscientemente da ansiedade que\nsentem diante de uma situação perturbadora,\nseja distorcendo a realidade, seja enganando a\nsi mesmas.\n    II No comportamento receptivo, as pessoas tendem\na reduzir a defesa quanto à outra parte, quando\nbuscam experimentar e explorar novas situações.    \nIII A empatia não tem relação com tentar colaborar\nna solução de um problema permitindo à outra\nparte designar seus próprios objetivos, de modo a\ncriar um clima receptivo.\n      Assinale a alternativa correta.", "alt": {"A": "Somente o item I está certo.", "B": "Somente os itens I e II estão certos.", "C": "Somente os itens I e III estão certos.", "D": "Somente os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "I (comportamento defensivo como defesa inconsciente da ansiedade) e II (comportamento receptivo reduz defesa para explorar) sao corretos. III esta errado porque a empatia justamente tem relacao com colaborar na solucao do problema. Apenas I e II = B."}, {"id": "2665318", "d": "psicologia", "a": ["Teorias da Personalidade", "Teorias da Personalidade - Outros Autores"], "ano": "2024", "org": "CREFITO", "t": "", "e": "Em relação à personalidade e ao relacionamento, julgue os\nitens a seguir.      \nI É possível conceituar a personalidade como a\norganização dinâmica interna daqueles sistemas\npsicofísicos do indivíduo que determinam seu\najuste individual ao ambiente.    \nII O caráter é um componente biologicamente\ndeterminado, que pode ser identificado desde\ncedo na infância.\n    III O temperamento representa as consequências\ndas experiências que vivemos e que influenciam\nna nossa maneira de ser, modulando as\npredisposições e tendências psicológicas.      Assinale a alternativa correta.", "alt": {"A": "Somente o item I está certo.", "B": "Somente os itens I e II estão certos.", "C": "Somente os itens I e III estão certos.", "D": "Somente os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "A", "j": "I esta correto (definicao de Allport de personalidade). II e III estao errados: caracter NAO e biologicamente determinado (e adquirido), e temperamento NAO representa consequencias de experiencias (e biologico, inato). Apenas I = A."}, {"id": "2665303", "d": "psicologia", "a": ["Clima e Cultura Organizacional na Psicologia", "Psicologia e Organizações"], "ano": "2024", "org": "CREFITO", "t": "", "e": "Em relação à cultura organizacional, é correto afirmar\nque ela", "alt": {"A": "representa as normas informais e não escritas\nque orientam o comportamento dos membros da\norganização no dia a dia e que direcionam suas ações\npara a realização dos objetivos organizacionais, e seu\núltimo nível é representado pelos artefatos.", "B": "constitui o meio interno ou a atmosfera psicológica\ncaracterística de cada organização, estando ligado\nao moral e à satisfação das necessidades dos\nparticipantes, e seu primeiro nível é representado\npelos artefatos.", "C": "representa as normas informais e não escritas\nque orientam o comportamento dos membros da\norganização no dia a dia e que direcionam suas ações\npara a realização dos objetivos organizacionais, e seu\nprimeiro nível é representado pelos artefatos.", "D": "constitui o meio interno ou a atmosfera psicológica\ncaracterística de cada organização, estando ligado\nao moral e à satisfação das necessidades dos\nparticipantes, e seu primeiro nível é representado\npelos valores compartilhados.", "E": "representa as normas informais e não escritas\nque orientam o comportamento dos membros da\norganização no dia a dia e que direcionam suas ações\npara a realização dos objetivos organizacionais, e\nseu primeiro nível é representado pelos valores\ncompartilhados."}, "g": "C", "j": "Cultura organizacional sao normas informais que orientam comportamento; pelo modelo de Schein, o PRIMEIRO nivel (mais superficial/visivel) sao os artefatos, seguido de valores compartilhados e pressupostos basicos. C combina ambas as caracterizacoes corretamente."}, {"id": "2527128", "d": "psicologia", "a": ["Liderança", "Psicologia e Organizações"], "ano": "2024", "org": "CRMV", "t": "", "e": "No que se refere à escola das relações humanas, Likert,\nao abordar os estilos de liderança, afirmava acerca\nda existência de um estilo que era típico da gerência\nfundamentada em hierarquia, porém enfatizava mais os\nincentivos que as punições. O autor também falava acerca\nde um estilo que se fundamentava no processo decisório\nem grupos de trabalho que se comunicam entre si por meio\nde indivíduos que ligam componentes, líderes de equipes\nou outros que também fazem parte de um ou mais grupos.\nConsiderando essas informações, é correto afirmar que\nesses estilos eram denominados, respectivamente, como", "alt": {"A": "autoritário explorador e consultivo.", "B": "autoritário benevolente e participativo.", "C": "autoritário explorador e consultivo.", "D": "autoritário benevolente e participativo.", "E": "consultivo e participativo."}, "g": "A", "j": "Os 4 sistemas de Likert: 1-autoritario coercitivo/explorador, 2-autoritario benevolente, 3-consultivo, 4-participativo. O enunciado descreve: (1) hierarquico com mais incentivos que punicoes = autoritario BENEVOLENTE (nao explorador); (2) decisao em grupos com lideres ligando equipes = PARTICIPATIVO. Resposta correta: B. Atencao: alternativas A=C e B=D estao duplicadas, possivel erro de coleta."}, {"id": "2458156", "d": "psicologia", "a": ["Psicologia Social"], "ano": "2024", "org": "CAU", "t": "", "e": "Quando se observa que as pessoas se defendem\ninconscientemente da ansiedade que sentem em uma\nsituação perturbadora e que há a necessidade de uma\nautoimagem positiva, de aprovar nosso comportamento e\nde justificá‑lo quando necessário e que, em algumas vezes,\na única maneira de conseguir isso é por meio de processos\ninconscientes, de modo a nos enganar e alterar os fatos\nreais, de forma a preservar a nossa autoimagem, está\nsendo observado o que se conceitua como", "alt": {"A": "receptividade.", "B": "empatia.", "C": "comportamento receptivo.", "D": "comportamento defensivo.", "E": "compreensão mútua."}, "g": "D", "j": "A defesa inconsciente da ansiedade, preservacao de autoimagem positiva e alteracao de fatos reais sao caracteristicas classicas do comportamento defensivo, conforme literatura de psicologia social e organizacional."}, {"id": "2363949", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2023", "org": "FSNH", "t": "", "e": "Assinale a alternativa que apresenta um dos principais\naspectos abordados nas regras para a elaboração, guarda,\ndestino e envio de documentos escritos produzidos pelo\npsicólogo em seu exercício profissional.", "alt": {"A": "princípios fundamentais na elaboração de documentos\npsicológicos", "B": "consequências éticas da elaboração de documentos\npsicológicos", "C": "variações de documentos", "D": "documentos psicológicos inexistentes", "E": "exclusão do prazo de validade do conteúdo dos\ndocumentos psicológicos"}, "g": "A", "j": "A Resolucao CFP 06/2019 (Manual de Elaboracao de Documentos Escritos) define principios fundamentais que devem nortear a elaboracao, guarda, destino e envio de documentos psicologicos."}, {"id": "2363948", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)", "Resoluções do Conselho Federal de Psicologia"], "ano": "2023", "org": "FSNH", "t": "", "e": "Assinale a alternativa que apresenta a consequência da\nnão observância das diretrizes do Conselho Federal de\nPsicologia referentes à comunicação por escrito no exercício\nprofissional da psicologia.", "alt": {"A": "O profissional terá seu registro profissional\ntemporariamente suspenso, mas poderá continuar a\nexercer a profissão durante esse período.", "B": "O profissional receberá uma advertência por escrito,\nsem qualquer outra consequência disciplinar.", "C": "A não observância das diretrizes resultará na\nexoneração imediata do profissional de sua posição\nou cargo.", "D": "A não observância constitui uma falta ético‑disciplinar\npassível de punição, de acordo com o Código de Ética\nProfissional do Psicólogo.", "E": "Não há consequências específicas para a não\nobservância dessas diretrizes."}, "g": "D", "j": "A nao observancia das diretrizes do CFP sobre comunicacao escrita constitui falta etico-disciplinar passivel de punicao conforme o Codigo de Etica Profissional do Psicologo (Resolucao CFP 10/2005)."}, {"id": "2363947", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "FSNH", "t": "", "e": "De acordo com o Código de Ética Profissional, o psicólogo\nnão deve", "alt": {"A": "realizar diagnósticos, divulgar procedimentos ou\napresentar resultados de serviços psicológicos em\nmeios de comunicação, promovendo a exposição\nde organizações.", "B": "assumir responsabilidades profissionais somente por\natividades para as quais esteja capacitado pessoal,\nteórica e tecnicamente.", "C": "estabelecer acordos de prestação de serviços que\nrespeitem os direitos do usuário ou beneficiário de\nserviços de psicologia.", "D": "informar, a quem for de direito, os resultados\ndecorrentes da prestação de serviços psicológicos,\ntransmitindo somente o que for necessário para\na tomada de decisões que afetem o usuário\nou beneficiário.", "E": "orientar, a quem for de direito, acerca dos\nencaminhamentos apropriados, a partir da prestação\nde serviços psicológicos, e fornecer, sempre que\nsolicitado, os documentos pertinentes ao bom termo\ndo trabalho."}, "g": "A", "j": "Conforme o art. 20 do Codigo de Etica do Psicologo (Resolucao CFP 10/2005), e vedado realizar diagnosticos ou apresentar resultados em meios de comunicacao expondo organizacoes ou pessoas. Demais alternativas descrevem condutas permitidas/exigidas."}, {"id": "2363946", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "FSNH", "t": "", "e": "Assinale a alternativa que apresenta um dever fundamental\ndos psicólogos, de acordo com o Código de Ética\nProfissional.", "alt": {"A": "divulgar serviços profissionais, quando houver\nsituações de calamidade pública ou de emergência,\nem valores reduzidos", "B": "informar, a quem for de direito, os resultados\ndecorrentes da prestação de serviços psicológicos,\ntransmitindo sempre informações completas\npara a tomada de decisões que afetem o usuário\nou beneficiário", "C": "sugerir serviços de outros psicólogos, sempre que, por\nmotivos justificáveis, não puderem ser continuados\npelo profissional que os assumiu inicialmente,\nfornecendo ao seu substituto as informações\nnecessárias à continuidade do trabalho", "D": "realizar atividades profissionais que se considere a\ncapacitação pessoal, teórica e técnica adequada.", "E": "negligenciar os princípios, os conhecimentos e as\ntécnicas fundamentados na ciência psicológica, tudo\nem prol de o profissional agir em detrimento da ética\ne da legislação profissional"}, "g": "C", "j": "Conforme art. 1, alinea g, do Codigo de Etica do Psicologo, e dever fundamental sugerir servicos de outros profissionais quando nao puder continuar, fornecendo ao substituto as informacoes necessarias a continuidade do trabalho."}, {"id": "2363945", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "FSNH", "t": "", "e": "Assinale a alternativa que apresenta dois dos princípios\nfundamentais que regem o trabalho do psicólogo, de\nacordo com o Código de Ética Profissional.", "alt": {"A": "fundamentar suas intervenções na supressão da\nliberdade individual.", "B": "trabalhar visando promover a baixa qualidade de vida\ndas pessoas e das coletividades.", "C": "não promover a inclusão da população do acesso\nuniversal às informações, ao conhecimento da\nciência psicológica, aos serviços e aos padrões éticos\nda profissão.", "D": "não considerar as relações de poder nos contextos em\nque atua.", "E": "basear seu trabalho no respeito e na promoção da\nliberdade, dignidade, igualdade e integridade do\nser humano, apoiado nos valores que embasam a\nDeclaração Universal dos Direitos Humanos."}, "g": "E", "j": "O Principio Fundamental I do Codigo de Etica determina que o psicologo baseia seu trabalho no respeito e promocao da liberdade, dignidade, igualdade e integridade do ser humano, apoiado nos valores da Declaracao Universal dos Direitos Humanos. Demais alternativas invertem os principios."}, {"id": "2363943", "d": "psicologia", "a": ["Qualidade de Vida", "Estresse Laboral", "Psicologia e Organizações"], "ano": "2023", "org": "FSNH", "t": "", "e": "No que concerne à relação entre o estresse ocupacional e a\nqualidade de vida, assinale a alternativa correta.", "alt": {"A": "O estresse ocupacional pode levar ao desenvolvimento\nde inúmeras doenças, mas não afeta diretamente a\nqualidade de vida.", "B": "O estresse ocupacional interfere na qualidade de vida\napenas no âmbito profissional, não afetando outras\náreas da vida das pessoas.", "C": "O estresse ocupacional pode prejudicar a qualidade\nde vida e a produtividade do indivíduo, gerando\ninteresse em pesquisas sobre as causas e os métodos\nde redução do estresse.", "D": "A relação entre estresse e qualidade de vida não tem\nsido estudada por pesquisadores, visto que estão\nfocados, principalmente, em outros aspectos da\nsaúde ocupacional.", "E": "O estresse ocupacional não possui nenhuma relação\nsignificativa com a qualidade de vida do trabalhador,\nsendo um problema menos relevante para a\nliteratura científica."}, "g": "C", "j": "O estresse ocupacional prejudica qualidade de vida e produtividade, sendo objeto crescente de pesquisas sobre causas e estrategias de reducao; alternativas opostas (A, B, D, E) negam esses fatos."}, {"id": "2363942", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)", "Resoluções do Conselho Federal de Psicologia"], "ano": "2023", "org": "FSNH", "t": "", "e": "Assinale a alternativa que apresenta corretamente a\nvisão da psicologia quanto à relação entre religiosidade/\nespiritualidade e a experiência humana e quanto aos\ndiscursos fundamentalistas religiosos.", "alt": {"A": "A psicologia considera a religiosidade/espiritualidade\ncomo irrelevantes para a experiência humana e não\nse preocupa com os discursos fundamentalistas\nreligiosos.", "B": "A psicologia reconhece a religiosidade/espiritualidade\ncomo dimensões constitutivas da experiência humana\ne adota um posicionamento crítico contra os discursos\nfundamentalistas religiosos que violem a liberdade de\ncrença e a diversidade social e religiosa.", "C": "A psicologia defende discursos fundamentalistas\nreligiosos como formas legítimas de expressão da\nreligiosidade/espiritualidade humana.", "D": "A psicologia vê a religiosidade/espiritualidade como\numa ameaça à liberdade de crença e busca restringir\nsua manifestação.", "E": "A psicologia reconhece a religiosidade/espiritualidade\ncomo importantes, mas não se preocupa com\ndiscursos fundamentalistas religiosos que\npossam surgir."}, "g": "B", "j": "A psicologia reconhece a religiosidade/espiritualidade como dimensao constitutiva da experiencia humana e adota posicao critica contra discursos fundamentalistas que violem liberdade de crenca e diversidade; alinhado a Resolucoes do CFP sobre laicidade e religiosidade."}, {"id": "2363941", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "FSNH", "t": "", "e": "Em relação à laicidade e à liberdade religiosa, é correto\nafirmar que a psicologia", "alt": {"A": "considera a laicidade como uma ameaça à liberdade\nde crença e defende a interferência dos grupos\nreligiosos nas ações governamentais.", "B": "reconhece a laicidade como um dos balizadores éticos\ndo exercício profissional e opõe‑se a qualquer forma\nde discurso fundamentalista religioso que viole a\nliberdade de crença e a diversidade social e religiosa.", "C": "defende a laicidade apenas como uma ideologia\nque sustenta o Estado laico, mas não se preocupa\ncom a interferência dos grupos religiosos nas ações\ngovernamentais.", "D": "considera a laicidade como uma imposição do Estado,\nmas apoia a interferência dos grupos religiosos nas\nações governamentais.", "E": "não possui um posicionamento claro em relação à\nlaicidade e à liberdade religiosa."}, "g": "B", "j": "A psicologia reconhece a laicidade como balizador etico do exercicio profissional e opoe-se a discursos fundamentalistas religiosos que violem liberdade de crenca e diversidade, conforme posicionamento do CFP."}, {"id": "2081695", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Eric Erickson, conhecido pelas explicações promissoras sobre\na relação de apego, acreditava que o indivíduo precisava\npercorrer oito estágios em seu ciclo de vida, cada um deles\ncaracterizado por conflitos distintos para ser atingido. A\nrespeito dos estágios iniciais, julgue os próximos itens.\nI Os conflitos característicos dos dois primeiros estágios\nproporcionam uma explicação para o aumento da\nansiedade das crianças quando elas são separadas de\nsuas mães, no final do primeiro ano de vida, e para seu\ndeclínio, durante o segundo ano.\nII Durante o primeiro estágio do desenvolvimento, a\nquestão com a qual os bebês lidam é a da confiança.\nIII Quando o bebê adquire confiança em seu cuidador, em\ngeral durante o segundo ano de vida, ele deixa de ficar\nansioso durante separações breves, pois sabe que seu\ncuidador voltará.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (conflitos dos dois primeiros estagios explicam ansiedade de separacao no fim do 1o ano), II (1o estagio = confianca vs desconfianca), III (com confianca adquirida, deixa de ficar ansioso em separacoes breves) sao todos consistentes com a teoria de Erikson."}, {"id": "2081693", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Bee, em seu livro A criança em desenvolvimento, descreve\ncada passo do desenvolvimento infantil, inclusive do\ndesenvolvimento de cada sentido. Porém, raramente as\ninformações são recebidas por um sentido de cada vez. Ao\nmesmo tempo, há a percepção de estímulos sonoros,\nvisuais, olfativos, táteis e gustativos. Tal capacidade de\nperceber os estímulos simultaneamente é denominada", "alt": {"A": "integração intersensorial.", "B": "adaptação.", "C": "estimulação cruzada.", "D": "sentido múltiplo.", "E": "integração modal."}, "g": "A", "j": "A capacidade de perceber estimulos sonoros, visuais, olfativos, tateis e gustativos simultaneamente e denominada integracao intersensorial, conforme Helen Bee em 'A crianca em desenvolvimento'."}, {"id": "2081260", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A intervenção psicológica no campo institucional e da saúde,\nseja ela individual ou coletiva, vem sendo permeada pelo\nparadigma da promoção da saúde. Dessa forma, a atuação do\npsicólogo encontra-se cada vez mais inserida em uma equipe\nmultidisciplinar, buscando gerar qualidade de vida e reduzir\nvulnerabilidades e riscos à saúde relacionados a seus diversos\ndeterminantes. Com relação a esse assunto, assinale a\nalternativa incorreta.", "alt": {"A": "Os psicólogos da saúde direcionam-se para a\ncompreensão da forma como os fatores\ncomportamentais e sociais influenciam a saúde e a\ndoença, não sendo necessário incluir os fatores\nbiológicos para sua atuação. Os psicólogos centrados\nna promoção da saúde trabalham com os fatores\npsicológicos que fortalecem a saúde, podendo elaborar\ne implementar programas de promoção e de educação\npara a saúde coletiva.", "B": "A intervenção psicológica em saúde faz-se em uma\natuação em equipe interdisciplinar, possibilitando a\ncolaboração de várias especialidades no atendimento à\namplitude do ser humano. Inserido na equipe, o\npsicólogo promove a prática da interdisciplinaridade,\ndefendendo suas ideias e buscando interação com os\ndemais profissionais.", "C": "Em uma equipe interdisciplinar, o psicólogo deve ter\nclareza de suas funções e das funções das outras\nespecialidades, podendo auxiliar na comunicação entre\nos membros da equipe. O psicólogo é, na maioria das\nvezes, o interlocutor entre a equipe, o paciente e seus\nfamiliares, propiciando uma atitude mais humanizada.", "D": "Quando o psicólogo inicia o seu trabalho no campo\ninstitucional, os primeiros contatos que ele estabelece\ncom a instituição já conduzem a uma impressão\npreliminar de caráter diagnóstico.", "E": "A instituição de saúde, por exemplo, o hospital,\ntornou-se um dos campos mais proveitosos para a\nutilização da psicologia institucional. Todo o hospital\ntransforma-se em um agente psicoterápico em\nprofundidade e amplitude e, nesse sentido, organiza a\natuação do psicólogo em nível institucional."}, "g": "A", "j": "Alternativa A esta incorreta porque psicologos da saude devem SIM considerar fatores biologicos (abordagem biopsicossocial). As demais alternativas (B-E) descrevem corretamente a atuacao em equipe interdisciplinar e psicologia institucional."}, {"id": "2081256", "d": "psicologia", "a": ["Psicologia da Saúde", "Dor, Estresse e Luto"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "No que se refere a teorias e técnicas de manejo do estresse\nem pacientes e em profissionais de saúde, bem como ao\ncoping, assinale a alternativa incorreta.", "alt": {"A": "O relaxamento pode ajudar as pessoas a lidar com\nvariados problemas relacionados ao estresse. Duas\ntécnicas de relaxamento possíveis são o relaxamento\nmuscular progressivo e a resposta de relaxamento.", "B": "O estresse ocupacional em profissionais de saúde, que\npode evoluir para a síndrome de burnout, pode ser\nabordado em intervenções com formato\npsicoeducativo que utilizem técnicas\ncognitivo-comportamentais para a redução da tensão\ne de pensamentos disfuncionais e para o aumento de\nhabilidades comunicativas, de solução de problemas,\nde manejo do tempo e de autocontrole, a fim de\nminimizar o impacto dos estressores ocupacionais.", "C": "As capacidades fisiológicas e psicológicas das pessoas\npara o enfrentamento do estresse podem ser\naumentadas a partir da prática regular de atividade\nfísica.", "D": "Uma das técnicas de manejo do estresse é o\nbiofeedback, que consiste em converter certas\nrespostas fisiológicas supostamente involuntárias em\nsinais elétricos e proporcionar um feedback visual ou\nauditivo a seu respeito.", "E": "O coping (enfrentamento), na perspectiva cognitivista,\npode ser definido como o esforço cognitivo, não\ncomportamental, empregado para lidar com demandas\nespecíficas, externas, que excedam os recursos do\nindivíduo."}, "g": "E", "j": "Alternativa E esta incorreta: Lazarus e Folkman definem coping como esforco cognitivo E COMPORTAMENTAL (nao 'nao comportamental'), e tambem para demandas internas/externas. As demais (A-D) descrevem corretamente tecnicas de manejo do estresse."}, {"id": "2081255", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Quanto às variáveis que interferem na adesão ao tratamento,\nfator importante para os cuidados em saúde, assinale a\nalternativa incorreta.", "alt": {"A": "A qualidade da comunicação está no centro do\nrelacionamento entre pacientes e profissionais, de\nmaneira que os pacientes cuidados por profissionais da\nsaúde que são bons comunicadores tendem a ter\nmenor probabilidade de adesão ao tratamento.", "B": "Expectativas otimistas, apoio familiar e confiança no\nprofissional são variáveis importantes para a adesão do\npaciente ao tratamento.", "C": "Programar o tratamento de acordo com o estilo de vida\ndo paciente e envolver familiares são medidas que\naumentam a probabilidade de adesão ao tratamento e\nque podem ser tomadas pelos profissionais da saúde.", "D": "O nível de satisfação do médico com o trabalho e o seu\nestilo de comunicação são variáveis do profissional de\nsaúde que podem afetar a adesão do paciente ao\ntratamento.", "E": "As variáveis do regime de tratamento são importantes\npara a adesão a ele: quanto mais complexo o regime de\ntratamento para o paciente, menor a adesão."}, "g": "A", "j": "A esta incorreta: bons comunicadores aumentam (nao reduzem) a probabilidade de adesao. Demais alternativas (B-E) descrevem variaveis validas de adesao ao tratamento."}, {"id": "2081254", "d": "psicologia", "a": ["Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Na contemporaneidade, pode-se observar o papel da\npsicologia da saúde nas novas concepções e ações em saúde\nque buscam superar o modelo biomédico. O paradigma\nbiopsicossocial traz mudanças no entendimento do processo\nsaúde-doença. Com relação a esse assunto, assinale a\nalternativa incorreta.", "alt": {"A": "Saúde e doença são condições que estão em equilíbrio\ndinâmico.", "B": "Os estados de saúde e doença estão determinados por\nvariáveis biológicas, psicológicas e sociais, que não\ninteragem entre si.", "C": "O processo de adoecimento e a etiologia dos estados\nde doença são sempre multifatoriais.", "D": "O estudo, o diagnóstico, a prevenção e o tratamento de\ndoenças devem considerar as contribuições das\nvariáveis biológicas, psicológicas e sociais.", "E": "As ações integradas realizadas por uma equipe de\nsaúde são a melhor maneira de cuidar de pessoas que\nestão doentes."}, "g": "B", "j": "B esta incorreta: no modelo biopsicossocial as variaveis biologicas, psicologicas e sociais INTERAGEM entre si. As demais alternativas descrevem corretamente o paradigma."}, {"id": "2081253", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Na psicologia, entre as inúmeras descrições da\npersonalidade, do comportamento humano e de seus\nsintomas, encontra-se a explicação psicanalítica da formação\ndas estruturas clínicas. As três grandes estruturas clínicas são:\nneurose; psicose; e perversão. A respeito desse tema, julgue\nos itens a seguir.\n  I A neurose é a estrutura clínica caracterizada pela\npresença do recalque e do efeito patogênico que ele\ncausa no inconsciente, surgindo, assim, os sintomas.\n  II Na psicanálise, a perversão é vista no âmbito da\nsexualidade e, de forma geral, pode ser definida como o\ncomportamento psicossexual atípico para a obtenção do\nprazer sexual. A perversão, enquanto estrutura clínica,\norganiza-se como defesa contra angústias.\n  III A psicose ocorre a partir da presença da função paterna\nno desenvolvimento da criança, ou seja, quando é\nnecessária a presença da função paterna para que a\ncriança reconheça a castração. O psicótico é aquele que\nreconhece a castração, mas não a internaliza\nsatisfatoriamente.\n  Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens I e III estão certos."}, "g": "D", "j": "I (neurose = recalque com efeito patogenico) e II (perversao psicossexual como defesa contra angustias) sao corretos na psicanalise. III esta errado: psicose ocorre por foraclusao/ausencia da funcao paterna, e o psicotico NAO reconhece a castracao. Apenas I e II = D."}, {"id": "2081252", "d": "psicologia", "a": ["Psicopatologia", "Psicopatologia do Trabalho", "Psicologia e Organizações"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Acerca da psicopatologia e dos transtornos de personalidade,\npsicossomáticos e relacionados ao uso e ao abuso de\nsubstâncias psicoativas, assinale a alternativa correta.", "alt": {"A": "Os indivíduos com transtorno de sintomas somáticos\ngeralmente apresentam sintomas somáticos múltiplos\ne atuais, que provocam sofrimento ou resultam em\nperturbação significativa da vida diária. Os sintomas do\ntranstorno não podem estar relacionados a outra\ncondição médica concomitante.", "B": "Uma característica importante dos transtornos por uso\nde substâncias é a não alteração dos circuitos\ncerebrais, independentemente da gravidade dos\ntranstornos.", "C": "A característica essencial de um transtorno por uso de\nsubstâncias consiste na presença de um agrupamento\nde sintomas cognitivos, comportamentais e fisiológicos\nque indicam o uso contínuo da substância pelo\nindivíduo.", "D": "Um transtorno da personalidade é um padrão\npersistente de experiência interna e de\ncomportamento que se desvia, acentuadamente, das\nexpectativas da cultura do indivíduo, é difuso e\ninflexível, começa na infância, é instável ao longo do\ntempo e leva a sofrimento ou prejuízo.", "E": "O diagnóstico de transtornos da personalidade exige a\navaliação dos padrões de funcionamento de longo\nprazo do indivíduo, e as características particulares da\npersonalidade devem estar evidentes no começo da\nfase infantil. Os traços de personalidade que definem\nesses transtornos não diferem das características que\nsurgem em resposta a estressores situacionais\nespecíficos."}, "g": "C", "j": "C esta correta segundo DSM-5: transtorno por uso de substancia caracteriza-se por agrupamento de sintomas cognitivos, comportamentais e fisiologicos indicando uso continuo. A (sintomas somaticos nao podem coexistir com condicao medica), B (nao alteracao dos circuitos), D (comeco na infancia, instavel) e E sao incorretas."}, {"id": "2081249", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "O psicólogo, em sua atuação, lida frequentemente com a\nresponsabilidade e a complexidade da tarefa de responder,\nterapeuticamente, ao pedido de ajuda de outro ser humano.\nTal complexidade é inerente tanto à psicoterapia individual\nquanto à psicoterapia grupal. Com relação a esse assunto,\nassinale a alternativa incorreta.", "alt": {"A": "A clínica psicológica caracteriza-se não pelo local em\nque se realiza, mas pela qualidade da escuta e da\nacolhida que se oferece ao sujeito.", "B": "Moderação, originalidade e capacidade de percepção\ninterior são algumas das qualidades esperadas do\nterapeuta em qualquer tipo de psicoterapia.", "C": "A psicoterapia de grupo, diferentemente da individual,\né um método que trata, conscientemente, das relações\ninterpessoais e dos problemas psíquicos de vários\nindivíduos de um grupo, dentro de um quadro\ncientífico empírico.", "D": "A psicoterapia de grupo é uma metodologia clínica que\nempreende o tratamento de vários indivíduos\ndentro de um grupo e, devido à singularidade de\ncada paciente, não há como desenvolvê-la\nsistematicamente.", "E": "Um aspecto importante e indispensável da\npsicoterapia em grupo é a igualdade de status dos\nmembros. Todos são tratados da mesma forma, com\nrespeito e dignidade, e cada participante é uma fonte\nrica de experiência tanto para si próprio quanto para os\ndemais."}, "g": "D", "j": "D esta incorreta: a psicoterapia de grupo PODE sim ser desenvolvida sistematicamente apesar da singularidade dos pacientes. Demais alternativas descrevem corretamente caracteristicas da clinica e da psicoterapia individual/grupal."}, {"id": "2081247", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A avaliação psicológica, desde os primórdios da psicologia,\nocupou uma posição central na afirmação da psicologia como\nciência. A respeito da avaliação psicológica e de seus\nfundamentos, processos e instrumentos, assinale a\nalternativa correta.", "alt": {"A": "A avaliação psicológica pode ser definida como a coleta\ne a integração de dados relacionados à psicologia, com\na finalidade de fazer uma estimação psicológica, que é\nrealizada por meio de instrumentos como, por\nexemplo, testes, entrevistas, estudos de caso,\nobservação comportamental e aparatos e\nprocedimentos de medidas especialmente projetados.", "B": "Uma das etapas do processo de avaliação psicológica\nconsiste no levantamento dos instrumentos\nadequados, o que independe do conhecimento do\navaliador acerca dos construtos que podem ser\navaliados por esses instrumentos.", "C": "Os testes psicológicos e outros instrumentos de\navaliação podem diferir conforme uma série de\nvariáveis, mas dois testes psicológicos que se\nproponham a medir a mesma coisa — por exemplo, a\npersonalidade — não diferirão no conteúdo dos itens.", "D": "Como um instrumento de avaliação psicológica, a\nentrevista é um método usado para obter informação,\npor intermédio da comunicação indireta, e pode variar\ncom relação ao propósito, à duração e à natureza.", "E": "Normalmente, a avaliação psicológica envolve uma\nabordagem de resolução de problemas que mobiliza\numa fonte de dados, com vistas ao esclarecimento do\nmotivo do encaminhamento."}, "g": "A", "j": "A esta correta: avaliacao psicologica e coleta e integracao de dados via testes, entrevistas, estudos de caso, observacao comportamental etc. B (independe de conhecimento do avaliador), C (testes nao diferem no conteudo), D (comunicacao indireta) e E (uma fonte de dados) sao incorretas."}, {"id": "2081246", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A missão primordial do estabelecimento de preceitos éticos\nprofissionais é assegurar, dentro de valores relevantes para a\nsociedade e para as práticas desenvolvidas, um padrão de\nconduta que fortaleça o reconhecimento social daquela\ncategoria. Acerca da ética profissional dos psicólogos,\nassinale a alternativa incorreta.", "alt": {"A": "O psicólogo trabalhará visando a promover a saúde e a\nqualidade de vida das pessoas e das coletividades e\ncontribuirá para a eliminação de quaisquer formas de\nnegligência, de discriminação, de exploração, de\nviolência, de crueldade e de opressão.", "B": "Como profissional da saúde, o psicólogo deve nortear\nsua assistência no respeito aos princípios básicos da\nbioética: beneficência; não maleficência; autonomia; e\njustiça.", "C": "No que se refere ao trabalho do psicólogo nas\ninstituições de saúde, um risco para a\nconfidenciabilidade relaciona-se ao registro no\nprontuário do paciente. Como é dever do psicólogo\nrespeitar o sigilo profissional, ele fica isento do dever\nde manter atualizado o acompanhamento do paciente.", "D": "No exercício de suas funções profissionais, no contexto\nclínico e nos demais contextos, é vedado ao psicólogo\ninduzir a convicções políticas, filosóficas, morais,\nideológicas, religiosas, de orientação sexual ou a\nqualquer tipo de preconceito.", "E": "Toda intervenção psicológica deve pretender a\nautonomização do paciente. A relação clínica não será\nsatisfatória e estará sendo violada sempre que o\npsicólogo utilizar seus conhecimentos para alcançar\noutros objetivos que não o bem-estar e o respeito aos\nlegítimos interesses e direitos dos pacientes."}, "g": "C", "j": "C esta incorreta: o sigilo profissional NAO desobriga o psicologo de manter atualizado o prontuario do paciente; o registro adequado e dever profissional. As demais alternativas descrevem deveres eticos validos."}, {"id": "2073661", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A saúde pública e a higiene mental são funções sociais da\npsicologia. A respeito dos objetivos da higiene mental,\nassinale a alternativa incorreta.", "alt": {"A": "O primeiro objetivo, ou a primeira etapa, da higiene\nmental inclui o que se formulou como “fazer algo pelo\ndoente mental”. Essa instrução refere-se, basicamente,\nao plano assistencial, para um trato mais humano do\ndoente mental e um melhoramento das instituições\nassistenciais.", "B": "O segundo objetivo da higiene mental é o diagnóstico\ntardio, pois detectar tardiamente as doenças mentais\npode oferecer maiores chances para que o paciente\ndesenvolva sua saúde mental sem a interferência de\nserviços hospitalares.", "C": "O terceiro objetivo da higiene mental refere-se à\nprofilaxia ou à prevenção da doença. Nesse caso, o\npsicólogo trata dos aspectos psicológicos dessa tarefa,\ndefinindo como o emprego dos recursos psicológicos\npode prevenir as doenças.", "D": "O quarto objetivo da higiene mental, ou sua quarta\netapa histórica, é a reabilitação, que consiste na ajuda\npsicológica ao sujeito curado, ou curado com certo\ndéficit, para que ele possa reintegrar-se à comunidade\ne à sua família, reduzindo o impacto dos fatores que\ndesencadearam sua doença ou que possam torná-lo\ndoente novamente.", "E": "O quinto objetivo da higiene mental, ou a quinta etapa,\nrefere-se à promoção da saúde, que se torna\nindependente da doença e constitui o campo\nespecífico da psico-higiene."}, "g": "B", "j": "B esta incorreta: o objetivo da higiene mental e o diagnostico PRECOCE, nao tardio, para maximizar chances de tratamento e prevencao do agravamento. As demais alternativas descrevem etapas validas (assistencia, profilaxia, reabilitacao, promocao)."}, {"id": "2073660", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde Coletiva"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A intervenção psicológica assume um papel significativo na\nabordagem de situações de crise e de alta complexidade.\nAcerca da atuação do psicólogo em problemas específicos\nque representem maiores impactos nos pacientes e na saúde\npública, assinale a alternativa correta.", "alt": {"A": "A intervenção psicológica no tratamento da\ndependência química envolve o treinamento de novas\nhabilidades e estratégias cognitivas, com participação\npassiva do paciente, que não pode ser\nresponsabilizado.", "B": "A atuação do psicólogo no manejo do transtorno de\nestresse pós-traumático restringe-se ao tratamento do\nquadro já estabelecido e à manutenção do\nfuncionamento e da qualidade de vida em longo prazo,\njá que não é possível pensar em estratégias de\nprevenção do desenvolvimento da doença após um\nevento traumático.", "C": "Ao tratar de situações de tentativa de suicídio, isto é,\nsituações de crise do paciente, o psicólogo deverá\nconsiderar os fatores envolvidos, avaliar o risco de\nsuicídio, realizar psicoterapia de apoio ao paciente e\nencaminhá-lo a outros serviços de saúde, caso\nnecessário. Não cabe ao psicólogo abordar e orientar\nfamiliares ou amigos do paciente caso haja risco\niminente de suicídio.", "D": "A intervenção psicológica em caso de acidente de\ntrabalho pode ter como foco a reabilitação profissional.\nA condição de afastamento após um acidente de\ntrabalho associa-se a aspectos psicológicos, como, por\nexemplo, a ruptura nos projetos de vida, a perda da\nidentidade pessoal e profissional, a quebra do\ncotidiano, a mudança nas relações familiares, o\nsentimento de falha, o preconceito gerado por\neventual acusação de simulação, entre outros, por isso\né importante o suporte psicológico para o diagnóstico\nna área da saúde mental e para a eficácia do programa\nde reabilitação.", "E": "O papel do psicólogo na abordagem de situações de\nluto pode ser essencial para as pessoas enlutadas após\no diagnóstico de uma doença grave ou a perda de um\nente querido, por exemplo. Nesse contexto, uma\nimportante ferramenta para a intervenção psicológica\nsão os cinco estágios do luto, segundo o modelo de\nKübler-Ross, que correspondem, respectivamente, a:\nnegação; raiva; depressão; barganha; e aceitação."}, "g": "D", "j": "D esta correta: intervencao em acidente de trabalho foca reabilitacao profissional, abordando ruptura nos projetos de vida, perda de identidade, etc. A (participacao passiva), B (nao prevencao), C (nao abordar familiares em risco iminente) e E (ordem incorreta dos estagios de Kubler-Ross: a sequencia correta e negacao, raiva, barganha, depressao, aceitacao) sao incorretas."}, {"id": "2073659", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde Coletiva"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Considerando a intervenção e a atuação do psicólogo nos três\nníveis de atenção à saúde pública e coletiva, julgue os itens\nsubsecutivos.\n    I O primeiro nível de intervenção psicológica ocorre nos\nserviços de atenção primária de saúde (unidades básicas\nde saúde da família e centros de saúde). A prevenção\nprimária, cuja característica central é a atuação nos\nproblemas da população, deve estar diretamente\nrelacionada e condicionada à promoção da saúde,\ninvestindo-se na construção de estilos de vida saudáveis\ne na evitação de comportamentos de risco. A\nintervenção primária do psicólogo na equipe de saúde,\nainda que este desempenhe um papel específico, deverá\nser realizada em uma perspectiva interdisciplinar e\nmultiprofissional.\n    II A intervenção em nível secundário ocorre nos\nambulatórios e(ou) centros de especialidades. Seu\nprincipal objetivo é dar acompanhamento ao paciente,\najudando-o no seguimento de seu tratamento e\nprevenindo o agravamento da doença. Nesse nível, o\npsicólogo pode oferecer assistência psicoterápica em\nsuas várias modalidades e realizar psicodiagnósticos,\nporém sua atuação é isolada da dos demais profissionais\nde saúde, não sendo necessária na elaboração de\nprogramas de adesão aos tratamentos médicos.\n    III A intervenção em nível terciário está relacionada à\nassistência em problemas de alta complexidade. Em\ngeral, é feita nos hospitais, mas também pode ser feita\nnos centros de especialidades. Os psicólogos podem\napoiar e orientar pacientes hospitalizados e suas famílias,\natuar nos cuidados paliativos e assistir outros\nprofissionais de saúde.\n    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens I e III estão certos."}, "g": "E", "j": "I (atencao primaria, prevencao, perspectiva interdisciplinar) e III (atencao terciaria em hospitais, cuidados paliativos) estao corretos. II esta errado pois afirma que a atuacao do psicologo no nivel secundario e ISOLADA dos demais profissionais, o que contraria o paradigma interdisciplinar. Apenas I e III = E."}, {"id": "2073652", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Considerando as principais abordagensteóricas da psicologia,\nassinale a alternativa incorreta.", "alt": {"A": "O processo analítico foi caracterizado por Freud como\num processo de mudança no paciente que, uma vez\niniciado, tem vida própria, independentemente do\nanalista e, em certa medida, do próprio paciente, e que\nconsiste em quatro elementos bem definidos: a\nassociação livre; a resistência; a interpretação; e a\nelaboração.", "B": "O modelo cognitivo foi construído originalmente de\nacordo com as pesquisas conduzidas por Aaron Beck\npara explicar os processos psicológicos na depressão. O\nprincípio fundamental da terapia cognitiva é o de que a\nmaneira como os indivíduos percebem e processam a\nrealidade influencia a forma como eles se sentem e se\ncomportam.", "C": "Na psicoterapia psicodramática, criada por Moreno, o\ncliente é convidado a compartilhar seu mundo privado,\ndando vida a ele e concretizando-o. O psicodrama,\nenquanto método, utiliza principalmente três\ninstrumentos: palco ou cenário; protagonista ou\npaciente; e diretor.", "D": "Segundo Carl Rogers, na abordagem humanista\nexistencial, o processo psicoterápico gira em torno do\nfuncionamento organísmico, por meio da tendência\natualizante do cliente, e o papel do psicoterapeuta é\nfacilitar que essa tendência atualizante possa fluir de\nforma natural e espontânea.", "E": "A abordagem comportamental baseia-se em alguns\npontos gerais do pensamento de Skinner: o\nestabelecimento do comportamento como objeto de\nestudo; a suposição do comportamento como\ndeterminado; a pretensão de fazer uma análise\ncientífica do comportamento a partir da noção de\nciência proposta pela ciência natural; o estudo\nrealizado a partir do dado empírico; o afastamento\nentre a metafísica e o saber científico; e a proposta de\nprevisão e controle."}, "g": "C", "j": "C esta incorreta: o psicodrama de Moreno utiliza CINCO instrumentos (palco/cenario, protagonista, diretor, ego-auxiliar e publico), nao tres. As demais (Freud, Beck, Rogers, Skinner) estao corretas."}, {"id": "2065797", "d": "psicologia", "a": ["Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade"], "ano": "2023", "org": "IIER", "t": "", "e": "Em relação à interdisciplinaridade e à multidisciplinaridade\nem saúde, assinale a alternativa correta.", "alt": {"A": "O trabalho interdisciplinar consiste no estudo de um\nobjeto por diferentes disciplinas, sem que haja\nconvergência entre os conceitos e métodos.", "B": "Na prática multidisciplinar, há uma integração das\ndisciplinas no que concerne a conceitos e a métodos.", "C": "No modelo multidisciplinar, certas subdisciplinas\nconstituem novas disciplinas ou subdisciplinas, com\nmétodos e conteúdos teóricos próprios.", "D": "O modelo interdisciplinar é resultante de uma soma de\n“olhares” e de métodos provenientes de diferentes\ndisciplinas ou práticas, quer normativas ou discursivas,\ncolocadas pelos profissionais.", "E": "No modelo interdisciplinar, há uma intercessão dos\nconhecimentos disciplinares."}, "g": "E", "j": "E esta correta: o modelo interdisciplinar caracteriza-se pela intercessao/integracao dos conhecimentos disciplinares. A multidisciplinaridade e apenas justaposicao sem integracao (oposto do que A e D afirmam)."}, {"id": "2065796", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2023", "org": "IIER", "t": "", "e": "No que diz respeito à atenção especializada à saúde, assinale\na alternativa correta.", "alt": {"A": "A atenção especializada é dividida em três: secundária;\nterciária; e emergencial.", "B": "A atenção especializada de alta complexidade é\ncomposta por serviços especializados encontrados em\nhospitais e em ambulatórios e envolve atendimento\ndirecionado para áreas como pediatria, ortopedia,\ncardiologia, oncologia, neurologia, psiquiatria,\nginecologia, oftalmologia, entre outras especialidades\nmédicas.", "C": "As unidades de pronto-atendimento (UPA)\nencaixam-se como atenção especializada e concentram\nos atendimentos de saúde de complexidade\nintermediária.", "D": "Os profissionais do SAMU atendem apenas urgências\nde natureza clínica.", "E": "As pessoas podem procurar a unidade de\npronto-atendimento mais próxima da residência para\nreceber atendimentos em praticamente todas as\nsituações, exceto naquelas em que há risco de morte."}, "g": "C", "j": "C esta correta: as UPAs constituem atendimento de complexidade intermediaria. A (3 niveis), B (alta complexidade tambem em ambulatorios), D (SAMU so clinicas) e E (UPA exceto risco de morte - na verdade UPA atende emergencias) estao incorretas."}, {"id": "2065795", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde da Família"], "ano": "2023", "org": "IIER", "t": "", "e": "Com relação à atenção primária à saúde, assinale a\nalternativa incorreta.", "alt": {"A": "As unidades básicas de saúde (UBS), conhecidas em\nmuitos locais como postos de saúde, realizam ações e\natendimentos voltados à prevenção e à promoção da\nsaúde.", "B": "Na atenção primária, as pessoas podem procurar a UBS\nmais próxima de suas residências para atendimentos\nem praticamente todas as situações, inclusive aquelas\nem que há risco de morte.", "C": "Na UBS, é possível fazer exames e consultas de rotina\ncom equipes multiprofissionais e com profissionais\nespecializados em saúde da família, que trabalham\npara garantir atenção integral à saúde no território.", "D": "É nesse nível que os profissionais se articulam para\natuar não apenas nas unidades de saúde, mas também\nem espaços públicos da comunidade, na oferta de\npráticas integrativas e complementares – como\nfitoterapia, yoga e Reiki –, e em visitas domiciliares às\nfamílias.", "E": "Mais do que prover assistência clínica, o objetivo é\nestar próximo às pessoas e promover a saúde e a\nqualidade de vida da comunidade."}, "g": "B", "j": "B esta incorreta: a UBS NAO atende situacoes de risco de morte (essas vao para UPA/emergencia hospitalar). Demais alternativas descrevem corretamente a atencao primaria."}, {"id": "2065794", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde"], "ano": "2023", "org": "IIER", "t": "", "e": "Acerca das estratégias de enfrentamento coping, assinale a\nalternativa correta.", "alt": {"A": "Um processo que pode ser desencadeado frente a\nestressores é a resiliência.", "B": "As estratégias de enfrentamento sempre devem ser\npositivas. Por exemplo, um motorista que está ansioso\nno trânsito pode tanto fumar um cigarro quanto fazer\num treino respiratório.", "C": "Nem todo esforço para lidar com o estressor é uma\nresposta de coping.", "D": "A estratégia de enfrentamento do tipo centrado na\nemoção tem como função reduzir as sensações\nemocionais ocasionadas pelas situações estressoras\npresentes nas situações que não se pode mudar.", "E": "Os fatores de risco e de proteção podem ser\nconsiderados como variáveis que interferem na\nresposta da pessoa a uma situação adversa, sendo que\no primeiro aumenta a probabilidade da resiliência."}, "g": "A", "j": "A esta correta: a resiliencia e processo que pode ser desencadeado frente a estressores. B (estrategias sempre positivas), D (parcialmente correta mas mal redigida) e E (fatores de risco aumentam resiliencia - errado, aumentam vulnerabilidade) sao incorretas."}, {"id": "2065793", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a traumas e estressores"], "ano": "2023", "org": "IIER", "t": "", "e": "A respeito das fases do estresse, assinale a alternativa\nincorreta.", "alt": {"A": "O estresse inicia-se com a fase de alerta, quando a\npessoa se defronta com uma situação estressora.", "B": "Na fase inicial do estresse, o organismo prepara-se para\nlutar ou fugir, gerando um estado de prontidão,\ncaracterizado por taquicardia, alteração da pressão\narterial, sudorese, boca seca, mãos e pés frios,\nmudanças de apetite, diarreia passageira, entre outros.", "C": "A segunda fase do estresse é a resistência. O organismo\ntenta restabelecer o equilíbrio interno, utilizando toda\na energia adaptativa.", "D": "A penúltima fase do estresse é considerada a mais\npatológica, pois há uma quebra total da resistência,\nocasionando exaustão psicológica em forma de\ndepressão e de exaustão física. Essa fase ainda não leva\no indivíduo à morte.", "E": "A fase de quase-exaustão é caracterizada pelo início do\nprocesso de adoecimento, pois há um\nenfraquecimento do sistema imunológico e as defesas\ndo organismo começam a ceder, dando início à quarta\nfase do estresse, a exaustão."}, "g": "D", "j": "D esta incorreta: a fase mais patologica do estresse e a EXAUSTAO (ultima), nao a quase-exaustao (penultima). A descricao tambem mistura caracteristicas das duas fases finais. Demais (A alerta, B sintomas iniciais, C resistencia, E quase-exaustao) estao corretas no modelo de Lipp."}, {"id": "2065792", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a traumas e estressores"], "ano": "2023", "org": "IIER", "t": "", "e": "Acerca do transtorno do estresse pós-traumático, assinale a\nalternativa incorreta.", "alt": {"A": "Pessoas com transtorno do estresse pós-traumático\nsão mais propensas a evitar situações que percebam\ncomo potencialmente ameaçadoras.", "B": "Os sintomas do estresse pós-traumático incluem\npersonalização, entorpecimento, amnésia dissociativa\ne hipervigilância.", "C": "Uma experiência traumática não tem “causalidade”\nbiológica, pois se trata de um evento externo que afeta\no indivíduo.", "D": "Tecnicamente, o transtorno do estresse\npós-traumático é atribuído a indivíduos que\nvivenciaram sintomas de transtorno de estresse agudo\npor mais de um mês.", "E": "Os sintomas do transtorno do estresse pós-traumático\ne de transtornos relacionados a ele podem persistir por\nmuitos anos."}, "g": "B", "j": "B esta incorreta: o sintoma classico do TEPT e DESPERSONALIZACAO (nao 'personalizacao'). Demais alternativas descrevem corretamente o transtorno."}, {"id": "2065791", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2023", "org": "IIER", "t": "", "e": "O transtorno fóbico gera sintomas fisiológicos relacionados\nao sistema nervoso autônomo (neurovegetativo).\nConsiderando essa informação, assinale a alternativa que só\napresenta sintomas característicos desse transtorno.", "alt": {"A": "sudorese, palpitações, pânico, vertigem e parestesias", "B": "palpitações, pânico, vertigem, parestesias e sono", "C": "vertigem, enjoo e queda de pressão", "D": "sudorese, perda de consciência e vômito", "E": "distúrbios gastrintestinais, queda de pressão e vômito"}, "g": "A", "j": "A apresenta sintomas neurovegetativos tipicos do transtorno fobico: sudorese, palpitacoes, panico, vertigem e parestesias. B inclui 'sono' (nao e neurovegetativo direto), demais alternativas incluem sintomas atipicos (perda de consciencia, queda de pressao, vomito) que nao caracterizam o quadro fobico."}, {"id": "2065790", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2023", "org": "IIER", "t": "", "e": "Uma excelente forma de se combater o burnout é engajar o\ncolaborador. Para que o engajamento positivo ocorra, é\nnecessário que o ambiente de trabalho atenda a algumas\ncondições. Considerando essas informações, assinale a\nalternativa que não apresenta uma das condições\nimprescindíveis ao ambiente de trabalho.", "alt": {"A": "segurança psicológica", "B": "local com móveis e com equipamentos apropriados", "C": "reconhecimento e recompensas apenas quando há\nrisco de perda do colaborador", "D": "transparência na tomada de decisões por parte dos\nsupervisores", "E": "sensação de que as tarefas vão de encontro com os\nvalores profissionais e morais do trabalhador"}, "g": "C", "j": "C NAO e condicao para engajamento: reconhecimento e recompensas apenas quando ha risco de perda e pratica reativa e contraproducente. As demais (seguranca psicologica, ambiente adequado, transparencia, alinhamento de valores) sao condicoes validas."}, {"id": "2065789", "d": "psicologia", "a": ["Qualidade de Vida", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2023", "org": "IIER", "t": "", "e": "A Organização Mundial de Saúde (OMS) considerou o burnout\ncomo uma das principais doenças entre europeus e\namericanos. Acerca desse tema, assinale a alternativa que\napresenta a classificação internacional de doenças da\nsíndrome de burnout.", "alt": {"A": "CID 11", "B": "CID H11", "C": "CID A09", "D": "CID F10", "E": "CID G43"}, "g": "A", "j": "A CID-11 (publicada em 2019 e em vigor desde 2022) classificou oficialmente o burnout como sindrome ocupacional. Demais codigos referem-se a outras patologias (otologia, intestinal, alcool, enxaqueca)."}, {"id": "2065788", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2023", "org": "IIER", "t": "", "e": "Assinale a alternativa que apresenta os sintomas mais\ncaracterísticos de burnout.", "alt": {"A": "cansaço e improdutividade", "B": "falta de foco e distanciamento social", "C": "autoexclusão e cansaço", "D": "falta de criatividade e falta de inovação", "E": "exaustão emocional e distanciamento afetivo"}, "g": "E", "j": "Os tres pilares de burnout segundo Maslach sao exaustao emocional, despersonalizacao/distanciamento afetivo e reducao da realizacao profissional. E captura os dois mais caracteristicos."}, {"id": "2065786", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2023", "org": "IIER", "t": "", "e": "A avaliação psicológica é um processo técnico e científico\nrealizado com pessoas ou com grupos de pessoas e que\nrequer metodologias específicas de aplicação. Sendo assim,\nassinale a alternativa que apresenta os instrumentos de\navaliação psicológica.", "alt": {"A": "teste psicológico, tomografia e degravação", "B": "dinâmicas, exames de imagem e observações", "C": "observação, teste psicológico e entrevista", "D": "entrevista, teste de personalidade e exames de\nimagem", "E": "tomografia, dinâmica e observações"}, "g": "C", "j": "Os instrumentos de avaliacao psicologica sao observacao, teste psicologico e entrevista. Tomografia e exames de imagem nao sao instrumentos psicologicos; degravacao e procedimento auxiliar."}, {"id": "2065781", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2023", "org": "IIER", "t": "", "e": "O prontuário psicológico e os documentos emitidos pelo\nprofissional responsável devem ser arquivados e mantidos\ndurante um certo tempo. Acerca desse assunto, assinale a\nalternativa correta.", "alt": {"A": "Os registros documentais do serviço psicológico devem\npermanecer arquivados por, ao menos, três anos.", "B": "Os registros documentais do serviço psicológico não\nnecessitam de tempo mínimo de arquivamento.", "C": "Os registros documentais do serviço psicológico devem\npermanecer arquivados por, ao menos, cinco anos.", "D": "Os registros documentais do serviço psicológico devem\npermanecer arquivados por, ao menos, um ano.", "E": "Os registros documentais do serviço psicológico devem\npermanecer arquivados por, ao menos, dez anos."}, "g": "C", "j": "Conforme art. 16 da Resolucao CFP 06/2019, os registros documentais do servico psicologico devem ser arquivados por no minimo 5 anos."}, {"id": "2065780", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2023", "org": "IIER", "t": "", "e": "Assinale a alternativa que apresenta as principais funções de\num atestado psicológico.", "alt": {"A": "registrar, de forma objetiva e sucinta, informações\npontuais sobre as consultas, tais como:\ncomparecimento e acompanhamento (tempo, dias e\nhorários)", "B": "justificar faltas, impedimentos, afastamentos ou\ndispensas ou, ainda, justificar aptidão para atividades\nespecíficas após um processo de avaliação psicológica", "C": "comunicar descritivamente a atuação profissional em\ndeterminado caso, podendo gerar orientações,\nrecomendações, encaminhamentos e intervenções", "D": "avaliar psicologicamente e subsidiar decisões\nrelacionadas ao contexto em que surgiu a demanda", "E": "oferecer uma resposta sobre uma questão-problema\npertinente ao campo da psicologia ou sobre algum\ndocumento psicológico, visando a subsidiar\ntecnicamente uma decisão"}, "g": "B", "j": "Conforme Res CFP 06/2019, o atestado psicologico tem a funcao de justificar faltas, afastamentos, dispensas ou aptidao para atividades especificas. A descreve a declaracao, C o relatorio, D a avaliacao psicologica, E o parecer."}, {"id": "2065779", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2023", "org": "IIER", "t": "", "e": "Uma entrevista de qualidade deve unir bom uso de técnicas\ne habilidades interpessoais. Essas atitudes devem ampliar o\nacesso ao entrevistado e, por consequência, gerar um\nambiente extremamente adequado à fluidez da pesquisa.\nPortanto, para levar uma entrevista a termo de modo\nadequado, o entrevistador deve", "alt": {"A": "evitar a expressão dos motivos que levaram a pessoa a\nbuscar ajuda.", "B": "evadir esclarecimento para colocações vagas ou\nincompletas.", "C": "delegar a iniciativa em momentos de impasse.", "D": "censurar defesas e modos de estruturação do sujeito.", "E": "confrontar, gentilmente, esquivas e contradições."}, "g": "E", "j": "Em uma entrevista de qualidade, o entrevistador deve confrontar gentilmente esquivas e contradicoes (manejo terapeutico). A, B, C e D descrevem comportamentos inadequados (evitar, evadir, delegar, censurar)."}, {"id": "2065778", "d": "psicologia", "a": ["Abordagem Centrada na Pessoa", "Teorias e Técnicas Psicoterápicas"], "ano": "2023", "org": "IIER", "t": "", "e": "A entrevista fenomenológica tem como objetivo definir uma\nrelação terapêutica baseada em três atitudes. Assinale a\nalternativa que apresenta corretamente essas atitudes.", "alt": {"A": "empatia, aceitação incondicional e autenticidade", "B": "validação interna, organização e criticidade", "C": "afinidade, unidade e simpatia", "D": "admiração, respeito e simpatia", "E": "admiração, respeito e empatia"}, "g": "A", "j": "As tres atitudes facilitadoras da Abordagem Centrada na Pessoa (Rogers) sao empatia, aceitacao incondicional (consideracao positiva incondicional) e autenticidade (congruencia)."}, {"id": "2065777", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2023", "org": "IIER", "t": "", "e": "Há vários tipos de entrevista que atendem a diferentes\ncritérios de classificação. Com base nessa informação,\nassinale a alternativa que apresenta um tipo de entrevista.", "alt": {"A": "entrevista finalística", "B": "entrevista conclusiva", "C": "entrevista não estruturada", "D": "entrevista lúdica", "E": "entrevista prognóstica"}, "g": "C", "j": "A entrevista nao estruturada e um tipo classico de classificacao por nivel de estruturacao. As demais (finalistica, conclusiva, prognostica) nao sao categorias formais consagradas; ludica e modalidade especifica para criancas."}, {"id": "2065776", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "IIER", "t": "", "e": "Os psicólogos que, porventura, transgredirem os preceitos do\ncódigo de ética profissional sofrerão infração disciplinar.\nNesse sentido, assinale a alternativa que apresenta\npenalidade que não pode ser aplicada.", "alt": {"A": "censura pública", "B": "multa", "C": "advertência", "D": "cassação do exercício profissional ad referendum do\nConselho Federal de Psicologia", "E": "suspensão do exercício profissional, por até um ano, ad\nreferendum do Conselho Federal de Psicologia"}, "g": "E", "j": "As penalidades do CEP (Res CFP 10/2005 e Lei 5766/71) sao advertencia, multa, censura publica, suspensao do exercicio (por ate 30 dias ad referendum CFP) e cassacao. A suspensao por ate 1 ano ad referendum CFP nao existe como categoria - E nao pode ser aplicada."}, {"id": "2065775", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "IIER", "t": "", "e": "O psicólogo, sempre que promover publicamente seus\nserviços, deverá", "alt": {"A": "utilizar o preço do serviço como forma de propaganda.", "B": "realizar previsão taxativa de resultados.", "C": "propor atividades que sejam atribuições privativas de\noutras categorias profissionais.", "D": "divulgar quaisquer qualificações, atividades e recursos\nrelativos a técnicas e a práticas próprias.", "E": "informar seu nome completo, o CRP e seu número de\nregistro."}, "g": "E", "j": "Ao promover publicamente seus servicos, o psicologo deve informar nome completo, CRP e numero de registro. A (preco como propaganda), B (previsao taxativa de resultados), C (atribuicoes de outras categorias) e D (qualificacoes nao reconhecidas) sao vedacoes."}, {"id": "2065773", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2023", "org": "IIER", "t": "", "e": "Assinale a alternativa que apresenta os deveres fundamentais\ndo psicólogo perante o código de ética profissional.", "alt": {"A": "assumir responsabilidades profissionais somente por\natividades para as quais esteja capacitado pessoal,\nteórica e tecnicamente", "B": "prestar serviços psicológicos de qualidade, em\nquaisquer condições de trabalho, utilizando princípios,\nconhecimentos e técnicas reconhecidamente\nfundamentados na ciência psicológica, na ética e na\nlegislação profissional", "C": "induzir pacientes a convicções políticas, filosóficas,\nmorais, ideológicas, religiosas ou de orientação sexual,\nou a qualquer tipo de preconceito, no exercício de suas\nfunções profissionais", "D": "utilizar ou favorecer o uso de conhecimento e a\nutilização de práticas psicológicas como instrumentos\nde castigo, tortura ou qualquer forma de violência", "E": "informar a quem de direito os resultados decorrentes\nda prestação de serviços psicológicos, transmitindo\ntoda informação que afete o usuário ou o beneficiário"}, "g": "A", "j": "A descreve corretamente dever fundamental do psicologo (assumir responsabilidades somente em atividades capacitadas). B contem 'em quaisquer condicoes' (errado), C (induzir) e D (instrumento de violencia) sao vedacoes, E afirma transmitir 'TODA' informacao (errado: so o necessario)."}, {"id": "2159889", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "Claudia apresenta dificuldades no aprendizado da\nMatemática, confunde-se com cálculos simples, sequências\nnuméricas e até com a transposição da Matemática no dia a\ndia. Ela não apresenta dificuldades visuais e auditivas ou\ndistúrbios neurológicos. Qual é o possível diagnóstico de\nCláudia?", "alt": {"A": "Afasia.", "B": "Disgrafia.", "C": "Disortografia", "D": "Discalculia.", "E": "Síndrome de Rett."}, "g": "D", "j": "Dificuldade especifica de aprendizagem em matematica (calculos, sequencias numericas, transposicao), sem deficits sensoriais ou neurologicos, caracteriza discalculia (transtorno especifico da aprendizagem com prejuizo na matematica, DSM-5)."}, {"id": "2159888", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Com base em Weiss (1994), assinale a alternativa que não\nse enquadra na elaboração de um diagnóstico\npsicopedagógico.", "alt": {"A": "Anamnese.", "B": "Entrevista Familiar Exploratória Situacional (EFES).", "C": "Síntese diagnóstica e devolutiva.", "D": "Sessões lúdicas centradas na aprendizagem.", "E": "Aplicação de testes cognitivos e de personalidade."}, "g": "E", "j": "No modelo de Weiss (1994) para diagnostico psicopedagogico, as etapas incluem anamnese, EFES, sessoes ludicas centradas na aprendizagem, sintese diagnostica e devolutiva. Testes cognitivos/personalidade nao integram o roteiro especifico psicopedagogico."}, {"id": "2159887", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2022", "org": "CFP", "t": "", "e": "A Entrevista Operativa Centrada na Aprendizagem (EOCA) é\na primeira sessão realizada com a criança (Sampaio, 2009).\nAssinale a alternativa incorreta sobre a EOCA, de acordo\ncom a autora.", "alt": {"A": "As observações da primeira entrevista devem ser\nsubmetidas a uma verificação mais rigorosa ao longo\ndo processo diagnóstico.", "B": "Por se tratar de uma primeira observação, o\npsicopedagogo não pode elaborar, a partir da EOCA,\nhipóteses diagnósticas.", "C": "Na EOCA, já é possível observar a modalidade de\naprendizagem da criança.", "D": "Durante a EOCA, o psicopedagogo deve estar atento\npara ouvir, perceber ansiedades, expectativas e\npostura do entrevistado.", "E": "A EOCA tem o objetivo de investigar os vínculos que o\nsujeito tem com os objetos e os conteúdos da\naprendizagem escolar."}, "g": "B", "j": "B esta incorreta: a EOCA permite SIM ao psicopedagogo elaborar hipoteses diagnosticas iniciais (a serem verificadas no decorrer do processo). Demais alternativas descrevem corretamente a tecnica de Sampaio."}, {"id": "2159886", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação psicopedagógica acontece quando uma família\ntem como queixa fundamental a dificuldade de um de seus\nmembros diante de sua aprendizagem (Acampora, 2015). A\ndevolutiva dessa avaliação é uma importante etapa do\nprocesso. Acerca da devolutiva, julgue os itens a seguir.\n    I. A devolutiva deve ser sempre exclusiva para os pais, a\nfim de proteger a criança.\n    II. O informe psicopedagógico deve ser sempre igual,\nindependentemente da pessoa para quem é\nencaminhado, a fim de manter a coerência e a ética da\navaliação.\n    III. A avaliação deve trazer recomendações e possíveis\nencaminhamentos, de acordo com a hipótese\ndiagnóstica.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "I esta errado (devolutiva nao e exclusiva para os pais), II esta errado (informe deve ser adaptado ao destinatario), III esta correto (devolutiva deve trazer recomendacoes e encaminhamentos). Apenas III = C."}, {"id": "2159883", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "Lúcia é estudante de Psicologia e tem dois filhos (Joaquim,\nde 7 anos, e Carlos, de 4 anos). Após estudar a teoria de\nWallon, ela resolveu testar em casa em qual fase do\ndesenvolvimento estavam seus filhos de acordo com a\nteoria do autor. Para tanto, pegou cinco maçãs e duas\nbananas, mostrou aos filhos e perguntou individualmente a\ncada um deles: “O que eu tenho mais aqui: mais maçãs ou\nmais frutas?”. Carlos respondeu rapidamente: “Mais\nmaçãs!”. Quando Lúcia perguntou a Joaquim, ele também\nrespondeu “Mais maçãs”, porém logo se corrigiu: “Mais\nfrutas, porque banana e maçã são frutas”. Com base nessas\nrespostas e embasada na teoria de Wallon, Lúcia chegou à\nseguinte conclusão:", "alt": {"A": "Carlos e Joaquim estão na fase do Personalismo, pois\nderam a mesma resposta, que revela o raciocínio\nsincrético, no qual a criança tem dificuldade de\nclassificação.", "B": "Carlos está na fase do Personalismo, com raciocínio\nsincrético, e Joaquim, na fase Categorial, pois, apesar\nde se confundir a princípio, ele logo conseguiu fazer a\nclassificação.", "C": "Carlos e Joaquim estão na fase Categorial, pois deram a\nmesma resposta, que revela o raciocínio sincrético, no\nqual a criança tem dificuldade de classificação.", "D": "Carlos está na fase Categorial, com raciocínio\nsincrético, e Joaquim, na fase do Personalismo, pois,\napesar de se confundir a princípio, ele logo conseguiu\nfazer a classificação.", "E": "Joaquim, ao se enganar na resposta, demonstrou que\nainda não fez a transição para a fase Categorial e, por\nisso, permanece na fase do Personalismo com o irmão\nCarlos."}, "g": "B", "j": "Pela teoria de Wallon: Carlos (4 anos) esta na fase do Personalismo (3-6 anos), com raciocinio sincretico (dificuldade de classificacao); Joaquim (7 anos) esta na fase Categorial (6-11 anos), conseguindo realizar classificacoes apos correcao."}, {"id": "2159882", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia da Educação", "Resoluções do Conselho Federal de Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "Os profissionais engajados no campo da Psicopedagogia\ntêm atentado para a importância do trabalho a ser\nrealizado na instituição escolar. Sobre a Psicopedagogia\nInstitucional é certo afirmar que o psicopedagogo escolar:", "alt": {"A": "substitui o psicólogo escolar, visto que trabalha com o\nenfoque clínico no processo ensino-aprendizagem", "B": "deve trabalhar exclusivamente com transtornos ou\ndificuldades de aprendizagem.", "C": "realiza o trabalho clínico dentro da escola, priorizando\natendimentos individuais dos alunos.", "D": "trabalha dentro de um espaço multidisciplinar,\ndesenvolvendo seu trabalho juntamente com toda a\ncomunidade educativa.", "E": "restringe seu trabalho ao do processo de alfabetização,\npois é no início da escolarização que muitas das\ndificuldades de aprendizagem aparecem entre\ncrianças."}, "g": "D", "j": "D descreve corretamente a Psicopedagogia Institucional: trabalho multidisciplinar com toda a comunidade educativa. As demais alternativas reduzem o papel do psicopedagogo escolar (substituir psicologo, exclusividade em transtornos, atendimentos individuais, restricao a alfabetizacao)."}, {"id": "2159877", "d": "psicologia", "a": ["Psicopatologia", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica", "CID-10 e DSM", "Transtornos do Neurodesenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "O diagnóstico de TDAH é difícil devido à natureza clínica\nheterogênea do transtorno. Sobre o TDAH, assinale a\nalternativa correta.", "alt": {"A": "A incapacidade de um indivíduo manter a atenção, a\natividade motora ou o controle dos impulsos são\ncaracterísticas apenas do TDAH.", "B": "No DSM-5, TDAH é caracterizado como um transtorno\ndo neurodesenvolvimento, tendo como característica\nessencial um padrão persistente de desatenção e/ou\nhiperatividade-impulsividade que interfere no\nfuncionamento ou no desenvolvimento do sujeito.", "C": "O TDAH só acontece em crianças. Ao longo do\ndesenvolvimento, os problemas vão se atenuando, até\ndesaparecerem por completo quando adultos.", "D": "O TDAH possui cura se for tratado corretamente,\ndevendo o tratamento ser exclusivamente feito de\nforma medicamentosa.", "E": "O diagnóstico de TDAH deve ser baseado unicamente\nna lista de sintomas, tais como desatenção e\nimpulsividade."}, "g": "B", "j": "B descreve corretamente o TDAH conforme DSM-5: transtorno do neurodesenvolvimento com padrao persistente de desatencao e/ou hiperatividade-impulsividade. As demais alternativas contem afirmacoes falsas (exclusividade dos sintomas, restricao a criancas, cura medicamentosa, diagnostico apenas por lista de sintomas)."}, {"id": "2159876", "d": "psicologia", "a": ["Psicopatologia", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica", "Transtornos do Neurodesenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "Os Transtornos Globais do Desenvolvimento são distúrbios\nnas interações sociais recíprocas que costumam\nmanifestar-se nos primeiros cinco anos de vida. Quanto\naos Distúrbios do Espectro do Autismo, assinale a\nalternativa correta.", "alt": {"A": "Os problemas apresentados pela criança com autismo\npodem aparecer em apenas um de seus contextos\ndesenvolvimentais: por exemplo, podem aparecer na\nescola, e não em casa.", "B": "Dificuldades de linguagem e comunicação e\ndesenvolvimento precário da imaginação não são\nmanifestações comuns dentro do autismo.", "C": "As crianças do espectro do autismo não gostam de\nrotinas e procuram sempre alterá-las para evitar a\nmonotonia.", "D": "A criança do espectro do autismo é fácil de ser\nidentificada, pois todas as pessoas com tal diagnóstico\napresentam as mesmas características.", "E": "A interação social é prejudicada qualitativamente,\npodendo ocasionar falta de reciprocidade social ou\nemocional."}, "g": "E", "j": "E descreve criterio classico do TEA: prejuizo qualitativo na interacao social, com falta de reciprocidade social/emocional. As demais alternativas trazem afirmacoes incorretas (manifestacao restrita, ausencia de prejuizo de linguagem, rejeicao de rotinas, homogeneidade de apresentacao)."}, {"id": "2159875", "d": "psicologia", "a": ["Psicopatologia", "Avaliação Psicológica", "Psicologia da Educação", "Psicodiagnóstico e Avaliação Psicológica", "Exames Mentais e Funções Psíquicas"], "ano": "2022", "org": "CFP", "t": "", "e": "São muitas as causas que podem levar uma criança a\napresentar desordens de aprendizagem. Com o diagnóstico\ne o tratamento certos, muitos indivíduos conseguem\navançar e evoluir em seu desenvolvimento. Com relação à\ndislalia, assinale a alternativa correta.", "alt": {"A": "A dislalia é uma alteração na escrita normalmente\nligada a problemas perceptivo-motores.", "B": "A dislalia caracteriza-se por troca, acréscimo ou\nomissão de fonemas na fala.", "C": "A dislalia é um distúrbio neurológico que afeta a\nhabilidade com números.", "D": "A dislalia caracteriza-se pela falta de concentração e\npela desatenção da criança.", "E": "A dislalia abrange, principalmente, a leitura e a\ninterpretação de enunciados e textos."}, "g": "B", "j": "A dislalia e distincao fonologica caracterizada por troca, acrescimo ou omissao de fonemas na fala. A descreve disgrafia, C discalculia, D desatencao, E dislexia."}, {"id": "2159869", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca da teoria da psicogênese da língua escrita e suas\nhipóteses, julgue os itens a seguir.\n    I. Segundo Emília Ferreiro, a alfabetização precisa ser\nsignificativa e contextualizada.    \nII. No nível pré-silábico, em um primeiro momento, o\naprendiz pensa que pode escrever com desenhos,\nrabiscos, letras ou outros sinais gráficos, imaginando\nque a palavra assim inscrita representa a coisa a que se\nrefere.    \nIII. A criança, antes do período de alfabetização escolar,\nnão possui nenhuma hipótese sobre o código escrito.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos"}, "g": "D", "j": "I (alfabetizacao significativa e contextualizada, Ferreiro) e II (nivel pre-silabico com desenhos/rabiscos representando a coisa) estao corretos. III esta errado: a crianca POSSUI hipoteses sobre o codigo escrito antes da alfabetizacao formal. Apenas I e II = D."}, {"id": "2159866", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas", "Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a contribuição da psicanálise para a Psicopedagogia,\njulgue os itens a seguir.\n    I. O objetivo na abordagem psicanalítica é investigar a\nforma como o sujeito pensa e resolve determinadas\nsituações, por meio das provas operatórias.\n    II. Para a psicanálise, considera-se que os jogos infantis\nreproduzem situações psíquicas estruturantes na\nconstituição do eu.    \nIII. A psicanálise permite a compreensão do sintoma\nenquanto problema de aprendizagem, percebendo-o\ncomo uma manifestação humana carregada de\nsignificado.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas o item III está certo.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I esta errado: provas operatorias sao da abordagem piagetiana, nao psicanalitica. II (jogos infantis reproduzem situacoes psiquicas estruturantes) e III (psicanalise compreende o sintoma como manifestacao com significado) sao corretos. Apenas II e III = B."}, {"id": "2159865", "d": "psicologia", "a": ["Psicanálise", "Freud", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2022", "org": "CFP", "t": "", "e": "Dentre as fases do desenvolvimento psicossexual de Freud,\numa se caracteriza por uma vivência em grande parte\nautoerótica, ou seja, o prazer é encontrado no próprio\ncorpo. A exploração dos objetos é, muitas vezes, marcada\npela voracidade típica da ausência de simbolização do\nobjeto. A fase assim caracterizada denomina-se:", "alt": {"A": "fase oral.", "B": "fase anal.", "C": "fase fálica.", "D": "período de latência.", "E": "fase genital."}, "g": "A", "j": "A fase oral em Freud caracteriza-se por vivencia autoerotica (prazer no proprio corpo), exploracao oral dos objetos e voracidade, com ausencia de simbolizacao do objeto."}, {"id": "2159864", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "O campo de atuação do psicopedagogo vai além do espaço\nfísico em que se dá esse trabalho, tal como clínica e escola.\nTambém se configura como um trabalho preventivo (Bossa,\n2011, p. 47). Assinale a alternativa incorreta sobre o campo\nde atuação da Psicopedagogia.", "alt": {"A": "O trabalho psicopedagógico é preventivo na medida\nem que favorece a apropriação do conhecimento pelo\nser humano.", "B": "O trabalho psicopedagógico deve detectar possíveis\nperturbações no processo de aprendizagem.", "C": "O trabalho psicopedagógico deve ser realizado sempre\nindividualmente, visando as especificidades do sujeito\nem desenvolvimento.", "D": "As empresas possuem campo de atuação para\npsicopedagogos, pois nelas ocorrem processos de\naprendizagens.", "E": "Cabe ao psicopedagogo participar da dinâmica das\nrelações da comunidade educativa, a fim de favorecer\nprocessos de integração e troca."}, "g": "C", "j": "C esta incorreta: o trabalho psicopedagogico NAO precisa ser realizado sempre individualmente; pode ser feito tambem em grupos. Demais alternativas descrevem caracteristicas validas do campo (preventivo, detectar perturbacoes, atuacao em empresas, participacao na comunidade educativa)."}, {"id": "2159862", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que não caracteriza a atuação do\npsicopedagogo no Brasil.", "alt": {"A": "Oferece assessoria psicopedagógica aos trabalhos\nrealizados em espaços institucionais", "B": "Realiza diagnóstico e intervenção psicolológica,\nutilizando métodos, testes, instrumentos e técnicas da\nPsicopedagogia.", "C": "Desenvolve pesquisas e estudos científicos\nrelacionados ao processo de aprendizagem.", "D": "Oferece oficinas psicopedagógicas, que podem ser\norganizadas em hospitais com internos, possibilitando\no lúdico e a aprendizagem.", "E": "Deve ampliar, nas empresas, formas de treinamento\nde pessoal, resgatando as múltiplas inteligências."}, "g": "B", "j": "B nao caracteriza a atuacao do psicopedagogo: ele realiza diagnostico e intervencao PSICOPEDAGOGICA, nao psicologica. Demais alternativas descrevem atuacoes validas (assessoria institucional, pesquisa, oficinas em hospitais, treinamento em empresas)."}, {"id": "2159861", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre as teorias que embasam o trabalho psicopedagógico,\nassinale a alternativa correta.", "alt": {"A": "A Pedagogia e a Psicologia são suficientes para\napreender o objeto de estudo da Psicopedagogia e\nnortear sua prática.", "B": "A Epistemologia e a Psicologia Genética encarregam-se\ndo mundo inconsciente, da dinâmica psíquica que se\nexpressa por sintomas e símbolos.", "C": "A Neuropsicologia possibilita compreender a\nconstituição dos sujeitos e as condições socioculturais\nque contextuam toda aprendizagem.", "D": "A Pedagogia contribui com a compreensão dos\nmecanismos cerebrais, do ponto de vista orgânico.", "E": "A Linguística traz a compreensão da língua enquanto\ncódigo disponível a todos os membros de uma\nsociedade, e a fala como fenômeno subjetivo,\nevolutivo e historiado."}, "g": "E", "j": "E descreve corretamente a contribuicao da Linguistica: lingua como codigo social e fala como fenomeno subjetivo e historico. As demais alternativas atribuem funcoes incorretas a Pedagogia, Epistemologia/Psicologia Genetica e Neuropsicologia."}, {"id": "2159860", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com o código de ética do psicopedagogo,\nassinale a alternativa que não constitui infração ética.", "alt": {"A": "Utilizar títulos acadêmicos e/ou de especialista que não\npossua.", "B": "Fazer falsas declarações sobre quaisquer situações da\nprática psicopedagógica.", "C": "Submeter-se à supervisão psicopedagógica e ao\nprocesso terapêutico pessoal.", "D": "Encaminhar ou desviar, por qualquer meio, cliente para\nsi.", "E": "Assinar qualquer procedimento psicopedagógico\nrealizado por terceiros ou solicitar que outros\nprofissionais assinem seus procedimentos."}, "g": "C", "j": "C nao constitui infracao etica: submeter-se a supervisao e ao processo terapeutico pessoal e conduta etica recomendada. Demais alternativas (titulos falsos, falsas declaracoes, desviar clientes, assinar trabalho de terceiros) sao infracoes."}, {"id": "2159829", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas", "Psicologia Social", "Papéis Sociais e Relações de Gênero", "Psicologia e Cultura"], "ano": "2022", "org": "CFP", "t": "", "e": "Foi uma pioneira da psicologia no Brasil, professora da USP,\nsocióloga e a primeira mulher psicanalista no país e\npioneira nos estudos das relações raciais na psicologia:", "alt": {"A": "Ecléa Bosi.", "B": "Virgínia Leone Bicudo.", "C": "Ana M Bahia Bock.", "D": "Carolina Martuscelli Bori.", "E": "Noemy Rudolfer."}, "g": "B", "j": "Virginia Leone Bicudo foi pioneira da psicologia no Brasil, professora da USP, primeira mulher psicanalista do pais e referencia nos estudos das relacoes raciais na psicologia."}, {"id": "2159828", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Foi uma referência para o ensino da psicologia social e\nbibliografia constante nos anos 1970 e 1980 nas disciplinas\nde graduação da psicologia social:", "alt": {"A": "Ana M Bahia Bock.", "B": "Arthur Ramos.", "C": "Helmuth Krüger.", "D": "Aroldo Rodrigues.", "E": "Virgínia Leone Bicudo."}, "g": "D", "j": "Aroldo Rodrigues foi referencia central no ensino de psicologia social no Brasil dos anos 1970-1980, autor de obra classica usada em disciplinas de graduacao."}, {"id": "2159827", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Políticas Públicas no ECA", "Políticas Públicas no SUAS", "Psicologia Jurídica", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Em um abrigo para acolhimento da população trans em\nsituação de rua, a equipe técnica constrói um combinado\ndos pontos que devem orientar o cuidado com essa\npopulação. Qual princípio não deve orientar a atuação do\npsicólogo?", "alt": {"A": "Reconhecer que tal população é atravessada por\nmúltiplas violências, que estas estão relacionadas ao\nmodo de produção social.", "B": "Priorizar ações de articulação de redes intersetoriais\nque busquem a produção de um cuidado integral que\nconsidere as múltiplas dimensões da produção\ncotidiana da vida.", "C": "Reconhecer o protagonismo da pessoa na construção\ndo seu processo de cuidado, sendo este partilhado\ntodo o tempo.", "D": "Reconhecer que tal identidade de gênero é\nconsequência de sofrimentos infantis e que é\nfundamental oferecer um atendimento terapêutico\nque ajude a superar esses traumas e, assim, reverter a\nsituação.", "E": "Reconhecer e apoiar movimentos coletivos de combate\nao preconceito e à violência de tal população,\nfortalecendo a rede territorial de proteção e defesa de\ndireitos."}, "g": "D", "j": "D NAO deve orientar a atuacao: a identidade de gênero NAO e consequencia de sofrimentos infantis nem deve ser 'revertida'. Tal abordagem patologizante contraria posicoes do CFP. Demais alternativas reconhecem violencias, articulam redes, respeitam protagonismo e apoiam movimentos."}, {"id": "2159826", "d": "psicologia", "a": ["Intervenção Psicossocial", "Políticas Públicas no SUAS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Um psicólogo contratado para trabalhar junto à população\nem situação de rua deve considerar qual perspectiva como\nprioritária?", "alt": {"A": "A importância de avaliações psicológicas usando\nprotocolos definidos para mensurar o tipo de\nsofrimento psíquico que acomete cada sujeito.", "B": "Oferecimento de atendimentos terapêuticos\nindividuais, visando trabalhar as motivações\npsicológicas que levaram à escolha de morar na rua.", "C": "Reconhecimento da produção múltipla da situação\nvivida e articulação de uma rede de cuidados que\nintegre várias políticas públicas.", "D": "Articulação com a polícia local para ter suporte de\nproteção frente aos riscos que envolvem o\natendimento a essa população.", "E": "Apoio à construção de um protocolo de cuidado que\nproíba o uso de álcool e outras drogas na rua, visando\nà proteção das pessoas."}, "g": "C", "j": "C alinha-se ao paradigma psicossocial e intersetorial do SUAS: reconhecimento da producao multipla da situacao e articulacao de rede de cuidados integrando varias politicas publicas. As demais individualizam, patologizam ou recorrem a policia/proibicoes."}, {"id": "2159822", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "No livro As raízes da psicologia social moderna, Robert M.\nFarr diz:\n    “O modelo de exportação de psicologia social dos EUA,\ndurante o período moderno, foi a forma dominante de\npsicologia social psicológica. Os americanos, após a guerra,\ndesempenharam um papel central na reconstrução das\nuniversidades, tanto na Alemanha como no Japão. A\npsicologia social que eles ajudaram a estabelecer ali foi uma\nforma psicológica, e não sociológica, da disciplina. Os\namericanos desempenharam também um papel importante\nna Europa, ao ajudar a constituir o que é hoje a Associação\nEuropeia de Psicólogos Sociais Experimentais.”\n      Assinale a alternativa correta.", "alt": {"A": "Robert M. Farr está falando da influência que a\npsicologia social psicológica exerceu na própria origem\nda psicologia.", "B": "A reconstrução das universidades na Alemanha e no\nJapão foi uma estratégia geopolítica de dominação dos\nEUA que foi apoiada pela psicologia social americana.", "C": "Os psicólogos sociais americanos, apoiados pelo grupo\nda Gestalt que imigrou para os EUA durante a II Guerra\nMundial, produziram uma revolução na psicologia\nsocial e tiveram forte influência na Europa após a\nguerra.", "D": "A psicologia social americana é somente um modelo de\nexportação e, internamente, prevalece a psicologia\nsocial sociológica.", "E": "A psicologia social moderna se inicia com a revolução\nproduzida pelos americanos, de caráter cognitivista e\ncompletamente ligada à corrente das ciências\ncognitivas inaugurada por Charles Sanders Peirce."}, "g": "C", "j": "C captura a tese de Farr: a psicologia social americana, apoiada por gestaltistas que imigraram para os EUA durante a II Guerra, produziu uma revolucao na disciplina e influenciou fortemente a Europa pos-guerra. Demais alternativas distorcem ou simplificam."}, {"id": "2159820", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2022", "org": "CFP", "t": "", "e": "“Na análise psicológica, essa lógica dialética inverte a ideia\nde inclusão social, desatrelando-a da noção de adaptação e\nnormatização, bem como de culpabilização individual, para\nligá-la aos mecanismos psicológicos de coação.”\n      Esse texto, de Bader B. Sawaia, refere-se ao conceito de:", "alt": {"A": "exclusão permanente.", "B": "sofrimento ético-político.", "C": "dimensões subjetivas da realidade.", "D": "representações sociais.", "E": "desenvolvimento desigual e combinado."}, "g": "B", "j": "O conceito de sofrimento etico-politico e formulacao classica de Bader Sawaia que desatrela a inclusao social de adaptacao/normatizacao e culpabilizacao individual, vinculando-a a mecanismos psicologicos de coacao na desigualdade."}, {"id": "2159819", "d": "psicologia", "a": ["Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "Durante os anos de 1980, muito se discutiu sobre formas de\natuação comunitária e se destacava a questão do método\nde pesquisa e intervenção. A questão central era o\nquestionamento aos conceitos de distanciamento do objeto\nde pesquisa de cunho positivista, e dois autores\nimportantes, Carlos Rodrigues Brandão e Michel Thiollent,\ndelinearam caminhos para uma pesquisa social\ncomprometida com a realidade. Fala-se, respectivamente,\ndas pesquisas:", "alt": {"A": "etnográfica e psicossocial.", "B": "fatorial e censitária.", "C": "qualitativa e quantitativa.", "D": "psicossocial e institucional.", "E": "participante e pesquisa-ação."}, "g": "E", "j": "Carlos Rodrigues Brandao e referencia da pesquisa PARTICIPANTE e Michel Thiollent da PESQUISA-ACAO, ambas metodologias engajadas e criticas ao distanciamento positivista."}, {"id": "2159818", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Qual das seguintes atuações não se insere na prática\nprofissional do psicólogo social?", "alt": {"A": "Coordenação de projetos.", "B": "Ensino universitário.", "C": "Avaliação de alunos da rede de ensino.", "D": "Atuação em CRAS.", "E": "Acompanhamento de projetos de Economia Solidária."}, "g": "C", "j": "C nao se insere na pratica do psicologo social: avaliacao de alunos e tarefa do psicologo escolar/educacional. Coordenacao de projetos, ensino universitario, atuacao em CRAS e acompanhamento de Economia Solidaria sao atuacoes tipicas."}, {"id": "2159817", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "A atuação do(a) psicólogo(a) social pode ser no sentido de\nefetuar avaliações psicossociais para identificar as\ndificuldades existentes no processo de discussão de grupos\ncomunitários. Considerando tal afirmativa, assinale a\nalternativa incorreta.", "alt": {"A": "A definição de um diagnóstico da situação vivida pelo\ngrupo depende da rigorosa escolha do teste psicológico\na ser aplicado.", "B": "A atuação deve levar em consideração a empatia com\no grupo atendido.", "C": "Quando o(a) psicólogo(a) social encontrar resistência\ndo grupo, poderá buscar superá-la por meio de\ndinâmicas grupais apropriadas para a situação.", "D": "É adequado ficar atento para a ocorrência de\ntransversalidades que possam ajudar a superar suas\nresistências aos objetivos propostos pelo coletivo.", "E": "As resistências podem se remeter a histórias ocultas\ndos grupos, e o(a) psicólogo(a) social deve estar atento\npara o não dito do grupo."}, "g": "A", "j": "A esta incorreta: o diagnostico psicossocial NAO depende da escolha de teste psicologico; baseia-se em escuta, observacao, dinamicas e analise das relacoes do grupo. Demais alternativas descrevem condutas adequadas."}, {"id": "2159815", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "“O desenvolvimento da psicologia social no Brasil, como\ncampo científico diferenciado, esteve e continua permeado\npor influências intelectuais vindas do estrangeiro. Na\nmedida em que o campo obteve maior institucionalização,\nos conflitos internos, que refletiam tanto influências\nteóricas como visões diferentes do papel da psicologia e do\npsicólogo na sociedade, foram gerando conflitos no interior\ndos departamentos de psicologia sobre a orientação a ser\ndada à disciplina. Alguns permitiram a convivência, outros\nlevaram à separação.”\n  JACÓ-VILELA, A. M.; DEGANI-CARNEIRO, F.; OLIVEIRA, D. M. (2016).\n      Quanto à formação da psicologia social como campo\ncientífico no Brasil, as autoras apontam que:", "alt": {"A": "a psicologia social no Brasil depende exclusivamente\ndo conhecimento produzido fora do país.", "B": "os departamentos de psicologia das universidades\nbrasileiras não se interessam em desenvolver uma\npsicologia social que busque compreender a realidade\nbrasileira.", "C": "a psicologia social é um conhecimento universal e\nindepende do país em que seu conhecimento é\ndesenvolvido", "D": "a crítica produzida após a década de 1970 incentivou a\nbusca de novos paradigmas teóricos e, até o momento,\nnão se construiu um paradigma único para a psicologia\nsocial no Brasil.", "E": "a crise da psicologia social no Brasil provocou a divisão\ndos departamentos de psicologia nas nossas\nuniversidades."}, "g": "D", "j": "D resume a tese de Jaco-Vilela e colegas: a critica pos-1970 incentivou novos paradigmas teoricos sem que se construisse um paradigma unico para a psicologia social no Brasil - convivem multiplas vertentes."}, {"id": "2159814", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto à atuação do(a) psicólogo(a) social, assinale a\nalternativa correta.", "alt": {"A": "A atuação profissional pode se dar no atendimento de\npopulação em situação de risco em várias\ncircunstâncias tanto para grupos mais pobres quanto\npara grupos melhor situados economicamente.", "B": "A psicologia social se interessa somente pelo segmento\nmais pobre da população, e sua base teórica não serve\npara trabalhar com uma população mais privilegiada\neconomicamente.", "C": "A psicologia social não exerce intervenção social.", "D": "Eticamente, o(a) profissional não deve atuar em\nsituação de desastres como os ocorridos em Mariana\n(MG) e Brumadinho (MG), por não estar preparado(a)\npara essa ação.", "E": "A psicologia social é extremamente teórica e não\npermite uma atuação mais concreta no seu campo da\nação."}, "g": "A", "j": "A esta correta: a atuacao do psicologo social abrange populacoes em situacao de risco em diversos contextos economicos, nao se restringe a grupos pobres nem se limita ao plano teorico."}, {"id": "2159813", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Atuando em uma comunidade ribeirinha, uma psicóloga\nsocial apresentou algumas alternativas para a organização\nda população local. Qual orientação não se aplica a tal\nsituação?", "alt": {"A": "Programar reuniões com a população para que as\ntomadas de decisão sejam coletivas e do interesse do\ngrupo.", "B": "Identificar a pesca como atividade principal dos\nmoradores da comunidade e buscar instruí-los sobre a\npossibilidade de constituição de uma cooperativa.", "C": "Procurar trabalhar a resistência ao enfrentamento dos\ngrupos com interesse econômico na área, buscando\norientação sobre a posse da terra e sobre a\nancestralidade dessa posse.", "D": "Estabelecer um plano de empreendedorismo,\nconsiderando a possibilidade de criar startups na\nregião.", "E": "Procurar reunir o conhecimento baseado na memória\ndo coletivo, como forma de garantir uma política\nidentitária daquela população."}, "g": "D", "j": "D nao se aplica a comunidade ribeirinha: criar startups e proposta descontextualizada que nao dialoga com modos de vida tradicionais. As demais (reunioes coletivas, cooperativa de pesca, posse da terra, memoria coletiva) sao orientacoes condizentes."}, {"id": "2159811", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "A psicologia da libertação é uma corrente importante da\npsicologia social latino-americana. Sobre ela, julgue os itens\na seguir.    \nI. A psicologia da libertação tem esse nome por defender\na libertação de presos políticos na América Latina.    \nII. Essa corrente tem como um de seus principais nomes o\npsicólogo espanhol, radicado em El Salvador, o jesuíta\nIgnacio Martín-Baró, que foi assassinado em 1989 por\nforças paramilitares dentro da universidade em que era\nvice-reitor.    \nIII. Ignácio Martín-Baró deixou um enorme legado para a\nPsicologia Social latino-americana e mundial e uma de\nsuas obras mais referenciadas é Sistema, Grupo y\nPoder: Psicología social desde Centroamérica.\n        Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas o item III está certo.", "E": "Apenas os itens II e III estão certos."}, "g": "E", "j": "I esta errado: 'libertacao' refere-se a libertacao das opressoes coloniais/sociais, nao especificamente de presos politicos. II (Martin-Baro, jesuita espanhol, assassinado em El Salvador em 1989) e III ('Sistema, Grupo y Poder' como obra central) sao corretos. Apenas II e III = E."}, {"id": "2159810", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Um campo de atuação da Psicologia Social, de modo amplo,\né sobre e nos meios de comunicação de massa. O acesso\nirrestrito à internet e a popularização dos smartphones\ndemocratizaram o acesso; em contrapartida, a mediação da\ncomunicação passou a ser controlada por grandes\nconglomerados que dominam a comunicação e que\nconhecemos como redes sociais e que se transformam nos\nprincipais meios de acesso, superando a transmissão\ntelevisiva. Com isso, a população fica exposta a todo tipo de\nmensagem, inclusive as chamadas fake news. Qual seria o\npapel da Psicologia Social frente a esse fenômeno?", "alt": {"A": "A Psicologia Social, por estudar pouco as mídias sociais,\nnão acumula conhecimento suficiente para enfrentar\nesse problema.", "B": "Considerando a capacidade interpretativa da Psicologia\nSocial e sua diversidade, podemos dizer que ela própria\né uma divulgadora de fake news.", "C": "A Psicologia Social é uma importante referência para o\nestudo das comunicações de massa e uma ferramenta\nimportante para analisar as mudanças na subjetividade\nocasionada pelo atual e intenso fluxo de informação e\npara combater as fake news.", "D": "Comunicação é um conceito clássico da Psicologia\nSocial, mas não a comunicação de massa. Sua principal\npreocupação é com a comunicação interpessoal, como\nbem define Fritz Heider.", "E": "O papel da Psicologia Social é o de superar as\ncontradições produzidas pela mídia."}, "g": "C", "j": "C esta correta: a Psicologia Social e referencia para o estudo das comunicacoes de massa e ferramenta para analisar mudancas na subjetividade e combater fake news. Demais alternativas minimizam ou distorcem seu papel."}, {"id": "2159809", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a Psicologia Social, jugue os itens a seguir.\n    I. A Psicologia Social enfrentou uma profunda crise na\ndécada de 1970, o que resultou na construção de\nvertentes críticas, dentre as quais o Construcionismo\nSocial, de Kenneth J. Gergen.    \nII. A Psicossociologia é uma corrente de origem francesa,\nque surge no pós-guerra e que visa atuar nos processos\nsociais a partir da pesquisa-ação com base no\nmarxismo e na psicanálise.    \nIII. A Psicologia Social no Brasil teve um grande impulso\ncom a publicação, em 1984, do livro Psicologia Social: o\nhomem em movimento, organizado por Silvia T. M.\nLANE e Wardeley CODO.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (crise dos anos 1970 e Construcionismo de Gergen), II (Psicossociologia francesa pos-guerra, pesquisa-acao, marxismo e psicanalise) e III (livro de Lane e Codo, 1984) sao todos corretos. Todos os itens = E."}, {"id": "2159807", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "A pandemia que vivemos no mundo todo e que atingiu\nfortemente o Brasil produziu muitos outros efeitos, além\ndos diretamente ligados à saúde das pessoas. O isolamento\nforçado para evitar o contágio, principal medida sanitária\nde proteção à população, teve efeitos drásticos. Entre eles,\na situação da população pobre das grandes cidades, cujo\nisolamento era de muita precariedade (local de moradia\npequeno, pouco espaço entres as casas, acesso precário à\ninternet), além do imperativo de precisar gerar alguma\nrenda para não morrer de fome. Uma grande parte da\npopulação pobre, com trabalhos precários, se manteve em\natividade para garantir o isolamento do segmento da\npopulação mais privilegiada, como os entregadores de\nprodutos comprados por meio dos aplicativos. Assinale a\nalternativa correta.", "alt": {"A": "A Psicologia Social não está apropriada para discutir\ntemas de saúde pública como o processo pandêmico\nque estamos vivendo.", "B": "A economia do país é a prioridade, e manter seu\nfuncionamento é central, mesmo que isso afete a\npopulação mais pobre.", "C": "Psicólogos sociais devem procurar orientar a população\nmais pobre sobre a importância de ficar em casa acima\nde qualquer circunstância.", "D": "A população pobre tem o mesmo direito à segurança\nsanitária que qualquer outro cidadão, e o Estado deve\ngarantir sua proteção por meio de programas de renda\ne de distribuição de alimentos, acesso ao cuidado em\nsaúde e ampla vacinação.", "E": "O trabalho de entrega é uma boa oportunidade de\nocupação e geração de renda e a proteção do cidadão\nque tem poder aquisitivo deve ser garantida a qualquer\ncusto por ele garantir o funcionamento da economia."}, "g": "D", "j": "D alinha-se aos principios de cidadania e protecao social: a populacao pobre tem o mesmo direito a seguranca sanitaria, e cabe ao Estado garantir protecao via renda, alimentos, cuidado em saude e vacinacao. Demais alternativas reduzem ou negam direitos."}, {"id": "2159805", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Uma psicóloga, especialista em Psicologia Social, orienta\num grupo de mulheres que se organizem em uma\ncooperativa popular de economia solidária e produzam e\nbordem panos de prato para vender. Pela baixa\nprodutividade e pelas poucas vendas, o grupo não se\nviabiliza financeiramente e discutem a proposta da\npsicóloga de encerrar aquela atividade. Entretanto, uma\ndas mulheres participantes do projeto argumenta que, mais\nque geração de renda, o grupo de mulheres é um lugar de\ntroca de afetos e conhecimento entre elas e se questiona,\nse o projeto terminar, onde iriam poder conversar tão\nlivremente sobre educação dos filhos, problemas conjugais,\nquestões femininas e outras de seu interesse. Qual deveria\nser a proposta da psicóloga que orienta o grupo?", "alt": {"A": "Independentemente da importância da circulação dos\nafetos nos coletivos, o que importa num projeto de\neconomia solidária é exclusivamente a geração de\nrenda.", "B": "O grupo deveria manter sua atividade e ser\nencaminhado para um serviço ou uma entidade\nespecializada em discussão da condição feminina.", "C": "A psicóloga não deveria estar no grupo – não se trata\nde atividade prevista na sua especialização.", "D": "A psicóloga deveria compreender a demanda e\ntransformar o objetivo do grupo de geração de renda\nem um grupo terapêutico.", "E": "Grupos de geração de renda na economia solidária são,\nantes de tudo, grupos humanos, e uma atividade de\ngeração de renda é compatível com a conversa sobre a\ncirculação de afeto no grupo."}, "g": "E", "j": "E captura a perspectiva integral da economia solidaria: grupos de geracao de renda sao antes de tudo grupos humanos, e a circulacao de afetos e parte legitima da experiencia coletiva. Demais alternativas reducionistas (so renda, encaminhar, terapeutizar)."}, {"id": "2159804", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando a atuação do(a) psicólogo(a) comunitário(a),\njulgue os itens a seguir.    \nI. O(A) psicólogo(a) comunitário(a) deve atuar de forma a\npromover a autonomia das comunidades em que atua,\nbuscando a melhor qualidade de vida da população.\n    II. Havendo necessidade ou demanda, o(a) psicólogo(a)\ncomunitário(a) deve efetuar atendimento\npsicoterapêutico com a população da região em que\natua.\n    III. Desastres ambientais como os ocorridos em Mariana\n(MG) e Brumadinho (MG) exigem presença dos(as)\npsicólogos(as) comunitários(as) para o trabalho com a\npopulação sobrevivente e desabrigada.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I (promover autonomia e qualidade de vida) e III (presenca em desastres como Mariana e Brumadinho) sao corretos. II esta errado: o psicologo comunitario NAO realiza atendimento psicoterapeutico individual com a populacao - encaminha para servicos especializados. Apenas I e III = C."}, {"id": "2159803", "d": "psicologia", "a": ["Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Psicologia Jurídica"], "ano": "2022", "org": "CFP", "t": "", "e": "“A temática da violência contra as mulheres foi incorporada\ncomo questão da Psicologia Social. Buscava-se\ncompreendê-la desde a perspectiva psicossocial,\nentendida como uma escolha teórico-metodológica capaz\nde produzir o rompimento das dicotomias: ‘social’ versus\n‘individual’, ‘objetivo’ versus ‘subjetivo’. O fenômeno da\nviolência contra a mulher revelava uma cultura da\nviolência, produzida e compartilhada socialmente,\nentranhada de tal modo no cotidiano das relações entre\nhomens e mulheres que era tomada como natural.”\n    MOREIRA, Maria Ignez Costa. Uma colcha de retalhos: legado feminista\npara a Psicologia Social. In RENA, L. C. et al. (Orgs.). A política no cotidiano:\ncontribuições teóricas e práticas da psicologia social. Porto Alegre:\nABRAPSO, 2016. p. 183.\n      O texto aponta que:", "alt": {"A": "a violência de gênero é natural entre homens e\nmulheres.", "B": "a psicologia social passa a pautar a discussão de gênero\npor exigência acadêmica baseada em bases teórico-metodológicas.", "C": "a cultura da violência está entranhada no cotidiano das\nrelações de gênero e sua superação é dificultada pela\nnaturalização.", "D": "uma colcha de retalhos está se referindo ao trabalho\nfeminino como alternativa à violência masculina.", "E": "dicotomias são inevitáveis quando se trata do\nfenômeno da violência de gênero, naturalizada pela\ncultura."}, "g": "C", "j": "C captura a tese central de Maria Ignez Costa Moreira: a cultura da violencia esta entranhada no cotidiano das relacoes de genero e sua naturalizacao dificulta a superacao. Demais alternativas naturalizam ou distorcem."}, {"id": "2159801", "d": "psicologia", "a": ["Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "As questões raciais estão cada vez mais presentes na\natuação dos psicólogos sociais. Se pensarmos que a maioria\ndo povo brasileiro é composta de negros, considerando a\nsoma de pessoas pretas e pardas que vivem no país,\ndevemos:", "alt": {"A": "ajudar a promover a ideia de que o racismo não faz\nparte da índole cordial dos brasileiros.", "B": "incentivar que os temas de defesa da cultura\nafrodescendente e da história dos povos africanos\nestejam presentes na formação das psicólogas e dos\npsicólogos brasileiros.", "C": "considerar que questões raciais são muito importantes,\nmas não fazem parte da realidade da ação da\nPsicologia.", "D": "apoiar os movimentos negros como alternativa viável\npara a construção da democracia racial.", "E": "atribuir a uma política de cotas eficiente a solução para\ntodos os problemas raciais que enfrentamos em nosso\npaís."}, "g": "B", "j": "B alinha-se as Resolucoes do CFP sobre relacoes raciais: incentivar temas de cultura afrodescendente e historia dos povos africanos na formacao dos psicologos brasileiros. Demais alternativas negam, reduzem ou simplificam."}, {"id": "2159800", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde Coletiva"], "ano": "2022", "org": "CFP", "t": "", "e": "Uma psicóloga, especialista em psicologia social, foi\ncontratada como gestora de um CRAS numa zona periférica\nde uma grande cidade com forte demanda social. Sua\norientação inicial foi para que as assistentes sociais\ncuidassem do cadastro do Bolsa Família e as psicólogas\nformassem grupos terapêuticos com a mães chefes de\nfamília na região. Essa orientação está:", "alt": {"A": "em consonância com o que prediz o SUAS sobre a\nequipe de um CRAS.", "B": "em contradição com o fato de psicólogas sociais não\npoderem ser gestoras de um CRAS.", "C": "inadequada, considerando-se que mães que são chefes\nde família não têm tempo para participar de grupos\nterapêuticos.", "D": "em desacordo com a orientação que preconiza que o\natendimento psicoterapêutico deve ser realizado nas\nUnidades Básicas de Saúde e o CRAS deve, quando\nnecessário, fazer o encaminhamento.", "E": "correta, considerando-se que o CRAS pode ser a única\nalternativa de atendimento na região e deve estar\npronto para toda demanda que se apresentar."}, "g": "D", "j": "D esta correta: o atendimento psicoterapeutico nao e tarefa do CRAS (SUAS), mas das UBS (SUS); o CRAS faz acolhimento, orientacao e encaminhamento. A orientacao da gestora confunde papeis dos sistemas."}, {"id": "2159769", "d": "psicologia", "a": ["Psicologia do Trabalho", "Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Bastos e Gondim (2010), a inserção de equipes como unidades de desempenho no cenário das organizações é uma\nprática bastante difundida na época atual. Em consequência, é cada vez maior a quantidade de estudos publicados a respeito de\ncaracterísticas, funcionamento e possíveis resultados do trabalho de equipes de forma geral. Entretanto, atualmente, inexiste\ninformação específica sobre a atuação do psicólogo sob essa condição de trabalho – razão pela qual se devem analisar tais\nsistemas de modo mais descritivo. Sobre os elementos constitutivos de uma equipe de trabalho, julgue os itens a seguir.    \nI. Células de trabalho das mais diversas naturezas recebem erroneamente a denominação de “equipe” sem necessariamente\napresentarem as características que permitem a adequada identificação. Podem ser denominados de “equipes de trabalho”\nsomente as reuniões de pessoas que constituem sistemas dinâmicos e interativos de atos protagonizados por conjuntos de\ntrabalhadores com habilidades complementares cujas ações laborais são norteadas por metas de trabalho comuns,\ntornando-os, dessa forma, mutuamente responsáveis pelo alcance de objetivos.    \nII. As equipes de trabalho são primordialmente concebidas com a finalidade de promover efetividade da organização. Dessa\nforma, define-se o desempenho efetivo das equipes de trabalho como o grau em que os resultados do desempenho das\nunidades se aproximam das metas especificadas. A efetividade da organização, por sua vez, é compreendida como um\npadrão externo de referência que indica quão bem a organização atende as demandas dos grupos que dela participam.\n    III. Sendo efetivas em seu desempenho, a fim de contribuírem para a consecução das metas organizacionais, não restam\ndúvidas sobre os critérios para mensurar tal efetividade de equipes de trabalho. Tal efetividade deve ser considerada a\npartir de indicadores sólidos baseados em critérios de rendimento, tais como peças produzidas com qualidade, redução de\ndesperdício etc. Parâmetros não consistentes, tais como resultados afetivos positivos e satisfação – apesar de benéficos –\nnão deveriam se constituir em aspectos adicionados aos indicadores de efetividade.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (definicao rigorosa de equipe: sistema dinamico, habilidades complementares, metas comuns, responsabilidade mutua) e II (efetividade como criterio organizacional alinhado a demandas externas) sao corretos. III esta errado pois descarta resultados afetivos como indicadores validos, contrariando literatura atual. Apenas I e II = B."}, {"id": "2159768", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Bittencourt (2004), aprendizagem organizacional\npode ser considerada uma resposta alternativa às\nmudanças enfrentadas pelas empresas, em que se busca\ndesenvolver a capacidade de aprender continuamente a\npartir das experiências organizacionais e a traduzir esses\nconhecimentos em práticas que contribuam para um\nmelhor desempenho, tornando a empresa mais\ncompetitiva. Julgue os itens apresentados pela autora sobre\naprendizagem organizacional.    \nI. A aprendizagem organizacional tem como pressuposto\nbásico o desenvolvimento de estratégias e\nprocedimentos a serem construídos continuamente\npara se atingirem melhores resultados, contando com\na participação efetiva das pessoas no processo de\naquisição e disseminação de conhecimento, fato esse\nque se relaciona diretamente com a questão do\ndesenvolvimento de habilidades e atitudes humanas.\n    II. Apesar de a literatura sobre aprendizagem\norganizacional ser vasta e crescente, existe ainda muita\ndiscordância em relação ao que é e como ocorre\nexatamente esse fenômeno, havendo concordância\napenas quanto à ideia de esse processo representar\numa modificação relativamente permanente na\ndisposição ou na capacidade do homem, ocorrida\ncomo resultado de sua atividade, que não pode ser\nsimplesmente atribuída ao processo de crescimento e\nmaturação ou a outras causas como doença, mutações\ngenéticas etc.\n    III. A aprendizagem organizacional traz uma proposta em\ntermos de mudança, ou seja, ênfase no processo em\ndetrimento do produto. Assim, não é concebível a ideia\nde programas ou modelos preconcebidos desprovidos\nde contextualização, respeitando a individualidade e a\nrealidade de cada organização.      \nAssinale alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (desenvolvimento de estrategias e procedimentos continuos, participacao efetiva), II (concordancia apenas sobre modificacao permanente como definicao classica de aprendizagem) e III (enfase no processo, sem programas preconcebidos descontextualizados) sao corretos. Todos = D."}, {"id": "2159767", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicopatologia do Trabalho", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Conforme Borges e Mourão (2013), há um interesse\ncrescente pela criação de ferramentas metodológicas para\navaliar eficiência (meios adequados para se se chegar a\nfins), eficácia (alcance dos fins pretendidos) e efetividade\nou impacto (resultados para a população beneficiária) de\nplanos, programas e projetos nos diversos âmbitos das\nações sociais e organizacionais. A respeito da avaliação de\nprogramas e projetos por parte do psicólogo organizacional\ne do trabalho, assinale a alternativa incorreta.", "alt": {"A": "Geralmente os profissionais de gestão de pessoas estão\ndevidamente familiarizados com ferramentas de\nplanejamento de programas e projetos e conhecem\nprofundamente a metodologia do marco lógico (ou matriz\nde planejamento de estrutura lógica) de projetos, visto\nque o uso de ferramentas metodológicas de pesquisa foi\nensinado em sua graduação.", "B": "O psicólogo organizacional e do trabalho que atua no\nsetor público possui formação em gestão ou tem\nexperiência na formulação de propostas para\nprestação de serviços no terceiro setor e transita com\nmais facilidade nesse repertório conceitual sobre\navaliação de programas e projetos. Ocorre que, no\nsetor público, há maior tradição no uso de ferramentas\nde planejamento e no controle de gastos e\ninvestimentos públicos por meio da avaliação de\nprogramas e projetos. E, no terceiro setor, esse\ndomínio de conhecimentos por parte do psicólogo é\nfundamental para pleitear financiamento de agências\nestrangeiras e, também, verbas públicas para\ndesenvolver programas e projetos sociais.", "C": "No setor privado, o domínio de ferramentas sobre\navaliação de programas e projetos permite ao\nprofissional de gestão de pessoas conseguir evidenciar\nos benefícios e as vantagens de investimento em\npessoas, utilizando uma linguagem mais compatível\ncom as demais instâncias de poder na organização.", "D": "A formação em pesquisa do profissional de gestão de\npessoas ajuda muito no desenvolvimento das\ncompetências requeridas para atuar na formulação e\nna avaliação de programas e projetos na área, visto\nque o trabalho de um avaliador e o de um formulador\nde programas e projetos situam-se, respectivamente,\nentre o papel desempenhado por um cientista social –\npreocupado com questões teóricas, desenho de\npesquisa e análise de dados – e o papel de um\nprofissional envolvido com a prestação de um serviço a\npessoas necessitadas.", "E": "Há uma forte demanda por delineamentos de\navaliação de programas e projetos que garantam\nconfiabilidade e generalização dos resultados, mas esse\nargumento não pode servir para criar uma cultura\nvoltada apenas para medidas e testes que perca a\ndimensão humana necessária às intervenções sociais."}, "g": "A", "j": "A esta incorreta: profissionais de gestao de pessoas geralmente NAO sao familiarizados com a metodologia do marco logico - o uso de ferramentas metodologicas de pesquisa nao e ensinado de forma consistente na graduacao. Demais alternativas descrevem corretamente o cenario."}, {"id": "2159766", "d": "psicologia", "a": ["Psicologia Organizacional", "Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Chanlat (1996), o ambiente organizacional,\nenquanto lugar privilegiado onde se tecem numerosas\nrelações, é um terreno fértil para observar as dinâmicas\npsíquicas dos seres humanos que lá trabalham. Esses\nprocessos, afetando de uma maneira ou de outra as\nrelações interpessoais e as relações intergrupais, não\npodem mais ser negados, a menos que se deseje manter\nafastada uma dimensão fundamental da humanidade\nconcreta, o que é arriscado para os indivíduos e para as\ncoletividades. Sobre as descobertas da vida psíquica nas\norganizações, julgue os itens a seguir.\n    I. O comportamento humano jamais é redutível ao que\nse pode observar exteriormente. A descoberta\nfundamental deve-se a Freud e às diversas correntes\npsicanalíticas. Fazendo emergir todo um mundo\nescondido, a psicologia de inspiração psicanalítica\nmostrou a partir de então a face de tal realidade: o ser\nhumano nas organizações é um ser de desejo e de\npulsão. Assim, as descobertas de Freud sobre a vida\npsíquica e as inúmeras contribuições trazidas por seus\nsucessores não deixaram de ter uma ressonância\nimportante no domínio das ciências humanas.\nContudo, essa concepção jamais tinha tocado em\nprofundidade o campo do \"comportamento\norganizacional\", até período recente.\n    II. A partir de uma insatisfação crescente em relação aos\nlimites dos modelos psicológicos ortodoxos de\nexplicação sobre os dispositivos psicológicos do\ncomportamento organizacional, as descobertas têm\ndirecionado cada vez mais os pesquisadores para os\nconceitos elaborados pela corrente psicanalítica.\nAlguns psicanalistas interessados pelos fenômenos\nhumanos observados nas organizações tentaram, cada\num à sua maneira, afirmar a importância e o papel que\nexerce a vida psíquica na dinâmica humana das\norganizações.\n    III. Algumas exceções à parte, cujas contribuições são\nainda levadas em consideração pelos representantes\nda velha ortodoxia, é possível afirmar que a vida\npsíquica e sua abertura psicodinâmica sempre\nconstituíram-se no cerne das descobertas sobre o\ndispositivo psicológico do comportamento\norganizacional nos países anglo-saxões. Libertando-se\nde um modelo comportamentalista inspirado pelo\npositivismo, a realidade interior dos seres humanos\nviu-se, na maioria dos casos, sendo desmascarada.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (Freud e ressonancia nas ciencias humanas, mas com toque tardio no comportamento organizacional) e II (insatisfacao com modelos ortodoxos direcionando para psicanalise) sao corretos. III esta errado pois contradiz I ao afirmar que a vida psiquica sempre constituiu o cerne nas descobertas nos paises anglo-saxoes. Apenas I e II = B."}, {"id": "2159765", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo o Conselho Federal de Psicologia (2010), do ponto\nde vista das teorias organizacionais, historicamente a\nPsicologia conhece o mundo do trabalho há muito e desde\no início do século 20, pelo menos, pesquisa e produz\nconhecimento sobre o assunto. Entretanto, sobre questões\nespecíficas, como a saúde do trabalhador, as relações\nsindicais, as formas solidárias de trabalho, o sofrimento\ncausado pelo desemprego, pode-se dizer que a Psicologia\navançou pouco em sua história. Essas demandas são\nrecentes e ainda carecem de maior sistematização para que\nse possa sugerir caminhos e reorganizar esse campo. Sobre\no histórico da Psicologia no mundo do trabalho, julgue os\nitens a seguir.\n    I. Historicamente, apesar das diversas metamorfoses\nobservadas nas práticas adotadas pela Psicologia no\nmundo do trabalho, tais mudanças não refletem uma\nguinada em termos de objetivos ou de concepção,\nainda que se possa observar mudanças na linguagem\nempregada – alteração de “gestão de recursos\nhumanos” para “gestão de pessoas” – bem como a\nadoção de um sem-número de palavras da língua\ninglesa (coaching, empowerment etc.).\n    II. Em termos das práticas, verifica-se historicamente que\nas mudanças na gestão empresarial conduziram a\nalterações na forma como a Psicologia atua no mundo\ndo trabalho. De um campo de aplicação que demanda\napenas o conhecimento e o desenvolvimento de\ntécnicas (de entrevista, de testes etc.), para um campo\nde pesquisa, uma vez que atualmente as atividades de\ngestão de recursos humanos estão migrando para as\ndivisões, os serviços, os setores e as equipes de\ntrabalho, cabendo agora à Psicologia o papel de\nassessoria aos gestores.    \nIII. Historicamente a Psicologia voltada para a gestão de\nrecursos humanos é a perspectiva que acabou por\ndemarcar o campo de uma Psicologia voltada para as\nquestões do trabalho e das organizações e mantém-se\nhegemônica na atualidade.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (metamorfoses sem guinada em objetivos), II (mudancas na atuacao com migracao para divisoes/equipes e papel de assessoria) e III (psicologia de RH como perspectiva hegemonica que demarcou o campo) sao todos consistentes com a analise do CFP. Todos = D."}, {"id": "2159764", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Davel e Vergara (2001), existe uma dinâmica subjetiva entre masculinidade e feminilidade (com consequências) nos\njogos emocionais que são cotidianamente experimentados nas organizações. Emoção e gênero fazem parte das competências\nsociais das pessoas, e, portanto, são processos-chave para sustentar qualquer tipo de mudança organizacional em profundidade.\nEstar consciente e atento às emoções tal como elas se exprimem no conjunto de referências masculinas e femininas que\npermeiam a vida corriqueira das organizações mostra nossos limites, ao mesmo tempo em que nos habilita a ter sucesso em\nnossas relações e ações profissionais. Acerca da questão da subjetividade da emoção e do gênero nas organizações, assinale a\nalternativa incorreta.", "alt": {"A": "Desde a década de 1990, a temática das pessoas, bem como daquilo que elas vivenciam nas organizações, tonou-se tema\ncentral tanto nos periódicos acadêmicos, como na imprensa especializada em negócios empresariais. Grande parte desse\ndiscurso induziu à ideia de que as pessoas são um trunfo estratégico maior. Por mais inverossímil que isso possa parecer,\nsabemos ainda poucas coisas sobre a subjetividade dos seres humanos e a maneira pela qual eles constituem-se como\nsujeitos nas organizações. Dispomos de poucos pontos de referência para compreender o EU como lugar de produção e\nreprodução de uma subjetividade ancorada nas emoções e no gênero.", "B": "A Teoria da Estruturação desenvolvida por Anthony Giddens pode fornecer um corpo de conhecimento útil para a\ncompreensão da subjetividade nas organizações, visto que tal abordagem permite compreender como a experiência social\ndo agente é construída no decorrer das interações, entre outras, por meio do corpo e de processos emocionais que estão\nno centro dos diversos encontros cotidianos.", "C": "As organizações mantêm-se através do tempo, entre outros motivos, porque elas estão, subjetivamente, ancoradas na\nreprodução social da masculinidade e da feminilidade. O gênero é a manifestação primeira das relações de poder tanto nos\nconjuntos organizados quanto na sociedade. Assim, o gênero age como modalidade de estruturação do conjunto de\nrelações sociais por meio de múltiplos repertórios.", "D": "Entende-se por repertório de gênero a forma relacional que toma a expressão da masculinidade ou da feminilidade e que,\npor meio da energia emocional que comporta, estrutura as relações sociais que os agentes dinamizam cotidianamente. Os\ndiferentes repertórios, de um ponto de vista subjetivo, contribuem para canalizar positiva ou negativamente a emoção, até\nmesmo a energia que é necessária para a performance nas interações.", "E": "As emoções verificam-se ser da ordem das causas e não das razões da ação. Assim, é necessário representá-las como sendo\nintrínsecas à pessoa, muito mais do que apenas relacionais. Sendo assim, as emoções são características individuais, e não\nsão propriedades de sua ação. Assim, as emoções são difíceis de representar e definir, dado que são, por sua vez, latentes e\ndinâmicas, resultado do passado e expressão do presente."}, "g": "E", "j": "E esta incorreta: as emocoes nao sao da ordem das causas, nem intrinsecas a pessoa, nem caracteristicas meramente individuais. Davel e Vergara argumentam que as emocoes sao RELACIONAIS e propriedades da acao - a alternativa inverte essa concepcao."}, {"id": "2159763", "d": "psicologia", "a": ["Psicologia do Trabalho"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Dejours (1992), o medo se constitui em uma\ndas dimensões da vivência dos trabalhadores quase sempre\nignorada por todos os estudos em psicopatologia do\ntrabalho, área que se encontra muito propícia para\nressaltar essa problemática nova na medida em que\nconstitui uma abordagem específica da relação do homem\ncom a realidade do seu trabalho. Com respeito à relação\nentre trabalho e medo, julgue os itens a seguir.    \nI. O medo está presente em todos os tipos de ocupação\nprofissional, inclusive nas tarefas repetitivas e nos\ntrabalhos de escritório, local onde parece ocupar um\npapel mais modesto. Isso ocorre porque em tais\ncategorias profissionais as pessoas são sempre\nexpostas a riscos, psicológicos ou físicos.\n    II. O risco em organizações é, via de regra, coletivo na\nmaioria das situações de trabalho em que vários\ntrabalhadores colaboram na mesma tarefa. Assim,\napesar de as medidas protetivas coletivas serem mais\neficazes, quase sempre são propostas ao trabalhador\napenas medidas preventivas individuais que podem ter\num caráter material ou psicológico. O problema do\nmedo surge da oposição entre a natureza coletiva do\nrisco residual (que não é completamente eliminado) e\na natureza individual da prevenção a cada instante de\ntrabalho.    \nIII. Contra esse medo, os trabalhadores elaboram defesas\nespecíficas. Quando são muito eficazes, praticamente\nnão se encontra mais nenhum traço de medo no\ndiscurso do trabalhador. Portanto é necessário\nprocurar sinais indiretos, que são justamente esses\nsistemas defensivos.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (medo presente em todas as ocupacoes), II (oposicao entre natureza coletiva do risco e prevencao individual), III (defesas eficazes apagam o traco do medo, busca por sinais indiretos via sistemas defensivos) sao todos consistentes com Dejours. Todos = D."}, {"id": "2159762", "d": "psicologia", "a": ["Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Limongi-França (2006), o cenário da gestão de\npessoas no Brasil mostra que a modernidade, ou a pós-modernidade da cultura, o risco como fator decisório e a\ndifícil união entre comportamento organizacional e\ncompetividade impulsionam ações complexas de troca de\ninformações, sistemas virtuais e milhares de formas de\nviabilizar uma sobrevivência com melhor sintonia entre as\nnecessidades da organização e das pessoas. Com relação ao\ncenário da gestão de pessoas, assinale a alternativa\nincorreta.", "alt": {"A": "O cenário da gestão de pessoas nas organizações está\nse elevando das atividades operacionais e legisladas\npara as ações corporativas estratégicas. As\nresponsabilidades dos profissionais envolvidos, que\ntiveram como origem o “registro em carteira”, estão se\nampliando para: qualidade pessoal, qualificações\nculturais, competências tecnológicas, responsabilidade\ne cidadania.", "B": "O cenário da gestão de pessoas mostra que é\nimprescindível obter uma base de aprendizagem e\nqualificação dos especialistas nesse inquieto trinômio:\npessoas – organização – trabalho para difundir uma\nefetiva visão de pessoa, então, com ênfase\npsicossocial.", "C": "O cenário da gestão de pessoas salienta e reitera que a\npedra fundamental desta área (gestão de pessoas) está\nna contribuição conceitual e prática para uma vida\nmais saudável e com resultados legítimos de\nprodutividade, qualidade e desenvolvimento, bem\ncomo competividade sustentável em organizações.", "D": "O cenário da gestão de pessoas mostra que\norganizações são feitas de pessoas para pessoas.\nAssim, os variados espaços organizacionais são\ncompostos de uma diversidade de atividades humanas\nformando um conjunto complexo e difuso (com\nlacunas e sobreposições) que dificultam a localização\nexata do locus da decisão.", "E": "O cenário da gestão de pessoas na nova economia e na\ngestão organizacional é a da era digital e dos novos\nparadigmas. É mister a adoção de novas reflexões,\nvisto que a abordagem da psicologia social e da\nadministração nos últimos 30 anos não consegue mais\ndar respostas a questões organizacionais e\nsocioeconômicas tão intensas, até porque são\nfartamente conhecidas as engrenagens tecnológicas da\nera pós-industrial."}, "g": "E", "j": "E esta incorreta: afirma que 'a abordagem da psicologia social e da administracao nos ultimos 30 anos nao consegue mais dar respostas' - posicao que contradiz Limongi-Franca, que defende justamente a continuidade e aprofundamento dessas abordagens com enfase psicossocial."}, {"id": "2159761", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Para Hutz, Bandeira, Terentine e Vazquez (2020), trabalhar com instrumentos de avaliação psicológica é um constante desafio,\njá que pressupõe necessariamente a atualização de conhecimentos por parte do psicólogo. A todo momento, novos testes são\nlançados, exigindo envolvimento do psicólogo com esses novos instrumentos, seja por meio de estudo, supervisão ou cursos\npráticos. Além disso, o uso de testes demanda conhecimentos básicos sobre medida em psicologia, ou seja, psicometria, área\nmuitas vezes vista com preconceito por psicólogos, já que envolve certo conhecimento lógico-matemático. Além disso, a\nproposta de avaliação desses instrumentos pelo Conselho Federal de Psicologia é relativamente recente. Acerca da utilização e\nda adaptação de instrumentos de avaliação psicológica para o contexto organizacional e do trabalho, assinale a alternativa\nincorreta.", "alt": {"A": "Atualmente, não há uma diversidade considerável de testes sendo utilizados na área da psicologia organizacional e do\ntrabalho (POT). Os que existem são instrumentos somente usados em processos de seleção e avaliação de desempenho.\nEntre eles a Bateria Fatorial de Personalidade e a Escala Vazquez-Hutz de Avaliação de Desempenho. Os vários testes que\neram utilizados em processos de seleção, principalmente os testes projetivos e de inteligência, foram considerados\ndesfavoráveis pelo CFP, visto que não atenderam os requisitos mínimos obrigatórios e/ou não apresentaram novos estudos\nde normatização e/ou validade no prazo estipulado pela Resolução CFP nº 009/2018.", "B": "É preciso cautela na escolha do instrumento para a área de POT. É importante salientar que vêm sendo utilizados vários\ninstrumentos que não foram devidamente adaptados para uso no Brasil, ou mesmo validados para o contexto\norganizacional. Mais uma vez, aponta-se para a necessidade de o psicólogo ter conhecimentos básicos de psicometria, de\nforma a entender o que é dito nos manuais dos testes, e mesmo ler estudos recentes que utilizam os instrumentos do seu\ninteresse.", "C": "Recentemente, vários instrumentos que avaliam construtos da psicologia positiva começaram a ser utilizados em POT,\nsobretudo para verificar e melhorar condições de trabalho, satisfação e engajamento no trabalho e flow. Podem-se alocar\ntambém nesse rol instrumentos que avaliam esperança, os quais, quando começaram a ser empregados, constataram que\nhá uma correlação elevada entre esperança e criatividade, e, portanto, instrumentos que avaliam esperança poderiam ser\nutilizados para uma avaliação indireta de criatividade em organizações.", "D": "Diante da realidade de instrumentos não adaptados ou de sua escassez para alguns construtos importantes na área de POT,\no caminho natural é a construção ou a adaptação de instrumentos de avaliação psicológica. Entretanto é vital tomar a\ncrucial decisão sobre se é melhor construir um novo instrumento ou adaptar um já existente. Vários aspectos devem ser\nconsiderados para chegar a essa resposta: a real necessidade do instrumento, os recursos pessoais e financeiros existentes,\na capacidade de atingir diferentes regiões do Brasil, a necessidade de contar com uma editora de testes, entre outros.", "E": "A vantagem de adaptar um instrumento está relacionada com a possibilidade de comparar os dados em diferentes\namostras, de diferentes contextos, permitindo uma maior equidade na avaliação, uma vez que se trata de uma mesma\nmedida, que avalia o construto a partir de uma mesma perspectiva teórica e metodológica. Em contrapartida, construir o\npróprio instrumento oferece maior liberdade de escolha da teoria a ser selecionada como base, assim como do formato das\nquestões/dos itens que vão compô-lo. A desvantagem da segunda escolha inclui tempo e recursos a serem investidos nessa\nconstrução."}, "g": "A", "j": "A esta incorreta: HA diversidade consideravel de testes em POT, nao apenas dois instrumentos. A afirmacao restritiva e factualmente errada. Demais alternativas descrevem corretamente cautelas, psicologia positiva, construcao/adaptacao e vantagens."}, {"id": "2159760", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Para Griffin e Moorhead (2006), comunicação é o processo\nsocial no qual duas ou mais pessoas trocam informações e\ncompartilham possíveis significados. Assim, tal processo\nafeta profundamente a vida cotidiana e, por conseguinte, o\ncomportamento organizacional. Nas organizações são\nmuitos os propósitos da comunicação; entre eles o de\nrepassar instruções específicas, alcançar ações\ncoordenadas, haja vista a existência de funções e tarefas\nseparadas etc. Sobre a comunicação no trabalho, julgue os\nitens a seguir.\n    I. As linhas do organograma, que originariamente\nmostram as relações de subordinação, também podem\nrepresentar canais de comunicação por meio dos quais\na informação flui, embora a comunicação também\npossa seguir caminhos que cruzem as linhas de\nsubordinação tradicionais.    \nII. No mundo contemporâneo é vital para o\ndesenvolvimento das redes de comunicação\norganizacional o advento de grupos digitais de troca de\ninformações; a saber: listas de distribuição eletrônicas,\ne--mails, salas de bate-papo, mesas de discussão,\naplicativos de mensagens instantâneas, aplicativos de\nvoz e outros sistemas não presenciais de comunicação.    \nIII. Pesquisas indicam alguns possíveis impactos negativos\ndas redes de comunicação. Estudos demonstraram que\numa informação não necessariamente verdadeira pode\nse disseminar rapidamente e impactar a imagem da\norganização, afetando as posições dos trabalhadores\nsobre ela. Isso particularmente ocorre em organizações\nonde existe uma maior rotatividade dos trabalhadores.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (organograma como canais de comunicacao que podem cruzar subordinacao), II (grupos digitais como redes contemporaneas) e III (impactos negativos: disseminacao de informacoes nao verdadeiras, especialmente em organizacoes com rotatividade) sao corretos. Todos = D."}, {"id": "2159759", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Robbins, Judge e Sobral (2010), até o final da\ndécada de 1980, o currículo das escolas de administração\nenfatizava os aspectos técnicos da gestão, focando em\neconomia, contabilidade, finanças e métodos quantitativos.\nTemas como comportamento e habilidades interpessoais\nrecebiam relativamente pouca atenção. Nas últimas três\ndécadas, contudo, as faculdades de administração\ncomeçaram a perceber a importância do papel que o\nconhecimento sobre o comportamento humano tem na\neficácia da administração, e cursos voltados para essa área,\ncomo comportamento organizacional, liderança,\nnegociação, motivação etc., foram sendo agregados ao\ncurrículo. Quanto à importância das habilidades\ninterpessoais, julgue os itens a seguir.    \nI. No mundo contemporâneo, em que ocorre um\nambiente de trabalho extremamente competitivo e\nexigente, os gestores não podem depender apenas de\nsuas competências técnicas. Eles precisam também de\nhabilidades interpessoais independentemente da\nsituação organizacional exigida.\n    II. O desenvolvimento de habilidades interpessoais por\nparte dos gestores auxilia as organizações a atrair e\nreter trabalhadores com alto nível de desempenho.\nOcorre que as habilidades interpessoais dos gestores\ntendem a criar um ambiente de trabalho mais\nagradável.\n    III. Pesquisas indicam que em organizações em que as\npráticas de liderança e relacionamento são muito bem\navaliadas, cerca de 95% dos trabalhadores\npermanecem por mais de trinta anos na mesma\norganização, ao passo que nas outras organizações\nbrasileiras esse índice é de apenas cinco por cento.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (habilidades interpessoais sao necessarias independentemente da situacao) e II (atraem e retem trabalhadores de alto desempenho) sao corretos. III esta errado: o numero especifico de 95% vs 5% e exagerado/inverificavel e nao corresponde a achados reais da literatura. Apenas I e II = B."}, {"id": "2159756", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Zanelli, Borges-Andrade e Bastos (2004), é\nimportante promover a valorização e a compreensão geral\ndos processos de produção do conhecimento científico em\nPsicologia Organizacional e do Trabalho, bem como a forma\ncomo ele é sistematizado nas organizações. Com relação à\nsistematização desses processos, julgue os itens a seguir.    \nI. É imprescindível que o profissional que trabalha com\nPsicologia Organizacional e do Trabalho efetue leituras\nde relatos completos de pesquisas científicas já\nrealizadas na área em que trabalha. Assim, o\nprofissional poderá estabelecer um ou mais paralelos\nde ajuda para seu exercício cotidiano nas organizações,\ntraduzindo questões práticas em hipóteses ou\nsuposições de pesquisa.\n    II. A maioria dos textos introdutórios que tratam da\nquestão da pesquisa em Psicologia Organizacional e do\nTrabalho fornece uma visão compactada sobre a\npesquisa em seus aspectos relativos a desenho,\nmétodos e técnicas de coleta e análise de dados. Isso\ngeralmente termina por levar a um tratamento\nsuperficial da metodologia.    \nIII. O profissional de Psicologia Organizacional e do\nTrabalho precisa desenvolver algumas estratégias de\ninvestigação científica para identificar as possíveis\nrazões para os problemas surgidos em sua área de\natuação. O referido profissional precisa da ajuda da\npesquisa cientifica, seja para saber que medidas usar,\nseja para desenvolver apropriadamente estas\nestratégias.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (leitura de relatos completos de pesquisas), II (textos introdutorios fornecem visao compactada com tratamento superficial) e III (estrategias de investigacao cientifica para identificar razoes de problemas) sao todos consistentes com Zanelli, Borges-Andrade e Bastos. Todos = D."}, {"id": "2159755", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Spector (2004), as organizações no mundo\nmoderno estão diante de um ambiente em que ocorre uma\nrápida evolução na sociedade, a qual requer mudanças\napropriadas tanto em sua estrutura quanto em seu\nfuncionamento. O campo do Desenvolvimento\nOrganizacional (DO) auxilia as organizações a implementar\ntais mudanças de forma racionalmente planejada, visto\nque, ao levar em consideração o lado humano na mudança\norganizacional, pode contribuir para uma melhor maneira\nde conduzi-la. Quanto aos pressupostos conceituais\npresentes na esfera do DO, julgue os itens seguintes.\n    I. O DO é uma família de técnicas elaboradas para ajudar\nas organizações a mudar, visto que desenvolver uma\norganização é sempre alterá-la. Tais métodos de\nmodificação das organizações envolvem a utilização de\nprincípios e procedimentos da ciência comportamental\nque supostamente podem ajudar os trabalhadores a\nmelhorar o seu desempenho e a interagir com mais\neficácia com os demais colegas de trabalho.\n    II. Uma iniciativa de DO sempre envolve uma organização\ninteira e jamais apenas uma parte dela. O foco dessa\nalteração integral reside em promover mudanças\nsubstanciais no modo como ela opera. Essas mudanças\npodem envolver uma reorganização estrutural por\nmeio da qual novos departamentos podem ser criados,\nassim como antigos podem ser eliminados, com\nfunções sendo transferidas de uma área para outra e\nde uma pessoa para outra.\n    III. Uma iniciativa de DO normalmente é muito mais que\nsomente mera reorganização estrutural. Em geral, ela\nmuda significativamente a forma com que as pessoas\nrealizam seu trabalho, como elas se comunicam umas\ncom as outras e como elas coordenam seus esforços e\nsuas ações.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I (DO como familia de tecnicas, ciencia comportamental, melhoria de desempenho) e III (DO e mais que reorganizacao estrutural, muda a forma de trabalho) estao corretos. II esta errado: iniciativa de DO NAO precisa envolver sempre toda a organizacao - pode envolver partes especificas. Apenas I e III = C."}, {"id": "2159754", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "Bastos e Gondim (2010) afirmam que a diversidade da\npsicologia como campo de produção de conhecimento e\ncomo campo de práticas profissionais é facilmente\nconstatada a partir do conceito de áreas de conhecimento\ne áreas de atuação. Contudo, tal diversidade não se esgota\napenas nesse conceito de área, pois inclui uma\nmultiplicidade teórico-metodológica que fundamenta a\nprática de pesquisa e as múltiplas intervenções\nprofissionais do psicólogo na mesma área. Sobre a\ndiversidade da psicologia e sua relação com as áreas,\njulgues os itens a seguir.    \nI. Em princípio, a noção de área de atuação profissional\naproxima pesquisadores, docentes e profissionais a\npartir de referenciais teóricos e de estratégias de\npesquisa e intervenção. Tal aproximação se manifesta\nnas interfaces que cada área estabelece com as outras\ndisciplinas ou outros campos profissionais, o que\ncontribui para a construção e para o uso de um\nvocabulário que a singulariza.    \nII. A natureza não paradigmática da Psicologia revela-se\nna existência de uma pluralidade de perspectivas\nteóricas que se apoiam em distintas concepções de\nhomem, de sociedade, de ciência e, em decorrência,\npostulam procedimentos e práticas distintos para lidar\ncom os mesmos problemas.\n    III. Discentes, docentes e psicólogos se reconhecem como\ninseridos em subdomínios da psicologia que\nconfiguram espaços próprios de investigação e de\natuação. Diferenças, semelhanças e antagonismos são\ntratados, portanto, no interior desse campo de\nconhecimento, tendo como base o conceito de áreas\nde atuação.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (areas de atuacao aproximam pesquisadores, docentes e profissionais), II (natureza nao paradigmatica da psicologia, pluralidade de perspectivas) e III (reconhecimento em subdominios) sao todos consistentes com a tese de Bastos e Gondim. Todos = D."}, {"id": "2159753", "d": "psicologia", "a": ["Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Borges e Mourão (2013), nas últimas décadas\nintensificou-se a discussão referente às alterações pelas\nquais passam as organizações no mundo inteiro. Essa\ndiscussão sinaliza mudanças profundas na forma de\nprodução de bens e serviços, a maneira como o trabalho é\norganizado e a forma como empregados e empregadores se\nrelacionam entre si. Estudiosos que se dedicam a esse tema\nafirmam que as transformações são tão significativas e\nabrangentes que já é possível identificar o surgimento de\nnovos paradigmas que rompem com as tradicionais e já\nestabelecidas formas de gestão profissional. Acerca dos\nnovos modelos de gestão, julgue os itens a seguir.\n    I. Existe um conjunto profundo de alterações ocorrendo\nque se traduz na necessidade de adoção de práticas de\ngerenciamento consideradas mais coerentes com a\nrealidade organizacional atual, constituindo-se, assim,\nno centro do que se poderia chamar de novos modelos\nde gestão, os quais representam um conjunto de\ncaracterísticas vitais que envolve as formas de\nestruturação, organização e funcionamento das\norganizações.\n    II. Os novos modelos de gestão nem sempre são\nclaramente visíveis no cotidiano de nossas\norganizações. Embora existam mudanças perceptíveis,\né certo também que, em muitas organizações, são as\npráticas tradicionais que se perpetuam e não parecem\nameaçadas. Quando se trata dos novos modelos de\ngestão, não existem configurações homogêneas, nem\ndifusão da mesma forma organizacional em todos os\ncontextos, na mesma velocidade.\n    III. As organizações adotam modelos e práticas de gestão\nem função das necessidades de superação e resolução\nde problemas concretos relacionados à produção e ao\ntrabalho. As organizações que lideram esses processos\nde mudança normalmente são aquelas que estão na\nvanguarda do enfrentamento dos novos desafios que\nsão postos por ambientes competitivos, novas\ntecnologias e alterações nos marcos regulatórios sob\nos quais elas operam.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (novos modelos de gestao com caracteristicas vitais de estruturacao), II (mudancas nem sempre visiveis, configuracoes heterogeneas) e III (organizacoes adotam modelos para resolver problemas concretos da producao/trabalho) sao todos corretos. Todos = D."}, {"id": "2159752", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Bittencourt (2004), o Pensamento Sistêmico (PS) se constitui em um processo em que se compreende a\nrealidade em termos da inter-relação entre as partes e as variáveis envolvidas em um sistema, um problema ou uma situação de\ninteresse. Em organizações, o PS considera todos os elementos – fatores econômicos, privados, emocionais, sociais, ecológicos,\ndentre outros – a partir de uma perspectiva dinâmica e interdependente. Na concepção do PS, um departamento, por exemplo,\nnão é uma entidade independente que possui variáveis ou dimensões de forma isolada. Sobre o PS, assinale a alternativa\nincorreta.", "alt": {"A": "Existe uma inadequação das ferramentas analíticas existentes para tratar os problemas organizacionais modernos, tendo\nem vista a complexidade dinâmica do mundo. Há um esgotamento do modelo mecanicista pela falência do arcabouço nele\nbaseado. Logo, o PS possui um interesse em desafiar e contextualizar o pensamento mecanicista, da mesma forma como,\nanalógica e contextualmente, o pensamento relativista de Einstein desafiou o pensamento Newtoniano.", "B": "A Teoria de Sistemas – que nasceu na administração em 1961 – se solidificou como paradigma a partir da constatação de\nque, com os recursos se tornando escassos, seria vital uma mudança no contexto global, com atributos como inovação,\nflexibilidade, tempo de resposta e qualidade, tornando-se condições básicas para a sobrevivência organizacional. Porém a\napropriação desses princípios do PS pelos praticantes organizacionais é mais recente, em função do processo de ampliação\nda percepção de que realmente existem outras forças inter-relacionadas influenciando na vida organizacional.", "C": "Na Teoria das Organizações, o tema do PS aparece em alguns tópicos e por essa razão parece evidente – para quem o\naborda – a compreensão sobre sua lógica e necessidade. Contudo, quando se tenta migrar para ações práticas, evidencia-se\na dificuldade em saber como aplicá-lo. Quando gestores que trabalham em grandes organizações tentam inserir novas\nformas mais sistêmicas de operação, tais como o desenvolvimento conjunto de procedimentos, construção de um trabalho\nem equipe, práticas coerentes com a complexidade das demandas do ambiente, enfim condutas de integração sistêmica,\nencontram enormes obstáculos.", "D": "Existem diversos fatores relevantes na realidade que impedem a existência do PS em organizações. Uma delas é o fato de\nque o ser humano em seu processo de aprendizagem vai gradativamente perdendo a capacidade de compreensão sistêmica\nao longo dos anos. No processo de socialização do conhecimento, o mundo vai se fracionando. Uma criança, por exemplo,\ndesde a mais tenra idade tem embutido em sua aprendizagem que a Matemática é uma disciplina isolada, Química é outra,\nHistória é outra e que tudo isso não possui relação alguma com Literatura. Há, então, uma aprendizagem calcada na\ndissociação dos elementos focalizados separadamente. Isso explica em parte por que nas organizações se analisam\nproblemas ou sistemas pela sua decomposição em partes e não de forma integrada.", "E": "Um dos facilitadores da implantação do PS em uma organização é a existência de uma estrutura de sustentação e\nordenamento de preceitos calcados em elementos filosóficos embutidos no pensamento linear. Tais arcabouços\norganizacionais fundamentados nos paradigmas institucionais permitem a adoção de comportamentos essenciais de\nintegração sistêmica consentindo assim, quando for o caso, no “descongelamento” integral de determinado tipo de padrão\nde comportamento mais fechado e moldado pela conjuntura tradicional. O PS se constitui, portanto, em uma perspectiva\nfilosófica que fundamenta uma reflexão de como se deve desafiar o status quo, propiciando novos padrões na disposição\nestrutural."}, "g": "E", "j": "E esta incorreta: o pensamento LINEAR e justamente o que o Pensamento Sistemico desafia e supera; nao pode ser facilitador da implantacao do PS. A alternativa inverte os principios."}, {"id": "2159750", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Para Dejours (1992), existe um sofrimento não reconhecido\nprovocado pela organização do trabalho (visto o\nafrontamento do trabalhador com sua tarefa\norganizacional), assim como existem diversos sistemas de\ndefesa colocados em prática para conter tal sofrimento. A\npartir dessa afirmação, analise os itens a seguir\napresentados pelo autor sobre as estratégias defensivas.    \nI. Mesmo intenso, o sofrimento é razoavelmente bem\ncontrolado pelas estratégias defensivas, que impedem\nque tal sofrimento se transforme em patologia. Assim,\nneuroses, psicoses e depressões em situações de\ntrabalho são compensadas precisamente pela\nutilização desses sistemas defensivos.    \nII. As defesas que não são psiconeuróticas, ou seja, as\ndefesas de comportamento são menos flexíveis que as\ndefesas mentais. Por causa disso, os sujeitos que\napresentam esse tipo de estrutura são mais frágeis\ndiante dos acontecimentos da vida laboral do que os\nsujeitos que apresentam uma estrutura neurótica.    \nIII. Quando as defesas comportamentais não conseguem\nconter a gravidade dos conflitos, tais sujeitos não\ndescompensam de um modo neurótico nem psicótico.\nA desorganização à qual sucumbe o doente não se\ntraduz por sintomas mentais, mas pelo aparecimento\nde uma doença somática.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (estrategias defensivas impedem que sofrimento se transforme em patologia), II (defesas comportamentais sao menos flexiveis que as mentais) e III (quando defesas comportamentais nao contem conflitos, surge doenca somatica - nao mental) sao todos consistentes com Dejours. Todos = D."}, {"id": "2159749", "d": "psicologia", "a": ["Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Davel e Vergara (2001), a gestão é\naprimorada com base na riqueza e na complexidade das\npessoas que dinamizam a vida organizacional, visto que os\nseres humanos e suas subjetividades representam a\nessência do sucesso sustentável e consistente das\norganizações contemporâneas. Sobre subjetividade e\nrelações humanas, julgue os itens a seguir.    \nI. Para que se possa entender o mundo organizacional e\nnele atuar de forma consequente, é de extrema\nrelevância penetrar na sutileza das relações humanas e\ntentar desvendar a teia que os seres humanos tecem a\npartir da subjetividade, visto que ela pode ajudar a\nidentificar a experiência humana em todos seus\ndilemas, formas de pensamento, condutas, emoções e\nações e lidar com ela.    \nII. Se voltarmos nossa atenção para as relações que as\npessoas estabelecem na organização, seremos capazes\nde desvendar a pluralidade e a heterogeneidade de\nlinguagens, espaços e práticas que nos governam\ndiariamente, permitindo indagar sobre como a\nsubjetividade vai sendo constituída pelas vozes em\nnossa mente e pelos sentimentos em nosso corpo que\nsão produzidos em ocasiões históricas, políticas e\nculturais precisas.    \nIII. A administração necessita tornar-se cada vez mais\norientada para gerir pessoas e suas relações subjetivas,\nvisto que nos é apresentada como a administração das\ncoisas, e não das pessoas. Contudo, essa objetivação\npossui uma utilidade intrínseca na compreensão do\nmundo organizacional em razão da possibilidade de\ndelineamento mais apurado dos problemas da vida real\nos quais são intensamente conectados. Assim, para\nque se possa conceber operacionalmente a atividade\norganizacional e administrativa, é necessário um\nfracionamento artificial objetivo.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (relevancia de penetrar na sutileza das relacoes humanas e na subjetividade) e II (vozes na mente, sentimentos no corpo, ocasioes historicas/politicas/culturais) sao corretos. III contem afirmacao confusa e parcialmente contraditoria sobre 'fracionamento artificial objetivo' que diverge da tese de Davel e Vergara. Apenas I e II = B."}, {"id": "2159748", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Para compreender as organizações, é necessário possuir a\nvisão que os seres humanos possuem. De acordo com\nLimongi-França (2006), as pessoas têm respostas\ncomplexas, com potencialidades e reações biológicas,\npsicológicas e sociais que reagem simultaneamente às\ncondições de vida. Essas reações, com variadas\ncombinações e intensidades, podem ser compreendidas em\ncamadas biopsicossociais interdependentes. Acerca da\nnatureza dessas camadas, julgue os itens a seguir.\n    I. A camada biológica refere-se às características físicas\nherdadas ou adquiridas pelo ser humano, ao nascer e\ndurante toda a vida. Inclui metabolismo, resistências e\nvulnerabilidades de órgãos ou sistemas.    \nII. A camada psicológica refere-se aos processos afetivos,\nemocionais e de raciocínio, conscientes ou\ninconscientes, que formam a personalidade de cada\nindivíduo e o seu modo de perceber e se posicionar\ndiante das pessoas e das circunstâncias vivenciadas.      \nIII. A camada social incorpora os valores, as crenças, o\npapel na família, no trabalho e em todos os grupos e\ncomunidades a que cada pessoa pertence e de que\nparticipa. O meio ambiente e a localização geográfica\ntambém formam a dimensão social.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (camada biologica: caracteristicas fisicas, metabolismo, resistencias), II (camada psicologica: processos afetivos, emocionais, racionais, conscientes e inconscientes) e III (camada social: valores, papeis, ambiente e localizacao) sao todos consistentes com o modelo biopsicossocial de Limongi-Franca. Todos = D."}, {"id": "2159747", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Griffin e Moorhead (2006), uma\norganização se constitui em um conjunto de pessoas que\ntrabalham juntas para atingir metas em comum. Para tanto\né necessária a existência de uma estrutura, a qual\nestabelece um sistema de coordenação dos esforços\nhumanos para que haja ganhos potenciais da força coletiva\nde trabalho. A respeito da natureza das estruturas\norganizacionais de trabalho, julgue os itens a seguir.    \nI. A estrutura organizacional de trabalho se constitui em\num sistema de relações entre tarefas, subordinação e\nautoridade que configura detalhadamente o desenho\nde como deve ocorrer a laboração em uma\norganização, delineando como as partes se subdividem\ne se associam em grupos de trabalho ou unidades\norganizacionais (setores, departamentos etc.)\n    II. A divisão do trabalho consiste na distribuição das\ntarefas da organização a funções diferentes para que\nsejam realizadas por pessoas diferentes. Constitui uma\ndas setes características básicas de estruturação\ndescritas por Max Weber. Sendo assim, só existem\nvantagens para a organização (e para os trabalhadores)\nnesse processo de divisão, visto que, do contrário, não\nse poderia obter o uso mais eficiente do trabalho\nhumano.    \nIII. Um organograma descreve as relações de\nsubordinação e os integrantes dos grupos de trabalho,\nalém de mostrar como os variados cargos e os\npequenos grupos de trabalho constituem as unidades\norganizacionais (setores ou departamentos), os quais,\njuntos, formam a configuração ou a forma da\norganização.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I (estrutura organizacional como sistema de relacoes entre tarefas, subordinacao e autoridade) e III (organograma descreve relacoes de subordinacao e grupos de trabalho) sao corretos. II esta errado: NAO 'so existem vantagens' na divisao do trabalho - ha desvantagens (alienacao, monotonia, etc.). Apenas I e III = C."}, {"id": "2159742", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Vasquez e Hutz (2020), a interface da\npsicologia organizacional e do trabalho com o movimento\nchamado de Psicologia Positiva conduziu a desdobramentos\ninovadores nesse campo de conhecimento, abrindo\ncaminho para o desenvolvimento de modelos teóricos por\nmeio dessa perspectiva. Com relação aos pressupostos da\npsicologia positiva no campo do trabalho e das\norganizações, julgue os itens a seguir.    \nI. Evidências empíricas mostram-se cada vez mais\nrobustas em demonstrar afirmativamente que a vida\nde significado e de preenchimento (ou vida plena,\ncomo alguns preferem denominar) está intimamente\nligada a valores, emoções e atitudes positivas em\nrelação ao que o ser humano produz com o seu\ntrabalho.\n    II. Embora não seja novidade teórica a proposição de que\no trabalho ocupa um espaço central na vida dos\nindivíduos e da sociedade, a contribuição da psicologia\npositiva está em colocar os holofotes em uma análise\nmais ampla desse processo. Em vez de investigá-lo\napenas pelos fatores assertivos associados, testando\naspectos convenientes e preservados nas pessoas, a\nproposta é identificar também transformações\nconfirmatórias causadas no sujeito pela danificação do\ntrabalho.    \nIII. O salto teórico propiciado pela Psicologia Positiva não\ntem como base apenas a proposição de mais uma\nabordagem psicológica. Seu ponto central está\njustamente no questionamento de pressupostos\nepistemológicos e ontológicos que levam os psicólogos\ntradicionais a tratar apenas de processos e desfechos\ndesfavoráveis associados aos adoecimentos na vida\nlaboral.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I (vida de significado ligada a valores e atitudes positivas no trabalho) e III (questionamento epistemologico ao tratamento apenas de desfechos desfavoraveis) sao corretos. II contem afirmacao confusa sobre 'transformacoes confirmatorias causadas pela danificacao do trabalho' que contradiz a proposta da Psicologia Positiva. Apenas I e III = C."}, {"id": "2159741", "d": "psicologia", "a": ["Motivação", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Schein (1982), no decorrer da história humana,\nhouve muitas tentativas no sentido de se chegar a saber em\nprofundidade o que é que realmente motiva as pessoas, o\nque é que na natureza dos seres humanos os faz\ncomportarem-se de determinadas maneiras. E, hoje em dia,\no debate sobre o que é que motiva as pessoas em seu\ncomportamento no trabalho continua tão aceso como\nantes. Quanto à motivação para o trabalho, julgue os itens\na seguir.    \nI. A compreensão definitiva sobre o que realmente\nmotiva as pessoas continua distante. Assim, é mister\nadotar uma atitude diagnóstica e flexível, sensível aos\nacontecimentos e à interpretação deles por parte das\npessoas que participam de determinada situação, de\ntal forma que se possa escolher um esquema de ação\napropriado a essa conjuntura.    \nII. É extremamente difícil determinar a “essência” da\nnatureza humana quando se revisam as diversas\nperspectivas que os dirigentes, no decurso da história,\nadotaram com relação à motivação. O exame de\nalgumas das mais importantes constatações da\npesquisa referentes a cada um dos principais grupos de\nhipóteses leva ao raciocínio de que cada uma das\nteorias sobre motivação é parcialmente correta, mas\nsó parcialmente.\n    III. Para compreendermos plenamente a motivação e o\ncomportamento humano, devemos desenvolver um\ncomplexo conjunto de hipóteses a respeito das pessoas\ne situar essas hipóteses dentro de um contexto\nespecífico. Não existe uma resposta única para essas\nquestões, não há uma forma que seja a única forma\n“correta” de se lidar com as pessoas, não há uma\nmaneira “perfeita” de organizar e distribuir o trabalho.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (compreensao definitiva distante, atitude diagnostica e flexivel), II (essencia da natureza humana dificil, teorias parcialmente corretas) e III (complexo conjunto de hipoteses, sem resposta unica) sao todos consistentes com a posicao de Schein. Todos = D."}, {"id": "2159740", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "A partir da afirmação de Zanelli, Borges-Andrade e Bastos\n(2004) sobre cognição nas organizações do trabalho,\nassinale a alternativa incorreta.", "alt": {"A": "Justamente porque uma organização se constitui em\ncriações ou ferramentas sociais interativas – produto de\nações individuais e coletivas estreitamente entrelaçadas –\n, fica clara a importância atribuída por pesquisadores e\ngestores ao papel do conhecimento, do pensamento e\ndos processos que os geram e os transformam para que\nhaja uma compreensão mais adequada das características\ne das dinâmicas das organizações.", "B": "Compreender as organizações requer,\nnecessariamente, uma teoria sobre o homem e,\nprincipalmente, sobre sua ação social interativa no\ninterior delas, mesmo quando se assume o\npressuposto válido de que tais unidades sociais se\nreduzem ao comportamento dos indivíduos singulares\nque as compõem.", "C": "A cognição se constitui em uma classe de fenômenos\ncentral para a compreensão dos processos\norganizacionais, visto que o pensamento, a linguagem,\no manejo de símbolos, de conceitos e de regras\ndesempenham importância no complexo cotidiano de\npessoas. Munidas de tais ferramentas cognitivas, as\npessoas articulam suas ações em torno de um ou de\nmúltiplos objetivos organizacionais.", "D": "Quanto ao termo “cognição”, a ideia mais fortemente\nevocada caracteriza-se pela noção restrita, leiga e\ndifundida de atividade racional, intelectual e\nconsciente. Essa noção está ancorada em uma\nconcepção tradicional de mente que integra três\ngrandes domínios referentes aos três processos\ncognitivos mentais básicos: pensamento (cognitivo),\nsensação (emocional) e vontade (conativo).", "E": "A emergência de uma ciência cognitiva é um fenômeno\nrelativamente recente e tem como marco o ano de 1956\ne a realização do Simpósio sobre Teoria da Informação no\nMassachusetts Institute of Technology (MIT)."}, "g": "B", "j": "B esta incorreta: contem o pressuposto reducionista de que unidades sociais 'se reduzem ao comportamento dos individuos singulares' - justamente o reducionismo que Zanelli e colegas criticam. As demais alternativas descrevem corretamente o papel da cognicao nas organizacoes."}, {"id": "2159624", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Adélia Socorro de Simões Almeida (2010), a\nmediação, como estratégia judiciária de resolução de conflitos,\ntem ganhado importância para os Tribunais de Justiça, a partir\nda década de 1990, no Brasil. Isso ocorre devido a várias\ncausas, entre as quais não se pode citar que:", "alt": {"A": "o Poder Judiciário, em sua maneira tradicional de\natuar, torna-se cada vez mais moroso, sobrecarregado\ne impessoal.", "B": "o número cada vez maior de processos impede uma\naproximação dos envolvidos no conflito com o juiz,\naquele que vai ouvir as demandas da parte e tomar\ndecisões para resolvê-lo.", "C": "o grande número de disputas judiciais faz com que o\njuiz muitas vezes tome decisões superficiais e de fácil\ndescumprimento, no transcurso do processo.", "D": "a mediação é de grande valia social, pois permite\nàqueles que argumentam melhor celebrar acordos que\nsão vantajosos para si.", "E": "a mediação faz com que a impessoalidade jurídica seja\nsuperada, levando o mediador a se colocar de forma\nmais humana, conhecendo mais profundamente os\nproblemas dos litigantes."}, "g": "D", "j": "D NAO pode ser citada como causa positiva da importancia da mediacao: 'permitir a quem argumenta melhor celebrar acordos vantajosos' descreve uma falha (assimetria/parcialidade), nao um beneficio social. Demais alternativas trazem causas validas (morosidade, sobrecarga, decisoes superficiais, humanizacao)."}, {"id": "2159623", "d": "psicologia", "a": ["Psicologia Jurídica", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2022", "org": "CFP", "t": "", "e": "Contemporaneamente, segundo Levinzon e Lisondo (2018),\na adoção é considerada pelos estudiosos do tema um\nprocesso complexo que envolve várias variáveis\npsicológicas e sociais, que podem levar a seu sucesso ou a\nseu fracasso. Podem-se apontar como características desse\nprocesso algumas variáveis. Julgue os itens a seguir.    \nI. A adoção, idealmente, pode ser considerada como um\nprocesso de gerar um encontro afetivo íntimo, com a\nconstrução de mundos compartilhados entre\nadotantes e adotados, no qual há o paradoxo de, ao\nmesmo tempo, poder-se alojar a diferença entre eles.    \nII. A revelação da adoção, dos pais para o filho, deve ser\nrealizada quando este é adulto, pois o adulto tem\nmaior capacidade de elaboração do que uma criança,\nque pode ficar abalada ou traumatizada ao saber que\nnão veio do ventre de sua mãe.    \nIII. Um dos fatores que pode contribuir para o sucesso de\numa adoção é a capacidade de os pais adotivos\nconsiderarem o filho como um outro, dotado de sua\nprópria personalidade e características e, ao mesmo\ntempo, ter com ele uma conexão afetiva profunda,\noferecendo a possibilidade de um apego seguro do\nfilho a eles.\n      Assinale a alternativa correta:", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I (encontro afetivo intimo, alojar a diferenca) e III (considerar o filho como outro com apego seguro) sao corretos. II esta errado: a revelacao da adocao NAO deve esperar a fase adulta - a literatura especializada recomenda revelacao gradual desde cedo. Apenas I e III = C."}, {"id": "2159622", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2022", "org": "CFP", "t": "", "e": "A separação conjugal, em relação ao casal que tem filhos,\npode causar, segundo Silva (2016), uma série de conflitos\nentre os genitores. Esses conflitos, por sua vez, prejudicam\ngrandemente os filhos. Sobre esses conflitos, assinale a\nalternativa correta.", "alt": {"A": "Ao invés de regulamentação de visitas por parte do\ngenitor que não é guardião, dever-se-ia falar de direito\nde convívio com o filho, por parte do primeiro.", "B": "O fenômeno da alienação parental diz respeito ao\ngenitor que não busca, no convívio com o filho, dar\nfundamentos de realidade.", "C": "A guarda unilateral da criança deve sempre ficar com a\nmãe, que sempre é a pessoa mais qualificada para dar\nafeto e cuidado ao filho.", "D": "A guarda compartilhada acontece quando a mãe não\npode se responsabilizar totalmente pelo filho.", "E": "É aceitável que, na regulamentação das visitas, o pai\ndispenda apenas o papel de “pai legal”, passando todo\ntempo só buscando diversões com o filho."}, "g": "A", "j": "A esta correta: a terminologia 'direito de convivio' substitui 'regulamentacao de visitas' (visao mais atualizada e protetiva dos vinculos parentais). B (alienacao parental mal definida), C (mae sempre como melhor guardia), D (guarda compartilhada como excecao) e E (papel meramente diversionista do pai) sao incorretas."}, {"id": "2159621", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Família", "Psicologia Jurídica"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Rovinski (2004), boa parte das perícias dos\npsicólogos em Varas de Família diz respeito a processos de\nregulamentação da guarda, após a separação dos pais da\ncriança ou do adolescente em tela. Nesse sentido, cabe ao\npsicólogo desenvolver uma metodologia para a avaliação\ndesses casos. Sobre tal metodologia, assinale a alternativa\ncorreta.", "alt": {"A": "Devem-se realizar entrevistas iniciais de coleta de\ndados, com os genitores, referentes à história de vida,\nà relação matrimonial e à relação com o filho.", "B": "Num segundo momento, com os genitores, devem-se\nrealizar entrevistas para avaliação da personalidade de\ncada um, com testes projetivos ou escalas de\npersonalidade.", "C": "Na avaliação da personalidade dos genitores, sempre\né, no Brasil, avaliada a questão cognitiva dos pais, com\naplicação de testes de inteligência como o WAIS.", "D": "No caso da entrevista com crianças, deve-se utilizar, se\npossível, a entrevista de coleta de dados, nos quais se\ninvestiga sobre sua rotina com cada um dos genitores e\nsobre as características do seu relacionamento com\neles.", "E": "No caso da avaliação da personalidade das crianças,\npodem-se utilizar testes gráficos ou projetivos, assim\ncomo a hora lúdica diagnóstica."}, "g": "A", "j": "A descreve corretamente o primeiro passo da metodologia de pericia em Varas de Familia: entrevistas iniciais com genitores cobrindo historia de vida, relacao matrimonial e relacao com o filho. As demais contem imprecisoes (B coloca testes como obrigatorios, C generaliza WAIS, D restringe entrevista com crianca, E sugere uso de testes graficos sem qualificacao adequada)."}, {"id": "2159614", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia Jurídica", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Crianças e Adolescentes - Menores Infratores"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a atuação do psicólogo em unidades de internação\npara adolescentes em conflito com a lei, de acordo com o\ndocumento do Conselho Federal de Psicologia (2010)\n“Referências técnicas para atuação de psicólogos no âmbito\ndas medidas socioeducativas em unidades de internação”,\nassinale a alternativa correta.", "alt": {"A": "Dá-se total autonomia ao psicólogo em termos de sua\natuação, não devendo receber influências de outros\nprofissionais que possam desviá-lo de seu olhar\nprofissional.", "B": "Pede-se tolerância com certas violências cometidas\ncontra os adolescentes em unidades de internação,\npois elas são necessárias para a correção de condutas\ndisfuncionais.", "C": "O psicólogo deve fazer uma análise da perspectiva de\numa visão psicológica exclusivamente intraindividual\nda personalidade do adolescente.", "D": "O psicólogo deve analisar o contexto social, a demanda\npor sua presença e a contribuição na política de\natendimento ao adolescente.", "E": "O psicólogo deve trabalhar para que o adolescente\nfique o maior tempo possível em medida de\ninternação, pois assim as medidas corretivas terão\nmais efeito."}, "g": "D", "j": "D alinha-se as Referencias Tecnicas do CFP (2010): o psicologo em unidades socioeducativas deve analisar contexto social, demanda por sua presenca e contribuicao na politica de atendimento. Demais alternativas reduzem ou distorcem a atuacao (autonomia absoluta, tolerar violencia, olhar intraindividual, prolongar internacao)."}, {"id": "2159602", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A perícia psicológica em processos de Vara de Família, no\nBrasil, surgiu na década de 1980, acompanhando tendência\ninternacional nesse sentido. A história da perícia psicológica\nem Varas de Família, segundo Castro (2003), é assunto\nainda pouco estudado. Sobre o tema, assinale a alternativa\nincorreta.", "alt": {"A": "As concepções iniciais da perícia psicológica estavam\ninfluenciadas pela perícia psiquiátrica no campo penal,\ndado que a práxis da segunda antecede o surgimento\nda primeira.", "B": "As concepções iniciais da perícia psicológica giravam\nem torno da determinação de culpados e inocentes,\nmas se mostraram inadequadas.", "C": "As concepções da perícia psicológica receberam\nquestionamento por parte das tendências psicológicas\nem voga, na época de sua constituição.", "D": "Havia, na época da constituição da teoria sobre a\nperícia psicológica, dados abundantes a respeito dela.", "E": "Uma das tendências da perícia psicológica é de\nnegação de sua validade, pelo fato da possibilidade de\nresolução dos problemas familiares por meio de\nmediação ou intervenção breve."}, "g": "D", "j": "D esta incorreta: na epoca da constituicao da teoria sobre pericia psicologica em Varas de Familia (anos 1980), havia ESCASSEZ de dados, nao abundancia. As demais (influencia da pericia psiquiatrica penal, foco em culpados/inocentes, questionamentos das tendencias da epoca, tendencia atual a mediacao) sao corretas."}, {"id": "2159599", "d": "psicologia", "a": ["Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2022", "org": "CFP", "t": "", "e": "O presídio acaba, de acordo com Wolff (2005), tornando-se\num sistema social específico, com suas regras e\ndeterminações. Assinale a alternativa correta.", "alt": {"A": "O presídio deve ser coercitivo, pois as pessoas que lá\nestão presas possuem graves transtornos de\npersonalidade, devendo ser reprimidas de qualquer\nmodo.", "B": "O sistema prisional brasileiro acolhe presos de todas as\nclasses sociais, pois a Justiça brasileira é imparcial\nquanto ao julgamento tanto do rico quanto do pobre.", "C": "O Brasil tende a seguir os EUA e a Europa em colocar\nna prisão parcelas precarizadas da classe operária,\nespecialmente de famílias afrodescendentes.", "D": "O presídio no Brasil funciona como uma instituição que\ncumpre a função de ressocializar os presos; aqueles\nque reincidem no crime são pessoas moralmente\nrecalcitrantes.", "E": "O sistema prisional brasileiro aplica, de forma\nequitativa, a Lei de Execução Penal, não havendo\npresos sem situação jurídica definida."}, "g": "C", "j": "C descreve corretamente a tese de Wolff: o sistema prisional brasileiro reproduz o padrao EUA/Europa de encarcerar parcelas precarizadas da classe operaria, especialmente afrodescendentes (encarceramento seletivo). As demais (coercao por transtorno, imparcialidade da justica, ressocializacao efetiva, aplicacao equitativa da LEP) sao falsas."}, {"id": "2159598", "d": "psicologia", "a": ["Foucault", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "O famoso filósofo e historiador Michel Foucault, em sua\nobra Vigiar e punir, analisou as formas de castigo que a\nsociedade francesa impunha aos que cometiam crimes,\ntanto no Antigo Regime, quanto após a Revolução\nFrancesa. Ele aponta para dois tipos principais de castigo,\npelo suplício, típico do Antigo Regime, e pela punição, típica\nda sociedade contemporânea. Nesse sentido, julgue os\nitens a seguir.\n    I. O suplício constitui-se num castigo que incide sobre o\ncorpo do criminoso, objetivando deixar-lhe uma\ncicatriz ou expô-lo ao público de forma degradante,\ntornando o sujeito infame.\n    II. O suplício deve ter uma violência excessiva, no qual o\ncerimonial da justiça manifesta sua força, fazendo o\ncriminoso gemer ou gritar com os golpes dados pelo\ncarrasco.    III. O suplício pode se estender após a morte do criminoso,\natravés de cadáveres queimados, cinzas jogadas ao\nvento, corpos arrastados na grade, expostos à beira da\nestrada.    \nIV. Na punição pós-Revolução, o objetivo da pena liga-se\nao contrato social estabelecido no Código Penal, no\nqual a todo crime deve-se estabelecer uma punição\nnão violenta.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e IV estão certos.", "B": "Apenas os itens I, II e III estão certos.", "C": "Apenas os itens I, III e IV estão certos.", "D": "Nenhum dos itens estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (suplicio no corpo, cicatriz, infamia), II (violencia excessiva, cerimonial), III (suplicio apos morte, cadaver queimado/exposto) e IV (punicao pos-Revolucao ligada ao contrato social do Codigo Penal) sao todos consistentes com a analise de Foucault em Vigiar e Punir. Todos = E."}, {"id": "2159597", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2022", "org": "CFP", "t": "", "e": "O famoso sociólogo americano Erving Goffman\ndesenvolveu o conceito de instituição total, na clássica obra\nManicômios, prisões e conventos, publicada em 1961.\nSegundo o sociólogo, a instituição total é aquela na qual o\nindivíduo vivencia todas as suas atividades, de forma\ndependente, sendo os outros pertencentes a essa\ninstituição as únicas pessoas com as quais convive. De\nacordo com Fiorelli e Mangini (2009), assinale a alternativa\nque não corresponde às características de uma instituição\ntotal.", "alt": {"A": "Despojamento pela instituição dos bens pessoais dos\ninstitucionalizados.", "B": "Favorecimento, por parte da instituição, a que o\ninstitucionalizado tenha garantido o acesso aos seus\ndireitos humanos fundamentais.", "C": "Participação do institucionalizado em atividades cujas\nconsequências simbólicas são incompatíveis com a\nconcepção de “eu”.", "D": "Exposição, pela instituição, do institucionalizado à\ncompanhia forçada.", "E": "Realização de todas as atividades dos\ninstitucionalizados segundo um esquema obrigatório\nde regras impostas pela instituição."}, "g": "B", "j": "B NAO corresponde a uma caracteristica de instituicao total: garantir direitos humanos fundamentais e justamente o OPOSTO do que ocorre em instituicoes totais segundo Goffman, que se caracterizam pelo despojamento, exposicao a companhia forcada e regras impostas. As demais (despojamento, atividades simbolicamente incompativeis, companhia forcada, esquema obrigatorio) sao caracteristicas validas."}, {"id": "2159596", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade"], "ano": "2022", "org": "CFP", "t": "", "e": "O trabalho interdisciplinar entre psicólogo e assistente\nsocial é muito comum em termos da atuação técnica nos\nprocessos das Varas de Infância e Juventude. Segundo\nJulião e Massaro, in Franco e Melão (2007), sobre as\ncaracterísticas desse tipo de trabalho, julgue os itens a\nseguir.\n    I. Há preponderância de uma ciência sobre a outra, seja a\nPsicologia ou o Serviço Social, no sentido de que uma\ndelas, no curso da investigação, dentro de um\nprocesso, se mostrará preponderante sobre a outra,\nque exercerá papel meramente auxiliar na\ninvestigação.\n    II. Há necessidade de, além de simples diálogo, existir\nrelacionamento, participação, comunicabilidade e\naceitação entre os profissionais.\n    III. Há postura profissional que permite se pôr a transitar o\nespaço da diferença, com sentido de busca, de\ndesvelamento da pluralidade de ângulos que\ndeterminado objeto investigativo é capaz de\nproporcionar.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I esta errado: a interdisciplinaridade nao envolve preponderancia de uma ciencia sobre a outra (isso seria hierarquizacao, nao interdisciplinaridade). II (relacionamento, participacao, comunicabilidade) e III (transito no espaco da diferenca, pluralidade) sao corretos. Apenas II e III = B."}, {"id": "2159595", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2022", "org": "CFP", "t": "", "e": "Shine (2003), ao definir a Psicologia Jurídica, coloca\nquestões sobre a definição do campo de trabalho do\npsicólogo e sobre a natureza de seu labor nele. Assinale a\nalternativa incorreta quanto à definição de Psicologia\nJurídica.", "alt": {"A": "A Psicologia Jurídica diz respeito ao trabalho do\npsicólogo nos Fóruns dos Tribunais de Justiça; portanto\no termo é sinônimo do termo Psicologia Forense – as\nduas denominações dando conta da imbricação entre\nDireito e Psicologia.", "B": "O objeto da intervenção psicológica na Psicologia\nJurídica é uma questão problema, formulada por um\noperador do Direito.", "C": "O objetivo da intervenção psicológica é dado pela\ndemanda do operador do Direito, em torno de\nquestões problemas de origem e natureza psicológicas.", "D": "A abordagem da Psicologia Jurídica é sempre\nintersubjetiva, no sentido de que a questão problema\nsurge de um operador do Direito e diz respeito a um\nsujeito humano, o periciado, que será avaliado por um\noutro humano, o perito psicólogo.", "E": "No caso da Psicologia Jurídica, diferentemente da\nPsicologia Clínica, a relação humana estabelecida não\nserá a de ajuda, posto que o periciando pode ser\nbeneficiado ou prejudicado pelo informe psicológico."}, "g": "A", "j": "A esta incorreta: Psicologia Juridica e Psicologia Forense NAO sao sinonimas. A Psicologia Juridica e mais ampla (envolve toda interface com o Direito); a Forense e mais restrita (atuacao especifica em pericias forenses)."}, {"id": "2159575", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a rotina do psicólogo hospitalar numa Unidade de\nTerapia Intensiva, de acordo com Baptista e Dias (2003),\nassinale a alternativa incorreta.", "alt": {"A": "Verificar quem são os pacientes internados e conhecer\na história da internação atual.", "B": "Avaliar as reações psicológicas do paciente frente à\nhospitalização.", "C": "Avaliar o estado mental do paciente.", "D": "Orientar e informar as rotinas da UTI.", "E": "Atender apenas a família do paciente por ele estar em\ncoma."}, "g": "E", "j": "E esta incorreta: o psicologo hospitalar NAO atende apenas a familia quando o paciente esta em coma; o cuidado psicologico ao paciente em coma (presenca, comunicacao, estimulacao) tambem e parte da rotina. As demais sao tarefas legitimas em UTI."}, {"id": "2159571", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação à atuação do psicólogo hospitalar com o\npaciente cirúrgico, julgue os itens que se seguem de acordo\ncom as ideias de Turra, Junior, Almeida e Doca (2011).    \nI. Estudos evidenciam que a preparação cirúrgica\nbaseada no estilo de enfrentamento individual dos\npacientes pode reduzir os níveis de ansiedade pré-operatória.\n    II. Se o modo de expressão dos medos do paciente\ncirúrgico é conhecido, podem-se desenvolver\nestratégias preventivas de manejo.    \nIII. A falta de informações para o paciente pré-cirúrgico\nreduz a colaboração e dificulta o enfrentamento do\ncontexto cirúrgico.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (preparacao baseada em estilo de enfrentamento reduz ansiedade), II (conhecer modo de expressao dos medos permite estrategias preventivas) e III (falta de informacao reduz colaboracao e dificulta enfrentamento) sao todos consistentes com Turra et al. Todos = D."}, {"id": "2159569", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa em que não representa a assistência\npsicológica ao paciente com AIDS, segundo Baptista e Dias\n(2003).", "alt": {"A": "Na maioria das vezes, as reações psicológicas se devem\nmuito mais ao próprio estigma da AIDS do que ao\nmedo da doença ou da morte.", "B": "Os pacientes com AIDS apresentam dificuldades para\naceitar o diagnóstico e adaptar-se à própria doença.", "C": "O paciente tem receio de ser abandonado por seu (sua)\ncompanheiro(a), e adota um comportamento de\nesquiva, distanciando-se das relações afetivas e\nsexuais", "D": "O psicólogo hospitalar tem a tarefa de auxiliar os\npacientes com AIDS para o enfrentamento do\ndiagnóstico, da doença, do próprio tratamento e do\npreconceito social.", "E": "É objetivo dos profissionais de psicologia aguardar o\ntempo do paciente para a adesão ao tratamento, sem\nestimular para não gerar constrangimentos."}, "g": "E", "j": "E NAO representa assistencia adequada: o psicologo NAO deve apenas 'aguardar o tempo' do paciente com AIDS; deve estimular ativamente a adesao ao tratamento, respeitando o ritmo mas oferecendo suporte motivacional. Demais alternativas descrevem aspectos validos do atendimento."}, {"id": "2159568", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Saúde da Família", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Em relação ao atendimento psicológico do paciente idoso, de\nacordo com Lustosa (2007), assinale a alternativa correta.", "alt": {"A": "Geriatria significa Gerontologia.", "B": "O atendimento do psicólogo clínico e do psicólogo\nhospitalar é igual para o paciente idoso.", "C": "A atuação da psicologia hospitalar tem como seus\nfocos de trabalho a família, o paciente idoso e a equipe\nde saúde.", "D": "O paciente idoso não necessita de estimulações.", "E": "A família do paciente idoso não faz parte do\natendimento psicológico."}, "g": "C", "j": "C esta correta: a psicologia hospitalar com idoso foca paciente, familia e equipe de saude. A (Geriatria=Gerontologia errada, sao distintas), B (atendimentos clinico e hospitalar nao sao iguais), D (idoso precisa de estimulacao) e E (familia faz parte) sao incorretas."}, {"id": "2159567", "d": "psicologia", "a": ["Psicanálise", "Terapia Cognitivo Comportamental", "Freud", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade", "Psicologia da Saúde", "Dor, Estresse e Luto", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Angerami-Camon (1998), existem alguns modelos\npsicológicos frequentemente utilizados no tratamento de\ndor tanto aguda quanto crônica. Considerando tal\nafirmativa, assinale a alternativa incorreta sobre os\npossíveis tratamentos para a dor.", "alt": {"A": "Tratamento operante para dor.", "B": "Tratamento eletromiográfico.", "C": "Tratamento cognitivo-comportamental.", "D": "Eletroencefalograma.", "E": "Hipnose."}, "g": "D", "j": "D esta incorreta: o eletroencefalograma e um EXAME diagnostico, nao um tratamento para dor. Tratamentos validos descritos por Angerami-Camon incluem operante, biofeedback eletromiografico, cognitivo-comportamental e hipnose."}, {"id": "2159566", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "O profissional de saúde demonstra não conseguir mais\nmanter o esforço para a adaptação, apresenta capacidade\ndo organismo de resistência superada pelo estresse, com\nlapsos de memória, dispersividade intensa e com o\nsurgimento de ideias suicidas. Diante do quadro descrito, o\nprofissional encontra-se em qual fase descrita por Selye?", "alt": {"A": "Choque.", "B": "Alarme.", "C": "Esgotamento.", "D": "Resistência.", "E": "Contrachoque."}, "g": "C", "j": "A descricao (capacidade de resistencia superada, lapsos de memoria, dispersividade, ideias suicidas) corresponde a fase de ESGOTAMENTO no modelo trifasico de Selye (alarme → resistencia → esgotamento)."}, {"id": "2159565", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Angerami-Camon (1998), quando o profissional de\nsaúde adota a postura de indiferença total à dor do\npaciente, não demonstrando sensibilidade pelo sofrimento,\nele assume a postura de:", "alt": {"A": "desamparo de diagnóstico.", "B": "profissionalismo afetivo.", "C": "distanciamentos críticos.", "D": "empatia genuína.", "E": "calosidade profissional."}, "g": "E", "j": "A postura de indiferenca total a dor do paciente, sem sensibilidade pelo sofrimento, e denominada CALOSIDADE PROFISSIONAL por Angerami-Camon - mecanismo de defesa rigido que embota a empatia."}, {"id": "2159564", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo hospitalar diante de um\npaciente em posição de revolta, assinale a alternativa\nincorreta.", "alt": {"A": "O psicólogo hospitalar deve compreender e mostrar,\nquando possível, que a raiva é defesa contra a\nimpotência, o desespero e a desesperança.", "B": "O psicólogo hospitalar deve focalizar a verdade da\npessoa, e não apenas o errado da situação", "C": "O psicólogo deve perceber que a revolta não é de\ncaráter pessoal, mas envolve a situação vivenciada pelo\npaciente e seu sentimento é transferido aos membros\nda equipe.", "D": "Se o psicólogo perceber sinais indicativos de violência\nou se o paciente já possuir histórico de episódios de\nviolência, o psicólogo deve estimular a expressão de\nsentimentos, enaltecendo-os como forma de validação.", "E": "O psicólogo hospitalar nunca deve retaliar, atacando o\npaciente."}, "g": "D", "j": "D esta incorreta: diante de sinais de violencia, o psicologo NAO deve estimular/enaltecer a expressao dos sentimentos violentos - deve fazer manejo de seguranca, conter, acionar equipe. Demais alternativas descrevem condutas adequadas (compreender raiva como defesa, focar a verdade da pessoa, perceber transferencia, nao retaliar)."}, {"id": "2159563", "d": "psicologia", "a": ["Psicologia da Saúde", "Dor, Estresse e Luto", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "A paciente, após notícia do médico sobre diagnóstico\ngrave de metástase de câncer de mama, relata ao\npsicólogo que o exame foi laudado errado, pois ela não\ntem nenhum sintoma nas mamas, mas seguirá o\ntratamento proposto. O psicólogo hospitalar analisa que\na paciente está no estágio de:", "alt": {"A": "negação.", "B": "barganha.", "C": "aceitação.", "D": "revolta.", "E": "depressão."}, "g": "A", "j": "A paciente que recebe diagnostico grave e afirma que 'o exame foi laudado errado' apesar de aceitar fazer o tratamento esta no estagio de NEGACAO (Kubler-Ross), primeira fase classica do processo de adaptacao ao luto/doenca terminal."}, {"id": "2159562", "d": "psicologia", "a": ["Psicopatologia", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas", "CID-10 e DSM", "Outros Transtornos", "Transtornos relacionados a traumas e estressores"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto às intervenções psicológicas em situações de\nemergência citadas por Franco (2015), assinale a alternativa\ncorreta.", "alt": {"A": "O psicólogo deve exercer a abordagem cognitivo- -\ncomportamental para cuidar de pessoas em situações\nde emergência.", "B": "O psicólogo em situações de emergência atende\napenas aos pacientes.", "C": "A ação do psicólogo no pós-desastre está relacionada à\nidentificação de transtornos mentais, com foco\nprincipal no Transtorno de Estresse Pós-Traumático.", "D": "A atuação do psicólogo de emergência é semelhante à\ndo psicólogo clínico.", "E": "A ferramenta debriefing não é utilizada em situações\nde emergência."}, "g": "C", "j": "C esta correta: a acao do psicologo no pos-desastre envolve identificacao de transtornos mentais com foco principal no TEPT. A (restringe a TCC), B (so pacientes), D (semelhante ao clinico) e E (debriefing nao usado) sao incorretas."}, {"id": "2159561", "d": "psicologia", "a": ["Psicologia da Saúde", "Dor, Estresse e Luto"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto aos rituais de luto e sua função em desastres,\njulgue os itens a seguir de acordo com as ideias de Franco\n(2015).    \nI. Os rituais têm como principais objetivos auxiliar na\nconcretização da morte, confirmar a perda, autorizar a\nexpressão de afetos e memórias, propiciar a\nconstrução de significados e fornecer suporte social ao\nenlutado.\n    II. A impossibilidade de realizar os rituais fúnebres pode\ndificultar o processo de luto.    \nIII. Os rituais estão presentes no processo de elaboração\ndo luto apenas quando realizado velório e\nsepultamento.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas o item III está certo.", "E": "Apenas os itens II e III estão certos."}, "g": "B", "j": "I (rituais auxiliam concretizacao da morte, expressao de afetos, construcao de significados e suporte social) e II (impossibilidade de rituais funebres dificulta o luto) sao corretos. III esta errado: rituais nao se limitam a velorio e sepultamento - ha outros (homenagens, escritas, ceremonias). Apenas I e II = B."}, {"id": "2159560", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca do diagnóstico em psicologia hospitalar, assinale a\nalternativa correta segundo as ideias do autor Simonetti\n(2013).", "alt": {"A": "O diagnóstico psicológico é o conhecimento da doença\npor meio de seus sintomas.", "B": "O diagnóstico psicológico é uma verdade absoluta.", "C": "O diagnóstico em psicologia hospitalar é um\npsicodiagnóstico, estruturado por meio de testes\npsicológicos.", "D": "O diagnóstico deve ser estruturado considerando a\nreação da pessoa à doença, sua condição médica, a\nanálise das diversas áreas da vida do paciente e suas\nrelações.", "E": "O psicólogo hospitalar não faz diagnóstico, pois é\nconsiderado um rótulo e instrumento de discriminação\ndos pacientes."}, "g": "D", "j": "D esta correta segundo Simonetti: o diagnostico em psicologia hospitalar considera a reacao da pessoa a doenca, condicao medica, analise das areas da vida e relacoes. A (conhecimento por sintomas), B (verdade absoluta), C (apenas psicodiagnostico via testes) e E (nao faz diagnostico) sao incorretas."}, {"id": "2159559", "d": "psicologia", "a": ["Psicologia da Saúde", "Dor, Estresse e Luto"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Franco (2015), “os primeiros socorros psicológicos\nreferem-se a uma resposta humana de suporte para uma\npessoa que está em sofrimento ou precisa de\nacolhimento”.\n    Acerca da atuação do psicólogo em situações de\ncatástrofes, julgue os itens a seguir sobre os primeiros\nsocorros psicológicos.    \nI. Os primeiros socorros psicológicos são oferecidos no\nprimeiro contato com as pessoas vitimadas, o que\ngeralmente ocorre durante ou imediatamente após\numa situação de emergência ou desastre.\n    II. Esse procedimento envolve prover cuidado prático e\nde suporte que respeite os limites da pessoa atendida.    \nIII. A maior parte da população apresenta diminuição\ngradativa dos sintomas após a exposição ao evento\ntraumático, mas em alguns casos esses sintomas\npodem perdurar, tais como no Transtorno de Estresse\nPós-Traumático.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (PSP oferecidos no primeiro contato apos emergencia/desastre), II (cuidado pratico que respeite limites) e III (diminuicao gradativa dos sintomas com possivel persistencia tipo TEPT em alguns) sao todos consistentes com Franco. Todos = E."}, {"id": "2159558", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "No pronto-socorro, uma das situações que mais demandam\na atenção do psicólogo hospitalar é a histeria. Assinale a\nalternativa correta sobre a atuação do psicólogo na\nabordagem da histeria, segundo Simonetti (2013).", "alt": {"A": "O tratamento emergencial da histeria no pronto- -\nsocorro tem apenas o objetivo de resolver a crise atual.", "B": "O psicólogo deve utilizar as seguintes frases com o\npaciente: “é só emocional” e “você não tem nada”.", "C": "O psicólogo busca controlar a agitação na sala de\nemergência, evitando que se forme uma plateia para o\npaciente.", "D": "O psicólogo precisa encaminhar o paciente apenas\npara o acompanhamento psiquiátrico.", "E": "O psicólogo deve se mostrar apressado, pois o\natendimento no pronto-socorro exige rapidez."}, "g": "C", "j": "C esta correta segundo Simonetti: na abordagem da histeria em pronto-socorro, o psicologo busca controlar a agitacao e evitar a formacao de plateia que reforce o quadro. As demais alternativas trazem condutas inadequadas."}, {"id": "2159557", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "O psicólogo hospitalar avalia uma paciente idosa internada\nnuma Unidade de Terapia Intensiva no período noturno,\ncom pneumonia, sem transtornos psiquiátricos e cognitivos\nprévios. Verifica-se que a paciente está acordada, tem\ndificuldade de manter a atenção no profissional, distrai-se\ncom facilidade, encontra-se agitada e relata estar em casa,\npreocupada com o filho que vai almoçar, e não se lembra\nda internação. Assinale a alternativa correta da hipótese\ndiagnóstica do psicólogo.", "alt": {"A": "Diagnóstico médico.", "B": "Histeria.", "C": "Hospitalismo negativo.", "D": "Coma vígil.", "E": "Delirium."}, "g": "E", "j": "O quadro descrito (paciente idosa em UTI, com pneumonia, sem TM previo, alteracao aguda da atencao, agitacao, desorientacao temporo-espacial, falsas crencas sobre localizacao) e diagnostico classico de DELIRIUM - sindrome confusional aguda comum em pacientes internados."}, {"id": "2159556", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "O psicólogo hospitalar, para concretizar sua estratégia de\ntrabalhar o adoecimento no registro simbólico, se vale de\nduas técnicas descritas por Simonetti (2013). Uma delas\nengloba intervenções direcionadas à situação que se forma\nem torno do adoecimento, chamada de:", "alt": {"A": "escuta analítica.", "B": "diagnóstico transferencial.", "C": "associação livre.", "D": "manejo situacional.", "E": "setting terapêutico."}, "g": "D", "j": "O MANEJO SITUACIONAL e a tecnica descrita por Simonetti que engloba intervencoes direcionadas a situacao que se forma em torno do adoecimento (familia, equipe, contexto), complementando a escuta analitica voltada ao sujeito."}, {"id": "2159555", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "A Psicologia Hospitalar, segundo Simonetti (2013), é “o\ncampo de entendimento e tratamento dos aspectos\npsicológicos em torno do adoecimento”. Tais aspectos\npsicológicos podem aparecer:", "alt": {"A": "somente como causa, pois toda doença é\npsicossomática.", "B": "apenas desencadeante sobre uma vulnerabilidade\nfísica preexistente.", "C": "exclusivamente como causa e consequência.", "D": "somente como agravante, ajudando a piorar o quadro\nclínico já instalado.", "E": "algumas vezes como manutenção da doença através\ndos ganhos secundários."}, "g": "E", "j": "Segundo Simonetti, os aspectos psicologicos podem aparecer no adoecimento como causa, desencadeante, consequencia, agravante OU como manutencao da doenca atraves dos ganhos secundarios. A, B, C e D fazem restricoes absolutas erroneas ('somente', 'apenas', 'exclusivamente'). E captura uma das formas legitimas."}, {"id": "2159554", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando o diagnóstico delirium uma complicação\nfrequente de pacientes internados no hospital, em especial\naqueles com condições clínicas graves, julgue os itens\nseguintes de acordo com o autor Botega (2002).    \nI. Existem três tipos de delirium: hipoativo, hiperativo e\nmisto, sendo que o hipoativo é caracterizado por\nexcesso de atividades motoras, inquietação e\nperegrinação.    \nII. O tratamento não farmacológico do delirium inclui a\npresença frequente da família e reajustes do ambiente,\ncomo por exemplo reduzir os possíveis barulhos e\nruídos.\n    III. O delirium é uma síndrome frequentemente\nsubdiagnosticada e indicativa de mau prognóstico,\nestando associada a maiores taxas de\nmorbimortalidade.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I esta errado: o delirium HIPOATIVO caracteriza-se por LENTIFICACAO motora e apatia, nao excesso de atividade (essa e a caracteristica do hiperativo). II (tratamento nao farmacologico inclui familia e ajustes ambientais) e III (subdiagnosticado e indicativo de mau prognostico) sao corretos. Apenas II e III = C."}, {"id": "2159553", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Simonetti (2013), assinale a alternativa que\ncaracteriza a atuação do psicólogo hospitalar.", "alt": {"A": "O objetivo principal do trabalho do psicólogo hospitalar\né a cura do paciente.", "B": "É pela fala que o psicólogo hospitalar faz o seu trabalho\nde tratar os aspectos psicológicos; portanto nada há a\nfazer com os pacientes impossibilitados de falar.", "C": "A relação do paciente com seu sintoma é um dos focos\ndo trabalho do psicólogo hospitalar.", "D": "O objeto de trabalho do psicólogo hospitalar é apenas\no paciente.", "E": "Geralmente, o psicólogo hospitalar estabelece uma\nmeta ideal para o paciente alcançar durante o\ntratamento."}, "g": "C", "j": "C esta correta segundo Simonetti: a relacao do paciente com seu sintoma e um dos focos centrais do trabalho do psicologo hospitalar. A (cura como objetivo), B (nada com pacientes que nao falam), D (objeto apenas o paciente) e E (meta ideal pre-estabelecida) sao incorretas."}, {"id": "2159552", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Saúde", "Psicologia Hospitalar", "Exames Mentais e Funções Psíquicas"], "ano": "2022", "org": "CFP", "t": "", "e": "O paciente apresenta-se consciente, com alucinações\nvisuais, delírio religioso, agitação psicomotora e labilidade\nafetiva. Diante do exame psíquico realizado pelo psicólogo\nhospitalar, as alterações encontradas foram:", "alt": {"A": "consciência, sensopercepção, pensamento e volição.", "B": "consciência, memória, pensamento e afetividade.", "C": "sensopercepção, memória e consciência do EU.", "D": "consciência, pensamento, linguagem e memória.", "E": "sensopercepção, pensamento e afetividade."}, "g": "E", "j": "As alteracoes descritas correspondem a tres funcoes psiquicas: alucinacoes visuais = SENSOPERCEPCAO, delirio religioso = PENSAMENTO, labilidade afetiva = AFETIVIDADE. E e a unica alternativa que combina exatamente essas tres funcoes."}, {"id": "2159551", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Angerami-Camon (1996), o hospitalismo positivo\ndiz respeito à:", "alt": {"A": "manifestação comportamental em que o paciente\nprefere ficar hospitalizado a voltar a enfrentar as\npenúrias sociais a que está submetido.", "B": "manifestação comportamental de rejeição à instituição\nhospitalar.", "C": "manifestação psíquica que demonstra a permanência\nde projeto de vida e expectativas frente a esta.", "D": "adaptação adequada da internação e da rotina\nhospitalar.", "E": "capacidade criativa do indivíduo no mundo interno e\nexterno, apontando para o comprometimento do juízo\nde realidade."}, "g": "A", "j": "A esta correta: o hospitalismo POSITIVO segundo Angerami-Camon refere-se a manifestacao em que o paciente prefere permanecer hospitalizado a enfrentar as penurias sociais externas - representa apego a instituicao como protecao."}, {"id": "2159550", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Baptista e Dias (2003), a síndrome da UTI é\ncaracterizada por um estado confusional, reversível e\nsecundário à internação. Nesse contexto, os fatores\nresponsáveis por ela são, exceto:", "alt": {"A": "privação de sono.", "B": "idade avançada.", "C": "presença do estímulo da família.", "D": "efeitos colaterais de alguns medicamentos.", "E": "comprometimento do quadro clínico."}, "g": "C", "j": "C NAO e fator da sindrome de UTI - pelo contrario, a presenca do estimulo da familia atua como fator PROTETOR contra a sindrome confusional. Demais alternativas (privacao de sono, idade avancada, medicamentos, gravidade clinica) sao fatores reconhecidos."}, {"id": "2159547", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "O professor está adoecendo, afirmam Facci et al. (2018).\nEm várias situações, a depender da condição do docente,\nrecomenda-se a readaptação. Nesse sentido, pode-se\nafirmar que, nesse campo de atuação, o psicólogo escolar\ndeverá estar atento a alguns aspectos. Sobre eles, julgue os\nitens a seguir.\n    I. Condições de trabalho do professor.  \nII. Ações e relações institucionais.\n  III. Limites e potencialidades dos docentes para que\npossam exercer sua atividade de ensino.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas os itens I e III estão certos.", "C": "Apenas os itens I e II estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (condicoes de trabalho do professor), II (acoes e relacoes institucionais) e III (limites e potencialidades dos docentes) sao todos aspectos legitimos a serem observados pelo psicologo escolar diante da readaptacao de professores adoecidos. Todos = D."}, {"id": "2159546", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "A formação continuada em Psicologia Escolar é considerada\ncomo parte de um compromisso social do psicólogo com as\nquestões da escola. Pode-se afirmar que sua atividade deve\nter como objetivo:", "alt": {"A": "fornecer um modelo de formação continuada, visando\ncolaborar para a ascensão profissional.", "B": "auxiliar o profissional a lidar com as incertezas e com\nas constantes mudanças, além de promover a reflexão\npessoal e profissional.", "C": "colaborar com o processo organizacional do sistema,\nvisando à análise de carreira dos envolvidos.", "D": "repassar as diretrizes das secretarias de educação,\nvisando à adequação das normativas à dinâmica da\nescola.", "E": "favorecer a integração dos docentes e dos gestores por\nmeio da adequação das normativas à dinâmica da\nescola."}, "g": "B", "j": "B esta correta: a formacao continuada em Psicologia Escolar visa auxiliar o profissional a lidar com incertezas, mudancas constantes e promover reflexao pessoal/profissional - perspectiva critica e formativa, nao apenas tecnica."}, {"id": "2159545", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "O psicólogo escolar deve se atentar à proposta curricular da\nescola. Há que se ter cuidados, portanto, para não\npsicologizar os fenômenos escolares. Nesse sentido, as\norientações desse profissional devem considerar que:", "alt": {"A": "o planejamento curricular deverá iniciar com as\nanálises das situações sociais e educativas,\nidentificando os principais problemas para, na\nsequência, selecionar as contribuições das demais\nciências para o enfrentamento dos problemas.", "B": "o planejamento curricular deverá se pautar nas\ndinâmicas psicológicas dos docentes e dos discentes.", "C": "a Base Nacional Comum Curricular já orienta sobre a\nresolução dos problemas.", "D": "as diretrizes do MEC são suficientes para o\nplanejamento.", "E": "o planejamento curricular deverá se pautar\nexclusivamente nas necessidades psicológicas dos\nalunos."}, "g": "A", "j": "A esta correta: o planejamento curricular deve iniciar pelas analises sociais e educativas, identificando problemas reais antes de buscar contribuicoes disciplinares - evita psicologizar fenomenos escolares. As demais alternativas reduzem o curriculo a dinamicas psicologicas ou normativas externas."}, {"id": "2159544", "d": "psicologia", "a": ["Psicopatologia", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas", "Psicologia da Educação", "Transtornos do Neurodesenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "A respeito dos estudos relacionados às explicações sobre\nestudantes que apresentam o Transtorno do Espectro\nAutista, julgue os itens a seguir.\n    I. As teorias cognitivas, segundo Scheuer e Andrade\n(2007), podem auxiliar a compreender o\nfuncionamento cognitivo e os comportamentos desse\ntranstorno, embora não exista uma teoria específica\nque justifique ou explique o autismo.    \nII. Crianças autistas muitas vezes apresentam ações e\ndiscursos reduzidos ou que não são facilmente\ninterpretados pelos outros (professores, mães, adultos\nou pares). O que geralmente acontece é uma\ndificuldade muito grande em atribuir sentido às ações\ndessa criança. Geralmente os outros entendem aquele\ncomportamento como um ato sem significado.    \nIII. Só a teoria comportamental é capaz de produzir\nafirmações plausíveis sobre a linguagem do estudante\ncom o Transtorno do Espectro Autista.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Nenhum item está certo.", "E": "Apenas os itens I e II estão certos."}, "g": "E", "j": "I (teorias cognitivas auxiliam mas nao ha teoria especifica que explique o autismo) e II (acoes reduzidas e dificuldade de atribuicao de sentido) sao corretos. III esta errado: a teoria comportamental NAO e a unica capaz de produzir afirmacoes sobre a linguagem no TEA. Apenas I e II = E."}, {"id": "2159542", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Educação", "Teorias da Personalidade", "Psicologia da Saúde", "Teorias da Personalidade - Outros Autores"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Zimmerman (2000), a autorregulação é um\nprocesso pelo qual o indivíduo gerencia seus pensamentos,\ncomportamentos e sentimentos, com o intuito de alcançar\ndeterminada meta. Ela é composta de três dimensões:", "alt": {"A": "comportamental, metacognitiva e motivacional.", "B": "metacognitiva, desenvolvimento e aprendizagem.", "C": "motivação, ensino e aprendizagem.", "D": "comportamento, vivências, metacognição.", "E": "afetividade, emoções, comportamento operante."}, "g": "A", "j": "Segundo Zimmerman (2000), a autorregulacao compoe-se de tres dimensoes: COMPORTAMENTAL (regulacao das acoes/comportamentos), METACOGNITIVA (regulacao dos processos cognitivos) e MOTIVACIONAL (regulacao das crencas e disposicoes)."}, {"id": "2159538", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Educação", "Psicologia da Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "O estresse é um fenômeno debatido no campo\neducacional. Pode-se afirmar que, no Brasil, os fatores\nestressores mais citados pelas pesquisas são:", "alt": {"A": "as crianças com deficiências e problemas de\naprendizagem que colaboram para o adoecimento do\nprofessor.", "B": "falta de alimentos e merenda escolar adequada.", "C": "infraestrutura inadequada da escola e os problemas de\ndisciplinas, mas que não são tão relevantes.", "D": "alta motivação dos alunos para se aprender e recursos\ninsuficientes para o trabalho que estressam o\nprofessor.", "E": "desinteresse da família em acompanhar a trajetória\neducacional dos filhos; desnível entre os alunos;\ndesvalorização profissional; assim como a falta de\ntrabalho em equipe."}, "g": "E", "j": "E lista corretamente os fatores estressores mais citados nas pesquisas brasileiras sobre adoecimento docente: desinteresse familiar, desnivel entre alunos, desvalorizacao profissional e falta de trabalho em equipe. As demais culpabilizam alunos (A), reduzem a infraestrutura (B, C) ou invertem (D)."}, {"id": "2159537", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicologia da Educação", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo escolar junto aos projetos\nde vida escolar, assinale a alternativa correta. O psicólogo\nescolar:", "alt": {"A": "deve aplicar testes vocacionais.", "B": "deve valorizar os testes, por serem os instrumentos\nprivativos para fazer orientação vocacional.", "C": "precisa considerar a dinâmica da família e os vínculos\nque os adolescentes estabelecem com os diversos\nmembros, os quais são importantes para a elaboração\ndo projeto de vida.", "D": "deve considerar que o projeto de vida vai acontecer\nnaturalmente, considerando as tendências inatas dos\njovens.", "E": "não pode e não deve trabalhar junto à gestão escolar,\npois ele não tem competência para exercer tal função."}, "g": "C", "j": "C esta correta: o psicologo escolar deve considerar a dinamica familiar e os vinculos do adolescente na elaboracao do projeto de vida. A e B reduzem ao uso de testes (vocacionais nao sao privativos), D naturaliza, E nega a participacao na gestao."}, {"id": "2159536", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação à atuação dos psicólogos escolares junto aos\nnúcleos de acessibilidade, assinale a alternativa incorreta.", "alt": {"A": "Atuar a favor das pessoas marginalizadas e excluídas\ncom vistas à sua participação social, de forma a\ngarantir que sua autonomia e seus direitos sejam\nrespeitados na luta contra preconceitos, estigmas e\ndiscriminações.", "B": "Favorecer o trânsito dos estudantes com deficiências\nnas instâncias sociais diversas da universidade.", "C": "Disponibilizar às pessoas com deficiência, que, ao\ningressarem na universidade, deparam-se com um\nnovo contexto, condições pedagógicas e tecnológicas\nadequadas para seu desenvolvimento acadêmico.", "D": "Corrigir as dificuldades de adaptação dos estudantes\ncom deficiência nas universidades, cuja inclusão\nacontecerá automaticamente, uma vez que eles já\nforam preparados para conquistar os seus espaços.", "E": "Investir na comunidade universitária com ações que\npromovam a sensibilização de equipes gestoras e a\ncriação de laboratório de apoio pedagógico com\nsuporte técnico e humano – pedagogos, psicólogos,\npsicopedagogos, fonoaudiólogos, profissionais da\ncomputação – capaz de criar soluções tecnológicas e\npedagógicas para o atendimento."}, "g": "D", "j": "D esta incorreta: a inclusao das pessoas com deficiencia na universidade NAO acontece automaticamente; demanda acoes ativas e contextuais. As demais alternativas descrevem corretamente o papel dos nucleos de acessibilidade."}, {"id": "2159534", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo escolar diante das análises\ndas funções psicológicas que estão envolvidas no processo\nde aprendizagem, assinale a alternativa incorreta.", "alt": {"A": "O desenvolvimento do raciocínio lógico é de suma\nimportância, pois esse é o processo responsável por\nsistematizar as vivências e particularmente as situações\nmais complexas.", "B": "É na aprendizagem escolar que o aluno assume novas\nformações que lhes são básicas, como é o caso da\ntomada de consciência e apreensão, incidindo em seu\ndesenvolvimento como um todo, possibilitando outras\nformas de contato com a realidade que o cerca e\nconsigo mesmo.", "C": "É essencial que os alunos dominem amplamente as\nfunções mentais (abstração, análise e síntese,\ngeneralização etc.) indispensáveis para formar os\nconceitos dos objetos e dos fenômenos da realidade:\nrealizar comparações de um objeto com outro e\nanalisar características gerais e distintas de objetos e\nfenômenos.", "D": "O processo de generalização e discriminação acontece\nnaturalmente, pois ele é inato e se desenvolve\nindependentemente da cultura.", "E": "O processo de generalização e de discriminação não\nacontecem naturalmente, pois são dependentes da\ncultura."}, "g": "D", "j": "D esta incorreta: os processos de generalizacao e discriminacao NAO sao inatos nem se desenvolvem independentemente da cultura - sao construidos socialmente, como a propria alternativa E afirma corretamente. D contradiz a perspectiva historico-cultural."}, {"id": "2159530", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Nos últimos anos estamos vivendo mudanças na dinâmica\nescolar em decorrência da cibercultura. O psicólogo escolar\ndeve, portanto, estar atento ao impacto desse fenômeno\nna aprendizagem escolar, porque a literatura sobre o tema\nrevela que:    \nI. a cibercultura influencia a forma com a qual os jovens\nnativos digitais se relacionam com a aprendizagem, à\nmedida que o uso das tecnologias digitais de\ninformação e comunicação é parte do seu cotidiano\npara acessar informações gerais ou para compreender\nconteúdos oriundos das atividades escolares.    \nII. os ambientes virtuais são atrativos, oferecem\npraticidade e rapidez, e seu uso é de domínio das\ncrianças e dos jovens nativos digitais.\n    III. o ambiente virtual demonstra toda sua atratividade e\npraticidade de interação por meio da possibilidade de\nacesso à informação a qualquer momento a partir do\nuso das mais variadas TICs.    \nIV. os jovens estão hiperconectados às tecnologias digitais,\nsão nativos digitais e estão presentes nas redes\nvirtuais, mas ao mesmo tempo não desqualificam a\nexperiência escolar.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens II e III estão certos.", "C": "Todos os itens estão certos.", "D": "Apenas o item III está certo.", "E": "Apenas os itens III e IV estão certos."}, "g": "C", "j": "I (cibercultura influencia relacao dos nativos digitais com a aprendizagem), II (ambientes virtuais sao atrativos para criancas e jovens), III (ambiente virtual permite acesso a informacao a qualquer momento) e IV (jovens hiperconectados que nao desqualificam a experiencia escolar) sao todos corretos. Todos = C."}, {"id": "2159526", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando a relação da Psicologia Escolar com a\nEducação Inclusiva, é certo afirmar que o profissional deve:", "alt": {"A": "adotar as práticas de medicalização dos problemas dos\nestudantes que estão em situação de dificuldade de\naprendizagem.", "B": "criar um espaço de escuta dos professores e promover\ncondições de mudança junto a eles.", "C": "estabelecer uma rede de avaliação diagnóstica para\nidentificar alunos com deficiência intelectual.", "D": "fazer terapia de grupo e individual para melhorar a\nsaúde mental da comunidade escolar.", "E": "substituir os professores quando for necessário para\nconter a indisciplina escolar."}, "g": "B", "j": "B esta correta: na perspectiva critica da Educacao Inclusiva, o psicologo escolar deve criar espaco de escuta dos professores e promover condicoes de mudanca junto a eles. As demais (medicalizacao, avaliacao para identificar deficiencia, terapia, substituir professores) sao abordagens tradicionais inadequadas."}, {"id": "2159525", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "O psicólogo escolar pode contribuir no processo de\nconscientização. Segundo Martín-Baró (1996), referenciado\npor Guzzo (2015), a conscientização é entendida como um\nprocesso:", "alt": {"A": "de transformação pessoal e social vivido por quem é\noprimido na descoberta da sua realidade.", "B": "que se restringe à mudança de opinião.", "C": "exclusivamente social.", "D": "de adaptação pessoal vivido na descoberta do mundo\nque cerca o indivíduo.", "E": "de autorregulação do comportamento, o qual implica o\ndomínio dos mecanismos de defesa."}, "g": "A", "j": "Segundo Martin-Baro, a conscientizacao e processo de transformacao pessoal e social vivido por quem e oprimido na descoberta de sua realidade - conceito chave da Psicologia da Libertacao em dialogo com Paulo Freire. B (mera mudanca de opiniao), C (exclusivamente social), D (adaptacao) e E (autorregulacao) reduzem o conceito."}, {"id": "2159524", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando os estudos de revisão sistemática de\nliteratura sobre a atuação do psicólogo escolar junto ao\nfenômeno bullying entre os escolares, podemos encontrar\nas explicações descritas nos itens a seguir.\n    I. Os dados sugerem que estudantes propensos ao\ndesengajamento moral podem praticar mais bullying\nquando comparados a estudantes com maior\nengajamento moral. Os meninos se desengajam\nmoralmente mais do que as meninas, assim como\npraticam mais bullying.\n\n    II. Os fatores cognitivos relacionados ao desengajamento\nmoral devem ser incluídos na discussão do fenômeno,\nbem como ser considerados nas propostas de\nintervenção antibullying.    \nIII. O psicólogo escolar deve atuar no ajustamento de\nconduta dos envolvidos nos conflitos escolares.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (desengajamento moral associado a pratica de bullying, com diferencas de genero) e II (fatores cognitivos do desengajamento devem ser incluidos nas intervencoes) sao corretos. III esta errado: 'ajustamento de conduta' e abordagem normalizadora, contraria a perspectiva critica. Apenas I e II = B."}, {"id": "2159523", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que caracteriza a atuação do\npsicólogo escolar na perspectiva crítica.", "alt": {"A": "Avaliação psicológica para fins de classificação e\ntriagem.", "B": "Ajustamento de conduta de jovens infratores.", "C": "Participação de atividades que oferecem apoio\npsicoeducacional à direção da escola", "D": "Realização de psicoterapias na escola.", "E": "Alfabetização dos estudantes com deficiências."}, "g": "C", "j": "C esta correta: na perspectiva critica, a atuacao do psicologo escolar inclui participacao em atividades de apoio psicoeducacional a gestao. A (classificacao/triagem), B (ajustamento), D (psicoterapia na escola) e E (alfabetizar) sao praticas tradicionais ou de outras categorias."}, {"id": "2159522", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando o conceito de medicalização das queixas\nescolares, julgue os itens a seguir.\n    I. A medicalização da educação pode ser entendida pela\nexpansão da jurisdição médica para o âmbito dos\nprocessos educacionais.\n    II. Inquietações, conflitos, tensões e perturbações que\nestudantes experimentam e apresentam no cotidiano\nda sala de aula passam a ser interpretados como\ndoenças, tornando-se a origem do insucesso e do\nfracasso escolar do(a) estudante.    \nIII. A medicalização refere-se ao poder com que a lógica\nbiomédica adentra a escola e determina os padrões de\nnormalidade dentro da vida escolar.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (expansao da jurisdicao medica para processos educacionais), II (inquietacoes interpretadas como doencas, individualizando o fracasso) e III (logica biomedica determinando padroes de normalidade na escola) sao todos consistentes com o conceito de medicalizacao da educacao. Todos = D."}, {"id": "2159520", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa correta sobre a perspectiva sócio- -\nhistórica de ser humano.", "alt": {"A": "É um ser constituído no seu movimento, ao longo do\ntempo, pelas relações sociais, pelas condições sociais e\nculturais engendradas pela humanidade.", "B": "É ser determinado pelas condições fenotípicas e\ngenotípicas.", "C": "O ser humano foi criado para se adaptar ao meio,\ngraças a seus mecanismos biológicos.", "D": "As condições hereditárias são determinantes do\ndesenvolvimento psicológico do ser humano.", "E": "O ser humano é visto de forma naturalizante e\nabstrata."}, "g": "A", "j": "A descreve corretamente a perspectiva socio-historica (Vygotsky): o ser humano se constitui em seu movimento atraves das relacoes sociais e das condicoes socio-culturais. As demais alternativas remetem a determinismo biologico (B, C, D) ou naturalizacao (E)."}, {"id": "2159459", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A Psicologia da Saúde divulga e reforça conhecimentos\nimportantes para auxiliar em uma reforma do atendimento\nde saúde, que se torna um de seus desafios no presente e\nno futuro. Sobre alguns aspectos das mensagens\nfundamentais da Psicologia da Saúde, assinale a alternativa\nincorreta.", "alt": {"A": "A prevenção e a promoção ou manutenção da saúde\ndevem ter um papel tão importante no sistema de\nsaúde quanto o tratamento de doenças possui\natualmente.", "B": "O atendimento de saúde deve ser definido de forma\nmais ampla, para que não se concentre apenas nos\nserviços prestados por médicos, enfermeiros, clínicos e\nhospitais.", "C": "Muitos psicólogos da saúde enfatizam a importância de\nos pacientes assumirem a responsabilidade por seu\npróprio bem-estar, enquanto também reconhecem que\nsão irrelevantes os papéis desempenhados pela família,\npelos amigos e pela comunidade.", "D": "O atendimento de saúde mais eficaz deve reconhecer\nque escolas e locais de oração e trabalho são\nimportantes para promover a saúde e devem se tornar\nparte da rede de serviços interconectados no sistema\nde saúde.", "E": "O importante papel dos psicólogos em melhorar a\nsaúde física aprimorando os resultados de tratamentos\njá foi estabelecido e levou ao aumento significativo no\nnúmero de psicólogos que trabalham em cenários de\natendimento geral de saúde."}, "g": "C", "j": "C esta incorreta: a Psicologia da Saude reconhece a RELEVANCIA dos papeis desempenhados pela familia, amigos e comunidade (modelo biopsicossocial). A alternativa contradiz o paradigma."}, {"id": "2159457", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde da Família", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A ciência da Psicologia da Saúde ainda está em pleno\ndesenvolvimento, mas já traz importantes constatações.\nCom relação aos conhecimentos desenvolvidos e\ndifundidos pela Psicologia da Saúde, assinale a alternativa\nincorreta.", "alt": {"A": "Fatores psicológicos e sociais interagem com a biologia\nna saúde. O comportamento, os processos mentais, as\ninfluências sociais e a saúde estão intimamente\nconectados.", "B": "Promover e manter a saúde é responsabilidade da\nprópria sociedade. A sociedade está se tornando cada\nvez mais consciente em relação à saúde, e, como\nresultado, mais pessoas compreendem que a\nresponsabilidade por sua saúde não está apenas nas\nmãos de profissionais de saúde, mas elas mesmas têm\npapel fundamental em seu bem-estar geral.", "C": "Estilos de vida insalubres são mais difíceis de mudar do\nque de prevenir. Nutrição adequada, boa forma,\nconsumo de bebida responsável e administração\nsaudável do peso corporal, estresse e relacionamentos\nsociais são desafios para a vida que devem começar\nbastante cedo.", "D": "Prevenir que maus hábitos de saúde se desenvolvam\nem primeiro lugar continua a ser uma alta prioridade\nda Psicologia da Saúde.", "E": "A avaliação e o manejo do estresse não possuem\nrelação específica com uma boa saúde."}, "g": "E", "j": "E esta incorreta: a avaliacao e manejo do estresse TEM relacao direta e bem documentada com boa saude - constitui area central da Psicologia da Saude. As demais descrevem corretamente principios do campo."}, {"id": "2159456", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Saúde da Família"], "ano": "2022", "org": "CFP", "t": "", "e": "A demanda por cuidados de saúde envolve múltiplos\nsaberes e fazeres que dizem respeito a conhecimentos e\npráticas de diversos profissionais. Sobre a prática\ninterdisciplinar no trabalho em saúde, assinale a alternativa\nincorreta.", "alt": {"A": "A prática interdisciplinar coloca-se como atenuante da\nintegração que permite uma compreensão ampliada\ndo objeto de trabalho em saúde.", "B": "A participação da Psicologia na área da saúde deverá\npromover a interdisciplinaridade na compreensão do\nsujeito que vivencia o processo saúde-doença.", "C": "A interdisciplinaridade pode proporcionar trocas\ngeneralizadas de informação e críticas, contribuindo\npara reorganizar o meio científico e possibilitar a\ntransformação da instituição em saúde.", "D": "A prática interdisciplinar amplia a formação geral de\npesquisadores das especialidades envolvidas, levando--\nos a reverem seu papel social e as posturas críticas\ndiante das informações recebidas.", "E": "A interdisciplinaridade prepara melhor os indivíduos\npara a formação profissional, garantindo não apenas\numa atuação multiprofissional, mas também uma\nvivência interdisciplinar fundamentada na unicidade do\nconhecimento do humano."}, "g": "A", "j": "A esta incorreta: a pratica interdisciplinar e FACILITADORA da integracao, nao 'atenuante'. A alternativa contradiz o conceito de interdisciplinaridade que justamente promove integracao entre saberes."}, {"id": "2159455", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "A contribuição da Psicologia no contexto da saúde,\nnotadamente no âmbito hospitalar, foi de extrema\nimportância nesses últimos anos para resgatar o ser\nhumano para além de sua dimensão físico-biológica e situá-lo num contexto maior de sentido e significado nas suas\ndimensões psíquica, social e espiritual. A respeito do papel\ndo psicólogo no contexto de humanização em saúde,\nassinale a alternativa correta.", "alt": {"A": "Percebe-se que a humanização hospitalar não\nnecessita de um profissional de Psicologia a serviço dos\npacientes que se encontram internados.", "B": "Com o passar do tempo, os hospitais passaram a\nconsiderar desnecessário o trabalho do psicólogo nas\nenfermarias e nos ambulatórios para atender de forma\nhumanizada os pacientes.", "C": "Como profissional de saúde, o psicólogo deve observar\ne ouvir a linguagem verbal e não verbal dos pacientes,\njá que ele é quem mais pode oferecer, no campo da\nterapêutica humana, a possibilidade de confronto do\npaciente com sua angústia e sofrimento.", "D": "A humanização do atendimento por parte dos\npsicólogos nos hospitais envolve observar aspectos\nligados ao adoecer, sem considerar temores, crenças e\nfragilidades dos pacientes e de seus familiares.", "E": "O trabalho do psicólogo nos hospitais está voltado\nexclusivamente aos pacientes, não sendo apoio aos\nfamiliares que os acompanham ou à equipe de saúde."}, "g": "C", "j": "C descreve corretamente o papel do psicologo no contexto hospitalar humanizado: observar e ouvir a linguagem verbal e nao verbal, oferecendo possibilidade de confronto do paciente com sua angustia. Demais alternativas negam ou restringem o papel da psicologia."}, {"id": "2159453", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Em situações de hospitalização, os pacientes que abordam\no tratamento com atitude otimista, geralmente, se saem\nmelhor após seu fim. Por essa razão, as intervenções\npsicológicas são cada vez mais usadas na preparação dos\npacientes para procedimentos médicos estressantes. Sobre\no tema, assinale a alternativa incorreta.", "alt": {"A": "As intervenções mais eficazes são aquelas que\naumentam a sensação de controle dos pacientes sobre\no tratamento e a recuperação.", "B": "As intervenções de controle informacional\nconcentram-se nos procedimentos e nas sensações\nfísicas que acompanham o tratamento médico. As\ninformações sensoriais permitem fazer uma atribuição\nprecisa das sensações que o paciente de fato\nexperimenta.", "C": "As intervenções de controle cognitivo direcionam a\natenção do paciente para os aspectos positivos de um\nprocedimento em vez de para as sensações de\ndesconforto.", "D": "As intervenções que se atêm ao controle cognitivo\nencorajam os pacientes a redefinirem seu papel, de um\ncorpo imóvel sendo manipulado para de um\nparticipante ativo.", "E": "As intervenções de controle comportamental ensinam\ntécnicas para controlar a dor e acelerar a recuperação\ndurante um procedimento médico e depois dele. Essas\nintervenções podem proporcionar aos pacientes uma\nsensação menor de controle, já que não se concentram\nno procedimento em si."}, "g": "E", "j": "E esta incorreta: as intervencoes de controle comportamental AUMENTAM a sensacao de controle (nao diminuem) ao ensinar tecnicas para manejo da dor e da recuperacao. A alternativa inverte o efeito esperado."}, {"id": "2159452", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2022", "org": "CFP", "t": "", "e": "Historicamente, o bem-estar psicológico do paciente não\ntem sido uma prioridade no tratamento de saúde. Um dos\npontos que merecem atenção a esse respeito são os casos\nque necessitam da hospitalização. Sobre os aspectos\nsubjetivos da hospitalização, assinale a alternativa correta.", "alt": {"A": "Ao entrarem no hospital, as pessoas podem sentir que\nestão sendo absorvidas pelo que foi descrito como\numa “instituição total”, que assume o controle sobre\npraticamente todos os aspectos da vida do paciente.", "B": "A maneira como o paciente se adapta à experiência\nhospitalar independe da natureza do problema de\nsaúde.", "C": "A idade do paciente é uma das variáveis que\ninterferem na adaptação hospitalar. Pacientes adultos\nmais velhos, por exemplo, em geral consideram mais\ndifícil o enfrentamento de condições crônicas do que\nadolescentes e adultos mais jovens.", "D": "Pacientes hospitalizados podem apresentar uma\nvariedade de sintomas psicológicos adversos, mas não\ncostumam tentar atribuir culpa por sua sina.", "E": "Psicólogos da saúde têm verificado que, quanto mais\nos pacientes se preocupam em atribuir culpa por suas\ndoenças a si mesmos ou a outras pessoas, melhor é sua\nadaptação emocional."}, "g": "A", "j": "A descreve corretamente o conceito goffmaniano de 'instituicao total' aplicado ao hospital: assume o controle sobre praticamente todos os aspectos da vida do paciente internado. Demais alternativas trazem afirmacoes incorretas sobre adaptacao hospitalar."}, {"id": "2159451", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação aos modelos de relacionamento entre\npacientes e profissionais, julgue os itens a seguir.    \nI. O modelo tradicional desse relacionamento é\npaternalista, no qual os profissionais tomam o lado\nativo e superior.\n    II. Atualmente, os pacientes estão se tornando mais\nassertivos, insistindo em serem ouvidos e inteiramente\ninformados. Eles são “consumidores bem informados”\nque querem desempenhar um papel mais ativo na\ninteração paciente-profissional de saúde.\n    III. A qualidade do relacionamento entre paciente e\nprofissional com frequência tem impacto direto sobre a\nsaúde. Pacientes satisfeitos com suas consultas, com o\nestilo de comunicação do profissional e com seu\nrelacionamento com ele em geral têm menor\nprobabilidade de seguir as instruções do tratamento.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas o item III está certo.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (modelo tradicional paternalista) e II (pacientes contemporaneos mais assertivos como consumidores informados) sao corretos. III esta errado: pacientes satisfeitos com a comunicacao tem MAIOR probabilidade (nao menor) de seguir instrucoes do tratamento. Apenas I e II = B."}, {"id": "2159450", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A qualidade do relacionamento paciente-profissional\ndesempenha importante papel em promover a adesão do\npaciente às instruções do tratamento. Sobre os fatores que\nafetam o relacionamento entre paciente e profissional da\nsaúde, assinale a alternativa incorreta.", "alt": {"A": "Os elementos centrais do relacionamento entre\npaciente e profissional da saúde são a continuidade do\natendimento, a comunicação e a qualidade geral das\nconsultas.", "B": "As informações trocadas entre médico e paciente\ndurante a consulta não auxiliam a formular\ndiagnósticos e decidir o rumo do tratamento.", "C": "A comunicação eficaz auxilia para que o profissional da\nsaúde entenda os sintomas e as preocupações dos\npacientes e para que o paciente receba as informações\ne as instruções do tratamento.", "D": "Quanto mais tempo os médicos passam com seus\npacientes, mais satisfeitos eles ficam, sobretudo\nquando eles dedicam um tempo para conversar.", "E": "As diferentes origens educacionais e sociais do\npaciente e do profissional da saúde podem ter um\nefeito adverso sobre a comunicação."}, "g": "B", "j": "B esta incorreta: as informacoes trocadas entre medico e paciente durante a consulta AUXILIAM essencialmente na formulacao de diagnosticos e decisoes terapeuticas. A alternativa nega a funcao basica da comunicacao clinica."}, {"id": "2159449", "d": "psicologia", "a": ["Psicologia da Saúde", "Doenças Crônico-Degenerativas", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A adesão ao tratamento é um ponto essencial em casos de\ndoenças crônicas, assim como medidas de prevenção.\nSobre as possíveis intervenções do psicólogo da saúde em\ncasos de doenças crônicas, assinale a alternativa incorreta.", "alt": {"A": "Diversos estudos já relataram os efeitos positivos de\nintervenções para doenças cardiovasculares buscando\nreduzir a raiva e a hostilidade. Uma das estratégias que\nos psicólogos da saúde têm utilizado para ajudar os\nindivíduos a enfrentarem a raiva é o treinamento para\nrelaxamento.", "B": "No cuidado de pessoas com diabetes, o papel do\npsicólogo da saúde é particularmente importante em\nintervenções educacionais, aumentando o\nconhecimento sobre a doença.", "C": "Psicólogos da saúde abordam a questão da adesão ao\ntratamento de doenças crônicas de duas maneiras:\nprocurando identificar os fatores preditivos da adesão\ne da não adesão e desenvolvendo intervenções para\naumentar a adesão a diferentes aspectos do regime de\ntratamento.", "D": "Os psicólogos da saúde têm feito progressos\nconsideráveis no desenvolvimento de intervenções\ncognitivo-comportamentais para um tratamento\nabrangente do câncer, porém não conseguem atuar no\nalívio da dor.", "E": "Os psicólogos da saúde desempenham diversos papéis\nna batalha contra a AIDS, incluindo orientar as pessoas\nsobre como fazer exames para HIV e modificar\ncomportamentos de alto risco."}, "g": "D", "j": "D esta incorreta: psicologos da saude DESEMPENHAM papel ativo no alivio da dor oncologica (intervencoes psicossociais, tecnicas cognitivo-comportamentais, mindfulness, etc.). A alternativa nega area consolidada da psicologia oncologica."}, {"id": "2159448", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a adesão ao tratamento é importante considerar três\ncategorias amplas de variáveis: variáveis do paciente;\nvariáveis do regime de tratamento; e a comunicação entre\npaciente e profissional de saúde. Acerca dessas variáveis,\nassinale a alternativa correta.", "alt": {"A": "Ter o apoio da família e dos amigos não representa um\nfator importante para a adesão ao tratamento.", "B": "Os indivíduos são mais propensos a seguir\nrecomendações nas quais acreditem, mas que não\nsejam capazes de executar sozinhos, privilegiando a ida\nao centro de saúde.", "C": "Programar o tratamento de acordo com o estilo de vida\ndo paciente pode ser uma medida tomada pelos\nprofissionais de saúde para aumentar a adesão ao\ntratamento.", "D": "A qualidade da interação interpessoal entre pacientes\ne profissionais da saúde não influencia diretamente\nnos resultados do tratamento.", "E": "No relacionamento entre o paciente e o profissional, a\nqualidade da comunicação torna-se fator insignificante."}, "g": "C", "j": "C esta correta: programar o tratamento de acordo com o estilo de vida do paciente e estrategia validada para aumentar a adesao. As demais alternativas negam o papel do apoio social, da autoeficacia, da qualidade interpessoal ou da comunicacao."}, {"id": "2159447", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A adesão ao tratamento assume papel importante para a\nsaúde do indivíduo e é um dos setores de atuação do\npsicólogo em saúde. Sobre o tema, assinale a alternativa\nincorreta.", "alt": {"A": "A adesão ao tratamento é definida, de forma ampla,\ncomo seguir a orientação de um profissional de saúde.", "B": "A adesão ao tratamento é uma postura e um\ncomportamento.", "C": "Como postura, a adesão ao tratamento acarreta a\ndisposição de seguir orientações sobre a saúde; como\ncomportamento, está relacionada com o cumprimento\nde determinadas recomendações.", "D": "A falta de adesão inclui recusar-se a seguir instruções\nou não se esforçar para realizar o regime de\ntratamento.", "E": "A falta de adesão ao tratamento não apresenta custos\npotenciais associados a ela."}, "g": "E", "j": "E esta incorreta: a falta de adesao ao tratamento TEM custos potenciais significativos (agravamento, hospitalizacoes evitaveis, custos diretos e indiretos a saude). A alternativa nega evidencias robustas da literatura."}, {"id": "2159445", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Vários fatores demográficos ou socioculturais\ndesempenham importantes funções em determinar se o\nindivíduo procurará atendimento médico, o que representa\num dos campos possíveis de atuação do psicólogo da\nsaúde. Sobre tais fatores, assinale a alternativa incorreta.", "alt": {"A": "De modo geral, as crianças e os idosos usam os serviços\nde saúde com mais frequência que os adolescentes e\nos adultos jovens.", "B": "Um dos fatores que interferem no uso de serviços de\nsaúde é o gênero. Começando na adolescência e\ncontinuando na idade adulta, os homens são mais\npropensos do que as mulheres a relatar sintomas e a\nusar os serviços de saúde.", "C": "Pesquisas relatam que as mulheres são mais sensíveis a\nseus sintomas corporais internos do que os homens e,\nportanto, relatam mais sintomas.", "D": "O status socioeconômico prevê o relato de sintomas e\na procura por atendimento de saúde. Pessoas de renda\nalta geralmente relatam menos sintomas e melhor\nsaúde do que as de renda baixa. Todavia, quando ficam\ndoentes, pessoas de status socioeconômico elevado\ntêm mais probabilidade de procurar atendimento de\nsaúde.", "E": "Os fatores culturais e a etnia também influenciam a\nmaneira como as pessoas respondem a sintomas\nfísicos. Algumas culturas encorajam uma reação forte a\nsintomas, enquanto outras socializam os membros do\ngrupo para que neguem a dor e guardem seus\nsintomas para si mesmos."}, "g": "B", "j": "B esta incorreta: na adolescencia e idade adulta, MULHERES (nao homens) sao mais propensas a relatar sintomas e usar servicos de saude - achado consistente da literatura. A alternativa inverte a relacao."}, {"id": "2159444", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "O estilo explanatório, a saúde psicológica e determinadas\nexperiências prévias também influenciam a maneira como\no indivíduo relata seus sintomas e podem ser ponto de\npartida para a atuação do psicólogo da saúde com o\npaciente. Sobre o assunto, assinale a alternativa incorreta.", "alt": {"A": "Pessoas que têm uma perspectiva mais positiva sobre a\nvida - estilo explanatório otimista - geralmente relatam\nmenos sintomas do que as que são mais negativistas.", "B": "Aquelas pessoas que têm bom estado de humor\napresentam maior saúde autorrelatada e se\nconsideram menos vulneráveis a doenças futuras do\nque as pessoas com mau humor.", "C": "Existe uma comorbidade substancial entre transtornos\npsicológicos e distúrbios físicos, significando que os\nsintomas e as condições físicas e psicológicas ocorrem\nde maneira simultânea.", "D": "Transtornos psicológicos como a ansiedade ou a\ndepressão não podem predispor a distúrbios físicos por\nmeio de vias biológicas, comportamentais, cognitivas e\nsociais.", "E": "A maneira como o indivíduo interpreta os sintomas\ntambém é influenciada por suas experiências prévias e\nexpectativas. Se ele tem uma história familiar ou\npessoal de determinada condição médica, tende a se\npreocupar menos com sintomas conhecidos do que\npessoas sem história da condição."}, "g": "D", "j": "D esta incorreta: transtornos psicologicos como ansiedade e depressao PODEM SIM predispor a disturbios fisicos por vias biologicas (estresse, sistema imune), comportamentais (autocuidado), cognitivas e sociais. A alternativa nega correlato bem estabelecido."}, {"id": "2159442", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde da Família", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Na busca pela saúde, os critérios que as pessoas usam para\nreconhecer e interpretar sintomas variam imensamente.\nPara a Psicologia da Saúde, é importante entender certos\nfatores psicossociais que desempenham um papel\nimportante nesse processo. Sobre esses fatores, assinale a\nalternativa correta.", "alt": {"A": "O foco atencional influencia a percepção dos sintomas\nfísicos. Se a pessoa possuir um forte foco atencional\ninterno sobre seu corpo, emoções e bem-estar, terá\nmenor probabilidade de detectar sintomas e relatá-los\nmais rapidamente.", "B": "Alguns fatores situacionais momentâneos têm impacto\nsubstancial na percepção de um sintoma. As pessoas\ntendem a ser mais conscientes de sensações físicas\nquando estão aborrecidas do que quando estão\nprofundamente envolvidas em uma tarefa.", "C": "O foco da atenção não determina a maneira como as\npessoas enfrentam problemas de saúde e outros\neventos estressantes.", "D": "Quando ameaçados com um evento adverso, os\nindivíduos sensibilizadores evitam e moderam\npsicologicamente suas reações. Pessoas que são\nrepressoras monitoram de forma ativa o evento.", "E": "O foco atencional enfatiza o papel irrelevante que os\nfatores pessoais desempenham na percepção de\nsintomas e na utilização do atendimento de saúde."}, "g": "B", "j": "B esta correta: fatores situacionais momentaneos influenciam a percepcao de sintomas - pessoas aborrecidas/ociosas tem maior consciencia das sensacoes fisicas do que aquelas profundamente envolvidas em uma tarefa (efeito atencional). Demais alternativas invertem ou negam relacoes validas."}, {"id": "2159441", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Os psicólogos da saúde devem defender políticas públicas\nque promovam a justiça social, os direitos humanos e a\nigualdade no acesso a tratamentos de saúde, além de\natuarem nelas. Sobre a relação da psicologia com o Sistema\nÚnico de Saúde (SUS), como proposta por Benevides\n(2005), assinale a alternativa incorreta.", "alt": {"A": "Discute-se a relação da Psicologia com o SUS tomando-se como ponto de partida uma crítica à separação\nentre clínica e política fortemente presente na\nformação e na prática profissional dos psicólogos.", "B": "Indicam-se três princípios para a construção de\npolíticas públicas em saúde: o da inseparabilidade; o da\nautonomia e da corresponsabilidade; e o da\ntransversalidade.", "C": "Constata-se que a contribuição da Psicologia no SUS\npode estar no entrecruzamento do exercício dos três\nprincípios para a construção de políticas públicas em\nsaúde.", "D": "Conclui-se que pensar e fazer políticas de saúde exige\ncriação de espaços de contratualização entre os\ndiversos atores que compõem as redes de saúde, em\nque a Psicologia pode fazer intercessão.", "E": "Indica-se a urgência na criação de dispositivos que\ndeem suporte à Psicologia, desconsiderando o jogo de\nconflito de interesses, desejos e necessidades dos\ndiferentes atores que compõem a rede de saúde."}, "g": "E", "j": "E esta incorreta: dispositivos de suporte a Psicologia no SUS DEVEM considerar (nao desconsiderar) o jogo de conflito de interesses, desejos e necessidades dos diversos atores - principio da contratualizacao/transversalidade defendido por Benevides."}, {"id": "2159440", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "O modelo biopsicossocial da saúde não se limita a\nindivíduos. A pesquisa sobre psicologia da saúde preventiva\ntem se concentrado cada vez mais nos diversos sistemas\nexternos que influenciam a saúde do indivíduo. Sobre o\nassunto, assinale a alternativa correta.", "alt": {"A": "O principal sistema externo que influencia a saúde do\nindivíduo é a família. Os hábitos de saúde costumam ser\nadquiridos dos pais e de outras pessoas que funcionam\ncomo modelos para comportamentos de saúde.", "B": "Pode haver uma base genética para comportamentos\ncomo fumar ou abusar de álcool, o que exclui a\npossibilidade de que as crianças possam adquirir\nexpectativas sobre comportamentos de risco\nobservando seus familiares.", "C": "O sistema de saúde influencia a saúde do indivíduo,\nevidenciando que forças econômicas apoiam os\nesforços de trabalhadores da saúde para promover\nmedidas preventivas.", "D": "As pessoas têm menor probabilidade de adotar\ncomportamentos que promovam a saúde quando eles\nsão defendidos por organizações comunitárias.", "E": "A Psicologia da Saúde concentra-se no indivíduo como\nunidade de intervenção, não abordando aspectos\nculturais, econômicos e comunitários em suas\natuações."}, "g": "A", "j": "A esta correta: a familia e o principal sistema externo que influencia a saude do individuo; os habitos de saude sao adquiridos por modelagem dos pais e cuidadores. Demais alternativas negam ou simplificam essa influencia."}, {"id": "2159439", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Com o avanço das concepções de saúde e do campo de\natuação dos psicólogos, concretizaram-se pesquisas que\ndemonstram a relação entre estilo de vida,\ncomportamentos e saúde. Os psicólogos da saúde\ndesenvolveram teorias para explicar por que as pessoas\npraticam ou não determinados comportamentos de saúde.\nSobre comportamento de saúde e teorias com relação a\neles, assinale a alternativa correta.", "alt": {"A": "Os comportamentos de saúde são comportamentos ou\nhábitos das pessoas para piorar seu estado de saúde.", "B": "Segundo o modelo de crença de saúde, as decisões\nrelacionadas com o comportamento de saúde se\nbaseiam em dois fatores: a suscetibilidade percebida; e\na gravidade percebida de ameaça à saúde.", "C": "A teoria do comportamento planejado prevê o\ncomportamento em saúde com base em três fatores: a\natitude pessoal para com o comportamento; a norma\nsubjetiva em relação ao comportamento; e o grau de\npercepção de controle sobre o comportamento.", "D": "O modelo transteórico sustenta que o comportamento\nrelacionado com a saúde muda sistematicamente ao\nlongo de quatro estágios.", "E": "Os estágios de mudança do modelo transteórico são\ndefinidos em termos de comportamentos passados e\nintenções de ações futuras, e são eles: pré-contemplação; contemplação; ação; manutenção."}, "g": "C", "j": "C descreve corretamente a Teoria do Comportamento Planejado de Ajzen: tres fatores - atitude pessoal, norma subjetiva e controle percebido. A (piorar saude), B (modelo de crenca tem 4 fatores, nao 2), D (transteorico tem 5 estagios, nao 4) e E (lista 4 dos 5 estagios) estao incorretas."}, {"id": "2159438", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde da Família", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando as possibilidades de atuação do psicólogo em\nsaúde, julgue os itens a seguir.\n    I. Elaborar e implementar programas de promoção e\neducação para a saúde.\n    II. Priorizar o desenvolvimento das atividades de pesquisa\ndos processos psicossociais de saúde e doença.    \nIII. Realizar psicodiagnósticos diferenciais (mediante uso\nde testes ou por meio de diagnósticos descritivos\nfenomenológicos).\n      Os itens correspondem, respectivamente, aos níveis de\natenção em saúde:", "alt": {"A": "primário, secundário e terciário.", "B": "primário, terciário e secundário.", "C": "secundário, terciário e primário.", "D": "terciário, secundário e primário.", "E": "terciário, primário e secundário."}, "g": "B", "j": "Mapeamento correto dos niveis: I (programas de promocao e educacao em saude) e atuacao do nivel PRIMARIO; II (pesquisa de processos psicossociais) e atividade do nivel TERCIARIO; III (psicodiagnosticos diferenciais) e do nivel SECUNDARIO. Ordem: primario, terciario, secundario = B."}, {"id": "2159437", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Saúde da Família"], "ano": "2022", "org": "CFP", "t": "", "e": "Os psicólogos podem atuar em diferentes níveis de atenção\nem saúde. Sobre essas possibilidades, assinale a alternativa\nincorreta.", "alt": {"A": "A intervenção do psicólogo na atenção primária à\nsaúde deve priorizar a saúde geral. Sabendo que a\natenção primária é a porta de entrada para todos os\nepisódios relacionados à saúde e à doença, o psicólogo\ndeverá cumprir seu papel acolhendo as pessoas que ali\ncheguem.", "B": "O psicólogo atuante na prevenção secundária tem\ncomo principal objetivo dar acompanhamento ao\npaciente ajudando-o no seguimento de seu\ntratamento, com a intenção de prevenir o\nagravamento da doença.", "C": "A intervenção secundária, em termos da Psicologia,\npossui um fundamento teórico/prático bem\nsedimentado na psicologia clínica. É o campo no qual\nse utilizam as técnicas mais tradicionalmente\ndesenvolvidas, a exemplo da psicoterapia.", "D": "As assistências terciárias, prioritariamente, guiadas\npelas pesquisas dos processos psicossociais de saúde e\ndoença, não englobam cuidados de saúde geral de\npacientes.", "E": "A intervenção de terceiro nível, no âmbito da\nPsicologia da Saúde, tem na pesquisa uma de suas mais\nimportantes atividades."}, "g": "D", "j": "D esta incorreta: as assistencias terciarias ENGLOBAM cuidados de saude geral dos pacientes (reabilitacao, cuidados paliativos, internacoes complexas). A alternativa restringe equivocadamente a atuacao terciaria a pesquisa."}, {"id": "2159436", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Saúde da Família"], "ano": "2022", "org": "CFP", "t": "", "e": "Para a atuação em Psicologia da Saúde é necessário\nreconhecer todo o histórico de mudança na concepção de\nsaúde e doença, além de entender o papel do psicólogo\nnesse campo. Os quatro objetivos da Psicologia da Saúde,\nlevantados por Matarazzo, trazem à tona o papel de quem\natua na área. Sobre esses objetivos, assinale a alternativa\nincorreta.", "alt": {"A": "É objetivo da Psicologia da Saúde estudar de forma\ncientífica as causas e as origens de determinadas\ndoenças, estando os psicólogos da saúde\nprincipalmente interessados nas origens psicológicas,\ncomportamentais e sociais da doença.", "B": "É objetivo da Psicologia da Saúde promover a saúde,\nconsiderando maneiras de fazer as pessoas adotarem\ncomportamentos que promovam a saúde.", "C": "É objetivo da Psicologia da Saúde prevenir e tratar\ndoenças, atuando em programas para ajudar as\npessoas em comportamentos saudáveis.", "D": "Os psicólogos da saúde também auxiliam pessoas que\njá estão doentes em seus esforços para se adaptarem a\nsua doença, mas não englobam intervenções no\ntratamento destas, sendo esse tema de\nresponsabilidade médica.", "E": "É objetivo da Psicologia da Saúde promover políticas de\nsaúde pública e o aprimoramento do sistema de saúde\npública."}, "g": "D", "j": "D esta incorreta: psicologos da saude TAMBEM atuam no tratamento das doencas (nao apenas na adaptacao), conforme o quarto objetivo de Matarazzo. A alternativa restringe equivocadamente a competencia profissional."}, {"id": "2159435", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Diante do surgimento da Psicologia da Saúde e das\nmudanças ocorridas no campo da saúde, novos aspectos\nforam introduzidos na prática do psicólogo que intervêm\nnesse sistema, como: definição de quem é o cliente;\nalteração na relação psicólogo-doente; tempo de\nintervenção. Sobre esses aspectos, assinale a alternativa\ncorreta.", "alt": {"A": "As equipes em que o psicólogo está incluído são mais\namplas e complexas, informadas por conhecimentos\nmais diversificados. É no âmbito da relação com o\nmédico ou outro profissional que o apoio psicológico é\nsolicitado, sendo o profissional que pediu ajuda\ntambém cliente, para além do próprio doente.", "B": "No seio da equipe multidisciplinar, o psicólogo deverá\npartilhar informações sem restrições.", "C": "Os pacientes, quando encaminhados ao psicólogo em\nsaúde, chegam conscientes do serviço e do que ele\nengloba, o que não se diferencia da abordagem da\npsicologia clínica, por exemplo.", "D": "A atuação do psicólogo em saúde não sofre limitações\ncaso esteja sendo realizada em ambiente hospitalar,\nem áreas como enfermarias.", "E": "A atuação do psicólogo em saúde, em seus diversos\nlocais de atendimento, geralmente é longa, podendo\nele acompanhar o paciente por um longo período de\ntempo."}, "g": "A", "j": "A esta correta: na Psicologia da Saude, as equipes sao mais amplas e o profissional que solicita o apoio (medico, enfermeiro) tambem se torna cliente, ao lado do doente. Demais alternativas trazem erros (partilha sem restricoes, equivalencia com clinica, ausencia de limites, longa duracao)."}, {"id": "2159434", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Saúde Coletiva"], "ano": "2022", "org": "CFP", "t": "", "e": "Acompanhando-se a evolução histórica dos conhecimentos\nem saúde, percebe-se que procurar apenas um fator causal\nproduz uma imagem incompleta da saúde e da doença de\numa pessoa. Os psicólogos da saúde trabalham, portanto, a\npartir da perspectiva biopsicossocial. Sobre essa\nperspectiva, assinale a alternativa correta.", "alt": {"A": "Essa perspectiva reconhece que apenas forças\nbiológicas e psicológicas agem em conjunto para\ndeterminar a saúde e a vulnerabilidade do indivíduo à\ndoença.", "B": "Um elemento fundamental do contexto biológico é a\nhistória evolutiva da nossa espécie, e a perspectiva\nevolutiva orienta o trabalho de muitos psicólogos da\nsaúde.", "C": "Os fatores psicológicos desempenham um papel\nimportante na saúde ou na doença do paciente, mas\nisso não é relevante no tratamento de condições\ncrônicas.", "D": "No contexto social, a perspectiva sociocultural\nconsidera como os fatores sociais contribuem para\nsaúde e doença, independentemente de valores e\ncostumes culturais.", "E": "Os aspectos socioculturais desempenham um papel\nirrelevante na variação em crenças e comportamentos\nrelacionados com a saúde."}, "g": "B", "j": "B esta correta: a perspectiva evolutiva (historia evolutiva da especie) e elemento fundamental do contexto biologico que orienta o trabalho de muitos psicologos da saude. As demais alternativas reduzem ou negam fatores essenciais do modelo biopsicossocial."}, {"id": "2159433", "d": "psicologia", "a": ["Psicopatologia", "Semiologia Psiquiátrica e Critérios de Normalidade"], "ano": "2022", "org": "CFP", "t": "", "e": "Com o advento da Psicologia da Saúde, novas visões\nsurgiram a respeito das psicopatologias, de modo a\nconsiderar a subjetividade do paciente. Dentro desse\ncontexto, o conceito de Psicopatologia Fundamental traz\numa nova postura diante do patológico. Sobre o tema,\nassinale a alternativa incorreta.", "alt": {"A": "A posição da Psicopatologia Fundamental é tal que se\ndispõe sempre a escutar um sujeito que porta uma\núnica voz que fale do páthos, que é somático e que\nvem de longe e de fora.", "B": "A Psicopatologia Fundamental é sempre objeto da\ntransferência, ou seja, de um discurso que narra o\nsofrimento e que possui um corpo onde brota, para um\ninterlocutor que, por suposição, seja capaz de\ntransformar, com o sujeito, essa narrativa numa\nexperiência.", "C": "A posição da Psicopatologia Fundamental é assim\ndenominada para se distinguir de uma outra posição,\nque é a da Psicopatologia Geral.", "D": "A Psicopatologia Fundamental está interessada em\nsuscitar uma experiência que seja compartilhada pelo\nsujeito.", "E": "O psicopatólogo fundamental não se interessa pela\nPsicopatologia Geral e não a visita com frequência."}, "g": "E", "j": "E esta incorreta: o psicopatologo fundamental SE INTERESSA pela Psicopatologia Geral e a visita com frequencia - justamente para distinguir-se dela. A alternativa contradiz a propria definicao da posicao da Psicopatologia Fundamental como contraponto a Geral."}, {"id": "2159432", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A Psicologia da Saúde surgiu apoiada nos avanços dos\nestudos no campo da medicina, que perpassaram por três\ncorrentes teóricas que a antecederam: modelo biomédico,\nmedicina psicossomática e medicina comportamental.\nSobre o tema, assinale a alternativa correta.", "alt": {"A": "O modelo biomédico de saúde sustenta que a doença\nsempre tem causas biológicas, pressupondo que a\ndoença seja um resultado de um patógeno.", "B": "O modelo biomédico faz menção às variáveis\npsicológicas na doença, mas não as considera como\nessenciais.", "C": "A medicina psicossomática diz respeito ao diagnóstico\ne ao tratamento de doenças físicas supostamente\ncausadas por processos mentais deficientes e apoiava-se no discurso não reducionista de que um único\nproblema psicológico seria suficiente para desencadear\na doença.", "D": "A medicina comportamental tem sua fonte no\nmovimento behaviorista e começou a explorar o papel\nde comportamentos inatos na saúde e na doença.", "E": "A medicina comportamental é um campo que se apoia\nexclusivamente nas ciências comportamentais para\npromover a saúde e tratar doenças."}, "g": "A", "j": "A esta correta: o modelo biomedico sustenta que a doenca sempre tem causas biologicas (resultado de patogeno). As demais alternativas distorcem o modelo biomedico (B), a medicina psicossomatica (C) ou a medicina comportamental (D e E)."}, {"id": "2159431", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A Psicologia da Saúde marca o interesse da Psicologia pela\nsaúde e pelas doenças não mentais. Algumas das possíveis\nrazões, levantadas por Belar, Deardorff e Kelly (1987, apud\nAlves, 2011), para o surgimento desse interesse são:\n    I. o crescimento da preocupação com a qualidade de vida\ne com a prevenção das doenças;    \nII. a maturidade da investigação nas ciências\ncomportamentais;\n    III. o sucesso do modelo biomédico na explicação das\ndoenças e da saúde.\n      Julgue os itens acima e assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e II estão certos."}, "g": "E", "j": "I (crescimento da preocupacao com qualidade de vida e prevencao) e II (maturidade das ciencias comportamentais) sao razoes validas para o surgimento da Psicologia da Saude. III esta errado: foi justamente a INSATISFACAO com o modelo biomedico (nao seu sucesso) que motivou o surgimento da Psicologia da Saude. Apenas I e II = E."}, {"id": "2159430", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Saúde da Família", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A Psicologia da Saúde emergiu na década de 1970, em uma\népoca de grandes alterações políticas, sociais, econômicas e\nculturais. Sobre os desdobramentos iniciais desse ramo da\nPsicologia, assinale a alternativa incorreta.", "alt": {"A": "A Psicologia da Saúde abre a Psicologia para dois\ncampos até então pouco considerados: a saúde como\ndimensão diferente das doenças e as doenças físicas\ncomo campo diferente do das doenças mentais.", "B": "Stone, em 1979, traz a primeira definição de Psicologia\nda Saúde como qualquer aplicação científica ou\nprofissional de conceitos e métodos psicológicos a\ntodas as situações próprias do campo da saúde.", "C": "A definição de Stone (1979) foi base para a definição\nclássica de Matarazzo (1980), que afirmava que a\nPsicologia da Saúde consiste no domínio da Psicologia\nque recorre aos conhecimentos provenientes das\ndiversas áreas da Psicologia com vistas à promoção e à\nproteção da saúde, evitando atuar no tratamento das\ndoenças.", "D": "O interesse da Psicologia pelos ambientes tradicionais\nde saúde e doença é paralelo ao desenvolvimento da\nconsciência acerca do papel do comportamento na\nsaúde e nas doenças mais comuns.", "E": "Uma das características da Psicologia da Saúde, para\nalém de focar o seu interesse nos aspectos de saúde e\nde doenças não mentais, é também a deslocação da\natenção do polo “doença” para o polo “saúde”."}, "g": "C", "j": "C esta incorreta: a definicao classica de Matarazzo (1980) INCLUI tratamento das doencas como objetivo da Psicologia da Saude - nao 'evita atuar no tratamento'. A alternativa adultera o conceito original."}, {"id": "2159329", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a substâncias", "Psicofarmacologia", "Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "O uso de substâncias que possuam efeitos sobre as funções\ncognitivas é bastante estudado, considerando-se seus\nimpactos para a condução veicular segura. Dentre as\ndescrições apresentadas, assinale a incorreta.", "alt": {"A": "O uso de cocaína pode gerar perda de atenção e\nconcentração", "B": "A Cannabis influencia a percepção e a performance\npsicomotora dos motoristas.", "C": "A anfetamina pode suscitar aumento de\ncomportamentos de risco devido à sensação de maior\nautoconfiança.", "D": "O efeito da cocaína sobre o condutor pode estimular os\ncomportamentos de riscos ao volante.", "E": "Os antidepressivos podem tornar os condutores mais\nagressivos na condução e algumas vezes provocam\nsono."}, "g": "E", "j": "E esta incorreta: antidepressivos geralmente tornam os condutores SONOLENTOS/ATENCIONALMENTE COMPROMETIDOS, nao agressivos. A agressividade nao e efeito tipico desses farmacos. Demais alternativas descrevem corretamente os efeitos cognitivos das substancias."}, {"id": "2159328", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Neto e Gunther (2015), os mecanismos\npsicológicos subjacentes ao ato de justificar os\ncomportamentos infracionais são estudos de algumas\nteorias da psicologia social. Assinale a alternativa incorreta.", "alt": {"A": "As justificativas são atribuídas para reduzir o\ndesconforto interno, sobretudo na percepção de\ncomportamentos aceitáveis.", "B": "As pessoas têm a tendência de explicar o\ncomportamento infrator e atribuir causas a ele,\nsegundo a teoria de atribuição da causalidade.", "C": "A teoria social cognitiva considera que as pessoas se\ncomportam da maneira que lhes proporcionem\nsatisfação pessoal, evitando violar padrões morais.", "D": "No contexto do trânsito, estudos indicam a justificativa\nde causas e determinantes situacionais para explicar\nseus comportamentos, mesmo que não condigam com\na realidade.", "E": "O desengajamento moral pode fazer com que o\ncondutor busque tornar pessoais e socialmente\naceitáveis as práticas prejudiciais no trânsito."}, "g": "A", "j": "A esta incorreta: as justificativas sao atribuidas para reduzir desconforto interno (dissonancia cognitiva) na percepcao de comportamentos INACEITAVEIS (transgressores), nao aceitaveis. A alternativa inverte a logica do mecanismo psicologico."}, {"id": "2159327", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre o Plano Nacional de Redução de Mortes e Lesões no\nTrânsito, julgue os itens a seguir.\n    I. Foi elaborado em conjunto pelos órgãos de saúde, de\ntrânsito, de transporte e de justiça. Traz as diretrizes\npara que o país reduza, no mínimo à metade, o índice\nnacional de mortos por grupo de veículos e o índice\nnacional de mortos por grupo de habitantes.\n    II. Constitui-se como um passo adiante na resolução de\nproblemas relacionados à infraestrutura viária\nbrasileira, à organização e ao alinhamento dos órgãos\ndo Sistema Nacional de Trânsito, à mobilidade urbana\ne à convivência harmoniosa entre pedestres, ciclistas,\nmotociclistas, entre outros aspectos.\n    III. Coaduna-se às ações positivas já existentes em torno\nda segurança viária, porém dá um passo adiante ao\npropor que iniciativas em torno da matéria estejam\npautadas em oito pilares fundamentais para o\ndesenvolvimento das propostas.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens II e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (elaboracao conjunta orgaos saude/transito/justica e diretrizes de reducao), II (avanco em infraestrutura, organizacao SNT, mobilidade) e III (oito pilares fundamentais) sao todos consistentes com o Plano Nacional de Reducao de Mortes e Lesoes no Transito. Todos = D."}, {"id": "2159323", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando que a perícia psicológica pode ser descrita,\nsegundo Cruz (2017), como “uma avaliação descritiva e\nconclusiva acerca de fatos, situações ou problemas que\nexijam juízo crítico por parte dos psicólogos, sobre matéria\nde psicologia, cujo conteúdo deverá certificar a medida da\ninvestigação realizada”, assinale a alternativa incorreta.", "alt": {"A": "Toda perícia psicológica é uma avaliação psicológica\nrealizada para fins específicos.", "B": "No contexto judicial, a perícia psicológica é\nconsiderada uma prova técnica.", "C": "A perícia psicológica é uma modalidade de avaliação\npsicológica.", "D": "A perícia psicológica no trânsito não possui natureza\nadministrativa.", "E": "Na perícia psicológica no contexto do trânsito, a prática\ntem se restringido ao seu valor preditivo instrumental."}, "g": "D", "j": "D esta incorreta: a pericia psicologica no transito TEM natureza administrativa (e parte do processo administrativo de obtencao/renovacao da CNH), nao judicial. A alternativa nega caracteristica essencial dessa modalidade."}, {"id": "2159321", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação à atuação do profissional na psicologia do\ntrânsito, julgue os itens a seguir.\n    I. As intervenções, por mais simples que sejam, devem\nser fundamentadas nos dados obtidos e no\nplanejamento criterioso. Isso dará base para a\navaliação e a interpretação da intervenção.\nAdicionalmente, os psicólogos devem preocupar-se\ntambém com questões de poder, liberdade e\nresponsabilidade ética dos resultados de suas\nintervenções.\n    II. A prática do psicólogo do trânsito e do transporte pode\nser bastante variada a depender de fatores, tais como\no foco, o setor (de educação de trânsito, de\ninfraestrutura de transporte, da organização não\ngovernamental etc.) ou o tipo de serviço em que\ntrabalha (clínica, gestão de pessoas, fiscalização de\ntrânsito etc.).\n    III. Entender as complexas relações que ocorrem no\ntrânsito e no transporte é uma tarefa desafiadora por\nenvolver mais do que o “simples” deslocamento. Isso\nporque o sistema trânsito e transporte é uma\nconstrução humana, social, portanto intencional. Como\nconsequência, o sistema influenciará e será\ninfluenciado por aspectos individuais, ambientais,\nsociais, econômicos, políticos, culturais e históricos que\no psicólogo do trânsito deve considerar.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (intervencoes fundamentadas em dados/planejamento com atencao etica), II (pratica variada conforme foco/setor) e III (transito como construcao humana e social influenciada por multiplos aspectos) sao todos consistentes com a literatura da area. Todos = D."}, {"id": "2159315", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que está em desacordo com o que\nestabelece a Resolução nº 425/2012, do CONTRAN,\nreferente aos resultados da avaliação psicológica do\ncandidato à obtenção da CNH ou do condutor de veículos\nautomotores.", "alt": {"A": "O avaliado será considerado apto com restrição\nquando não apresentar desempenho condizente para a\ncondução de veículo automotor, porém passível de\nadequação.", "B": "O resultado da avaliação psicológica deverá ser\ndisponibilizado pelo psicólogo no prazo de dois dias\núteis.", "C": "O resultado de inapto temporário constará em sistema\ne consignará o prazo de inaptidão, findo o qual deverá\no candidato ser submetido a nova avaliação\npsicológica.", "D": "Quando apresentar distúrbios ou comprometimentos\npsicológicos que estejam temporariamente sob\ncontrole, o candidato será considerado apto, com\ndiminuição do prazo de validade da avaliação.", "E": "Os resultados de inaptidão temporária ou inaptidão\ndeverão ser comunicados para o imediato bloqueio do\ncadastro nacional, competindo a esse órgão executivo\nde trânsito o devido desbloqueio no vencimento do\nprazo."}, "g": "A", "j": "A esta em desacordo com a Res CONTRAN 425/2012: o status APTO COM RESTRICAO aplica-se quando o avaliado apresenta desempenho condizente COM restricoes especificas de uso (lentes corretivas, horario diurno etc.) - nao por nao apresentar desempenho condizente. A alternativa inverte o conceito."}, {"id": "2159314", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo do trânsito, dentro do que\nestabelece a Resolução CFP nº 016/2002, assinale a\nalternativa incorreta.", "alt": {"A": "O CFP considera importante que todas as avaliações\npsicológicas sejam distribuídas imparcialmente, por\nmeio de divisão equitativa, aleatória e impessoal, entre\nas entidades credenciadas na área de jurisdição do\nórgão executivo do trânsito.", "B": "Os exames de sanidade física e mental para fins da\nCarteira Nacional de Habilitação (CNH) poderão ser\nrealizados nos mesmos locais da realização das\navaliações psicológicas para candidatos à CNH e\ncondutores de veículos automotores.", "C": "A Avaliação Psicológica de Candidatos à Carteira\nNacional de Habilitação e condutores de veículos\nautomotores poderá ser realizada em centros de\nformação de condutores.", "D": "Aos psicólogos peritos responsáveis pela avaliação\npsicológica fica vedado estabelecer qualquer vínculo\ncom os Centros de Formação de Condutores, seja\ncomo pessoa física, seja como jurídica.", "E": "O CFP considera necessárias a normatização e a\nqualificação de procedimentos relacionados à prática\nda avaliação psicológica de candidatos à CNH e de\ncondutores de veículos automotores."}, "g": "C", "j": "C esta incorreta: a Resolucao CFP 016/2002 VEDA a realizacao da Avaliacao Psicologica de candidatos a CNH em centros de formacao de condutores - deve ser feita em local independente para garantir imparcialidade."}, {"id": "2159312", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa em que há desvio no entendimento\nacerca da responsabilidade e da ética dos profissionais da\nPsicologia.", "alt": {"A": "Prestar serviços psicológicos de qualidade, em\ncondições de trabalho dignas e apropriadas à natureza\ndesses serviços, utilizando princípios, conhecimentos e\ntécnicas reconhecidamente fundamentados na ciência\npsicológica, na ética e na legislação profissional.", "B": "Orientar quem de direito sobre os encaminhamentos\napropriados, a partir da prestação de serviços\npsicológicos, e fornecer, sempre que solicitado, os\ndocumentos pertinentes ao bom termo do trabalho.", "C": "Oferecer serviços profissionais em situações de\ncalamidade pública ou de emergência, para divulgar a\nPsicologia e ampliar o mercado de trabalho.", "D": "Sugerir serviços de outros psicólogos, sempre que, por\nmotivos justificáveis, não puderem ser continuados\npelo profissional que os assumiu inicialmente,\nfornecendo este ao substituto as informações\nnecessárias à continuidade do trabalho.", "E": "Levar ao conhecimento das instâncias competentes o\nexercício ilegal ou irregular da profissão e as\ntransgressões a princípios e diretrizes do Código de\nÉtica ou da legislação profissional."}, "g": "C", "j": "C representa desvio etico: oferecer servicos em calamidade publica/emergencia 'para divulgar a Psicologia e ampliar mercado' contraria os principios eticos - tais servicos devem ser oferecidos pela responsabilidade social, nao por interesses promocionais/mercadologicos."}, {"id": "2159310", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que não corresponde a uma\nespecialidade da Psicologia reconhecida pelo Conselho\nFederal de Psicologia.", "alt": {"A": "Psicologia do trânsito.", "B": "Psicopedagogia.", "C": "Psicomotricidade.", "D": "Psicoterapia.", "E": "Avaliação psicológica."}, "g": "D", "j": "D esta correta: PSICOTERAPIA nao e especialidade reconhecida pelo CFP - e pratica de qualquer psicologo formado. Sao especialidades reconhecidas: Psicologia do Transito, Psicopedagogia, Psicomotricidade, Avaliacao Psicologica, entre outras."}, {"id": "2159309", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca da atuação do psicólogo do trânsito, julgue os itens\na seguir.    \nI. O psicólogo do trânsito pode prestar assessoria e\nconsultoria a órgãos públicos e privados nas questões\nrelacionadas ao trânsito e transporte.    \nII. O psicólogo do trânsito realiza diagnóstico da estrutura\ndinâmica de indivíduos e grupos nos aspectos afetivos,\ncognitivos e comportamentais.\n    III. O psicólogo do trânsito, no uso de suas atribuições,\npoderá colaborar na elaboração e na implantação de\nações de engenharia e operação de tráfego.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (assessoria e consultoria a orgaos publicos e privados), II (diagnostico da estrutura dinamica de individuos/grupos nos aspectos afetivos, cognitivos e comportamentais) e III (colaboracao em engenharia e operacao de trafego) sao todos atribuicoes legitimas do psicologo do transito. Todos = E."}, {"id": "2159307", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "A psicóloga na realização da avaliação psicológica deve\nutilizar métodos, técnicas e/ou instrumentos psicológicos\ncientificamente reconhecidos. Nesse contexto, há fontes de\ninformação fundamentais e complementares. Assinale a\nalternativa em que não se aplicam as fontes de informação.", "alt": {"A": "Relatórios de equipes multiprofissionais.", "B": "Anamnese.", "C": "Entrevistas psicológicas.", "D": "Relatos da comunidade sobre o comportamento do\navaliado.", "E": "Protocolos de observação comportamental."}, "g": "D", "j": "D NAO se aplica como fonte de informacao da avaliacao psicologica: relatos da COMUNIDADE sobre o avaliado nao integram as fontes tecnicas validas (entrevistas, anamnese, testes, observacao, relatorios multiprofissionais). Demais alternativas sao fontes legitimas."}, {"id": "2159306", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Em qual alternativa a atuação do psicólogo do trânsito para a\npromoção da saúde e a preservação da vida no trânsito não\nestá coerente? O psicólogo do trânsito:", "alt": {"A": "pode atuar na proposição de medidas interventivas ao\npoder público para a promoção da saúde.", "B": "deve buscar estimular a aquisição da CNH pelos jovens.", "C": "pode identificar sinais de saúde e encaminhar os\ncandidatos aos devidos cuidados.", "D": "deve ser imparcial e ético, buscando avaliar os riscos para\na sociedade.", "E": "pode atuar de forma a orientar os atores no trânsito a\ncomportamentos seguros e preventivos."}, "g": "B", "j": "B NAO e coerente com a atuacao para promocao da saude e preservacao da vida: estimular AQUISICAO da CNH pelos jovens nao e papel do psicologo do transito (essa nao e uma intervencao em saude/seguranca). Demais alternativas descrevem condutas legitimas."}, {"id": "2159305", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "O psicólogo do trânsito, em sua atuação, deve sempre\nelaborar documento psicológico após a conclusão do processo\nde avaliação psicológica. Acerca das modalidades de\ndocumentos psicológicos escritos que podem ser elaborados\npelo profissional da psicologia, assinale a alternativa incorreta.", "alt": {"A": "Laudo psicológico.", "B": "Atestado psicológico.", "C": "Parecer de saúde mental.", "D": "Relatório multiprofissional.", "E": "Declaração."}, "g": "C", "j": "C esta incorreta: 'Parecer de saude mental' NAO e modalidade de documento psicologico definida na Res CFP 06/2019. Modalidades reconhecidas: declaracao, atestado psicologico, relatorio (ou laudo) psicologico e parecer psicologico."}, {"id": "2159304", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando a elaboração de documentos escritos\nproduzidos pelo psicólogo no exercício profissional, julgue os\nitens a seguir.    \nI. O psicólogo, ao redigir o documento psicológico, deve\nexpressar-se de maneira coloquial, para a compreensão\nde todos, descrevendo todo o processo do atendimento\nrealizado, além de expor o raciocínio psicológico\nresultante da sua atuação profissional.    \nII. O documento psicológico é um instrumento de\ncomunicação escrita resultante da prestação de um\nserviço psicológico a pessoa, grupo ou instituição.    \nIII. É dever do psicólogo elaborar e fornecer documentos\npsicológicos sempre que solicitado ou quando finalizado\num processo de avaliação psicológica.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item II está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Todos ositens estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I esta errado: a Res CFP 06/2019 exige linguagem TECNICA, clara e objetiva - nao 'coloquial'. II (documento como instrumento de comunicacao escrita) e III (dever de elaborar quando solicitado/apos avaliacao) sao corretos. Apenas II e III = C."}, {"id": "2159303", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que não caracteriza a atuação do\npsicólogo do trânsito.", "alt": {"A": "Desenvolvimento de ações socioeducativas.", "B": "Realização de pesquisas científicas.", "C": "Atuação como perito em exames de readaptação\nprofissional.", "D": "Realização de treinamento de direção veicular.", "E": "Avaliação psicológica."}, "g": "D", "j": "D NAO caracteriza atuacao do psicologo do transito: treinamento de direcao veicular e atribuicao de instrutores de auto-escola/Centros de Formacao de Condutores, nao do psicologo. Demais (acoes socioeducativas, pesquisa, pericia, avaliacao) sao atribuicoes legitimas."}, {"id": "2159302", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação psicológica é a única atividade privativa das\npsicólogas e dos psicólogos. Segundo Barros (2019), ao longo\ndos anos, a área vem evoluindo na qualidade dos\ninstrumentos e das garantias científicas deles, mas, como se\npode analisar a questão da inclusão? Assinale a alternativa que\nnão está correta no que concerne aos procedimentos ou aos\ncuidados para a avaliação psicológica da pessoa surda.", "alt": {"A": "Deve ser utilizada uma abordagem de avaliação\npsicometricamente justa, compreensiva e apropriada às\npessoas com deficiência.", "B": "A psicóloga deve verificar se existem normas específicas\npara surdos ou se foram realizados estudos psicométricos\npara analisar diferenças entre ouvintes e surdos.", "C": "Na ausência de instrumentos adequados para a\npopulação com surdez, é fundamental utilizar outros\nrecursos que fazem parte dos processos de avaliação\npsicológica.", "D": "Uma dificuldade para a atuação profissional é decorrente\nda falta de sinais para os termos comuns da Psicologia,\nreforçando a necessidade de usar o tecnicismo na\ncomunicação com os surdos.", "E": "É fundamental seguir os parâmetros éticos da profissão,\nutilizando os recursos disponíveis, que tenham evidências\nde funcionalidade, respeitem as especificidades próprias\nda deficiência e estejam alinhados às perspectivas de\ngarantias dos direitos humanos, por meio de práticas\ninclusivas."}, "g": "D", "j": "D NAO esta correta: a abordagem com pessoas surdas exige linguagem ADEQUADA E ACESSIVEL (uso de Libras quando possivel, intermediacao com interprete), nao o uso de TECNICISMO - o tecnicismo dificulta a compreensao e contraria a logica inclusiva. Demais alternativas descrevem cuidados validos."}, {"id": "2159301", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "Ao considerar as diretrizes básicas para a realização de\navaliação psicológica no exercício profissional do psicólogo,\ndescritas na Resolução CFP nº 09/2018, assinale a alternativa\nque corresponde à concepção incorreta sobre esse assunto.", "alt": {"A": "Os testes psicológicos abarcam também os seguintes\ninstrumentos: escalas, inventários, questionários e\nmétodos projetivos/expressivos.", "B": "A avaliação psicológica é definida como um processo não\nestruturado de investigação de fenômenos psicológicos,\ncomposto de métodos, técnicas e instrumentos, com o\nobjetivo de prover informações à tomada de decisão, no\nâmbito individual, grupal ou institucional, com base em\ndemandas, condições e finalidades específicas.", "C": "Na hipótese de dúvida acerca da classificação do\ninstrumento (teste psicológico ou instrumento não\npsicológico), ficam legitimados os Conselhos Regionais de\nPsicologia (CRPs) a submeter o respectivo instrumento à\nComissão Consultiva em Avaliação Psicológica (CCAP) do\nCFP para apreciação.", "D": "A psicóloga e o psicólogo têm a prerrogativa de decidir\nquais são os métodos, as técnicas e os instrumentos\nempregados na Avaliação Psicológica, desde que\ndevidamente fundamentados na literatura científica\npsicológica e nas normativas vigentes do Conselho\nFederal de Psicologia (CFP).", "E": "Na realização da avaliação psicológica, a psicóloga e o\npsicólogo devem basear sua decisão, obrigatoriamente,\nem métodos e/ou técnicas e/ou instrumentos\npsicológicos reconhecidos cientificamente para uso na\nprática profissional da psicóloga e do psicólogo."}, "g": "B", "j": "B esta incorreta: a Res CFP 09/2018 define a avaliacao psicologica como processo ESTRUTURADO (nao 'nao estruturado') de investigacao de fenomenos psicologicos. A alternativa contradiz a definicao normativa."}, {"id": "2159264", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre os deveres do psicólogo esportivo, julgue os itens a\nseguir.\n    I. Prestar serviços psicológicos: consultas e/ou\natendimentos psicológicos de diferentes tipos de\nmaneira síncrona ou assíncrona; fazer uso de\ninstrumentos psicológicos devidamente\nregulamentados por resoluções pertinentes e com\nparecer favorável do Sistema de Avaliação de\nInstrumentos Psicológicos (SATEPSI); e a supervisão\ntécnica dos serviços prestados por psicólogas e\npsicólogos nos mais diversos contextos (Conselho\nFederal de Psicologia, 2018).\n    II. A utilização de métodos e técnicas psicológicas é de\natribuição, privativa, da(o) psicóloga(o), tendo como\nbase os objetivos previstos no parágrafo 1º, do artigo\n13, da Lei nº 4.119, de 27 de agosto de 1962, e no\nartigo 4º, do Decreto nº 53.464/1964. Os instrumentos\nutilizados nas avaliações são aqueles que devem ser\nreconhecidos/aprovados pelo Conselho Federal de\nPsicologia (Conselho Federal de Psicologia, 2018).    III. A Resolução CFP 01/2018 estabelece normas de\natuação para as psicólogas e os psicólogos em relação\nàs pessoas transexuais e travestis. É papel da(o)\npsicóloga(o) utilizar seu conhecimento científico para\nfortalecer a transfobia e o preconceito em relação às\npessoas transexuais e travestis. Então o profissional\ndeve colaborar, bem como utilizar de instrumentos ou\ntécnicas que criam, mantenham e reforcem o\npreconceito, estigma, estereótipos e discriminação em\nrelação a esse grupo populacional (Conselho Federal de\nPsicologia, 2018).\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas o item III está certo.", "E": "Apenas os itens II e III estão certos."}, "g": "B", "j": "I (prestar servicos psicologicos com instrumentos com parecer SATEPSI) e II (atribuicao privativa conforme Lei 4.119/62 e Decreto 53.464/64) sao corretos. III esta CLARAMENTE errado: a Res CFP 01/2018 PROIBE (nao autoriza) o uso de conhecimento psicologico para fortalecer transfobia. Apenas I e II = B."}, {"id": "2159263", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "O biofeedback é uma técnica em que:", "alt": {"A": "se aprende o controle voluntário de funções\nfisiológicas das quais as pessoas não têm consciência.", "B": "se aprende o controle involuntário de funções\nfisiológicas das quais as pessoas têm consciência.", "C": "o controle voluntário aumenta o conteúdo reforçador\ndas interpretações limitantes dos estímulos.", "D": "o controle voluntário diminui o conteúdo reforçador\ndas interpretações limitantes dos estímulos.", "E": "o controle voluntário estabiliza o conteúdo reforçador\ndas interpretações limitantes dos estímulos."}, "g": "A", "j": "A esta correta: biofeedback e tecnica em que o individuo aprende o CONTROLE VOLUNTARIO de funcoes fisiologicas das quais normalmente nao tem consciencia (frequencia cardiaca, tensao muscular etc.), atraves de monitoramento e feedback continuo."}, {"id": "2159261", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que não caracteriza a atuação do\npsicólogo esportivo com grupos esportivos.", "alt": {"A": "Realizar sociometria.", "B": "Analisar as relações de vínculo.", "C": "Estimular a construção de valores sociais.", "D": "Orientar pais.", "E": "Fazer avaliação psicossexual dos atletas."}, "g": "E", "j": "E NAO caracteriza atuacao do psicologo esportivo com grupos: 'avaliacao psicossexual dos atletas' nao e procedimento padrao da area e nao se justifica no contexto esportivo. Demais alternativas (sociometria, analise de vinculos, valores sociais, orientacao a pais) sao praticas legitimas."}, {"id": "2159260", "d": "psicologia", "a": ["Trabalho em Equipe", "Grupos e Equipes"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Barbosa et al. (2019), os lugares, a segurança e a\nmanutenção dos profissionais de psicologia do esporte\nestão ainda por ser efetivamente entendidos e demarcados\nem sua importância e funcionalidade dentro das equipes de\ntrabalho. Existe enorme preocupação com a\nempregabilidade e a partir dela uma busca maior ainda pela\nqualificação e pela capacitação profissional. Assinale a\nalternativa correta.", "alt": {"A": "O papel do psicólogo esportivo é clínico, tendo a\nfunção de aplicar testes de personalidade e obter\nquocientes de inteligência de modo a entender os\nproblemas que inviabilizam o desempenho esportivo.", "B": "A principal função do psicólogo esportivo é a de ser\nmediador de conflitos, resolvendo as questões\ncomportamentais daqueles que não se encaixam em\npadrões esperados.", "C": "A observação comportamental e o aconselhamento\nsão as atividades centrais de um psicólogo esportivo,\nque deve atuar a partir da demanda delineada pela\ncomissão técnica.", "D": "O psicólogo, para ingressar em uma organização,\nassociar-se a ela ou permanecer nela, considerará a\nmissão, a filosofia, as políticas, as normas e as práticas\nnela vigentes e sua compatibilidade com os princípios e\nas regras do Código de Ética profissional.", "E": "O psicólogo, ao promover publicamente seus serviços,\npor quaisquer meios, individual ou coletivamente, não\ninformará o CRP e seu número de registro."}, "g": "D", "j": "D esta correta: o psicologo, ao ingressar em uma organizacao, deve considerar missao, filosofia, politicas, normas e praticas vigentes e sua compatibilidade com o Codigo de Etica. Demais alternativas reduzem a clinica/testes (A), mediacao (B), aconselhamento (C) ou negam dever etico (E)."}, {"id": "2159259", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Com o envelhecimento populacional, o Brasil e o mundo\nprecisam preparar os profissionais da saúde para identificar\nprecocemente os indivíduos com comprometimento\ncognitivo e encaminhá-los para avaliação especializada. A\navaliação breve, ou de rastreio, deve fazer parte de\nacademias, instituições de reabilitação de doenças crônicas,\nentre outras. Qual é o protocolo de avaliação indicado\nantes do início da prática de atividade física?", "alt": {"A": "BRUMS (Escala de Humor de Brunel).", "B": "MEEM (Miniexame do Estado Mental).", "C": "RESTQ – SPORT (Questionário de estresse e\nrecuperação).", "D": "BGFM-3 (Bateria Geral de Funções Mentais).", "E": "DFH (Desenho da Figura Humana)."}, "g": "B", "j": "O Miniexame do Estado Mental (MEEM) e o protocolo de RASTREIO COGNITIVO classicamente indicado para identificar comprometimento cognitivo em idosos antes da pratica de atividade fisica. BRUMS (humor), RESTQ-SPORT (estresse), BGFM-3 (funcoes mentais ampla) e DFH nao sao especificos para rastreio cognitivo breve."}, {"id": "2159257", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a traumas e estressores"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto ao estresse, assinale a alternativa correta.", "alt": {"A": "Disforia e euforia são tipos de estresse.", "B": "Distress e tristeza são tipos de estresse.", "C": "Eustress e disforia são tipos de estresse.", "D": "Eustress e distress são tipos de estresse.", "E": "Euforia e distress são tipos de estresse."}, "g": "D", "j": "D esta correta: Hans Selye distinguiu dois tipos de estresse - EUSTRESS (estresse positivo, motivador, adaptativo) e DISTRESS (estresse negativo, desadaptativo, prejudicial). Demais alternativas misturam emocoes (disforia, euforia, tristeza) com tipos de estresse."}, {"id": "2159254", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Qual das seguintes atuações insere-se na prática\nprofissional do psicólogo do esporte?", "alt": {"A": "Orientar a ingesta de alimentos.", "B": "Analisar lesão de atleta.", "C": "Mediar relação entre técnicos e instituições esportivas.", "D": "Coordenar projeto pedagógico da equipe esportiva.", "E": "Avaliar história de vida dos atletas."}, "g": "E", "j": "E e a unica pratica que se insere legitimamente na atuacao do psicologo do esporte: avaliar a historia de vida dos atletas (anamnese esportiva). As demais sao atribuicoes de outras areas: nutricao (A), fisioterapia (B), gestao esportiva (C), pedagogia (D)."}, {"id": "2159253", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Crianças e adolescentes praticam esportes e exercícios\nfísicos em diversos contextos: escola, clubes, locais\ndesignados por ONGs que promovem atividades\ndenominadas de esporte educacional, projetos sociais\nesportivos, equipes de competição, seletivas para\ncampeonatos nacionais e internacionais, entre outros.\nDentre as atividades oferecidas a essas populações, alguns\nefeitos são possíveis, assim como processos específicos no\nambiente esportivo. Assinale a alternativa incorreta.", "alt": {"A": "Especialização precoce, lazer e recreação e educação\nfísica escolar.", "B": "TLP, TGO, TGP e formação esportiva.", "C": "TLP, especialização esportiva e promoção de talento.", "D": "Overtraining, burn-out e drop-out.", "E": "Fair-play, esporte educacional, cooperação e\ncompetição e formação integral."}, "g": "B", "j": "B esta incorreta: TGO e TGP sao exames de funcao hepatica (transaminases), nao conceitos da Psicologia do Esporte. A alternativa mistura abreviacoes medicas com tematicas esportivas, configurando combinacao indevida."}, {"id": "2159252", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "No contexto do esporte de rendimento, a atuação do\npsicólogo tem diversas atribuições. Sobre elas, assinale a\nalternativa incorreta.", "alt": {"A": "Participar de treinamentos, competições e viagens em\ncooperação com as demais áreas profissionais, estando\nà disposição para ações planejadas ou demandas\nsituacionais.", "B": "Elaborar testes e questionários de acordo com os\ninteresses da comissão técnica para informar quais\natletas têm o perfil vencedor ou não.", "C": "Realizar dinâmicas, oficinas, workshops ou demais\natividades relativas a temas do ambiente competitivo.", "D": "Identificar demandas e criar estratégias de\npsicoeducação a fim de fortalecer a preparação mental\nde atletas diante de desafios ou reveses.", "E": "Fazer preparação psicológica utilizando técnicas\nconhecidas como visualização, relaxamento,\nestabelecimento de metas, controle de ativação, uso\nde diálogo interno, autofala, entre outros."}, "g": "B", "j": "B esta incorreta: o psicologo do esporte NAO deve classificar atletas em 'perfil vencedor ou nao' - tal pratica e reducionista, estigmatizante e contraria aos principios eticos. Demais alternativas descrevem atribuicoes legitimas no esporte de rendimento."}, {"id": "2159251", "d": "psicologia", "a": ["Psicoterapias", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "O perfeccionismo é considerado pela Terapia Cognitivo- -\nComportamental (TCC):", "alt": {"A": "generalização baseada em uma única tentativa.", "B": "o caráter consciente da supressão de um afeto.", "C": "o comportamento operante em simulação de esportes.", "D": "crenças que provocam efeitos no desempenho.", "E": "a ambivalência pela presença simultânea de ideias."}, "g": "D", "j": "D esta correta: na TCC, o perfeccionismo e compreendido como conjunto de CRENCAS (esquemas/cognicoes disfuncionais sobre desempenho e padrao pessoal) que provocam efeitos no desempenho - tanto positivos quanto negativos."}, {"id": "2159250", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Dentre as descrições apresentadas, assinale a que se refere\nàs principais ênfases na preparação mental de atletas,\nsegundo os principais autores da área.", "alt": {"A": "Estabelecimento de metas, regulação da ativação,\nconcentração, mentalização e autoconfiança.", "B": "Estabelecimento de metas, visualização, relaxamento,\ndiálogo interior, diálogo exterior e conversas de\nbastidores.", "C": "Equilíbrio emocional, controle cognitivo, controle de\ndesativação, controle de pensamentos negativos e\nênfase em motivação passiva.", "D": "Programa de psicologia aplicada ao esporte voltado\npara rotinas competitivas apenas.", "E": "Aplicação de protocolos de mindfulness, uso de rotinas\npré-competitivas e visualização do podium, educação\npara lidar com frustrações e ser competitivo sempre."}, "g": "A", "j": "A descreve corretamente as principais enfases da preparacao mental de atletas segundo a literatura: estabelecimento de metas, regulacao da ativacao, concentracao, mentalizacao (imageria) e autoconfianca. Demais alternativas incluem expressoes invalidas ('motivacao passiva') ou reducionistas."}, {"id": "2159249", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Embora a literatura apresente diferentes expressões ao\nreferir-se ao trabalho específico do psicólogo do esporte no\ncontexto do rendimento esportivo. Alguns dos termos a\nseguir são coerentes com o Plano de Trabalho em\nPsicologia do Esporte. Assinale a alternativa incorreta.", "alt": {"A": "Domínio de técnicas psicológicas e habilidades\npsicológicas, intrapessoais e interpessoais, favoráveis à\nperformance esportiva.", "B": "Treinamento de Competências Psicológicas; THP;\nPeriodização Psicológica.", "C": "O perfil psicológico de performance corresponde à\nanálise dos níveis de preparação mental de atletas de\nalto rendimento.", "D": "Preparação Psicológica, Treinamento Psicológico e\nPrograma de Treino de Competências Psicológicas.", "E": "Habilidades e técnicas psicológicas não são distintas e\nsão organizadas em básicas, de performance ou\nfacilitadoras."}, "g": "E", "j": "E esta incorreta: habilidades psicologicas e tecnicas psicologicas SAO DISTINTAS (habilidades sao capacidades intrinsecas como concentracao, autoconfianca; tecnicas sao instrumentos para desenvolve-las como visualizacao, relaxamento). A alternativa nega distincao reconhecida na area."}, {"id": "2159248", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Em qual alternativa a atuação do psicólogo esportivo junto\nàs famílias de atletas está coerente?", "alt": {"A": "O psicólogo deve buscar aproximar a família e a\ninstituição esportiva, favorecendo que a vontade do\natleta seja cumprida pela equipe profissional.", "B": "O psicólogo pode atuar com o atleta e sua família\nparticularmente, mesmo quando é contratado da\ninstituição esportiva, desde que a comissão técnica\nseja avisada de que haverá um trabalho particular em\nparalelo.", "C": "O psicólogo é um dos profissionais envolvidos na\nrelação família-esporte e deve se posicionar sempre à\nfrente de outras ações como a atuação do\nfisioterapeuta, do pedagogo ou do gestor esportivo em\nsituações delicadas entre a família, o atleta e o\ntreinador.", "D": "O psicólogo deve trabalhar de modo imparcial e buscar\nfavorecer a comunicação e a compreensão de\ndemandas do atleta entre família e instituição.", "E": "O psicólogo deve primar para que a família aceite o\nque determina a instituição esportiva, indicando as\nescolhas do atleta em relação à sua carreira."}, "g": "D", "j": "D esta correta: o psicologo esportivo deve trabalhar de modo IMPARCIAL, favorecendo a comunicacao e a compreensao das demandas do atleta entre familia e instituicao. Demais alternativas trazem condutas problematicas (favorecer vontade incondicional, trabalho paralelo a equipe, hierarquia entre profissionais, submissao a instituicao)."}, {"id": "2159247", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Durante os Jogos Olímpicos de Tokyo, em 2020, o tema\n“saúde mental no esporte de alto rendimento” teve\ndestaque em especial pela visibilidade dos\ncomportamentos das atletas Simone Biles e Naomi Osaka.\nConsiderando as abordagens desses tópicos em psicologia\ndo esporte, assinale a alternativa que corresponde à\nconcepção correta sobre esse assunto.", "alt": {"A": "A saúde mental de atletas corresponde aos transtornos\npsiquiátricos ligados ao comprometimento do\ndesempenho esportivo, fazendo com que atletas de\nalto rendimento não devam progredir na modalidade\nesportiva.", "B": "Dentre as organizações esportivas de relevância\ninternacional, a FIFA e o COI têm apoiado ações de\nsegregação de atletas com problemas mentais.", "C": "A compreensão e o tratamento de transtornos mentais\ntêm sido alvo de literatura e cursos especializados em\nPsicologia e Psiquiatria do Esporte, abordando temas\ncomo estresse, ansiedade, depressão, transtornos\nalimentares, dificuldades na regulação sono-vigília,\nabuso de substâncias etc.", "D": "A cultura e a dinâmica esportiva são excludentes de\nabordagens humanizadas, pois somente os atletas com\nforça mental positiva podem permanecer em alto nível\ncompetitivo.", "E": "A psiquiatria do esporte sobrepõe os conhecimentos\nde psicologia do esporte, pois utiliza as estratégias de\npreparação mental, oportunizando que as equipes\nmultiprofissionais tenham apenas um(a) psicólogo(a)\nou um(a) psiquiatra no contexto de ação institucional e\npermitindo uma maior especialização médica e menos\nnecessidade de atuação do psicólogo do esporte."}, "g": "C", "j": "C esta correta: a compreensao e tratamento de transtornos mentais em atletas de alto rendimento tem sido alvo de literatura e cursos especializados em Psicologia e Psiquiatria do Esporte (estresse, ansiedade, depressao, transtornos alimentares, sono, abuso de substancias). Demais alternativas patologizam, segregam ou negam direitos."}, {"id": "2159244", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando a atuação do(a) psicólogo(a) no contexto\nesportivo, julgue os itens a seguir.    \nI. Atualmente, já é uma realidade consolidada em todos\nos ambientes esportivos a necessidade de atuação\ninterdisciplinar, em especial nas situações de\ngerenciamento de conflitos, reabilitação de lesões,\npromoção de talentos e transição de carreira esportiva.    \nII. Saber lidar com a diversidade de perspectivas\nprofissionais no cotidiano da ação, corresponde a uma\nnecessidade inerente do trabalho multiprofissional.\n    III. A prática transdisciplinar é uma obrigatoriedade da\natuação profissional em qualquer situação, valorizando\na ética e os direitos humanos em todas as\ncomunicações profissionais.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "I esta errado por generalizacao excessiva ('em TODOS os ambientes esportivos'); III tambem usa absoluto invalido ('obrigatoriedade em QUALQUER situacao'). II (saber lidar com diversidade no trabalho multiprofissional) e a unica afirmacao bem calibrada. Apenas II = B."}, {"id": "2159242", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação à psicologia do esporte e à reabilitação,\nassinale a alternativa incorreta.", "alt": {"A": "Controle de peso, manutenção das doenças\ncardiovasculares, nível de estresse, estética, ansiedade\ne depressão, gratificação pessoal e aumento de\nsocialização são motivos para realizar exercícios físicos.", "B": "A literatura aponta como interesses dos psicólogos do\nesporte a variação das dinâmicas individuais e grupais\nque ocorre nos contextos esportivos e da atividade\nfísica. O objetivo é compreender como fatores sociais e\nambientais podem afetar o comportamento e a adesão\ndos participantes.", "C": "No contexto do exercício, precisamos levar em conta as\ndiferenças individuais e o ambiente em que cada um\nvive. As características individuais são os traços\nestáveis e as características do indivíduo como idade,\npersonalidade, carga genética e história de vida.", "D": "A vida social, características pessoais, níveis de estresse\ne estado de humor podem influenciar de maneira\nnegativa. Estudos sugerem que a ativação crônica do\nsistema nervoso simpático cria um clima cardiovascular\ntóxico ou que indivíduos em constante estado de\nexcitação simpática, causado por estresse\ndescontrolado ou enfrentamento social precário,\napresentam alto risco para o clima cardíaco tóxico.", "E": "Problemas psicológicos podem levar à redução da\nadesão aos regimes médicos prescritos, assim como a\nbusca de comportamentos não saudáveis."}, "g": "A", "j": "A esta incorreta: o exercicio fisico visa PREVENCAO (nao 'manutencao') das doencas cardiovasculares. A alternativa contradiz a logica preventiva da atividade fisica regular."}, {"id": "2159241", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Humor", "Transtornos da Ansiedade", "Outros Transtornos"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre aspectos da ansiedade e da depressão e estudos da\npsicologia do esporte, assinale a alternativa correta.", "alt": {"A": "Ao ocorrer um desequilíbrio no nível de ansiedade do\nindivíduo, o organismo humano responde com reações\ncognitivas e somáticas, que são componentes\npsicofisiológicos da depressão.", "B": "Alterações de substâncias químicas, como as aminas\n(dopamina e adrenalina), são com frequência\nassociadas aos distúrbios ansiosos.", "C": "Ansiedade cognitiva são alternâncias de pensamentos\nque levam a perda de autoestima, medo de desafios,\napatia na tomada de decisões e desinteresse. A\nansiedade somática relaciona-se com os aspectos\nfisiológicos como aumento da frequência cardíaca e\nrespiratória, sudorese nas mãos, boca seca, perda de\nexplosão muscular e tensão muscular.", "D": "Na psicologia do esporte, os termos “ativação”,\n“estresse” e “ansiedade” significam o mesmo, e não é\npreciso diferenciá-los.", "E": "A hipótese do U invertido, muito trabalhada na\npsicologia do esporte, explica a relação entre\nansiedade e desempenho."}, "g": "C", "j": "C distingue corretamente ansiedade cognitiva (pensamentos disfuncionais, perda de autoestima, apatia) e ansiedade somatica (frequencia cardiaca, sudorese, tensao muscular). Demais alternativas trocam aspectos da depressao com ansiedade (A, B), igualam conceitos distintos (D) ou misturam ativacao com ansiedade (E)."}, {"id": "2159239", "d": "psicologia", "a": ["Psicopatologia", "Transtornos da Ansiedade"], "ano": "2022", "org": "CFP", "t": "", "e": "Ao se trabalhar com ansiedade, ativação e estresse no\ncontexto esportivo, é preciso levar em conta alguns pontos.\nSobre eles, julgue os itens a seguir.    \nI. Identificar qual são a combinação ideal de emoções, os\nfatores pessoais e os situacionais relacionados à\nativação necessários para um bom desempenho.    \nII. Trabalhar junto com o atleta para identificar os sinais\nde ativação e ansiedade, adaptando-os em\ntreinamentos.\n    III. Ativação e ansiedade aumentam o campo de atenção,\nestimulando o rastreamento do ambiente,\ninfluenciando positivamente o desempenho.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (identificar combinacao ideal de emocoes, fatores pessoais e situacionais) e II (identificar sinais de ativacao/ansiedade adaptando-os ao treinamento) sao corretos. III esta errado: ativacao e ansiedade tendem a ESTREITAR (nao ampliar) o campo atencional, com efeito de Easterbrook. Apenas I e II = B."}, {"id": "2159238", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre as diferentes abordagens teóricas de psicologia do\nesporte, assinale a alternativa correta.", "alt": {"A": "Na fenomenologia aplicada à psicologia do esporte, a\nmente do sujeito é vista como o lugar de investigação e\ntrabalho junto ao atleta.", "B": "A fenomenologia no contexto esportivo considera o\natleta como protagonista da atuação, ou seja, da\ninvestigação e da intervenção da psicologia. Nesse\ncampo, ele é entendido por meio do entrelaçamento\nfísico e mental via compreensão do corpo e da\nmotricidade.", "C": "A psicologia positiva pode ser definida como estudo\ndas condições e dos processos que contribuem para o\namadurecimento e a otimização do desempenho de\npessoas, grupos e instituições. Seu principal foco é a\nremediação de problemas e, por isso, tem sido muito\nusada na psicologia do esporte.", "D": "A psicologia positiva acredita que o psicólogo deve ter\num olhar fundamentalmente clínico e,\nconsequentemente, de resolução de problemas.", "E": "O ponto-chave que diferencia as intervenções na\nperspectiva da psicologia positiva é o olhar para as\npatologias psicológicas, para que não interfiram\nnegativamente no percurso do indivíduo/atleta."}, "g": "B", "j": "B esta correta: a fenomenologia aplicada ao esporte considera o atleta como PROTAGONISTA da investigacao/intervencao, compreendido pelo entrelacamento corpo-motricidade-mente. A (reduz a mente como lugar isolado), C/D/E distorcem a Psicologia Positiva."}, {"id": "2159237", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2022", "org": "CFP", "t": "", "e": "Na psicologia do esporte, lidamos com diferentes formas de\ntrabalhar, uma vez que é uma área interdisciplinar e\nmultidisciplinar. Assinale a alternativa correta.", "alt": {"A": "A atuação no campo do esporte e do exercício é\nsempre interdisciplinar e multidisciplinar, pois\nconsegue integrar diferentes perspectivas de análise e\nintervenção.", "B": "Em programas de reabilitação, a equipe\nmultiprofissional promove apenas orientações para\nmudanças no estilo de vida. Tudo isso com o objetivo\nde diminuir as chances de ocorrência de novos\nproblemas cardiovasculares, uma vez que fatores\npsicossociais afetam diretamente a origem e a\nmanutenção dos fatores.", "C": "O modelo de crença na saúde é muito utilizado como\ntermômetro motivacional na psicologia do esporte.", "D": "Pesquisas sobre adesão ao exercício buscam investigar\nvariáveis isoladas do comportamento em relação ao\nexercício, ou seja, fatores sociais e ambientais.", "E": "A prática interdisciplinar favorece a intervenção\npsicológica e a coesão da equipe, pois trabalha com\nobjetivos em comum e atua no programa de\ntreinamento psicológico, trazendo benefícios\ncomplementares para os esportistas."}, "g": "E", "j": "E esta correta: a pratica interdisciplinar favorece intervencao psicologica e coesao da equipe, com objetivos comuns no programa de treinamento psicologico. Demais alternativas absolutizam (A), restringem (B, D) ou trocam contexto (C)."}, {"id": "2159235", "d": "psicologia", "a": ["Motivação", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "A motivação é uma questão central na psicologia do\nesporte, pois se propõe a investigar, analisar e explicar os\ncomportamentos dos praticantes dirigidos a uma meta,\nconhecida ou desconhecida. Conhecer as teorias é\nnecessário para orientação, acompanhamento e gestão de\natletas e praticantes de atividade física. Sobre a orientação\nconceitual da motivação no contexto do esporte e do\nexercício, assinale a alternativa correta.", "alt": {"A": "Teoria da Necessidade de Realização (Atkinson); Teoria\nda Atribuição (Heider e Weiner); Teoria das Metas de\nRealização (Nicholls e Duda); Teoria da Avaliação\nCognitiva (Deci e Ryan).", "B": "Teoria do Apoio social (Shumaker e Brownell); Teoria\nda Justiça (Anshel); Teoria da Produtividade Real (Ivan\nSteiner); Teoria da Habilidade Individual e\nDesempenho em Grupo (Comrey e Deskin).", "C": "Teoria da aderência (Estabrooks e Carron); Teoria\nfocada no ambiente (Prapavessis, Carron e Spink);\nTeoria do Traço (Barrow); Teoria da Motivação para a\nCompetência (Weiss e Chaumeton).", "D": "Teoria de Liderança e Mediação Cognitiva (Smoll e\nSmith); Teoria de Motivação para o Rendimento\n(Heckhausen); Teoria do Modelo Conceitual de Coesão\n(Carron,et.al).", "E": "Teoria Multimodal de Redução da Ansiedade (Ronald\nSmith); Teoria Psiconeuromuscular (Carpenter); Teoria\nda Aprendizagem Simbólica (Sacket); Teoria do Modelo\nde Código Triplo (Ashen)."}, "g": "A", "j": "A apresenta corretamente as principais teorias da motivacao no contexto esportivo: Teoria da Necessidade de Realizacao (Atkinson), Teoria da Atribuicao (Heider/Weiner), Teoria das Metas de Realizacao (Nicholls/Duda), Teoria da Avaliacao Cognitiva (Deci/Ryan - autodeterminacao)."}, {"id": "2158994", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Uma das questões críticas relacionadas ao término da\nterapia refere-se a como identificar esse momento, de\nforma que não seja precipitado ou postergado. Alguns\nindicadores clínicos podem ser utilizados como balizas que\nauxiliam o terapeuta a reconhecer que o término se\naproxima e a conduzi-lo adequadamente. Com relação aos\nindicadores de que é o momento para o término da\npsicoterapia, julgue os itens a seguir.    \nI. Menção do paciente sobre os ganhos alcançados e o\ndesejo de encerramento da psicoterapia.    \nII. Falta de “assunto” ou de “material” para as sessões e\nindícios de que os problemas foram adequadamente\nresolvidos.    \nIII. Redução dos sintomas apresentados no início do\ntratamento (avaliada clinicamente ou com escalas\nespecíficas).    \nIV. Maior capacidade de lidar com a realidade e de tolerar\nfrustrações.      \nAssinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens III e IV estão certos.", "D": "Apenas os itens I, II e III estão certos.", "E": "Apenas os itens II, III e IV estão certos."}, "g": "A", "j": "I (mencao do paciente sobre ganhos), II (falta de assunto/material), III (reducao de sintomas) e IV (maior capacidade de lidar com realidade e tolerar frustracoes) sao indicadores classicos de termino da psicoterapia. Todos = A."}, {"id": "2158993", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Volich, “à função terapêutica, pouco importa,\ninicialmente, a especialidade daquele que a exerce. O\nterapeuta pode ser um médico, um psicólogo, um\nfisioterapeuta, uma enfermeira, até mesmo um vizinho, ou\nseja, todo aquele a quem, em um certo momento é dirigido\num insidioso pedido de ajuda com relação a um sofrimento\nque busca um outro que possa compartilhá-lo, e que se\ndisponha a acolher esse pedido”. Julgue os itens a seguir.\n    I. O conhecimento, a técnica e a experiência acumulada\nao longo dos séculos na tentativa de compreensão das\ndiferentes formas de manifestação do sofrimento\nhumano não são essenciais para aliviar tais\nmanifestações.\n    II. A função terapêutica resgata uma experiência\nprimordial que nos constitui, que todos\ncompartilhamos. A experiência do nosso desamparo\nprimitivo que, para ser superado, necessitou do\nexercício, pelo outro, da função materna.    \nIII. Os elementos técnicos e do conhecimento científico\npressupõem, antes de tudo, uma capacidade de entrar\nem contato com a experiência mais essencial do\nindivíduo que apresenta sua queixa, o órgão lesado, o\ndesequilíbrio revelado nos exames clínicos.      \nAssinale a alternativa correta", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I esta errado: conhecimento, tecnica e experiencia SAO essenciais para aliviar manifestacoes do sofrimento. II (funcao terapeutica resgata experiencia primordial do desamparo) e III (elementos tecnicos pressupoem capacidade de contato com a experiencia essencial) sao corretos. Apenas II e III = C."}, {"id": "2158992", "d": "psicologia", "a": ["Avaliação Psicológica", "Entrevista e Anamnese", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "O psicodiagnóstico com idosos inicia-se com a entrevista de\nanamnese, que busca o conhecimento da demanda e a\nelaboração de hipóteses diagnósticas. A seguir, o psicólogo\nmonta uma bateria de testes, fazendo então a correção e a\ninterpretação de seus resultados. Depois, é preciso um\nraciocínio clínico que busque integrar dados dos testes com\ndados da história clínica e de vida do paciente, assim como\nsuas queixas, sinais e sintomas, visando a uma\ncompreensão dinâmica de seu funcionamento, de suas\npotencialidades e de suas dificuldades (Hutz & cols., 2016).    \nAssinale a alternativa incorreta.", "alt": {"A": "Na entrevista clínica com idosos, é importante\nidentificar fatores sociodemográficos e alterações\nsensoriais, motoras e cognitivas que acompanham o\nenvelhecimento e podem influenciar os resultados dos\ntestes administrados.", "B": "Na entrevista clínica, deve-se questionar a profissão e a\nrotina do idoso antes de iniciar com as queixas de\ndeclínio cognitivo, para verificar se costumava fazer\natividades como leitura, escrita e cálculos, e se essas se\nmostram atualmente comprometidas na avaliação.", "C": "Deve-se analisar também quanto as queixas trazidas\npelo paciente e por seus familiares estão impactando a\nindependência funcional e a rotina do paciente. Por\nisso, é importante verificar quais atividades ele\nconsegue fazer sem ajuda e para quais precisa de\nsupervisão.", "D": "O paciente idoso não é uma fonte de informação\nfidedigna sobre seu desempenho atual. Por isso,\ndevem-se averiguar os dados obtidos por meio de\nentrevista com um informante. O informante deve,\nnecessariamente, ser alguém da família do paciente.", "E": "Em diversas ocasiões, é preciso entrevistar\nprofissionais que acompanham o paciente em casa,\ncomo técnicos de enfermagem e/ou “cuidadores” em\ngeral. Nos casos em que o idoso estiver\ninstitucionalizado, o informante precisa ser alguém que\ntem contato direto, e preferencialmente diário, com o\npaciente."}, "g": "D", "j": "D esta incorreta: o informante NAO precisa NECESSARIAMENTE ser alguem da familia - pode ser cuidador profissional, vizinho proximo, profissional do equipamento institucional. A alternativa restringe indevidamente a fonte de informacao."}, {"id": "2158991", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2022", "org": "CFP", "t": "", "e": "No que diz respeito à ordenação metodológica do exame\ndo estado mental, há um consenso de que as principais\nalterações envolvem sinais e/ou sintomas nas seguintes\náreas da conduta humana: atenção, sensopercepção,\nmemória, orientação, consciência, pensamento, linguagem,\ninteligência, afetividade e conduta (Cunha). Assinale a\nalternativa correta sobre o exame do pensamento.", "alt": {"A": "No exame do pensamento, cabe analisar as\ndenominadas operações racionais: (I) análise e síntese;\n(II) generalização e sistematização; (III) abstração e\nconcreção; (IV) comparação.", "B": "Nas denominadas manifestações qualitativas do\npensamento, avalia-se a velocidade de associação das\nideias ou o fluxo de ideias.", "C": "Quanto ao conteúdo, costumam-se distinguir\npensamento mágico e pensamento lógico.", "D": "Na produção do pensamento, observa-se, na prática\nclínica, que ele se apresenta sem as alterações\nconcomitantes de todo o pensamento. São exemplos\nde tais alterações: (I) fuga de ideias; (II) inibição do\npensamento; (III) perseveração; (IV) desagregação.", "E": "No exame do curso do pensamento, encontram-se os\nprincipais transtornos dessa área: os delírios, as ideias\nsupervalorizadas e o delirium."}, "g": "A", "j": "A esta correta: no exame do pensamento, as operacoes racionais incluem analise/sintese, generalizacao/sistematizacao, abstracao/concrecao e comparacao. Demais alternativas confundem aspectos do pensamento (velocidade e curso vs conteudo vs producao)."}, {"id": "2158989", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a traumas e estressores"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com o CID-10, “uma resposta tardia e/ou\nprotraída a um evento ou situação estressante (de curta ou\nlonga duração) de uma natureza excepcionalmente\nameaçadora ou catastrófica, a qual provavelmente causa\nangústia invasiva em quase todos as pessoas. [...] Sintomas\ntípicos incluem episódios de repetidas revivescências do\ntrauma sob a forma de memorias intrusas (flashbacks) ou\nsonhos, ocorrendo contra o fundo persistente de uma\nsensação de ‘entorpecimento’ e embotamento emocional,\nafastamento de outras pessoas, falta de expansividade ao\nambiente, anedonia e evitação de atividades e situações\nrecordativas do trauma”. O conjunto dessas características\ne desses sintomas refere-se a qual das seguintes categorias\ndiagnósticas?", "alt": {"A": "Alteração permanente de personalidade após\nexperiência catastrófica.", "B": "Reação aguda a estresse.", "C": "Transtornos de ajustamento.", "D": "Reação mista de ansiedade e depressão.", "E": "Transtorno de estresse pós-traumático."}, "g": "E", "j": "A descricao (resposta tardia/protraida a evento traumatico, flashbacks/revivescencias, entorpecimento, evitacao) corresponde exatamente ao Transtorno de Estresse Pos-Traumatico (CID-10 F43.1). Demais sao categorias proximas mas distintas (reacao aguda, ajustamento, alteracao permanente)."}, {"id": "2158988", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "A relação terapêutica envolve todos os elementos,\nsentimentos, pensamentos e atitudes que ocorrem a partir\ndo momento em que se forma uma dupla terapeuta- -\npaciente. Em psicoterapia, além de técnicas especiais de\ncada escola psicoterapêutica, os fenômenos que ocorrem\nna relação entre terapeuta e paciente são determinantes\npara que se consiga atingir os objetivos propostos. Assinale\na alternativa incorreta sobre Aliança Terapêutica ou de\nTrabalho (AT) em psicoterapia.", "alt": {"A": "A AT é composta de três elementos essenciais: (1)\ndesenvolvimento de vínculo pessoal composto de\nsentimentos positivos recíprocos; (2) acordo sobre os\nobjetivos do tratamento; (3) acordo sobre as tarefas\nque cabem ao terapeuta e ao paciente no processo\npsicoterapêutico.", "B": "A AT é um elemento determinante e comum a todas as\nformas de psicoterapia e refere-se ao vínculo\nestabelecido entre paciente e terapeuta, o qual é\nfundamental para o trabalho psicoterapêutico.", "C": "A técnica é baseada na teoria clínica (e norteada por\nela) que referencia o tratamento, enquanto a aliança\nrepresenta quanto terapeuta e paciente estão\nconseguindo caminhar juntos no processo terapêutico.\nSob esse ponto de vista, é um elemento comum a\ntodas as técnicas psicoterapêuticas.", "D": "A AT representa o componente do relacionamento\nentre o paciente e seu terapeuta impactado pela\ntransferência; corresponde aos elementos da relação\nreal e simbólica que atuam nos objetivos terapêuticos.", "E": "A AT diz respeito à parte racional e intencional dos\nsentimentos do paciente para com seu terapeuta. Para\nGreenson, a origem da AT está na motivação do\npaciente para superar sua sensação de desamparo."}, "g": "D", "j": "D esta incorreta: a Alianca Terapeutica representa a parte REAL/CONSCIENTE/RACIONAL da relacao (vinculo de trabalho), nao a parte transferencial. A transferencia e dimensao distinta da relacao psicoterapeutica. A alternativa confunde os conceitos."}, {"id": "2158985", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Em relação aos fatores de risco de suicídio e a semiotécnica\nda ideação e do impulso suicida, conforme Dalgalarrondo,\njulgue os itens a seguir.\n    I. A ideação, os impulsos e os planos suicidas devem ser\nsempre investigados no caso de mínima suspeita. O\ntema deve ser tratado como algo delicado e pessoal, de\nmodo circunspecto, mas franco.\n    II. Após contato inicial, inquirir de modo que seja mais\nfácil para o paciente falar sobre o tema, começando a\nperguntar sobre o desejo de “desaparecer”, de “sair de\ncena”, de “dormir para sempre”, até o desejo definido\nde se matar.\n    III. Entre os fatores de risco consideram-se: depressão\nmoderada ou grave, traços autodestrutivos e impulsos,\nhistória de tentativas ou ameaças suicidas recentes,\ndesesperança, falta de perspectiva e sensação de\nfracasso pessoal, morar sozinho, não ter família ou\nvínculos sociais, fácil acesso a meios violentos (armas,\nalturas, venenos, fármacos etc.).\n      Assinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Nenhum item está certo"}, "g": "A", "j": "I (investigar com minima suspeita), II (perguntar de modo gradual partindo de 'desaparecer'/'dormir para sempre' ate o desejo definido) e III (fatores de risco classicos: depressao, traços autodestrutivos, tentativas previas, desesperanca, isolamento, acesso a meios violentos) sao todos consistentes com Dalgalarrondo. Todos = A."}, {"id": "2158984", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Figueiredo, “é comum se fazer distinção\nentre Psicologia básica e Psicologia aplicada, que nos\ncurrículos corresponde à distinção entre formação básica e\nformação profissionalizante”. Assinale a alternativa correta\nque define a clínica psicológica para esse autor.", "alt": {"A": "A clínica sempre implica uma intervenção; podemos\ndefini-la como uma psicologia aplicada, aplicação de\nconhecimentos básicos.", "B": "O sentido da intervenção clínica se diferencia em\nalguns aspectos dos sentidos da intervenção\neducacional e organizacional; portanto podemos\ndefinir a clínica como uma área de atuação.", "C": "O que define a clínica psicológica é sua ética; portanto\na clínica está comprometida com a escuta do\ninterditado e com a sustentação das tensões e dos\nconflitos.", "D": "Há um tipo de conhecimento que é produzido na\nclínica e só nela. Podemos definir a clínica como uma\nárea de conhecimento separada de outras áreas.", "E": "É extremamente verdadeiro pensar a oposição entre a\npsicologia clínica e a psicologia experimental como\numa questão de método – há sem dúvida um método\nclínico de pesquisa –; portanto podemos definir a\nclínica como um método de pesquisa."}, "g": "C", "j": "C captura a definicao de Figueiredo: a clinica psicologica define-se essencialmente por sua ETICA - escuta do interditado e sustentacao das tensoes/conflitos. Demais alternativas reduzem a clinica a aplicacao tecnica, area de atuacao ou metodo."}, {"id": "2158982", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A dimensão cuidadora na produção de saúde deve ser\nincorporada ao processo de trabalho nos CAPS, que deve\nter como objetivo principal a produção de atos de cuidado\ne de intervenções sociais visando à construção de\nautonomia nos usuários. Esta é a essência do trabalho em\nsaúde mental: a construção permanente do sujeito na\nrelação com a sociedade. Julgue os itens a seguir.    \nI. Na clínica da saúde mental, os psicólogos devem\nconstruir diagnósticos que se apresentem como ponto\nde orientação num percurso a ser construído na\nhistória do sujeito. Ele deve significar a possibilidade,\nmuito menos de responder sobre uma doença e muito\nmais de indicar as possibilidades de projetos a partir do\nque se identifica como um modo de o sujeito atuar na\nvida, estabelecer relações e constituir sua experiência\nsubjetiva.    \nII. O diagnóstico não deve, por isso, ser buscado para\nresponder ao psicólogo ou à equipe quem é o sujeito\nou qual é sua doença, mas para apresentar dificuldades\ndesse sujeito que apontem as possibilidades de\nassistência da equipe e do profissional na construção\nparceira de uma nova trajetória de vida.\n    III. Do ponto de vista do diagnóstico, das teorias e das\nreferências de projetos de intervenção para a prática\ndos psicólogos nos CAPS, devemos nos orientar sempre\npela indagação acerca daquilo para que servem os\nrecursos utilizados e se eles estão a serviço da atenção\npsicossocial.      Assinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Nenhum item está certo."}, "g": "A", "j": "I (diagnostico como ponto de orientacao no percurso do sujeito, indicando possibilidades de projetos), II (diagnostico para apresentar dificuldades e possibilidades de assistencia) e III (orientacao pela atencao psicossocial) sao todos consistentes com a logica dos CAPS na Atencao Psicossocial. Todos = A."}, {"id": "2158981", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A clínica dos CAPS distancia-se da ideia corrente que\nreferencia a percepção social acerca do fazer clínico. Ou\nseja, a clínica de um CAPS não se faz só de colóquios\níntimos. Conjuga elaboração subjetiva e reabilitação no\nprocesso de construção da autonomia e da capacidade de\ncada usuário. Assinale a alternativa incorreta.", "alt": {"A": "A crise do sujeito, ou o conflito que não encontrou\nlugar na subjetividade e por isso tornou-se insuportável\ne transbordou, precisa ser escutada naquilo que\nproduz de tensionamento, ruptura ou conexão com os\nlaços sociais.", "B": "O sofrimento psíquico ou a crise – sua expressão mais\nintensa – podem ser percebidos para além da\ndimensão psicopatológica. Entra em jogo a necessária\nescuta e o reconhecimento do sujeito e do laço social.\nPor isso, não inclui a psicoterapia.", "C": "Oficinas, assembleias, permanência, hospitalidade,\nmediação das relações entre os sujeitos e seus\nfamiliares, suas referências e redes têm tanto valor\nquanto os recursos da ciência e da técnica.", "D": "Tratar – para essa clínica, é construir as condições de\nliberdade e capacidade de se inserir na cidade, de fazer\ncaber a diferença – sempre singular, no universal da\ncidadania, com cada usuário.", "E": "Para tratar, rigorosamente, é necessário ser livre para\ndecidir quando e por que tratar-se, sendo igualmente\nimportante, para essa clínica, tratar sem trancar, tratar\ndentro da cidade, buscando os laços sociais, o\nfortalecimento ou a reconstrução das redes que\nsustentam a vida de cada usuário."}, "g": "B", "j": "B esta incorreta: a clinica dos CAPS INCLUI a psicoterapia entre suas modalidades de cuidado, ao lado de oficinas, assembleias, mediacao etc. A alternativa exclui erroneamente uma pratica integrante."}, {"id": "2158980", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A Clínica Ampliada se refere a uma prática que engloba, e\nnão se limita a, a Psicologia ou a Equipe da Saúde da Família\n(ESF), envolvendo a integralidade como atributo da\nAtenção Básica em saúde púbica, que compreenda a\nconstrução compartilhada de diagnósticos e terapêuticas\ncomo plano de cuidado, não somente centrado na doença.\nEm relação à prática da psicologia clínica em saúde, assinale\na alternativa incorreta.", "alt": {"A": "A Clínica Ampliada não é específica da prática da\nPsicologia. Ela trata de uma forma de compreensão do\nsujeito e de suas necessidades de saúde que pode ser\nexercida por qualquer profissional, e psicólogas(os)\npodem cooperar para a construção de uma\nsensibilidade nesse sentido.", "B": "Na construção de estratégias de prevenção e\npromoção de saúde, a equipe profissional precisa\nconsiderar aquelas já utilizadas por uma população,\nnuma postura de troca de saberes e de abordagens de\nacolhimento das estratégias construídas pela própria\npopulação, mesmo que essas ainda não tenham sido\nenunciadas pela ciência.", "C": "Entender as estratégias que podem ser usadas para\numa trabalhadora que sofre assédio moral\ncotidianamente e tem picos de hipertensão,\nprocurando a UBS como um espaço de acolhimento\npara seus problemas, ou uma mulher que chega à\nunidade à procura de cuidados para enxaqueca que\nsurge sempre quando seu companheiro a agride.", "D": "Trata-se de uma clínica que pode acontecer também\nem muitos espaços – o setting é múltiplo. Essa forma\nde atuação pode trazer desconfortos para a(o)\npsicóloga(o) e se mostrar muito desafiadora, ao\napresentar as incertezas que regem o campo da saúde\ne uma prática ligada a um território.", "E": "Na Clínica Ampliada, o compartilhamento deve ser\nfeito também com o próprio usuário. É certo que a\nproposta é sempre tudo informar, portanto sem\nnecessidade de sigilo, nem de justificar com essa\nestratégia a não comunicação com a equipe."}, "g": "E", "j": "E esta incorreta: na Clinica Ampliada o compartilhamento NAO significa 'tudo informar' nem ausencia de sigilo - o sigilo profissional permanece, e o compartilhamento e seletivo e etico. A alternativa nega principio etico basico."}, {"id": "2158979", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Rogers (1961) delineou três condições, as quais, quando\nestão presentes no terapeuta e o cliente as percebe, pelo\nmenos parcialmente, o movimento terapêutico continua.\n“O cliente nota que aprende e se desenvolve, dolorosa e\ndefinitivamente, e ambos consideram que o resultado é\npositivo”. Em relação às condições do psicólogo na relação\nterapêutica, assinale a alternativa incorreta.", "alt": {"A": "Quando o psicoterapeuta é aquilo que é, quando as\nsuas relações com o cliente são autênticas e sem\nmáscara nem fachada, exprimindo abertamente os\nsentimentos e as atitudes que nesse momento fluem\nnele, utilizamos o termo “congruência” para tentar\ndescrever essa condição.", "B": "Utilizamos o termo “congruência” para que os\nsentimentos que o terapeuta estiver vivenciando\nestejam disponíveis para o cliente, e o terapeuta pode\nviver esses sentimentos, portanto deve assumi-los e\ncomunicá-los ao cliente para realizar plenamente tal\ncondição.", "C": "Quando o terapeuta está vivenciando uma atitude\ncalorosa, positiva e de aceitação, o terapeuta se\npreocupa com seu cliente de uma forma não\npossessiva, que o aprecia mais na sua totalidade do\nque de uma forma condicional; trata-se de um\nsentimento positivo que se exterioriza sem reservas e\nsem avaliações. Designou-se essa situação:\n“consideração positiva incondicional”.", "D": "Quando o terapeuta é sensível aos sentimentos e às\nsignificações pessoais que o cliente vivencia a cada\nmomento, quando pode apreendê-los “de dentro” tal\ncomo o paciente os vê, e quando consegue comunicar\ncom êxito alguma coisa dessa compreensão ao\npaciente, então está cumprida a terceira condição,\ndesignada “compreensão empática”", "E": "O terapeuta ser “congruente” significa que qualquer\natitude ou sentimento que estiver vivenciando vem\nacompanhado da consciência dessa atitude. Quando\nisso é verdade, sou, naquele momento, uma pessoa\nunificada e inteirada e é então que posso ser o que sou\nno mais íntimo de mim mesmo."}, "g": "B", "j": "B esta incorreta ao afirmar que o terapeuta 'deve assumi-los e comunica-los' - Rogers fala em CONGRUENCIA (estar em contato consciente com os proprios sentimentos) mas NAO obriga a comunicar todos eles ao cliente; a comunicacao deve ser ponderada. A alternativa distorce o conceito."}, {"id": "2158978", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com a Resolução CFP 011/2018 e a Resolução\nCFP 04, de 26 de março de 2020, que dispõe sobre\nregulamentação de serviços psicológicos prestados por\nmeio de Tecnologia da Informação e da Comunicação\ndurante a pandemia da Covid-19, assinale a alternativa\ncorreta.", "alt": {"A": "O atendimento de crianças e adolescentes ocorrerá\ncom o consentimento expresso de ao menos um dos\nresponsáveis legais e mediante avaliação de viabilidade\ntécnica por parte da psicóloga ou do psicólogo para a\nrealização desse tipo de serviço.", "B": "O atendimento de pessoas e grupos em situação de\nurgência e emergência pelos meios de tecnologia e\ninformação é inadequado, devendo a prestação desse\ntipo de serviço ser executada por profissionais e\nequipes de forma presencial.", "C": "O atendimento de pessoas e grupos em situação de\nemergência e desastres pelos meios de tecnologia e\ninformação é vedado, devendo a prestação desse tipo\nde serviço ser executada por profissionais e equipes de\nforma presencial.", "D": "É vedado o atendimento de pessoas e grupos em\nsituação de violação de direitos ou de violência pelos\nmeios de tecnologia e informação, devendo a\nprestação desse tipo de serviço ser executada por\nprofissionais e equipes de forma presencial.", "E": "A prestação de serviços psicológicos referentes a essas\nresoluções está condicionada à realização de cadastro\nprévio na plataforma e-Psi. O psicólogo não poderá\nprestar os serviços psicológicos até a emissão de\nparecer do respectivo CRP."}, "g": "A", "j": "A esta correta segundo Res CFP 011/2018 e 04/2020: o atendimento de criancas e adolescentes via TICs requer consentimento expresso de ao menos um dos responsaveis legais e avaliacao de viabilidade tecnica pelo psicologo. Demais alternativas trazem vedacoes/restricoes que nao existem nas resolucoes."}, {"id": "2158977", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Humor"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com a revista Cult (12/2021), “com o aumento\nexpressivo de doenças psicológicas durante a pandemia da\nCovid-19, criou-se uma espécie de ‘epidemia paralela’ de\nangústia, ansiedade e síndromes depressivas”. De acordo\ncom Dalgalarrondo, assinale a alternativa correta.", "alt": {"A": "A angústia é definida como o estado de humor\ndesconfortável, apreensão negativa em relação ao\nfuturo, inquietação interna desagradável. Inclui\nmanifestações somáticas e fisiológicas.", "B": "O termo “ansiedade” relaciona-se diretamente à\nsensação de aperto no peito e na garganta, de\ncompressão, sufocamento. Assemelha-se muito à\nangústia, mas tem conotação mais corporal e mais\nrelacionada ao passado.", "C": "Do ponto de vista existencial, a ansiedade tem\nsignificado mais marcante, é algo que define a\ncondição humana, é um tipo de vivência mais\n“pesada”, mais fundamental que a experiência da\nangústia.", "D": "Do ponto de vista psicopatológico, as síndromes\ndepressivas têm como elementos mais salientes o\nhumor triste e o desânimo. Entretanto, elas\ncaracterizam-se por uma multiplicidade de sintomas\nafetivos, instintivos e neurovegetativos, ideativos e\ncognitivos, relativos à autovaloração, à vontade e à\npsicomotricidade.", "E": "Não podem estar presentes, para caracterizar as\nsíndromes depressivas: sintomas psicóticos (delírios\ne/ou alucinações), nem alteração psicomotora ou\nfenômenos biológicos associados."}, "g": "D", "j": "D esta correta segundo Dalgalarrondo: as sindromes depressivas caracterizam-se por humor triste, desanimo E multiplicidade de sintomas afetivos, instintivos/neurovegetativos, ideativos/cognitivos, autovaloracao, vontade e psicomotricidade. Demais alternativas confundem ansiedade e angustia ou restringem indevidamente o quadro depressivo."}, {"id": "2158976", "d": "psicologia", "a": ["Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Cordioli, “não há dúvidas de que a TCC – Terapia\nCognitivo-Comportamental – é o modelo de terapia mais\nestudado empiricamente pela ciência contemporânea,\napresentando uma diversidade de aplicações clínicas\neficazes. Atualmente, há centenas de metanálises de\nensaios clínicos que comprovam a eficácia da TCC”. Julgue\nos itens a seguir sobre as técnicas da TCC.\n    I. No início da terapia, o paciente é treinado a identificar\ne a registrar seus sentimentos e queixas subjacentes.    II. O paciente usa os próprios recursos para identificar\nerros de lógica, pensamentos e crenças errôneos ou\ndisfuncionais e, posteriormente, corrigi-los mediante\nexame das evidências, testes comportamentais e\ngeração de pensamentos alternativos.    \nIII. Utiliza técnicas comportamentais como exposição,\nprevenção de rituais, modelação, role-playing, treino\nde assertividade, técnicas de relaxamento muscular e\ncontrole respiratório, planilhas de atividades e ensaio\nde comportamentos.\n      Assinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "I esta errado pela imprecisao: a TCC treina o paciente a identificar pensamentos automaticos (nao apenas 'sentimentos e queixas'). II (paciente usa recursos proprios para identificar erros de logica e corrigi-los) e III (tecnicas comportamentais: exposicao, prevencao de rituais, modelacao, role-playing, treino de assertividade) sao corretos. Apenas II e III = C."}, {"id": "2158975", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com o Conselho Federal de Psicologia (CFP),\nassinale a alternativa incorreta em relação às atribuições\nprofissionais do psicólogo clínico.", "alt": {"A": "Participa da elaboração de programas de pesquisa\nsobre a saúde mental da população, bem como sobre a\nadequação das estratégias diagnósticas e terapêuticas\nà realidade psicossocial da clientela.", "B": "Trabalha em situações de agravamento físico e\nemocional, sem participar de decisões com relação à\nconduta a ser adotada em situações de internações,\nintervenções cirúrgicas, exames e altas hospitalares.", "C": "Cria, coordena e acompanha, individualmente ou em\nequipe multiprofissional, tecnologias próprias ao\ntreinamento em saúde, particularmente em saúde\nmental, com o objetivo de qualificar o desempenho de\nvárias equipes.", "D": "Participa da elaboração (e a acompanha) de programas\neducativos e de treinamento em saúde mental, a nível\nde atenção primária, em instituições formais e\ninformais como creches, asilos, sindicatos, associações,\ninstituições de menores, penitenciárias, entidades\nreligiosas etc.", "E": "Colabora, em equipe multiprofissional, no\nplanejamento das políticas de saúde, em nível de\nmacro e microssistemas."}, "g": "B", "j": "B esta incorreta: nas atribuicoes do psicologo clinico segundo CFP, ele PARTICIPA das decisoes em situacoes de internacao, intervencao cirurgica, exames e altas (interconsulta psicologica). A alternativa restringe indevidamente sua atuacao em equipe."}, {"id": "2158974", "d": "psicologia", "a": ["Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "A Terapia Cognitiva (TC) valoriza a aliança terapêutica na\nmedida em que considera o próprio processo terapêutico\numa descoberta guiada, um trabalho conjunto\ncaracterizado como um empiricismo colaborativo. Segundo\nCordioli, fazem parte do contrato na terapia cognitiva os\nseguintes itens:    \nI. participação ativa nas sessões – na avaliação do humor,\nno estabelecimento da agenda, na escolha das tarefas\nde casa e na avaliação da sessão;\n    II. desenvolvimento de habilidades para identificar\npensamentos e crenças disfuncionais;\nIII. desenvolvimento de habilidades para o uso de técnicas\ncognitivas;\n    IV. uso de instrumentos de automonitoramento.      \nAssinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens III e IV estão certos.", "D": "Apenas os itens I, II e III estão certos.", "E": "Apenas os itens II, III e IV estão certos."}, "g": "A", "j": "I (participacao ativa nas sessoes), II (identificar pensamentos e crencas disfuncionais), III (uso de tecnicas cognitivas) e IV (uso de instrumentos de automonitoramento) sao todos componentes do contrato terapeutico em TC segundo Cordioli. Todos = A."}, {"id": "2158973", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "Em relação aos tratamentos breves em psicoterapia, de\nacordo com Braier (1986), assinale a alternativa correta.", "alt": {"A": "É importante a indagação exaustiva dos dados\nbiográficos e do psicodiagnóstico, a fim de se elaborar\numa ampla hipótese psicodinâmica inicial, que\nfundamentará o planejamento terapêutico.", "B": "Não se pode trabalhar com boas perspectivas\nprognósticas com pacientes que apresentam\nmarcantes transtornos de personalidade.", "C": "Propiciar ao paciente a aquisição de insight por meio\nde interpretações transferenciais, especialmente dos\npsicodinamismos relacionados com os conflitos\nbásicos, deve constituir nosso principal propósito.", "D": "O trabalho terapêutico está “enfocado” para\ndeterminado conflito inconsciente do paciente, que\nadquire prioridade, dada a sua urgência, porém não se\ndeixam de lado as demais dificuldades.", "E": "As vezes teremos de mudar o foco, mas não as metas\nterapêuticas, em pleno tratamento. Mesmo que\nocorram situações novas ou imprevistas na vida do\npaciente."}, "g": "A", "j": "A esta correta segundo Braier: em tratamentos breves, a indagacao exaustiva dos dados biograficos e o psicodiagnostico inicial sao FUNDAMENTAIS para elaborar a hipotese psicodinamica que orientara o planejamento terapeutico focal. Demais alternativas trazem afirmacoes incorretas sobre prognostico, interpretacao transferencial central ou manutencao rigida das metas."}, {"id": "2158971", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "“A psicanálise, como psicologia profunda, considera a vida\npsíquica de três perspectivas: a dinâmica, a econômica e a\ntopológica”. De acordo com Freud (1926), assinale a\nalternativa correta.\n    I. A perspectiva dinâmica faz remontar todos os\nprocessos psíquicos - salvo a recepção de estímulos\nexternos - ao jogo de forças que promovem ou inibem\numas às outras, juntam-se, entram em compromissos\netc. Originalmente essas forças são todas da natureza\nde instintos [Triebe], ou seja, de origem orgânica,\ncaracterizada por enorme capacidade somática\n(compulsão à repetição), e acham representação\npsíquica em ideias investidas de afeto.\n    II. O ponto de vista econômico supõe que as\nrepresentações psíquicas dos instintos sofrem\ninvestimento (cathexis) de determinadas quantidades\nde energia e que o aparelho psíquico tende a evitar um\nrepresamento dessas energias e manter o mais baixa\npossível a soma total de excitações que a atingem. O\ncurso dos processos psíquicos é regulado pelo princípio\ndo prazer-desprazer.\n    III. O ponto de vista topológico apreende o aparelho\npsíquico como um instrumento composto. Segundo\nnossas concepções atuais, o aparelho psíquico se\ndivide em um Id, que é o portador dos impulsos\ninstintuais, em um Eu, que constitui a parte mais\nsuperficial do Id, modificada por influência do mundo\ninterior, e um Super-eu, que, oriundo do Id, domina o\nEu e representa as inibições instintuais características\ndo ser humano.      \nAssinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I (perspectiva dinamica como jogo de forcas) e II (perspectiva economica com investimento de energia e principio do prazer-desprazer) sao corretos. III esta errado: na perspectiva topologica freudiana, o Eu e parte modificada pelo MUNDO EXTERIOR (nao 'mundo interior') e e parte mais superficial do Id. Apenas I e II = B."}, {"id": "2158970", "d": "psicologia", "a": ["Psicanálise", "Freud", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2022", "org": "CFP", "t": "", "e": "Segundo Freud (1938), “o conceito de inconsciente por\nmuito tempo esteve batendo aos portões da psicologia,\npedindo para entrar. A psicanálise apossou-se do conceito,\npor suas pesquisas, ela foi conduzida a um conhecimento\ndas características do inconsciente psíquico que até então\nnão haviam sido suspeitadas, e descobriu algumas das leis\nque o governam”. Assinale a alternativa incorreta.", "alt": {"A": "A consciência é uma qualidade constante. A\nconsciência pode nos oferecer uma cadeia completa de\nfenômenos.", "B": "Os chamados processos psíquicos inconscientes são os\nprocessos orgânicos que há muito tempo foram\nreconhecidos como correndo paralelos aos mentais.", "C": "O psíquico, seja qual for sua natureza, é em si mesmo\ninconsciente e provavelmente semelhante em espécie\na todos os outros processos naturais de que obtivemos\nconhecimento.", "D": "Nosso trabalho científico em psicologia consistirá em\ntraduzir processos inconscientes em conscientes e,\nassim, preencher as lacunas da percepção consciente.", "E": "Nada disso implica que a qualidade de ser consciente\ntenha perdido sua importância para a psicanálise. Ela\npermanece uma luz que ilumina nosso caminho e nos\nconduz através das trevas da vida mental."}, "g": "A", "j": "A esta incorreta: a consciencia NAO e qualidade constante segundo Freud (e descontinua, intermitente) nem oferece cadeia completa de fenomenos (justamente por isso o inconsciente foi postulado, para preencher lacunas). A alternativa contradiz tese central freudiana."}, {"id": "2158966", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com Novaes de Sá (CFP, 2009), assinale a\nalternativa incorreta sobre psicoterapia.", "alt": {"A": "No caso da psicoterapia desenvolvida no âmbito da\nPsicologia, seu caráter específico é dado por dirigir-se\nessencialmente à subjetividade, tendo como condição\nde possibilidade a subjetividade do psicoterapeuta.", "B": "O que a singulariza, entre as diversas práticas\nterapêuticas, é o cuidado pela liberdade e pela\nautonomia possível do sujeito concreto e singular.", "C": "Uma clínica do sujeito caracteriza-se essencialmente, e\nprincipalmente, pelas representações conceituais\nsobre alguma estrutura psíquica, sobre leis de cognição\ne aprendizagem.", "D": "No contexto clínico, as perguntas e as respostas\nconcernentes às questões da vida nunca estão\nformuladas a priori, pois, ainda que se repitam, apenas\ntêm sentido a partir do contexto existencial concreto\nno qual surgem, como se fossem feitas sempre pela\nprimeira vez.", "E": "A psicoterapia não se reduz ao tipo de conhecimento\nque pode ser sistematizado em algum método e\nrepetido na forma de uma técnica, embora\nprocedimentos técnicos possam e devam ser utilizados\nna psicoterapia."}, "g": "C", "j": "C esta incorreta segundo Novaes de Sa: uma clinica do SUJEITO NAO se caracteriza essencialmente por representacoes conceituais sobre estrutura psiquica ou leis de cognicao/aprendizagem (isso seria objetivacao); caracteriza-se pelo cuidado com a singularidade do sujeito concreto."}, {"id": "2158965", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "Ao adotar o conceito de ambiência para a arquitetura nos\nespaços de saúde, atinge-se um avanço qualitativo no\ndebate da humanização dos territórios de encontros do\nSUS. Vai-se além da composição técnica, simples e formal\ndos ambientes, passando a considerar as situações que são\nconstruídas. O conceito de ambiência segue\nprimordialmente três eixos. Sobre eles, julgue os itens a\nseguir.    \nI. O espaço que visa à confortabilidade focada na\nprivacidade e na individualidade dos sujeitos\nenvolvidos, valorizando elementos do ambiente que\ninteragem com as pessoas – cor, cheiro, som,\niluminação, morfologia etc. – e garantindo conforto a\ntrabalhadores e usuários.    \nII. O espaço que possibilita a produção de subjetividades\n– encontro de sujeitos – por meio de ação e reflexão\nsobre os processos de trabalho.\n    III. O espaço usado como ferramenta facilitadora do\nprocesso de trabalho, favorecendo a otimização de\nrecursos, o atendimento humanizado, acolhedor e\nresolutivo.      \nAssinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "A", "j": "I (confortabilidade focada na privacidade, elementos sensoriais), II (espaco de producao de subjetividades e reflexao sobre processos de trabalho) e III (ferramenta facilitadora do trabalho, otimizacao de recursos, atendimento humanizado) sao os tres eixos do conceito de ambiencia no SUS. Todos = A."}, {"id": "2158964", "d": "psicologia", "a": ["Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação neuropsicológica (AN) começa a ser solicitada\nno contexto jurídico com diferentes finalidades. Considere\nessa prática e assinale a alternativa incorreta.", "alt": {"A": "Existem quatro principais objetivos da AN para\ncolaborar com a perícia: caracterizar a insanidade,\nverificar as capacidades mentais, decidir sobre pensão\nalimentícia, deliberar sobre penalidade adequada.", "B": "A AN pericial pode ter objetivos diferentes de acordo\ncom a vara judicial em que ocorre, no entanto deve\nbuscar incluir instrumentos fidedignos e válidos para\nincluir na bateria.", "C": "As perícias para estabelecer imputabilidade do réu\ninvestigam a saúde mental do examinando e suas\ncondições cognitivas, emocionais e comportamentais.", "D": "A verificação da eficácia do processo reeducativo inclui\num parecer sobre reinserção social e probabilidade de\nreincidência.", "E": "No âmbito trabalhista, a AN deve auxiliar na verificação\nda capacidade laboral e das condições mentais\nespecialmente para fins de aposentadoria."}, "g": "A", "j": "A esta incorreta: 'decidir sobre pensao alimenticia' nao e objetivo da avaliacao neuropsicologica pericial - e decisao judicial baseada em fatores patrimoniais/economicos. Os objetivos perciais corretos sao verificar imputabilidade, capacidades mentais, reabilitacao etc."}, {"id": "2158963", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos", "Outros Transtornos"], "ano": "2022", "org": "CFP", "t": "", "e": "Após o traumatismo cranioencefálico (TCE), distúrbios de\nsono e fadiga são frequentes. Sobre o tema, assinale a\nalternativa correta.", "alt": {"A": "O tratamento preferencial para o controle\nmedicamentoso da fadiga mental ocorre com o uso de\nantidepressivos.", "B": "A inexistência de medidas validadas de autorrelato\npara identificar e estimar o problema de sono leva o\nclínico a utilizar apenas entrevistas durante a avaliação.", "C": "O trabalho com clientes após TCE com fadiga deve ter\nintervalos flexíveis, independentemente do tipo de\nfadiga relatada (mental ou física).", "D": "Os distúrbios de sono nesse quadro associam-se a\nmaior prejuízo cognitivo e funcional, aumento da\nincidência de transtornos de humor e aumento da dor\ne redução da qualidade de vida.", "E": "Os actígrafos detectam os momentos de fadiga física\ncom precisão e podem ser utilizados durante a\nexecução das atividades de vida diária."}, "g": "D", "j": "D esta correta: os disturbios de sono apos TCE associam-se a maior prejuizo cognitivo e funcional, aumento da incidencia de transtornos de humor, aumento da dor e reducao da qualidade de vida - achados consolidados na literatura."}, {"id": "2158962", "d": "psicologia", "a": ["Psicopatologia", "CID-10 e DSM", "Outros Transtornos"], "ano": "2022", "org": "CFP", "t": "", "e": "O estudo do sono e seus transtornos demonstraram\nimplicações para as funções cognitivas. Assinale a\nalternativa correta.", "alt": {"A": "A relação entre sono e cognição nas diferentes fases do\ndesenvolvimento se mantém inalterada em termos de\nsua organização e papel.", "B": "A restrição do sono resulta em diminuição da ativação\ncerebral nos córtices pré-frontal, parietal inferior e\ntemporal superior.", "C": "A principal estrutura responsável pelo ritmo biológico\ncircadiano é o lobo temporal, especificamente, o\nhipocampo.", "D": "O distúrbio do sono prevalente na população brasileira\né a síndrome das pernas inquietas quando se observam\nproblemas de memória não declarativa.", "E": "Os prejuízos cognitivos causados pela apneia do sono\nrelacionam-se com problemas recorrentes no\narmazenamento envolvido no domínio da memória\nepisódica."}, "g": "B", "j": "B esta correta: a restricao do sono resulta em diminuicao da ativacao cerebral em areas pre-frontais, parietais inferiores e temporais superiores - achados de neuroimagem em estudos de privacao de sono. Demais alternativas trazem inconsistencias anatomicas e clinicas."}, {"id": "2158961", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "O diagnóstico de Comprometimento Cognitivo Leve (CCL) tem\nsido intensamente estudado. Assinale a alternativa correta.", "alt": {"A": "Existem evidências suficientes para comprovar que o\ntreino cognitivo impede a progressão das perdas\ncognitivas.", "B": "Segundo o DSM-V, idosos com depressão desenvolvem\nCCL, e essas duas comorbidades não podem ser\ndiscriminadas.", "C": "A observação comportamental e o aconselhamento\nsão as duas principais técnicas utilizadas no diagnóstico\nde CCL.", "D": "Os déficits em atividades de vida diária instrumentais\nnão podem ser observados diretamente. Assim, sua\ninvestigação não deve ser aprofundada.", "E": "O indivíduo com tal diagnóstico apresenta\nfuncionamento cognitivo global e as atividades da vida\ndiária instrumentais e ocupacionais preservadas."}, "g": "E", "j": "E esta correta: o Comprometimento Cognitivo Leve (CCL) caracteriza-se por funcionamento cognitivo global e atividades da vida diaria instrumentais/ocupacionais PRESERVADAS, com declinio cognitivo objetivo em pelo menos um dominio - definicao classica que o distingue da demencia."}, {"id": "2158960", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "O envelhecimento da população brasileira exigiu que o\nneuropsicólogo se capacitasse para diagnosticar os quadros\nde demência e intervir neles. Considerando tais quadros\nclínicos, assinale a alternativa incorreta.", "alt": {"A": "A Doença de Alzheimer (DA) é a causa preponderante\ndos quadros demenciais.", "B": "Uma diferença entre a DA e a demência frontotemporal\n(DFT) é que esta última se manifesta mais\nfrequentemente entre 45 e 65 anos, enquanto a primeira\ntende a se apresentar após a idade de 65 anos.", "C": "As demências têm em comum a etiologia dos sintomas\ne os domínios cognitivos afetados.", "D": "A demência com corpos de Lewy é marcada pela\npresença de parkinsonismo, alucinações visuais e\nflutuação cognitivas", "E": "A demência vascular é a segunda causa mais frequente\nde demências e associa-se a diferentes tipos de lesão\nvascular encefálica, o que leva a uma variabilidade nos\nresultados da avaliação cognitiva."}, "g": "C", "j": "C esta incorreta: as demencias NAO tem etiologia comum nem dominios cognitivos comuns afetados - sao quadros etiologicamente heterogeneos (Alzheimer, DFT, vascular, corpos de Lewy etc.) com perfis cognitivos distintos. A alternativa generaliza indevidamente."}, {"id": "2158959", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Avanços importantes na avaliação neuropsicológica de\ncrianças em idade pré-escolar ocorreram neste século.\nAssinale a alternativa correta quanto às peculiaridades da\navaliação em tal faixa etária.", "alt": {"A": "Os estudos apontam para a falibilidade do processo de\navaliação neuropsicológica com instrumentos\npadronizados. Oor isso, recomenda-se a entrevista\nlúdica.", "B": "Os princípios da intervenção precoce substituíram a\nrealização das tarefas funcionais e cognitivas em\ncrianças não oralizadas.", "C": "Os diagnósticos de transtornos do\nneurodesenvolvimento devem ser feitos apenas após o\nquarto ano de vida.", "D": "Durante a entrevista devolutiva, o neuropsicólogo deve\nevitar apontar as dificuldades observadas na criança\nquando elas não indicam um diagnóstico específico.", "E": "A avaliação do desenvolvimento em suas diversas\ndimensões é complexa e exige trabalho em equipe e a\ncolaboração de pais e cuidadores."}, "g": "E", "j": "E esta correta: a avaliacao neuropsicologica de pre-escolares e complexa, multidimensional, e exige trabalho em equipe e colaboracao de pais/cuidadores como informantes essenciais. Demais alternativas restringem ou contradizem boas praticas."}, {"id": "2158958", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação neuropsicológica deve gerar um documento\nque apresente os principais achados e recomendações.\nAssinale a alternativa correta quanto ao relatório.", "alt": {"A": "A identificação, item inicial do relatório, deve conter\nunicamente os dados da criança: nome, idade e\nescolaridade.", "B": "As observações diretas do comportamento do cliente\nfeitas sem escalas específicas constituem material\nsuplementar e devem ser apresentadas em anexo ao\ndocumento.", "C": "A linguagem dos documentos deve ser neutra, clara e\nsem julgamentos pessoais.", "D": "Os resultados dos testes padronizados precisam ser\napresentados numericamente em gráfico ou tabela por\nmeio da comparação dos percentis obtidos em cada\num deles; a interpretação deles é opcional.", "E": "Como as atividades informais enviesam os dados\ndiagnósticos, não precisam ser relatadas nem\ndocumentadas."}, "g": "C", "j": "C esta correta: o relatorio neuropsicologico deve ter linguagem NEUTRA, CLARA e SEM JULGAMENTOS PESSOAIS - principios da Res CFP 06/2019. Demais alternativas restringem identificacao (A), classificam erroneamente observacoes (B), tornam interpretacao opcional (D) ou omitem atividades informais (E)."}, {"id": "2158957", "d": "psicologia", "a": ["Transtornos da Ansiedade"], "ano": "2022", "org": "CFP", "t": "", "e": "Considere o diagnóstico de transtorno obsessivo\ncompulsivo e as possíveis contribuições da neuropsicologia\ne assinale a alternativa correta.", "alt": {"A": "Os déficits de linguagem são os mais frequentes.", "B": "A fisiopatologia parece envolver os córtices pré-frontal\ndorsolateral e orbito frontal lateral e núcleo caudado.", "C": "O papel do hipocampo no transtorno evidencia as\ndificuldades de memória semântica.", "D": "As funções executivas permanecem saudáveis, posto\nque o automonitoramento busca a precisão das\nrespostas.", "E": "A percepção auditiva deve ser investigada\ncuidadosamente para determinar a presença de\nagnosias auditivas."}, "g": "B", "j": "B esta correta: a fisiopatologia do TOC envolve o circuito cortico-estrio-talamico-cortical, com participacao do cortex pre-frontal dorsolateral, orbito-frontal lateral e nucleo caudado - achados consolidados em neuroimagem do TOC."}, {"id": "2158956", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Humor"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação à neuropsicologia do transtorno depressivo\nmaior, julgue os itens a seguir.\n    I. Há um consenso na literatura de que existe um\ncomprometimento de múltiplos domínios cognitivos.    \nII. Um modelo neurobiológico sobre a depressão sugere\nque existe uma atividade excessiva em áreas límbicas e\ninibição em áreas pré-frontais.    \nIII. Os sintomas emocionais e motivacionais parecem estar\nrelacionados ao déficit nas funções executivas.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (comprometimento de multiplos dominios cognitivos), II (modelo neurobiologico de hiperatividade limbica e inibicao pre-frontal) e III (sintomas emocionais/motivacionais relacionados ao deficit em funcoes executivas) sao todos consistentes com a neuropsicologia da depressao. Todos = D."}, {"id": "2158955", "d": "psicologia", "a": ["Psicopatologia", "Transtornos da Ansiedade"], "ano": "2022", "org": "CFP", "t": "", "e": "Transtornos de ansiedade (T.A.), quando ocorrem na\ninfância, podem trazer prejuízos acadêmicos, sociais e\nfuncionais. Assinale a alternativa incorreta.", "alt": {"A": "O transtorno de ansiedade de pânico foi retirado na\núltima edição do DSM-V.", "B": "Comprometimentos atencionais e mnemônicos são\nobservados com frequência.", "C": "O comportamento inibido observado em crianças pode\nestar associado ao aumento da vigilância", "D": "Existem evidências que crianças com diagnóstico de\nansiedade social apresentam dificuldade em\nreconhecer faces de felicidade, tristeza e nojo.", "E": "Estudos sugerem que T.A. generalizado prediz maior\norientação da atenção em direção a ameaças."}, "g": "A", "j": "A esta incorreta: o Transtorno de Panico NAO foi retirado do DSM-5 - continua sendo diagnostico valido (300.01). A alternativa contem informacao factualmente falsa."}, {"id": "2158954", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa correta quanto ao transtorno de\ndéficit de atenção hiperatividade.", "alt": {"A": "Estudos de ressonância magnética revelaram o\nenvolvimento de regiões frontais e occipitais.", "B": "Déficits de memória operacional, de velocidade\npsicomotora, de atenção sustentada e de controle\ninibitório são frequentes.", "C": "De acordo com o DSM-V, o transtorno de espectro\nautista não pode ser comorbidade do TDAH.", "D": "Os novos parâmetros admitem que o diagnóstico seja\nfeito para adultos mesmo que não relatem queixas\ndurante a infância.", "E": "A inteligência geralmente está rebaixada em\nadolescentes com TDAH."}, "g": "B", "j": "B esta correta: o TDAH apresenta deficits frequentes em memoria operacional, velocidade psicomotora, atencao sustentada e controle inibitorio - perfil neuropsicologico classico do transtorno. A (envolve frontoestriatal, nao occipital), C (TEA pode ser comorbido), D (queixas na infancia sao necessarias) e E (inteligencia nao esta rebaixada) sao incorretas."}, {"id": "2158953", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2022", "org": "CFP", "t": "", "e": "A reabilitação cognitiva apresenta técnicas de intervenção\nque fundamentam as escolhas de estratégias. Assinale a\nalternativa correta.", "alt": {"A": "A reestruturação visa ao fortalecimento da função por\nprática, repetição e organização das informações.", "B": "A restauração considera o planejamento e a\nmodificação ambiental facilitando a funcionalidade.", "C": "A mediação busca equilibrar as funções cognitivas com\no perfil de personalidade.", "D": "A compensação estimula a realização de atividades por\nmeio de estratégias e apoios externos.", "E": "A autoavaliação utiliza o ensino de parâmetros\npsicométricos para os clientes."}, "g": "D", "j": "D esta correta: a COMPENSACAO em reabilitacao cognitiva consiste em estimular a realizacao de atividades por meio de estrategias e apoios externos (agendas, listas, lembretes, dispositivos). Demais alternativas trocam definicoes (restauracao seria fortalecer a funcao, modificacao ambiental seria adaptacao)."}, {"id": "2158952", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "Um dos modelos de reabilitação neuropsicológica mais\nimportantes é o Modelo Holístico. Considerando- o,\nassinale a alternativa incorreta.", "alt": {"A": "Procura enfocar o treino cognitivo por meio de um\nprograma computadorizado de intervenção.", "B": "Preocupa-se em aumentar a conscientização do cliente\ne aliviar os déficits cognitivos.", "C": "Inclui intervenções para abordar as questões\nemocionais da lesão cerebral.", "D": "Busca compreender os problemas de identidade\nrelacionados às mudanças no autoconceito e às novas\nlimitações funcionais.", "E": "Integra a família dos clientes nas intervenções para\neleger prioridades e compreender expectativas."}, "g": "A", "j": "A esta incorreta: o Modelo Holistico de reabilitacao neuropsicologica NAO se foca em treino cognitivo por programa computadorizado isolado - integra dimensoes cognitivas, emocionais, identitarias, familiares e sociais. A alternativa reduz indevidamente o modelo."}, {"id": "2158951", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2022", "org": "CFP", "t": "", "e": "A cognição social consiste na habilidade de identificar,\nmanipular e adequar o comportamento de acordo com\ninformações do ambiente social (Monteiro & Louzã, 2018).    \nAssinale a alternativa incorreta.", "alt": {"A": "A neurocognição e a cognição social são diferentes\nformas de análise do comportamento humano.", "B": "Testes de reconhecimento de faces e tarefas de Teoria\nda Mente são exemplos de instrumentos de avaliação\ndesse domínio.", "C": "O cerebelo e os gânglios da base são as principais\nestruturas envolvidas no processamento emocional e\nna tomada de decisão.", "D": "O processamento automático da informação social é\nqualitativamente diferente do processamento\ncontrolado.", "E": "A Teoria da Mente pode ser observada em estudos\ncom humanos e com primatas."}, "g": "C", "j": "C esta incorreta: o cerebelo e os ganglios da base NAO sao as principais estruturas do processamento emocional - sao predominantemente AMIGDALA, INSULA, CORTEX PRE-FRONTAL (especialmente ventromedial e orbitofrontal) e cortex cingulado. A alternativa erra a neuroanatomia."}, {"id": "2158950", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "“Um dos aspectos cruciais do desenvolvimento psicológico\nhumano é o aumento da capacidade de autorregulação dos\nprocessos cognitivos, emoções e comportamentos.”\n  Oliveira & Correia, 2021.\n        Assinale a alternativa correta sobre o desenvolvimento.", "alt": {"A": "A substância cinzenta e a branca do cérebro seguem\numa trajetória na forma de V e completam seu\ncrescimento durante a puberdade.", "B": "Existem marcos na aquisição da linguagem. Por\nexemplo: começo das vocalizações aos 12 meses;\nprimeiras palavras aos 26 meses; e enunciação de\nfrases simples aos 36 meses.", "C": "Os sistemas atencionais executivos são os primeiros a\nse desenvolverem completamente, e a atenção\nsustentada é o primeiro componente atencional a\ndiminuir com o envelhecimento.", "D": "O declínio da eficiência da memória de longo prazo no\nenvelhecimento pode ser percebido primeiramente\ndurante as tarefas de reconhecimento e depois nas\ntarefas de evocação livre.", "E": "A inibição apresenta uma progressão acentuada antes\ndos 6 anos de vida enquanto a flexibilidade cognitiva e\na memória operacional têm incremento mais\nprolongado."}, "g": "E", "j": "E esta correta: a INIBICAO tem progressao acentuada antes dos 6 anos enquanto FLEXIBILIDADE COGNITIVA e MEMORIA OPERACIONAL tem incremento mais prolongado (ate a adolescencia/inicio adultez). Demais alternativas trocam marcos do desenvolvimento neurocognitivo."}, {"id": "2158949", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto ao campo de estudo da discalculia, assinale a\nalternativa correta.", "alt": {"A": "As dificuldades observadas na trigonometria decorrem\ndos problemas em discriminar a magnitude dos\nconjuntos.", "B": "Os transtornos específicos de aprendizagem são\nindependentes e raramente coocorrem.", "C": "Recentemente foram identificados biomarcadores para\na discalculia como a presença do gene APOE2.", "D": "Existe um modelo explicativo desse transtorno que\npropõe que os déficits decorrem de um\ncomprometimento do senso numérico.", "E": "Por meio das técnicas de neuroimagem, observou-se\ncomprometimento persistente no hipocampo de\ncrianças com discalculia."}, "g": "D", "j": "D esta correta: o modelo do SENSO NUMERICO (Dehaene) propoe que os deficits da discalculia decorrem de comprometimento desse sistema basico de representacao das quantidades. A trigonometria (A) e habilidade de alto nivel; transtornos de aprendizagem CO-OCORREM com frequencia (B errada); APOE2 (C) e marcador de Alzheimer; hipocampo (E) nao e a area chave."}, {"id": "2158948", "d": "psicologia", "a": ["Comunicação em Psicologia", "Psicologia e Organizações"], "ano": "2022", "org": "CFP", "t": "", "e": "A linguagem permite a utilização de sistemas de\ncomunicação complexos. Com essa perspectiva, assinale a\nalternativa que não se aplica a essa função cognitiva.", "alt": {"A": "A aquisição da linguagem é maturacional, ou seja,\nindepende das interações sociais.", "B": "Propriedades importantes da linguagem são a\narbitrariedade simbólica e a estruturação hierárquica.", "C": "Seu processamento se fundamenta inicialmente na\ncompreensão receptiva e na decodificação e,\nposteriormente, na codificação expressiva e na\nprodução dos códigos linguísticos.", "D": "Existe um período crítico de aquisição da primeira\nlíngua em que o inato e o aprendido ocorrem\nsimultaneamente.", "E": "Existem centros localizados nos hemisférios esquerdo e\ndireito e modulados por estruturas subcorticais que\ncoordenam os processos dessa função."}, "g": "A", "j": "A NAO se aplica a linguagem: a aquisicao da linguagem NAO e puramente maturacional - DEPENDE essencialmente das interacoes sociais (input linguistico, motherese, conversacao). Demais alternativas (arbitrariedade simbolica, processamento receptivo/expressivo, periodo critico, lateralizacao) descrevem corretamente a linguagem."}, {"id": "2158947", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa correta sobre a neuroplasticidade", "alt": {"A": "Trata exclusivamente de apoptose que ocorre durante\na primeira infância.", "B": "Justifica o fato de lesões durante a infância serem\ncuráveis, enquanto aquelas ocorridas na vida adulta\nterem perfil crônico.", "C": "O termo denomina as alterações estruturais do\nadolescente, enquanto “reestruturação cognitiva” se\nrefere ao aumento de conexões no cérebro.", "D": "Consiste na alteração na estrutura e na função do\nsistema nervoso que ocorre em qualquer etapa da\nontogenia decorrente da interação com o meio\nambiente interno e externo.", "E": "A nível neuroquímico, a dopamina é o principal\nneurotransmissor envolvido no processo."}, "g": "D", "j": "D esta correta: a neuroplasticidade consiste em alteracao na estrutura e funcao do sistema nervoso que ocorre em QUALQUER etapa da ontogenia (do desenvolvimento ao envelhecimento) decorrente da interacao com o meio ambiente interno e externo - definicao ampla aceita."}, {"id": "2158944", "d": "psicologia", "a": ["Psicopatologia", "CID-10 e DSM"], "ano": "2022", "org": "CFP", "t": "", "e": "O Manual Diagnóstico e Estatístico de Transtornos Mentais\n(DSM-V) alterou consideravelmente o conceito de\ndeficiência intelectual (DI). Considerando a colaboração da\nneuropsicologia para a compreensão do conceito de\ninteligência e sua avaliação, julgue os itens a seguir.\n    I. A etiologia da deficiência intelectual é heterogênea e\nestá correlacionada com desnutrição, privação cultural\ne saúde precária, no entanto as causas genéticas são as\nfrequentes.\n    II. O DSM-V estabelece 3 principais critérios para o\ndiagnóstico: limitações nas habilidades mentais gerais\n(QI dois desvios padrão abaixo da média), dificuldade\nde funcionamento em pelo menos 2 domínios\nadaptativos e características observadas antes dos 18\nanos de idade.    \nIII. Uma das mudanças mais importantes para a avaliação\nde pessoas com DI foi a incorporação dos\ncomportamentos adaptativos aos critérios\ndiagnósticos, posto que a ênfase passou a ser dada em\nhabilidades como autonomia e autocuidado.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (etiologia heterogenea com causas genecicas frequentes), II (3 criterios DSM-5: QI 2dp abaixo da media, dificuldades em pelo menos 2 dominios adaptativos, inicio antes dos 18 anos) e III (incorporacao dos comportamentos adaptativos como criterio diagnostico) sao todos consistentes com o DSM-5. Todos = E."}, {"id": "2158943", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2022", "org": "CFP", "t": "", "e": "A percepção visual foi estudada desde os primórdios da\npsicologia, e tal função é fundamental para o\ndesenvolvimento das habilidades visuoespaciais e\nconstrutivas. Assinale a alternativa incorreta.", "alt": {"A": "As áreas visuais e espaciais associativas localizadas no\nlobo parieto-occiptal têm como função a orientação\ntopográfica, a localização no espaço e a orientação\nquanto à direção e à distância.", "B": "A prosopagnosia, ou seja, dificuldade em reconhecer\nfaces familiares, está relacionada à lesão bilateral no\nlobo occipital.", "C": "A avaliação das habilidades visuoespaciais e\nconstrutivas inclui uma variedade de tarefas como\ntarefas de percepção e discriminação visual, de\npercepção visual de objetos, de orientação espacial e\nde discriminação figura-fundo.", "D": "As agnosias visuais aperceptivas, quando a pessoa não\nconsegue descrever as características de estrutura e\nforma do estímulo, relacionam-se com o\nprocessamento ascendente da percepção.", "E": "As apraxias construtivas, distúrbio que consiste na\ntendência de negligenciar uma metade do espaço extra\npessoal durante realização de atividades, são comuns\nem crianças."}, "g": "E", "j": "E esta incorreta: o disturbio que consiste em 'negligenciar uma metade do espaco extra pessoal' e HEMINEGLIGENCIA (neglect), nao apraxia construtiva. A apraxia construtiva e dificuldade de copia/construcao espacial. A alternativa confunde duas condicoes distintas e adiciona 'comuns em criancas' (incorreto)."}, {"id": "2158942", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação da memória é parte integrante da avaliação\nneuropsicológica, posto que disfunções mnemônicas são\nfrequentes em quadros clínicos. Assinale a alternativa\nincorreta.", "alt": {"A": "A avaliação da memória implícita é feita através de\nmétodos qualitativos como observações, entrevistas e\njogos.", "B": "A reabilitação da memória se utiliza de estratégias\ninternas que interferem com o processo mnemônico e\nexternas que incluem equipamentos e outras\ntecnologias.", "C": "Os testes, como as listas de palavras, acessam a\nmemória operacional não declarativa.", "D": "A amnésia anterógrada é frequente após traumatismo\ncranioencefálico e se refere à habilidade de aprender\nnovas informações.", "E": "O “priming” envolve o armazenamento sensorial por\nmeio de um processo de codificação sem consciência."}, "g": "C", "j": "C esta incorreta: as listas de palavras acessam a memoria EPISODICA DECLARATIVA (memoria explicita), nao a memoria operacional nao declarativa. A alternativa troca os sistemas de memoria."}, {"id": "2158940", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "Conhecer as relações entre regiões cerebrais e funções\ncognitivas é essencial para o neuropsicólogo. Assinale a\nalternativa correta.", "alt": {"A": "O córtex de projeção auditiva localiza-se no chamando\nplano parietal, nas áreas de Brodmann 41 e 42.", "B": "No córtex visual primário, observa-se uma\ncorrespondência entre regiões da retina e sua\nrepresentação.", "C": "A área visual de associação unimodal ocupa regiões\ndos lobos occipital e parietal.", "D": "O córtex somestésico se encontra no lobo temporal e\nrecebe fibras da porção posterior do tálamo.", "E": "O córtex pré-frontal recebe fibras talâmicas e, por isso,\né um dos últimos a mostrar involução com o\nenvelhecimento."}, "g": "B", "j": "B esta correta: o cortex visual primario (V1) tem organizacao RETINOTOPICA - correspondencia ponto a ponto entre regioes da retina e suas representacoes corticais. A (auditivo esta no temporal superior), C (visual associativa esta no occipital), D (somestesico esta no parietal), E (pre-frontal involui precocemente) sao incorretas."}, {"id": "2158939", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "Considerando os conhecimentos de neuroanatomia\nfuncional que fundamentam a neuropsicologia, julgue os\nitens a seguir.    \nI. Isocórtex apresenta 6 camadas de células\nmorfologicamente diferentes: camada molecular,\ngranular externa, piramidal externa, granular interna,\npiramidal interna e camada das células fusiformes.      \nII. As áreas límbicas conectam-se com o hipotálamo e\náreas de associação unimodais, e tais conexões\nrespondem pelas áreas motoras e sensoriais. Por essa\nrazão, quando as áreas límbicas são lesionadas,\napraxias são observadas.    \nIII. Cinco redes neurocognitivas integradas são\nconhecidas. Uma delas, a rede para atenção espacial,\ntem epicentros nos córtices parietal, pré-frontal e giro\ndo cíngulo, predominantemente no hemisfério direito.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item I está certo", "C": "Apenas os itens II e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "A", "j": "I (isocortex com 6 camadas: molecular, granular externa, piramidal externa, granular interna, piramidal interna, fusiformes) e III (rede de atencao espacial com epicentros em cortices parietal, pre-frontal e cingulo, predominantemente no hemisferio direito - modelo de Mesulam) sao corretos. II esta errado: lesoes limbicas causam alteracoes emocionais/memoria, nao apraxias. Apenas I e III = A."}, {"id": "2158938", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2022", "org": "CFP", "t": "", "e": "Pereira e Carneiro (2018) apresentaram o papel histórico\ndo estudo de caso para a neuropsicologia. Assinale a\nalternativa que caracteriza o estudo de caso na área.", "alt": {"A": "Técnicas estatísticas descritivas e inferenciais\ninadequadas.", "B": "Falta de validade e fidedignidade.", "C": "Estudo transversal e prospectivo.", "D": "Estudo naturalístico e descritivo.", "E": "Falta de medidas repetidas e longitudinais"}, "g": "D", "j": "D esta correta: o estudo de caso na neuropsicologia caracteriza-se como NATURALISTICO (estudo do paciente em seu contexto real) e DESCRITIVO (relato pormenorizado dos fenomenos observados). Demais alternativas negam suas caracteristicas (validade, repeticao etc.)."}, {"id": "2158937", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2022", "org": "CFP", "t": "", "e": "A entrevista clínica é parte importante tanto do processo\nde avaliação quanto do de intervenção em neuropsicologia.\nAssinale a alternativa que não está correta sobre a\nentrevista clínica em neuropsicologia.", "alt": {"A": "O modelo mais utilizado na área da neuropsicologia é o\nda entrevista semiestruturada.", "B": "A entrevista neuropsicológica com adultos exige\nconhecimento geral sobre seu cotidiano e dispensa a\ninvestigação sobre o desenvolvimento das funções\ncognitivas.", "C": "A entrevista com a família de crianças é importante,\npois traz informações fidedignas.", "D": "No diagnóstico de demência, a interação entre fatores\ncognitivos e funcionais deve ser questionada\ndetalhadamente com foco nas atividades da vida diária\ne nas instrumentais.", "E": "A entrevista deve colaborar para estabelecer o nível de\nfuncionamento cognitivo pré-mórbido."}, "g": "B", "j": "B esta incorreta: a entrevista neuropsicologica com adultos NAO dispensa a investigacao sobre desenvolvimento das funcoes cognitivas - historia do desenvolvimento (escolar, profissional, eventos significativos) e essencial para estabelecer funcionamento pre-morbido e fatores etiologicos."}, {"id": "2158936", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Comparando a avaliação psicológica com a avaliação\nneuropsicológica, assinale a alternativa que corresponde à\nconcepção incorreta sobre esse assunto.", "alt": {"A": "Os dois tipos de avaliação se assemelham em seus\nprocessos à medida em que incluem entrevistas,\nanamneses, escalas e instrumentos padronizados.", "B": "A avaliação neuropsicológica encontra-se\nfundamentada em modelos neurocognitivos, ou seja,\nrelação entre funções cognitivas, executivas e\ncomportamentos com o funcionamento do sistema\nnervoso central.", "C": "A avaliação psicológica privilegia a abordagem\nnomotética, que busca comparar o desempenho do\nindivíduo com o grupo normativo.", "D": "A avaliação neuropsicológica foi inicialmente concebida\npara avaliar indivíduos com lesão encefálica durante o\nperíodo de guerra.", "E": "Os dois tipos de avaliação diferenciam-se devido ao\nfato de que a avaliação neuropsicológica não deve\nincluir testes de personalidade."}, "g": "E", "j": "E esta incorreta: a avaliacao neuropsicologica PODE e frequentemente INCLUI testes de personalidade (especialmente para avaliacao de mudancas pos-lesao, transtornos psiquiatricos comorbidos). A alternativa restringe indevidamente o escopo da AN."}, {"id": "2158935", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2022", "org": "CFP", "t": "", "e": "“Discorrer sobre as origens da reabilitação cognitiva pode\nfacilitar o raciocínio clínico do terapeuta, uma vez que se\ntrata de um tema que comporta um conglomerado de\nconhecimentos oriundos de diferentes vertentes filosóficas,\nsociais e científicas.”\n    Abrisqueta-Gomez & Silva, 2016.\n    Assinale a alternativa correta de acordo com a constatação\ncitada.", "alt": {"A": "A reabilitação cognitiva tem por objetivo a reparação\ndas funções cognitivas deficitárias.", "B": "O treino cognitivo é o método de intervenção que\natualmente acumula maior evidência de eficácia.", "C": "A maioria dos pesquisadores concorda que a\nreabilitação cognitiva é um processo interativo entre\ncliente, sua família e a equipe de profissionais.", "D": "A ciência contemporânea demonstrou que existe uma\ndeterminação genética e as interações sociais são\nineficazes para influenciar o perfil fenotípico.", "E": "Existem três principais técnicas de reabilitação\ncognitiva: cirúrgica, funcional e ambiental."}, "g": "C", "j": "C esta correta: ha consenso de que a reabilitacao cognitiva e processo INTERATIVO entre cliente, sua familia e a equipe de profissionais - integra dimensoes psicossociais, nao apenas neuropsicologicas. Demais alternativas reduzem a reabilitacao a 'reparacao', supervalorizam treino cognitivo, negam plasticidade ou inventam tipologia."}, {"id": "2153997", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "No que diz respeito à ética do psicólogo na avaliação\npsicológica, assinale a alternativa incorreta.", "alt": {"A": "Definir atributos e características a serem avaliadas.", "B": "Ensinar as pessoas a responder aos testes psicológicos,\ninfluenciando no desempenho.", "C": "Saber os limites de sua atuação.", "D": "Oferecer informações claras e adequadas no processo\nde avaliação.", "E": "Responsabilizar-se pela qualidade na administração\ndos testes psicológicos."}, "g": "B", "j": "B esta incorreta: ENSINAR pessoas a responder aos testes psicologicos para influenciar o desempenho viola a etica e a integridade do processo de avaliacao - configura quebra etica grave. Demais alternativas descrevem condutas eticas validas."}, {"id": "2153996", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Os métodos projetivos envolvem tarefas vagas ou ambíguas\ncom instruções relativamente amplas. Acerca dos métodos\nprojetivos, assinale a alternativa correta.", "alt": {"A": "Os estímulos dos métodos projetivos são ordenados de\ntal modo que o examinando discorra sobre os temas\noferecidos, sem que se desmotive da tarefa.", "B": "Pfister, Zulliguer e Fábulas de Düss são exemplos de\ntestes projetivos aprovados pelo Satepsi.", "C": "O Teste de Apercepção Temática consiste em uma\ntarefa em que o examinando precisa contar histórias.", "D": "No Teste das Pirâmides Coloridas de Pfister, o\nexaminando deve realizar uma série sequencial de\ndesenhos.", "E": "O termo projetivo proposto por Frankl remete à\npsicanálise, fazendo com que os resultados obtidos a\npartir dos testes projetivos sejam interpretados a partir\nde teorias psicodinâmicas."}, "g": "C", "j": "C esta correta: o Teste de Apercepcao Tematica (TAT) de Murray consiste em apresentar pranchas com cenas ambiguas a partir das quais o examinando deve CONTAR HISTORIAS, revelando dinamica intrapsiquica e necessidades motivacionais."}, {"id": "2153995", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca da técnica projetiva do desenho HTP (Casa, Árvore,\nPessoa), assinale a alternativa correta.", "alt": {"A": "O teste HTP permite uma descrição detalhada das\ncapacidades cognitivas da pessoa avaliada.", "B": "O teste HTP tem por objetivo compreender aspectos\nda personalidade do indivíduo, bem como a forma de\nesse indivíduo interagir com as pessoas e com o\nambiente.", "C": "A tarefa consiste em realizar, no mínimo, 4 desenhos.", "D": "O desenho da árvore evoca associações referentes à\nvida familiar do sujeito e às relações intrafamiliares.", "E": "As respostas são determinadas pelo conteúdo\nnomotético trazido pelo indivíduo."}, "g": "B", "j": "B esta correta: o HTP (Casa, Arvore, Pessoa) de Buck tem por objetivo compreender aspectos da personalidade e do modo do individuo interagir com pessoas e ambiente, atraves da analise projetiva dos desenhos."}, {"id": "2153994", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A inteligência é uma capacidade mental muito geral que,\nentre outras coisas, implica a habilidade para raciocinar,\nplanejar, resolver problemas, pensar de maneira abstrata e\naprender da experiência. Não se pode considerar um mero\nconhecimento enciclopédico, uma habilidade acadêmica\nparticular ou uma destreza para resolver um teste.\nEntretanto, reflete uma capacidade mais ampla e profunda\npara compreender o ambiente – perceber, dar sentido às\ncoisas ou imaginar o que deve ser feito. Sobre as\nformulações teóricas acerca da inteligência e a avaliação da\ninteligência, julgue os itens a seguir.\n    I. Spearman, considerado o pai da psicometria,\nacreditava na ideia da existência de um fator geral\nunitário de inteligência (fator G).\n  II. O conceito de inteligência envolve as habilidades de\nplanejamento e resolução de problemas.\n  III. Stern criou o conceito de quociente intelectual (QI),\nrepresentado pela fração cujo numerador é a idade\ncronológica e o denominador é a idade mental.\n  IV. Thurstone defendia a ideia de que a inteligência\nconsistia em uma entidade multifatorial.\nAs escalas de Wechsler, em versão para adultos e para\ncrianças, não são atualmente utilizadas como\nindicativos para a avaliação da inteligência.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e III estão certos.", "B": "Apenas os itens I e IV estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens III, IV e V estão certos.", "E": "Apenas os itens I, II e IV estão certos."}, "g": "E", "j": "I (Spearman e fator G), II (inteligencia envolve planejamento e resolucao de problemas) e IV (Thurstone com habilidades primarias multifatoriais) sao corretos. III esta errado: o QI de Stern e (idade MENTAL/idade CRONOLOGICA) x 100 - a ordem da fracao esta invertida na alternativa. V tambem esta errado (Wechsler e amplamente usado). Apenas I, II e IV = E."}, {"id": "2153993", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Maria participou de um processo seletivo para uma vaga na\nárea de vendas e respondeu à Bateria Fatorial de\nPersonalidade. Maria teve desempenho situado no\npercentil 90 no fator de socialização. Maria tem uma\nsocialização:", "alt": {"A": "alta, ou seja, é uma pessoa que adora ideias novas e\nsempre novas formas de fazer as coisas.", "B": "alta, o que significa que é uma pessoa rude e hostil\ncom as demais pessoas.", "C": "alta, o que significa que ela é uma pessoa que tende a\nconfiar nos outros e acredita no lado bom das pessoas.", "D": "maior que 90% da amostra normativa.", "E": "média."}, "g": "D", "j": "D esta correta: estar no percentil 90 significa que o escore de Maria e maior do que 90% da amostra normativa - definicao psicometrica de percentil. As alternativas A, B e C interpretam erroneamente o conteudo do fator de socializacao."}, {"id": "2153992", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2022", "org": "CFP", "t": "", "e": "O Conselho Federal de Psicologia publicou a Resolução nº\n009/2018, que apresenta as diretrizes para a condução do\nprocesso de avaliação psicológica. Nesse sentido, a\navaliação psicológica tem objetivo de:", "alt": {"A": "produzir documentos escritos acerca do\nfuncionamento psicológico das pessoas.", "B": "fornecer informações que auxiliem no processo de\ntomada de decisões.", "C": "desenvolver instrumentos que mensurem fenômenos\npsicológicos.", "D": "aplicar testes psicológicos.", "E": "treinar profissionais da área para terem expertise na\nutilização de instrumentos psicológicos."}, "g": "B", "j": "B esta correta segundo Res CFP 09/2018: o objetivo central da avaliacao psicologica e fornecer informacoes que auxiliem no processo de tomada de decisoes (individuais, grupais ou institucionais). Demais alternativas reduzem a avaliacao a produto, instrumento, aplicacao ou treinamento."}, {"id": "2153991", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca da avaliação da capacidade decisional de pessoas\ncom deficiência e/ou com doenças crônicas, julgue os itens\na seguir.\n    I. A avaliação psicológica da capacidade decisional é uma\navaliação global da capacidade da pessoa.\n  II. A avaliação psicológica de capacidade decisional\nequivale à avaliação de deficiência intelectual.  \nIII. A avaliação psicológica de capacidade decisória deve\nconsiderar recursos de apoio para a tomada de\ndecisão, tais como tecnologia assistiva e comunicação\nalternativa, utilização de tradução e intérprete.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "I esta errado: a avaliacao da capacidade decisional e ESPECIFICA para a decisao em questao, nao 'global'. II esta errado: NAO equivale a avaliacao de DI - sao construtos distintos. III (considerar recursos de apoio: tecnologia assistiva, comunicacao alternativa, traducao, interprete) esta correto e alinhado a perspectiva inclusiva. Apenas III = C."}, {"id": "2153990", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a utilização de testes psicológicos em serviços\nrealizados por meio de tecnologias de informação e da\ncomunicação, assinale a alternativa correta.", "alt": {"A": "Testes informatizados e lápis e papel devem apresentar\nevidências específicas para o formato de aplicação.", "B": "Cabem ao Satepsi a análise e o estudo do manual do\nteste psicológico para identificar a forma de aplicação\nrecomendada.", "C": "Testes de aplicação informatizada e on-line são\nrecursos equivalentes.", "D": "O Satepsi garante as condições adequadas da aplicação\ne respostas colhidas no processo de avaliação.", "E": "Atualmente, não existem testes informatizados\naprovados pelo Satepsi, por essa ser uma área ainda\nem desenvolvimento no Brasil."}, "g": "A", "j": "A esta correta: testes informatizados e em lapis-e-papel sao FORMATOS DIFERENTES de aplicacao que devem apresentar evidencias especificas para cada formato (validade ecologica, equivalencia psicometrica). A simples conversao papel→online nao garante equivalencia."}, {"id": "2153988", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca da guarda e do envio de documentos decorrentes\nde serviços psicológicos, assinale a alternativa correta.", "alt": {"A": "A responsabilidade pela guarda do material cabe à\ninstituição em que o psicólogo prestou seus serviços\nprofissionais.", "B": "Os documentos escritos decorrentes da prestação de\nserviços psicológicos devem ser guardados pelo prazo\nmáximo de cinco anos.", "C": "É necessário um protocolo para registro da entrega de\ndocumentos.", "D": "Caso o solicitante seja um órgão ou uma instituição, o\nbeneficiário não tem direito ao documento final.", "E": "O prazo de validade do laudo psicológico tem prazo\nmáximo de um ano."}, "g": "C", "j": "C esta correta segundo Res CFP 06/2019: e necessario protocolo para registro da entrega de documentos psicologicos. Demais alternativas trazem erros (A guarda e do psicologo, B prazo minimo de 5 anos, D beneficiario tem direito, E nao ha prazo maximo unico de 1 ano)."}, {"id": "2153987", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que não contém uma fonte de\nevidência de validade.", "alt": {"A": "Conteúdo.", "B": "Estrutura interna.", "C": "Relações com variáveis externas.", "D": "Processo de resposta.", "E": "Teste-reteste."}, "g": "E", "j": "E ('teste-reteste') NAO e fonte de evidencia de VALIDADE - e medida de PRECISAO (estabilidade temporal). As fontes de validade segundo Standards (APA/AERA/NCME) sao: conteudo (A), estrutura interna (B), relacoes com variaveis externas (C), processo de resposta (D) e consequencias do teste."}, {"id": "2153986", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Os testes psicológicos precisam apresentar características\ntécnicas que informem sobre a qualidade das informações\nobtidas com seu uso, os chamados parâmetros\npsicométricos. Com relação ao assunto, julgue os itens a\nseguir.\n    I. A validade de um teste psicológico se refere ao grau\nem que a teoria e as evidências sustentam a\nintepretação dos escores.\n  II. A precisão se refere ao grau com que os itens\napresentam correlações entre si e com construtos\nsimilares.\n  III. A precisão pode ser medida pelo coeficiente alfa de\nCronbach, em que são esperados valores menores que\n0,7.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "A", "j": "I esta correto: a validade refere-se ao grau em que teoria e evidencias sustentam a interpretacao dos escores. II esta errado: precisao refere-se a CONSISTENCIA/estabilidade das medidas (nao 'correlacao com construtos similares', que e validade convergente). III esta errado: espera-se valores MAIORES (nao menores) que 0,7 no alfa de Cronbach. Apenas I = A."}, {"id": "2153985", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre a testagem e a avaliação psicológica, julgue os itens a\nseguir.\n    I. A testagem psicológica pauta seus resultados nas\ninformações obtidas por meio de entrevistas e testes\npsicológicos.\n  II. A avaliação psicológica envolve a integração de\ninformações oriundas de diversas fontes.\n  III. O Satepsi determina qual teste psicológico o psicólogo\ndeve utilizar em cada situação.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "I esta errado: a TESTAGEM psicologica refere-se especificamente a aplicacao de testes (e mais restrita); ja a entrevista integra a AVALIACAO. III esta errado: o Satepsi credencia/aprova testes mas NAO determina qual teste o psicologo deve usar em cada caso. II (avaliacao integra multiplas fontes) esta correto. Apenas II = B."}, {"id": "2153984", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca dos documentos psicológicos, o documento que tem\npor finalidade certificar, com fundamento em um\ndiagnóstico psicológico, determinada situação, estado ou\nfuncionamento psicológico, com a finalidade de afirmar as\ncondições psicológicas de quem, por requerimento, o\nsolicita, é o(a):", "alt": {"A": "declaração.", "B": "atestado psicológico.", "C": "laudo.", "D": "relatório.", "E": "parecer."}, "g": "B", "j": "O ATESTADO PSICOLOGICO e o documento que certifica, com base em diagnostico psicologico, determinada situacao, estado ou funcionamento psicologico, conforme definicao da Res CFP 06/2019."}, {"id": "2153983", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Não é considerado um avanço da área de avaliação\npsicológica no Brasil:", "alt": {"A": "a criação do Sistema de Avaliação dos Testes\nPsicológicos.", "B": "a criação de entidades científicas.", "C": "o rápido crescimento da quantidade de cursos de\nPsicologia.", "D": "melhora na qualidade dos manuais de testes.", "E": "desenvolvimento de pesquisas."}, "g": "C", "j": "C NAO e avanco para a area de avaliacao psicologica: o rapido crescimento da quantidade de cursos de Psicologia, sem controle de qualidade, pode INCLUSIVE comprometer a formacao em avaliacao. Demais alternativas (Satepsi, entidades cientificas, qualidade dos manuais, pesquisas) sao avancos efetivos."}, {"id": "2153979", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Acerca dos modelos de avaliação psicológica e\npsicodiagnóstico, julgue os itens a seguir.\n    I. Nos modelos mais tradicionais de realizar avaliações\npsicológicas ou psicodiagnóstico, ainda vigentes no\nBrasil e no mundo, o foco é a coleta de informações\nsobre o cliente.\n  II. Perspectivas emergentes compreendem o\ndesempenho nos testes como algo a ser\ncolaborativamente explorado, visando ampliar uma\ncompreensão de fenômenos que são fruto de um\ncontexto.\n  III. A avaliação terapêutica é baseada em princípios\nhumanísticos/fenomenológicos e intersubjetivos,\nporém não está atrelada a uma abordagem teórica ou\ntécnica específica.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (modelos tradicionais com foco em coleta de informacoes sobre o cliente), II (perspectivas emergentes como exploracao colaborativa), III (avaliacao terapeutica baseada em principios humanisticos/fenomenologicos e intersubjetivos, sem amarra a uma abordagem unica) sao todos corretos. Todos = E."}, {"id": "2153976", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "O campo da avaliação e da testagem psicológica contribuiu\npara o desenvolvimento da Psicologia como ciência; no\nentanto o desenvolvimento dessas áreas no Brasil\nenfrentou diversas dificuldades nas últimas décadas. São\nfatores que dificultaram a expansão da avaliação\npsicológica no Brasil, exceto:", "alt": {"A": "rápida criação dos cursos de Psicologia.", "B": "má qualidade psicométrica dos instrumentos.", "C": "falta de professores qualificados para o ensino de\navaliação psicológica.", "D": "ensino contextualizado, com ênfase na aplicação de\ninstrumentos, na contagem de pontos e interpretação\nestatística do resultado.", "E": "abordagens do pensamento psicológico, como a\nhumanista e a sócio-histórica, que eram reativas à\nquantificação e ao positivismo e suas manifestações."}, "g": "D", "j": "D NAO dificultou - pelo contrario, um 'ensino contextualizado' com aplicacao, contagem e interpretacao seria positivo. Demais alternativas (criacao rapida de cursos sem qualidade, ma qualidade dos instrumentos, falta de professores qualificados, abordagens reativas a quantificacao) sao dificuldades historicas reais."}, {"id": "2153974", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Qual alternativa fere a garantia de direitos humanos na\navaliação psicológica?", "alt": {"A": "Os itens das escalas contemplam a diversidade sócio- -\nhistórico-cultural brasileira dos diversos grupos.", "B": "Há coerência, no processo de avaliação psicológica,\ncom as demais políticas do Sistema de Conselhos de\nPsicologia.", "C": "Quanto ao teste, os instrumentos não devem\nestigmatizar algum grupo social (gênero, orientação\nsexual, identidade de gênero, étnico-racial, geográfica,\ngeracional, classe socioeconômica).", "D": "Os instrumentos utilizados sugerem implícita e/ou\nexplicitamente que as características avaliadas são\ncausadas por algum atributo intrínseco de grupos\nsociais.", "E": "A amostra normativa representa a diversidade sócio- -\nhistórico-cultural brasileira."}, "g": "D", "j": "D fere direitos humanos: instrumentos que sugerem que caracteristicas avaliadas decorrem de 'atributo intrinseco de grupos sociais' essencializam diferencas e reforcam estereotipos discriminatorios. Demais alternativas descrevem praticas validas e protetivas."}, {"id": "2153973", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Os testes psicológicos:", "alt": {"A": "avaliam construtos observados diretamente.", "B": "são procedimentos assistemáticos que têm como\nobjetivo coletar amostras de comportamento.", "C": "incluem os seguintes instrumentos: escalas,\ninventários, questionários e métodos\nprojetivos/expressivos.", "D": "configuram-se como ferramentas não padronizadas\npara obtenção de respostas que representam uma\namostra de comportamento.", "E": "dispensam o profissional de treinamento específico."}, "g": "C", "j": "C esta correta segundo Res CFP 09/2018: os testes psicologicos incluem escalas, inventarios, questionarios e metodos projetivos/expressivos. A (avaliam construtos nao observados diretamente), B (sao procedimentos sistematicos), D (sao padronizados) e E (exigem treinamento) sao incorretas."}, {"id": "2153972", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação às propriedades psicométricas, julgue os itens\na seguir.\n    I. Quanto maior o erro de medida, maior será a\nfidedignidade dos escores.\n  II. Condições de testagem do examinando, o formato do\ninstrumento e diferenças entre os avaliadores\ninterferem nos escores dos indivíduos.\n  III. É possível e necessário controlar todas as fontes de\nerro de medida.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Nenhum item está certo."}, "g": "B", "j": "I esta errado: quanto MENOR (nao maior) o erro de medida, MAIOR a fidedignidade. II (condicoes, formato, diferencas entre avaliadores interferem nos escores) esta correto. III esta errado: NAO e possivel controlar TODAS as fontes de erro - sempre ha erro residual. Apenas II = B."}, {"id": "2153971", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "Assinale a alternativa que não apresenta um parâmetro\npsicométrico indispensável para a construção de testes\npsicológicos.", "alt": {"A": "Precisão.", "B": "Fidedignidade.", "C": "Objetividade.", "D": "Normatização.", "E": "Confiabilidade."}, "g": "C", "j": "C ('objetividade') NAO e parametro psicometrico classico - nao integra o triplet validade, precisao/fidedignidade/confiabilidade (sinonimos) e normatizacao. Demais alternativas sao parametros essenciais para a construcao de testes."}, {"id": "2153970", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação psicológica é um campo do conhecimento com\npressupostos teóricos e metodológicos próprios e uma\nprática profissional que perpassa diversas áreas da\nPsicologia. Sobre a avaliação psicológica, assinale a\nalternativa correta.", "alt": {"A": "No processo de avaliação psicológica, é indispensável a\nutilização de testes psicológicos.", "B": "Envolve levantamento de demandas; elaboração de um\nplano de trabalho; execução do plano; análise e\ninterpretação dos dados; elaboração de documento e\ndevolução dos resultados obtidos.", "C": "Segundo a resolução 009/2018, o processo de\navaliação psicológica tem como fontes fundamentais\nde informação entrevistas, testes psicológicos e\nrelatórios de equipes multiprofissionais.", "D": "Caracteriza-se como um processo semiestruturado de\ninvestigação de fenômenos psicológicos, composto de\nmétodos, técnicas e instrumentos, com o objetivo de\nprover informações à tomada de decisão, no âmbito\nindividual, grupal ou institucional, com base em\ndemandas, condições e finalidades específicas.", "E": "No processo de avaliação psicológica, as questões\ncontextuais e do histórico de vida do sujeito avaliado\nnão são de preocupação do psicólogo."}, "g": "B", "j": "B descreve corretamente o processo completo da avaliacao psicologica: levantamento de demandas, elaboracao de plano de trabalho, execucao, analise/interpretacao, elaboracao de documento e devolucao. A (testes indispensaveis - errado), C (relatorio multiprofissional nao e fonte fundamental segundo Res 09/2018 - e complementar), D (processo estruturado, nao semiestruturado), E (questoes contextuais sao centrais) sao incorretas."}, {"id": "2153969", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "A avaliação psicológica e a avaliação educacional estão\nentre as contribuições mais importantes das ciências\ncognitivas para nossa sociedade. Considerando que a\ntestagem é um dos recursos utilizados nas avaliações,\nassinale a alternativa correta.", "alt": {"A": "Todos os testes são bem construídos, subsidiando\npráticas benéficas para a sociedade.", "B": "Os testes psicológicos são adequados e benéficos.", "C": "O uso adequado de tais testes não auxilia na tomada\nde decisão sobre a vida das pessoas.", "D": "O uso inapropriado de testes não causa danos às\npessoas avaliadas.", "E": "Testes bem desenvolvidos que são válidos para seus\npropósitos pretendidos têm potencial de oferecer\nbenefícios."}, "g": "E", "j": "E esta correta: testes bem desenvolvidos e validos para seus propositos pretendidos tem potencial de oferecer beneficios. Demais alternativas absolutizam ('todos sao bem construidos', 'sao adequados e beneficos') ou negam evidencias (uso adequado auxilia decisao, uso inapropriado causa danos)."}, {"id": "2153968", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2022", "org": "CFP", "t": "", "e": "No que diz respeito à avaliação psicológica destinada às\npessoas que apresentam deficiências, mais\nespecificamente àquelas que apresentam deficiência\nintelectual, Anache (2018) faz a seguinte afirmação:    \n“Desde a década de 1980, os processos avaliativos e os\nlaudos que deles depreendem têm sido alvo de críticas,\ndentre as quais se destacaram que eles discriminam e\nexcluem os indivíduos, que os métodos empregados não\nsão adequados para o intento, sobretudo para\ncompreender as suas condições de aprendizagem.”\n    A autora afirma que a construção de propostas de\navaliação psicológica de indivíduo que apresenta\ndeficiência intelectual é desafiadora. Acerca da avaliação\npsicológica realizada com pessoas com deficiência,\nassinale a alternativa correta.", "alt": {"A": "O modelo processual, interventivo e relacional, é\ntradicional no campo da Educação Especial.", "B": "A natureza quantitativa dos processos avaliativos\npermite construir explicações sobre a particularidade\ndo funcionamento psicológico e sua constituição\nsubjetiva, a qual se desenvolve em meio às condições\nsocioculturais.", "C": "Nessas situações, faz-se necessária a adaptação dos\nrecursos a serem utilizados, como materiais adaptados\npara idade e característica do sujeito.", "D": "A avaliação psicológica no contexto da educação\nespecial é um processo contínuo, interventivo, com o\nobjetivo de analisar quantitativamente o que o sujeito\né capaz de fazer em diferentes espaços da vida social.", "E": "A avaliação psicológica de pessoas com deficiência\nintelectual tem como ênfase a mensuração de\nsintomas expressos na forma de comportamentos\ninadaptados."}, "g": "C", "j": "C esta correta: na avaliacao de pessoas com deficiencia (especialmente DI), e fundamental a ADAPTACAO dos recursos a serem utilizados (materiais adaptados a idade e caracteristicas do sujeito). Demais alternativas trazem afirmacoes inversas ou conteudo incompativel com a perspectiva inclusiva de Anache."}, {"id": "2153967", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "Quanto ao prazo de validade do conteúdo dos documentos,\ndeterminado pela Resolução nº 06/2019, julgue os itens\nque se seguem.\n    I. O prazo de validade do conteúdo do documento\nescrito, decorrente da prestação de serviços\npsicológicos, deverá ser indicado no último parágrafo\ndo documento.\n  II. A validade indicada deverá considerar a normatização\nvigente na área em que atua a(o) psicóloga(o), bem\ncomo a natureza dinâmica do trabalho realizado e a\nnecessidade de atualização contínua das informações.\n  III. Não havendo definição normativa, o prazo de validade\ndeve ser indicado pela(o) psicóloga(o), levando em\nconsideração os objetivos da prestação do serviço, os\nprocedimentos utilizados, os aspectos subjetivos e\ndinâmicos analisados e as conclusões obtidas.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas o item I está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "I (prazo de validade indicado no ultimo paragrafo do documento), II (validade considera normatizacao vigente e natureza dinamica do trabalho) e III (na ausencia de normatizacao, psicologo indica considerando objetivos/procedimentos/aspectos analisados) sao todos consistentes com Res CFP 06/2019. Todos = E."}, {"id": "2153966", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "A Resolução CFP nº 6, de 29 de março de 2019, institui\nregras para a elaboração de documentos escritos\nproduzidos pela(o) psicóloga(o) no exercício profissional.\nCom relação aos princípios técnicos do documento\npsicológico, julgue os itens subsequentes.    \nI. Os documentos emitidos pela(o) psicóloga(o)\nconcretizam informações fundamentais e devem\nconter dados fidedignos que validam a construção do\npensamento psicológico e a finalidade a que se destina.\n  II. A elaboração de documento decorrente do serviço\nprestado no exercício da profissão deve considerar que\neste é o resultado de uma avaliação e/ou intervenção\npsicológica, observando os condicionantes históricos e\nsociais e seus efeitos nos fenômenos psicológicos.  \nIII. O documento escrito resultante da prestação de\nserviços psicológicos deve considerar a natureza\ndinâmica, não definitiva e não cristalizada do\nfenômeno psicológico.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas o item II está certo.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "I (documentos com informacoes fundamentais e dados fidedignos), II (resultado de avaliacao/intervencao observando condicionantes historicos e sociais) e III (natureza dinamica, nao definitiva e nao cristalizada do fenomeno psicologico) sao todos principios tecnicos da Res CFP 06/2019. Todos = D."}, {"id": "2153965", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com a Resolução nº 06/2019, assinale a\nalternativa incorreta quanto ao atestado psicológico.", "alt": {"A": "Atestado psicólogo consiste em um documento escrito\nque tem por finalidade registrar, de forma objetiva e\nsucinta, informações sobre a prestação de serviço\nrealizado ou em realização, abrangendo as seguintes\ninformações: comparecimento da pessoa atendida e\nseu acompanhante; acompanhamento psicológico\nrealizado ou em realização; informações sobre tempo\nde acompanhamento, dias e horários.", "B": "O atestado presta-se a comunicar o diagnóstico de\ncondições mentais que incapacitem a pessoa atendida,\ncom fins de: justificar faltas e impedimentos; justificar\nestar apto ou não para atividades específicas\n(manusear arma de fogo, dirigir veículo motorizado no\ntrânsito, assumir cargo público ou privado, entre\noutros), após realização de um processo de avaliação\npsicológica, dentro do rigor técnico e ético previsto nas\nresoluções do CFP; solicitar afastamento e/ou\ndispensa, subsidiada na afirmação atestada do fato.", "C": "O atestado psicológico resulta de uma avaliação\npsicológica. É responsabilidade da(o) psicóloga(o)\natestar somente o que foi verificado no processo de\navaliação e que esteja dentro do âmbito de sua\ncompetência profissional.", "D": "A emissão de atestado deve estar fundamentada no\nregistro documental, conforme dispõe a Resolução CFP\nnº 01/2009 ou aquelas que venham a alterá-la ou\nsubstituí-la, não isentando a(o) psicóloga(o) de guardar\nos registros em seus arquivos profissionais, pelo prazo\nestipulado nesta resolução.", "E": "Os Conselhos Regionais podem, no prazo de até cinco\nanos, solicitar à(ao) psicóloga(o) a apresentação da\nfundamentação técnico-científica do atestado."}, "g": "A", "j": "Res CFP 06/2019: a descricao em A (registrar comparecimento, acompanhamento, tempo, dias e horarios) corresponde a DECLARACAO, nao ao atestado psicologico. O atestado tem finalidade de comunicar diagnostico/aptidao (alternativa B). Alternativa A e a unica incorreta sobre atestado."}, {"id": "2153964", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "O relatório psicológico consiste em um documento que, por\nmeio de uma exposição escrita, descritiva e\ncircunstanciada, considera os condicionantes históricos e\nsociais da pessoa, grupo ou instituição atendida, podendo\ntambém ter caráter informativo. Assinale a alternativa que\ncontraria o conceito e/ou a finalidade desse documento,\nconforme previsto na Resolução nº 06/2019.", "alt": {"A": "Visa comunicar a atuação profissional da(o)\npsicóloga(o) em diferentes processos de trabalho já\ndesenvolvidos ou em desenvolvimento, podendo gerar\norientações, recomendações, encaminhamentos e\nintervenções pertinentes à situação descrita no\ndocumento, não tendo como finalidade produzir\ndiagnóstico psicológico.", "B": "É uma peça de natureza e valor técnico-científico,\ndevendo conter narrativa detalhada e didática, com\nprecisão e harmonia. A linguagem utilizada deve ser\nacessível e compreensível ao destinatário, respeitando\nos preceitos do Código de Ética Profissional do\nPsicólogo.", "C": "Deve ser construído com base no registro documental\nelaborado pela(o) psicóloga(o), em conformidade com\na Resolução CFP no 01/2009 ou resoluções que\nvenham a alterá-la ou substituí-la.", "D": "Corresponde à descrição literal das sessões,\natendimento ou acolhimento realizado. Deve explicitar\na demanda, os procedimentos e o raciocínio técnicocientífico da(o) profissional, bem como suas conclusões\ne/ou recomendações.", "E": "Deve apresentar as informações da estrutura\ndetalhada a seguir, em forma de itens ou texto corrido.\nÉ composto de 5 (cinco) itens: identificação; descrição\nda demanda; procedimento; análise; conclusão."}, "g": "D", "j": "Res CFP 06/2019: o relatorio psicologico nao e descricao literal de sessoes (isso seria registro/prontuario). E exposicao escrita descritiva e circunstanciada com analise. Alternativa D contraria o conceito do art. 4 da resolucao."}, {"id": "2153963", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com a Resolução CFP nº 1, de 30 de março de\n2009, a guarda do registro documental é de\nresponsabilidade do psicólogo e/ou da instituição em que\nocorreu o serviço. Assinale a alternativa correta.", "alt": {"A": "O período de guarda deve ser de no mínimo 5 anos,\npodendo ser ampliado nos casos previstos em lei,\napenas por determinação judicial.", "B": "O período de guarda deve ser de no mínimo 5 anos,\npodendo ser ampliado nos casos previstos em lei, por\ndeterminação judicial, ou ainda em casos específicos\nem que seja necessária a manutenção da guarda por\nmaior tempo.", "C": "O período de guarda deve ser de no mínimo 2 anos,\npodendo ser ampliado nos casos previstos em lei, por\ndeterminação judicial, ou ainda em casos específicos\nem que seja necessária a manutenção da guarda por\nmaior tempo.", "D": "O período de guarda deve ser de 2 anos, podendo ser\nampliado nos casos previstos em lei, apenas por\ndeterminação judicial.", "E": "O período de guarda deve ser de no mínimo 3 anos,\npodendo ser ampliado nos casos previstos em lei, por\ndeterminação judicial, ou ainda em casos específicos\nem que seja necessária a manutenção da guarda por\nmaior tempo."}, "g": "B", "j": "Res CFP 01/2009, art. 1, par. 2: periodo minimo de guarda do registro documental e de 5 anos, podendo ser ampliado nos casos previstos em lei, por determinacao judicial, ou ainda em casos especificos que demandem manutencao por maior tempo. Alternativa B reproduz a letra da norma."}, {"id": "2153962", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2022", "org": "CFP", "t": "", "e": "No que diz respeito à Resolução CFP nº 1/2009, que dispõe\nsobre a obrigatoriedade do registro documental decorrente\nda prestação de serviços psicológicos, julgue os itens que se\nseguem.\n    I. Em caso de serviço psicológico prestado em serviçosescola e campos de estágio, o registro deve contemplar\na identificação e a assinatura do responsável\ntécnico/supervisor que responderá pelo serviço\nprestado, bem como do estagiário.\n  II. A guarda do registro documental é de responsabilidade\ndo psicólogo e/ou da instituição em que ocorreu o\nserviço. O registro documental deve ser mantido em\nlocal que garanta sigilo e privacidade e mantenha-se à\ndisposição dos Conselhos de Psicologia para orientação\ne fiscalização, de modo que sirva como meio de prova\nidônea para instruir processos disciplinares e à defesa\nlegal.\n  III. Quando em serviço multiprofissional, o registro deve\nser realizado em prontuário único. Devem ser\nregistradas apenas as informações necessárias ao\ncumprimento dos objetivos do trabalho.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens I e III estão certos.", "C": "Apenas o item I está certo.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Res CFP 01/2009: I (servicos-escola exigem identificacao/assinatura do responsavel tecnico/supervisor + estagiario), II (guarda em local com sigilo, a disposicao dos CRPs) e III (em servico multiprofissional, prontuario unico com apenas informacoes necessarias) sao todos corretos conforme arts. 2 a 4."}, {"id": "2153961", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2022", "org": "CFP", "t": "", "e": "As transgressões dos preceitos do Código de Ética\nProfissional do Psicólogo constituem infração disciplinar\ncom a aplicação das seguintes penalidades:", "alt": {"A": "advertência pública; multa; censura pública; suspensão\ndo exercício profissional, por até 30 (trinta) dias, ad\nreferendum do Conselho Federal de Psicologia;\ncassação do exercício profissional, ad referendum do\nConselho Federal de Psicologia.", "B": "advertência confidencial; censura confidencial;\nsuspensão do exercício profissional, por até 60\n(sessenta) dias, ad referendum do Conselho Federal de\nPsicologia; cassação do exercício profissional, ad\nreferendum do Conselho Federal de Psicologia.", "C": "advertência; multa; censura pública; suspensão do\nexercício profissional, por até 30 (trinta) dias, ad\nreferendum do Conselho Federal de Psicologia;\ncassação do exercício profissional, ad referendum do\nConselho Federal de Psicologia.", "D": "advertência; multa; censura pública; suspensão do\nexercício profissional, por até 60 (sessenta) dias, ad\nreferendum do Conselho Federal de Psicologia;\ncassação do exercício profissional, ad referendum do\nConselho Federal de Psicologia.", "E": "advertência; multa; censura pública; suspensão do\nexercício profissional, por até 90 (noventa) dias, ad\nreferendum do Conselho Federal de Psicologia;\ncassação do exercício profissional, ad referendum do\nConselho Federal de Psicologia."}, "g": "C", "j": "Codigo de Etica do Psicologo (Res CFP 10/2005), art. 21: penalidades sao advertencia; multa; censura publica; suspensao do exercicio profissional por ate 30 dias ad referendum do CFP; cassacao ad referendum do CFP. Alternativa C reproduz exatamente."}, {"id": "2153960", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2022", "org": "CFP", "t": "", "e": "Com relação às responsabilidades do psicólogo,\nestabelecidas no Código de Ética Profissional, assinale a\nalternativa incorreta.", "alt": {"A": "Em caso de interrupção do trabalho do psicólogo, por\nquaisquer motivos, ele deverá zelar pelo destino dos\nseus arquivos confidenciais, devendo repassar todo o\nmaterial ao psicólogo que vier a substituí-lo, somente\nem caso de demissão.", "B": "Nos documentos que embasam as atividades em\nequipe multiprofissional, o psicólogo registrará apenas\nas informações necessárias para o cumprimento dos\nobjetivos do trabalho.", "C": "O psicólogo não divulgará, ensinará, cederá,\nemprestará ou venderá a leigos instrumentos e\ntécnicas psicológicas que permitam ou facilitem o\nexercício ilegal da profissão.", "D": "No atendimento à criança, ao adolescente ou ao\ninterdito, deve ser comunicado aos responsáveis o\nestritamente essencial para se promoverem medidas\nem seu benefício.", "E": "O psicólogo, na realização de estudos, pesquisas e\natividades voltadas para a produção de conhecimento\ne desenvolvimento de tecnologias, garantirá o acesso\ndas pessoas, grupos ou organizações aos resultados\ndas pesquisas ou estudos, após seu encerramento,\nsempre que assim o desejarem."}, "g": "A", "j": "Codigo de Etica do Psicologo: em caso de interrupcao do trabalho, o psicologo deve zelar pelos arquivos confidenciais e destina-los a quem o substituir ou inutiliza-los, NAO somente em caso de demissao. A restricao 'somente em caso de demissao' em A esta incorreta. Demais alternativas (B,C,D,E) reproduzem deveres/vedacoes do CEP."}, {"id": "2153959", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2022", "org": "CFP", "t": "", "e": "De acordo com a Resolução nº 10/2005 (que aprova Código\nde Ética Profissional), o psicólogo poderá intervir na\nprestação de serviços psicológicos que estejam sendo\nefetuados por outro profissional, em determinadas\nsituações. Sobre elas, julgue os itens a seguir.    \nI. A pedido do profissional responsável pelo serviço.  \nII. Em caso de emergência ou risco ao beneficiário ou\nusuário do serviço, quando dará imediata ciência ao\nprofissional.\n  III. Quando informado expressamente, por qualquer uma\ndas partes, da interrupção voluntária e definitiva do\nserviço.  IV. Quando se tratar de trabalho multiprofissional e a\nintervenção fizer parte da metodologia adotada.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens I e III estão certos.", "C": "Apenas os itens I, II e III estão certos.", "D": "Nenhum item está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Codigo de Etica do Psicologo (Res CFP 10/2005), art. 24: o psicologo podera intervir em servico de outro profissional (a) a pedido do responsavel, (b) em emergencia/risco com imediata ciencia, (c) quando informado da interrupcao voluntaria e definitiva, (d) em trabalho multiprofissional quando a intervencao integra a metodologia. Todos os itens corretos."}, {"id": "2153958", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2022", "org": "CFP", "t": "", "e": "Sobre os deveres fundamentais do Psicólogo, previstos na\nResolução nº 10/2005 (que aprova Código de Ética\nProfissional), assinale a alternativa incorreta.", "alt": {"A": "Estabelecer acordos de prestação de serviços que\nrespeitem os direitos do usuário ou beneficiário de\nserviços de Psicologia.", "B": "Fornecer, a quem de direito, na prestação de serviços\npsicológicos, informações concernentes ao trabalho a\nser realizado e ao seu objetivo profissional.", "C": "Informar, a quem de direito, os resultados decorrentes\nda prestação de serviços psicológicos, transmitindo\nsomente o que for necessário para a tomada de\ndecisões que afetem o usuário ou beneficiário.", "D": "Desviar para serviço particular ou de outra instituição\npessoas ou organizações atendidas por instituição com\na qual mantenha qualquer tipo de vínculo profissional,\nvisando benefício próprio.", "E": "Sugerir serviços de outros psicólogos, sempre que, por\nmotivos justificáveis, não puderem ser continuados\npelo profissional que os assumiu inicialmente,\nfornecendo ao seu substituto as informações\nnecessárias à continuidade do trabalho."}, "g": "D", "j": "Codigo de Etica do Psicologo: 'desviar para servico particular ou outra instituicao pessoas atendidas, visando beneficio proprio' constitui VEDACAO ao psicologo, nao dever fundamental. Alternativas A, B, C e E reproduzem deveres do art. 1."}, {"id": "1841919", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2021", "org": "CRP", "t": "", "e": "Considerando a Resolução n.º 1/2009 do Conselho Federal de\nPsicologia, que dispõe sobre a obrigatoriedade do registro\ndocumental decorrente da prestação de serviços\npsicológicos, assinale a alternativa correta.", "alt": {"A": "Fica garantido exclusivamente ao usuário o acesso\nintegral às informações registradas, pelo psicólogo, em\nseu prontuário.", "B": "Para atendimento em grupo não eventual, o psicólogo\nnão precisa manter os registros dos atendimentos e a\ndocumentação individual referente a cada usuário.", "C": "O período de guarda do registro documental deve ser\nde, no mínimo, dez anos, podendo ser ampliado nos\ncasos previstos em lei, por determinação judicial, ou\nem casos específicos em que seja necessária a\nmanutenção da guarda por maior tempo.", "D": "Quando em serviço multiprofissional, o registro deve\nser realizado em prontuário único.", "E": "O registro documental constitui um conjunto de\ninformações que tem por objetivo contemplar,\nde forma sucinta, o trabalho prestado, a descrição\ne a evolução da atividade e os procedimentos\ntécnico-cientıficos adotados. Para que se cumpra o ́\ncaráter sigiloso do conteúdo, é obrigatório que o\nregistro seja informatizado."}, "g": "D", "j": "Res CFP 01/2009, art. 3: em servico multiprofissional, o registro deve ser realizado em prontuario unico. Alternativa A falha por 'exclusivamente ao usuario'; B falha pois grupo nao eventual exige registro; C falha pois prazo e 5 anos (nao 10); E falha pois nao ha exigencia de informatizacao."}, {"id": "1837008", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2021", "org": "CRP", "t": "", "e": "Considerando a Resolução n.° 3/2007 do Conselho Federal de\nPsicologia, assinale a alternativa correta no que diz respeito à\npublicidade do trabalho de psicólogo.", "alt": {"A": "É vedada qualquer previsão sobre os resultados de seus\nserviços.", "B": "São vedados o recurso e a menção a técnicas\npsicológicas e clínicas.", "C": "É vedada a autopromoção.", "D": "É vedado esclarecer a natureza particular de seus\nserviços.", "E": "É vedado o recurso a conteúdos sensacionalistas."}, "g": "E", "j": "Res CFP 03/2007 sobre publicidade profissional: e vedado o recurso a conteudos sensacionalistas. A previsao de resultados, mencao a tecnicas reconhecidas e autopromocao moderada nao sao vedados em si — sao admitidos com criterios. Alternativa E e a unica vedacao expressa entre as opcoes."}, {"id": "1837007", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2021", "org": "CRP", "t": "", "e": "Assinale a alternativa que apresenta a sanção passível de\naplicação a inscrito no Conselho Regional de Psicologia, em\nrazão de infração disciplinar.", "alt": {"A": "cassação do exercício profissional, desde que com\nreferendo do Conselho Federal de Psicologia", "B": "advertência verbal e reservada", "C": "suspensão do exercício profissional por até um ano", "D": "agravo em assentamento funcional", "E": "prestação de serviços comunitários"}, "g": "A", "j": "Codigo de Etica do Psicologo, art. 21: cassacao do exercicio profissional ad referendum do CFP e penalidade prevista. Suspensao por ate um ano (C) excede o limite de 30 dias; advertencia verbal/reservada (B), agravo (D) e prestacao de servicos comunitarios (E) nao constam no rol legal."}, {"id": "1299802", "d": "psicologia", "a": ["Psicodrama", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "As pessoas nascem dentro de um átomo social, formado\npor suas famílias imediatas ou, como Moreno denominou,\nseus grupos-modelo. O átomo social de uma pessoa é um\nconstruto dinâmico que cresce, muda e, muitas vezes,\nencolhe, à medida que o indivíduo vai vivendo sua vida. Ele\né espontâneo, momentâneo e se altera constantemente.\nSendo assim, assinale a alternativa correta.", "alt": {"A": "O átomo social é um mapa das conexões sociométricas\nem determinada situação. Tele é a corrente de\nsentimentos que flui entre duas pessoas. Moreno a\nconsiderava como a menor unidade de sentimento\ntransmitida de um indivíduo a outro.", "B": "Em termos de psicodrama, Moreno (1977) pensava que\na tele ocorria quando um indivíduo desempenhava um\npapel aprendido anteriormente (velho papel) em uma\nsituação nova.", "C": "Moreno definiu transferência como um modo de:\n“compreender na intimidade”, “avaliar” e “sentir” o\nmodo de ser de outra pessoa.", "D": "Toda vez que se ingressa em um grupo, leva-se consigo\nos papéis que se desempenha no átomo social do\ngrupo-modelo; somente as relações de papel\nfuncionais são recriadas nos vários grupos aos quais se\npertence ao longo da vida.", "E": "A tele é o conhecimento verdadeiro da pessoa com\nquem se está interagindo no presente momento. O\npsicodrama impede que os membros do grupo\ntrabalhem as relações télicas e transferenciais para,\nassim, poder desenvolver novos papéis para lidar com\nvelhas situações."}, "g": "A", "j": "Moreno (Psicodrama): atomo social e o mapa das conexoes sociometricas; tele e a corrente de sentimentos que flui entre duas pessoas e foi definida por Moreno como a menor unidade de sentimento transmitida entre individuos. Alternativa A esta tecnicamente correta. B confunde tele com role-playing antigo; C inverte tele e transferencia; D restringe a 'somente funcionais'; E afirma erroneamente que o psicodrama impede trabalho com tele/transferencia."}, {"id": "1299797", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Terapia familiar"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Fishman & Minuchin, o terapeuta de família\ndeve, desde o início, tomar certa posição de liderança.\nTeoricamente, a família e o terapeuta começam a terapia\ncom os mesmos objetivos. A presença da família é um\nreconhecimento de que eles querem ajuda e de que estão\nconvidando o terapeuta, um especialista, a se introduzir em\nseu sistema e a ajudá-los a mudar a situação que está\nproduzindo ou mantendo tensão, desconforto ou\nsofrimento. Porém, na prática, é possível e frequente que\nos membros da família e o terapeuta divirjam em sua\ncompreensão quanto à localização do sofrimento, à sua\ncausa e ao processo de cura. Com relação a esse assunto,\nassinale a alternativa incorreta.", "alt": {"A": "A família tem geralmente identificado em um membro\na localização do problema. Acredita que a causa seja a\npatologia internalizada desse indivíduo. Esperam que o\nterapeuta se concentre nesse indivíduo, trabalhando\npara mudá-lo.", "B": "Para o terapeuta de família, o paciente identificado é\nsomente o portador do sintoma; a causa do problema\nsão as transações disfuncionais da família e o processo\nde cura envolverá a mudança dessas transações\ndisfuncionais.", "C": "Família e terapeuta formam uma sociedade com um\nobjetivo comum, que é mais ou menos formulado:\nlibertar o portador do sintoma na família de seus\nsintomas, reduzir o conflito e a tensão em toda a\nfamília e aprender novos meios de superar as\ndificuldades.", "D": "Dois sistemas sociais entram em coparticipação, para\num propósito amplo e por um tempo indeterminado.\nAs funções dos participantes no sistema terapêutico\ndevem ser definidas pelo terapeuta.", "E": "Na maioria dos casos, a família aceitará o terapeuta\ncomo líder de sua sociedade. Não obstante, ele terá́de\nconseguir seu direito de liderar. Como todo líder, ele\nterá de se acomodar, de seduzir, de submeter, de\napoiar, de dirigir, de sugerir e de seguir a fim de\nconduzir."}, "g": "D", "j": "Fishman & Minuchin (Tecnicas de Terapia Familiar): o sistema terapeutico forma-se por tempo DETERMINADO e as funcoes/objetivos sao definidos EM CONJUNTO com a familia, nao unilateralmente pelo terapeuta. Alternativa D contraria essa premissa (tempo indeterminado, funcoes definidas pelo terapeuta). Demais alternativas reproduzem o pensamento estrutural de Minuchin."}, {"id": "1299796", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Uma parte integrante de todas as terapias é um acordo\nentre paciente/cliente/usuário e psicoterapeuta, em que se\ndefine o que é psicoterapia; para quem e para que se\ndestina, quais seus objetivos ou suas metas, quem será\nenvolvido, onde e com que frequência irão ocorrer os\nencontros, quais as responsabilidades (ou papéis) dos\nparticipantes e o que é esperado de cada um. Os objetivos\ndevem ser aceitos pelo paciente, bem como apropriados,\ndo ponto de vista ético e profissional, ao psicoterapeuta.\nEsse acordo é chamado de", "alt": {"A": "aliança terapêutica.", "B": "contrato terapêutico.", "C": "aliança de trabalho.", "D": "plano terapêutico singular.", "E": "setting terapêutico."}, "g": "B", "j": "O acordo formal entre paciente e psicoterapeuta sobre definicao, objetivos, papeis, frequencia e responsabilidades e o CONTRATO TERAPEUTICO. A alianca terapeutica (A) refere-se ao vinculo afetivo/colaborativo; alianca de trabalho (C) e conceito proximo mas distinto do acordo formal; PTS (D) e instrumento do SUS; setting (E) e o enquadre fisico/temporal."}, {"id": "1299791", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Assinale a alternativa correta no que diz respeito às ações\nfundamentais do acolhimento e da atenção à alteridade e à\nambiência, que são diretrizes do Humaniza SUS que\npossibilitam a construção de um plano de atenção singular\nao usuário, fomentando o vínculo e o acompanhamento\nterapêutico longitudinal.", "alt": {"A": "A ambiência é um dispositivo destinado à escuta dos\nusuários em todas as suas dimensões e destina-se à\nconstrução de vínculos desses sujeitos com os\nprofissionais que compõem as equipes de saúde, para\ngarantir o acesso aos serviços.", "B": "A alteridade pressupõe a construção de redes de\nconversação afirmadoras de relações importantes nos\nprocessos de produção de saúde. Cabe aos\nprofissionais ouvir o usuário, atendendo a seus pedidos\ne assumindo, no serviço, uma postura capaz de dar\nrespostas mais adequadas, ainda que esta seja o\nencaminhamento para outros pontos de atenção da\nrede.", "C": "O acolhimento é uma postura ética, que envolve\nresolutividade e responsabilidade. Implica estar atento\ne aberto às diversidades culturais, raciais e étnicas. No\nprocesso de acolher, o profissional ouve as queixas dos\nusuários, por meio da escuta qualificada, analisando a\ndemanda.", "D": "O acolhimento refere-se à experiência internalizada da\nexistência do outro, não como um objeto, mas como\num outro sujeito. Trata-se de colocar-se no lugar do\nusuário para se comunicar com este com fluidez, ética,\nempatia e responsabilidade, compreendendo, assim,\nsuas necessidades e demandas de saúde.", "E": "A alteridade trata do cuidado com os componentes\nestéticos que podem melhorar a condição de saúde da\npopulação, como, por exemplo, o cuidado com o\nespaço geográfico e afetivo, tal como luminosidade,\npresença de ruídos e temperatura, ou o cuidado com\nas características socioculturais, locais e regionais.\nInclui a recepção dos usuários e sua relação com\nprofissionais e gestores da forma mais ética, humana,\nrespeitosa e inclusiva possível."}, "g": "C", "j": "Politica Nacional de Humanizacao (HumanizaSUS): acolhimento e postura etica de escuta qualificada, com resolutividade e responsabilidade, atenta a diversidades. Alternativa C reproduz a definicao oficial. A e B confundem ambiencia/alteridade com escuta; D descreve alteridade como se fosse acolhimento; E descreve ambiencia (cuidado com espaco fisico, luminosidade, ruidos) atribuindo-a a alteridade."}, {"id": "1299790", "d": "psicologia", "a": ["Jung", "Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Kholenberg & Tsai, a regra n.ᵒ 1 da\npsicoterapia analítica funcional (FAP) é prestar atenção aos\ncomportamentos clinicamente relevantes (CRB) e aos\nproblemas que ocorrem na sessão (CRB1), visando a\nmelhorar o resultado da terapia. Portanto, quanto maior\nfor a proficiência do terapeuta em identificar CRB,\nmelhores serão os resultados alcançados. Seguir a regra n.ᵒ\n1 conduzirá a uma crescente intensidade, ou seja, a reações\nemocionais mais fortes entre cliente e terapeuta durante a\nsessão. Quanto à FAP, julgue os itens seguintes. I. Em uma sessão de terapia, a consequência primária do\ncomportamento do cliente é a reação do terapeuta.\nCaso o terapeuta não proceda a uma observação clara\ndo comportamento do cliente, suas reações poderão\nser inconsistentes ou antiterapêuticas, o que\ncomprometeria o progresso.   II. Se o terapeuta não estiver ciente dos comportamentos\nclinicamente relevantes do cliente que ocorrerem\ndurante a sessão, o reforçamento dos progressos no\nmomento de sua ocorrência será algo do tipo “pegar\nou perder”.   III. Se o terapeuta estiver consciente e prestar atenção nos\nCRB, ele garantirá que as melhoras sejam reforçadas e\nos comportamentos desfavoráveis sejam extintos ou\npunidos, porém isso aumenta a probabilidade de\nreações inapropriadas do terapeuta.     Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "C", "j": "Kohlenberg & Tsai (FAP - Psicoterapia Analitica Funcional): I (reacao do terapeuta como consequencia primaria; falta de observacao gera reacoes inconsistentes ou antiterapeuticas) e II ('pegar ou perder' quando o terapeuta nao esta atento aos CRBs) sao corretos. Item III erra ao afirmar que prestar atencao AUMENTA a probabilidade de reacoes INAPROPRIADAS — na FAP, a atencao aumenta reacoes apropriadas; alem disso, a 'punicao' nao e estrategia central. Apenas I e II corretos."}, {"id": "1299789", "d": "psicologia", "a": ["Psicopatologia", "Psicossomática"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Volich, qualquer sintoma, mental,\ncomportamental ou somático, é, antes de tudo, uma\nmanifestação do sofrimento do sujeito, uma demanda\noriunda das marcas de seu desamparo, mais fundamental e\nsistematicamente dirigida para o outro.\nIndependentemente de sua etiologia ou de sua forma, o\nsintoma e a doença são, por eles mesmos, perturbadores\ndo equilíbrio da economia psicossomática, pela ameaça que\nrepresentam para a integridade do indivíduo, podendo\npromover e mesmo intensificar uma desorganização. Nesse\ncontexto, julgue os itens a seguir. I. Torna-se bastante problemático sustentar a existência\nde limites rígidos entre o normal e o patológico, uma\nvez que ambos se mesclam a fim de atingir, a cada\nmomento, o equilíbrio psicossomático e de assegurar a\nvida do indivíduo. Toda reação “normal\" apresenta\ntambém componentes desviantes ou desorganizados,\nassim como toda patologia também comporta um\nmínimo de organização, para que a sobrevivência do\nsujeito ainda seja possível.   II. Essas perspectivas revelam a importância das interrelações entre fatores e campos de conhecimento,\ncomo a biologia, a fisiologia, a anatomia, a genética, a\nmedicina, a psicologia, a sociologia, a educação e a\nantropologia, geralmente considerados como\nheterogêneos e alheios uns aos outros por uma visão\nespecializada da ciência.   III. A experiência clínica sistematicamente revela que, do\nponto de vista individual, a tentativa de distinguir dor e\nsofrimento, dor física e dor moral é difícil, senão\nimpossível, por não corresponder à experiência do\nsujeito que sofre e, dessa forma, empobrecer a\ncompreensão dessa experiência. Toda dor, mesmo a\noriunda de uma lesão real, remete o indivíduo a suas\nexperiências mais primitivas de desamparo.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Volich (Psicossomatica): I — limites entre normal e patologico nao sao rigidos, sintoma e doenca participam do equilibrio psicossomatico (correto); II — psicossomatica reconhece interrelacoes entre multiplas disciplinas (biologia, fisiologia, antropologia etc., correto); III — distinguir dor fisica e moral e clinicamente dificil; toda dor remete ao desamparo primitivo (correto). Todos os itens reproduzem teses centrais de Volich."}, {"id": "1299788", "d": "psicologia", "a": ["Psicopatologia", "Transtornos de Personalidade", "CID-10 e DSM"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação às características essenciais para os critérios\ndiagnósticos do transtorno da personalidade borderline, de\nacordo com o DSM-V, julgue os itens subsequentes.\nI. Um padrão difuso de instabilidade das relações\ninterpessoais, da autoimagem e dos afetos e uma\nimpulsividade acentuada, que surge no começo da vida\nadulta e está presente em vários contextos, são\ncaracterísticas desse transtorno de personalidade.\nII. Um padrão difuso de deficits sociais e interpessoais,\nmarcado por desconforto agudo e capacidade reduzida\npara relacionamentos íntimos, bem como por\ndistorções cognitivas ou perceptivas e comportamento\nexcêntrico são características desse transtorno de\npersonalidade.\nIII. Um padrão de desconfiança e suspeita difusa dos\noutros, que surge no início da vida adulta, de modo\nque suas motivações são interpretadas como\nmalévolas, é característico desse transtorno de\npersonalidade.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "A", "j": "DSM-5: o transtorno da personalidade borderline e definido por padrao difuso de instabilidade em relacoes interpessoais, autoimagem e afetos + impulsividade acentuada — apenas o item I. Item II descreve transtorno da personalidade ESQUIZOTIPICA. Item III descreve transtorno da personalidade PARANOIDE."}, {"id": "1299786", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade"], "ano": "2020", "org": "CFP", "t": "", "e": "O apoio matricial é uma ferramenta estratégica da Política\nde Saúde Mental para garantir o princípio da integralidade\ndas ações em saúde. Ele se dá a partir da oferta de\nsaberes/fazeres técnicos especializados. Sendo assim, é\ncorreto afirmar que matriciamento é", "alt": {"A": "a intervenção psicossocial coletiva realizada apenas\npelo profissional de saúde mental.", "B": "o encaminhamento ao especialista.", "C": "um novo modo de produzir saúde, em que duas ou\nmais equipes, em um processo de construção\ncompartilhada, criam uma proposta de intervenção\nterapêutica.", "D": "o atendimento individual pelo profissional de saúde\nmental.", "E": "um conjunto de propostas e condutas terapêuticas\narticuladas pela equipe interdisciplinar do serviço local,\num dispositivo potencial para o planejamento das\nações em saúde."}, "g": "C", "j": "Apoio matricial/Matriciamento (Campos & Domitti, 2007): novo modo de produzir saude em que duas ou mais equipes, em processo de construcao compartilhada, criam proposta de intervencao terapeutica. Alternativa C reproduz a definicao. A e D restringem a profissional unico; B reduz a encaminhamento; E descreve PTS, nao matriciamento."}, {"id": "1299785", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Em conformidade com a Portaria n.ᵒ 336/GM/MS, do\nMinistério da Saúde, os Centros de Atenção Psicossocial\n(CAPS) poderão ser classificados nas seguintes modalidades\nde serviços: CAPS I; CAPS II; e CAPS III, definidos por ordem\ncrescente de porte/complexidade e abrangência\npopulacional. No que se refere a esse tema, assinale a\nalternativa incorreta.", "alt": {"A": "As três modalidades de serviço cumprem a mesma\nfunção no atendimento público em saúde mental.", "B": "As três modalidades deverão estar capacitadas para\nrealizar prioritariamente o atendimento de pacientes\ncom transtornos mentais severos e persistentes,\nprincipalmente em regime de tratamento intensivo.", "C": "Os CAPS I, II e III deverão constituir serviço\nambulatorial de atenção diária que funcione segundo a\nlógica do território.", "D": "Nos CAPS I, II e III, a assistência prestada ao paciente\ninclui as seguintes atividades: atendimento individual,\nfamiliar ou em grupos domiciliar; e o atendimento em\noficinas terapêuticas.", "E": "Entre as atividades desenvolvidas pelos psicólogos no\nCAPS I, II e III, estão os atendimentos individuais em\npsicoterapia breve e os atendimentos grupais, como os\ngrupos operativos e(ou) a psicoterapia em grupo."}, "g": "B", "j": "Portaria 336/GM/MS, art. 1, par. 2: as tres modalidades de CAPS atendem prioritariamente transtornos mentais severos e persistentes em regimes INTENSIVO, SEMI-INTENSIVO E NAO-INTENSIVO. Alternativa B esta incorreta ao afirmar 'principalmente em regime de tratamento intensivo'. As demais (A — mesma funcao, C — territorio, D — atividades, E — atividades dos psicologos) reproduzem a portaria."}, {"id": "1299783", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com o Humaniza SUS, a clínica ampliada deve ser\nentendida como uma das diretrizes impostas pelos\nprincípios do SUS. A universalidade do acesso, a\nintegralidade da rede de cuidado e a equidade das ofertas\nem saúde obrigam à modificação dos modelos de atenção e\nde gestão dos processos de trabalho em saúde. Acerca\ndesse assunto, assinale a alternativa incorreta.", "alt": {"A": "A clínica ampliada é específica da prática da psicologia\ne visa a construir vínculos positivos e intervenções\nclínicas efetivas, centradas na pessoa, na perspectiva\nde ampliação dos graus de autonomia dos indivíduos.\nEla trata de uma forma de compreensão do sujeito e\nde suas necessidades de saúde.", "B": "O plano terapêutico singular (PTS) envolve um\nconjunto de propostas de condutas terapêuticas\narticuladas, direcionadas a um indivíduo, a uma família\nou à coletividade. Tem como objetivo traçar uma\nestratégia de intervenção para o usuário, contando\ncom os recursos da equipe, do território, da família e\ndo próprio sujeito.", "C": "Com relação a outros tipos de sofrimento que possam\nser relativos a processos de marginalização, exclusão\nou violência, o acolhimento coloca-se na porta de\nentrada do serviço, como uma prática que requer a\npostura inclusiva.", "D": "O PTS desenvolve-se em quatro momentos:\ndiagnóstico; definição de meta; divisão de\nresponsabilidades; e reavaliação.", "E": "No que concerne à psicologia, sublinha-se a\nimportância de se considerar que o trabalho no SUS\nnão pode ser uma mera adaptação de práticas clínicas\nindividuais à rotina desse sistema, mas exige mudanças\nna maneira como se constrói esse processo de\ntrabalho; no modelo de atendimento aos sujeitos e na\npostura da psicologia diante de si e inserida em uma\nequipe multiprofissional."}, "g": "A", "j": "HumanizaSUS: a clinica ampliada NAO e especifica da psicologia — e proposta INTERDISCIPLINAR/multiprofissional. Alternativa A esta incorreta nesse ponto. B (PTS), C (acolhimento), D (quatro momentos do PTS) e E (mudanca de postura no SUS) reproduzem a politica."}, {"id": "1299780", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicoterapia é uma prática do psicólogo por constituir,\ntécnica e conceitualmente, um processo científico de\ncompreensão, análise e intervenção, que se realiza por\nmeio da aplicação sistematizada e controlada de métodos e\ntécnicas psicológicas reconhecidos pela ciência, pela prática\ne pela ética profissional, promovendo a saúde mental e\npropiciando condições para o enfretamento de conflitos\ne(ou) transtornos psíquicos de indivíduos ou grupos. Para\nefeito da realização da psicoterapia, de acordo com a\nResolução CFP n.ᵒ 10/2000 e a Resolução CFP n.ᵒ 1/2009, o\npsicólogo deverá observar alguns procedimentos.\nConsiderando essas informações, julgue os itens seguintes.\n I. O psicólogo deverá esclarecer à pessoa atendida o\nmétodo e as técnicas utilizadas, mantendo-a informada\nsobre as condições do atendimento e sobre seus\nlimites e suas possibilidades.   II. O psicólogo deverá dispor, para consulta da pessoa\natendida, de um exemplar do Código de Ética\nProfissional do Psicólogo no local do atendimento.   III. O psicólogo deverá pautar-se em avaliação diagnóstica\nfundamentada, devendo, ainda, manter registro\nreferente ao atendimento realizado, no qual deverá\nindicar o meio utilizado para o diagnóstico ou o motivo\ninicial, a atualização, o registro de interrupção e a alta.   Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Res CFP 10/2000 (psicoterapia) e Res 01/2009 (registro): I — esclarecer metodo/tecnicas e manter pessoa informada (correto); II — dispor de exemplar do CEP no local de atendimento (correto); III — avaliacao diagnostica fundamentada e registro com meio diagnostico, motivo inicial, atualizacao, interrupcao e alta (correto). Todos os itens corretos."}, {"id": "1299779", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com o Código de Ética Profissional do Psicólogo\n(Resolução CFP n.ᵒ 10/2005), o psicólogo clínico não deve", "alt": {"A": "fornecer, a quem de direito, na prestação de serviços\npsicológicos, informações concernentes ao trabalho a\nser realizado e a seu objetivo profissional.", "B": "orientar a quem de direito sobre os encaminhamentos\napropriados, a partir da prestação de serviços\npsicológicos, e fornecer, sempre que solicitado, os\ndocumentos pertinentes ao bom termo do trabalho.", "C": "informar, a quem de direito, os resultados decorrentes\nda prestação de serviços psicológicos, transmitindo\nsomente o que for necessário para a tomada de\ndecisões que afetem o usuário ou beneficiário.", "D": "realizar diagnósticos, divulgar procedimentos e\napresentar resultados de testes psicológicos, em meios\nde comunicação, ao público em geral, sempre que for\nsolicitado pelas autoridades competentes.", "E": "respeitar o sigilo profissional a fim de proteger, por\nmeio da confidencialidade, a intimidade das pessoas,\ndos grupos ou das organizações a que tenha acesso no\nexercício profissional."}, "g": "D", "j": "CEP (Res CFP 10/2005): e VEDADO ao psicologo realizar diagnosticos, divulgar procedimentos e apresentar resultados de testes psicologicos em meios de comunicacao ao publico em geral (art. 20). 'Sempre que solicitado pelas autoridades' nao desfaz a vedacao. Alternativas A, B, C e E sao deveres expressos."}, {"id": "1299729", "d": "psicologia", "a": ["Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "A expectativa de vida da população brasileira aumentou\nconsideravelmente neste século e a neuropsicologia do\nenvelhecimento acompanhou esse processo. Com relação à\nintervenção neuropsicológica junto ao idoso, assinale a\nalternativa correta.", "alt": {"A": "Há indicadores de que a neuroplasticidade cessa após\nos sessenta anos de idade e, diante desse fato, a\nliteratura sugere que as intervenções sejam apenas no\nâmbito das atividades diárias.", "B": "A estimulação cognitiva do idoso pode reduzir o risco\nde demência, mas amplia o potencial para depressão,\nespecialmente em mulheres.", "C": "Ao avaliar o idoso, o neuropsicólogo deve considerar a\nreserva cognitiva, as habilidades desenvolvidas pela\neducação formal, o desempenho funcional durante a\nvida e as demandas emocionais da tarefa.", "D": "Pode-se dizer que qualidade da educação formal e\nreserva cognitiva são sinônimos, uma vez que a baixa\nescolaridade denuncia provável deficit cognitivo.", "E": "As reações emocionais diante das provas\nneuropsicológicas são isentas de influência da\nescolaridade do examinando. Desse modo, os idosos\nnão devem fazer avaliação de cognição geral."}, "g": "C", "j": "Neuropsicologia do envelhecimento: ao avaliar idoso, deve-se considerar reserva cognitiva, escolaridade/educacao formal, desempenho funcional ao longo da vida e demandas emocionais da tarefa. A neuroplasticidade nao cessa aos 60 (refuta A); estimulacao cognitiva nao amplia depressao (refuta B); reserva cognitiva nao e sinonimo de educacao formal (refuta D); escolaridade influencia reacoes emocionais nas provas (refuta E)."}, {"id": "1299728", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A entrevista devolutiva e o laudo neuropsicológico são\ncruciais para fundamentar a eficácia da avaliação\nneuropsicológica, uma vez que as possíveis intervenções\nfuturas podem se delinear nesse momento. Quanto à\nelaboração de laudos, assinale a alternativa correta.", "alt": {"A": "A estrutura do laudo neuropsicológico deve ser flexível,\npor exemplo, a história médica do examinando adulto\ncom AVC é opcional, pois a saúde física independe das\ncondições neuropsicológicas.", "B": "O laudo tem características técnico-científicas e, por\nisso, deve apresentar os resultados com objetividade,\npor meio da apresentação dos escores obtidos, e\ndispensar as análises e interpretações subjetivas do\nprofissional.", "C": "O laudo apresenta as características globais do\nexaminando e, independentemente da demanda, deve\nconter dados redundantes e informações amplas sobre\na rotina e a história familiar, pois eles suplementam a\nhipótese diagnóstica.", "D": "Os laudos, mesmo quando direcionados para a leitura\nde outros profissionais, devem apresentar uma\nlinguagem clara e simples, com todos os termos\ntécnicos explicados, uma vez que o examinando e sua\nfamília também precisam compreendê-lo.", "E": "Os laudos neuropsicológicos para fins educacionais,\ndirecionados para escolas, requerem que o quociente\nde inteligência da criança seja apresentado e dispensa\na utilização de outras técnicas de avaliação de\ndesempenho."}, "g": "D", "j": "Laudo neuropsicologico (Res CFP 06/2019 + literatura): linguagem clara e simples, termos tecnicos explicados, para compreensao do examinando/familia, mesmo quando direcionado a outros profissionais. A (historia medica opcional) e falso; B (dispensar interpretacoes) contraria a logica de laudo; C (dados redundantes) e ma pratica; E (apenas QI) e reducionista."}, {"id": "1299720", "d": "psicologia", "a": ["Psicofarmacologia"], "ano": "2020", "org": "CFP", "t": "", "e": "O uso de psicotrópicos e os transtornos psiquiátricos\npodem afetar a cognição. O conhecimento de\npsicofarmacologia auxilia o neuropsicólogo no\nplanejamento de suas intervenções e em seu trabalho junto\nà equipe interdisciplinar. Acerca dos efeitos de medicações\npsicotrópicas na cognição, assinale a alternativa correta.", "alt": {"A": "No dia da avaliação neuropsicológica, os seguintes\nestimulantes devem ser suspensos: oxcarbazepina e\ngabapentina.", "B": "A prescrição do lítio deve ser evitada durante o\ntratamento do transtorno bipolar do tipo I.", "C": "A amnésia retrógrada é o principal efeito do uso\ncontinuado de benzodiazepínicos.", "D": "Os antidepressivos tricíclicos são fator protetivo para o\ndeficit atencional e mnemônico.", "E": "Os antipsicóticos de primeira geração estão\nrelacionados ao comprometimento na memória de\ntrabalho, na velocidade de processamento da\ninformação e nas habilidades motoras."}, "g": "E", "j": "Psicofarmacologia: antipsicoticos de primeira geracao (tipicos, ex. haloperidol, clorpromazina) estao associados a comprometimento de memoria de trabalho, velocidade de processamento e habilidades motoras (efeitos extrapiramidais). A (oxcarbazepina e gabapentina sao estimulantes) e falso — sao anticonvulsivantes; B (litio evitado no TB-I) e falso — e primeira linha; C (benzodiazepinicos causam amnesia retrograda) e falso — causam ANTEROGRADA; D (triciclicos como fator protetivo) e falso — tem efeito anticolinergico negativo."}, {"id": "1299713", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Avanços importantes foram feitos para viabilizar a\nrealização de avaliações neuropsicológicas. Com relação às\ncaracterísticas de uma avaliação neuropsicológica válida,\njulgue os itens subsequentes.\n    I. A bateria deve apresentar fundamento teórico sólido,\npermitir explorar funções básicas, ser aplicável com o\nmínimo de ajuda e instruções verbais e ter critérios de\navaliação objetivos.\n  II. O neuropsicólogo clínico deve zelar pelas diretrizes\néticas previstas no Código de Ética Profissional e\nconsiderar o contexto sociocultural e educacional do\nexaminando.\n  III. Para estabelecer com precisão em que consistem os\ndistúrbios que dificultam a realização de uma prova, é\nnecessário não se limitar à sua execução\nestandardizada e também introduzir tarefas específicas\nao longo da avaliação.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Avaliacao neuropsicologica valida (Luria, Lezak, Cunha): I — fundamento teorico solido, exploracao de funcoes basicas, instrucoes minimas, criterios objetivos (correto); II — diretrizes eticas do CEP e contexto sociocultural/educacional (correto); III — nao se limitar a aplicacao estandardizada, introduzir tarefas especificas para investigar disturbios (metodo lurianista, correto). Todos corretos."}, {"id": "1299703", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à avaliação psicológica e ao armazenamento de\ndados e de materiais, assinale a alternativa correta.", "alt": {"A": "Não é obrigatório o registro documental de toda\nprestação de serviço realizada pelo psicólogo.", "B": "Os protocolos utilizados são de uso exclusivo do\npsicólogo e deverão ser arquivados em local de acesso\nrestrito do psicólogo.", "C": "Toda e qualquer avaliação psicológica realizada deve\nter o material utilizado arquivado por cinco anos (salvo\ncasos específicos), com garantia de sigilo e privacidade.", "D": "É direito do cliente ter acesso a seus registros\nmediante protocolo de solicitação ao profissional\npsicólogo ou à instituição responsável.", "E": "Quando em serviço multiprofissional, o registro em\nprontuário não deve ser realizado em prontuário único,\nmesmo que sejam registradas as informações\nnecessárias para o objetivo do trabalho."}, "g": "C", "j": "Res CFP 06/2019 e 01/2009: todo material de avaliacao psicologica deve ser arquivado por no minimo 5 anos (salvo casos especificos), com garantia de sigilo e privacidade. A (nao obrigatorio registro) e falso; B (uso exclusivo) e impreciso; D (acesso mediante protocolo) e parcial; E (nao prontuario unico em multiprofissional) contraria Res 01/2009."}, {"id": "1299687", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "A orientação do trabalho do psicólogo está embasada no\nCódigo de Ética Profissional do Psicólogo. Quando ele\nestiver trabalhando em equipe multidisciplinar, o Código\ngarante que é preciso compartilhar conhecimento e\nprocedimentos psicológicos com os demais membros da\nequipe, dentro de limites que respeitem a privacidade das\npessoas. Com essa perspectiva, julgue os seguintes itens.    \nI. O sigilo faz parte da prática profissional do psicólogo,\nexigindo que o psicólogo resguarde o caráter\nconfidencial de suas comunicações e limite seu\ncompartilhamento.  \nII. O psicólogo, ao compartilhar laudos ou informes com\noutros profissionais, indicará o caráter confidencial dos\ndocumentos e a responsabilidade de quem os receber\nde preservar o sigilo.  \nIII. No trabalho em equipe multiprofissional, o fenômeno\npsicológico deve ser compreendido somente pelo\nprofissional da psicologia.  \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "CEP em equipe multidisciplinar: I — sigilo profissional, caracter confidencial das comunicacoes (correto); II — ao compartilhar laudos/informes, indicar o caracter confidencial e responsabilidade do receptor (correto, art. 12). Item III ('compreendido somente pelo profissional da psicologia') contraria o trabalho em equipe interdisciplinar — incorreto. Apenas I e II."}, {"id": "1299668", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "A questão da agressividade e sua relação com o trânsito é\ntema de pesquisas e debates há bastante tempo. Na revista\nPsicologia: Pesquisa & Trânsito (2006), no artigo\nAgressividade, raiva e comportamento de motorista,\nMonteiro & Gunther analisaram as relações entre\nagressividade e raiva na direção e erros e violações de\nmotoristas. Baseando-se no estudo realizado por eles, com\nescalas de raiva na direção, de agressividade e de violações\ne erros de motorista, assinale a alternativa incorreta.", "alt": {"A": "Os resultados apontam que, quanto menores os\níndices de raiva na direção, provocada por progresso\ndo veículo impedido, por direção agressiva por parte\nde outro motorista e por incômodo no ambiente físico\n(calor e barulho), menores são os índices de erro e\nviolação de motoristas, em termos de erro, violação,\nviolação agressiva e violação agressiva interpessoal.", "B": "Os estudos sugerem que, quanto menores os índices\nde agressividade verbal e de irritabilidade, maiores são\nos indicadores de raiva na direção em termos de\nprogresso do veículo impedido, direção agressiva de\noutro motorista e incômodo no ambiente físico (calor e\nbarulho).", "C": "Qualquer correlação aponta uma relação\npotencialmente bidirecional, isto é, tanto a raiva pode\nconfigurar antecedente de erro e violação quanto o\nfato de cometer erro e violações pode provocar mais\nraiva no motorista.", "D": "Observou-se que a maioria dos motoristas admitiu\nsentir raiva diante de situações de progresso do veículo\nimpedido, direção agressiva e incômodo no ambiente\nfísico.", "E": "Os dados indicam que raiva na direção pode ser uma\nvariável mediadora entre agressividade e\ncomportamentos inadequados de motoristas,\npotencializando as reações agressivas."}, "g": "B", "j": "Monteiro & Gunther (2006): a correlacao entre agressividade verbal/irritabilidade e raiva na direcao e POSITIVA (maior agressividade → maior raiva). A alternativa B inverte essa relacao ('menor agressividade → maior raiva'), tornando-se incorreta. Demais alternativas reproduzem achados do estudo."}, {"id": "1299666", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "No texto de Soares Junior (2019) intitulado Direção\ndistraída de veículos pelo uso do telefone celular,\npublicado no livro Transitando pela psicologia do trânsito\nno Brasil: ontem, hoje e amanhã, o autor discorre sobre\num dos importantes fatores de risco apontados pelos\nestudos da OMS. A direção distraída de veículos pelo uso de\nmodernas tecnologias veiculares móveis, cujo uso envolve\ndistrações visuais, manuais e cognitivas, é um foco de\natenção da OPAS (2018) no que diz respeito à segurança\nviária, sendo um problema na relação entre trânsito e\nsaúde. O conceito de direção distraída é bastante amplo e\nnão está restrito somente ao uso do telefone.\n    Considerando essas informações, assinale a alternativa\nincorreta.", "alt": {"A": "Sherin et al. (2014) definem a direção distraída como\nas atividades que são realizadas concomitantemente\ncom o dirigir e que prejudicam a atenção do condutor,\ndividindo-a e retirando sua dedicação da condução do\nveículo.", "B": "Segundo Sherin, o American College of Preventive\nMedicine destaca que os resultados das pesquisas\ncientíficas no cenário internacional deixam bastante\nevidentes as relações entre a direção distraída e a\nocorrência de acidentes.", "C": "A NHTSA (National Highway Traffic Safety\nAdministration) afirma, em um estudo realizado nos\nEstados Unidos, que, no ano de 2015, 10% dos\nacidentes fatais e 15% dos acidentes com vítimas\nregistrados tiveram como causas apontadas a direção\ndistraída.", "D": "Uma pesquisa da Seguradora Líder (2018), com 2.606\nparticipantes, acerca da percepção da população sobre\no comportamento dos brasileiros no trânsito, aponta\nque 78% dos respondentes entendem que o uso do\ncelular no trânsito não é um problema e não estaria\nrelacionado diretamente com a ocorrência de\nacidentes de trânsito.", "E": "No estudo de Drews, Patsupathi e Strayer (2008), ficou\ndemonstrado, com o uso de simulador de direção e de\ncelular concomitantemente, que a capacidade de\ndirigir do motorista fica afetada, diminuindo sua\natenção e limitando a varredura perceptiva realizada\nno ambiente do trânsito."}, "g": "D", "j": "Soares Junior (2019) e Seguradora Lider (2018): a pesquisa indica que a MAIORIA dos respondentes reconhece o uso do celular como problema relacionado a acidentes. A alternativa D inverte ('78% entendem que NAO e problema'), o que e factualmente incorreto. Demais alternativas (Sherin, NHTSA, Drews) reproduzem dados do capitulo."}, {"id": "1299655", "d": "psicologia", "a": ["Psicologia do Trânsito", "Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Rozestraten, os elementos que caracterizam os\nprocessos de trânsito são bastante abrangentes e é\nfundamental refletir sobre as inter-relações entre\npsicologia, ambiente e trânsito. Com relação à importância\ndos vínculos teórico-metodológicos em psicologia do\ntrânsito, psicologia social e psicologia ambiental, julgue os\nitens seguintes.\n    I. O homem é um ser ambiental.\n  II. O comportamento no trânsito e sua relação com o\nambiente social e o ambiente normativo são\nconsiderados como de fácil dimensão e controle.\n  III. Andar pelas calçadas de uma cidade, pedalar em\nciclovias e dirigir um automóvel são, todos,\ncomportamentos orientados e continuamente\nregulados pelo ambiente.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Rozestraten (Psicologia do Transito): I — o homem e ser ambiental, ecologico (correto); III — andar, pedalar e dirigir sao comportamentos orientados/regulados pelo ambiente (correto). Item II ('facil dimensao e controle') contraria a complexidade do comportamento no transito — incorreto. Apenas I e III."}, {"id": "1299653", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Com base na Resolução CFP n.ᵒ 6/2019, julgue os itens\nsubsequentes.\nI. De acordo com os deveres fundamentais previstos no\nCódigo de Ética Profissional do Psicólogo, na prestação\nde serviços psicológicos, os envolvidos no processo\npossuem o direito de receber informações sobre os\nobjetivos e resultados do serviço prestado, bem como\nde ter acesso ao documento produzido pela atividade\ndo psicólogo.\n  II. A confecção do documento psicológico deve ser\nrealizada mediante solicitação do usuário do serviço de\npsicologia, de seus responsáveis legais, de um\nprofissional específico, das equipes multidisciplinares\nou das autoridades, ou ser resultado de um processo\nde avaliação psicológica.\n  III. O documento escrito resultante da prestação de\nserviços psicológicos deve considerar a natureza\nestática, definitiva e cristalizada do fenômeno\npsicológico.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item II está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Res CFP 06/2019: I — envolvidos tem direito de receber informacoes sobre objetivos e resultados e acesso ao documento (correto); II — confeccao mediante solicitacao do usuario/responsavel/profissional/equipe/autoridade ou resultado de avaliacao (correto). Item III ('natureza estatica, definitiva e cristalizada') contraria a Res 06/2019, que reconhece o fenomeno psicologico como DINAMICO e PROCESSUAL — incorreto. Apenas I e II."}, {"id": "1299649", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com as referências técnicas para atuação de\npsicólogos em políticas públicas de mobilidade humana e\ntrânsito (CREPOP), em seu eixo 1: dimensão ético-política\nna relação entre psicologia, mobilidade humana e trânsito,\nassinale a alternativa incorreta.", "alt": {"A": "A mobilidade humana é um campo de fenômenos de\ninteresse da psicologia que inclui aspectos relativos ao\ntrânsito, ao transporte e, ao mesmo tempo, às\nespecificidades da psicologia, como, por exemplo, foco\nde estudos, pesquisa e ação.", "B": "O transporte coletivo, embora possua alguma\nrepresentatividade no Brasil, é proporcionalmente\npequeno em relação à frota nacional circulante e ao\ntamanho da população, precisando, desse modo, ser\nextinto para propiciar uma adequada mobilidade\nhumana.", "C": "Os modos escolhidos ou induzidos para trespassar\nespaços dizem respeito à forma como as pessoas se\nrelacionam com os espaços, não apenas do ponto de\nvista pessoal, mas, sobretudo, do ponto de vista\ncoletivo e político, uma vez que são\nocupados/utilizados por muitos.", "D": "No que concerne à mobilidade como campo de\nconhecimento e ação, a infusão dos pressupostos\nmercantilistas está fortemente enraizada e se\nconfunde com as escolhas de estilo de vida, isto é, de\nrelações sociais e de como os espaços evidenciam\nessas escolhas.", "E": "Pensar a mobilidade humana é concebê-la como\nresistência à mercantilização da vida, dos espaços e do\naparelhamento sustentável voltado prioritariamente à\nestabilidade econômica e política das sociedades."}, "g": "B", "j": "Referencias tecnicas CREPOP (Psicologia em Mobilidade Humana e Transito): defendem o FORTALECIMENTO do transporte coletivo como meio de mobilidade socialmente justa, NUNCA sua extincao. Alternativa B afirma o contrario ('precisa ser extinto'), sendo a incorreta. Demais reproduzem o eixo etico-politico (mobilidade como campo da psicologia, dimensao coletiva, critica a mercantilizacao)."}, {"id": "1299625", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Vários fatores demográficos ou socioculturais\ndesempenham importantes funções para determinar se\numa pessoa procurará tratamento médico, podendo ser\nfocos de atuação do psicólogo da saúde. Quanto a esse\ntema, julgue os itens seguintes.    I. A idade e o gênero dos indivíduos são fatores que\ninfluenciam na busca por tratamento. De modo geral,\ncrianças e idosos usam os serviços de saúde com mais\nfrequência que os adolescentes e os adultos jovens, e\nmulheres são mais propensas a relatar sintomas e a\nusar os serviços de saúde que os homens.  II. O status socioeconômico prevê o relato de sintomas e\nde procura por atendimento de saúde. Pessoas de\nrenda alta relatam mais sintomas que as de renda\nbaixa, porém têm menor probabilidade de procurar\natendimento de saúde.  III. Fatores culturais também influenciam a tendência em\nbuscar tratamento. Um fator cultural relacionado com\na probabilidade de uma pessoa procurar tratamento é\na criação. Pessoas cujos pais prestavam muita atenção\nem sintomas físicos e buscavam tratamento com\nfrequência, possivelmente, farão o contrário, a fim de\nevitar o excesso de cuidados.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e III estão certos."}, "g": "B", "j": "Sarafino (Psicologia da Saude): I — idade/genero influenciam busca por tratamento; criancas e idosos usam mais; mulheres mais propensas (correto). II — pessoas de renda BAIXA, nao alta, relatam mais sintomas e tem MAIOR (nao menor) probabilidade de procurar atendimento — item inverte os dados (incorreto). III — filhos de pais atentos a sintomas tendem a procurar tratamento, NAO o contrario (incorreto). Apenas I certo."}, {"id": "1299623", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Técnicas de manejo de estresse estão sendo utilizadas de\nforma ampla, nos dias atuais, no auxílio à adaptação de\npacientes às doenças crônicas e aos procedimentos\nmédicos estressantes. Com relação ao manejo do estresse,\nassinale a alternativa incorreta.", "alt": {"A": "A prática regular de atividade física pode aumentar as\ncapacidades fisiológicas e psicológicas para enfrentar o\nestresse.", "B": "Técnicas de relaxamento, como as de relaxamento\nmuscular progressivo e a resposta de relaxamento,\npodem ajudar as pessoas a lidar com vários problemas\nrelacionados ao estresse, como, por exemplo,\nhipertensão, dores crônicas e ansiedade.", "C": "O biofeedback é uma técnica usada para converter\ncertas respostas fisiológicas supostamente\ninvoluntárias, como a atividade muscular, a frequência\ncardíaca e a pressão arterial, em sinais elétricos e\nproporcionar um feedback visual ou auditivo a seu\nrespeito, o que a torna uma maneira viável de tratar\nalgumas condições relacionadas ao estresse.", "D": "O manejo cognitivo comportamental do estresse é uma\nforma multimodal de terapia que ajuda as pessoas a\nconfrontar eventos estressantes.", "E": "O treinamento de inoculação do estresse, integrante\ndo manejo cognitivo comportamental, é um processo\nem dois estágios (reconceituação e manutenção), em\nque o terapeuta utiliza uma dose enfraquecida de um\nestressor na tentativa de construir imunidade contra o\nestressor total."}, "g": "E", "j": "Treinamento de Inoculacao do Estresse (Meichenbaum) tem TRES estagios (conceitualizacao/educacao, aquisicao de habilidades, aplicacao/follow-through), nao dois. Alternativa E reduz incorretamente para 'reconceituacao e manutencao'. A (atividade fisica), B (relaxamento), C (biofeedback) e D (manejo cog-comp) sao corretas."}, {"id": "1299621", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Considerando o campo das políticas públicas de saúde, a\nsaúde mental aparece como área de conhecimento e\natuação importante para diversos profissionais, incluindo o\npsicólogo da saúde. No que se refere a esse tema, assinale\na alternativa incorreta.", "alt": {"A": "A saúde mental é um campo polissêmico e plural, na\nmedida em que diz respeito ao estado mental dos\nsujeitos, e não das coletividades.", "B": "A saúde mental caracteriza-se como um campo de\nconhecimento complexo, plural, intersetorial e de\ngrande transversalidade de saberes.", "C": "O processo de Reforma Psiquiátrica surgiu no contexto\nnacional a partir da década de 1980 do século XX,\ncomo proposta à ruptura do modelo\nclínico-psiquiátrico centrado na referência hospitalar.", "D": "A Reforma Psiquiátrica propôs um processo de\ndesconstrução e reconstrução da atenção à pessoa que\nsofre mentalmente.", "E": "A atenção psicossocial remete a práticas de reinserção\ne permanência do sujeito que sofre mentalmente no\nconvívio social."}, "g": "A", "j": "Saude mental e campo polissemico que abrange dimensao INDIVIDUAL E COLETIVA. Alternativa A afirma indevidamente que se refere 'ao estado mental dos sujeitos, e nao das coletividades', restringindo o campo — incorreto. B (campo plural/intersetorial), C (Reforma Psiquiatrica anos 80), D (desconstrucao/reconstrucao) e E (atencao psicossocial e reinsercao) reproduzem a literatura."}, {"id": "1299620", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Benevides (2005) propõe que, no entrecruzamento do\nexercício de três princípios, pode estar a interface entre a\npsicologia e o SUS. A respeito desses princípios, assinale a\nalternativa correta.", "alt": {"A": "O princípio da inseparabilidade considera a psicologia\ncomo o campo do saber voltado aos estudos da\nsubjetividade, que é entendida como processo\nindividual de produção.", "B": "Relacionando política pública com subjetividade, o\nprincípio da inseparabilidade traz à tona a divergência\nentre processo de subjetividade e plano público.", "C": "O princípio da autonomia e da corresponsabilidade\nesclarece que é possível pensar em práticas dos\npsicólogos que não estejam comprometidas com a\nrealidade vivida.", "D": "Segundo o princípio da autonomia e da\ncorresponsabilidade, a interface da psicologia com o\nSUS dá-se pela certeza de que o processo de se\ninventar é independente da invenção do mundo e\nvice-versa.", "E": "O princípio da transversalidade entende que a\npsicologia é um campo de saber que deve ser explicado\nna intercessão com outros saberes. É a combinação\nentre saberes que contribui para uma outra saúde\npossível."}, "g": "E", "j": "Benevides (2005) propoe tres principios para interface psicologia-SUS: inseparabilidade (sujeito-mundo nao se separam), transversalidade (saberes em interseccao) e autonomia/corresponsabilidade. Alternativa E descreve corretamente a TRANSVERSALIDADE como interseccao de saberes para uma 'outra saude possivel'. A, B, C e D invertem ou distorcem os principios."}, {"id": "1299619", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "No campo da saúde coletiva e pública, a criação do Sistema\nÚnico de Saúde (SUS) foi uma grande conquista. Para a\npsicologia, inserir profissionais no SUS tem sido um desafio.\nSendo assim, é correto afirmar que corresponde a uma\nproposta de ação para colaborar com esse processo o(a)", "alt": {"A": "oferecimento de mais possibilidades de estágio em\ninstituições particulares de saúde.", "B": "organização dos serviços de saúde, desconsiderando-se\nas especificidades regionais.", "C": "entendimento de que a produção de conhecimento é\numa prática dispensável na formação do psicólogo.", "D": "desencorajamento da prática da pesquisa no campo\ndas políticas públicas de saúde.", "E": "formação de psicólogos para atuação em saúde pública\nde forma transversal, articulando política, teoria e\nprática."}, "g": "E", "j": "Insercao do psicologo no SUS exige formacao TRANSVERSAL que articule politica, teoria e pratica. Alternativa E reproduz a proposta. A (estagios em particulares), B (desconsiderar regionais), C (dispensar conhecimento) e D (desencorajar pesquisa) contrariam diretrizes do SUS e da formacao em psicologia da saude."}, {"id": "1299553", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere a preconceito, julgue os itens\nsubsequentes.\n I. Os preconceitos fazem parte de uma tradição cultural\nque se transmite de geração a geração.     II. O autoconceito é construído, nas relações sociais, por\nmeio de um processo interativo que inclui família,\namigos e organizações significantes.     III. A difusão da crença da inferioridade das pessoas\nnegras pode provocar alienação e negação da\nidentidade racial.     IV. Para evitar o alijamento do negro e do índio na\nsociedade, não se pode relacionar preconceito com\nquestões étnico-raciais. Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e IV estão certos.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I, II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Sobre preconceito: I — tradicao cultural transmitida entre geracoes (correto); II — autoconceito construido em relacoes sociais com familia, amigos, organizacoes (correto); III — crenca na inferioridade de pessoas negras provoca alienacao e negacao da identidade racial (correto). Item IV inverte: para combater alijamento, e PRECISO relacionar preconceito com etnico-racial (incorreto). Apenas I, II e III."}, {"id": "1299552", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2020", "org": "CFP", "t": "", "e": "O racismo pode ser considerado como uma", "alt": {"A": "crença na existência de raça naturalmente\nhierarquizada pela relação intrínseca entre o físico e o\nmoral, o físico e o intelecto e o físico e o cultural.", "B": "forma de expressão de liberdade social.", "C": "onda vivenciada em países de regime ditatorial e que,\nportanto, não considera a hegemonia das raças.", "D": "tradição de países emergentes.", "E": "produção da filogenia amalgamada pela ontogenia."}, "g": "A", "j": "Racismo (definicao classica em Munanga, Schwarcz): crenca na existencia de racas naturalmente hierarquizadas pela relacao entre o fisico, moral, intelectual e cultural. Alternativa A reproduz a definicao academica. B, C, D e E sao formulacoes sem suporte na literatura sobre racismo."}, {"id": "1299545", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Além das práticas tradicionais, o psicólogo pode\ndesempenhar outras atividades na escola. Sendo assim,\njulgue os itens a seguir.\n I. O psicólogo deverá participar do processo de seleção\ndos membros da equipe pedagógica e do processo de\navaliação dos resultados do trabalho.     II. O psicólogo deverá contribuir para a coesão da equipe\nde direção pedagógica e para sua formação técnica.     III. O psicólogo deverá realizar pesquisas diversas, com o\nobjetivo de aprimorar o processo educativo. Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Atribuicoes do psicologo escolar (referencias CFP/Almeida, Guzzo): I — participar do processo de selecao da equipe pedagogica e avaliacao dos resultados (correto); II — contribuir para coesao e formacao tecnica da direcao pedagogica (correto); III — realizar pesquisas para aprimorar o processo educativo (correto). Todos os itens corretos."}, {"id": "1299544", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "No que concerne ao processo de orientação e formação de\nprofessores, julgue os itens que se seguem.\n I. A complexidade do processo de aprendizagem e\ndesenvolvimento, em suas variadas formas de\nexpressão, deve ser considerada.     II. Os aspectos subjetivos que envolvem os processos de\naprendizagem devem ser considerados.     III. As condições históricas e culturais implicadas no\nprocesso de aprendizagem devem ser consideradas. Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Orientacao e formacao de professores deve considerar: I — complexidade do processo de aprendizagem/desenvolvimento (correto); II — aspectos subjetivos do aprender (correto); III — condicoes historicas e culturais (correto, perspectiva critica/historico-cultural). Todos os tres itens corretos."}, {"id": "1299541", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca da orientação aos pais e(ou) responsáveis por parte\ndos psicólogos escolares, julgue os próximos itens.\n I. Os psicólogos escolares devem estar atentos ao\ndesenvolvimento integral dos estudantes para\nestruturar um trabalho de orientação a alunos e pais,\nseja de forma individualizada, seja de forma grupal,\nque contribua para o desenvolvimento almejado.     II. É necessário que os psicólogos escolares coordenem\ngrupos de orientação de pais, em função de suas\ndemandas, no que diz respeito aos aspectos\npsicológicos do desenvolvimento e da educação dos\nfilhos.\n    III. É necessário que os psicólogos escolares proporcionem\norientações em relação ao sentido atribuído à\nsexualidade, à responsabilidade para com o outro, às\ndúvidas e inquietações sobre desejos e afetos, à\ncontribuição para o desenvolvimento do\nautoconhecimento, à autorreflexão, à capacidade de\nantecipar consequências e à tomada de decisões\néticas. Essas orientações constituem um objeto\nsignificativo do trabalho do psicólogo escolar, tanto em\nsua expressão individual quanto na grupal.     Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Orientacao a pais pelo psicologo escolar: I — atencao ao desenvolvimento integral, individual e grupal (correto); II — coordenar grupos de orientacao de pais (correto); III — orientacoes sobre sexualidade, autoconhecimento, decisoes eticas como objeto significativo do trabalho (correto). Todos os itens corretos."}, {"id": "1299537", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "As políticas governamentais sobre a diversidade sexual na\nescola ganharam força no cenário brasileiro a partir da\ndécada de 1990. Elas surgiram com o objetivo de prevenir\ndoenças, promover saúde e garantir os direitos sexuais e\nreprodutivos. A partir dessas informações, assinale a\nalternativa que apresenta diploma(s) legal(is) que apoia(m)\na atuação profissional nesse campo.", "alt": {"A": "Política Nacional de Educação Especial na perspectiva\nda educação Inclusiva", "B": "Programa Brasil e Homofobia de 2001", "C": "Programa Gênero e Diversidade na Escola e\nParâmetros Curriculares Nacionais", "D": "Programa de Educação Sexual na escola", "E": "Lei Brasileira de Inclusão (LBI)"}, "g": "C", "j": "Politicas de diversidade sexual na escola: o Programa Genero e Diversidade na Escola (GDE/SECAD-MEC) e os Parametros Curriculares Nacionais (PCN, especialmente os temas transversais Orientacao Sexual) sao os diplomas que apoiam a atuacao profissional. Alternativa C correta. A (PNEE Inclusiva) trata de educacao especial; B nomeia incorretamente 'Brasil e Homofobia' (correto seria 'Brasil sem Homofobia', 2004); D e generica; E (LBI) trata de pessoa com deficiencia."}, {"id": "1299531", "d": "psicologia", "a": ["Estresse Laboral", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Estresse é qualquer mudança que precisa de adaptação.\nHans Selye foi um dos primeiros a estudar o assunto. De\nacordo com suas ideias, assinale a alternativa incorreta.", "alt": {"A": "Eustress é o nível positivo de estresse.", "B": "A síndrome geral de adaptação é a reação do sujeito,\ncom um conjunto de respostas específicas a estímulos\nque ameacem sua homeostase.", "C": "A síndrome geral de adaptação é composta por três\nfases: reação de alarme; fase de resistência; e fase de\nexaustão.", "D": "A UTI é considerada como uma unidade estressante\npara o paciente, para a família e para os próprios\nprofissionais de saúde.", "E": "Os estímulos estressores são sempre externos\n(trabalho, meio social, condição econômica, entre\noutros)."}, "g": "E", "j": "Selye (Sindrome Geral de Adaptacao): estimulos estressores podem ser EXTERNOS (ambiente, trabalho) OU INTERNOS (cognicoes, expectativas, doencas, lesoes organicas). Alternativa E ('sempre externos') esta incorreta. A (eustress), B (SGA como reacao), C (tres fases: alarme, resistencia, exaustao) e D (UTI estressante) reproduzem Selye corretamente."}, {"id": "1299448", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Fonseca afirma que a hominização sintetizada ilustra que a\nevolução filogenética e sociogenética decorreu em cerca de\nsete milhões de anos. Por analogia, a ontogênese\npsicomotora pode ser observada em cerca de sete anos,\nevocando, quer em um caso, quer em outro, a imbricação\nacoplada e a integração cortical sucessiva das seguintes\nconquistas psicomotoras emergentes:", "alt": {"A": "macromotricidade – micromotricidade –\noromotricidade – grafomotricidade.", "B": "macromotricidade – oromotricidade –\nmicromotricidade – grafomotricidade.", "C": "micromotricidade – macromotricidade –\noromotricidade – grafomotricidade.", "D": "oromotricidade – macromotricidade –\nmicromotricidade – grafomotricidade.", "E": "macromotricidade – micromotricidade –\ngrafomotricidade – ortomotricidade."}, "g": "A", "j": "Fonseca (Psicomotricidade): sequencia ontogenetica das conquistas psicomotoras e macromotricidade (controle postural global) → micromotricidade (motricidade fina/manual) → oromotricidade (controle fonoarticulatorio) → grafomotricidade (escrita). Alternativa A reproduz a sequencia. As demais invertem etapas (B inverte oro/micro; C inverte macro/micro; D inicia por oro; E substitui grafo por 'ortomotricidade')."}, {"id": "1299447", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "O teste Bender é um instrumento psicotécnico de avaliação\npsicológica para avaliar o funcionamento visomotor e a\npercepção visual nas diversas fases do desenvolvimento\nhumano. Com o teste, é possível identificar danos orgânicos\ncerebrais, grau de maturação do sistema nervoso,\nmaturidade visual, integração visomotora, estilo de\nresposta, reação à frustração, habilidade para corrigir erros,\nhabilidades de planificação e organização e motivação.\nAcerca desse assunto, julgue os próximos itens.\n      I. Bender (1955) salienta que a criança em idade escolar\n(três anos de idade) possui a capacidade de ler e\nescrever, já que suas funções visomotoras estão\nmaduras, ou seja, distantes das funções de um adulto.\nContudo, é a partir dos doze anos de idade que essa\ncapacidade se torna consolidada.  \nII. Noronha, Santos e Sisto (2007) constataram que a\nvariável sexo não possui associação significativa com a\nprodução no Bender, comentando que não há\nevidências de que meninos e meninas possuam\ndiferenças no processo de amadurecimento em nível\nperceptomotor.\n  III. A partir da idade de oito anos, pelo amadurecimento\ndo sistema nervoso central, a criança já tem condições\nde executar a cópia de forma a não produzir tantos\nerros em nível de distorção da forma, rotação,\nintegração e perseverança. Esses mesmos erros,\nquando muito frequentes em algumas figuras,\nevidenciam dificuldades maturacionais em nível\nneurológico na criança.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "E", "j": "Teste Bender: I e factualmente incorreto — aos 3 anos a crianca NAO le nem escreve; suas funcoes visomotoras estao em desenvolvimento. II correto (Noronha, Santos & Sisto, 2007: sem associacao significativa sexo-Bender). III correto (a partir dos 8 anos, amadurecimento do SNC permite copia com menos erros de distorcao/rotacao/integracao/perseveranca). Apenas II e III."}, {"id": "1299444", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo a teoria de Cratty, citada em Fonseca (2008), a\nmotricidade e a inteligência equacionam alguns princípios.\nCom relação a eles, julgue os itens a seguir.      \nI. A precisão da motricidade é essencial à expressão da\ninteligência. A situação motora é um meio ótimo para\ndesenvolver os níveis de vigilância e atenção e a\nparticipação lúdica facilita a aquisição de noções\nsimbólicas, fundamentais para a aprendizagem escolar.\n  II. A motricidade facilita as condições de autocontrole e\naumenta a capacidade de autorregulação, enquanto a\nsatisfação inerente à experiência motora contribui\ngrandemente para o sentimento de competência.  \nIII. Os movimentos globais e finos são uma modalidade\nmultissensorial de aprendizagem e a motricidade deve\nser reconhecida como experiência de aprendizagem,\numa vez que, por meio dela, se promove o\npensamento criativo.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Cratty (citado em Fonseca, 2008): I — precisao motora essencial a expressao da inteligencia; participacao ludica facilita simbolizacao (correto); II — motricidade facilita autocontrole e autorregulacao; satisfacao motora produz sentimento de competencia (correto); III — movimentos globais/finos como aprendizagem multissensorial; motricidade como experiencia de aprendizagem que promove pensamento criativo (correto). Todos certos."}, {"id": "1299437", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicomotricidade, quando aplicada ao idoso, se preocupa\ncom os efeitos retrogênicos causados pelo processo de\nenvelhecimento. Com essa perspectiva, assinale a\nalternativa incorreta.", "alt": {"A": "Deve ter uma grande preocupação com a lentidão\ncognitiva e motora porque, no caso do idoso, esses são\nos problemas mais relevantes.", "B": "Deve considerar que toda atitude tônica tem uma\nresposta afetiva e que nem todo estado emocional\nimplica em um comportamento tônico", "C": "Deve se preocupar com projetos de intervenção\ncriativa e promotora de saúde nessa fase.", "D": "Deve realizar atividades para reintegração e\nsimbolização da imagem corporal.", "E": "Deve colocar o corpo em movimento, especialmente\nna dança ou em atividades que gerem prazer."}, "g": "B", "j": "Psicomotricidade (Wallon, Ajuriaguerra): a relacao tonico-afetiva e BIDIRECIONAL — toda atitude tonica tem ressonancia afetiva E todo estado emocional repercute no tonus. Alternativa B nega a segunda parte ('nem todo estado emocional implica comportamento tonico'), contrariando a fundamentacao classica. Demais alternativas (A — lentidao cognitiva/motora, C — projetos criativos, D — imagem corporal, E — dança/movimento) estao corretas."}, {"id": "1299435", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Com base em Le Boulch, em Educação pelo movimento\n(1983), julgue os itens subsequentes.      \nI. O esquema corporal pode ser considerado como uma\nintuição de conjunto ou de um conhecimento imediato\nque se tem do próprio corpo, em posição estática ou\nem movimento, na relação de suas diferentes partes\nentre si, sobretudo nas relações com o espaço e os\nobjetos que o circundam.  \nII. O esquema corporal acontece ao longo do\ndesenvolvimento da criança, a partir da formação do\nego e da percepção do outro como um movimento de\nautopreservação da espécie.  III. O esquema corporal vago ou mal estruturado produz\ncomo corolário um deficit na relação sujeito-mundo\nexterior, traduzindo-se no plano da percepção, da\nmotricidade e da relação com outrem.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Le Boulch (Educacao pelo movimento, 1983): I — esquema corporal como intuicao de conjunto/conhecimento imediato do corpo em posicao e movimento (correto); III — esquema corporal mal estruturado produz deficit na relacao sujeito-mundo (correto). Item II ('autopreservacao da especie') nao corresponde a formulacao de Le Boulch, que situa o esquema corporal no desenvolvimento da percepcao do corpo proprio e do outro como construcao psicomotora — incorreto. Apenas I e III."}, {"id": "1299431", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A BPM de Fonseca é um instrumento que favorece a\navaliação psicomotora e pode fazer parte dos processos\nrealizados pelos psicólogos. A respeito desse assunto,\nassinale a alternativa incorreta.", "alt": {"A": "A BPM não deve ser usada para diagnosticar deficits\nneurológicos nem para diagnosticar disfunções ou\nlesões cerebrais.", "B": "A BPM tem uma utilidade educacional comprovada por\ndiversos profissionais, tais como educadores físicos,\nenfermeiros de reabilitação, entre outros.", "C": "A BPM, quando aplicada com outros instrumentos,\npode ajudar na prevenção, na compensação e na\nreeducação motoras, impedindo a evolução para um\nproblema maior.", "D": "A BPM pode substituir os testes estandardizados que\nsão aplicados somente por psicólogos.", "E": "A BPM requer afinamentos, mas dá um suporte clínico\ncomo modelo original de observação dinâmica do\npotencial de aprendizagem da criança."}, "g": "D", "j": "BPM de Fonseca COMPLEMENTA, mas NAO SUBSTITUI testes estandardizados aplicados por psicologos. Alternativa D esta incorreta. A (nao diagnostica deficits neurologicos), B (utilidade educacional ampla), C (prevencao/compensacao/reeducacao) e E (suporte clinico, modelo de observacao dinamica) reproduzem corretamente os limites e o uso da BPM."}, {"id": "1299429", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Fonseca (2012), a bateria psicomotora (BPM)\nconsiste em uma série de simples tarefas distribuídas em\ndeterminados fatores psicomotores. São eles:", "alt": {"A": "tonicidade; equilibração; lateralização; noção de corpo;\nestruturação espaço-temporal; praxia global; praxia\nfina; e aspectos emocionais.", "B": "tonicidade; equilibração; lateralização; noção de corpo;\nestruturação espaço-temporal; praxia global; praxia\nfina; e aspectos psíquicos.", "C": "tonicidade; equilibração; lateralização; noção de corpo;\nestruturação espaço-temporal; praxia global; praxia\nfina; e aspectos biopsicossociais.", "D": "tonicidade; equilibração; lateralização; noção de corpo;\nestruturação espaço-temporal; praxia global; praxia\nfina; e aspectos socioeducacionais.", "E": "tonicidade; equilibração; lateralização; noção de corpo;\nestruturação espaço-temporal; praxia global; e praxia fina."}, "g": "E", "j": "Fonseca (2012) — Bateria Psicomotora (BPM) consiste em 7 fatores psicomotores: tonicidade, equilibracao, lateralizacao, nocao de corpo, estruturacao espaco-temporal, praxia global e praxia fina. Alternativa E enumera exatamente esses 7. As demais (A, B, C, D) acrescentam indevidamente um 8 fator (emocional/psiquico/biopsicossocial/socioeducacional) que nao consta da BPM."}, {"id": "1299428", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Turtelli e Tavares (2008) apresentam a teoria de\nKestenberg, que considera que o movimento humano é\ncontextualizado no mundo psíquico. Com base nessa\ninformação, julgue os itens a seguir.\n      I. Kestenberg traz à tona a relação entre o\ndesenvolvimento dos padrões motores e o\ndesenvolvimento da psique, assim como as origens dos\npadrões de movimento dos adultos em suas\nexperiências e preferências da primeira infância.  \nII. Os estudos de Kestenberg vêm ao encontro de uma\nnecessidade atual de aprofundar a compreensão do\nmovimento humano, por meio de dados consistentes\nsobre os entrelaçamentos entre o mover e o afeto. O\nmovimento em Kestenberg é reconhecido como um\nfenômeno que evidencia, a todo momento, a\nsingularidade dos sentidos de cada ser humano.\n  III. Outro aspecto relevante dos estudos Kestenberg diz\nrespeito às relações entre os corpos. Kestenberg\nenfoca a importância da sintonia entre os movimentos\nde mãe e filho, entre coleguinhas, entre terapeuta e\npaciente, entre observador e observado e outros.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Turtelli & Tavares (2008) sobre Kestenberg: I — relacao entre padroes motores e desenvolvimento da psique, origens dos movimentos adultos na primeira infancia (correto); II — entrelacamento mover/afeto, singularidade dos sentidos (correto); III — sintonia entre mae-filho, terapeuta-paciente, observador-observado (correto). Todos os itens reproduzem teses centrais de Kestenberg."}, {"id": "1299424", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Prestes, Weiss e Araujo (2010), as atividades que\nenvolveram o cavalo e seu ambiente favoreceram o\nenriquecimento de repertórios motores dos sujeitos\npesquisados. Durante a montaria, os escolares deveriam\npermanecer atentos e concentrados nas atividades que\nestavam realizando para poder conduzir o animal\ncorretamente por caminhos e percursos adequados e\nindicados. O movimento constante do cavalo desencadeou\nrespostas motoras que estimularam constantes reajustes\ntônicos e posturais, que, por sua vez, incitaram os sistemas\nresponsáveis pela propriocepção e pelo equilíbrio.\nSomando-se a isso, para conduzir o cavalo, as crianças\ntiveram que perceber seu corpo em conjunto com o corpo\ndo cavalo. Compreender o movimento e o ritmo das\nandaduras dele, para que pudessem manter-se montadas,\nsem cair e sem colidir com objetos, pessoas, animais ou\nqualquer outro tipo de obstáculo, incidiu sobre o\ndesenvolvimento, entre outros aspectos, do esquema\ncorporal e da organização espacial e temporal. A\nmanutenção da postura montado e a execução de\ndiferentes posturas sobre o cavalo, como ficar em pé sobre\nos estribos, sentar-se de costas para a cabeça do animal,\nrealizar o trote e o galope, são exemplos de atividades e\nsituações que estimulam a motricidade global e o\nequilíbrio. Adiciona-se a isso a necessidade de manusear as\nrédeas constantemente, favorecendo intensamente o\navanço da motricidade fina.       De acordo com o texto acima, assinale a alternativa correta.", "alt": {"A": "Os alunos de comunidades apresentam dificuldades\nmotoras maiores, por causa de sua condição social e de\nescolas boas.", "B": "O tamanho do cavalo é o fator mais importante para o\ndesenvolvimento de cada criança.", "C": "Além do que já foi citado no texto, as relações sociais\ndas crianças são trabalhadas.", "D": "Todos os autores dessa linha de pensamento\nconcordam com o exposto no texto acima.", "E": "As dificuldades de compreender o movimento, em\nparte, são culpa dos pais, que negligenciam a vida do\nfilho."}, "g": "C", "j": "Prestes, Weiss & Araujo (2010) — equoterapia: alem do desenvolvimento psicomotor descrito no texto, as atividades com cavalo trabalham as RELACOES SOCIAIS das criancas (interacao com o animal, instrutores, colegas) — alternativa C correta. As demais sao estereotipadas e nao fundamentadas no estudo (A — culpa social; B — tamanho do cavalo; D — generalizacao indevida; E — culpa dos pais)."}, {"id": "1299410", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Perícia Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Um aspecto importante no processo avaliativo está na\ncomunicação dos resultados. No que concerne a esse\ntópico, Rovinski (apud Grow-Marnat, 2003) considera que\nas críticas aos laudos psicológicos estão centradas\npredominantemente em", "alt": {"A": "dados brutos dos resultados.", "B": "teorias psicológicas.", "C": "métodos empregados.", "D": "inferências e generalizações.", "E": "demandas definidas."}, "g": "D", "j": "Rovinski (apud Groth-Marnat, 2003): as criticas aos laudos psicologicos concentram-se predominantemente em INFERENCIAS E GENERALIZACOES indevidas — extrapolacao alem dos dados, conclusoes nao fundamentadas. Alternativa D reproduz a critica. Demais (dados brutos, teorias, metodos, demandas) nao sao o foco central das criticas tecnicas."}, {"id": "1299406", "d": "psicologia", "a": ["Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2020", "org": "CFP", "t": "", "e": "Nas diretrizes para a atuação e formação dos psicólogos do\nsistema prisional brasileiro, são apresentadas propostas de\nação do psicólogo diante do exame criminológico e da\nComissão Técnica de Classificação. Com relação a elas,\njulgue os seguintes itens.\nI. Enquanto categoria, é atribuição do psicólogo apontar\naos envolvidos no campo da execução penal que a\nrealização do exame criminológico, enquanto\ndispositivo disciplinar que viola, entre outros, o direito\nà intimidade e à personalidade, não deve ser mantido\ncomo sua atribuição, devendo ser prioritária a\nconstrução de propostas para desenvolver formas de\naboli-lo.\nII. Enquanto não for abolido, o psicólogo, na construção\ndos seus laudos e pareceres, deve contribuir para a\ndesconstrução de tal exame, questionando conceitos\ncomo a periculosidade e a irresponsabilidade penal,\nrealizando-os em uma abordagem transdisciplinar,\ncomo um momento de encontro com o indivíduo,\nresgatando o saber teórico e contribuindo para revelar\nos aspectos envolvidos na prisionalização.\nIII. Enquanto existir a Comissão Técnica de Classificação, o\npsicólogo deve ter entendimento do papel institucional\nque ocupa, dando evidência ao Código de Ética\nProfissional e a instrumentos nacionais e internacionais\nde direitos humanos nas opiniões que emitir sobre\ntodas as pautas a serem debatidas e estimulando os\ntemas sobre saúde, educação e programas de\nreintegração social.\nAssinale a alternativa correta", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Diretrizes do CFP para atuacao no sistema prisional (Res 09/2010 e atualizacoes): I — categoria deve apontar que o exame criminologico viola direitos e construir formas de aboli-lo (correto); II — enquanto nao abolido, contribuir para sua desconstrucao, questionando periculosidade e irresponsabilidade penal (correto); III — na CTC, dar evidencia ao CEP e DH, estimulando saude/educacao/reintegracao (correto). Todos os itens corretos."}, {"id": "1299404", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "A direção de estabelecimento penal pode ser ocupada por\nportador de diploma de nível superior de", "alt": {"A": "administração, ou economia, ou pedagogia, ou serviços\nsociais.", "B": "direito, ou contabilidade, ou administração, ou\npedagogia, ou serviços sociais.", "C": "economia, ou ciências sociais, ou pedagogia, ou\nserviços sociais.", "D": "contabilidade, ou administração, ou economia, ou\npedagogia, ou serviços sociais.", "E": "direito, ou psicologia, ou ciências sociais, ou pedagogia,\nou serviços sociais."}, "g": "E", "j": "Lei de Execucao Penal (Lei 7.210/84), art. 75: a direcao do estabelecimento penal podera ser ocupada por portador de diploma de nivel superior de DIREITO, ou PSICOLOGIA, ou CIENCIAS SOCIAIS, ou PEDAGOGIA, ou SERVICOS SOCIAIS. Alternativa E reproduz a letra da lei. As demais omitem cursos previstos (direito, psicologia) ou incluem cursos nao previstos (contabilidade, economia)."}, {"id": "1299402", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "Julgue os itens que se seguem.\nI. No exame para a obtenção de dados reveladores da\npersonalidade, observando a ética profissional e tendo\nsempre presentes as peças ou informações do\nprocesso, a Comissão Técnica de Classificação poderá\nentrevistar a pessoa.\nII. No exame para a obtenção de dados reveladores da\npersonalidade, observando a ética profissional e tendo\nsempre presentes as peças ou informações do\nprocesso, a Comissão Técnica de Classificação poderá\nrequisitar, de repartições ou estabelecimentos\nprivados, dados e informações a respeito do\ncondenado.\nIII. No exame para a obtenção de dados reveladores da\npersonalidade, observando a ética profissional e tendo\nsempre presentes as peças ou informações do\nprocesso, a Comissão Técnica de Classificação poderá\nrealizar outras diligências e exames necessários.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Lei de Execucao Penal, art. 9: a Comissao Tecnica de Classificacao, no exame para obtencao de dados reveladores da personalidade, podera I — entrevistar a pessoa, II — requisitar dados de reparticoes ou estabelecimentos privados, III — realizar outras diligencias e exames necessarios. Todos os itens reproduzem o art. 9. Gabarito E."}, {"id": "1299393", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Goulart e Sampaio (1998), a psicologia\norganizacional e do trabalho surgiu à medida que os\npsicólogos deixaram de estudar os postos de trabalho para\ncontribuir também com a discussão acerca das estruturas\nda organização. Considerando essa informação, julgue os\nitens seguintes.      \nI. Na história, o surgimento da psicologia organizacional\ne do trabalho não foi apenas uma ruptura radical com a\npsicologia da indústria. Foi uma ampliação de seu\nobjeto de estudo, posto que os psicólogos\ncontinuavam atrelados ao problema da produtividade\ndas empresas.\n  II. Na história da psicologia organizacional e do trabalho,\no caráter instrumental acabou por supervalorizar as\nteorias comportamentais na psicologia, que\nmaximizaram a influência do ambiente no\ncomportamento humano e minimizaram as influências\nintrapsíquicas, reduzindo-as ao âmbito da “satisfação”.  III. Na história da psicologia organizacional e do trabalho,\nteorias mais complexas de homem, como a análise\ntransacional, a dinâmica de grupos e a díade\nsociometria/sociodrama, agora aplicadas à formação\nde mão de obra no trabalho, dão suporte ao\ndesenvolvimento interpessoal.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Goulart & Sampaio (1998) sobre POT: I — surgimento como AMPLIACAO da psicologia industrial (nao ruptura radical), mantendo atrelamento a produtividade (correto); II — carater instrumental supervalorizou teorias comportamentais que reduziram intrapsiquico a 'satisfacao' (correto); III — teorias mais complexas (analise transacional, dinamica de grupos, sociometria/sociodrama) ampliam o desenvolvimento interpessoal (correto). Todos os itens corretos."}, {"id": "1299390", "d": "psicologia", "a": ["Liderança", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Para Dubrin (2003), a liderança envolve influenciar outros a\nalcançar objetivos que são importantes para eles e para a\norganização, pois traduz-se como a habilidade de inspirar\nconfiança e apoio entre as pessoas de cuja competência e\ncompromisso depende o desempenho. Dessa forma,\nembora a liderança seja uma função principal do\ngerenciamento, ela não é o mesmo que gerenciamento.\nConsiderando tais pressupostos, julgue os itens a seguir.      I. O gerenciamento lida com a complexidade, que requer\na preservação da ordem e da consistência. A liderança,\npor sua vez, lida com as mudanças em um mundo\ncompetitivo, rapidamente mutante.\n  II. Os líderes eficazes, embora lidem com as mudanças e\ndevam formular uma visão do futuro, estabelecendo\numa direção para essa visão, não devem se envolver\nem persuadir ou inspirar os outros para as mudanças\nprevistas, pois isso compete ao gerenciamento.\n  III. O gerenciamento e a liderança eficaz são igualmente\nexigidos no moderno ambiente de trabalho. Os\ngerentes devem ser líderes, mas os líderes também\ndevem ser bons gestores.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Dubrin (2003) sobre lideranca: I — gerenciamento lida com complexidade/ordem; lideranca com mudancas em mundo competitivo (correto, base Kotter/Dubrin); III — gerenciamento e lideranca ambos necessarios; gerentes devem ser lideres e vice-versa (correto). Item II inverte o conceito de lideranca: lideres EFETIVAMENTE devem persuadir/inspirar para a visao do futuro — afirmar que isso 'compete ao gerenciamento' contraria a teoria (incorreto). Apenas I e III."}, {"id": "1299388", "d": "psicologia", "a": ["Psicopatologia do Trabalho", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Dejours (1992), a psicopatologia do trabalho\nesteve em estado embrionário durante muitas décadas,\napesar de existirem alguns trabalhos importantes dos anos\n1950. Houve uma lentidão da psicopatologia do trabalho\nem conquistar seu lugar de distinção no que tange ao\nafrontamento do homem com sua tarefa e com os perigos\nexistentes para sua vida mental ao realizá-la. Considerando\nessas informações, julgue os próximos itens.      \nI. Se a psicopatologia do trabalho não foi mais estudada,\né porque as condições para seu crescimento ainda não\nestavam reunidas, ao contrário do que acontece agora.\n  II. O campo potencial da psicopatologia do trabalho é\nocupado pela psicanálise, pela psicossociologia e pela\npsicologia abstrata. Contudo, essas disciplinas, além de\nnão conseguirem dar conta da unicidade do drama\nexistencial vivido pelos trabalhadores, fornecem um\nquadro de referências teóricas e conceituais que\nperturbam a elaboração de concepções diferentes.  \nIII. Para se compreender a evolução das condições de vida\ne de trabalho e, portanto, de saúde dos trabalhadores,\né necessário dissociar tal conjuntura do histórico de\ndesenvolvimento das lutas e das reivindicações\noperárias em geral.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos", "E": "Todos os itens estão certos."}, "g": "C", "j": "Dejours (1992) — psicopatologia do trabalho: I — condicoes historicas para o crescimento da psicopatologia do trabalho nao estavam reunidas anteriormente (correto); II — campo ocupado por psicanalise, psicossociologia e psicologia abstrata, cujos quadros teoricos perturbam concepcoes diferentes (correto). Item III inverte: para compreender saude dos trabalhadores e necessario ASSOCIAR (nao dissociar) o historico das lutas e reivindicacoes operarias — incorreto. Apenas I e II."}, {"id": "1299386", "d": "psicologia", "a": ["Qualidade de Vida", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Bergamini e Coda (1997), os fatores de satisfação\ne de contrassatisfação endógenos são providos por fontes\nintrínsecas e estão relacionados com o processo cognitivo,\nque inclui consciência e julgamento. Com relação aos\nexemplos de fatores de satisfação e de contrassatisfação,\nassinale a alternativa incorreta.", "alt": {"A": "Decisões e julgamentos feitos pela própria pessoa, via\nprocessos cognitivos e por meio do próprio intelecto,\npodem ser fatores de contrassatisfação, enquanto\ndecisões e julgamentos pobres podem ser fatores de\nsatisfação.", "B": "Coragem, resistência, autocontrole, exercício da\nprópria vontade etc., via processos cognitivos e por\nmeio do próprio intelecto da pessoa, podem ser\nfatores de satisfação, enquanto a falta de tais fatores\npode ser fator de contrassatisfação.", "C": "A resolução de problemas, via processos cognitivos e\npor meio do próprio intelecto, pode ser um fator de\nsatisfação, enquanto a inabilidade em resolver\nproblemas pode ser fator de contrassatisfação.", "D": "A hostilidade, a raiva etc., quando não causadas por\nfatores extrínsecos, mas oriundas de processos\ncognitivos do próprio intelecto, podem ser\nconsideradas como fator de satisfação ou de\ncontrassatisfação.", "E": "Honestidade, integridade, compaixão, amor, caridade\netc., via processos cognitivos e por meio do próprio\nintelecto, podem ser fatores de satisfação ou de\ncontrassatisfação, assim como seus opostos também\npodem ser fatores de satisfação ou de\ncontrassatisfação, dependendo das preferências do\nindivíduo."}, "g": "A", "j": "Bergamini & Coda (1997) sobre fatores endogenos: a alternativa A INVERTE — decisoes/julgamentos PROPRIOS sao tipicamente fatores de SATISFACAO; decisoes POBRES, fatores de CONTRASSATISFACAO. O enunciado da A apresenta a relacao invertida, tornando-a a incorreta. B (coragem/autocontrole), C (resolucao de problemas), D (hostilidade/raiva intrinseca) e E (valores morais) reproduzem corretamente os exemplos endogenos."}, {"id": "1299385", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Zanelli, Borges-Andrade e Bastos (2004), o tema\nsocialização organizacional insere-se no campo de estudo\nda psicologia organizacional e do trabalho, mas também\nconsiste em um conceito da psicologia social. Quanto à\ndefinição de socialização, julgue os itens que se seguem.\n      I. Socialização é um processo em que o ponto de partida\né a maneira como um indivíduo se torna membro de\num grupo, uma organização ou uma sociedade,\nentendendo que o indivíduo socializado é o sujeito ou\no personagem principal desse processo.  \nII. Em uma perspectiva funcionalista, socialização é um\nprocesso de manutenção e reprodução da estrutura\nsocial, em um movimento de homogeneização.  \nIII. Em uma perspectiva a partir do interacionismo\nsimbólico, a socialização compreende que os indivíduos\nsão sujeitos do processo no qual desenvolvem sua\nprópria personalidade e, ao mesmo tempo,\napropriam-se dos costumes e dos valores sociais em\ninteração com o contexto sócio-histórico em que se\ninserem, por intermédio do convívio, em vários grupos\nsociais.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Zanelli, Borges-Andrade & Bastos (2004) sobre socializacao organizacional: I — individuo socializado como sujeito do processo de tornar-se membro (correto); II — perspectiva funcionalista vê socializacao como manutencao/reproducao da estrutura, homogeneizacao (correto); III — interacionismo simbolico ve sujeitos do processo, apropriando-se de costumes/valores em interacao com contexto socio-historico (correto). Todos certos."}, {"id": "1299384", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Bastos e Gondim (2010), desde as últimas\ndécadas do século XX, se assiste a uma crescente atenção à\nsaúde/doença entre os trabalhadores, associada às\ntransformações no cenário mundial e a suas expressões no\nmundo do trabalho. Com base nessa informação, julgue os\nitens subsequentes.\n      I. Segundo estimativa da Organização Mundial de Saúde,\nos chamados transtornos mentais menores acometem\ncerca de 30% dos trabalhadores ocupados e os\ntranstornos mentais graves, cerca de 5 a 10%.\n  II. Estudos e pesquisas, cada vez mais frequentes sobre o\ntema, indicam que são comuns as explicações sobre a\netiologia do adoecimento psíquico, baseadas no\ncotidiano do trabalho, sem considerar a genética e(ou)\nas relações familiares.  \nIII. Paulatinamente, a implicação do trabalho no processo\nde saúde/doença psíquica vem sendo incorporada pelo\nimaginário social, em especial por meio da associação\nentre trabalho e estresse. Sendo assim, o senso comum\ntende a tratar o assunto ainda de uma forma dualista,\nem que o trabalho está implicado ou só na promoção\nde saúde ou só na promoção da doença.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item IIII está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Bastos & Gondim (2010) sobre saude/doenca no trabalho: I — estimativa OMS de transtornos mentais menores em ~30% e graves em 5-10% (correto); III — imaginario social associa trabalho e estresse, senso comum tende a dualismo (correto). Item II inverte a critica dos autores — explicacoes monocausais (apenas trabalho, ignorando genetica/familia) sao limitacoes a serem superadas, nao algo a celebrar — incorreto. Apenas I e III."}, {"id": "1299378", "d": "psicologia", "a": ["Recrutamento e Seleção", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Schein (1982), as organizações são conjuntos\nordenados de atividades humanas que só passam a\nfuncionar depois que as pessoas forem recrutadas para\nocupar determinados papéis e executar determinadas\natividades. A respeito de recrutamento e seleção, julgue os\nitens que se seguem.    \n    I. Se as necessidades da organização, assim como as\nnecessidades dos membros (que ingressam por meio\nde recrutamento e seleção), mudam com o tempo,\nentão torna-se complexo manter ambas as\nexpectativas em sintonia, apesar de ser possível.  \nII. Uma política de recrutamento e seleção com vistas a\nobter das pessoas o melhor desempenho não assegura\nautomaticamente que, de fato, serão satisfeitas as\nnecessidades e expectativas individuais inerentes às\npessoas que estão ingressando na organização.\n  III. As soluções às demandas internas (que o recrutamento\ne a seleção satisfazem), que se aplicam a um ponto da\nhistória da organização, podem iniludivelmente ser\naplicáveis em outro ponto, visto que as interações\nindivíduo-organização se encontram em uma\nininterrupta replicação.\n      Assinale a alternativa correta", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Schein (1982) sobre R&S: I — necessidades de organizacao e membros mudam, dificultando manter sintonia (correto); II — boa politica de R&S nao assegura automaticamente satisfacao das expectativas individuais (correto). Item III contraria Schein — solucoes historicamente situadas NAO sao iniludivelmente aplicaveis a outros pontos historicos; interacoes individuo-organizacao mudam (incorreto). Apenas I e II."}, {"id": "1299376", "d": "psicologia", "a": ["Motivação", "Liderança", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "A partir da reflexão de Bergamini e Coda (1997) sobre a\nrelação entre liderança e motivação, julgue os itens\nsubsequentes.      \nI. É possível se cogitar que motivação e liderança estejam\ndentro de um mesmo contínuo, embora não sejam\nexatamente sinônimos. São parentes próximos que\npossuem laços em comum.\n  II. Tanto a motivação quanto a liderança sofreram um\nduro impacto vindo das opiniões e crenças populares.\nAdministradores formados pela prática do dia a dia\nousaram tecer suas próprias teorias e conceitos leigos\nsobre liderança.\n  III. A maior parte das empresas no Brasil tem procurado ir\nem direção ao desenvolvimento de pesquisas\nrealizadas no âmbito da ciência pelo fato de estarem\nconvencidas de que os problemas relacionados à\nliderança e à motivação não podem apenas se bastar\nno pragmatismo.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Bergamini & Coda (1997) sobre lideranca e motivacao: I — lideranca e motivacao em continuum, parentes proximos sem serem sinonimos (correto); II — opinioes e crencas populares e teorizacao leiga de administradores impactaram o campo (correto). Item III contraria os autores — empresas brasileiras nao tem, em sua maioria, buscado pesquisas cientificas para problemas de lideranca/motivacao; predomina o pragmatismo (incorreto). Apenas I e II."}, {"id": "1299375", "d": "psicologia", "a": ["Psicopatologia", "Psicossomática"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Limongi-França (2008), para se explicar a\nabordagem psicossocial no processo psicossomático em\norganizações, a psicologia social possui o auxílio de ciências\ncorrelatas, tais como a medicina psicossomática, a\nergonomia e a antropologia social. Com base nessa\ninformação, julgue os itens que se seguem.      \nI. Todas as pessoas se manifestam de maneira\npsicossomática, pois têm potencialidades e reações\nbiológicas, psicológicas e sociais que respondem\nsimultaneamente às condições de vida.\n  II. O conceito biopsicossocial origina-se da medicina\npsicossomática, que propõe uma visão integrada do ser\nhumano.  \nIII. No ambiente do trabalho, a abordagem biopsicossocial\ndá suporte a uma atitude ética nas exigências da\ncondição humana. A atitude ética deve ocorrer desde a\nidentificação, a eliminação, a neutralização ou o\ncontrole dos riscos ocupacionais no ambiente físico.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Limongi-Franca (2008) — abordagem biopsicossocial: I — todas pessoas se manifestam de maneira psicossomatica (correto); II — conceito biopsicossocial origina-se da medicina psicossomatica com visao integrada (correto, cf. Engel); III — no trabalho, biopsicossocial fundamenta atitude etica desde identificacao a controle de riscos ocupacionais (correto). Todos os itens corretos."}, {"id": "1299372", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Chanlat (1996), o saber no domínio do\n“comportamento organizacional” desenvolveu-se, antes de\nmais nada, com o desejo e a vontade de melhorar a\nprodutividade e a satisfação no trabalho, enfatizando uma\nnítida influência das categorias econômicas e,\nconsequentemente, desenvolvendo uma concepção de ser\nhumano no trabalho. No que se refere a esse assunto,\njulgue os próximos itens.\n      I. A contaminação das categorias econômicas teve como\nefeito conceber o ser humano de forma isolada, visto\nque desembocou em perspectivas mecânicas,\ninstrumentais, elitistas e utilitaristas como se a\norganização fosse um conjunto fechado e\nautossuficiente.\n  II. A contaminação das categorias econômicas teve como\nefeito centrar o objeto de estudo unicamente no bom\ndesempenho, o que simplifica em demasia a\nespecificidade do ser humano e de suas dimensões\nfundamentais, resumindo sua experiência\norganizacional e ignorando o mundo próprio do\nhomem e o conjunto de conhecimentos existentes\nsobre o ser humano a partir de outras disciplinas.\n  III. A contaminação das categorias econômicas teve como\nefeito a fragmentação do comportamento\norganizacional em partes distintas, tais como biologia,\npsicologia, psicologia social, psicanálise, sociologia etc.,\ncomo se ele não fosse, em sua essência, uno. Ele é\núnico enquanto espécie. Ele o é igualmente enquanto\nindivíduo. E assim deveria ser compreendido pela\ndiversidade das disciplinas que o estudam.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.Apenas os itens I e II estão certos.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Chanlat (1996) — comportamento organizacional: I — contaminacao economica concebeu ser humano de forma isolada, mecanica, utilitarista (correto); II — centrou objeto no desempenho, simplificando o humano e ignorando outras disciplinas (correto); III — fragmentacao do comportamento organizacional em multiplas disciplinas, embora ele seja uno como especie e como individuo (correto). Todos os itens reproduzem a critica de Chanlat. Gabarito E."}, {"id": "1299366", "d": "psicologia", "a": ["Liderança", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "A partir da reflexão de Bergamini e Coda (1997) sobre\nliderança, julgue os seguintes itens.\n      I. Ninguém poderá ser eficaz como líder se não entender\nque, antes de mais nada, cada um vê no próprio\ntrabalho a oportunidade de realizar suas próprias\npotencialidades, buscando conseguir uma\nindispensável ligação com a comunidade em sentido\nmais amplo.  \nII. Após toda a evolução das concepções sobre liderança,\ncontinuar apegado ao conceito de controle como\nsinônimo de liderança é, no mínimo, sinal de falta de\nrecursos intelectuais para analisar aquilo que acontece,\ne também, o que é mais grave para o administrador,\nfalta de estabilidade emocional, o que entorpece a\nacuidade do sentir e do perscrutar a respeito daquilo\nque seus possíveis seguidores esperam dele.  \nIII. Cada ser humano deve ser considerado como capaz de\ncorrigir o curso das suas ações quando elas não o\nconduzem para o resultado almejado. Segundo essa\nconcepção, por meio do trabalho (considerado como\numa necessidade típica do homem), cada ser humano\nrecebe aquilo que mais lhe importa, o reconhecimento\ndo próprio valor; com isso, ele consegue chegar ao\nnível de estima que tem por si mesmo.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Bergamini & Coda (1997) sobre lideranca: I — eficacia do lider passa por entender que cada um busca realizar potencialidades no trabalho e ligar-se a comunidade (correto); II — apego ao controle como sinonimo de lideranca denota falta de recursos intelectuais/estabilidade emocional (correto); III — ser humano capaz de corrigir suas acoes; o reconhecimento do proprio valor via trabalho fundamenta a autoestima (correto). Todos certos."}, {"id": "1299363", "d": "psicologia", "a": ["Psicologia Social", "História da Psicologia", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "A origem da psicologia social remonta ao século XIX e dois\nautores têm muita importância em sua construção. Um\ndeles, na Alemanha, dividiu a psicologia em duas vertentes\n(uma delas referia-se à psicologia dos povos) e o outro,\nfrancês, promoveu a primeira discussão sobre psicologia\ndas massas. Esses autores são:", "alt": {"A": "Kurt Lewin e Willian McDougall.", "B": "Floyd Henry Allport e Serge Moscovici.", "C": "Fritz Heider e Solomon Asch.", "D": "Sigmund Freud e Gabriel Tarde.", "E": "Wilhelm Wundt e Gustave Le Bon."}, "g": "E", "j": "Origem da psicologia social no seculo XIX: na Alemanha, WILHELM WUNDT dividiu a psicologia em individual (experimental) e social (Volkerpsychologie/psicologia dos povos). Na Franca, GUSTAVE LE BON promoveu a primeira discussao sobre psicologia das massas (Psychologie des foules, 1895). Alternativa E correta."}, {"id": "1299362", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "A partir da compreensão da subjetividade sob a perspectiva\nfreudiana e da teoria crítica de T. Adorno e da concepção\nde indústria cultural, a autora (Ângela Caniato In: A\nconstituição do sujeito e a historicidade) defende a revisão\nna psicanálise e na clínica, considerando os rumos que a\nsociedade tem tomado nos últimos tempos, com a\nexacerbação do consumo e um verdadeiro bombardeio da\nindústria cultural, que apoia esta ideologia, que é cada vez\nmais destrutiva ao indivíduo. Quanto a esse assunto,\nassinale a alternativa correta.", "alt": {"A": "É correto afirmar que a psicanálise não tem os\ninstrumentos necessários para uma análise psicossocial\nconsistente.", "B": "A psicanálise, desde os seus primórdios, se dispôs a\numa análise psicossocial e autores como Adorno, com\nsua teoria crítica, potencializaram esse conhecimento,\nproduzindo importante análise sobre a indústria\ncultural.", "C": "O sofrimento na contemporaneidade é bastante\ndiscutido no campo da psicanálise, mas não se aplica\naos estudos da psicologia social.", "D": "A exacerbação do consumo deve ser estudada, pela\npsicanálise, como forma de combater a indústria\ncultural que aniquila os indivíduos.", "E": "Ângela Caniato perde a ortodoxia freudiana ao\nrelacionar a sociologia de Theodor Adorno com a\npsicanálise."}, "g": "B", "j": "Angela Caniato articula Freud com Adorno (teoria critica/Escola de Frankfurt): a psicanalise, desde seus primordios (Mal-Estar na Civilizacao, Psicologia das Massas), dispos-se a analise psicossocial; Adorno potencializou esse conhecimento com a teoria critica e a analise da industria cultural. Alternativa B reproduz a tese da autora. A (psicanalise sem instrumentos), C (sofrimento so na psicanalise), D (somente combate ao consumo) e E (perda da ortodoxia) distorcem o argumento."}, {"id": "1299361", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Em Trabalho e Solidariedade, Furtado fala da relação entre\no mundo do trabalho e as dimensões subjetivas da\nrealidade. Com essa categoria, o autor", "alt": {"A": "quer dizer que o emprego, como expressão atual das\nrelações de trabalho, cada vez mais depende da\nsubjetividade do trabalhador.", "B": "quer dizer que as formas, como a subjetividade, são\ncontroladas pela realidade, apontando para o aumento\nda depressão como principal sintoma do adoecimento\nlaboral.", "C": "infere que a saúde do trabalhador ficou mais\ncomprometida com o advento do toyotismo, uma vez\nque essa forma de administração das relações de\ntrabalho se apropria da subjetividade dos\ntrabalhadores.", "D": "entende a dimensão subjetiva da realidade como o\nconjunto de crenças e valores historicamente definidos\ne que servem de repertório, estabelecido como\nreferência subjetiva, para os sujeitos.", "E": "quer dizer que a dimensão subjetiva da realidade diz\nrespeito às medidas possíveis por meio dos\ninstrumentos de avaliação psicológica, muito utilizados\nnas organizações."}, "g": "D", "j": "Furtado (Trabalho e Solidariedade) define dimensao subjetiva da realidade como CONJUNTO DE CRENCAS E VALORES HISTORICAMENTE DEFINIDOS que servem de repertorio/referencia subjetiva para os sujeitos. Alternativa D reproduz a categoria do autor (cf. Furtado & Svartman, perspectiva da psicologia socio-historica). A, B, C e E desviam para outras leituras (emprego, controle pela realidade, toyotismo, instrumentos de avaliacao)."}, {"id": "1299360", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2020", "org": "CFP", "t": "", "e": "A grande cantora brasileira Elza Soares, um ícone da MPB,\ncanta uma música composta por Seu Jorge cujo refrão diz:\n“A carne mais barata do mercado é a carne negra”. A letra", "alt": {"A": "aponta para o racismo, a discriminação e a segregação\nda pessoa negra, fazendo referência ao período\nescravagista no qual se mercantilizava o corpo negro e\natualizando para a situação atual com, entre outros,\nreferência à morte de jovens negros nas periferias das\ngrandes cidades.", "B": "aponta para uma metáfora que expõe a relação entre a\ncarne de má qualidade e o fato de a cor negra ser um\nsignificante polissêmico que permite formular uma\ncrítica ao consumo alienado.", "C": "denota que a disparada do preço da carne no Brasil\nexige das pessoas mais pobres estratégias defensivas\nque muitas vezes comprometem a própria saúde.", "D": "refere-se ao fenômeno da prostituição e à forma como\nmuitas mulheres, particularmente mulheres pobres e\nnegras, são compulsoriamente levadas a comercializar\nseus corpos para garantir a sobrevivência.", "E": "acaba incorrendo em um deslize que pode ser\ncompreendido como racismo estrutural ao relacionar o\nsignificante carne à cor negra."}, "g": "A", "j": "'A carne mais barata do mercado e a carne negra' (Seu Jorge/Elza Soares) e leitura politico-psicossocial da mercantilizacao do corpo negro: do passado escravagista a atualizacao na morte de jovens negros nas periferias. Alternativa A captura essa critica do racismo estrutural. Demais alternativas distorcem (B — critica ao consumo; C — disparada do preco; D — prostituicao; E — leitura como racismo no compositor)."}, {"id": "1299359", "d": "psicologia", "a": ["Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Psicologia Jurídica", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "A violência estrutural, que impede a satisfação das\nnecessidades básicas da maioria, não se reduz à\ndistribuição inadequada dos recursos disponíveis; além\ndisso, a violência estrutural exige o ordenamento da\ndesigualdade opressiva por meio de uma legislação que\nampara os mecanismos de distribuição social da riqueza e\nque produz uma força coercitiva que obriga a maioria\nrespeitar tais mecanismos. Posto que a ordem social é\nproduto e reflexo do domínio de uma classe social sobre as\noutras, a conclusão mais importante é também a mais\nóbvia: a violência está presente na própria ordem social e,\nportanto, não é arbitrário falar de violência estrutural.\nA citação de Ignácio Martín-Baró acima, extraída de Martins\n& Lacerda Jr (2014), significa que o(a)", "alt": {"A": "violência somente poderá ser combatida se houver\ndistribuição adequada dos recursos.", "B": "violência estrutural emana do Estado e a própria\nordem social é produto e reflexo do domínio em uma\nsociedade de classes.", "C": "texto citado é datado e refere-se a conflitos específicos\nde guerra civil em que a violência era banalizada.", "D": "psicólogo social tem pouco a fazer nessas\ncircunstâncias, por se tratar de fenômeno\nessencialmente político e de ordem social.", "E": "a questão estrutural depende da organização social e\neconômica e a violência mencionada muitas vezes é da\nordem do próprio controle da população mais pobre,\nque não respeita a ordem constituída."}, "g": "B", "j": "Martin-Baro (apud Martins & Lacerda Jr, 2014): a violencia estrutural emana do Estado, com legislacao que ampara a distribuicao desigual; a ordem social e produto e reflexo do dominio de uma classe sobre outras. Alternativa B reproduz a tese. As demais reducem ou negam (A — so distribuicao; C — texto datado; D — psicologo impotente; E — controle da pobreza)."}, {"id": "1299358", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2020", "org": "CFP", "t": "", "e": "Em publicação da ABRAPSO DE 2015, Sônia Grubits\napresentou um importante resultado de pesquisa sobre\npopulações indígenas do Mato Grosso do Sul.\nRecentemente, o conflito entre fazendeiros e os\nGuarani/Kaiowá, Kadiwéu e Terena recrudesceu e vários\nindígenas foram assassinados. A psicologia do indígena vem\ncrescendo de importância e representa uma novidade nas\npesquisas e nos estudos em psicologia social, apesar de um\nconsiderável atraso sobre uma questão de suma\nimportância para a proteção e garantia de vida dos povos\nindígenas radicados no Brasil.    \nA partir do texto acima, assinale a alternativa correta.", "alt": {"A": "O conflito entre fazendeiros e indígenas, não somente\nno Centro-Oeste brasileiro, mas também em toda a\nregião Norte, é fruto das características do\ndesenvolvimento brasileiro e a política equivocada de\nproteção às populações indígenas, que deveriam ser\nincluídas na política de desenvolvimento sustentável, é\na principal causa desse conflito.", "B": "Os conflitos que envolvem as populações indígenas e\nas várias violências a estas impostas são um\nimportante objeto de estudo e atuação da psicologia\nsocial, que deve ser aprofundado para contribuir na\nsuperação da quebra de direitos desses povos.", "C": "A psicologia não pode contribuir com a causa indígena\npor se tratar de um conhecimento produzido a partir\nda cultura judaico-cristã e ser incompatível com os\nvalores e as crenças dos povos indígenas, que têm uma\noutra referência simbólica do mundo.", "D": "O atraso mencionado na premissa é relativo à\ndificuldade de contato de psicólogos com um tipo de\nlinguagem que eles desconhecem, o que,\nevidentemente, é um forte obstáculo para a\npsicoterapia, que depende fundamentalmente da\npalavra.", "E": "O Mato Grosso do Sul, pelas extensas áreas cultiváveis\nou destinadas à produção pecuária, é um estado que\nnão se adequa à política protecionista de reserva\nindígena, o que torna este o principal fator de conflito\nentre indígenas e fazendeiros."}, "g": "B", "j": "Sonia Grubits (ABRAPSO, 2015): os conflitos envolvendo Guarani/Kaiowa, Kadiweu e Terena e as violencias contra povos indigenas devem ser objeto de estudo e atuacao da psicologia social, para superar a quebra de direitos. Alternativa B reproduz a tese da autora. A culpa indigenas/desenvolvimento; C nega contribuicao da psicologia; D reduz a barreira linguistica; E culpa as reservas."}, {"id": "1299357", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Sandra Jovchelovich, pesquisadora brasileira radicada na\nLondon School of Economics and Political Science, aponta\nque não há uma relação direta, uma correspondência\nperfeita entre o ser humano e o mundo. O objeto-mundo\nsomente se torna um conhecido se não se der o trabalho de\nrepresentá-lo. Faz parte, tanto da história humana\nontogenética como da filogenética, dar-se esse trabalho: é\num trabalho que leva tempo e é um trabalho duro, que\nenvolve um processo intenso e apaixonado de\ncoconstrução entre infante, aquele que lhe presta cuidados\ne o objeto-mundo (DUVEEN, 1997, 2001; VALSINER, 2000).\nAssinale a alternativa correta.\n    Tendo o texto acima como referência inicial, assinale a\nalternativa correta.", "alt": {"A": "A autora cita Valsiner por seu vínculo com a linha\nvygotskyana da psicologia histórico-cultural.", "B": "O objeto-mundo mencionado pela autora representa\num retorno à visão kantiana de estudo sobre o\nconhecimento, principalmente no que concerne à\nrazão como critério central para a conduta humana.", "C": "O objeto-mundo somente pode ser entendido como\nreflexo, como apontado por Gyorg Lukács em A\nOntologia do Ser Social.", "D": "Assim como Moscovici, Jovchelovich inspira-se na visão\nde Émile Durkheim sobre o conceito de representação,\nprincipalmente quando se trata da representação de\nmundo para o sujeito.", "E": "A autora discute a relação fundamental entre processo\nrepresentacional e contexto, entendido como o lugar\nhistórico, social, simbólico e cultural de uma\ncomunidade humana."}, "g": "E", "j": "Jovchelovitch discute a relacao fundamental entre processo representacional e CONTEXTO (historico, social, simbolico e cultural de uma comunidade), articulando representacoes sociais com situacao concreta. Alternativa E captura essa tese central. A (Valsiner como vygotskyano) e leitura forcada; B (Kant), C (Lukacs reflexo) e D (Durkheim como em Moscovici) extrapolam o argumento da autora."}, {"id": "1299356", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Silvia Lane e Wanderley Codo organizaram o livro Psicologia\nSocial: o homem em movimento retratando o estado da\narte da nova psicologia social no Brasil na década de 1980 e\no livro tornou-se uma referência válida até os dias de hoje.\nQual das alternativas abaixo está correta?", "alt": {"A": "A partir da influência exercida pela leitura do livro e\npor seu uso na graduação em psicologia, a pesquisa\nqualitativa passou a ser a única referência para a\npesquisa em psicologia social.", "B": "A psicologia social comunitária passou a ser o conteúdo\ncentral dos estudos e das pesquisas realizadas no\ncampo da psicologia social.", "C": "Categorias como consciência, atividade e identidade,\nmencionadas por Silvia Lane e, fundamentalmente, a\nlinguagem passaram a ser discutidas intensamente\ndepois do lançamento dessa obra.", "D": "O autor de referência para a psicologia social no Brasil\npassa a ser o francês da linha da análise do discurso,\nMichel Pêcheux.", "E": "A psicologia cognitivista, antes dominante na formação\nacadêmica em psicologia social, caiu em desuso."}, "g": "C", "j": "Lane & Codo (Psicologia Social: o homem em movimento, 1984) introduzem como referencial as categorias CONSCIENCIA, ATIVIDADE, IDENTIDADE e LINGUAGEM como temas centrais da nova psicologia social brasileira. Alternativa C reproduz essa contribuicao. A (so qualitativa), B (so comunitaria), D (Pecheux como referencia) e E (cognitivista em desuso) sao generalizacoes ou inversoes."}, {"id": "1299355", "d": "psicologia", "a": ["Grupos nas Organizações", "Intervenção Psicossocial", "Psicologia e Organizações", "Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere às estratégias de intervenção institucional,\njulgue os itens que se seguem.    \nI. Há um consenso na literatura de que as estratégias de\nintervenção institucional devem contribuir para a\nconstituição dos grupos sujeitos nas organizações, em\ndetrimento dos grupos sujeitados.\n  II. Para René Lourau, a análise institucional deve priorizar\no ponto de vista da hierarquia das organizações.  \nIII. Lapassade considerava a intervenção institucional\ncomo estratégia disruptiva que prejudicaria a relação\nentre os diferentes grupos na organização.\n    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e III estão certos."}, "g": "B", "j": "Analise institucional (Lourau, Lapassade): I — estrategias de intervencao devem favorecer GRUPOS SUJEITOS em detrimento dos sujeitados (correto). Item II inverte Lourau, que critica e desnaturaliza a hierarquia — nao a prioriza (incorreto). Item III contraria Lapassade, que ve a intervencao disruptiva como produtiva (analisadores) para revelar contradicoes — nao como prejudicial (incorreto). Apenas I."}, {"id": "1299354", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação às várias vertentes teóricas da psicologia\nsocial, assinale a alternativa incorreta.", "alt": {"A": "A psicologia sócio-histórica está baseada na produção\ndo autor russo Lev Vygotsky.", "B": "A psicanálise está presente na psicologia social, na\ndiscussão sobre cultura.", "C": "A psicologia social de cunho cognitivista estuda\nfenômenos como as atitudes e a dissonância cognitiva.", "D": "A vertente construcionista em psicologia social é\nfortemente influenciada por Jean Piaget.", "E": "A teoria das representações sociais tem origem em\numa pesquisa realizada por Serge Moscovici sobre a\nrepresentação da psicanálise entre os franceses."}, "g": "D", "j": "Vertentes da psicologia social: A (socio-historica = Vygotsky), B (psicanalise na cultura), C (cognitivista = atitudes/dissonancia) e E (Moscovici = representacao da psicanalise na Franca) sao corretas. Alternativa D e incorreta: a vertente CONSTRUCIONISTA (Gergen, Spink, Iniguez) e influenciada por Vygotsky, Bakhtin, Foucault, NAO por Piaget — Piaget e referencia do construtivismo, nao do construcionismo social."}, {"id": "1299353", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Um grupo de pessoas desempregadas há mais de\ndois anos se reúne para discutir estratégias sugeridas pelo\npadre de uma paróquia de um bairro de periferia de uma\ncidade de médio porte para produção de renda. Analisando\nas alternativas apresentadas por uma psicóloga social, que\ncolabora com a paróquia, decidem iniciar um\nempreendimento conjunto de produção de alimentos para\natender ao público interessado: cantina da escola; festas de\naniversário; coffee break de eventos; e outros. As tarefas\nsão compartilhadas e o lucro dividido entre os\nparticipantes.\n    Com base nesse caso hipotético, é correto afirmar que se\ntrata de", "alt": {"A": "constituição de startups.", "B": "cooperativa popular de economia solidária.", "C": "empreendedorismos via SEBRAE.", "D": "programa de evangelização católica.", "E": "planejamento e desenvolvimento de networking."}, "g": "B", "j": "O caso descrito (grupo de desempregados, tarefas compartilhadas, lucro dividido, producao de alimentos por interesse coletivo) e tipico de COOPERATIVA POPULAR DE ECONOMIA SOLIDARIA (Singer, Gaiger). Demais alternativas (A — startups, C — SEBRAE/empreendedorismo, D — evangelizacao, E — networking) nao capturam o carater associativo, autogestionario e popular do empreendimento."}, {"id": "1299352", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Padre Jesuíta, foi vice-reitor da Universidad\nCentroamericana José Simeón Cañas, de El Salvador, e\nassassinado por forças paramilitares durante a guerra civil,\nem El Salvador, em 1989. É considerado como o principal\nnome e criador da psicología de la liberación. Trata-se de", "alt": {"A": "Fernando González Rey.", "B": "Amálio Blanco.", "C": "Enrique Dussel.", "D": "Augusto Salazar Bondy.", "E": "Ignácio Martín-Baró."}, "g": "E", "j": "IGNACIO MARTIN-BARO (1942-1989): padre jesuita, vice-reitor da Universidade Centro-Americana Jose Simeon Canas (UCA), em El Salvador, assassinado por forcas paramilitares em 16/11/1989. Criador da Psicologia da Libertacao. Alternativa E correta. Demais (Gonzalez Rey, Blanco, Dussel, Salazar Bondy) sao autores latino-americanos relevantes, mas nao se ajustam a descricao."}, {"id": "1299351", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Mary Jane Spink e Peter K. Spink são pesquisadores,\nradicados no Brasil, com vasta publicação em psicologia\nsocial, e, a partir da vertente construcionista, apresentam\num referencial metodológico que define um excelente\ninstrumento de observação e análise do material de campo.\nEsse instrumento é o(a)", "alt": {"A": "campo-tema.", "B": "teoria do ator-rede.", "C": "pesquisa qualitativa.", "D": "epistemologia do sujeito.", "E": "condicionamento operativo."}, "g": "A", "j": "Mary Jane Spink & Peter K. Spink, na perspectiva CONSTRUCIONISTA, propoem o CAMPO-TEMA como referencial metodologico para observacao/analise do material de campo (Spink, M.J., 2003). Alternativa A correta. B (ator-rede e de Latour), C (pesquisa qualitativa e generica), D (epistemologia do sujeito), E (condicionamento operativo de Pichon-Riviere) nao sao a contribuicao especifica dos Spink."}, {"id": "1299350", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "O desastre ambiental de Mariana e de Brumadinho, com o\nrompimento de barragens de contenção de rejeitos da\nmineração, representou uma tragédia que atingiu a\npopulação de várias cidades, com consequências\ninimagináveis. Psicólogos foram deslocados para as regiões\natingidas e vários acompanham até hoje essa população.\nEstes profissionais da psicologia podem ser enquadrados na\nmodalidade da psicologia social denominada psicologia", "alt": {"A": "das organizações e do trabalho.", "B": "social comunitária.", "C": "social cognitivista.", "D": "das emergências e dos desastres.", "E": "sócio-histórica."}, "g": "D", "j": "Desastres ambientais como Mariana (2015) e Brumadinho (2019) sao objeto da PSICOLOGIA DAS EMERGENCIAS E DOS DESASTRES (referencias CREPOP/CFP). Alternativa D correta. As demais sao especialidades distintas (organizacoes, comunitaria, cognitivista, socio-historica) — embora todas possam contribuir, a modalidade especifica para atuacao pos-desastre e a referida em D."}, {"id": "1299349", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Crescem os estudos no campo da psicologia social sobre\nhomens autores de atos de violência contra as mulheres.\nTais estudos apontam para a compreensão ampla e social\ndesse problema, evitando personalizar a queixa e\nculpabilizar o autor da violência como um caso isolado.\nAssim, para reverter essa condição, vem crescendo o\nnúmero de centros de apoio ao autor de ato de violência, e\numa estratégia é o grupo no qual circula a fala dos\nagressores. Evidentemente, o apoio não desresponsabiliza\no autor da violência, mas sua participação nos grupos pode\nretirá-lo do lugar de agressor quando ele compreende a\ncondição feminina e os direitos da mulher. O grupo permite\no reconhecimento da violência como ato criminoso e\ncondenável e a busca do diálogo como a melhor alternativa\npara o enfrentamento das diferenças.\n    Tendo o texto acima como referência inicial, assinale a\nalternativa correta.", "alt": {"A": "A premissa dessa questão está fora da realidade e\nhomens violentos não devem receber atendimento,\ndevem ser denunciados para a justiça.", "B": "A Delegacia da Mulher deve encaminhar os casos de\nviolência doméstica contra a mulher ao CRAS para\nconciliação entre as partes.", "C": "A premissa da questão está correta e,\nindependentemente do papel exercido pela força\npolicial e pela justiça, o problema é social, devendo\nhaver a atuação da psicologia social nos grupos de\napoio.", "D": "Apesar de correta a premissa, não existe ainda nenhum\nserviço desse porte para o acompanhamento do\nhomem autor de ato de violência contra a mulher.", "E": "O problema apresentado não é relevante socialmente."}, "g": "C", "j": "O texto descreve a atuacao em grupos de apoio a homens autores de violencia contra a mulher como estrategia psicossocial complementar (nao substitutiva) a policia/justica. Alternativa C captura essa compreensao do problema como SOCIAL, com atuacao da psicologia social. As demais negam a premissa (A, E), substituem por conciliacao (B) ou negam a existencia de servicos (D)."}, {"id": "1299348", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "O jornal Folha de São Paulo do dia 29/12/2019 entrevistou\nGuilherme Terreri, que se apresenta como a drag queen\nRita Von Hunty. Segundo a matéria, Guilherme está mais\npara a turma queer, “uma galera que entendeu que o\ngênero é uma construção social”, afirma o entrevistado. A\ntemática LGBT, questão atualmente muito estudada pela\npsicologia social, enfrenta uma de suas últimas barreiras de\ninclusão, representada pelo T da sigla. Alguns consideram\nque a sigla deveria ser LGBTQI+, representando, além das\nlésbicas, dos gays e dos bissexuais, os transexuais, travestis\ne transgêneros, os queers e os intersexuais; o + incluiria a\nassexualidade e a pansexualidade, resumindo uma sigla\ncom doze possibilidades de expressão de gênero e\nsexualidade. Considerando os estudos psicossociais sobre\nesse fenômeno, assinale a alternativa correta.", "alt": {"A": "O movimento LGBT ganhou expressão a partir de lutas\ncontra a discriminação e o preconceito e suas\nconquistas permitiram uma maior expressão da\ndiversidade sexual humana, fazendo valer a expressão\ndo entrevistado de que gênero é uma construção\nsocial, mas há muito a ser conquistado e essa é uma\nbatalha que está no seu início.", "B": "Os estudos psicossociais não são conclusivos e não há\ncomprovação científica para a expressão LGBTQI+, que\nrepresenta apenas interesses dos militantes mais\nradicais desse campo.", "C": "Os transexuais, travestis e transgêneros não podem ser\nincluídos na temática homoafetiva, por\ncorresponderem apenas a uma expressão de cunho\ncomportamental.", "D": "Evidentemente, a fala do entrevistado pela FSP\nrepresenta uma realidade, mas pessoas como ele\ndeveriam se expressar em lugares fechados e\nprotegidos para preservar a moral de crianças e\npessoas idosas.", "E": "O preconceito e a discriminação sexual são um câncer\nsocial e a psicologia social deveria assumir claramente\na bandeira LGBTQI+."}, "g": "A", "j": "O movimento LGBT/LGBTQI+ ganhou expressao em lutas contra discriminacao e preconceito; suas conquistas permitiram maior visibilidade da diversidade sexual humana, com genero entendido como construcao social (cf. Butler). Alternativa A reproduz essa compreensao. B nega comprovacao cientifica; C exclui pessoas trans; D defende invisibilizacao; E adota formulacao 'cancer social' (estigma) e patologiza."}, {"id": "1299347", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo social, assinale a alternativa\ncorreta.", "alt": {"A": "Trata-se de profissional de uma vertente teórica da\npsicologia, não havendo espaço para uma atuação\nprática a não ser a docência.", "B": "Os psicólogos brasileiros somente poderão se formar\ncomo psicólogos sociais se buscarem formação na\nArgentina, país que oferece formação específica para\nessa especialidade.", "C": "Esse profissional depende do aval do psicólogo clínico\npara seu desempenho técnico.", "D": "Trata-se de um profissional polivalente,\nconsiderando-se que sua formação universitária é\ngeneralista e que toda a psicologia é social, como\nafirmaram Sílvia Lane e Sigmund Freud.", "E": "O profissional dessa especialidade dificilmente exerce\nsua função no serviço público."}, "g": "D", "j": "O psicologo social tem formacao GENERALISTA/POLIVALENTE; a tese 'toda psicologia e social' e atribuida a Silvia Lane e dialoga com Freud (Psicologia das Massas). Alternativa D captura essa concepcao. A restringe a docencia; B a Argentina; C a aval do clinico; E nega atuacao no servico publico — todas restritivas e incorretas."}, {"id": "1299346", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "O processo intenso de imigração e da busca de refúgio, seja\npor motivos políticos ou para escapar da fome, leva\nmilhares de pessoas, particularmente do continente\nafricano, para a Europa e os EUA. A noção de identidade\ncultural e diáspora, cunhados por Stuart Hall, cabem muito\nbem para se discutir esse fenômeno, atual e importante,\nque também se reflete no Brasil, com o aumento da\nchegada de imigrantes africanos na última década. Na\ncidade de São Paulo, esse fenômeno é visível com a\npresença de imigrantes que vendem tecidos e objetos da\narte africana nas proximidades da praça da República, no\ncentro da cidade.    \nA partir do texto acima, assinale a alternativa correta.", "alt": {"A": "Há muito pouco que a Psicologia Social possa contribuir\ncom esse fenômeno, considerando que se trata de\nquestão econômica mundial estrutural consolidada.", "B": "Muito desse movimento populacional migratório é\nprovocado por interesses locais, conflitos tribais,\ninstabilidade política dos países africanos e uma\nmiséria endêmica da população, impossibilitando uma\npolítica social eficiente.", "C": "A globalização da economia é o fator preponderante da\nbusca de novas oportunidades, que são legítimas do\nponto de vista da solução individual do problema.", "D": "A diáspora mencionada por Hall foi o que destruiu a\nidentidade cultural de negros trazidos à força, como\nmão de obra escrava, para o território americano.", "E": "Segundo Stuart Hall, a alternativa não é se apegar a\nmodelos fechados, unitários e homogêneos de\npertencimento cultural, mas abarcar os processos mais\namplos, o jogo da semelhança e da diferença que está\ntransformando a cultura no mundo inteiro."}, "g": "E", "j": "Stuart Hall (Identidade cultural na pos-modernidade): a identidade cultural na diaspora nao se apega a modelos fechados, unitarios e homogeneos de pertencimento; abrange processos mais amplos, jogo da semelhanca e diferenca em transformacao mundial. Alternativa E reproduz a tese central. A nega contribuicao; B reduz a fatores locais; C destaca so globalizacao; D so destruicao identitaria."}, {"id": "1299345", "d": "psicologia", "a": ["Intervenção Psicossocial", "Políticas Públicas no SUAS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicologia, de uma maneira geral, e a psicologia social,\nem particular, têm, nas políticas públicas, uma alternativa\nde atuação que cresce com o reconhecimento do potencial\nda profissão. Acerca desse tema, julgue os seguintes itens.\n    I. Políticas de inclusão social são importantes para\ngarantir o exercício do direito de cidadania a todos.  \nII. O compromisso ético-político e os estudos sobre a\ndialética inclusão-exclusão são importantes\nferramentas para a intervenção psicossocial nas\ncomunidades.\n  III. A retirada de verbas para as políticas públicas e sociais\nnão afetam, de forma determinante, a cobertura\nnecessária para garantir maior inclusão social.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "C", "j": "Politicas publicas e psicologia: I — politicas de inclusao social sao importantes para cidadania (correto); II — compromisso etico-politico e dialetica inclusao/exclusao (Sawaia) sao ferramentas centrais (correto). Item III nega o impacto da retirada de verbas — contraria evidencias empiricas e diretrizes CREPOP (incorreto). Apenas I e II."}, {"id": "1299344", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Em publicação da ABRAPSO de 2009 – Psicologia social e\npolíticas de existência: fronteiras e conflitos, Pedrinho\nGuareschi aponta que cabe à psicologia (social), por meio\ndo estudo da ideologia, mostrar que, muitas vezes, por\ndetrás das práticas pedagógicas, escondem-se relações de\nautoritarismo, até mesmo de violência, que podem\nreproduzir tais relações no próprio ambiente social. Sugere\nainda que o núcleo central do ensino da psicologia (social)\nseja o estudo da consciência, das representações, do\nmundo imaterial e simbólico, das ideologias, dos sentidos.\nEla tem como tarefa fundamental tentar compreender o ser\nhumano, sua dignidade, a partir da discussão da\nconsciência, da liberdade e da responsabilidade humanas.\nTendo o texto acima como referência inicial, assinale a\nalternativa correta.", "alt": {"A": "Pedrinho Guareschi apresenta uma discussão\nimportante sobre o princípio pedagógico que deve\nreger o ensino da psicologia social e antecipa uma\ndiscussão importante para o momento político\nbrasileiro atual.", "B": "O autor, ao mencionar o mundo imaterial e simbólico,\nescapa da discussão central da psicologia social, que é\nmaterial e concreta por se científica.", "C": "O texto de Guareschi politiza demasiadamente o\nensino da psicologia social e acaba justificando os\nargumentos do movimento Escola Sem Partido.", "D": "Por ser uma disciplina crítica e estável, práticas\npedagógicas que escondem relações de autoritarismo\nnão fazem parte do ensino da psicologia.", "E": "Essa discussão não se aplica ao ensino da psicologia\nsocial."}, "g": "A", "j": "Pedrinho Guareschi (ABRAPSO, 2009 — Psicologia social e politicas de existencia): articula ensino da psicologia social com a critica a ideologia que sustenta praticas pedagogicas autoritarias, propondo nucleo do ensino centrado em consciencia, representacao, simbolico, ideologias. Alternativa A captura a tese. B foge ao argumento; C inverte (Escola Sem Partido); D nega problema; E nega aplicabilidade."}, {"id": "1299343", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca da atuação do psicólogo social, julgue os itens\nsubsequentes.\n    I. O psicólogo social deve atuar frente às demandas\nsociais, de forma a oferecer atendimento psicoterápico\naos participantes de situação de conflito ou desastres\nnaturais.\n  II. O psicólogo social deve manter-se neutro nas situações\nde conflito em que seja chamado a atuar, visando a\nmanter isenta sua capacidade de arbitrar quando\nnecessário.  \nIII. O psicólogo social, no uso de suas atribuições, poderá\natender, por meio de projetos específicos, pessoas,\nfamílias, grupos sociais ou comunidades.     Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Atuacao do psicologo social: III — pode atender, por meio de projetos especificos, pessoas, familias, grupos sociais ou comunidades (correto). I e equivocado — o psicologo social nao oferece psicoterapia tradicional como pratica padrao em situacoes de conflito/desastre; oferece intervencao psicossocial. II contraria o compromisso etico-politico explicito da psicologia social brasileira — neutralidade nao e estrategia. Apenas III."}, {"id": "1299342", "d": "psicologia", "a": ["Psicologia Social", "Movimentos Sociais e de Massa"], "ano": "2020", "org": "CFP", "t": "", "e": "No artigo Movimentos sociais como política, Tilly\nargumenta que, de suas origens no século XVIII em diante,\nos movimentos sociais prosseguiram não apenas como\nperformances isoladas, mas como campanhas interativas.\nAssim como as campanhas eleitorais, as rebeliões\npopulares e as mobilizações religiosas consistem em\ninterações entre grupos reivindicantes temporariamente\nconectados (e cambiantes) e os objetos de suas demandas\ncom terceiros, tais como representantes, aliados,\nreivindicadores rivais, inimigos, autoridades e vários\npúblicos, que muitas vezes exercem papéis significativos no\ndesenrolar da campanha. Nunca se poderá explicar a\nvariação e a mudança nos movimentos sociais se não\nhouver dedicação cuidadosa, atenção aos outros atores\npolíticos, além dos reivindicantes centrais, como, por\nexemplo, a polícia, com a qual os demonstrantes tenham\nlutado, colaborado e desenvolvido suas estratégias. Para\nesse autor, considera-se como um movimento social", "alt": {"A": "a jornada de junho de 2013.", "B": "o movimento de ocupação das escolas secundárias de\n2016.", "C": "o movimento dos Gilets Jaunes, em 2018, na França.", "D": "os protestos, em Hong Kong, em 2019.", "E": "o Movimento dos trabalhadores Sem Terra no Brasil."}, "g": "E", "j": "Charles Tilly (Movimentos Sociais como Politica) define movimento social como CAMPANHA SUSTENTADA AO LONGO DO TEMPO, com reivindicantes coletivos, organizacao, repertorios de acao e interacao continua com autoridades, terceiros, aliados. Entre as opcoes, o MST (Movimento dos Trabalhadores Sem Terra) e o exemplo classico brasileiro de movimento social tilliano, com decadas de campanha. As demais (junho 2013, ocupacao 2016, Gilets Jaunes, Hong Kong) sao protestos ou mobilizacoes de duracao limitada, nao se enquadrando integralmente na definicao de Tilly."}, {"id": "1299341", "d": "psicologia", "a": ["Psicologia do Trabalho", "Análise do Trabalho", "Psicologia e Organizações", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "No artigo Gêneros e os sentidos do trabalho social, Curado\n& Menegon apontam que, a partir dos relatos e da\ndiscussão dos participantes da pesquisa, é possível observar\nque suas estratégias de empoderamento estão mais\nancoradas em laços afetivos (família, amigos, colegas) e, em\nque pese sua positividade, não alteram o valor salarial nem\naumentam o poder político dessa atividade. Ou seja, não se\ntrata de um empoderamento com ampliação de\noportunidades de acesso aos bens e serviços. Ao\ncompreender que as relações de gênero são formas de dar\nsentido às relações de poder, observa-se que a\nnaturalização do feminino no trabalho social está\nrelacionada à desvalorização, à não monetarização e à não\nprofissionalização existente nesse trabalho. Considerá-lo\ncomo extensão da mulher e de sua função reprodutiva é\nretirar o que há de humano e cultural dessa atividade,\nposicionando-a na esfera da natureza, que dispensa valor\nsocial e, por isso, não é considerada como moeda de troca.\nTendo o texto acima como referência inicial, assinale a\nalternativa correta.", "alt": {"A": "Retirar o que há de humano no trabalho social é uma\nforma de se garantir menores salários para essa\nfunção.", "B": "Dar sentido às relações de poder é uma forma de\nreverter a condição inferior da mulher e proceder a\numa troca de posição com o opressor.", "C": "As estratégias de empoderamento estão mais\nancoradas em laços afetivos em função de as mulheres\nterem o afeto como a principal estratégia de\nenfrentamento nas relações de trabalho.", "D": "O trabalho social ganha um viés de cuidado e, como\ntal, a função de trabalho tem perfil historicamente\nfeminino. Por isso, sofre desvalorização, baixos salários\ne desprofissionalização.", "E": "O trabalho social é eminentemente feminino, pela\nvocação natural das mulheres com o cuidado."}, "g": "D", "j": "Curado & Menegon (Generos e os sentidos do trabalho social): o trabalho social, por seu vies de cuidado e perfil historicamente feminino, sofre desvalorizacao, baixos salarios e desprofissionalizacao — a naturalizacao do feminino retira o carater humano-cultural da atividade. Alternativa D reproduz a tese. A inverte a causalidade; B propoe troca de posicoes; C e E naturalizam o feminino como vocacao."}, {"id": "1299340", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2020", "org": "CFP", "t": "", "e": "Em uma universidade de renome, um professor\nreconhecido por sua empatia com os estudantes,\nrespeitoso e tido como um excelente pesquisador em sua\nárea, foi duramente criticado por dizer que negros não\nentram nos cursos mais concorridos da universidade por\numa lacuna na formação básica e não reúnem\nconhecimento suficiente para obter notas excelentes no\nENEM. Ele também se manifestou contra cotas, por\nconsiderá-las como antidemocráticas, já que não respeitam\no critério do mérito. Ele ficou chocado com as críticas por\nse considerar uma pessoa aberta e não racista.\nCom base nessa situação hipotética, é correto afirmar que o\nprofessor se enquadra no(na)", "alt": {"A": "incoerência dos professores universitários.", "B": "racismo estrutural.", "C": "racismo institucional.", "D": "discriminação provocada pelo ódio racial.", "E": "equívoco dos movimentos negros na universidade."}, "g": "B", "j": "Silvio Almeida (Racismo Estrutural): o racismo nao se reduz a atos individuais conscientes — opera estruturalmente, sustentado por discursos meritocraticos que invisibilizam desigualdades historicas. O professor (empatico, bem intencionado) reproduz logica do mito da meritocracia que naturaliza a exclusao racial — caracteristica nuclear do RACISMO ESTRUTURAL. Distingue-se do institucional (politicas formais de uma instituicao) e da discriminacao por odio (ato individual de hostilidade)."}, {"id": "1299339", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Um clássico da psicologia social, que, na realidade, foi\nescrito por um antropólogo canadense, retrabalha a noção\nde representação do eu a partir de referências do\ndesempenho teatral e faz uma profunda análise do\nprocesso de institucionalização nas sociedades modernas.\nTrata-se do(da)", "alt": {"A": "René Lourau.", "B": "Cornelius Castoriadis.", "C": "Thomas Luckmann.", "D": "Erving Goffman.", "E": "George Herbert Mead."}, "g": "D", "j": "ERVING GOFFMAN (1922-1982), sociologo/antropologo canadense, autor de 'A representacao do eu na vida cotidiana' (1959), retrabalha a nocao de self a partir de metaforas teatrais (ator, palco, plateia, fachada). Sua obra e classica para a psicologia social e analise da institucionalizacao ('Manicomios, prisoes e conventos'). Demais alternativas: Lourau (analise institucional francesa), Castoriadis (imaginario social), Luckmann (alemao), Mead (americano)."}, {"id": "1299338", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Considerando a prática do psicólogo social nas intervenções\nrealizadas por ele, julgue os itens a seguir.    \nI. O psicólogo social deve buscar compreender a\ndimensão subjetiva que envolve o fenômeno que ele\nestuda.  \nII. O psicólogo social não trabalha com intervenção direta.  \nIII. O psicólogo social deve estar atento para as condições\nde sofrimento ético-político.    \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Pratica do psicologo social: I — buscar compreender a dimensao subjetiva do fenomeno (correto); III — atencao ao sofrimento etico-politico (Sawaia, 2001 — correto). Item II e INCORRETO: o psicologo social trabalha COM intervencao direta (institucional, grupal, comunitaria, em politicas publicas). Apenas I e III."}, {"id": "1299337", "d": "psicologia", "a": ["Análise do Trabalho", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "É possível que a esfera laboral seja organizadora das demais\nesferas da vida humana, o quanto o mundo do trabalho se\narticula com a dimensão subjetiva, por isso, como\nmencionaram Sato, Coutinho e Bernardo (2017, p. 13), só\nse torna possível “estudar a dimensão psicológica dos\ntrabalhadores, a intersubjetividade e as relações\ninterpessoais no trabalho, situando-as concretamente nos\ncontextos micro e macrossocial”.\n    No texto acima, Gerusa Coutinho D’Ávila & Maria Chalfin\nCoutinho, citando Sato, Coutinho e Bernardo, apontam que", "alt": {"A": "o trabalho é o único fenômeno produtor de\nsubjetividade.", "B": "a articulação da dimensão psicológica e interpessoal\ndeve ser situada na interconexão entre o micro e o\nmacrossocial.", "C": "o micro e o macrossocial são parte da esfera laboral e\norganizadores das demais esferas da vida humana.", "D": "só há interesse pela dimensão psicológica dos\ntrabalhadores.", "E": "a dimensão psicológica dos trabalhadores difere da\ndimensão psicológica dos não trabalhadores."}, "g": "B", "j": "Sato, Coutinho & Bernardo (2017) defendem que estudar a dimensao psicologica dos trabalhadores requer situar a intersubjetividade e as relacoes interpessoais nos contextos MICRO e MACROSSOCIAL articulados. Alternativa B captura essa articulacao. A absolutiza o trabalho; C inverte hierarquia; D restringe interesse; E diferencia trabalhadores de nao-trabalhadores."}, {"id": "1299336", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "A branquitude, enquanto construção social e histórica,\npossibilita que os indivíduos se situem no interior de uma\nformação coletiva, sólida, uma comunidade de negação,\nque nega e exclui da realidade o que não a interessa. Essa\ndimensão profundamente ideológica da branquitude\nexpressa e mascara a realidade e só tem sentido em\nsociedades divididas por conflitos sociais. Aí, sua função\nserá ocultar o conflito, apregoar o povo unido e mascarar a\ndominação.\n    O texto acima, de Maria Aparecida Bento, aponta que o(a)", "alt": {"A": "branquitude reflete uma visão de mundo que opera\nem localidades de características étnicas peculiares,\nem que domina o padrão branco de população.", "B": "mascaramento da realidade se dá a partir do\nencobrimento das diferenças sociais, deixando a\nentender que todos são iguais.", "C": "branquitude é um conceito social e histórico e,\nportanto, não encontrado na realidade.", "D": "mencionada dominação se refere à divisão de classes e\nà exploração dos trabalhadores pela burguesia.", "E": "branquitude reflete uma elaboração ideológica que\nvaloriza esse padrão na sociedade e nega ou mascara o\nvalor da cultura e da realização negra."}, "g": "E", "j": "Maria Aparecida Bento (Branqueamento e branquitude no Brasil): a branquitude e elaboracao ideologica que valoriza o padrao branco e simultaneamente NEGA E MASCARA o valor da cultura e realizacao negra, ocultando conflitos sociais. Alternativa E reproduz a tese. A restringe a localidades; B mascara apenas diferencas sociais; C trata como abstracao; D reduz a classes/burguesia (sem dimensao racial)."}, {"id": "1299335", "d": "psicologia", "a": ["Políticas Públicas no SUAS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Em uma unidade do Conselho Regional de Serviço\nSocial (CRAS) de uma grande cidade, em um bairro\nperiférico de uma região com incidência de muita pobreza e\npoucos recursos, a psicóloga da equipe acompanha uma\nfamília em que uma mulher de 34 anos de idade é a\nmantenedora do lar, com quatro filhos: de catorze, doze,\ndez e quatro anos de idade. O companheiro, pai do filho\nmais novo, está desempregado e é usuário de crack.\nMoram em uma pequena casinha com 15 m²\n, sem\nsaneamento básico. A mulher trabalha como diarista,\nfazendo limpeza nos bairros mais abastados, longe da sua\ncasa. Leva quatro horas diárias para ir e vir do trabalho e\nconsegue uma renda de dois mil reais, sem nenhuma\ngarantia trabalhista. Essa é a única renda da família. As\ncrianças mais velhas estão na escola, mas com pouco\nacompanhamento, e a mais nova fica com uma cuidadora\nde crianças da região, que cobra pelo serviço. O\ncompanheiro, que não é violento, sofre de forte depressão\npelo desemprego e se apoia na droga e na bebida. Essa\nmulher, com essa vida estafante, precária e tensa, encontra\napoio em sua comunidade religiosa, no culto que frequenta\naos finais de semana.\n    Com base nesse caso hipotético, assinale a alternativa\ncorreta quanto à atuação da psicologia no Sistema Único de\nAssistência Social (SUAS).", "alt": {"A": "Entendendo que o trabalho do psicólogo nos CRAS faz\nparte de uma engrenagem mais complexa, que é o\nSUAS, a atuação desse profissional é perpassada por\nelementos tanto da esfera local (o CRAS, a comunidade\nenvolvida e o município) quanto da esfera mais geral (o\nSUAS, as políticas, a federação, os conselhos, as\ndiretrizes de trabalho e os gestores). Sua rotina de\ntrabalho envolve tarefas padronizadas, propostas na\npolítica – visita às famílias, busca ativa, realização de\noficinas socioeducativas, benefícios assistenciais etc., e\ntambém atividades que sua sensibilidade e seu vínculo\ncom a situação exigir, coerentes com as diretrizes da\npolítica.", "B": "O trabalho no CRAS deve evitar a personificação da\natuação dos técnicos envolvidos, principalmente os da\npsicologia e da assistência social. Seguir o protocolo de\natendimento é fundamental e exige desprendimento\ndo profissional, que não deve se envolver\nemocionalmente com os problemas pontuais,\nmantendo a distância necessária para a atuação\ntécnica estabelecida, conforme definida pela gestão.", "C": "Quando um psicólogo se depara com situações que não\nsão extremas, cuja família atendida mantém alguma\nestrutura e o quadro não difere muito do quadro geral\nda população da região, a família deve ser encaminhada\naos demais serviços regulares da região que mantenham\nalgum apoio à comunidade. Na sua ausência,\ninfelizmente, o CRAS não poderá fazer nada, já que é\ndestinado ao apoio de pessoas ou famílias desprovidas\nde qualquer condição mínima de estrutura familiar.", "D": "Definindo, de maneira bastante simples, as controvérsias,\npode-se dizer que são situações de discordância em que\nos atores ainda não têm uma referência clara dos fatos e\nestão longe de chegar a um consenso. Segundo Venturini\n(2009), as controvérsias são capazes de apresentar o\nsocial em sua forma mais dinâmica e, portanto, como\ninstável e absolutamente incerto.", "E": "Para garantir maior harmonia familiar e atenção aos\nfilhos, particularmente à filha de quatro anos de idade\ne ao companheiro, a psicóloga deverá garantir a maior\nempatia possível com a senhora que está sendo\natendida no CRAS. O aconselhamento é a técnica mais\nadequada para a ocasião e deve ser recomendada uma\nmaior interação com o grupo religioso."}, "g": "A", "j": "Referencias CREPOP (Atuacao do psicologo no SUAS): o trabalho do psicologo no CRAS articula esfera local (CRAS, comunidade, municipio) e geral (SUAS, politicas, federacao, diretrizes), com rotina mista de tarefas padronizadas (visita, busca ativa, oficinas, beneficios) e atividades sensiveis ao contexto. Alternativa A reproduz a diretriz. B propoe distancia/burocratizacao; C exclui populacao com 'alguma estrutura'; D introduz conceito de controversias (Latour) sem aplicacao direta; E reduz a aconselhamento e religiao."}, {"id": "1299334", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2020", "org": "CFP", "t": "", "e": "Para George Lapassade, importante autor francês que é\nmuito utilizado no campo da psicologia social, há três\ndimensões que regem a vida das pessoas nas relações\nsociais. São elas:", "alt": {"A": "consciência; atividade; e personalidade.", "B": "objetividade; subjetividade; e sujeito.", "C": "grupos; organizações; e instituições.", "D": "totalidade; particularidade; e singularidade.", "E": "sociedade; grupos; e indivíduo."}, "g": "C", "j": "George Lapassade (Analise Institucional): identifica TRES dimensoes/niveis que regem as relacoes sociais: GRUPOS, ORGANIZACOES e INSTITUICOES. Alternativa C correta. A (consciencia/atividade/personalidade) e de Leontiev/Lane; B (objetividade/subjetividade) e dialetica geral; D (totalidade/particularidade/singularidade) e de Lukacs; E (sociedade/grupos/individuo) e generica."}, {"id": "1299272", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "Consiste em um desvio no exercício profissional do\npsicopedagogo", "alt": {"A": "detectar possíveis perturbações no processo de\naprendizagem.", "B": "promover orientações metodológicas de acordo com\nas características dos indivíduos e dos grupos.", "C": "realizar processos de orientação educacional.", "D": "levantar hipóteses para compreender os processos\nsubjetivos e objetivos que impedem o sujeito de\naprender.", "E": "aplicar testes de inteligência (WISC, WAIS) para a\nelaboração de diagnósticos psicopedagógicos."}, "g": "E", "j": "A aplicacao de testes psicologicos de inteligencia (WISC, WAIS) e atividade PRIVATIVA DO PSICOLOGO (Lei 4.119/62, art. 13; Res CFP 09/2018). O psicopedagogo, ao aplica-los, comete DESVIO de exercicio profissional, invadindo competencia privativa. Demais alternativas (detectar perturbacoes na aprendizagem, orientacoes metodologicas, orientacao educacional, levantar hipoteses) integram o escopo do psicopedagogo segundo a ABPp."}, {"id": "1299264", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "O Estatuto da Criança e do Adolescente completará trinta\nanos em 2020, sendo reconhecido internacionalmente\ncomo uma das melhores legislações protetivas da infância e\nda adolescência. À luz dessa legislação, assinale a\nalternativa correta.", "alt": {"A": "É apenas do Estado – Poder Público – a\nresponsabilidade do que é estabelecido pelo Estatuto.", "B": "Segundo o Estatuto, é direito dos pais ou responsáveis\nter ciência do processo pedagógico, bem como\nparticipar das propostas educacionais.", "C": "Desde sua criação, em 1990, o Estatuto não sofreu\nnenhuma alteração", "D": "É dever do Estado assegurar ensino fundamental,\nobrigatório e gratuito, apenas para as crianças e os\nadolescentes que estiverem na idade própria.", "E": "O processo educacional deve ser padronizado, para\ngarantir uniformidade do aprendizado no Brasil,\nevitando-se valores culturais, artísticos e históricos do\ncontexto social da criança e do adolescente."}, "g": "B", "j": "ECA (Lei 8.069/90), art. 53, paragrafo unico: e direito dos pais ou responsaveis ter ciencia do processo pedagogico, bem como participar da definicao das propostas educacionais. Alternativa B reproduz a lei. A erra (responsabilidade e da familia, sociedade E Estado, art. 4); C erra (o ECA ja sofreu varias alteracoes desde 1990); D erra (idade propria nao restringe direito); E erra (deve respeitar valores culturais)."}, {"id": "1299254", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com o Código de Ética do Psicopedagogo, não é\num dever do psicopedagogo", "alt": {"A": "se submeter à supervisão psicopedagógica e ao\nprocesso terapêutico pessoal.", "B": "preservar a identidade dos sujeitos e dos sistemas nos\nrelatos e nas discussões a título de exemplo e estudos\nde casos.", "C": "assumir as responsabilidades para as quais esteja\npreparado e nos parâmetros da competência\npsicopedagógica.", "D": "se manter atualizado quanto aos conhecimentos\ncientíficos e técnicos que tratam da aprendizagem\nhumana.", "E": "aplicar testes de inteligência com a supervisão de um\nprofissional da psicologia."}, "g": "E", "j": "Codigo de Etica do Psicopedagogo (ABPp): A (supervisao e processo terapeutico pessoal), B (preservar identidade dos sujeitos), C (assumir responsabilidades em sua competencia) e D (manter-se atualizado) sao deveres do psicopedagogo. Alternativa E ('aplicar testes de inteligencia com supervisao de psicologo') NAO e dever — a aplicacao de testes de inteligencia e ATIVIDADE PRIVATIVA do psicologo e nao integra as atribuicoes do psicopedagogo, ainda que sob supervisao."}, {"id": "1296431", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Rueda e Zanini (2018) discutiram as mudanças promovidas\npela Resolução CFP n.ᵒ 9/2018 e os impactos na área de\navaliação psicológica. Acerca desse assunto, julgue os itens\nque se seguem. I. A Resolução CFP n.ᵒ 9/2018 aborda questões\nrelacionadas à justiça e à proteção dos direitos\nhumanos no processo de AP.   II. A Resolução CFP n.ᵒ 9/2018 reforça o entendimento da\nAP como processo, retirando o foco dos chamados\ntestes psicológicos como ferramentas exclusivas para\nsua realização.   III. A atualização de normas é compreendida como um\nprocesso de elaboração de novos estudos normativos\npara testes psicológicos aprovados e com evidências de\nvalidade vigentes. Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Rueda & Zanini (2018) sobre Res CFP 09/2018: I — aborda justica e direitos humanos no processo de AP (correto); II — reforca AP como processo, retirando foco exclusivo dos testes psicologicos (correto); III — atualizacao normativa abrange novos estudos para testes aprovados e com evidencias de validade vigentes (correto). Todos os itens corretos."}, {"id": "1296419", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Em relação à Fairness in Testing, apresentada nos\nStandards for Educational and Psychological Testing,\nAndrade e Valentini (2018) afirmam que a justiça na\navaliação psicológica deve ser entendida como uma\nquestão fundamental para a proteção dos direitos dos\ntestandos. Considerando essa informação, julgue os\npróximos itens.    I. A justiça é uma questão fundamental de estimativa de\nerro de medida da interpretação dos escores\nindividuais para os usos pretendidos.\nII. A justiça é uma questão fundamental da padronização\ndos escores individuais para os usos pretendidos.\nIII. A justiça é uma questão fundamental de validade da\ninterpretação dos escores individuais para os usos\npretendidos.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e III estão certos."}, "g": "D", "j": "Andrade & Valentini (2018) — Fairness in Testing nos Standards (AERA/APA/NCME, 2014): a justica em testagem e questao FUNDAMENTAL DE VALIDADE da interpretacao dos escores individuais para os usos pretendidos. Nao se trata de questao de erro de medida (item I) nem de padronizacao dos escores (item II), mas de validade. Apenas item III correto."}, {"id": "1296417", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2020", "org": "CFP", "t": "", "e": "A respeito da entrevista devolutiva (Hutz, Bandeira, Trentini\n& Krug, 2015; e Resolução CFP n.ᵒ 6/2019), assinale a\nalternativa correta.", "alt": {"A": "Consiste em uma comunicação unidirecional, do\npsicólogo para o avaliado ou seus responsáveis, e deve\nser realizada exclusivamente no final, como\nfechamento do processo de avaliação psicológica.", "B": "Independentemente do tipo de documento psicológico\nelaborado pelo profissional, é recomendado ao\npsicólogo, sempre que solicitado, realizar a entrevista\ndevolutiva. Contudo, para entrega do relatório e do\nlaudo psicológico, é dever do psicólogo realizar ao\nmenos uma entrevista devolutiva da pessoa, do grupo,\nda instituição atendida ou dos responsáveis legais.", "C": "Diante de uma avaliação psicológica, a entrevista\ndevolutiva verbal exime o psicólogo de elaborar um\ndocumento por escrito.", "D": "Quando se trata de criança, adolescente ou adulto\ndependente, é suficiente a entrevista de devolução\ncom os pais ou responsáveis.", "E": "Na impossibilidade de se realizar a entrevista\ndevolutiva, o psicólogo não precisará explicitar suas\nrazões. Um exemplo desse caso é quando o paciente\nrevela risco para si mesmo ou para a sociedade, como\nos casos de crises psicóticas, tendências suicidas, ideias\nhomicidas ou atos antissociais graves."}, "g": "B", "j": "Res CFP 06/2019, art. 6 e Hutz et al. (2015): a entrevista devolutiva e BIDIRECIONAL, podendo ocorrer em diferentes momentos do processo; para entrega de RELATORIO PSICOLOGICO e LAUDO PSICOLOGICO, o psicologo deve realizar ao menos uma entrevista devolutiva. Alternativa B reproduz a norma. A (unidirecional, so no final), C (devolutiva exime documento), D (so com pais), E (sem explicitar razoes) contrariam a Resolucao e a Etica."}, {"id": "1296416", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca da Resolução CFP n.ᵒ 6/2019 comentada, julgue os\nitens seguintes.    I. O relatório multiprofissional é resultante da atuação do\npsicólogo em contexto multiprofissional,\ninterdisciplinar ou transdisciplinar, preservando-se a\nautonomia e a ética profissional dos envolvidos.\nII. No relatório multiprofissional, quando a atividade\ndesenvolvida no atendimento de\npessoa/grupo/instituição consistir em métodos e\ntécnicas privativos da psicologia, estes devem ser\nrelatados em itens diferentes dos itens dos demais\nprofissionais, destacando-se que foram utilizados\napenas pelo psicólogo da equipe.\nIII. O título “Laudo Psicológico” deve ser alterado segundo\na orientação ou especificidade teórico-metodológica\ndo processo. Caso queira, o psicólogo poderá substituir\no título “Laudo Psicológico” pelo título “Avaliação\nNeuropsicológica”.\nIV. Na elaboração de laudos psicológicos, é obrigatória a\ninformação das fontes científicas ou referências\nbibliográficas utilizadas, preferencialmente em nota de\nrodapé. Contudo, no relatório multiprofissional e no\nparecer psicológico, essa é uma questão facultativa.    \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item IV está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Apenas os itens III e IV está certo."}, "g": "C", "j": "Res CFP 06/2019 comentada: I — relatorio multiprofissional resulta de atuacao em contexto multi/inter/transdisciplinar, preservando autonomia/etica (correto); II — metodos privativos da psicologia devem ser relatados em itens diferenciados (correto). Item III esta INCORRETO: o titulo 'Laudo Psicologico' nao pode ser livremente substituido por 'Avaliacao Neuropsicologica' — a Res 06/2019 admite especificacao adicional mas mantem a natureza do documento. Item IV INCORRETO: a indicacao das fontes cientificas/referencias e exigencia geral, nao facultativa em relatorio multiprofissional/parecer. Apenas I e II."}, {"id": "1296412", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere à Resolução CFP n.ᵒ 9/2018, que\nestabelece diretrizes para a realização de avaliação\npsicológica no exercício profissional do psicólogo e\nregulamenta o Satepsi, julgue os itens que se seguem.    I. Constituem fontes fundamentais de informação em um\nprocesso de avaliação: os testes psicológicos com\nparecer favorável do Satepsi; a entrevista; a anamnese;\ne os protocolos ou registros de observação de\ncomportamento obtidos individualmente ou por meio\nde processo grupal e(ou) de técnicas de grupo.\nII. Com a definição de fontes fundamentais de\ninformação, o trabalho do psicólogo passa a ter um\ncaráter mais amplo, no sentido de retirar o foco dos\ntestes psicológicos e de evitar a famosa confusão de\n“avaliação psicológica” com “testagem psicológica”.III. Constituem fontes complementares de informação:\ntécnicas e instrumentos não psicológicos que possuam\nrespaldo da literatura científica da área e que\nrespeitem o Código de Ética e as garantias da legislação\nda profissão e os documentos técnicos, como\nprotocolos ou relatórios, de equipes multiprofissionais.\nIV. Em hipótese alguma, o profissional poderá realizar uma\navaliação psicológica sem uma fonte fundamental de\ninformação.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II, III e IV estão certos.", "B": "Apenas os itens III e IV estão certos.", "C": "Apenas os itens I, II e III estão certos.", "D": "Apenas os itens I, II e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Res CFP 09/2018: I — fontes fundamentais incluem testes Satepsi, entrevista, anamnese, observacao (correto, art. 4); II — caracter mais amplo retirando foco dos testes psicologicos, evitando confusao AP=testagem (correto, fundamento da Resolucao); III — fontes complementares: instrumentos nao psicologicos com respaldo cientifico e documentos de equipes (correto); IV — em hipotese alguma a AP pode prescindir de fonte fundamental (correto, art. 4 caput). Todos os itens corretos."}, {"id": "1296410", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "À luz da legislação pertinente à avaliação psicológica do\nConselho Federal de Psicologia, julgue os itens\nsubsequentes. I. Todas as resoluções do Conselho Federal de Psicologia\nsobre avaliação psicológica e sobre a atuação de\npsicólogos passam pela Assembleia de Políticas da\nAdministração e das Finanças (Apaf), que é composta\npor representantes do Conselho Federal de Psicologia e\npor conselheiros de todos os Conselhos Regionais de\nPsicologia.   II. Nos contextos de trânsito, manuseio de arma de fogo e\nconcursos públicos, cabe ao psicólogo, por meio de um\natestado psicológico, informar se o candidato está,\nnaquele momento, apto ou inapto para exercer a\ntarefa que se espera que ele realize. Entretanto, cabe\nressaltar que não há o impedimento da emissão de\nmais de um documento. Por exemplo, pode ser que\numa pessoa que se submeteu à avaliação psicológica\npara manuseio de arma de fogo obtenha o atestado\nque deverá apresentar à polícia federal e solicite um\nlaudo psicológico para compreender seu\nfuncionamento psicológico. Nessas situações, caberá\nao profissional fornecer ambos os documentos.   III. Ter vínculos pessoais ou profissionais, atuais ou\nanteriores, não interfere na qualidade do trabalho\nrealizado ou na fidelidade aos resultados da avaliação\ndo perito, avaliador ou parecerista, o que é diferente\nquando se trata do trabalho de um psicoterapeuta.  Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Legislacao do CFP: I — as resolucoes do CFP passam pela APAF (Assembleia das Politicas, Administracao e Financas), composta por representantes do CFP e dos CRPs (correto); II — em transito, arma e concursos, pode-se emitir atestado de apto/inapto e, complementarmente, laudo psicologico para fins distintos (correto). Item III INCORRETO: vinculos pessoais/profissionais interferem no trabalho do perito/avaliador (Res CFP 17/2012) tanto quanto no psicoterapeuta — afirmar o contrario contraria a etica. Apenas I e II."}, {"id": "1296409", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo a Resolução CFP n.ᵒ 6/2019, que versa sobre a\nelaboração de documentos escritos por psicólogos,\nconsistem em documentos decorrentes de avaliação\npsicológica o", "alt": {"A": "relatório profissional e o relatório multiprofissional.", "B": "laudo psicológico e o atestado psicológico.", "C": "laudo psicológico e o relatório profissional.", "D": "parecer psicológico e os relatórios psicológicos.", "E": "atestado e o parecer psicológicos."}, "g": "B", "j": "Res CFP 06/2019: os documentos DECORRENTES DE AVALIACAO PSICOLOGICA sao o LAUDO PSICOLOGICO e o ATESTADO PSICOLOGICO — ambos pressupoem processo de AP. Declaracao e relatorio psicologico podem decorrer de outras atuacoes (acompanhamento, psicoterapia, atendimento). Parecer psicologico responde a consulta especifica. Alternativa B correta."}, {"id": "1296408", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "Considerando as orientações do Código de Ética do\nPsicólogo no Brasil (2005), julgue os próximos itens. I. No atendimento à criança, ao adolescente ou ao\ninterdito, para promover medidas benéficas, devem\nser comunicadas aos responsáveis todas as\ninformações essenciais e não essenciais.   II. É vedado interferir na fidedignidade de resultados de\ninstrumentos e técnicas psicológicas.   III. Em caso de demissão ou exoneração, o psicólogo de\numa empresa ou instituição não deverá repassar todo\no material ao psicólogo que vier a substituí-lo, devendo\nguardá-lo sob sua responsabilidade pelo prazo de cinco\nanos.   IV. Em caso de extinção do serviço psicológico em uma\nempresa, os arquivos deverão ser incinerados pelo\nprofissional responsável até aquela data. Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens III e IV estão certos.", "E": "Apenas os itens I, II e III estão certos."}, "g": "B", "j": "CEP (Res 10/2005): I incorreto — no atendimento a crianca/adolescente/interdito, comunica-se aos responsaveis APENAS o estritamente essencial (nao 'todas as informacoes essenciais e nao essenciais'). II correto — e vedado interferir na fidedignidade de resultados de instrumentos psicologicos. III incorreto — em demissao o psicologo DEVE repassar o material ao substituto (nao guardar por 5 anos). IV incorreto — em extincao do servico, deve-se zelar pelo destino dos arquivos (encaminhar ao CRP, manter sigilo), nao simplesmente incinerar. Apenas II."}, {"id": "1296407", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Um paciente de sete anos de idade, segundo os\npais, sempre foi alegre, confiante e comunicativo. A\nadaptação inicial na escola foi boa. Ele dizia que gostava da\nprofessora e dos amigos. No entanto, nos últimos seis\nmeses, começou a se recusar a ir para a escola.\nAtualmente, só de ouvir falar da escola, o paciente começa\na chorar. Ele chora desde a entrada até a saída da escola e\nnão quer mais brincar com os colegas, optando por passar\no recreio sozinho ou com a professora. Às vezes, apresenta\ncomportamento agressivo sem motivo aparente e\ndificuldade para realizar as tarefas propostas pela\nprofessora. Sua mãe comentou que ele tem tido muito\nmedo de monstros na hora de dormir e só concorda em\ncomer quando a mãe está amamentando seu irmão\nrecém-nascido.\nCom base nesse caso hipotético e na Resolução CFP n.ᵒ\n9/2018, para fazer uma avaliação de aspectos da dinâmica\nde personalidade do paciente, o psicólogo poderia usar,\ncomo fonte fundamental,", "alt": {"A": "a grafologia e o teste de apercepção temática (TAT).", "B": "desenhos livres e da família.", "C": "o teste das pirâmides coloridas de Pfister.", "D": "uma bateria de funções mentais para motorista – teste\nde atenção concentrada (BFM-4).", "E": "o teste D2 revisado, que avalia a atenção concentrada."}, "g": "C", "j": "Para avaliar dinamica de personalidade infantil em fonte fundamental (Res CFP 09/2018), o Teste das Piramides Coloridas de Pfister e instrumento expressivo aprovado pelo Satepsi para essa finalidade. A (grafologia nao tem reconhecimento cientifico no Satepsi); B (desenhos livres nao constituem teste com validade — HTP/DFH seriam diferentes); D (BFM-4 avalia atencao para motoristas); E (D2 avalia atencao concentrada) nao avaliam personalidade."}, {"id": "1296405", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca dos critérios para escolha de testes psicológicos\ndiscutidos por Carvalho e Ambiel (2017), julgue os itens a\nseguir. I. Considerar o uso de instrumentos com diferentes\nformatos, isto é, heterogêneos, ou com naturezas\ndistintas possibilita uma avaliação mais ampla dos\nconstrutos relevantes, diminuindo a possibilidade de\nperda de informação para o processo avaliativo, pois\nqualquer fonte de informação é incompleta e\napresenta erro de medida. Desse modo, é necessário\nque o psicólogo utilize procedimentos de naturezas\ndistintas para realizar a avaliação dos aspectos\npsicológicos.   II. Tal qual expresso na Resolução CFP n.ᵒ 10/2005,\ntratando do Código de Ética Profissional do Psicólogo, a\ntomada de decisão acerca dos procedimentos\navaliativos a serem utilizados é de responsabilidade\nespecífica do profissional. A inadequação na escolha\ndas ferramentas de avaliação pode prejudicar as\npessoas que procuram pelo serviço do psicólogo, além\nde configurar prática inadequada da profissão.  III. O Satepsi pode ser utilizado como fonte única para\nescolher um teste psicológico, pois, por meio dele, a\npessoa já discrimina qual o construto que o teste\navalia, se o teste é válido, se tem normas atualizadas e\npara qual faixa etária o teste foi aprovado para uso\nprofissional.\nIV. O primeiro critério que deve guiar o profissional na\nescolha do teste psicológico se refere ao construto que\nse pretende avaliar e a se o construto é relevante para\na avaliação naquele contexto e(ou) caso específico.\nNesse mesmo sentido, deve-se considerar que, na\npsicologia, o mesmo construto pode apresentar\ndiferentes definições e compreensões, a depender da\nperspectiva teórica subjacente, o que também deve ser\nobservado pelo profissional. III. O Satepsi pode ser utilizado como fonte única para\nescolher um teste psicológico, pois, por meio dele, a\npessoa já discrimina qual o construto que o teste\navalia, se o teste é válido, se tem normas atualizadas e\npara qual faixa etária o teste foi aprovado para uso\nprofissional.   IV. O primeiro critério que deve guiar o profissional na\nescolha do teste psicológico se refere ao construto que\nse pretende avaliar e a se o construto é relevante para\na avaliação naquele contexto e(ou) caso específico.\nNesse mesmo sentido, deve-se considerar que, na\npsicologia, o mesmo construto pode apresentar\ndiferentes definições e compreensões, a depender da\nperspectiva teórica subjacente, o que também deve ser\nobservado pelo profissional. Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens I, II e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Carvalho & Ambiel (2017) sobre escolha de testes: I correto (instrumentos heterogeneos diminuem perda de informacao); II correto (responsabilidade do profissional pela escolha, conforme CEP); IV correto (construto e o primeiro criterio; mesmo construto pode ter diferentes compreensoes). Item III INCORRETO: o Satepsi e fonte importante mas NAO unica para escolha — o profissional tambem deve considerar manuais, literatura, adequacao ao caso. Apenas I, II e IV."}, {"id": "1296402", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto ao relatório psicológico, assinale a alternativa\nincorreta à luz da Resolução CFP n.ᵒ 6/2019.", "alt": {"A": "O relatório psicológico é uma peça de natureza e valor\ntécnico-científico, devendo conter narrativa detalhada\ne didática, com precisão e harmonia. A linguagem\nutilizada deve ser acessível e compreensível ao\ndestinatário, respeitando os preceitos do Código de\nÉtica Profissional do Psicólogo.", "B": "O relatório psicológico deve corresponder à descrição\nliteral das sessões, do atendimento ou do acolhimento\nrealizado. Ele deve explicitar precisamente a demanda,\nos procedimentos e o raciocínio técnico-científico do\nprofissional, bem como suas conclusões e(ou)\nrecomendações.", "C": "O relatório psicológico consiste em um documento\nque, por meio de uma exposição escrita, descritiva e\ncircunstanciada, considera os condicionantes históricos\ne sociais da pessoa, do grupo ou da instituição\natendida, podendo também ter caráter informativo.", "D": "O relatório psicológico visa a comunicar a atuação\nprofissional do psicólogo em diferentes processos de\ntrabalho já desenvolvidos ou em desenvolvimento,\npodendo gerar orientações, recomendações,\nencaminhamentos e intervenções pertinentes à\nsituação descrita no documento e não tendo como\nfinalidade produzir diagnóstico psicológico.", "E": "O relatório psicológico é composto de cinco itens:\nidentificação; descrição da demanda; procedimento;\nanálise; e conclusão."}, "g": "B", "j": "Res CFP 06/2019: o relatorio psicologico NAO e descricao literal de sessoes/atendimentos (isso seria registro/prontuario). E narrativa descritiva e circunstanciada com analise tecnico-cientifica. Alternativa B confunde relatorio com registro documental — incorreta. A, C, D e E reproduzem corretamente caracteristicas do relatorio segundo a Res 06/2019."}, {"id": "1296398", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "As transgressões dos preceitos do Código de Ética\nProfissional do Psicólogo constituem infração disciplinar\ncom aplicação das seguintes penalidades:", "alt": {"A": "advertência; multa; censura pública; suspensão do\nexercício profissional por até trinta dias, ad referendum\ndo Conselho Federal de Psicologia; e cassação do\nexercício profissional, ad referendum do Conselho\nFederal de Psicologia.", "B": "multa; suspensão do exercício profissional por até\nnoventa dias, ad referendum do Conselho Federal de\nPsicologia; e cassação do exercício profissional, ad\nreferendum do Conselho Federal de Psicologia.", "C": "advertência; multa; e cassação do exercício\nprofissional, ad referendum do Conselho Federal de\nPsicologia.", "D": "multa; e cassação do exercício profissional, ad\nreferendum do Conselho Federal de Psicologia.", "E": "advertência disciplinar; multa; e suspensão do\nexercício profissional por até noventa dias, ad\nreferendum do Conselho Federal de Psicologia."}, "g": "C", "j": "Lei 5.766/71 (art. 27) e CEP (Res 10/2005, art. 21): as penalidades por transgressao do CEP sao CINCO: advertencia; multa; censura publica; suspensao do exercicio profissional por ate 30 dias ad referendum do CFP; e cassacao do exercicio profissional ad referendum do CFP. Apenas a alternativa A enumera o rol completo. O gabarito candidato C ('advertencia; multa; e cassacao') esta INCOMPLETO — omite censura publica e suspensao. CORRIGIDO para A."}, {"id": "1296396", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com a Resolução CFP n.ᵒ 6/2019, os documentos\npsicológicos devem ser elaborados conforme os princípios\nde qualidade técnica e científica presentes nesse\nregulamento. No que se refere a esses princípios, assinale a\nalternativa incorreta.", "alt": {"A": "O documento escrito resultante da prestação de\nserviços psicológicos deve considerar a natureza\ndinâmica, não definitiva e não cristalizada do\nfenômeno psicológico.", "B": "A elaboração de documento decorrente do serviço\nprestado no exercício da profissão deve considerar\nque este é o resultado de uma avaliação e(ou) de uma\nintervenção psicológica, observando os\ncondicionantes históricos e sociais e seus efeitos nos\nfenômenos psicológicos.", "C": "Ao produzir documentos escritos, o psicólogo deve se\nbasear no que dispõe o artigo 1.ᵒ, alínea c, do Código\nde Ética Profissional do Psicólogo, prestando serviços\npsicológicos de qualidade, em condições de trabalho\ndignas e apropriadas à natureza desses serviços, e\nutilizando princípios, conhecimentos e técnicas\nreconhecidamente fundamentados na ciência\npsicológica, na ética e na legislação profissional.", "D": "Ao elaborar um documento em que seja necessário\nreferenciar material teórico técnico, as referências\ndevem ser colocadas, preferencialmente, em nota de\nrodapé, observando a especificidade do documento\nproduzido.", "E": "Toda e qualquer modalidade de documento\npsicológico deverá primar pela organização e pela\nfacilidade de localização das informações técnicas,\nficando a critério de cada psicólogo a necessidade ou\nnão de numerar e(ou) rubricar as laudas."}, "g": "E", "j": "Res CFP 06/2019: e exigencia da Resolucao a numeracao das laudas e a aposicao de rubrica/assinatura do psicologo, NAO ficando 'a criterio' do profissional. Alternativa E esta incorreta nesse ponto. A (natureza dinamica do fenomeno), B (resultado de avaliacao/intervencao com condicionantes), C (art. 1-c do CEP, condicoes dignas) e D (referencias em rodape) reproduzem a Resolucao."}, {"id": "1296395", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "Julgue os itens a seguir.\n    I. O psicólogo, na realização de estudos, pesquisas e\natividades voltadas para a produção de conhecimento\ne desenvolvimento de tecnologias, garantirá o caráter\nvoluntário da participação dos envolvidos, mediante\nconsentimento livre e esclarecido, salvo nas situações\nprevistas em legislação específica, e respeitando os\nprincípios do Código de Ética Profissional do Psicólogo.\nII. O psicólogo, na realização de estudos, pesquisas e\natividades voltadas para a produção de conhecimento\ne desenvolvimento de tecnologias, avaliará os riscos\nenvolvidos, tanto pelos procedimentos quanto pela\ndivulgação dos resultados, com o objetivo de proteger\nas pessoas, os grupos, as organizações e as\ncomunidades envolvidas.\nIII. O psicólogo, na realização de estudos, pesquisas e\natividades voltadas para a produção de conhecimento\ne desenvolvimento de tecnologias, garantirá o acesso\ndas pessoas, dos grupos ou das organizações aos\nresultados das pesquisas ou dos estudos, após seu\nencerramento, sempre que assim o desejarem.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "CEP, art. 16 (pesquisas): I — garantir carater voluntario via TCLE, salvo legislacao especifica (correto); II — avaliar riscos dos procedimentos e da divulgacao para proteger envolvidos (correto); III — garantir acesso das pessoas/grupos/organizacoes aos resultados, apos encerramento (correto). Todos os itens reproduzem deveres do art. 16 do CEP."}, {"id": "1296394", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2020", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta ação que contraria um\ndever fundamental estabelecido pelo Código de Ética\nProfissional do Psicólogo.", "alt": {"A": "Ter, para com o trabalho dos psicólogos e de outros\nprofissionais, respeito, consideração e solidariedade e,\nquando solicitado, colaborar com estes, salvo se em\nimpedimento por motivo relevante.", "B": "Deixar de prestar serviços profissionais em situações\nde calamidade pública, de forma a respeitar a atuação\nde outras esferas profissionais competentes para\ntanto.", "C": "Estabelecer acordos de prestação de serviços que\nrespeitem os direitos do usuário ou beneficiário de\nserviços de psicologia.", "D": "Fornecer, a quem de direito, na prestação de serviços\npsicológicos, informações concernentes ao trabalho a\nser realizado e a seu objetivo profissional.", "E": "Sugerir serviços de outros psicólogos, sempre que, por\nmotivos justificáveis, não puderem ser continuados\npelo profissional que os assumiu inicialmente,\nfornecendo a seu substituto as informações\nnecessárias à continuidade do trabalho."}, "g": "B", "j": "CEP, art. 1: e dever fundamental do psicologo PRESTAR servicos profissionais em situacoes de calamidade publica (apoio a populacao afetada). Alternativa B ('deixar de prestar servicos em calamidade publica') CONTRARIA esse dever. A, C, D e E sao deveres expressos do art. 1 do CEP."}, {"id": "1296393", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme estabelecido pela Resolução CFP n.ᵒ 6/2019, o\ndocumento psicológico constitui instrumento de\ncomunicação escrita resultante da prestação de serviço\npsicológico à pessoa, a grupo ou à instituição. Com relação\na esse documento, assinale a alternativa incorreta.", "alt": {"A": "A confecção do documento psicológico deve ser\nrealizada mediante solicitação do usuário do serviço de\npsicologia, de seus responsáveis legais, de um\nprofissional específico, das equipes multidisciplinares\nou das autoridades, ou ser resultado de um processo\nde avaliação psicológica.", "B": "De acordo com os deveres fundamentais previstos no\nCódigo de Ética Profissional do Psicólogo, na prestação\nde serviços psicológicos, os envolvidos no processo\npossuem o direito de receber informações sobre os\nobjetivos e os resultados do serviço prestado, bem\ncomo de ter acesso ao documento produzido pela\natividade do psicólogo.", "C": "Segundo o Código de Ética Profissional do Psicólogo, a\nconfecção do documento psicológico deve ser\nrealizada mediante solicitação única e exclusiva do\nusuário do serviço de psicologia, já que o princípio\nbasilar e norteador da relação profissional entre as\npartes é o sigilo.", "D": "Os documentos emitidos pelo psicólogo concretizam\ninformações fundamentais e devem conter dados\nfidedignos que validem a construção do pensamento\npsicológico e a finalidade a que se destina.", "E": "O documento psicológico sistematiza uma conduta\nprofissional na relação direta de um serviço prestado à\npessoa, a um grupo ou a uma instituição."}, "g": "C", "j": "Res CFP 06/2019, art. 2, §1: a confeccao do documento psicologico pode ser realizada mediante solicitacao do USUARIO, dos RESPONSAVEIS LEGAIS, de PROFISSIONAL especifico, das EQUIPES MULTIDISCIPLINARES ou das AUTORIDADES, ou ser resultado de AP. Alternativa C ('solicitacao unica e exclusiva do usuario') restringe indevidamente — incorreta. A, B, D e E reproduzem a Resolucao."}, {"id": "1097846", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A Bioética é um ramo da Ética que pode  ter seus princípios \naplicados  para  refletir  e  observar  a  conduta  de  um \nprofissional  na  área  médica,  incluindo  o  psicólogo  em \ndiversos  contextos  de  atuação.  Assinale  a  alternativa  que \napresenta todos  os  princípios da Bioética.", "alt": {"A": "autonomia e justiça", "B": "autonomia; não maleficência; e sigilo", "C": "autonomia; beneficência, não maleficência; e justiça", "D": "autonomia; beneficência; e confidencialidade", "E": "confidencialidade e justiça"}, "g": "C", "j": "Bioetica (Beauchamp & Childress, Principios de Etica Biomedica): os quatro principios sao AUTONOMIA, BENEFICENCIA, NAO-MALEFICENCIA e JUSTICA. Alternativa C reproduz o rol completo. Demais alternativas omitem principios ou substituem por confidencialidade/sigilo (que sao deveres derivados, nao principios bioeticos)."}, {"id": "1097843", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "Na  emissão  de  documentos  psicológicos,  o  profissional \npsicólogo deve seguir  as normas que regem sua elaboração, \nassim  como  o  destino  desses  documentos.  No  caso  de \nrelatórios  ou  laudos  psicológicos,  o  psicólogo  deve, preferencialmente, optar  por um modo de entrega. Assinale \na alternativa que  apresenta o modo de entrega que  deve ser preferido  pelos psicólogos no  caso desses  documentos.", "alt": {"A": "entrevista de anamnese", "B": "e‐mail", "C": "entrevista devolutiva", "D": "correspondência", "E": "telefone"}, "g": "C", "j": "Res CFP 06/2019 e Hutz et al. (2015): para entrega de relatorios e laudos psicologicos, o modo PREFERENCIAL e a ENTREVISTA DEVOLUTIVA — comunicacao bidirecional que permite esclarecimentos, contextualizacao e apoio a compreensao. E-mail, correspondencia ou telefone nao garantem o cuidado etico necessario."}, {"id": "1097822", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "Considerando o Código de Ética Profissional do Psicólogo, ao \npsicólogo é vedado", "alt": {"A": "fixar  o  valor  de  seus  serviços  considerando  as \ncondições do usuário  ou  beneficiário.", "B": "recusar‐se a prestar seus serviços a organizações onde \nhaja  incompatibilidade  entre  as  práticas  da \norganização  e  os  princípios  do  Código  de  Ética \nProfissional  do  Psicólogo.", "C": "apresentar  diagnósticos  em  meios  de  comunicação \nexpondo pessoas, grupos  ou  organizações.", "D": "compartilhar  informações  relevantes  sobre  um  caso \nquando em trabalho com  profissionais não psicólogos.", "E": "comunicar  o  valor  de  seus  serviços  para  os  usuários \nantes do início do trabalho  a ser efetuado."}, "g": "C", "j": "CEP, art. 20: e VEDADO ao psicologo realizar diagnosticos, divulgar procedimentos ou apresentar resultados de servicos psicologicos em meios de comunicacao, expondo pessoas, grupos ou organizacoes. Alternativa C reproduz a vedacao. A (fixar valor considerando condicoes) e permitido; B (recusar servicos incompativeis) e direito; D (compartilhar com equipe multi) e permitido com criterio; E (comunicar valor antes) e dever."}, {"id": "1301786", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Dor, Estresse e Luto"], "ano": "2018", "org": "CFP", "t": "", "e": "Os desastres provocam  rupturas bruscas na vida das \npessoas  em  virtude  da  sua  manifestação  violenta  e \ndestruidora,  deixando‐as  subitamente  enlutadas,  não \nsomente as que vivenciam perdas por mortes, mas também \naquelas  que  perdem  suas  casas,  seus  pertences  ou  até \nmesmo sua segurança no mundo que conheciam.     Franco (org.). A Intervenção Psicológica em \nEmergências. 2015 (com adaptações).       Acerca  do  luto  das  pessoas  que  vivenciaram  um  desastre, \njulgue os itens que se seguem.       \n  I  Em situações de desastre, a pessoa sobrevivente pode \nnão se permitir vivenciar e compartilhar sua dor, já que \nestá viva quando tantos outros morreram.   \n  II  O luto não reconhecido é definido como aquele que as \npessoas experimentam quando ocorre uma perda que \nnão  é  ou  não  pode  ser  abertamente  conhecida, \npublicamente lamentada ou socialmente apoiada.     \n  III  A vivência do desastre provoca a ideia de que o mundo \né  um  lugar  inseguro,  levando  ao  desequilíbrio \nemocional,  aspecto  que  pode  ser  considerado  como \num  fator  de  risco  para  o  desenvolvimento  de  luto \npatológico. \n      Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Franco (2015) — Intervencao Psicologica em Emergencias: I — o sobrevivente pode bloquear o luto por culpa do sobrevivente, dificuldade de legitimar a propria dor (correto); II — luto nao reconhecido/desautorizado (Doka, 1989) e aquele que nao pode ser abertamente conhecido, lamentado ou socialmente apoiado (correto); III — sentir o mundo como inseguro apos desastre e fator de risco para luto patologico/TEPT (correto). Todos os itens corretos."}, {"id": "1301785", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2018", "org": "CFP", "t": "", "e": "As  unidades  de  urgência  e  emergência  frequentemente \nrecebem casos de pessoas com tentativa de autoextermínio. \nConsiderando essa informação, assinale a alternativa que não\napresenta um fator de risco para o suicídio.", "alt": {"A": "ser do sexo masculino", "B": "ser adulto jovem ou idoso", "C": "ter transtorno mental", "D": "tentativa de suicídio pregressa", "E": "prática religiosa"}, "g": "E", "j": "Fatores de risco para suicidio (OMS, Botega): sexo masculino, adulto jovem ou idoso, transtorno mental e tentativa pregressa sao fatores de risco classicos. A PRATICA RELIGIOSA (E) e fator de PROTECAO contra suicidio (apoio comunitario, sentido de vida, valores anti-suicidio). Alternativa E e a unica que NAO e fator de risco."}, {"id": "1301784", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Sim, ainda há muito o que fazer pelo paciente quando \njá não há mais nada a fazer pela cura.  \nSimonetti, 2014.  \nConsiderando o texto acima, julgue os próximos itens. I  O psicólogo hospitalar deve evitar conversas a respeito \nde  conteúdos  relacionados  à  morte,  pois  o  paciente \nencontra‐se em um momento de sofrimento psíquico. \nII  A equipe de saúde deve dizer a verdade do diagnóstico, \ndo  prognóstico e  do  tratamento  ao  paciente,  sem  se \npreocupar com os recursos de enfrentamento que ele \ntem. \nIII  O  termo  cuidados  paliativos  implica  cuidado  total  e \nativo  de  pacientes  cuja  enfermidade  não  mais \nresponda  aos  tratamentos  curativos  e  em  que  a \nprioridade  seja  o  controle  da  dor  e  a  abordagem  de \naspectos psicológicos, sociais e espirituais. \nIV  O profissional de saúde mental e a equipe de saúde não \ndevem mediar conflitos familiares. \nV  O  acompanhamento  psicológico  da  família  durante  a \ninternação  do  paciente  terminal  pode  evitar  lutos \npatológicos, que incluem identificações com o morto, \nquadros  melancólicos,  somatizações  e  mortes, \nsuicídios e autopunições inconscientes. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "B", "j": "Simonetti (2014) e psicologia hospitalar: I incorreto (o psicologo NAO deve evitar conversas sobre morte — deve acolher); II incorreto (a equipe deve avaliar recursos de enfrentamento antes de comunicar prognostico); III correto (cuidados paliativos como cuidado total/ativo); IV incorreto (a equipe DEVE mediar conflitos familiares); V correto (acompanhamento familiar previne luto patologico). Corretos: apenas III e V — quantidade = 2."}, {"id": "1301781", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  ao  comportamento  suicida,  julgue  os  itens  que  se \nseguem. \nI  A  fala  “Quero  sumir  desse  mundo”  indica  um  plano \nsuicida. \nII  A  fala  “Se  eu  pudesse,  dormiria  para  nunca  mais \nacordar” refere uma ideação suicida. \nIII  O psicólogo hospitalar, ao identificar o risco de suicídio \ndo paciente, deve orientar a equipe e a família para que \nele  não  permaneça  sozinho  e  seja  mantido  sob \nobservação 24h por dia. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Comportamento suicida (Botega): I incorreto — 'Quero sumir desse mundo' configura IDEACAO (nao plano; o plano envolve metodo, hora, local); II correto — 'Dormiria para nunca acordar' e ideacao passiva de morte; III correto — diante de risco de suicidio, manter o paciente sob observacao 24h e orientacao a equipe/familia. Apenas II e III."}, {"id": "1301780", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo  Botega  (2017),  em  alguns  casos,  podem  existir \nrazões psiquiátricas para atrasar a cirurgia bariátrica ou não a \nindicar. Considerando essa informação, assinale a alternativa \nque não apresenta uma delas.", "alt": {"A": "transtorno mental grave insuficientemente controlado", "B": "ansiedade leve reativa", "C": "abuso ou dependência de álcool ou drogas", "D": "incapacidade  de  fornecer  consentimento  livre  e \nesclarecido para a cirurgia", "E": "recusa  em  cumprir  o  protocolo  do  tratamento  \npós‐operatório"}, "g": "B", "j": "Botega (2017) — razoes psiquiatricas para atrasar/contraindicar bariatrica: transtorno mental grave nao controlado (A), abuso/dependencia de alcool ou drogas (C), incapacidade de TCLE (D), recusa em cumprir protocolo pos-operatorio (E). ANSIEDADE LEVE REATIVA (B) e reacao comum e nao constitui contraindicacao — alternativa B e a unica que NAO e razao para atrasar a cirurgia."}, {"id": "1301778", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2018", "org": "CFP", "t": "", "e": "Para  o  International  Work  Group  on  Death  Dying \nBereavement  (2002),  desastre  é  um  acontecimento \ntraumático  que  causa  perda  de  vidas,  da  saúde  e  de  bens \nmateriais e impacta muitas pessoas. Acerca das intervenções \npsicológicas em situações de desastre, assinale a alternativa \ncorreta.", "alt": {"A": "O campo de atuação da psicologia vai desde uma ação \npreventiva até o pós‐trauma.", "B": "O objetivo da intervenção na crise desencadeada por \ndesastres é resolver situações de pequena pressão em \num período extenso e com o uso de intervenção direta \ne ampla.", "C": "As  técnicas  terapêuticas  convencionais, por meio  das \nquais  o  paciente  fala  sobre  os  problemas,  são  mais \nvantajosas que os métodos de intervenção de crise.", "D": "As  situações  de  desastre  têm  sido  estudadas  pela \npsicologia  em  dois  campos  específicos:  na  psicologia \nambiental e na psicologia escolar.", "E": "A  psicologia  em  emergência  e  desastre  desvincula‐se \nda  psicologia  da  saúde,  da  psicofisiologia  e  da \npsiconeuroimunologia,  pois  impossibilita  uma \navaliação acurada das necessidades dos afetados."}, "g": "A", "j": "Psicologia em emergencias e desastres (referencias CFP/Franco): o campo de atuacao vai da PREVENCAO (planejamento, mitigacao, preparacao) ao POS-TRAUMA (acolhimento, intervencao breve, prevencao de TEPT/luto patologico). Alternativa A correta. B (intervencao com pequena pressao em periodo extenso) inverte a logica; C (tecnicas convencionais mais vantajosas) contraria a literatura sobre primeiros cuidados psicologicos; D (so ambiental/escolar) restringe; E (desvinculacao da saude) e falsa."}, {"id": "1301775", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  relação  à  equipe  que  atua  dentro  da  UTI,  julgue  os \npróximos itens. \nI  Na UTI, torna‐se fundamental a realização de reuniões \nmultiprofissionais da equipe para troca de informações \ne  percepções  sobre  os  casos,  pois  elas  terão \nrepercussão  direta  nos  vínculos  terapêuticos  com  os \npacientes, com impacto no  tratamento e  também no \nambiente de trabalho. \nII  As trocas entre os membros da equipe demonstram ser \numa  estratégia  resiliente  para  lidar  com  as  angústias \nque  são  mobilizadas  e  as  dificuldades  que  emergem \npelo ambiente estressor da UTI. \nIII  Muitas  vezes,  observa‐se  o  uso  exacerbado  de \nmecanismos de defesa dos profissionais de saúde que \natuam  na  UTI  na  tentativa  de  lidar  com  o  estresse \nproporcionado nesse ambiente, como, por exemplo, a \nconstrução de uma couraça impermeável às emoções \ne  aos  sentimentos,  que  se  expressa  por  um \nembotamento emocional, traduzido por uma aparente \n“frieza” no contato com os pacientes e com as pessoas \nde um modo geral, ou, ainda, pelo uso de ironias. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Equipe na UTI: I — reunioes multiprofissionais sao fundamentais para troca de informacoes e vinculos terapeuticos (correto); II — trocas como estrategia resiliente diante das angustias do ambiente estressor (correto); III — uso exacerbado de defesas (couraca, embotamento, ironia) na tentativa de lidar com o estresse (correto, cf. Kovacs, Pitta). Todos os itens corretos."}, {"id": "1301774", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  família  no  ambiente  da  UTI,  julgue  os  itens \nsubsequentes. \nI  A internação do paciente na UTI provoca um período \nde  crise  na  família,  porém  não  interferem  nele  os \nconflitos  pré‐existentes  que  acompanham  o  grupo \nfamiliar.  \nII  É indicado que o psicólogo avalie e identifique, entre os \nmembros  da  família,  aquele(s)  que  demostre(m)  ter \nrecursos  internos  mais  preservados,  pois  poderá(ão) \nser um elo facilitador da relação equipe‐família. \nIII  A  maneira  como  a  família  irá  lidar  com  tal  situação \nindepende de sua história familiar, do quanto o sistema \nera  saudável  emocionalmente  e  dos  mecanismos  de \ndefesa que utilizem no cenário de gravidade. \nIV  A internação na UTI promove elevado grau de estresse. \nNessas  situações,  os  familiares  podem escutar  aquilo \nque  é  menos  difícil  de  assimilar  do  ponto  de  vista \nemocional,  estando  muitas  vezes  despreparados  ou \nsendo  incapazes  de  ouvir,  aceitar  ou  interpretar  a \nverdade em determinado momento. \nV  Na  UTI,  é  comum  o  surgimento  de  fantasias  e  a \n“contaminação  do  cenário”  por  vivências \nexperimentadas  por  outras  famílias  na  mesma \ncondição e(ou) passando por outras experiências. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Familia na UTI: I incorreto — conflitos pre-existentes INTERFEREM no enfrentamento da crise; II correto (identificar membro com recursos preservados); III incorreto — a forma de lidar DEPENDE da historia familiar e dos mecanismos de defesa; IV correto (familiares escutam o que e menos dificil de assimilar); V correto (fantasias e contaminacao por outras familias). Corretos: II, IV, V = 3 itens. Gabarito C."}, {"id": "1301770", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação ao  trabalho do psicólogo na UTI, julgue os itens \nseguintes. \nI  Na  UTI,  os  sinais  e  sintomas  que  merecem  atenção \nespecial do psicólogo e de todos os membros da equipe \nsão:  desânimo;  negatividade;  agressividade;  e \nalterações  de  sono  ou  apetite,  pois  podem  indicar  a \nevolução  para  quadros  psicopatológicos  mais  graves, \nque  necessitem  de  avaliação  psiquiátrica  e  uso  de \npsicofármacos. \nII  Na  UTI,  há  pacientes  conscientes  que  não  podem  se \ncomunicar verbalmente,  como,  por exemplo, aqueles \nque estão em uso de ventilação mecânica. Para eles, o \npsicólogo  aguarda  melhora  clínica  para  realizar  o \natendimento,  visto  que  a  comunicação  alternativa  é \nineficiente. \nIII  No caso de pacientes sedados ou em coma na UTI, o \npsicólogo  fala  para  ele  sobre  ele.  Diz,  por  exemplo, \ncomo está indo o tratamento, o quanto a família deseja \nsua  recuperação  e  outras  coisas  positivas  e \nesperançosas, pois ainda há subjetividade ali.  \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Psicologo na UTI: I — sinais (desanimo, agressividade, alteracoes sono/apetite) podem indicar evolucao para psicopatologia (correto); III — paciente sedado/coma: falar sobre o tratamento, esperanca, mensagem positiva, pois ha subjetividade preservada (correto). Item II INCORRETO: para pacientes em ventilacao mecanica e necessario usar comunicacao alternativa (gestos, escrita, expressao facial) — NAO 'aguardar melhora'. Apenas I e III."}, {"id": "1301768", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito da UTI, julgue os próximos itens. \nI  É importante que o psicólogo hospitalar na UTI realize, \ncomo  conduta,  a  orientação  espaçotemporal  ao \npaciente,  facilitada  com  a  presença  de  relógios  e \ncalendários próximos ao leito. \nII  Durante a internação na UTI, o paciente necessita da \nmanutenção/recuperação  de  sua  identidade  e  da \npreservação das necessidades psicológicas básicas por \nmeio da alta tecnologia envolvida. \nIII  Na UTI,  o  paciente  não  deve  ser  tocado  pela  família, \nvisto  que  existem  muitos  equipamentos  de \nmonitoramento e preservação da vida. \nIV  As  reações  mais  comuns  entre  os  familiares  dos \npacientes  da  UTI  são:  ansiedade;  estresse;  negação; \nmedo; e desespero pela falta de controle da situação. \nV  Os equipamentos de ventilação mecânica geralmente \nassustam os familiares que têm contato com o paciente \nnas  situações  de  visita,  portanto  é  interessante  que \nrecebam orientações antes de entrarem na UTI. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "UTI: I correto (orientacao espacotemporal com relogios/calendarios); IV correto (ansiedade, estresse, negacao, medo nos familiares); V correto (orientar familiares antes da visita devido aos equipamentos). Item II INCORRETO — identidade nao se preserva 'por meio da alta tecnologia'; ao contrario, a tecnologia tende a despersonalizar, e o psicologo atua para preservar identidade APESAR da tecnologia. Item III INCORRETO — o toque familiar e ESTIMULADO, nao proibido. Corretos: I, IV, V = 3."}, {"id": "1301766", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Um paciente de 32 anos de idade, casado, sempre foi \numa pessoa conflituosa com seus relacionamentos afetivos, \ncom experiências “desregradas” sexualmente e histórico de \nadultério. Começou a sentir fraqueza, febre e emagrecimento \ne  procurou  orientação  médica,  necessitando  de  ficar \ninternado. Após exames, constatou o contágio pelo vírus HIV. \nA  equipe  contou  a  ele  o  resultado,  esclarecendo  algumas \ndúvidas quanto à doença e ao tratamento. Após algum tempo \nda  constatação  do  diagnóstico,  uma  de  suas  falas  com  a \nequipe  foi  a  de  que  renovaria  os  votos  com  sua  esposa  e \nreceberia a cura.  \nCom  base  nesse  caso  hipotético,  assinale  a  alternativa  que \napresenta a fase/o estado em que o paciente estaria.", "alt": {"A": "depressão", "B": "barganha", "C": "aceitação", "D": "negação", "E": "revolta"}, "g": "B", "j": "Kubler-Ross (Sobre a morte e o morrer): a fase de BARGANHA caracteriza-se por promessas e negociacoes (frequentemente religiosas ou existenciais) em troca de cura/sobrevida. 'Renovaria votos com a esposa e receberia a cura' configura barganha tipica (negociacao moral por cura). Negacao (D) e revolta (E) sao fases anteriores; aceitacao (C) seria reconciliacao final; depressao (A) e luto antecipatorio."}, {"id": "1301762", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "A gente pensa uma coisa, acaba escrevendo outra e o \nleitor entende uma terceira e, enquanto se passa tudo isso, a \ncoisa  propriamente  dita  começa  a  desconfiar  que  não  foi \npropriamente dita.  \nMário Quintana. Considerando o psicólogo como parte da equipe do hospital, \nassinale  a  alternativa  correta  a  respeito  da  comunicação \nentre equipe e paciente.", "alt": {"A": "O  psicólogo  tem  a  função  fundamental  de  mediar  a \ncomunicação  entre  equipe  e  paciente,  sendo  que \nsomente  ele  tem  competência  para  esclarecer \ntermos/palavras de acordo com o grau de escolaridade \ne a área de atuação do indivíduo.", "B": "A  comunicação  efetiva  deve  conter:  expressão \n(verificar  se  a  compreensão  está  correta); \nesclarecimento  (compreensão  de  raciocínio,  ideia, \npostura,  gesto  ou  comportamento);  e  validação  do \nentendimento de algo (não repetir a informação).", "C": "O  sermão  em  caráter  punitivo  deve  ser  utilizado  em \ncasos  em  que  o  paciente  não  esteja  aderindo  ao \ntratamento ou tenha atitudes prejudiciais à saúde.", "D": "O  ponto  fundamental  da  comunicação  é  saber  ouvir. \nNada é mais prejudicial ao paciente que a antecipação \nda resposta.", "E": "A ausência de informação é a melhor opção em casos \nde  doenças  graves,  pois  não  permite  margem  a \nfantasias e reações inadequadas."}, "g": "D", "j": "Comunicacao equipe-paciente: o ponto fundamental e SABER OUVIR, evitando antecipar a resposta. Alternativa D captura essa premissa basica da escuta clinica. A absolutiza competencia do psicologo; B distorce o conceito de validacao (que envolve sim confirmar entendimento); C propoe sermao punitivo (anti-etico); E defende ausencia de informacao (contraria autonomia/TCLE)."}, {"id": "1301761", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  base  nas  ideias  de  Caponero  (2015)  sobre  a \ncomunicação de más notícias no contexto hospitalar, julgue \nos itens subsequentes. \nI  Uma das técnicas utilizadas para a comunicação de más \nnotícias  é  o  protocolo  SPIKES  (Setting  –  Perception  – \nInvitation  –  Knowledge  –  Emotions  –  Strategy  and \nSummary). \nII  Uma  forma  adequada  de  reduzir  a  ansiedade  é \npartilhar  com  o  paciente  as  decisões  terapêuticas, \npermitindo sua autonomia no tratamento. \nIII  O  psicólogo hospitalar acompanha a comunicação  de \nmás  notícias,  geralmente  dadas  pelo  médico.  Uma \nimportante intervenção é investigar  como o  paciente \nenxerga  sua  condição  clínica  e  verificar  se  ele  está \nnegando  a  doença.  Além  disso,  deve‐se  avaliar  se  o \nindivíduo  está  utilizando  pensamento  mágico, \ncomportamento  que  pode  fazer  parte  de  sua \npersonalidade  ou  constituir‐se  em  um  mecanismo \nmomentâneo de proteção. Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Caponero (2015) — comunicacao de mas noticias: I — protocolo SPIKES (Baile et al., 2000): Setting, Perception, Invitation, Knowledge, Emotions, Strategy/Summary (correto); II — partilhar decisoes terapeuticas para promover autonomia reduz ansiedade (correto); III — investigar percepcao da condicao, negacao e pensamento magico como mecanismo de protecao (correto). Todos os itens corretos."}, {"id": "1301759", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito da pessoa idosa, julgue os itens a seguir. \nI  Muitas  vezes,  os  idosos  recusam  o  tratamento \nproposto  por  sua  grande  invasão  ou  por  não \nacreditarem em sua eficácia. \nII  A  velhice é  o  período existencial em  que geralmente \nacontecem perdas significativas. Pode haver alteração \nda  autoestima  e  visão  negativa  da  autoimagem.  O \nimpacto de todos esses aspectos negativos pode atingir \no  humor,  com  perigo  de  desenvolver  transtornos \nmentais. \nIII  O  paciente  idoso  que  se  submeta  a  uma  cirurgia  de \namputação  vivenciará  a  perda  de  acordo  com  a \nrepresentação  simbólica  que  ele  tenha  do  membro \namputado, dependendo dos danos ocasionados. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Idoso em contexto hospitalar: I — recusa de tratamento por invasao ou descrenca na eficacia (correto); II — velhice com perdas significativas, alteracao da autoestima/autoimagem e risco de transtornos do humor (correto, cf. Botega); III — amputacao vivenciada conforme representacao simbolica do membro perdido (correto, perspectiva da imagem corporal/Le Boulch). Todos certos."}, {"id": "1301754", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2018", "org": "CFP", "t": "", "e": "A diretriz da Política Nacional de Humanização (2003) que é \nconsiderada  como  uma  ferramenta  teórica  e  prática  cuja \nfinalidade  é  contribuir  para  uma  abordagem  clínica  do \nadoecimento e do sofrimento que considere a singularidade \ndo sujeito e a complexidade do processo saúde/doença é o(a)", "alt": {"A": "ambiência.", "B": "transversalidade.", "C": "clínica ampliada e compartilhada.", "D": "acolhimento.", "E": "gestão participativa."}, "g": "C", "j": "Politica Nacional de Humanizacao (PNH, 2003): a CLINICA AMPLIADA E COMPARTILHADA e a diretriz teorica e pratica que contribui para abordagem clinica do adoecimento considerando singularidade do sujeito e complexidade do processo saude/doenca. Alternativa C correta. A (ambiencia) trata do espaco fisico/afetivo; B (transversalidade) e principio geral; D (acolhimento) e postura etica; E (gestao participativa) e diretriz de gestao."}, {"id": "1299603", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CFP", "t": "", "e": "A  Resolução  CFP  n.º  3/2003,  que  institui  o  manual  de \nelaboração  de  documentos  por  psicólogos,  delimita  o \nparecer. Considerando essa informação, julgue os próximos \nitens. \nI  Parecer  é  um  documento  fundamentado  e  resumido \nsobre  uma  questão  focal  do  campo  psicológico  cujo \nresultado pode ser indicativo ou conclusivo. \nII  O  psicólogo  parecerista  deve  fazer  a  análise  do \nproblema  apresentado,  destacando  os  aspectos \nrelevantes,  e  opinar  a  respeito,  considerando  os \nquesitos  apontados  com  fundamento  em  referencial \nteórico‐científico.  Em  havendo  quesitos,  o  psicólogo \ndeverá respondê‐los de forma sintética e convincente, \npodendo deixar alguns quesitos em aberto.  \nIII Quando não houver dados para a resposta ou quando \no psicólogo não puder ser categórico, deve‐se utilizar a \nexpressão “sem elementos de convicção”. Se o quesito \nestiver mal formulado, pode‐se afirmar “prejudicado”, \n“sem elementos” ou “aguarda evolução”. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Dois dos itens estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Res CFP 03/2003 (atual Res 06/2019) sobre parecer: I correto (documento fundamentado, resumido, focal, indicativo ou conclusivo); III correto (expressoes 'sem elementos de conviccao', 'prejudicado' quando ha limitacoes). Item II tem ressalva problematica ('podendo deixar alguns quesitos em aberto') — o parecerista deve responder todos, mesmo que com 'sem elementos'. Dois itens corretos (I e III) — gabarito D."}, {"id": "1299602", "d": "psicologia", "a": ["Psicologia Jurídica", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2018", "org": "CFP", "t": "", "e": "De acordo com Brodzinsky (1990), uma boa porcentagem de \ncrianças adotivas e seus pais experienciam como estressante \no  período  que  se  segue  à  colocação,  o  que  aumenta  a \nvulnerabilidade  da  criança  para  problemas  emocionais  e \ncomportamentais. Segundo o autor, a ideia de que a adoção \né  estressante  contraria  vários  mitos  e  estereótipos \nprevalentes  sobre  essa  situação,  que  tem  sido  vista, \ntipicamente, como uma solução da sociedade para o estresse \nque envolve as três partes do triângulo da adoção. \nI  Uma  das  partes  do  triângulo  da  adoção  é  a  dos  pais \nbiológicos, que não desejam ou não podem ficar com o \nfilho. \nII  Uma das partes do triângulo da adoção é a infertilidade \nou  ausência  de  filhos  por  parte  dos  pais  adotivos \n(acrescente‐se, aqui, o desejo de ter outros filhos). \nIII Uma das partes do triângulo da adoção é um estado de \nausência de lar e insegurança por parte da criança a ser \nadotada. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Brodzinsky (1990) — triangulo da adocao: I — pais biologicos que nao desejam ou nao podem ficar com o filho (correto); II — pais adotivos com infertilidade ou ausencia de filhos (correto); III — crianca em ausencia de lar e inseguranca (correto). Todas as tres partes do triangulo. Gabarito E."}, {"id": "1299601", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "É dever do psicólogo respeitar o sigilo profissional a fim de proteger, por meio da confidencialidade, a intimidade das pessoas, dos grupos ou das organizações a que tenha acesso no exercício profissional, conforme estabelecido no Código de ética profissional\ndo psicólogo. Com base nos preceitos presentes neste Código, assinale a alternativa incorreta.", "alt": {"A": "Quando requisitado a depor em juízo, o psicólogo poderá prestar informações, considerando o  previsto neste Código.", "B": "Nos documentos que embasem as atividades em equipe multiprofissional, o psicólogo deverá  registrar  toda e qualquer \ninformação  que  julgue  necessária,  pois  poderão  posteriormente  ser  relevantes  para  o  cumprimento  dos  objetivos  do \ntrabalho.", "C": "No atendimento à criança, ao adolescente ou ao interdito, deverá ser comunicado aos responsáveis o estritamente essencial \npara se promoverem medidas em seu benefício.", "D": "A utilização de quaisquer meios de  registro e observação da prática psicológica obedecerá às normas deste Código e à \nlegislação profissional vigente, devendo o usuário ou beneficiário, desde o início, ser informado.", "E": "Em caso de interrupção do trabalho do psicólogo, por quaisquer motivos, ele deverá zelar pelo destino de seus arquivos \nconfidenciais. Em caso de demissão ou exoneração, o psicólogo deverá repassar todo o material ao psicólogo que vier a \nsubstitui‐lo ou lacrá‐lo para posterior utilização pelo psicólogo substituto."}, "g": "B", "j": "CEP em equipe multiprofissional, art. 12: o psicologo registrara APENAS as informacoes necessarias para o cumprimento dos objetivos do trabalho — NAO 'toda e qualquer informacao'. Alternativa B contraria esse principio. A (depor em juizo conforme CEP), C (atendimento a crianca/adolescente: estritamente essencial), D (registros conforme normas) e E (interrupcao/demissao: repassar ou lacrar) sao corretas."}, {"id": "1299600", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "O Código de ética do psicólogo pautou‐se pelo princípio geral \nde aproximar‐se mais de um instrumento de reflexão que de \num  conjunto  de  normas  a  serem  seguidas  pelo  psicólogo. \nConsiderando essa informação, julgue os seguintes itens.  \nI  Na  construção  do  Código  de  ética  dos  psicólogos, \nbuscou‐se  valorizar  os  princípios  fundamentais  como \ngrandes  eixos  que  devem  orientar  a  relação  do \npsicólogo  com  a  sociedade,  a  profissão,  as  entidades \nprofissionais  e  a  ciência,  pois  esses  eixos  atravessam \ntodas  as  práticas  e  estas  demandam  uma  contínua \nreflexão sobre o contexto social e institucional. \nII  Na  construção  do  Código  de  ética  dos  psicólogos, \nbuscou‐se  abrir  espaço  para  a  discussão,  pelo \npsicólogo,  das  interseções  e  dos  limites  relativos \napenas aos direitos individuais, questão crucial para as \nrelações que estabelece com a sociedade, os colegas de \nprofissão  e  os  usuários  ou  beneficiários  de  seus \nserviços. \nIII  Na  construção  do  Código  de  ética  dos  psicólogos, \nbuscou‐se  contemplar  a  diversidade  que  configura  o \nexercício  da  profissão  e  a  crescente  inserção  do \npsicólogo  em  contextos  institucionais  e  em  equipes \nmultiprofissionais. \nIV  Na  construção  do  Código  de  ética  dos  psicólogos, \nbuscou‐se  estimular  reflexões  que  considerem  a \nprofissão  como  um  todo  e  não  em  suas  práticas \nparticulares, uma vez que os principais dilemas éticos \nnão se restringem a práticas específicas e surgem em \nquaisquer contextos de atuação. \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Construcao do CEP (Res 10/2005): I correto (principios fundamentais como eixos); III correto (diversidade do exercicio e equipes multi); IV correto (profissao como um todo, dilemas nao restritos). Item II INCORRETO: o CEP nao se restringe a 'direitos individuais' — abrange dimensoes coletivas, sociais, institucionais. Corretos: I, III, IV = 3 itens. Gabarito D."}, {"id": "1299599", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CFP", "t": "", "e": "De acordo com a Resolução CFP n.º 3/2003, o parecer não é \ncomposto de", "alt": {"A": "identificação.", "B": "exposição de motivos.", "C": "análise.", "D": "conclusão.", "E": "resumo/anexo."}, "g": "E", "j": "Res CFP 03/2003 sobre parecer psicologico: a estrutura e composta de IDENTIFICACAO, EXPOSICAO DE MOTIVOS, ANALISE e CONCLUSAO. NAO inclui 'resumo/anexo' como item formal. Alternativa E (resumo/anexo) e a unica que nao faz parte. Demais (A, B, C, D) sao os 4 itens estruturais."}, {"id": "1299584", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Crianças e Adolescentes - Menores Infratores"], "ano": "2018", "org": "CFP", "t": "", "e": "Julgue os próximos itens. \nI  Os programas e  serviços destinados a dar  retaguarda \nao cumprimento das medidas  socioeducativas devem \nconsiderar  a  distribuição  coordenadora e executiva  a \nque se refere à CF (art. 204). \nII  Os programas e  serviços destinados a dar  retaguarda \nao cumprimento das medidas  socioeducativas devem \nconsiderar a conceituação da política de atendimento \ncomo conjunto articulado de ações governamentais e \nnão governamentais da União, dos estados, do Distrito \nFederal e dos municípios. \nIII  Os programas e  serviços destinados a dar  retaguarda \nao cumprimento das medidas  socioeducativas devem \nconsiderar  a  possibilidade  de  criar  diretrizes  de \nmunicipalização  do  atendimento  e  descentralização \npolítico‐administrativa  na  criação  e  manutenção  de \nprogramas, conforme as competências. \nIV  Os programas e  serviços destinados a dar  retaguarda \nao cumprimento das medidas  socioeducativas devem \nconsiderar  a  integração  operacional  de  órgãos  do \nJudiciário e de assistência social, preferencialmente em \num  mesmo  local,  para  efeito  de  agilização  do \natendimento  e  garantia  dos  direitos  processuais  ao \nadolescente  a  quem  se  atribua  autoria  de  ato \ninfracional.  \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "ECA, art. 88 (diretrizes da politica de atendimento): I — distribuicao coordenadora/executiva (CF art. 204); II — politica de atendimento como conjunto articulado de acoes governamentais e nao governamentais (Uniao, estados, DF, municipios); III — municipalizacao e descentralizacao politico-administrativa; IV — integracao operacional dos orgaos do Judiciario e assistencia social. Todos os 4 itens corretos. Gabarito E."}, {"id": "1299583", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Crianças e Adolescentes - Menores Infratores"], "ano": "2018", "org": "CFP", "t": "", "e": "Para Volpi (2002), prestar serviços à comunidade constitui uma medida com forte apelo comunitário e educativo tanto para o jovem  infrator quanto para a comunidade, que,  por sua vez, poderá responsabilizar‐se pelo desenvolvimento integral desse adolescente. Para o jovem, é oportunizada a experiência da vida comunitária, de valores sociais e compromisso social. Com relação \na esse tema, julgue os itens que se seguem. I O envolvimento da comunidade por intermédio de órgãos governamentais, clubes de serviços, entidades sociais e outros é \nfundamental na operacionalização dessa medida. \nII  A  aplicação  dessa  medida  depende  exclusivamente  da  Justiça  da  Infância  e  Juventude,  mas,  na sua operacionalização, recomenda‐se o uso de um programa que estabeleça parcerias com órgãos públicos e organizações não governamentais.III  A prestação de serviços à comunidade será cada vez mais efetiva na medida em que houver o  adequado acompanhamento da família pelo órgão executor, o apoio da entidade que o recebe e a utilidade real da dimensão  social do trabalho realizado. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Volpi (2002) sobre Prestacao de Servicos a Comunidade: I — envolvimento de orgaos governamentais, clubes, entidades sociais (correto); II — aplicacao depende da JIJ, com operacionalizacao via parcerias publicas/ONGs (correto); III — efetividade depende do acompanhamento familiar, apoio da entidade e utilidade real do trabalho (correto). Todos certos."}, {"id": "1299582", "d": "psicologia", "a": ["Foucault", "Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "No que diz respeito à obra Vigiar e punir de Foucault (1993), \njulgue os itens seguintes. \nI  O  prejuízo  que  um  crime  traz  ao  corpo  social  é  a \ndesordem que introduz nele: o escândalo que suscita; \no exemplo  que  dá;  a  incitação  a  recomeçar  se  não é \npunido;  e  a  possibilidade  de  generalização  que  traz \nconsigo.  \nII  Para  ser  útil,  o  castigo  deve  ter  como  objetivo  as \nconsequências  do  crime, entendidas  como a  série  de \ndesordens que este é capaz de abrir. \nIII Deve‐se calcular uma pena em  função do crime, mas \nnão de sua possível repetição. É necessário visar não à \nofensa passada, mas à desordem futura. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Foucault (Vigiar e Punir, 1975/1993): I — o prejuizo do crime ao corpo social inclui desordem, escandalo, exemplo, possibilidade de generalizacao (correto); II — o castigo deve visar as consequencias do crime, a desordem aberta (correto). Item III INCORRETO: para Foucault, a pena deve VISAR a desordem FUTURA e prevenir REPETICAO — afirmar 'nao em funcao de sua possivel repeticao' contraria a tese central. Apenas I e II."}, {"id": "1299581", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "Silva  (2009)  esclarece  as  recomendações  sobre  guarda  de \ndocumentos e condições de guarda. Com relação a esse tema, \njulgue os itens a seguir. \nI  Os  documentos  escritos  decorrentes  de  avaliação \npsicológica,  bem  como  todo  o  material  que  os \nfundamentou,  deverão  ser  guardados  pelo  prazo \nmínimo de cinco anos. \nII Deve‐se  observar  a  responsabilidade  pelos \ndocumentos  tanto do psicólogo quanto da instituição \nem que ocorreu a avaliação psicológica.  \nIII O  prazo  para  guarda  dos  documentos  poderá  ser \nampliado nos casos previstos em lei, por determinação \njudicial.  \nIV O  prazo  para  guarda  dos  documentos  poderá  ser \nampliado em casos específicos em que seja necessária \na manutenção da guarda por maior tempo.V Em caso de extinção de serviço psicológico, o destino \ndos documentos deverá seguir as orientações definidas \nno Código de ética do psicólogo. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "E", "j": "Silva (2009) e Res CFP 01/2009: I — documentos da AP e material que os fundamentou guardados pelo prazo minimo de 5 anos (correto); II — responsabilidade do psicologo e da instituicao (correto); III — ampliacao por determinacao judicial (correto); IV — ampliacao em casos especificos (correto); V — em extincao do servico, seguir orientacoes do CEP (correto). Todos os 5 itens corretos. Gabarito E."}, {"id": "1299580", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  relação  à  validade  dos  conteúdos  dos  documentos \nsegundo Silva (2009), julgue os itens subsequentes. \nI  O  prazo  de  validade  do  conteúdo  dos  documentos \nescritos  decorrentes  das  avaliações  psicológicas  \ndeverá  considerar  a  legislação  vigente  nos  casos  já \ndefinidos.  \nII Em  todos  os  casos  de  documentos  de  perícia,  o \npsicólogo tem autonomia para determinar os prazos de \nvalidade. \nIII Em não havendo definição legal, o psicólogo, quando \nfor possível, indicará o prazo de validade do conteúdo \nemitido  no  documento em  função  das  características \navaliadas, das informações obtidas e dos objetivos da \navaliação. \nIV Ao  definir  o  prazo,  o  psicólogo  deverá  dispor  dos \nfundamentos para a indicação, devendo apresentá‐los \nsempre que solicitado. \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Silva (2009) sobre validade dos documentos: I correto (prazo conforme legislacao vigente nos casos definidos); III correto (sem definicao legal, o psicologo indica conforme caracteristicas avaliadas, informacoes obtidas, objetivos); IV correto (fundamentos disponiveis para apresentacao). Item II INCORRETO — em pericia, o psicologo nao tem autonomia 'em todos os casos' (ha normas processuais e prazos legais). Corretos: I, III, IV = 3. Gabarito D."}, {"id": "1298799", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  base  nos  conceitos  e  nas  abordagens  propostas  por \nGoulart e Sampaio (1998) sobre testes psicológicos e seu uso \nna POT, julgue os próximos itens.  \nI  Os  testes  de  personalidade  buscam  identificar \ncaracterísticas  mais  ou  menos  constantes  da \npersonalidade e podem ser subdivididos em sintéticos \n(que visam à personalidade como um todo) e analíticos \n(que visam a aspectos ou traços de personalidade).  \nII  Dados os fatores intervenientes nos resultados obtidos \npor testes (nervosismo, resistência etc.) que situariam \no  sujeito  em  uma  condição  diversa  da  que  ele \napresenta  cotidianamente,  os  psicólogos  trabalham \nvisando realizar um processo psicodiagnóstico, ou seja, \nos  resultados  obtidos  são  checados  entre  si  e \nconfrontados  com  outros  procedimentos  de  análise, \ncomo, por exemplo, a entrevista. \nIII  Independentemente  do  uso  que  alguns  profissionais \npossam  fazer  dos  testes  psicológicos,  eles  têm  por \nobjetivo,  principalmente,  evidenciar  as  diferenças \nindividuais  das  pessoas  que  são  testadas  em  uma \nsituação  de  controle  das  variáveis  que  possam \ninterferir na obtenção do objeto em avaliação.  \nIV  O teste psicológico pode ser compreendido como uma \nsituação  padronizada  que  serve  de  estímulo  a  um \ncomportamento por parte do examinando em questão, \nsendo  que  esse  comportamento  é  avaliado  por \ncomparação  estatística  com  o  de  outros  indivíduos \nsubmetidos à mesma situação, permitindo, assim, sua \nclassificação quantitativa e(ou) qualitativa. \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Goulart & Sampaio (1998) sobre testes na POT: I correto (testes de personalidade sao sinteticos ou analiticos); II correto (psicodiagnostico checa resultados entre si e com entrevista); III correto (objetivo principal: evidenciar diferencas individuais em situacao controlada); IV correto (teste como situacao padronizada com comparacao estatistica para classificacao quanti/qualitativa). Todos os 4 itens corretos. Gabarito E."}, {"id": "1298796", "d": "psicologia", "a": ["Motivação", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "As  teorias  de  motivação  no  trabalho  normalmente  se \npreocupam mais com as razões que com as habilidades que \nlevam certos indivíduos a realizar suas tarefas mais bem que \noutros. Dependendo da situação, essas teorias podem prever \nas escolhas de comportamento para a tarefa, o esforço ou a \npersistência  dessas  pessoas.  Por  isso,  algumas  teorias  de \nmotivação  partem  de  perspectivas  bastante  diferentes, \ndestacando‐se, entre elas, a  teoria da equidade. No que se \nrefere à teoria da equidade, assinale a alternativa correta.", "alt": {"A": "Concentra‐se  nos  valores  pessoais,  e  não  nas \nnecessidades,  nas  crenças e  nos  reforços. Essa  teoria \npresume  que  as  pessoas  valorizem  universalmente  a \njustiça em suas relações sociais no trabalho.", "B": "Preocupa‐se  com  as  coisas  que  as  pessoas  são \nmotivadas  a  alcançar,  como  seu  sustento  ou \nreconhecimento. Essa teoria classifica as necessidades \ndos  seres  humanos  em  um  pequeno  número  de \ncategorias.", "C": "Vê o comportamento como resultado de recompensas \nou reforços. Essa teoria descreve a motivação como o \nresultado de influências ambientais, e não de motivos \ngerados internamente.", "D": "Preocupa‐se em estudar como a crença das pessoas em \nsuas  próprias  habilidades  pode  afetar  seu \ncomportamento.  De  acordo  com  essa  teoria,  a \nmotivação para uma tarefa está relacionada ao fato de \na  pessoa  acreditar  ou  não  que  é  capaz  de  conclui‐la \ncom sucesso.", "E": "Explica  como  os  objetivos  e  as  intenções  pessoais \npodem levar a um determinado comportamento.  Essa \nteoria  entende  que  a  motivação  começa  no  próprio \nindivíduo, mas também demonstra como as influências \nambientais  podem  moldar  a  motivação  e  o \ncomportamento."}, "g": "A", "j": "Teoria da Equidade (Adams, 1965): foca em VALORES pessoais (especialmente justica/equidade nas relacoes sociais de trabalho), nao em necessidades. Alternativa A descreve corretamente. B descreve teorias das necessidades (Maslow); C descreve reforco/comportamentalismo (Skinner); D descreve autoeficacia (Bandura); E descreve teoria do estabelecimento de metas (Locke & Latham)."}, {"id": "1298792", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Conforme  Borges‐Andrade  et  al  (2006),  historicamente,  as \norganizações vêm desenvolvendo estratégias com o objetivo \nde  transformar  o  conhecimento  adquirido  pelos  indivíduos \nem  conhecimento  organizacional.  Entre  essas  estratégias, \ndespontam  a  socialização  e  a  codificação.  A  respeito  desse \ntema, julgue os itens a seguir. \nI O processo de  socialização pode  ser definido como o \nmeio por meio do qual a organização busca moldar, em \nníveis diversos, o indivíduo às suas necessidades. \nII  Os  processos  de  socialização  são  postos  em  marcha \npelas  organizações  no  sentido  de  difundir  o \nconhecimento  (tácito  ou  explícito)  entre  seus \nmembros,  de  modo  a  convertê‐lo  em  conhecimento \norganizacional. \nIII  A codificação do conhecimento refere‐se ao conjunto \ndos  diferentes  processos  para  formatar  o \nconhecimento tácito, como, por exemplo, em manuais, \nformatos  organizados,  software,  padrões,  projetos  e \nprocedimentos. \nIV  A aprendizagem de indivíduos nas organizações e sua \ntransformação  em  aprendizagem  organizacional \ndependem  da  variedade,  do  grau  de  interação  e  da \nintensidade de  uso  das  fontes internas e externas de \nconhecimento,  assim  como  da  variedade  e  da \nintensidade de uso e de interação entre os diferentes \nmecanismos de socialização e de codificação do que foi \naprendido pelos indivíduos nas organizações. \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Borges-Andrade et al. (2006) — socializacao e codificacao do conhecimento: I correto (socializacao molda individuo); II correto (difunde conhecimento tacito/explicito convertendo-o em organizacional); III correto (codificacao formata conhecimento tacito em manuais, software, padroes); IV correto (aprendizagem depende de variedade, interacao e intensidade de fontes). Todos os 4 itens corretos. Gabarito E."}, {"id": "1298787", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca do feedback no sistema de avaliação de desempenho \nde  pessoas  nas  organizações  de  trabalho,  julgue  os  itens \nsubsequentes.  \nI  Para que os funcionários melhorem e mantenham seu \ndesempenho  e  suas  habilidades,  eles  precisam  que \nseus  supervisores  lhes  deem  feedback  de  seu \ndesempenho no trabalho. \nII  Os  feedbacks  podem  ser  úteis  para  explicar  aos \nfuncionários  como  aprimorar  suas  habilidades  a  fim, \npor exemplo, de conquistar cargos mais elevados. \nIII  Até  mesmo  os  funcionários  que  tiverem  bom \ndesempenho  podem  aproveitar  os  feedbacks  \nrecebidos para melhorá‐lo, embora não necessitem de  \nrecebê‐los. \nIV  Os  funcionários  precisam  saber  quando  estão \napresentando  bom  desempenho,  para  que  possam \nmantê‐lo,  e  quando  não  mostram  desempenho \nsatisfatório, para que modifiquem seu procedimento. \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens III e IV estão certos.", "C": "Apenas os itens I, II e III estão certos.", "D": "Apenas os itens I, II e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Feedback na avaliacao de desempenho: I correto (feedback para melhorar/manter); II correto (feedback para conquistar cargos); IV correto (saber quando bom/insatisfatorio para manter ou modificar). Item III INCORRETO: AFIRMA que bons funcionarios 'nao necessitam' de feedback — pelo contrario, todos necessitam de feedback continuo para manter e aprimorar desempenho. Apenas I, II e IV."}, {"id": "1298783", "d": "psicologia", "a": ["Comunicação em Psicologia", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo Dubrin (2003), a comunicação é um fenômeno social \nque  afeta  indiscutivelmente  o  alcance  de  resultados \norganizacionais. Ao estudar tal fenômeno, percebe‐se que as \nmensagens  veiculadas  na  organização  passam  por  vários \ncanais  ou  caminhos  diferentes  e  estes  podem  ser \ncategorizados  pela  direção  que  seguem.  A  partir  dessa \nclassificação, julgue os itens a seguir. \nI  Os  canais  formais  de  comunicação  são  os  caminhos \noficiais para o envio de informações dentro e  fora da \norganização, sendo claramente especificados, em uma \norganização burocrática, em seus diversos níveis. \nII  Os canais de comunicação são mais fáceis de seguir na \nmoderna organização em rede, uma estrutura esférica \nque pode rotar equipes de trabalho autogerenciadas e \noutros  recursos  ao  redor  de  uma  base  comum  de \nconhecimento. \nIII  O  propósito  principal  da  organização em  rede é  criar \nalianças  temporárias  com  outras  empresas  para \ncapitalizar a combinação de talentos. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Dubrin (2003) sobre comunicacao: I correto (canais formais sao caminhos oficiais especificados em organizacao burocratica); III correto (organizacao em rede como aliancas temporarias para combinar talentos). Item II INCORRETO: os canais sao MAIS DIFICEIS de seguir na organizacao em rede (estrutura nao hierarquica), nao mais faceis — exige mapeamento de fluxos informais. Apenas I e III."}, {"id": "1298771", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo  Limongi‐França  (2008),  a  análise  da  pessoa  na \norganização  deve  ocorrer  não  só  a  partir  dos  processos \ntécnicos de trabalho, mas das condições de vida laboral, das \npráticas e dos valores de cada organização, dos significados \nvividos no trabalho e da legitimação de ações de desempenho \ne  produtividade.  A  respeito  dessa  temática,  julgue  os  itens \nseguintes. \nI  Todos se manifestam de maneira psicossomática, tanto \nno trabalho como em suas vidas. Têm potencialidades \ne  reações  biológicas,  psicológicas  e  sociais  que \nrespondem simultaneamente às condições de trabalho \ne  da  vida  em  geral.  Essas  respostas  apresentam \nvariadas combinações e intensidades nesses três níveis \n(ou  camadas)  e  as  manifestações  podem  ser  mais \nvisíveis e específicas em um ou outro aspecto, embora \ntodas  sejam  sempre  interdependentes.  Tal  conceito \nbiopsicossocial  propõe  uma  visão  integrada  do  ser \nhumano. \nII  Os estudos  sobre  psicossomática  no  trabalho  partem \nda  premissa  de  que  os  processos  corporais \n(decorrentes  da  atividade  de  trabalho)  influenciam \nmuito mais a dinâmica psíquica que o contrário. Assim, \nas  somatizações  caracterizam‐se  por  se  constituírem \nem  disfunções  psíquicas  (conteúdos  emocionais, \nestresse)  como  respostas  originadas  a  partir  das \nsensações  corporais,  tais  como  dores  generalizadas, \ndisfunções orgânicas e lesões de órgão. A somatização \nconsidera uma  total integração entre esses processos \nmentais e físicos no ambiente de trabalho.  \nIII  As  respostas  psicossomáticas  são  manifestações \nhumanas  decorrentes  de  impactos  na  dinâmica \nbiopsicossocial.  No  contexto  do  trabalho  em \norganizações, essas respostas psicossomáticas podem \nmobilizar  processos  simultâneos  e  interdependentes \nem busca de adaptação e equilíbrio interno e externo. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Limongi-Franca (2008) sobre psicossomatica no trabalho: I correto (manifestacao psicossomatica universal, biopsicossocial integrado); III correto (respostas psicossomaticas no trabalho mobilizam processos simultaneos e interdependentes). Item II INCORRETO: a psicossomatica defende INTEGRACAO TOTAL entre processos mentais e fisicos — NAO predominancia dos processos corporais sobre os psiquicos. Apenas I e III."}, {"id": "1298767", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  base  nos  pressupostos  de  Robbins  (1998)  sobre  a \nentrevista psicológica, julgue os próximos itens. \nI  Entre  todos  os  mecanismos  de  seleção  que  as \norganizações  usualmente  utilizam  para  diferenciar \ncandidatos  ao  trabalho,  a  entrevista  psicológica \ncostuma ser o recurso menos frequentemente usado e, \ngeralmente,  seus  resultados  tendem a possuir menor \npeso de influência na decisão de seleção.  \nII  A  entrevista  de  curta  duração,  causal  e  composta  de \nperguntas  aleatórias  provou‐se  um  mecanismo  de \nseleção  ineficaz.  Os  dados  coletados  nessas  breves \nentrevistas  são  geralmente  tendenciosos  e \nfrequentemente  não  relacionados  ao  futuro \ndesempenho no cargo. \nIII  É  mister  salientar  a  importância  do  papel  do \nentrevistador  nesse  método  de  seleção.  Os \nentrevistadores, se não possuírem formação adequada \ne  não  usarem  um  conjunto  padronizado  de \nprocedimentos,  tenderão  a  favorecer  candidatos  que \npartilhem  de  suas  atitudes,  dando  peso  excessivo  à \ninformação negativa e permitindo que a ordem na qual \nos  candidatos  sejam  entrevistados  influencie  as \navaliações.  \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Robbins (1998) sobre entrevista psicologica: II correto (entrevista breve/casual com perguntas aleatorias e ineficaz, dados tendenciosos); III correto (importancia do entrevistador treinado e procedimento padronizado para evitar vies de similaridade/ordem/info negativa). Item I INCORRETO: a entrevista e dos mecanismos de selecao MAIS frequentemente usados em organizacoes, com peso significativo (apesar de fraquezas psicometricas). Apenas II e III."}, {"id": "1298759", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "A  avaliação  pode  ser  realizada,  com  suas  respectivas \nfinalidades,  em  três  momentos  diferentes.  Considerando \nessa informação, julgue os próximos itens. \nI  Gerar conhecimentos sobre as experiências prévias do \naluno  em  relação  aos  novos  conteúdos  de \naprendizagem refere‐se à avaliação inicial.\nII  Identificar  estratégias,  erros  e  dificuldades  de \naprendizagem,  proporcionando  informações  que \npossam ajustar ou mudar a atuação educativa que se \nprocessa, diz respeito à avaliação formativa.\nIII  Observar os resultados das aprendizagens realizadas e \no  grau  de  alcance  dos  objetivos  educacionais \ncorresponde à avaliação somativa.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Avaliacao da aprendizagem (Coll, Zabala): I correto — AVALIACAO INICIAL (diagnostica) gera conhecimento sobre experiencias previas; II correto — AVALIACAO FORMATIVA identifica estrategias/erros e ajusta a atuacao educativa em processo; III correto — AVALIACAO SOMATIVA observa resultados ao final e o grau de alcance dos objetivos. Todos os itens corretos."}, {"id": "1298741", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  se  refere  à  história  da psicologia escolar,  julgue  os \nitens a seguir. \nI  Seu percurso histórico é posterior ao período formativo \nda psicologia, surgindo em meados da década de 1980.\nII  Surgiu  em  um  paradigma  de  quantificação  de \nfenômenos  psicológicos,  com  o  uso  de  testes  e \nintervenções clínicas.\nIII  Com  a  crítica  a  seus  momentos  iniciais,  passou  a  se \npreocupar  com  os  fatores externos  (sociais,  políticos, \ninstitucionais etc.) que produzem o fracasso escolar.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Historia da psicologia escolar: II correto (paradigma de quantificacao com testes nos primordios — psicometria/testagem); III correto (a partir dos anos 1980, criticas e foco nos fatores externos — sociopoliticos, institucionais — para entender fracasso escolar). Item I INCORRETO: a psicologia escolar nao surgiu nos anos 1980 — e contemporanea ao proprio surgimento da psicologia (final do seculo XIX, com Witmer; no Brasil, desde os primordios da profissao). Apenas II e III."}, {"id": "1298740", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito das transformações da psicologia como ciência e \nprofissão no Brasil e de suas repercussões para a organização \ndo currículo, assinale a alternativa incorreta.", "alt": {"A": "Nas  décadas  de  1960  e  1970,  os  currículos  eram \nvoltados  para  o  ensino  de  disciplinas  clínicas,  como \npsicoterapia e  psicodiagnóstico,  focadas  na  formação \ndo profissional liberal de consultório.", "B": "Nos períodos iniciais da psicologia como profissão no \nBrasil,  a  psicologia  escolar  era  voltada  para  o \ndiagnóstico  de  dificuldades  de  aprendizagem  e \ndeficiências intelectuais, com alocação de crianças para \nclasses especiais.", "C": "A  partir  da  década  de  1980,  ocorreu  uma  crítica  ao \nenfoque  do  fracasso  escolar  no  indivíduo,  gerando  a \nconstrução  de  novos  modos  de  pensar  a  psicologia \nescolar no Brasil.", "D": "Do final da década de 1990 até o início do ano 2000, os \ncurrículos baseavam‐se em núcleos comuns e ênfases, \nintegrados  em  habilidades  e  competências  a  serem \nconquistadas.", "E": "A  partir  do  final  da  primeira  década  dos  anos  2000, \nhouve uma tentativa de retorno ao currículo mínimo, \ncom enfoque na formação do profissional generalista."}, "g": "E", "j": "Curriculos de psicologia no Brasil: A (anos 60-70 clinico/profissional liberal), B (psicologia escolar inicial = diagnostico de dificuldades), C (criticas a partir dos anos 80) e D (DCNs do final dos 90/2000 com nucleos comuns e enfases) sao corretas. Alternativa E INCORRETA: nao houve 'retorno ao curriculo minimo' — as Diretrizes Curriculares Nacionais (2004 e 2011) propoem formacao generalista por competencias/habilidades, NAO o curriculo minimo do CFE 403/1962."}, {"id": "1298738", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia Jurídica", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Crianças e Adolescentes - Menores Infratores"], "ano": "2018", "org": "CFP", "t": "", "e": "Um  dos  campos  de  atuação  do  psicólogo escolar é  com  os \nadolescentes  que  cumprem  medidas  socioeducativas.  Em \nrelação a esse tema, julgue os itens subsequentes. \nI  As  estatísticas  apontam  que  os  adolescentes  que \ncometem atos infracionais estão, em sua maioria, nas \ncamadas  mais  vulneráveis  da  sociedade,  com \ndificuldades  de acesso às  necessidades e aos  direitos \nmais básicos.\nII  O fato de esses adolescentes sofrerem com exclusão e \nmarginalização explica e justifica o ato infracional. \nIII  Qualquer  trabalho  com  o  adolescente  em \ncumprimento  de  medidas  socioeducativas  deve  ser \niniciado  em  uma  relação  de  confiança,  fundamental \npara o diálogo.\nIV  É necessário conhecer a história do direito da criança e \ndo  adolescente,  assim  como  documentos  oficiais, \ncomo  o  Estatuto  da  Criança  e  do  Adolescente  (ECA), \npara a realização do trabalho.\nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Adolescentes em medidas socioeducativas: I correto (vulnerabilidade socioeconomica como contexto majoritario); III correto (relacao de confianca como fundamento do dialogo); IV correto (necessidade de conhecer ECA e historia do direito da crianca/adolescente). Item II INCORRETO: a exclusao EXPLICA mas NAO JUSTIFICA o ato infracional — distincao etica fundamental. Corretos: I, III, IV = 3."}, {"id": "1298734", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "A  cada  foco  de  atuação  do  psicólogo  escolar  pode \ncorresponder  um  conjunto  de  conhecimentos  necessários \npara o fazer da prática. Considerando essa informação, julgue \nos próximos itens. \nI  As implicações do fazer pedagógico relacionam‐se aos \nconhecimentos sobre as teorias do desenvolvimento e \nda aprendizagem. \nII  Ao  envolvimento  dos  pais  na  educação  dos  filhos \ncorrespondem  as  teorias  sobre  a  dinâmica  e  o \ndesenvolvimento das famílias. \nIII  Às  dimensões  psicológicas  no  ensino‐aprendizagem \ncorrespondem  as  teorias  dos  processos  cognitivos  e \nsuas alterações. \nIV  Os  sistemas  de  interações  nas  escolas  estão \nrelacionados  às  teorias  de  grupos,  papéis  e  atitudes \nsociais. \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Atuacao do psicologo escolar e bases teoricas: I correto (fazer pedagogico — teorias do desenvolvimento e aprendizagem); II correto (envolvimento dos pais — teorias da dinamica/desenvolvimento familiar); III correto (ensino-aprendizagem — teorias cognitivas); IV correto (interacoes nas escolas — teorias de grupos, papeis, atitudes). Todos os 4 itens corretos. Gabarito E."}, {"id": "1298370", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  às  intervenções  da  psicologia  da  saúde  para \nmaximizar a promoção da saúde, julgue os itens seguintes.  I O  desafio  é  dar  mais  ênfase  a  comportamentos  e \nfatores que favoreçam a saúde e que possam retardar \na mortalidade e reduzir a morbidade. \nII  Uma atenção maior precisa ser dada à forma como as \npessoas  resilientes  manejam  o  estresse,  mantêm  um \nforte  sentimento de controle  sobre  suas vidas e uma \natitude  positiva  e  otimista,  além  de  avaliar  se  tais \ncaracterísticas podem ser ensinadas a outras pessoas. \nIII Um  desafio  constante  para a  psicologia  da  saúde é a \ndocumentação da eficácia de suas intervenções. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Promocao da saude pela psicologia da saude: I correto (enfase em comportamentos que reduzam mortalidade/morbidade); II correto (estudo da resiliencia, controle, otimismo como caracteristicas ensinaveis); III correto (documentacao da eficacia das intervencoes como desafio constante). Todos os itens corretos."}, {"id": "1298366", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  às  influências  do  status  socioeconômico  da \npopulação na saúde e ao papel da psicologia da saúde nesse \nâmbito, é correto afirmar que", "alt": {"A": "as minorias e as  pessoas pobres  de  todas as etnias e \nraças geralmente tenham igual acesso ao atendimento \npreventivo de saúde.", "B": "um  dos  desafios  da  psicologia  da  saúde,  juntamente \ncom a Política Nacional, seja atingir o mesmo nível de \nacesso  a  serviços  de  saúde  preventiva  para  todas  as \npessoas.", "C": "minorias  que  tenham  acesso  limitado  a  atendimento \npreventivo  de  saúde  tendam  a  ter  um  número \ndesproporcionalmente menor de problemas de saúde \ne uma taxa alta de mortalidade.", "D": "o  sistema  de  saúde  permaneça  unificado,  apesar  das \ndiferenças  socioeconômicas  permitirem  que  certas \npessoas tenham acesso a um atendimento de saúde de \nqualidade e outros não.", "E": "a  reforma  do  sistema  de  saúde  seja  um  desafio  já \nvencido  para  a  psicologia  da  saúde  e  para  a  Política \nNacional."}, "g": "B", "j": "Sarafino sobre SES e saude: e desafio da psicologia da saude (com a Politica Nacional de Saude) atingir o MESMO NIVEL DE ACESSO a servicos preventivos para todas as pessoas, reduzindo desigualdades. Alternativa B reproduz essa premissa. A inverte (minorias NAO tem igual acesso); C inverte (menor acesso → MAIS problemas e maior mortalidade); D nega a iniquidade existente; E nega que reforma esteja pendente."}, {"id": "1298363", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Saúde Coletiva"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo documento expedido pela Associação Brasileira de \nPós‐Graduação  em  Saúde  Coletiva  (2006),  a  formação  na \nsaúde  que  se  conhece  hoje  é,  essencialmente,  acadêmica, \ndistante  da  realidade  do  País  e  não  implicada  com  a \ntransformação social. Essa constatação incentiva estratégias \nde  humanização  da  saúde,  nas  quais  a  psicologia  tem \nimportante  papel,  para alcançar  uma maior  qualificação  da \natenção e  da gestão em  saúde. No  que  se  refere à  Política \nNacional de Humanização, julgue os próximos itens. \nI A  Política  Nacional  de  Humanização,  de  forma \nresumida, consiste na construção/ativação de atitudes \nético‐estético‐políticas em sintonia com um projeto de \ncorresponsabilidade  e  qualificação  dos  vínculos \ninterprofissionais  e  destes  com  os  usuários  na \nprodução da saúde.  \nII É  uma  rede  de  construção  permanente  de  cidadania \nque implica uma mudança na cultura de atenção aos \nusuários e da gestão de processos de trabalho. \nIII  A  Política  Nacional  de  Humanização  supõe  um  novo \ntipo  de  interação  entre  os  sujeitos  e  nos  modos  de \ntrabalhar  em  equipe  porque  implica  produzir \n“cumplicidade” entre esses atores. \nIV Essa Política propõe que se olhe para cada sujeito como \nsujeito de um coletivo, recusando sua especificidade e \nse  afastando  da  perspectiva  orientada  por  uma \nconcepção biologizante e mecanizada da vida. \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Politica Nacional de Humanizacao: I correto (atitudes etico-estetico-politicas, corresponsabilidade); II correto (rede de construcao de cidadania); III correto (interacao com 'cumplicidade' entre sujeitos). Item IV INCORRETO: a PNH NAO recusa especificidade do sujeito — pelo contrario, valoriza singularidade enquanto integra o sujeito ao coletivo (clinica ampliada). Corretos: I, II, III = 3."}, {"id": "1298350", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo Benevides (2005), a contribuição e a interface entre \na  psicologia  e  o  SUS  pode  estar  no  entrecruzamento  do \nexercício  de  três  princípios.  Considerando essa  informação, \njulgue os seguintes itens. \nI De  acordo  com  o  princípio  da  inseparabilidade,  é \nnecessário compreender a psicologia como um campo \nde saber voltado aos estudos da subjetividade, sendo \nesta  entendida  como  um  processo  coletivo  de \nprodução. A  interface  da  psicologia  com  o  SUS  dá‐se \nexatamente  por  este  ponto,  considerando  que  os \nprocessos de subjetivação se deem no plano coletivo, \nno plano de multiplicidades e no plano público. \nII O princípio da autonomia e corresponsabilidade afirma \nque as práticas psicológicas devem ser imediatamente \ncomprometidas  com  o  mundo,  com  as  condições  de \nvida  da  população  brasileira,  com  o  engajamento  na \nprodução  de  saúde,  que  implique  a  produção  de \nsujeitos  autônomos,  protagonistas,  copartícipes  e \ncorresponsáveis por suas vidas. \nIII  Conforme o princípio da transversalidade, a psicologia \né  um  campo  de  saber  que  deve  ser  explicado  e \nconstruído na intercessão com outros saberes. É entre \nos saberes que a invenção acontece e os saberes têm \ncom o que contribuir para uma outra saúde possível.  \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Benevides (2005) — tres principios para interface psicologia-SUS: I — INSEPARABILIDADE (subjetividade como processo coletivo, sujeito-mundo); II — AUTONOMIA E CORRESPONSABILIDADE (praticas comprometidas com a producao de saude e sujeitos autonomos); III — TRANSVERSALIDADE (psicologia construida na interseccao de saberes). Todos os 3 itens corretos."}, {"id": "1298349", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Desde a implantação do Sistema Único de Saúde  (SUS), em \n1990, o campo da saúde pública no Brasil tem vivido inúmeras \ntransformações.  Para  a  psicologia,  inserir  e  manter  uma \npresença  qualificada  de  profissionais  no  SUS  tem  sido  um \ndesafio. Para colaborar com tal processo, Spink (2007) expõe \nem  seu  livro  A  psicologia  em  diálogo  com  o  SUS  algumas \npropostas  de  ação.  Com  base  nessa  informação,  assinale  a \nalternativa que não apresenta uma proposta útil para o tema.", "alt": {"A": "desconsiderar especificidades regionais na organização \ndos serviços de saúde", "B": "garantir uma formação para a saúde pública de forma \ntransversal, articulando política, teoria e prática", "C": "oferecer  mais  possibilidades  de  estágios  em \ninstituições públicas de saúde", "D": "estimular a prática da pesquisa no campo das políticas \npúblicas de saúde", "E": "estimular a produção de conhecimento como uma das \npráticas fundamentais na formação do psicólogo"}, "g": "A", "j": "Spink (2007) — A psicologia em dialogo com o SUS: as propostas uteis incluem formacao transversal (B), estagios em instituicoes publicas (C), estimular pesquisa em politicas publicas (D) e estimular producao de conhecimento (E). Alternativa A ('desconsiderar especificidades regionais') CONTRARIA as diretrizes do SUS (descentralizacao, regionalizacao) e nao e proposta valida — sendo a unica que NAO e proposta de Spink."}, {"id": "1298348", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Saúde Coletiva"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo Spink (2007), o fazer do psicólogo da saúde pública \ndeve  ser  objeto  de  reflexão  ao  se  pensar  a  respeito  da \nformação desse profissional. A prática acontece como parte \ndo  trabalho  em  saúde  coletiva,  que  apresenta  uma \nconfiguração  própria  e  peculiar.  A  respeito  desse  tema, \nassinale a alternativa incorreta.", "alt": {"A": "O  trabalho  em  saúde  coletiva  tem  como  objeto  a \nrelação dos indivíduos no território, sendo seu sujeito \num indivíduo inserido, em relação, na coletividade que \nhabita  esse  território.  Seu  processo  de  trabalho  é \nnecessariamente multiprofissional.", "B": "A  formação  do  psicólogo,  embora  já  tenha  sofrido \nalgumas mudanças, ainda constrói um profissional que \nlida com a queixa, a patologia, o cliente e sua verdade. \nEssa  configuração  estabelece  uma  dicotomia  para  o \npsicólogo na saúde pública, pois o cliente lhe apresenta \na  vida  em  toda  a  sua  complexidade,  com  todo  seu \nentorno.", "C": "O  foco  do  trabalho  é  a  enfermidade  do  sujeito.  O \npaciente  é  quem  busca  ou  necessita  de  cuidado  e  o \npsicólogo  oferece  um  saber  que  deve  se  centrar  na \ndoença do sujeito naquele momento.", "D": "A  exigência  da  saúde  coletiva  é  uma  clínica  que  se \namplie e amplie o objeto. A clínica ampliada leva em \nconta  a  interação,  o  conflito,  o  convívio  e  todo  o \nentorno do paciente.", "E": "Fazer clínica ampliada na saúde coletiva não é apenas \nlidar  com  a  interioridade  psicológica  do  sujeito,  mas \nlidar com a rede de subjetividade que o envolve."}, "g": "C", "j": "Spink (2007) sobre saude coletiva: A (objeto e relacao individuos no territorio, multiprofissional), B (formacao do psicologo ainda dicotomica), D (clinica ampliada) e E (rede de subjetividade) sao corretas. Alternativa C INCORRETA: o foco na saude coletiva NAO e a enfermidade do sujeito centrada na doenca — e a saude no territorio com clinica ampliada que considera o entorno. C contradiz as demais e a propria proposta de Spink."}, {"id": "1298339", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Os  psicólogos  da  saúde  trabalham  a  partir  da  perspectiva \nbiopsicossocial,  que  reconhece  que  forças  biológicas, \npsicológicas  e  socioculturais  agem  em  conjunto  para \ndeterminar  a  saúde  e  a  vulnerabilidade  de  um  indivíduo  à \ndoença.  Com  relação  a  esse  tema,  julgue  os  itens  que  se \nseguem.        \n  I No  contexto  biológico,  a  psicologia  da  saúde  chama \natenção para os aspectos do corpo que influenciam a \nsaúde  e  a  doença,  procurando  explicar  a  influência \nmútua entre biologia e comportamento.\n  II  No  contexto  psicológico,  a  mensagem  central  da \npsicologia  da  saúde  é  que  a  saúde  e  a  doença  estão \nsujeitas  às  influências  psicológicas.  Os  fatores \npsicológicos  têm  um  papel  importante  na \nvulnerabilidade  a  doenças,  no  tratamento  e  na \nmanutenção da saúde.\n  III  No contexto e na perspectiva sociocultural, a psicologia \nda  saúde  procura  compreender  e  atuar  sobre  a \nmaneira como os fatores sociais e culturais contribuem \npara a saúde e para doença.\n  IV  Na  perspectiva  sociocultural,  a  psicologia  da  saúde \nchama  a  atenção  para  o  fato  de  que  os  aspectos \nsocioculturais  têm  papel  importante  na  variação  de \ncrenças  sobre  a  saúde,  mas  não  influenciam  nos \ncomportamentos relacionados à saúde.    \n    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Modelo biopsicossocial (Engel; Sarafino): I correto (contexto biologico — influencia mutua biologia/comportamento); II correto (contexto psicologico — fatores psicologicos na vulnerabilidade, tratamento, manutencao); III correto (contexto sociocultural — fatores sociais/culturais como determinantes). Item IV INCORRETO: aspectos socioculturais influenciam TAMBEM os COMPORTAMENTOS relacionados a saude (estilos de vida, adesao), nao apenas as crencas. Corretos: I, II, III = 3."}, {"id": "1297705", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "A  Resolução  Contran  n.º  425/2012  prevê  a  utilização  de \ntécnicas  e  instrumentos  para  a  avaliação  psicológica  do \ncandidato. Com base nessa informação, julgue os itens que se \nseguem. \nI  Na  avaliação,  o  candidato  deverá  ser  capaz  de \napresentar,  entre  outras  características,  tomada  de \ninformação  –  detecção,  que  é  a  capacidade  de \nperceber  e  interpretar  os  estímulos  fracos  de \nintensidade ou após ofuscamento.\nII  Na  avaliação,  o  candidato  deverá  ser  capaz  de \napresentar,  entre  outras  características, \nprocessamento  de  informação  –  identificação \nsignificativa,  que  consiste  em  identificar  sinais  e \nsituações de trânsito.\nIII  Na  avaliação,  o  candidato  deverá  ser  capaz  de \napresentar,  entre  outras  características, \ncomportamento,  isto  é,  capacidade  para  perceber \nquando suas ações no  trânsito correspondem ou não \nao que pretendia fazer.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Res CONTRAN 425/2012, Anexo VIII (categorias da avaliacao psicologica para conducao): I — tomada de informacao/deteccao (perceber estimulos fracos ou apos ofuscamento); II — processamento da informacao/identificacao significativa (sinais e situacoes de transito); III — comportamento (perceber correspondencia entre acao e intencao). Todos os itens reproduzem a Resolucao. Gabarito E."}, {"id": "1297700", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo a Resolução CFP n.º 7/2003, a estrutura mínima de \num relatório psicológico é composta pelos seguintes pontos:", "alt": {"A": "descrição  da  demanda;  procedimento;  resultados; \nanálise qualitativa e quantitativa; e conclusão.", "B": "identificação;  exposição  de  motivos;  descrição  da \ndemanda; procedimento; e conclusão.", "C": "identificação;  descrição  da  demanda;  análise;  e \nconclusão.", "D": "identificação;  descrição  da  demanda;  procedimento; \nanálise; e conclusão.", "E": "descrição  da  demanda;  procedimento;  resultados;  e \nanálise."}, "g": "D", "j": "Res CFP 7/2003 (atual Res 06/2019): a estrutura minima do relatorio psicologico contem cinco itens — IDENTIFICACAO, DESCRICAO DA DEMANDA, PROCEDIMENTO, ANALISE e CONCLUSAO. Alternativa D reproduz exatamente. Demais alternativas omitem itens essenciais."}, {"id": "1297699", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "Julgue os próximos itens. \nI  Segundo  o  art.  21  do  Código  de ética  profissional  do \npsicólogo, são penalidades aplicadas para as infrações \ndisciplinares:  advertência;  multa;  censura  pública; \nsuspensão do exercício profissional por até trinta dias; \ne cassação do exercício profissional.\nII  Segundo  o  art.  21  do  Código  de ética  profissional  do \npsicólogo, são penalidades aplicadas para as infrações \ndisciplinares:  multa;  censura;  suspensão  do  exercício \nprofissional  por  até  sessenta  dias;  e  cassação  do \nexercício profissional.\nIII  Segundo  o  art.  21  do  Código  de ética  profissional  do \npsicólogo, são penalidades aplicadas para as infrações \ndisciplinares: advertência; censura pública; suspensão \ndo  exercício  profissional  por  até  noventa  dias;  e \ncassação do exercício profissional.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "CEP, art. 21: as penalidades sao advertencia; multa; censura publica; suspensao do exercicio profissional por ate 30 dias ad referendum do CFP; cassacao do exercicio profissional ad referendum do CFP. Item I reproduz fielmente. Item II erra (60 dias) e omite advertencia/multa. Item III erra (90 dias) e omite multa. Apenas I correto."}, {"id": "1297698", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  se  refere  à  guarda  de  documentos  psicológicos,  a \nResolução CFP n.º 7/2003 determina que", "alt": {"A": "os  documentos  escritos  decorrentes  unicamente  de \navaliação psicológica, bem como  todo o material que \nos  fundamentou,  deverão  ser  guardados  pelo  prazo \nmínimo de dez anos.", "B": "os  documentos  escritos  decorrentes  de  avaliação \npsicológica,  bem  como  todo  o  material  que  os \nfundamentou,  deverão  ser  guardados  pelo  prazo \nmínimo de cinco anos.", "C": "os atestados têm seu tempo de guarda definido em dez \nanos, com registro de informação complementar.", "D": "não  há  um  tempo  definido  de  guarda  do  material, \ncabendo  ao  profissional  defini‐lo  conforme  a \ncaracterística de sua atividade.", "E": "os laudos deverão ser guardados pelo prazo mínimo de \ncinco anos e os pareceres, por um ano."}, "g": "B", "j": "Res CFP 7/2003 (e atual Res 01/2009): os documentos escritos decorrentes de avaliacao psicologica, bem como todo material que os fundamentou, devem ser guardados pelo prazo MINIMO de 5 ANOS. Alternativa B reproduz a norma. A (10 anos) e errada; C (10 anos para atestados) idem; D (sem tempo definido) idem; E (laudos 5 / pareceres 1) idem."}, {"id": "1297561", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  deficiência  intelectual,  julgue  os  itens  que  se \nseguem. \nI  O  diagnóstico  ocorre,  geralmente,  durante  a \nadolescência e no início da idade adulta.  II  A avaliação engloba, essencialmente, a investigação do \nnível intelectual e do comportamento adaptativo. \nIII  Uma  dificuldade  enfrentada  durante  a  avaliação  é  a \nescassez de medidas que mantenham suas qualidades \npsicométricas  mesmo  nas  faixas  de  escores \nextremamente baixos. \nIV  É um transtorno de etiologia bastante específica. \nV  O  diagnóstico  diferencial  deve  descartar, \nprincipalmente, casos de transtornos da comunicação \ne de transtorno do espectro autista. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Deficiencia intelectual (DSM-5): I INCORRETO — o diagnostico ocorre durante o periodo do desenvolvimento (infancia/escolar), nao na adolescencia/idade adulta como regra; II correto (avalia nivel intelectual e comportamento adaptativo); III correto (escassez de medidas com qualidades psicometricas em escores extremamente baixos); IV INCORRETO (etiologia MULTIPLA — genetica, ambiental, perinatal — nao especifica); V correto (diagnostico diferencial com transtornos da comunicacao e TEA). Corretos: II, III, V = 3."}, {"id": "1297558", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  se  refere  aos  transtornos  específicos  da \naprendizagem (TEA), julgue os itens seguintes. \nI  Apresentam  um  curso  temporal  bastante  instável, \npodendo desaparecer naturalmente na medida em que \na criança se desenvolva. \nII A heterogeneidade neuropsicológica e a comorbidade \nentre os TEA constituem duas importantes questões a \nserem  investigadas  para  se  assegurar  a  validade \nnosológica. \nIII  Os TEA são, em sua essência, de origem genética. \nIV  As crianças com TEA tendem a responder rapidamente \nàs práticas de intervenção.Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens II e IV estão certos.", "D": "Apenas os itens III e IV estão certos.", "E": "Apenas o item IV está certo."}, "g": "B", "j": "Transtornos especificos da aprendizagem (DSM-5): II correto (heterogeneidade neuropsicologica e comorbidade sao questoes centrais para validade nosologica); III correto (origem genetica em sua essencia — herdabilidade alta para dislexia, discalculia, disgrafia). Item I incorreto — curso e PERSISTENTE, nao desaparece espontaneamente. Item IV incorreto — criancas com transtorno especifico de aprendizagem NAO respondem rapidamente; exigem intervencoes prolongadas. Apenas II e III."}, {"id": "1297165", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "A criança atua no mundo por meio de seus movimentos. Para \ntanto, precisa de que suas capacidades motoras, intelectuais e afetivas estabeleçam contato. Em uma criança de zero a seis meses de vida, não se espera a maturidade de", "alt": {"A": "executar a preensão de objetos de forma involuntária.", "B": "balbuciar.", "C": "sentar‐se com apoio.", "D": "começar a apontar os objetos.", "E": "segurar a mamadeira voluntariamente."}, "g": "D", "j": "Desenvolvimento de 0 a 6 meses: a crianca apresenta preensao reflexa/involuntaria (A), balbucio (B), senta com apoio aos ~6 meses (C) e comeca a segurar mamadeira voluntariamente proximo aos 5-6 meses (E). 'Apontar objetos' (D) emerge tipicamente entre 9-12 meses, NAO sendo esperado entre 0-6 meses."}, {"id": "1297162", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  das  teorias  em  psicologia  social,  julgue  os  itens \nseguintes. \nI  Há  uma  unidade  teórica e metodológica  com  relação \naos diferentes temas de análise. \nII  A  psicologia  sócio‐histórica  é  a  principal  teoria  que \norienta as práticas em psicologia social. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "E", "j": "Teorias em psicologia social: I incorreto — NAO ha unidade teorica/metodologica; a psicologia social e plural (cognitivista, socio-historica, construcionista, fenomenologica, psicanalitica). II incorreto — nao ha 'principal teoria' que oriente exclusivamente as praticas; a socio-historica e uma das vertentes, nao a unica nem necessariamente a principal. Nenhum item certo."}, {"id": "1297161", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere às noções de sujeito e subjetividade para a \npsicologia social, julgue os itens que se seguem. \nI  São  duas  categorias  importantes,  pois  expressam  a \nforma  como  os  indivíduos  configuram  o  vivido  e  se \nposicionam diante dos dilemas da vida. \nII  São  noções  delimitadas  em  uma  teoria  da  psicologia \nque  tem  feito esforços  para  que esses  conceitos  não \nsejam naturalizados.  \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "C", "j": "Sujeito e subjetividade na psicologia social: I correto — sao categorias centrais que expressam como individuos configuram o vivido e se posicionam diante dos dilemas. Item II incorreto — essas nocoes NAO sao delimitadas a 'uma teoria' da psicologia, sao construidas/disputadas em multiplas vertentes (socio-historica, gonzalez rey, construcionista, psicanalitica). Apenas I correto."}, {"id": "1297160", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação à ideia de psicologia como ciência e profissão, \njulgue os itens subsequentes.  \nI  É  importante  a  reflexão  crítica  tanto  com  relação  à \nprática  quanto  com  relação  às  teorias  para  o \ndesenvolvimento de um campo. \nII  É necessário não dissociar teoria e prática, assim como \nnão  dicotomizar  os  diferentes  campos  de atuação  da \npsicologia. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "A", "j": "Psicologia como ciencia e profissao: I correto (reflexao critica sobre pratica e teoria); II correto (nao dissociar teoria/pratica nem dicotomizar campos). Ambos os itens corretos e relacionados — afirmacoes complementares sobre a integracao entre ciencia, profissao e pratica reflexiva. Gabarito A."}, {"id": "1297159", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  à  psicologia  social  e  a  seus  contextos  e  práticas, \njulgue os itens a seguir. \nI  Duas  influências  estiveram  presentes  na  origem  da \npsicologia  social:  materialismo  cientificista  e \nindividualismo cartesiano. \nII  A  análise  de  diferentes  autores  e  teorias  evidencia \ndiferentes  concepções  de  social,  o  que  implica \ndiferentes formas de problematizar a prática. \nIII  A  psicologia  social  não  se  ocupa  dos  problemas  da \nescola,  pois  eles  dizem  respeito  a  questões  de \naprendizagem. \nIV  Em relação à prática do psicólogo social, é importante \nque ele reflita e atue sobre os problemas econômicos \ndo país. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens II e III estão certos.", "D": "Apenas os itens III e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Psicologia social: I correto — materialismo cientificista e individualismo cartesiano sao influencias historicas (Farr, Jaco-Vilela); II correto — diferentes autores/teorias geram diferentes concepcoes de 'social' e diferentes problematizacoes da pratica. Item III INCORRETO — a psicologia social SE OCUPA dos problemas escolares (medicalizacao, fracasso, exclusao). Item IV INCORRETO — o psicologo social pode refletir sobre problemas economicos, mas afirmar que 'deve atuar sobre os problemas economicos do pais' extrapola seu escopo profissional. Apenas I e II."}, {"id": "1297158", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca da relação da psicologia social com outros campos, é \ncorreto afirmar que", "alt": {"A": "a psicologia social se expresse em diferentes campos e \nnão esteja dissociada da psicologia em termos gerais.", "B": "as  políticas  públicas  limitem  a  dimensão  política  da \nação profissional do psicólogo.", "C": "a  intervenção  em  contextos  de  violência  deva  ser \npautada  por  teorias  que  especificamente  discutam \nesse tema.", "D": "a psicologia social, em razão de seu objeto de estudo, \ntenha mais articulações com a psicologia da saúde.", "E": "seja necessário, em saúde mental, ter clareza quanto a \ndiagnósticos de transtorno."}, "g": "A", "j": "Psicologia social e outros campos: A correta — a psicologia social se expressa em diferentes campos (educacional, saude, juridica, organizacional) sem se dissociar da psicologia em termos gerais. B inverte (politicas publicas potencializam, nao limitam, dimensao politica); C restringe indevidamente; D nao prioriza saude; E confunde com psicopatologia."}, {"id": "1297156", "d": "psicologia", "a": ["Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Psicologia Jurídica", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Papéis Sociais e Relações de Gênero"], "ano": "2018", "org": "CFP", "t": "", "e": "Os serviços de atendimento a mulheres vítimas de violência \ntêm algumas especificidades. Com relação a esse tema, julgue \nos próximos itens. \nI  É  importante  traçar  metas  de  diagnóstico  para \ncompreender a real situação. Deve‐se analisar a família \nda pessoa e fazer encaminhamento para um abrigo. \nII  Deve  realizar  ações  que  se  pautem  pelo \nreconhecimento  da  mulher  como  sujeito  e  \nencaminhá‐la para psicoterapia de casal. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "E", "j": "Atendimento a mulheres vitimas de violencia: I incorreto — 'analisar a familia e encaminhar para abrigo' como conduta padrao distorce a abordagem (cada caso deve ser singularizado; nao se 'analisa a familia' de modo abstrato); II incorreto — em violencia domestica, a PSICOTERAPIA DE CASAL e CONTRAINDICADA pela literatura especializada (risco de revitimizacao). Nenhum item certo. Gabarito E."}, {"id": "1297155", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "O  conceito  de  práticas  discursivas  é  importante  para  a \npsicologia  social.  Considerando  essa  informação,  é  correto \nafirmar que", "alt": {"A": "sua utilização e conceitualização apareça com força na \npsicanálise pela necessidade do estudo da associação \nlivre.", "B": "as  práticas  discursivas  impliquem  a  produção  de \nsentidos  que  se  organizem  a  partir  de  processos \nindividuais, e não coletivos.", "C": "se procure entender, na pesquisa, como as diferentes \nemoções constituem processos individuais diversos.", "D": "seja  importante  reconhecê‐las  como  produções \nconjuntas,  construções  sociais,  ao  se  analisar  as \npráticas discursivas.", "E": "o  conceito  de  representações  sociais  seja \nepistemologicamente  coerente  com  o  conceito  de \npráticas discursivas."}, "g": "D", "j": "Praticas discursivas (Spink, Iniguez, Foucault): sao PRODUCOES CONJUNTAS, construcoes SOCIAIS — o sentido emerge na interacao, nao em processos individuais. Alternativa D reproduz essa premissa. A localiza erroneamente na psicanalise (associacao livre); B atribui a processos individuais; C reduz a emocoes individuais; E afirma coerencia com representacoes sociais (que tem epistemologias distintas)."}, {"id": "1297154", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "González Rey desenvolveu a categoria subjetividade social e \nexplicitou sua importância para a psicologia social. A respeito\ndessa temática, é correto afirmar que", "alt": {"A": "a subjetividade seja um sistema abstrato e impessoal; \nnesse  aspecto,  possibilita  compreender  as  diferentes \nfacetas dos processos humanos.", "B": "o  conceito  de  subjetividade  individual  seja \ndesnecessário  para  a  compreensão  da  subjetividade \nsocial.", "C": "a subjetividade social se expresse por meio de sujeitos \nconcretos  que  vivenciem  problemas  relacionados  à \nexclusão social.", "D": "seja  uma  categoria  que  reforça  a  fragmentação  dos \ndiferentes campos da psicologia social.", "E": "o conceito de subjetividade social tenha como objetivo \nexplicar  a  complexidade  de  funcionamento  dos \nespaços sociais."}, "g": "C", "j": "Gonzalez Rey — Subjetividade Social: expressa-se por SUJEITOS CONCRETOS que vivenciam problemas reais (como exclusao social) em contextos historicos especificos. Alternativa C reproduz essa premissa. A absolutiza/abstrai; B descarta subjetividade individual (na verdade Gonzalez Rey articula individual e social); D inverte (integra, nao fragmenta); E reduz a 'explicacao de espacos sociais', sem o ancoramento no sujeito concreto."}, {"id": "1297152", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2018", "org": "CFP", "t": "", "e": "Exclusão  é  tema  da  atualidade,  usado \nhegemonicamente  em  diferentes  áreas  de  conhecimento, \nmas pouco preciso e dúbio do ponto de vista ideológico.  Sawaia, 2002.  \nQuanto a esse assunto, assinale a alternativa correta.", "alt": {"A": "Os excluídos não são simplesmente rejeitados  física e \ngeograficamente, mas de todas as riquezas espirituais, \numa vez que seus valores não são reconhecidos.", "B": "A exclusão é o resultado de um processo de construção \nsocial  e  histórico  e  é  determinada  pelos  processos \neconômicos.", "C": "É  um  conceito  “mala”  ou  “bonde”,  pois  possibilita \nexplicar os vários fenômenos que se expressam nesse \nprocesso.", "D": "É um estado que envolve os indivíduos e suas relações \ncom  o  outro.  É  uma  falha  no  sistema  e  deve  ser \ncombatida como algo que perturba a ordem social.", "E": "A  exclusão  pode  ser  tomada  nas  sociedades \ncontemporâneas  como  uma  nova  manifestação  dos \nproblemas individuais."}, "g": "C", "j": "Sawaia (As artimanhas da exclusao, 2002): conceitua a exclusao como CONCEITO 'MALA' OU 'BONDE' — categoria ampla e dubia que carrega/explica multiplos fenomenos heterogeneos, justamente por sua imprecisao. Alternativa C captura essa critica de Sawaia. A (exclusao espiritual) e parcial; B (so economica) reduz; D (falha do sistema, perturba ordem) inverte — Sawaia mostra que a exclusao e PRODUZIDA pela ordem social, dialeticamente; E reduz a problemas individuais."}, {"id": "1297151", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  psicologia  social  na  América  Latina,  é  correto \nafirmar que", "alt": {"A": "seja  importante  um  modelo  que  tenha  viabilidade  e \naplicabilidade  apenas  em  termos  regionais,  pois  sua \nespecificidade é grande.", "B": "seu  objeto  não  seja  univocamente  definido  e \ndeterminado,  mas  constitua‐se  a  partir  de  processos \nsociais  e  culturais  peculiares  às  diversas  realidades \nlatino‐americanas.", "C": "a  psicologia  da  libertação  de  Mead  seja  um  esforço \npara  problematizar  as  condições  adversas  das \npopulações latino‐americanas.", "D": "as  condições  econômicas  e  sociais  sejam  fatores  que \nnão  interfiram  nas  pesquisas,  pois  dizem  respeito  a \noutro campo de atuação.", "E": "alguns  teóricos afirmem que se sofre de colonialismo \nepistemológico  em  razão  da  pouca  visibilidade  da \nteoria das representações sociais."}, "g": "B", "j": "NOTA SISTEMICA: todas as 20 questoes do lote 030 tem gab_candidato=C — erro evidente de importacao da fonte. Tecnicamente: a alternativa correta e B — 'o objeto da psicologia social na America Latina nao e univocamente definido, constituindo-se a partir de processos sociais e culturais peculiares as diversas realidades latino-americanas' (Martin-Baro, Lane, Montero). A alternativa C atribui erroneamente a 'psicologia da libertacao' a MEAD — quando o criador e IGNACIO MARTIN-BARO. CORRIGIDO para B."}, {"id": "1297149", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  diz  respeito  ao  conceito  de  subjetividade desenvolvido por González Rey, é correto afirmar que", "alt": {"A": "seja  um  processo  intrapsíquico  e  expresse  a  forma \ncomo os indivíduos se sentem no mundo.", "B": "seja  um  sistema  racional  e  que  sua  forma  de \norganização esteja subordinada à  razão humana e ao \ncomportamento social.", "C": "seja uma categoria importante para a psicologia, pois \npossibilita  compreender  a  forma  como  ocorre  o \ndesenvolvimento humano.", "D": "seja  um  sistema  complexo  que  tem  dois  espaços  de \nconstituição:  individual  e  social,  configurados \nreciprocamente.", "E": "o  trabalho  do  psicólogo  social  esteja  centrado  na \nsociedade e, por isso, não se ocupe da subjetividade."}, "g": "D", "j": "Subjetividade em Gonzalez Rey: sistema complexo que tem DOIS espacos de constituicao — INDIVIDUAL e SOCIAL — configurados reciprocamente. Alternativa D reproduz essa definicao. A reduz a intrapsiquico; B subordina a razao; C e generica; E nega ocupacao com subjetividade. CORRIGIDO para D (gab_candidato C esta errado)."}, {"id": "1297148", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito da psicologia social, julgue os itens que se seguem.     I  Quando  a  psicologia,  em  razão  da  guerra,  iniciava‐se  nos  Estados  Unidos,  era  uma  psicologia  fisiológica.  Quando  transpôs  essa  barreira,  tornou‐se  psíquica,  imaterial,  mental,  mas  permaneceu,  contudo,   absolutamente individual, não conseguindo incorporar  o social.   II  Mead sistematizou a primeira síntese dialética entre o  individual e  o  social e entre  o  biológico e  o  psíquico.  Pensou o instinto como base da vida em sociedade e  admitiu a realidade do simbólico; essa síntese seria o   self.   III  O social pode ser definido como a soma do individual,  isto  é,  o  coletivo.  Dessa  forma,  o  social  configura‐se  pela força que o individual expressa na sociedade.   IV  Em  meados  do  século  XX,  os  chamados  “trabalhos  comunitários”,  no  Brasil  e  na  América  Latina,  eram  dirigidos  aos  setores  populares  e  aos  grandes  contingentes  de  migrantes,  tendo  o  intuito  de    adaptá‐los, inseri‐los ou adequá‐los às novas condições  de moradia, trabalho e convivência urbanos.   V  A criação oficial da Associação Brasileira de Psicologia  Social (ABRAPSO), em 1980, fortaleceu a aproximação  e o comprometimento da psicologia e, em especial, da  psicologia social comunitária.     A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "D", "j": "Sobre psicologia social: I correto (psicologia americana inicial era fisiologica e tornou-se mental mas permaneceu individual); II correto (Mead sistematizou primeira sintese dialetica individual-social/biologico-psiquico no conceito de self); IV correto (trabalhos comunitarios em meados do seculo XX dirigidos a setores populares e migrantes); V correto (ABRAPSO criada em 1980 fortaleceu psicologia social comunitaria). Item III INCORRETO (social NAO e soma do individual). Corretos: I, II, IV, V = 4. CORRIGIDO para D."}, {"id": "1297145", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Diferentes teóricos discutem o que implica pensar a ideia de \nsocial  na  psicologia.  Com  relação  esse  assunto,  é  correto \nafirmar que", "alt": {"A": "o  social  seja  um  fato  natural  fundado  sobre  o  senso \ncomum  e  a  vida  em  sociedade  e,  por  ser  um  objeto \nnatural, deva ser estudado pela psicologia social.", "B": "o  social  seja  uma  evidência  e,  portanto,  se  constitua \ncomo elemento a ser considerado para a compreensão \nde processos humanos.", "C": "o  social  tenha  dimensão  histórica  e  cultural  que  o \nconfigure e implique diferentes processos tanto sociais \nquanto individuais.", "D": "as  aproximações  da  psicologia  em  direção  ao  social \ndevam  contribuir  para  novas  formas  de  regulação do \ncomportamento.", "E": "o  social  deva  ser  individualizado  para  ser \ncompreendido."}, "g": "C", "j": "Sobre o social na psicologia: alternativa C correta — 'o social tem dimensao historica e cultural que o configure e implique diferentes processos tanto sociais quanto individuais'. Captura a tese socio-historica (Vygotsky, Lane). A (fato natural) e reificacao; B (evidencia) e superficial; D (regulacao do comportamento) e behaviorista; E (individualizado) e contradicao. Confirmado."}, {"id": "1297144", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "A  respeito  das  reflexões  de  Martin  Baró  sobre  o  papel  do  psicólogo, julgue os itens que se seguem.      I  O saber mais importante do ponto de vista psicológico  não é o conhecimento explícito e  formalizado, mas o  saber inserido na práxis cotidiana.     II  Na psicologia, deve‐se assumir o trabalho de eliminar  ou controlar os mecanismos da identidade pessoal.     III  O  psicólogo  deve  mudar  as  estruturas  econômicas  a  partir da conscientização.     Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Martin-Baro sobre o papel do psicologo: I correto — 'o saber mais importante psicologicamente nao e o conhecimento explicito e formalizado, mas o saber inserido na praxis cotidiana' (premissa central da psicologia da libertacao). Item II INCORRETO — Martin-Baro nao defende 'eliminar/controlar mecanismos da identidade pessoal' (pelo contrario, valoriza identidade autoctone). Item III INCORRETO — Martin-Baro fala em conscientizacao para libertacao, nao em o psicologo 'mudar estruturas economicas'. Apenas I. CORRIGIDO para B."}, {"id": "1297143", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação à psicologia social, julgue os itens seguintes.     I  É  um  campo  coeso  em  que  as  diferentes  correntes  teóricas têm em comum a preocupação em elaborar as  melhores estratégias de intervenção comunitária.     II  O tema geral de suas análises está centrado na forma  como  um  conjunto  de  práticas  produz  formas  de  subjetivação.     III  É  um  campo  de  aplicação  de  diferentes  testes  de  análise dos processos sociais.      Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Sobre psicologia social: I INCORRETO (NAO e campo coeso — e plural); II correto — 'tema centrado em como praticas produzem formas de subjetivacao' (Foucault, Spink, construcionismo); III INCORRETO (nao e aplicacao de testes). Apenas II correto. Gabarito C confirmado."}, {"id": "1297142", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  psicologia  social  cognitiva,  julgue  os  itens  subsequentes.     I  A  teoria  da  atribuição  de  causalidade  tem  apontado  que os indivíduos  tendem a explicar os  resultados de seus  comportamentos  com  realização  positiva  e  negativa.     II  A  teoria  da  atribuição  representa  um  interessante  corpo teórico para analisar as explicações causais que  as pessoas elaboram a respeito dos eventos e de como  essas  atribuições  causais  influenciam  expectativas   futuras, o autoconceito e a autoestima.     Assinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "A", "j": "Teoria da atribuicao causal (Weiner, Heider): I correto — individuos explicam resultados de seus comportamentos com realizacao positiva e negativa; II correto — atribuicoes causais influenciam expectativas futuras, autoconceito e autoestima. Ambos itens corretos e RELACIONADOS (II detalha o que I afirma). CORRIGIDO para A."}, {"id": "1297141", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  a  atitudes  e  à  comunicação,  duas  categorias  clássicas da psicologia social cognitivista, julgue os próximos itens.     I  São  estáveis  e,  depois  de  instaladas,  raramente  mudam.  Para  sua  mudança,  dependem  de  que  seus  componentes sejam fortemente afetados, produzindo  dissonância suficiente para alterar crenças.   II  Trata‐se  de  um  fenômeno  contemporâneo  da  maior  importância que afeta a relação dos grupos de  forma  substancial.  Seus  efeitos  podem  produzir  efeitos  nas  relações  interpessoais  e  seus  princípios  são  muito   utilizados  para  influenciar  comportamentos  sociais.  É  um fator importante de produção de dissonâncias.     Assinale a alternativa correta.", "alt": {"A": "O item I refere‐se à comunicação e o item II a atitudes.", "B": "O item I refere‐se a atitudes, mas o item II não se refere \nà comunicação.", "C": "O  item  I  refere‐se  a  atitudes  e  o  item  II  refere‐se  à \ncomunicação.", "D": "O item II refere‐se a atitudes, mas o item I não se refere \nà comunicação.", "E": "As ideias apresentadas nos itens I e II não se referem \nnem à comunicação nem a atitudes."}, "g": "C", "j": "Atitudes (item I) e Comunicacao (item II) na psicologia social cognitivista: I descreve ATITUDES (estaveis, raramente mudam, dissonancia cognitiva para alterar — Festinger); II descreve COMUNICACAO (fenomeno que afeta grupos, influencia comportamentos, produz dissonancias — Hovland, McGuire). Alternativa C 'I refere-se a atitudes e II a comunicacao' esta correta. Confirmado."}, {"id": "1297139", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "A especialização em psicologia social tornou‐se necessária se   se considerar que os psicólogos sociais estejam cada vez mais   presentes no cotidiano do trabalho profissional da psicologia.   Com base nessa informação, julgue os itens a seguir.    I  A  inserção  do  trabalho  do  psicólogo  no  sistema  de  assistência social é fator importante de atuação desse  profissional no cotidiano da população.     II  Os CAPS são equipamentos de atenção à saúde mental  em que o psicólogo exerce uma função que se beneficia  de sua qualificação no campo da psicologia social.     III  A psicologia social comunitária é um grande campo de  atuação  dos  psicólogos  sociais,  mas  não  seu  campo   exclusivo, como ocorre com outros setores de inserção  desse profissional que têm atividade multidisciplinar.     IV  Um  campo mais  raro, mas  conhecido,  de atuação  do  psicólogo social é o da análise qualitativa de pesquisas de mercado e da avaliação de peças publicitárias, em  que  o  conhecimento  dos  métodos  e  das  teorias  da  psicologia social é extremamente útil.     A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Especializacao em psicologia social: I correto (insercao no SUAS); II correto (CAPS como campo de atuacao); III correto (psicologia social comunitaria e grande campo mas nao exclusivo, contexto multidisciplinar); IV correto (pesquisa de mercado/peca publicitaria como campo conhecido, ainda que mais raro). Todos os 4 itens corretos. CORRIGIDO para E."}, {"id": "1297138", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Bock,  Furtado  e  Gonçalves,  em  momentos  diferentes, \npostularam o conceito de dimensões subjetivas da realidade. \nTrata‐se de um conceito sócio‐histórico que aponta que", "alt": {"A": "a  subjetividade  social  pode  ser  quantificada \nexperimentalmente.", "B": "a  realidade,  para  a  psicologia  sócio‐histórica,  é  multideterminada  e,  portanto,  não  é  facilmente  capturada.", "C": "falar de dimensões subjetivas faz referência ao campo  do simbólico, do real e do imaginário.", "D": "há um padrão na produção desses autores, que vai da  multideterminação do sujeito às medidas da realidade.", "E": "dimensões  subjetivas  supõem que haja outra medida  da  realidade,  que  é  a  objetiva,  e  ela  esteja  dialeticamente relacionada com a subjetiva, formando   uma unidade."}, "g": "E", "j": "Dimensoes subjetivas da realidade (Bock, Furtado, Goncalves): a dimensao subjetiva supoe outra medida da realidade, a OBJETIVA, dialeticamente relacionada com a subjetiva, formando UMA UNIDADE (perspectiva socio-historica). Alternativa E reproduz exatamente. C ('simbolico, real, imaginario') e categoria lacaniana, nao socio-historica. CORRIGIDO para E."}, {"id": "1297137", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Um  dos  desafios  centrais  do  desenvolvimento  da \npsicologia  social  é  elaborar  modelos  de  conhecimento \nsuscetíveis de conceituar essas tramas complexas e sutis da \nsubjetividade social e de comprometer‐se com a crítica como \nmomento  permanente  e  necessário  da  configuração  de \nqualquer ordem social. As ciências sociais deixariam de sê‐lo \nse se convertessem em espaços apologéticos e domesticados \nde  qualquer  ordem  estabelecida,  o  que  não  significa  a \nanarquia,  e  sim  o  exercício  da  crítica  como  espaço  de \ndesenvolvimento. \nF. González Rey. O social na psicologia e a psicologia \nsocial: a emergência do sujeito. Petrópolis: \nVozes, 2004 (com adaptações). \nCom base no texto acima, assinale a alternativa correta.", "alt": {"A": "A subjetividade social é sutil o suficiente para evitar os \nconflitos,  permitindo  sua  captura  pelos  espaços \napologéticos e domesticados das ciências sociais.", "B": "A  psicologia  social  enfrenta  um  dilema,  que  é  a \nelaboração  de  conhecimentos  com  potencial  para \nconceituar  as  tramas  complexas  e  sutis  da \nsubjetividade social.", "C": "A  psicologia  social,  de  acordo  com  a  teoria  \nhistórico‐cultural,  não  tem  instrumentos  críticos  para \nconceituar a subjetividade social.", "D": "A  subjetividade  social  é  derivada  da  subjetividade \nindividual  e,  portanto,  é  suscetível  a  toda  a \nvariabilidade característica do ser humano.", "E": "Não é possível  o  trabalho  crítico com a  subjetividade \nsocial  do  ponto  de  vista  das  ciências  sociais,  já  que \nestas  são  necessariamente  espaços  apologéticos  e \ndomesticados."}, "g": "B", "j": "Gonzalez Rey (O social na psicologia, 2004): o texto-base afirma que e desafio da psicologia social elaborar modelos para conceituar tramas complexas e sutis da subjetividade social, comprometendo-se com a critica. Alternativa B reproduz fielmente: 'a psicologia social enfrenta um dilema — a elaboracao de conhecimentos com potencial para conceituar as tramas complexas e sutis da subjetividade social'. C nega instrumentos criticos a teoria historico-cultural (oposto da tese). CORRIGIDO para B."}, {"id": "1297136", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2018", "org": "CFP", "t": "", "e": "O movimento da luta antimanicomial completou trinta anos  no mês de dezembro de 2017 e comemorou com um grande  evento  em  Bauru  (SP),  cidade  que  sediou  o  primeiro  encontro. O evento é muito atual em razão da  tentativa de   retrocesso promovida pelo Ministério da Saúde com portarias  que incluem os manicômios na rede de atenção psicossocial  (RAPS),  aumentando  o  valor  remunerado  e  contrariando  a  conhecida  Lei  Paulo  Delgado,  um  dos  marcos  da  reforma  psiquiátrica. Acerca desse assunto, julgue os itens seguintes.     I  Nos  últimos  anos,  a  consolidação  da  reforma  psiquiátrica brasileira levou à expansão da RAPS, com  milhares de centros de atenção psicossocial (CAPS) em todo o Brasil e a diminuição dos leitos psiquiátricos em  manicômios.   II  O  Programa  de  Volta  para  Casa  retirou  milhares  de  moradores  dos  hospitais  psiquiátricos,  devolvendo  a  eles  a  condição  de morar  em  liberdade,  nas  cidades,  nos  chamados  serviços  residenciais  terapêuticos,   presentes em muitos municípios brasileiros.     Assinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "A", "j": "Luta antimanicomial e reforma psiquiatrica: I correto (RAPS expandiu com CAPS em todo o Brasil; leitos psiquiatricos diminuiram); II correto (Programa De Volta para Casa retirou moradores dos hospitais psiquiatricos, devolvendo direito de morar em liberdade nos servicos residenciais terapeuticos — Lei 10.708/2003). Ambos certos e RELACIONADOS (sao processos da mesma reforma). CORRIGIDO para A."}, {"id": "1297135", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Tendo  em  vista  a  diversidade  do  ser  humano,  as  políticas  públicas  e  as  práticas  psicológicas  não  podem dispensar,  também,  uma  discussão  ontológica  e  epistemológica  sobre  sujeito  e  realidade,  que  norteiam  as v  ações que constituem suas intervenções.      Strey, Azambuja e Jaeger. Violência, gênero e políticas públicas.    Porto Alegre: EDIPUCRS, 2004. p. 190 (com adaptações).      Com base no texto acima, assinale a alternativa correta.", "alt": {"A": "A diversidade do ser humano impede que se encontre \numa única solução para seus conflitos.", "B": "Políticas  públicas  e  práticas  psicológicas  devem  considerar a diversidade do ser humano e, para tanto,  devem enfrentar uma discussão de caráter ontológico   e epistemológico para definir suas intervenções.", "C": "A  raiz  onto  refere‐se  a  ser  e  a  episteme,  a  conhecimento. Assim, o texto busca marcar a diferença  entre sujeito e realidade e, apontando a diversidade do   ser, considera impossível seu conhecimento.", "D": "Políticas  públicas  geralmente  são  pensadas  do  ponto  de vista eleitoral e não levam em consideração os reais interesses  dos  usuários  desses  serviços,  que  são  relegados a um plano unidimensional, que não leva em consideração sua diversidade", "E": "Sujeito  e  realidade  norteiam  as  intervenções \nprofissionais,  mas  falta  a  esses  sujeitos  e  a  essa \nrealidade uma discussão de caráter ontológico (sujeito) \ne epistemológico (realidade)."}, "g": "B", "j": "Strey, Azambuja & Jaeger (2004): o texto-base afirma que politicas publicas e praticas psicologicas devem considerar a diversidade do ser humano e enfrentar discussao ontologica (sobre o ser/sujeito) e epistemologica (sobre o conhecimento/realidade) para nortear suas intervencoes. Alternativa B reproduz fielmente. C inverte ao concluir 'impossivel seu conhecimento'. CORRIGIDO para B."}, {"id": "1297134", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2018", "org": "CFP", "t": "", "e": "Bader  Sawaia  é  conhecida  pela  discussão  sobre  exclusão  e  desenvolve  o  conceito  de  sofrimento  ético‐político,  que  ajuda  a  compreender a  dialética da  relação  pobreza‐riqueza. Sawaia  considera que  o binômio exclusão‐inclusão  não  ocorra  de  forma  isolada, mas de forma articulada e, dependendo do referencial que se adote, formas de exclusão e exploração possam ocorrer   mesmo entre pessoas que vivem em situação de vulnerabilidade. A partir dessas informações, é correto afirmar que", "alt": {"A": "a dialética exclusão‐inclusão se refira às cotas raciais e considere que muitas vezes os beneficiados possam ser mais ricos  que outros que não conseguiram as cotas.", "B": "o termo ético‐político se refira à situação que se vive hoje no País e aponte para uma melhor escolha de parlamentares e  dirigentes, considerando que, em última instância, as pessoas são responsáveis por seus votos.", "C": "haja uma clara relação entre o sofrimento ético‐político e as formas de inclusão, pois, em geral, as crises éticas ocorrem entre os que são mais beneficiados.", "D": "o  sofrimento  ético‐político  se  refira  à  condição  daquele  que  passa  por  humilhação  e  sofrimento  em  sua  condição  de  excluído;  nesse  caso,  trata‐se  de  sofrimento  psíquico.  O  slogan  de  um  cartaz  de  direitos  humanos  do  CFP  traduzia  perfeitamente essa posição de Sawaia: “preconceito humilha e humilhação faz sofrer”.", "E": "a dialética exclusão‐inclusão possa trazer como consequência o sofrimento ético‐político e isso ocorra quando pessoas em  condições sociais de desvantagem resolvem enfrentar a diversidade, aceitando ajuda de políticos clientelistas e de pouco caráter."}, "g": "D", "j": "Bader Sawaia (As artimanhas da exclusao) — sofrimento etico-politico: refere-se a condicao daquele que passa por humilhacao e sofrimento em sua condicao de excluido, sendo SOFRIMENTO PSIQUICO produzido pela exclusao social. O slogan 'preconceito humilha e humilhacao faz sofrer' (cartaz CFP) traduz essa posicao. Alternativa D reproduz exatamente. C inverte (sofrimento entre 'mais beneficiados'). CORRIGIDO para D."}, {"id": "1297133", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Saúde da Família"], "ano": "2018", "org": "CFP", "t": "", "e": "Desde que as políticas de saúde passaram a priorizar a  atenção  primária  como  forma  de  fazer  frente  às  questões  contemporâneas  de  saúde,  a  saúde  promocional  tornou‐se parte importante das políticas setoriais e, em sua formulação  mais  abrangente,  não  visa  imputar  responsabilidade  às  pessoas.  A  moderna  concepção  de  promoção  da  saúde,  segundo  Márcia  Westphal  (2006),  tem  por  base  cinco  princípios:  uma  concepção  holística  de  saúde,  voltada  à  multicausalidade  do  processo  saúde‐doença;  a  equidade  como  forma  de  enfrentar  as  desigualdades  estruturais,  relacionada,  portanto,  à  distribuição  desigual  dos  determinantes  da  saúde  na  população;  a  intersetorialidade  como estratégia para dar conta da complexidade do processo  saúde‐doença; a participação social na definição das políticas, no controle social e na avaliação das ações e dos serviços; e a sustentabilidade como forma de garantir ações duradouras.  \n  \n Mary Jane Spink. Psicologia social e políticas de existência:   fronteiras e conflitos. Bernardes e Medrado (orgs.).   1.ª ed. Maceió: ABRAPSO, 2009 (com adaptações). \n \n  \n   Segundo Mary Jane Spink,", "alt": {"A": "o cuidado em saúde deve superar o velho paradigma \nde  saúde  versus  doença  e  ampliar  seu  conceito, \natentando para a produção multicausal da saúde, que \nconsidera o sujeito integralmente, e a política de saúde \nprecisa  incorporar  políticas  e  ações  de  promoção  da \nsaúde.", "B": "a  concepção  holística  de  saúde  prevê  que  a  prática  psicológica na atenção básica deve analisar as práticas  alternativas  como  forma  de  intervenção  e  que  tais  práticas, ainda hoje, não são consideradas pela ciência  tradicional  e  foram  excluídas  da  grade  curricular  dos  cursos  de  psicologia,  provocando  um  descompasso  entre a promoção da saúde e o modelo com base na  patologia.", "C": "o  Sistema  Único  de  Saúde  (SUS)  não  está  preparado  para  aplicar  noções  de  equidade  e  intersetorialidade  nem a compreensão da multicausalidade do processo  saúde‐doença.  Assim,  não  se  pode  falar  de  saúde  promocional  na  atenção  básica  à  saúde  no  caso  brasileiro.", "D": "por  políticas  setoriais  entende‐se  que  imputar  responsabilidades  aos  usuários  do  SUS  seja  um  equívoco,  sabendo  que  o  paciente  não  deve  ser  o responsável  pelo  cuidado  pessoal  à  sua  saúde.  Essa  responsabilidade é do técnico que acompanha o caso e  reúne  o  saber  necessário  para  as  decisões  clínicas  necessárias.", "E": "por  atenção  primária  entende‐se  o  primeiro  diagnóstico,  que  deve  ser  realizado  por  técnico  especializado  e  em  condições  adequadas  de atendimento, nem  sempre  observadas  pela estrutura  pública de atenção à saúde."}, "g": "A", "j": "Spink (2009) sobre Westphal e promocao da saude: o cuidado em saude deve superar o paradigma saude vs doenca, ampliar o conceito para multicausalidade, considerar o sujeito integralmente; a politica de saude precisa incorporar acoes de promocao da saude. Alternativa A reproduz essa premissa. C contraria afirmando que o SUS nao esta preparado. CORRIGIDO para A."}, {"id": "1297132", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "No livro Psicologia Social para a América Latina: o resgate da  psicologia da libertação, os autores priorizam um importante  autor  latino‐americano  que  representa  um  marco  para  a  psicologia da libertação. Trata‐se de", "alt": {"A": "Simón Bolívar.", "B": "Silvia T. M. Lane.", "C": "Ignácio Martín‐Baró.", "D": "José Martí.", "E": "Ignácio Dobles."}, "g": "C", "j": "O autor central da Psicologia da Libertacao na America Latina e IGNACIO MARTIN-BARO (1942-1989), padre jesuita salvadorenho. Alternativa C correta — Martin-Baro e marco fundador do movimento. Bolivar (A), Lane (B), Marti (D) e Dobles (E) sao referencias importantes mas nao o autor central deste livro. Confirmado."}, {"id": "1297131", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  se  refere  à  psicologia  social  do  trabalho,  julgue  os  itens subsequentes.     I  A psicologia social do trabalho não pertence ao campo  da  psicologia  social  por  tratar  de  fenômenos  que  concernem  a  uma especialidade  da  psicologia menos  afetada  pela  realidade  social  que  pelo  campo  organizacional.   II  O  trabalho,  ao  menos  como  aparece  nas  condições  brasileiras  no  presente  momento,  é  fonte  de  adoecimento e produz transtornos importantes, como  a  depressão,  segundo  levantamentos  e  estudos  realizados  a  partir  de  notificações  ao  INSS  de  afastamento do trabalho.   III  No  presente  momento,  o  aumento  do  emprego   deve‐se  ao  aumento  do  trabalho  informal.  Essa  condição  que  desorganiza  o  mercado  de  trabalho  e  corrói  o  rendimento  dos  trabalhadores  é,  também,  oportunidade para o crescimento de uma importante  alternativa  de  rendimento  por  meio  da  economia solidária,  forma  de  organização  autônoma  dos  trabalhadores.   IV  Todo psicólogo do trabalho deve evitar o trabalho no  âmbito das organizações pela pouca oportunidade de  transformação das relações de trabalho.     V  O CEREST é uma espécie de unidade básica de saúde  que  atende  somente  trabalhadores  que  sofreram  acidentes  de  trabalho.  O  atendimento  depende  do  preenchimento da CAT.     A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "B", "j": "Psicologia social do trabalho: II correto (trabalho como fonte de adoecimento; depressao em estudos do INSS de afastamento); III correto (aumento do trabalho informal e crescimento da economia solidaria como alternativa). Item I INCORRETO (psicologia social do trabalho PERTENCE a psicologia social); item IV INCORRETO ('todo psicologo evitar organizacoes' e generalizacao injusta); item V INCORRETO (CEREST atende mais amplamente, nao 'somente acidentes' e nao depende exclusivamente da CAT). Corretos: II e III = 2. CORRIGIDO para B."}, {"id": "1297130", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação aos autores e a suas respectivas obras, julgue os   itens que se seguem.     I  José  Moura  Gonçalves  Filho,  autor  do  conceito  de  humilhação  social,  refere‐se à  noção  de  produção  da  invisibilidade  social  como  estratégia  defensiva  que  produz a anulação  social do  ser em circunstâncias de   vivência comunitária.     II  Tanto  José Moura  Gonçalves  Filho  quanto  Ecléa  Bosi  discutiram e ampliaram o conceito de enraizamento e  desenraizamento de Simone Weil.   III  Ecléa  Bosi,  ao  dizer:  “Esta  é  uma  questão  relevante  para  pensarmos  a  memória:  qual  versão  de  um  fato  deve  ser  considerada  verdadeira?  Nós  estávamos  e  sempre  estaremos  ausentes  do  fato  que  está  sendo   narrado.”,  está  se  referindo  ao  que  expressa  em  seu  livro Memória e Sociedade.   IV  Uma  grande  inspiração  de  Ecléa  Bosi  para  sua  tese  sobre  memória  foram  o  francês  Maurice  Halbwachs   (1877 – 1945) e seu livro A Memória Coletiva.     Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens III e IV estão certos.", "C": "Apenas os itens I, II e III estão certos.", "D": "Apenas os itens I, II e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "NOTA SISTEMICA: continua erro de gab_candidato=C importado da fonte (igual ao lote 030). Tecnicamente: I correto (Jose Moura Goncalves Filho — Humilhacao Social, 1998 — conceito de invisibilidade publica); II correto (JMGF e Eclea Bosi discutiram enraizamento/desenraizamento de Simone Weil); III correto (Eclea Bosi, Memoria e Sociedade, 1979); IV correto (Maurice Halbwachs, 1877-1945, frances, A Memoria Coletiva, postumo 1950, influencia central para Bosi). Todos corretos. CORRIGIDO para E."}, {"id": "1297129", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Sabe‐se  que  o  Brasil  é  um  dos  países  com  a  maior  desigualdade social do planeta e, ao mesmo tempo, é um país  rico,  cuja  economia  está  entre  os  dez  maiores  PIBs.  Essa  contradição exige a produção de um repertório peculiar, no  campo  das  ciências  sociais  e  psicológicas,  em  sua  ação  concreta  nas  comunidades.  Considerando  essa  premissa,  assinale a alternativa correta.", "alt": {"A": "Tal  peculiaridade  impede  a  importação  de  qualquer conhecimento  produzido  fora  do  País,  sem  noção  de  sua realidade.", "B": "A psicologia social comunitária nasceu como forma de  atender  aos  sujeitos  desvalidos  que  estão  abaixo  da linha da pobreza, enquanto a psicologia clínica atende  aos  que  têm  recursos  para  remunerar  os  psicólogos  que trabalhem em seus consultórios privados.", "C": "A  psicologia  social  não  tem  recursos  teóricos  e  metodológicos para compreender um fenômeno que é  mais estudado pelas ciências sociais.", "D": "A psicóloga  social venezuelana Maritza Montero, que  foi parceira de Silvia Lane e Bader Sawaia, inspirou‐se  nas  pesquisadoras  brasileiras  para  a  construção  da  teoria  do  fracasso  escolar,  baseada  e  inspirada  nas  condições brasileiras.", "E": "Jessé  de  Souza  é  um  pesquisador  brasileiro,  em   ampla  divulgação  no  presente  momento,  cuja  produção foi muito utilizada por Ana M. B. Bock e Maria   da  Graça  M.  Gonçalves  na  discussão  sobre desigualdade social."}, "g": "E", "j": "Sobre desigualdade no Brasil e psicologia social: alternativa E correta — Jesse de Souza (A Ralé Brasileira, Os Batalhadores Brasileiros, A Elite do Atraso) e pesquisador brasileiro em ampla divulgacao recente, utilizado por Bock e Goncalves na discussao sobre desigualdade social. C nega recursos teoricos a psicologia social (oposto). D atribui erroneamente a Maritza Montero a teoria do fracasso escolar (Montero e da psicologia comunitaria latino-americana). CORRIGIDO para E."}, {"id": "1297128", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "A ação concreta dos psicólogos sociais na realidade, em sua  intervenção  técnica,  seja  nas relações  institucionais  ou  em  uma ação comunitária, exige um repertório amplo e diverso.  Um desses repertórios diz respeito à psicologia política como  ramo  específico  da  psicologia  social.  Considerando  essa  informação, assinale a alternativa correta.", "alt": {"A": "A ciência, como é o caso da psicologia social, e a política não se misturam. A primeira  trabalha com  resultados  experimentais  e  a  segunda  é  profundamente  ideológica.", "B": "Apesar  do  desenvolvimento  das  ciências  políticas  no  campo  das  ciências  sociais,  na  psicologia  social,  essa  discussão  é  precária  em  função  de  estudar  primordialmente o indivíduo.", "C": "Em sua ação concreta, representada pela intervenção  no cotidiano, o psicólogo social deve buscar manter a  distância necessária dos sujeitos de sua ação, evitando  a política como parâmetro de seu trabalho", "D": "A  política,  tanto  em  seu  âmbito  mais  específico,  o  comportamento  político,  quanto  em  sua  dimensão  mais ampla, políticas públicas, política partidária etc., é  um fenômeno humano estudado pela psicologia social.", "E": "A  ideologia  é  uma  categoria  importante  para  a \npsicologia  política.  Assim,  psicólogos  sociais  devem \ndefinir  claramente  o  âmbito  de  sua  ideologia  como \ncondição  ética  para  a  ação  em  comunidades  em \nsituação de risco."}, "g": "D", "j": "Psicologia politica como ramo da psicologia social: alternativa D correta — a politica, em ambito especifico (comportamento politico) e mais amplo (politicas publicas, partidaria), e fenomeno humano estudado pela psicologia social. C inverte ao propor 'manter distancia, evitar politica como parametro'. A, B sao reducionistas. CORRIGIDO para D."}, {"id": "1297127", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Na  história  da  psicologia  social,  uma  grande  referência  é  o  livro  de  Robert  Farr,  autor  britânico  que  estabeleceu  o  famoso  paradigma  entre  a  psicologia  social  psicológica  e  a  psicologia social sociológica. Acerca desse assunto, assinale a alternativa correta.", "alt": {"A": "Farr  referia‐se  a  uma  clássica  definição  da  psicologia  social na primeira metade do século XX e que perdurou  até os anos de 1980. A vertente psicológica refere‐se à  tradição  focada  no  indivíduo,  considerando  que  o  indivíduo  seja  o  construtor  da  sociedade  e  que  a  vertente  sociológica  parta  do  pressuposto  de  que  a  sociedade e a cultura são matrizes que irão influenciar  a formação do indivíduo.", "B": "Fortemente influenciado pela visão de Émile Durkheim, \nFarr  desenvolveu  sua  avaliação  da  psicologia  social  a \npartir  das  noções  de  solidariedade  orgânica  e \nsolidariedade  mecânica,  sendo  essa  a  origem  da \nclassificação proposta.", "C": "Farr  foi  um  grande  divulgador  da  teoria  das  representações  sociais em  solo  britânico. A  teoria  de  Serge  Moscovici  foi  a  base  para  a  denominação  da   psicologia social sociológica", "D": "Na realidade, Farr cometeu um equívoco ao construir o  paradigma. Toda psicologia social é psicológica.", "E": "George Herbert Mead e Erving Goffman,  que, apesar  de antropólogo, teria produzido uma psicologia social,  influenciaram  a  criação  do  interacionismo  simbólico  (Blumer).  Tal  vertente  e  esses  autores  seriam  classificados por Farr como, claramente, do campo da  psicologia social sociológica."}, "g": "A", "j": "Robert Farr — paradigma psicologia social PSICOLOGICA (foco no individuo como construtor da sociedade, tradicao norte-americana — Allport, comportamentalismo) vs SOCIOLOGICA (sociedade/cultura como matrizes que influenciam a formacao do individuo, tradicao europeia/Mead/interacionismo simbolico). Alternativa A reproduz essa definicao classica. B atribui erroneamente a Durkheim como origem; D afirma que Farr 'cometeu equivoco'; C reduz a divulgacao de Moscovici. CORRIGIDO para A."}, {"id": "1297126", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "Sua publicação, na década de 1980, representou a renovação \nda psicologia social no Brasil e produziu um forte impacto no \nensino  dessa  área  em  muitos  cursos  de  graduação  em \npsicologia,  repercutindo  até  os  dias  de  hoje.  O  texto  \nrefere‐se ao", "alt": {"A": "livro Metodologia da Pesquisa em Ciências Sociais, de \nFred N. Kerlinger.", "B": "portal  de  revistas  da  CAPES  e  ao  sistema  Qualis  de \navaliação.", "C": "livro  de  Fritz  Heider,  Psicologia  das  Relações \nInterpessoais.", "D": "livro de Silvia T. M. Lane e Wanderley Codo, Psicologia  Social: o homem em movimento.", "E": "livro de Gustav Jahoda, A Cross‐Cultural Perspective on  Experimental Social Psychology."}, "g": "D", "j": "Livro publicado na decada de 1980 que renovou a psicologia social no Brasil e impactou cursos de graduacao: 'PSICOLOGIA SOCIAL: O HOMEM EM MOVIMENTO' de Silvia T. M. Lane e Wanderley Codo (1984). Marco da virada socio-historica e do compromisso etico-politico. Alternativa D correta. Heider (C) e dos anos 1950; demais (Kerlinger, CAPES, Jahoda) nao se aplicam. CORRIGIDO para D."}, {"id": "1297125", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "O  Conselho  Federal  de  Psicologia  (CFP)  e  os  conselhos  regionais  fazem um belo  trabalho de resgate da memória e  da história da implantação da psicologia no Brasil. O CRP‐SP  disponibiliza, em seu sítio eletrônico, um bom material sobre  a  implantação  da  psicologia  social  no  Brasil.  Considerando  essas informações, julgue os próximos itens.  I  As  informações  disponíveis  sobre  a  história  da  psicologia social no Brasil apontam para uma completa  dependência  da  psicologia  social  estadunidense  do  início  do  século  XX,  contando  com  a  importação  e  a  implantação  acrítica  do  conhecimento  e  com  a  imediata tradução dos manuais em voga no período.  II  Otto  Klineberg,  canadense  que  foi  professor  de  psicologia na Universidade de Columbia (EUA), esteve  no Brasil de 1945 a 1947 e ministrou o primeiro curso  de  psicologia  social  na  USP.  Deixou  uma  marca  profunda, que influenciou a construção do campo no  Brasil.  Sua  linha  de  pesquisa  era  behaviorista  e  estritamente experimental.  III  Um  dos  nomes  mais  importantes  na  emergente  psicologia  social  brasileira  foi  Dante  Moreira  Leite.  Dante  publicou  um  livro  que  é  um  marco  nessa  disciplina  e  atual  até  hoje:  O  Caráter  Nacional  Brasileiro.  Foi  orientador  de  Ecléa  Bosi,  que  faleceu  recentemente e foi autora dos não menos importantes:  Memória  e  Sociedade  e  Cultura  de Massa  e  Cultura  Popular: leituras de operárias. Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Historia da psicologia social no Brasil: I incorreto (nao houve 'completa dependencia' acritica — houve dialogo critico desde os anos 1970-80); II incorreto — Otto Klineberg era CROSS-CULTURAL (assistente de Franz Boas), nao behaviorista experimental; III correto — Dante Moreira Leite, 'O Caracter Nacional Brasileiro' (1954), orientou Eclea Bosi na USP. Apenas III. CORRIGIDO para D."}, {"id": "1297124", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "No livro Método Histórico‐social na Psicologia Social, há um \nprimoroso capítulo de Betty Oliveira intitulado: A dialética do\nsingular‐particular‐universal.  Nele,  Oliveira  discute  uma \nreferência  importante  para  o  campo  histórico‐cultural  do \nponto de vista do método. Trata‐se", "alt": {"A": "do  modo  de  utilização  do  método  qualitativo  na  proposta de Fernando González Rey.", "B": "de  Leon  S.  Vygotsky  e  de  sua  noção  de  nexo, \nparticularmente  quando  fala  das  funções  psíquicas \nsuperiores.", "C": "do manejo das leis da dialética, do ponto de vista de \nMarx  &  Engels,  nas  três  dimensões  de  expressão  da \nrealidade.", "D": "do  singular,  do  particular  e  do  universal,  caminho \nrealizado  pelo  psiquismo  na  teoria  histórico‐cultural, \nque sempre vai da parte para o todo.", "E": "da  importante  solução  apontada  por  Oliveira  para  a  interação entre o indivíduo e a sociedade, garantindo  que sua inevitável divisão possa ser compreendida em  suas múltiplas determinações."}, "g": "C", "j": "Betty Oliveira ('A dialetica do singular-particular-universal'): a referencia central e o MANEJO DAS LEIS DA DIALETICA conforme MARX & ENGELS, nas tres dimensoes de expressao da realidade (singular, particular, universal — categorias hegelianas reapropriadas pelo marxismo). Alternativa C correta. Confirmado."}, {"id": "1297123", "d": "psicologia", "a": ["Políticas Públicas no SUAS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2018", "org": "CFP", "t": "", "e": "A  Lei  Orgânica  da  Assistência  Social  (LOAS)  prevê  a  equipe  básica de um centro de referência da assistência Social (CRAS)  com a presença de um assistente social e de um psicólogo. Há  orientação de que o psicólogo contratado para trabalhar no  CRAS  não exerça ali  técnicas  de  psicoterapia,  considerando  que  tal  prática  profissional  seja  exercida  na  saúde  pelas  equipes de referência. A respeito desse tema, julgue os itens  a seguir.      I  Não há segurança, para o campo da assistência social,  da  base  científica  dos  recursos  técnicos  empregados  pelos psicólogos em seu trabalho no CRAS.      II  O  trabalho da assistência social  realizado pela equipe  do CRAS é multidisciplinar e visa ao apoio à população  em  geral,  privilegiando  a  população  que  sofre  algum  risco social. Assim, os recursos do campo da assistência  social e da psicologia  social são aplicados, de comum  acordo, pela equipe básica do CRAS.     III  Considerando  que  o  trabalho  do  CRAS  consista  prioritariamente  na  distribuição  das  Bolsas‐Família,  conforme  preconiza  a  LOAS,  o  psicólogo  social  ficará  necessariamente subordinado ao assistente social.     Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "C", "j": "LOAS/CRAS: I incorreto (ha base cientifica para os recursos do psicologo no CRAS — psicologia social, comunitaria); II correto (trabalho multidisciplinar com recursos da assistencia social e psicologia social aplicados de comum acordo pela equipe basica); III incorreto (psicologo NAO e subordinado ao assistente social — sao profissoes complementares com mesmo status na equipe). Apenas II. Confirmado."}, {"id": "1296922", "d": "psicologia", "a": ["Psicopatologia", "CID-10 e DSM", "Transtornos da Ansiedade", "Outros Transtornos"], "ano": "2018", "org": "CFP", "t": "", "e": "As abordagens psicoterápicas usualmente direcionam‐se ao \ntratamento  de  condições  que  trazem  sofrimento  ao \nindivíduo. No  que  se  refere  a  esse  assunto,  julgue  os  itens \nsubsequentes. \nI  Os transtornos de ansiedade incluem o transtorno de \npânico,  o  transtorno  de  ansiedade  generalizada  e  a \nfobia social, entre outras condições. \nII  Na agorafobia, existe o medo de ter medo, levando à \nevitação e ao transtorno de pânico. \nIII  A  fobia  social  refere‐se  a  uma  antecipação  de \nembaraço ou humilhação em situações sociais, em que \no  indivíduo  teme  que  os  outros  o  rejeitem  ao \nperceberem suas deficiências e fraquezas. \nIV  O  transtorno obsessivo‐compulsivo  (TOC) usualmente \napresenta  grande  intolerância  à  incerteza, \nsubestimando níveis de risco. \nV  De  acordo  com  o  modelo  cognitivo,  a  depressão  é \nproduzida  por  um  padrão  negativista  de  avaliar  a  si \npróprio, o futuro e o mundo. \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas os itens II e V estão certos.", "C": "Apenas os itens I, II e V estão certos.", "D": "Apenas os itens I, III e V estão certos.", "E": "Apenas os itens I, III, IV e V estão certos."}, "g": "C", "j": "DSM-5/Cordioli sobre transtornos: I correto (transtornos de ansiedade incluem panico, TAG, fobia social); III correto (fobia social = antecipacao de embaraco/humilhacao em situacoes sociais — definicao DSM-5); V correto (modelo cognitivo de Beck — depressao como triade negativa: self/futuro/mundo). Item II tem formulacao problematica — agorafobia NAO 'leva ao transtorno de panico' (sao entidades distintas no DSM-5). Item IV INCORRETO — TOC envolve SUPERESTIMACAO de risco, nao subestimacao. Corretos: I, III, V. CORRIGIDO para D."}, {"id": "1296920", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2018", "org": "CFP", "t": "", "e": "A loucura tem sido uma companheira inseparável do \nhomem  ao  longo  de  todo  o  seu  trajeto  conhecido  pela \nhistória.  As  referências  a  loucos  são  encontradas  desde  o \nVelho  Testamento  até  os  estudos  etnográficos  das \nsociedades  chamadas  de  primitivas. Não existe  cultura  que \ndeixe  de  ser  sensível  àquilo  que  escapa  à  sua  norma, \ndefinindo incessantemente as fronteiras entre a loucura e a \nnormalidade,  voltando  seu  olhar  para  a  presença  dos \n“loucos” no convívio com as pessoas “normais” e produzindo \nestratégias para enfrentar os produtos dessa divisão. Como já \nfoi demonstrado no clássico História da Loucura, de Michel \nFoucault, a partir do século XIX, a tarefa de vigiar a fronteira \nentre a razão e a loucura e montar guarda em sua cancela foi \ndestinada à medicina. \nFernando Freitas. Cidadania e loucura. Tundis e  \nCosta, 2001 (com adaptações). \nCom base no texto acima, julgue os itens a seguir. I  A loucura costuma ser, em alguma medida, delimitada \nou  definida,  pelas  diferentes  culturas,  por  nomes \ndiversos.\nII  Os  estudos  etnográficos  de  sociedades  primitivas \nconfirmam  a  criação  de  normas  que  estabelecem \nfronteiras entre o normal e o louco.\nIII  As  culturas  produzem  estratégias  para  lidar  com  a \ndicotomia normalidade/loucura.Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Loucura na perspectiva foucaultiana (Freitas, 2001): I correto (loucura definida culturalmente, com nomes diversos); II correto (estudos etnograficos de sociedades primitivas confirmam normas que distinguem o normal do louco); III correto (culturas produzem estrategias para lidar com a dicotomia). Todos os itens corretos. CORRIGIDO para E."}, {"id": "1296915", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  1998,  o  Conselho  Federal  de  Psicologia  (CFP), \nconsiderando  a  relevância  do  respeito  aos  direitos  para  o \nexercício  de  toda  e  qualquer  atividade  profissional, \nnotadamente  para  a  psicologia  e  os  psicólogos,  instituiu  a \ncomissão  de  direitos  humanos  do  CFP.  São  objetivos  dessa \ncomissão:  incentivar  a  reflexão  sobre  os  direitos  humanos \ninerentes à formação, à prática profissional e à pesquisa em \npsicologia;  intervir  em  todas  as  situações  em  que  existam \nviolações  dos  direitos  humanos  que  produzam  sofrimento \nmental;  participar  de  todas as  iniciativas  que  preservem  os \ndireitos  humanos  na  sociedade  brasileira;  apoiar  o \nmovimento  internacional  dos  direitos  humanos;  e  estudar \ntodas as formas de exclusão que violem os direitos humanos \ne  provoquem  sofrimento  mental.  No  que  diz  respeito  à \nprática do psicólogo, assinale a alternativa incorreta segundo \nos objetivos propostos pela comissão.", "alt": {"A": "O  psicólogo  baseará  seu  trabalho  no  respeito  e  na \npromoção da liberdade, da dignidade, da igualdade e \nda integridade do ser humano, apoiado nos valores que \nembasem  a  Declaração  Universal  dos  Direitos \nHumanos.", "B": "O  respeito  aos  direitos  humanos  em  psicologia \ncorresponde a uma prática comprometida com o social \ne atenta ao sujeito concreto.", "C": "O  respeito  aos  direitos  humanos  em  psicologia  exige \numa atuação que compreenda psicologia como ciência \ne  como  profissão,  não  se  concebendo  como  ciência \nautossuficiente  e  estabelecendo  diálogo  com  outras \náreas de saber.", "D": "O respeito aos direitos humanos em psicologia exige do \npsicólogo  uma  atuação  que  se  sustente  em  uma \nformação  cuidadosa,  crítica  e  em  constante \naperfeiçoamento.", "E": "A  psicologia  deve  favorecer  prioritariamente  a \nadaptação do sujeito a seu meio, independentemente \ndas  circunstâncias,  visando  minorar  o  sofrimento \npsíquico."}, "g": "C", "j": "Comissao de Direitos Humanos do CFP (1998): A, B, C, D sao premissas de uma pratica do psicologo respeitosa aos DH (DUDH, dialogo interdisciplinar, formacao critica, compromisso social). Alternativa E INCORRETA: 'adaptacao do sujeito ao meio INDEPENDENTEMENTE das circunstancias' contraria a CDH/CFP, que defende emancipacao, autonomia e critica as condicoes que produzem sofrimento. CORRIGIDO para E."}, {"id": "1296914", "d": "psicologia", "a": ["Psicanálise", "Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "A psicanálise ocupa‐se do sujeito que fala, do assunto \nsobre  o  qual  ele  fala  e  do  objetivo  de  sua  fala  em  termos \ndefinidos pela dimensão do inconsciente, mas, para começar \na  falar,  ninguém  precisa  esperar  chegar  ao  consultório  do \npsicanalista. É psicanalista quem, por atender ao discurso do \ninconsciente onde quer que este se faça ouvir, não desatenda \nàs consequências lógicas e éticas desse ato.  \n  O discurso médico‐psiquiátrico, ao se valer apenas dos \nelementos de seu próprio discurso, abole tudo o que nele não \npossa  se  inscrever,  o  que  Clavreul  (1983)  chamou  de  sua \nfunção silenciadora. A experiência psicanalítica mostrou que \ntambém se sofre do que não se pode dizer. Borges, 2001 (com adaptações). \nA partir do  texto, é correto afirmar que a autora considere \nque", "alt": {"A": "a  psicanálise  ocorra  somente  no  contexto  do \nconsultório do psicanalista.", "B": "sejam  opostos  os  discursos  da  psicanálise,  do \npsicanalista e do médico psiquiatra.", "C": "existam  sobreposições  entre  os  discursos  da \npsicanálise e da psiquiatria.", "D": "Clavreul  aponte  a  falta  de  interlocução  do  discurso \nmédico com as outras ciências como resultado de sua \nfunção silenciada.", "E": "a proposta da psicanálise, ao mostrar que o não dito \npode  se  associar  ao  sofrimento  psíquico,  \ncontraponha‐se  ao  discurso  médico‐psiquiátrico \ntradicional."}, "g": "C", "j": "Borges (2001) sobre psicanalise e discurso medico-psiquiatrico: a psicanalise mostra que tambem se sofre do que nao se pode dizer, CONTRAPONDO-SE ao discurso medico-psiquiatrico tradicional (que tem 'funcao silenciadora' de Clavreul). Alternativa E reproduz essa tese. A (so consultorio) e restritiva; B (opostos) e absoluta; C (sobreposicoes) nao captura o ponto; D distorce Clavreul. CORRIGIDO para E."}, {"id": "1296913", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2018", "org": "CFP", "t": "", "e": "O  Ministério  da  Saúde,  em  sua  Portaria  n.º  336/2002, \nestabeleceu  as  modalidades  dos  centros  de  atenção \npsicossocial  (CAPS I, II e III) e sua  forma de  funcionamento. \nConsiderando  essa  informação,  assinale  a  alternativa \nincorreta.", "alt": {"A": "Os CAPS deverão ser serviços ambulatoriais de atenção \ndiária.", "B": "Os CAPS deverão funcionar em áreas físicas específicas \ne independentes de qualquer estrutura hospitalar.", "C": "A denominação dos CAPS I, II e III em ordem crescente \ncorresponde ao porte, à complexidade e à abrangência \npopulacional.", "D": "Os  CAPS  deverão  estar  capacitados  para  realizar \nsomente o atendimento de pacientes com transtornos \nmentais  leves,  em  sua  área  territorial,  após  alta \nhospitalar.", "E": "Os  regimes  de  tratamento  dos  CAPS,  em  sua  área \nterritorial,  poderão  ser: intensivos;  semi‐intensivos; e \nnão intensivos."}, "g": "C", "j": "Portaria 336/2002 (CAPS): A, B, C, E reproduzem normas (ambulatoriais diarios; independentes de hospitais; ordem crescente de complexidade; regimes intensivo/semi/nao-intensivo). Alternativa D INCORRETA: os CAPS sao capacitados para atender PRIORITARIAMENTE pacientes com TRANSTORNOS MENTAIS SEVEROS E PERSISTENTES — nao 'somente transtornos leves apos alta hospitalar'. CORRIGIDO para D."}, {"id": "1296912", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2018", "org": "CFP", "t": "", "e": "O Ministério da Saúde estabeleceu, na Portaria n.º 251/GM, \nas  diretrizes  e  normas  para  a  assistência  hospitalar \npsiquiátrica.  Com  relação  a  esse  tema,  julgue  os  próximos \nitens. \nI  Define como hospital psiquiátrico aquele cuja maioria \nde  leitos  se  destine  ao  tratamento  especializado  de \nclientela psiquiátrica em regime de internação.   II  Exige  a  obrigatoriedade  do  registro  periódico,  em \nprontuário,  dos  procedimentos  diagnósticos  e \nterapêuticos.  \nIII  Proíbe a existência de espaços restritivos (cela forte). \nAssinale a alternativa correta.", "alt": {"A": "Todos os itens estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Nenhum item está certo."}, "g": "C", "j": "Portaria 251/GM do Ministerio da Saude (assistencia hospitalar psiquiatrica): I correto (define hospital psiquiatrico como aquele com maioria de leitos para clientela psiquiatrica em internacao); II correto (obrigatoriedade do registro periodico em prontuario); III correto (proibicao de espacos restritivos como cela forte). Todos os itens corretos. CORRIGIDO para A."}, {"id": "1296910", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)", "Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere aos aspectos éticos envolvidos na realização \nde estudos, pesquisas e atividades voltadas para a produção \nde conhecimento e desenvolvimento de tecnologias, assinale \na alternativa incorreta.", "alt": {"A": "O psicólogo deverá garantir o anonimato de pessoas, \ngrupos ou instituições envolvidas, salvo se se tratar de \ninteresse manifesto destes.", "B": "O  psicólogo  deverá  garantir  o  caráter  voluntário  da \nparticipação dos envolvidos, inclusive mediante o uso \nde termo de consentimento livre e esclarecido.", "C": "O  psicólogo  deverá  garantir  o  acesso  dos  envolvidos \naos resultados das pesquisas ou dos estudos, após seu \nencerramento, sempre que assim o desejarem.", "D": "O  psicólogo  deverá  avaliar  os  riscos  envolvidos  no \nestudo,  tanto  pelos  procedimentos  quanto  pela \ndivulgação dos resultados, com o objetivo de proteger \nos envolvidos.", "E": "O psicólogo poderá se abster de obter autorização dos \nenvolvidos  em  casos  de  divulgação  de  suas \ninformações pessoais, particularmente em se tratando \nde atendimentos clínicos de consultório."}, "g": "C", "j": "CEP, art. 16 (pesquisas): A (anonimato), B (TCLE), C (acesso aos resultados), D (avaliacao de riscos) sao deveres expressos. Alternativa E INCORRETA: o psicologo NAO pode se abster de obter autorizacao para divulgacao de informacoes pessoais — em pesquisa ou divulgacao, o TCLE e exigencia etica (Res CONEP 466/2012 e 510/2016). CORRIGIDO para E."}, {"id": "1296909", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Saúde Coletiva", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "No que concerne às doenças cardiovasculares e à diabetes de \nacordo com Straub (2005), julgue os itens subsequentes. \nI  Na década de 1950, Friedman e Rosenman propuseram \nque  a  personalidade  tipo  A  apresenta  um  padrão  de \ncomportamento  que  predispõe  à  ocorrência  de \nproblemas coronarianos. \nII  O paciente que recebe o diagnóstico de diabetes pode \nexperimentar  emoções  diferentes,  que  incluem  o \nchoque, a negação, a raiva e a depressão. \nIII  Hostilidade  e  raiva  são  considerados  como  fatores \nprotetores  para  a  ocorrência  de  problemas \ncardiovasculares,  pois  favorecem  a  externalização  de \nconflitos.  \nIV  Em  doenças  cardiovasculares,  a  capacidade  de \nenfrentamento  e  a  depressão  são  fatores  de  risco \nincontroláveis  que  devem  ser  abordados  pelo \npsicólogo. \nV  O autocuidado e o automanejo são fundamentais para \no  cuidado  de  pessoas  com  diabetes,  sendo  fatores \ninfluenciados  por  seu  nível  de  conhecimento  sobre  a \ndoença. \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas os itens I, II e V estão certos.", "C": "Apenas os itens I, III e V estão certos.", "D": "Apenas os itens II, III e IV estão certos.", "E": "Apenas os itens II, IV e V estão certos."}, "g": "C", "j": "Straub (Psicologia da Saude) sobre doencas cardiovasculares e diabetes: I correto (Friedman & Rosenman, anos 50, personalidade tipo A — competitividade, hostilidade, urgencia — fator de risco para coronariopatias); II correto (paciente com diabetes vivencia luto: choque, negacao, raiva, depressao); V correto (autocuidado/automanejo influenciados por nivel de conhecimento). Item III INCORRETO — hostilidade/raiva sao FATORES DE RISCO, nao protetores. Item IV INCORRETO — enfrentamento e depressao sao fatores MODIFICAVEIS pelo trabalho psicologico, nao incontrolaveis. Corretos: I, II, V. CORRIGIDO para B."}, {"id": "1296885", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando as disposições do Código de ética profissional dos psicólogos, assinale a alternativa incorreta.", "alt": {"A": "É  vedado  ao  psicólogo  fazer  previsão  taxativa  de \nresultados", "B": "É vedado ao psicólogo utilizar o valor do serviço como \nforma de propaganda.", "C": "É  vedado  ao  psicólogo  propor  atividades  que  sejam \nprivativas de outras categorias profissionais.", "D": "É  vedado  ao  psicólogo  fazer  divulgação  de  suas \natividades profissionais.", "E": "É vedado ao psicólogo  fazer publicamente divulgação \nde seu trabalho sem informar seu nome e seu número \nde registro profissional."}, "g": "D", "j": "CEP (Res 10/2005): A (previsao taxativa — vedada), B (valor como propaganda — vedada), C (atividades privativas de outras categorias — vedada), E (divulgacao sem nome/CRP — vedada). Alternativa D INCORRETA como vedacao — a divulgacao das atividades profissionais NAO e vedada em si; e regulamentada (sem sensacionalismo, com nome/CRP), mas nao proibida. Gabarito D confirmado."}, {"id": "1296884", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "CFP", "t": "", "e": "De acordo com o Código de ética profissional dos psicólogos, julgue os itens a seguir.\n\n   \n   \n\n \nI  É vedado aos psicólogos fazer registros de suas atividades e de informações sobre usuários/pacientes em seus prontuários para garantir o sigilo.\nII  É vedado aos psicólogos induzir o paciente/usuário a convicções políticas e(ou) religiosas, morais ou ideológicas.\nIII  É  vedado  ao  psicólogo  prestar  em  juízo  informações \nsobre seu paciente, pois isso quebraria o sigilo\n\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "B", "j": "CEP (Res 10/2005): I INCORRETO — registros em prontuario sao DEVER do psicologo (Res 01/2009), nao vedacao; II CORRETO — vedado induzir paciente a conviccoes politicas, religiosas, morais ou ideologicas (art. 2); III INCORRETO — o psicologo PODE prestar informacoes em juizo conforme previsto no CEP (art. 9). Apenas II. Gabarito B confirmado."}, {"id": "1296883", "d": "psicologia", "a": ["Psicologia Institucional"], "ano": "2018", "org": "CFP", "t": "", "e": "Bleger (1984) afirma que a psicologia institucional deve começar sempre por ser aplicada ao próprio grupo que tem a seu cargo a tarefa em uma instituição e isto é assim não só por interesse ou conveniência, mas também por uma exigência técnica do trabalho a se realizar. Considerando essa informação, assinale a alternativa incorreta.", "alt": {"A": "As tensões associadas à tarefa poderão afetar as relações pessoais e profissionais, repercutindo na realização da tarefa.", "B": "A urgência da equipe pela prática e pela produção de resultados é sempre decorrente de exigências não explicitadas pela instituição.", "C": "As tensões intragrupais podem comprometer a qualidade do trabalho e levar a uma compulsão para agir na instituição, saltando etapas de organização.", "D": "É fundamental que os psicólogos não atuem seus conflitos nem estruturem uma situação persecutória na instituição.", "E": "São fundamentais a clareza na delimitação de papéis e funções e a autorregulação da equipe."}, "g": "B", "j": "Bleger (1984) — Psicologia Institucional: a urgencia da equipe pela pratica/producao nao e SEMPRE decorrente de exigencias nao explicitadas — pode ter multiplas origens (cobranca interna, demanda institucional explicita, projecoes da equipe). Alternativa B absolutiza erroneamente ('sempre... nao explicitadas'). A, C, D, E reproduzem premissas blegerianas sobre dinamica grupal e enquadre."}, {"id": "1296834", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  atuação  do  psicólogo  esportivo,  julgue  os  itens \nsubsequentes. I  Participa, juntamente com a equipe multidisciplinar, da \nobservação  e  do  acompanhamento  de  atletas  e \nequipes  esportivas,  visando  ao  estudo  das  variáveis \npsicológicas  que  interfiram  no  desempenho  de  suas \natividades específicas, como treinos e competições.II  Colabora para a adesão e participação nos programas \nde  atividades  físicas  da  população  em  geral  ou \nportadora de necessidades especiais. II  Não orienta pais ou responsáveis nas questões que se \nrefiram  à  escolha  da  modalidade  esportiva  e  à \nconsequente  participação  em  treinos  e  competições, \nbem  como  ao  desenvolvimento  de  uma  carreira \nprofissional e às implicações dessa escolha no ciclo de \ndesenvolvimento da criança.Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "C", "j": "Psicologo esportivo (Res CFP 13/2007 especialista em esporte): I correto (participa de equipe multi para observacao de variaveis psicologicas em treinos/competicoes); II correto (colabora para adesao a programas de atividade fisica, inclusive populacao com necessidades especiais); item III INCORRETO — o psicologo esportivo ORIENTA SIM pais/responsaveis sobre escolha de modalidade, treinos, carreira. Apenas I e II. Gabarito C."}, {"id": "1296831", "d": "psicologia", "a": ["Psicopatologia", "Transtornos da Ansiedade", "Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Atenção plena no futebol         A ansiedade gerada pode causar grandes impactos, na \nmaioria  das  vezes  negativos,  nos  atletas.  Como  trabalhar  o \ncontrole emocional antes de grandes disputas?      Gustavo D'Avila (com adaptações).   \n  \n    A  atenção  plena  pode  ser  compreendida  como  um \nestilo  de  vida,  que  pode  exercer  influência  na  saúde,  no \nequilíbrio mental, no bem‐estar e na felicidade.      Ao praticá-la, o atleta começará a perceber que seus pensamentos vêm e vão por si próprios e descobrirá que ele \nnão é  seus  pensamentos. Ele  poderá  observá‐los enquanto \naparecem  de  repente e  enquanto  desaparecem  como  uma \nbolha de sabão. Quando se dá conta disso, fica mais claro que \npensamentos  e  sensações  (mesmo  os  negativos)  são \ntransitórios e que todo atleta poderá ter a opção de agir com \nbase neles ou não.  \n\n  \ninternet: <https://universidadedofutebol.com.br>\n    Com base nos textos acima, julgue os próximos itens.      I  Os  textos  indicam  que  o  atleta  utilize  uma  técnica \nchamada de interrupção do pensamento.\n  II  Uma técnica que pode ajudar o atleta a manter o foco \nno  presente  é  o  que  se  chama  de  diálogo  interior \npositivo.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "D", "j": "Atencao plena (mindfulness) no esporte: item I INCORRETO — o texto descreve MINDFULNESS (observacao sem julgamento dos pensamentos como bolhas que vem e vao), NAO interrupcao do pensamento (tecnica distinta de TCC); item II correto — o dialogo interior positivo (Bandura, Bandeira) e tecnica psicologica do esporte que ajuda foco/desempenho. Apenas II. Gabarito D."}, {"id": "1296823", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação ao histórico e às áreas de atuação da psicologia \ndo esporte, julgue os itens a seguir. \n\n\n\nI  Na  história  da  psicologia  do  esporte,  a  divisão  47  – \npsicologia  do  esporte  –  foi  desenvolvida  pela  APA \n(American Psychological Association) na Era Griffith, ou \nseja, no segundo período da história da psicologia do \nesporte.\n\nII  Todos os psicólogos do esporte estão aptos a intervir \nem questões referentes à área clínica.\n\nIII  É  importante  que  o  psicólogo  do  esporte  possua \ntambém  conhecimentos  de  ciência  do  esporte,  \ncomo  biomecânica,  fisiologia  do  exercício  e \ndesenvolvimento motor.\n\n\n\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "B", "j": "Historia da psicologia do esporte: I INCORRETO — a Divisao 47 (Exercise and Sport Psychology) da APA foi criada em 1986, MUITO depois da Era Griffith (anos 1920-30) — sao periodos historicos distintos; II INCORRETO — nem todo psicologo do esporte esta apto a intervir em area clinica (exige formacao especifica); III correto — conhecimento de biomecanica, fisiologia do exercicio, desenvolvimento motor sao importantes complementos. Apenas III. Gabarito B."}, {"id": "1151341", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "À luz da Resolução CFP n.º 10 /2017, assinale a alternativa que\napresenta a modalidade de fiscalização motivada pela\ninscrição junto ao CRP.", "alt": {"A": "diligência", "B": "averiguação", "C": "inspeção de pessoa jurídica", "D": "estratégia", "E": "análise"}, "g": "C", "j": "Res CFP 10/2017 — modalidades de fiscalizacao: a INSPECAO DE PESSOA JURIDICA e a modalidade motivada pela inscricao da PJ junto ao CRP. Diligencia (A) e averiguacao (B) sao motivadas por outras situacoes (representacao, indicios de infracao). Gabarito C."}, {"id": "1151340", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Resolução CFP n.º 10/2017, o processo de\norientação dirigido aos psicólogos e à sociedade terá como\nfundamento o(a)", "alt": {"A": "Código de ética profissional do psicólogo e as demais\nnormas do Sistema Conselhos de Psicologia.", "B": "participação nas reuniões da comissão de orientação e\nfiscalização e em outras atividades segundo a política\nde orientação de fiscalização.", "C": "realização de diligências para obter informações acerca\ndo teor de uma representação e elementos de prova\nou averiguar indícios de infração.", "D": "apresentação à comissão de orientação e fiscalização,\nperiodicamente, dos documentos pertinentes ao\nexercício de suas funções.", "E": "inspeção do exercício profissional da psicologia e de\nsua divulgação, obedecidas as disposições éticas e\nlegais."}, "g": "A", "j": "Res CFP 10/2017: o processo de orientacao dirigido aos psicologos e a sociedade tem como FUNDAMENTO o CODIGO DE ETICA PROFISSIONAL DO PSICOLOGO e as demais normas do Sistema Conselhos de Psicologia. Alternativa A correta. B, C, D, E descrevem atividades/atribuicoes, nao o fundamento."}, {"id": "1151339", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Segundo a Resolução CFP n.º 3/2007, o processo por meio do\nqual, por intermédio de métodos e técnicas psicológicas, se\ninvestigam os interesses, as aptidões e as características de\npersonalidade do consultante, visando proporcionar-lhe\ncondições para a escolha de uma profissão, é o(a)", "alt": {"A": "método.", "B": "diagnóstico psicológico.", "C": "técnica.", "D": "orientação psicopedagógica.", "E": "orientação profissional."}, "g": "E", "j": "Res CFP 3/2007: o processo que, por meio de metodos e tecnicas psicologicas, investiga interesses, aptidoes e caracteristicas de personalidade para escolha profissional e a ORIENTACAO PROFISSIONAL. Alternativa E correta. Diagnostico psicologico (B) e atividade diferente; metodo/tecnica/orientacao psicopedagogica nao se ajustam."}, {"id": "1151338", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Acerca dos serviços psicológicos realizados por meios\ntecnológicos de comunicação a distância e regulamentados\npela Resolução CFP n.º 11/2012, assinale a alternativa\ncorreta.", "alt": {"A": "Em caso de atendimento psicoterapêutico realizado\npor meios tecnológicos de comunicação a distância, o\nsigilo não é relevante.", "B": "A observância ao Código de ética profissional do\npsicólogo é relativizada em caso de atendimento\npsicoterapêutico realizado por meios tecnológicos de\ncomunicação a distância.", "C": "Em caso de atendimento psicoterapêutico realizado\npor meios tecnológicos de comunicação a distância em\ncaráter exclusivamente experimental, o participante\npesquisado deverá receber remuneração.", "D": "O atendimento eventual de clientes em trânsito e(ou)\nde clientes que momentaneamente se encontrem\nimpossibilitados de comparecer ao atendimento\npresencial é um dos serviços psicológicos reconhecidos\nque são realizados a distância.", "E": "O psicólogo não é obrigado a especificar os recursos\ntecnológicos utilizados para garantir o sigilo das\ninformações nem a esclarecer o cliente sobre isso em\ncaso de serviços psicológicos realizados por meios\ntecnológicos de comunicação a distância."}, "g": "D", "j": "Res CFP 11/2012 (atendimento online — atualmente Res 04/2020): D correta — o atendimento eventual de clientes em transito ou impossibilitados de comparecer presencialmente e servico psicologico reconhecido. A (sigilo nao relevante), B (CEP relativizado), C (remuneracao obrigatoria em pesquisa) e E (sem especificar recursos de sigilo) contrariam a Resolucao."}, {"id": "1151337", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Conforme o disposto na Resolução CFP n.º 2/2003, assinale a\nalternativa que apresenta um requisito mínimo e obrigatório\npara os instrumentos de avaliação psicológica que utilizem\nquestões de múltipla escolha e outros similares, tais como\n“acerto e erro”, “inventários” e “escalas”.", "alt": {"A": "comunicação da avaliação aos requerentes, com prazo\npara recurso", "B": "revisar os dados empíricos das propriedades de um\nteste psicológico, com um intervalo entre um estudo e\noutro superior a 25 anos", "C": "apresentação de dados empíricos sobre as\npropriedades psicométricas dos itens do instrumento", "D": "apresentação clara somente dos procedimentos de\naplicação e correção", "E": "desconsiderar a perspectiva da integralidade dos\nfenômenos sociais, multifatoriais, culturais e\nhistoricamente construídos"}, "g": "C", "j": "Res CFP 2/2003 (atual 9/2018) — Satepsi: requisito minimo para instrumentos com itens de multipla escolha, escalas e inventarios e a APRESENTACAO DE DADOS EMPIRICOS SOBRE AS PROPRIEDADES PSICOMETRICAS DOS ITENS (validade, precisao, normas). Alternativa C correta."}, {"id": "1151336", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Em relação aos registros documentais dispostos na Resolução\nCFP n.º 1/2009, assinale a alternativa correta.", "alt": {"A": "O registro documental somente poderá ser realizado\nem papel.", "B": "O registro documental constitui-se de um conjunto de\ninformações que têm por objetivo contemplar, de\nforma extensa, o trabalho prestado.", "C": "Os documentos agrupados nos registros do trabalho\nrealizado não necessitam de contemplar a avaliação de\ndemanda e a definição de objetivos do trabalho.", "D": "O registro documental deve ser mantido\npermanentemente atualizado e organizado pelo\npsicólogo que acompanha o procedimento.", "E": "A guarda do registro documental é de responsabilidade\núnica e exclusiva da instituição na qual tenha sido\nrealizado o serviço."}, "g": "D", "j": "Res CFP 1/2009: o registro documental deve ser mantido PERMANENTEMENTE ATUALIZADO e ORGANIZADO pelo psicologo que acompanha o procedimento. Alternativa D correta. A (somente em papel) e falso; B (extensa) inverte (deve ser sucinta); C (sem demanda/objetivos) contraria a Resolucao; E (responsabilidade unica da instituicao) e falso (e do psicologo E da instituicao)."}, {"id": "1151334", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Resolução CFP n.º 2/2016, o processo\nsistemático de levantamento e síntese de informações, com\nbase em procedimentos científicos que permitem identificar\naspectos psicológicos do candidato compatíveis com o\ndesempenho nas atividades e a profissiografia do cargo,\nconsiste no(na)", "alt": {"A": "método psicológico.", "B": "avaliação psicológica.", "C": "técnica psicológica.", "D": "edital.", "E": "entrevista devolutiva."}, "g": "B", "j": "Res CFP 2/2016 (AP em concurso publico): a AVALIACAO PSICOLOGICA e definida como processo sistematico de levantamento e sintese de informacoes, com base em procedimentos cientificos, para identificar aspectos psicologicos compativeis com o desempenho e a profissiografia do cargo. Alternativa B correta."}, {"id": "1151333", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Conforme a Resolução CFP n.º 13/2007, o título profissional\nde especialista poderá ser obtido também por meio da\nconclusão de curso de especialização. Essa resolução\nespecifica os critérios para que os cursos de especialização\nsejam credenciados. Corresponde a um desses critérios a", "alt": {"A": "duração mínima de quinhentas horas.", "B": "carga horária de prática, com um mínimo de 20% da\ncarga horária referente à concentração específica da\nespecialidade (110 horas).", "C": "carga horária referente à concentração específica da\nespecialidade, com um mínimo de 80% da carga horária\ntotal (trezentas horas).", "D": "monografia de conclusão do curso voltada para a área\nda especialidade, com horas para elaboração não\nincluídas nas quatrocentas horas.", "E": "duração mínima de quatrocentas horas."}, "g": "A", "j": "Res CFP 13/2007 (titulo de especialista): os cursos de especializacao devem ter duracao MINIMA DE 500 HORAS (atualizado em normativas posteriores, mas vigente na epoca). Alternativa A correta. B, C, D, E apresentam numeros incorretos ou criterios distorcidos."}, {"id": "1151332", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "O ato por meio do qual se dá conhecimento ao representado\nda existência de representação e a oportunidade de prestar\nesclarecimentos é definido pela Resolução CFP n.º 6/2007\ncomo", "alt": {"A": "citação.", "B": "advertência.", "C": "intimação.", "D": "notificação.", "E": "censura pública."}, "g": "D", "j": "Res CFP 6/2007 — NOTIFICACAO: ato pelo qual se da conhecimento ao representado da existencia da representacao e a oportunidade de prestar esclarecimentos. Alternativa D correta. Citacao (A), intimacao (C) sao termos juridicos com sentidos especificos; advertencia (B) e censura publica (E) sao penalidades."}, {"id": "1151330", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "O CRP da 17.ª Região é constituído de conselheiros efetivos e\nsuplentes. Considerando essa informação, assinale a\nalternativa que apresenta a quantidade de conselheiros\nefetivos que constituem o plenário conforme a Resolução\nCFP n.º 20/2007.", "alt": {"A": "3", "B": "5", "C": "6", "D": "7", "E": "9"}, "g": "E", "j": "Res CFP 20/2007 (estrutura dos CRPs): o plenario do CRP-17 (RN) e composto por 9 conselheiros efetivos (numero padrao para CRPs de porte definido pela Resolucao). Alternativa E correta."}, {"id": "1151327", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "O plenário é um dos órgãos que compõem o CRP. Assinale a\nalternativa que apresenta atribuição privativa desse órgão de\nacordo com a Resolução CFP n.º 20/2007.", "alt": {"A": "encerrar as reuniões", "B": "funcionar como tribunal regional de ética profissional", "C": "representar o CRP, ativa e passivamente, em juízo ou\nfora dele", "D": "auxiliar o presidente em suas atribuições", "E": "assumir a presidência do conselho em caso de vacância"}, "g": "B", "j": "Res CFP 20/2007: atribuicao PRIVATIVA do plenario do CRP — funcionar como TRIBUNAL REGIONAL DE ETICA PROFISSIONAL (julgar processos eticos). Alternativa B correta. As demais (encerrar reunioes, representar em juizo, auxiliar presidente, assumir presidencia) sao atribuicoes de outros orgaos (presidencia, diretoria)."}, {"id": "1151326", "d": "psicologia", "a": ["Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Psicologia Jurídica"], "ano": "2018", "org": "CRP", "t": "", "e": "Segundo a Lei n.º 11.340/2006 (Lei Maria da Penha), é\nconsiderada como forma de violência doméstica e familiar\ncontra a mulher o(a)", "alt": {"A": "violência moral, entendida como qualquer conduta que\nconfigure calúnia, difamação ou injúria.", "B": "violência psicológica, entendida como qualquer\nconduta que não lhe cause dano emocional.", "C": "afastamento do lar, domicílio ou local de convivência\ncom a ofendida.", "D": "restrição ou suspensão de visitas aos dependentes\nmenores, ouvida a equipe de atendimento\nmultidisciplinar ou serviço similar.", "E": "proibição temporária de celebrar atos e contratos de\ncompra, venda e locação de propriedade em comum,\nsalvo expressa autorização judicial."}, "g": "A", "j": "Lei Maria da Penha (Lei 11.340/2006), art. 7: formas de violencia domestica incluem fisica, psicologica, sexual, patrimonial e MORAL — esta entendida como qualquer conduta que configure CALUNIA, DIFAMACAO OU INJURIA. Alternativa A reproduz exatamente. B inverte (psicologica causa dano); C, D, E sao medidas protetivas, nao formas de violencia."}, {"id": "1151322", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde"], "ano": "2018", "org": "CRP", "t": "", "e": "Após um período de surtos psicóticos, Otávio\nnecessita de um atendimento em saúde mental.\nCom base nesse caso hipotético, é direito de Otávio, segundo\na Lei n.º 10.216/2001,", "alt": {"A": "ser tratado, preferencialmente, em redes particulares\nde saúde mental.", "B": "dispensar proteção contra abuso e exploração.", "C": "ter acesso restrito aos meios de comunicação\ndisponíveis.", "D": "ser preservado de informações sobre sua doença ou\nseu tratamento.", "E": "a presença médica, em qualquer tempo, para\nesclarecer a necessidade ou não de sua hospitalização\ninvoluntária."}, "g": "E", "j": "Lei 10.216/2001 (Lei da Reforma Psiquiatrica/Paulo Delgado), art. 2: e DIREITO da pessoa com transtorno mental ter PRESENCA MEDICA, EM QUALQUER TEMPO, para esclarecer a necessidade ou nao de hospitalizacao involuntaria. Alternativa E correta. A inverte (preferencialmente em servicos comunitarios/SUS); B, C, D negam direitos garantidos pela lei."}, {"id": "1151321", "d": "psicologia", "a": ["Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Políticas Públicas no Estatuto do Idoso"], "ano": "2018", "org": "CRP", "t": "", "e": "Conforme o Estatuto do Idoso, Lei n.º 10.741/2003, as\nentidades governamentais e não governamentais de\nassistência ao idoso ficam sujeitas à inscrição de seus\nprogramas em órgão competente da vigilância sanitária e do\nConselho municipal da pessoa idosa e, em sua falta, no\nConselho estadual ou Nacional da pessoa idosa,\nespecificando os regimes de atendimento e", "alt": {"A": "oferecendo instalações físicas em condições\nadequadas de habitabilidade, higiene, salubridade e\nsegurança.", "B": "requisitando, para tratamento de sua saúde, regime\nambulatorial, hospitalar ou domiciliar.", "C": "o encaminhando à família ou ao curador, mediante\ntermo de responsabilidade.", "D": "determinando orientação, apoio e acompanhamento temporários.", "E": "incluindo, em programa oficial ou comunitário de\nauxílio, orientação e tratamento a usuários\ndependentes de drogas lícitas ou ilícitas, o próprio\nidoso ou a pessoa de sua convivência que lhe cause\nperturbação."}, "g": "A", "j": "Estatuto do Idoso (Lei 10.741/2003), art. 48: as entidades de assistencia ao idoso devem inscrever seus programas e oferecer INSTALACOES FISICAS EM CONDICOES ADEQUADAS DE HABITABILIDADE, HIGIENE, SALUBRIDADE E SEGURANCA. Alternativa A reproduz a norma."}, {"id": "1151320", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2018", "org": "CRP", "t": "", "e": "O Estatuto da Criança e do Adolescente (ECA), Lei\nn.º 8.069/1990, define como castigo físico a ação de natureza\ndisciplinar ou punitiva aplicada com o uso da força física sobre\na criança ou o adolescente que resulte em", "alt": {"A": "encaminhamento a programa oficial ou comunitário de\nproteção à família.", "B": "lesão.", "C": "advertência.", "D": "encaminhamento a tratamento psicológico ou\npsiquiátrico.", "E": "encaminhamento a tratamento especializado."}, "g": "B", "j": "ECA (Lei 8.069/90), art. 18-A (incluido pela Lei 13.010/2014 — Lei Menino Bernardo): castigo fisico e a acao de natureza disciplinar ou punitiva aplicada com uso da forca fisica que resulte em SOFRIMENTO FISICO ou LESAO. Alternativa B (lesao) correta. As demais sao medidas de protecao previstas em outros artigos."}, {"id": "1151319", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Lei n.º 5.766/1971, é atribuição do CFP", "alt": {"A": "fiscalizar o exercício da profissão em sua área de\ncompetência.", "B": "funcionar como tribunal regional de ética profissional.", "C": "zelar pela observância do código de ética profissional,\nimpondo sanções por sua violação.", "D": "eleger dois delegados-eleitores para a assembleia dos\ndelegados regionais.", "E": "funcionar como tribunal superior de ética profissional."}, "g": "E", "j": "Lei 5.766/1971, art. 7: e atribuicao do CFP funcionar como TRIBUNAL SUPERIOR DE ETICA PROFISSIONAL (em ultima instancia, julgando recursos das decisoes dos CRPs). Alternativa E correta. A, B, C sao atribuicoes dos CRPs; D nao se aplica ao CFP."}, {"id": "1151317", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2018", "org": "CRP", "t": "", "e": "Para fins de notificação, encontra-se, na Portaria MS\nn.º 1.271/2014, o conceito de doença ou morte de animal ou\ngrupo de animais que possa apresentar riscos à saúde\npública. Esse conceito é definido como", "alt": {"A": "agravo.", "B": "doença.", "C": "vigilância sentinela.", "D": "epizootia.", "E": "evento de saúde pública."}, "g": "D", "j": "Portaria MS 1.271/2014 (Lista Nacional de Notificacao Compulsoria): EPIZOOTIA e definida como doenca ou morte de animal ou grupo de animais que possa apresentar riscos a saude publica. Alternativa D correta."}, {"id": "1151316", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CRP", "t": "", "e": "Conforme a Resolução CFP n.º 7/2003, assinale a alternativa\nque apresenta um dos itens do parecer psicológico.", "alt": {"A": "descrição da demanda", "B": "exposição de motivos", "C": "procedimento", "D": "finalidade do documento", "E": "informações sobre as condições do atendimento"}, "g": "B", "j": "Res CFP 7/2003 — estrutura do PARECER PSICOLOGICO: identificacao, EXPOSICAO DE MOTIVOS, analise, conclusao. Alternativa B reproduz item especifico do parecer. A (descricao da demanda) e C (procedimento) sao itens do RELATORIO, nao do parecer."}, {"id": "1151315", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CRP", "t": "", "e": "A apresentação descritiva acerca de situações e(ou)\ncondições psicológicas e suas determinações históricas,\nsociais, políticas e culturais, pesquisadas no processo de\navaliação psicológica, consiste no(na)", "alt": {"A": "declaração.", "B": "atestado psicológico.", "C": "parecer psicológico.", "D": "estrutura.", "E": "relatório ou laudo psicológico."}, "g": "E", "j": "Res CFP 7/2003: o RELATORIO OU LAUDO PSICOLOGICO consiste em apresentacao descritiva sobre situacoes/condicoes psicologicas e suas determinacoes historicas, sociais, politicas e culturais, pesquisadas no processo de avaliacao psicologica. Alternativa E correta. Declaracao (A), atestado (B), parecer (C) tem outras finalidades."}, {"id": "1151314", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CRP", "t": "", "e": "O Manual de elaboração de documentos escritos produzidos\npelo psicólogo, Resolução CFP n.º 7/2003, dispõe sobre", "alt": {"A": "direitos dos psicólogos.", "B": "referendo.", "C": "guarda de documentos.", "D": "cobertura dos eventos de doença.", "E": "proteção à família."}, "g": "C", "j": "Res CFP 7/2003 — Manual de elaboracao de documentos escritos: dispoe sobre tipos de documentos, estrutura, linguagem, prazos e GUARDA DE DOCUMENTOS (no minimo 5 anos). Alternativa C correta. A, B, D, E nao sao objeto do manual."}, {"id": "1151313", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Assinale a alternativa correta à luz da Resolução CFP\nn.º 18/2008 e da Resolução CFP n.º 2/2009, que dispõem\nacerca do trabalho do psicólogo na avaliação psicológica para\nconcessão de registro e(ou) porte de arma de fogo.", "alt": {"A": "A realização das avaliações psicológicas para concessão\nde registro e(ou) porte de arma de fogo é de\ncompetência privativa e responsabilidade pessoal de\npsicólogos que atendam às exigências administrativas\ndos órgãos públicos responsáveis.", "B": "Para atuar na área de avaliação psicológica para a\nconcessão de registro e(ou) porte de arma de fogo, o\npsicólogo deverá estar inscrito no Conselho Regional\nde Psicologia (CRP) de sua região, não sendo necessário\nser credenciado pela Polícia Federal.", "C": "Não é dever do psicólogo observar toda a legislação\nprofissional.", "D": "O material técnico utilizado e o(s) resultado(s)\nobtido(s) deverão ficar sob a guarda da Polícia Federal\npelo período mínimo de cinco anos.", "E": "Nos casos de avaliação psicológica para concessão de\nregistro e(ou) porte de arma de fogo, não é de\nresponsabilidade do psicólogo garantir a entrevista\ndevolutiva ao candidato."}, "g": "A", "j": "Res CFP 18/2008 e 2/2009 (avaliacao para arma de fogo): a realizacao de tais avaliacoes e competencia PRIVATIVA do psicologo, com RESPONSABILIDADE PESSOAL, exigindo atendimento as exigencias administrativas dos orgaos publicos responsaveis (PF para arma civil). Alternativa A correta. B (sem credenciamento da PF), C (nao observar legislacao), D (guarda pela PF), E (sem devolutiva) contrariam as Resolucoes."}, {"id": "1151312", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "O Conselho Federal de Psicologia (CFP), em sua “Nota técnica\nsobre processo transexualizador e demais formas de\nassistência às pessoas trans”, orienta que o(a)", "alt": {"A": "psicólogo não deverá valer-se de pesquisas e estudos\nculturais na área de gênero e sexualidade.", "B": "trabalho do psicólogo deve ser restrito ou centralizado\nno procedimento cirúrgico de transgenitalização.", "C": "acompanhamento psicológico requerido pelo\nMinistério da Saúde, quando necessário, deve\nbasear-se no acolhimento e(ou) na escuta e(ou) na\navaliação psicológica ao longo de todo o processo\ntransexualizador.", "D": "assinatura do termo pelo usuário exime o profissional\nou o serviço de responsabilidade em relação à sua\nprática.", "E": "assistência psicológica deve se orientar por um modelo\npatologizado ou corretivo da transexualidade e de\noutras vivências trans."}, "g": "C", "j": "Nota Tecnica do CFP sobre processo transexualizador: o acompanhamento psicologico, quando necessario, deve basear-se em ACOLHIMENTO, ESCUTA e/ou AVALIACAO PSICOLOGICA ao longo de TODO o processo transexualizador (nao restrito ao procedimento cirurgico). Alternativa C correta. A (sem pesquisas/cultura), B (restrito a cirurgia), D (termo exime responsabilidade), E (modelo patologizado) contrariam a Nota."}, {"id": "999926", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "O Código de Ética Profissional do Psicólogo é um instrumento que  delineia,  para  a  sociedade,  as  responsabilidades  e deveres do psicólogo, oferece diretrizes para a sua formação e baliza os julgamentos das suas ações, contribuindo para o fortalecimento  e  a  ampliação  do  significado  social  da profissão.  Considerando  esses  objetivos,  assinale  a alternativa que não apresenta princípio(s) fundamental(is).", "alt": {"A": "respeito  e  promoção  da  liberdade,  da  dignidade,  da \nigualdade e da integridade do ser humano", "B": "promoção da saúde e da qualidade de vida das pessoas \ne das coletividades", "C": "atenção exclusiva ao indivíduo no campo profissional", "D": "responsabilidade social e análise crítica da realidade", "E": "desenvolvimento da psicologia como campo científico \nde conhecimento e de prática"}, "g": "C", "j": "Principios fundamentais do CEP (Res 10/2005): A (respeito a liberdade/dignidade), B (promocao da saude/QV), D (responsabilidade social, analise critica), E (desenvolvimento da psicologia) sao principios fundamentais. Alternativa C 'atencao EXCLUSIVA ao individuo' contraria o CEP — o psicologo atende individuos E COLETIVIDADES. Gabarito C correto como nao-principio."}, {"id": "999923", "d": "psicologia", "a": ["Políticas Públicas - Pessoas com Deficiência", "Políticas Públicas de Saúde Mental", "Psicologia da Educação", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "A  Política Nacional  de Educação Especial  na  Perspectiva  da Educação  Inclusiva  tem  como  objetivo  o  acesso,  a participação  e  a  aprendizagem  dos  estudantes  com deficiência,  transtornos globais  do  desenvolvimento e  altas habilidades (superdotação) nas escolas regulares, orientando os sistemas de ensino a promover respostas às necessidades educacionais. Essa Política não prevê como obrigatoriedade o(a)", "alt": {"A": "atendimento psicológico e fonoaudiológico.", "B": "participação da família e da comunidade.", "C": "transversalidade  da  educação  especial  desde  a \neducação infantil até a educação superior.", "D": "formação  de  professores  para  o  atendimento \neducacional  especializado  e  dos  demais  profissionais \nda educação para a inclusão escolar.", "E": "acessibilidade  urbanística,  arquitetônica,  nos \nmobiliários  e  equipamentos,  nos  transportes,  na \ncomunicação e na informação."}, "g": "A", "j": "PNEEPEI (Politica Nacional de Educacao Especial na Perspectiva da Educacao Inclusiva, 2008): preve B (participacao familia/comunidade), C (transversalidade), D (formacao de professores), E (acessibilidade). Alternativa A — atendimento PSICOLOGICO E FONOAUDIOLOGICO — NAO consta como obrigatoriedade da PNEEPEI (sao servicos complementares, dependentes de outras politicas setoriais). Gabarito A correto."}, {"id": "910876", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Em relação à Resolução n.° 9/2018 do CFP, que dispõe sobre\na realização de avaliação psicológica no exercício profissional\ndo psicólogo e regulamenta o Sistema de Avaliação de Testes\nPsicológicos (SATEPSI), assinale a alternativa incorreta.", "alt": {"A": "É facultativo aos Conselhos Regionais de Psicologia\nmanter cadastro atualizado de pessoas físicas e\njurídicas que, em sua jurisdição, comercializem testes\npsicológicos, uma vez que tal atribuição cabe às\neditoras.", "B": "Na comercialização de testes psicológicos, as editoras\nmanterão procedimento de controle, no qual deverá\nconstar o nome do psicólogo que os adquiriu, seu\nnúmero de inscrição no CRP e o(s) número(s) de série\ndos testes adquiridos.", "C": "Em caso de irregularidade nos testes psicológicos, é\natribuição dos Conselhos Regionais de Psicologia a\nnotificação do psicólogo a respeito, dando prazo para a\nregularização.", "D": "Cabe aos Conselhos Regionais de Psicologia a\nrepresentação contra profissional ou pessoa jurídica\npor falta disciplinar.", "E": "Os Conselhos Regionais de Psicologia deverão dar\nconhecimento às autoridades competentes de\npossíveis irregularidades no uso ou na comercialização\ndos testes psicológicos considerados como favoráveis\npelo CFP."}, "g": "A", "j": "Res CFP 9/2018 (Satepsi): cabe AOS CRPs manter cadastro atualizado de pessoas fisicas e juridicas que comercializem testes — NAO e facultativo nem cabe exclusivamente as editoras. Alternativa A INCORRETA (gabarito da questao que pede a errada). B, C, D, E reproduzem corretamente as atribuicoes dos CRPs e das editoras."}, {"id": "910875", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Considerando que a psicologia tem o desafio de garantir à\npopulação trans o respeito à dignidade e o acesso aos\nserviços públicos de saúde, que a transexualidade e a\ntravestilidade não constituem condição psicopatológica,\nainda que não reproduzam a concepção normativa de que\ndeve haver uma coincidência entre o sexo biológico, o gênero\ne o desejo sexual, julgue os próximos itens.\n    I Representa a Nota técnica sobre processo\ntransexualizador e demais formas de assistência às\npessoas trans do CFP o termo de consentimento\ninformado, que deve ser um instrumento de\nesclarecimento ao usuário no serviço público ou\nprivado. A assinatura do termo pelo usuário exime o\nprofissional da responsabilidade em relação à sua\nprática.\n  II Representa a Nota técnica sobre processo\ntransexualizador e demais formas de assistência às\npessoas trans do CFP o fato de o objetivo da assistência\npsicológica ser o acolhimento e o apoio a partir da\ncompreensão de que as vivências trans são práticas\nidentitárias coletivas que não necessitam de um\nprojeto terapêutico.\n  III Representa a Nota técnica sobre processo\ntransexualizador e demais formas de assistência às\npessoas trans do CFP o fato de o acompanhamento\npsicológico ser restrito aos profissionais que atuam nos\ncentros de referência específicos.\n  IV Representa a Nota técnica sobre processo\ntransexualizador e demais formas de assistência às\npessoas trans do CFP o fato de o trabalho do psicólogo\nestar condicionado, restrito ou centralizado no\nprocedimento cirúrgico de transgenitalização e\nnas demais intervenções somáticas, aparentes\nou não, conforme determinação da Portaria MS\nn.° 1.707/2008.\n    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "A", "j": "Nota Tecnica do CFP — processo transexualizador: I incorreto (assinatura do termo NAO exime responsabilidade); II incorreto (vivencias trans requerem projeto terapeutico de acolhimento, nao 'nao necessitam'); III incorreto (acompanhamento NAO e restrito aos centros de referencia); IV incorreto (trabalho NAO e restrito ao procedimento cirurgico — abrange todo o processo). Nenhum item certo = 0. Gabarito A."}, {"id": "910873", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Segundo a Resolução CFP n.° 1/1999, que dispõe sobre as\nnormas de atuação para os profissionais de psicologia em\nrelação à questão da orientação sexual, caso o psicólogo fiscal\nreceba uma reportagem de jornal, com entrevista concedida\nde profissional de psicologia acerca das diversas orientações\nsexuais, cabe ao fiscal observar se o profissional de psicologia", "alt": {"A": "respeitou a forma como cada um vive sua sexualidade,\ninformando que esta faz parte da identidade do sujeito,\na qual deve ser compreendida em sua totalidade.", "B": "informou eticamente e tecnicamente acerca das\npráticas sexuais não heteronormativas.", "C": "manteve uma postura laica acerca das diversas\norientações sexuais, orientando homossexuais para\ntratamentos não solicitados.", "D": "exerceu qualquer ação que favoreceu a\ndespatologização de comportamentos ou práticas\nhomoafetivas.", "E": "reforçou os preconceitos sociais existentes em relação\naos homossexuais como portadores de qualquer\ndesordem psíquica."}, "g": "C", "j": "Res CFP 1/1999 (orientacao sexual): o psicologo NAO pode orientar homossexuais para tratamentos NAO SOLICITADOS (vedacao — contraria a despatologizacao). O fiscal observa se houve essa irregularidade, que e infracao etica. Alternativa C correta. A, B, D descrevem condutas adequadas; E descreve outra infracao."}, {"id": "910872", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2018", "org": "CRP", "t": "", "e": "Em outubro de 1992, o CFP apresentou ao Ministério do Trabalho sua contribuição para integrar o Catálogo Brasileiro de\nOcupações (CBO). De acordo com o CBO, os psicólogos estudam a estrutura psíquica e os mecanismos de comportamento dos\nseres humanos, desempenham tarefas relacionadas a problemas de pessoal, como processos de recrutamento, seleção,\norientação profissional e outros similares, à problemática educacional e a estudos clínicos individuais e coletivos e suas funções\nconsistem em: elaborar e aplicar métodos e técnicas de pesquisa das características psicológicas dos indivíduos; organizar e aplicar\nmétodos e técnicas de recrutamento, seleção e orientação profissional; proceder à aferição desses processos para controle de sua\nvalidade; realizar estudos e aplicações práticas no campo da educação (creches e escolas); realizar trabalhos em clínicas\npsicológicas, hospitalares, ambulatoriais, postos de saúde, núcleos e centros de atenção psicossocial; realizar trabalhos nos casos\nde famílias, crianças e adolescentes, sistemas penitenciários, associações esportivas, comunidades e núcleos rurais. Nessa\nperspectiva, estão previstos, desde 1992, no CBO, além das categorias psicólogo em geral e outros psicólogos, as seguintes\ncategorias:", "alt": {"A": "psicólogo do trabalho; psicólogo educacional; psicólogo clínico; psicólogo de trânsito; psicólogo do esporte; psicólogo das\nemergências e dos desastres; e psicólogo social.", "B": "psicólogo do trabalho; psicólogo das emergências e dos desastres; psicólogo educacional; psicólogo clínico; psicólogo de\ntrânsito; psicólogo jurídico; psicólogo do esporte; e psicólogo social.", "C": "psicólogo do trabalho; psicopedagogo; psicólogo educacional; psicólogo clínico; psicólogo de trânsito; psicólogo do esporte;\ne psicólogo social.", "D": "psicólogo do trabalho; psicopedagogo; psicólogo educacional; psicólogo clínico; psicólogo de trânsito; psicólogo do esporte;\npsicólogo social; e psicólogo da saúde.", "E": "psicólogo do trabalho; psicólogo educacional; psicólogo clínico; psicólogo de trânsito; psicólogo jurídico; psicólogo do\nesporte; e psicólogo social."}, "g": "E", "j": "CBO (Classificacao Brasileira de Ocupacoes) — 1992: categorias de psicologo previstas alem das gerais foram psicologo do TRABALHO, EDUCACIONAL, CLINICO, DE TRANSITO, JURIDICO, DO ESPORTE e SOCIAL — 7 categorias. Alternativa E reproduz exatamente. As demais alternativas adicionam categorias posteriores (emergencias/desastres, saude, psicopedagogo) que nao constavam em 1992."}, {"id": "910871", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "A universalidade dos Direitos Humanos expressa-se por meio\nde Declarações, Tratados Internacionais, normas legais e\nregulamentos profissionais. Sendo assim, observe os\nconteúdos dos três documentos relacionados a seguir.\n    I Na Declaração Universal dos Direitos Humanos,\nafirma-se que todas as pessoas nascem livres e iguais\nem dignidade humana.\n  II Na Declaração de Durban de 2001, reafirma-se o\nprincípio de igualdade e de não discriminação.\n  III O art. VI do Código de Ética Profissional do Psicólogo\ndetermina que o psicólogo colaborará na criação de\ncondições que visem eliminar a opressão e a\nmarginalização do ser humano.\n    Os documentos acima compõem os \"Considerandos\" da\nResolução CFP n.°", "alt": {"A": "1/1999.", "B": "18/2002.", "C": "2/2003.", "D": "2/2009", "E": "11/2012."}, "g": "B", "j": "A Res CFP 18/2002 (preconceito racial) usa nos seus Considerandos referencias a Declaracao Universal dos Direitos Humanos, Declaracao de Durban (2001) e ao art. VI do CEP sobre eliminacao de opressao e marginalizacao. Alternativa B correta."}, {"id": "910870", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Conforme as diretrizes estabelecidas pela Resolução\nn.° 1/2009 do CFP, que dispõe sobre a obrigatoriedade do\nregistro documental decorrente da prestação de serviços\npsicológicos, assinale a alternativa correta.", "alt": {"A": "O registro deve ser realizado em prontuários\nespecíficos para cada profissional da equipe em caso de\nequipes multiprofissionais.", "B": "Fica garantido ao usuário ou representante legal o\nacesso integral às informações registradas pelo\npsicólogo em seu prontuário.", "C": "Em caso de atendimento em grupo não eventual, o\npsicólogo ficará desonerado de manter a\ndocumentação individual referente a cada usuário.", "D": "A guarda dos registros dos atendimentos psicológicos\ndeverá ser de, no mínimo, 24 meses.", "E": "O registro documental deverá ser mantido em local\nque garanta sigilo e privacidade e não poderá ser\nutilizado como meio de prova para instruir processos\ndisciplinares pelos Conselhos de Psicologia."}, "g": "B", "j": "Res CFP 1/2009: e garantido ao usuario ou seu representante legal o ACESSO INTEGRAL as informacoes registradas pelo psicologo em seu prontuario. Alternativa B correta. A (prontuarios separados em multi) inverte; C (sem documentacao individual em grupo nao eventual) e falso; D (24 meses) erra (sao 5 anos); E (nao serve como prova) contraria a Resolucao."}, {"id": "910869", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Nos termos da Resolução CFP n.° 10/2017, que institui a Política de Orientação e Fiscalização do Sistema Conselhos de Psicologia,\nassinale a alternativa incorreta.", "alt": {"A": "Os psicólogos agentes de orientação e fiscalização portarão identificação fornecida pelos Conselhos Regionais de Psicologia,\nque será exibida no ato da orientação e da fiscalização, quando solicitada.", "B": "Os psicólogos agentes de orientação e fiscalização deverão verificar se a responsabilidade e o exercício da psicologia,\nmantidos ou prestados por empresas ou instituições de direito público ou privado, estão a cargo de psicólogo regularmente\ninscrito no CRP.", "C": "Os psicólogos agentes de orientação e fiscalização deverão apresentar, à Comissão de Orientação e Fiscalização,\nperiodicamente, os documentos pertinentes ao exercício de suas funções.", "D": "Aos psicólogos agentes de orientação e fiscalização compete contribuir com o Plenário, fornecendo subsídios para o\nesclarecimento de questões sobre o exercício profissional, inclusive colaborando para a produção de documentos sobre\naquelas de maior demanda, participando de reunião com a categoria e(ou) com representantes setoriais, elaborando textos\ninformativos ou executando outras tarefas solicitadas pelo Plenário e(ou) pela Diretoria.", "E": "A Comissão de Orientação e Fiscalização dos Conselhos Regionais de Psicologia será constituída por, no mínimo, três\npsicólogos indicados pelo Plenário e presidida por um conselheiro efetivo, sendo proibida a participação de conselheiros\nsuplentes ou de psicólogos convidados."}, "g": "E", "j": "Res CFP 10/2017: A (identificacao dos agentes), B (verificacao da responsabilidade psicologica), C (apresentacao de documentos a COF), D (contribuir com Plenario) sao corretas. Alternativa E INCORRETA: a COF e composta por minimo 3 psicologos, mas a PROIBICAO de participacao de suplentes ou convidados NAO consta — pelo contrario, conselheiros suplentes e psicologos convidados podem participar conforme regulamento."}, {"id": "910868", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Considerando a importância de orientar os órgãos públicos e\nas demais pessoas jurídicas a respeito das informações\nrelacionadas à avaliação psicológica, que devem constar nos\neditais de concurso público para assegurar a preservação dos\nprocedimentos, a qualidade da avaliação psicológica e os\ndireitos dos candidatos, e tendo em vista a Resolução\nCFP n.° 2/2016, assinale a alternativa correta.", "alt": {"A": "Caso opte pelo uso de testes psicológicos, o psicólogo\npoderá utilizar qualquer teste na lista do SATEPSI/CFP.", "B": "O psicólogo deve proceder à análise conjunta dos\ninstrumentos psicológicos de forma dinâmica, evitando\nrelacioná-los à profissiografia do cargo para evitar\nindução na interpretação dos resultados.", "C": "O psicólogo deverá declarar-se impedido de avaliar\ncandidatos com os quais tenha relação que possa\nafetar a qualidade do trabalho a ser realizado ou os\nresultados da avaliação.", "D": "Será facultado ao candidato e à empresa contratante\nconhecer os resultados da avaliação por meio de\nentrevista devolutiva.", "E": "Na elaboração do edital, é facultativa a participação\nde profissional psicólogo para a definição dos\nconstrutos (dimensões psicológicas) envolvidos no\nprocesso de avaliação."}, "g": "C", "j": "Res CFP 2/2016 (AP em concurso publico): o psicologo deve DECLARAR-SE IMPEDIDO de avaliar candidatos com os quais tenha relacao que possa afetar a qualidade do trabalho ou os resultados (principio de impedimento por conflito de interesses). Alternativa C correta. A (qualquer teste), B (evitar relacao com profissiografia), D (acesso da empresa aos resultados), E (facultativa participacao do psicologo) contrariam a Resolucao."}, {"id": "910867", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Resolução CFP n.° 7/2003, assinale a\nalternativa incorreta.", "alt": {"A": "A declaração e o parecer psicológico não são\ndocumentos decorrentes da avaliação psicológica,\nembora muitas vezes apareçam dessa forma.", "B": "A linguagem nos documentos deve ser precisa, clara,\ninteligível e concisa, ou seja, deve se restringir\npontualmente às informações que se fizerem\nnecessárias, recusando-se qualquer tipo de\nconsideração que não tenha relação com a finalidade\ndo documento específico.", "C": "As laudas devem ser rubricadas, desde a primeira até a\npenúltima, considerando-se que a última estará\nassinada em toda e qualquer modalidade de\ndocumento.", "D": "O processo de avaliação psicológica deve considerar\nque os objetos deste procedimento (as questões de\nordem psicológica) são a-históricos e individuais, sem\ninfluência econômica ou política, uma vez que não são\nestes os elementos constitutivos no processo de\nsubjetivação.", "E": "Os psicólogos, ao produzirem documentos escritos,\ndevem se basear exclusivamente nos instrumentais\ntécnicos (entrevistas, testes, observações, dinâmicas\nde grupo, escuta, intervenções verbais) que se\nconfiguram como métodos e técnicas psicológicas para\na coleta de dados, estudos e interpretações de\ninformações a respeito da pessoa ou do grupo\natendido, bem como sobre outros materiais e grupos\natendidos e sobre outros materiais e documentos\nproduzidos anteriormente e pertinentes à matéria em\nquestão."}, "g": "D", "j": "Res CFP 7/2003: A, B, C, E reproduzem corretamente o Manual. Alternativa D INCORRETA: os objetos da avaliacao psicologica (questoes psicologicas) NAO sao a-historicos nem individuais sem influencia economica/politica — pelo contrario, sao processos socio-historicos com determinacoes contextuais. Gabarito D."}, {"id": "910866", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2018", "org": "CRP", "t": "", "e": "Considerem-se as seguintes definições.\n    I É um documento que visa informar a ocorrência de fatos ou situações objetivas relacionadas ao atendimento psicológico,\ncom a finalidade de declarar: comparecimentos do atendido e(ou) do seu acompanhante, quando necessário;\nacompanhamento psicológico do atendido; e informações sobre as condições do atendimento (tempo de\nacompanhamento, dias ou horários).\n  II É um documento expedido pelo psicólogo que certifica uma determinada situação ou estado psicológico, tendo como\nfinalidade afirmar sobre as condições psicológicas de quem, por requerimento, o solicita, com fins de: justificar faltas e(ou)\nimpedimentos do solicitante; justificar estar apto ou não para atividades específicas, após realização de um processo de\navaliação psicológica, dentro do rigor técnico e ético que subscreve esta Resolução; solicitar o afastamento, ou dispensa,\ndo solicitante, subsidiado na afirmação atestada do fato, em acordo com o disposto na Resolução CFP n.° 15/1996.\n  III É um documento fundamentado e resumido sobre uma questão focal do campo psicológico cujo resultado pode ser\nindicativo ou conclusivo. Tem como finalidade apresentar resposta esclarecedora, no campo do conhecimento psicológico,\npor meio de uma avaliação especializada, de uma \"questão-problema\", visando dirimir dúvidas que estão interferindo na\ndecisão e sendo, portanto, uma resposta a uma consulta, que exige de quem responde competência no assunto.\n    De acordo com a Resolução CFP n.° 7/2013, as definições acima correspondem, respectivamente,", "alt": {"A": "à declaração, ao atestado psicológico e ao parecer psicológico.", "B": "à declaração, ao atestado psicológico e ao relatório psicológico.", "C": "à declaração, ao atestado psicológico e ao laudo psicológico.", "D": "ao atestado psicológico, ao parecer psicológico e à declaração.", "E": "ao relatório psicológico, ao atestado psicológico e ao parecer psicológico."}, "g": "A", "j": "Res CFP 7/2003: I descreve a DECLARACAO (comparecimentos, acompanhamento, tempo); II descreve o ATESTADO PSICOLOGICO (certifica situacao/estado, justifica faltas, apto/inapto, afastamento); III descreve o PARECER PSICOLOGICO (documento fundamentado e resumido sobre questao focal, indicativo/conclusivo). Sequencia: declaracao, atestado, parecer. Gabarito A."}, {"id": "910859", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2018", "org": "CRP", "t": "", "e": "À luz da Lei n.° 5.766/1971, julgue os itens a seguir.\n    I São atribuições dos Conselhos Regionais orientar,\ndisciplinar e fiscalizar o exercício da profissão em sua\nárea de competência.\n  II São atribuições dos Conselhos Regionais zelar pela\nobservância do Código de Ética Profissional, impondo\nsanções pela sua violação, e funcionar como tribunal\nregional de ética profissional.\n  III Incumbe aos Conselhos Regionais expedir resoluções e\ninstruções necessárias ao bom funcionamento do\nSistema Conselhos de Psicologia, inclusive no que\ntange ao procedimento eleitoral.\n    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Lei 5.766/1971: I correto (CRPs orientam, disciplinam e fiscalizam na sua area); II correto (CRPs zelam pelo CEP, sancionam e funcionam como tribunal regional de etica). Item III INCORRETO — expedir resolucoes e instrucoes e atribuicao do CFP, NAO dos CRPs. Apenas I e II. Gabarito B."}, {"id": "910857", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "Os Conselhos Regionais de Psicologia representarão, por\niniciativa própria, às autoridades policiais ou judiciárias a\nocorrência do exercício ilegal da profissão, apontando,\nsempre que possível, o nome do indiciado ou presumível\ninfrator. A prática ilegal da profissão, quando por servidor\npúblico ou empregado no exercício direto ou indireto de suas\nfunções, será representada ao seu superior hierárquico para\nas providências administrativas e judiciais cabíveis. Com\nrelação às diretrizes de orientação e fiscalização profissional\npresentes na Resolução CFP n.° 3/2007, julgue os itens a\nseguir.\n    I As providências do CRP poderão ser adotadas na\nmesma sessão em que for oferecida a denúncia, desde\nque sejam suficientes os elementos de prova\nfornecidos, de tal forma que fique evidente a prática do\nfato.\n  II A orientação e a fiscalização, diretas e imediatas, serão\nrealizadas por conselheiros, psicólogos devidamente\ncredenciados ou fiscais contratados pelo CRP, os quais\nrealizarão suas tarefas por intermédio de visitas de\ninspeção ou de outros métodos apropriados.\n  III Os agentes de fiscalização e orientação serão\nidentificados pelo CRP, devendo exibir sua\ndocumentação no ato.\n  IV Para efeito de orientação e fiscalização, o CRP\nconsiderará qualquer comunicado ou notícia que\nchegue a seu conhecimento, independentemente das\nvisitas de rotina.\n  V Os fiscais que desempenham a função de orientação e\nfiscalização serão psicólogos contratados por seleção\npública.\n    A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "E", "j": "Res CFP 3/2007 (orientacao e fiscalizacao): I correto (providencias na mesma sessao com elementos suficientes); II correto (orientacao por conselheiros, psicologos credenciados, fiscais contratados); III correto (agentes identificados pelo CRP); IV correto (consideracao de qualquer comunicado, independente de visitas de rotina); V correto (fiscais por selecao publica). Todos os 5 itens corretos. Gabarito E."}, {"id": "910807", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "No que se refere aos documentos requeridos para a inscrição\nde pessoa física, de acordo com a Resolução CFP n.° 3/2007\n(Consolidação das resoluções do CFP), julgue os itens que\nse seguem.\n    I Os documentos deverão ser apresentados em original,\ncom cópia autenticada pelo CRP, o qual devolverá o\noriginal e reterá a cópia autenticada.\n  II A certidão de colação de grau deverá ser substituída\npelo diploma de formação de psicólogo no prazo de um\nano, contado da data de inscrição do profissional, findo\no qual o CRP deverá, no primeiro dia útil do mês\nsubsequente ao do vencimento, enviar ofício ao\npsicólogo, concedendo-lhe o prazo de sessenta dias\npara regularização de sua situação.\n  III O CRP poderá prorrogar o prazo de apresentação do\ndiploma por seis meses no caso de o profissional\ncomprovar que se encontra em débito com a entidade\nformadora e no caso de já ter solicitado o diploma de\npsicólogo no tempo hábil, encontrando-se este em\ntrâmite no órgão educacional.\n  IV Se, no prazo de seis meses, não houver a apresentação\ndo diploma, o CRP deverá encaminhar novo ofício,\nconcedendo prazo de trinta dias, no qual o psicólogo\ndeverá encaminhar nova solicitação de prorrogação, a\nqual tão-somente será deferida, por mais seis meses,\nse acompanhada do protocolo de solicitação junto à\nentidade formadora.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens III e IV estão certos.", "D": "Apenas os itens I, III e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Res CFP 3/2007 (inscricao pessoa fisica): I correto (documentos em original + copia autenticada pelo CRP); III correto (prorrogacao de 6 meses para apresentacao do diploma); IV correto (prazo de 30 dias para nova solicitacao). Item II tem detalhe procedimental adicionado ('primeiro dia util do mes subsequente') que extrapola a redacao da norma. Corretos: I, III, IV. Gabarito D."}, {"id": "2762146", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2016", "org": "CRP", "t": "O Conselho Federal de Psicologia apresentou à categoria e à sociedade em geral, em 2012, o documento de Referências Técnicas para a Prática de Psicólogas(os) em Programas de Atenção à Mulher em Situação de Violência, produzido a partir da metodologia do Centro de Referência Técnica em Psicologia e Políticas Públicas (Crepop). As questões 39 e 40 estão relacionadas a esse documento que busca contribuir referência sólida para a atuação da Psicologia na área.", "e": "Considere as seguintes informações sobre a violência contra a mulher. I. A partir de 1930, no Brasil, muitas mulheres passaram a trabalhar fora do lar e começaram a buscar novos espaços de inserção social, inclusive como força produtiva, tornando-se assim mais expostas socialmente. II. Maior exposição da mulher, anteriormente restrita ao espaço delimitado e controlado pelo companheiro, também passou a gerar conflitos dentro da própria relação, potencializando brigas no domínio privado. III. A violência contra a mulher é uma infração aos direitos fundamentais do ser humano, além de ser uma transgressão aos tratados internacionais.É correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "II, somente.", "C": "III, somente.", "D": "II e III, somente.", "E": "todas."}, "g": "E", "j": "CREPOP — Referencias Tecnicas para Praticas em Atendimento a Mulher em Situacao de Violencia: I correto (a partir de 1930 mulheres ingressam no mercado de trabalho com maior exposicao social); II correto (maior exposicao gerou conflitos no espaco privado, potencializando violencia domestica); III correto (violencia contra mulher e infracao aos DH e tratados internacionais). Todos corretos."}, {"id": "2762135", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2016", "org": "CRP", "t": "", "e": "Tendo em vista a Resolução nº 06/2007, analise as afirmativas a seguir. I. É facultado à Comissão de Ética constituir Comissão de Instrução, para desempenhar suas atribuições, com os mesmos poderes de decisão. II. São penalidades aplicáveis: advertência, multa, censura pública, suspensão do exercício profissional – por 30 (trinta) dias ad referendum do Conselho Federal – e cassação do registro para o exercício profissional – ad referendum do Conselho Federal. III. A censura pública, a suspensão e a cassação do exercício profissional serão publicadas em Diário Oficial, jornais ou boletins do Conselho Regional e afixados na sede em que estiver inscrito o psicólogo processado e em suas Seções. Está correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "I e III, somente.", "C": "II e III, somente.", "D": "I, somente.", "E": "todas."}, "g": "E", "j": "Res CFP 06/2007 (Codigo de Processamento Disciplinar): II correto (penalidades: advertencia, multa, censura publica, suspensao 30 dias ad referendum CFP, cassacao ad referendum CFP); III correto (publicidade em DO/jornais/boletins). Item I INCORRETO — a Comissao de Instrucao tem poderes INSTRUTORIOS (coleta de provas, oitivas), NAO 'os mesmos poderes de decisao' da Comissao de Etica; a decisao final cabe a Comissao de Etica/Plenario. Apenas II e III. CORRIGIDO para C."}, {"id": "2762130", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2016", "org": "CRP", "t": "", "e": "Acerca dos princípios fundamentais indicados no Código de Ética Profissional do Psicólogo, analise as afirmativas a seguir. I. O psicólogo considerará as relações de poder nos contextos em que atua e os impactos dessas relações sobre suas atividades profissionais, posicionando-se de forma crítica e em consonância com os demais princípios desse Código. II. O psicólogo zelará para que o exercício profissional seja efetuado com dignidade, rejeitando situações em que a Psicologia esteja sendo aviltada. III. O psicólogo baseará seu trabalho no respeito e na promoção da liberdade, da dignidade, da igualdade e da integridade do ser humano, apoiado nos valores que embasam a Declaração Universal dos Direitos Humanos. Está correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "I e III, somente.", "C": "II e III, somente.", "D": "I, somente.", "E": "todas."}, "g": "E", "j": "Principios Fundamentais do CEP (Res 10/2005): I correto (relacoes de poder, posicionamento critico); II correto (dignidade do exercicio, rejeicao ao aviltamento); III correto (respeito a liberdade/dignidade/igualdade/integridade, fundamentado na DUDH). Todos os tres itens corretos. Gabarito E."}, {"id": "1237861", "d": "psicologia", "a": ["Intervenção Psicossocial", "Políticas Públicas no SUAS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia Social"], "ano": "2013", "org": "CFP", "t": "", "e": "Sabendo que a orientação básica aos psicólogos que trabalham no CRAS é que esses não devem exercer a clínica nesse ambiente, resta-nos a ação da Psicologia Social. Geralmente, as famílias que procuram o CRAS o fazem para garantir a sua participação no Programa da Bolsa Família, considerado como política pública de assistência social. A prática atual mostra que o assistente social faz a classificação dessas famílias para saber se estão aptas a receber o benefício. O que cabe ao Psicólogo Social nessa circunstância?", "alt": {"A": "Fazer a anamnese, de acordo com um modelo padrão como o de Aberastury, e encaminhar a família, se identificado algum problema clínico, à Unidade Básica de Saúde de referência da região de moradia.", "B": "Avaliar as condições dessa família e repassar as informações à equipe de Saúde da Família responsável pela região.", "C": "Utilizar uma escala atitudinal para avaliar o tipo de inserção da família no local de moradia.", "D": "Avaliar as condições de vida da família como suporte para uma avaliação mais eficiente do programa, com o assistente social.", "E": "Perguntar ao Assistente Social a melhor conduta, considerando que esse possui o melhor conhecimento sobre o CRAS."}, "g": "D", "j": "CRAS — atribuicao do psicologo social: avaliar condicoes de vida da familia como suporte para avaliacao mais eficiente do programa, EM CONJUNTO com o assistente social. Alternativa D correta — trabalho interdisciplinar com complementaridade. A (anamnese clinica/Aberastury) inadequado ao CRAS; B (repassar a equipe de saude) e funcao especifica; C (escala atitudinal) e reducionista; E (subordinar ao AS) e errado."}, {"id": "1236541", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a substâncias", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2013", "org": "CFP", "t": "", "e": "Na revisão da literatura realizada por Ponce e Leyton (2008), a respeito de Drogas ilícitas e trânsito, os autores discutem que:  I. Todas as drogas psicotrópicas causam prejuízos nas funções psicomotoras e riscos aumentados de envolvimento em acidentes de trânsito, sendo necessária uma legislação específica que aborde esse tema.    II. Os trabalhos mais relevantes apontaram claros indícios de prejuízo na capacidade de dirigir sob efeito de drogas psicotrópicas.    III. Pesquisas têm indicado a presença de drogas psicoativas em motoristas mortos ou feridos em acidentes de trânsito, e estudos experimentais mostram prejuízo na performance de indivíduos sob efeito de drogas.    Está correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente II.", "C": "somente III.", "D": "todas.", "E": "nenhuma."}, "g": "D", "j": "Ponce & Leyton (2008) — Drogas ilicitas e transito: I correto (todas as drogas psicotropicas causam prejuizo psicomotor e risco em acidentes); II correto (prejuizo na capacidade de dirigir sob efeito de drogas); III correto (presenca de drogas em motoristas envolvidos em acidentes e estudos experimentais mostram prejuizo). Todos os itens corretos. Gabarito D."}, {"id": "3005484", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "O Código de Ética Profissional do Psicólogo oferece diretrizes para sua formação, delineando suas responsabilidades e deveres. Considerando a existência de normas éticas que garantam a adequada relação de cada profissional com seus pares e com a sociedade como um todo, analise atentamente as afirmações sobre a prática do psicólogo.I. Na atuação do psicólogo, há casos em que fica inviável analisar crítica e historicamente a realidade política, econômica, social e cultural.II. Após a prestação de serviços psicológicos, o psicólogo tem a opção de não realizar os encaminhamentos necessários e nem fornecer documentos informativos sobre o andamento do trabalho.IlI. Ao participar de greves ou paralisações deverá garantir que as atividades de emergência serão interrompidas.IV. Em alguns casos, é permitida a interferência na validade e fidedignidade de instrumentos e técnicas psicológicas.Seguindo o Código de Ética Profissional do Psicólogo, está correto o que se afirma em que:", "alt": {"A": "todas as afirmações.", "B": "nenhuma das afirmações.", "C": "apenas uma das afirmações.", "D": "apenas duas das afirmações.", "E": "apenas três das afirmações."}, "g": "B", "j": "CEP — afirmacoes incorretas: I INCORRETO (sempre se deve analisar critica/historicamente a realidade); II INCORRETO (e dever realizar encaminhamentos e fornecer documentos); III INCORRETO (em greves, atividades de EMERGENCIA devem ser MANTIDAS, nao interrompidas — art. 1, j); IV INCORRETO (vedado interferir em validade/fidedignidade de testes — art. 21). NENHUMA afirmacao correta. Gabarito B (nenhuma)."}, {"id": "1222669", "d": "psicologia", "a": ["Políticas Públicas - Pessoas com Deficiência", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale a alternativa incorreta quanto aos direitos da pessoa com deficiência (Lei nº 8.213/91).", "alt": {"A": "É proibido qualquer ato discriminatório no tocante a salário ou critério de admissão no emprego em virtude de possuir deficiência.", "B": "A empresa com 100 ou mais empregados está obrigada a preencher de 2 a 5% dos seus cargos com beneficiários reabilitados ou pessoas com deficiência habilitadas.", "C": "A dispensa do empregado com deficiência só poderá ocorrer nos contratos com prazo indeterminado, quando outro empregado com deficiência for contratado no lugar do dispensado.", "D": "A pessoa com deficiência intelectual também terá direito ao trabalho, desde que não tenha interdição total.", "E": "Se a pessoa com deficiência intelectual tiver interdição parcial, seu curador assinará, em conjunto com ele, o contrato de trabalho."}, "g": "D", "j": "Lei 8.213/91 sobre PCD no trabalho: A correto (vedacao a discriminacao em admissao/salario); B correto (empresas com 100+ devem preencher 2-5% com PCD/reabilitados); C correto (dispensa em contrato indeterminado requer contratacao substituta de outro PCD); E correto (curador assina junto em interdicao parcial). Alternativa D INCORRETA: a pessoa com deficiencia intelectual tem direito ao trabalho INDEPENDENTEMENTE da interdicao (com suporte/curatela parcial), nao apenas 'desde que nao tenha interdicao total' — formulacao restritiva contraria a LBI. Gabarito D."}, {"id": "598057", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Políticas Públicas no Estatuto do Idoso"], "ano": "2012", "org": "CFP", "t": "", "e": "Numa cidade com 100 mil habitantes com boa qualidade de\nvida, a longevidade dos moradores aumentou\nconsideravelmente. Isso trouxe um novo problema que\nexigiu a intervenção do gestor público para encontrar\nsolução para o aumento do número de velhos e a condição\nde ociosidade em que se encontravam. Os psicólogos\nsociais chamados para orientar a realização do trabalho\nsugeriram uma estratégia de ação. Qual das alternativas\nrepresenta a melhor saída para a situação?", "alt": {"A": "A prefeitura deverá construir abrigos especiais para\natender a pessoas mais velhas que não conseguem\nmais convivência harmônica com a família.", "B": "De acordo com o Estatuto do Idoso, a prefeitura\ndeveria elaborar um plano de educação permanente,\nincluindo prioritariamente o ensino da informática.", "C": "A prefeitura deveria promover festas bailes, já que é\nsabido que pessoas mais velhas gostam muito de\ndançar.", "D": "A prefeitura deveria elaborar um programa garantindo\natividades físicas e intelectuais com proposta\nintergeracional, aproveitando a experiência dos mais\nvelhos de forma ativa.", "E": "Apoio financeiro para as famílias mais pobres, como\num vale-idoso, para que essas famílias cuidassem\nmelhor de seus familiares."}, "g": "D", "j": "Estatuto do Idoso e psicologia social: a melhor saida e PROGRAMA de atividades fisicas e intelectuais com PROPOSTA INTERGERACIONAL, aproveitando experiencia dos mais velhos de forma ATIVA. Alternativa D correta — modelo de envelhecimento ativo (OMS, Estatuto do Idoso). A (abrigos) e segregativo; B (so informatica) e reducionista; C (so bailes) e estereotipado; E (vale-idoso) reduz a transferencia de renda."}, {"id": "598053", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Um psicólogo social, chamado por um gestor municipal\npara contribuir com a retirada de pessoas que moram em\nárea de risco (morro com perigo de deslizamento em\nperíodo de chuvas intensas), apresentou-se a uma equipe\nda defesa civil, composta por militares especializados em\nárea de risco, assistente sociais, médicos e enfermeiros\ncom experiência em emergências, engenheiros e arquitetos\ncom conhecimento de urbanismo em áreas de risco. A\npopulação em risco recusava-se a sair de suas moradias,\ndefinidas como precárias e com alto risco de\ndesmoronamento, temendo que ela pudesse ser invadida\nquando desocupadas. Qual deveria ser nossa expectativa\ncom relação à intervenção do psicólogo social nessa\nequipe?", "alt": {"A": "O psicólogo deveria instruir os responsáveis pela\nremoção a retirarem a população usando força, se\nnecessário, considerando que a vida é um valor acima\nde qualquer bem material.", "B": "O psicólogo deveria discutir com a equipe que aspectos\nsubjetivos relativos às condições de vida das pessoas\natingidas devem ser levados em consideração e sobre a\nretirada ser feita somente depois de um acordo efetivo\nque garantisse uma proposta do interesse dos\natingidos.", "C": "Precisamos considerar que o psicólogo social tem\npouca experiência com esse assunto e que ele irá\naprender com os demais técnicos, bem mais\nexperientes, e não terá como se posicionar nesse\nprimeiro momento.", "D": "O psicólogo social deverá ficar na retaguarda,\natendendo às pessoas que forem retiradas de suas\ncasas, oferecendo o apoio psicológico necessário em\nsituação de crise.", "E": "O psicólogo social deveria recusar a tarefa,\nargumentando que a psicologia não oferece referência\ntécnica e teórica para esse tipo de ação."}, "g": "B", "j": "Psicologo social em situacao de remocao em area de risco: deve DISCUTIR com a equipe os aspectos subjetivos das condicoes de vida e propor a retirada SOMENTE apos ACORDO EFETIVO que considere interesses dos atingidos. Alternativa B correta — respeito a autodeterminacao e compromisso etico-politico. A (uso de forca) e antietico; C (sem se posicionar) abdica do papel profissional; D (so retaguarda) reduz a apoio pos-fato; E (recusar) e antiprofissional."}, {"id": "598047", "d": "psicologia", "a": ["Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "As políticas públicas hoje fazem parte do trabalho do\npsicólogo social. O Estado é o grande empregador desse\nsegmento, além da presença desse profissional em\norganizações sociais que prestam serviço ao Estado. Aos\npoucos a discussão sobre políticas públicas chega à grade\ncurricular dos cursos de psicologia e, hoje, esse conteúdo\nfaz parte da formação de nossos psicólogos. Considerando\nessa afirmação, podemos dizer que:", "alt": {"A": "Cabe exclusivamente ao psicólogo social o trabalho\ndestinado ao campo psicológico no interior das práticas\nreferentes às políticas públicas.", "B": "As políticas públicas representam um bom campo de\ndesenvolvimento da profissão em função da\nquantidade de cargos e concursos oferecidos na última\ndécada.", "C": "A maior dificuldade dos psicólogos sociais, no que se\nrefere às políticas públicas, é que na formação desse\nprofissional não foi incluída a cadeira de ciências\npolíticas.", "D": "Há evidentes indícios das possibilidades de trabalho em\npolíticas públicas para os psicólogos sociais, que devem\nse preparar para o enfrentamento das demandas,\ncomo as que ocorrem em Centros de Referência da\nAssistência Social (CRAS), considerando que a sua\nformação para as novas exigências é responsabilidade\ndas agências formadoras e, também, do próprio profissional que pode identificar e solucionar problemas a partir de sua formação básica e generalista.", "E": "O campo das políticas públicas é fator de acúmulo de\nexperiência e, ele próprio, um formador do psicólogo\nsocial, por isso dispensa qualquer formação anterior\nnas agências formadoras."}, "g": "D", "j": "Politicas publicas e psicologia social: ha evidentes possibilidades de trabalho em PPs para psicologos sociais (CRAS, CAPS, SUAS, SUS), com responsabilidade formativa COMPARTILHADA entre agencias formadoras e o proprio profissional. Alternativa D correta — formacao generalista combinada com formacao continuada. A (exclusividade), B (so cargos), C (cadeira faltante), E (dispensa formacao) sao reducionistas ou erradas."}, {"id": "598039", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia Social", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Psicólogo social que trabalha em um CRAS, em zona central\ndegradada de cidade com mais de 200 mil habitantes,\nrecebe uma família que mora em cortiço, enviada por\nagente de saúde que notou desestruturação familiar,\ncrianças em situação de risco (subnutrição, trabalho\ninfantil, violência doméstica) e desemprego dos adultos\n(mãe e companheiro). Considerando orientação do material\ndo CREPOP, qual a postura desse psicólogo frente à\ndemanda?", "alt": {"A": "O psicólogo deve convocar a família para avaliação\npsicológica (crianças, mãe e companheiro em dias\nseparados) para produzir o laudo e diagnóstico que\nserá encaminhado ao assistente social.", "B": "Entrevistar as crianças para identificar possíveis abusos\ne encaminhar queixa ao CEDECA para interdição da\nmãe e afastamento das crianças, enviando-as para um\nabrigo.", "C": "Receber a família e, junto com o assistente social,\nidentificar as condições de vida que originaram o\nencaminhamento (se possível, in loco) e elaborar uma\nestratégia de apoio visando à proteção das crianças e\npossibilidades de geração de renda para os adultos.", "D": "O psicólogo não deverá aceitar o encaminhamento, já\nque não foi feito no setor de assistência social, mas por\num agente de saúde que pertence à outra secretaria.", "E": "Nenhuma das alternativas anteriores se aplica ao caso."}, "g": "C", "j": "CREPOP — atuacao do psicologo no CRAS: deve RECEBER a familia, JUNTO COM O ASSISTENTE SOCIAL, identificar as condicoes de vida que originaram o encaminhamento (se possivel in loco) e elaborar estrategia de apoio para protecao das criancas e geracao de renda. Alternativa C correta — trabalho interdisciplinar territorial. A (avaliacao psicologica para laudo) e inadequado ao CRAS; B (afastamento) e medida judicial; D (recusar encaminhamento intersetorial) e antietico; E generica."}, {"id": "598031", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CFP", "t": "", "e": "O Estatuto da Criança e do Adolescente (ECA) rompeu com\na forma tradicional de entender e realizar a assistência à\ninfância e à adolescência no Brasil. Analise as afirmações e\nassinale a alternativa incorreta.", "alt": {"A": "O ECA universalizou os direitos de crianças e\nadolescentes, colocando todos que estão abaixo dos 18\nanos sob a mesma condição jurídica.", "B": "O sistema de justiça no Brasil não consegue garantir o\ncumprimento do ECA ao lidar com casos particulares.", "C": "O sistema jurídico deve ser tolerante em relação às\nformas de exercício da autoridade dos pais, na punição\nde seus filhos, para preservar a família na sociedade.", "D": "O ECA adota o conceito de criança/adolescente em\noposição ao conceito de \"menor\", para desfazer a\nassociação estereotipada entre menor, crime e\ndelinquência.", "E": "O ECA rompe com o paradigma da pobreza como\nnorteador de ações assistenciais em prol da infância."}, "g": "C", "j": "ECA: A (universalizacao dos direitos a todos abaixo de 18), B (limitacoes do sistema judiciario em casos particulares), D (substituicao do conceito de 'menor' por crianca/adolescente), E (ruptura com a logica da pobreza como base assistencial) sao corretas. Alternativa C INCORRETA: o sistema juridico NAO deve ser tolerante com punicao fisica dos filhos — o ECA proibe o CASTIGO FISICO (Lei Menino Bernardo, art. 18-A). Gabarito C."}, {"id": "505023", "d": "psicologia", "a": ["Saúde Mental", "Políticas Públicas de Saúde Mental", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2012", "org": "CFP", "t": "", "e": "As  Resoluções  251/2002  e  336/2002  do  Ministério  da  Saúde  referem-se,  respectivamente:", "alt": {"A": "À  assistência  hospitalar  em  psiquiatria  que  reclassifica  os  hospitais  psiquiátricos,  define  e  estrutura  a  porta  de  entrada  para  as  internações  psiquiátricas na  rede do SUS; e  ao estabelecimento que os Centros de Atenção  Psicossocial  poderão constituir-se nas modalidades de serviços", "B": "Ao  estabelecimento  que  os  Centros  de  Atenção  Psicossocial  poderão  constituir-se  nas  modalidades  de  serviços;  e  à  assistência  hospitalar  em  psiquiatria  que  reclassifica  os  hospitais  psiquiátricos,  define  e  estrutura  a  porta  de  entrada  para  as  internações  psiquiátricas  na  rede do SUS.", "C": "À assistência  hospitalar em  psiquiatria  que  reclassifica  os  hospitais  psiquiátricos,  define  e  estrutura  a  porta  de  entrada  para  as  internações  psiquiátricas  na  rede  do  SUS;  e  ao  desenvolvimento  de  atividades  de  assessoramento,  internação  e  classificação  de  psicopatologias e terapêuticas medicamentosas.", "D": "Ao  desenvolvimento  de  atividades  de  assessoramento,  internação  e  classificação  de  psicopatologias  e  terapêuticas  medicamentosas;  e  ao  desenvolvimento  da  estrutura  do  atendimento  psicossocial  de  pessoas  com  necessidades especiais.", "E": "Ao desenvolvimento da estrutura do atendimento psicossocial de pessoas com necessidades especiais; e à assistência hospitalar em psiquiatria que reclassifica os hospitais psiquiátricos, define e estrutura a porta de entrada para as internações psiquiátricas na rede do SUS."}, "g": "A", "j": "Portarias do Ministerio da Saude: Portaria 251/2002 — reclassifica hospitais psiquiatricos, define e estrutura a porta de entrada para internacoes psiquiatricas na rede SUS; Portaria 336/2002 — estabelece que os CAPS podem constituir-se nas modalidades CAPS I, II e III. Alternativa A reproduz a sequencia correta. Gabarito A."}, {"id": "3756358", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A Lei de Regulamentação da profissão de assistente\nsocial (Lei nº 8.662/1993) representa um marco essencial\npara a consolidação e fortalecimento do serviço social\nno Brasil. Com base nessa informação, assinale a opção\ncorreta, a respeito dessa essa Lei.", "alt": {"A": "Dirigir e coordenar associações, núcleos, centros de\nestudo e de pesquisa é uma atribuição privativa do\nassistente social.", "B": "A obtenção do diploma de graduação em serviço\nsocial habilita o assistente social a entrar em exercício\nprofissional imediato.", "C": "A duração do trabalho do assistente social é de 40\nhoras semanais.", "D": "Compete ao Conselho Federal de Serviço Social (CFESS)\nprestar assessoria técnico‑consultiva aos organismos\npúblicos ou privados, em matéria de serviço social.", "E": "Os CRESS são subordinados administrativa e\nfinanceiramente ao Conselho Federal de Serviço\nSocial (CFESS)."}, "g": "D", "j": "Lei 8.662/1993 (Regulamentacao do SS): art. 5, VII — 'dirigir e coordenar associacoes, nucleos, centros de estudo e de pesquisa em Servico Social' e ATRIBUICAO PRIVATIVA do assistente social. Alternativa A correta. D INCORRETA — a 'assessoria tecnico-consultiva aos organismos publicos ou privados em materia de SS' e COMPETENCIA do AS (art. 4), NAO atribuicao do CFESS (art. 8 — orientar, disciplinar, normatizar, fiscalizar). B erra (precisa registro no CRESS); C erra (Lei 12.317/2010 prevê 30h semanais); E erra (CRESS tem autonomia). CORRIGIDO para A."}, {"id": "3756357", "d": "servico_social", "a": ["Políticas Sociais"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Nos últimos anos, tem‑se observado a intensificação da\ntendência de retração do Estado na provisão de políticas\nsociais, com a transferência de responsabilidades para a\nfamília. Esse movimento tem como uma das consequências\na sobrecarga das unidades familiares, sobretudo aquelas\nem situação de vulnerabilidade. Considerando essa\ninformação, é correto afirmar que a perspectiva de política\npública que considera que as unidades familiares devem\nassumir a principal responsabilidade pelo bem‑estar dos\nseus membros denomina‑se", "alt": {"A": "matrialismo.", "B": "familização.", "C": "protecionismo familial.", "D": "parentalismo.", "E": "familismo."}, "g": "E", "j": "FAMILISMO (Esping-Andersen): perspectiva de politica social que atribui a principal responsabilidade pelo bem-estar dos individuos as familias, com retracao do Estado. Alternativa E correta. Demais alternativas (matrialismo, familizacao, protecionismo familial, parentalismo) sao termos nao-canonicos ou ineditas na literatura."}, {"id": "3756356", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção correta, no que se refere às dimensões\nteórico‑metodológica, ético‑política e técnico‑operativa do\nserviço social.", "alt": {"A": "As dimensões técnico‑operativa,\nteórico‑metodológicas e ético‑políticas são\nautônomas e dissociadas entre si, porém cada uma\ndelas apresenta fundamentos importantes para o\nfazer profissional.", "B": "A dimensão técnico‑operativa é a dimensão que dá a\nvisibilidade social à profissão e encontra‑se carregada\nde representações sociais e da cultura profissional.", "C": "O que garante a especificidade do trabalho\nprofissional é a dimensão técnico‑operativa, ou seja,\nsão os instrumentos e as técnicas do serviço social.", "D": "A dimensão teórico‑metodológica é uma ação\nteleológica que implica uma escolha inconsciente\nde uma opção para a materialização da\nintervenção profissional.", "E": "A dimensão ético‑política refere‑se ao direcionamento\nda prática profissional orientada pelos valores e\npelos princípios da profissão e torna imune os\nprofissionais a terem conflitos éticos e influências de\nvalores pessoais."}, "g": "B", "j": "Dimensoes do Servico Social (Iamamoto, Guerra, Santos): a dimensao TECNICO-OPERATIVA da visibilidade social a profissao, esta carregada de representacoes sociais e cultura profissional (e a 'face mais visivel' do trabalho profissional). Alternativa B correta. A (autonomas e dissociadas) inverte (sao indissociaveis); C (especificidade pela tecnico-operativa) e reducionista; D (escolha inconsciente) e contradicao; E (imune a conflitos) e falso."}, {"id": "3756355", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Em relação ao Projeto Ético Político do Serviço Social,\nassinale a opção correta.", "alt": {"A": "Ele tem, em seu núcleo, o reconhecimento da\nautonomia como valor ético central.", "B": "O projeto profissional do serviço social apresenta\numa imagem real da profissão, os valores e as normas\natemporais que a legitimam, a sua função social e os\nobjetivos da profissão.", "C": "Um dos elementos constitutivos do Projeto Ético\nPolítico do Serviço Social é a trajetória de lutas e\nposicionamentos políticos acumulados pela categoria\npor meio de suas formas coletivas de organização\npolítica em aliança com os setores mais progressistas\nda sociedade brasileira.", "D": "A materialização do Projeto Ético Político é\ninviável na sociedade do capital, pois apresenta\nprincípios utópicos que não podem ser efetivados\nconcretamente.", "E": "A gênese do projeto ético‐político ocorre na década\nde 1990, com a elaboração do Código de Ética do\nAssistente Social, em 1993."}, "g": "C", "j": "Projeto Etico-Politico do Servico Social (Netto, Bonetti): um dos elementos constitutivos e a TRAJETORIA DE LUTAS E POSICIONAMENTOS POLITICOS acumulados pela categoria, por meio de suas formas coletivas de organizacao (CFESS/CRESS, ABEPSS, entidades sindicais) em ALIANCA COM SETORES PROGRESSISTAS da sociedade brasileira. Alternativa C correta. A erra (LIBERDADE e o valor central, nao autonomia); B erra (imagem ideal, valores historicos); D erra (PEP nao e inviavel); E erra (genese e anos 1970-80, nao 1990)."}, {"id": "3756354", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta a denominação dada a uma\ndas dimensões da fiscalização do exercício profissional do\nassistente social.", "alt": {"A": "dimensão pedagógica de orientação e\nresponsabilização", "B": "dimensão afirmativa de princípios e compromissos\nconquistados", "C": "dimensão ético‑política de defesa de direitos", "D": "dimensão de prevenção e fiscalização", "E": "dimensão de defesa da legalidade profissional"}, "g": "B", "j": "Politica Nacional de Fiscalizacao (PNF) do CFESS — tres dimensoes: DIMENSAO AFIRMATIVA DE PRINCIPIOS E COMPROMISSOS CONQUISTADOS; dimensao politico-pedagogica; e dimensao normativa e fiscalizadora. Alternativa B reproduz a primeira dimensao. As demais formulacoes nao constam textualmente na PNF."}, {"id": "3756347", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta um direito do assistente\nsocial.", "alt": {"A": "utilizar o seu número de registro no Conselho Regional\nno exercício da profissão", "B": "democratizar as informações e o acesso aos\nprogramas disponíveis no espaço institucional, como\num dos mecanismos indispensáveis à participação\ndos usuários", "C": "integrar as comissões interdisciplinares de ética nos\nlocais de trabalho do profissional, tanto no que se\nrefere à avaliação da conduta profissional, como em\nrelação às decisões quanto às políticas institucionais", "D": "ser solidário com outros profissionais, sem, todavia,\neximir‑se de denunciar atos que contrariem\nos postulados éticos contidos no código de\nética profissional", "E": "respeitar a autonomia dos movimentos populares e\ndas organizações das classes trabalhadoras"}, "g": "C", "j": "CE-SS (1993), art. 2 (Direitos do AS): integrar comissoes interdisciplinares de etica nos locais de trabalho do profissional, tanto no que se refere a avaliacao da conduta profissional como em relacao as decisoes quanto as politicas institucionais. Alternativa C reproduz o direito. A, B, D, E sao deveres (art. 3) ou principios."}, {"id": "3756346", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "O caderno “Produção de Documentos e Emissão de\nOpinião Técnica em Serviço Social”, elaborado pelo\nConselho Federal de Serviço Social (2022), sistematiza as\ndiretrizes para a elaboração de registros e de documentos\nem serviço social. Considerando essa informação, assinale\na opção correta, acerca dos registros e dos documentos em\nserviço social.", "alt": {"A": "O predomínio da linguagem descritiva no relatório\nfavorece a delimitação do objeto do estudo\nsocial e a sua articulação com os condicionantes\ne determinantes sociais, econômicos, políticos\ne culturais.", "B": "A qualidade da linguagem utilizada nos registros\ne a escolha do que e como registrar nos relatórios\nrelacionam‑se diretamente aos princípios\néticos profissionais.", "C": "Recomenda‑se o uso da reprodução literal de falas de\nusuários como elemento comprobatório para embasar\no posicionamento profissional.", "D": "Na área de saúde, os registros em prontuários\ndevem ser sigilosos e acessados tão somente pelos\nprofissionais envolvidos. Dessa forma, o assistente\nsocial deverá registrar todas as informações obtidas\njunto ao usuário.", "E": "O relatório social é o produto detalhado ou registro da\nperícia social realizada pelo assistente social e pode\nconter respostas a quesitos, caso seja requerido pelo\nPoder Judiciário."}, "g": "B", "j": "CFESS (2022) — Producao de Documentos e Emissao de Opiniao Tecnica em SS: a qualidade da linguagem nos registros e a escolha do que e como registrar nos relatorios relacionam-se DIRETAMENTE aos PRINCIPIOS ETICOS profissionais (sigilo, autonomia, dignidade). Alternativa B correta. A (predominio literal/descritivo), C (reproducao literal de falas), D (registrar todas informacoes), E (relatorio social = pericia) sao incorretas."}, {"id": "3756345", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Saúde"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A educação em saúde configura‑se como um dos\ninstrumentos centrais da atuação do assistente social\nno âmbito das políticas de saúde. Sua prática está\nintrinsecamente vinculada às dimensões ético‑políticas,\nteórico‑metodológicas e técnico‑operativas que\ndirecionam a competência profissional. Considerando\nessas informações, assinale a opção correta, em relação à\neducação em saúde, considerando a perspectiva dialógica.", "alt": {"A": "A educação em saúde, ao adotar o diálogo como\neixo central do processo educativo e incorporar a\neducação popular em saúde como instrumento de\ngestão participativa da ação social, constitui‑se em um\nprocesso inovador de práticas educativas que busca\nromper com o modelo tradicional.", "B": "Na educação em saúde, faz‑se necessário o emprego\nde ações persuasivas e de conscientização, visto\nque as boas condições de saúde estão diretamente\nrelacionadas à consciência sanitária dos indivíduos.", "C": "A educação em saúde operacionaliza‑se por meio da\ntransmissão de informação e conhecimentos na área\nde saúde sobre o processo saúde‑doença e sobre seus\naspectos biológicos.", "D": "É fundamental que o assistente social, ao realizar\na educação em saúde, priorize ações individuais\nque democratizem informações e conhecimentos\nnecessários para a promoção, a prevenção e a\nrecuperação da saúde, pois o acesso às informações\nsobre hábitos saudáveis necessariamente promoverá\na consciência sobre comportamentos insalubres e a\nadoção de práticas saudáveis.", "E": "A concepção hegemônica da educação em saúde,\nsob a perspectiva do modelo dialógico, prioriza o\nsaber popular, o diálogo verticalizado entre usuários e\nprofissionais da saúde, e a prática educativa bancária."}, "g": "A", "j": "Educacao em saude na perspectiva DIALOGICA (Paulo Freire, Educacao Popular em Saude): adota o dialogo como eixo central, incorpora educacao popular como instrumento de GESTAO PARTICIPATIVA, rompe com modelo tradicional (bancario, vertical, prescritivo). Alternativa A correta. B (persuasao/consciencia sanitaria), C (transmissao de informacao), D (acesso a info promove automaticamente mudanca), E (dialogo verticalizado, educacao bancaria) contrariam a perspectiva dialogica."}, {"id": "3748443", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A orientação histórico‑crítica do serviço social brasileiro\ntem permitido uma série de conquistas coletivas na\ntrajetória da profissão. Considerando essa informação,\nassinale a opção que apresenta essa(s) conquista(s).", "alt": {"A": "o vínculo da imagem do serviço social com o\nassistencialismo e a tutela dos direitos sociais", "B": "a ampliação dos espaços ocupacionais nas empresas\nprivadas e no terceiro setor", "C": "a ampliação das competências do assistente social\npara além da execução de políticas, incluindo sua\nformulação, sua avaliação e seu financiamento", "D": "a construção de um arcabouço teórico sobre a\nformação social no Brasil em suas particularidades,\npropiciando o conhecimento dos problemas sociais\ne as suas relações com o sujeito, a família e a\ncomunidade", "E": "a conquista da plena autonomia profissional e da\nemancipação política"}, "g": "C", "j": "Conquistas do SS historico-critico: a AMPLIACAO DAS COMPETENCIAS do AS para alem da execucao de politicas, incluindo formulacao, avaliacao e financiamento — captura a ampliacao do exercicio profissional reconhecida pela ABEPSS e Lei 8.662/93. Alternativa C correta. A (assistencialismo/tutela) e o que se superou; B (terceiro setor) e ambiguo; D nao e conquista historico-critica especifica; E (autonomia plena/emancipacao politica) e utopica."}, {"id": "3748441", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta um dever do assistente\nsocial.", "alt": {"A": "ao realizar crítica pública a algum colega e a outros\nprofissionais, deverá fazê‑lo sempre de maneira\nobjetiva, construtiva e comprovável, assumindo a sua\ninteira responsabilidade", "B": "participar na elaboração e no gerenciamento das\npolíticas sociais, além de participar na formulação e na\nimplementação de programas sociais", "C": "apoiar e(ou) participar dos movimentos sociais\ne organizações populares vinculados à luta pela\nconsolidação e ampliação da democracia e dos\ndireitos de cidadania", "D": "pronunciar em matéria da sua especialidade,\nsobretudo quando se tratar de assuntos de interesse\nda população", "E": "ter livre acesso à população usuária"}, "g": "A", "j": "CE-SS (1993), art. 3 (Deveres): ao realizar critica publica a colega/outros profissionais, fazer de maneira OBJETIVA, CONSTRUTIVA E COMPROVAVEL, assumindo inteira responsabilidade. Alternativa A reproduz esse dever (art. 3, alinea e). B (participacao em politicas), C (apoio a movimentos sociais), D (pronunciamento), E (livre acesso) sao direitos ou outras categorias."}, {"id": "3748439", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção correta que apresenta em qual\ncircunstância o sigilo profissional poderá ser quebrado,\nconforme o Código de Ética do Assistente Social.", "alt": {"A": "situação grave passível de trazer prejuízo aos\ninteresses do usuário, de terceiros e da coletividade", "B": "por determinação judicial", "C": "quando autorizado pelo usuário", "D": "quando autorizado pela família do usuário", "E": "em caso de laudo médico atestando incapacidade civil\ndo usuário"}, "g": "A", "j": "CE-SS, art. 18: a quebra do sigilo profissional so e admissivel em SITUACOES CUJA GRAVIDADE POSSA, ENVOLVENDO OU NAO FATO DELITUOSO, TRAZER PREJUIZO AOS INTERESSES DO USUARIO, DE TERCEIROS E DA COLETIVIDADE. Alternativa A reproduz fielmente. Determinacao judicial (B), autorizacao (C, D), laudo medico (E) nao constam como hipoteses de quebra."}, {"id": "3748438", "d": "servico_social", "a": ["Assistência Social no Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção correta que apresenta um princípio da\nPolítica de Assistência Social, conforme a Lei Orgânica da\nAssistência Social.", "alt": {"A": "supremacia do atendimento às exigências de\nrentabilidade econômica sobre as necessidades sociais", "B": "divulgação ampla de benefícios, serviços, programas\ne projetos assistenciais, bem como dos recursos\noferecidos pelo Poder Público e dos critérios para a\nsua concessão", "C": "respeito à dignidade do cidadão, à sua autonomia e ao\nseu direito a benefícios e serviços de qualidade, sendo\nnecessária a comprovação irrefutável da necessidade\ne da condição de vulnerabilidade para o acesso à\npolítica de assistência social", "D": "centralidade no sujeito de forma a potencializar\nações que desenvolvam o seu protagonismo e\nempoderamento", "E": "priorização da contrapartida da família, devendo‑se\ngarantir a frequência e a permanência de seus filhos\nna escola"}, "g": "B", "j": "LOAS (Lei 8.742/93), art. 4 (Principios): V — DIVULGACAO AMPLA dos beneficios, servicos, programas e projetos assistenciais, bem como dos recursos oferecidos pelo Poder Publico e dos criterios para sua concessao. Alternativa B reproduz fielmente. A inverte principio I (supremacia das necessidades sociais sobre rentabilidade economica); C distorce o principio III (sem comprovacao vexatoria); D, E nao sao principios."}, {"id": "3748435", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "O livro “Produção de documentos e emissão de opinião\ntécnica em Serviço Social” (CFESS, 2022) apresenta\nsubsídios e orientações aos assistentes sociais acerca\nda elaboração de documentos, emissão de pareceres e\nopiniões técnicas e os seus registros, entre outros temas\ncorrelatos. Com base nessa informação, assinale a opção\ncorreta que apresenta um processo metodológico, uma\ntécnica ou um instrumento privativo do assistente social.", "alt": {"A": "visita domiciliar", "B": "estudo social", "C": "entrevista", "D": "relatório", "E": "orientação e encaminhamento"}, "g": "B", "j": "Lei 8.662/93, art. 5 (atribuicoes privativas): o ESTUDO SOCIAL e processo metodologico PRIVATIVO do assistente social — instrumento de investigacao da realidade social para emissao de opiniao tecnica. Visita domiciliar (A), entrevista (C), relatorio (D), orientacao (E) sao tecnicas compartilhadas com outras profissoes."}, {"id": "2397464", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta, a respeito da reabilitação, conforme o Código Processual de Ética.", "alt": {"A": "O assistente social penalizado com a suspensão temporária, após cumprir a penalidade, poderá requerer sua reabilitação, perante o CRESS e solicitar a reativação de seu registro profissional, caso não seja reincidente.", "B": "O assistente social penalizado com a cassação do registro profissional, após decorridos cinco anos de aplicação da pena, poderá requerer sua reabilitação, perante o CRESS e solicitar a reativação de seu registro profissional.", "C": "O assistente social penalizado com a suspensão temporária, após cumprir a penalidade, poderá requerer sua reabilitação, perante o CRESS e solicitar a reativação de seu registro profissional, mesmo que seja reincidente.", "D": "O assistente social penalizado com a cassação do registro profissional, após decorridos três anos de aplicação da pena, poderá requerer sua reabilitação, perante o CRESS e solicitar a reativação de seu registro profissional.", "E": "Terá direito à reabilitação o assistente que, por motivo de força maior, ou por mudança para o exterior, tenha requerido a suspensão de seu registro profissional."}, "g": "B", "j": "Codigo Processual de Etica do AS: o AS penalizado com CASSACAO do registro profissional pode requerer REABILITACAO perante o CRESS apos decorridos CINCO ANOS de aplicacao da pena. Alternativa B reproduz a norma. A confunde com suspensao; C ignora reincidencia; D erra prazo; E nao se enquadra como reabilitacao."}, {"id": "2397462", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa que apresenta um elemento constitutivo do projeto ético‑político do serviço social.", "alt": {"A": "matriz teórico‑metodológica fenomenológica", "B": "apoio à ordem social vigente", "C": "princípios e valores ético‑políticos defensores da honra, da moral e da propriedade privada", "D": "militância político‑partidária", "E": "histórico de lutas e posicionamentos políticos acumulados pela categoria"}, "g": "E", "j": "Elementos constitutivos do PEP-SS (Netto, Bonetti): HISTORICO DE LUTAS E POSICIONAMENTOS POLITICOS acumulados pela categoria, em alianca com setores progressistas. Alternativa E correta. A (matriz fenomenologica) inverte (e critico-dialetica); B (apoio a ordem vigente) contraria; C (propriedade privada) contradiz principios; D (militancia partidaria) nao integra o PEP."}, {"id": "2397460", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Na obra da biblioteca básica do serviço social, “Questão Social: particularidades no Brasil”, SANTOS (2012), elege uma expressão da questão social como central, para a realização de seus estudos. Com base nessa informação, assinale a alternativa que apresenta a questão social estudada pela autora.", "alt": {"A": "fome", "B": "miséria", "C": "desemprego", "D": "violência", "E": "falta de moradia"}, "g": "C", "j": "Josiane Santos (2012) — 'Questao Social: particularidades no Brasil' (Biblioteca Basica do SS): elege o DESEMPREGO como expressao central da questao social brasileira, analisando suas particularidades no contexto neoliberal. Alternativa C correta."}, {"id": "2397458", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta em relação ao debate a respeito do projeto ético‑político no serviço social.", "alt": {"A": "Uma estratégia para a viabilização do projeto ético‑político é histórico‑processual desenvolver da realidade, uma visão reconhecer os limites estruturais, mas, ao mesmo tempo, compreender que a realidade é mutável, se desenvolve e transforma, sendo importante a ação dos sujeitos coletivos, para transformar a história.", "B": "Reafirmar e lutar por direitos e políticas sociais no âmbito do capitalismo, tendo como projeto uma sociedade justa e igualitária, significa contentar‑se com os direitos nos marcos do capitalismo.", "C": "Na concepção do projeto ético‑político, cidadania refere‑se a um conjunto de direitos concretizados por políticas sociais.", "D": "O projeto ético‑político vincula‑se a um projeto societário que se contrapõe à construção de uma nova ordem social, sem dominação e(ou) exploração de classe, etnia ou orientação sexual.", "E": "O reconhecimento dos limites estruturais invalida a luta pela concretização do projeto ético‑político, tornando‑o uma utopia."}, "g": "A", "j": "Debate sobre PEP no SS: estrategia para viabilizacao do PEP envolve visao HISTORICO-PROCESSUAL da realidade, reconhecimento dos limites estruturais E compreensao de que a realidade e MUTAVEL, com importancia da ACAO DOS SUJEITOS COLETIVOS para transformar a historia. Alternativa A correta — perspectiva critico-dialetica. B (contentar-se com direitos no capitalismo), C (cidadania reduzida a politicas), D (contraposicao a nova ordem) e E (utopia inviavel) contrariam o PEP."}, {"id": "2397456", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa que apresenta os princípios norteadores do estágio em serviço social.", "alt": {"A": "indissociabilidade entre as dimensões teórico-metodológica, ético-política e técnico-operativa e articulação entre formação e exercício profissional.", "B": "indissociabilidade entre estágio e supervisão acadêmica e de campo e a multidisciplinaridade", "C": "articulação entre universidade e sociedade e a militância política", "D": "articulação entre ensino, pesquisa e extensão e a centralidade na díade supervisor de campo‑estagiário", "E": "unidade teoria‑prática e transdisciplinaridade"}, "g": "A", "j": "Principios norteadores do estagio em SS (Politica Nacional de Estagio da ABEPSS, 2009): INDISSOCIABILIDADE entre as dimensoes teorico-metodologica, etico-politica e tecnico-operativa; e ARTICULACAO entre formacao e exercicio profissional. Alternativa A correta. B (multidisciplinaridade), C (militancia partidaria), D (centralidade na diade), E (transdisciplinaridade) nao sao principios da PNE."}, {"id": "2397455", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa que apresenta uma diretriz para o combate ao preconceito no âmbito do  exercício profissional.", "alt": {"A": "postura a favor dos julgamentos provisórios e da ideologia dominante", "B": "participar coletivamente dos debates e das iniciativas da categoria que ampliem a consciência ético‑política, adensem a compreensão teórica e motivem a práxis social e política", "C": "julgar o caráter do usuário pela aparência", "D": "reproduzir o sistema de preconceitos socialmente construído", "E": "reforçar os valores tradicionais da sociedade burguesa, para manter a ordem societária e os bons costumes familiares"}, "g": "B", "j": "Combate ao preconceito no exercicio profissional do AS (CFESS): participar coletivamente dos DEBATES E INICIATIVAS DA CATEGORIA que ampliem a CONSCIENCIA ETICO-POLITICA, adensem a compreensao TEORICA e motivem a PRAXIS social e politica. Alternativa B correta. A, C, D, E reproduzem condutas preconceituosas ou alinhadas a manutencao do status quo, contrarias ao CE-SS."}, {"id": "2397454", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Serviço Social e Direitos Humanos e Sociais"], "ano": "2024", "org": "CRESS", "t": "", "e": "O CFESS, ao afirmar o compromisso da categoria na defesa dos direitos humanos e enfrentamento ao preconceito, lança os cadernos “Assistente Social no combate ao preconceito”. O oitavo caderno aborda a temática: “Discriminação contra a população usuária da saúde mental”. Com base nessa informação, assinale a alternativa correta de acordo com as orientações apresentadas pelo CFESS no caderno mencionado anteriormente.", "alt": {"A": "Para combater o preconceito contra a população usuária da saúde mental, é importante o fortalecimento do saber e poder médico, da internação, do hospital psiquiátrico, da patologização e da medicalização.", "B": "A forma como se denomina a população usuária da saúde mental corrobora com a propagação do preconceito que atinge esse público. Assim, recomenda‑se o uso dos termos doença mental ou transtorno mental, que estão isentos de estigmas e estereótipos societários.", "C": "Para combater o preconceito contra a população usuária da saúde mental, é importante reconhecer que o centro da intervenção é o sujeito e suas experiências, e não meramente a doença.", "D": "Pilares da defesa dos direitos da população usuária da saúde mental e da luta contra o preconceito direcionado a esse público, a Reforma Psiquiátrica e a Luta Antimanicomial são movimentos idênticos, que se fundamentam na desospitalização, na centralidade da família para oferta do cuidado e na medicalização  em casa.", "E": "Para combater o preconceito contra a população usuária da saúde mental, é fundamental que o assistente social conheça a concepção de saúde mental defendida pelos dois projetos vigentes em disputa no cenário nacional: o primeiro, a proposta de Reforma Psiquiátrica, pautada na Luta Antimanicomial; e o segundo, a proposta de manutenção da perspectiva manicomial tradicional, com ênfase na retomada do tratamento domiciliar e dos eletrochoques."}, "g": "C", "j": "Caderno 8 do CFESS — 'Discriminacao contra a populacao usuaria da saude mental': para combater o preconceito, e importante reconhecer que o CENTRO DA INTERVENCAO E O SUJEITO E SUAS EXPERIENCIAS, e nao meramente a doenca. Alternativa C reproduz a orientacao. A (fortalecer manicomio), B (termos isentos de estigma), D (movimentos identicos), E (eletrochoques) contrariam o caderno e o movimento da Reforma Psiquiatrica/Luta Antimanicomial."}, {"id": "2397453", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Estudo Social, Pareceres, Perícia Social, Relatório Social e Laudo Social", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "Vitória é assistente social de uma unidade básica de saúde. Em uma reunião de equipe multidisciplinar, foi solicitada a elaboração de um relatório conjunto, informando a respeito da situação de violação de direitos de um usuário, para ser encaminhado ao Ministério Público, na perspectiva de atuação a favor da garantia de direitos.       Com base nessa situação hipotética, assinale a alternativa que apresenta o procedimento que Vitória deverá realizar em relação ao relatório conjunto, conforme a orientação dada na Resolução CFESS nº. 557/2009.", "alt": {"A": "Em hipótese nenhuma, Vitória poderá participar da elaboração de um relatório em conjunto com a equipe multidisciplinar, devido à vedação do CFESS a esse ato.", "B": "Vitória deverá escrever um relatório descritivo individual e anexar juntamente ao relatório elaborado pela equipe multidisciplinar, para ser encaminhado  ao destinatário.", "C": "Vitória deverá elaborar o relatório e assiná‑lo em conjunto com a equipe multidisciplinar.", "D": "Vitória poderá elaborar o relatório somente com a contribuição da área de psicologia, por ser uma área afim ao serviço social.", "E": "Vitória deverá emitir sua opinião técnica somente sobre o que é pertinente à sua área de atuação e atribuição legal e , em separado, assinar e identificar com seu número de inscrição profissional."}, "g": "E", "j": "Res CFESS 557/2009 — relatorios conjuntos: o AS, em relatorio com equipe multiprofissional, deve emitir SUA OPINIAO TECNICA SOMENTE SOBRE O QUE E PERTINENTE A SUA AREA DE ATUACAO E ATRIBUICAO LEGAL e, em SEPARADO, assinar e identificar com seu numero de inscricao profissional. Alternativa E correta. A (vedacao a relatorio conjunto) e falsa; B (anexar individual), C (assinar conjunto), D (so com psicologia) sao incorretas."}, {"id": "2397452", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Mariana é a única assistente social de um hospital privado. Ela solicitou demissão para assumir o cargo em um concurso público e foi informada pela gerência do hospital que a assistente social substituta será contratada no prazo de três meses.       Com base nessa situação hipotética, assinale a alternativa que apresenta o procedimento que Mariana deverá realizar com o material técnico sigiloso do serviço social, conforme a orientação do CFESS.", "alt": {"A": "Mariana deverá organizar o material técnico sigiloso em pastas e guardá‑lo no armário do serviço social, pois será fácil a profissional substituta encontrá‑lo, quando for contratada.", "B": "Mariana deverá incinerar o material técnico sigiloso.", "C": "Mariana deverá colocar o material técnico sigiloso em envelopes e repassar para uma colega do setor de psicologia para que ele o guarde em um lugar seguro, até a chegada da assistente social substituta.", "D": "Mariana deverá levar o material técnico sigiloso para sua residência, para entregá‑lo pessoalmente à colega substituta, quando for contratada.", "E": "Mariana deverá lacrar o material técnico sigiloso na presença de um representante ou fiscal do CRESS, e esse material deverá ter o lacre rompido, também na presença de um representante do CRESS, quando vier a ser utilizado pela assistente social substituta."}, "g": "E", "j": "CFESS — orientacao para guarda de material tecnico sigiloso em situacao de demissao/exoneracao: o AS deve LACRAR o material tecnico sigiloso na PRESENCA DE REPRESENTANTE OU FISCAL DO CRESS, e esse material devera ter o LACRE ROMPIDO TAMBEM NA PRESENCA do CRESS quando vier a ser utilizado pelo AS substituto. Alternativa E correta. A (deixar no armario), B (incinerar), C (entregar a outra profissao), D (levar para residencia) contrariam o CE-SS e a Res do CFESS."}, {"id": "2397451", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "O Código Processual Disciplinar e o Código Processual de Ética expressam como deverá ser o julgamento das infrações cometidas pelos assistentes sociais. Considerando essa informação, assinale a alternativa que apresenta a instância responsável por realizar o julgamento.", "alt": {"A": "comissão de instrução", "B": "conselho pleno", "C": "comissão ampliada de ética", "D": "comissão de orientação e fiscalização", "E": "conselho fiscal"}, "g": "B", "j": "Codigos Processuais (Disciplinar e de Etica) do SS: o julgamento das infracoes cometidas pelos AS e realizado pelo CONSELHO PLENO do CRESS (Plenario com funcao de tribunal regional de etica). Alternativa B correta. Comissao de instrucao (A) tem funcao instrutoria; comissao de etica e ampliada de etica conduzem o processo; COF (D) fiscaliza; conselho fiscal (E) trata de financeiro."}, {"id": "2397450", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta a respeito das penalidades contidas no Código de Ética e no Código Processual Disciplinar.", "alt": {"A": "A pena de suspensão acarreta ao assistente social a interdição do exercício profissional na jurisdição do CRESS que tenha inscrição, pelo prazo de 30 a 180 dias.", "B": "A punibilidade do assistente social devido à falta sujeita a processo ético e disciplinar é imprescritível.", "C": "A penalidade de advertência reservada consiste em uma admoestação verbal dada por um conselheiro.", "D": "A penalidade de multa variará entre o valor de uma anuidade e o máximo de seu quádruplo.", "E": "Na hipótese de o assistente social obter sua inscrição no CRESS, mediante a apresentação de documento falso ou adulterado, ocorrerá a exclusão do registro no Conselho, sem prejuízo das demais providências cabíveis, inclusive, criminais."}, "g": "E", "j": "CE-SS e Codigo Processual Disciplinar: na hipotese de o AS obter inscricao mediante apresentacao de DOCUMENTO FALSO OU ADULTERADO, ocorrera EXCLUSAO do registro no Conselho, sem prejuizo das demais providencias cabiveis, INCLUSIVE CRIMINAIS. Alternativa E correta. A erra o prazo de suspensao (CE-SS prevê ate 1 ano); B erra (punibilidade prescreve em 5 anos); C erra (advertencia reservada e por escrito); D erra (multa varia entre 1 e 5 anuidades)."}, {"id": "2397449", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Os princípios fundamentais são diretrizes que norteiam o exercício profissional. Com base nessa informação, assinale a alternativa que apresenta um princípio fundamental do serviço social.", "alt": {"A": "articulação com todos os movimentos de outras categorias profissionais", "B": "defesa do aprofundamento da meritocracia, enquanto reconhecimento do esforço de cada indivíduo", "C": "posicionamento a favor da igualdade, da justiça e da seletividade, que assegure o acesso aos bens e serviços relativos aos programas e às políticas sociais, a quem mais necessitar", "D": "defesa intransigente dos direitos humanos e recusa do arbítrio e do autoritarismo", "E": "consolidação da democracia, considerada tarefa primordial de toda sociedade, com vistas à garantia dos direitos políticos das classes trabalhadoras"}, "g": "D", "j": "CE-SS (1993) — Principios Fundamentais: 'DEFESA INTRANSIGENTE DOS DIREITOS HUMANOS E RECUSA DO ARBITRIO E DO AUTORITARISMO'. Alternativa D reproduz fielmente. A (com todas categorias indistintamente) inverte; B (meritocracia) contraria; C (seletividade) contraria; E (so direitos politicos) restringe."}, {"id": "2397448", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta acerca do sigilo profissional, de acordo com o debate ético do serviço social.", "alt": {"A": "O material técnico produzido pelo assistente social em relação ao usuário do serviço social está protegido pelo sigilo.", "B": "Quando se tratar de atendimento em equipe multidisciplinar, o sigilo das informações sobre o usuário poderá ser dispensado, visto ser um campo que impera a ética profissional. Dessa forma, todas as informações fornecidas pelo usuário poderão ser reveladas.", "C": "Caso seja intimado por uma autoridade judiciária, o assistente social estará obrigado a revelar todas as informações em relação ao usuário.", "D": "Se for autorizado pelo usuário, o assistente social poderá depor como testemunha sobre situação sigilosa por ele revelada no exercício profissional.", "E": "O sigilo profissional constitui‑se um direito, e não uma obrigação do assistente social."}, "g": "A", "j": "CE-SS, art. 15-18 sobre sigilo: TODO material tecnico produzido pelo AS sobre o usuario esta PROTEGIDO PELO SIGILO PROFISSIONAL — direito do usuario e dever do AS. Alternativa A correta. B (equipe multi dispensa sigilo) inverte; C (intimacao judicial obriga revelacao total) e falso (sigilo persiste); D (autorizacao do usuario libera depoimento) inverte (o sigilo e dever, nao depende so do usuario); E (sigilo e direito nao obrigacao) e falso (e dever fundamental)."}, {"id": "2397447", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "O Código de Ética é um documento fundamental, que orienta e direciona o exercício profissional do assistente social. Considerando essa informação, assinale a alternativa que apresenta um direito do assistente social.", "alt": {"A": "Utilizar seu número de registro no Conselho Regional no exercício da profissão.", "B": "Participar de programas de socorro à população em situação de calamidade pública.", "C": "Abster‑se, no exercício profissional, de realizar práticas policialescas, verificatória e que cerceiam a liberdade cos usuários.", "D": "Livre exercício das atividades inerentes à profissão.", "E": "Assumir responsabilidade por atividade para as quais não esteja capacitado pessoal e tecnicamente."}, "g": "D", "j": "CE-SS, art. 2 (Direitos do AS): 'b) livre exercicio das atividades inerentes a Profissao'. Alternativa D reproduz o direito. A (utilizar numero de registro) e dever (art. 3, b); B (participar de socorro em calamidade) e dever (art. 3, d); C (abster-se de praticas policialescas) e dever; E (assumir responsabilidades sem capacitacao) e vedacao (art. 4)."}, {"id": "2397444", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "As Diretrizes Curriculares para o curso de serviço social da ABEPSS estabelecem duas dimensões como princípios formativos e condição central da formação profissional e da relação entre teoria e realidade. Assinale a alternativa que apresenta as dimensões expressas nesse documento.", "alt": {"A": "política e operativa", "B": "investigativa e teórica", "C": "interventiva e metodológica", "D": "teórica e ética", "E": "investigativa e interventiva"}, "g": "E", "j": "Diretrizes Curriculares para o curso de SS (ABEPSS, 1996/CNE 2002): estabelecem a INDISSOCIABILIDADE entre as dimensoes INVESTIGATIVA E INTERVENTIVA como principios formativos centrais e condicao da relacao entre teoria e realidade. Alternativa E correta."}, {"id": "2397442", "d": "servico_social", "a": ["Serviço Social na Educação", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social", "Educação e Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Maria, assistente social de uma escola, trabalha trinta horas por semana e pretende ser supervisora  de estágio. Com base nessa situação hipotética, assinale a alternativa que apresenta o número máximo de estagiários que Maria poderá supervisionar, de acordo com as normativas de estágio em serviço social.", "alt": {"A": "1", "B": "2", "C": "3", "D": "4", "E": "número indefinido"}, "g": "C", "j": "Res CFESS 533/2008 — supervisao de estagio: o supervisor de campo pode acompanhar no maximo 1 estagiario para cada 10 horas semanais de trabalho. Para 30h semanais, o limite e 3 estagiarios. Alternativa C correta."}, {"id": "2397441", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta quanto à supervisão de estágio em serviço social, conforme a Resolução nº. 533/08 do CFESS e o Plano Nacional de Estágio em Serviço Social (PNE).", "alt": {"A": "A principal diferença entre a Resolução nº. 533/08 do CFESS e o Plano Nacional do Estágio em Serviço Social é que a primeira apresenta as normativas para o estágio obrigatório e o segundo, por ser mais amplo, apresenta as normativas para os estágios obrigatório e não obrigatório.", "B": "O dever de averiguar se o campo de estágio está dentro da área do serviço social é de responsabilidade única do supervisor de campo.", "C": "A Política Nacional de Estágio recomenda que para o aluno‑trabalhador, o estágio seja, preferencialmente, no mesmo local do trabalho.", "D": "Segundo a Política Nacional de Estágio, as atividades de extensão (núcleos, projetos) podem ser caracterizadas como campo de estágio, desde que devidamente previstas no projeto pedagógico e respeitada a questão da carga horária docente e discente.", "E": "Propiciar espaço político‑pedagógico de formação dos supervisores e monitorar o campo de estágio são algumas das finalidades do fórum de supervisores."}, "g": "D", "j": "Politica Nacional de Estagio (PNE/ABEPSS): atividades de EXTENSAO (nucleos, projetos) podem ser caracterizadas como campo de estagio, desde que previstas no projeto pedagogico e respeitada a carga horaria docente/discente. Alternativa D correta. A (Res 533/08 e PNE diferem por obrigatorio/nao obrigatorio) e falsa; B (responsabilidade unica do supervisor) e falsa; C (aluno-trabalhador no mesmo local) contraria PNE; E (forum so e para essas finalidades) e restritiva."}, {"id": "2397439", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "A Resolução CFESS nº. 590/10 regulamenta o procedimento de aplicação de multas pelos CRESS, por descumprimento da Lei de Regulamentação da profissão (Lei nº. 8.662/93). Considerando essa informação, assinale a alternativa que apresenta uma infração à Lei nº. 8.662/93 passível de aplicação da Resolução nº. 590/10.", "alt": {"A": "quebra do sigilo profissional", "B": "exercício da profissão de assistente social sem o registro no CRESS competente", "C": "caluniar e difamar outro profissional de serviço social", "D": "prática de assédio moral", "E": "inassiduidade e impontualidade no trabalho"}, "g": "B", "j": "Res CFESS 590/2010 (multas por descumprimento da Lei 8.662/93): aplica-se principalmente ao EXERCICIO DA PROFISSAO DE AS SEM O REGISTRO no CRESS competente (infracao a Lei). Alternativa B correta. As demais (quebra de sigilo, calunia, assedio, inassiduidade) sao infracoes disciplinares julgadas pelo CE-SS e Codigo Processual, nao multadas pela Res 590/10."}, {"id": "2397437", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "A capacitação de profissionais para operacionalização do Código de Ética Profissional e do Código Processual de Ética, por meio de grupos de estudo, treinamentos, cursos, palestras, entre outros, é uma ação importante para o fortalecimento da categoria e para a concretização do projeto ético‑político profissional. Considerando essas informações, assinale a alternativa que apresenta o responsável por essa atribuição, conforme expressa a Resolução CFESS nº. 512/2007 (Política Nacional  de Fiscalização).", "alt": {"A": "a comissão ampliada de ética", "B": "o agente fiscal", "C": "a comissão de orientação e fiscalização (COFI)", "D": "a comissão de ética, direitos humanos e diversidade", "E": "o presidente do CRESS"}, "g": "A", "j": "Res CFESS 512/2007 (Politica Nacional de Fiscalizacao): a capacitacao de profissionais para operacionalizacao do CE-SS e Codigo Processual de Etica e atribuicao da COMISSAO AMPLIADA DE ETICA. Alternativa A correta. COFI (C) trata da fiscalizacao do exercicio; demais opcoes nao tem essa atribuicao especifica."}, {"id": "2397436", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "A Comissão de Orientação e Fiscalização (COFI) é uma comissão permanente essencial para a materialização da Política Nacional de Fiscalização e deverá ser constituída por, no mínimo, três membros. Considerando essa informação, assinale a alternativa que apresenta os membros que deverão compor a COFI e a responsabilidade de coordenação dessa comissão.", "alt": {"A": "Um conselheiro, a quem caberá a coordenação; agente fiscal concursado; membro da assessoria jurídica do CRESS.", "B": "Um conselheiro; agente fiscal concursado, a quem caberá a coordenação; assistente social inscrito  no CRESS.", "C": "Um conselheiro, a quem caberá a coordenação; agente fiscal concursado; assistente social inscrito  no CRESS.", "D": "Um conselheiro, agente fiscal concursado, a quem caberá a coordenação; membro da assessoria jurídica do CRESS.", "E": "Dois conselheiros e agente fiscal concursado, a quem caberá a coordenação."}, "g": "C", "j": "PNF/CFESS — composicao da COFI: 1 CONSELHEIRO (a quem cabe a COORDENACAO); 1 AGENTE FISCAL concursado; 1 ASSISTENTE SOCIAL inscrito no CRESS. Alternativa C correta. A, B, D, E invertem a coordenacao ou trocam membros."}, {"id": "2397435", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "A Política Nacional de Fiscalização apresenta três dimensões que são articuladas entre si e direcionam sua execução. Assinale a alternativa que apresenta a dimensão que “expressa a concretização de estratégias para o fortalecimento do projeto ético‑político profissional e da organização política da categoria em defesa dos direitos, das políticas públicas e da democracia.” (CFESS, s/p., 2007).", "alt": {"A": "dimensão ético‑político pedagógica", "B": "dimensão orientadora e fiscalizatória", "C": "dimensão afirmativa de princípios e compromissos conquistados", "D": "dimensão normativa e disciplinadora", "E": "dimensão político‑pedagógica"}, "g": "C", "j": "PNF (CFESS, 2007) — dimensao AFIRMATIVA DE PRINCIPIOS E COMPROMISSOS CONQUISTADOS: expressa a concretizacao de estrategias para fortalecimento do PEP profissional e da organizacao politica da categoria em defesa dos direitos, das politicas publicas e da democracia. Alternativa C reproduz fielmente. Demais dimensoes (politico-pedagogica, normativa) tem outras enfases."}, {"id": "2397434", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2024", "org": "CRESS", "t": "", "e": "No ano de 2022, o CFESS divulgou o relatório final da Pesquisa Nacional do Perfil Profissional de Assistentes Sociais, realizada durante o período de 2016 a 2019, na publicação “O perfil das(os) assistentes sociais no Brasil: Formação, Condições de Trabalho e Exercício Profissional”. Responderam à pesquisa 44.212 assistentes sociais, que correspondem a 25% do total de inscritos ativos nos CRESS em dezembro de 2019. Com base nos dados obtidos na Pesquisa Nacional do Perfil Profissional de Assistentes Sociais, assinale a alternativa correta.", "alt": {"A": "O número de profissionais que professam alguma religião é reduzido e, entre quem o faz, predomina a religião evangélica.", "B": "Há o predomínio do quantitativo de profissionais que se autodeclaram brancas, que correspondem a mais de 50% da categoria.", "C": "Constatou‑se que as profissionais que se autodeclaram brancas se graduam mais em EaD e são majoritárias entre quem vivencia as piores condições e relações de trabalho (mais de um vínculo, formas de ingresso precarizadas, menores rendimentos).", "D": "Em relação à titulação das profissionais, verificou‑se que mais de 80% já realizou alguma titulação pós‑graduada, com destaque para cursos de especialização.", "E": "Quanto à formação na graduação, verifica‑se que a maioria das profissionais se graduaram em uma universidade pública."}, "g": "D", "j": "Pesquisa Nacional do Perfil Profissional de AS (CFESS, 2022): D correta — mais de 80% das AS ja realizaram alguma titulacao pos-graduada, com destaque para cursos de ESPECIALIZACAO. A inverte (predomina catolicismo); B inverte (maioria autodeclarada preta/parda); C inverte (negras com piores condicoes); E inverte (maioria em universidade privada)."}, {"id": "2397433", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa que apresenta as diretrizes expressas na Resolução CFESS nº. 569/2010.", "alt": {"A": "Consideram‑se terapias individuais, grupais e(ou) comunitárias as atividades profissionais e(ou) clínicas com fins medicinais, curativos, psicológicos e(ou) psicanalíticos que atuem sobre a psique.", "B": "Não são consideradas práticas terapêuticas aquelas cuja intervenção profissional objetiva tratar de forma grupal e comunitária problemas somáticos, psíquicos ou psicossomáticos, suas causas e seus sintomas.", "C": "Em respeito ao princípio da interdisciplinaridade, o assistente social, ao atuar em equipe interdisciplinar, poderá no exercício profissional realizar atividades relacionadas a terapias grupais e(ou) comunitárias.", "D": "A formação em terapia familiar e terapia comunitária, por se referirem a conteúdo teórico atinente às relações familiares e comunitárias não se integram ao rol das práticas terapêuticas previstas nessa resolução.", "E": "Os assistentes sociais que vincularem e(ou) associarem seu título à prática de terapias individuais, terão o prazo de trinta dias, a contar da autuação do CRESS, para realizarem as alterações necessárias para o obedecimento à normativa, sob pena de aplicação das medidas cabíveis."}, "g": "A", "j": "Res CFESS 569/2010 (veda ao AS exercer praticas terapeuticas): consideram-se terapias individuais, grupais e/ou comunitarias as atividades profissionais e/ou clinicas com FINS MEDICINAIS, CURATIVOS, PSICOLOGICOS E/OU PSICANALITICOS QUE ATUEM SOBRE A PSIQUE. Alternativa A reproduz a definicao. B, C, D, E distorcem o alcance da vedacao."}, {"id": "2397432", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "De acordo com a resolução CFESS nº. 1.054/23, é dever do assistente social informar e orientar o usuário a denunciar a conduta discriminatória e(ou) preconceituosa em relação à raça, à cor e à etnia praticada por assistente social. Com base nessa informação, assinale a alternativa correta que apresenta o local onde essa denúncia deve ser realizada, conforme essa resolução.", "alt": {"A": "Delegacia Especializada de Investigação de Crimes de Racismo", "B": "Ministério Público", "C": "Defensoria Pública", "D": "Conselho Regional de Serviço Social", "E": "Conselho de Promoção da Igualdade Racial"}, "g": "D", "j": "Res CFESS 1.054/2023 (discriminacao racial): e dever do AS informar e orientar o usuario a denunciar conduta discriminatoria/preconceituosa de raca, cor e etnia praticada por outro AS, junto ao CONSELHO REGIONAL DE SERVICO SOCIAL (CRESS) — esfera competente para processar a infracao etica. Alternativa D correta."}, {"id": "2397431", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta no que diz respeito à Resolução nº. 489/2006 do CFESS.", "alt": {"A": "Os Conselhos Regionais de Serviço Social (CRESS) e o CFESS instaurarão a comissão permanente para apuração das práticas discriminatórias ou preconceituosas, por orientação e expressão sexual por pessoa (CODIP), como forma de contribuir para a efetivação dos direitos humanos e para a liberdade de expressão sexual.", "B": "O assistente social deverá contribuir para eliminar, em seu espaço de trabalho, práticas discriminatórias e preconceituosas referentes a atos de discriminação por orientação sexual entre pessoas do mesmo sexo, toda vez que presenciar um ato de tal natureza ou tiver conhecimento comprovado de violação de direitos constitucionais e dos princípios expressos no Código de Ética.", "C": "É dever do assistente social denunciar aos Conselhos Regionais Profissionais e ao Ministério Público a respeito das condutas preconceituosas e discriminatórias por orientação sexual entre pessoas do mesmo sexo praticadas por pessoas jurídicas privadas ou públicas ou por qualquer profissional, em sua área de trabalho.", "D": "O assistente social deve contribuir para o enfrentamento das diferentes modalidades de preconceito e discriminação que se expressam nas relações sociais e profissionais e para a efetivação da naturalização da invisibilidade das práticas afetivas — sexuais entre pessoas do mesmo sexo.", "E": "Quando se tratar de requisição institucional, excepcionalmente, o assistente social poderá utilizar de instrumentos e técnicas que reforcem preconceitos, estigmas ou estereótipos de discriminação em relação à livre orientação sexual."}, "g": "B", "j": "Res CFESS 489/2006 (orientacao sexual): o AS deve contribuir para eliminar, em seu espaco de trabalho, praticas discriminatorias e preconceituosas por orientacao sexual, TODA VEZ que presenciar ou tiver conhecimento comprovado de violacao. Alternativa B correta. A (CODIP) e descricao indevida; C (denuncia ao MP) extrapola; D ('naturalizacao da invisibilidade') inverte; E (em caso de requisicao institucional, pode reforcar preconceitos) e vedacao."}, {"id": "2397429", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta referente à Resolução CFESS nº. 443/2003, que institui procedimentos para a realização de desagravo público.", "alt": {"A": "Por ter a incumbência de preservar a imagem coletiva da profissão de serviço social, é competência do CFESS a análise de todo pedido de desagravo público.", "B": "O desagravo público é um direito do assistente social e será concedido sempre que a ofensa for de natureza pessoal; técnica ou profissional e configurar crítica de caráter teórico‑metodológico, doutrinário, político e ideológico.", "C": "Existindo mais que um assistente social requerente, ou seja, havendo dois ou mais ofendidos, a renúncia de um deles implica automaticamente a renúncia do(s) outro(s) e a desistência do procedimento.", "D": "O assistente social postulante terá o direito de determinar dia, horário e local para a realização do desagravo público.", "E": "A renúncia de exercer o direito de desagravo não será cabível quando se tratar de fato que atinja a toda a categoria indistintamente."}, "g": "E", "j": "Res CFESS 443/2003 (desagravo publico): a RENUNCIA do direito ao desagravo NAO sera cabivel quando se tratar de fato que atinja TODA A CATEGORIA INDISTINTAMENTE (preserva-se a imagem coletiva da profissao). Alternativa E correta. A (competencia do CFESS) inverte (e do CRESS); B (critica teorico-metodologica enseja desagravo) e falso; C (renuncia automatica de outros) e falso; D (postulante define data) e falso."}, {"id": "2397427", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "A Lei nº. 8.662/1993, conhecida como a Lei de regulamentação da profissão de assistente social, elenca as atribuições privativas desse profissional. Considerando essa informação, assinale a alternativa que apresenta uma atribuição privativa do assistente social.", "alt": {"A": "coordenar, elaborar, executar, supervisionar e avaliar estudos, pesquisas, planos, programas e projetos", "B": "prestar orientação a indivíduos e grupos de diferentes segmentos sociais com o objetivo de identificar recursos e garantir direitos", "C": "dirigir e coordenar unidades de ensino e cursos de serviço social, de graduação e pós‑graduação", "D": "treinamento, avaliação e supervisão direta de profissionais de serviço social", "E": "prestar assessoria e apoio aos movimentos sociais em matéria relacionada às políticas sociais"}, "g": "C", "j": "Lei 8.662/93, art. 5 (atribuicoes privativas): VI — 'dirigir e coordenar Unidades de Ensino e Cursos de Servico Social, de graduacao e pos-graduacao'. Alternativa C reproduz uma atribuicao privativa. A, B, E sao competencias (art. 4); D, embora possa ser privativa em parte, e mais geral. C e a opcao mais especifica e privativa."}, {"id": "2397426", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Estudo Social, Pareceres, Perícia Social, Relatório Social e Laudo Social", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta quanto à temática referente aos estudos sociais, estudos socioeconômicos e perícia social apresentada no livro do CFESS (2022), “Produção de documentos e emissão de opinião técnica em  Serviço Social”.", "alt": {"A": "Para Mioto, o estudo social e o estudo socioeconômico são similares e podem ser definidos como o processo de conhecimento, análise e interpretação de uma determinada situação social.", "B": "A realização de estudo social e a emissão de parecer social prescinde de conhecer quais são as políticas sociais ofertadas no território e como ocorre o acesso a elas pelo usuário.", "C": "Fávero expressa que o estudo social é uma técnica específica do serviço social, cuja finalidade é conhecer, com profundidade, os problemas sociais vivenciados pelos usuários.", "D": "No serviço social, o estudo socioeconômico deve ser utilizado como critério de elegibilidade e(ou) seletividade para acesso aos direitos e  benefícios sociais.", "E": "Toda perícia social pressupõe o estudo social, assim todo estudo social é uma perícia social."}, "g": "A", "j": "CFESS (2022) — Producao de Documentos: para MIOTO, o estudo social e o estudo socioeconomico sao SIMILARES e podem ser definidos como o processo de CONHECIMENTO, ANALISE E INTERPRETACAO de uma determinada situacao social. Alternativa A reproduz fielmente. B (prescinde de politicas) e falso; C (Favero ve como tecnica) e impreciso; D (estudo socioeconomico como criterio de seletividade) contraria CE-SS; E (todo estudo e pericia) e falso."}, {"id": "2397425", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Estudo Social, Pareceres, Perícia Social, Relatório Social e Laudo Social", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2024", "org": "CRESS", "t": "", "e": "No ano de 2022, o Conselho Federal de Serviço Social (CFESS) lançou o livro “Produção de documentos e emissão de opinião técnica em Serviço Social”, com o objetivo de responder às demandas da categoria referentes aos estudos sociais, estudos socioeconômicos, emissão de pareceres e opinião técnica e seus registros. Com base nessa informação, assinale a alternativa correta a respeito das orientações referentes à emissão da opinião técnica do assistente social.", "alt": {"A": "A produção de documentos e a emissão da opinião técnica vinculam‑se unicamente à dimensão técnico‑operativa, que se atém ao uso de instrumentos e técnicas utilizadas em serviço social.", "B": "As avaliações realizadas pelo assistente social no exercício profissional apresentadas na emissão de uma opinião técnica são sempre valoradas.", "C": "Uma das finalidades da opinião técnica profissional é emitir uma decisão sobre a vida dos usuários.", "D": "A instrumentalidade concebida como o conjunto dos instrumentos e técnicas utilizados na intervenção profissional requer a neutralidade e é uma ferramenta essencial para a elaboração da opinião técnica do assistente social.", "E": "A opinião técnica do profissional deve ser necessariamente documentada, por meio de uma linguagem preferencialmente descritiva, visto que esta favorece a delimitação e a compreensão do objeto do estudo social."}, "g": "B", "j": "CFESS (2022): as avaliacoes apresentadas na emissao de opiniao tecnica do AS sao SEMPRE VALORADAS — nao existe neutralidade absoluta, pois envolvem juizo profissional fundamentado em valores e principios eticos. Alternativa B correta. A (unicamente tecnico-operativa) reducionista; C ('decisao sobre vida') inadequado; D (instrumentalidade requer neutralidade) inverte; E (linguagem preferencialmente descritiva) tambem reducionista."}, {"id": "2081320", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais", "Proteção Social à Criança, ao Adolescente e à Família", "Proteção Social aos Usuários de Álcool e outras Drogas"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "O uso de drogas não se limita às questões individuais e \nconstitui um grave problema de saúde pública, com reflexos \nnos diversos segmentos da sociedade. Assim, suas \nconsequências incidem, direta ou indiretamente, nos \nespaços familiares e em outros contextos sociais, incluindo \nos serviços de segurança pública, de educação e de saúde e \nos sistemas de justiça, de assistência social, entre outros. A \nrespeito da prevenção ao uso de drogas, assinale a \nalternativa incorreta.", "alt": {"A": "O planejamento das ações de prevenção ao uso de drogas deve levar em consideração a multifatorialidade das causas do uso indevido e da dependência das drogas lícitas e ilícitas.", "B": "A efetiva prevenção ao uso de tabaco e seus derivados, de álcool e de outras drogas deve envolver o comprometimento, a cooperação e a parceria entre os diferentes segmentos da sociedade brasileira e dos órgãos da Administração Pública Federal, estadual, distrital e municipal, fundamentada na filosofia da responsabilidade compartilhada.", "C": "Entre as principais medidas de prevenção promovidas pelo Poder Público, a construção de redes se mostra como essencial. Tais redes devem buscar: a melhoria das condições de vida e saúde da população; a promoção de habilidades sociais e para a vida; o fortalecimento de vínculos interpessoais; a promoção dos fatores de proteção ao uso de drogas lícitas e ilícitas; e a conscientização e proteção dos fatores de risco.", "D": "O Poder Público deverá promover a capacitação continuada dos profissionais envolvidos na prevenção ao uso de drogas. O trabalho interdisciplinar e multiprofissional, com a participação dos atores sociais envolvidos no processo, também se mostra como importante medida para o desenvolvimento integrado de programas de promoção geral da saúde e de prevenção ao uso de tabaco e seus derivados, de álcool e de outras drogas.", "E": "O emprego de novas formas de abordagem (com o uso de tecnologias, ferramentas, serviços e ações digitais inovadoras) não se mostra como uma diretriz do Poder Público brasileiro em ações preventivas ao uso de drogas."}, "g": "E", "j": "Prevencao ao uso de drogas (Politica Nacional sobre Drogas): A (multifatorialidade), B (responsabilidade compartilhada), C (redes de protecao), D (capacitacao continuada) sao diretrizes oficiais. Alternativa E INCORRETA: o emprego de NOVAS FORMAS DE ABORDAGEM com tecnologias e ferramentas digitais E sim diretriz do Poder Publico (inclusive prevista em programas como PROERD digital, campanhas online etc.)."}, {"id": "2081319", "d": "servico_social", "a": ["Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "O desenvolvimento psicossocial de adolescentes mostra-se \ncomo uma temática complexa, ainda mais quando esse \ndesenvolvimento se dá em contextos de vulnerabilidade \nsocial. A compreensão do desenvolvimento inserida em um \nparadigma contemporâneo demanda a articulação de \nconhecimentos que evidenciem a interdependência entre \nmúltiplos fatores que compõem esse processo. Acerca do \ndesenvolvimento psicossocial de adolescentes residentes \nem comunidades vulneráveis socialmente, assinale a \nalternativa incorreta.", "alt": {"A": "O desenvolvimento acontece em um contexto familiar e comunitário que, por sua vez, se inscreve em uma conjuntura social mais ampla, na qual estão presentes políticas públicas e instituições. Nesse sentido, observa-se que ainda existe uma distância entre os direitos previstos em lei e sua efetivação na vida de adolescentes residentes em comunidades vulneráveis socialmente. A redução das desigualdades sociais para essa população segue, pois, como um desafio para as políticas públicas brasileiras.", "B": "A formação e os espaços de diálogo oferecidos aos profissionais que atuam nesses contextos podem favorecer a superação de um olhar que reduza adolescentes às condições de vulnerabilidade por eles enfrentadas. A promoção de articulações institucionais também se mostra como um importante meio de promoção do desenvolvimento e do enfrentamento das condições de vulnerabilidade social.", "C": "No trabalho com adolescentes, torna-se relevante a compreensão das funções dos vínculos e da identificação de recursos e potenciais comunitários como embasamento para intervenções profissionais que possam favorecer o desenvolvimento dessa população.", "D": "Vínculos significativos com familiares e profissionais, assim como a oferta de atividades lúdicas, culturais e desportivas pelas instituições, podem contribuir para o enfrentamento da condição de vulnerabilidade social de adolescentes. Ao demonstrarem a capacidade de acolher necessidades emocionais, psicológicas e até materiais dos adolescentes, os profissionais podem exercer uma função de apoio ao desenvolvimento (por meio das políticas públicas).", "E": "Há diversos tensionamentos entre os projetos de vida dos adolescentes e o contexto de vulnerabilidade social, permeado por experiências como o contato com o tráfico de drogas, a gravidez precoce e a violência doméstica e familiar. Tais tensionamentos, por sua vez, não interagem de maneira significativa com as características de desenvolvimento psicossocial inerentes a essa fase da vida."}, "g": "E", "j": "Desenvolvimento psicossocial de adolescentes em vulnerabilidade: A, B, C, D apresentam premissas reconhecidas pela literatura (politicas publicas, formacao profissional, vinculos, suporte institucional). Alternativa E INCORRETA — os tensionamentos entre projetos de vida e contextos de vulnerabilidade (trafico, gravidez precoce, violencia) INTERAGEM SIM significativamente com as caracteristicas do desenvolvimento adolescente. Gabarito E (incorreta)."}, {"id": "2069807", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Serviço Social e Ética"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Acerca das questões éticas presentes na prática profissional\ndos assistentes sociais, julgue os próximos itens.\n      I As infrações ao Código de Ética profissional acarretarão\npenalidades. As penalidades aplicáveis são: multa;\nadvertência reservada ou pública; suspensão do\nexercício profissional; e cassação do registro profissional.\n  II O assistente social deverá oferecer denúncia ao Conselho\nRegional de Assistência Social quando as instituições\npúblicas ou privadas não apresentarem condições de\ntrabalho dignas ou oferecerem condições que possam\nprejudicar os usuários ou os profissionais.\n  III Em trabalho multidisciplinar, poderão ser fornecidas\nquaisquer informações sobre os usuários atendidos pelo\nassistente social. Nesse caso, não há risco de quebra do\nsigilo profissional, tendo em vista que as demais\nprofissões também obedecem ao dever ético de\nresguardo do sigilo.\n  IV A quebra do sigilo é admitida quando a gravidade da\nsituação puder trazer prejuízo aos interesses do usuário,\nde terceiros e da coletividade, mesmo que não envolva\nfato delituoso. De qualquer forma, a revelação deverá\nser feita dentro do estritamente necessário.\n      A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Questoes eticas SS: I correto (penalidades — multa, advertencia reservada/publica, suspensao, cassacao, art. 23 CE-SS); IV correto (quebra do sigilo em gravidade, mesmo sem fato delituoso, art. 18 CE-SS, com revelacao estritamente necessaria). Item II INCORRETO — a denuncia deve ser ao CRESS (Conselho Regional de Servico Social), NAO ao Conselho de Assistencia Social (que e orgao da politica publica, nao profissional). Item III INCORRETO — em multi NAO se podem fornecer quaisquer informacoes; o sigilo persiste. Apenas I e IV = 2. CORRIGIDO para C."}, {"id": "2069806", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "O serviço social apresenta uma trajetória histórica humanista,\nmanifesta no compromisso ético com os usuários dos\nserviços, visando ao cumprimento de seus direitos. O atual\nCódigo de Ética do Assistente Social mostra-se como um dos\nalicerces desse compromisso, fornecendo a base de\nfundamentação dos valores que orientam o exercício\nprofissional e formas para a sua operacionalização concreta.\nConsiderando essas informações, assinale a alternativa\nincorreta no que se refere à ética profissional.", "alt": {"A": "O assistente social deve obedecer aos princípios e às\ndiretrizes do código de ética profissional, mesmo\nquando houver decisão institucional em sentido\ncontrário.", "B": "O profissional de serviço social deve contribuir para a\nviabilização da participação efetiva da população nas\ndecisões institucionais.", "C": "Constitui dever do assistente social a participação em\nprogramas de socorro à população em situação de\ncalamidade pública, no atendimento e na defesa de\nseus interesses e de suas necessidades.", "D": "O assistente social deverá fornecer à população\nusuária, sempre que solicitado, quaisquer informações\nconcernentes ao trabalho desenvolvido pelo serviço\nsocial e às suas conclusões. Nesse caso, não há a\nnecessidade de se resguardar o sigilo profissional,\ntendo em vista que o pedido de informação veio da\nprópria população usuária.", "E": "Ao exercer cargo de chefia, o assistente social tem a\nobrigação de mobilizar sua autoridade funcional para\nliberar subordinado, em sua carga horária, para fins de\nestudos ou pesquisas que visem ao aprimoramento\nprofissional. A mesma obrigatoriedade existirá quando\no subordinado desejar ocupar representação ou\ndelegação de entidade de organização da categoria ou\noutras."}, "g": "D", "j": "CE-SS — alternativa incorreta: D afirma que 'quando pedido de informacao vem da populacao usuaria, NAO HA NECESSIDADE DE RESGUARDAR SIGILO'. INCORRETA — o sigilo profissional persiste mesmo quando solicitado pelo usuario (informacoes sao fornecidas no que se referem ao trabalho desenvolvido com ele, mas o sigilo sobre terceiros e demais aspectos permanece). A, B, C, E reproduzem corretamente deveres do CE-SS."}, {"id": "2069805", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "No que diz respeito às mudanças relativas à gestão da Política de Assistência Social a partir da Constituição Federal de 1988,\nassinale a alternativa incorreta.", "alt": {"A": "A assistência social passou a ser organizada pela LOAS, em um sistema político, descentralizado e participativo, denominado\nSUAS. Esse sistema é composto, exclusivamente, pelo Poder Público e abarca os três níveis de governo", "B": "A partir do SUAS, foram ampliados os espaços de participação política e social nos trâmites de gestão e deliberação da\nPolítica de Assistência Social.", "C": "As peculiaridades (culturais, naturais e históricas, entre outras) de cada município passaram a ser reconhecidas no sistema\nde gestão estabelecido no SUAS.", "D": "A atuação de instituições privadas e mistas, como, por exemplo, as organizações não governamentais, passou a ser\nintegrada à Política de Assistência Social, por prover necessidades voltadas à defesa de direitos, especialmente dos direitos\nsocioassistenciais.", "E": "A Política de Assistência Social brasileira evoluiu em seus aspectos conceituais e operacionais, que passaram a evidenciar a\nconstrução teórica de um modelo pautado na lógica da garantia de direitos. Todavia, existem ainda muitos desafios a se\nenfrentar, como, por exemplo, a ampliação das políticas, a melhoria na qualidade dos serviços e a valorização dos\ntrabalhadores, visto que são os agentes executores dessa política."}, "g": "A", "j": "SUAS — alternativa incorreta: A afirma que o SUAS e composto EXCLUSIVAMENTE pelo Poder Publico. INCORRETO — o SUAS integra TAMBEM as entidades nao governamentais (terceiro setor, ONGs, instituicoes mistas) na rede socioassistencial. B, C, D, E reproduzem corretamente caracteristicas do SUAS."}, {"id": "2069804", "d": "servico_social", "a": ["Previdência Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Nas últimas décadas, a gestão do sistema previdenciário\nenvolveu polêmicos embates. Esse contexto remete aos\nfundamentos do papel do Estado e de sua relação com a\nsociedade, pondo em questão o modelo de desenvolvimento\neconômico dominante na América Latina e no Brasil. Não\nobstante todos os efeitos danosos registrados,\nparticularmente no que concerne às políticas sociais, o\nmodelo neoliberal persiste ainda nos primeiros anos do\nséculo XXI. Quanto à Política Pública da Previdência Social\nbrasileira, assinale a alternativa correta.", "alt": {"A": "De acordo com a recente reforma previdenciária,\nrealizada por meio da Emenda Constitucional\nn.º 103/2019, no regime geral de previdência social, a\naposentadoria é assegurada a homens com 65 anos de\nidade e a mulheres com 62 anos de idade, incluindo-se\nos trabalhadores rurais.", "B": "O benefício de prestação continuada (BPC) é um\nbenefício prestado pelo Instituto Nacional do Seguro\nSocial (INSS) e garantido, na Constituição Federal de\n1988, como um dos objetivos da Política de Previdência\nSocial no Brasil. Consiste em uma renda de um\nsalário-mínimo, destinada a idosos e a pessoas com\ndeficiência que não possuam condições para manter\nsua subsistência e não possam ser mantidos por suas\nfamílias.", "C": "Algumas inovações trazidas pela reforma da\nprevidência brasileira foram: aumento de tempo de\ncontribuição para os homens se aposentarem, também\ncom idade em fase idosa; aumento do tempo de\ncontribuição, somado à idade mínima avançada, para\nter direito à aposentadoria com valor integral; e\nredução no valor de aposentadoria por incapacidade e\npedágio de 50% a 100% sobre o tempo de contribuição\nfaltante para a aposentadoria.", "D": "As mudanças decorrentes da reforma previdenciária\nrealizada em 2019 não influenciam, de imediato, a\ncomposição de renda das famílias brasileiras, mesmo\ncom a instituição do aumento das alíquotas de\ncontribuições dos trabalhadores e a exigência de cotas\nfamiliares para valores de pensão por morte.", "E": "No caso das mulheres, a reforma previdenciária de\n2019 levou em consideração as suas duplas ou triplas\njornadas, associando trabalho, tarefas do lar e cuidado\ncom filhos. Assim, não houve alteração, para essa\nparcela da população brasileira, no que se refere à\nexigência de idade mínima para se aposentar."}, "g": "C", "j": "Reforma da Previdencia (EC 103/2019): C correta — entre as inovacoes estao aumento do tempo de contribuicao para homens e mulheres aposentarem, idade minima avancada para aposentadoria com valor integral, e PEDAGIO DE 50% A 100% sobre o tempo de contribuicao faltante. A erra (regras especificas para rurais); B erra (BPC e da ASSISTENCIA SOCIAL, nao previdencia); D erra (mudancas influenciam imediatamente); E erra (mulheres tambem tiveram alteracao)."}, {"id": "2069803", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Política Nacional de Assistência Social – PNAS"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A Política de Assistência Social foi legalmente reconhecida\ncomo direito social e dever estatal pela Constituição Federal\nde 1988, quando passou a apresentar uma trajetória de\navanços, que a transportou da concepção de favor e\ndispersão ao estatuto de política pública e da ação focal e\npontual à dimensão da universalização. Com relação à Política\nPública de Assistência Social, assinale a alternativa correta.", "alt": {"A": "A assistência social tem sido regulamentada, ao longo\ndas últimas décadas, pela LOAS, pela Política Nacional\nde Assistência Social (PNAS), pelo SUAS e pela Norma\nOperacional Básica (NOB) do SUS, com aprovação do\nConselho Nacional de Assistência Social (CNAS).", "B": "As ações realizadas no âmbito do SUAS têm o território\ncomo base de organização. O Centro de Referência da\nAssistência Social (Cras) e o Centro de Referência\nEspecializado de Assistência Social (Creas) são\nunidades públicas estatais que, em interação com as\ndemais políticas públicas, articulam, coordenam e\nofertam os serviços, os programas, os projetos e os\nbenefícios da assistência social.", "C": "A proteção social básica é destinada a populações que\nse encontrem em situação de violação de direitos e\nrefere-se a ações preventivas (que reforçam a\nconvivência, a socialização, o acolhimento e a inserção)\ncom caráter mais genérico, voltado prioritariamente\npara o indivíduo. As ações socioassistenciais da\nproteção social básica serão realizadas,\nprioritariamente, pelo Cras.", "D": "A proteção social especial refere-se a serviços mais\nespecializados e com caráter mais complexo,\ndestinados a pessoas em situações de risco pessoal ou\nsocial. Diferencia-se da proteção social básica por se\ntratar de um atendimento dirigido às situações graves\nde vulnerabilidade social.", "E": "A realização das modalidades de proteção social não\nrequer a articulação entre os serviços socioassistenciais\ne outros tipos de proteção garantidos pelas demais\npolíticas públicas. Assim, seus serviços devem\nestabelecer programas específicos e focais, que\nassegurem o acesso aos direitos sociais, tendo em vista\nque à assistência social é atribuída a tarefa de realizar,\nexclusivamente, a proteção social, nos termos do SUAS."}, "g": "B", "j": "PNAS/SUAS: B correta — as acoes do SUAS tem territorio como base; CRAS e CREAS sao UNIDADES PUBLICAS ESTATAIS que articulam, coordenam e ofertam servicos, programas, projetos e beneficios da assistencia social em interacao com outras politicas. A erra (NOB do SUAS, nao do SUS); C inverte (PSB e para risco/preventiva, nao para violacao); D e parcial; E nega articulacao intersetorial."}, {"id": "2069801", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A respeito dos princípios legislativos relacionados ao serviço\nsocial e do compromisso profissional com a implementação\ndesses princípios, assinale a alternativa correta.", "alt": {"A": "Entre os princípios fundamentais previstos no Código\nde Ética Profissional dos Assistentes Sociais, aprovado\nem 1993, estão o reconhecimento da solidariedade\ncomo valor ético central e o reconhecimento das\ndemandas políticas a ela inerentes (emancipação,\nplena expansão dos indivíduos sociais e autonomia).", "B": "São objetivos dos princípios fundamentais previstos na\nConstituição Federal de 1988: a construção de uma\nsociedade livre, justa e solidária; o desenvolvimento\nprioritário da economia nacional; a diminuição da\npobreza e das desigualdades sociais; e a promoção do\nbem de todos, a depender da origem, da raça, do sexo,\nda cor, da idade e do segmento populacional.", "C": "A defesa dos direitos humanos, com o uso do arbítrio e\ndo autoritarismo somente quando estritamente\nnecessário, é um dos princípios fundamentais\nobedecidos pelo assistente social.", "D": "A defesa da democracia é um importante princípio\nético a ser observado pelos assistentes sociais, tendo\nem vista a participação política e a socialização da\nriqueza produzida, de maneira proporcional aos meios\nde produção e de reprodução do capital.", "E": "Constitui princípio ético da profissão o esforço para\neliminar quaisquer formas de preconceito e, ao mesmo\ntempo, incentivar o respeito à diversidade, a\nparticipação de grupos socialmente discriminados e a\ndiscussão das diferenças. Além disso, o projeto\nprofissional vincula-se, em seus princípios, à\nconstrução de uma nova ordem societária, sem\ndominação/exploração de gênero, etnia ou classe."}, "g": "E", "j": "Principios eticos do SS: E correta — constitui principio do CE-SS o EMPENHO PARA ELIMINAR QUAISQUER FORMAS DE PRECONCEITO, com respeito a diversidade, e a vinculacao do projeto profissional a CONSTRUCAO DE UMA NOVA ORDEM SOCIETARIA SEM DOMINACAO/EXPLORACAO de classe, etnia, genero. A inverte (LIBERDADE e o valor central, nao solidariedade); B distorce CF/88; C admite arbitrio; D fala em socializacao 'proporcional ao capital' (CE-SS fala em socializacao efetiva)."}, {"id": "2069796", "d": "servico_social", "a": ["Trabalho e Serviço Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Na direção do projeto ético-político profissional adotado pelo\nserviço social na contemporaneidade, a prática profissional\ndeve observar três dimensões: ético-política;\nteórico-metodológica; e técnico-operativa, que norteiam o\nagir profissional e constituem sua instrumentalidade. No que\nse refere a essas dimensões da prática profissional, assinale a\nalternativa incorreta.", "alt": {"A": "Ao se inserir nas atividades que se tornaram\nauxiliadoras dos processos especificamente\nmonopólicos de reprodução, acumulação e valorização\ndo capital, o serviço social passou a desempenhar\nfunções essencialmente produtivas.", "B": "O movimento de reconceituação contribuiu para que o\nserviço social assumisse um caráter científico,\ndesenhando novos contornos a seu status de\ncompetência. A partir do diálogo com a tradição\nmarxista e com outras ciências, denominadas humanas\ne sociais (antropologia, sociologia, psicologia,\neconomia e ciência política), foi possível traçar\nobjetivos maiores para a atuação profissional e romper\ncom características conservadoras, assistencialistas e\nmeramente executivas. Assim, a profissão conquistou\nnovas atribuições no mercado de trabalho,\nreconfigurando-se como uma atividade capaz de\ndecifrar a realidade, produzir conhecimentos e\nprovocar transformações.", "C": "A dimensão teórico-metodológica da competência\nprofissional pressupõe que o assistente social seja\nqualificado para conhecer a realidade social na qual\natua em seus níveis políticos, econômicos e culturais,\nbaseando-se em um rigoroso trato teórico e\nmetodológico, que, por sua vez, lhe permita decifrar a\nrealidade social em sua essência e dinamicidade, com\npossibilidades de transformação.", "D": "A competência técnico-operativa é caracterizada pelo\nreconhecimento e pela apropriação de um conjunto de\nhabilidades técnicas que permitam ao profissional\natuar junto aos cidadãos usuários e às instituições\ncontratantes, no sentido de desenvolver ações que\nrespondam, com qualidade, tanto às demandas\napresentadas pela sociedade quanto às colocadas pela\ninstituição empregadora.", "E": "A dimensão ético-política precisa ser desenvolvida em\nsinergia com as outras duas dimensões do fazer\nprofissional. Desenvolvidas isoladamente, poderão\ntransformar-se em armadilhas (militantismo,\nteoricismo e tecnicismo). É necessário também\ncompreendê-las de maneira crítica e interrelacionada,\nconfrontando pesquisas, produções teóricas e a práxis\nprofissional, de modo a promover a inquietação\nnecessária para que se desenvolvam as transformações\nsociais a que se propõe o serviço social."}, "g": "A", "j": "Dimensoes da pratica profissional do SS: A INCORRETA — o SS NAO desempenha funcoes essencialmente produtivas (no sentido de produzir mais-valia diretamente); atua na reproducao das relacoes sociais e produz servicos. B, C, D, E reproduzem corretamente concepcoes de Iamamoto e do movimento de reconceituacao sobre as tres dimensoes (etico-politica, teorico-metodologica, tecnico-operativa)."}, {"id": "2069795", "d": "servico_social", "a": ["Serviço Social e Equipe Multi e Interdisciplinar", "Serviço Social na Educação", "Trabalho e Serviço Social", "Assistência Social no Serviço Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Com relação à prática profissional do assistente social,\nassinale a alternativa incorreta.", "alt": {"A": "Como uma resultante da especialização do trabalho\ncoletivo, a prática profissional é previamente\ndeterminada pela divisão sociotécnica do trabalho.\nSitua-se no âmbito das relações sociais concretas, com\numa dimensão historicamente determinada, que se\ntorna particularizada em diferentes campos de\ntrabalho vinculados ao todo social.", "B": "A prática profissional deve direcionar-se para a\nconstrução de um sujeito profissional que tenha\ncompetência para negociar com a instituição e propor\nseus projetos, indo além das rotinas institucionais\nvigentes e buscando apreender, no movimento da\nrealidade, tendências e possibilidades passíveis de\nserem desenvolvidas e transformadas para o alcance\nprioritário dos objetivos institucionais.", "C": "Ao longo de sua trajetória, a profissão assumiu a função\nde realizar a intermediação entre a população\nreceptora das políticas públicas e o poder institucional\nque executa essas políticas. Como produto histórico, a\nprática profissional é então condicionada pela\nconfiguração estrutural da sociedade na qual se\ndesenvolve e pelo movimento tenso e conflituoso das\nconjunturas particulares de cada período.", "D": "Ainda que ambas representem momentos\ndiferenciados, a unicidade da teoria com a prática\nforma o mesmo todo, em uma relação dialética de\ntotalidade. A prática profissional, assim, constitui um\nimportante momento de materialização da teoria, que,\npor sua vez, a retroalimenta.", "E": "As mediações presentes no cotidiano muitas vezes não\nsão apreendidas nem colocadas em ação de forma\nconsciente e crítica pelo profissional. Sendo assim, suas\nações perdem-se no âmbito da imediaticidade, ou seja,\nos sujeitos acabam por não perceber o vínculo\nimediato entre pensamento e ação, absortos em\nrepetições automáticas de modos de comportamento,\nvaloradas por escolhas hierárquicas desvinculadas da\nteoria crítica e do projeto ético-político profissional."}, "g": "B", "j": "Pratica profissional do AS: B INCORRETA — o AS deve buscar apreender tendencias para alcance prioritario dos INTERESSES DA POPULACAO USUARIA (compromisso etico-politico), NAO dos 'objetivos institucionais' (que podem conflitar com interesses dos usuarios). A (Iamamoto sobre divisao sociotecnica), C (intermediacao), D (unicidade teoria-pratica), E (mediacoes no cotidiano) sao corretas."}, {"id": "2069794", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Serviço Social na América Latina"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Quanto às condições históricas latino-americanas e a suas\nrelações com a formação profissional do serviço social\nbrasileiro, assinale a alternativa incorreta.", "alt": {"A": "O processo de colonização da América Latina\nencontra-se na origem histórica da questão social, que,\nao adquirir características mais agudas e complexas ao\nlongo da história do continente, impõe desafios ao\nserviço social nacional desde seu início.", "B": "O projeto de serviço social surgiu no Chile, nos anos\n1920, e se expandiu na América Latina e no Caribe sob\na égide das transformações capitalistas, com forte\ninfluência do pensamento europeu. Tal projeto, sob a\nmediação do Estado e da igreja católica, orientou os\nprofissionais a atuar no sentido da construção de\nrespostas adequadas aos interesses da classe\ndominante, no controle das relações sociais que\nsubjugam e subalternizam a classe trabalhadora.", "C": "A partir dos anos 1970, o projeto de formação\nprofissional passou a apresentar avanços, com clara\ndireção sociopolítica a processos emancipatórios. Nas\ndécadas de 1980 e 1990, o projeto consolidou-se, por\nmeio do alinhamento da profissão com a perspectiva\nhistórica das classes subalternas, ancorado,\nprincipalmente, na matriz teórico-metodológica de\ntradição marxista.", "D": "No período contemporâneo, diversos desafios se\napresentam, a partir da orientação neoconservadora\nem âmbito mundial. Nesse contexto, faz-se necessário\no fortalecimento do projeto de formação, sob o risco\nde ocorrerem retrocessos em conquistas teóricas,\néticas e políticas que vêm orientando o projeto\nprofissional de ruptura com o conservadorismo nas\núltimas décadas.", "E": "A experiência brasileira com as diretrizes curriculares\naprovadas em 1996 indica uma forte incidência sobre o\nprojeto de formação profissional orientado pelo\nprojeto ético-político dos assistentes sociais. O\nprocesso de elaboração das diretrizes curriculares foi\ndefendido e realizado pela Associação Brasileira de\nEnsino e Pesquisa em Serviço Social (ABEPSS), sem\ncontar com a sustentação de outras entidades políticas\nda categoria, como, por exemplo, o Conselho Federal\nde Serviço Social e a Executiva Nacional de Estudantes\nde Serviço Social (Enesso)."}, "g": "E", "j": "SS na America Latina: A, B (surgimento no Chile, 1920), C (avancos pos-1970 com marxismo), D (desafios neoconservadores) sao corretas. Alternativa E INCORRETA: as Diretrizes Curriculares de 1996 foram defendidas e realizadas pela ABEPSS COM SUSTENTACAO de OUTRAS entidades politicas, como o CFESS e a ENESSO — nao foi sem sustentacao destas."}, {"id": "2053915", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2023", "org": "IIER", "t": "", "e": "Quanto ao projeto ético-político do serviço social, assinale a\nalternativa correta.", "alt": {"A": "O projeto ético‐político efetiva-se integralmente na\nrealidade em toda prática profissional.", "B": "O projeto ético-político do serviço social é expressão\ndas contradições que particularizam a profissão, e seus\nprincípios e valores colidem com os pilares\nfundamentais que sustentam a ordem do capital.", "C": "O corpo profissional é uma unidade homogênea, o que\ngarante a hegemonia do projeto profissional do serviço\nsocial.", "D": "Um projeto profissional é constituído por elementos,\nque permanecem inalterados, pois configuram a\nidentidade profissional como uma imagem ideal da\nprofissão, pelos valores que a legitimam, por sua\nfunção social, por seus objetivos e pelos\nconhecimentos teóricos e interventivos.", "E": "Os elementos éticos de um projeto profissional são\ncircunscritos às normativas morais e às prescrições de\ndireitos e deveres."}, "g": "B", "j": "PEP do SS: B correta — o PEP e expressao das CONTRADICOES que particularizam a profissao, e seus principios e valores COLIDEM COM OS PILARES FUNDAMENTAIS QUE SUSTENTAM A ORDEM DO CAPITAL (e projeto contra-hegemonico, anti-capitalista). A (efetiva-se integralmente) e utopico; C (corpo profissional homogeneo) inverte; D (elementos inalterados) nega historicidade; E (elementos circunscritos a normativas morais) reduz a moralismo."}, {"id": "2053912", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Estudo Social, Pareceres, Perícia Social, Relatório Social e Laudo Social", "Instrumentos e Técnicas de Intervenção"], "ano": "2023", "org": "IIER", "t": "", "e": "No que diz respeito aos instrumentos e às técnicas em serviço\nsocial, assinale a alternativa correta.", "alt": {"A": "O parecer social é um instrumento de caráter\nessencialmente sugestivo, que emite uma\ninterpretação, uma análise e uma opinião profissional\nsobre determinado problema social.", "B": "O estudo social é uma competência do assistente\nsocial, mas não é considerado como uma atividade\nprivativa do profissional.", "C": "A comunicação que se estabelece entre locutor e\ninterlocutor, na forma escrita, fica à mercê da\nunilateralidade de interpretação.", "D": "Para que a mensagem escrita pelo profissional seja\nbem compreendida, é fundamental que seja registrada\nsegundo as normas da língua formal, seja coerente\ntecnicamente e utilize terminologias e conceitos\nespecíficos e herméticos.", "E": "O relatório social é um documento padronizado que\ncontém um nível maior de detalhamento, enquanto o\ninforme social é um instrumento com menor nível de\ndetalhamento."}, "g": "C", "j": "Instrumentos e tecnicas em SS: C correta — a comunicacao escrita estabelecida entre locutor e interlocutor fica a merce da UNILATERALIDADE DE INTERPRETACAO (sem possibilidade imediata de esclarecimento), o que exige cuidado redobrado na redacao. A (parecer essencialmente sugestivo) inverte (e tambem analitico/conclusivo); B (estudo social nao privativo) inverte; D (terminologias hermeticas) e antiético; E (relatorio padronizado) inverte."}, {"id": "2053907", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2023", "org": "IIER", "t": "", "e": "É direito do assistente social", "alt": {"A": "o exercício das atividades inerentes à profissão,\nconforme as normas da instituição empregadora.", "B": "o desagravo público por ofensa que atinja a sua honra\nprofissional.", "C": "empregar com transparência as verbas sob a sua\nresponsabilidade, de acordo com os interesses e as\nnecessidades coletivas dos usuários.", "D": "contribuir para a alteração da correlação de forças\ninstitucionais, apoiando as legítimas demandas de\ninteresse da população usuária.", "E": "empenhar-se na viabilização dos direitos sociais dos\nusuários, por meio dos programas e das políticas\nsociais."}, "g": "B", "j": "CE-SS, art. 2 (Direitos): 'e) DESAGRAVO PUBLICO por ofensa que atinja a sua honra profissional'. Alternativa B reproduz o direito. A (atividade conforme normas da empregadora) inverte (livre exercicio); C, D, E sao deveres (transparencia, alteracao da correlacao de forcas, viabilizacao de direitos)."}, {"id": "2053906", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2023", "org": "IIER", "t": "", "e": "Constitui um princípio fundamental expresso no Código de\nÉtica do Assistente Social o(a)", "alt": {"A": "participação na elaboração e no gerenciamento das\npolíticas sociais, bem como na formulação e na\nimplementação de programas sociais.", "B": "reconhecimento da cidadania como valor ético central\ne das demandas políticas a ela inerentes — autonomia,\neducação e plena expansão dos indivíduos sociais.", "C": "posicionamento em favor da igualdade, da liberdade e\nda justiça comutativa.", "D": "defesa intransigente dos direitos individuais, com\nvistas à emancipação política.", "E": "garantia do pluralismo, por meio do respeito às\ncorrentes profissionais democráticas existentes e suas\nexpressões teóricas."}, "g": "E", "j": "CE-SS — Principios Fundamentais: 'GARANTIA DO PLURALISMO, atraves do respeito as correntes profissionais democraticas existentes e suas expressoes teoricas, e compromisso com o constante aprimoramento intelectual'. Alternativa E reproduz o principio. A (dever, nao principio); B (cidadania como valor central — e LIBERDADE); C (justica COMUTATIVA — e SOCIAL); D (direitos INDIVIDUAIS / emancipacao POLITICA — sao COLETIVOS / emancipacao HUMANA)."}, {"id": "2053903", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Matricialidade Sociofamiliar", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família"], "ano": "2023", "org": "IIER", "t": "", "e": "Uma das importantes discussões sobre família realizadas no\nserviço social é a relação da família com as políticas sociais.\nNesse debate, surge o conceito de familismo, que", "alt": {"A": "ocorre quando os regimes de bem-estar abrandam a\nresponsabilidade familiar em relação à provisão de\nbem-estar social, por meio do Estado ou do mercado.", "B": "concebe a família enquanto rede primária dos sujeitos\nsociais e a principal articuladora das políticas sociais.", "C": "está presente nos sistemas de proteção social, à\nmedida que a política pública considera que as\nunidades familiares devem assumir a principal\nresponsabilidade pelo bem-estar de seus membros.", "D": "denuncia o Estado mínimo e aponta a necessidade de\nampliação das políticas sociais para o atendimento\nefetivo das demandas familiares.", "E": "é referente à construção do sentimento de intimismo,\nprivacidade e amor na esfera familiar."}, "g": "C", "j": "FAMILISMO (Esping-Andersen, Mioto, Pereira): perspectiva em politicas sociais segundo a qual as UNIDADES FAMILIARES devem assumir a PRINCIPAL RESPONSABILIDADE pelo bem-estar dos seus membros — com correspondente retracao do Estado. Alternativa C correta. A descreve DESFAMILIZACAO; B, D, E nao capturam o conceito especifico."}, {"id": "2053902", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Proteção Social aos Usuários de Álcool e outras Drogas"], "ano": "2023", "org": "IIER", "t": "", "e": "A respeito de drogas e de seus diferentes usos, temática\nrecorrente na prática profissional dos assistentes sociais,\nassinale a alternativa correta.", "alt": {"A": "O principal debate do serviço social em relação ao uso\ndo álcool e de outras drogas reforça a necessidade da\nampliação do poder punitivo do Estado para a coibição\ndessa prática.", "B": "O uso de drogas é uma prática social motivada por\ninteresses individuais, que não possui relação com a\nlógica mercantil e alienante da sociedade capitalista.", "C": "O termo “psicotrópico” tem sido usado de maneira\ninapropriada, contribuindo com visões mistificadoras\nsobre o uso de psicoativos, bem como com a\nreprodução acrítica de juízos de valor estigmatizantes.", "D": "A proibição é a melhor alternativa para responder aos\ndanos sociais e de saúde decorrentes do uso de\npsicoativos ilícitos.", "E": "A redução de danos é um paradigma que articula\nestratégias de cuidados e de redução de danos sociais\ne de saúde decorrentes do consumo de psicoativos."}, "g": "E", "j": "Drogas e SS: E correta — REDUCAO DE DANOS e paradigma que articula estrategias de CUIDADOS e de REDUCAO DE DANOS sociais e de saude decorrentes do consumo de psicoativos (perspectiva de saude publica nao-proibicionista). A (ampliacao do poder punitivo) inverte; B (uso individual sem relacao social) inverte; C (termo psicotropico inapropriado) e impreciso; D (proibicao como melhor alternativa) contradiz a evidencia."}, {"id": "2053897", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Proteção Social ao Idoso", "Serviço Social na Empresa, Responsabilidade Social, Terceiro Setor, ONGs, Entidades Sociais, Recursos Humanos e Gestão de Pessoas"], "ano": "2023", "org": "IIER", "t": "", "e": "Acerca dos programas de preparação para a aposentadoria,\nassinale a alternativa correta.", "alt": {"A": "O Estatuto da Pessoa Idosa recomenda a preparação\ndos trabalhadores para a aposentadoria, com\nantecedência mínima de dez meses.", "B": "Os programas de preparação para a aposentadoria\ndeverão ser inscritos no Conselho de Direitos da Pessoa\nIdosa.", "C": "Conforme a legislação, a oferta de programas de\npreparação para a aposentadoria é obrigatória para as\nempresas privadas.", "D": "O receio de tornar-se improdutivo ou inativo e a falta\nde realização de atividades paralelas ao trabalho ao\nlongo da vida são alguns dos fatores que dificultam a\naposentadoria.", "E": "A participação nos programas de preparação para a\naposentadoria é obrigatória para o trabalhador que\nalmeja se aposentar."}, "g": "D", "j": "Preparacao para aposentadoria: D correta — o receio de tornar-se IMPRODUTIVO ou inativo e a FALTA DE REALIZACAO DE ATIVIDADES PARALELAS ao trabalho ao longo da vida sao fatores que dificultam a aposentadoria. A (10 meses) e incorreta; B (Conselho de Direitos) inadequado; C (obrigatoria para privadas) inverte (e recomendacao); E (participacao obrigatoria) inverte."}, {"id": "2053894", "d": "servico_social", "a": ["Serviço Social na Empresa, Responsabilidade Social, Terceiro Setor, ONGs, Entidades Sociais, Recursos Humanos e Gestão de Pessoas"], "ano": "2023", "org": "IIER", "t": "", "e": "A temática referente à responsabilidade social corporativa\nvem alcançando projeção no universo corporativo. Em\nrelação ao debate sobre a responsabilidade social corporativa\ntravado pelo serviço social, assinale a alternativa correta.", "alt": {"A": "A responsabilidade social corporativa refere-se às\ntradicionais práticas filantrópicas e assistencialistas\nrealizadas, pelas empresas e fundações, em prol do\ndesenvolvimento econômico e social do País.", "B": "Uma das principais características da responsabilidade\nsocial corporativa é o fato de ser uma prática voltada\nsomente para a comunidade local e a sociedade.", "C": "Uma das críticas realizadas pelo serviço social à\nresponsabilidade social corporativa é o uso dessa\nprática como forma de manipulação dos programas\nsociais para angariar subsídios e incentivos fiscais ou\ncomo estratégias de promoção e marketing social.", "D": "A responsabilidade social corporativa é uma prática\ninovadora, que ganhou proeminência no Brasil a partir\ndos anos 2000, por influência do mercado europeu.", "E": "A parceria entre Estado e empresas, efetivada por meio\nda responsabilidade social corporativa, é uma iniciativa\nestatal fundamental no enfrentamento das expressões\nda questão social, que reafirma o protagonismo do\nEstado para o combate das mazelas sociais."}, "g": "C", "j": "Responsabilidade Social Corporativa (RSC) — critica do SS: C correta — uma das principais criticas e o uso da RSC como forma de MANIPULACAO dos programas sociais para angariar SUBSIDIOS E INCENTIVOS FISCAIS ou como estrategia de PROMOCAO E MARKETING SOCIAL. A (mera filantropia tradicional) e incompleta; B (somente comunidade local) e restritiva; D (so anos 2000 / influencia europeia) e imprecisa; E (iniciativa estatal) inverte (e iniciativa empresarial)."}, {"id": "1979317", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Com base na Resolução n.º 493/2006 do CFESS, que dispõe\nsobre as condições éticas e técnicas do exercício profissional\ndo assistente social, assinale a alternativa correta.", "alt": {"A": "O arquivo do material técnico utilizado pelo assistente\nsocial deverá necessariamente ficar no mesmo espaço\nfísico onde o profissional trabalha.", "B": "É condição essencial, porém não obrigatória, para a\nrealização e a execução de qualquer atendimento ao\nusuário do serviço social a existência de espaço físico\nnas condições estabelecidas pela citada Resolução.", "C": "O assistente social deve informar, por escrito, ao CRESS\nde sua jurisdição as inadequações constatadas no\nambiente de trabalho, requerendo a fiscalização da\ninstituição.", "D": "O atendimento efetuado pelo assistente social deve ser\nfeito a portas fechadas, de forma a garantir-se o sigilo.", "E": "É atribuição do CFESS fiscalizar as condições éticas e\ntécnicas estabelecidas na referida Resolução."}, "g": "D", "j": "Res CFESS 493/2006 (condicoes eticas e tecnicas do exercicio profissional): D correta — o atendimento efetuado pelo AS deve ser feito A PORTAS FECHADAS, de forma a garantir o SIGILO PROFISSIONAL. A (mesmo espaco fisico) e incorreta; B (espaco fisico nao obrigatorio) inverte; C ('por escrito' nao e exigencia da Res); E (fiscalizacao pelo CFESS) inverte (e dos CRESS)."}, {"id": "1979315", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua"], "ano": "2022", "org": "PRODAM", "t": "", "e": "O Conselho Federal de Serviço Social lançou a série\n“Assistente Social no Combate ao Preconceito”, que busca\nreassegurar e fortalecer a dimensão política da profissão por\nmeio de informações e reflexões importantes para o\nenfrentamento à discriminação e ao preconceito. No Caderno\n3 dessa série, a temática abordada é o racismo. Com\nfundamento nas discussões apresentadas nesse material,\nassinale a alternativa correta, referente às discussões sobre o\nracismo no serviço social.", "alt": {"A": "Do ponto de vista da biologia genética, as raças\ndefinem os diferentes fenótipos dos seres humanos,\nque devem ser agrupados em categorias humanas\nsocialmente definidas.", "B": "Etnia e raça são conceitos idênticos.", "C": "Apesar de não ser consenso, a categoria “cor” é\nutilizada para registro de informação dos serviços\npúblicos e de atendimento à população, sendo dividida\nem branca, preta, parda, amarela e indígena, devendo\nesse item ser preenchido pelo atendente/servidor\npúblico, de acordo com a sua percepção.", "D": "O racismo é um crime previsto na Constituição Federal\nde 1988, passível de fiança e com prescrição de cinco\nanos, sendo os casos mais graves sujeitos à pena de\nreclusão.", "E": "A discriminação racial é a materialização concreta do\npreconceito de raça."}, "g": "E", "j": "Caderno 3 do CFESS sobre racismo: E correta — a DISCRIMINACAO RACIAL e a MATERIALIZACAO CONCRETA do preconceito de raca (passagem do plano mental/atitudinal para a pratica). A (raca pela biologia genetica) e refutada pela ciencia; B (etnia=raca) e incorreto; C (preenchida pelo servidor) inverte (e auto-atribuicao); D (racismo afiancavel/prescritivel) contraria CF/88 art. 5 XLII (INAFIANCAVEL e IMPRESCRITIVEL)."}, {"id": "1979314", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Uma das dimensões da Política Nacional de Fiscalização do\nServiço Social é a dimensão afirmativa de princípios e de\ncompromissos conquistados, que expressa", "alt": {"A": "a adoção de procedimentos técnico-políticos de\norientação e politização dos assistentes sociais, dos\nusuários, das instituições e da sociedade em geral\nacerca dos princípios e dos compromissos ético- políticos do serviço social.", "B": "as ações que possibilitam, a partir da aproximação das\nparticularidades socioinstitucionais, instituir bases e\nparâmetros normativo-jurídicos reguladores do\nexercício profissional.", "C": "a consolidação do projeto ético-político profissional,\nem articulação com a Associação Brasileira de Ensino e\nPesquisa em Serviço Social (ABEPSS) e a Executiva\nNacional de Estudantes de Serviço Social (ENESSO), no\nâmbito da categoria.", "D": "a concretização de estratégias para o fortalecimento\ndo projeto ético-político profissional e da organização\npolítica da categoria em defesa dos direitos, das\npolíticas públicas e da democracia e,\nconsequentemente, para a luta por condições de\ntrabalho condignas e pela qualidade dos serviços\nprofissionais prestados.", "E": "a importância do aprofundamento do debate sobre a\nformação e o exercício profissional para a construção\nde estratégias que valorizem e defendam a profissão."}, "g": "D", "j": "PNF — dimensao AFIRMATIVA: 'concretizacao de estrategias para fortalecimento do PEP profissional e da organizacao politica da categoria em defesa dos direitos, das politicas publicas e da democracia e, consequentemente, para a luta por condicoes de trabalho condignas e qualidade dos servicos profissionais prestados'. Alternativa D reproduz fielmente. As demais descrevem outras dimensoes (politico-pedagogica em A, normativo-juridica em B etc)."}, {"id": "1979313", "d": "servico_social", "a": ["Serviço Social na Educação", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social", "Educação e Serviço Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "O processo coletivo de ensino-aprendizagem no qual se\nrealiza a observação, o registro, a análise e o\nacompanhamento da atuação do estagiário no campo de\nestágio em serviço social, bem como a avaliação do processo\nde aprendizagem discente, visando-se à construção de\nconhecimentos e de competências para o exercício da\nprofissão, é chamado de", "alt": {"A": "supervisão direta, cujos participantes são apenas o\nsupervisor de campo e o estagiário.", "B": "supervisão direta, cujos participantes são apenas o\nsupervisor acadêmico e o estagiário.", "C": "supervisão direta, cujos participantes são o supervisor\nde campo, o supervisor acadêmico e o estagiário.", "D": "supervisão integrada, cujos participantes são o\nsupervisor de campo, o supervisor acadêmico e o\nestagiário.", "E": "supervisão integrada, cujos participantes são apenas o\nsupervisor de campo e o estagiário."}, "g": "C", "j": "PNE/Res CFESS 533/2008 — SUPERVISAO DIRETA de estagio: processo coletivo de ensino-aprendizagem com observacao, registro, analise e acompanhamento — envolve TRES participantes: SUPERVISOR DE CAMPO, SUPERVISOR ACADEMICO e ESTAGIARIO. Alternativa C correta. A, B reduzem a dois participantes; D, E confundem com 'supervisao integrada'."}, {"id": "1979310", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Serviço Social no campo sócio jurídico", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família", "Violência e Serviço Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Com base na Lei Maria da Penha, assinale a alternativa\ncorreta.", "alt": {"A": "Configura violência doméstica e familiar contra a\nmulher qualquer ação ou omissão que lhe cause morte,\nlesão, sofrimento físico, sexual ou psicológico, e dano\nmoral ou patrimonial.", "B": "Para fins da aplicação da Lei Maria da Penha, a família\né compreendida como núcleo constituído por pessoas\nque necessariamente apresentam laços consanguíneos\ne convivem no mesmo espaço doméstico.", "C": "A Lei Maria da Penha pode ser aplicada a qualquer\nrelação íntima de afeto em que o agressor conviva ou\ntenha convivido com a ofendida, independentemente\nde coabitação.", "D": "São quatro os tipos de violência previstos na Lei Maria\nda Penha: violência física; violência patrimonial;\nviolência sexual; e violência moral.", "E": "O poder público é a única esfera responsável para criar\nas condições necessárias para o efetivo exercício dos\ndireitos previstos na Lei Maria da Penha."}, "g": "C", "j": "Lei Maria da Penha (Lei 11.340/2006), art. 5, III: aplica-se a QUALQUER RELACAO INTIMA DE AFETO, na qual o agressor conviva ou tenha convivido com a ofendida, INDEPENDENTEMENTE DE COABITACAO. Alternativa C reproduz fielmente. A omite 'baseada no genero'; B restringe a lacos consanguineos; D omite violencia psicologica (sao 5 tipos); E reduz a responsabilidade ao poder publico."}, {"id": "1979308", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Estudo Social, Pareceres, Perícia Social, Relatório Social e Laudo Social", "Instrumentos e Técnicas de Intervenção"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Considerando os instrumentos e as técnicas do serviço social,\nassinale a alternativa correta.", "alt": {"A": "O relatório social é uma apresentação descritiva e fiel\ndo problema retratado pelo usuário, não cabendo\ninterpretações do assistente social.", "B": "Uma das principais características do relatório é o alto\nnível de detalhamento do seu conteúdo.", "C": "As entrevistas, em uma perícia social, devem ser\nindividuais e diretivas e abordar somente o fato a ser\nesclarecido.", "D": "Na realização da perícia social, o assistente social não\ndeverá informar ao sujeito entrevistado o objetivo do\nseu trabalho, uma vez que tal informação poderá\ncomprometer o sigilo.", "E": "O parecer social diz respeito a esclarecimentos e a\nanálises, com base em conhecimento específico de\nserviço social, de questões relacionadas a decisões a\nserem tomadas."}, "g": "E", "j": "Instrumentos e tecnicas em SS: E correta — o PARECER SOCIAL diz respeito a ESCLARECIMENTOS E ANALISES, com base em conhecimento ESPECIFICO de servico social, sobre questoes relacionadas a DECISOES a serem tomadas (carater analitico/conclusivo). A (relatorio sem interpretacoes) inverte; B (alto detalhamento) e generico; C (entrevistas individuais/diretivas) e restritivo; D (nao informar objetivo) viola TCLE."}, {"id": "1979306", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Conforme o Código de Ética Profissional, é vedado ao\nassistente social", "alt": {"A": "mobilizar sua autoridade funcional, ao ocupar uma\nchefia, para a liberação de carga horária de\nsubordinado, para fim de estudos e de pesquisas que\nvisem ao aprimoramento profissional.", "B": "realizar crítica pública a colega e a outros profissionais,\nmesmo que de maneira objetiva, construtiva e\ncomprovável.", "C": "emprestar seu nome e seu registro profissional a\nfirmas, a organizações ou a empresas para simulação\ndo exercício efetivo do serviço social.", "D": "intervir na prestação de serviços que estejam sendo\nefetuados por outro profissional, em quaisquer\ncircunstâncias.", "E": "contribuir para a criação de mecanismos que venham a\ndesburocratizar a relação dele com os usuários."}, "g": "C", "j": "CE-SS, art. 4 (Vedacoes): e VEDADO ao AS 'emprestar seu nome e/ou registro profissional a firmas, organizacoes ou empresas para simulacao do exercicio efetivo do Servico Social'. Alternativa C reproduz a vedacao. A (mobilizar autoridade para subordinado) e dever da chefia; B (critica publica objetiva/construtiva) e dever (art. 3, e); D ('em quaisquer circunstancias') extrapola (intervencao e permitida em certos casos); E (desburocratizar) e dever."}, {"id": "1979305", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Em relação ao sigilo profissional, assinale a alternativa\ncorreta.", "alt": {"A": "É direito do assistente social revelar sigilo profissional.", "B": "O sigilo profissional deverá ser quebrado sempre que\nfor revelado um fato criminoso do usuário ao\nassistente social.", "C": "Caso ocorra a quebra do sigilo, o assistente social\ndeverá relatar à autoridade competente todas as\ninformações dadas pelo usuário.", "D": "A quebra de sigilo só poderá ocorrer nas situações cuja\ngravidade possa trazer prejuízos aos interesses do\nusuário, de terceiros e da coletividade,\nindependentemente de se tratar de fato delituoso ou\nnão.", "E": "No trabalho multidisciplinar, o assistente social poderá\nprestar à equipe todas as informações fornecidas pelo\nusuário."}, "g": "D", "j": "CE-SS, art. 18 (sigilo): a quebra do sigilo SO PODERA OCORRER nas situacoes cuja GRAVIDADE possa trazer PREJUIZOS AOS INTERESSES DO USUARIO, DE TERCEIROS E DA COLETIVIDADE, INDEPENDENTEMENTE de se tratar de fato delituoso ou nao. Alternativa D reproduz fielmente. A (direito de revelar) inverte (e dever guardar); B (sempre em fato criminoso) inverte; C (relatar todas informacoes) viola 'estritamente necessario'; E (em multi prestar todas info) viola sigilo."}, {"id": "1979304", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Acerca da questão social e de suas expressões no Brasil\ncontemporâneo, assinale a alternativa correta.", "alt": {"A": "A questão social circunscreve-se aos problemas sociais\nque são vivenciados pelas famílias demandatárias da\nação do serviço social.", "B": "O serviço social, como expressão do trabalho coletivo\nno âmbito das políticas sociais, abrange a mediação\nprivilegiada e exclusiva do trabalho profissional frente\nàs configurações da questão social.", "C": "Os termos “expressões da questão social” e “exclusão\nsocial ” são sinônimos e expressam o mesmo fenômeno\nsocial.", "D": "A questão social e suas manifestações na sociedade\nbrasileira são objeto de ação e de intervenção\nunicamente do Estado.", "E": "A questão social é indissociável da sociabilidade\ncapitalista e envolve uma arena de lutas políticas e\nculturais contra as desigualdades socialmente\nproduzidas."}, "g": "E", "j": "Questao social no Brasil (Iamamoto, Netto): E correta — a QUESTAO SOCIAL e INDISSOCIAVEL DA SOCIABILIDADE CAPITALISTA (resultado da contradicao capital-trabalho) e envolve uma ARENA DE LUTAS POLITICAS E CULTURAIS contra as desigualdades socialmente produzidas. A (so problemas familiares), B (mediacao exclusiva do SS), C (sinonimo de exclusao), D (acao unica do Estado) reducionistas."}, {"id": "1979302", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)", "Benefícios Eventuais e de Prestação Continuada/LOAS"], "ano": "2022", "org": "PRODAM", "t": "", "e": "De acordo com a Lei Orgânica da Assistência Social, as\nprovisões suplementares e provisórias que integram\norganicamente as garantias do Sistema Único de Assistência\nSocial (SUAS) e que são prestadas aos cidadãos e às famílias\nem virtude de nascimento, morte, situações de\nvulnerabilidade temporária e de calamidade pública são\nchamadas de", "alt": {"A": "benefícios emergenciais.", "B": "benefícios provisórios.", "C": "benefícios contingenciais.", "D": "benefícios temporários.", "E": "benefícios eventuais."}, "g": "E", "j": "LOAS (Lei 8.742/93), art. 22: os BENEFICIOS EVENTUAIS sao 'provisoes suplementares e provisorias que integram organicamente as garantias do SUAS, prestadas aos cidadaos e as familias em virtude de NASCIMENTO, MORTE, situacoes de VULNERABILIDADE TEMPORARIA e de CALAMIDADE PUBLICA'. Alternativa E correta."}, {"id": "1979300", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2022", "org": "PRODAM", "t": "", "e": "No Brasil, a Política de Assistência Social", "alt": {"A": "é de caráter contributivo.", "B": "tem como princípio a regionalização dos direitos\nsociais, de forma a disponibilizar maiores recursos às\nregiões mais necessitadas.", "C": "visa, entre outros objetivos, à promoção da integração\nao mercado de trabalho.", "D": "está estruturada em três níveis de complexidade:\nproteção social básica, proteção social complexa e\nproteção social emergencial.", "E": "tem o objetivo de assegurar que as ações no âmbito da\nassistência social tenham centralidade no indivíduo."}, "g": "C", "j": "PAS/LOAS, art. 2, II: a Politica de Assistencia Social tem como objetivo, entre outros, a PROMOCAO DA INTEGRACAO AO MERCADO DE TRABALHO. Alternativa C correta. A (carater contributivo) inverte (PAS NAO e contributiva); B (regionalizacao) nao e principio; D (proteccao 'complexa' e 'emergencial') inverte (sao BASICA e ESPECIAL/media-alta complexidade); E (centralidade no individuo) inverte (e matricialidade sociofamiliar)."}, {"id": "1979295", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Acerca do projeto ético-político do serviço social, é correto\nafirmar que", "alt": {"A": "seu valor ético central são os direitos.", "B": "sua dimensão política é expressa pelo posicionamento\na favor da equidade e da justiça social, na perspectiva\nda universalização do acesso a bens e a serviços, bem\ncomo da ampliação e da consolidação da cidadania.", "C": "sua gênese data da segunda metade da década de 80.", "D": "ele é um projeto que possui uma estrutura básica\nconsolidada, definida e acabada, que permanece\ninalterada, o que lhe garante confiabilidade e\nfidedignidade.", "E": "ele é um projeto hegemônico fundamentado em\nprincípios liberais e, para a sua materialização,\nnecessariamente deve estar alinhado ao projeto\nsocietário vigente."}, "g": "B", "j": "PEP — dimensao politica: B correta — expressa-se pelo POSICIONAMENTO A FAVOR DA EQUIDADE E DA JUSTICA SOCIAL, na perspectiva da UNIVERSALIZACAO DO ACESSO a bens e servicos, bem como da AMPLIACAO E CONSOLIDACAO DA CIDADANIA. A (valor central = direitos) inverte (e LIBERDADE); C (genese na segunda metade dos 80) reduz; D (estrutura inalterada) nega historicidade; E (hegemonico em principios liberais) contradiz (e critico-dialetico)."}, {"id": "1979294", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "De acordo com a Lei de Regulamentação do Serviço Social (Lei\nn.º 8.662/2010), que estabelece as competências e as\natribuições do assistente social, as atividades privativas do\nassistente social incluem", "alt": {"A": "encaminhar providências e prestar orientação social a\nindivíduos, a grupos e à população.", "B": "elaborar, implementar, executar e avaliar políticas\nsociais junto a órgãos da Administração Pública, direta\nou indireta, a empresas, a entidades e a organizações\npopulares.", "C": "ocupar cargos e funções de direção e de fiscalização da\ngestão financeira em órgãos e entidades\nrepresentativas da categoria profissional.", "D": "realizar estudos socioeconômicos com os usuários,\npara fins de comprovação de renda, junto a órgãos da\nAdministração Pública direta e indireta, a empresas\nprivadas e a outras entidades.", "E": "planejar, organizar e administrar benefícios e serviços\nsociais."}, "g": "C", "j": "Lei 8.662/93, art. 5 (atribuicoes privativas): inclui 'ocupar cargos e funcoes de DIRECAO E FISCALIZACAO DA GESTAO FINANCEIRA em orgaos e entidades representativas da CATEGORIA PROFISSIONAL'. Alternativa C correta (privativa). A, B sao competencias (art. 4); D, E tambem sao privativas mas a banca elegeu C."}, {"id": "1979293", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social", "Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Tendo em vista que o debate sobre gênero é fundamental\npara a materialização do projeto ético-político do serviço\nsocial, assinale a alternativa correta a respeito dos estudos de\ngênero no serviço social.", "alt": {"A": "A produção teórica sobre gênero originada a partir da\nperspectiva teórica marxista é vasta e profícua, o que\npossibilitou às feministas marxistas criar e desenvolver\no conceito de gênero enquanto fenômeno relacional.", "B": "O gênero é um fenômeno histórico, social e natural.", "C": "O machismo é uma categoria teórica utilizada para\ncompreender as práticas dominadoras do homem\nsobre a mulher. Assim, o machismo é um privilégio dos\nhomens, que são os responsáveis por sua reprodução\nna sociedade.", "D": "O gênero é um elemento constitutivo das relações\nsociais, está intimamente interligado a fatores políticos\ne econômicos em cada sociedade e está presente em\ntodas as dimensões do trabalho do assistente social.", "E": "A categoria gênero expressa que existe uma essência\nmasculina e uma feminina de caráter universal, com as\nquais os homens e as mulheres devem identificar-se."}, "g": "D", "j": "Estudos de genero no SS (Joan Scott, Saffioti, Lisboa): D correta — o GENERO e ELEMENTO CONSTITUTIVO DAS RELACOES SOCIAIS, intimamente interligado a fatores POLITICOS E ECONOMICOS e presente em TODAS as dimensoes do trabalho do AS. A (perspectiva marxista vasta sobre genero) e impreciso historicamente; B (genero como fenomeno NATURAL) inverte (e historico-social); C (machismo como privilegio so dos homens) reducionista; E (essencia universal de generos) inverte (genero e construcao social)."}, {"id": "1875960", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Proteção Social Básica", "Proteção Social Especial de Média e Alta Complexidade", "Sistema Único de Assistência Social – SUAS (Gestão da AS)", "Conselhos de Assistência Social (nacional, estaduais e municipais)"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Acerca da Política de Assistência Social, assinale a alternativa\ncorreta.", "alt": {"A": "O Serviço de Proteção e Atendimento Especializado a\nFamílias e Indivíduos (Paefi) integra a proteção social\nbásica nos Centros de Referência de Assistência\nSocial (CRAS) e tem o objetivo de atender famílias com\nrompimento dos vínculos familiares e violência no\nâmbito de suas relações, garantindo o direito à\nconvivência familiar e comunitária.", "B": "Uma das diretrizes da Política de Assistência Social é o\nrespeito à dignidade do cidadão, ao seu direito à tutela\ndo Estado e ao acesso a benefícios e serviços de\nqualidade quando comprovada, por meio de\ndocumentação, de forma inquestionável, a sua\nnecessidade.", "C": "O Conselho Nacional de Assistência Social (CNAS) é um\nórgão consultivo da Política de Assistência Social que\ntem caráter permanente e composição tripartite entre\ngoverno, representantes de instituições de assistência\nsocial e usuários da Política de Assistência Social.", "D": "A segurança de acolhida supõe ações de abordagem\nem territórios de incidência de situações de risco e a\noferta de uma rede de serviços e de locais de\npermanência de indivíduos e famílias sob curta, média\ne longa duração.", "E": "Tem como um de seus objetivos assegurar que as ações\nno âmbito da assistência social tenham centralidade no\nindivíduo."}, "g": "D", "j": "PAS/Tipificacao: D correta — a SEGURANCA DE ACOLHIDA supoe acoes de ABORDAGEM em territorios de incidencia de situacoes de risco e a oferta de uma rede de servicos e LOCAIS DE PERMANENCIA de individuos e familias sob curta, media e longa duracao. A (PAEFI na PSB no CRAS) inverte (PAEFI e PSE de media complexidade, ofertado no CREAS); B (tutela do Estado / comprovacao inquestionavel) inverte (sem vexar); C (CNAS consultivo) inverte (e deliberativo); E (centralidade no individuo) inverte (matricialidade sociofamiliar)."}, {"id": "1770341", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Lei Orgânica da Assistência Social afirma que a assistência\nsocial é uma política de seguridade social que provê os\nmínimos sociais e se realiza por meio de um conjunto\nintegrado de ações de iniciativa pública e da sociedade, para\ngarantir o atendimento às necessidades básicas. Conforme a\nLei Orgânica da Assistência Social, assinale a alternativa\nincorreta.", "alt": {"A": "Um dos objetivos da assistência social é a vigilância\nsocioassistencial, que visa a analisar territorialmente a\ncapacidade protetiva das famílias e, nela, a ocorrência\nde vulnerabilidades, de ameaças, de vitimizações e de\ndanos.", "B": "Um dos princípios que regem a assistência social é a\nuniversalização dos direitos sociais, a fim de tornar o\ndestinatário da ação assistencial alcançável pelas\ndemais políticas públicas.", "C": "O SUAS é integrado exclusivamente pelos entes\nfederativos e pelas entidades e organizações de\nassistência social abrangidas por esta Lei.", "D": "A organização da assistência social tem como base\nalgumas diretrizes, entre elas a da participação\npopular.", "E": "A vigilância socioassistencial é um dos instrumentos\ndas proteções da assistência social que identifica e\nprevine as situações de risco e vulnerabilidade social e\nseus agravos no território."}, "g": "C", "j": "LOAS — alternativa incorreta: C afirma que o SUAS e integrado EXCLUSIVAMENTE pelos entes federativos e entidades de assistencia social. INCORRETO — a LOAS inclui tambem os CONSELHOS de assistencia social, os FUNDOS, entre outros componentes. A, B, D, E reproduzem corretamente disposicoes da LOAS."}, {"id": "1770335", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Serviço Social no campo sócio jurídico", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família", "Violência e Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Lei n.o\n 11.340/2006 (Lei Maria da Penha) afirma que\nconfigura violência doméstica e familiar contra a mulher\nqualquer ação ou omissão baseada no gênero que lhe cause\nmorte, lesão, sofrimento físico, sexual ou psicológico e dano\nmoral ou patrimonial. Com base nessa Lei, julgue os itens a\nseguir.     I A política pública que visa a coibir a violência doméstica\ne familiar contra a mulher tem como uma de suas\ndiretrizes a implementação do atendimento policial\nespecializado para as mulheres, em particular nas\nDelegacias de Atendimento à Mulher.\n  II O juiz assegurará à mulher em situação de violência\ndoméstica e familiar, para preservar sua integridade\nfísica e psicológica, a manutenção do vínculo trabalhista,\nquando necessário o afastamento do local de trabalho,\npor até seis meses.  \nIII Aquele que, por ação ou omissão, causar lesão, violência\nfísica, sexual ou psicológica e dano moral ou patrimonial\nà mulher fica obrigado a ressarcir todos os danos\ncausados, inclusive ressarcir ao Sistema Único de\nSaúde (SUS) os custos relativos aos serviços de saúde\nprestados para o total tratamento da vítima em situação\nde violência doméstica e familiar.  \nIV A mulher em situação de violência doméstica e familiar\ntem prioridade para matricular seus dependentes na\ninstituição de educação básica mais próxima de seu\ndomicílio ou para transferi-los para essa instituição,\nmediante a apresentação dos documentos\ncomprobatórios do registro da ocorrência policial ou do\nprocesso de violência doméstica e familiar em curso.\n    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Lei Maria da Penha: I correto (atendimento policial especializado, DEAM); II correto (manutencao do vinculo trabalhista por ate 6 meses em afastamento); III correto (ressarcimento de danos incluindo SUS); IV correto (prioridade para matricula dos dependentes, incluido pela Lei 13.882/2019). Todos os 4 itens corretos. Gabarito E."}, {"id": "1770333", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2021", "org": "CRESS", "t": "", "e": "Segundo a Norma Operacional Básica do Sistema Único de\nAssistência Social (SUAS), assinale a alternativa incorreta.", "alt": {"A": "O SUAS é integrado pelos entes federativos, pelos\nrespectivos conselhos de assistência social e pelas\nentidades e organizações de assistência social\nabrangidas pela Lei Orgânica da Assistência Social.", "B": "A União, os estados, o Distrito Federal e os municípios\ndeverão elaborar os respectivos planos de assistência\nsocial a cada ano, de acordo com os períodos de\nelaboração do plano plurianual.", "C": "São instrumentos da gestão financeira e orçamentária\ndo SUAS o orçamento da assistência social e os fundos\nde assistência social.", "D": "O Pacto de Aprimoramento do SUAS firmado entre a\nUnião, os estados, o Distrito Federal e os municípios é\no instrumento por meio do qual se materializam as\nmetas e as prioridades nacionais no âmbito do SUAS e\nconsiste em um mecanismo de indução do\naprimoramento da gestão, dos serviços, dos\nprogramas, dos projetos e dos benefícios\nsocioassistenciais.", "E": "O cofinanciamento dos serviços socioassistenciais\ndar-se-á por meio do Bloco de Financiamento da\nProteção Social Básica e do Bloco de Financiamento da\nProteção Social Especial, compostos pelo conjunto de\npisos relativos a cada proteção, de acordo com a\nTipificação Nacional dos Serviços Socioassistenciais."}, "g": "B", "j": "NOB-SUAS — alternativa incorreta: B afirma que os planos de assistencia social sao elaborados A CADA ANO. INCORRETO — os planos sao QUADRIENAIS, elaborados conforme periodos do PPA (Plano Plurianual). A, C, D, E reproduzem corretamente disposicoes da NOB-SUAS."}, {"id": "1104834", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Matricialidade Sociofamiliar", "Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "De acordo com a LOAS, assinale a alternativa correta.", "alt": {"A": "O  respeito  ao  direito  no  acesso  ao  atendimento  e  à   individualidade  do  cidadão,  sem  discriminação  de   qualquer  natureza,  garantindo‐se  igualdade  às   populações  urbanas  e  rurais,  é  um  dos  princípios  da   Política de Assistência Social.", "B": "A  descentralização  político‐administrativa  e  a   responsabilidade  compartilhada  entre  o  Estado  e  a   sociedade civil na condução da Política de Assistência   Social  são  diretrizes  da  organização  da  assistência   social.", "C": "Cabe ao Ministério Público zelar pelo efetivo respeito   aos direitos estabelecidos na LOAS.", "D": "As ações no Sistema Único de Assistência Social (SUAS)   têm por objetivo a proteção à família, à maternidade,   à infância, à pessoa com deficiência, à adolescência e à   velhice e, como base de organização, a matricialidade   familiar.", "E": "O  funcionamento  das  entidades  e  organizações  de   assistência social depende de prévia inscrição no CRAS,   se  as  instituições  atuarem  na  proteção  social  básica,    ou  nos  Centros  de  Referência  Especializados  de   Assistência  Social  (CREAS),  se  atuarem  na  proteção   social especial."}, "g": "C", "j": "LOAS, art. 31: CABE AO MINISTERIO PUBLICO zelar pelo efetivo respeito aos direitos estabelecidos na LOAS. Alternativa C correta. A (igualdade urbanas/rurais como principio) e diretriz, nao principio; B descreve diretrizes mas a formulacao tem nuances; D (matricialidade familiar) reduz o termo correto (sociofamiliar); E (inscricao no CRAS/CREAS) inverte (e no CMAS/CNAS)."}, {"id": "1151329", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Lei n.º 12.435/2011, assinale a alternativa\nque apresenta um objetivo da assistência social.", "alt": {"A": "consolidar a gestão compartilhada, o cofinanciamento\ne a cooperação técnica entre os entes federativos que,\nde modo articulado, operem na proteção social não\ncontributiva", "B": "definir os níveis de gestão, respeitadas as diversidades\nregionais e municipais", "C": "afiançar a vigilância socioassistencial e a garantia de\ndireitos", "D": "estabelecer a gestão integrada de serviços e benefícios", "E": "defender direitos, visando a garantir o pleno acesso a\neles no conjunto das provisões socioassistenciais"}, "g": "E", "j": "Lei 12.435/2011 (que altera a LOAS), art. 2, III: e objetivo da assistencia social a DEFESA DE DIREITOS, visando a garantir o PLENO ACESSO a eles no conjunto das provisoes socioassistenciais. Alternativa E correta. A (gestao compartilhada) e diretriz; B (niveis de gestao) e instrumento; C (vigilancia socioassistencial) e outro objetivo, mas a redacao mais especifica esta em E; D (gestao integrada) e operacional."}, {"id": "1151325", "d": "servico_social", "a": ["Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS", "Sistema Único de Assistência Social – SUAS (Gestão da AS)"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Lei n.º 8.742/1993, que dispõe sobre a\norganização da assistência social e dá outras providências,\nassinale a alternativa que apresenta um dos objetivos da\nassistência social.", "alt": {"A": "vigilância socioassistencial, que visa a analisar\nterritorialmente a capacidade protetiva das famílias e,\nnela, a ocorrência de vulnerabilidades, ameaças,\nvitimizações e danos", "B": "garantir a supremacia do atendimento às necessidades\nsociais sobre as exigências de rentabilidade econômica", "C": "incentivar a participação da população, por meio de\norganizações representativas, na formulação das\npolíticas e no controle das ações em todos os níveis", "D": "estabelecer a primazia da responsabilidade do Estado\nna condução da política de assistência social em cada\nesfera de governo", "E": "consolidar a gestão compartilhada, o cofinanciamento\ne a cooperação técnica entre os entes federativos que,\nde modo articulado, operem na proteção social não\ncontributiva"}, "g": "A", "j": "LOAS (Lei 8.742/93, alterada pela 12.435/2011), art. 2, II: e objetivo da assistencia social a VIGILANCIA SOCIOASSISTENCIAL, que visa a ANALISAR TERRITORIALMENTE A CAPACIDADE PROTETIVA DAS FAMILIAS e, nela, a ocorrencia de VULNERABILIDADES, AMEACAS, VITIMIZACOES E DANOS. Alternativa A reproduz fielmente. B (supremacia das necessidades sociais) e principio (art. 4); C (participacao popular) e diretriz; D (primazia da responsabilidade do Estado) e diretriz; E (gestao compartilhada) e diretriz."}, {"id": "3179870", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública", "Servidores Públicos"], "ano": "2024", "org": "CORE", "t": "", "e": "À luz das disposições constitucionais sobre a Administração\nPública Federal, julgue as afirmativas a seguir.\n    I Decorre do princípio da impessoalidade que\na publicidade dos atos, dos programas, das\nobras, dos serviços e das campanhas dos órgãos\npúblicos deverá ter caráter educativo, informativo\nou de orientação social, dela não podendo\nconstar nomes, símbolos ou imagens que\ncaracterizem promoção pessoal de autoridades ou\nservidores públicos.    \nII A CF/1988 veda, de forma absoluta, a acumulação\nremunerada de cargos públicos, inclusive nas\nautarquias, nas fundações, nas empresas públicas,\nnas sociedades de economia mista – bem\ncomo em suas subsidiárias – e nas sociedades\ncontroladas, direta ou indiretamente, pelo\nPoder Público.    \nIII O servidor público ocupante de cargo efetivo\nque venha a ser investido no cargo de prefeito\npode exercer as duas funções, desde que haja\ncompatibilidade de horários.\n      Assinale a alternativa correta.", "alt": {"A": "Somente o item I está certo.", "B": "Somente os itens I e II estão certos.", "C": "Somente os itens I e III estão certos.", "D": "Somente o item II está certo.", "E": "Somente os itens II e III estão certos."}, "g": "A", "j": "CF/88 sobre Administracao Publica: I correto — art. 37, par. 1 (publicidade dos atos com carater educativo/informativo/social, vedados nomes/simbolos/imagens de promocao pessoal); item II INCORRETO — a vedacao a acumulacao remunerada NAO e absoluta (art. 37, XVI prevê excecoes — dois cargos de professor, professor + tecnico-cientifico, dois de saude); item III INCORRETO — art. 38, I-II preve afastamento do servidor investido em mandato de prefeito (apenas vereador pode acumular com compatibilidade de horarios). Apenas I. Gabarito A."}, {"id": "2159619", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Igualdade"], "ano": "2022", "org": "CFP", "t": "", "e": "A Constituição Federal de 1988 legisla sobre a relação entre\nhomens e mulheres, de forma diferente das anteriores,\ncom várias disposições nesse sentido. Julgue os itens a\nseguir.    \nI. Segundo a Constituição, homens e mulheres são iguais\nem direitos e obrigações, estabelecendo uma\nigualdade jurídica.    \nII. Por outro lado, a Constituição de 1988 reconhece que,\nna realidade, a igualdade entre homens e mulheres\nnão acontece, ao que propõe aos estados políticas de\nproteção do mercado de trabalho à mulher.    III. Em termos da sociedade conjugal, homens e mulheres\nsão iguais em deveres e direitos.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Todos os itens estão certos.", "E": "Nenhum item está certo."}, "g": "D", "j": "CF/88 sobre igualdade entre homens e mulheres: I correto (art. 5, I — iguais em direitos e obrigacoes — igualdade juridica formal); II correto (art. 7, XX — protecao do mercado de trabalho da mulher mediante incentivos especificos, reconhecendo desigualdade material); III correto (art. 226, par. 5 — direitos e deveres referentes a sociedade conjugal sao exercidos igualmente pelo homem e pela mulher). Todos os itens corretos. Gabarito D."}, {"id": "2001749", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2022", "org": "Prefeitura de Barreiras", "t": "", "e": "A Constituição Federal de 1988 (CF) estabelece os princípios\nque regem a Administração Pública. Em relação a esse\nassunto, considere os efeitos apresentados nos itens a seguir.      \nI presunção do conhecimento dos interessados em relação\nao comportamento da administração pública direta,\nindireta e fundacional\n    II desencadear o decurso dos prazos de interposição de\nrecursos    \nIII marcar o início dos prazos de decadência e prescrição    \nIV impedir a alegação de ignorância em relação ao\ncomportamento da administração pública direta e\nindireta\n      Esses efeitos são decorrentes do princípio da", "alt": {"A": "legalidade.", "B": "impessoalidade.", "C": "moralidade.", "D": "publicidade."}, "g": "D", "j": "CF/88 — Principios da Administracao Publica (art. 37): os efeitos listados (presuncao de conhecimento; desencadeamento dos prazos de recursos; inicio dos prazos de decadencia e prescricao; impedimento da alegacao de ignorancia) sao decorrentes do PRINCIPIO DA PUBLICIDADE. Alternativa D correta. Legalidade (A), impessoalidade (B), moralidade (C) sao outros principios com efeitos distintos."}, {"id": "1877738", "d": "psicologia", "a": ["Absenteísmo e Rotatividade", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "A rotatividade de pessoal é um grande desafio enfrentado por\nmuitas organizações nos dias atuais. A rotatividade em\nexcesso pode provocar sérios problemas no clima, na cultura,\nna produtividade e na longevidade das empresas.\nConsiderando essa informação, assinale a alternativa que\napresenta o cálculo utilizado para se determinar o indicador\nde rotatividade de pessoal.", "alt": {"A": "(total de admissões + total de demissões ÷ 2) ÷ número\nde funcionários ativos x 100", "B": "total de admissões ÷ número de funcionários ativos x 100", "C": "total de demissões ÷ número de funcionários ativos x 100", "D": "(total de admissões + total de demissões voluntárias ÷ 2)\n÷ número de funcionários ativos x 100", "E": "(total de admissões + total de demissões involuntárias ÷ 2)\n÷ número de funcionários ativos x 100"}, "g": "A", "j": "Formula classica de Chiavenato para indice de rotatividade (turnover): [(admissoes+demissoes)/2] / efetivo medio x 100. Alternativa A reproduz exatamente essa formula."}, {"id": "1877737", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta o conceito de psicologia\nsocial.", "alt": {"A": "É a área de estudo da psicologia que analisa as\ninterações humanas e se debruça sobre os problemas\nrelativos às atitudes e aos valores.", "B": "É a área de estudo da psicologia que se dedica à analise\ndos transtornos mentais e dos aspectos psíquicos de\ndoenças não mentais. Seus temas incluem a etiologia,\na classificação, o diagnóstico, a epidemiologia e a\nintervenção.", "C": "É a área de estudo da psicologia que analisa os\nfenômenos cognitivos, comportamentais, subjetivos e\npsicológicos presentes no ambiente de trabalho.", "D": "É a área de estudo da psicologia que tem como\nprincipal objeto a saúde mental do paciente internado\nem alguma instituição de saúde.", "E": "É a área de estudo da psicologia que visa a promover a\nmelhoria da qualidade de vida e do desempenho\nesportivo dos atletas."}, "g": "A", "j": "Psicologia social estuda interacoes humanas, atitudes e valores. B descreve psicopatologia, C psicologia organizacional, D psicologia hospitalar e E psicologia do esporte."}, {"id": "1877736", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Segundo Boff, a ética vem da filosofia e considera as\nconcepções de fundo, os princípios e os valores que orientam\nas pessoas e as sociedades. Uma pessoa é ética quando tem\ncaráter e boa índole e quando se orienta por princípios e\nconcepções éticos. Com base nessas informações, assinale a\nalternativa que apresenta um comportamento organizacional\nético no âmbito da psicologia organizacional.", "alt": {"A": "prover feedbacks individuais de melhoria na frente de\noutros membros da equipe, com o objetivo de gerar\nmaior competitividade e produtividade entre os\nmembros", "B": "instalar câmeras de segurança nos banheiros, com o\nintuito de proteger os colaboradores", "C": "solicitar tarefas com prazos insuficientes para seu\ncumprimento, com o intuito de desafiar o colaborador", "D": "excesso de pressão para gerar maior efetividade no\ndesenvolvimento do trabalho", "E": "identificar e reportar comportamentos que exponham\npessoas a constrangimento e possam gerar assédio\nmoral"}, "g": "E", "j": "Identificar e reportar comportamentos que gerem assedio moral e o unico comportamento etico listado. A, B, C, D descrevem condutas antieticas (feedback negativo em publico, cameras em banheiros, prazos abusivos, excesso de pressao)."}, {"id": "1877735", "d": "psicologia", "a": ["Absenteísmo e Rotatividade", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta um resultado possível da\nalta rotatividade para as empresas.", "alt": {"A": "alto desempenho", "B": "formação de equipes de alto desempenho e\ndiversificadas", "C": "engajamento com a cultura da empresa", "D": "relações interpessoais diversificadas e profundas", "E": "aumento dos gastos com processos de recrutamento e\nseleção"}, "g": "E", "j": "Alta rotatividade gera aumento de custos com recrutamento e selecao, perda de conhecimento e ruptura de equipes. As demais alternativas (A-D) descrevem efeitos positivos, contrarios ao enunciado."}, {"id": "1877734", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta os fatores estruturantes\ndas representações de bem-estar e mal-estar no trabalho da\nEAA_QVT para a organização do trabalho.", "alt": {"A": "relações hierárquicas (chefia imediata, chefias\nsuperiores), relações com os pares (colegas de\ntrabalho, membros de equipes) e relações\nexternas (cidadãos-usuarios dos serviços públicos, ́\nclientes e fornecedores de produtos e serviços\nprivados, prestadores de serviços, auditores, fiscais)", "B": "missão, objetivos e metas organizacionais (qualidade e\nquantidade, parametragens), divisão do\ntrabalho (hierárquica, técnica, social), processo de\ntrabalho (ciclos, etapas, ritmos, tipos de pressão),\npadrão de conduta (conhecimento, atitudes,\nhabilidades previstas, higiene, trajes/vestimentas),\ntrabalho prescrito (planejamento, tarefas, natureza e\nconteúdos das tarefas, regras formais e informais,\nprocedimentos técnicos, prazos), tempo de\ntrabalho (jornada [duração, turnos], pausas, férias,\nflexibilidade) e gestão do trabalho (controles,\nsupervisão, fiscalização, disciplina)", "C": "reconhecimento (do trabalho realizado, do empenho,\nda dedicação, da hierarquia [chefia imediata e\nsuperiores, da instituição, dos cidadãos-usuarios, dos ́\nclientes, dos consumidores, da sociedade) e\ncrescimento profissional (uso da criatividade,\ndesenvolvimento de competências, capacitações,\noportunidades, incentivos, equidade, carreira)", "D": "equipamentos arquitetônicos (piso, paredes, teto,\nportas, janelas, decoração, arranjos físicos, layouts),\nambiente físico (espaços de trabalho,\niluminação, temperatura, ventilação, acústica),\ninstrumental (ferramentas, máquinas, aparelhos,\ndispositivos informacionais, documentação,\npostos de trabalho, mobiliário complementar),\nmatéria-prima (materiais, bases informacionais) e\nsuporte organizacional (informações, suprimentos,\ntecnologias, políticas de remuneração, de capacitação\ne de benefícios)", "E": "sentido do trabalho (prazer, bem-estar, valorização do\ntempo vivenciado na organização, sentimento de\nutilidade social, produtividade saudável), importância\nda instituição empregadora (significado pessoal,\nsignificado profissional, significado familiar, significado\nsocial) e vida social (relação trabalho-casa, relação\ntrabalho-família, relação trabalho-amigos, relação\ntrabalho-lazer, relação trabalho-sociedade)"}, "g": "B", "j": "No modelo EAA_QVT de Ferreira, o fator 'organizacao do trabalho' compreende missao/metas, divisao do trabalho, processo de trabalho, padrao de conduta, trabalho prescrito, tempo de trabalho e gestao do trabalho - exatamente a descricao da alternativa B."}, {"id": "1877733", "d": "psicologia", "a": ["Qualidade de Vida", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Sob a perspectiva dos trabalhadores, a qualidade de vida no\ntrabalho (QVT) se expressa por meio das representações\nglobais (contexto organizacional) e específicas (situações de\ntrabalho) que estes constroem, indicando o predomínio de\nexperiências de bem-estar no trabalho, de reconhecimento\ninstitucional e coletivo, de possibilidade de crescimento\nprofissional e de respeito às características individuais.\nSegundo Ferreira, o modelo teórico da ergonomia\nda atividade aplicada à qualidade de vida no\ntrabalho (EAA_QVT), de natureza descritiva, contempla níveis\nanalíticos, fatores estruturadores e métodos voltados para a\navaliação da QVT sob a perspectiva da EAA. Considerando\nessas informações, assinale a alternativa que apresenta os\nfatores estruturantes das representações de bem-estar e de\nmal-estar no trabalho da EAA_QVT.", "alt": {"A": "condições do trabalho, organização do trabalho,\nrelações socioprofissionais do trabalho,\nreconhecimento e crescimento profissional e elo entre\ntrabalho e vida social", "B": "condições do trabalho, organização do trabalho,\nrelações socioeconômicas do trabalho,\nreconhecimento e crescimento profissional e elo entre\ntrabalho e vida social", "C": "condições pessoais, organização do trabalho, relações\nsocioprofissionais do trabalho, reconhecimento e\ncrescimento profissional e elo entre trabalho e\nprogressão salarial", "D": "condições pessoais, organização do trabalho, relações\nsocioprofissionais do trabalho, reconhecimento e\ncrescimento profissional e elo entre trabalho e vida\nsocial", "E": "condições do trabalho, organização do trabalho,\nrelações socioeconômicas do trabalho,\nreconhecimento e crescimento profissional e elo entre\ntrabalho e progressão salarial"}, "g": "A", "j": "Ferreira define cinco fatores estruturantes do EAA_QVT: condicoes do trabalho, organizacao do trabalho, relacoes socioprofissionais, reconhecimento e crescimento profissional e elo trabalho-vida social. Alternativa A reproduz integralmente."}, {"id": "1877732", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Para Marras, o treinamento corresponde a um processo de\nassimilação da cultura em curto prazo, que objetiva repassar\nou reciclar conhecimentos, habilidades ou atitudes\nrelacionados diretamente à execução de tarefas ou à sua\notimização no trabalho. Sendo assim, assinale a alternativa\nque apresenta um objetivo específico de T&D.", "alt": {"A": "aumento direto da produtividade", "B": "aumento direto da qualidade", "C": "especialização", "D": "otimização pessoal e organizacional", "E": "atendimento de exigências das mudanças"}, "g": "C", "j": "Segundo Marras, objetivos especificos de T&D incluem formacao profissional, especializacao e reciclagem. As demais alternativas (aumento direto da produtividade/qualidade, otimizacao e atendimento de mudancas) sao classificadas como objetivos genericos."}, {"id": "1877731", "d": "psicologia", "a": ["Qualidade de Vida", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta fator diretamente\nrelacionado com os resultados da promoção da saúde e da\nqualidade de vida no trabalho.", "alt": {"A": "aumento dos afastamentos", "B": "aumento do absenteísmo", "C": "aumento dos custos com a saúde", "D": "aumento da produtividade e da qualidade dos\nprodutos e serviços", "E": "incapacidade laboral"}, "g": "D", "j": "Resultados da promocao da saude e QVT incluem aumento da produtividade e da qualidade dos produtos e servicos. Alternativas A, B, C, E descrevem consequencias negativas, opostas ao esperado da QVT."}, {"id": "1877730", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "O Ministério da Saúde afirma que as condições de\ntrabalho (sejam elas físicas, químicas ou biológicas)\nvinculadas à execução do trabalho e à sua\norganização (estruturação, hierarquia, divisão de tarefa,\njornada, ritmo, trabalho em turno, intensidade, monotonia,\nrepetitividade e responsabilidade excessiva) favorecem o\naparecimento das doenças ocupacionais. Considerando essa\ninformação, é correto afirmar que o modelo adotado pela\nOrganização Mundial da Saúde, para um ambiente\ncorporativo saudável, abrange o(a)", "alt": {"A": "perspectiva externa, que inclui as relações fora do local\nde trabalho.", "B": "fator psicossocial, que inclui a organização do trabalho\ne a cultura organizacional.", "C": "gestão de desempenho do colaborador, que inclui o\nplano de desenvolvimento individual dos\ncolaboradores.", "D": "gestão de reconhecimento organizacional, que inclui\naumentos salariais e projeções de carreira.", "E": "aspecto motivacional da organização, que inclui as\nvariáveis de crescimento organizacional."}, "g": "B", "j": "O modelo OMS de ambiente de trabalho saudavel abrange ambiente fisico, ambiente psicossocial (organizacao do trabalho, cultura organizacional), recursos pessoais de saude e envolvimento com a comunidade. O fator psicossocial e justamente o descrito na alternativa B."}, {"id": "1877728", "d": "psicologia", "a": ["Recrutamento e Seleção", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "De acordo com Orlickas, a seleção tem o objetivo de\npesquisar, suprir e identificar profissionais qualificados que\ncolaborem para a superação do resultado, como o\naprimoramento e a realização pessoal. Sendo assim, é correto\nafirmar que está diretamente ligado(a) ao processo de\nrecrutamento e seleção o(a)", "alt": {"A": "avaliação de desempenho.", "B": "pesquisa de clima.", "C": "desenho de cargos.", "D": "plano de desenvolvimento individual.", "E": "plano de progressão."}, "g": "C", "j": "Segundo Orlickas, o desenho de cargos esta diretamente ligado a R&S, pois define o perfil de competencias e atribuicoes a serem buscadas no processo seletivo. Avaliacao de desempenho, pesquisa de clima, PDI e plano de progressao sao processos pos-contratacao."}, {"id": "1877727", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta a ferramenta utilizada\npara se entender o ambiente de trabalho e seus efeitos nos\ncolaboradores.", "alt": {"A": "pesquisa de clima organizacional", "B": "teste de personalidade", "C": "plano de cargos e salários", "D": "mapeamento de competências", "E": "avaliação de desempenho"}, "g": "A", "j": "Pesquisa de clima organizacional e a ferramenta usada para entender o ambiente de trabalho e seus efeitos nos colaboradores. As outras opcoes (teste de personalidade, plano de cargos, mapeamento, AD) sao instrumentos com finalidades distintas."}, {"id": "1877726", "d": "psicologia", "a": ["Liderança", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta os comportamentos\ncondizentes com a liderança transacional.", "alt": {"A": "estimulação intelectual e comportamentos idealizados", "B": "inspiração de motivação e consideração individual", "C": "recompensa contingente e foco de atenção em\nirregularidades, erros, exceções e desvios de padrões", "D": "intensificação do desejo das pessoas pelo sucesso e\natributos idealizados", "E": "ausência quando for necessária a demonstração de que\nos problemas tornar-se-ão crônicos antes que se tome\numa ação"}, "g": "C", "j": "Lideranca transacional (Bass) e caracterizada por recompensa contingente e gestao por excecao (atencao a erros, irregularidades, desvios de padrao). Alternativas A, B, D descrevem lideranca transformacional; E descreve laissez-faire."}, {"id": "1877725", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta a descrição correta da\navaliação de desempenho.", "alt": {"A": "É o desenvolvimento de um quadro de pessoal com as\ncompetências necessárias para satisfazer às\nnecessidades e aos objetivos da organização, de modo\na garantir o seu bom desempenho e o alcance dos\nresultados e das metas estabelecidos no planejamento\nestratégico.", "B": "É o sistema de adequação do perfil do quadro de\npessoal às necessidades da organização, em termos de\nconhecimentos, habilidades e atitudes que devem\nestar presentes para a realização das atividades típicas.", "C": "É um sistema formal de gerenciamento que provê a\nmensuração da qualidade da performance individual\ne(ou) institucional em uma organização e que pode\nvisar apenas ao indivíduo ou também às equipes, às\náreas e à organização.", "D": "É a definição das estratégias e ações para a viabilização\ndo suprimento das necessidades alinhadas aos\nobjetivos e às metas organizacionais, integradas ao\nplanejamento estratégico e vinculadas às\ndisponibilidades orçamentárias e às exigências legais.", "E": "É o sistema de adequação estratégica do mapeamento\nde competências, conhecimentos, habilidades e\natitudes ao alinhamento organizacional."}, "g": "C", "j": "Avaliacao de desempenho e um sistema formal de gerenciamento que mensura a qualidade da performance individual e/ou institucional. A descreve dimensionamento de pessoal, B gestao de competencias, D planejamento estrategico de RH, E mapeamento estrategico."}, {"id": "1877724", "d": "psicologia", "a": ["Gestão por Competências", "Gestão de Conhecimento em Psicologia", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Para a implementação da gestão estratégica de pessoas,\nnovas atividades, mecanismos e instrumentos deverão ser\nincluídos no escopo de ação e atuação da área. Para que haja\na efetiva percepção da real dimensão do que se denomina\ngestão estratégica de pessoas e do esforço a ser empreendido\npara a implantação dessas mudanças, é necessária a\nutilização dos seguintes mecanismos e instrumentos:", "alt": {"A": "gestão orçamentária; capacitação continuada com\nbase em competências; avaliação contábil de período;\ne planejamento de recursos humanos.", "B": "gestão de competências; capacitação continuada com\nbase em competências; avaliação de desempenho e de\ncompetências; e planejamento de recursos humanos.", "C": "gestão financeira da arquitetura de cargos; capacitação\ncontinuada com base em competências; avaliação de\ndesempenho e de competências; e planejamento\nestratégico organizacional.", "D": "gestão logística de recursos; capacitação continuada\ncom base em competências; avaliação de desempenho\ne de competências; e planejamento de recursos\nhumanos.", "E": "gestão de competências; capacitação continuada com\nbase em competências; avaliação de desempenho e de\ncompetências; e gestão orçamentária."}, "g": "B", "j": "Mecanismos da gestao estrategica de pessoas (PNDP - Decreto 5.707/2006 e literatura correlata): gestao de competencias, capacitacao continuada com base em competencias, avaliacao de desempenho e de competencias e planejamento de RH. Alternativa B reproduz exatamente."}, {"id": "1877723", "d": "psicologia", "a": ["Recrutamento e Seleção", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta técnicas de\nrecrutamento e seleção.", "alt": {"A": "testes psicométricos, análise curricular e plano de\ncargos e salários", "B": "técnicas de simulação, testes psicométricos e plano de\ndesenvolvimento individual", "C": "avaliação de desempenho, testes de personalidade e\nentrevista por competências", "D": "plano de cargos e salários, análise curricular e\nentrevista de seleção estruturada", "E": "testes psicométricos, entrevista de seleção não\nestruturadas e técnicas de simulação"}, "g": "E", "j": "Testes psicometricos, entrevistas (estruturadas ou nao) e tecnicas de simulacao sao tecnicas classicas de R&S. As demais alternativas incluem instrumentos pos-contratacao (plano de cargos e salarios, PDI, avaliacao de desempenho)."}, {"id": "1877720", "d": "psicologia", "a": ["Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Entre os processos e as políticas da gestão de pessoas,\ndiversas atividades estão envolvidas. Sendo assim, assinale a\nalternativa que apresenta a descrição correta da atividade a\nque se refere.", "alt": {"A": "análise e descrição dos cargos: desenho e\nenquadramento feitos pela equipe administrativa dos\ncolaboradores e seus respectivos cargos", "B": "desenvolvimento organizacional: aplicação de\ntreinamentos e atualizações constantes aos\nfuncionários, fazendo com que isso seja um diferencial\nperante a concorrência no mercado", "C": "comunicação aos funcionários: entrosamento e\nintegração dos novos trabalhadores da organização,\nacompanhamento que é bastante importante e poderá́\nser determinante para o futuro dos novos\ntrabalhadores e da própria organização", "D": "desenho de cargos: diante da estrutura da organização,\no pessoal é enquadrado; análise que é feita pela equipe\nde gestão da organização", "E": "avaliação do desempenho dos funcionários: avaliação\ndo cumprimento dos objetivos traçados e mensuração\nda capacidade produtiva dos funcionários, além da\nanálise da manutenção de funcionários ou da abertura\nde novos processos"}, "g": "E", "j": "Avaliacao de desempenho mensura o cumprimento de objetivos e a capacidade produtiva dos funcionarios. As demais descricoes estao trocadas: A confunde analise com desenho de cargos, B reduz DO a treinamento, C confunde comunicacao com integracao, D confunde desenho de cargos com alocacao."}, {"id": "1877719", "d": "psicologia", "a": ["Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "A gestão de pessoas é a área de uma empresa que se destina a", "alt": {"A": "realizar os pagamentos dos colaboradores e dar a\nmanutenção necessária aos processos burocráticos de\ncontratos.", "B": "cuidar das políticas e dos métodos que orientam o\ncomportamento humano e as relações interpessoais\nno ambiente de trabalho.", "C": "controlar e manter os processos e os projetos\nestratégicos relativos às áreas finalísticas do negócio.", "D": "realizar check-ups financeiros e operacionais ligados ao\nindivíduo e à organização.", "E": "adequar os indivíduos que nela trabalham ao modelo\nde trabalho e aos protocolos tecnológicos utilizados\npela organização."}, "g": "B", "j": "Gestao de pessoas cuida das politicas e metodos que orientam o comportamento humano e as relacoes interpessoais no trabalho. As outras alternativas descrevem departamento pessoal (A), nucleo de negocios (C), controladoria (D) e padronizacao tecnologica (E)."}, {"id": "1841922", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "À luz da Resolução n.º 36/2020 do Conselho Federal de Psicologia, que dispõe sobre a realização de atos processuais, audiências\ne julgamentos, por videoconferência, de processos disciplinares durante o período de pandemia por covid-19, com o uso de\ntecnologias de informação em caráter excepcional, no âmbito do Sistema Conselhos de Psicologia, assinale a alternativa incorreta.", "alt": {"A": "Os atos processuais e as diligências em geral poderão ser realizados por meio virtual, observando-se o disposto no Código\nde Processamento Disciplinar.", "B": "É dever do Conselho Federal de Psicologia fornecer aos conselheiros, às partes e a seus procuradores recursos tecnológicos\npara a transmissão de sons e imagens em tempo real, ativos durante toda a realização de audiência e sessão de julgamento\npor videoconferência.", "C": "A audiência por videoconferência deverá ser realizada via recurso tecnológico de transmissão de sons e imagens em tempo\nreal.", "D": "As gravações das audiências e das sessões deverão ser armazenadas em meio eletrônico, juntadas ao processo e\nacompanhadas das atas, dos termos, dos acórdãos e dos demais documentos escritos previstos no Código de\nProcessamento Disciplinar.", "E": "A sessão de julgamento por videoconferência deverá ser realizada via recurso tecnológico de transmissão de sons e imagens\nem tempo real, observando-se as disposições constantes nos artigos 106 a 117 do Código de Processamento Disciplinar."}, "g": "B", "j": "Resolucao CFP 36/2020 - questao pede alternativa INCORRETA. A norma estabelece que e dever do CFP fornecer recursos tecnologicos aos conselheiros, nao as partes e procuradores (que devem providenciar seus proprios meios). Alternativas A, C, D, E reproduzem corretamente a resolucao."}, {"id": "1841921", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2021", "org": "CRP", "t": "", "e": "Conforme a resolução do Conselho Federal de Psicologia que institui normas e procedimentos para a perícia psicológica no\ncontexto do trânsito, assinale a alternativa correta no que se refere à entrevista psicológica.", "alt": {"A": "A entrevista psicológica é uma conversação livre e sem um propósito definido da perícia, a fim de prover o psicólogo de\nsubsídios técnicos acerca da conduta, dos comportamentos, dos conceitos, dos valores e das opiniões do candidato.", "B": "Durante a entrevista, não é permitido ao psicólogo o registro das observações do comportamento, devido ao caráter\nsigiloso das informações ali obtidas.", "C": "O psicólogo deve planejar e sistematizar a entrevista a partir de indicadores objetivos de avaliação, correspondentes ao\nque pretende examinar.", "D": "Na perícia psicológica realizada no contexto do trânsito, a entrevista tem caráter individual e opcional.", "E": "Em caso de candidato com deficiência, a perícia psicológica não deve ser realizada, a fim de não discriminar o indivíduo por\nseus aspectos de funcionalidade."}, "g": "C", "j": "Resolucao CFP sobre pericia psicologica no transito (Res 002/2018) estabelece que a entrevista deve ser planejada e sistematizada a partir de indicadores objetivos. Demais alternativas contrariam o carater obrigatorio, planejado e sistematico da pericia."}, {"id": "1841920", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "De acordo com a resolução do Conselho Federal de Psicologia\nque regulamenta a prestação de serviços psicológicos\nrealizados por meio de tecnologias da informação, assinale a\nalternativa incorreta.", "alt": {"A": "São autorizadas consultas psicológicas de diferentes\ntipos apenas de maneira síncrona.", "B": "São autorizados os processos de seleção de pessoal no\nformato virtual.", "C": "Em quaisquer modalidades de atendimento\npsicológico, o psicólogo estará obrigado a especificar\nos recursos tecnológicos que serão utilizados para\ngarantir o sigilo das informações e a esclarecer o cliente\nsobre isso.", "D": "É autorizada a supervisão técnica dos serviços\nprestados por psicólogos, nos mais diversos contextos\nde atuação, de maneira remota (virtual).", "E": "É autorizada a utilização de instrumentos psicológicos\ndevidamente regulamentados por resolução\npermanente, sendo que os testes psicológicos devem\nter parecer favorável do Sistema de Avaliação de\nInstrumentos Psicológicos (SATEPSI), com\npadronização e normalização específica para essa\nfinalidade."}, "g": "A", "j": "Questao pede INCORRETA. Res CFP 011/2018 (TIC) autoriza atendimentos sincronos E assincronos em situacoes especificas. Afirmar 'apenas de maneira sincrona' contraria a norma. Alternativas B-E reproduzem disposicoes corretas da resolucao."}, {"id": "1841918", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "Segundo a Resolução n.º 18/2002 do Conselho Federal de\nPsicologia, que estabelece normas de atuação para os\npsicólogos, em relação ao preconceito e à discriminação\nracial, assinale a alternativa incorreta.", "alt": {"A": "Os psicólogos atuarão segundo os princípios éticos da\nprofissão, contribuindo com o seu conhecimento para\numa reflexão sobre o preconceito e para a eliminação\ndo racismo.", "B": "Os psicólogos, no exercício profissional, serão\nconiventes ou se omitirão perante o crime de racismo.", "C": "Os psicólogos não exercerão qualquer ação que\nfavoreça a discriminação ou o preconceito de raça ou\netnia.", "D": "Os psicólogos não se utilizarão de instrumentos ou\ntécnicas psicológicas para criar, manter ou reforçar\npreconceitos, estigmas, estereótipos ou discriminação\nracial.", "E": "Os psicólogos não se pronunciarão nem participarão de\npronunciamentos públicos nos meios de comunicação\nde massa para reforçar o preconceito racial."}, "g": "B", "j": "Questao pede INCORRETA. Res CFP 18/2002 proibe expressamente a conivencia e a omissao do psicologo diante de crime de racismo. Demais alternativas reproduzem as normas de atuacao etica contra racismo previstas na resolucao."}, {"id": "1841917", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "As provas poderão ser documentais, testemunhais e técnicas,\nentendendo-se por provas documentais quaisquer escritos,\ninstrumentos e representações gráficas. À luz do art. 38 da\nResolução n.º 7/2016 do Conselho Federal de Psicologia,\nassinale a alternativa correta.", "alt": {"A": "Não poderá constituir prova de qualquer natureza a\ninformação produzida no curso do procedimento de\nmediação.", "B": "As provas documentais e técnicas serão apresentadas\npelo psicólogo processado, junto com o denunciante.\nAs provas testemunhais só poderão ser apresentadas\ncaso requeridas.", "C": "Na análise do processo disciplinar, o presidente do\nConselho, sempre que julgar necessário, poderá\nsolicitar diligência com o objetivo de obter mais\nelementos de prova.", "D": "Em caso de procedimento instaurado de ofício, não se\nfaz necessário o acompanhamento da representação\ncom as provas documentais.", "E": "O rol de testemunhas, as provas documentais e a\npretensão de realização de prova técnica deverão ser\napresentadas, pelo representante, por meio de\nprocedimento instaurado de ofício."}, "g": "A", "j": "Art. 38 da Res CFP 7/2016 (Codigo de Processamento Disciplinar) preserva o sigilo das informacoes produzidas em mediacao, vedando seu uso como prova. As demais alternativas distorcem regras processuais (apresentacao de provas, ofereta de oficio, diligencias)."}, {"id": "1841916", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "Segundo a resolução do Conselho Federal de Psicologia que\ninstitui normas e procedimentos para a perícia psicológica no\ncontexto do trânsito, assinale a alternativa incorreta.", "alt": {"A": "Deve-se avaliar, quanto ao juízo crítico e ao\ncomportamento do candidato, a impulsividade\nadequada.", "B": "Deve-se avaliar, quanto ao juízo crítico e ao\ncomportamento do candidato, a ansiedade adequada.", "C": "Deve-se avaliar, quanto ao juízo crítico e ao\ncomportamento do candidato, a agressividade\nadequada.", "D": "Deve-se avaliar, quanto ao juízo crítico e ao\ncomportamento do candidato, a reação adequada às\nsituações no trânsito.", "E": "Deve-se avaliar, quanto ao juízo crítico e ao\ncomportamento do candidato, a atenção concentrada."}, "g": "E", "j": "Questao pede INCORRETA. Na pericia psicologica do transito, juizo critico e comportamento envolvem impulsividade, ansiedade, agressividade e reacao adequada. Atencao concentrada e habilidade cognitiva mensurada por teste especifico, fora do escopo de 'juizo critico e comportamento'."}, {"id": "1841914", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "Com base no art. 2 da Resolução n.º 10/1997 do Conselho\nFederal de Psicologia, assinale a alternativa incorreta.", "alt": {"A": "As técnicas e práticas ainda não reconhecidas pela\npsicologia poderão ser utilizadas no exercício\nprofissional, enquanto recursos complementares,\ndesde que estejam em processo de pesquisa, conforme\nos critérios dispostos na Resolução n.º 196/1996, do\nConselho Nacional de Saúde do Ministério da Saúde.", "B": "As técnicas e práticas ainda não reconhecidas pela\npsicologia poderão ser utilizadas no exercício\nprofissional, enquanto recursos complementares,\ndesde que o cliente declare expressamente ter\nconhecimento do caráter experimental da técnica e da\nprática utilizadas.", "C": "As técnicas e práticas ainda não reconhecidas pela\npsicologia poderão ser utilizadas no exercício\nprofissional, enquanto recursos complementares,\ndesde que o profissional possa comprovar junto ao\nConselho Regional de Psicologia a habilitação\nadequada para desenvolver aquela técnica.", "D": "As técnicas e práticas ainda não reconhecidas pela\npsicologia poderão ser utilizadas no exercício\nprofissional, enquanto recursos complementares,\ndesde que respeitem os princípios éticos fundamentais\ndo Código de Ética Profissional do Psicólogo.", "E": "As técnicas e práticas ainda não reconhecidas pela\npsicologia poderão ser utilizadas no exercício\nprofissional, enquanto recursos complementares,\ndesde que ocorra um registro prévio da técnica\nutilizada no Conselho Regional de Psicologia e seja\nemitida uma autorização preliminar."}, "g": "E", "j": "Questao pede INCORRETA. Art. 2 da Res CFP 10/1997 nao exige registro previo de tecnica nem autorizacao preliminar pelo CRP. Os requisitos sao pesquisa conforme Res 196/96 CNS, consentimento informado do cliente, habilitacao do profissional e respeito ao CEP - todos presentes em A, B, C, D."}, {"id": "1841913", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "De acordo com a Resolução n.º 10/1997 do Conselho Federal\nde Psicologia, é permitido ao psicólogo, no exercício\nprofissional, na divulgação e na publicidade, por meio dos\ncanais de comunicação, vincular ou associar ao título de\npsicólogo e(ou) ao exercício profissional", "alt": {"A": "qualquer técnica psicológica conhecida em âmbito\nnacional e conferida pelo Conselho Federal de\nPsicologia.", "B": "as práticas psicológicas já reconhecidas como próprias\ndo profissional psicólogo ou de linhas alternativas, que\nestejam de acordo com os critérios científicos\nestabelecidos no campo da psicologia.", "C": "somente técnicas já reconhecidas pelo Conselho\nFederal de Psicologia e que estejam de acordo com os\ncritérios burocráticos estabelecidos no campo de\natuação da psicologia.", "D": "somente técnicas ou práticas psicológicas já\nreconhecidas como próprias do profissional psicólogo\ne que estejam de acordo com os critérios científicos\nestabelecidos no campo da psicologia.", "E": "somente as técnicas psicológicas já reconhecidas como\npróprias do profissional psicólogo."}, "g": "D", "j": "Res CFP 10/1997 autoriza vinculacao publicitaria apenas a tecnicas/praticas reconhecidas como proprias do psicologo e em conformidade com criterios cientificos da psicologia. Alternativa D reproduz literalmente a regra; demais alternativas ampliam ou reduzem indevidamente o escopo."}, {"id": "1837098", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Com fundamento na Resolução n.° 3/2007 do Conselho\nFederal de Psicologia, assinale a alternativa que\ncorretamente complementa a seguinte afirmação: o número\nde membros efetivos dos Conselhos Regionais de Psicologia\nleva em conta o(a)", "alt": {"A": "arrecadação média prevista no orçamento do ano\nanterior ao da eleição.", "B": "número geral de inscritos previsto no orçamento do\nano da eleição.", "C": "número de formandos em psicologia no ano anterior\nao da eleição.", "D": "número de inscritos, ativos e adimplentes, previsto no\norçamento do ano anterior ao da eleição.", "E": "número de inscritos, ativos, previsto no orçamento do\nano das eleições."}, "g": "E", "j": "Res CFP 3/2007 estabelece que o numero de membros efetivos dos CRPs e definido pelo numero de inscritos ativos previsto no orcamento do ano das eleicoes. Demais alternativas misturam arrecadacao, formandos ou inadimplencia, fora do criterio normativo."}, {"id": "1837097", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "À luz da Resolução n.° 3/2007 do Conselho Federal de\nPsicologia, assinale a alternativa correta.", "alt": {"A": "Método é o conhecimento aplicado, e não o produzido.", "B": "A técnica é uma atividade específica e prescinde de\nmétodo.", "C": "Orientação profissional é o diagnóstico e o prognóstico\ndas condições de ajustamento e desempenho da\npessoa a um cargo ou a uma atividade.", "D": "A solução de problemas de ajustamento é um processo\nque propicia condições de autorrealização, convivência\ne desempenho.", "E": "A seleção profissional é o diagnóstico e o prognóstico\nsobre interesses, aptidões e características de\npersonalidade."}, "g": "D", "j": "Res CFP 3/2007 define solucao de problemas de ajustamento como processo que propicia condicoes de autorrealizacao, convivencia e desempenho. As demais alternativas trocam definicoes (orientacao x selecao) ou negam vinculo entre tecnica e metodo."}, {"id": "1837096", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Com base na Lei n.° 5.766/1971, assinale a alternativa correta\nno que se refere à gestão financeira do Conselho Federal e\ndos Conselhos Regionais de Psicologia.", "alt": {"A": "É vedado o recebimento de doações.", "B": "Dotações orçamentárias somente poderão advir do\nPoder Público Federal.", "C": "A aquisição ou a alienação de bens de interesse de um\nConselho Regional dependerá da aprovação prévia da\nrespectiva assembleia geral.", "D": "A aquisição de bens é livre, mas a alienação deverá\nconstar previamente do orçamento anual.", "E": "A aprovação do orçamento anual do Conselho Federal\ndependerá de maioria simples."}, "g": "C", "j": "Lei 5.766/1971 exige que aquisicao ou alienacao de bens de interesse de CRP dependa de aprovacao previa da assembleia geral. Doacoes nao sao vedadas, dotacoes podem vir de varias fontes, alienacao nao e livre e orcamento exige maioria absoluta - todas erradas."}, {"id": "1837095", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Considerando a Resolução n.° 3/2007 do Conselho Federal de\nPsicologia, assinale a alternativa correta.", "alt": {"A": "Os valores das anuidades são fixados em\nsalários-mínimos.", "B": "Não se admitem descontos nos valores das anuidades.", "C": "É admissível o parcelamento em mais de três vezes das\nanuidades em geral.", "D": "Valores de anuidades em atraso acumulados não\npoderão ser parcelados.", "E": "O Conselho Regional de Psicologia no qual o\nprofissional esteja inscrito será o responsável por\nefetivar a cobrança de débitos."}, "g": "E", "j": "Res CFP 3/2007 atribui ao CRP em que o profissional esta inscrito a responsabilidade pela cobranca de debitos (principio territorial). Anuidades nao sao fixadas em salarios minimos, admitem descontos e parcelamentos, e atrasados podem ser parcelados."}, {"id": "1837092", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Segundo a Lei n.o\n 5.766/1971, assinale a alternativa que\napresenta o requisito necessário para a inscrição de\ncandidato no Conselho Regional de Psicologia de sua área de\natuação.", "alt": {"A": "gozar de boa reputação", "B": "possuir diploma de psicólogo, com seis meses de\natuação prática, residente e supervisionada", "C": "ter cidadania brasileira", "D": "apresentar certidão negativa de processos criminais", "E": "apresentar certidão negativa ou positiva com efeitos\nde negativa perante a Receita Federal"}, "g": "A", "j": "Lei 5.766/1971 art. 17 exige, entre outros requisitos para inscricao no CRP, que o candidato goze de boa reputacao. Pratica supervisionada, cidadania brasileira nata, certidoes criminais ou da Receita nao sao exigidos pela lei."}, {"id": "1837091", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Com base no Decreto n.° 53.464/1964, assinale a alternativa\ncorreta no que diz respeito ao funcionamento e ao\nreconhecimento legal dos cursos de psicologia.", "alt": {"A": "As faculdades que mantinham curso de psicologia\nanteriormente à edição do Decreto n.° 53.464/1964\ntiveram seu reconhecimento automático.", "B": "As faculdades que solicitarem autorização para o\nfuncionamento de um dos cursos de psicologia deverão\napresentar corpo docente devidamente habilitado nas\ndisciplinas do primeiro semestre do curso.", "C": "Os serviços clínicos exigidos das faculdades que\nrequeiram autorização para funcionamento do curso\nde psicologia deverão ser necessariamente abertos ao\npúblico e gratuitos.", "D": "É admissível a prestação indireta, por convênio, do\nserviço clínico por faculdade que pretenda abrir curso\nde psicologia.", "E": "O currículo e a duração mínima dos cursos de\npsicologia são fixados por ato do Conselho Federal de\nPsicologia."}, "g": "D", "j": "Decreto 53.464/1964 admite a prestacao indireta, por convenio, do servico clinico exigido das faculdades que pretendam abrir curso de psicologia. As demais alternativas distorcem regras de reconhecimento, corpo docente, gratuidade e fixacao curricular (que cabe ao CFE, nao ao CFP)."}, {"id": "1837009", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP", "t": "", "e": "É(são) competência(s) da assembleia geral dos Conselhos\nRegionais de Psicologia", "alt": {"A": "adquirir e alienar bens.", "B": "aprovar cobrança de inscrito inadimplente.", "C": "convocar candidatos aprovados em concurso público.", "D": "destituir um de seus membros.", "E": "aprovar a criação de novo curso universitário na área\nde psicologia."}, "g": "A", "j": "Lei 5.766/1971 atribui a assembleia geral do CRP a competencia para deliberar sobre aquisicao e alienacao de bens. Cobranca de inadimplentes, concursos, destituicao de membros e criacao de cursos universitarios nao sao competencias da assembleia."}, {"id": "1837006", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP", "t": "", "e": "De acordo com a Lei n.° 5.766/1971, assinale a alternativa\ncorreta quanto aos membros dos Conselhos Regionais de\nPsicologia.", "alt": {"A": "Devem ser brasileiros natos.", "B": "Devem possuir idade mínima de trinta anos.", "C": "Têm seu presidente e vice-presidente eleitos por\nvotação do conselho regional, ou seja, indireta.", "D": "São eleitos, em votação pública e ostensiva, pelos\nprofissionais inscritos na respectiva unidade territorial.", "E": "Têm mandato de três anos, podendo reeleger-se\nindefinidamente."}, "g": "C", "j": "Lei 5.766/1971 estabelece que presidente e vice-presidente dos CRPs sao eleitos indiretamente, por votacao dos conselheiros eleitos. Brasileiros natos, idade minima de 30 anos, votacao publica e mandato de 3 anos reelegivel indefinidamente nao constam da lei."}, {"id": "1837005", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP", "t": "", "e": "Com base na Resolução n.° 3/2007 do Conselho Federal de\nPsicologia, assinale a alternativa correta.", "alt": {"A": "É requisito para cadastramento de pessoa jurídica a\nnão inscrição em dívida ativa.", "B": "Da negativa de pedido de cadastramento deduzido por\npessoa jurídica caberá pedido de reconsideração e,\neventualmente, recurso.", "C": "Somente poderão cadastrar-se no Conselho Regional\nde Psicologia pessoas jurídicas que possuam a\npsicologia como atividade principal de competência.", "D": "As pessoas jurídicas cadastradas junto aos conselhos\nregionais devem pagar anuidades, taxas e\nemolumentos.", "E": "O pedido de cadastro de pessoa jurídica deve ser\ndirigido ao Conselho Federal de Psicologia, a quem\ncompetirá avaliar o preenchimento dos requisitos."}, "g": "B", "j": "Res CFP 3/2007 preve que da negativa de cadastramento de PJ cabem pedido de reconsideracao e, eventualmente, recurso. Nao se exige psicologia como atividade principal, nem ha pagamento de anuidades por PJ, nem competencia do CFP para o pedido inicial."}, {"id": "1837004", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2021", "org": "CRP", "t": "", "e": "À luz da Resolução n.° 3/2007 do Conselho Federal de\nPsicologia, é elemento a ser levado em consideração para a\ncriação de novos conselhos regionais o(a)", "alt": {"A": "potencial de arrecadação de novas anuidades.", "B": "baixo número de profissionais.", "C": "evidência de que psicólogos residentes na zona de\njurisdição a ser criada possuem interesse em sua\ncriação.", "D": "falha profissional que inspire uma fiscalização mais\npróxima e apurada.", "E": "inadimplência que justifique um controle orçamentário\nmais rígido e cobranças mais céleres."}, "g": "C", "j": "Res CFP 3/2007 estabelece como elemento para criacao de novos CRPs a evidencia de interesse dos psicologos residentes na zona de jurisdicao a ser criada. Arrecadacao, baixo numero de profissionais, falhas ou inadimplencia nao sao criterios."}, {"id": "1837000", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2021", "org": "CRP", "t": "", "e": "Com fundamento na Lei n.° 4.119/1962, assinale a alternativa\ncorreta.", "alt": {"A": "O portador de diploma de licenciado em psicologia tem\no direito de exercer a profissão de psicólogo.", "B": "O portador de diploma de bacharel em psicologia tem\no direito de ensinar em cursos de grau médio.", "C": "Constitui função privativa do psicólogo a utilização de\nmétodos psicológicos.", "D": "Constituem funções privativas do psicólogo a seleção\nde pessoal e o recrutamento.", "E": "Constitui função privativa do psicólogo colaborar em\nassuntos psicológicos ligados a outras ciências."}, "g": "B", "j": "Lei 4.119/1962 art. 11, paragrafo unico, permite ao bacharel em psicologia ensinar psicologia em cursos de grau medio. As demais alternativas extrapolam ou restringem indevidamente as funcoes privativas do psicologo definidas na lei."}, {"id": "1299808", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "O psicodiagnóstico é um procedimento científico, limitado\nno tempo, que utiliza técnicas e testes psicológicos para\nidentificar e avaliar aspectos específicos da personalidade\ne(ou) comportamentais ou para classificar o caso e prever\nseu curso possível. Abrange aspectos do passado, do\npresente e do futuro e inclui os aspectos sadios e os\npatológicos. Com relação a esse assunto, assinale a\nalternativa incorreta.", "alt": {"A": "O diagnóstico psicológico é a conclusão obtida somente\npor meio dos resultados da aplicação de testes\npsicológicos. Na prática clínica, o diagnóstico psicológico\nou a conclusão diagnóstica ou a hipótese diagnóstica\npode ser expressa nos seguintes termos: descritivo;\ncompreensivo/dinâmico; e nosológico-classificatório.", "B": "Diagnosticar não é rotular, mas pode ser nomear. O\npsicodiagnóstico é o processo de compreender e\ndescrever um conhecimento (diagnóstico) sobre um\nsujeito, por meio da operacionalização de recursos\ntécnicos de investigação psicológica.", "C": "O psicodiagnóstico é um processo científico porque parte\nda coleta de dados, por meio de técnicas próprias e de um\nlevantamento prévio de hipóteses, que serão confirmadas\nou afirmadas por passos pré-determinados e com\nobjetivos precisos. Os objetivos do psicodiagnóstico\npodem ser de: descrição; classificação nosológica;\ndiagnóstico diferencial; avaliação compreensiva; e\nentendimento dinâmico e(ou) prognóstico.", "D": "O diagnóstico psicológico caracteriza-se por ser uma\ndescrição e, como tal, seleciona, prioriza e recorta\naspectos do objeto. O diagnóstico é sempre parcial e\nnão abrange o objeto total nem o que tem de\nessencial. Ele não é o diagnóstico do homem, mas a\nexplicação de um ponto de vista sobre ele.", "E": "Diagnosticar não é uma opção, mas uma condição do\nconhecimento. É verdade parcial, e não absoluta. O\ncaminho que se vislumbra, para o psicólogo, é o de\ndiscernir entre suas duas funções, no campo científico e\nno campo que se costuma chamar de relação com o\ncliente. Nessa medida, há, sim, que se viabilizar o\ndiagnóstico como uma estratégia de início de intervenção."}, "g": "A", "j": "Questao pede INCORRETA. Psicodiagnostico nao se obtem 'somente por meio de testes psicologicos' - envolve entrevistas, observacoes, anamnese e outros instrumentos alem dos testes. As demais alternativas (B-E) reproduzem definicoes consagradas de Cunha sobre psicodiagnostico."}, {"id": "1299807", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Dalgalarrondo afirma que, quando, no exame psíquico, se\nobserva o fenômeno de uma ideia se seguir à outra, de\nforma extremamente rápida, perturbando-se as\nassociações lógicas entre os juízos e os conceitos, as\nassociações entre as palavras deixam de seguir uma lógica\nou finalidade, passando a ocorrer por assonância (por\nexemplo, amor, flor, cor, ou cidade, idade, realidade etc.), e\nas ideias se associam muito mais pela presença de\nestímulos externos contingentes. Nesse caso, o fenômeno\n(sintoma) e a função psíquica que está alterada são,\nrespectivamente, o(a)", "alt": {"A": "delírio e uma alteração no juízo de realidade.", "B": "aceleração e uma alteração no curso do pensamento.", "C": "fuga de ideias e uma alteração na forma ou na\nestrutura do pensamento.", "D": "desagregação e uma alteração na forma ou na\nestrutura do pensamento.", "E": "dissociação e uma alteração no curso do pensamento."}, "g": "C", "j": "Dalgalarrondo - fuga de ideias e caracterizada por associacoes rapidas por assonancia, ritmo ou contiguidade externa, com perda de finalidade logica. Trata-se de alteracao na FORMA/estrutura do pensamento (nao no curso, no juizo nem dissociacao)."}, {"id": "1299804", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2020", "org": "CFP", "t": "", "e": "No exame das funções psíquicas, segundo Dalgalarrondo, as\nalterações qualitativas da sensopercepção são as mais\nimportantes em psicopatologia. Sendo assim, assinale a\nalternativa que apresenta o nome que se dá ao fenômeno\nque se caracteriza pela percepção deformada, alterada, de\num objeto real e presente.", "alt": {"A": "ilusão.", "B": "alucinação.", "C": "hipertensia.", "D": "confabulação.", "E": "pseudoalucinação."}, "g": "A", "j": "Dalgalarrondo - ilusao e a percepcao deformada de objeto real e presente. Alucinacao ocorre sem objeto real, pseudoalucinacao no espaco subjetivo, confabulacao e da memoria e hipertensia (hiperestesia) e quantitativa."}, {"id": "1299803", "d": "psicologia", "a": ["Psicanálise", "Psicopatologia", "Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Exames Mentais e Funções Psíquicas", "Semiologia Psiquiátrica e Critérios de Normalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Dalgalarrondo, embora muitos autores utilizem os\ntermos ansiedade e angústia como sinônimos, cabe\nressaltar algumas diferenças. Tem-se definido, em algumas\ncorrentes teóricas, certos tipos de angústia e de ansiedade.\nConsiderando essas informações, assinale a alternativa\nincorreta.", "alt": {"A": "Nas escolas comportamentalistas e cognitivistas,\nansiedade de desempenho é a reação de ansiedade\nassociada a temores em relação à execução de uma\ntarefa ou à possibilidade de ser avaliado criticamente\npor pessoas importantes ou significativas.", "B": "No existencialismo de Sartre, angústia existencial não\nseria apenas um sintoma patológico, mas, antes de\ntudo, um estado anímico básico, constituinte do ser\nhumano. O homem se angustia diante de algumas\nsituações existenciais inescapáveis da vida, pois a\nangústia existencial se articula com o fato de o homem\nestar condenado a ser livre, em oposição aos\ndeterminismos históricos e sociais.", "C": "Na Escola kleiniana, ansiedade depressiva é o tipo de\nansiedade vivido como temor de retaliação feroz aos\nataques imaginários e fantasmáticos que o sujeito, em\nsua fantasia, perpetrou contra seus objetos internos ou\nexternos.", "D": "De acordo com Freud, angústia de castração, em sensu\nstrictu, seria o medo de perder ou ferir os genitais, de\nser castrado, no contexto do complexo de Édipo. Tal\nconceito foi ampliado posteriormente, recebendo o\nsentido de uma angústia de perda, ou de risco de\nperda, de algo importante, do ponto de vista narcísico,\npara o indivíduo.", "E": "Spitz e Bowlby afirmam que a angústia de separação\nconsiste nas reações emocionais vividas pela criança\nquando separada da mãe, manifestando seus afetos\ncom choro, desespero e grande aflição."}, "g": "C", "j": "Questao pede INCORRETA. Na escola kleiniana, ansiedade depressiva e o temor de ter destruido o objeto amado (culpa/reparacao), enquanto a descricao de retaliacao por ataques fantasmaticos corresponde a ansiedade PERSECUTORIA. As demais definicoes (Sartre, Freud, Spitz/Bowlby, comportamentalismo) estao corretas."}, {"id": "1299801", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Sartre, o homem é livre porque não é ele mesmo,\nmas a presença de si. O ser que é o que é não poderia ser livre.\nA liberdade é precisamente o nada, que é tendo sido no\nâmago do homem e obriga a realidade humana a fazer-se em\nvez de ser. Para a realidade humana, ser é escolher-se. Com\nbase nessas informações, julgue os itens seguintes.     I. A liberdade sartreana em nada equivale à vontade, pelo\ncontrário; segundo o autor, a vontade não é senão uma\nanunciadora do que a liberdade já escolheu: “Quando\ndelibero, os dados já́estão lançados. Quando a vontade\nintervém, a decisão já está tomada, e a vontade não tem\noutro valor senão o de anunciadora”.\nII. A escolha fundamental da liberdade sartreana é posterior\nà reflexão, é irrefletida e espontânea, constitutiva dos\npróprios caminhos da reflexão. Indica uma principialidade\ne uma autonomia do irrefletido em Sartre.\nIII. Escolhe-se simplesmente porque se é liberdade, esta é\numa condição ontológica de ser, que significa a\ndeterminação por uma natureza substancial. Tal condição\nde natureza determinante indica, por si só, que cada traço\ndo existir é uma escolha.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e II estão certos."}, "g": "B", "j": "Apenas o item I esta correto: para Sartre, a vontade e apenas anunciadora do que a liberdade ja escolheu. Item II inverte (a escolha fundamental e ANTERIOR a reflexao, nao posterior); item III contradiz Sartre ao afirmar 'natureza substancial determinante' (Sartre nega essencia humana)."}, {"id": "1299800", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Psicologia Institucional"], "ano": "2020", "org": "CFP", "t": "", "e": "A atitude do psicólogo, empática e continente das angústias\ndo paciente/cliente ou usuário, em uma disposição para a\nescuta e para estabelecer um verdadeiro vínculo, deve\nincluir o paciente no processo, compartilhando o trabalho\ncompreensivo em curso. Segundo Bleger, assinale a\nalternativa incorreta.", "alt": {"A": "A chave fundamental da entrevista está na\ninvestigação que se realiza durante seu transcurso.\nUma forma de se observar bem é ir formulando\nhipóteses enquanto observa e, durante a entrevista,\nverificar e retificar as hipóteses no momento em que\nocorrem, em função das observações subsequentes,\nque, por sua vez, se enriquecem com as hipóteses\nprévias.", "B": "Observar, pensar e imaginar coincidem totalmente e\nformam parte de um só e único processo dialético.\nQuem não utiliza sua fantasia poderá ser um bom\nverificador de dados, porém nunca um investigador.", "C": "A entrevista diagnóstica é sempre e, ao mesmo tempo,\ne, em parte, terapêutica. O primeiro fator terapêutico\né sempre a compreensão do entrevistador, que deverá\ncomunicar alguns elementos dessa compreensão que\npossam ser úteis ao entrevistado. Nesse sentido,\nBleger enfatiza a qualidade da relação entre psicólogo\ne cliente como fator que intervém no efeito\nterapêutico.", "D": "O entrevistado controla a entrevista, porém quem a\ndirige é o entrevistador. A relação entre ambos\ndelimita e determina o campo da entrevista e tudo o\nque nela acontece, contudo o entrevistado deve\npermitir que o campo da relação interpessoal seja\npredominantemente estabelecido e configurado pelo\nentrevistador.", "E": "Tempo, lugar e papel do profissional são fatores do\nenquadramento da entrevista. O papel técnico do\npsicólogo implica que ele nunca deverá ser como um\namigo em um encontro fortuito nem pretender outro\nbenefício da entrevista que não sejam os seus\nhonorários e(ou) interesses científicos e(ou)\nprofissionais."}, "g": "D", "j": "Questao pede INCORRETA. Em Bleger, o entrevistador CONTROLA a entrevista e o entrevistado a DIRIGE (no sentido de configurar o campo com seu material). A alternativa D inverte os papeis. Demais alternativas reproduzem corretamente Bleger sobre hipoteses, fantasia, dimensao terapeutica e enquadramento."}, {"id": "1299799", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Cordioli, as principais técnicas utilizadas na\nterapia cognitiva focada em esquemas são assim\nclassificadas: técnicas cognitivas; técnicas\ncomportamentais; técnicas interpessoais; e técnicas\nexperienciais. A respeito desse tema, julgue os itens\nsubsequentes. I. Diálogo de esquemas é uma técnica experiencial; o\npaciente deve representar (encenar) dois papéis: o de\nesquema disfuncional e o de esquema adaptativo. Sua\ntarefa é a de promover uma discussão entre essas duas\npartes, argumentando como se fosse cada uma delas.   II. Revisão da vida é uma técnica interpessoal e busca\nevidências na história de vida do paciente que\nrealmente corroboram os esquemas. O paciente inicia\no processo de distanciamento do esquema e pode\nidentificar-se com ele.   III. Uma técnica cognitiva é desenvolver cartões que\ncontradizem os esquemas. O paciente é encorajado a\nlevá-los consigo e a lê-los com frequência,\nprincipalmente quando há a ativação dos esquemas. Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Cordioli - dialogo de esquemas e tecnica experiencial (item I correto); cartoes que contradizem esquemas e tecnica cognitiva (item III correto). Revisao da vida e tecnica COGNITIVA e nao interpessoal, tornando o item II incorreto. Apenas I e III certos."}, {"id": "1299798", "d": "psicologia", "a": ["Abordagem Centrada na Pessoa", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Rogers postulava a existência, no “organismo”, de certas\ntendências e linhas de força e de certas necessidades:\nComo o pleno desenvolvimento dessas tendências é função\nde condições bem determinadas, nossa teoria implica a\nnoção de um ótimo na atualização do ser humano. Esse\nótimo pode ser definido como o objetivo da avaliação\nsocial, como o resultado final (ideal) da psicoterapia. A\npessoa hipotética que se atualizasse plenamente\nfuncionaria, portanto, de um modo ótimo. Quanto à “teoria\ndo funcionamento ótimo” de Rogers, assinale a alternativa\nincorreta.", "alt": {"A": "O indivíduo tem a capacidade de representar a si\nmesmo, isto é, de simbolizar sua experiência na\nconsciência. Esse segmento simbolizado corresponde à\nconsciência de existir e de agir – a experiência do eu.", "B": "A consciência de existir cresce e se organiza\ngradativamente para formar a noção do eu, que,\nenquanto objeto da percepção, faz parte do campo da\nexperiência total.", "C": "Todo indivíduo possui uma tendência inerente de\natualizar as potencialidades de seu organismo – “a\ntendência à atualização”.", "D": "O indivíduo sente uma necessidade de consideração\npositiva. Ele também sente uma necessidade de\nconsideração positiva de si, ou seja, o reconhecimento\npositivo e assertivo do outro sobre si mesmo.", "E": "As manifestações das tendências à atualização e de\nsimbolização da experiência na consciência expressamse na medida em que o indivíduo sente a consideração\nincondicional de pessoas e desenvolve uma\nconsideração positiva de si."}, "g": "D", "j": "Questao pede INCORRETA. Em Rogers, 'consideracao positiva de si' e a estima/aceitacao interna que o individuo desenvolve em relacao a si mesmo, distinta da 'consideracao positiva do outro'. A alternativa D confunde os dois conceitos."}, {"id": "1299795", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Braier, o trabalho terapêutico em psicoterapia\nbreve (PB) está “focado” em uma determinada\nproblemática do paciente, por isso a PB também é chamada\nde focal, o que permite distingui-la da técnica psicanalítica\ncorrente, a qual não opera com um módulo conceitual de\nfoco. No que concerne à técnica na PB, assinale a\nalternativa incorreta.", "alt": {"A": "A situação-problema pode ser provocada por\nocorrências como um exame, uma viagem, uma\nintervenção cirúrgica próxima, a perda de um ser\nquerido, um acidente, uma crise evolutiva como a da\nadolescência, uma gravidez, o nascimento de um filho,\numa mudança de trabalho etc. Implica, então,\nreferência a fatos que são manifestos e objetiváveis.\nCom relação a eles, e como consequência de uma falta\nde resolução favorável, aparecem no sujeito inibições e\nsintomas diversos (ansiedade, medo, depressão,\ndistúrbios corporais), que costumam constituir o\nmotivo (manifesto) da consulta.", "B": "O foco deve ser concebido, primordial e\nessencialmente, a partir de uma perspectiva\npsicopatológica. Nesse sentido, será definido como\numa estrutura integrada pelos distintos fatores\nintervenientes na gênese da que foi escolhida como a\nproblemática central do tratamento, constituindo, ao\nmesmo tempo, uma hipótese do terapeuta a respeito\ndos mecanismos operantes dentro de tal problemática,\nou seja, da complexa interação existente entre os\nfatores.", "C": "O ponto de urgência corresponde à situação psíquica\ninconsciente de conflito que, pela ação de fatores\natuais, predomina no sujeito em um dado momento,\nsendo motivo de determinadas ansiedades e defesas. A\ndetecção do ponto de urgência conduz, como a própria\ndenominação sugere, ao trabalho terapêutico\nimediato; daí seu valor clínico.", "D": "A focalização é um esboço reconstrutivo da história\ndinâmica do paciente, uma tentativa de compreensão\nglobal de sua psicopatologia, que tende a incluir todas\nas perturbações do paciente que sejam conhecidas e\nque, a partir dos dados, aflorem nas primeiras\nentrevistas e no psicodiagnóstico.", "E": "Uma hipótese psicodinâmica inicial por parte do\nterapeuta ou da equipe terapêutica permitirá: extrair\nelementos suficientes para uma devolução diagnóstica\nao paciente, que, por sua vez, acionará a busca de\nacordo com as metas terapêuticas; e desenvolver um\nplano de tratamento coerente com a hipótese\nformulada e com os objetivos selecionados."}, "g": "D", "j": "Questao pede INCORRETA. Em Braier, focalizacao na PB e justamente ESTREITAR o campo a uma problematica nuclear, nao incluir todas as perturbacoes. A alternativa D contraria a logica do foco e da brevidade. Demais alternativas reproduzem conceitos validos (situacao-problema, ponto de urgencia, hipotese psicodinamica)."}, {"id": "1299794", "d": "psicologia", "a": ["Psicopatologia", "CID-10 e DSM", "Transtornos da Ansiedade"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme o DSM-V, os ataques de pânico destacam-se, nos\ntranstornos de ansiedade, como um tipo particular de\nresposta ao medo. Os transtornos de ansiedade diferem,\nentre si, nos tipos de objetos ou situações que induzem\nmedo, ansiedade ou comportamento de esquiva e na\nideação cognitiva associada. A respeito desse assunto,\njulgue os itens que se seguem. I. As principais características do transtorno de\nansiedade social (fobia social) são ansiedade e\npreocupação persistentes e excessivas acerca de vários\ndomínios, incluindo desempenho no trabalho e escolar,\nque o indivíduo tem dificuldades de controlar. Além\ndisso, são experimentados sintomas físicos, como, por\nexemplo, inquietação ou sensação de “nervos à flor da\npele”; fadiga; dificuldade de concentração ou “ter\nbrancos”; irritabilidade; tensão muscular; e\nperturbação do sono.     II. O indivíduo com agorafobia é temeroso, ansioso ou se\nesquiva de interações e situações sociais que envolvam\na possibilidade de ser avaliado. Estão inclusas também\nas situações sociais de se encontrar com pessoas que\nnão são familiares, as situações em que o indivíduo\npode ser observado comendo ou bebendo e as\nsituações de desempenho diante de outras pessoas. A\nideação cognitiva associada é a de ser avaliado\nnegativamente pelos demais, ficar embaraçado, ser\nhumilhado ou rejeitado ou ofender os outros.     III. Os indivíduos com transtorno de ansiedade\ngeneralizada são apreensivos e ansiosos acerca de duas\nou mais das seguintes situações: usar transporte\npúblico; estar em espaços abertos, estar em lugares\nfechados; ficar em fila ou estar no meio de uma\nmultidão; ou estar fora de casa sozinho em outras\nsituações. O indivíduo teme essas situações devido aos\npensamentos de que pode ser difícil escapar ou de que\npode não haver auxílio disponível caso desenvolva\nsintomas de pânico ou outros sintomas incapacitantes\nou constrangedores.     Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e II estão certos."}, "g": "A", "j": "Nenhum item esta certo - todos trocam as definicoes do DSM-V: item I descreve TAG (atribuido a fobia social), item II descreve fobia social (atribuido a agorafobia) e item III descreve agorafobia (atribuido a TAG)."}, {"id": "1299793", "d": "psicologia", "a": ["Freud", "Teorias da Personalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "Freud (apud Volich) revelou que o sintoma não é apenas\num corpo estranho a ser erradicado, mas, antes de tudo, o\nmensageiro de um apelo a ser compreendido. Por\nintermédio dele, pode ser resgatada a história do indivíduo,\npropiciando a reorganização de seus modos de\nfuncionamento psicossomático, condição para a\ntransformação do sujeito. Acerca desse tema, assinale a\nalternativa incorreta.", "alt": {"A": "Diante de qualquer profissional de saúde, o paciente\napresenta, incrustado em seu sintoma, seu desamparo.\nA doença revela, ao mesmo tempo que alimenta, a\nfragilização de todo o seu funcionamento\npsicossomático.", "B": "Toda iniciativa de eliminação da sintomatologia, das\nintercorrências, das reações do paciente à consulta e\nao tratamento, ou seja, a tentativa de assepsia da\nrelação terapêutica, descartando as manifestações\nsubjetivas do paciente relacionadas ao processo\nterapêutico, enriquece a experiência de seus\nprotagonistas.", "C": "A impossibilidade de contato com essas dimensões\nhumanas do ato terapêutico é uma das principais\nfontes da experiência melancólica do terapeuta, da\nresistência dos pacientes ao tratamento, dos impasses\ne dos erros terapêuticos.", "D": "A experiência demonstra que o contato com a experiência\nindividual de cada protagonista da relação terapêutica é o\nprincipal catalisador dos processos de cura.", "E": "Médico, psicólogo e qualquer outro profissional de\nsaúde são convocados ao exercício da função materna,\nque tem como paradigma a função exigida da mãe pela\nfragilidade dos recursos internos do bebê."}, "g": "B", "j": "Questao pede INCORRETA. Para Freud/Volich, a tentativa de 'assepsia' da relacao terapeutica - eliminacao das manifestacoes subjetivas - EMPOBRECE a experiencia, nao a enriquece. Demais alternativas reproduzem corretamente a perspectiva psicossomatica de Volich."}, {"id": "1299792", "d": "psicologia", "a": ["Psicoterapias", "Freud", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Volich, a intensa implicação exigida do\nterapeuta no trabalho com os pacientes mais\ndesorganizados em sua economia psicossomática é muitas\nvezes questionada e, mesmo, criticada por aqueles que se\naferram, a todo custo, ao princípio de neutralidade\nterapêutica e aos dogmas de escolas. Essa implicação é,\nporém, inevitável, não apenas para tornar minimamente\neficaz a clínica desses pacientes, mas, inclusive, antes disso,\npara viabilizá-la. A partir dessas informações, julgue os\npróximos itens. I. É importante considerar que acolher não significa\nassumir a vida ou o desejo do outro e que\ncompreender não significa ser condescendente.   II. Compartilhar não implica em realizar concretamente\naquilo que os limites do paciente impedem que ele\nmesmo realize.   III. A regra da abstinência do analista, preconizada por\nFreud, continua a ter função em sua essência, mesmo\nque uma implicação maior do terapeuta seja\nnecessária.      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens estao corretos conforme Volich: acolher nao e assumir o desejo do outro (I); compartilhar nao implica realizar concretamente pelo paciente (II); a regra da abstinencia mantem sua funcao essencial mesmo com maior implicacao do terapeuta (III)."}, {"id": "1299787", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Bleichmar & Bleichmar: o termo pós-kleiniano\ndesigna um grupo de analistas que desenvolveram a teoria\ne a técnica originais de Melanie Klein e criaram conceitos e\nnovas estratégias. Um de seus membros mais criativos e\naudazes, tanto para enfocar problemas novos quanto para\ninventar modelos que podem explicá-los, estabeleceu uma\nmudança muito importante no pensamento kleiniano, com\na ideia de função continente da mãe. A ideia de que o\nterapeuta deve ser continente das angústias do paciente se\ngeneralizou tanto que penetrou nos mais vastos campos,\ndesde a análise até as psicoterapias individuais e de grupo,\nassim como nas propostas institucionais. Com base nessas\ninformações, assinale a alternativa que apresenta o nome\ndo psicanalista que incursionou no tratamento dos grupos\nterapêuticos e se interessou, de maneira especial, pela\nanálise de psicóticos.", "alt": {"A": "Donald Meltzer.", "B": "Wilfred Bion.", "C": "Donald Winnicott.", "D": "Hanna Segal.", "E": "Heinz Kohut."}, "g": "B", "j": "Wilfred Bion e o psicanalista pos-kleiniano que desenvolveu o conceito de funcao continente da mae, trabalhou com grupos terapeuticos e dedicou-se especialmente a analise de psicoticos. Meltzer, Winnicott, Segal e Kohut tem outras especialidades distintas."}, {"id": "1299784", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo as concepções de psicologia clínica do professor\nClaudio Figueiredo, assinale a alternativa incorreta.", "alt": {"A": "O psicólogo clínico é um profissional do encontro, na\nmedida em que esteja disponível para se abrir à\nalteridade, entendendo-a como algo desconhecido e\ninusitado.", "B": "A definição de psicologia clínica não pode se restringir\nao local, à clientela, a uma prática, a um campo de\nintervenção ou a uma área de conhecimento.", "C": "Pode-se definir psicologia clínica como a prática das\ndiferentes abordagens em psicoterapia.", "D": "A psicologia clínica é uma atitude, um modo de se\nrelacionar com o outro, um cuidado que possibilitará\nao homem sentir-se acolhido em uma morada.", "E": "A singularidade do homem dá-se a partir da\nexperiência e dos significados que ele atribui ao\nmundo. A escuta clínica e o entendimento da pessoa\ndão-se por meio da revelação de seus modos de ser."}, "g": "C", "j": "Questao pede INCORRETA. Claudio Figueiredo argumenta justamente que a psicologia clinica NAO se reduz a 'pratica das diferentes abordagens em psicoterapia' - ela e uma atitude, modo de relacao e cuidado. As demais alternativas reproduzem corretamente seu pensamento."}, {"id": "1299733", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Os processos atencionais são extremamente complexos e\nencontram-se subjacentes à execução de tarefas\nneuropsicológicas. A reabilitação neuropsicológica engloba\na reestruturação de tais processos. Acerca dos processos\natencionais, assinale a alternativa correta.", "alt": {"A": "A atenção sustentada refere-se aos mecanismos\ntônicos de controle interno e fásicos de modificações\nmomentâneas.", "B": "O neurotransmissor serotonina exerce papel crucial na\nregulação da atenção seletiva e, por isso, está\nenvolvido no tratamento medicamentoso dos\nproblemas atencionais.", "C": "A atenção alternada é um exemplo de processo\natencional que os testes neuropsicológicos não\navaliam.", "D": "Devido à complexidade dos processos atencionais, as\nestruturas subcorticais, como o sistema límbico e o\nsistema reticular, não estão envolvidas.", "E": "A atenção seletiva define-se como a capacidade para\neleger o estímulo a ser processado em detrimento de\noutros estímulos presentes e, por isso, facilita o\nprocessamento e a execução de uma tarefa."}, "g": "E", "j": "Atencao seletiva e a capacidade de eleger um estimulo a ser processado em detrimento de outros, facilitando a tarefa. A) confunde sustentada com alternada; B) o neurotransmissor central da atencao e a noradrenalina/dopamina; C) atencao alternada e avaliavel; D) estruturas subcorticais participam."}, {"id": "1299732", "d": "psicologia", "a": ["Psicopatologia"], "ano": "2020", "org": "CFP", "t": "", "e": "A memória é constituída por vários sistemas que\ngeralmente estão comprometidos em quadros\nneurológicos. Com base nessa informação, assinale a\nalternativa correta.", "alt": {"A": "A amnésia pode ser classificada como anterógrada, ou\nseja, a perda do registro dos eventos ocorridos antes\nda lesão, e retrógrada, que se refere à dificuldade em\nconsolidar os traços mnemônicos após a lesão.", "B": "Pacientes amnésicos são capazes de recordar tarefas\nprocedurais já aprendidas antes da lesão.", "C": "A prática repetitiva não é recomendada durante o\nprocesso de intervenção junto a pessoas com lesões\nencefálicas adquiridas, pois gera comportamentos de\ndesatenção.", "D": "A utilização de estratégias compensatórias na\nintervenção com crianças e adultos com deficits de\nmemória não tem eficácia comprovada.", "E": "A técnica de “aprendizagem sem erro” consiste na\nutilização de um equipamento de gravação das\ninstruções para a realização de tarefas, assim as\ninstruções são sempre iguais."}, "g": "B", "j": "Memoria procedural costuma estar preservada em pacientes amnesicos, permitindo recordar tarefas aprendidas antes da lesao. A inverte definicoes de amnesia anterograda/retrograda; C, D, E sao falsas (pratica repetitiva, estrategias compensatorias sao eficazes; aprendizagem sem erro nao se resume a gravacao de instrucoes)."}, {"id": "1299731", "d": "psicologia", "a": ["Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "A respeito do processo de reabilitação neuropsicológica,\nassinale a alternativa correta.", "alt": {"A": "O estabelecimento de metas para a intervenção\napresenta vantagens: aumenta a motivação dos\nenvolvidos e permite o monitoramento e a avaliação\nda eficácia dos procedimentos.", "B": "A equipe tem metas de longo prazo, dentro do plano\nde intervenção, que configuram os desejos e sonhos\ndos clientes, enquanto as metas de curto prazo\nenfocam as vontades e os problemas identificados pela\nfamília.", "C": "As metas de intervenção devem ser estabelecidas por\nmeio de critérios técnicos discutidos em equipe e,\nposteriormente, comunicadas ao cliente e à sua\nfamília.", "D": "A literatura demonstrou que a intervenção individual é\nmais eficaz que a intervenção em grupo, uma vez que\ncontempla os deficits específicos do cliente.", "E": "O intuito da intervenção em grupo é lidar com a\ndemanda crescente de atendimento neuropsicológico\ne carece de evidências de eficácia nas questões\ntécnicas."}, "g": "A", "j": "O estabelecimento de metas na reabilitacao neuropsicologica aumenta a motivacao e permite o monitoramento da eficacia. B inverte fontes das metas; C exclui o cliente da definicao; D nao ha superioridade da intervencao individual sobre grupo; E intervencao em grupo tem evidencias."}, {"id": "1299730", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere ao papel da avaliação neuropsicológica\ncomo fundamento para estruturar a intervenção em\nneuropsicologia, assinale a alternativa correta.", "alt": {"A": "Deve-se evitar a utilização das informações de\nfamiliares e pessoas significativas da convivência do\ncliente para que tais depoimentos não interfiram no\njulgamento clínico do neuropsicólogo.", "B": "A observação das interações sociais do examinando\nnos diferentes contextos de sua vida pode invalidar os\nresultados objetivos dos testes.", "C": "A observação comportamental e a formação da aliança\nterapêutica devem ser postergadas até a entrevista\ndevolutiva.", "D": "Ao eleger os testes, as escalas e as tarefas que farão\nparte da avaliação neuropsicológica, é importante\nconsiderar a validade ecológica desses instrumentos.", "E": "A utilização de instrumentos padronizados para avaliar\nos domínios cognitivos garante que os fatores\neducacionais e culturais sejam contemplados."}, "g": "D", "j": "Validade ecologica - capacidade do instrumento de prever desempenho no cotidiano - e criterio essencial na escolha de testes e tarefas da avaliacao neuropsicologica. Demais alternativas contradizem boas praticas (uso de informacoes de familiares, observacao social, alianca terapeutica desde o inicio, instrumentos padronizados nao garantem fatores culturais)."}, {"id": "1299727", "d": "psicologia", "a": ["Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Estima-se que existem mais de dois milhões de pessoas no\nBrasil que vivem com acidente vascular cerebral (AVC);\nmais de 20% desse grupo relata incapacidades. O\natendimento neuropsicológico é essencial para auxiliar no\nprocesso de reabilitação. Considerando o conhecimento\natual sobre AVC, assinale a alternativa incorreta.", "alt": {"A": "O AVC pode ser classificado como isquêmico (o tipo\nmais frequente) e hemorrágico (tende a ser mais\ngrave).", "B": "A principal sequela física do AVC é a hemiplegia do lado\noposto ao lesionado.", "C": "A negligência visual e a afasia são frequentemente\nobservadas após um AVC, mas podem gradualmente\nmelhorar.", "D": "As variáveis demográficas, as características da lesão e\nos fatores psicológicos são os principais fatores a\nserem considerados no planejamento da intervenção\nneuropsicológica e no prognóstico.", "E": "O grau de perda funcional depende especificamente\ndas características pré-mórbidas de personalidade, da\nclasse social e da estrutura familiar."}, "g": "E", "j": "Questao pede INCORRETA. O grau de perda funcional pos-AVC depende principalmente das caracteristicas da lesao (localizacao, extensao, tipo) e nao 'especificamente' de personalidade pre-morbida, classe social e estrutura familiar. Demais alternativas (A-D) descrevem corretamente epidemiologia, sequelas e fatores de planejamento."}, {"id": "1299726", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "O traumatismo cranioencefálico (TCE) caracteriza-se por\num insulto externo que causa uma lesão intracraniana e\napresenta diferentes etiologias e sequelas. Acerca do TCE,\nassinale a alternativa correta.", "alt": {"A": "A escala de coma de Glasgow, usada desde o primeiro\natendimento médico após TCE até a alta hospitalar,\nmede cinco áreas importantes: atenção; memória;\nlinguagem; funções executivas; e teoria da mente.", "B": "O TCE na infância e na adolescência é raro, devido à\nneuroplasticidade, é plenamente superado e o\ndesenvolvimento das funções neuropsicológicas ocorre\nsem prejuízos após a recuperação física.", "C": "Sequelas físicas, cognitivas, emocionais e\ncomportamentais são frequentes e podem ser\nincapacitantes mesmo após TCE leve.", "D": "A fadiga, a insônia e a irritabilidade são observadas\napenas após TCE severo e podem ser tratadas com\nsucesso por meio de psicofármacos.", "E": "A indicação de avaliação neuropsicológica deve ocorrer\napós o primeiro ano da lesão, pois, nesse período, a\nrecuperação espontânea estabilizou-se."}, "g": "C", "j": "Sequelas fisicas, cognitivas, emocionais e comportamentais ocorrem com frequencia mesmo em TCE leve. A descricao da Glasgow esta errada (mede abertura ocular, resposta verbal e motora); B subestima TCE infantil; D fadiga/insonia/irritabilidade ocorrem em todos os graus; E avaliacao neuropsicologica e indicada antes de 1 ano."}, {"id": "1299725", "d": "psicologia", "a": ["Psicopatologia", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "No que diz respeito às epilepsias, julgue os itens que se\nseguem.\n    I. Há um consenso na literatura de que, na epilepsia de\nlobo temporal, as crianças afetadas podem apresentar\nprejuízo na atenção, na aprendizagem, na memória,\nnas habilidades visoespaciais e nas funções executivas.\n  II. A epilepsia de lobo frontal, segunda razão mais\nfrequente para o tratamento cirúrgico, facilita um perfil\ncognitivo com prejuízos na organização, no\nplanejamento, na impulsividade e na labilidade de\nhumor.\n  III. Na cirurgia para epilepsia refratária ao tratamento\nmedicamentoso, as técnicas de neuroimagem\nsubstituíram a intervenção em avaliação e reabilitação\nneuropsicológica.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Apenas I e II estao certos. Epilepsia de lobo temporal afeta atencao, aprendizagem, memoria, visoespacial e executivas (I); epilepsia de lobo frontal compromete organizacao, planejamento, impulsividade e labilidade (II). Item III e falso - a neuroimagem complementa, nao substitui, a avaliacao/reabilitacao neuropsicologica."}, {"id": "1299724", "d": "psicologia", "a": ["Psicopatologia", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "O perfil cognitivo típico no transtorno do espectro do\nautismo tem sido estudado com frequência dentro das\nneurociências. A neuropsicologia colabora ativamente para\ndelinear instrumentos de avaliação adequados para\ndiagnosticar e intervir junto a esse grupo. Com relação a\nesse tema, assinale a alternativa correta.", "alt": {"A": "As funções executivas, frequentemente, estão\nprejudicadas em crianças e adolescentes com\ntranstorno do espectro do autismo, no entanto, as\nevidências ainda não são conclusivas quanto a quais\ncomponentes executivos específicos são deficitários\nnesses quadros.", "B": "A intervenção neuropsicológica e fonoaudiológica pode\nsanar os problemas comunicativos encontrados nas\npessoas com esse diagnóstico, por meio da técnica de\nassociação básica atencional (ABA).", "C": "A família deve ser mantida afastada da criança com\ntranstorno do espectro do autismo, durante as\nintervenções sistemáticas, devido aos fatores\ndistratores e emocionais envolvidos.", "D": "As características de personalidade e a irritabilidade\ndesse grupo mostram-se estáveis e estão dissociadas\ndas condições cognitivas observadas.", "E": "Como a neuroplasticidade não ocorre, o processo de\nensino e aprendizagem está comprometido no\ntranstorno do espectro do autismo e as intervenções\ndevem sempre ter um caráter compensatório."}, "g": "A", "j": "Disfuncao executiva e frequente no TEA, mas a literatura ainda nao e conclusiva sobre quais componentes especificos sao deficitarios. B confunde ABA com 'associacao basica atencional' e supercredita a tecnica; C contradiz inclusao familiar; D ignora variabilidade comportamental; E nega a neuroplasticidade."}, {"id": "1299723", "d": "psicologia", "a": ["Psicopatologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Existe um debate importante sobre o diagnóstico de\ntranstorno de atenção e hiperatividade (TDAH) no qual o\nneuropsicólogo está diretamente envolvido. No que se\nrefere a TDAH, assinale a alternativa correta.", "alt": {"A": "O DSM-V trouxe algumas alterações na caracterização\ndo TDAH, como a alteração de idade de início dos sete\npara os nove anos.", "B": "O diagnóstico do TDAH deve ser concluído por meio da\nanálise dos resultados obtidos na escala Wechsler de\ninteligência, posto que o examinando deve obter um\nescore total indicativo de inteligência limítrofe ou\nrebaixado.", "C": "O neuropsicólogo deve esclarecer para a família que o\nTDAH pode ser curado após o uso continuado da\nmedicação e o ingresso na vida adulta.", "D": "A hiperatividade pode ser observada pelos\ncomportamentos de agitar as mãos ou os pés, não\nconseguir permanecer sentado e correr em demasia e\nfalar muito e rapidamente.", "E": "O sintoma de impulsividade caracteriza-se pela\noposição sistemática à figura de autoridade."}, "g": "D", "j": "Hiperatividade no DSM-V manifesta-se por agitar maos/pes, nao permanecer sentado, correr/escalar em demasia e falar excessivamente. A inverte idade (DSM-V mudou de 7 para 12 anos, nao 9); B nao se diagnostica TDAH por Wechsler; C TDAH nao se 'cura'; E descreve oposicionismo, nao impulsividade."}, {"id": "1299722", "d": "psicologia", "a": ["Psicopatologia", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A intervenção neuropsicológica para quadros de\ntranstornos específicos de aprendizagem (TEA) é uma\ndemanda frequente no contexto da neuropsicologia\npediátrica. O diagnóstico de TEA deve incluir", "alt": {"A": "o diagnóstico de deficit intelectual estabelecido nos\núltimos seis meses e ainda precocemente e os deficits\nde leitura detectáveis por medidas psicométricas.", "B": "um conjunto de sintomas específicos durante pelo\nmenos seis meses, deficits detectáveis em medidas\npsicométricas de início precoce e pouca resposta às\nintervenções convencionais e ausência de outros\ndeterminantes.", "C": "um sintoma específico, presente por pelo menos seis\nanos, mas indetectável por meio de testes\npsicométricos, juntamente com a ausência de outros\ndeterminantes", "D": "desempenho acadêmico abaixo daquele do grupo\nnormativo durante os três primeiros anos escolares e\nproblemas comportamentais concomitantes.", "E": "dificuldades de relacionamento recorrentes durante\nseis meses e um conjunto de sintomas específicos na\naprendizagem da matemática ou da leitura detectáveis\npor provas convencionais."}, "g": "B", "j": "Criterios DSM-V para transtorno especifico de aprendizagem: sintomas por ao menos 6 meses, deficits detectaveis em medidas psicometricas de inicio precoce, pouca resposta a intervencoes convencionais e ausencia de outros determinantes (deficiencia intelectual, sensorial, neurologica). Alternativa B reproduz fielmente."}, {"id": "1299714", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Um dos problemas para implementar a avaliação\nneuropsicológica na clínica foi a utilização de instrumentos\ninternacionais apenas traduzidos, mas não adaptados à\nrealidade linguística e cultural brasileira. A partir dessa\ninformação, assinale a alternativa correta.", "alt": {"A": "A adaptação de testes neuropsicológicos pode ser\nconceituada como um processo de construção\nfundamentado nas demandas do mercado e na\nfacilidade de tradução.", "B": "Os testes que se utilizam de estímulos não verbais são\nmais facilmente adaptados, pois requerem apenas\ntradução das instruções e formação de grupo\nnormativo.", "C": "A adaptação de instrumentos neuropsicológicos exige a\nintegração entre conhecimentos de neuropsicologia,\npsicologia cognitiva, neuropsicolinguística, psicometria\ne avaliação psicológica.", "D": "Como os instrumentos neuropsicológicos\ninternacionais já possuem características psicométricas\nestabelecidas, a adaptação torna-se mais curta, pois\nesse procedimento não precisa ser realizado.", "E": "O cuidado com a linguagem restringe-se à primeira\nfase de adaptação do instrumento: as instruções das\natividades para os participantes."}, "g": "C", "j": "Adaptacao de testes neuropsicologicos exige integracao multidisciplinar entre neuropsicologia, psicologia cognitiva, neuropsicolinguistica, psicometria e avaliacao psicologica. As demais alternativas reduzem indevidamente o processo (mercado/traducao, apenas estimulos nao verbais, padronizacao pre-existente, primeira fase)."}, {"id": "1299711", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Diversas tarefas neuropsicológicas clássicas são\namplamente utilizadas no Brasil. Quanto a esse assunto,\nassinale a alternativa incorreta.", "alt": {"A": "A tarefa de fluência verbal é usada para avaliar os\ncomponentes verbal e executivo da cognição e pode\nser utilizada em uma ampla faixa etária.", "B": "Os testes de lista de palavras, como o teste de\naprendizagem auditivo-verbal de Rey, investigam a\nmemória recente, a aprendizagem, a interferência, a\nretenção e a memória de reconhecimento.", "C": "A tarefa de cubos de Corsi examina as funções\nvisoespaciais e a memória de trabalho; no entanto, a\nausência de padronização pode dificultar sua\nutilização.", "D": "O teste da figura complexa de Rey busca mensurar os\nprocessos atencionais e a capacidade linguística de\ndescrever estímulos abstratos e, por ser de fácil\nadministração e pontuação, tem grande fidedignidade.", "E": "Estudos demonstram diferenças culturais significativas\nno desempenho no teste de trilhas, que avalia atenção\ne aspectos das funções executivas."}, "g": "D", "j": "Questao pede INCORRETA. A figura complexa de Rey avalia memoria visual, organizacao perceptual e construcao visoespacial, NAO processos atencionais e capacidade linguistica de descrever estimulos abstratos. Demais alternativas (fluencia verbal, Rey lista de palavras, cubos de Corsi, trilhas) sao descritas corretamente."}, {"id": "1299710", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A avaliação neuropsicológica busca um equilíbrio entre dois\nenfoques: o enfoque nomotético e o enfoque ideográfico.\nCom base nessa informação, assinale a alternativa correta.", "alt": {"A": "O enfoque idiográfico compara o desempenho do\nindivíduo com o do grupo normativo em vários testes\nneuropsicológicos.", "B": "Um importante exemplo da abordagem nomotética foi\na criação da bateria neuropsicológica Halstead-Reitan,\nque, até a atualidade, tem grande acurácia em\ndiscriminar pessoas com e sem lesão cerebral.", "C": "Existem limitações importantes para o enfoque\nideográfico, como, por exemplo, o número\nconsiderável de funções a serem avaliadas e a\ninexistência de grupo normativo de número grande o\nsuficiente.", "D": "O enfoque nomotético foi desenvolvido inicialmente\npela terapia comportamental, que propõe observar a\nfrequência de um comportamento do cliente.", "E": "Um exemplo da aplicação do enfoque nomotético foi a\nobservação de dupla dissociação quando, por exemplo,\ndeficits na memória episódica ocorrem, enquanto a\nmemória de curto prazo é preservada."}, "g": "B", "j": "A bateria Halstead-Reitan e exemplo classico de abordagem nomotetica, com grande acuracia na discriminacao de pessoas com e sem lesao cerebral. A inverte ideografico/nomotetico, C descreve nomotetico como ideografico, D atribui origem comportamentalista incorreta, E dissociacao dupla e exemplo ideografico."}, {"id": "1299709", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A relação entre a psicometria e a neuropsicologia cognitiva\ntem sido intensamente explorada por pesquisadores que\nressaltam diversos aspectos derivados dessa relação.\nConsiderando essa informação, assinale a alternativa\ncorreta.", "alt": {"A": "O desenvolvimento de um instrumento de avaliação\nneuropsicológica deve seguir critérios específicos,\ndiferentes dos utilizados para desenvolver\ninstrumentos de avaliação psicológica, visto que serão\nutilizados em grupos minoritários.", "B": "A neuropsicologia cognitiva consiste no ramo da\npsicologia cognitiva que utiliza dados de pessoas com\nalterações cognitivas para mais bem entender os\nprocessos envolvidos na cognição normal.", "C": "Com o intuito de estabelecer validade baseada em\ncritério, busca-se um padrão de correlação entre os\nescores do teste-alvo e o de outras variáveis que\nmedem o mesmo construto ou construtos\nrelacionados.", "D": "Observam-se quatro procedimentos utilizados nos\nestudos de evidências de validade com base no\nconteúdo: tempo de resposta; rastreamento ocular;\nentrevistas; e grupo focal.", "E": "As evidências de validade com base na consequência\ndas respostas investigam as consequências sociais do\nuso dos testes quando a validade se restringe aos\nescores do teste em si."}, "g": "B", "j": "Neuropsicologia cognitiva utiliza dados de pessoas com alteracoes cognitivas para entender melhor a cognicao normal (logica da dissociacao). A iguala criterios neuropsicologicos a psicologicos gerais; C confunde validade de criterio com de construto; D confunde conteudo com processo de resposta; E inverte logica da validade de consequencia."}, {"id": "1299708", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A contribuição da psicometria para a neuropsicologia é\ninegável tanto no aspecto teórico quanto no aspecto\nprático da área de conhecimento. A formação em\nneuropsicologia requer um sólido conhecimento dos\nprincípios da psicometria. A respeito das contribuições da\npsicometria, julgue os itens a seguir.    I. A escolha entre modelos teóricos na neuropsicologia\ncognitiva deve ser fundada unicamente nas evidências\nestatísticas, uma vez que os números revelam o\nmodelo com o melhor ajuste, o qual será sempre o\nescolhido.   II. Uma contribuição da psicometria para a\nneuropsicologia é a crítica contra os testes de\nsignificância e a importância dada ao tamanho do\nefeito e dos intervalos de confiança.   III. A psicometria é um campo do conhecimento que\nenfoca a construção de evidências por meio da\nmodelagem dos construtos psicológicos, que ocorre\npor meio de um conjunto de técnicas e procedimentos\npara a construção e a validação de testes e\ninstrumentos psicológicos.     Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens II e III corretos: psicometria criticou os testes de significancia e valoriza tamanho de efeito/IC (II); a disciplina modela construtos psicologicos via construcao e validacao de testes (III). Item I e falso: escolha de modelos teoricos integra evidencias estatisticas com conceituais e clinicas, nao se baseia 'unicamente' em estatistica."}, {"id": "1299707", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A avaliação neuropsicológica (AN) foi definida de diferentes\nmodos na literatura da área. No entanto, algumas\ncaracterísticas desta já são bem estabelecidas na prática\nclínica. Quanto às características da AN, assinale a\nalternativa correta.", "alt": {"A": "Tem por objetivos explorar as razões do desempenho\ncomprometido, compreender a inter-relação entre o\ndesempenho observado e as demandas ambientais e\nidentificar as áreas cognitivas, comportamentais e\nafetivas preservadas e deficitárias.", "B": "Utiliza-se, exclusivamente, de procedimentos e\ninstrumentos padronizados e universais para viabilizar\na análise quantitativa de dados objetivos e embasados\nnas amostras normativas.", "C": "A análise qualitativa das respostas às entrevistas\nestruturadas e aos instrumentos de avaliação\nneuropsicológica dispensa modelos teóricos e outros\nmodos de determinação de comprometimento\ncognitivo.", "D": "Como os procedimentos de AN são estruturados e\nnormatizados, o neuropsicólogo não deve adotar um\nreferencial teórico para interpretar o comportamento\n(sintoma) e o relacionar com suas bases\nneurobiológicas.", "E": "A AN possibilita um diagnóstico, correlaciona estrutura\nanatômica e função e apresenta dados sigilosos que\ndevem ser omitidos na documentação do estado do\npaciente."}, "g": "A", "j": "Objetivos centrais da AN: explorar razoes do desempenho comprometido, compreender a inter-relacao com demandas ambientais e identificar areas preservadas/deficitarias. Demais alternativas contradizem boas praticas (uso exclusivo de testes padronizados, dispensa de modelos teoricos, omissao de dados sigilosos)."}, {"id": "1299706", "d": "psicologia", "a": ["Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "As doenças ligadas ao funcionamento cerebral constituem\numa das maiores causas de deficiências no mundo. Nesse\ncontexto, a reabilitação neuropsicológica adquiriu um papel\nimportante para a prática da neuropsicologia clínica. No\nque se refere às diretrizes para realizar tal intervenção,\nassinale a alternativa incorreta.", "alt": {"A": "O processo de reabilitação deve ser considerado como\numa parceria entre o cliente, sua família e os\nprofissionais de saúde.", "B": "Os deficits cognitivos, emocionais e psicossociais\nencontram-se conectados e são integrados ao\nprograma terapêutico.", "C": "A intervenção pode ser iniciada durante a terapia\nintensiva, antes mesmo da estabilização das condições\nmédicas do paciente.", "D": "Várias tecnologias e equipamentos podem ser\nincorporados como auxílio na reabilitação de pessoas\ncom problemas neuropsicológicos.", "E": "Como os deficits cognitivos derivados da lesão cerebral\nsão dinâmicos, estabelecer objetivos mensuráveis para\na intervenção torna-se inviável."}, "g": "E", "j": "Questao pede INCORRETA. Estabelecer objetivos mensuraveis e parte essencial da reabilitacao neuropsicologica (permite monitoramento e avaliacao da intervencao). Demais alternativas descrevem corretamente parceria multidisciplinar, integracao de deficits, inicio precoce e uso de tecnologias."}, {"id": "1299705", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "A neuropsicologia, enquanto campo de conhecimento,\nnasceu durante o século XIX. Este período é marcado pela\ncontrovérsia entre localizacionismo e holismo. Com relação\na esse período histórico, assinale a alternativa correta.", "alt": {"A": "O maior expoente do localizacionismo das funções\nmentais foi o médico Jean Pierre Flourens (1794-1867),\nque caracterizou as funções e suas respectivas\nlocalizações anatômicas.", "B": "Paul Broca (1824-1880) descreveu casos em que a\nlesão no terço posterior do giro temporal superior\nesquerdo determinava a perda da capacidade de\ncompreensão da linguagem.", "C": "Franz Gall (1758-1828) acreditava que as funções\nmentais se originavam em estruturas cerebrais,\nhavendo tantas estruturas cerebrais quantas\nfaculdades ou processos mentais existissem.", "D": "Durante o século XIX, o holismo defendia que as\nestruturas cerebrais, cardíacas e gástricas estavam\nenvolvidas diretamente no desempenho das funções\ncerebrais.", "E": "O holismo, ou frenologia, como era chamado na\nFrança, acreditava que o cérebro fosse uma massa\nhomogênea, funcionando de modo integrado."}, "g": "C", "j": "Franz Gall, criador da frenologia, postulava tantas estruturas cerebrais quantas faculdades/processos mentais existissem. A erra atribuindo localizacionismo a Flourens (holista); B confunde area de Wernicke com Broca; D inclui coracao e estomago indevidamente; E iguala holismo a frenologia (que e localizacionista)."}, {"id": "1299698", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "No livro La preparación psicológica del deportista, o autor\nHiram M. Valdes Casal (2002) apresenta diversos\nparadigmas relativos à preparação psicológica, entre os\nquais se destaca o quarto, referente ao ensino de\nautocontrole dos atletas (nos Esquemas de Loher, Garfield,\nSuinn e Unestahl). Acerca desse tema, assinale a alternativa\nincorreta.", "alt": {"A": "A busca do controle emocional dá-se por meio do\nautoconhecimento.", "B": "A análise de motivação perpassa o reconhecimento de\nexperiências de êxito.", "C": "O controle de estresse e a prática de pensamentos\npositivos são necessários para se atingir o estado\npsicológico desejado.", "D": "Conhecer e praticar estratégias, como, por exemplo,\ntreinamento psicotônico, auto-hipnose e descarga\ntensional, é necessário aos atletas.", "E": "O trabalho psicológico é independente do sistema de\npreparação geral do atleta, não havendo interferência\nnas qualidades volitivas."}, "g": "E", "j": "Questao pede INCORRETA. Em Valdes Casal, o trabalho psicologico esta INTEGRADO ao sistema de preparacao geral do atleta e impacta diretamente as qualidades volitivas - portanto, afirmar independencia/ausencia de interferencia contraria o paradigma de autocontrole."}, {"id": "1299696", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Preparação psicológica, treinamento mental e treino de\nhabilidades psicológicas são termos utilizados em psicologia\ndo esporte. Com base nessa informação, julgue os itens\nseguintes.    \nI. A aplicação desses termos deve considerar a\nperiodização do treinamento esportivo que, por sua\nvez, diz respeito à estrutura de um plano de trabalho\nde preparação em unidades de micro e macrociclos e\nem sessões de atividades.  \nII. A aplicação desses termos deve considerar a\nperiodização do treinamento esportivo que, por sua\nvez, diz respeito ao planejamento e à organização dos\nciclos de atividades, em função dos objetivos e das\nnecessidades específicas da população de atletas.  \nIII. A aplicação desses termos deve considerar a\nperiodização do treinamento esportivo que, por sua\nvez, diz respeito à organização de tarefas e\nprocedimentos de treinamento, em função do\ncalendário competitivo.    \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: periodizacao envolve estrutura de plano em micro/macrociclos (I), planejamento por objetivos da populacao de atletas (II) e organizacao de tarefas pelo calendario competitivo (III) - tres dimensoes complementares e classicas da preparacao psicologica esportiva."}, {"id": "1299692", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com a Resolução CFP n.ᵒ 13/2007, que institui a\nConsolidação das resoluções relativas ao título profissional\nde especialista em psicologia e dispõe sobre normas e\nprocedimentos para seu registro, não é atribuição de um\npsicólogo do esporte", "alt": {"A": "ensinar os princípios técnicos da modalidade esportiva.", "B": "aplicar testes psicológicos avaliados no Satepsi.", "C": "discutir casos com a equipe multiprofissional.", "D": "dar orientação aos familiares dos atletas.", "E": "acompanhar a equipe técnica em campeonatos."}, "g": "A", "j": "Ensinar principios tecnicos da modalidade esportiva e atribuicao do TREINADOR, nao do psicologo do esporte. Res CFP 13/2007 reserva ao psicologo aplicar testes, discutir casos com equipe multi, orientar familiares e acompanhar equipe em campeonatos."}, {"id": "1299686", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Apesar de serem conhecidos os benefícios psicológicos e\nfisiológicos do exercício, como, por exemplo, redução do\nestresse e da depressão, aumento da autoestima,\ndiminuição do risco de doenças cardiovasculares e\nequilíbrio do metabolismo, apenas uma pequena parcela da\npopulação realiza algum tipo de exercício de forma regular.\nNesses casos, trabalhar a adesão é fundamental. O\npsicólogo do esporte poderá auxiliar os professores de\neducação física ao", "alt": {"A": "enfatizar os diversos benefícios do exercício,\ntransformar a prática em um momento agradável,\ntrabalhar de forma individualizada e obter apoio\nfamiliar ou do grupo social.", "B": "criar prescrições baseadas em dados de\ncondicionamento, de forma restritiva, para que o\npraticante atinja seus objetivos e aumente sua\nmotivação.", "C": "motivar o novo praticante a ter um corpo perfeito,\nestimulando-o com vídeos de blogueiras do Instagram\ne do Youtube. Os novos modelos de fitness são de\ngrande auxílio para motivar a adesão ao exercício.", "D": "não prestar auxílio na orientação desses profissionais\ndevido a ser antiético.", "E": "auxiliar no conhecimento da legislação e da\nresponsabilidade legal do profissional da educação\nfísica."}, "g": "A", "j": "Adesao ao exercicio e favorecida por enfase nos beneficios, ambiente agradavel, individualizacao do trabalho e apoio familiar/social. As demais alternativas listam praticas inadequadas (prescricao restritiva, comparacao com blogueiras, recusa de orientacao, foco apenas em legislacao)."}, {"id": "1299683", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Saúde", "Processo Saúde-Doença", "Transtornos Alimentares"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação a transtornos alimentares e a exercício, julgue\nos itens subsequentes.    \nI. Atletas costumam aderir à combinação entre exercícios\nfísicos e dieta alimentar como estratégia para melhorar\nseus resultados. A modificação do padrão alimentar\nnos períodos de treino e pré-competição costuma ser\numa prática entre os profissionais ligados ao esporte.  II. A alimentação pode ser planejada com o objetivo de\naumentar as reservas de glicogênio do organismo, com\no atleta ingerindo mais carboidratos para melhorar seu\nrendimento, ou como um meio para reduzir o\npercentual de gordura corporal.  III. Ao lidar com um atleta com predisposição a um\ntranstorno alimentar, é imprescindível encaminhá-lo a\num especialista. Recomenda-se também que ele não\ncomente sobre sua situação, principalmente quando há\nperda ou ganho de peso, para evitar ser ridicularizado.    \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item III está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Itens I (combinacao exercicio + dieta) e II (alimentacao para aumentar glicogenio e reduzir gordura) sao corretos. Item III e contraditorio - recomenda-se justamente CONVERSAR abertamente sobre a situacao, nao silenciar para evitar ridicularizacao, contrariando a logica de cuidado psicologico em transtornos alimentares."}, {"id": "1299681", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "A atenção plena é definida como o foco, sem julgamento,\nda atenção de alguém na experiência que ocorre no\nmomento presente. Acerca de mindfulness e esporte,\nassinale a alternativa correta.", "alt": {"A": "A atenção plena tem suas raízes nas práticas budistas\norientais e auxilia a direcionar a atenção para a\nexperiência passada, momento a momento.", "B": "Os exercícios de meditação incentivam os indivíduos a\nse engajar na percepção julgadora de sua experiência\ninterna, que ocorre a cada momento, como sensações\ncorporais, cognições e emoções, e de estímulos\nambientais, como visões e sons.", "C": "Estudos recentes em psicologia do esporte\nestabeleceram uma relação entre atenção plena e\ndesempenho esportivo. Eles descobriram que a\natenção plena está ligada ao foco no momento\npresente, que é a essência da psicologia do\ndesempenho máximo no esporte.", "D": "Pesquisas com mindfulness e esporte demonstram que\ntreinamentos para percepção do aqui e do agora,\nrealizados por meio de autorregulação, não auxiliam na\nmelhora do desempenho e no prazer durante a prática\ndo esporte.", "E": "As recentes pesquisas relacionando mindfulness e\nesporte mostram que atenção plena e aceitação têm\nefeitos apenas para melhorar o desempenho atlético."}, "g": "C", "j": "Mindfulness no esporte e ligada ao foco no momento PRESENTE, essencia do desempenho maximo. A inverte (passado), B contradiz a postura nao-julgadora, D e E negam evidencias bem documentadas sobre beneficios do mindfulness no desempenho e bem-estar atletico."}, {"id": "1299677", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Assinale a alternativa que não apresenta um tipo de foco\nde atenção.", "alt": {"A": "amplo", "B": "externo", "C": "interno", "D": "vigilante", "E": "estreito"}, "g": "D", "j": "Tipos classicos de foco de atencao (Nideffer): amplo, estreito, externo e interno (combinacao em quatro quadrantes). 'Vigilante' nao integra essa classificacao, sendo a alternativa que NAO apresenta tipo de foco."}, {"id": "1299673", "d": "psicologia", "a": ["Psicologia do Trânsito", "Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo dados da OMS (2018), os acidentes de trânsito são\nresponsáveis por cerca de 1,35 milhão de mortes por ano,\nsendo a principal causa de mortes de jovens entre cinco e\n29 anos de idade, e resultam em cerca de vinte a cinquenta\nmilhões de pessoas com sequelas em todo o mundo. Desse\nmodo, os acidentes de trânsito tornaram-se um problema\nde saúde pública mundial. A respeito desse tema, assinale a\nalternativa incorreta.", "alt": {"A": "De acordo com Klauer et al. (2014), a direção distraída\nligada ao desempenho de tarefas secundárias não é\numa causa de acidente automobilístico entre os\nmotoristas novatos ou entre os condutores\nexperientes.", "B": "Hole (2017) esclarece que a condução de veículos\nconcomitantemente com o uso de celular tem\nimportante efeito na esfera cognitiva, trazendo um\naumento no tempo de reação em situações fáceis de\nserem medidas pelas pesquisas da área, como, por\nexemplo, uma frenagem emergencial, aumentando o\nespaço de execução e maximizando a ocorrência de\nacidentes.", "C": "Além de danos causados à saúde física (ocasionando\nlesões e óbitos) e prejuízos materiais, envolver-se em\nacidentes de trânsito pode resultar em problemas\npsicológicos, que são evidenciados em termos de\npontuações mais elevadas em depressão, ansiedade e\nestresse pós-traumático.", "D": "Um sistema seguro requer que a interação complexa e\ndinâmica entre as velocidades de operação, os\nveículos, a infraestrutura viária e o comportamento\ndos usuários das vias sejam compreendidos e\nadministrados de maneira holística e integrada.", "E": "Ramaekers (2003) aponta que drogas sedativas,\nanti-histamínicos, antidepressivos tricíclicos e maconha\nforam fortemente associados ao prejuízo na\ncapacidade de conduzir veículos automotores na\nsituação de laboratório."}, "g": "A", "j": "Questao pede INCORRETA. Klauer et al. (2014) e literatura solida apontam que a direcao distraida por tarefas secundarias E causa importante de acidentes tanto em novatos quanto em experientes. Demais alternativas reproduzem corretamente Hole (2017), epidemiologia psicossocial, sistemas seguros e efeitos farmacologicos (Ramaekers, 2003)."}, {"id": "1299672", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "As CREPOP dedicam parte de seu eixo 3, que aborda a\ndimensão técnica do trabalho do psicólogo do trânsito, à\nimportância da educação para o trânsito. Analisando as\nnormatizações do Sistema Nacional de Trânsito para as\nquestões da educação para o trânsito, as CREPOP definem\natividades. Uma atividade que não se encaixa nesse campo\nde atuação é a educação para o trânsito", "alt": {"A": "no contexto escolar.", "B": "em blitz de fiscalização de trânsito.", "C": "promovida por órgãos, entidades, instituições e\nprofissionais autônomos.", "D": "na capacitação de profissionais de centros de formação\nde condutores.", "E": "na capacitação de agentes de trânsito."}, "g": "B", "j": "Blitz de fiscalizacao e atividade de FISCALIZACAO, nao de EDUCACAO para o transito. As demais alternativas (escolar, orgaos/entidades, formacao de condutores, agentes) integram o eixo educacional definido nas CREPOP."}, {"id": "1299671", "d": "psicologia", "a": ["Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à perícia psicológica de candidatos à Carteira\nNacional de Habilitação e de condutores de veículos\nautomotores, julgue os itens que se seguem.    I. Os candidatos à Carteira Nacional de Habilitação e os\ncondutores de veículos automotores deverão ser\navaliados, ao menos, nos aspectos cognitivos, no juízo\ncrítico, no comportamento e em traços de\npersonalidade.   II. A entrevista psicológica é uma conversação dirigida a\num propósito definido da perícia, que visa a prover o\npsicólogo de subsídios técnicos acerca da conduta, dos\ncomportamentos, dos conceitos, dos valores e das\nopiniões do candidato. Deve ser planejada e\nsistematizada a partir de indicadores objetivos de\navaliação, correspondentes ao que pretende examinar,\ne possui caráter inicial obrigatório.   III. Os aspectos cognitivos mínimos a serem avaliados são:\ninteligência; atenção dividida; atenção alternada;\nmemória de longa duração; e atenção concentrada.   IV. O psicólogo deverá obter informações a respeito do\nhistórico do candidato com relação a acidentes de\ntrânsito e opiniões sobre cidadania e mobilidade\nhumana e urbana.   V. Para ser devidamente realizada, a perícia psicológica\nprecisa de que o perito verifique as normas relativas ao\ngrupo de referência à qual pertencem os sujeitos\navaliados, pois elas podem variar de acordo com a\népoca, os costumes e a evolução da cultura.     Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e IV estão certos.", "B": "Apenas os itens I, IV e V estão certos.", "C": "Apenas os itens II, III e IV estão certos.", "D": "Apenas os itens II, IV e V estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas I, IV e V corretos. Item III erra ao listar 'memoria de LONGA duracao' entre os aspectos cognitivos minimos - a norma exige outras funcoes (memoria recente). Item II afirma que entrevista 'possui carater inicial obrigatorio' - incorreto na Res 425/2012 (a entrevista nao tem etapa unica obrigatoria)."}, {"id": "1299669", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Considerando as regras estabelecidas na Resolução CFP n.ᵒ\n6/2019 para a elaboração de documentos, em decorrência\nda perícia psicológica para o trânsito, pelo psicólogo, no\nexercício profissional, assinale a alternativa incorreta.", "alt": {"A": "O documento a ser elaborado após uma perícia\npsicológica para fins de obtenção da Carteira Nacional\nde Habilitação resulta de uma avaliação psicológica e é\nresponsabilidade do psicólogo atestar somente o que\nfoi verificado no processo de avaliação e esteja dentro\ndo âmbito de sua competência profissional.", "B": "Os Conselhos Regionais podem solicitar ao psicólogo a\napresentação da fundamentação técnico-científica do\ndocumento elaborado após a perícia psicológica dentro\nde um prazo de até cinco anos.", "C": "No documento elaborado, é preciso constar a\ndescrição das condições psicológicas do beneficiário do\nserviço psicológico advindas do raciocínio psicológico\nou do processo de avaliação psicológica realizado,\nrespondendo à finalidade deste.", "D": "Sendo o atestado uma peça de natureza e valor\ntécnico-científico, deve conter narrativa detalhada e\ndidática, com precisão e harmonia. A linguagem\nutilizada deve ser acessível e compreensível ao\ndestinatário, respeitando os preceitos do Código de\nÉtica Profissional do psicólogo.", "E": "Quando justificadamente necessário, fica facultado ao\npsicólogo o uso da Classificação Internacional de\nDoenças (CID) ou outras classificações de diagnóstico,\ncientífica e socialmente reconhecidas, como fonte para\no enquadramento de diagnóstico."}, "g": "D", "j": "Questao pede INCORRETA. Res CFP 6/2019 distingue ATESTADO (breve, conciso, afirmativo) de LAUDO/RELATORIO (detalhados, didaticos). A alternativa D atribui ao atestado caracteristicas que sao do laudo/relatorio. Demais alternativas reproduzem corretamente a resolucao."}, {"id": "1299665", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "O Conselho Federal de Psicologia, em documento no qual\nestabelece diretrizes para a realização de avaliação\npsicológica no exercício profissional do psicólogo e\nregulamenta o Satepsi (Resolução n.ᵒ 9/2018), define várias\nnormas profissionais. Com relação a elas, julgue os itens a\nseguir.     I. Ao psicólogo, na produção, validação, tradução,\nadaptação, normatização, comercialização e aplicação\nde testes psicológicos, é vedado realizar atividades que\ncaracterizem negligência, preconceito, exploração,\nviolência, crueldade ou opressão.  II. Os psicólogos poderão elaborar, validar, traduzir,\nadaptar, normatizar, comercializar e fomentar\ninstrumentos ou técnicas psicológicas para criar,\nmanter ou reforçar convicções políticas, filosóficas,\nmorais ou ideológicas.III. O psicólogo, na realização de estudos, pesquisas e\natividades voltadas para a produção de conhecimento\ne desenvolvimento de tecnologias, atuará\nconsiderando processos de desenvolvimento humano,\nconfigurações familiares, conjugalidade, sexualidade,\norientação sexual, identidade de gênero, identidade\nétnico-racial, características das pessoas com\ndeficiência, classe social e intimidade como\nconstruções sociais, históricas e culturais.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens I e III estão certos."}, "g": "E", "j": "Apenas I e III corretos. Item II inverte regra da Res CFP 9/2018 - e VEDADO ao psicologo usar instrumentos para criar/manter convicoes politicas, filosoficas, morais ou ideologicas. Itens I (vedacao a negligencia e preconceitos) e III (consideracao de diversidade) reproduzem a norma."}, {"id": "1299663", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere aos marcos históricos da psicologia do\ntrânsito no Brasil, assinale a alternativa incorreta.", "alt": {"A": "A implantação do laboratório de psicotécnica da\nEstrada de Ferro Sorocabana possibilitou as primeiras\navaliações de condutores de que se teve conhecimento\nem 1928.", "B": "Resolução do Contran tornou obrigatório, em 1953, o\nexame psicotécnico, no Brasil, para todos os\ncandidatos à profissão de motorista.", "C": "Em 1962, o exame psicotécnico passou a ser exigido\npara todos os candidatos à Carteira Nacional de\nHabilitação.", "D": "No ano de 1997, foi vetada a avaliação psicológica no\nCódigo de Trânsito Brasileiro, sendo proibida a sua\nrealização em todo o País. Assim, por quatro meses,\nnão houve avaliação psicológica para obtenção da\nCarteira Nacional de Habilitação.", "E": "O Contran publicou, em 1998, a primeira resolução que\nespecificamente dispunha sobre a avaliação psicológica\nno contexto do trânsito."}, "g": "D", "j": "Questao pede INCORRETA. A avaliacao psicologica nao foi vetada por 4 meses em 1997 - o CTB (Lei 9.503/1997) manteve a previsao, ainda que tenha havido debates regulatorios. Demais marcos historicos (Sorocabana 1928, Contran 1953, CNH 1962, resolucao Contran 1998) sao corretos."}, {"id": "1299662", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "Não são citados no roteiro de entrevista psicológica do\npsicólogo do trânsito sugerido na Resolução Contran n.ᵒ\n425/2012 os", "alt": {"A": "motivos da avaliação psicológica.", "B": "históricos escolares, profissionais e familiares.", "C": "aspectos culturais e religiosos.", "D": "indicadores de saúde/doença.", "E": "aspectos da conduta social."}, "g": "C", "j": "Roteiro de entrevista psicologica do psicologo do transito sugerido na Res Contran 425/2012 inclui motivos da avaliacao, historicos escolares/profissionais/familiares, indicadores de saude/doenca e aspectos da conduta social - NAO menciona explicitamente aspectos culturais e religiosos."}, {"id": "1299659", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "Não corresponde às regulamentações do Contran e do\nConselho Federal de Psicologia para o credenciamento e o\nexercício profissional do psicólogo perito examinador na\navaliação psicológica de candidatos à Carteira Nacional de\nHabilitação, atualmente,", "alt": {"A": "estar regularmente inscrito no respectivo Conselho\nRegional há pelo menos dois anos.", "B": "aplicar os testes psicológicos em uma sala de teste\nindevassável, de forma a evitar interferência ou\ninterrupção na execução das tarefas dos candidatos.", "C": "ter título de especialista em psicologia do trânsito\nreconhecido pelo Conselho Federal de Psicologia.", "D": "possuir, no mínimo, três anos de formado.", "E": "estar devidamente credenciado junto ao órgão\nexecutivo de trânsito do estado ou do Distrito Federal."}, "g": "D", "j": "Tempo minimo de formado nao integra as regulamentacoes do Contran/CFP para credenciamento de perito - exigem-se inscricao no CRP ha 2+ anos, titulo de especialista, sala indevassavel e credenciamento no orgao executivo de transito."}, {"id": "1299657", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "A Resolução CFP n.ᵒ 16/2002 dispõe acerca do trabalho do\npsicólogo na avaliação psicológica de candidatos à Carteira\nNacional de Habilitação e de condutores de veículos\nautomotores. Sendo assim, assinale a alternativa incorreta\nconforme essa Resolução.", "alt": {"A": "A avaliação psicológica de candidatos à Carteira\nNacional de Habilitação e de condutores de veículos\nautomotores poderá ser realizada em centros de\nformação de condutores ou em qualquer outro local,\npúblico ou privado, cujos agentes tenham interesse no\nresultado dos exames psicológicos, dada sua natureza\npericial.", "B": "É importante que todos os exames de avaliação\npsicológica sejam distribuídos imparcialmente, por\nmeio de divisão equitativa, aleatória e impessoal entre\nas entidades credenciadas na área de jurisdição do\nórgão executivo do trânsito.", "C": "Nos locais para a realização das avaliações psicológicas\npara candidatos à Carteira Nacional de Habilitação e\ncondutores de veículos automotores, poderão ser\nrealizados, também, exames de sanidade física e\nmental.", "D": "Aos psicólogos peritos responsáveis pela avaliação\npsicológica fica vedado estabelecer qualquer vínculo\ncom os centros de formação de condutores, seja como\npessoa física, seja como pessoa jurídica.", "E": "Há a necessidade de normatização e qualificação de\nprocedimentos relacionados à prática da avaliação\npsicológica de candidatos à Carteira Nacional de\nHabilitação e de condutores de veículos automotores."}, "g": "A", "j": "Questao pede INCORRETA. Res CFP 16/2002 exige imparcialidade da avaliacao pericial; locais com 'interesse no resultado dos exames' contrariam o principio. Demais alternativas (B, C, D, E) reproduzem a resolucao quanto a distribuicao impessoal, exames concomitantes, vedacao de vinculo do perito e qualificacao de procedimentos."}, {"id": "1299654", "d": "psicologia", "a": ["Psicologia do Trânsito", "Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Hoffmann e Cruz (2003), o passo inicial para se\nrealizar uma pesquisa sobre o comportamento humano no\ntrânsito consiste em", "alt": {"A": "analisar os testes psicológicos aprovados pelo ConselhoFederal de Psicologia para aplicação.", "B": "definir variáveis a serem descartadas.", "C": "identificar o fenômeno que se quer investigar.", "D": "escolher a(s) técnica(s) para coleta de dados.", "E": "realizar o tratamento estatístico."}, "g": "C", "j": "Hoffmann e Cruz (2003) - o passo inicial de uma pesquisa sobre comportamento no transito e a identificacao do fenomeno a ser investigado, antes de definir variaveis, instrumentos e analises."}, {"id": "1299652", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com a Resolução CFP n.ᵒ 1/2019, assinale a\nalternativa incorreta a respeito de perícia psicológica.", "alt": {"A": "Utiliza-se de estratégias psicológicas reconhecidas pela\npsicologia.", "B": "É um processo técnico-científico de coleta de dados,\nestudos e interpretação de informações acerca dos\nfenômenos psicológicos resultantes da relação do\nindivíduo com a sociedade.", "C": "Deve ser realizada por psicólogo qualificado no\nassunto.", "D": "É uma avaliação psicológica direcionada a responder\numa demanda legal específica.", "E": "É uma técnica psicológica que deve ser realizada\nindividualmente, com o uso de testes psicológicos."}, "g": "E", "j": "Questao pede INCORRETA. Pericia psicologica e processo de AVALIACAO (nao tecnica isolada), pode ser individual ou coletiva e nao requer obrigatoriamente testes psicologicos. Demais alternativas reproduzem corretamente a Res CFP 1/2019."}, {"id": "1299651", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "A Resolução CFP n.ᵒ 13/2007 define as especialidades a\nserem concedidas pelo Conselho Federal de Psicologia. À\nluz dessa Resolução, assinale a alternativa incorreta.", "alt": {"A": "O psicólogo do trânsito elabora e aplica técnicas de\nmensuração das aptidões, habilidades e capacidades\npsicológicas dos condutores e candidatos à habilitação,\natuando, quando necessário, em equipes\nmultiprofissionais, para aplicar os métodos de\ndiagnóstico.", "B": "O psicólogo do trânsito desenvolve estudos sobre o\nfator humano para favorecer a elaboração e a\naplicação de medidas de punição aos condutores\ninfratores.", "C": "O psicólogo do trânsito realiza pesquisas científicas no\ncampo dos processos psicológicos, psicossociais e\npsicofísicos para elaborar e implantar programas de\nsaúde, educação e segurança do trânsito.", "D": "O psicólogo do trânsito colabora na elaboração e na\nimplantação de ações de engenharia e operação de\ntráfego.", "E": "O psicólogo do trânsito realiza o diagnóstico da\nestrutura dinâmica dos indivíduos e grupos nos\naspectos afetivos, cognitivos e comportamentais."}, "g": "B", "j": "Questao pede INCORRETA. O psicologo do transito NAO elabora medidas de PUNICAO a infratores - sua atribuicao e tecnico-cientifica (avaliacao, pesquisa, prevencao, educacao). Demais alternativas descrevem corretamente o escopo da especialidade conforme Res CFP 13/2007."}, {"id": "1299650", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca dos princípios fundamentais da ética profissional,\nassinale a alternativa incorreta.", "alt": {"A": "O psicólogo atuará com responsabilidade, por meio do\ncontínuo aprimoramento profissional, contribuindo\npara o desenvolvimento da psicologia como campo\ncientífico de conhecimento e de prática.", "B": "O psicólogo zelará para que o exercício profissional seja\nefetuado com dignidade, rejeitando situações em que\na psicologia esteja sendo aviltada.", "C": "O psicólogo trabalhará visando a promover a saúde e a\nqualidade de vida das pessoas e das coletividades e\ncontribuirá para a eliminação de quaisquer formas de\nnegligência, discriminação, exploração, violência,\ncrueldade e opressão.", "D": "O psicólogo contribuirá para promover o sigilo\nprofissional e evitar o acesso da população às\ninformações, ao conhecimento da ciência psicológica,\naos serviços e aos padrões éticos da profissão", "E": "O psicólogo atuará com responsabilidade social,\nanalisando, crítica e historicamente, a realidade\npolítica, econômica, social e cultural."}, "g": "D", "j": "Questao pede INCORRETA. O CEP do psicologo determina justamente PROMOVER o acesso da populacao a informacoes, conhecimento e servicos psicologicos, nao evita-lo. Demais alternativas reproduzem corretamente os principios fundamentais (responsabilidade, dignidade, qualidade de vida, responsabilidade social)."}, {"id": "1299648", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo o Plano Nacional de Redução de Mortes e Lesões no\nTrânsito (PNATRANS), os acidentes de trânsito são\nreconhecidos pela Organização Mundial de Saúde (OMS) como\num grave problema de saúde pública e uma das principais\ncausas de mortes e de lesões em todo o mundo. Além do\nelevado custo para os serviços de saúde e para as economias\ndos países, podendo atingir de 1% a 3% do produto interno\nbruto (PIB), os acidentes de trânsito desencadeiam diversos\ntraumas para a sociedade e para as relações sociais, além de\nacarretar a perda precoce de vidas. Com base nessas\ninformações, assinale a alternativa incorreta.", "alt": {"A": "Para que o enfrentamento aos acidentes de trânsito\nseja eficaz, a política de segurança viária deve contar\ncom o empenho de todos os setores e a\nresponsabilidade deve ser compartilhada entre os\nvários atores sociais: o Poder Executivo; o Poder\nLegislativo; o Poder Judiciário; os órgãos e as entidades\npertencentes ao Sistema Nacional de Trânsito; os\nsetores de saúde, transporte e indústria\nautomobilística; as organizações não governamentais;\ne a sociedade.", "B": "A segurança viária envolve a responsabilidade quanto à\nmobilidade das pessoas e dos veículos na via, bem\ncomo a complexa dinâmica de compartilhamento de\nespaço e o estabelecimento de normas de circulação\ncom o objetivo de proteger os usuários e evitar\nreflexos negativos em todo o aparato estatal.", "C": "O desenvolvimento desordenado das cidades, com vias\npouco interconectadas, ocasiona melhoria à\nmobilidade urbana, com o aumento da velocidade nas\nvias que atendem a necessidade de maior rapidez de\ndeslocamento.", "D": "A evolução da segurança viária no Brasil deve\nconsiderar o desenvolvimento de um sistema de\ntrânsito que seja capaz de acomodar o erro humano\ncom a maior margem de segurança possível, levando\nem consideração a vulnerabilidade do corpo humano.", "E": "O trânsito deve facilitar a circulação de pessoas e bens\ne melhorar o acesso à educação, aos serviços de saúde,\nao emprego e ao desenvolvimento."}, "g": "C", "j": "Questao pede INCORRETA. O desenvolvimento desordenado das cidades NAO melhora a mobilidade urbana - ao contrario, agrava congestionamentos e inseguranca viaria. Demais alternativas (PNATRANS) reproduzem corretamente a logica multissetorial, vulnerabilidade humana e funcao social do transito."}, {"id": "1299647", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicologia ambiental pode ser definida como o estudo da\nrelação recíproca entre as pessoas e seu ambiente\n(Günther, 2009). No livro Pesquisas sobre comportamento\nno trânsito (2015), Günther e Neto tratam de como a\npsicologia ambiental investiga os eventos que ocorrem no\ntrânsito. Sendo assim, assinale a alternativa que não\napresenta uma estratégia utilizada pela psicologia\nambiental na investigação dos eventos ocorridos no\ntrânsito.", "alt": {"A": "abordagem holística", "B": "enfoque multimétodo", "C": "abordagem multidisciplinar", "D": "abordagem unidimensional", "E": "pesquisa-ação"}, "g": "D", "j": "Psicologia ambiental opera por abordagens holistica, multimetodo, multidisciplinar e pesquisa-acao. 'Abordagem unidimensional' contradiz a logica de complexidade que orienta o campo."}, {"id": "1299646", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito"], "ano": "2020", "org": "CFP", "t": "", "e": "Na Resolução n.ᵒ 425/2012, o Conselho Nacional de\nTrânsito (Contran) estabeleceu os instrumentos e as\ntécnicas que deverão ser utilizadas no processo de\navaliação psicológica. Quanto a esse tema, assinale a\nalternativa correta.", "alt": {"A": "Utilizam-se dinâmicas de grupo, testes psicológicos,\nque deverão estar de acordo com as resoluções\nvigentes do Conselho Federal de Psicologia, e escutas.", "B": "Utilizam-se entrevistas diretas, individuais e coletivas,\ntestes psicológicos, que deverão estar de acordo com\nas resoluções vigentes do Conselho Federal de\nPsicologia, e intervenções verbais.", "C": "Utilizam-se testes psicológicos, que deverão estar de\nacordo com as resoluções vigentes do Conselho\nFederal de Psicologia, entrevistas diretas, individuais e\ncoletivas, e dinâmicas de grupo.", "D": "Utilizam-se escutas e intervenções verbais, entrevistas\ndiretas e individuais, testes psicológicos, que deverão\nestar de acordo com as resoluções vigentes do\nConselho Federal de Psicologia, e dinâmicas de grupo.", "E": "Utilizam-se entrevistas estruturadas, testes\npsicológicos e inventários."}, "g": "D", "j": "Res Contran 425/2012 lista como instrumentos/tecnicas: escutas, intervencoes verbais, entrevistas diretas individuais, testes psicologicos conforme normas do CFP e dinamicas de grupo. Alternativa D reproduz exatamente esse rol; as demais omitem ou trocam itens."}, {"id": "1299645", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Assinale a alternativa que não apresenta um título\nprofissional de especialista em psicologia reconhecido pelo\nConselho Federal de Psicologia.", "alt": {"A": "neuropsicologia", "B": "psicologia em saúde", "C": "psicologia do trânsito", "D": "psicoterapia", "E": "avaliação psicológica"}, "g": "D", "j": "Especialidades reconhecidas pelo CFP (Res 13/2007 e atualizacoes) incluem neuropsicologia, psicologia em saude, psicologia do transito e avaliacao psicologica. 'Psicoterapia' NAO consta como titulo de especialista isolado - integra a clinica."}, {"id": "1299644", "d": "psicologia", "a": ["Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação à avaliação psicológica, julgue os seguintes\nitens.\n    I. A avaliação psicológica é definida como um processo\nestruturado de investigação de fenômenos\npsicológicos, composto de métodos, técnicas e\ninstrumentos, visando a prover informações para a\ntomada de decisão, no âmbito individual, grupal ou\ninstitucional, com base em demandas, condições e\nfinalidades específicas.\n  II. Os testes psicológicos abarcam, entre outros, os\nseguintes instrumentos: escalas; inventários;\nquestionários; métodos projetivos/expressivos; e\ndocumentos técnicos, protocolos ou relatórios de\nequipes multiprofissionais.\n  III. O profissional da psicologia tem a prerrogativa de\ndecidir quais são os métodos, as técnicas e os\ninstrumentos empregados na avaliação psicológica,\ndesde que devidamente fundamentados na literatura\ncientífica psicológica e nas normativas vigentes do\nConselho Federal de Psicologia.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item III está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (definicao de AP) e III (prerrogativa do psicologo) corretos. Item II e falso ao incluir 'documentos tecnicos, protocolos ou relatorios de equipes multiprofissionais' entre 'testes psicologicos' - sao instrumentos de natureza distinta."}, {"id": "1299633", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicologia da saúde é a aplicação dos conhecimentos e\ndas técnicas psicológicas à saúde, às doenças e aos\ncuidados de saúde, visando à promoção e à manutenção da\nsaúde e à prevenção da doença. Com relação ao trabalho\ndo psicólogo da saúde, assinale a alternativa incorreta.", "alt": {"A": "Os psicólogos da saúde direcionam-se para a\ncompreensão da forma como os fatores biológicos,\ncomportamentais e sociais influenciam a saúde e a\ndoença.", "B": "Podem estar centrados na promoção da saúde e na\nprevenção de doença, trabalhando com os fatores\npsicológicos que fortalecem a saúde e que reduzem o\nrisco de adoecer, podem disponibilizar serviços clínicos\na indivíduos saudáveis ou doentes em diferentes\ncontextos e podem, ainda, estar envolvidos em\npesquisa e investigação, no ensino e na formação.", "C": "A ênfase dos psicólogos da saúde na prevenção, se\nempregada de forma ampla, representa maiores custos\nno sistema de saúde.", "D": "Psicólogos da saúde exercem uma ampla variedade de\natividades, incluindo treinar futuros médicos e\nenfermeiros sobre a importância dos fatores\npsicossociais na adesão do paciente ao tratamento e\nem sua recuperação, além de intervirem diretamente\npra ajudar pacientes que estejam enfrentando\nprocedimentos difíceis.", "E": "É importante que o psicólogo da saúde tenha\nconhecimento sobre avaliação, assessoramento e\nintervenção em saúde, políticas e organização em\nsaúde e colaboração interdisciplinar."}, "g": "C", "j": "Questao pede INCORRETA. A enfase na prevencao REDUZ custos do sistema de saude no medio/longo prazo, ao evitar doencas e complicacoes. Demais alternativas descrevem corretamente o escopo bio-psicossocial e os ambitos de atuacao do psicologo da saude."}, {"id": "1299632", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicologia da saúde possui desafios futuros a fim de\ncontinuar seu crescimento e benefício à população. Quanto\na esses desafios, assinale a alternativa incorreta.", "alt": {"A": "O primeiro desafio é aumentar o tempo de vida\nsaudável das pessoas, desenvolvendo intervenções\neficazes que proporcionem aos adultos mais velhos a\nmanutenção ou a melhoria do nível de funcionamento,\npelo maior número de anos possível.", "B": "O segundo desafio consiste em reduzir as discrepâncias\nde saúde, pensando em atitudes concretas para as\nrazões que as provocam que já conseguiram ser\nextensamente explicadas pelos psicólogos da saúde.", "C": "O terceiro desafio é atingir o mesmo nível de acesso a\nserviços de saúde preventiva para todas as pessoas,\nconsiderando que a reforma do sistema de saúde\ncontinua sendo um desafio permanente para a\npsicologia da saúde e para a política nacional.", "D": "O quarto desafio consiste em ajustar o foco de\npesquisa e intervenção para maximizar a promoção da\nsaúde com abordagens baseadas em evidências,\ncolocando mais ênfase em comportamentos e fatores\nque favoreçam a saúde e que possam retardar a\nmortalidade e reduzir a morbidade.", "E": "O quinto desafio é auxiliar na reforma do atendimento\nde saúde, considerando que a prevenção, a promoção\nou a manutenção da saúde devem ter um papel tão\nimportante no sistema de saúde quanto o tratamento\nde doenças."}, "g": "B", "j": "Questao pede INCORRETA. As razoes das discrepancias de saude NAO foram extensamente explicadas pelos psicologos da saude - permanecem multifatoriais e desafiadoras. Demais desafios (longevidade saudavel, acesso a servicos preventivos, evidencias, reforma do atendimento) sao descritos corretamente."}, {"id": "1299631", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "Em seus anos de existência enquanto campo de\nconhecimento e atuação, a psicologia da saúde\ndesenvolveu lições sobre o processo saúde-doença. A\nrespeito dessas lições, assinale a alternativa correta.", "alt": {"A": "Os fatores psicológicos e sociais interagem com a\nbiologia da saúde. A mensagem fundamental do\nmodelo biopsicossocial é a constatação de que o\ncomportamento, os processos mentais, as influências\nsociais e a saúde estão intimamente conectados.", "B": "Promover e manter a saúde é de responsabilidade de\ntodos, profissionais e pacientes. No cuidado com a\nprópria saúde, a partir das intervenções realizadas, as\npessoas aprendem sobre a importância de realizar\nexames preventivos, aderir ao tratamento receitado e\nter comportamentos saudáveis. Essa consciência\ngarante que as pessoas sigam aquele que sabem ser o\ncurso de ação mais saudável.", "C": "Estilos de vida insalubres são mais difíceis de mudar\nque de prevenir e, por essa razão, a alta prioridade da\npsicologia da saúde está em mudar maus hábitos de\nsaúde já instalados na comunidade.", "D": "A avaliação e o manejo do estresse são essenciais para\numa boa saúde. Uma das ações da psicologia da saúde\nna área do estresse foi a manutenção da controvérsia\nem relação ao caráter interno ou externo do estresse.", "E": "Entende-se que cada um dos eventos estressantes da\nvida é avaliado como um obstáculo ameaçador, o qual\nnão pode ser administrado."}, "g": "A", "j": "O modelo biopsicossocial e licao central da psicologia da saude: comportamento, processos mentais, influencias sociais e biologia estao intimamente conectados. Demais alternativas trazem afirmacoes categoricas e equivocadas (consciencia GARANTE adesao, foco apenas em maus habitos, manutencao de controversia, eventos sempre nao manejaveis)."}, {"id": "1299630", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "As intervenções psicológicas para a preparação para a\nhospitalização podem oferecer maior segurança ao\npaciente nesta etapa do tratamento. Acerca desse assunto,\nassinale a alternativa incorreta.", "alt": {"A": "As intervenções mais eficazes são aquelas que\naumentam a sensação de controle dos pacientes sobre\no tratamento e a recuperação.", "B": "As intervenções de controle informacional referem-se\nao conhecimento dos pacientes em relação aos\nprocedimentos e às sensações físicas que acompanham\no tratamento médico, e suas reações dependem, em\nparte, de seu estilo de enfrentamento.", "C": "As intervenções de controle cognitivo direcionam a\natenção do paciente para os possíveis aspectos\nnegativos de um procedimento, preparando\nestratégias de enfrentamento.", "D": "Diversas intervenções visando ao controle cognitivo\nincorporam a visualização guiada, na qual os pacientes\nensaiam instruções para influenciar mentalmente a\npercepção da dor, o fluxo de sangue, o funcionamento\nimunológico e outros processos capazes de interferir\nem sua recuperação.", "E": "As intervenções de controle comportamental ensinam\ntécnicas para controlar a dor e acelerar a recuperação\ndurante um procedimento médico e depois. Elas\npodem incluir instruções para relaxamento, exercícios\nde respiração e outros métodos para reduzir o\ndesconforto."}, "g": "C", "j": "Questao pede INCORRETA. Intervencoes de controle cognitivo direcionam a atencao para aspectos POSITIVOS ou neutros (visualizacao, foco em recuperacao), nao para os negativos do procedimento. Demais alternativas descrevem corretamente controles informacional, cognitivo e comportamental."}, {"id": "1299629", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Muitos tratamentos em saúde envolvem a hospitalização,\nque pode provocar uma variedade de sintomas psicológicos\nadversos. Com relação a esse tema, assinale a alternativa\ncorreta.", "alt": {"A": "A maneira como o paciente se adapta à experiência\nhospitalar depende de uma variedade de fatores, como\na idade e o apoio emocional, e independe da natureza\ndo problema de saúde.", "B": "Ao entrarem no hospital, os pacientes podem sentir a\ndespersonalização, pois estão sendo absorvidos por\numa instituição que assume o controle de\npraticamente todos os aspectos de sua vida e\ncomeçam a ser tratados como uma não pessoa, o que\npode fazer da hospitalização uma experiência\nestressante.", "C": "Pacientes hospitalizados podem manifestar uma\ntentativa de atribuir culpa por sua sina. Psicólogos da\nsaúde têm verificado que, quanto mais os pacientes se\npreocupam em atribuir culpa por suas doenças a si\nmesmos ou a outras pessoas, melhor é sua adaptação\nemocional.", "D": "As crianças lidam com o estresse da hospitalização de\nmaneira semelhante à maneira como os adultos lidam,\nnão exigindo tratamento diferenciado da equipe de\nprofissionais da saúde.", "E": "As crianças, assim como os adultos, com frequência,\nusam estratégias de enfrentamento mais eficazes para\nsi mesmas do que as que recomendariam a um amigo\nque lidasse com fatores estressores semelhantes."}, "g": "B", "j": "Despersonalizacao - o paciente e absorvido pela instituicao que assume controle de quase tudo - e um dos fenomenos centrais da hospitalizacao como evento estressante. Demais alternativas contradizem evidencias (adaptacao depende da natureza do problema, culpa nao melhora adaptacao, criancas tem necessidades especificas)."}, {"id": "1299628", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade"], "ano": "2020", "org": "CFP", "t": "", "e": "O relacionamento entre o profissional de saúde e o\npaciente é a base do tratamento. Quanto aos elementos\ndessa relação, assinale a alternativa incorreta.", "alt": {"A": "Os elementos centrais do relacionamento entre o\nprofissional de saúde e o paciente são a continuidade\ndo atendimento, a comunicação e a qualidade geral\ndas consultas.", "B": "As variáveis que podem prejudicar a comunicação\nentre profissional e paciente são a pressão do tempo\npara o atendimento, poucas habilidades comunicativas\nde ambas as partes, crenças de pacientes e\nprofissionais em relação a seus papéis e diferenças de\ngênero, cultura e educação.", "C": "A comunicação eficaz garante que o profissional da saúde\nentenda os sintomas dos pacientes e que o paciente\nreceba e siga as informações e as instruções do\ntratamento.", "D": "O modelo tradicional do relacionamento\npaciente-profissional da saúde indica o profissional\ncomo ativo e os pacientes como essencialmente\npassivos e tem sido o modelo que sustenta maior\nadesão ao tratamento.", "E": "Os profissionais de saúde, cada vez mais, entendem\nque os pacientes seguem instruções e respondem bem\nao tratamento quando seu conhecimento é\nreconhecido e incorporado ao regime terapêutico."}, "g": "D", "j": "Questao pede INCORRETA. O modelo TRADICIONAL (ativo/passivo) sustenta MENOR adesao, nao maior - o paradigma contemporaneo de relacionamento colaborativo/participativo e o que melhora os resultados. Demais alternativas descrevem corretamente os elementos da relacao profissional-paciente."}, {"id": "1299627", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "Um fator importante para os cuidados em saúde é a adesão ao\ntratamento, que é definida, de forma ampla, como o\nseguimento da orientação de um profissional de saúde. Os\npsicólogos da saúde podem contribuir com tal fator. No que\nconcerne às variáveis que preveem a adesão ao tratamento,\nassinale a alternativa incorreta.", "alt": {"A": "Dentre as variáveis do paciente que afetam a adesão\nao tratamento, apresentar expectativas otimistas, ter\nconfiança no profissional e ter o apoio da família e dos\namigos são fatores importantes para a adesão ao\ntratamento.", "B": "As variáveis do profissional de saúde, como o nível de\nsatisfação do médico com o trabalho e o estilo de\ncomunicação, podem afetar a adesão do paciente ao\ntratamento.", "C": "As variáveis do regime de tratamento são importantes\npara a adesão a ele. Quando o tratamento é\nconsiderado como útil, a capacidade do paciente de\nexecutar o regime depende do grau de dificuldade e do\napoio disponível. Quanto mais complexo o regime de\ntratamento, menor a adesão.", "D": "Os profissionais da saúde podem realizar várias\nmedidas para aumentar a adesão de pacientes, como\nprogramar o tratamento de acordo com o estilo de\nvida do paciente e não envolver familiares, amigos e\noutras pessoas no tratamento, a fim de preservá-lo.", "E": "No centro do relacionamento entre paciente e\nprofissional, estão a natureza e a qualidade da\ncomunicação. Profissionais da saúde que são bons\ncomunicadores tendem a ter pacientes com maior\nprobabilidade de aderir às recomendações."}, "g": "D", "j": "Questao pede INCORRETA. Envolver familiares e amigos AUMENTA a adesao ao tratamento - a alternativa D recomenda o oposto, contrariando a literatura. Demais alternativas listam corretamente variaveis do paciente, do profissional e do regime que afetam adesao."}, {"id": "1299626", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "O processo de tomada de decisão de procurar cuidados\nmédicos é composto por cinco estágios, durante os quais\npodem ocorrer comportamentos de demora na busca de\ntratamento. A respeito desses estágios, assinale a\nalternativa correta.", "alt": {"A": "As pessoas podem evitar procurar atenção médica\nporque os sintomas podem passar despercebidos,\ncausando uma demora na avaliação, estágio no qual a\nproeminência sensorial dos sintomas é o fator mais\nimportante.", "B": "No estágio da demora na aceitação da doença, a\ndoença parece improvável e a experiência anterior com\nos sintomas pode influenciar. Indivíduos que já\nexperimentaram sintomas semelhantes anteriormente\ntêm menor probabilidade de buscar atenção médica\nque aqueles que os experienciam pela primeira vez.", "C": "No terceiro estágio, a demora comportamental, a\najuda profissional é considerada como necessária,\nporém o indivíduo ainda não se comporta de modo a\nbuscar essa ajuda.", "D": "O estágio da demora na marcação de consulta indica\nque os benefícios percebidos do tratamento não\nsuperam seu custo.", "E": "Nos últimos três estágios, a demora para busca de\ntratamento é mais longa para pacientes com pouca dor\ne com dúvidas sobre a cura de seus sintomas e\nindepende dos gastos do tratamento."}, "g": "A", "j": "Na demora na avaliacao (primeiro estagio), a proeminencia sensorial dos sintomas e fator central para o reconhecimento da doenca. Demais alternativas trocam logicas (experiencia anterior aumenta busca; estagios e demoras tem outros determinantes), com afirmacoes invertidas."}, {"id": "1299624", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicologia da saúde atenta-se para a visão pessoal do\nindivíduo sobre sua saúde e sua doença como fatores que\ninfluenciam seu comportamento. A representação da\ndoença afeta a saúde, influenciando o comportamento\npreventivo e a reação ao surgimento de sintomas. Acerca\ndos componentes da representação da doença (identidade,\ncausas, consequências, curso e grau de controle), assinale a\nalternativa correta.", "alt": {"A": "A identidade da doença diz respeito a seu rótulo e a\nseus sintomas. Parece haver uma relação simétrica\nentre o rótulo de uma doença e seus sintomas. Todas\nas condições médicas são construídas por forças\nbiológicas, não sendo o diagnóstico e a identidade da\ndoença influenciados pela cultura e pelas construções\nsociais.", "B": "O grau de controle indica as crenças relacionadas com\na possibilidade de a doença ser prevenida, controlada\ne(ou) curada. Se o paciente considerar a doença como\nincurável, pode faltar a consultas, negligenciar o\ntratamento ou até mesmo agir de maneira\nautodestrutiva.", "C": "O paciente pode atribuir a causa da doença a fatores\nexternos ou a fatores internos, o que não influencia no\nmodo de busca ao tratamento.", "D": "O curso da doença indica a duração e a velocidade do\ndesenvolvimento da doença. Com frequência,\npacientes que acreditam que sua doença seja aguda\npersistem mais no tratamento que aqueles que\nacreditam que sua doença seja crônica.", "E": "As consequências são o impacto físico, social e\neconômico da doença. Pacientes buscam mais o\ntratamento a partir de sintomas que os perturbam em\nníveis mínimos."}, "g": "B", "j": "Grau de controle e o componente da representacao da doenca ligado a crencas sobre prevencao, controle e cura - se incuravel, o paciente pode negligenciar tratamento. Demais alternativas distorcem componentes (identidade so biologica, causas sem efeito, curso invertido, consequencias com niveis minimos)."}, {"id": "1299622", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Doenças Crônico-Degenerativas"], "ano": "2020", "org": "CFP", "t": "", "e": "Os psicólogos da saúde estão cada vez mais envolvidos no\ntratamento das doenças e das condições crônicas. Quanto a\nesse assunto, assinale a alternativa incorreta.", "alt": {"A": "Em doenças cardiovasculares, as intervenções voltadas\npara a hostilidade ajudam as pessoas a adquirir\ncontrole sobre os fatores ambientais que\ndesencadeiam a raiva, prevenindo recaídas nos\nsintomas.", "B": "No caso do diabetes, o papel da psicologia da saúde\ninclui estudar fatores que contribuam ou atrapalhem a\nadaptação à condição.", "C": "Os psicólogos da saúde atuam no tratamento primário\ndo diabetes, reduzindo o caráter invasivo da doença e\naumentando a capacidade de se controlar o peso e de\nse manejar o estresse.", "D": "Uma variedade de intervenções psicossociais tem sido\nutilizada para auxiliar os pacientes no enfrentamento\ndo câncer. Nessas intervenções, os psicólogos da saúde\nentendem que é necessário evitar oferecer\ninformações sobre os processos e as etapas do\ntratamento, pois estas produzem um efeito negativo\nno paciente, prejudicando sua adesão.", "E": "Os psicólogos da saúde desempenham diversos papéis\nna batalha contra a Aids, incluindo orientar as pessoas\nsobre como fazer exames para HIV e sobre como\nmodificar comportamentos de alto risco e ajudar\npacientes com Aids a enfrentar perturbações\nemocionais e cognitivas."}, "g": "D", "j": "Questao pede INCORRETA. Intervencoes psicossociais para pacientes com cancer DEVEM oferecer informacoes claras sobre processos e etapas do tratamento - isso AUMENTA adesao e reduz angustia, nao a piora. Demais alternativas descrevem corretamente atuacao em cardiovasculares, diabetes e HIV/Aids."}, {"id": "1299618", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde Coletiva"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação à ação do psicólogo da saúde em saúde\ncoletiva, assinale a alternativa incorreta.", "alt": {"A": "O trabalho em saúde coletiva tem como objeto a\nrelação dos indivíduos no território, sendo seu sujeito\num indivíduo inserido nessa coletividade.", "B": "O processo de trabalho do psicólogo é essencialmente\nindividual, não havendo inter-relação com outros\nprofissionais.", "C": "A saúde coletiva traz ao psicólogo a exigência de uma\nclínica ampliada, que considera a interação, o conflito e\no convívio em torno do paciente.", "D": "Atuar com uma clínica ampliada em saúde coletiva é\nlidar com a interioridade psicológica do sujeito e com a\nrede de subjetividade que o envolve.", "E": "Na atuação em saúde pública, o psicólogo encontra\nclientes que lhe apresentam a vida em toda a sua\ncomplexidade, exigindo do profissional uma formação\nque vai além da patologia."}, "g": "B", "j": "Questao pede INCORRETA. O trabalho do psicologo em saude coletiva e ESSENCIALMENTE INTERDISCIPLINAR e ARTICULADO com outros profissionais e com o territorio, nao individual e isolado. Demais alternativas descrevem corretamente clinica ampliada e atuacao coletiva."}, {"id": "1299617", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "O modelo biopsicossocial da saúde não se limita a\nindivíduos. A pesquisa sobre a psicologia da saúde tem se\nconcentrado, cada vez mais, nos diversos sistemas externos\nque influenciam a saúde do indivíduo. Acerca desse tema,\nassinale a alternativa incorreta.", "alt": {"A": "O principal sistema externo que influencia a saúde do\nindivíduo é a família. O contexto social da família tem\nforte influência sobre comportamentos de risco à\nsaúde.", "B": "A comunidade é uma força poderosa para promover ou\ndesencorajar uma vida saudável.", "C": "As pessoas têm menor probabilidade de adotar\ncomportamentos que promovam a saúde quando eles\nsão defendidos por organizações comunitárias.", "D": "A psicologia da saúde comunitária concentra-se na\ncomunidade como unidade de intervenção,\nreconhecendo que os indivíduos fazem parte de uma\nfamília e de contextos culturais, econômicos e\ncomunitários.", "E": "Os psicólogos da saúde costumam defender políticas\npúblicas que promovam a justiça social, os direitos\nhumanos e a igualdade no acesso a tratamentos de\nsaúde."}, "g": "C", "j": "Questao pede INCORRETA. Comportamentos defendidos por organizacoes comunitarias aumentam (nao reduzem) a probabilidade de adocao por individuos - efeito da influencia social. Demais alternativas reproduzem corretamente o papel de familia, comunidade, psicologia comunitaria e politicas publicas."}, {"id": "1299616", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "No que concerne à prevenção e à intervenção terciárias,\nassinale a alternativa correta.", "alt": {"A": "A prevenção terciária inclui o seguimento de pacientes\nem tratamento clínico, exceto em casos de tratamento\ncirúrgico.", "B": "A prevenção terciária não engloba a orientação e o\npreparo dos familiares do paciente.", "C": "A intervenção de terceiro nível, no âmbito da\npsicologia da saúde, não inclui a pesquisa como uma de\nsuas atividades.", "D": "Os psicólogos da saúde podem, na intervenção\nterciária, atuar nas urgências psicológicas por meio de\nplantões em serviços substitutivos aos hospitais\npsiquiátricos.", "E": "A atuação do psicólogo em intervenção terciária\nengloba apoio e orientação a pacientes internados e a\nseus familiares, excluindo os casos que estão em\nunidade de terapia intensiva, que são amparados\napenas por outras especialidades."}, "g": "D", "j": "Na intervencao terciaria, psicologos da saude atuam em urgencias psicologicas, inclusive em plantoes de servicos substitutivos aos hospitais psiquiatricos (CAPS, UPA etc.). Demais alternativas excluem indevidamente cirurgia, familiares, pesquisa ou UTI do escopo terciario."}, {"id": "1299615", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "A respeito da prevenção e da intervenção secundárias,\nassinale a alternativa incorreta.", "alt": {"A": "O principal objetivo da prevenção secundária é dar\nacompanhamento ao paciente, ajudando-o no\nseguimento de seu tratamento, seja físico ou\npsicológico, com o objetivo de prevenir o agravamento\nda doença.", "B": "Para atuar bem nesse nível de prevenção, os psicólogos\nda saúde devem utilizar o conhecimento produzido por\nmeio das investigações das causas e dos fatores\nassociados à falta de adesão ao tratamento.", "C": "A intervenção secundária possui um fundamento\nteórico/prático bem sedimentado na psicologia clínica.", "D": "Entre as atividades compatíveis com a intervenção\nsecundária, cabe aos psicólogos oferecer as\nassistências psicoterápicas, em suas várias\nmodalidades, em todas as idades.", "E": "Na intervenção secundária, não cabe ao psicólogo da\nsaúde realizar diagnósticos diferenciais mediante o uso\nde testes ou por meio de diagnósticos descritivos\nfenomenológicos."}, "g": "E", "j": "Questao pede INCORRETA. Cabe ao psicologo da saude realizar diagnosticos diferenciais e descritivos fenomenologicos na intervencao secundaria - sao parte essencial do trabalho clinico. Demais alternativas descrevem corretamente acompanhamento, adesao, fundamentos e psicoterapia."}, {"id": "1299614", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à prevenção e à intervenção primárias, assinale a\nalternativa incorreta.", "alt": {"A": "A prevenção primária deve estar diretamente\nrelacionada e condicionada à promoção da saúde. Suas\nações devem ser direcionadas a um único indivíduo,\ntendo como suporte conteúdos de outras áreas de\naplicação da psicologia.", "B": "A prevenção primária tem como característica central a\natuação nos problemas epidemiológicos da população\nbeneficiária e investe na construção de estilos de vida\nsaudáveis e na evitação de comportamentos de risco.", "C": "A intervenção primária trata da primeira ação de saúde\nna presença de um problema, que deverá ser\nidentificado.", "D": "Após a intervenção primária, se o caso necessitar de\numa intervenção psicológica especializada, será\nencaminhado a um dos outros níveis de atenção de\nsaúde.", "E": "A intervenção primária do psicólogo na equipe de\nsaúde, ainda que desempenhe um papel específico,\ndeverá ser realizada em uma perspectiva\ninterdisciplinar e multiprofissional."}, "g": "A", "j": "Questao pede INCORRETA. A prevencao primaria tem alcance COLETIVO e populacional, nao se dirige a 'um unico individuo' - sua logica e epidemiologica e de promocao em escala. Demais alternativas descrevem corretamente estilos de vida, intervencao precoce e perspectiva interdisciplinar."}, {"id": "1299613", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca dos níveis de prevenção em saúde, julgue os itens\nque se seguem.    I. A prevenção primária refere-se a ações que promovem\na saúde e que são realizadas para prevenir que uma\ndoença ou lesão ocorra.  II. A prevenção secundária envolve ações para identificar\ne tratar uma doença no início de seu curso.  III. A prevenção terciária envolve ações para conter ou\nretardar danos, uma vez que a doença já tenha\navançado além de seus estágios iniciais, sendo a forma\nmenos comum de cuidado em saúde.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (prevencao primaria = promocao/prevencao de ocorrencia) e II (secundaria = identificar e tratar no inicio) corretos. Item III erra ao caracterizar prevencao terciaria como 'forma menos comum de cuidado' - na verdade e frequente, sobretudo no manejo de doencas cronicas."}, {"id": "1299612", "d": "psicologia", "a": ["Psicologia da Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "O modelo transteórico sustenta que o comportamento\nmuda, sistematicamente, ao longo de estágios distintos.\nCom relação a esse modelo, assinale a alternativa correta.", "alt": {"A": "Esse modelo afirma que as pessoas progridem por\nmeio de quatro estágios ao alterar comportamentos\nrelacionados com a saúde.", "B": "O primeiro estágio, a pré-contemplação, envolve\npensamentos de seriedade sobre a mudança de\ncomportamento, reconhecendo o problema e a\nnecessidade de mudança.", "C": "No segundo estágio, a contemplação, as pessoas\navaliam a possibilidade de mudança em um futuro\ndistante.", "D": "O terceiro estágio, a preparação, envolve pensamentos\ne ações para mudança do comportamento.", "E": "No quarto estágio, a manutenção, as pessoas obtêm\nsucesso em seus esforços para alcançar seu objetivo\nfinal."}, "g": "D", "j": "No modelo transteorico, a preparacao envolve pensamentos e acoes para a mudanca (planejamento dentro de 30 dias). A erra no numero de estagios (sao 5/6, nao 4); B confunde pre-contemplacao com contemplacao; C inverte logica do horizonte temporal; E define manutencao incorretamente."}, {"id": "1299611", "d": "psicologia", "a": ["Behaviorismo", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Assim como o modelo de crença de saúde, a teoria do\ncomportamento planejado especifica relações entre\ncomportamentos e saúde. No que se refere à teoria do\ncomportamento planejado, assinale a alternativa incorreta.", "alt": {"A": "A teoria prevê o comportamento saudável com base\nem três fatores: a atitude pessoal para com o\ncomportamento; a norma subjetiva em relação ao\ncomportamento; e o grau de percepção de controle\nsobre o comportamento.", "B": "A atitude pessoal do indivíduo para com o\ncomportamento não envolve a crença sobre os\nresultados desse comportamento.", "C": "A norma subjetiva em relação ao comportamento\nreflete a motivação para aderir à visão de outras\npessoas com relação ao comportamento em questão.", "D": "A percepção de controle sobre o comportamento\nrefere-se à expectativa de sucesso ao realizar o\ncomportamento de saúde esperado.", "E": "O modelo do comportamento planejado é mais preciso\npara prever comportamentos intencionais orientados\npara objetivos e encaixa-se em um modelo racional."}, "g": "B", "j": "Questao pede INCORRETA. A atitude pessoal frente ao comportamento, na teoria de Ajzen, INCLUI a crenca sobre os resultados desse comportamento (modelo expectativa-valor). Demais alternativas descrevem corretamente os tres fatores (atitude, norma subjetiva, controle percebido) e o escopo do modelo."}, {"id": "1299610", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "A conexão entre estilo de vida, comportamento e saúde é\num dos focos principais da psicologia em saúde. Os\npsicólogos da saúde desenvolveram diversas teorias para\nexplicar porque as pessoas praticam, ou não, determinados\ncomportamentos de saúde. A respeito da teoria do modelo\nde crença de saúde, assinale a alternativa incorreta.", "alt": {"A": "O modelo de crença de saúde afirma que as decisões\nrelacionadas com o comportamento de saúde se\nbaseiam em quatro fatores.", "B": "O fator da suscetibilidade percebida sugere que as\npessoas se preocupam constantemente com sua\nvulnerabilidade a ameaças à saúde. Quanto maior a\nsuscetibilidade percebida, maior a motivação para\npraticar comportamentos que promovam a saúde.", "C": "Segundo esse modelo, as pessoas agirão para afastar\nou controlar condições que induzam doenças se\nacreditarem que a condição possa trazer\nconsequências pessoais sérias, configurando o fator de\ngravidade percebida de ameaça à saúde.", "D": "Fatores que envolvem os benefícios e as barreiras\npercebidas no tratamento e as dicas para ação\ninfluenciam a probabilidade de que o indivíduo venha a\nagir de determinada maneira.", "E": "O modelo de crença de saúde representa uma\nperspectiva relevante e completa de teoria lógica dos\nfatores que influenciam na decisão das pessoas de\ncontrolar condições que induzem doenças."}, "g": "E", "j": "Questao pede INCORRETA. O modelo de crenca de saude e INCOMPLETO - ha criticas conhecidas (nao contempla emocoes, normas sociais, eficacia percebida). Demais alternativas descrevem corretamente os fatores (suscetibilidade, gravidade, beneficios/barreiras, dicas para acao)."}, {"id": "1299609", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca da atuação em psicologia da saúde, assinale a\nalternativa correta.", "alt": {"A": "Os psicólogos da saúde estão envolvidos, sobretudo,\nem três ramos de atividades: ensino; pesquisa; e\nintervenção clínica.", "B": "Os hospitais caracterizam-se como o único cenário de\ntrabalho dos psicólogos da saúde.", "C": "As intervenções dos psicólogos da saúde limitam-se\nàqueles que já estão sofrendo um problema de saúde.", "D": "Os psicólogos da saúde prestam uma variedade de\nserviços, mas não se envolvem no desenvolvimento de\npolíticas públicas para o cuidado em saúde.", "E": "A atuação dos psicólogos da saúde acontece, apenas e\ndiretamente, com o paciente, segregada da atuação\ncom outros profissionais da saúde."}, "g": "A", "j": "Psicologos da saude atuam em tres ramos centrais: ensino, pesquisa e intervencao clinica. Demais alternativas restringem indevidamente (so hospital, so doentes, sem politicas publicas, sem outros profissionais)."}, {"id": "1299608", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo a evolução do conceito de saúde, procurar apenas\num fator causal produz uma imagem incompleta da saúde e\nda doença de uma pessoa. Portanto, os psicólogos da saúde\ntrabalham a partir da perspectiva biopsicossocial. Quanto a\nessa perspectiva, assinale a alternativa incorreta.", "alt": {"A": "Essa perspectiva reconhece que forças biológicas,\npsicológicas e socioculturais agem conjuntamente para\ndeterminar a saúde e a vulnerabilidade do indivíduo à\ndoença.", "B": "Nessa perspectiva, um elemento fundamental do\ncontexto biológico é a história evolutiva da espécie\nhumana.", "C": "Com base nessa perspectiva, a saúde e a doença estão\nsujeitas aos fatores psicológicos, exceto no tratamento\nde condições crônicas.", "D": "Essa perspectiva considera que os aspectos\nsocioculturais também desempenham um papel\nimportante na variação em crenças e comportamentos\nrelacionados com a saúde.", "E": "A perspectiva biopsicossocial está também\nfundamentada na teoria sistêmica do comportamento,\nque permite que se compreenda o indivíduo de forma\nintegral."}, "g": "C", "j": "Questao pede INCORRETA. A perspectiva biopsicossocial aplica-se a TODAS as condicoes, inclusive cronicas - nao admite excecao. Demais alternativas descrevem corretamente os fatores biologicos, evolucionarios, socioculturais e a base sistemica do modelo."}, {"id": "1299607", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2020", "org": "CFP", "t": "", "e": "Influenciada pelo movimento behaviorista, a medicina\ncomeçou a explorar o papel dos comportamentos\naprendidos na saúde e na doença, o que foi denominado\nmedicina comportamental. Em 1973, uma força-tarefa foi\nindicada, pela American Psychological Association, para\nexplorar o papel da psicologia no campo da medicina\ncomportamental e, em 1978, criou-se a divisão de\npsicologia da saúde. No que se refere aos objetivos desse\nnovo campo, julgue os itens a seguir.    I. A psicologia da saúde tem como um de seus objetivos,\nestudar, de forma científica, a etiologia de\ndeterminadas doenças. Interessa-se, principalmente,\npelas origens psicológicas, comportamentais e sociais\nda doença.  II. A psicologia da saúde objetiva, além de promover a\nsaúde, prevenir e tratar doenças.  III. A psicologia da saúde inclui, em seus objetivos, a\npromoção de políticas de saúde pública e o\naprimoramento do sistema de saúde pública.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: psicologia da saude estuda etiologia psicossocial das doencas (I), promove/previne/trata (II) e atua em politicas publicas e aprimoramento do sistema (III). Sao objetivos consagrados na criacao da Divisao da APA em 1978."}, {"id": "1299605", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "Na psicologia, o tema da saúde tem sido abordado com\nfrequência em diferentes campos de atuação na área.\nRelevante para diferentes reflexões, a saúde tem sido\nentendida como um processo que permite a compreensão\nsobre o individual e o social em sua constituição,\nenvolvendo uma visão sistêmica. Porém, na primeira parte\ndo século XX, a saúde não era compreendida dessa forma.\nCom relação ao modelo biomédico de saúde, assinale a\nalternativa correta.", "alt": {"A": "O modelo biomédico de saúde sustenta que a doença\nnem sempre tem causas apenas biológicas.", "B": "O modelo biomédico de saúde faz menção às variáveis\npsicológicas na doença, mas não as considera como\ndeterminantes.", "C": "De acordo com o modelo biomédico, as variáveis\nsociais e comportamentais na doença são\ncompreendidas como os fatores que podem auxiliar a\nexplicação da doença, mas não podem ser a causa\ndesta.", "D": "O modelo biomédico tem como base a doutrina\ncartesiana do dualismo mente-corpo, que os considera\ncomo entidades separadas e autônomas que interagem\nde forma mínima.", "E": "Segundo o modelo biomédico, a saúde vai além da\nausência de doenças."}, "g": "D", "j": "O modelo biomedico apoia-se no dualismo cartesiano mente-corpo, tratando-os como entidades separadas. Demais alternativas contradizem o modelo (que so admite causas biologicas, ignora variaveis psicologicas/sociais e equipara saude a ausencia de doenca)."}, {"id": "1299604", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2020", "org": "CFP", "t": "", "e": "A saúde envolve o bem-estar físico, assim como o\npsicológico e o social. Entretanto, os benefícios à saúde não\nsão desfrutados universalmente, o que representa um\ncontexto de ação fundamental para a psicologia da saúde.\nAcerca desse assunto, assinale a alternativa incorreta.", "alt": {"A": "A psicologia da saúde se configura como um subcampo\nda psicologia que aplica princípios e pesquisas\npsicológicos para melhoria da saúde.", "B": "Os princípios da psicologia da saúde podem ser\nutilizados para o tratamento e a prevenção de\ndoenças.", "C": "Os interesses da psicologia da saúde incluem condições\nsociais, fatores biológicos e traços de personalidade.", "D": "A compreensão da saúde como ausência de doenças se\nconcentra apenas na ausência de um estado negativo\ne, por essa razão, é incompleta.", "E": "Uma pessoa que está livre de doenças, com certeza,\ndesfruta de uma vida vigorosa e satisfatória."}, "g": "E", "j": "Questao pede INCORRETA. Ausencia de doenca NAO garante vida vigorosa e satisfatoria - o conceito ampliado de saude (OMS/biopsicossocial) inclui bem-estar fisico, mental e social. Demais alternativas descrevem corretamente o subcampo da psicologia da saude."}, {"id": "1299563", "d": "psicologia", "a": ["Orientação Profissional na Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Levenfus (2016), são aspectos que precisam\nser considerados para o processo de orientação profissional", "alt": {"A": "os gostos, as dúvidas, as decisões, as escolhas, a\ninterferência financeira, a universidade, o mercado de\ntrabalho, as informações, a influência, o\nautoconhecimento, a identificação e o sistema de\ningresso, entre outros aspectos relacionados à\nformação pessoal e a contextos socioculturais.", "B": "a tendência vocacional e o mercado de trabalho.", "C": "os níveis de inteligência, aptidão e autoconhecimento.", "D": "a aptidão genuína e a posição socioeconômica da\nfamília, que influenciam diretamente no\ndesenvolvimento vocacional do jovem.", "E": "as aptidões, pois, com o potencial para o desempenho\nda atividade profissional, o indivíduo conseguirá uma\ncolocação no mercado de trabalho."}, "g": "A", "j": "Levenfus (2016) propoe abordagem ampla da orientacao profissional, incluindo gostos, duvidas, escolhas, fatores financeiros, universidade, mercado, informacoes, influencia, autoconhecimento, identificacao e sistema de ingresso - lista coerente com perspectiva sociocultural integrada."}, {"id": "1299562", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Para que uma conduta possa ser qualificada como moral, é\npreciso mais que um acordo exterior com o conteúdo das\nregras admitidas; convém que a consciência tenda para a\nmoralidade como um bem autônomo e seja capaz, ela\nmesma, de apreciar o valor das regras que propostas.     A autoria do texto acima pode ser atribuída a", "alt": {"A": "Lev Vygotsky, quando se referiu ao desenvolvimento\nda consciência.", "B": "Lev Vygotsky, quando se referiu ao desenvolvimento\ndas funções psicológicas superiores.", "C": "Jean Piaget, quando se referiu à formação da\nconsciência moral da criança.", "D": "Carl Rogers, quando se referiu à formação da\nconsciência da criança.", "E": "Leontiev, quando se referiu ao processo de\ndesenvolvimento da autonomia da criança."}, "g": "C", "j": "O fragmento e tipico de Piaget sobre julgamento moral da crianca (autonomia x heteronomia), enfatizando a interiorizacao e apreciacao critica das regras. Vygotsky, Rogers e Leontiev tem outras matrizes teoricas e nao adotam essa formulacao especifica."}, {"id": "1299555", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "O bullying ocorre principalmente na escola e atinge toda a\ncoletividade de atores sociais participantes da comunidade\neducativa em torno do aluno, como, por exemplo, a família,\nos educadores, as equipes técnicas e os pares. Portanto, na\navaliação desse fenômeno, os profissionais da escola", "alt": {"A": "devem ser neutros e não devem se envolver, uma vez\nque essas situações se resolvem espontaneamente.", "B": "devem se envolver e aprimorar medidas para a\nresolução da situação, identificando a frequência, a\nintencionalidade e o desequilíbrio de poder entre os\nenvolvidos e criando estratégias de enfrentamento.", "C": "devem denunciar o caso imediatamente para as\nautoridades competentes e deixar que eles tomem\nprovidências na justiça comum.", "D": "devem identificar o agressor e convidá-lo a se retirar\nda escola.", "E": "não devem se importar com a situação, pois ela faz\nparte do cotidiano da escola e se resolve\nespontaneamente."}, "g": "B", "j": "Os profissionais devem se envolver, avaliar frequencia/intencionalidade/desequilibrio de poder e criar estrategias de enfrentamento - definicao classica de bullying (Olweus). Demais alternativas defendem omissao, denuncia automatica, expulsao do agressor ou naturalizacao - todas inadequadas."}, {"id": "1299554", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A atenção é um dos requisitos fundamentais para se\nproporcionar condições de aprendizagem, pois ela é\nnecessária para que um estímulo seja percebido, elaborado\ne se transforme em uma resposta, que deve, em seguida,\nser avaliada. A teoria do processamento da informação\npressupõe momentos distintos para que a aprendizagem\nocorra. Sendo assim, assinale a alternativa que apresenta\nesses momentos.", "alt": {"A": "INPUT e PROCESSING", "B": "INPUT e ONPUT", "C": "INPUT, PROCESSING e OUTPUT", "D": "ONPUT, OFPUT e INPUT", "E": "INPUT e OUTPUT"}, "g": "C", "j": "Teoria do processamento da informacao adota tres momentos: INPUT (entrada do estimulo), PROCESSING (processamento) e OUTPUT (resposta). Demais alternativas omitem ou inventam etapas (ONPUT/OFPUT nao existem na teoria)."}, {"id": "1299551", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "A respeito da importância da análise dos cadernos\nescolares, julgue os itens que se seguem.\n I. É necessário diferenciar o que foi realizado por meio de\ncópia do que foi uma produção mais autônoma do\naluno.     II. A análise dos cadernos não pode trazer informações\nsobre o que o estudante domina. Há a necessidade de\navaliações psicológicas para isso.     III. As cópias podem trazer informações sobre as\ncaracterísticas dos erros.     Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens I e III estão certos."}, "g": "B", "j": "Correcao: gabarito tecnico e E (apenas I e III). Item I (diferenciar copia de producao autonoma) e correto pedagogicamente; item III (copias trazem informacoes sobre erros) e correto; item II e falso pelo 'NAO PODE' - cadernos sao fonte importante de informacao sobre o que o aluno domina. Gabarito original B (apenas II) e logicamente incoerente."}, {"id": "1299546", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à participação da família no contexto escolar,\nassinale a alternativa correta.", "alt": {"A": "Há a necessidade de se estimular a participação das\nfamílias por meio de projetos colaborativos.", "B": "As famílias carentes têm pouco a contribuir, pois não\npossuem recursos para colaboração.", "C": "As famílias atuais são desestruturadas, portanto não se\npode contar com sua participação na escola.", "D": "As famílias podem participar de atividades\ncomemorativas.", "E": "As famílias não estão preparadas para participar da\neducação escolar de seus filhos."}, "g": "A", "j": "A participacao das familias na escola deve ser estimulada por meio de projetos colaborativos. Demais alternativas refletem visoes preconceituosas/limitantes sobre a familia (carencia, desestruturacao, comemorativismo, despreparo), incompativeis com a abordagem critica da psicologia escolar."}, {"id": "1299543", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta o nome do\npesquisador que afirma que a educação libertadora,\nproblematizadora, já não pode ser o ato de depositar, ou\nde narrar, ou de transferir, ou de transmitir\n“conhecimentos” e valores aos educandos, meros pacientes\nà maneira da educação “bancária”, mas um ato\ncognoscente.", "alt": {"A": "Gilberto Freire", "B": "Demerval Saviani", "C": "Paulo Freire", "D": "Carlos Jamil Cury", "E": "Jean Piaget"}, "g": "C", "j": "O conceito de 'educacao bancaria' e a defesa da 'educacao libertadora/problematizadora' como 'ato cognoscente' sao formulacoes classicas de Paulo Freire (Pedagogia do Oprimido). Os demais autores tem outras matrizes teoricas."}, {"id": "1299542", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Para a avaliação, o diagnóstico, o atendimento e o\nencaminhamento de alunos com dificuldades escolares, é\nimportante", "alt": {"A": "utilizar apenas testes recomendados pelos Conselho\nFederal de Psicologia.", "B": "utilizar variados instrumentos de investigação – como a\nobservação dos alunos em situações de atividade\nescolar cotidiana, das conversações com eles e com\naqueles com quem interagem, de jogos e de situações\ndiversas – para a compreensão das causas que\noriginam as dificuldades.", "C": "encaminhar para os profissionais de saúde todos os\nestudantes que apresentem dificuldades de\naprendizagem.", "D": "não realizar nenhuma intervenção, para não\ndiscriminar o estudante.", "E": "ignorar os encaminhamentos, visto que as dificuldades\nsão construídas pelo professor e, portanto, deve-se\norientar apenas ele."}, "g": "B", "j": "A avaliacao de dificuldades escolares requer variados instrumentos de investigacao (observacao em atividade cotidiana, conversacoes, jogos, situacoes diversas) para compreender as causas. Demais alternativas reducionistas ou nocivas (so testes do CFP, encaminhamento a saude, omissao, culpabilizacao do professor)."}, {"id": "1299540", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere aos três temas recorrentes na obra de\nPierre Bourdieu, segundo os estudos de David Swartz, um\ndos colaboradores da obra de Patto (1997), assinale a\nalternativa correta.", "alt": {"A": "O desempenho acadêmico está relacionado ao\nbackground cultural; a educação escolar resulta em\numa diferença; o processo seletivo da educação está\nrelacionado à classe social, sem se reduzir a um simples\ndeterminismo de classe social.", "B": "O desempenho acadêmico não está relacionado ao\nbackground cultural; a educação escolar resulta em\numa diferença; o processo seletivo da educação está\nrelacionado à classe social, sem se reduzir a um simples\ndeterminismo de classe social.", "C": "O desempenho acadêmico não está relacionado ao\nbackground cultural; a educação escolar é\nheterogênea; o processo seletivo da educação está\nrelacionado à classe social, sem se reduzir a um simples\ndeterminismo de classe social.", "D": "O desempenho acadêmico não está relacionado ao\nbackground cultural; a educação escolar é\nheterogênea; o processo seletivo da educação não está\nrelacionado à classe social.", "E": "O desempenho acadêmico está relacionado ao\nbackground cultural; a educação escolar opera em\nnível de igualdade; o processo seletivo da educação\nnão está relacionado à classe social, pois, se assim\nfosse, ela seria reducionista."}, "g": "A", "j": "Segundo Swartz/Patto, Bourdieu propoe que desempenho academico esta ligado ao background cultural, a educacao escolar produz diferenca e o processo seletivo se relaciona a classe social sem se reduzir a determinismo simples. Demais alternativas negam ou simplificam esses tres temas."}, {"id": "1299539", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto às ações do psicólogo escolar e educacional que\natua diretamente em escolas ou que desenvolve atividades\ncom o objetivo de assessorar ou dar algum tipo de suporte\npara os profissionais que trabalham nas escolas, julgue os\nitens subsequentes.  I. É uma dessas ações contribuir para a construção da\ngestão escolar democrática a partir do trabalho\ncoletivo e colaborativo.     II. É uma dessas ações fortalecer a autonomia do\nprofessor e do papel dirigente.     III. É uma dessas ações contribuir para fortalecer a ação\npopular na escola.     IV. É uma dessas ações participar do planejamento da\nescola e da orientação dos discentes, considerando as\nnecessidades e os interesses dos estudantes.     V. É uma dessas ações contribuir para a definição de\nconteúdos e de materiais de ensino que garantam a\napropriação do saber.     Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e V estão certos.", "B": "Apenas os itens I, III e IV estão certos.", "C": "Apenas os itens II, III e V estão certos.", "D": "Apenas os itens I, II, III e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens (I-V) descrevem acoes legitimas do psicologo escolar e educacional: gestao democratica, autonomia do professor, acao popular, planejamento e orientacao discente, definicao de conteudos e materiais."}, {"id": "1299538", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação aos processos de aprendizagem e\ndesenvolvimento, assinale a alternativa que apresenta o\nnome do autor segundo o qual a educação deve\ndesempenhar o papel central na transformação do homem\ne, nesta estrada de formação social consciente de gerações\nnovas, a educação deve ser a base para a alteração do tipo\nhumano histórico", "alt": {"A": "Jean Piaget", "B": "Lev Vygotsky", "C": "Alexander Luria", "D": "Fernando González Rey", "E": "Burrhus Frederic Skinner"}, "g": "B", "j": "A formulacao sobre a educacao como base para alterar o 'tipo humano historico' e tipica de Vygotsky, em sua psicologia historico-cultural - educacao como instrumento de transformacao social consciente das geracoes. Demais autores tem outras matrizes (Piaget, Luria, Gonzalez Rey, Skinner)."}, {"id": "1299536", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Julgue os itens a seguir.\n I. Caracteriza a atuação do psicólogo escolar orientar a\ngestão escolar.   II. Caracteriza a atuação do psicólogo escolar colaborar\nno planejamento do projeto pedagógico da escola.   III. Caracteriza a atuação do psicólogo escolar oferecer\norientação psicoeducacional para a comunidade\nescolar.   IV. Caracteriza a atuação do psicólogo escolar orientar os\nenvolvidos com a educação do estudante, como, por\nexemplo pai, mãe, responsáveis, cuidadores e\nprofissionais.   V. Caracteriza a atuação do psicólogo escolar fazer\natendimento de psicoterapia breve, na escola, com\ntodos os envolvidos.     Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e V estão certos.", "B": "Apenas os itens I, III e IV estão certos.", "C": "Apenas os itens II, III e V estão certos.", "D": "Apenas os itens I, II, III e IV estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I-IV (orientar gestao, projeto pedagogico, orientacao psicoeducacional, orientar familiares e responsaveis) caracterizam corretamente a atuacao do psicologo escolar. Item V (psicoterapia breve na escola com 'todos os envolvidos') extrapola a atribuicao - psicoterapia nao e atividade tipica desse contexto."}, {"id": "1299535", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Considerando a história da psicologia escolar no Brasil,\njulgue os itens seguintes.I. O ensino formal de psicologia foi ministrado em cursos\nsuperiores de filosofia e da área de educação, entre os\nquais se registra o curso de pedagogia.    II. A educação é um dos pilares que sustentou o\ndesenvolvimento da psicologia e um dos fundamentos\npara a educação, sobretudo no âmbito pedagógico.     III. O ensino de psicologia sempre teve espaço privilegiado\nnos currículos das escolas normais e dos cursos de\npedagogia.     Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens correspondem ao percurso historico da psicologia escolar brasileira: ensino em cursos de filosofia e pedagogia (I), educacao como pilar do desenvolvimento da psicologia (II) e presenca da psicologia nas escolas normais e cursos de pedagogia (III)."}, {"id": "1299534", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta o campo de ação da\npsicologia escolar na versão de Mitsuko Aparecida Makino\nAntunes (2008).", "alt": {"A": "A psicologia escolar pode ser definida segundo o\nâmbito profissional e refere-se a um campo de ação\ndeterminado, isto é, o processo de escolarização. Tem\npor objeto a escola e as relações que aí se estabelecem\ne fundamenta sua atuação nos conhecimentos\nproduzidos pela psicologia da educação, por outras\nsubáreas da psicologia e por outras áreas de\nconhecimento.", "B": "A psicologia escolar não pode ser definida segundo o\nâmbito profissional. Deve ser definida de acordo com o\nâmbito político, pois envolve outras áreas, que se\nimbricam e se excluem ao mesmo tempo, tornando-se\num campo de celeumas teóricas e metodológicas.", "C": "A psicologia escolar pode ser entendida como uma\nsubárea de conhecimento que tem como vocação a\nprodução de saberes relativos ao fenômeno\npsicológico constituinte do processo educativo.", "D": "A psicologia escolar pode ser entendida como um\nespaço para fundamentação, sistematização e\norganização da prática educativa.”", "E": "A psicologia escolar e a psicologia educacional são\ndefinidas como áreas idênticas para o catálogo de\nespecialidade. A diferenciação entre elas é apenas de\nordem epistemológica.”"}, "g": "A", "j": "Em Antunes (2008), a psicologia escolar e definida segundo o ambito profissional, refere-se ao processo de escolarizacao e fundamenta-se em conhecimentos da psicologia da educacao e de outras areas. Demais alternativas negam a definicao profissional ou confundem com psicologia da educacao."}, {"id": "1299533", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto ao atendimento psicológico a pacientes cirúrgicos,\njulgue os itens a seguir.    I. Algumas intervenções relevantes do psicólogo\nhospitalar para pacientes que serão submetidos à\ncirurgia são: música; suporte emocional centrado na\npessoa; esclarecimento das dificuldades físicas e\npsicológicas esperadas; vídeo como medida profilática;\ne procedimentos psicoeducacionais.  II. Os pacientes cirúrgicos geralmente trazem como\ndemandas ao psicólogo o manejo de dor, os\nconstrangimentos da internação e a ansiedade em\nrelação à cirurgia.  III. Existe a necessidade de integração entre os membros\nda equipe no processo de comunicação sobre a\ncirurgia.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: intervencoes (musica, suporte centrado, esclarecimento, video, psicoeducacao) em I; demandas tipicas (dor, internacao, ansiedade) em II; necessidade de integracao da equipe em III - todos consagrados na literatura de psicologia hospitalar."}, {"id": "1299530", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Os estressores encontrados na UTI podem ser minimizados\ncom ações de humanização. Sendo assim, assinale a\nalternativa que não apresenta uma das formas como o\npsicólogo hospitalar pode amenizar o estresse nesse\nambiente", "alt": {"A": "realizar leitura religiosa, independentemente da crença\ndo paciente", "B": "conversar sobre as angústias, as fantasias e os medos\ndo paciente", "C": "criar estratégias singulares junto à equipe, voltadas\npara o que o paciente considera como estressante no\nambiente de UTI", "D": "estimular, quando possível, a autonomia do paciente\npor meio do autocuidado", "E": "levar em consideração que a família pode ser fonte\natenuadora dos estressores"}, "g": "A", "j": "Realizar leitura religiosa INDEPENDENTEMENTE da crenca do paciente viola o respeito a diversidade religiosa do CEP e a autonomia do paciente, NAO sendo forma adequada de amenizar estresse em UTI. Demais alternativas (escuta, estrategias singulares, autonomia, familia) sao apropriadas."}, {"id": "1299529", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo na UTI neonatal, julgue os\nitens subsequentes.    I. O psicólogo em UTI neonatal evita a criação de grupos\nde pais, devido aos altos índices de óbito dos\nrecém-nascidos.  II. Faz parte do trabalho do psicólogo em UTI neonatal o\nincentivo ao acompanhamento pré-natal, a prevenção\nde gravidez indesejada, a alimentação adequada da\ngestante, bem como os programas voltados à\ninformação sobre os problemas de saúde do feto\ndetectados ainda na gravidez ou após o nascimento.  III. Os psicólogos trabalham com avaliação e intervenção\npsicológica com pais ou responsáveis, familiares e\nequipe de saúde, objetivando, além da vinculação\ninicial com o bebê, o bom contato entre os membros\nda equipe de saúde e entre estes e o cuidador.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas III correto. Item I e falso - grupos de pais sao incentivados, nao evitados. Item II descreve acoes de pre-natal/atencao primaria, nao de UTI neonatal. Item III descreve corretamente as intervencoes psicologicas com pais, familiares e equipe."}, {"id": "1299527", "d": "psicologia", "a": ["Psicologia da Saúde", "Cuidados Paliativos na Psicologia", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "O manejo psicológico dos pacientes diagnosticados com\nsíndrome da imunodeficiência adquirida (Aids) deve levar\nem consideração alguns aspectos psicológicos durante o\ntratamento. Sendo assim, assinale a alternativa incorreta.", "alt": {"A": "As reações emocionais mais frequentes, demonstradas\npelos indivíduos que começam a desenvolver os\nprimeiros sinais da doença, são os sintomas de\ndepressão intensos e associados à perda da autonomia,\nao medo do futuro e à ansiedade sobre a morte.", "B": "O psicólogo somente estabelece contato com a família\napós o consentimento do próprio paciente, visto que é\ndireito dele estabelecer sigilo de seu diagnóstico, até\nmesmo com os parceiros sexuais que não tenham\nconhecimento deste.", "C": "No estágio final da doença, ocorre uma mudança na\nimagem corporal e uma evidente redução do\nautoconceito do paciente.", "D": "O paciente, muitas vezes, demonstra receio de ser\njulgado e pode sentir-se culpado. Desse modo, acaba\nadotando um comportamento autopunitivo e de\nafastamento e isolamento do meio.", "E": "No momento inicial de avaliação psicológica, é de\nextrema importância fornecer informações sobre a\ndoença e o tratamento, dar apoio psicológico e\nestimular o vínculo e a adesão do paciente ao\ntratamento."}, "g": "B", "j": "Questao pede INCORRETA. Em situacoes de risco a parceiros sexuais que desconhecem o diagnostico, o sigilo profissional admite excecao (Res CFP 01/2018 sobre HIV), nao podendo o psicologo se omitir absolutamente. Demais alternativas descrevem corretamente o manejo psicologico de pacientes com Aids."}, {"id": "1299526", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Desastre é um acontecimento traumático que causa perda\nde vidas, da saúde e de bens materiais de muitas pessoas.\nEm relação às intervenções psicológicas em emergência,\njulgue os itens que se seguem.    I. Em situações de desastre, são dadas informações aos\nsujeitos envolvidos sobre as reações e os\ncomportamentos esperados.  II. O psicólogo trabalha nos seguintes locais de acidente:\nsaguão de aeroporto; canteiro de obras; velórios;\ncemitérios; Instituto Médico Legal (IML); hotéis; ou\ncasa dos familiares das vítimas, ou seja, onde for\npreciso.  III. Muitas vezes, as pessoas envolvidas no desastre param\nde realizar cuidados básicos como dormir e comer.\nNesses casos, cabe ao psicólogo somente compreender\ne aguardar o tempo de cada um no retorno à\nrealização desses cuidados.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Itens I (informacoes sobre reacoes) e II (atuacao em diferentes locais do desastre) corretos. Item III e falso - frente a abandono de cuidados basicos, o psicologo deve INTERVIR ativamente, nao apenas 'compreender e aguardar'."}, {"id": "1299525", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Ludoterapia", "Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto ao cuidado com a criança, julgue os itens seguintes.I. O brincar é excelente instrumento preventivo,\ndiagnóstico, prognóstico e terapêutico para crianças\nem fase terminal.II. Algumas atividades que o psicólogo hospitalar pode\nexecutar com as crianças que estão internadas no\nhospital são: desenho; pintura; recortes; colagens;\nteatro de fantoches; e playmobil de hospital.III. O psicólogo deve orientar a família a não falar sobre a\nmorte de um ente querido com a criança, para\nprotegê-la da dor.Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Itens I (brincar como instrumento preventivo/diagnostico/terapeutico) e II (atividades ludicas com criancas internadas) corretos. Item III e falso e contrario as recomendacoes da psicologia hospitalar pediatrica - a crianca deve ser informada sobre a morte de forma adequada a sua compreensao."}, {"id": "1299523", "d": "psicologia", "a": ["Psicologia da Saúde", "Dor, Estresse e Luto", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca das fases da depressão vivenciada pelo paciente,\nassinale a alternativa incorreta.", "alt": {"A": "O luto é um mecanismo vivenciado somente pela\nperda de ente querido.", "B": "O paciente apresenta tristeza e falta de interesse.", "C": "A emoção evitada é a raiva.", "D": "O paciente tende a querer desistir do tratamento.", "E": "A pessoa não acredita ser capaz de ficar curada nem de\nenfrentar a situação provocada pela doença."}, "g": "A", "j": "Questao pede INCORRETA. O luto NAO se restringe a perda de ente querido - inclui perdas simbolicas (saude, autonomia, projetos), tipicas da vivencia de adoecimento. Demais alternativas descrevem corretamente sintomas da depressao no paciente (tristeza, raiva evitada, desistencia, descrenca na cura)."}, {"id": "1299521", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "A escala Glasgow é utilizada para a avaliação da\nconsciência. A respeito desse tema, assinale a alternativa\ncorreta.", "alt": {"A": "O paciente com pontuação 3 na escala Glasgow\napresenta consciência normal.", "B": "A escala Glasgow avalia a abertura dos olhos, a melhor\nresposta verbal e a melhor resposta motora.", "C": "O paciente com pontuação 15 na escala Glasgow não\nabre os olhos, não responde e não reage à dor.", "D": "A escala Glasgow avalia a consciência do eu.", "E": "As pontuações da escala Glasgow variam de 0 a 15\npontos."}, "g": "B", "j": "A escala de coma de Glasgow avalia tres dimensoes: abertura ocular, melhor resposta verbal e melhor resposta motora. A pontuacao varia de 3 (coma profundo) a 15 (consciencia normal). Demais alternativas erram nas pontuacoes minimas/maximas e na natureza do que se avalia."}, {"id": "1299520", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Simonetti (2013), assinale a alternativa correta\nacerca da intervenção do psicólogo junto ao paciente em\ncada estágio da doença.", "alt": {"A": "No estágio de negação, mesmo que o paciente aceite o\ntratamento, o psicólogo deverá confrontá-lo a\nqualquer custo.", "B": "Na fase da revolta, o paciente tem muitos conflitos\ncom a equipe e a família. Sendo assim, o psicólogo\ndeverá reprimir seu comportamento.", "C": "Na depressão preparatória, que leva em conta as\nperdas que estão por vir, incluindo a perda da própria\nvida, a melhor opção do psicólogo é a intervenção de\notimismo e encorajamento exagerado.", "D": "Durante a fase de negação, o objetivo do psicólogo não\né convencer o paciente de que ele é um doente nem o\nforçar a concordar com o diagnóstico médico.", "E": "Quando o paciente está no estágio da revolta, o\npsicólogo deve exaltar somente seus erros."}, "g": "D", "j": "Segundo Simonetti, na fase de negacao o psicologo NAO deve convencer o paciente de que esta doente nem forca-lo a concordar com o diagnostico - a negacao tem funcao protetiva. Demais alternativas defendem confronto, repressao, otimismo exagerado ou exaltacao de erros, contrariando a etica da escuta."}, {"id": "1299518", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere ao papel do psicólogo hospitalar, no\nacompanhamento dos familiares, enquanto recebem a\nnotícia do óbito de criança, assinale a alternativa incorreta.", "alt": {"A": "Acompanhar esses familiares permite ao psicólogo\nobservar o momento e a maneira mais adequada para\nintervir, de acordo com as características emocionais\nde cada familiar enlutado.", "B": "Cabe ao psicólogo apontar a importância do papel dos\npais, os investimentos realizados e as limitações\ninerentes ao ser humano, aliviando, em muitos casos,\npossível sentimento de culpa pela patologia, que é\nnatural.", "C": "Nesse momento, reforçar os vínculos e a rede de apoio\nfamiliar pode ajudar a vivenciar o luto.", "D": "Nessas situações, é comum que se exija afetivamente\ntambém do psicólogo, por enfrentar um processo de\nluto por seu paciente falecido.", "E": "O psicólogo que não tenha vínculo com a família da\ncriança não poderá atendê-la no momento do óbito."}, "g": "E", "j": "Questao pede INCORRETA. Vinculo previo com a familia NAO e requisito para atendimento no momento do obito - qualquer psicologo hospitalar capacitado pode acompanhar a familia. Demais alternativas descrevem corretamente a postura tecnica, etica e o autocuidado do profissional diante do luto."}, {"id": "1299517", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Simonetti (2013), a psicologia hospitalar utiliza-se\nde algumas ferramentas para traçar estratégias\nterapêuticas para o paciente. Sendo assim, assinale a\nalternativa incorreta com relação ao diagnóstico realizado\npelo psicólogo.", "alt": {"A": "É o conhecimento da doença por meio de seus\nsintomas.", "B": "Consegue compreender a “verdade” do paciente sobre\nsua doença.", "C": "É uma hipótese de trabalho do psicólogo hospitalar.", "D": "É o modo de que o psicólogo hospitalar dispõe para\norganizar seu pensamento.", "E": "Nada tem a ver com o psicodiagnóstico."}, "g": "A", "j": "Questao pede INCORRETA. Em Simonetti, o diagnostico do psicologo hospitalar NAO se reduz ao 'conhecimento da doenca por meio de seus sintomas' (definicao medica) - e hipotese de trabalho voltada a subjetividade do paciente. Demais alternativas descrevem corretamente a natureza hipotetica, organizativa e distinta do psicodiagnostico classico."}, {"id": "1299516", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à morte encefálica e à doação de órgãos, julgue os\nitens subsequentes.    I. No imaginário de algumas famílias, a doação de órgãos\né a continuidade da vida do ente querido, que\npermanecerá vivo em outra pessoa.  II. Na maioria dos casos, a morte encefálica é identificada\ncomo a impossibilidade de o paciente vir a recuperar a\nconsciência, e não como sua morte, dificultando a\naceitação do óbito.  III. Quando há desconfiança a respeito da eficácia do\natendimento prestado ao paciente, a família, por\nvezes, estende a mesma desconfiança ao\nprocedimento de captação de órgãos.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: a doacao como continuidade simbolica (I), a confusao entre morte encefalica e coma irreversivel (II) e a transferencia de desconfianca do atendimento para a captacao (III) sao fenomenos amplamente descritos na literatura sobre psicologia hospitalar e doacao de orgaos."}, {"id": "1299515", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "O trabalho de Elisabeth Kluber-Ross explica os estágios\npelos quais o paciente em fase terminal passa. No que\nconcerne a eles, assinale a alternativa correta.", "alt": {"A": "A seguinte fala de paciente diante do diagnóstico de\numa doença terminal é um exemplo de barganha:\n“deve ser um engano”.", "B": "Na fase da negação, a pessoa acredita que o fato de\nnão pensar na doença pode fazer com que ela\ndesapareça.", "C": "A negação se dá principalmente por falta de\ninformação; não se dá por falta de condições\npsicológicas.", "D": "A fase de negação é sempre total e permanente.", "E": "A emoção predominante na fase de negação é a\ntristeza."}, "g": "B", "j": "Na fase de negacao (Kubler-Ross), o paciente acredita que nao pensar na doenca pode faze-la desaparecer - mecanismo defensivo classico. A confunde com negacao ('deve ser um engano' tambem e negacao, mas o gabarito atribui a barganha indevidamente em A); C, D, E erram ao defender carater so informacional, totalidade permanente ou predominio de tristeza."}, {"id": "1299514", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca dos subtipos de delirium, julgue os itens que se\nseguem.    I. Pacientes com delirium hiperativo interagem pouco\ncom o ambiente e apresentam retardo motor e verbal,\nbaixa responsividade e lentificação psíquica.  II. O diagnóstico de pacientes com delirium hipoativo\npassa despercebido com maior frequência. Também há\ncasos em que o paciente é erroneamente\ndiagnosticado com depressão.  III. Caso haja evidência dos dois tipos (hiperativo e\nhipoativo) nas últimas 24 h, trata-se de delirium misto.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Apenas II e III corretos. Item I e falso - INVERTE as descricoes: pacientes com delirium HIPOATIVO (nao hiperativo) e que apresentam retardo motor/verbal e baixa responsividade. Item II (hipoativo passa despercebido, confundido com depressao) e III (misto = ambos em 24h) sao corretos."}, {"id": "1299513", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Alfredo Simonetti, a psicologia hospitalar é o\ncampo de entendimento e tratamento dos aspectos\npsicológicos em torno do adoecimento. Com essa\nperspectiva, assinale a alternativa incorreta.", "alt": {"A": "O psicólogo hospitalar trabalha com os aspectos\npsicológicos do paciente (desencadeante, causa,\nagravante, consequência e manutenção da doença).", "B": "O objetivo da psicologia hospitalar é a subjetividade.", "C": "O paciente, a família, a equipe e as relações entre eles\nsão os focos da psicologia hospitalar.", "D": "A estratégia da psicologia hospitalar é tratar do\nadoecimento no registro do simbólico.", "E": "O psicólogo hospitalar utiliza as mesmas técnicas e\nintervenções do psicólogo clínico, porém o setting\nterapêutico acontece no hospital."}, "g": "E", "j": "Questao pede INCORRETA. A psicologia hospitalar exige adaptacoes especificas no setting, tempo de intervencao e tecnicas - nao reproduz integralmente o modelo da clinica ambulatorial. Demais alternativas (aspectos psicologicos do adoecer, subjetividade como objeto, foco em paciente/familia/equipe, registro simbolico) reproduzem Simonetti."}, {"id": "1299512", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "A atuação do psicólogo na UTI envolve o atendimento à\nfamília do paciente. Sendo assim, assinale a alternativa\nincorreta.", "alt": {"A": "Algumas fontes de ansiedade para a família do\npaciente internado na UTI, além do abalo devido ao\nestado de saúde do paciente, são: vulnerabilidade do\npaciente; mudanças repentinas do estado geral; falta\nde informação ou informação excessiva ou\ndesencontrada; lidar com a troca constante de\nmédicos; e acesso restrito à unidade.", "B": "Em situações de estresse alto, os familiares escutam\naquilo que é menos difícil de assimilar do ponto de\nvista emocional, estando, muitas vezes, despreparados\npara ouvir, aceitar ou interpretar a verdade em\ndeterminado momento.", "C": "Quando há piora ou óbito de algum paciente na UTI, as\noutras famílias podem se sentir ameaçadas,\nidentificadas e mais angustiadas.", "D": "Quando o paciente é internado na UTI, desencadeia-se\num desequilíbrio no sistema familiar, mas os conflitos\npré-existentes acompanham o grupo familiar no\nperíodo de internação e podem se refletir diretamente\nna relação com a equipe e com o próprio paciente.", "E": "O tempo de visita da família na UTI é limitado, pois\nnem todos os familiares têm condições emocionais\npara lidar com o ambiente e, assim, sua permanência\nprolongada atrapalharia o tratamento."}, "g": "E", "j": "Questao pede INCORRETA. A presenca prolongada da familia na UTI e BENEFICA (politica de humanizacao do SUS) - nao 'atrapalha o tratamento'. Demais alternativas descrevem corretamente fontes de ansiedade, comunicacao em estresse, contagio emocional entre familias e conflitos pre-existentes."}, {"id": "1299509", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "O psicólogo hospitalar trabalha na UTI com a tríade:\npaciente; família; e equipe. No que se refere ao papel do\npsicólogo na equipe, assinale a alternativa incorreta.", "alt": {"A": "Participa de reuniões multidisciplinares com o intuito\nde exploração mais cuidadosa das particularidades do\ncaso e de alinhamento de condutas.", "B": "Faz trocas com os outros membros da equipe sobre as\ndificuldades enfrentadas no contexto da UTI.", "C": "Realiza atendimento psicoterápico individual com os\nmembros da equipe.", "D": "Pode fazer atendimento ao paciente em conjunto com\nprofissionais de outras áreas da saúde.", "E": "Consegue verificar qual membro da família tem mais\ncondições emocionais e intelectuais para compreender\ninformações importantes passadas pela equipe."}, "g": "C", "j": "Questao pede INCORRETA. NAO cabe ao psicologo hospitalar realizar atendimento PSICOTERAPICO INDIVIDUAL com membros da equipe (constitui duplo vinculo e atendimento clinico fora do escopo). Demais alternativas descrevem corretamente reunioes multi, trocas tecnicas, atendimento conjunto e avaliacao do cuidador familiar."}, {"id": "1299506", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2020", "org": "CFP", "t": "", "e": "As influências do ambiente da unidade de terapia intensiva\n(UTI), como, por exemplo, a presença constante de\nluminosidade e de ruídos dos aparelhos, a falta de\nprivacidade, a alteração dos ciclos circadianos, os\nprocedimentos invasivos, o desconforto e as privações\nsensório-motoras, favorecem o surgimento de sintomas\npsicopatológicos e são geradoras de angústia. Com relação\nao papel do psicólogo hospitalar no ambiente da UTI, julgue\nos seguintes itens.    I. No caso de pacientes que não podem se comunicar\nverbalmente, buscam-se alternativas de comunicação\npor meio de leitura labial, sinalizações, gestos, uso da\nescrita ou de figuras, incentivando a capacidade de\nexpressão do indivíduo e acessando seu universo\nsubjetivo.  II. O paciente em coma não pode receber atendimento\npsicológico devido à ausência da fala, instrumento\nimprescindível para o psicólogo.  III. No caso de o paciente estar em coma ou sedado, apesar de\nnão ser capaz de falar, o psicólogo pode falar para ele e\nsobre ele. O psicólogo pode, por exemplo, dizer como está\nindo o tratamento, o quanto a família deseja sua\nrecuperação e outras coisas positivas e motivadoras.    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Apenas I e III corretos. Item II e falso - pacientes em coma RECEBEM atendimento psicologico (presenca, fala, escuta do que o corpo e contexto comunicam). Itens I (alternativas comunicacionais) e III (falar para e sobre o paciente) sao praticas consagradas em UTI."}, {"id": "1299505", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2020", "org": "CFP", "t": "", "e": "No exame psíquico, um paciente apresenta-se\nconsciente, desorientado no tempo e no espaço, com\nalucinação visual, delírio persecutório e labilidade afetiva.Com base nesse caso hipotético, é correto afirmar que o\npaciente demonstra alterações psicopatológicas", "alt": {"A": "da memória, do pensamento, da consciência clínica e\nda linguagem.", "B": "do pensamento, da sensopercepção, da consciência do\neu e do humor.", "C": "do pensamento, da memória, da motivação e da\nconsciência clínica.", "D": "da consciência clínica, do pensamento, da volição e da\nmemória.", "E": "da consciência do eu, do pensamento, do humor e da\nlinguagem."}, "g": "B", "j": "Desorientacao tempo-espaco = consciencia do eu (orientacao); alucinacao visual = sensopercepcao; delirio persecutorio = pensamento; labilidade afetiva = humor/afeto. Alternativa B reproduz exatamente esse mapeamento psicopatologico."}, {"id": "1299452", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A prática psicomotora Aucouturier é um método criado por\nBernard Aucouturier, que observou e criou práticas\neducativas e preventivas para crianças. Os princípios são a\nescuta, a compreensão e o acolhimento no olhar à criança.\nAcerca dessa prática psicomotora, assinale a alternativa\ncorreta.", "alt": {"A": "Não apresenta a maturidade como expressão do prazer\ndo agir e do prazer do pensar.", "B": "Utiliza como instrumento materiais estáticos e\nconsistentes.", "C": "Defende uma relação terapeuta-criança baseada na\nautoridade deste último.", "D": "Entende que a expressão psicomotora demonstra a\nrelação do mundo interno da criança com seus pais.", "E": "Entende que a maturidade psicomotora acontecerá na\nmedida em que a relação terapeuta-criança aconteça,\nde forma interativa e construída, por meio de materiais\ntransformáveis e coloridos."}, "g": "E", "j": "Pratica psicomotora Aucouturier: maturidade psicomotora emerge da relacao terapeuta-crianca interativa e construida, com materiais transformaveis e coloridos. Demais alternativas negam o prazer agir/pensar, restringem materiais a estaticos, defendem autoritarismo do terapeuta ou reducionismo da expressao."}, {"id": "1299451", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "O ritmo, enquanto habilidade do desenvolvimento\npsicomotor, pode ser visto de duas formas: ritmo vital e\nritmo psicológico. Entretanto, os ritmos apresentam\nobjetivos próprios de aprendizagem. No que se refere a\nesse assunto, assinale a alternativa correta.", "alt": {"A": "A habilidade do ritmo depende de muitos fatores, tais\ncomo a condição financeira dos pais e a capacidade\npsicossocial de convivência da criança.", "B": "Favorecer o conhecimento do corpo, o esquema\ncorporal e o uso da linguagem são os únicos elementos\nque favorecem a habilidade do ritmo.", "C": "Pular corda, cantar e fazer teatro não são atividades\nque favorecem o desenvolvimento do ritmo.", "D": "Por meio do ritmo, a criança pode entender a\npontuação e a entonação típica de cada língua.", "E": "O ritmo da criança depende, somente, das condições\nde estimulação precoce realizadas pela família ao longo\ndo primeiro ano de vida."}, "g": "D", "j": "Por meio do ritmo, a crianca compreende a pontuacao e a entonacao tipica de cada lingua - habilidade central no desenvolvimento musical e linguistico. Demais alternativas reducionistas (condicao financeira, unicidade de elementos, atividades irrelevantes, dependencia exclusiva da familia)."}, {"id": "1299450", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Fraga (2016), assinale a alternativa correta\ncom relação à importância da entrevista inicial em\npsicodiagnóstico.", "alt": {"A": "A entrevista inicial é importante para que o psicólogo\nconheça o cliente de forma simplificada e possa extrair\ndados para a formulação de hipóteses e para o\nplanejamento de uma bateria de testes e possa\ninterpretar, com precisão, os dados dos testes e da\nentrevista devolutiva.", "B": "A entrevista inicial é importante para que o psicólogo\nconheça o cliente de forma exaustiva e possa extrair\ndados para a formulação de hipóteses,\nindependentemente do planejamento de uma bateria\nde testes e de que possa interpretar com precisão os\ndados dos testes e da entrevista devolutiva.", "C": "A entrevista inicial é importante para que o psicólogo\nconheça o cliente de forma exaustiva e possa extrair dados\npara a formulação de hipóteses e para o planejamento de\nbateria de testes e possa interpretar, com precisão, os\ndados dos testes e da entrevista devolutiva.", "D": "A entrevista inicial é importante para que o psicólogo\nconheça o cliente de forma exaustiva e possa extrair\ndados para a formulação de hipóteses e para o\nplanejamento de uma bateria de testes e possa\ninterpretar com precisão os dados dos testes.", "E": "A entrevista inicial é importante para que o psicólogo\nconheça o cliente de forma simplificada e possa extrair\ndados para a formulação de hipóteses e para o\nplanejamento de uma bateria de testes e possa\ninterpretar com precisão os dados dos testes"}, "g": "C", "j": "Em Fraga (2016), a entrevista inicial em psicodiagnostico permite conhecer o cliente de forma EXAUSTIVA, formular hipoteses, planejar a bateria de testes e interpretar com precisao tanto os dados dos testes quanto da entrevista devolutiva. Alternativa C reproduz integralmente; as demais omitem etapas ou contradizem a exaustividade."}, {"id": "1299449", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "No que concerne ao desenvolvimento psicomotor de uma\ncriança de três para quatro anos de idade, assinale a\nalternativa correta.", "alt": {"A": "Tem dificuldade de correr, parar, andar de ré, subir,\ndescer, girar, pular, cair e levantar.", "B": "Nessa idade, a criança ainda não entende o conceito da\nescrita.", "C": "Não entende que as palavras de um livro transmitem\nmensagens.", "D": "Presta atenção somente em grandes eventos sociais", "E": "Adora contar histórias sobre lugares que visitou\nrecentemente e coisas que aconteceram."}, "g": "E", "j": "Criancas de 3-4 anos tem capacidade narrativa desenvolvida e gostam de contar historias sobre experiencias recentes. Demais alternativas subestimam habilidades motoras, leitoras, sociais ou de compreensao da escrita - todas presentes nessa faixa etaria."}, {"id": "1299446", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "O “brincar” pode ser considerado como uma estratégia\nfundamental para a psicomotricidade. A respeito desse\ntema, assinale a alternativa correta.", "alt": {"A": "A prática psicomotora tem ação preventiva na\nalfabetização de crianças com problemas sociais.", "B": "É brincando que a criança aprende a aceitar suas\nfrustrações, na medida em que perde ou ganha.", "C": "O papel da sexualidade infantil no desenvolvimento e\nna aprendizagem é central na psicomotricidade,\nressaltando a importância de mecanismos de\ntransferência e identificação projetiva com a família.", "D": "Ao trazer os conceitos de psicomotricidade e do\nbrincar, suas relações podem ser recíprocas, visto que,\nao brincar, a criança, ao mesmo tempo, tem o prazer,\naprende e, ainda, socializa-se com diferentes sujeitos e\nobjetos. Dessa forma, vale a seguinte reflexão: a\npsicomotricidade consiste na unidade dinâmica das\natividades, dos gestos, das atitudes e das posturas,\nenquanto sistema expressivo, realizador e\nrepresentativo do “ser-em-ação” e da “coexistência”\ncom outrem”.", "E": "A teoria ressalta, primariamente, o papel da interação\nsocial no desenvolvimento cognitivo, em que a\naprendizagem do brincar precede o desenvolvimento e\nocorre dentro do contexto de um diálogo previamente\npreparado."}, "g": "D", "j": "O brincar e a psicomotricidade tem relacao reciproca (prazer + aprendizagem + socializacao), e psicomotricidade e definida como unidade dinamica das atividades, gestos, atitudes e posturas - sistema expressivo do 'ser-em-acao' e da 'coexistencia'. Demais alternativas reduzem ou distorcem o conceito."}, {"id": "1299445", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Ao pensar em um desenvolvimento normativo das\nhabilidades psicomotoras em crianças do primeiro ano do\nensino fundamental, espera-se que elas consigam realizar\natividades de equilíbrio, imitação, reconhecimento e\nnomeação das partes do corpo em si e no outro,\ndissociação de movimentos, velocidade e precisão motora e\nhabilidades rítmicas. A partir dessa informação, assinale a\nalternativa incorreta.", "alt": {"A": "Os elementos psicomotores bem organizados atuam\nde forma integrada e são requisitos essenciais para que\na aprendizagem escolar aconteça de forma fluente e\nregular.", "B": "Os meninos sempre são melhores que as meninas\nnessas atividades, por causa da plasticidade de seu\ncérebro e dos estímulos socioambientais que recebem.", "C": "Cada uma dessas unidades básicas exibe uma estrutura\nhierarquizada, com pelo menos três zonas corticais\nconstruídas uma sobre a outra: as áreas primárias, que\nsão áreas de projeção, recebem impulsos da periferia\nou os enviam para ela; as áreas secundárias, que são\náreas de projeção-associação, nas quais as informações\nque chegam são processadas ou reprogramadas; e as\náreas terciárias, de superposição, sendo os últimos\nsistemas dos hemisférios cerebrais a se desenvolverem\ne responsáveis pelas formas mais complexas de\natividade mental, que requerem a participação de\nvárias áreas corticais, como a linguagem e a\naprendizagem.", "D": "A aprendizagem ocorre por meio da mudança de\ncomportamento viabilizada pela plasticidade neural.", "E": "A criança com seis anos de idade ingressa na escola e\nbruscamente é exposta a uma situação nova, à qual\ndeverá se adaptar rapidamente. Os problemas com os\nquais ela se envolverá implicam, em muitos casos, a\nreconsideração de hábitos e atitudes anteriores. Essa\nexigência de desempenho é exacerbada pelas\ncomparações feitas entre uma criança e outra e esse\nambiente competitivo passará, rapidamente, a ter\nsignificado afetivo e moral."}, "g": "B", "j": "Questao pede INCORRETA. Afirmar que 'meninos SEMPRE sao melhores que meninas' nas habilidades psicomotoras e estereotipo de genero, contrario a literatura cientifica. Demais alternativas descrevem corretamente integracao psicomotora, organizacao hierarquica das areas corticais (Luria), aprendizagem por plasticidade e adaptacao escolar aos 6 anos."}, {"id": "1299443", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Piaget", "Teorias da Personalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "Fontana, em A importância da psicomotricidade na\neducação infantil (2012), cita que Wallon, Piaget e\nAjuriaguerra iniciaram os estudos da psicomotricidade com\npesquisas na área das patologias para, logo após, se\naprofundarem nos estudos voltados para o campo do\ndesenvolvimento humano. Considerando essa informação,\nassinale a alternativa incorreta.", "alt": {"A": "Hoje a psicomotricidade ocupa um lugar de destaque\nna educação perceptivo-motora, buscando o\ndesenvolvimento global da criança, fazendo com que\nos profissionais de educação física que atuam nas\nescolas tenham uma nova perspectiva pedagógica e\nmelhorando a qualidade de sua aula e o processo de\nensino-aprendizagem.", "B": "A base do processo intelectivo e da aprendizagem da\ncriança está na estrutura da educação psicomotora, em\nque sua evolução parte do geral para o específico.", "C": "A formação das habilidades físicas do indivíduo\nacontecerá ao longo de sua interação com a família.", "D": "A aprendizagem ocorre na vivência do dia a dia,\nentretanto, a escola, sendo uma instituição social que\nse apresenta como responsável pela educação\nsistemática de crianças, jovens e adultos, deve dar\nclareza e segurança quanto aos objetivos e às\natividades propostas", "E": "A educação psicomotora auxilia a criança, em sua\npsicomotricidade, em seus aspectos neurológicos de\nmaturação, em planos rítmicos e espaciais, no plano da\npalavra e no plano corporal, a adquirir o estágio de\nperfeição motora até o final da infância, que ocorre\nentre os sete e os onze anos de idade."}, "g": "C", "j": "Questao pede INCORRETA. Formacao das habilidades fisicas NAO ocorre 'SOMENTE pela interacao com a familia' - envolve escola, pares, atividades estruturadas e outros contextos. Demais alternativas descrevem corretamente o lugar da psicomotricidade na educacao, base intelectivo-perceptual, dia a dia e maturacao."}, {"id": "1299440", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Os objetivos do trabalho corporal em Ramain-Thiers, de\nforma geral, são despertar a “atenção interiorizada” e\ntornar o indivíduo uno nas relações entre seu mundo\ninterno e a sociedade em que vive. Essa teoria está baseada\nno desenho a seguir.           O desenho demostra um corpo que se constrói no aspecto\nbiológico, fantasmático e psicanalítico e depois se mostra\nno psicomotor. A partir dessa condição, foram gerados\nobjetivos específicos para a realização do trabalho. São\neles:", "alt": {"A": "liberar recalques; liberar a repressão sexual; despertar\na sensibilidade; promover a integração\nmente-consciência corporal-afetos-social; facilitar a\ninter-relação do indivíduo nos grupos; e fortalecer o\nnível da realidade e a estrutura egoica.", "B": "liberar recalques; liberar a repressão sexual; despertar\na sensibilidade; promover a integração\nmente-consciência corporal-afetos-social; interrogar a\nformação do esquema e da imagem corporal; facilitar a\ninter-relação do indivíduo nos grupos; e fortalecer o\nnível da realidade e a estrutura egoica.", "C": "liberar recalques; liberar a depressão sexual e social;\ndespertar a sensibilidade; promover a integração\nmente-consciência corporal-afetos-social; favorecer a\nformação do esquema e da imagem corporal; facilitar a\ninter-relação do indivíduo nos grupos; e fortalecer o\nnível da realidade e a estrutura egoica.", "D": "liberar recalques; liberar a repressão sexual; despertar\na sensibilidade; promover a integração\nmente-consciência corporal-afetos-social; favorecer a\nformação do esquema e da imagem corporal; facilitar a\ninter-relação do indivíduo nos grupos; e fortalecer o\nnível da realidade e a estrutura egoica.", "E": "liberar recalques; liberar a repressão sexual; despertar\na sensibilidade; promover a integração\nmente-consciência corporal-afetos-social; favorecer a\nformação do esquema e da imagem corporal; facilitar a\ninter-relação do indivíduo nos grupos; e fortalecer o\nnível da realidade e a estrutura fantasmática individual."}, "g": "D", "j": "Objetivos do trabalho corporal em Ramain-Thiers: liberar recalques, liberar repressao sexual, despertar sensibilidade, integrar mente-corpo-afeto-social, favorecer formacao de esquema e imagem corporal, facilitar inter-relacao em grupos e fortalecer realidade/estrutura egoica. Alternativa D reproduz com precisao."}, {"id": "1299438", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Com relação à atuação do psicomotricista na terceira idade,\njulgue os seguintes itens.      \nI. A saúde do cérebro depende da saúde de todo o corpo.\n  II. Tudo se relaciona ao estilo de vida, e não à idade: até\nsessenta ou setenta anos de idade, os problemas de\nmemória, atenção, fluência verbal ou execução de\npequenas tarefas estão relacionados a excesso de\nestresse, a desequilíbrio emocional, a sono desregrado,\nà alimentação desbalanceada e, principalmente, a\nsedentarismo.\n  III. Somente o exercício físico voluntário e prazeroso é\nsuficiente e eficaz para manter a massa cinzenta.      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Itens I (saude cerebral depende do corpo) e II (estilo de vida x idade) corretos. Item III erra ao afirmar que SOMENTE o exercicio voluntario e suficiente e eficaz - manutencao da massa cinzenta envolve multiplos fatores (sono, alimentacao, cognicao, vinculos)."}, {"id": "1299434", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com a visão de Thiers (1998), a construção do\nsujeito social passa pela criança, pelo adolescente e por seu\ndesenvolvimento psíquico e pelas questões sociológicas e\nantropológicas. Nesse cenário, assinale a alternativa que\nnão apresenta desvio quanto à atuação do psicólogo\nescolar.", "alt": {"A": "Os adolescentes são crianças adultas que caminham\nem direção de si mesmos, buscando viver em uma\nsociedade na qual eles sucumbem, e a obrigação do\nterapeuta é vê-los como seres perdidos que buscam\nseus sonhos.", "B": "Os adolescentes têm problemas que são inerentes à\nprópria transição, como, por exemplo, distinguir\npassado, presente e futuro. A busca da identidade está\nintrinsicamente ligada aos lutos que precisa viver,\nentre eles, a perda da infância e do próprio corpo, que\nse transforma.", "C": "Os adolescentes têm problemas que não são inerentes\na essa fase, mas ligados efetivamente às condições\nsocioculturais e à própria família, que não lida com os\nlutos.", "D": "Os adolescentes são pessoas que causam agitação sem\nmotivo e(ou) consistência psíquica, uma vez que\nprecisam deixar sua marca na vida de seus pais.", "E": "Os adolescentes são pessoas referenciadas somente\npor seu grupo, têm necessidades fisiológicas causadas\npelas mudanças das glândulas sexuais e não atuam de\nforma sensível quanto às perdas corporais."}, "g": "B", "j": "Em Thiers (1998), os problemas adolescentes sao inerentes a propria transicao - busca de identidade ligada aos lutos pela infancia e pelo corpo que se transforma. Demais alternativas estigmatizam (criancas adultas, agitacao sem motivo) ou negam o carater inerente da fase."}, {"id": "1299433", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Le Boulch, julgue os itens que se seguem acerca\nda atuação do psicólogo na educação psicomotora na idade\npré-escolar.\n      I. Deve-se observar que, partindo do princípio de que a\nprioridade fundamental dessa fase é a atividade\nmotora global, a criança está buscando o\naprimoramento da expressão verbal, a expressão das\ncoordenações finas da mão e dos dedos e a expressão\nvisomanual, a valorização da percepção e do\nconhecimento do seu próprio corpo, por meio do jogo\nda função de interiorização, o ritmo, a percepção do\nespaço e das estruturas espaciais e o grafismo.  \nII. Deve-se observar que, partindo do princípio de que a\nprioridade fundamental dessa fase é a inteligência, a\ncriança está buscando o aprimoramento da expressão\nverbal, a expressão das coordenações finas da mão e\ndos dedos e a expressão visomanual, a valorização da\npercepção e do conhecimento do seu próprio corpo,\npor meio do jogo da função de interiorização, o ritmo,\na percepção do espaço e das estruturas espaciais e o\ngrafismo.\n  III. Deve-se observar que, partindo do princípio de que a\nprioridade fundamental dessa fase é a comunicação, a\ncriança está buscando o aprimoramento da expressão\nverbal, a expressão das coordenações finas da mão e\ndos dedos e a expressão visomanual, a valorização da\npercepção e do conhecimento do seu próprio corpo,\npor meio do jogo da função de interiorização, o ritmo,\na percepção do espaço e das estruturas espaciais e o\ngrafismo.\n      Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Apenas os itens I e II estão certos."}, "g": "B", "j": "Em Le Boulch, a prioridade fundamental na idade pre-escolar e a ATIVIDADE MOTORA GLOBAL (item I correto). Itens II (inteligencia) e III (comunicacao) trocam o eixo principal por outras dimensoes que sao desdobramentos, nao a base."}, {"id": "1299432", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo o propósito proposto por Thiers (1998) para a\nfunção do sociopsicomotricista, assinale a alternativa\nincorreta.", "alt": {"A": "O psicomotricista deve sempre preparar o material\ncom antecedência, pois esse é o seu instrumento de\nrelação.", "B": "O psicomotricista deve ter uma disponibilidade\nincondicional para com o grupo.", "C": "O psicomotricista deve ter uma identidade única,\nintegrando em si sua própria existência, e aceitar\ntrabalhar o indivíduo de forma global\n(corpo-mente-afetos-social).", "D": "O psicomotricista pode fazer as devolutivas por\ninterpretação, clarificação, por meio de uma proposta\npela leitura horizontal ou individualmente.", "E": "O psicomotricista deve falar e agir depois que os\nfenômenos ocorrem porque, às vezes, é importante\nque o terapeuta se omita para manter a liberdade de\nexpressão do grupo."}, "g": "E", "j": "Questao pede INCORRETA. Em Thiers, o sociopsicomotricista precisa estar PRESENTE, atento e atuante durante os fenomenos, intervindo no tempo proprio - nao se omite nem age 'depois' das ocorrencias. Demais alternativas reproduzem corretamente preparacao, disponibilidade, identidade integrada e devolutivas."}, {"id": "1299430", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à atuação do psicólogo psicomotricista, assinale a\nalternativa correta", "alt": {"A": "Pode fazer avaliação psicomotora, avaliação\npsicomotora relacionada ao grafismo, psicomotricidade\nindividual e psicomotricidade em grupo, entretanto\nnão deve realizar terapia psicomotora individual, uma\nvez que o grupo é fundamental para a\npsicomotricidade.", "B": "Pode fazer avaliação psicomotora, avaliação\npsicomotora relacionada ao grafismo e\npsicomotricidade individual, mas não pode fazer\npsicomotricidade em grupo, terapia psicomotora\nindividual e terapia psicomotora em grupo.", "C": "Pode fazer avaliação psicomotora, mas não pode fazer\na avaliação psicomotora relacionada ao grafismo,\npsicomotricidade individual, psicomotricidade em\ngrupo, terapia psicomotora individual e terapia\npsicomotora em grupo.", "D": "Pode fazer avaliação psicomotora, avaliação\npsicomotora relacionada ao grafismo, psicomotricidade\nindividual, psicomotricidade em grupo, terapia\npsicomotora individual e terapia psicomotora em\ngrupo.", "E": "Pode fazer avaliação psicomotora, avaliação\npsicomotora relacionada ao grafismo, psicomotricidade\nindividual, psicomotricidade em grupo exclusivamente\npara crianças, terapia psicomotora individual e terapia\npsicomotora em grupo."}, "g": "D", "j": "O psicologo psicomotricista pode realizar todo o espectro de praticas: avaliacao psicomotora (incluindo grafismo), psicomotricidade individual e em grupo, terapia psicomotora individual e em grupo - sem restricoes etarias ou de modalidade. Demais alternativas restringem indevidamente o escopo."}, {"id": "1299426", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Existem diferenças entre a psicomotricidade funcional e a\npsicomotricidade relacional. Acerca desse tema, assinale a\nalternativa incorreta.", "alt": {"A": "Na psicomotricidade funcional, a criança depende das\nescolhas feitas pelo profissional e raramente tem\ncontato corporal.", "B": "Na psicomotricidade funcional, as atividades são\ndirigidas pelo psicomotricista, em um enfoque dualista.", "C": "Na psicomotricidade relacional, o brincar é livre,\nbuscando um prazer no movimento.", "D": "Na psicomotricidade relacional, o psicomotricista\nprecisa ter uma formação pessoal consolidada e uma\npostura ativa e influente sobre o processo nas sessões.", "E": "Na psicomotricidade relacional, há o contato corporal,\na apresentação de diversos modelos motores e o\ncontato com outros profissionais envolvidos com a\ncriança."}, "g": "D", "j": "Questao pede INCORRETA. Na psicomotricidade RELACIONAL, o psicomotricista assume postura ATIVA-DISPONIVEL mas NAO INFLUENTE sobre o processo - respeita o brincar livre e o protagonismo da crianca. Demais alternativas descrevem corretamente a funcional (dirigida, dualista) e a relacional (brincar livre, contato corporal)."}, {"id": "1299425", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicomotricidade relacional, na perspectiva da educação,\nentende que a atuação se estabelece de forma mais\npreventiva, buscando potencializar o desenvolvimento\nintegral das crianças, indicando e reforçando todo e\nqualquer aspecto positivo de sua conduta, de seu modo de\nser, e trabalhando com o que há de positivo nas relações\ninterpessoais, reforçando-as e renovando-as. Considerando\nessa informação, assinale a alternativa correta.", "alt": {"A": "A relação entre a escola e a psicomotricidade\ndependerá das condições socioeconômicas.", "B": "Sendo o corpo o primeiro meio disponível e utilizado\npara se entrar em contato com o conhecimento, a\naprendizagem passa a ter uma inter-relação intrínseca\ncom a motricidade.", "C": "Todas as condições usadas na psicomotricidade escolar\nservem para os diferentes lócus de aplicação da\npsicomotricidade.", "D": "As instituições escolares têm programas que\nidentificam alunos com problema psicomotor para\nindicar a psicoterapia.", "E": "As instituições de saúde pública têm programas que\nidentificam crianças com problema psicomotor para\nindicar a psicoterapia."}, "g": "B", "j": "Sendo o corpo o primeiro meio para entrar em contato com o conhecimento, a aprendizagem tem inter-relacao intrinseca com a motricidade - tese central da psicomotricidade educacional. Demais alternativas reduzem a praticas socioeconomicas, generalizam locais ou confundem com encaminhamentos clinicos."}, {"id": "1299423", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à condução de um processo pericial, assinale a\nalternativa correta.", "alt": {"A": "O psicólogo assistente técnico não deve estar presente\ndurante a realização dos procedimentos metodológicos\nque norteiam o atendimento do psicólogo perito e\nvice-versa, para que não haja interferência na dinâmica\ne na qualidade do serviço realizado.", "B": "O psicólogo assistente técnico deve estar presente\ndurante a realização dos procedimentos metodológicos\nque norteiam o atendimento do psicólogo perito e\nvice-versa, para que não haja interferência na dinâmica\ne na qualidade do serviço realizado.", "C": "O psicólogo assistente técnico não deve estar presente\ndurante a realização dos procedimentos metodológicos\nque norteiam o atendimento do psicólogo perito e\nvice-versa, o acompanhamento na dinâmica e a\nqualidade do serviço realizado.", "D": "O psicólogo assistente técnico deve estar presente\ndurante a realização dos procedimentos metodológicos\nque norteiam o atendimento do psicólogo perito e\nvice-versa, para garantir a qualidade do serviço\nrealizado.", "E": "O psicólogo assistente técnico deve acompanhar\nsistematicamente a realização dos procedimentos\nmetodológicos que norteiam o atendimento do\npsicólogo perito e vice-versa, para que não haja\ninterferência na dinâmica e na qualidade do serviço\nrealizado."}, "g": "A", "j": "Res CFP 8/2010 estabelece que o psicologo assistente tecnico NAO deve estar presente durante os procedimentos metodologicos do perito (e vice-versa), preservando a dinamica e a qualidade da avaliacao. Demais alternativas defendem presenca ou acompanhamento sistematico, contrariando a norma."}, {"id": "1299422", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Perícia Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "É vedado ao psicólogo, enquanto psicoterapeuta das partes\nem litígio,", "alt": {"A": "eximir-se de atuar como perito ou assistente técnico de\npessoas atendidas por ele e(ou) de terceiros envolvidos\nna mesma situação litigiosa.", "B": "produzir documentos advindos do processo\npsicoterápico com a finalidade de fornecer\ninformações à instância judicial acerca das pessoas\natendidas.", "C": "deixar de manter atendimento de criança, adolescente\nou interdito, mesmo com o consentimento formal.", "D": "atuar como perito ou assistente técnico de pessoas\natendidas por ele e(ou) de terceiros envolvidos na\nmesma situação litigiosa.", "E": "atuar quando a pessoa atendida for criança,\nadolescente ou interdito, sem o consentimento formal\ndos genitores."}, "g": "D", "j": "E VEDADO ao psicologo psicoterapeuta das partes atuar como perito ou assistente tecnico dessas mesmas pessoas (Res CFP 8/2010, art. 2) - duplo vinculo viola a etica e a imparcialidade. Demais alternativas invertem ou reformulam vedacoes ja previstas."}, {"id": "1299421", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Tendo em vista a Resolução CFP n.⁰ 8/2010, julgue os itens\na seguir.I. Conforme a especificidade de cada situação, o trabalho\npericial poderá contemplar observações, entrevistas,\nvisitas domiciliares e institucionais, aplicação de testes\npsicológicos, utilização de recursos lúdicos e outros\ninstrumentos, métodos e técnicas reconhecidas pelo\nConselho Federal de Psicologia.II. A realização da perícia exige espaço físico apropriado\nque zele pela privacidade do atendido, bem como pela\nqualidade dos recursos técnicos utilizados.\nIII. O psicólogo perito poderá atuar em equipe\nmultiprofissional desde que preserve sua\nespecificidade e seu limite de intervenção, não se\nsubordinando, técnica e profissionalmente, a outras\náreas.\nAssinale a alternativa correta", "alt": {"A": "Apenas o item III está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos conforme Res CFP 8/2010: trabalho pericial inclui multiplos instrumentos (I); exige espaco apropriado (II); atuacao em equipe multiprofissional preservando especificidade tecnica (III)."}, {"id": "1299418", "d": "psicologia", "a": ["Avaliação Psicológica", "Avaliação Psiquiátrica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A respeito da avaliação de casos de alienação parental, a\nperícia será realizada", "alt": {"A": "por equipe multidisciplinar habilitada, sendo exigido o\nhistórico profissional ou acadêmico no atendimento de\ncasos infantis.", "B": "por profissional, sendo exigida, em qualquer caso, a\naptidão comprovada por histórico profissional ou\nacadêmico para diagnosticar alterações\npsicopatológicas tanto em crianças quanto em adultos.", "C": "por profissional ou equipe multidisciplinar habilitados,\nsendo exigida, em qualquer caso, a aptidão\ncomprovada por histórico profissional ou acadêmico\npara diagnosticar atos de alienação parental.", "D": "por profissional com histórico de expertise para\ndiagnosticar atos de alienação parental.", "E": "por profissional da área de saúde mental."}, "g": "C", "j": "Lei 12.318/2010 (Alienacao Parental), art. 5, paragrafo 2: pericia sera realizada por profissional ou equipe multidisciplinar habilitados, com aptidao comprovada por historico profissional ou academico para diagnosticar atos de alienacao parental."}, {"id": "1299417", "d": "psicologia", "a": ["Avaliação Psiquiátrica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Caso haja indício da prática de ato de alienação parental,\nem ação autônoma ou incidental, o juiz, se necessário,\ndeterminará", "alt": {"A": "prisão do genitor responsabilizado e perícia psicológica\nou biopsicossocial.", "B": "avaliação psiquiátrica do genitor e perícia psicológica\nou biopsicossocial.", "C": "suspensão das visitas.", "D": "perícia psicológica ou biopsicossocial.", "E": "avaliação psiquiátrica do genitor e início de processo\nde responsabilidade."}, "g": "D", "j": "Lei 12.318/2010, art. 5: havendo indicio de alienacao parental, o juiz determinara, se necessario, pericia psicologica ou biopsicossocial. Demais alternativas extrapolam (prisao, avaliacao psiquiatrica obrigatoria, suspensao automatica de visitas)."}, {"id": "1299412", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A perícia psicológica diferencia-se das avaliações realizadas\nem contextos clínicos e, segundo a literatura, alguns\ncuidados devem ser observados quanto às etapas do\nprocesso. São eles:", "alt": {"A": "objetivos; métodos; instrumentos; e ações do\npsicólogo.", "B": "preparação; coleta de dados; interpretação de dados; e\ncomunicação de dados.", "C": "objetivos; interpretação de dados; instrumentos; e\nmétodos.", "D": "coleta de dados; objetivos; instrumentos;\ninterpretação de dados; e ações do psicólogo.", "E": "preparação; objetivos; métodos; e instrumentos."}, "g": "B", "j": "Em Rovinski, as etapas da pericia psicologica sao: preparacao, coleta de dados, interpretacao de dados e comunicacao dos dados - ciclo metodologico distintivo da avaliacao clinica. Demais alternativas misturam objetivos com etapas ou omitem fases centrais."}, {"id": "1299411", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Entrevista Psicológica e Técnicas de Entrevista", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "O objetivo da entrevista investigativa é", "alt": {"A": "verificar a demanda.", "B": "elucidar fatos.", "C": "identificar autores.", "D": "implicar o avaliando.", "E": "avaliar o potencial de insight."}, "g": "B", "j": "O objetivo da entrevista investigativa em psicologia juridica e elucidar fatos - distingue-se da entrevista clinica (verificar demanda, avaliar insight) e da investigacao policial (identificar autores)."}, {"id": "1299409", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A perícia, segundo Rovinski, é considerada como", "alt": {"A": "o processo que decide o pleito jurídico.", "B": "a decisão sobre a questão jurídica.", "C": "um meio de prova.", "D": "fato improcedente.", "E": "um exame inquestionável."}, "g": "C", "j": "Em Rovinski, a pericia psicologica e considerada um MEIO DE PROVA - subsidia, mas nao decide o pleito juridico (cabe ao juiz). Demais alternativas confundem o papel auxiliar da pericia com a decisao judicial ou negam sua valencia probatoria."}, {"id": "1299408", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "A ciência que, valendo-se de conceitos, conhecimentos,\nprincípios e métodos de investigação e prevenção\nmédico-psicológicos (e sociofamiliares), ocupa-se da pessoa\ndo apenado, para nele investigar a dinâmica de sua conduta\ncriminosa, sua personalidade e seu “estado perigoso”\n(diagnóstico), as perspectivas de desdobramentos futuros\n(prognóstico) e assim propor e perseguir estratégias de\nintervenção, com vistas à superação ou contenção de uma\npossível tendência criminal e a evitar uma recidiva\n(tratamento), segundo Sá (apud Diretrizes para Atuação e\nFormação dos Psicólogos do Sistema Prisional Brasileiro), é\ndenominada", "alt": {"A": "criminologia psicológica.", "B": "psicologia crítica.", "C": "criminologia clínica.", "D": "psicopatologia criminal.", "E": "criminologia psicossocial."}, "g": "C", "j": "Sa define criminologia clinica como ciencia que investiga diagnostico, prognostico e tratamento do apenado, articulando metodos medico-psicologicos e sociofamiliares - distincao classica em relacao a criminologia critica ou psicossocial."}, {"id": "1299407", "d": "psicologia", "a": ["Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto às duas vertentes da criminologia, a criminologia\nclínica e a criminologia crítica, assinale a alternativa correta.", "alt": {"A": "A criminologia clínica responsabiliza o sujeito como\nautor do fato antijurídico, preconiza sua segregação e\ntem, na observação, na vigilância, na disciplina e nos\ndiversos métodos punitivos, a forma de “tratamento”\npara corrigir o indivíduo. A criminologia crítica rebate\ntais procedimentos, alegando que a vulnerabilidade\nsocial recruta, seleciona e cria estereótipos que\npoderão direcionar o destino de um significativo\ncontingente da sociedade: a prisão.", "B": "A criminologia crítica responsabiliza o sujeito como\nautor do fato antijurídico, preconiza sua segregação e\ntem, na observação, na vigilância, na disciplina e nos\ndiversos métodos punitivos, a forma de “tratamento”\npara corrigir o indivíduo. A criminologia clínica alega\nque a vulnerabilidade social recruta, seleciona e cria\nestereótipos que poderão direcionar o destino de um\nsignificativo contingente da sociedade: a prisão.", "C": "A criminologia clínica responsabiliza a sociedade por\ninduzir o fato antijurídico e preconiza a ressignificação\nde infração. A criminologia crítica mostra a ação\nindividual como de importância no contexto social e no\ndirecionamento do destino da sociedade.", "D": "A criminologia crítica responsabiliza a interação entre\nsujeito e sociedade, como autores não dissociáveis,\npelo fato antijurídico, preconiza a análise e a revisão de\nfatos e tem, na observação, na vigilância, na disciplina\ne nos diversos métodos assertivos, a proposta de\nintervenção para reordenar a díade. A criminologia\nclínica alega que a vulnerabilidade social induz e\nseleciona, por estereótipos, a direcionalidade do\ndestino pela dominância de classes.", "E": "A criminologia clínica entende que a sociedade é o\nautor-indutor do fato antijurídico, por suas\nclassificações e por seus estereótipos, e preconiza a\nreorganização social, da forma mais democrática, para\ncorrigir o risco de novas infrações. A criminologia\ncrítica rebate tais procedimentos, alegando que a\nvulnerabilidade social recruta, seleciona e cria\nestereótipos que poderão direcionar o destino de um\nsignificativo contingente da sociedade: a prisão."}, "g": "A", "j": "Criminologia clinica responsabiliza o sujeito e preconiza segregacao/disciplina como tratamento; criminologia critica rebate apontando que a vulnerabilidade social recruta e seleciona contingentes para a prisao. Alternativa A reproduz essa diferenciacao classica."}, {"id": "1299401", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "Na Lei de execução penal, a proposta para a atividade do\nprofissional psicólogo é compor", "alt": {"A": "a Comissão Técnica de Classificação, responsável pela\nelaboração dos exames criminológicos e de\npersonalidade, além do programa individualizador da\npena.", "B": "a Comissão Técnica de Classificação e\nAcompanhamento, responsável pela avaliação da\npersonalidade e do programa de ressocialização.", "C": "a Comissão Técnica de Classificação da Pena,\nresponsável pela elaboração dos exames\ncriminológicos e de personalidade e de ressocialização.", "D": "a Comissão Técnica de Classificação de Risco,\nresponsável pela elaboração dos exames\ncriminológicos e de personalidade, além do programa\nindividualizador da pena.", "E": "a Comissão Técnica de Classificação e Progressão da\nPena, responsável pela elaboração dos exames\ncriminológicos e de personalidade."}, "g": "A", "j": "LEP preve a Comissao Tecnica de Classificacao (CTC), responsavel pelos exames criminologicos, de personalidade e pelo programa individualizador da pena - composta tambem por psicologo. Demais alternativas inventam nomenclaturas inexistentes na lei."}, {"id": "1299400", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "No que diz respeito às questões éticas decorrentes das\nfunções de perito e de assistente técnico, descritas por\nBrandão e Gonçalves, assinale a alternativa correta.", "alt": {"A": "É um ilícito penal a falsa perícia condicionada à\nverificação e o psicólogo responderá criminalmente se\nfor condenado em julgamento ético, realizado pelo\nConselho Federal de Psicologia.", "B": "O descumprimento dos prazos processuais de entrega\ndos laudos periciais, conforme previsto no Código de\nProcesso Civil, determina falta ética punível com:\nadvertência; e censura ou censura pública.", "C": "O Código de Ética tem respaldada a admissibilidade de\nquebra do sigilo profissional quando o psicólogo estiver\ndiante de conhecimento de fatos que deva denunciar\ndevido à sua atuação profissional.", "D": "O psicólogo apresenta autonomia e liberdade, como\nperito ou assistente técnico, para utilizar todos os\ntestes psicológicos disponíveis no mercado, desde que\ncomprovado o fundamento e o embasamento\nteórico-metodológico.", "E": "A condição de uso de testes psicológicos pode ser\nrespaldada na necessidade do caso, mesmo que\ndestoante do originalmente preconizado pelo manual."}, "g": "C", "j": "O CEP do psicologo admite a quebra de sigilo quando o profissional toma conhecimento de fatos cuja denuncia decorra de sua atuacao - excecao prevista para preservar direitos e seguranca. Demais alternativas distorcem competencias (CFP nao julga ilicito penal), prazos ou liberdade no uso de testes."}, {"id": "1299396", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2020", "org": "CFP", "t": "", "e": "A Lei de execuções penais previa, segundo Rovinski apud Sá\n(2007), três instrumentos de avaliação técnica. São eles: o\nexame", "alt": {"A": "psiquiátrico; o exame criminológico; e o exame de\nestado mental.", "B": "Criminalístico; o exame criminológico; e o exame de\npersonalidade.", "C": "de estado mental; o parecer das comissões técnicas de\nclassificação; e o exame criminalístico.", "D": "criminológico; o exame de personalidade; e o parecer\ndas comissões técnicas de classificação.", "E": "Criminológico; o exame de corpo e delito; e o exame\nde estado mental."}, "g": "D", "j": "LEP preve tres instrumentos de avaliacao tecnica: exame criminologico, exame de personalidade e parecer das comissoes tecnicas de classificacao - exatamente o conjunto descrito em D."}, {"id": "1299395", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Para realizar perícia psicológica, duas condições são\nnecessárias ao profissional psicólogo. Assinale a alternativa\nque as apresenta corretamente.", "alt": {"A": "possuir diploma de curso de especialização na área\nforense e possuir especialização pelo Conselho Federal\nde Psicologia", "B": "possuir especialização pelo Conselho Federal de\nPsicologia e possuir mestrado ou doutorado", "C": "possuir diploma de graduação em psicologia e estar\ninscrito no Conselho Regional de Psicologia", "D": "possuir especialização em psicologia jurídica e ser\nespecialista pelo Conselho Federal de Psicologia.", "E": "possuir título de pós-graduação strictu sensu e título de\npós-graduação lato sensu em psicologia forense e\njurídica"}, "g": "C", "j": "Para realizar pericia psicologica sao necessarios: diploma de graduacao em psicologia e inscricao regular no CRP. Especializacao, mestrado, doutorado e titulos de especialista nao sao requisitos minimos legais para o exercicio da pericia."}, {"id": "1299394", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2020", "org": "CFP", "t": "", "e": "Psicologia e direito, mesmo consistindo em disciplinas\ndistintas, possuem, como ponto de intersecção, o interesse\nno(na):", "alt": {"A": "aplicação de normas.", "B": "comportamento humano.", "C": "forma de pensar do homem.", "D": "entendimento da sociedade.", "E": "busca pela verdade."}, "g": "B", "j": "O ponto de interseccao entre psicologia e direito e o COMPORTAMENTO HUMANO - ambas as disciplinas, com metodos distintos, tomam-no como objeto. Demais alternativas listam aspectos derivados (normas, pensamento, sociedade, verdade), nao o objeto comum nuclear."}, {"id": "1299392", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Siqueira (2008), a ética deixou de ser uma\nquestão estritamente do indivíduo que enfrenta dilemas\nmorais em sua vida, adquirindo uma dimensão maior, a\norganizacional, que impacta o público interno,\nespecificamente os empregados, e a sociedade como um\ntodo. Nesse contexto, assinale a alternativa incorreta.", "alt": {"A": "A ética empresarial é definida como um conjunto de\nregras, princípios e padrões que regem e orientam o\ncomportamento da organização no mundo dos\nnegócios.", "B": "Práticas organizacionais éticas seriam as baseadas em\nvalores morais, tais como respeito no trato\ninterpessoal, valores de igualdade de oportunidade,\ntratamento não discriminatório, respeito aos prazos,\ncomprometimento com normas sociais etc.", "C": "A literatura é farta em apontar os conceitos de ética\nempresarial e responsabilidade social como\nintimamente relacionados, podendo, em alguns casos,\nconsiderá-los como sinônimos.", "D": "O custo de uma conduta antiética pode ir muito além\nde penalidades legais, notícias desfavoráveis na\nimprensa ou prejuízos nas relações com os clientes.", "E": "A tendência atual consiste em passar de iniciativas\néticas de base legal para iniciativas cujas raízes estejam\nna cultura ou na integridade das empresas, nas quais a\nética deve estar presente como valor fundamental."}, "g": "C", "j": "Questao pede INCORRETA. Etica empresarial e responsabilidade social NAO sao sinonimos - ainda que relacionadas, a primeira diz respeito a principios internos de conduta e a segunda envolve obrigacoes externas/sociais da empresa. Demais alternativas reproduzem corretamente Siqueira (2008)."}, {"id": "1299391", "d": "psicologia", "a": ["Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Para Bergamini e Coda (1997), podem existir divergências\nna relação entre o superior e seu subordinado. Tanto o\nsuperior quanto o subordinado darão grandes passos\nquando eles considerarem que esses conflitos podem ser\ncondições de desenvolvimento. A respeito de conflitos,\njulgue os itens que se seguem.      I. O superior está mal posicionado para servir como\nterapeuta de seus subordinados. Ele não deveria tentar\nfazer isso. Deveria saber o suficiente para distinguir os\nproblemas razoáveis das relações de trabalho daqueles\nconflitos neuróticos do desenvolvimento pessoal.\n  I. O superior e o subordinado podem aprender pela\nexperiência quando estiverem razoavelmente libertos\ndos conflitos passados. O crescimento e a mudança\nrealmente podem acontecer, dependendo, porém (tal\naprendizagem), dos alicerces sólidos de competência\npessoal de ambos.\n  III. O superior, ao se prender aos problemas razoáveis,\naumenta o sentimento de culpa que perturba as\nrelações de trabalho. Tal atitude serve para ampliar\ngrande parte daquilo que obscurece as comunicações.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Em Bergamini e Coda, o superior nao deve atuar como terapeuta dos conflitos neuroticos do subordinado (I) e ambos podem aprender pela experiencia quando libertos de conflitos passados (II). Item III erra ao defender que prender-se aos problemas razoaveis aumenta culpa - na verdade, esclarece e desimpede a comunicacao."}, {"id": "1299389", "d": "psicologia", "a": ["Grupos nas Organizações", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Schein (1982), um grupo é um conjunto de\npessoas que interagem umas com as outras, são\npsicologicamente conscientes umas das outras e\npercebem-se como grupo dentro de uma organização.\nSendo assim, a força básica para a formação de um grupo\nse origina no próprio processo organizacional. Com relação\na esse assunto, assinale a alternativa incorreta.", "alt": {"A": "Grupos formais são aqueles deliberadamente criados\npelos dirigentes com a finalidade de desempenharem\ntarefas específicas, visivelmente relacionadas com a\nmissão da organização em sua totalidade.", "B": "A totalidade das pessoas que comparecem ao trabalho\npossui necessidades que vão além daquelas\nnecessidades mínimas referentes à execução de sua\ntarefa. Assim, elas procuram satisfazer algumas dessas\nnecessidades por meio do desenvolvimento de uma\nsérie de relacionamentos para além do trabalho, com\noutros membros da organização, formando os grupos\ninformais.", "C": "A qualidade do trabalho de um setor da organização\ndepende da troca de informações entre seus membros,\no que torna importante projetar a infraestrutura física\ne de comunicação de tal modo que proporcione um\naumento dessas interações.", "D": "O modo como evolui a tendência para formação de\ngrupos informais depende muito da natureza do\ntrabalho das pessoas, de seus horários, da identificação\nentre eles e assim por diante.", "E": "O tamanho de um grupo pode ser ilimitado dentro das\norganizações, visto que as possibilidades de mútua\ninteração e mútua percepção consciente podem\nocorrer de forma indistinta."}, "g": "E", "j": "Questao pede INCORRETA. Em Schein, o tamanho de um grupo NAO e ilimitado - depende da possibilidade de interacao e percepcao consciente entre os membros, o que impoe limites efetivos. Demais alternativas descrevem corretamente grupos formais/informais, infraestrutura e fatores de formacao."}, {"id": "1299387", "d": "psicologia", "a": ["Qualidade de Vida", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Bergamini e Coda (1997), o tema qualidade\nde vida no trabalho sempre foi objeto de ampla discussão.\nNesse sentido, parece haver hoje uma situação em que os\nempregados vivenciam mais insatisfação que satisfação nas\nempresas onde trabalham. Embora tais efeitos da\ninsatisfação no trabalho ainda não tenham sido\nsuficientemente mapeados nas organizações brasileiras, é\nsabido que as prováveis consequências negativas estão\nligadas a alguns fatores. A respeito deles, julgue os\nseguintes itens.      \nI. São fatores a inércia organizacional e a dificuldade de\nimplantação eficaz de programas de melhoria de qualidade.  \nII. É um fator o comprometimento da saúde física e\nmental dos empregados.  \nIII. São fatores o estresse, as faltas, a baixa produtividade\ne o baixo desempenho no trabalho.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os fatores listados (inercia organizacional, comprometimento da saude fisica/mental, estresse/faltas/baixa produtividade) sao consequencias da insatisfacao no trabalho descritas por Bergamini e Coda."}, {"id": "1299383", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "O treinamento é uma das principais atividades da maioria\ndas grandes organizações, incluindo-se o Setor Público e o\nsetor privado, em todo o mundo. Conforme Spector (2004),\ncinco etapas são necessárias para que os programas de\ntreinamento das organizações sejam eficazes, e cada etapa\nobrigatoriamente deve ter como base a etapa que a\nprecede. A partir dessa informação, assinale a alternativa\ncorreta.", "alt": {"A": "A primeira etapa consiste em definir os objetivos do\ntreinamento. A segunda etapa consiste em conduzir\numa avaliação da necessidade de treinamento. A\nterceira etapa consiste no projeto de treinamento. A\nquarta etapa consiste na aplicação do treinamento\npropriamente dito. A quinta e última etapa consiste na\navaliação do treinamento.", "B": "A primeira etapa consiste no projeto de treinamento. A\nsegunda etapa consiste em definir os objetivos do\ntreinamento. A terceira etapa consiste em conduzir\numa avaliação da necessidade de treinamento. A\nquarta etapa consiste na aplicação do treinamento\npropriamente dito. A quinta e última etapa consiste na\navaliação do treinamento.", "C": "A primeira etapa consiste em conduzir uma avaliação\nda necessidade de treinamento. A segunda etapa\nconsiste em definir os objetivos do treinamento. A\nterceira etapa consiste no projeto de treinamento. A\nquarta etapa consiste na aplicação do treinamento\npropriamente dito. A quinta e última etapa consiste na\navaliação do treinamento.", "D": "A primeira etapa consiste em definir os objetivos do\ntreinamento. A segunda etapa consiste no projeto de\ntreinamento. A terceira etapa consiste em conduzir\numa avaliação da necessidade de treinamento. A\nquarta etapa consiste na aplicação do treinamento\npropriamente dito. A quinta e última etapa consiste na\navaliação do treinamento.", "E": "A primeira etapa consiste no projeto de treinamento. A\nsegunda etapa consiste em conduzir uma avaliação da\nnecessidade de treinamento. A terceira etapa consiste\nem definir os objetivos do treinamento. A quarta etapa\nconsiste na aplicação do treinamento propriamente\ndito. A quinta e última etapa consiste na avaliação do\ntreinamento."}, "g": "C", "j": "Em Spector, as cinco etapas do treinamento sao: 1) avaliacao da necessidade; 2) definicao de objetivos; 3) projeto; 4) aplicacao; 5) avaliacao. A logica e cumulativa - cada etapa baseia-se na anterior. Demais alternativas trocam a ordem inicial das etapas."}, {"id": "1299382", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Borges e Mourão (2013), no campo dos estudos\norganizacionais, o interesse pelo tema aprendizagem tem\ncrescido de forma rápida. A luta diuturna contra a\nobsolescência profissional requer das pessoas o\naprimoramento incessante de meios que levem à\naprendizagem e exige das organizações maior suporte a\nelas nos ambientes de trabalho. Considerando essas\ninformações, julgue os próximos itens.      \nI. Os desafios inerentes ao mundo do trabalho são\nmúltiplos e complexos. Por essa razão, a aprendizagem\nimpõe ao trabalhador uma atualização constante de\nsaberes, o que, consequentemente, exige grande\ndisposição para enfrentar a aventura de conhecer e\natribuir novos significados ao mundo em profunda\ntransformação.  \nII. A aprendizagem é um processo psicológico de\nmudança que ocorre no indivíduo e que não é apenas\nresultado direto da passagem do tempo, da maturação\nou de outros fenômenos associados à idade ou a fases\nda vida.\n  III. Os processos individuais de aprendizagem incluem a\naquisição (atenção, percepção, codificação), a retenção\n(memorização), a generalização e a transferência.      \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: a aprendizagem como atualizacao constante (I); como processo psicologico distinto de maturacao (II); e composta por aquisicao, retencao, generalizacao e transferencia (III) - definicao integrada de Borges & Mourao."}, {"id": "1299380", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Para Griffin e Morhead (2006), o comportamento\norganizacional tem estreita relação com vários desafios\norganizacionais e gerenciais. Sendo assim, assinale a\nalternativa incorreta quanto aos desafios e às\noportunidades que se colocam diante dos gestores e à sua\nrelevância no comportamento organizacional.", "alt": {"A": "Um grande desafio na área do comportamento\norganizacional é gerenciar demissões. O termo\ndownsizing denota um aumento proposital da força de\ntrabalho para minimizar a eliminação de divisões ou de\nnegócios inteiros, uma vez que esses cortes foram\ncomuns em meados da década de 1980. O downsizing\nfoi necessário porque as organizações realizaram\ngrandes programas de enxugamento, que provocaram\na demissão de milhares de funcionários. As\norganizações que empreenderam iniciativas de\ndownsizing precisavam gerir os efeitos das demissões,\nnão só sobre os funcionários que saíram, mas também\nsobre os que permaneceram e se sentiam ameaçados.", "B": "Um grande desafio na área do comportamento\norganizacional é a adequação da força de trabalho. O\ntermo “terceirizar” significa contratar outras\norganizações para desempenhar algumas funções. Essa\nprática tornou-se corriqueira há muitos anos. Muitas\norganizações costumam terceirizar atividades como\nlimpeza, alimentação de funcionários, segurança etc.\nPresume-se que essa organização, ao concentrar a\nforça de trabalho em suas atividades principais,\nforneça estabilidade de empregos e se tome mais\ncompetitiva.", "C": "Um grande desafio na área do comportamento\norganizacional é a expansão da organização na medida\nem que ela se desenvolve. Com a chegada da alta\ntecnologia, a mão de obra operacional foi sendo\nsubstituída por máquinas, robôs e sistemas de\ninformação, em um processo chamado de\n“desemprego estrutural”. Os gestores que\ncompreendem bem esse fenômeno possuem\ncondições de lidar mais bem com situações como essa,\ntanto atraindo novos trabalhadores, com as\ncapacidades e as habilidades necessárias, quanto\nretendo os funcionários que são imprescindíveis.", "D": "Um grande desafio na área do comportamento\norganizacional é a globalização. Tanto a economia\nquanto as transações humanas têm-se tornado mais\ninternacionalizadas, o que impõe à gestão desafios e\noportunidades diversos. Portanto, é imprescindível\nlevar em consideração a variação do comportamento\nconforme a cultura de cada país. Os valores, os\nsímbolos e as crenças diferem significativamente de\numa cultura para outra.", "E": "Um grande desafio na área do comportamento\norganizacional é relativo à ética e à responsabilidade\nsocial. Tanto a ética quanto a responsabilidade social\nganharam relevância nos últimos anos e constituem\npilares da empresa moderna – desafios que são\ncorrelatos, apesar de distintos."}, "g": "A", "j": "Questao pede INCORRETA. Downsizing e REDUCAO proposital da forca de trabalho (corte de divisoes/postos), nao 'aumento proposital' - a alternativa A inverte o conceito. Demais alternativas descrevem corretamente terceirizacao, desemprego estrutural, globalizacao e etica."}, {"id": "1299379", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Spector (2004), um programa de treinamento não\nestará completo até que ele tenha sido avaliado e sua\neficácia tenha sido determinada. Nesse sentido, os critérios\nde treinamento servem como um padrão por meio do qual\num treinamento pode ser avaliado. Com relação a esse\nassunto, julgue os itens a seguir.      \nI. O critério chamado de “nível de treinamento” indica o\nque uma pessoa é capaz de fazer, ao final do\ntreinamento, dentro do ambiente de treinamento em\nsi, ao invés de no ambiente de trabalho.\n  II. O critério chamado de “nível de desempenho” indica o\ndesempenho da pessoa no trabalho, ou seja, refere-se\nao nível de transferência do treinamento.  \nIII. O critério chamado de “nível de desempenho”\nrefere-se estritamente ao que a pessoa aprendeu,\nenquanto o critério chamado de “nível de\ntreinamento” se refere estritamente aos efeitos do\ntreinamento no trabalho.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Itens I (nivel de treinamento avalia o que se faz no ambiente de treinamento) e II (nivel de desempenho refere-se a transferencia ao trabalho) corretos. Item III inverte as definicoes dos dois criterios em Spector."}, {"id": "1299377", "d": "psicologia", "a": ["Avaliação de Desempenho", "Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Borges e Mourão (2013), o desempenho\norganizacional de um ser humano deveria ser definido a\npartir de uma perspectiva ampla, como algo inerente à sua\nvida junto a outras pessoas e dentro de diversos ambientes\npsicossociais. Tal definição necessita de ser realizada,\nlevando em consideração o contexto no qual o ser humano\nestá inserido. Considerando essas informações, assinale a\nalternativa incorreta.", "alt": {"A": "As ações dos seres humanos em seu cotidiano, na\nmaior parte das vezes, são realizadas de forma\nautomática, isto é, eles não precisam tomar uma\ndistância reflexiva dos eventos que cercam seu dia para\npensar no curso de ação mais apropriado.", "B": "Quanto mais socializado um indivíduo for, mais\nambíguas serão suas ações e mais dúvidas ele terá\nacerca de quais comportamentos adotar para\nresponder às demandas provenientes de outras\npessoas ou do próprio ambiente em que vive.", "C": "O desempenho pode ser conceituado como um\nconjunto de ações que um ser humano exibe em\ndeterminadas situações e que depende de sua\ncompreensão tácita ou explícita do que seja esperado.", "D": "O comportamento humano não é um evento discreto,\nno sentido de exibir uma ação isolada no ambiente.\nPelo contrário, ele é uma cadeia de ações articuladas e\nque só ganham sentido conforme sejam apresentadas\nem um contexto em que certas regras sejam\nrespeitadas.", "E": "O desempenho humano depende da compreensão do\nsujeito acerca dos esquemas compartilhados que\norganizam cognitivamente determinada situação e\ninteração social, tais como a cultura de um país, de um\ngrupo e de uma organização."}, "g": "B", "j": "Questao pede INCORRETA. Em Borges & Mourao, quanto mais socializado o individuo, MENOS ambiguas (e nao mais) sao suas acoes - a socializacao reduz incerteza por internalizacao de esquemas compartilhados. Demais alternativas descrevem corretamente cotidiano, desempenho, comportamento e cultura."}, {"id": "1299374", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "A partir da afirmação de Zanelli, Borges-Andrade e Bastos\n(2004) sobre a psicologia organizacional e do trabalho como\ncampo de investigação e produção de conhecimento,\nassinale a alternativa incorreta.", "alt": {"A": "O que torna a psicologia organizacional e do trabalho\núnica é o fato de que seu foco de interesse está no\nestudo de fenômenos humanos nos contextos de\ntrabalho e das organizações.", "B": "A psicologia organizacional e do trabalho estuda\nfenômenos como, por exemplo, comportamentos em\ngeral, relações entre pessoas e grupos, disposições,\nmotivos, percepções, crenças, reações, atitudes,\nsignificados, valores e sentimentos, tal como outras\nsubáreas da psicologia.", "C": "Os fenômenos que a psicologia organizacional e do\ntrabalho investiga podem incluir tudo o que o ser\nhumano faz, existindo hoje um grande e crescente\ninteresse no que se exprime ou em como as pessoas\ncriam e usam símbolos nesses contextos.", "D": "A psicologia organizacional e do trabalho não está\nsomente interessada em mensurar e descrever\nisoladamente os fenômenos humanos organizacionais,\nmas também os seus antecedentes e as\nconsequências de tais fenômenos, visto que o\ndesempenho humano em seu trabalho é modificado\npelos diferentes níveis de seu ambiente.", "E": "A psicologia organizacional e do trabalho também\nestuda a produtividade humana, a qual, apesar de não\nestar diretamente relacionada a resultados específicos\ndo comportamento humano no trabalho, pode ser\ncompreendida a partir da compreensão de outros\nfenômenos complexos relacionados, tais como a\ncultura, o poder organizacional, as equipes e a saúde\nno trabalho."}, "g": "E", "j": "Questao pede INCORRETA. A produtividade humana ESTA diretamente relacionada aos resultados especificos do comportamento humano no trabalho - sao categorias acopladas em POT. A alternativa E afirma o contrario, contrariando Zanelli et al."}, {"id": "1299373", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Schein (1982), uma organização é a coordenação\nplanejada das atividades de uma série de pessoas para a\nconsecução de algum propósito ou objetivo comum,\nexplícito, por meio da divisão do trabalho e de funções e\npor meio de uma hierarquia de autoridade e\nresponsabilidade. Sendo assim, julgue os itens seguintes.\nI. Se partes diferentes fazem coisas diferentes, é\nnecessária uma função integradora para assegurar que\ntodos os elementos trabalhem, pelos objetivos\nestabelecidos, de comum acordo.\nII. A noção de coordenação implica que cada unidade\norganizacional se submeta a alguma espécie de\nautoridade, em prol da consecução de um objetivo\ncomum. Se cada unidade seguir seus próprios\ninteresses e ignorar as atividades das outras unidades,\na coordenação, por definição, será desfeita. No\nentanto, a noção de submissão à alguma espécie de\nautoridade significa necessariamente controle externo.III. A organização é um complexo conjunto de grupos\ninterdependentes, possuindo um modelo de\ndiferenciação muito mais intrincado em seu\nfuncionamento que uma simples divisão do trabalho.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item IIII está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (integracao) e III (complexo de grupos interdependentes) corretos. Item II erra ao afirmar que submissao a autoridade significa NECESSARIAMENTE controle externo - em Schein, autoridade pode ser internalizada via compromisso e identificacao, sem controle coercitivo."}, {"id": "1299371", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Spector (2004), a maior parte dos treinamentos\norganizacionais é conduzida na expectativa de que os\nfuncionários apliquem o que aprenderam no trabalho. E,\npara que se planeje um programa eficiente para a mudança\ndo comportamento no trabalho, é necessário considerar os\nfatores que afetam a transferência do treinamento e a\naprendizagem. Dentre os componentes que revelam sobre\na aprendizagem, destaca-se o feedback. A respeito desse\ntema, assinale a alternativa incorreta.", "alt": {"A": "O treinamento que possui o objetivo de ensinar uma\nhabilidade deve permitir aos treinandos praticar e\nobter um feedback à medida que aprendem.", "B": "O feedback deve ser inserido no treinamento de forma\nadequada para que o treinando possa afirmar se está\naprendendo o conteúdo da forma correta.", "C": "A habilidade não é a única característica individual dos\ntreinandos que afeta o resultado do treinamento, visto\nque as atitudes e a motivação também podem vir a\nafetar tal resultado. Portanto, ambas devem ser\nconsideradas no processo de feedback.", "D": "O treinamento, que possui como objetivo transmitir\ninformações, pode realizar um feedback de duas\nmaneiras: os treinandos podem ser testados quanto às\ninformações por meio de um exame; e eles podem\nfazer perguntas para quem está aplicando o\ntreinamento.", "E": "No treinamento, o feedback atua como um simulador\nde alta fidelidade, que irá oferecer uma boa\ntransferência, garantindo uma aprendizagem eficaz\npelo desenvolvimento de novas habilidades."}, "g": "E", "j": "Questao pede INCORRETA. Feedback e mecanismo de informacao corretiva sobre o desempenho do treinando, NAO atua como 'simulador de alta fidelidade' (este e outro componente distinto que diz respeito a similaridade entre ambiente de treino e trabalho). Demais alternativas descrevem corretamente Spector."}, {"id": "1299370", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Griffin e Morhead (2006), a crescente\ndiversidade de mão de obra presente nas organizações\nmodernas deve-se a mudanças demográficas na população\nmundial em geral e resulta da internacionalização dos\nprodutos, serviços, fornecedores, clientes e funcionários.\nNo que concerne à diversidade, julgue os itens que se\nseguem.\n      I. A crescente diversidade da força de trabalho no mundo\ndeve-se a algumas tendências, como a profunda\nalteração do mercado de trabalho em razão das\ncondições econômicas. Tais circunstâncias levam as\npessoas a sair do ambiente cultural em que estavam\nimersos para se aventurar em busca de oportunidades\nmelhores. Alie-se a isso o fato de as organizações\nmodernas estarem cada vez mais preocupadas em\nencontrar os melhores funcionários e distribuí-los para\nmais bem atender a organização, não importando sua\norigem.  \nII. A crescente diversidade da força de trabalho no mundo\ndeve-se a algumas tendências, tais como a\nglobalização, fenômeno que naturalmente destrói\nbarreiras geográficas, culturais etc. Assim, as empresas\nmodernas, ao expandir seus limites geográficos,\nampliam seus mercados ao redor do mundo, o que\nobrigatoriamente requer maior diversidade de\npensamento para alcançar efetivamente a\nparticularidade de cada mercado consumidor.   III. A crescente diversidade da força de trabalho no mundo\ndeve-se a algumas tendências, tais como a crescente\nexistência de programas de divulgação e marketing\nvoltados para a valorização do “diferente” e realizados\ncom o propósito de evidenciar a naturalidade de\nfatores como idade, sexo, herança étnica, habilidades\nfísicas e orientação sexual e, também, os ganhos de\nprodutividade no ambiente quando se respeita o fato\nde que é natural e saudável que indivíduos diferentes\najam e reajam de diferentes formas.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: mobilidade economica (I), globalizacao (II) e programas de valorizacao da diversidade/diferenca (III) sao tendencias que ampliam a diversidade da forca de trabalho, conforme Griffin e Morhead."}, {"id": "1299369", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Para Borges e Mourão (2013), apesar de ser uma questão\nfortemente presente nas discussões sobre atuação\nprofissional do psicólogo, o compromisso social tem sido\nconceituado de formas muito distintas, quase sempre\nsimplificadas. Com relação a esse assunto, jugue os itens\nsubsequentes.\n      I. Formar um profissional em psicologia organizacional e\ndo trabalho envolve colocá-lo em contato com um\ncorpo de conhecimentos científicos e tecnologias dele\ndecorrentes para aprender a lidar com problemas\nespecíficos postos pela sociedade.\n  II. A relação entre os campos profissionais e a sociedade\nem que esses se inserem é vasta e tênue. Tais campos\ntendem a se desenvolver à revelia das demandas\nhistoricamente constituídas na sociedade.\n  III. É comum pensar as profissões como conjuntos bem\ndelimitados de práticas, instrumentos, métodos e\nprocedimentos construídos por campos científicos que\nsão desenvolvidos ou utilizados por profissionais, isto\né, pessoas socialmente reconhecidas como tendo a\nformação adequada e competente para tal uso e\nprestação de serviço.\n      Assinale a alternativa correta:", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item IIII está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (formacao em POT articula conhecimentos cientificos para problemas sociais) e III (profissoes como conjuntos delimitados de praticas e instrumentos) corretos. Item II contradiz Borges & Mourao ao afirmar que profissoes se desenvolvem 'a revelia' das demandas sociais."}, {"id": "1299367", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "Para Schein (1982) o campo da psicologia organizacional é\ninterdisciplinar. Nesse sentido, ela se fundamenta em\nconhecimentos científicos provindos da sociologia, da\nantropologia, da ciência política e de vários outros sistemas\nque procuram compreender os fenômenos organizacionais.\nA partir dessas informações, julgue os itens a seguir.      I. A primeira perspectiva da psicologia organizacional é a\ndo empregado ou funcionário individual que depende\nda organização como fonte de trabalho, subsistência\neconômica, associação, identidade, contato social e\nrotinas de vida básicas, reconhecendo-se o fato de que,\nna sociedade moderna, a maioria das pessoas passa a\nmaior parte das horas de atividade em alguma forma\nde organização.\n  II. A segunda perspectiva da psicologia organizacional é a\nperspectiva do dirigente da organização, que atua no\ninteresse da organização, introduzindo diretrizes e\ntomando decisões que afetam a rotina diária de um\ngrande número de indivíduos e que, em última análise,\nafetam o destino da organização como um todo. Essa\nperspectiva não deve induzir a noção de que a\norganização atue como uma entidade abstrata; ao\ncontrário, ela atua por meio do comportamento\nindividual de certos membros-chave, que ocupam\nposições de gerência ou liderança.  \nIII. Uma terceira perspectiva da psicologia organizacional,\nque está se tornando cada vez mais importante, é a\nperspectiva do cliente, ou seja, do consumidor dos\nprodutos ou dos serviços da organização. É\nimprescindível que a psicologia organizacional\ncompreenda o modo como as organizações funcionam\nna relação com seus consumidores, visto que pode\nocorrer uma indevida exploração, por parte de\norganizações, no que tange a fenômenos como falta de\ntransparência, consumismo, ambientalismo, direitos do\ncidadão e assim por diante.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Em Schein, a psicologia organizacional tem tres perspectivas principais corretas: a do empregado (I), a do dirigente (II) e a do cliente (III). Todas reproduzem fielmente as posicoes destacadas pelo autor."}, {"id": "1299364", "d": "psicologia", "a": ["Motivação", "Psicologia e Organizações"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Spector (2004), dependendo da situação, as\nteorias da motivação para o trabalho podem prever as\nescolhas de comportamento para a tarefa, os esforços ou a\npersistência dessas pessoas. Todas essas teorias se baseiam\nna compreensão de que a motivação dos funcionários surge\na partir de perspectivas muito diferentes, embora não\nnecessariamente levem a previsões diferentes sobre o\ncomportamento no trabalho. Considerando essas\ninformações, assinale a alternativa incorreta.", "alt": {"A": "A teoria da equidade se concentra nos valores\npessoais. Ela presume que as pessoas valorizam\nuniversalmente a justiça em suas relações sociais.", "B": "A teoria do reforço afirma que o comportamento é\nresultado de recompensas que provocam o ser\nhumano. Ela descreve a motivação como resultado de\ninfluências internas ao sujeito, ou seja, os motivos\nseriam gerados de forma intrínseca a cada um.", "C": "A teoria da hierarquia das necessidades afirma que o\ncomportamento das pessoas está direcionado para a\nsatisfação de suas necessidades físicas, sociais e\npsicológicas, nesta ordem.", "D": "A teoria da autoeficácia afirma que a crença das\npessoas em suas próprias habilidades pode afetar o seu\ncomportamento. Segundo essa concepção, a\nmotivação para uma tarefa está relacionada ao fato de\na pessoa acreditar ou não que é capaz de concluir a\ntarefa com sucesso.", "E": "A teoria da fixação de metas explica como os objetivos\ne as intenções pessoais podem levar a um determinado\ncomportamento. Assim como outras teorias, ela\nentende que a motivação começa no próprio indivíduo,\nmas também demonstra como as influências\nambientais podem moldar a motivação e o\ncomportamento."}, "g": "B", "j": "Questao pede INCORRETA. A teoria do REFORCO descreve motivacao como resultado de RECOMPENSAS EXTERNAS (e nao influencias internas/intrinsecas) - alternativa B inverte o eixo classico do behaviorismo skinneriano. Demais alternativas descrevem corretamente equidade, hierarquia, autoeficacia e fixacao de metas."}, {"id": "1299283", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Sampaio (2009), a devolução psicopedagógica é\numa comunicação verbal, feita aos pais e ao paciente, dos\nresultados obtidos por meio de uma investigação que se\nutilizou do diagnóstico para obter resultados. Considerando\nessa informação, assinale a alternativa incorreta no que\nconcerne a essa etapa diagnóstica.", "alt": {"A": "Quando o paciente é criança, a devolução deve ser\nfeita apenas para os pais e(ou) responsáveis, a fim de\nproteger a criança.", "B": "Para ajudar a amenizar a ansiedade que normalmente\nenvolve essa etapa do processo, o psicopedagogo deve\nestar seguro do resultado do seu diagnóstico.", "C": "Quando o diagnóstico é de algum distúrbio, como\nTDAH ou dislexia, é preciso esclarecer que esses\ndiagnósticos são multidisciplinares e envolvem outras\nespecialidades, como psicologia, neurologia e\npsiquiatra.", "D": "Se, durante o diagnóstico, for observado quadro de\nagressividade intenso, estados psicóticos ou\nneuróticos, deve-se encaminhar o paciente para a\npsicoterapia.", "E": "Se o profissional estiver inseguro com o diagnóstico,\ndeve discutir o caso com outros especialistas e(ou) com\num supervisor psicopedagógico."}, "g": "A", "j": "Questao pede INCORRETA. A devolucao psicopedagogica de Sampaio deve incluir a CRIANCA (em linguagem adequada), nao se restringe aos pais. A alegacao de 'proteger a crianca' contradiz a etica do trabalho e o direito a informacao do periciado."}, {"id": "1299282", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicologia da Educação", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "As provas operatórias visam a conhecer o desenvolvimento\ndas funções lógicas da criança. Não é uma prova operatória\na prova de", "alt": {"A": "conservação (de líquido, de comprimento, de volume e\nde peso).", "B": "classificação (intersecção de classes).", "C": "seriação (seriação de palitos).", "D": "espaço (unidimensional, bidimensional e\ntridimensional).", "E": "destreza (motricidade fina e motricidade grossa)."}, "g": "E", "j": "Provas operatorias de Piaget avaliam funcoes logicas: conservacao, classificacao, seriacao, espaco. 'Destreza (motricidade fina/grossa)' NAO e prova operatoria - pertence a avaliacao psicomotora, nao a avaliacao das estruturas logicas piagetianas."}, {"id": "1299281", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Sampaio (2009), a entrevista operativa\ncentrada na aprendizagem (EOCA) é a primeira sessão\nrealizada com a criança. A respeito da EOCA, julgue os itens\na seguir.\nI. A EOCA tem o objetivo de investigar os vínculos que o\nsujeito tem com os objetos e os conteúdos da\naprendizagem escolar.\nII. As observações da primeira entrevista devem ser\nsubmetidas a uma verificação mais rigorosa ao longo\ndo processo diagnóstico.\nIII. Por se tratar de uma primeira observação, o\npsicopedagogo não pode elaborar, a partir da EOCA,\nhipóteses diagnósticas.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (investigar vinculos com objetos/conteudos da aprendizagem) e II (verificacao mais rigorosa ao longo do processo) corretos. Item III erra ao negar a possibilidade de elaboracao de hipoteses diagnosticas a partir da EOCA - a entrevista e justamente fonte de hipoteses iniciais."}, {"id": "1299280", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Simaia Sampaio, no diagnóstico psicopedagógico\nclínico, uma etapa importante é a entrevista contratual.\nPara a autora, não faz parte desse momento do diagnóstico", "alt": {"A": "colher dados pessoais e ouvir as queixas sobre o\nproblema que a criança apresenta.", "B": "fazer enquadramento sobre horários, quantidade de\nsessões, frequência e honorários.", "C": "colher dados históricos da criança.", "D": "informar objetivos do tratamento e procedimentos que\nserão adotados.", "E": "estar atento e registrar falas dos pais, a compreensão\nque possuem sobre as dificuldades da criança, bem\ncomo suas resistências ao tratamento."}, "g": "C", "j": "Em Sampaio, a entrevista contratual e dedicada a estabelecer o enquadre (horarios, sessoes, honorarios), informar objetivos/procedimentos e ouvir queixas iniciais. A coleta de dados historicos da crianca pertence a anamnese, etapa posterior do diagnostico."}, {"id": "1299273", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas", "Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "A psicanálise pode ser utilizada pelo psicopedagogo com o\nobjetivo de compreender o sentido inconsciente das\ndificuldades de aprendizagem. Com base nessa teoria,\nassinale a alternativa incorreta.", "alt": {"A": "O inconsciente não se manifesta de forma direta, mas\npor meio de chistes, lapsos, atos falhos, sonhos e\nsintomas.", "B": "A projeção é um mecanismo de defesa por meio do\nqual o indivíduo expulsa de si e localiza nos outros as\nqualidades, os desejos e os sentimentos que recusa em\nsi.", "C": "Os mecanismos de defesa são métodos inconscientes\nque o ego utiliza para distorcer a realidade e se\nproteger da ansiedade.", "D": "A negação é o mecanismo por meio do qual o indivíduo\nnega conscientemente um fato, mentindo para os\noutros para evitar constrangimento", "E": "A sublimação é o mecanismo por meio do qual a\npessoa canaliza impulsos socialmente constrangedores\npara atividades socialmente reconhecidas."}, "g": "D", "j": "Questao pede INCORRETA. Na psicanalise, a NEGACAO e um mecanismo INCONSCIENTE de defesa do ego (Verleugnung), nao um ato consciente de mentir aos outros. Demais alternativas descrevem corretamente inconsciente, projecao, mecanismos de defesa e sublimacao."}, {"id": "1299271", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "O diagnóstico de TDAH é difícil devido à natureza clínica\nheterogênea do transtorno. Acerca do TDAH, assinale a\nalternativa correta.", "alt": {"A": "A incapacidade de um indivíduo manter a atenção, a\natividade motora ou o controle dos impulsos é\ncaracterística apenas do TDAH.", "B": "Os aspectos fundamentais do TDAH no DSM-5\nencaixam-se em dois eixos: desatenção e\nhiperatividade-impulsividade.", "C": "O TDAH só acontece em crianças; ao longo do\ndesenvolvimento, os problemas vão se atenuando, até\ndesaparecerem por completo quando na fase adulta.", "D": "Os sintomas de TDAH não variam significativamente de\num contexto para o outro e conforme o estágio de\ndesenvolvimento.", "E": "O TDAH é um transtorno neurológico de base\nsocioemocional. Sendo assim, as famílias disfuncionais\ne o excesso de televisão estão entre as principais\ncausas do transtorno."}, "g": "B", "j": "DSM-5 organiza o TDAH em dois eixos sintomaticos: desatencao e hiperatividade-impulsividade. A erra ao afirmar exclusividade (sintomas tambem ocorrem em outros transtornos); C nega persistencia adulta; D nega variabilidade contextual; E erra etiologia."}, {"id": "1299270", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "Quando a criança recebe o diagnóstico de espectro do\nautismo, a família constata que é preciso fazer adaptações.\nO processo educativo em geral fica mais fácil quando as\npessoas se libertam de seus medos e passam a\ncompreender o que leva a criança a se comportar, algumas\nvezes, de modo incomum. A respeito dos distúrbios do\nespectro do autismo, assinale a alternativa correta.", "alt": {"A": "Os problemas apresentados pela criança com autismo\npodem aparecer em apenas um de seus contextos\ndesenvolvimentais; por exemplo, podem aparecer na\nescola, mas não em casa.", "B": "A área social não é prejudicada. A criança com autismo\ntem facilidade de expressar suas emoções e de\ncompartilhar seus brinquedos.", "C": "Dificuldades de linguagem e comunicação e\ndesenvolvimento precário da imaginação são\ncaracterísticas essenciais do autismo.", "D": "As crianças com espectro do autismo não gostam de\nrotinas e procuram sempre alterá-las para evitar a\nmonotonia.", "E": "A criança com espectro do autismo faz sempre uso de\nlinguagem abstrata, por isso, algumas vezes, a\ncomunicação fica prejudicada."}, "g": "C", "j": "Dificuldades de linguagem/comunicacao e desenvolvimento precario da imaginacao integram a triade classica de Wing para autismo (com prejuizo social). A nega pervasividade contextual; B nega prejuizo social; D inverte preferencia por rotinas; E confunde abstracao com literalidade."}, {"id": "1299269", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "São muitas as causas que podem levar uma criança a\napresentar desordens de aprendizagem. Com o diagnóstico\ne o tratamento certos, muitos indivíduos conseguem\navançar e evoluir em seu desenvolvimento. Sendo assim,\nassinale a alternativa correta no que se refere à disgrafia.", "alt": {"A": "A disgrafia é uma alteração na escrita normalmente\nligada a problemas perceptivos e motores.", "B": "A disgrafia caracteriza-se pela troca de fonemas na\nescrita.", "C": "A disgrafia é um distúrbio neurológico que afeta a\nhabilidade com números.", "D": "A disgrafia caracteriza-se pela falta de concentração e\npela desatenção da criança.", "E": "A disgrafia abrange, principalmente, a leitura e a\ninterpretação de enunciados e textos."}, "g": "A", "j": "Disgrafia e alteracao da escrita ligada a problemas perceptivos e motores (organizacao espacial, traco, coordenacao). B descreve disortografia (troca de fonemas); C descreve discalculia; D descreve atencao; E descreve dislexia."}, {"id": "1299268", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A reabilitação neuropsicológica avançada pela\nneuropsicologia de Luria antecipa um constructo decisivo\npara a compreensão do desenvolvimento ontogenético\nhumano, a saber, a plasticidade. Com relação a esse\nconstructo, assinale a alternativa correta.", "alt": {"A": "A plasticidade cerebral é a alteração adaptativa na\nestrutura e no funcionamento do sistema nervoso, em\nfunção, exclusivamente, de interações com o meio\nambiente externo.", "B": "O neurodesenvolvimento tem seu curso guiado pela\nmaturação e a presença de um evento disruptivo\n(lesão cerebral) ou de um componente congênito não\naltera este processo.", "C": "A plasticidade é um fenômeno puramente biológico e\norganiza-se a partir da integração dinâmica de\naspectos filogenéticos, ontogenéticos e\nsócio-históricos.", "D": "A plasticidade é uma fraqueza do ser humano, pois a\ncriança humana nasce indefesa e dependente de\ncuidadores.", "E": "A cultura pode ofertar ferramentas que serão\nincorporadas, potencializando o funcionamento e\nminimizando as limitações impostas por uma lesão\ne(ou) uma disfunção do sistema nervoso central."}, "g": "E", "j": "Em Luria/Vigotski, a cultura oferta ferramentas (signos, mediacoes, instrumentos) que sao incorporadas, potencializando o funcionamento e minimizando limitacoes neurologicas. A erra restringindo plasticidade ao ambiente externo; B nega papel de eventos disruptivos; C reduz plasticidade ao biologico; D inverte funcao adaptativa."}, {"id": "1299265", "d": "psicologia", "a": ["Psicologia da Educação", "Teorias da Personalidade", "Teorias da Personalidade - Outros Autores"], "ano": "2020", "org": "CFP", "t": "", "e": "Howard Gardner desenvolveu a teoria de inteligências\nmúltiplas a partir de sua insatisfação com as visões unitárias\nde inteligência. Quanto à teoria desse autor, julgue os itens\nsubsequentes.\nI. Cada uma das formas de inteligência é relativamente\nindependente das demais e tem sua origem, seus\nlimites genéticos próprios e seus substratos\nneuroanatômicos específicos.\nII. A inteligência lógico-matemática e a inteligência\nlinguística são as mais valorizadas no sistema de ensino\ntradicional.\nIII. A inteligência interpessoal é caracterizada como o\nconhecimento dos próprios aspectos internos e o\nacesso aos próprios sentimentos e emoções.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Itens I (independencia das inteligencias) e II (valorizacao escolar de logico-matematica e linguistica) corretos. Item III INVERTE: o acesso aos proprios sentimentos/emocoes corresponde a inteligencia INTRAPESSOAL, nao interpessoal (que e voltada para os outros)."}, {"id": "1299263", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A respeito da teoria da psicogênese da língua escrita, julgue\nos itens a seguir.\nI. Segundo Emília Ferreiro, a alfabetização precisa ser\nsignificativa e contextualizada.\nII. Na fase silábica, a criança já escreve todas as sílabas\ncorretamente.\nIII. A fase pré-silábica inicia-se antes do período de\nalfabetização escolar.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (alfabetizacao significativa e contextualizada em Ferreiro) e III (fase pre-silabica inicia antes da alfabetizacao formal) corretos. Item II e falso - na fase silabica, a crianca representa cada silaba com uma letra (geralmente vogal), nao escreve todas as silabas corretamente."}, {"id": "1299262", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A linguagem, segundo Vygotsky, é o sistema simbólico\nfundamental na mediação entre o sujeito e o objeto de\nconhecimento. Para o autor, as duas funções básicas da\nlinguagem são:", "alt": {"A": "assimilação e acomodação.", "B": "intercâmbio social e pensamento generalizante.", "C": "zona de desenvolvimento proximal e zona de\ndesenvolvimento distal.", "D": "fala egocêntrica e intercâmbio social.", "E": "intercâmbio social e zona do desenvolvimento\nproximal."}, "g": "B", "j": "Para Vygotsky, as duas funcoes basicas da linguagem sao o intercambio social (comunicacao) e o pensamento generalizante (organizacao do real em conceitos). Demais alternativas misturam conceitos de outros autores (Piaget) ou inventam categorias (zona de desenvolvimento 'distal')."}, {"id": "1299261", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Piaget", "Teorias da Personalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca da teoria de Piaget, assinale a alternativa incorreta.", "alt": {"A": "O desenvolvimento da linguagem é influenciado pelas\naquisições do estágio sensório-motor.", "B": "Pela linguagem, a criança adquire a capacidade de\nrepresentar eventos que não estão presentes.", "C": "A imitação é fundamental para a aquisição da\nlinguagem.", "D": "A fala egocêntrica é importante no processo de\nexternalização da linguagem egocêntrica para a\nlinguagem socializada.", "E": "As questões afetivas e contextuais não influenciam o\ndesenvolvimento da linguagem."}, "g": "E", "j": "Questao pede INCORRETA. Em Piaget, questoes afetivas e contextuais INFLUENCIAM sim o desenvolvimento da linguagem (interacao com objetos e pessoas e fonte da construcao cognitiva). Demais alternativas descrevem corretamente sensorio-motor, representacao, imitacao e fala egocentrica."}, {"id": "1299260", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2020", "org": "CFP", "t": "", "e": "A teoria de Henri Wallon também é conhecida como a\npsicogênese da pessoa completa. Com relação a ela,\nassinale a alternativa correta.", "alt": {"A": "A passagem de um estágio do desenvolvimento para\noutro é uma simples ampliação do estágio anterior.\nSendo assim, a criança não passa por nenhuma crise.", "B": "O ato motor não influencia na atividade cognitiva da\ncriança.", "C": "O conceito de predominância funcional significa que a\natividade cognitiva predomina em todos os estágios do\ndesenvolvimento.", "D": "Afetividade, motricidade e inteligência são os campos\nfuncionais nos quais se distribui a atividade infantil.", "E": "A criança é um ser total, concreto e ativo, portanto não\nsofre influências contextuais em seu desenvolvimento."}, "g": "D", "j": "Em Wallon (psicogenese da pessoa completa), afetividade, motricidade e inteligencia sao os tres campos funcionais que organizam a atividade infantil, integrando dimensoes biologicas e sociais. Demais alternativas negam crises, motricidade, predominancia funcional ou influencias contextuais."}, {"id": "1299259", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Freud", "Teorias da Personalidade"], "ano": "2020", "org": "CFP", "t": "", "e": "Entre as fases do desenvolvimento psicossexual de Freud,\numa se caracteriza pela descoberta dos órgãos genitais\ncomo fonte privilegiada de prazer. O superego, instância do\npsiquismo responsável pela censura, é herdeiro do\ncomplexo de Édipo, que também marca esta fase. A fase\nassim caracterizada denomina-se", "alt": {"A": "fase oral.", "B": "fase anal.", "C": "fase fálica.", "D": "fase genital.", "E": "período de latência."}, "g": "C", "j": "A fase falica (3-6 anos) e caracterizada pela descoberta dos orgaos genitais como fonte privilegiada de prazer, vivencia do complexo de Edipo e formacao do superego (herdeiro do Edipo). Demais fases (oral, anal, latencia, genital) tem outros marcadores estruturais."}, {"id": "1299258", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2020", "org": "CFP", "t": "", "e": "Quanto à utilização de jogos nos tratamentos\npsicopedagógicos, julgue os itens seguintes.\nI. O jogo constitui uma importante ferramenta\nterapêutica, pois, do ponto de vista cognitivo, o saber\nda criança é uma via de acesso.\nII. Para Piaget, o jogo simbólico surge aos sete anos de\nidade, na fase das operações concretas.\nIII. Do ponto de vista afetivo, considera-se que os jogos\ninfantis reproduzem situações psíquicas estruturantes\nna constituição do sujeito.\nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens II e III estão certos.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (jogo como ferramenta terapeutica e via cognitiva) e III (jogos reproduzem situacoes psiquicas estruturantes) corretos. Item II e falso - em Piaget o jogo simbolico surge no estagio PRE-OPERATORIO (2-7 anos), nao nas operacoes concretas."}, {"id": "1299257", "d": "psicologia", "a": ["Psicologia Institucional"], "ano": "2020", "org": "CFP", "t": "", "e": "No que se refere à atuação da psicopedagogia institucional,\nassinale a alternativa incorreta.", "alt": {"A": "O sujeito da psicopedagogia institucional é a\ninstituição, com sua complexa rede de relações.", "B": "Já existem experiências da psicopedagogia institucional\nem empresas, hospitais, creches e organizações\nassistenciais.", "C": "O psicopedagogo institucional deve evitar trabalhar\ncom as filosofias, os valores e as ideologias das\ninstituições, para que estas não percam sua identidade.", "D": "Oficinas psicopedagógicas podem ser organizadas em\nhospitais com internos, possibilitando o lúdico e a\naprendizagem.", "E": "Nas empresas, é possível ampliar as formas de\ntreinamento de pessoal, resgatando as múltiplas\ninteligências."}, "g": "C", "j": "Questao pede INCORRETA. A psicopedagogia institucional DEVE trabalhar com filosofias, valores e ideologias das instituicoes - sao constitutivos da analise institucional. A alternativa C inverte a logica de intervencao. Demais alternativas (sujeito = instituicao, ambitos de atuacao, oficinas, treinamento) sao corretas."}, {"id": "1296432", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com Pacico (2015), a avaliação psicológica é a\natividade constituída pela busca sistemática de\nconhecimento a respeito do funcionamento psicológico das\npessoas. Com relação a esse tema, julgue os seguintes\nitens.     I. Os instrumentos de avaliação psicológica são\nferramentas que representam avanço científico na área\nde avaliação psicológica. \n  II. Testes psicológicos contribuem com a avaliação da\neficácia de um programa de intervenções.\nIII. Ao avaliar, o psicólogo mede variáveis, compara\npadrões e testa hipóteses.     Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: instrumentos como avanco cientifico (I), testes para avaliacao de eficacia de intervencoes (II) e ato de avaliar como mensuracao, comparacao e teste de hipoteses (III) - tres dimensoes complementares em Pacico."}, {"id": "1296430", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Barros (2019) afirma, na revista Diálogos, que há registro de 45 milhões de pessoas com deficiência no Brasil, dos quais 9,7 milhões se referem a pessoas com deficiência auditiva congênita ou adquirida. A respeito da avaliação psicológica dessa população, assinale a alternativa correta.", "alt": {"A": "Os vários termos da língua brasileira de sinais que se\naplicam à psicologia facilitam a comunicação entre\navaliador e avaliado e, portanto, não há alterações\nprevistas para a prática avaliativa.", "B": "É recomendado que se use uma abordagem de\navaliação justa, compreensiva e apropriada para\nclientes com deficiência.", "C": "O fato de os surdos serem obrigatoriamente\nalfabetizados na língua brasileira de sinais torna\ndesnecessária qualquer adaptação adicional para o\natendimento da população.", "D": "Tabelas normativas de testes psicológicos elaboradas\npara amostra geral podem ser utilizadas pelas pessoas\nsurdas, tendo em vista que também fazem parte da\npopulação geral e que prejuízos na audição não\nimplicam outros deficits a elas.", "E": "Toda forma de entrevista pode ser utilizada no\nprocesso avaliativo, mas a literatura indica que a\nentrevista livre é a mais recomendada, pois, assim, a\npopulação surda poderá se expressar mais livremente,\ngarantindo o princípio do respeito, defendido pelos\ndireitos humanos."}, "g": "B", "j": "Avaliacao psicologica de pessoas com deficiencia exige abordagem justa, compreensiva e apropriada (recomendacao internacional). Demais alternativas naturalizam barreiras (sem adaptacao), generalizam alfabetizacao em Libras, validam normas inadequadas ou defendem entrevista livre como padrao."}, {"id": "1296428", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Oliveira e Nunes (2019) discutem a aplicação dos princípios\ndo desenho universal ao instrumental da psicologia. Acerca\ndesse assunto, assinale a alternativa correta.", "alt": {"A": "Os princípios do desenho universal consistem em:\npopulação de avaliação inclusiva; definição precisa do\nconstruto; itens acessíveis; testes flexíveis a\nacomodações; instruções simples; texto de fácil leitura;\ne máxima legibilidade.", "B": "Os princípios do desenho universal consistem em:\ncadernos de testes novos; aplicação coletiva;\npreservação de silêncio; iluminação adequada; e\nambiente acessível.", "C": "Os princípios do desenho universal consistem em três\ndesenhos: árvore; casa; e figura humana.", "D": "Os princípios do desenho universal defendem que o\nteste deverá ser simples e acessível a todo tipo de\npopulação, ainda que não meça o fenômeno\npsicológico de modo adequado.", "E": "Os princípios do desenho universal consistem em:\ntestagem universal objetiva; e aplicação do mesmo\nteste em diferentes culturas, pois o processo de\nconstrução dele, por ser universal, permite a ampla\ncomparação entre amostras com características\ndistintas."}, "g": "C", "j": "Correcao: gabarito tecnico e A. Oliveira & Nunes (2019) definem desenho universal aplicado a testes pelos principios: populacao inclusiva, definicao precisa do construto, itens acessiveis, testes flexiveis a acomodacoes, instrucoes simples, texto de facil leitura e maxima legibilidade. A alternativa C (arvore, casa, figura humana) corresponde ao HTP, instrumento totalmente distinto."}, {"id": "1296427", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A medida tem como função permitir a descrição objetiva de\ndeterminados fenômenos. A teoria de medida utiliza um\nsistema numérico para descrever os fenômenos naturais e\nseu foco é propor novos e melhores métodos para\ndesenvolver instrumentos de medida (Andrade, Esteves &\nLaros, 2019). A partir dessas informações, assinale a\nalternativa correta", "alt": {"A": "A mensuração é um conjunto de regras utilizadas para\nrepresentar o comportamento por meio de números.", "B": "Mensurar significa atribuir números para\ncaracterísticas dos indivíduos, como forma de\nrepresentar tais fenômenos psicológicos.", "C": "A medida operacionaliza um construto psicológico.", "D": "É difícil controlar o erro de medida na mensuração\npsicológica.", "E": "A Teoria Clássica dos Testes refere-se à análise\nqualitativa da mensuração."}, "g": "C", "j": "A medida operacionaliza um construto psicologico - definicao central em teoria da medida. Demais alternativas descrevem aspectos correlatos (regras de mensuracao, atribuicao de numeros), mas nao a funcao operacionalizadora propriamente dita; E inverte natureza quantitativa da TCT."}, {"id": "1296425", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Um determinado teste psicológico foi aplicado em\numa amostra de 400 participantes. Após um mês, o mesmo\nteste foi reaplicado na mesma amostra. Após correlacionar\nos dados obtidos nas duas aplicações, os resultados\nevidenciaram coeficientes de correlações entre 0,34 e 0,85. Com base nessa situação hipotética, é correto afirmar que,\nno estudo, foi realizado o procedimento de verificação da\nprecisão denominado", "alt": {"A": "consistência interna.", "B": "split-half.", "C": "teste-reteste.", "D": "estrutura interna.", "E": "ômega de McDonald."}, "g": "C", "j": "Aplicar o mesmo teste em duas ocasioes na mesma amostra, com intervalo entre as aplicacoes, e calcular a correlacao entre os escores = procedimento teste-reteste (estabilidade temporal da medida). Demais opcoes referem-se a outros tipos de precisao (consistencia interna, split-half, omega)."}, {"id": "1296424", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme a Resolução CFP n.ᵒ 9/2018, são considerados\ncomo requisitos mínimos na conclusão das evidências de\nvalidade", "alt": {"A": "os estudos experimentais/quase experimentais nos\nquais se verifica se um instrumento é capaz de captar\nmudanças resultantes de intervenção (variável\nexterna).", "B": "a presença de um estudo de estrutura interna, quando\naplicável, e de um estudo de validade (exceto\nconteúdo).", "C": "o estudo de normatização que inclua participantes em\nnúmero adequado para os estudos realizados,\nconsiderando a natureza do teste (projetivo ou\nobjetivo).", "D": "a presença de estudo que contemple as cinco regiões\ngeopolíticas brasileiras, com, no mínimo, 250 por\nregião ou 1.000 no total.", "E": "o estudo de precisão entre avaliadores."}, "g": "B", "j": "Res CFP 9/2018 exige, como requisito minimo, a presenca de um estudo de estrutura interna (quando aplicavel) e ao menos um estudo de validade adicional, exceto conteudo. Demais alternativas extrapolam ou restringem o que a resolucao define."}, {"id": "1296423", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Os princípios beneficência e não maleficência, respeito e\njustiça são amplamente discutidos na prática de pesquisas\ncientíficas. Quanto à sua aplicação na avaliação psicológica,\njulgue os itens a seguir.I. A beneficência promove a reflexão sobre os benefícios\ntrazidos ao indivíduo avaliado e a ponderação sobre os\neventuais prejuízos advindos de uma avaliação\nimprecisa.\nII. O respeito se refere à necessidade de que as pessoas\nsejam informadas explicitamente sobre os passos do\nprocesso avaliativo.\nIII. A justiça implica a utilização de instrumentos de\navaliação com qualidades psicométricas comprovadas\ne adequados à situação.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os principios corretamente aplicados: beneficencia (I, beneficios e prejuizos da avaliacao), respeito (II, informacao explicita ao avaliado) e justica (III, uso de instrumentos com qualidade psicometrica adequada)."}, {"id": "1296422", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "A adaptação de instrumentos de avaliação psicológica é\nassunto discutido por Bandeira (2019). Considerando essa\ninformação, assinale a alternativa correta.", "alt": {"A": "Os processos de tradução de testes psicológicos e de\nadaptação de testes psicológicos são os mesmos.", "B": "São etapas da tradução de testes psicológicos:\ntradução do instrumento do idioma de origem para o\nidioma-alvo; síntese das versões traduzidas; avaliação\nda síntese por juízes experts; avaliação do instrumento\npelo público-alvo; tradução reversa; e estudo-piloto.", "C": "A adaptação transcultural torna desnecessária a busca\nde outras evidências empíricas.", "D": "São etapas da adaptação transcultural de testes\npsicológicos: tradução do instrumento do idioma de\norigem para o idioma-alvo; síntese das versões\ntraduzidas; avaliação da síntese por juízes experts;\navaliação do instrumento pelo público-alvo; tradução\nreversa; e estudo-piloto.", "E": "A tradução de testes psicológicos de outro idioma para\no português é mais complexa que o processo de\nadaptação de um teste psicológico estrangeiro."}, "g": "D", "j": "Em Bandeira, a adaptacao transcultural de testes envolve seis etapas: traducao para idioma-alvo, sintese das versoes, avaliacao por juizes experts, avaliacao pelo publico-alvo, traducao reversa e estudo-piloto. Tracucao isolada nao se confunde com adaptacao (que e mais ampla e complexa)."}, {"id": "1296420", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo Reppold e Noronha (2018), o Satepsi refere-se", "alt": {"A": "à pré-avaliação dos testes psicológicos para verificar se\neles possuem referências bibliográficas atuais.", "B": "à forma adotada pelo Conselho Federal de Psicologia\nde ensinar aos psicólogos sobre as melhores condições\nde aplicação dos testes psicológicos, evitando-se,\nassim, erros na avaliação psicológica.", "C": "à informação sobre a construção de testes psicológicos\ninternacionais e nacionais, sobre o manejo de\nentrevistas e sobre a utilização adequada de outras\nformas de avaliação.", "D": "ao sistema de avaliação dos testes psicológicos que\nanalisa os requisitos mínimos que um teste psicológico\nprecisa ter e que divulga as informações à comunidade.", "E": "a premissas técnicas de elaboração de medidas em\nconsonância com a ITC."}, "g": "D", "j": "Satepsi e o sistema do CFP que avalia testes psicologicos quanto aos requisitos minimos tecnicos e cientificos e divulga as informacoes a comunidade profissional. Demais alternativas restringem a referencias bibliograficas, ensino tecnico, instrucoes de aplicacao ou ITC."}, {"id": "1296418", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Anache (2018), o objetivo da avaliação\npsicológica no contexto educacional é promover\ninformações relevantes sobre as características dos\nmovimentos das funções psicológicas engendradas nos\nprocessos de aprendizagem dos indivíduos. Quanto à\navaliação psicológica, assinale a alternativa correta", "alt": {"A": "A avaliação deve constituir um parecer a ser entregue\npara a direção da escola, com vistas a classificar\nadequadamente o grau de deficiência intelectual.", "B": "Na avaliação, será necessário identificar os aspectos\npsicológicos que promoverão o desenvolvimento da\ncriança, para que sejam feitos os investimentos\neducacionais adequados.", "C": "A avaliação servirá para responsabilizar pais e\nprofessores pelas eventuais dificuldades escolares dos\nfilhos/alunos.", "D": "A avaliação permitirá obter o diagnóstico de alunos de\nacordo com os critérios de classificação contidos no\nDSM V.", "E": "A avaliação, em sua complexa análise, encontrará\njustificativas para os problemas do aluno, com o intuito\nde obter métodos de correção dos desajustes de\naprendizagem."}, "g": "B", "j": "A avaliacao psicologica educacional deve identificar aspectos psicologicos que promoverao o desenvolvimento, orientando investimentos educacionais adequados. Demais alternativas instrumentalizam a avaliacao como classificacao, responsabilizacao ou diagnostico nosologico."}, {"id": "1296415", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Considerando as explanações de Reppold e Noronha (2018)\nsobre o Satepsi, assinale a alternativa incorreta.", "alt": {"A": "Foi criado pelo Conselho Federal de Psicologia, com o\nobjetivo de avaliar a qualidade dos testes psicológicos\nsob a perspectiva técnico-científica e de divulgar\ninformações sobre estes instrumentos para os\npsicólogos.", "B": "Suas ações envolvem questões referentes à divulgação\nde informações sobre avaliação psicológica à\ncomunidade, atividades de formação continuada e,\nsobretudo, questões relacionadas à ingerência do\nensino da avaliação nas instituições de ensino superior,\ninterferindo diretamente na proposição das Diretrizes\nCurriculares Nacionais e na orientação dos psicólogos\nquanto à escolha dos testes psicológicos em seus\nprocessos avaliativos.", "C": "É reconhecido, por órgãos internacionais vinculados à\nárea, como a American Psychological Association –\nDivision 5 e a ITC (International Test Commission),\ncomo pioneiro na certificação dos instrumentos\npsicológicos com base em critérios internacionais de\nqualidade e estendidos à avaliação de todos os\ninstrumentos disponíveis para uso profissional por\nparte dos psicólogos.", "D": "O Conselho Federal de Psicologia tem instituído uma\nComissão Consultiva de Avaliação Psicológica (CCAP),\nformada por conselheiros e por pesquisadores com\nexperiência e produção científica na área, os quais são\napoiados por consultores ad hoc, selecionados por\neditais públicos.", "E": "Foi criado em um contexto em que vários testes\npsicológicos utilizados profissionalmente não\napresentavam manuais com fundamentação teórica,\ncom instruções completas de aplicação e detalhes de\nsuas propriedades psicométricas, o que comprometia\nos resultados obtidos nas avaliações."}, "g": "B", "j": "Questao pede INCORRETA. O CFP NAO tem ingerencia sobre o ensino da avaliacao nas IES nem sobre as Diretrizes Curriculares Nacionais (atribuicao do MEC/CNE). A alternativa B extrapola as competencias do Satepsi. Demais alternativas descrevem corretamente origem, reconhecimento, CCAP e contexto historico."}, {"id": "1296411", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Villemor-Amaral e Resende (2018) explicitam um novo\nmodelo de avaliação psicológica no Brasil. Com relação a\nesse novo modelo, de acordo com as autoras, assinale a\nalternativa correta.", "alt": {"A": "O foco é a coleta de informações sobre o cliente ou os\nclientes (família, empresa, contexto judiciário etc.),\ncom o objetivo de fazer indicações terapêuticas ou\noutros tipos de intervenção mais adequados para a\nsituação. Contudo, nem sempre a pessoa se sente\nrealmente compreendida e motivada a levar adiante as\nrecomendações derivadas das avaliações.", "B": "Nesse novo modelo, a qualidade dos instrumentos é\nmais importante para alcançar resultados\nverdadeiramente úteis que a habilidade do avaliador\nde fazer daquela experiência algo positivamente\nsignificativo para o avaliado.", "C": "O novo modelo é tão eficiente que a aliança no\ntrabalho de investigação não é tão útil para o efeito\npretendido, isto é, para o encaminhamento mais\nadequado possível ao caso.", "D": "Constitui um método específico de avaliação\ncolaborativa que visa à intervenção psicológica em um\nmodelo semiestruturado, organizado em etapas, no\nqual o teste psicológico é usado no centro de uma\nintervenção terapêutica limitada no tempo.", "E": "Uma de suas vantagens é o efeito iatrogênico, ou seja,\no efeito de simplesmente ampliar o potencial\ntransformador que uma avaliação psicológica pode ter\nsobre o avaliando. Por efeito iatrogênico se entende\numa peça do quebra-cabeça que foi encontrada,\nresultando em insight e em bem-estar do cliente."}, "g": "D", "j": "Villemor-Amaral & Resende descrevem a Avaliacao Terapeutica - metodo colaborativo semiestruturado, em etapas, no qual o teste e usado no centro de uma intervencao terapeutica limitada no tempo. Demais alternativas reducionistas, invertem prioridades ou confundem efeito iatrogenico."}, {"id": "1296404", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "Conforme Hutz (2015), julgue os itens seguintes acerca de\navaliação psicológica (métodos, técnicas e testes).    I. A avaliação psicológica é um processo complexo,\nempregado em diferentes contextos, que tem por\nobjetivo produzir hipóteses ou diagnósticos sobre uma\npessoa ou um grupo. Essas hipóteses ou diagnósticos\npodem, por exemplo, tratar do funcionamento\nintelectual, das características da personalidade ou da\naptidão para desempenhar uma tarefa ou um conjunto\nde tarefas.\nII. A testagem psicológica é parte (nem sempre ou não\nnecessariamente) da avaliação psicológica e consiste\nna aplicação de um ou mais testes psicológicos.\nIII. Psicometria é um instrumento psicológico que avalia\n(mede ou faz uma estimativa) construtos (também\nchamados de variáveis latentes) que não podem ser\nobservados diretamente e que podem ser aplicados em\ngrupo ou individualmente. Exemplos desses construtos\nseriam altruísmo, inteligência, extroversão, otimismo e\nansiedade.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Itens I (AP como processo complexo para hipoteses/diagnosticos) e II (testagem como parte da AP) corretos. Item III define INCORRETAMENTE psicometria como 'instrumento psicologico' - psicometria e a CIENCIA/DISCIPLINA dedicada a teoria da medida, nao um instrumento."}, {"id": "1296403", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2020", "org": "CFP", "t": "", "e": "De acordo com as constatações de Faiad, Pasquali e Oliveira\n(2019) sobre o histórico e os futuros desafios da avaliação\npsicológica, assinale a alternativa correta.", "alt": {"A": "Com a chegada do século XX, Locke reaparece nos\nEstados Unidos e Rousseau, na Europa, mostrando\nduas grandes vertentes (mecanicista e organicista) da\navaliação psicológica. No Brasil, são as vertentes\norganicistas de Freud e Piaget que predominam, sendo\no maior desafio a dificuldade de aferir importantes\npressupostos estatísticos por meio dessas duas\nvertentes.", "B": "O primeiro laboratório de avaliação psicológica foi\nfundado pelo fisiólogo alemão Wundt, em 1879, em\nLeipzig, na Alemanha. Wertheimer foi um importante\ndivulgador do trabalho de Wundt nos Estados Unidos.\nEm seguida, surgiu Titchener, que se dedicava aos\nestudos dos processos da percepção. No Brasil, a\navaliação psicológica foi reconhecida como função do\npsicólogo por meio da Lei n.ᵒ 4.119, quando o curso de\nformação profissional em psicologia foi oficializado no\nMinistério da Educação (MEC). Atualmente, o maior\ndesafio da avaliação é a falta de referências para\navaliar populações com deficiências.", "C": "O primórdio da avaliação psicológica está nos estudos\ndo temperamento do romano Galeno, que embasou,\npor décadas, a proposta de classificação da\npersonalidade. No Brasil, o marco foi a criação do\nSistema de Avaliação dos Testes Psicológicos (Satepsi).\nO futuro da avaliação está na busca das causas do\ncomportamento no funcionamento neurológico. Essa\nperspectiva dirige a atenção do pesquisador à base\ncorporal de todo processo psíquico e contribui com\nconhecimento básico a respeito do funcionamento das\nfunções psíquicas, como, por exemplo, pensamento,\nmemória e percepção.", "D": "A testagem psicológica teve seus avanços iniciais\nmarcados pelos estudos de Galton, Cattell, Binet e\nSpearman. Novos avanços foram impulsionados com a\nnecessidade de seleção de recrutas do exército durante\na I Guerra Mundial e com o desenvolvimento da\ntécnica estatística Análise Fatorial. Outros marcos\nimportantes foram o desenvolvimento da Teoria de\nResposta ao Item e a elaboração de documentos\nnormativos, Standards, para melhoria da avaliação\npsicológica no mundo. No Brasil, a década de 1990 se\ndestaca por uma série de eventos específicos que\ncolocaram a avaliação psicológica como uma área\nimportante da psicologia, desencadeando seu\nreconhecimento como uma área de especialização pelo\nConselho Federal de Psicologia em 2019. Uma\nperspectiva futura dessa área, talvez, seja investigar o\nuso da inteligência artificial e da robótica como\nprocesso de avaliação do comportamento humano.", "E": "Somente com o desenvolvimento da computação, a\nárea de avaliação psicológica teve o reconhecimento\nde sua relação indissociável entre o estabelecimento\nda psicologia como ciência e profissão. Hoje há meios\npara avaliar muitos construtos psicológicos,\nenvolvendo comportamentos, afetos, processos\ncognitivos, sintomas, valores e atitudes, entre outros\naspectos da vida íntima das pessoas. Atualmente, o\núnico desafio para a área é a restrição de conteúdos e\nde cargas horárias de avaliação psicológica nos cursos\nde graduação."}, "g": "D", "j": "Faiad, Pasquali e Oliveira (2019) descrevem o historico da AP: Galton/Cattell/Binet/Spearman, I Guerra Mundial (selecao de recrutas), Analise Fatorial, TRI, Standards. No Brasil, decada de 1990 (Satepsi, reconhecimento profissional) e especializacao em AP pelo CFP em 2019, com IA/robotica como perspectiva futura."}, {"id": "1296401", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Segundo a Resolução CFP n.ᵒ 1/2009, julgue os itens que se\nseguem.    I. Os documentos agrupados nos registros do trabalho\nrealizado devem contemplar a identificação do usuário\nou da instituição.\nII. Os documentos agrupados nos registros do trabalho\nrealizado devem contemplar a avaliação de demanda e\na definição de objetivos do trabalho.\nIII. Os documentos agrupados nos registros do trabalho\nrealizado devem contemplar o registro da evolução do\ntrabalho, de modo a permitir seu acompanhamento e\nos procedimentos técnico-científicos adotados.\nIV. Os documentos agrupados nos registros do trabalho\nrealizado devem contemplar o registro de\nencaminhamento ou encerramento.\nV. Os documentos resultantes da aplicação de\ninstrumentos de avaliação psicológica deverão ser\narquivados em pasta de acesso exclusivo do psicólogo.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens II, III, IV e V estão certos.", "B": "Apenas os itens I, III e V estão certos.", "C": "Apenas os itens I, II e IV estão certos.", "D": "Apenas os itens I, III, IV e V estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos conforme Res CFP 1/2009: identificacao (I), avaliacao da demanda e objetivos (II), registro de evolucao (III), encaminhamento/encerramento (IV) e arquivo de instrumentos de avaliacao em pasta de acesso exclusivo do psicologo (V)."}, {"id": "1296399", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2020", "org": "CFP", "t": "", "e": "Acerca da guarda do registro documental que, conforme\nestabelecido pela Resolução CFP n.ᵒ 1/2009, é de\nresponsabilidade do psicólogo e(ou) da instituição em que\nocorreu o serviço, assinale a alternativa correta.", "alt": {"A": "O período de guarda deve ser de, no mínimo, dez anos,\npodendo ser ampliado nos casos previstos em lei, por\ndeterminação judicial, ou em casos específicos em que\nseja necessária a manutenção da guarda por maior\ntempo.", "B": "O período de guarda deve ser de três anos, podendo\nser ampliado nos casos previstos em lei, por\ndeterminação judicial, ou em casos específicos em que\nseja necessária a manutenção da guarda por maior\ntempo.", "C": "O período de guarda deve ser de um ano, podendo ser\nampliado nos casos previstos em lei, por determinação\njudicial, ou em casos específicos em que seja\nnecessária a manutenção da guarda por maior tempo.", "D": "O período de guarda deve ser de, no mínimo, cinco\nanos, podendo ser ampliado nos casos previstos em lei,\npor determinação judicial, ou ainda em casos\nespecíficos em que seja necessária a manutenção da\nguarda por maior tempo.", "E": "O período de guarda deve ser de dois anos, podendo\nser ampliado nos casos previstos em lei, por\ndeterminação judicial, ou em casos específicos em que\nseja necessária a manutenção da guarda por maior\ntempo."}, "g": "D", "j": "Res CFP 1/2009 estabelece prazo MINIMO de 5 anos para guarda do registro documental psicologico, podendo ser ampliado por lei, decisao judicial ou casos especificos. Demais alternativas apresentam prazos incorretos (1, 2, 3 ou 10 anos)."}, {"id": "1097860", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a substâncias"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A  dependência  química  é  um  problema  que  pode  afetar \nindivíduos  e  causar  danos  individuais  e  sociais.  Saber \nidentificá‐la  é  o  primeiro  passo  para  uma  intervenção  \nbem‐sucedida uma vez que seu tratamento é complexo assim \ncomo  sua etiologia.  Assinale a alternativa que apresenta os \ncritérios  diagnósticos  para  os  transtornos  do  uso  de \nsubstâncias.", "alt": {"A": "compulsão, perda de controle e uso apesar do prejuízo", "B": "tempo  gasto  para  o  uso  e  recuperação  do  uso  da \nsubstância e compulsão.", "C": "tolerância, compulsão, perda de controle, síndrome de \nabstinência, negligência  de  atividades, tempo gasto no \nuso e na recuperação do uso e uso apesar do prejuízo.", "D": "negligência  de  atividades,  perda  de  controle  e  uso \napesar do prejuízo.", "E": "compulsão, perda de controle e negligência."}, "g": "C", "j": "Criterios diagnosticos para transtornos por uso de substancias (DSM-5/CID): tolerancia, compulsao, perda de controle, sindrome de abstinencia, negligencia de atividades, tempo gasto no uso/recuperacao e uso apesar do prejuizo. Demais alternativas apresentam subconjuntos incompletos."}, {"id": "1097856", "d": "psicologia", "a": ["Psicopatologia", "Transtornos da Ansiedade"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "Nervosismo,  tremores,  tensão  muscular,  transpiração, \npalpitações  e  desconforto  gástrico  são  sintomas  do \ntrasntorno", "alt": {"A": "psicossomático.", "B": "neurótico.", "C": "ansioso.", "D": "depressivo.", "E": "psicótico."}, "g": "C", "j": "Nervosismo, tremores, tensao muscular, transpiracao, palpitacoes e desconforto gastrico configuram sintomas tipicos do transtorno ansioso (manifestacoes neurovegetativas da ansiedade)."}, {"id": "1097839", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A utilização de testes psicológicos pode ser feita com diversos\nobjetivos.  Assinale  a  alternativa  que  apresenta  os \nprofissionais que podem utilizá‐los.", "alt": {"A": "médicos e psicólogos", "B": "psicólogos e psicopedagogos", "C": "psicólogos", "D": "psiquiatras e psicólogos", "E": "neurologistas e psicólogos"}, "g": "C", "j": "A utilizacao de testes psicologicos e atividade PRIVATIVA do psicologo, conforme Lei 4.119/1962 e regulamentacoes do CFP. Medicos, psiquiatras, neurologistas e psicopedagogos nao possuem essa prerrogativa profissional."}, {"id": "1097833", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A  Psicanálise  tem  diversos  métodos.  Assinale  a  alternativa \nque apresenta um  desses métodos.", "alt": {"A": "neurose", "B": "psicose", "C": "associação livre", "D": "análise comportamental", "E": "perversão"}, "g": "C", "j": "Associacao livre e o metodo fundamental da psicanalise (Freud) - paciente fala tudo o que vem a mente sem censura. Neurose, psicose e perversao sao categorias diagnosticas; analise comportamental e de outra abordagem teorica."}, {"id": "1301789", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Considere‐se  a  seguinte  fala  de  um  médico  e  seu \nrelacionamento  profissional  de  saúde  com  o  doente  e  a \ndoença:  “A  senhora  é  uma  bomba  relógio,  pode  morrer  a \nqualquer momento com a doença que tem”. De acordo com \nAngerami‐Camon  (2002),  é  correto  afirmar  que  esse \nprofissional de saúde tenha adotado como postura o(a)", "alt": {"A": "empatia genuína.", "B": "calosidade profissional.", "C": "profissionalismo afetivo.", "D": "barreira profissional.", "E": "abertura profissional."}, "g": "B", "j": "Em Angerami-Camon, a 'calosidade profissional' descreve a postura insensivel/dura do profissional que comunica diagnosticos graves de forma seca, sem cuidado afetivo - exatamente como na fala do medico exemplificada."}, {"id": "1301788", "d": "psicologia", "a": ["Psicologia da Saúde", "Dor, Estresse e Luto", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  ao  luto  vivenciado  pela  criança  em  situações  de \ndesastre, assinale a alternativa incorreta.", "alt": {"A": "Geralmente,  o  luto  da  criança  não  é  reconhecido  ou \nvalidado.", "B": "O não fornecimento de informações corretas a respeito \ndo ocorrido é benéfico ao processo de luto da criança, \npois ela não tem compreensão para assimilá‐lo.", "C": "Grande  parte  da  construção  de  significado  que  a \ncriança  pode  fazer  de  seu  luto  é  influenciada  pela \nfamília, que lhe dá suporte tanto para crescer quanto \npara lidar com crises desencadeadas por perdas.", "D": "Estudos  comprovam  que  pessoas  que  apresentaram \ndistúrbios  psiquiátricos  após  a  perda  provavelmente \nreceberam  uma  atenção  paterna  ou  materna \ndeficiente no processo de luto.", "E": "A  criança  em  processo  de  luto  pode  canalizar  sua \nansiedade de separação em algo que lhe dê segurança, \ncomo um bichinho de pelúcia, um animal de estimação \nou o pai sobrevivente."}, "g": "B", "j": "Questao pede INCORRETA. O nao fornecimento de informacoes corretas NAO e benefico - dificulta o processo de luto e o reconhecimento do real pela crianca. Demais alternativas reproduzem corretamente caracteristicas do luto infantil em desastres."}, {"id": "1301787", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  à  prática  profissional  do  psicólogo  em \nemergências e desastres, julgue os itens seguintes.  \nI  A  ação  do  psicólogo  no  pós‐desastre  é  somente \nidentificar os  transtornos mentais, com  foco principal \nno transtorno de estresse pós‐traumático. \nII  Uma  das  importantes  funções  do  psicólogo  de \nemergências  e  desastres  é  cuidar  das  pessoas,  \nlembrá‐las,  incentivá‐las  ou  conduzi‐las  para \nrealizarem cuidados básicos, como o de se alimentar e \no de dormir. \nIII  Muitas  vezes,  o  atendimento  psicológico  é  feito  em \nlocal  público,  com  pessoas  passando,  chorando  ou \ngritando, barulhos e cheiros. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "E", "j": "Apenas II e III corretos. Item I e falso ao restringir a acao do psicologo SOMENTE ao diagnostico de TEPT - sua atuacao e ampla (acolhimento, suporte, cuidados basicos). Item II (cuidados basicos) e III (atendimento em local publico) descrevem corretamente o trabalho em desastres."}, {"id": "1301783", "d": "psicologia", "a": ["Psicofarmacologia"], "ano": "2018", "org": "CFP", "t": "", "e": "A psicofarmacologia é a ciência que estuda os  remédios de \nação psíquica. Nesse contexto, é correto afirmar que", "alt": {"A": "o  mecanismo  de  ação  do  medicamento  seja  a  forma \ncomo o organismo irá reagir a ele.", "B": "efeito colateral  seja o  resultado desejado da ação do \nremédio.", "C": "efeito  placebo  seja  o  efeito  que  uma  substância \nquimicamente  produza  em  uma  pessoa  que  recebeu \nefetivamente um remédio.", "D": "psicotrópicos  sejam  os  medicamentos  para  a  vida \npsíquica.", "E": "nenhuma  medicação  possa  auxiliar  no \ndesencadeamento de transtornos mentais."}, "g": "D", "j": "Psicotropicos sao medicamentos com acao sobre a vida psiquica (sistema nervoso central). A confunde mecanismo de acao com efeito; B confunde colateral com terapeutico; C confunde placebo com farmaco ativo; E nega potencial iatrogenico de farmacos."}, {"id": "1301782", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica", "Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Um  paciente  de  25  anos  de  idade  encontra‐se \ninternado  na  UTI  há  vinte  dias  por  ter  sofrido  acidente \nautomobilístico,  com  grave  dano  neurológico.  Durante  o \natendimento da equipe, não abriu os olhos, não  respondeu \nverbalmente e não reagiu ao estímulo de dor.  \nCom base nesse caso hipotético, assinale a alternativa correta \nde acordo com a escala de Glasgow", "alt": {"A": "A  escala  de  Glasgow  classifica  o  estado  neurológico \ne(ou)  de  consciência  do  paciente  e  varia  de  0  a  15 \npontos.", "B": "O paciente descrito tem escore de Glasgow igual a 15.", "C": "A  escala  de  Glasgow  avalia  quantitativamente  e \nqualitativamente a consciência.", "D": "A escala de Glasgow avalia a abertura ocular, a resposta \nmotora e a memória.", "E": "O paciente descrito tem escore de Glasglow igual a 3."}, "g": "E", "j": "Paciente sem abertura ocular (1) + sem resposta verbal (1) + sem resposta motora a dor (1) = 3 pontos na escala de Glasgow (coma profundo). A erra ao apontar variacao 0-15 (e 3-15); B erra na pontuacao maxima; C erra natureza (e quantitativa); D inclui memoria indevidamente."}, {"id": "1301779", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação aos aspectos emocionais envolvidos nas urgências \nem obstetrícia e ginecologia, julgue os itens a seguir. \nI  Um óbito fetal pode representar a frustração de muitos \ndesejos e fantasias e, sobretudo, rompe a possibilidade \ndo exercício da maternidade. \nII  O luto de uma criança pode desenvolver sentimentos \nde  raiva,  hostilidade  e  rancor  nos  familiares,  que \npodem depositá‐los na equipe de saúde. \nIII  O  nascimento  de  uma  criança  com  malformação \ncongênita  geralmente  envolve  a  perda  do  filho \nidealizado. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: obito fetal rompe possibilidade da maternidade idealizada (I); luto pode gerar raiva projetada na equipe (II); malformacao congenita envolve perda do filho idealizado (III) - aspectos emocionais classicos em ginecologia/obstetricia."}, {"id": "1301777", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando  a  atuação  do  psicólogo  hospitalar,  assinale  a \nalternativa  que  apresenta  conduta  que  não  se  insere  na \nprática de manejo da ansiedade do paciente no pré‐cirúrgico.", "alt": {"A": "aumentar o acesso dos familiares ao paciente", "B": "orientação a respeito do procedimento cirúrgico", "C": "prescrever ansiolíticos", "D": "técnica de relaxamento", "E": "promover  trocas  de experiências  com  outras  pessoas \nque já passaram por cirurgias"}, "g": "C", "j": "Prescrever ansioliticos NAO e atribuicao do psicologo hospitalar - cabe ao medico. Demais condutas (acesso da familia, orientacao, relaxamento, troca de experiencias) sao do manejo psicologico no pre-cirurgico."}, {"id": "1301776", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere à avaliação psicológica e aos envolvidos no \nprocesso  de  transplantes  de  órgãos,  assinale  a  alternativa \nincorreta.", "alt": {"A": "A  atuação  do  psicólogo  no  processo  de  transplante \ncontempla:  contato  inicial;  avaliação  para  ser  aceito \ncomo um potencial receptor de transplante; cirurgia e \nperíodo de recuperação pós‐cirúrgica; e ajustes a longo \nprazo do pós‐transplante.", "B": "Os  componentes  básicos  da  avaliação  psicológica  \npré‐transplante  podem  ser  resumidos  na  história \npregressa e atual de saúde mental, de enfrentamento \nda  doença,  de  uso  de  drogas,  de  estado  mental,  de \napoio  social,  de  compreensão  da  doença  e  de \nprocedimento do transplante.", "C": "Os  candidatos  a  transplante  apresentam \nsignificativamente  maiores  risco  de  angústia  e(ou) \ndistúrbios depressivos que a população em geral.", "D": "A  avaliação  psicológica  dos  sujeitos  a  serem \nsubmetidos a  transplante visa apenas a identificar  os \nque deveriam ser excluídos como candidatos.", "E": "O  receptor  geralmente  se  sente  como  um  devedor, \ncarregado  de  sentimento  de  culpa,  sendo  difícil  para \nele não atender a qualquer demanda do doador."}, "g": "D", "j": "Questao pede INCORRETA. A avaliacao psicologica em transplantes NAO visa APENAS excluir candidatos - tem funcao tambem de preparacao, suporte e acompanhamento. Demais alternativas descrevem corretamente etapas, componentes, risco psiquiatrico e dinamica doador-receptor."}, {"id": "1301773", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Saúde", "Psicologia Hospitalar", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto ao  quadro de delirium  nos  pacientes internados na \nUTI, assinale a alternativa correta.", "alt": {"A": "Algumas escalas e entrevistas semiestruturadas foram \ndesenvolvidas para auxiliar o clínico na avaliação e no \ndiagnóstico  de  delirium,  como,  por  exemplo,  o  CAM \n(Confusion Assessment Method).", "B": "Pacientes  com  delirium  hiperativo  interagem  pouco \ncom  o  ambiente  e  encontram‐se  letárgicos  e \nsonolentos.", "C": "Pacientes  com  delirium  hipoativo  são,  em  geral, \ninquietos  e  agitados,  apresentando  frequentemente \ndelírios,  ilusões,  alucinações,  atividades \nestereotipadas,  logorreia,  hiperatividade  motora  e \nagressividade.", "D": "As estratégias centrais para prevenir o delirium incluem \natividades  terapêuticas,  reorientação,  otimização  do \nsono, pouca mobilização do paciente, desidratação oral \ne auxílio visual e auditivo.", "E": "A deficiência visual e(ou) auditiva e a contenção física \nsão fatores favoráveis para controle do delirium."}, "g": "A", "j": "O CAM (Confusion Assessment Method) e uma das escalas semiestruturadas mais utilizadas para rastreio e diagnostico de delirium na UTI. B e C invertem caracteristicas de hipoativo/hiperativo; D inclui 'desidratacao oral' (deveria ser HIDRATACAO); E inverte fatores de risco como protecao."}, {"id": "1301772", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Saúde", "Psicologia Hospitalar", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Na UTI,  são  frequentes  os quadros de confusão mental e a \npresença  de  delirium  nos  pacientes  internados.  A  respeito \ndesse tema, assinale a alternativa incorreta.", "alt": {"A": "O  delirium,  ou  estado  confusional  agudo,  é \ncaracterizado  por  estreitamento  da  consciência, \nprejuízo  na  atenção  e  alterações  cognitivas  e \nsensoperceptivas.", "B": "O  delirium  pode  ser  uma  consequência  fisiológica \ndireta  de  uma  condição médica geral,  intoxicação  ou \nabstinência  de  substâncias  psicoativas,  uso  de \nmedicação,  exposição  a  toxinas  ou  uma  combinação \ndesses fatores.", "C": "O  delirium  tem  caráter  flutuante  dos  sintomas,  com \nperíodos de melhora e de piora.", "D": "Ter  idade  avançada,  lesão  cerebral  prévia  e \ncomprometimento  cognitivo  são  fatores  de  proteção \nde delirium.", "E": "O  delirium  pode  estar  associado  a  internações  mais \nlongas e ser indicativo de mau prognóstico."}, "g": "D", "j": "Questao pede INCORRETA. Idade avancada, lesao cerebral previa e comprometimento cognitivo sao FATORES DE RISCO para delirium, nao de protecao. Demais alternativas descrevem corretamente estreitamento da consciencia, etiologia, flutuacao dos sintomas e prognostico."}, {"id": "1301771", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  se  refere  a  fases/estados  estudados  por  Elisabeth  \nKluber‐Ross, julgue os itens que se seguem. \nI  Não  há  uma  ordem  para  a  ocorrência  dessas \nmanifestações e o paciente pode vivenciar mais de um \ndesses estágios concomitantemente, ou não vivenciar \nalguns deles. \nII  A  divisão  em  fases  é  bastante  didática  e  se  aplica \nsomente quando a terminalidade for real. \nIII  As  fases/os  estados  que  um  paciente  pode  vivenciar \ndurante  sua  terminalidade  são:  negação;  raiva; \nbarganha; depressão; e angústia.  \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas I correto - nao ha ordem fixa para os estagios de Kubler-Ross. Item II e falso pois a divisao aplica-se tambem a outras perdas. Item III troca 'aceitacao' por 'angustia' - as cinco fases sao: negacao, raiva, barganha, depressao e ACEITACAO."}, {"id": "1301769", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  apresenta  atuação  que  não  se \ninsere na prática profissional do psicólogo hospitalar.", "alt": {"A": "ajudar o paciente a expressar suas emoções", "B": "ajudar  o  paciente  a  buscar  recursos  internos  para \nenfrentar suas dificuldades", "C": "desconvencer o paciente de realizar alta a pedido", "D": "esclarecer ao paciente fantasias que possam prejudicar \nseu tratamento", "E": "incentivar a confiança do paciente na equipe"}, "g": "C", "j": "Desconvencer o paciente de uma alta a pedido NAO se insere na pratica psicologica - viola a autonomia do paciente (CEP). O papel do psicologo e escutar, esclarecer e respeitar a decisao. Demais alternativas (expressar emocoes, recursos internos, fantasias, confianca) sao corretas."}, {"id": "1301767", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  relação  ao  setting  terapêutico  descrito  por  Simonetti \n(2014), julgue os itens que se seguem. \nI  O ambiente hospitalar tem condições desfavoráveis à \natividade  psicoterapêutica:  local  com  falta  de \nprivacidade;  barulhos;  interrupções  etc.,  porém  isso \nnão impede que seja realizada. \nII  O propósito da psicologia hospitalar é levar o paciente \na  uma  psicoterapia  mais  prolongada  após  a  alta  do \nhospital. \nIII  A cessação da demanda do paciente determina o final \ndo tratamento psicológico no hospital.  \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (ambiente hospitalar adverso mas viavel) e III (cessacao da demanda determina o fim do tratamento no hospital) corretos. Item II e falso - o proposito da psicologia hospitalar nao e conduzir a psicoterapia prolongada apos a alta, mas atuar nos aspectos psicologicos do adoecimento."}, {"id": "1301765", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "O  psicólogo  hospitalar  precisa  compreender  algumas \npeculiaridades de fases/estados que os pacientes vivenciam \nno processo de perda e luto ligado à doença, à hospitalização \ne  ao  tratamento.  Acerca  desse  tema,  assinale  a  alternativa \ncorreta.", "alt": {"A": "Na fase da negação, o paciente absorve com clareza os \nresultados de exames ou da terapêutica.", "B": "O  psicólogo  hospitalar  compreende  as  angústias  dos \npacientes  na  fase  da  revolta e  suporta  “indiretas”  ou \nagressões  por  atos  ou  verbalizações,  orientando  a \nequipe e a família sobre essas reações.", "C": "Na  fase  da  depressão,  o  paciente  é  sempre \ndiagnosticado com transtorno de depressão e recebe o \ntratamento conforme a doença mental.", "D": "Na fase da revolta, é fundamental que o profissional de \npsicologia apresente os pontos positivos da situação.", "E": "Na  fase  da  negação,  o  psicólogo  hospitalar  deve \nconvencer o paciente de que ele é doente e necessita \nde aderir ao tratamento."}, "g": "B", "j": "Na fase da revolta, o psicologo deve compreender as angustias, suportar agressoes/indiretas e orientar equipe e familia sobre o significado dessas reacoes. Demais alternativas distorcem negacao (paciente nao absorve), depressao (nao se diagnostica automaticamente), e abordagem na revolta."}, {"id": "1301764", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  à  psicologia  hospitalar,  assinale  a  alternativa \nincorreta.", "alt": {"A": "A psicologia hospitalar utiliza‐se de recursos técnicos e \nmetodológicos  de  outras  áreas  do  conhecimento  da \npsicologia, como a clínica, a organizacional, a social e a \neducacional.", "B": "A  psicologia  hospitalar  pode  ser  entendida  como  o \ncampo  de  entendimento  e  tratamento  dos  aspectos \npsicológicos em torno do adoecimento.", "C": "A psicologia hospitalar define como objeto de trabalho \na angústia do paciente, da família e da equipe.", "D": "O  objetivo  da  psicologia  hospitalar  é  dar  voz  à \nsubjetividade  do  sujeito  com  foco  nos  aspectos \npsicológicos em torno do adoecimento.", "E": "A  psicologia  hospitalar  tem  como  principal  objetivo \nauxiliar  a  medicina  na  cura  e  no  tratamento  do \npaciente."}, "g": "E", "j": "Questao pede INCORRETA. O principal objetivo da psicologia hospitalar NAO e 'auxiliar a medicina na cura' - e dar voz a subjetividade no contexto do adoecimento. Demais alternativas descrevem corretamente recursos interdisciplinares, escopo e objeto."}, {"id": "1301763", "d": "psicologia", "a": ["Comunicação em Psicologia", "Psicologia e Organizações", "Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Estudiosos  chegam  a  afirmar  que  93%  dos \npensamentos são transmitidos de forma não verbal. \n  Caponero, 2015.\n    De acordo com esse autor, assinale a alternativa correta.", "alt": {"A": "A comunicação verbal é responsável pelo maior volume \nde informações transmitidas.", "B": "É irrelevante considerar o tom de voz, o jeito como as palavras são ditas, olhares e expressões faciais, gestos \nque  acompanham  o  discurso,  postura  corporal, tamanho  da  distância  física  que  as  pessoas  mantêm umas das outras, suas roupas e características físicas.", "C": "O psicólogo hospitalar precisa estar atento às reações \ndo  paciente  durante  algumas  orientações.  Se  houver \nchoro, é necessário interromper a explicação, esperar \nque  se  recupere  e,  em  seguida,  retomar  a  conversa, \nrepassando todas as informações aglomeradas.", "D": "Muitas  vezes,  o  psicólogo  hospitalar  utiliza‐se  do \nrecurso  de  permanecer  ao  lado  de  uma  pessoa em \nsilêncio.  Demonstrar  disponibilidade  para  ficar  junto “mais um pouco” e disposição para ouvir substituem o \nfalar.", "E": "A  comunicação  é  uma  habilidade  que  não  pode  ser \ntreinada."}, "g": "D", "j": "Em Caponero, o psicologo hospitalar pode permanecer em silencio ao lado do paciente, demonstrando disponibilidade e disposicao para ouvir - postura terapeutica que substitui o falar. A inverte proporcao verbal/nao verbal; B nega importancia da comunicacao nao verbal; C confunde manejo do choro; E nega treinabilidade da habilidade."}, {"id": "1301757", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Nesse local onde tudo é da ordem do imprevisível, o \natendimento psicológico também é.  \nCotta & Miranda, 1997.  \nA  frase  se  refere  ao  atendimento  do  psicólogo  diante  da \nurgência do pronto‐socorro (PS). Nesse contexto, a respeito \nda  atuação  do  profissional  de  psicologia,  assinale  a \nalternativa incorreta.", "alt": {"A": "A prática do psicólogo não é isolada, ela  faz parte de \numa equipe multiprofissional. Muitas vezes, a equipe \ntem  dificuldade  de  lidar  com  a  questão  da  morte  e \npode manifestar raiva diante de casos de maus‐tratos \nde crianças, estupro, abandono e tentativa de suicídio. \nAs  dificuldades  vividas  pela  equipe  muitas  vezes  são \nexperimentadas pelo psicólogo.", "B": "O paciente idoso no PS costuma criar fantasias bizarras \ne assustadoras a respeito de seu processo de adoecer. \nDiante  disso,  o  psicólogo  pode  clarificar  percepções \ndistorcidas,  informações  errôneas  e  fantasias, \nfacilitando uma percepção mais real.", "C": "É importante que o psicólogo saiba que o adolescente \nem  situação  de  doença  vivencia  um  processo  de \nnegação, portanto se preocupa mais com a imagem e \nas  alterações  corporais  provocadas  pela  doença  que \ncom a possibilidade de morte.", "D": "O  psicólogo  no  PS  deve  orientar  a  equipe  a  evitar \ninformar à criança na idade pré‐escolar a respeito dos \nprocedimentos  dolorosos,  pois  poderá  enfraquecê‐la \npsicologicamente diante das fantasias sobre a morte.", "E": "A prática do psicólogo no PS não deve ser pautada no \nmodelo clínico tradicional."}, "g": "D", "j": "Questao pede INCORRETA. Criancas em idade pre-escolar DEVEM ser informadas sobre procedimentos dolorosos, em linguagem adequada - a omissao gera fantasias mais aterradoras que a realidade. Demais alternativas descrevem corretamente trabalho multiprofissional, atendimento ao idoso, adolescente e modelo nao tradicional."}, {"id": "1299591", "d": "psicologia", "a": ["Psicologia Jurídica", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  à  obra  Adoção  Tardia  de  Vargas,  julgue  os  itens \nseguintes.  \nI  A questão do preconceito é levantada pela maioria dos \nautores  de  diversas  formas,  desde  a  pouca \ndisponibilidade  das  pessoas  para  a  adoção  até  a \ncarência de publicação em seu meio. II  A adoção continua sendo mais aceita quando atende a \numa  necessidade  “natural”  de  um  casal,  com \nimpedimentos para gerar filhos, de adotar crianças de \nqualquer idade.  \nIII  A maioria dos pais referiu ter sido ou estar sendo alvo \nde  perguntas  ou  observações  do  tipo:  “por  que  não \nadotaram  um  nenezinho?”;  “deve  ser  muito  difícil \neducar uma criança ‘assim’, não pode contrariar nem \nnada, né?”; ou “puxa, que coragem a sua!”.  \nIV Alguns,  por  terem  a  prática  como  algo  inserido  na \ncultura  familiar e  na  fé  religiosa, consideram‐na  bem \naceita dentro desse contexto. Por outro lado, todos os \nguardiões, em algum momento do acompanhamento, \nexpressaram  de  forma  quase  idêntica:  “parece  que \nele(a) sempre viveu aqui, sempre foi nosso(a) filho(a)”. \nV Pode‐se acompanhar o quão sofrido pode ser para os \npais  adotivos  lidarem  com  esse  procedimento, \nprincipalmente  quando  ele  se  soma  à  sensação  de \nimpotência, ao sentimento de menos‐valia relacionado \nà não procriação do filho.A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "D", "j": "Quatro itens corretos (I, III, IV e V) em Vargas. Item II e falso ao afirmar que a adocao 'continua sendo mais aceita... de qualquer idade' - na pratica, a aceitacao se concentra em criancas pequenas, o que justifica a denominacao 'adocao tardia' como questao."}, {"id": "1299574", "d": "psicologia", "a": ["Família", "Psicologia Jurídica"], "ano": "2018", "org": "CFP", "t": "", "e": "Julgue os itens a seguir. \nI  Segundo  Silva  (2006),  o  processo  de  alienação  pode \nassumir  a  forma  de  obstrução  a  todo  contato,  sendo \nque  o  argumento  mais  utilizado  é  o  de  que  o  outro \ngenitor não é capaz de ocupar‐se dos filhos e que estes \nnão se sentem bem quando voltam das visitas. \nII  Segundo  Silva  (2006),  o  processo  de  alienação  pode \nassumir  a  forma  de  argumento  de  que  ver  o  outro \ngenitor  não é  conveniente  para  os  filhos e  que estes \nnecessitam de tempo para se adaptar.  \nIII  Segundo  Silva  (2006),  o  processo  de  alienação  pode \nassumir  a  forma  de  mensagem  dirigida  aos  filhos  de \nque é desagradável ir conviver com o outro genitor. \nIV  Segundo  Silva  (2006),  o  processo  de  alienação  pode \nassumir  a  forma  de  denúncias  falsas  de  abuso;  dos \nabusos  normalmente  invocados,  o  mais  grave  é  o \n“abuso  sexual”,  que  ocorre em  cerca  de metade  dos \ncasos  de  separação  problemática,  especialmente \nquando os filhos são pequenos e mais manipuláveis.  \nV  Segundo  Silva  (2006),  o  processo  de  alienação  pode \nassumir  a  forma  de  “abuso  emocional”,  que  ocorre \nquando  um  genitor  acusa  o  outro,  por  exemplo,  de \nmandar os filhos dormirem demasiadamente tarde. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "E", "j": "Todos os cinco itens descrevem corretamente formas do processo de alienacao em Silva (2006): obstrucao a contato, argumento de inconveniencia, mensagens negativas, denuncias falsas (incluindo abuso sexual) e abuso emocional."}, {"id": "1299565", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Família", "Psicologia Jurídica"], "ano": "2018", "org": "CFP", "t": "", "e": "Silva (2009) cita Douglas Darnall, na obra Protegendo os seus \nfilhos da alienação parental (Protecting your children  from \nparental alienation), ao descrever o genitor alienador como \nproduto  de  um  sistema  ilusório  em  que  todo  o  seu  ser  se \norienta para a destruição da relação dos  filhos com o outro \ngenitor,  de  forma  a  ficar  com  o  controle  total  dos  filhos, \ntransformando essa situação em uma questão de vida ou de \nmorte. Considerando essa informação, assinale a alternativa \nque  apresenta  um  comportamento  clássico  de  um  genitor \nalienador na relação.", "alt": {"A": "apresentar  pessoas  próximas  (amigos  \nrecém‐conhecidos, novo cônjuge etc.) para convivência \ncom os filhos", "B": "tomar  decisões  importantes  a  respeito  dos  filhos, \nconsultando  o  outro  genitor  (escolha  da  religião,  da \nescola etc.)", "C": "propor  que  o  outro  genitor  tenha  acesso  às \ninformações escolares e(ou) médicas dos filhos", "D": "sair  de  férias  sem  os  filhos,  deixando‐os  com  outras \npessoas, que não o outro genitor, ainda que este esteja \ndisponível e queira ocupar‐se dos filhos", "E": "permitir que os filhos usem roupas e outras ofertas do \noutro genitor"}, "g": "D", "j": "Comportamento classico do genitor alienador (Darnall apud Silva): sair de ferias sem os filhos, deixando-os com terceiros, mesmo quando o outro genitor esta disponivel - inviabiliza convivencia paterna. Demais alternativas descrevem comportamentos COLABORATIVOS, opostos ao perfil alienador."}, {"id": "1298801", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando  a  conceituação  e  as  características  das \npropriedades  básicas  dos  instrumentos  de  avaliação \npsicológica, especialmente as relativas a testes psicológicos, \nsegundo  Goulart  e  Sampaio  (1998),  assinale  a  alternativa \ncorreta.", "alt": {"A": "A capacidade do teste de medir o que se propõe, isto \né,  se  as  diferenças  de  resultado  refletem  diferenças \nreais  entre  os  indivíduos  ou  do mesmo  indivíduo  em \nsituações diferentes, é denominada de fidedignidade.", "B": "A padronização refere‐se ao controle das condições de \naplicação, avaliação e interpretação do teste, de forma \na obter uma uniformidade do processo de testagem.", "C": "A validade envolve as noções de realização normal ou \nmédia  dos  sujeitos  testados,  com  seus  respectivos \ndesvios.", "D": "A  norma  reflete  a  capacidade  do  instrumento  de \nreproduzir  os  resultados  de  um  teste  em  diferentes \nocasiões  de  condições  similares  para  assegurar \nconfiabilidade de resultados.", "E": "A norma envolve as noções de precisão, estabilidade e \nconsistência interna."}, "g": "B", "j": "Padronizacao refere-se ao controle das condicoes de aplicacao, avaliacao e interpretacao do teste para garantir uniformidade do processo de testagem. A define fidedignidade como validade (inverte); C confunde validade com norma; D/E confundem norma com fidedignidade."}, {"id": "1298798", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Os  psicólogos organizacionais executam  diferentes  tipos de \ntrabalho  em  uma  enorme  variedade  de  ambientes.  Muitas \nvezes,  esses  ambientes  são  divididos  naqueles  que  dizem \nrespeito  à  prática  e  naqueles  relativos  à  pesquisa.  Diante \ndessa  perspectiva,  assinale  a  alternativa  que  apresenta \natividade que não seja de um psicólogo organizacional.", "alt": {"A": "analisar a natureza de uma atividade (análise da tarefa) \ne as exigências de competências para seu desempenho", "B": "conduzir  uma  análise  para  implementar  mudanças  e \ndeterminar a solução de um problema organizacional", "C": "projetar  sistemas  de  seleção  de  funcionários  e  de \nprogramas de treinamento", "D": "projetar  sistemas  de  tecnologia  de  informação  para \nresolução de problemas operacionais na organização", "E": "realizar  pesquisas  sobre  opiniões  e  sentimentos  dos \nfuncionários"}, "g": "D", "j": "Projetar sistemas de tecnologia da informacao para problemas operacionais NAO e atividade do psicologo organizacional - cabe a engenheiros de sistemas/TI. Demais alternativas (analise de tarefa, mudanca organizacional, selecao/treinamento, pesquisa de opinioes) sao do escopo da POT."}, {"id": "1298797", "d": "psicologia", "a": ["Psicologia Organizacional", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Na  empresa,  a  partir  do  limite  da  “dor  do  corpo”  ou  de \nsensações  de  sofrimento  psíquico,  segundo  Limongi‐França \n(2008),  ocorrem  processos  de  interação  interpessoal \nmarcados  pela  percepção  de  fenômenos  associados  à \ndoença, à saúde, ao trabalho e à produtividade. O sofrimento \npessoal  é  intrínseco  à  dor,  à  queixa  e  aos  sintomas.  Para \ntanto,  existem  recursos  terapêuticos  e  de  prevenção  que \npodem  atenuar,  ou  mesmo  eliminar,  esse  sofrimento. \nAssinale  a  alternativa  que  apresenta,  exclusivamente, \nrecursos terapêuticos e de prevenção que visem a atenuar ou \neliminar o sofrimento emocional no trabalho.", "alt": {"A": "bens de consumo, educação, segurança e mudança de \nemprego", "B": "afastamento  das  condições  adversas,  conversa, \ncompartilhamento  de  problemas  e  revisão  das \ncondições de trabalho", "C": "misticismo, desinformação, oportunismo e excesso de \ntrabalho", "D": "dispensa  do  trabalho,  demissão,  desabafo  e \nrelacionamento comprometido", "E": "repouso,  mudança  de  ambiente,  CIPA  e  criação  de \nconflitos de papéis"}, "g": "B", "j": "Recursos terapeuticos/preventivos para sofrimento no trabalho (Limongi-Franca): afastamento das condicoes adversas, conversa, compartilhamento de problemas e revisao das condicoes de trabalho. Demais alternativas misturam fatores que agravam, sao paliativos ou nao terapeuticos (misticismo, demissao, criacao de conflitos)."}, {"id": "1298795", "d": "psicologia", "a": ["Psicodinâmica do Trabalho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Conforme Limongi‐França (2008), a essência de cada pessoa \né  sua  personalidade,  a  qual  exerce  uma  significativa \ninfluência  no  ambiente  de  trabalho.  Com  relação  à \npersonalidade segundo a autora, é correto afirmar que", "alt": {"A": "se manifeste apenas nas organizações de trabalho.", "B": "envolva  a  organização  integrada  de  características \ncognitivas, afetivas, volitivas e físicas e o modo como se \nmanifesta é que diferencie cada indivíduo.", "C": "seja  tão‐somente  resultado  do  fator  hereditariedade, \nnão podendo ser estimulada ou desenvolvida.", "D": "seja resultado dos aspectos ambientais, a despeito das \ncaracterísticas físicas ou neurológicas.", "E": "seja  um  fenômeno  psicossocial  que  se  refere  à \nnecessidade  de  recompensas  que  cada  indivíduo \nconstrói na sua trajetória de vida."}, "g": "B", "j": "Em Limongi-Franca, personalidade e organizacao integrada de caracteristicas cognitivas, afetivas, volitivas e fisicas, sendo o modo de manifestacao o que diferencia cada individuo. Demais alternativas restringem a manifestacao a organizacoes, reduzem a hereditariedade ou ambiente, ou a recompensas."}, {"id": "1298793", "d": "psicologia", "a": ["Qualidade de Vida", "Comportamento Organizacional em Psicologia", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "O  estresse  negativo,  segundo  Dubrin  (2003),  é  prejudicial \ntanto  para  a  produtividade  quanto  para  o  bem‐estar  do \nempregado.  Como  consequência,  as  empresas  estão \nativamente  envolvidas  na  administração  do  estresse, \nadotando comportamentos de apoio como", "alt": {"A": "reduzir  os  canais  de  comunicação  na  empresa  para \nevitar  preocupação  com  informações  associadas  à \nmissão e a objetivos da organização.", "B": "agir como um controlador, evitando que o empregado \nanalise um problema sob uma nova perspectiva.", "C": "não  esperar  para  transmitir  uma  informação \nestressante, espalhando, por exemplo, rumores sobre \ndownsizing.", "D": "providenciar  algum  tipo  de  ajuda,  como \nencorajamento verbal ou um período de afastamento \ndo trabalho para se recuperar de um pesado estressor.", "E": "estimular o conflito de papéis, com diversos objetivos \na serem atingidos simultaneamente."}, "g": "D", "j": "Comportamentos de apoio na administracao do estresse (Dubrin): providenciar ajuda como encorajamento verbal ou periodo de afastamento para recuperacao. Demais alternativas listam comportamentos NOCIVOS (reduzir comunicacao, controlar, espalhar rumores, estimular conflitos), contrarios ao apoio."}, {"id": "1298791", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Estresse Laboral", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "O estresse no trabalho constitui‐se em um tema de extremo \ninteresse para as organizações por causa do seu efeito sobre \na produtividade, com consequências legais e humanas. Uma \ngama  de  fatores  pessoais  internos,  bem  como  condições \norganizacionais adversas, podem causar ou contribuir para o \nestresse no trabalho. Conforme Dubrin (2003), vários fatores \ncontribuem  para  o  estresse  no  trabalho.  Sendo  assim, \nassinale a alternativa que não apresenta um deles.", "alt": {"A": "fatores negativos de estilo de vida, incluindo  falta de \nexercícios físicos, hábitos alimentares pouco saudáveis \ne alto consumo de álcool, tabaco ou outras drogas", "B": "exigências  do  cargo  associadas  ao  absoluto  controle, \npor parte do trabalhador, sobre a atividade exercida", "C": "aumento  da  carga  de  trabalho  associada  a  cortes  de \nfuncionários pela empresa", "D": "conflito  de  papéis,  em  que  o  trabalhador  precise \nescolher  entre  exigências  competitivas  ou \nexpectativas,  como,  por  exemplo,  quando  deve \nalcançar dois objetivos conflitantes", "E": "trabalho  emocional  relacionado  ao  peso  de  ter  de \nmodificar  ou  disfarçar  emoções,  ou  pelo  menos \nexpressões faciais, ao lidar com outras pessoas"}, "g": "B", "j": "Exigencias do cargo com ABSOLUTO CONTROLE do trabalhador NAO contribuem para estresse - ao contrario, a FALTA de controle e fator estressor (modelo demanda-controle de Karasek). Demais alternativas (estilo de vida, sobrecarga, conflito de papeis, trabalho emocional) sao fatores reais de estresse em Dubrin."}, {"id": "1298790", "d": "psicologia", "a": ["Conflito nas Organizações", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Conforme  Dubrin  (2003),  os  conflitos,  na  medida  certa, \nmelhoram  o  desempenho,  ao  mesmo  tempo  que  uma \nquantidade  muito  pequena,  ou  muito  grande,  pode  \ndiminui‐lo.  Considerando  essa  informação,  assinale  a \nalternativa incorreta.", "alt": {"A": "O  conflito  funcional  ocorre  quando  os  interesses  da \norganização são atendidos como resultado da disputa \nou do desacordo. O conflito disfuncional, por sua vez, \nacontece quando a disputa ou o desacordo prejudicam \na organização.", "B": "O  conflito  disfuncional  pode  desperdiçar  tempo  e \nenergia, desviando os trabalhadores do caminho para \nalcançar  metas  importantes  e  prejudicando  a \norganização.", "C": "O conflito funcional é destrutivo em muitos aspectos, \nincluindo a deterioração de relações e a diminuição dos \nníveis de desempenho.", "D": "Os  conflitos  podem  acarretar  muitas  consequências \nnegativas, como, por exemplo, a raiva, que pode, por \nsua  vez,  resultar  em  violência  perpetrada  por \ntrabalhadores  descontentes  ou  antigos  empregados \nremoendo conflitos não resolvidos.", "E": "O  conflito  na  medida  certa  pode  melhorar  o \ndesempenho.  Quando  a  comunicação  é  franca  e  os \ndiferentes pontos de vista são encorajados, o conflito \npode, por exemplo, estimular o pensamento inovador."}, "g": "C", "j": "Questao pede INCORRETA. O conflito FUNCIONAL e construtivo (estimula inovacao e melhora desempenho), nao destrutivo - quem deteriora relacoes e o conflito DISFUNCIONAL. Demais alternativas (A, B, D, E) descrevem corretamente os dois tipos."}, {"id": "1298789", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo  Robbins  (2005),  empregados  competentes  não \npermanecem,  necessariamente,  competentes  para  sempre. \nAs habilidades podem  se deteriorar ou  tornar‐se obsoletas, \npor  isso  as  organizações  investem  em  desenvolvimento  de \npessoas  e  em  novas  metodologias  de  treinamento. \nConsiderando  a  perspectiva  do  autor  sobre  o  método  de \ntreinamento no emprego, julgue os itens seguintes. \nI  A maioria dos treinamentos dá‐se no emprego.  \nII  Essa  preferência  pode  ser  atribuída  à  simplicidade  e, \ngeralmente,  ao  custo  mais  baixo  dos  métodos  de \ntreinamento no emprego. \nAssinale a alternativa correta.", "alt": {"A": "Os  dois  itens  estão  certos  e  o  segundo  completa  o \nprimeiro.", "B": "Os  dois  itens  estão  certos,  mas  o  segundo  não  se \nrelaciona ao primeiro.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "A", "j": "Ambos itens corretos e relacionados (Robbins): a maioria dos treinamentos da-se no emprego (I) e a preferencia se deve a simplicidade e custo mais baixo (II). O segundo item efetivamente COMPLEMENTA/explica o primeiro."}, {"id": "1298788", "d": "psicologia", "a": ["Psicodinâmica do Trabalho", "Psicologia e Organizações", "Teorias da Personalidade", "Teorias da Personalidade - Outros Autores"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando  as  ideias  de  Robbins  (2005)  sobre \npersonalidade, julgue os itens a seguir. \nI  A  personalidade  reúne  alguns  agregados  que  são  maiores que a soma das partes da pessoa. II A personalidade pode ser compreendida como a soma \ntotal de maneiras como um indivíduo reage e interage \ncom os outros, sendo descrita, mais  frequentemente, \nem  termos  de  traços  mensurados  que  uma  pessoa \nexiba. \nIII  O  ambiente  ao  qual  somos  expostos  pode  interferir, \nmas  não  representar  um  papel  substancial  na \nmoldagem  da  personalidade,  ao  contrário  da \nhereditariedade.  \nIV  As  recentes  pesquisas  sobre  a  combinação  entre  os \nfenômenos  da  personalidade  em  relação  ao  trabalho \nargumentam  que  a  satisfação  é  mais  alta  e  a \nrotatividade é mais baixa quando a personalidade e a \nocupação estão em concordância.  \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item IV está certo.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens III e IV estão certos.", "D": "Apenas os itens I, II e III estão certos.", "E": "Apenas os itens I, II e IV estão certos."}, "g": "E", "j": "Itens I (agregados maiores que soma das partes), II (soma das reacoes/interacoes via tracos mensurados) e IV (concordancia personalidade-ocupacao melhora satisfacao e reduz rotatividade) corretos. Item III erra ao minimizar o papel do ambiente na moldagem da personalidade."}, {"id": "1298786", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "A partir dos pressupostos de Spector (2006) sobre avaliação \nde desempenho, é correto afirmar que", "alt": {"A": "muitas  decisões  que  afetam  os  funcionários  tenham \ncomo base, pelo menos em parte, o desempenho. As \norganizações  sempre  utilizam  o  desempenho  no \ntrabalho  como  fundamento  para  penalidades  e \nrecompensas.", "B": "as  penalidades  possam  incluir  advertências  ou \ndemissões,  sendo estas aplicadas exclusivamente aos \nque apresentem desempenho insatisfatório.", "C": "as  recompensas  possam  incluir  a  promoção  e  o \naumento  de  salário  e  muitas  empresas  utilizem \nsistemas de pagamento por mérito, associando‐os ao \ndesempenho no trabalho.", "D": "o  desempenho  no  trabalho,  mesmo  para  uma  única \ntarefa,  possa  ser  avaliado  juntamente  com  as \ndimensões de qualidade e de quantidade, ainda que a \ncomplexidade  do  desempenho  no  trabalho  não \nsignifique  que  diferentes  critérios  sejam  necessários \npara avaliá‐lo adequadamente.", "E": "a escolha do instrumento de avaliação de desempenho \nindependa  da  natureza  e  da  tipologia  do  trabalho \nrealizado pelos funcionários."}, "g": "C", "j": "Em Spector, recompensas vinculadas ao desempenho incluem promocao e aumento de salario, com adocao de sistemas de pagamento por merito. A generaliza indevidamente; B restringe demissoes; D nega complexidade do desempenho; E nega especificidade do instrumento."}, {"id": "1298785", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista", "Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "A  entrevista  psicológica  é  um  procedimento  de  avaliação \ncomplexo  e  pode  ser  realizada  com  diferentes  objetivos.  É \nextremamanete  utilizada  pelos  psicólogos  devido  às \ninúmeras vantagens na sua prática. Entretanto, há barreiras \nque,  em  determinadas  circunstâncias,  impedem  sua \nutilização. Sendo assim, assinale a alternativa que apresenta \numa  barreira  na  utilização  da  entrevista  psicológica  como \ntécnica de avaliação psicológica.", "alt": {"A": "Exige especialista em facilitação de grupos.", "B": "Para ser aplicada, precisa acompanhar outras técnicas \n(por exemplo, testes ou dinâmicas de grupo).", "C": "Exige  infraestrutura  e  condições  adequadas  para  sua \nrealização.", "D": "Por ser uma técnica psicométrica, seus resultados são \ngeralmente objetivos e costuma ser um procedimento \ndispendioso.", "E": "Em sua aplicação individual, exige um número mínimo \nde indivíduos a serem avaliados, não se recomendando \nrealizá‐la com menos de cinco avaliandos."}, "g": "C", "j": "A exigencia de infraestrutura e condicoes adequadas (sala, privacidade, tempo) e uma barreira pratica para a utilizacao da entrevista psicologica. Demais alternativas atribuem caracteristicas incorretas (necessidade de especialista em grupos, dependencia de outras tecnicas, natureza psicometrica, minimo de 5 avaliados)."}, {"id": "1298784", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "A  avaliação  psicológica  tem sido  percebida  como  uma  das \nmais  importantes  atividades  do  psicólogo  organizacional, \nconstituindo‐se  em  um  processo  de  se  conhecer  e \ndimensionar  fenômenos  psicológicos  por  meio  de \nprocedimentos  e  instrumentos  apropriados.  Considerando \nessa  informação,  assinale  a  alternativa  que  não  apresenta \nprocedimento ou técnica de avaliação psicológica.", "alt": {"A": "entrevista psicológica", "B": "testes  psicológicos  psicométricos  aprovados  pelo \nSATEPSI", "C": "testes psicológicos projetivos aprovados pelo SATEPSI", "D": "observação sistemática", "E": "exame grafotécnico"}, "g": "E", "j": "Exame grafotecnico NAO e procedimento de avaliacao psicologica - pertence a grafoscopia/pericia documental, area distinta da psicologia. Demais alternativas (entrevista, testes do Satepsi, observacao sistematica) sao tecnicas legitimas de AP."}, {"id": "1298772", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere às concepções de Bittencourt (2004) sobre \naprendizagem organizacional, julgue os itens a seguir. \nI  A aprendizagem organizacional traz uma proposta em \ntermos  de  mudança:  a  ênfase  no  processo  em \ndetrimento  do  produto,  ou  seja,  não  é  concebível  a \nideia  de  programas  ou  modelos  preconcebidos \ndesprovidos  de  uma  contextualização  ou  não \nrespeitando  a  individualidade  e  a  realidade  de  cada \norganização (especificidade). Nesse sentido, o que faz \na  diferença  em  um  processo  de  mudança  é  a  forma \ncom que essa mudança é concebida e implementada, \nficando em segundo plano o programa adotado. \nII  Tendo  como  foco  a  aprendizagem,  as  organizações \ndesenvolvem uma postura mais flexível, em que o erro \né  visto  como  uma  experiência  positiva  e  uma \noportunidade  na  construção  do  conhecimento, \nportanto  torna‐se  fundamental  que  as  organizações \naprendam  a  aprender,  ou  seja,  a  partir  de  uma \nmudança  de  mentalidade,  atitude  e  percepção, \naprendam  a  construir  novos  caminhos  com  base  na \naquisição,  disseminação  e  interpretação  de \ninformações.  \nIII  O conceito de organização de aprendizagem refere‐se \na  organizações  capacitadas  em  criar,  adquirir  e \ntransferir  conhecimentos  e  modificar  seus \ncomportamentos  para  refletir  esses  novos \nconhecimentos  e  insights.  O  conceito  abordado \ncentraliza‐se  na  visão  interna  da  organização \n(ambiente  interno).  Para  essa  análise,  prevalecem  as \npráticas organizacionais que são construídas conforme \na cultura e o clima organizacional. Assim, fatores como \nespírito  empreendedor,  orientação  para  mercado, \nestrutura  orgânica,  liderança,  estratégia \ndescentralizada,  entre  outros,  são  de  importância \nfundamental nessa configuração. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: enfase no processo sobre o produto e respeito a especificidade organizacional (I); erro como oportunidade de aprendizagem (II); organizacao de aprendizagem como criacao/aquisicao/transferencia de conhecimento via cultura e clima (III) - reproduzem fielmente Bittencourt."}, {"id": "1298770", "d": "psicologia", "a": ["Trabalho em Equipe", "Psicologia do Trabalho", "Psicologia e Organizações", "Grupos e Equipes"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando  os  pressupostos  relativos  ao  conceito  de \nequipes  de  trabalho  em  organizações  conforme  Bastos \n(2010), julgue os itens subsequentes. \nI  Equipes de trabalho constituem sistemas dinâmicos de \natos  protagonizados  por  conjuntos  de  pessoas  com \nhabilidades  complementares  cujas  ações  laborais  são \nnorteadas por metas de trabalho comuns. Assim, essas \npessoas são mutuamente responsáveis pelo alcance de \nseus  objetivos.  Nesse  sentido,  uma  equipe  é \ncaracterizada pela complementaridade das habilidades \nde  seus  membros,  pelas  experiências  de  trabalho \ncoletivas,  pela  responsabilidade  compartilhada  tanto \nna execução das tarefas quanto no alcance das metas.  II  As equipes de trabalho são concebidas com a finalidade \nde  promover  a  efetividade  da  organização.  A \nefetividade  da  organização,  por  sua  vez,  é \ncompreendida como um padrão externo de referência \nque  indica  quão  bem  a  organização  atende  às \ndemandas  dos  grupos  que  dela  participam.  Dessa \nforma, espera‐se que as equipes sejam efetivas no seu \ndesempenho a fim de contribuírem para a consecução \ndas metas da organização. \nIII  Em decorrência de sua enorme divulgação no mundo \norganizacional,  células  de  trabalho  das  mais  diversas \nnaturezas recebem imprecisamente a denominação de \n“equipe”,  sem  necessariamente  apresentarem \ncaracterísticas  que  permitam  sua  adequada \nidentificação.  Contudo,  é  mister  para  o  psicólogo \norganizacional  detalhar  peculiaridades  que \ncaracterizem  esse  campo  do  conhecimento,  com  o \nobjetivo  de  favorecer  a  compreensão  do \nfuncionamento  das  células  de  trabalho  denominadas \nde equipes e, assim, auxiliá‐las. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: definicao de equipe (complementaridade, metas comuns, responsabilidade compartilhada) em I; equipes para efetividade organizacional em II; necessidade de detalhar caracteristicas das equipes para nao confundir com 'celulas' genericas em III."}, {"id": "1298768", "d": "psicologia", "a": ["Análise do Trabalho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  dos  pressupostos  relativos  à  análise  do  trabalho  de \nacordo com Spector (2010), julgue os itens que se seguem. \nI  Análise  do  trabalho  é  um  método  utilizado  para \ndescrever tanto os diferentes tipos de trabalho quanto \nas  características  humanas  necessárias  para  o \ndesenvolvimento  das atividades. Não  há apenas  uma \núnica maneira de realizá‐la. Muitos métodos fornecem \ndiferentes  tipos de informações sobre as atividades e \nos requisitos para desenvolvê‐las. \nII  Na  análise  do  trabalho,  a  tarefa  é  o  componente \nprincipal  de  um  trabalho.  Para  que  cada  tarefa  seja \nconcluída com êxito, uma ou mais funções associadas \nprecisam  ser  realizadas.  Uma  função  é  uma  parte \ncompleta  do  trabalho,  que  envolve  algum  objetivo \nparticular.  Cada  função  pode  ser  subdividida  em \natividades.  Cada  atividade  pode  ser  subdividida  em \nvárias ações. \nIII  Uma  análise  do  trabalho  pode  conter  um  grande \nnúmero  de  informações  muito  específicas  sobre  a \nrealização  de  um  determinado  trabalho. Uma análise \ndo  trabalho  que  chega  ao  nível  das  ações  gera  um \nrelatório longo e detalhado. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Itens I (multiplicidade de metodos para descrever trabalho) e III (analise gera relatorio longo e detalhado) corretos. Item II INVERTE hierarquia em Spector - a FUNCAO e o componente principal, sendo a tarefa parte da funcao (nao o contrario)."}, {"id": "1298766", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Para  Zanelli  (2004),  o  trabalho  e  as  organizações  de  trabalho  estão  presentes  na  vida  de  todos.  O  cotidiano  de  cada  um  é \nenormemente afetado pelo funcionamento das organizações sociais. Acerca desse assunto, julgue os itens que se seguem.  \nI A psicologia, tradicionalmente, ocupou‐se em compreender e intervir sobre fenômenos e processos relativos ao mundo do \ntrabalho e das organizações. De forma crescentemente explícita, ela se dá conta de que não se pode reproduzir, no campo \ncientífico e profissional, a junção entre a esfera do trabalho e as demais esferas da vida pessoal do sujeito. A compreensão \ndo ser humano, portanto, depende da nítida separação das atividades de seu trabalho no interior das organizações (quando \nlidam com ocupações e profissões) e do que ocorre no vasto campo de ações do ser humano fora das organizações.  \nII Considerando se o conjunto de transformações que estão marcando o mundo do trabalho, a ideia de organização, sob o \nolhar da psicologia, não está, por decorrência, restrita à produção de bens no vasto mercado da competitividade globalizada \ne abrange também a prestação de serviços em sentido amplo, que vai, por exemplo, de hospitais a sindicatos.  \nIII  Uma  das  tarefas  centrais  da  psicologia  organizacional e  do trabalho  constitui‐se em analisar e  compreender a  vida  das \npessoas, dos grupos e das organizações, em  um mundo crescentemente  complexo e em  transformação, construindo, a \npartir daí, estratégias e procedimentos que possam promover, preservar e restabelecer a qualidade de vida e o bem‐estar \ndas pessoas. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens II (organizacao alem da producao, abrangendo servicos) e III (POT analisa pessoas/grupos/organizacoes para promover qualidade de vida) corretos. Item I defende SEPARACAO entre trabalho e demais esferas da vida - posicao contraria a Zanelli, que advoga integracao."}, {"id": "1298765", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo  Bittencourt  (2004),  as  competências  pessoais \nconduzem  à  necessidade  crescente  de  formar e  valorizar  o \nprofissional  para  oferecer  respostas  mais  rápidas  às \ndemandas do mercado e da organização, por meio de uma \npostura aberta à inovação, com base em um perfil criativo e \nflexível. Considerando essa informação, assinale a alternativa \nincorreta.", "alt": {"A": "Há uma constatação de que o treinamento tradicional \njá não responde mais às necessidades de formação das \npessoas, às expectativas das empresas em  termos de \nnovas  habilidades e atitudes mais  condizentes  com a \nrealidade  organizacional  e  às  exigências  de  um \nmercado mais competitivo. Nesse contexto, o conceito \nde competência adquire relevância.", "B": "As  organizações  contemporâneas  têm  sido  levadas  à \nmodernização  e(ou)  adequação  ao  novo  contexto \nprodutivo  por  diferentes  caminhos.  Seja  pela  via \ntecnológica,  seja  pela  via  gerencial,  múltiplos \nmecanismos e(ou) ferramentas são empregados, além \nde  um  esforço  voltado  à  eficácia  na  utilização  de \nrecursos  produtivos,  visando,  em  última  instância,  à \nmelhor adequação das pessoas ao trabalho. Por meio \nda construção de modelos que reconhecem a definição \nde  competências  como  possibilidade  concreta  de \nproporcionar  ganhos  organizacionais,  é  possível, \ndentro  dessa  lógica,  recompensar  o  esforço  dos \nindivíduos.", "C": "A  noção  de  competência  surgiu  como  parte  de  um \ndiscurso empresarial, com ausência da ideia de relação \nsocial, sendo uma espécie de contraponto ao conceito \nde  qualificação. Nessa mesma  perspectiva,  o modelo \nde  competências  se  encaixa  em  uma  dimensão  que \nexige  respostas  a  problemas  ligados  à  remuneração, \ntendo‐se  em  vista  sua  aproximação  à  gestão  da \nprodução.", "D": "A gestão de competências visa aproximar os objetivos \norganizacionais  e  os  pessoais  (profissionais).  Tal \ndiferenciação  facilita  a  compreensão  dos  principais \ntipos  de  competências:  o  organizacional  e  o  das \npessoas.  A  ênfase  para  esse  “ganho”  é  a  busca  do \nautodesenvolvimento  como  estratégia  de \naprendizagem contínua baseada em um perfil proativo. \nNesse  caso,  a  vantagem  não  é  monetária,  mas  não \ndeixa de envolver o reconhecimento.", "E": "Existe  atualmente  a  necessidade  de  reformulação  do \nconceito de qualificação. Via de regra, essa linha, mais \npróxima  da  formação  profissional,  argumenta  que  as \ncompetências  gerais  que  um  trabalhador  possui \n(vindas  de  sua  formação  anterior)  não  seriam \nsuficientes para o novo contexto produtivo em que se \nprocura  integrar  a  educação  com  o  trabalho.  Isso \nrecupera  a  ideia  de  que  seriam  necessárias  atitudes \ncríticas  e  reflexivas  do  sujeito,  uma  vez  que  sua \npreparação  deveria  estar  voltada  somente  para  uma \nocupação, e não para o trabalho como um todo."}, "g": "E", "j": "Questao pede INCORRETA. Em Bittencourt, a formacao por competencias NAO deve estar voltada SOMENTE para uma ocupacao, mas para o trabalho como um todo - a alternativa E inverte o argumento da autora. Demais alternativas (treinamento tradicional, modernizacao, noção de competencia, gestao) reproduzem corretamente."}, {"id": "1298764", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "A  partir  da  reflexão  de Tamayo  (2005) acerca  da  influência \ndos valores sobre o comportamento nas organizações, julgue \nos itens a seguir. \nI  Os  valores  funcionam  como guias  que  têm  influência \ncentral  sobre  as  percepções  e  os  julgamentos \nespecíficos,  tais  como  a  percepção  da  retaliação  no \ntrabalho. Os valores induzem valências sobre objetos e \nsituações.  Dessa  forma,  conduzem  a  percepção  a \nrespeito  da  importância  positiva  ou  negativa  de  um \nevento em uma situação específica. O pressuposto de \nque  os  valores  induzem  à  atribuição  valorativa  de \nimportância dada a um evento específico não exclui o \nreconhecimento  de  que  as  avaliações  subjetivas \ntambém possam ser influenciadas por outros fatores. \nII  Os  valores  sofrem  influência  de  concepções \nideológicas,  mas  são,  também,  fortemente \ninfluenciados pela cultura na qual as pessoas estejam \ninseridas. São crenças individuais sobre estados  finais \nde  existência  e  sobre  comportamentos  desejáveis  e \ntêm como característica o  fato de serem importantes \nno  nível  individual  e  societal.  Assim,  a  maneira  das \npessoas  reagirem  diante  de  resultados  e  eventos  da \nvida cotidiana é frequentemente influenciada por seus \nvalores.  No  contexto  organizacional,  os  valores  são \ncapazes  de  descrever  o  que  é  importante  para  os \nempregados  individualmente  e  para  a  organização \ncomo um todo. \nIII  Os  valores  influenciam  diferentes  tipos  de \ncomportamentos no trabalho e sinalizam situações de \nmudança  organizacional.  Os  valores  relacionam‐se \ndiretamente  aos  mais  diversos  aspectos  do \ncomportamento  humano,  podendo  influenciar,  de \nforma  mais  elaborada,  tanto  os  comportamentos  \npró‐sociais  quanto  a  percepção  das  ações  negativas \nvivenciadas  no  sistema  organizacional.  Dessa  forma, \nindivíduos  que  compartilhem  os  mesmos  valores \ntendem  a  apresentar  aspectos  similares  das  funções \ncognitivas,  pois  classificam  e  interpretam  situações  e \neventos  com  base  em  uma  mesma  estrutura  de \nvalores,  além  de  possuírem  um  sistema  comum  de \ncomunicação. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos em Tamayo: valores como guias com influencia sobre percepcoes (I); valores influenciados por ideologia e cultura, importantes no nivel individual e organizacional (II); valores moldam comportamentos pro-sociais e reacoes a eventos no trabalho (III)."}, {"id": "1298762", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Piaget", "Teorias da Personalidade"], "ano": "2018", "org": "CFP", "t": "", "e": "No que diz respeito ao desenvolvimento cognitivo do bebê, é \ncorreto afirmar que", "alt": {"A": "o bebê se encontre no estágio operacional de acordo \ncom a teoria de Piaget.", "B": "a permanência do objeto, marco do desenvolvimento \nconceitual, ocorra em  torno dos dois anos e meio de \nidade.", "C": "o bebê nasça com uma variedade de  reflexos, alguns \ndos  quais  apresentem  função  evolutiva  importante \npara desenvolvimentos sensório‐motores posteriores.", "D": "a resolução de problemas seja um processo cognitivo \ncomplexo  que  não  está  presente  nos  bebês  e  só  se \ndesenvolve a partir da primeira infância.", "E": "o  surgimento  dos  comportamentos  inequivocamente \nintencionais,  por  serem  mais  complexos,  ocorra  ao \nfinal do segundo ano de vida."}, "g": "C", "j": "Bebes nascem com variedade de reflexos (sucção, preensão, Moro, Babinski etc.) com funcao evolutiva e base para desenvolvimentos sensorio-motores posteriores. A erra o estagio (e sensorio-motor); B erra a idade da permanencia do objeto (em torno de 8-9 meses); D nega cognicao precoce; E erra a idade dos comportamentos intencionais."}, {"id": "1298761", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto à adolescência, assinale a alternativa incorreta.", "alt": {"A": "É uma fase evolutiva em que se identificam mudanças \nsignificativas  do  ponto  de  vista  biológico,  social  e \npsicológico.", "B": "Dura dos doze aos dezoito anos de idade em todas as \nculturas.", "C": "É uma fase essencial para o desenvolvimento humano, \ncuja  manifestação  sofre  influência  da  cultura,  mas \napresenta aspectos psicodinâmicos importantes.", "D": "As  transformações  corporais  características  da \nadolescência  exigem  uma  reformulação  do  esquema \ncorporal e a elaboração da perda do corpo infantil.", "E": "Segundo  a  abordagem  psicanalítica,  identifica‐se, \nnesse período, a fase genital."}, "g": "B", "j": "Questao pede INCORRETA. A duracao da adolescencia (12-18 anos) NAO e universal - varia conforme a cultura, contexto socioeconomico e marcadores biopsicossociais. Demais alternativas descrevem corretamente mudancas, papel da cultura, esquema corporal e fase genital psicanalitica."}, {"id": "1298760", "d": "psicologia", "a": ["Psicopatologia", "Outros Transtornos"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  relação  aos  transtornos  da  aprendizagem  específica, \njulgue os itens a seguir. \nI  Podem atingir as áreas de leitura, expressão escrita e \nmatemática. II  Constituem deficits globais de aprendizagem.\nIII  São  causados  por  fatores  de  ordem  emocional  e  por \nquestões de estrutura familiar.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas I correto - transtornos especificos de aprendizagem atingem leitura, expressao escrita e matematica. Item II e falso (sao ESPECIFICOS, nao globais); item III e falso (etiologia neurobiologica, nao apenas familiar/emocional)."}, {"id": "1298758", "d": "psicologia", "a": ["Orientação Profissional na Psicologia", "Psicologia da Educação", "Psicologia e Organizações"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  se  refere  ao  conceito  de  satisfação  profissional, \nassinale a alternativa correta.", "alt": {"A": "Estudos têm mostrado que a satisfação profissional se \nrelaciona mais com questões de rendimento ou ganhos \nfinanceiros gerados pelo trabalho.", "B": "A satisfação profissional é facilitada por haver sempre \numa correspondência entre as características do curso \ne as do mercado de trabalho.", "C": "O  maior  impacto  da  universidade  sobre  a  satisfação \nprofissional  encontra‐se  na  aprendizagem  percebida \npelo  estudante,  que  está  diretamente  relacionada  a \numa  possibilidade  de  alocação  no  mercado  de \ntrabalho.", "D": "A satisfação profissional é a expressão do autoconceito \ne  envolve  um  sentimento  de  identificação  e \najustamento à área de formação.", "E": "Na relação entre a satisfação profissional e a inserção \nno mercado de trabalho, os fatores internos dominam \na  preocupação  tanto  de  estudantes  ingressantes  nas \nuniversidades  quanto  daqueles  que  já  estejam  se \nformando."}, "g": "D", "j": "Satisfacao profissional e expressao do autoconceito, envolvendo identificacao e ajustamento a area de formacao. Demais alternativas reducionistas (ganhos financeiros, correspondencia automatica, alocacao no mercado, fatores internos exclusivos) ou afirmacoes categoricas indevidas."}, {"id": "1298750", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Com base na abordagem teórico‐crítica da psicologia escolar, \nassinale a alternativa correta.", "alt": {"A": "Sua base está no darwinismo social, concebendo dons \nou  aptidões  pessoais  como  formas  de  expressão  da \naprendizagem,  e  a  origem  dos  problemas  de \naprendizagem  estão  no  indivíduo  e  nas  questões  da \nhereditariedade.", "B": "A base ideológica pode ser identificada no movimento \nhigienista, dentro de uma abordagem de modificação \ndo  comportamento,  e  a  origem  dos  problemas  de \naprendizagem  pode  ser  identificada  no  ambiente \nfamiliar desajustado e nos fatores emocionais.", "C": "Toma  como  referência o  conjunto  de elaborações  do \nmaterialismo histórico dialético, vendo a escola como \num  instrumento  de  emancipação  e  a  aprendizagem \ncomo  um  processo  dinâmico  que  modifica  e \nmovimenta o processo de desenvolvimento.", "D": "Identifica‐se  como  abordagem  das  ideias  de  saúde \nescolar, em que ocorre uma visão organicista na qual a \norigem  dos  problemas  de  aprendizagem  se  encontra \nem disfunções neurológicas e orgânicas.", "E": "Encontra‐se em uma visão pós‐moderna, baseada nas \nvisões  de  inatismo  e  interacionismo,  em  que  os \nproblemas  de  aprendizagem  ocorrem  por  um \ndesenvolvimento  inadequado  do  indivíduo,  por \nausência  de  um  ambiente  facilitador  ou  por \nimaturidade."}, "g": "C", "j": "A abordagem teorico-critica da psicologia escolar fundamenta-se no materialismo historico dialetico, vendo a escola como instrumento de emancipacao e a aprendizagem como processo dinamico de transformacao do desenvolvimento. Demais alternativas descrevem abordagens organicistas, higienistas, inatistas ou darwinistas, contrarias a perspectiva critica."}, {"id": "1298743", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto a aplicações da psicologia escolar ao ensino superior, \né correto afirmar que", "alt": {"A": "o trabalho do psicólogo escolar seja mais restrito à área \nde  pesquisa  devido  às  peculiaridades  do  ensino \nsuperior em relação aos demais níveis educacionais.", "B": "se abram,  com a  democratização  do ensino  superior, \nnovas  possibilidades  de  atuação  relacionadas  à \npermanência  das  pessoas  historicamente  excluídas \ndesse espaço.", "C": "o espaço  da  avaliação  tenha encolhido  nesse  campo, \npois outras formas de conceber a qualidade do ensino \ntêm emergido.", "D": "a  expansão  do  ensino  superior  de  certa  forma  tenha \nprejudicado  a  atuação  dos  psicólogos  educacionais, \npois  os  investimentos  na  educação  básica,  campo \ntradicional de atuação, diminuíram.", "E": "o trabalho do psicólogo escolar no ensino superior deva \nser  focado  na  análise  institucional,  pouco  se \nrelacionando com as políticas públicas em vigência."}, "g": "B", "j": "A democratizacao do ensino superior abre novas possibilidades de atuacao do psicologo escolar, especialmente no apoio a permanencia de grupos historicamente excluidos. Demais alternativas restringem indevidamente o trabalho (so pesquisa, encolhimento da avaliacao, prejuizo pela expansao, foco apenas institucional)."}, {"id": "1298742", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  relação  aos  estágios  de  desenvolvimento,  assinale  a \nalternativa incorreta.", "alt": {"A": "Consistem  em  fases  cujas  mudanças  evolutivas  são \nessencialmente quantitativas.", "B": "São cumulativos, sendo que a resolução das situações \nno estágio posterior é superior à que o antecede.", "C": "São etapas invariáveis  (ordem constante) e universais \n(presente em todos).", "D": "A  universalidade  dos  estágios  implica  que  todas  as \npessoas  passem  pelos estágios,  não  necessariamente \nna mesma idade.", "E": "Representam saltos qualitativos no desenvolvimento."}, "g": "A", "j": "Questao pede INCORRETA. Estagios de desenvolvimento representam saltos QUALITATIVOS (nao quantitativos) - cada estagio reorganiza o pensamento de modo qualitativamente novo. Demais alternativas descrevem corretamente cumulatividade, invariabilidade, universalidade e mudanca qualitativa."}, {"id": "1298739", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Fracasso escolar é mais recorrente entre alunos negros \nMariana Mandelli \n    A  porcentagem  de  alunos  negros  com  mais  de  dois \nanos  de atraso escolar  chega a  14%  no  Brasil. Entre alunos \nbrancos,  a  taxa  cai  pela  metade:  7%.  Além  disso,  apenas \nmetade dos estudantes negros, ao atingir o 6.º ano do ensino \nfundamental, tem a idade correta para o ano em que estuda. \nOs  números  estão  na  Pesquisa  Nacional  por  Amostra  de \nDomicílios (Pnad) 2011.Internet: <www.todospelaeducacao.org.br>O texto acima traz algumas informações sobre a desigualdade \neducacional entre brancos e negros no Brasil. Considerando \nesses aspectos, assinale a alternativa incorreta.", "alt": {"A": "A  universalização  da  educação  é  um  reflexo  da \ndemocracia  racial  brasileira,  que  tem  feito  esforços \npara equiparar negros e brancos no acesso aos direitos.", "B": "Uma  psicologia  socialmente  comprometida  não  pode \nignorar aspectos relevantes da população que atende; \nno caso, efeitos do racismo no acesso à educação.", "C": "Os dados mostram que as políticas de universalização \nda educação implantadas a partir de meados da década \nde  1990  não  foram,  ainda,  suficientes  para  sanar  as \ndiferenças raciais no que tange à educação.", "D": "Ainda  é  necessário  identificar,  compreender  e \nreconhecer  os  processos  sociais  que  produzem  as \ndesigualdades raciais no campo da educação.", "E": "Reconhecer  o  racismo  como  fato  social  é  necessário \npara se pensar ações para combatê‐lo."}, "g": "A", "j": "Questao pede INCORRETA. A universalizacao da educacao NAO reflete 'democracia racial brasileira' - mito desmontado pelos dados de desigualdade racial. Demais alternativas reconhecem o compromisso social da psicologia, insuficiencia das politicas de universalizacao e necessidade de combater o racismo."}, {"id": "1298736", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca das teorias da cognição, julgue os itens seguintes. \nI  De acordo com as neurociências, a dotação genética e \na maturação cerebral  são enfatizadas no processo de \nmudança  cognitiva  e  o  biológico  simultaneamente \nenriquece e limita o desenvolvimento cognitivo.\nII  A  teoria  de  Piaget  afirma  que  o  funcionamento \ncognitivo  ocorre  por  meio  de  adaptações  biológicas \nque,  de  maneira  ativa,  selecionam  e  interpretam  a \ninformação  ambiental  por  meio  de  processos  de \nassimilação e acomodação.\nIII  Segundo  a  teoria  contextual  e  de  processamento  de \ninformações,  as  influências  sociais  na  cognição  são \ndecisivas e a orientação e o suporte dos adultos são o \nprincipal processo do desenvolvimento cognitivo, pois \na criança, no contexto social, é uma unidade de estudo \nirredutível.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: neurociencias (dotacao genetica e maturacao cerebral) em I; Piaget (assimilacao e acomodacao) em II; teoria contextual e de processamento (suporte social como motor do desenvolvimento) em III - tres perspectivas complementares sobre a cognicao."}, {"id": "1298733", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  à  presença  de  queixa  escolar  nos \nencaminhamentos  psicológicos,  assinale  a  alternativa \nincorreta.", "alt": {"A": "Pode  haver  uma  confusão  por  parte  do  professor \nquanto a problemas de aprendizagem e a problemas de \ncomportamento, como indisciplina.", "B": "Há  uma  tendência  a  encaminhar  preventivamente \ncrianças ingressantes no sistema escolar que, quando \nnão  cumprem  expectativas,  podem  ser  vistas  como \nproblemas em potencial.", "C": "Há  uma  questão  de  gênero  nos  encaminhamentos, \nsendo  que  os  meninos  são,  em  geral,  mais \nencaminhados que as meninas.", "D": "O que se constata, em geral, é a presença de problemas \nemocionais (devidos à desestruturação familiar que se \nobserva  a  partir  deste  século)  que  causam  as \ndificuldades escolares.", "E": "O  uso  exclusivo  de  um  modelo  psicológico  clínico  ao \natendimento  das  queixas  escolares  pode  ocultar  a \npresença de influências institucionais e sociais sobre a \nqueixa, isentando a escola."}, "g": "D", "j": "Questao pede INCORRETA. Atribuir as dificuldades escolares apenas a 'problemas emocionais por desestruturacao familiar deste seculo' simplifica e patologiza o aluno, ignorando determinantes institucionais e pedagogicos. Demais alternativas reconhecem corretamente confusao docente, encaminhamentos preventivos, genero e limites do modelo clinico."}, {"id": "1298730", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  avaliação  psicológica  na  educação,  assinale  a \nalternativa incorreta.", "alt": {"A": "No  contexto  educacional,  a  avaliação  tem  como \nfinalidade  básica a  coleta  de  informações  que  sirvam \npara a tomada de decisões educativas.", "B": "Durante  a  avaliação,  é  importante  contrastar  as \nhipóteses  geradas  no  processo  com  as  avaliações  de \noutras pessoas que se relacionem com a criança, como, \npor exemplo, pais e professores.", "C": "A  avalição  não  deve  focar  apenas  na  criança,  mas \ntambém no próprio processo de intervenção educativa \na que se proponha.", "D": "A  avaliação  pode  ser  realizada  em  diferentes \nmomentos  da  vida  escolar  da  criança  e  ter  diversas \nfinalidades.", "E": "Para  que  a  avaliação  psicológica  ocorra  de  forma \ncientífica,  deve‐se  sempre  fazer  uso  de  testes  que \nforneçam os parâmetros de desempenho."}, "g": "E", "j": "Questao pede INCORRETA. A AP educacional NAO depende SEMPRE de testes para ser cientifica - observacao, entrevista e analise documental tambem sao instrumentos validos. Demais alternativas descrevem corretamente coleta de informacoes, contrastacao de hipoteses, intervencao e momentos diversos."}, {"id": "1298726", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Paulo Freire distingue dois tipos de educação: a “bancária” e \na  libertadora.  Considerando  essa  informação,  assinale  a \nalternativa  que  não  apresenta  uma  descrição  da  educação \n“bancária”.", "alt": {"A": "Um  tipo  de  educação  focado  na  memorização \nmecânica de conteúdos por parte dos alunos, os quais \nsão narrados pelo professor.", "B": "O educador comunica aos alunos os conteúdos, isto é, \no  “saber”  é  uma  doação  feita  pelo  professor  a  seus \nalunos.", "C": "O educador identifica sua ação com a dos educandos, \ntrabalhando no sentido da humanização de ambos.", "D": "O  educador  é  quem  educa;  os  educandos  são \neducados.", "E": "Os seres humanos são vistos como seres da adaptação, \ndo ajustamento."}, "g": "C", "j": "O educador que identifica sua acao com a dos educandos visando a humanizacao de ambos descreve a educacao LIBERTADORA (nao a bancaria). Demais alternativas (memorizacao mecanica, doacao do saber, dicotomia educador-educando, ajustamento) caracterizam a educacao bancaria em Paulo Freire."}, {"id": "1298725", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca de bullying, assinale a alternativa incorreta.", "alt": {"A": "O  bullying  tem  como  características  a  existência  de \nações  agressivas,  intencionais,  repetitivas  e  sem \nmotivação  aparente,  que  causam  dor,  angústia  ou \nintimidação nas vítimas.", "B": "A  presença  de  um  desequilíbrio  entre  o  agressor  e  a \nvítima, que não consegue se defender, é o que propicia \na ocorrência do bullying.", "C": "Entre  as  caracterizações  do  bullying,  podem  estar \npresentes  insultos,  difamação,  exclusão,  isolamento, \napelidos, humilhações e até agressões físicas.", "D": "As  vítimas  de  bullying  sempre  apresentam \nconsequências  psicológicas  e  emocionais,  como \nquadros  depressivos  e  de  ansiedade  e  problemas  de \naprendizagem, que são irreversíveis.", "E": "O  bullying  nasce  de  uma  recusa  à  diferença,  da \nintolerância e do desrespeito ao outro."}, "g": "D", "j": "Questao pede INCORRETA. As consequencias do bullying podem ser graves, mas NAO sao SEMPRE irreversiveis - reversibilidade depende de intervencao oportuna e suporte. Demais alternativas descrevem corretamente caracteristicas, desequilibrio de poder, manifestacoes e raizes do bullying."}, {"id": "1298373", "d": "psicologia", "a": ["Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito da psicologia da saúde e da psicologia hospitalar, \njulgue os itens a seguir. \nI A atuação do psicólogo da saúde é realizada no âmbito \nda atenção primária, secundária e terciária. \nII Em ambas as especialidades, a prática do psicólogo é \ninterdisciplinar e utiliza distintas teorias psicológicas. \nIII  A  atuação  do  psicólogo  hospitalar  é  realizada  no \nâmbito da atenção secundária e terciária. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: psicologo da saude atua em atencao primaria/secundaria/terciaria (I); ambas as especialidades exigem trabalho interdisciplinar e multiteorico (II); psicologo hospitalar atua majoritariamente em atencao secundaria/terciaria (III)."}, {"id": "1298372", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Saúde da Família"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando  a  formação  indicada  para  os  psicólogos  que \ndesejem trabalhar no âmbito da saúde, assinale a alternativa \nincorreta.", "alt": {"A": "A  formação  do  psicólogo  da  saúde  deve  contemplar \nconhecimentos  sobre  bases  biológicas,  sociais  e \npsicológicas da saúde e da doença.", "B": "É  importante  que  o  psicólogo  da  saúde  tenha \nconhecimentos  sobre  avaliação,  assessoramento  e \nintervenção  em  saúde,  políticas  e  organização  em \nsaúde e colaboração interdisciplinar.", "C": "O  psicólogo  da  saúde  tem  sua  função  centrada  nos \nâmbitos secundário e terciário de atenção à saúde.", "D": "O  psicólogo  da  saúde  deve  dominar  temas \nprofissionais,  éticos  e  legais  e  conhecimentos  de \nmetodologia e pesquisa em saúde.", "E": "Para  o  psicólogo  da  saúde  que  atue  especificamente \nem hospitais, é indispensável um bom treinamento em \ntrês áreas básicas: clínica; pesquisa; e programação."}, "g": "C", "j": "Questao pede INCORRETA. O psicologo da saude NAO atua apenas em secundario/terciario - sua funcao abrange tambem a atencao primaria (promocao e prevencao). Demais alternativas reproduzem corretamente componentes da formacao (bases biopsicossociais, etica, pesquisa, atuacao hospitalar)."}, {"id": "1298371", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Um dos desafios da psicologia da saúde é ajudar na reforma \ndo  atendimento  de  saúde.  Acerca  desse  desafio,  assinale  a \nalternativa incorreta.", "alt": {"A": "O  importante  papel  dos  psicólogos  em  melhorar  a \nsaúde  física,  melhorando  os  resultados  de \ntratamentos,  ainda  não  pode  ser  considerado  como \nestabelecido.  Isso  levou  à  redução  do  número  de \npsicólogos que trabalham em cenários de atendimento \ngeral de saúde.", "B": "De forma geral, a política de saúde coloca maior ênfase \nem  prevenir  outros  episódios  de  uma  doença  em \npessoas que já estão doentes  (prevenção secundária) \nque em prevenir o começo de uma doença (prevenção \nprimária).", "C": "A  ênfase  das  políticas  de  saúde  na  prevenção \nsecundária é compreensível, pois baseia‐se no modelo \nbiomédico  tradicional. A  prevenção primária,  por  sua \nvez,  baseia‐se  em  um  modelo  comportamental  ao \ninvés de um modelo de doença, que tem sido uma das \nênfases da psicologia da saúde.", "D": "Os  programas  de  prevenção  secundária \nfrequentemente  são  caros  e  podem  gerar  poucos \nbenefícios  mensuráveis.  Em  comparação,  muitos \nesforços  de  prevenção  primária  e  intervenções \npsicossociais economizam dinheiro, produzindo iguais \nou maiores benefícios para a saúde.", "E": "O  modelo  de  atendimento  interdisciplinar  tem  sido \nadotado  nas  reformas  dos  atendimentos  em  saúde, \nrefletindo a crescente aceitação da psicologia da saúde."}, "g": "A", "j": "Questao pede INCORRETA. O papel dos psicologos em melhorar a saude fisica esta firmemente estabelecido, com numero CRESCENTE (nao reduzido) de psicologos nos servicos de saude. Demais alternativas reproduzem o desafio da reforma do atendimento e o equilibrio entre prevencao primaria/secundaria."}, {"id": "1298369", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Historicamente,  várias  medidas  de  saúde  mostraram \ndiferenças  substanciais  entre  vários  grupos  étnicos  e \nsociodemográficos, assim como entre os gêneros, fato que se \nconstitui como um desafio para a atuação do psicólogo em \nsaúde.  No  que  diz  respeito  a  esse  assunto,  assinale  a \nalternativa incorreta.", "alt": {"A": "As  razões  para  as  discrepâncias  relacionadas  à  saúde \nsão complexas, mas podem incluir o acesso desigual ao \natendimento  de  saúde,  a  suscetibilidade  genética  a \ndoenças específicas e as diferenças de estilo de vida.", "B": "Os  psicólogos  da  saúde,  por  algum  tempo,  não \nconseguiram  identificar  as  razões  para  as \ndiscrepâncias,  pois  os  conhecimentos  sobre  \nsaúde  e  doença  eram  obtidos  de  pesquisas \ndesproporcionalmente  concentradas  em  sujeitos \njovens,  relativamente  saudáveis,  brancos  e  do  sexo \nmasculino, provocando uma perspectiva limitada sobre \nos fatores que influenciam a saúde e a doença.", "C": "Os psicólogos da saúde começaram a ampliar o âmbito \nde  suas  pesquisas  para  incluir  maior  variedade  de \nparticipantes  e  concentrar‐se  especificamente  em \ngrupos  subestudados,  tendo  como  desafio  reduzir  as \ndiscrepâncias  de  saúde  e  aumentar  o  conhecimento \nacerca desses grupos.", "D": "As pesquisas em psicologia da saúde já verificaram, por \nexemplo,  que  as  mulheres  e  os  homens  apresentam \ncaracterísticas e vulnerabilidades psicológicas, sociais e \nbiológicas  bastante  diferentes,  o  que  faz,  portanto, \ncom que apresentem diferenças em sua suscetibilidade \na várias doenças e em suas reações de enfrentamento \nao estresse.", "E": "Um importante fator de influência nas discrepâncias de \nsaúde é a educação. Independentemente da etnia, as \npessoas  que  alcançam  níveis  mais  altos  de  educação \nvivem menos tempo e têm uma saúde geral pior que as \nque têm grau de educação menor."}, "g": "E", "j": "Questao pede INCORRETA. Maior nivel educacional esta associado a VIVER MAIS TEMPO e ter melhor saude geral (nao o contrario). A alternativa E inverte a relacao. Demais alternativas descrevem corretamente discrepancias por etnia/genero/socioeconomico em psicologia da saude."}, {"id": "1298368", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Envelhecimento da população mundial preocupa pesquisadores \nNúmero  de  pessoas  com  mais  de  sessenta  anos  de  idade \ndeve triplicar até 2050 \nEstimativas  da  ONU  indicam  menor  crescimento  da \npopulação de 7 bilhões \n    O  mundo  está  envelhecendo  rapidamente.  Entre  as \nprincipais  preocupações  dos  estudiosos  de  demografia  ao \ncomentar as estimativas da ONU de que o mundo atingirá a \nmarca de 7 bilhões de pessoas está não o aumento do total \nde pessoas no planeta, mas a  tendência de crescimento da \npopulação com mais de sessenta anos de idade, que triplicará \nnos próximos quarenta anos.Internet: <http://g1.globo.com> (com adaptações).  Em  relação  ao  texto  e  às  implicações  para  a  atuação  em \npsicologia da saúde, assinale a alternativa incorreta.", "alt": {"A": "O  envelhecimento  rápido  da  população  chama  a \natenção para um desafio crucial da psicologia da saúde: \ndesenvolver  intervenções  eficazes  que  proporcionem \naos  adultos mais  velhos  a manutenção  do  nível mais \nalto possível de  funcionamento ou  sua melhoria pelo \nmaior número de anos possível.", "B": "A  vida  saudável  é  uma  combinação  da  expectativa \nmédia  de  vida  e  da  qualidade  de  vida.  O  desafio  da \npsicologia da saúde é aumentar o número de anos de \nvida  ajustados  por  qualidade  (“anos  bons”), \njuntamente com uma compreensão da morbidade.", "C": "Torna‐se necessário entender que a discrepância entre \nexpectativa de vida e os “anos bons” é menor quando \nse comparam vários grupos socioeconômicos.", "D": "Um status socioeconômico mais baixo está associado à \nexpectativa média de vida mais curta e a menos “anos \nbons”.", "E": "A separação entre a expectativa de vida em anos com \nboa saúde e em anos vividos com incapacidade amplia, \nem vez de reduzir, a diferença do status de saúde entre \nas populações mais ricas e as mais pobres."}, "g": "C", "j": "Questao pede INCORRETA. A discrepancia entre expectativa de vida e 'anos bons' e MAIOR (nao menor) ao se comparar grupos socioeconomicos - quanto pior o status, maior a diferenca. Alternativa C inverte. Demais alternativas (envelhecimento, anos bons, status socioeconomico, ampliacao da diferenca) sao corretas."}, {"id": "1298367", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Entre as lições da psicologia da saúde citadas por Straub (2014), estão a lição de que estilos de vida insalubres são mais difíceis  \nde  mudar  que  de  prevenir  e  a  lição  de  que  se  deve  considerar  o  papel  do  manejo  do  estresse  para  o  \nbem‐estar físico, psicológico e emocional. Acerca dessas duas lições, é correto afirmar que", "alt": {"A": "prevenir  o  desenvolvimento  de  maus  hábitos  de  saúde  continue  sendo  a  prioridade  da  psicologia  da  saúde,  com \nintervenções mais eficientes para atingir o maior número de pessoas no local de trabalho, em escolas, universidades e na \ncomunidade.", "B": "o  uso  de  programas  de  imunização  comportamental,  como  os  voltados  para  adolescentes  mais  propensos  a  ter \ncomportamentos de riscos à saúde, deva decrescer.", "C": "o objetivo do manejo do estresse seja eliminar o estresse totalmente, enfrentando estressores de forma adaptativa.", "D": "muitas estratégias tenham se mostrado eficazes no manejo do estresse, como, por exemplo, seguir uma dieta equilibrada, \npraticar exercícios físicos, compartilhar sentimentos incômodos e aprender a relaxar, porém a intervenção em pensamentos \nestressantes, tentando transformá‐los em elementos que combatam o estresse, é uma estratégia que não tem se mostrado \nbenéfica.", "E": "cada um dos eventos da vida que seja avaliado pelo indivíduo como estressor não possa ser avaliado como um desafio ou \numa oportunidade."}, "g": "A", "j": "Em Straub, prevenir maus habitos continua sendo prioridade da psicologia da saude, com intervencoes em locais de trabalho, escolas, universidades e comunidade. Demais alternativas distorcem objetivos do manejo do estresse, propoem reducao de programas preventivos ou negam beneficios de estrategias eficazes."}, {"id": "1298364", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo  Straub  (2014),  o  objetivo  geral  da  psicologia  da \nsaúde  é  o  aperfeiçoamento  da  saúde  e  a  prevenção  e  o \ntratamento das doenças. Para alcançar esse objetivo geral, a \npsicologia da saúde tem quatro objetivos específicos, sendo \neles:  identificar  os  fatores  psicológicos,  comportamentais e \nsociais  da  doença;  promover  e  manter  a  saúde;  prevenir  e \ntratar doenças; e melhorar o sistema e as políticas de saúde. \nConsiderando‐se  o  que  autor  explica  acerca  do \ndesenvolvimento  desses  objetivos  específicos,  é  correto \nafirmar que", "alt": {"A": "inúmeros  estudos  sugiram  que  fatores  psicossociais \ntambém  possam  afetar  o  desenvolvimento  e  a \nprogressão  de  doenças  que  variem  de  um  simples \nresfriado  a  condições  crônicas.  Um  tema  recorrente \nsobre esses fatores é a relação entre estresse e saúde, \nmas  ainda  não  se  comprovou,  em  pesquisa,  a \nexistência de influência entre eles.", "B": "a promoção e a manutenção da saúde sejam os pilares \nda pesquisa e da intervenção em psicologia da saúde. \nOs  esforços  dos  psicólogos  para  mudar \ncomportamentos  relacionados  ao  estilo  de  vida \nconcentram‐se  principalmente  em  abordagens \ncomportamentais  e  cognitivas,  porém, \nnumericamente, essas medidas não  têm se mostrado \neficazes.", "C": "as intervenções psicológicas no âmbito de tratamento \nda doença abranjam  todos os domínios da saúde. No \ndomínio  biológico,  o  tratamento  é  projetado  para \nmudar  respostas  fisiológicas  envolvidas  na  doença, \ncomo,  por  exemplo,  o  relaxamento  para  reduzir  a \nhipertensão.  No  domínio  psicológico,  são  aplicadas \nintervenções cognitivas e comportamentais, como, por \nexemplo,  técnicas  para  diminuição  da  ansiedade.  No \ndomínio  social,  podem  ser  realizados,  por  exemplo, \ngrupos de apoio e orientações a familiares.", "D": "uma  das  mensagens  fundamentais  da  psicologia  da \nsaúde  com  relação  a  melhorar  o  atendimento  e  o \nsistema  em  saúde  seja  a  de  que  a  prevenção,  a \npromoção ou a manutenção da saúde não devem ser \ntão importantes para o sistema de saúde como o é o \ntratamento de doenças.", "E": "o  atendimento  em  saúde  deva  reconhecer  que  os \npacientes  têm  responsabilidade  central  pelo  próprio \nbem‐estar, além de valorizar os papéis da família, dos \namigos  e  da  comunidade.  Com  relação  a  esta  última \nquestão, cabe um alerta: o atendimento à saúde não \npode dar importância a lugares que não sejam parte da \nrede  de  serviços  do  sistema  de  saúde,  como,  por \nexemplo, escolas, igrejas e locais de trabalho."}, "g": "C", "j": "Intervencoes psicologicas em tratamento abrangem todos os dominios: biologico (relaxamento p/ hipertensao), psicologico (TCC p/ ansiedade) e social (grupos de apoio, orientacao familiar). Demais alternativas negam evidencias do estresse, restringem eficacia, invertem importancia da prevencao ou excluem espacos comunitarios."}, {"id": "1298362", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "O  importante  papel  dos  psicólogos  na  saúde  física  para \nmelhorar  os  resultados  dos  tratamentos  médicos  está \nestabelecido  de  maneira  firme.  Quanto  à  participação  da \npsicologia  nos  cenários  de atendimento à  saúde, assinale a \nalternativa incorreta.", "alt": {"A": "Um  número  crescente  de  programas  de  residência \nmédica encoraja o uso de atendimento cooperativo, no \nqual  médicos,  psicólogos  e  outros  profissionais  de \nsaúde juntam suas forças para melhorar o atendimento \nao paciente.", "B": "Novas diretrizes nesse campo de atuação orientam que \nos psicólogos devem conhecer, cada vez mais, sobre o \natendimento primário, de maneira que compreendam \no  trabalho  do  médico.  Por  outro  lado,  ainda  não  é \nexigido  que  os  médicos  conheçam  as  ciências \nepidemiológicas  e  sociocomportamentais  e  sejam \ncapazes de aplicar esse conhecimento no atendimento \nao paciente.", "C": "A mensagem  fundamental da psicologia da saúde é a \nde  que  o  atendimento  não  é  atingido  por  meio  de \nresponsabilidades  separadas  de  pacientes  e \nprofissionais  de  saúde,  mas  por  sua  interação \nharmoniosa.", "D": "Na  era  de  participação  mútua  entre  pacientes  e \nprofissionais, cada um é encorajado a adotar um papel \nmais ativo em relação à própria saúde.", "E": "A psicologia da  saúde informa  sobre o papel de cada \npessoa envolvida nos atendimentos em saúde por meio \nde  achados  de  pesquisas  sobre  fatores  socioculturais \nenvolvidos  no  comportamento  em  relação  à  doença, \nnos relacionamentos entre pacientes e profissionais e \nnos estilos de enfrentamento do tratamento de saúde \ne da hospitalização."}, "g": "B", "j": "Questao pede INCORRETA. As diretrizes contemporaneas exigem que medicos TAMBEM conhecam ciencias epidemiologicas e sociocomportamentais e as apliquem no atendimento. Demais alternativas (cooperacao multiprofissional, interacao paciente-profissional, participacao mutua, achados em psicologia da saude) sao corretas."}, {"id": "1298361", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "As intervenções psicológicas são cada vez mais usadas para preparar os pacientes para hospitalizações e procedimentos médicos \nestressantes. As intervenções mais eficazes são aquelas que aumentam a sensação de controle dos pacientes sobre o tratamento \ne a recuperação. Com relação a esse tema, é correto afirmar que", "alt": {"A": "a maioria das intervenções possa ser categorizada em relação a três tipos de controle: o controle informacional; o controle \ncognitivo; e o controle comportamental.", "B": "o  controle  informacional  seja  composto  por  intervenções  concentradas  nos  procedimentos  e  nas  sensações  físicas \nparticulares  que  acompanhem  o  tratamento.  Quando  os  procedimentos  são  esperados  e  previsíveis,  muitos  pacientes \ndesenvolvem menor confiança e ficam menos relaxados", "C": "as intervenções que se atenham ao controle cognitivo auxiliem os pacientes a se perceberem como  um corpo imóvel sendo \nmanipulado de forma passiva.", "D": "o controle comportamental represente intervenções que ensinem técnicas para controlar a dor e seja bastante utilizado, \nainda que não tenha efeitos quanto ao tempo de recuperação durante e após o procedimento médico.", "E": "as intervenções que visem ao controle comportamental  sejam mais benéficas para procedimentos médicos nos quais a \nparticipação do paciente não possa auxiliar o progresso."}, "g": "A", "j": "As intervencoes pre-hospitalizacao se organizam em tres tipos de controle: informacional (sobre procedimentos), cognitivo (mudanca de avaliacao) e comportamental (tecnicas como relaxamento). B inverte previsibilidade/confianca; C reduz cognitivo a corpo manipulado; D nega efeito sobre recuperacao; E inverte beneficio."}, {"id": "1298360", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  aos  aspectos  psicológicos  de  uma  hospitalização, \nassinale a alternativa correta.", "alt": {"A": "Ao  entrarem  no  hospital,  os  pacientes  sentem‐se \nabsorvidos por uma instituição que assume o controle \nde praticamente todos os aspectos de suas vidas. Além \nda perda de controle, os pacientes também sofrem por \nnão  serem  tratados  como  pessoa,  resultando  na \ndespersonalização.", "B": "A  visão  unidimensional  e  despersonalizada  dos \npacientes por parte da equipe de saúde é causada pela \nnecessidade de eficiência e de reduzir o estresse diário \ndo ambiente hospitalar.", "C": "Os  pacientes  hospitalizados  apresentam  inúmeros \nsintomas  psicológicos  adversos,  particularmente  se \nmanifestarem  alguma  tentativa  autodestrutiva  de \natribuir  culpa  por  sua  doença.  Quanto  mais  os \npacientes se preocupam em atribuir culpa a si mesmos \nou a outras pessoas, pior é sua adaptação emocional.", "D": "O quanto uma pessoa se adapta a uma hospitalização \ndepende  de  o  enfrentamento  estar  focalizado  no \nproblema ou na emoção.", "E": "Na maioria das situações, o enfrentamento mais ativo \nà condição de hospitalização (a coleta de informações, \na  busca  de  apoio  social  e  a  reestruturação  cognitiva, \npor exemplo) está  relacionado  com a  pior adaptação \npsicológica em doentes terminais adultos."}, "g": "A", "j": "Na hospitalizacao, o paciente sente-se absorvido pela instituicao que assume controle, perdendo autonomia e sendo tratado como nao-pessoa (despersonalizacao). B justifica indevidamente; C inverte relacao culpa-adaptacao; D simplifica o enfrentamento; E inverte efeito do enfrentamento ativo."}, {"id": "1298359", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Cuidados Paliativos na Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "O relacionamento entre o profissional da saúde e o paciente \né  a  base  de  todo  tratamento  médico.  Um  dos  elementos \ncentrais desse relacionamento é a comunicação. No que diz \nrespeito a esse tema, julgue os itens subsequentes.  \nI  A  comunicação  eficaz  garante  que  os  sintomas  e  as \npreocupações  dos  pacientes  sejam  compreendidos \npelos  profissionais  de  saúde  e  que  as  informações  e \ninstruções do  tratamento  sejam  recebidas e  seguidas \nde forma precisa.\nII A  qualidade  do  relacionamento  entre  paciente  e \nprofissional com frequência tem impacto direto sobre \na saúde.\nIII  Existem  técnicas  e  treinamentos  que  podem  ser \nensinados  em  intervenções  para  melhorar  a \ncomunicação  na  relação  profissional  de  \nsaúde‐paciente.  Essas  técnicas  são  aplicadas  nas \nequipes de saúde, única parte da  relação que precisa \nser mais desenvolvida na comunicação. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Itens I (comunicacao eficaz para compreensao e adesao) e II (qualidade do relacionamento impacta saude) corretos. Item III erra ao afirmar que SOMENTE a equipe precisa ser desenvolvida - ambos paciente e profissional sao foco de intervencoes para melhorar a comunicacao."}, {"id": "1298358", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  às  características  dos  pacientes  ao  procurar \ntratamento,  Straub  (2014)  afirma  que  categoriza  a  maioria \ndas  pessoas  na  classificação  de  “uso  normal”, mas  existem \nduas  categorias  amplas  para  os  demais  pacientes:  os \nprocrastinadores e os que usam exageradamente o sistema. \nOs psicólogos da saúde têm investigado as razões para essas \nduas  formas extremas  de  comportamento. Em  uma análise \ndos  fatores  envolvidos  no  comportamento  de  demora  na \nbusca  por  tratamento,  descreve  cinco estágios  no  processo \nde tomada de decisão de procurar cuidado médico, que são:", "alt": {"A": "demora na percepção; demora na aceitação da doença; \ndemora  comportamental;  demora  na  marcação  de \nconsulta; e demora no tratamento.", "B": "demora  na  avaliação;  demora  na  anuência;  demora \ncomportamental; demora na marcação de consulta; e \ndemora no tratamento.", "C": "demora na avaliação; demora na aceitação da doença; \ndemora depressiva; demora na marcação de consulta; \ne demora no tratamento.", "D": "demora na avaliação; demora na aceitação da doença; \ndemora  comportamental;  demora  na  marcação  de \nconsulta; e demora no tratamento.", "E": "demora na avaliação; demora na aceitação da doença; \ndemora  comportamental;  demora  na  marcação  de \nconsulta; e demora na cura."}, "g": "D", "j": "Em Straub, os cinco estagios da demora na busca por tratamento sao: demora na avaliacao, na aceitacao da doenca, comportamental, na marcacao de consulta e no tratamento. Demais alternativas substituem termos (percepcao, anuencia, depressiva, cura) que nao integram o modelo."}, {"id": "1298357", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2018", "org": "CFP", "t": "", "e": "O fato de reconhecer um sintoma ou um grupo de sintomas \nnão  leva  automaticamente  ao  cuidado  da  saúde.  Vários \nfatores  socioculturais  influenciam  na  determinação  dos \ncomportamentos  do  “papel  de  doente”.  Acerca  desses \nfatores, é correto afirmar que", "alt": {"A": "os muito jovens e os idosos, em geral, usem o serviço \nde saúde com mais  frequência que os adolescentes e \nos adultos jovens.", "B": "o status socioeconômico preveja o relato de sintomas \ne  a  procura  por  atendimento  de  saúde.  Pessoas  de \nrenda  alta  geralmente  relatam  mais  sintomas  e  pior \nestado de saúde que pessoas de baixa renda.", "C": "os  fatores  culturais  e  a  etnia  não  influenciem  na \nmaneira como a pessoa responde ao sintoma físico.", "D": "muitas pessoas sejam motivadas a determinar a causa \nda  enfermidade.  Geralmente,  tais  atribuições  são \nprecisas e influenciam na busca pelo tratamento.", "E": "geralmente  se  observe, ao  construir  internamente as \ncausas  de  uma  doença,  o  movimento  de  busca  de \ntratamento se as causas forem atribuídas às emoções. \nCaso a doença seja atribuída a infecções, por exemplo, \nprovavelmente a pessoa não procurará tratamento."}, "g": "A", "j": "Muito jovens (criancas) e idosos sao os grupos etarios que mais utilizam servicos de saude - dado epidemiologico classico. B inverte relacao renda/relato; C nega influencia cultural/etnica; D supervaloriza precisao atributiva; E inverte logica das atribuicoes causais."}, {"id": "1298356", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Cuidados Paliativos na Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "Pesquisadores  estudaram  vários  componentes  do  modo \ncomo uma doença pode ser representada pelo paciente. Cada \ncomponente  pode  afetar  a  motivação  do  indivíduo  para \nbuscar  cuidado  médico.  A  respeito  desses  componentes, \nassinale a alternativa incorreta.", "alt": {"A": "Um  dos  componentes  é  a  identidade  da  doença, \nincluindo seu rótulo e os sintomas. Alguém que tenha \nsintomas  irá  buscar  um  rótulo  para  eles.  Da  mesma \nforma  que  alguém  que  tenha  sido  diagnosticado  irá \nbuscar sintomas consistentes daquele rótulo.", "B": "O grau  de  controle  que  o  paciente avalia  ter  sobre a \ndoença é outro componente. Pessoas que consideram \nsua  doença  ou  problema  de  saúde  como  incurável \ntendem  a  procurar  mais  as  consultas  e  a  seguir  o \ntratamento.", "C": "A maneira como o paciente interpreta as causas de sua \nenfermidade  é  outro  componente  que  influencia  na \nrepresentação  da  doença.  A  reação  do  paciente  se \ndiferencia  de  acordo  com  a  gravidade  que  ele  avalie \nque causou seus sintomas.", "D": "O  curso  de  desenvolvimento  da  doença  é  um \ncomponente  que  atua  sobre  o  comportamento  do \npaciente. Os pacientes que acreditam que sua doença \né  aguda  e  curta  abandonam  o  tratamento  antes  que \naqueles que acreditam que ela é crônica.", "E": "As  consequências  percebidas  da  doença  também \ninfluenciam  em  sua  representação.  Os  pacientes \nignoram  mais  os  sintomas  que  perturbam  em  nível \nmínimo sua vida cotidiana."}, "g": "B", "j": "Questao pede INCORRETA. Pacientes que consideram a doenca incuravel tendem a ABANDONAR o tratamento e nao a procurar mais consultas - a alternativa B inverte a relacao entre crenca de controle e adesao. Demais alternativas descrevem corretamente identidade, causas, curso e consequencias da doenca."}, {"id": "1298355", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo Straub (2014), um dos aspectos que os psicólogos da \nsaúde usam para descrever a maneira como as pessoas lidam \ncom  sintomas  médicos  é  o  comportamento  em  relação  à \ndoença. Acerca desse aspecto, assinale a alternativa correta.", "alt": {"A": "O  comportamento  em  relação  à  doença  refere‐se  às \nmaneiras  como  as  pessoas  respondem  aos  sintomas \nfísicos.", "B": "Um  dos  fatores  psicológicos  que  influenciam  a \nconsciência das pessoas em relação a sintomas físicos \né  o  foco  de  atenção.  As  pessoas  tendem  a  ser  mais \nconscientes  de  sensações  físicas  quando  estão \nprofundamente envolvidas em uma tarefa.", "C": "O  fato  de  uma  pessoa  ser  normalmente  otimista  ou \npessimista  também  influencia  o  relato  dos  sintomas. \nPessoas  que  têm  perspectiva  otimista  de  vida,  em \ngeral, relatam menos sintomas que pessoas que veem \no mundo de forma negativa.", "D": "A maneira como os indivíduos reagem aos sintomas é \ninfluenciada por suas percepções de saúde e doença, \nchamadas de representações da doença.", "E": "A maneira como as pessoas interpretam os sintomas é \ninfluenciada  por  fatores  socioculturais,  como \nexperiência prévia e expectativas."}, "g": "A", "j": "Comportamento em relacao a doenca em Straub refere-se as maneiras como as pessoas respondem aos sintomas fisicos. B inverte foco de atencao (mais conscientes quando NAO envolvidos em tarefas); C, D, E descrevem aspectos correlatos mas nao o conceito nuclear."}, {"id": "1298354", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Doenças Crônico-Degenerativas", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação à atuação  do psicólogo da  saúde em casos de \ndoenças crônicas e fatais, julgue as os itens que se seguem. \nI  Em  casos  de  doenças  cardiovasculares,  os  psicólogos \nda  saúde  proporcionaram  uma  explicação \nbiopsicossocial para a maneira como a hostilidade e a \nraiva  contribuem  para essas enfermidades. Espera‐se \nque  estados  emocionais‐cognitivos  hostis  levem  a \ncomportamentos  antagônicos  e  agressivos  que \nproduzem  conflitos  interpessoais,  que,  por  sua  vez, \ngeram redução no apoio social, mais efeitos negativos \ne reatividade cardíaca que prejudica as artérias.\nII  Sobre  diabete,  o  conhecimento,  as  crenças  e  o \ncomportamento  dos  pacientes  afetam  muito  a \ncapacidade de manejar a doença. Isso torna o papel do \npsicólogo  da  saúde  particularmente  importante.  O \npsicólogo auxilia na adaptação do paciente ao diabete, \nno  tratamento  de  transtornos  psicológicos \nrelacionados com a doença, no controle do peso e do \nestresse,  no  aumento  da  adesão  aos  regimes  de \ntratamento,  na  melhoria  da  comunicação  e  no \naumento do apoio social.\nIII  Nos  tratamentos  contra  o  câncer,  os  psicólogos  da \nsaúde  fizeram  um  progresso  considerável, \ncompreendendo as reações psicológicas dos pacientes \nem relação ao  tratamento e aos  tipos de intervenção \neficazes.  Eles  observaram,  por  exemplo,  que \ninformações  metodológicas  sobre  os  processos  e  as \netapas do tratamento produzem um efeito negativo no \npaciente, prejudicando sua adesão.\nIV  Os  psicólogos  da  saúde  têm  investigado  diversos \nfatores  psicossociais  que  interferem  no  rumo  da \ninfecção  por  HIV  e  da  AIDS.  O  estresse,  as  emoções \nnegativas  e  o  isolamento  social  influenciam  a \nvelocidade em que a doença avança, talvez alterando \nos ambientes hormonais e imunológicos que afetam a \nresistência das células hospedeiras do vírus invasor.\nV Com  relação  à  AIDS,  os  psicólogos  da  saúde \ndesempenham seu papel de tratamento, auxiliando os \npacientes no enfrentamento da doença, mas não tendo \ncomo  campo  de  atuação  a  prevenção  primária  e \nsecundária.\nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Tres itens corretos (I, II, IV). Item III erra ao afirmar que informacoes sobre processos de tratamento de cancer produzem efeito negativo - na verdade, informacoes claras reduzem ansiedade e aumentam adesao. Item V erra ao excluir prevencao primaria/secundaria do campo de atuacao em HIV/Aids."}, {"id": "1298353", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Os psicólogos da saúde desenvolveram numerosas teorias na \ntentativa de explicar a razão por que as pessoas praticam ou \nnão  determinados  comportamentos  de  saúde.  Entre  essas \nteorias,  o  modelo  transteórico  é  a  teoria  de  estágios  mais \nusada  em  psicologia  da  saúde  e  sustenta  que  as  pessoas \nprogridem  por  meio  de  cinco  estágios  ao  alterar \ncomportamentos com relação à saúde. Os estágios propostos \npor este modelo, em sua ordem correta, são:", "alt": {"A": "pré‐contemplação; preparação; contemplação; ação; e \nmanutenção.", "B": "preparação; pré‐contemplação; ação; contemplação; e \nmanutenção.", "C": "preparação; ação; pré‐contemplação; contemplação; e \nmanutenção.", "D": "pré‐contemplação; contemplação; preparação; ação; e \nmanutenção.", "E": "pré‐contemplação; ação; preparação; contemplação; e \nmanutenção."}, "g": "D", "j": "Modelo transteorico (Prochaska & DiClemente): pre-contemplacao -> contemplacao -> preparacao -> acao -> manutencao. Alternativa D reproduz a sequencia correta; demais alternativas embaralham a ordem."}, {"id": "1298352", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Um  aspecto  importante  para  a  atuação  da  psicologia  da \nsaúde é a adesão do paciente ao tratamento. Segundo Straub \n(2014),  existem  fatores  que  influenciam  na  adesão  ao \ntratamento e podem ser campo de atuação do psicólogo. No \nque se refere a esses fatores, julgue os itens a seguir. \nI  As  variáveis  do  paciente  afetam  sua  adesão  ao \ntratamento.  Ter  o  apoio  da  família,  estar  de  bom \nhumor  e  ter  expectativas  positivas  são  fatores \nimportantes.  \nII A comunicação entre médico e paciente é outro fator \nque influencia a adesão ao tratamento. Geralmente, os \nmédicos mais comerciais, breves e  com postura mais \nfechada ao contato são considerados como mais sérios \nem sua profissão, fazendo com que os pacientes sigam \nmais bem as recomendações. \nIII As variáveis do regime de tratamento são importantes \npara que os pacientes o cumpram. A probabilidade de \nadesão  é  maior  quando  os  pacientes  acreditam  nas \nrecomendações e são capazes de cumpri‐las. \nAssinale a alternativa correta", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Itens I (variaveis do paciente: apoio familiar, humor, expectativas positivas) e III (variaveis do regime: crenca e capacidade de cumprir) corretos. Item II e falso - medicos com postura COMERCIAL, BREVE e FECHADA reduzem (nao aumentam) a adesao, contrariando a logica relacional do atendimento."}, {"id": "1298351", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "A  saúde  de  uma  pessoa  pode  ser  diretamente  influenciada \npelos comportamentos por ela adotados. Em sua atuação, o \npsicólogo  da  saúde  deve  estar  atento  aos  patógenos  e  aos \nimunógenos  comportamentais adotados  pelo  paciente.  São \nexemplos  de  patógenos  e  imunógenos  comportamentais, \nrespectivamente,", "alt": {"A": "uso de filtro solar e consumo de substâncias tóxicas.", "B": "prática de sexo seguro e comer de forma excessiva.", "C": "dieta  com  pouca  gordura  e  práticas  inseguras  no \ntrânsito.", "D": "fumar e manter uma perspectiva de vida otimista.", "E": "praticar exercícios e comportamentos sexuais de risco"}, "g": "D", "j": "Patogenos comportamentais (fumar) afetam negativamente a saude; imunogenos comportamentais (otimismo) protegem a saude. Demais alternativas misturam categorias ou apresentam apenas patogenos/imunogenos do mesmo tipo, sem o par contrastante exigido."}, {"id": "1298345", "d": "psicologia", "a": ["Psicologia da Saúde", "Psicologia Hospitalar"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando a prevenção e a intervenção terciárias, assinale \na alternativa correta.", "alt": {"A": "A  prevenção  terciária  inclui  acompanhamento  de \npacientes sem diagnóstico de enfermidade.", "B": "A  preparação  dos  pacientes  para  cirurgias  e  outros \nprocedimentos é uma atividade muito corrente nesse \nnível de atenção. Quando esse preparo  for  realizado, \nnão será necessária a intervenção voltada às famílias, \njá  que  estas  não  influenciam  na  condição  geral  do \npaciente.", "C": "No atendimento infantil, não  se utilizam informações \npreparatórias,  já  que  as  crianças  podem  não \ncompreender  bem  o  procedimento  pelo  qual  irão \npassar,  aumentando  a  mistificação  acerca  da \nhospitalização.", "D": "A atuação nesse nível de atenção à saúde corresponde \nà  assistência  aos  problemas  de  alta  complexidade \nderivados de outros níveis de atenção e às pesquisas \nem saúde e, em geral, faz‐se em hospitais.", "E": "A intervenção de terceiro nível, no âmbito da psicologia \nda  saúde,  tem,  na  pesquisa,  uma  de  suas  atividades \nsecundárias,  já  que  não  é  responsabilidade  do \npsicólogo  a  investigação  de  fatores  biopsicossociais \nque intervenham na etiologia dos problemas de saúde."}, "g": "D", "j": "A atuacao em prevencao terciaria corresponde a assistencia em alta complexidade, derivada de outros niveis, geralmente em hospitais. A erra ao incluir pacientes sem diagnostico; B nega importancia da familia; C nega valor de informacoes para criancas; E reduz pesquisa a atividade secundaria."}, {"id": "1298344", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "A atuação no âmbito de prevenção e intervenção secundárias \nfaz‐se  nos ambulatórios,  tendo  como  principal  objetivo  dar \nacompanhamento  ao  paciente,  ajudando‐o  no  seguimento \nde  seu  tratamento.  A  respeito  desse  assunto,  assinale  a \nalternativa  que  não  apresenta  atividades  psicológicas \ncompatíveis com esse nível de atenção à saúde.", "alt": {"A": "realizar  orientação  e  propor  apenas  atividades  de \nsuporte  individual,  não  realizando  encaminhamentos \nde  pacientes  a  outros especialistas e embasando  sua \natuação na psicologia clínica", "B": "oferecer  assistências  psicoterápicas  em  suas  várias \nmodalidades para todas as idades", "C": "realizar psicodiagnósticos diferenciais mediante o uso \nde testes ou por meio de diagnósticos descritivos", "D": "elaborar  pareceres  para  atender  às  demandas  de \noutros  profissionais,  atuando  em  conjunto  com  os \ndemais  profissionais  e  as  equipes  de  saúde  básica  e \nespecializada", "E": "elaborar, em conjunto com a equipe multiprofissional, \nprogramas  de  seguimento/adesão  de  tratamentos \nmédicos"}, "g": "A", "j": "A alternativa A NAO descreve pratica compativel com a prevencao secundaria - restringe atividades a 'suporte individual', exclui encaminhamentos e reduz embasamento a 'psicologia clinica'. Demais alternativas (psicoterapia, psicodiagnostico, parecer, programas de adesao) sao atividades legitimas do nivel secundario."}, {"id": "1298342", "d": "psicologia", "a": ["Psicologia da Saúde", "Equipes de Saúde, Multidisciplinaridade e Interdisciplinaridade", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "A  intervenção  primária  pode  ser  explicada  como  uma \nintervenção  direta  sobre  uma  queixa  detectada  em  um \nindivíduo ou em um coletivo social. Acerca da intervenção do \npsicólogo nesse âmbito, assinale a alternativa incorreta.", "alt": {"A": "Trata‐se  da  primeira  ação  de  saúde  diante  de  um \nproblema que deverá ser identificado e orientado.", "B": "Identificando‐se um problema, se o caso necessitar de \numa  intervenção  psicológica  especializada,  será \nencaminhado a outros níveis de atenção de saúde, já \nque,  nesse  nível,  a  intervenção  nunca  deverá  ser \nespecializada", "C": "A  intervenção  primária  do  psicólogo  na  equipe  de \nsaúde,  ainda  que  desempenhe  um  papel  específico, \ndeverá  ser  realizada  em  uma  perspectiva \ninterdisciplinar e multiprofissional.", "D": "O psicólogo, para trabalhar nesse nível de atenção de \nsaúde,  necessita  de  contribuir  restritamente  com  os \nconhecimentos  psicológicos,  não  precisando  se \npreocupar em somar conhecimentos de outras áreas, \njá que se entende que estes conhecimentos devam ser \ntrazidos  por  outros  membros  da  equipe \nmultiprofissional.", "E": "As  intervenções  do  psicólogo  na  atenção  primária \ndeverão  priorizar  a  saúde  geral.  O  psicólogo  deverá \ncumprir  seu  papel,  acolhendo  todas  as  pessoas  que \nchegarem  e  tendo  clareza  dos  encaminhamentos \nnecessários."}, "g": "D", "j": "Questao pede INCORRETA. Na atencao primaria, o psicologo PRECISA articular conhecimentos com outras areas (saude, educacao, social), nao se restringir a sua disciplina. Demais alternativas (primeira acao, encaminhamento, interdisciplinaridade, acolhimento) reproduzem corretamente o trabalho primario."}, {"id": "1298341", "d": "psicologia", "a": ["Psicologia da Saúde", "Saúde da Família", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "No âmbito da prevenção de doenças, a atuação do psicólogo \né realizada nos diversos níveis de atenção à saúde. O primeiro \nnível  da  intervenção  psicológica  faz‐se  nos  serviços  de \natenção primária de saúde. No que diz respeito à prevenção \nprimária, é correto afirmar que", "alt": {"A": "deva ser realizada assim que se encontre um problema \nconcreto no contexto social.", "B": "seja  importante,  para  atuar  em  seu  âmbito,  o \nconhecimento epidemiológico prévio do coletivo social \na ser assistido, que deverá ser utilizado como guia das \nações de saúde.", "C": "esteja diretamente relacionada à promoção da saúde, \ndirigindo suas ações em âmbito individual.", "D": "tenha  como  característica  central  a  atuação  nos \nproblemas  individuais,  construindo  estilos  de  vida \nsaudáveis,  sem  realizar  ações  de  prevenção  aos \ncomportamentos de risco.", "E": "trabalhar nesse nível de intervenção seja desconsiderar \nas  possibilidades  de  que  possa  aparecer  uma \nenfermidade"}, "g": "B", "j": "Atuar em prevencao primaria exige conhecimento epidemiologico previo do coletivo social a ser assistido - guia das acoes preventivas em larga escala. Demais alternativas restringem indevidamente a 'problema concreto', 'individual', 'sem prevencao de riscos' ou negam a relevancia da prevencao."}, {"id": "1298340", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Na  atuação  do  psicólogo  da  saúde,  apesar  dos  avanços \nobservados  no  âmbito  acadêmico,  ainda  se  encontram \ndubiedades  quanto  à  compreensão  dos  conceitos  de \npromoção  da  saúde  e  prevenção  de  doenças.  No  que  diz \nrespeito  à  promoção  da  saúde,  assinale  a  alternativa \nincorreta.", "alt": {"A": "Promover  saúde  significa  educar  e  instaurar  na \npopulação  comportamentos  que  sejam  realmente \neficazes para a construção de uma saúde ótima.", "B": "A promoção da saúde deve ser pensada sobre a base \ndo  perfil  epidemiológico  da  comunidade  em  que  se \ndeseje intervir.", "C": "Ações  de  promoção  da  saúde  devem  ser  voltadas  à \nproposição  de  assistências  antes  mesmo  do \naparecimento de enfermidades.", "D": "Promover saúde é pensar em um caráter amplo, com \nações  que  respondam  ao  compromisso  ético  de \nmelhorar o potencial de saúde das comunidades.", "E": "A promoção da saúde, em uma relação hierarquizada, \ndeve  ser  uma  intervenção  posterior  à  prevenção  de \ndoenças."}, "g": "E", "j": "Questao pede INCORRETA. Promocao da saude NAO e hierarquicamente posterior a prevencao - sao processos complementares e simultaneos, com enfoques distintos. Demais alternativas (educacao, perfil epidemiologico, antes do aparecimento da doenca, compromisso etico) descrevem corretamente a promocao."}, {"id": "1298338", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Com a compreensão multidimensional da saúde, a psicologia \nganhou mais espaço na área da medicina. Em 1978, criou‐se \nentão a psicologia da saúde. Considerando essa informação, \nassinale  a  alternativa  que  não  apresenta  um  objetivo  da \npsicologia da saúde.", "alt": {"A": "atuar unicamente no processo psicológico que leve o \nindivíduo a mais bem compreender a própria doença", "B": "estudar,  de  forma  científica,  as  causas  e  origens  de \ndeterminadas doenças, pesquisando sua etiologia", "C": "promover a saúde", "D": "prevenir e tratar doenças", "E": "promover  políticas  de  saúde  pública  e  o \naprimoramento do sistema de saúde pública"}, "g": "A", "j": "Atuar 'unicamente no processo psicologico individual' restringe indevidamente a atuacao da psicologia da saude - que tambem inclui pesquisa, promocao, prevencao, tratamento e politicas publicas. Demais alternativas descrevem corretamente os objetivos do campo."}, {"id": "1297707", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "A  condição  técnica  que  antecede  o  emprego  de  qualquer \ntécnica  ou  procedimento  instrumental  em  avaliação \npsicológica é o(a)", "alt": {"A": "dessensibilização instrumental.", "B": "orientação terapêutica.", "C": "uso do setting.", "D": "Rapport.", "E": "insight."}, "g": "D", "j": "Rapport - condicao tecnica de estabelecimento de relacao empatica e de confianca - e pre-requisito para qualquer procedimento de avaliacao psicologica, antecedendo a aplicacao de instrumentos. Demais opcoes referem-se a conceitos terapeuticos (insight) ou tecnicas especificas."}, {"id": "1297706", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "As expressões técnicas relacionadas aos testes para avaliação \nde  características  de  personalidade,  Zulliger,  palográfico  e \nPMK, são, respectivamente:", "alt": {"A": "resposta F; aceleração vertical; e palo.", "B": "sombreado acromático; palo; e esquema T.", "C": "cartão; tetron; e psicograma.", "D": "zigue‐zague; FC’; e tetron.", "E": "psicograma; nível de oscilação rítmica; e lineogramas."}, "g": "E", "j": "Termos tecnicos especificos: Zulliger usa psicograma como sintese interpretativa; o palografico utiliza nivel de oscilacao ritmica; o PMK (Psicodiagnostico Miocinetico) baseia-se em lineogramas. Alternativa E mapeia corretamente os tres instrumentos."}, {"id": "1297704", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "A  produção  técnica  relativa  à  elaboração  qualificada  de \ninformes  técnicos  científicos  decorrentes  de  avaliação \npsicológica é denominada de", "alt": {"A": "relatório  sobre avaliação  psicológica  para a  obtenção \nda CNH.", "B": "manual  de  elaboração  e  redação  de  informes  e \ndocumentos da avaliação psicológica.", "C": "resolução  relativa  em  psicologia  a  normas  e \nprocedimentos para registro documental.", "D": "normas e procedimentos para avaliação psicológica no \ncontexto do trânsito.", "E": "manual de elaboração de documentos, decorrente de \navaliação psicológica."}, "g": "E", "j": "Manual de elaboracao de documentos decorrentes de avaliacao psicologica (Res CFP 7/2003, atualizada pela 6/2019) e a producao tecnica oficial que orienta a redacao de informes psicologicos. Demais opcoes referem-se a instrumentos normativos especificos da CNH ou do Satepsi."}, {"id": "1297696", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2018", "org": "CFP", "t": "", "e": "A  revisão  da  avaliação  psicológica  ocorrerá  por  meio  de \ninstauração de junta psicológica, pelo órgão ou pela entidade \nexecutiva de trânsito do estado ou do Distrito Federal, e será \nconstituída por", "alt": {"A": "um  médico  e  um  psicólogo  peritos  examinadores  de \ntrânsito ou especialistas em psicologia de trânsito.", "B": "três  psicólogos  peritos  examinadores  de  trânsito  ou \nespecialistas em psicologia de trânsito.", "C": "um  psicólogo  perito  examinador  de  trânsito  ou \nespecialista em psicologia de trânsito.", "D": "dois psicólogos e um médico peritos examinadores de \ntrânsito ou especialistas em psicologia de trânsito.", "E": "dois  médicos  psiquiatras  e  um  psicólogo  perito \nexaminador  de  trânsito  ou especialista em  psicologia \nde trânsito."}, "g": "B", "j": "A junta psicologica de revisao da AP para CNH e composta por TRES psicologos peritos examinadores de transito ou especialistas em psicologia do transito - composicao monodisciplinar definida nas normas do Contran/CFP. Demais alternativas incluem indevidamente medicos/psiquiatras."}, {"id": "1297690", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "No  CFP,  a  avaliação  dos  testes  psicológicos  é  realizada \npelo(pela)", "alt": {"A": "Assembleia  de  Políticas  da  Administração  e  das \nFinanças (APAF).", "B": "Centro  de  Referências  Técnicas  em  Psicologia  e \nPolíticas Públicas (CREPOP).", "C": "Sistema de Avaliação de Testes Psicológicos (SATEPSI).", "D": "Comissão Nacional de Psicologia na Assistência Social \n(CNPAS).", "E": "Secretaria de Orientação e Ética (SOE)."}, "g": "C", "j": "No CFP, a avaliacao tecnico-cientifica dos testes psicologicos e realizada pelo SATEPSI (Sistema de Avaliacao de Testes Psicologicos). Demais opcoes referem-se a outras instancias do sistema conselhos (APAF, CREPOP, CNPAS, SOE)."}, {"id": "1297689", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  apresenta  o  instrumento \npsicológico  cuja  resposta  é  um  conteúdo  verbalizado,  uma \nideia,  um  conceito  vinculado  diretamente  a  determinada \nárea‐estímulo do dispositivo ou do cartão.", "alt": {"A": "teste PMK", "B": "técnica do desenho da figura humana", "C": "teste palográfico", "D": "teste de Zulliger", "E": "técnica de entrevista motivacional"}, "g": "D", "j": "O teste de Zulliger e instrumento projetivo em que a resposta e um conteudo verbalizado (ideia/conceito) vinculado a area-estimulo de cada cartao. Demais opcoes sao tecnicas grafomotoras (PMK, palografico), graficas (HTP) ou entrevista."}, {"id": "1297678", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2018", "org": "CFP", "t": "", "e": "Na  Resolução  n.º  425/2012,  o  Contran  determina  que,  no \nprocesso  de  avaliação  psicológica,  sejam  empregados  os \nseguintes recursos técnicos:", "alt": {"A": "entrevistas  diretas  e  individuais;  testes  psicológicos, \nque  deverão  estar  de  acordo  com  as  resoluções \nvigentes  do  CFP;  dinâmicas  de  grupo;  escuta;  e \nintervenções verbais.", "B": "entrevistas  diretas  (individuais  e  coletivas);  testes \npsicológicos em acordo com as resoluções vigentes do \nCFP; dinâmicas de grupo; e escuta.", "C": "entrevistas  diretas  (individuais  ou  coletivas);  testes \npsicológicos de acordo com as resoluções vigentes do \nCFP; dinâmicas de grupo; escutas orientadas; e técnicas \nobservacionais.", "D": "entrevistas  diretas  e  individuais;  testes  psicológicos, \nque  deverão  estar  de  acordo  com  as  resoluções \nvigentes  do  CFP;  escutas;  e  intervenções  (debates  e \nensaios) verbais.", "E": "entrevistas  coletivas;  testes  psicológicos  de  acordo \ncom  as  resoluções  vigentes  do  CFP;  e  intervenções \nverbais ou dinâmicas de grupo."}, "g": "A", "j": "Res Contran 425/2012 estabelece os recursos tecnicos da AP do transito: entrevistas diretas e individuais; testes psicologicos conforme normas CFP; dinamicas de grupo; escuta; e intervencoes verbais. Alternativa A reproduz integralmente."}, {"id": "1297676", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2018", "org": "CFP", "t": "", "e": "Na  análise  das  investigações  científicas  da  psicologia  no \ntrânsito, Sampaio & Nakano (2011) concluem que", "alt": {"A": "a  origem  das  dificuldades  dos  psicólogos  está  na \nformação  universitária,  pois  não  há  nenhuma  base \nsobre psicologia do trânsito na universidade.", "B": "é a área da psicologia que mais emprega profissionais \ne apresenta uma franca expansão com o novo Código \nde Trânsito.", "C": "órgãos governamentais não permitem que se realizem \npesquisas  sobre  acidentes,  especialmente  de \nmotocicletas.", "D": "o  problema  se  situa  principalmente  na  carência  de \nestudos voltados para esse contexto.", "E": "existem  muitas  opções  de  testes  psicológicos  para \natender a realidade brasileira."}, "g": "D", "j": "Em Sampaio & Nakano (2011), o problema central da pesquisa em psicologia do transito esta na CARENCIA de estudos voltados para esse contexto - lacuna persistente na area. Demais alternativas exageram ou negam aspectos especificos."}, {"id": "1297672", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2018", "org": "CFP", "t": "", "e": "Na  Nota  Técnica  CFP  n.º  1/2011  do  Conselho  Federal  de \nPsicologia  (CFP),  um  dos  construtos  mais  avaliados,  a \natenção, é descrito. Acerca desse tema, julgue os itens que se \nseguem. \nI  O tipo de atenção mensurado deve ser informado pelos \nautores dos testes. \nII  A  atenção  pode  ser  definida  como  o  fenômeno  por \nmeio do qual se processa uma quantidade ilimitada de \ninformações. \nIII  A  atenção  refere‐se  à  capacidade  exercida  para \nrepresentar recursos cognitivos. \nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas I correto - na NT CFP 1/2011, o tipo de atencao mensurado deve ser informado pelos autores dos testes. Item II e falso (atencao processa quantidade LIMITADA de informacoes); item III deturpa a definicao operacional (atencao = alocacao de recursos cognitivos, nao 'representacao')."}, {"id": "1297567", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas", "Transtornos Neurocognitivos", "Semiologia Psiquiátrica e Critérios de Normalidade"], "ano": "2018", "org": "CFP", "t": "", "e": "São  objetivos  do  diagnóstico  funcional  (F) e  do  diagnóstico \ntopográfico (T), respectivamente,", "alt": {"A": "investigar o desempenho em baterias normatizadas e \nusar exames de imagem.", "B": "levantar o perfil de pontos fortes e fracos do paciente \ne revelar a magnitude da lesão cerebral.", "C": "determinar  um  diagnóstico  nosológico  e  localizar  no \ncérebro o processo disfuncional.", "D": "levantar as habilidades preservadas e prejudicadas do \npaciente e localizar no cérebro o processo disfuncional.", "E": "determinar um diagnóstico nosológico e usar exames \nde imagem."}, "g": "D", "j": "Diagnostico FUNCIONAL: identifica habilidades preservadas e prejudicadas. Diagnostico TOPOGRAFICO: localiza no cerebro o processo disfuncional. Distincao fundamental em neuropsicologia clinica."}, {"id": "1297566", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas", "CID-10 e DSM", "Transtornos Neurocognitivos"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  da  doença  de  Alzheimer  (DA),  julgue  os  itens \nsubsequentes. \nI  Possui  um  estágio  inicial  marcado  por  perda  de \nmemória para eventos recentes e estágios posteriores \nmarcados  por  perda  de  memória  semântica  e  para \nfatos remotos. \nII  As  habilidades  de  linguagem  permanecem  intactas \ndurante todo o percurso da DA. \nIII  Escalas de inteligência, como o WAIS e as matrizes de \nRaven,  são  os  instrumentos  mais  empregados  para \ndiagnóstico de DA. \nIV  Ao contrário de outros quadros demenciais, a DA não é \nacompanhada por sintomas psiquiátricos.   \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Apenas os itens II e IV estão certos."}, "g": "A", "j": "Apenas I correto - perda de memoria para eventos recentes no inicio, com posterior afetacao da memoria semantica e remota e prejuizo de linguagem nos estagios avancados. Item II e falso (linguagem se altera); III erra (instrumentos especificos como MMSE/MoCA, nao Wechsler ou Raven); IV nega sintomas psiquiatricos frequentes na DA."}, {"id": "1297564", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas", "Transtornos Neurocognitivos"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação aos diferentes quadros de demência, julgue os \nitens a seguir. \nI  Uma  importante  diferença  entre  um  quadro  de \ndemência e um quadro de comprometimento cognitivo \nleve é a intensidade dos sintomas. \nII  Nem  todos  os  casos  de  demência  apresentam \ncomprometimento  da  memória  como  primeiro \nsintoma identificado. \nIII  Os  sintomas  comportamentais  da  demência \nfrontotemporal podem ser tanto de apatia quanto de \ndesinibição. \nIV  Um  dos  sintomas  da  demência  frontotemporal  é  a \nanosognosia. \nV  A  demência  semântica  é  caracterizada  por \ndegeneração  nos  lobos  temporais,  em  especial  no \nesquerdo. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "E", "j": "Todos os cinco itens corretos: distincao demencia x CCL pela intensidade (I); memoria nem sempre primeiro sintoma (II); apatia/desinibicao na frontotemporal (III); anosognosia na frontotemporal (IV); demencia semantica no temporal esquerdo (V)."}, {"id": "1297562", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas", "Transtornos Neurocognitivos"], "ano": "2018", "org": "CFP", "t": "", "e": "A  informação  sensorial  captada  pelo  ouvido  direito  \nprojeta‐se", "alt": {"A": "para os córtices auditivos direito e esquerdo.", "B": "somente para o córtex auditivo direito.", "C": "somente para córtex auditivo esquerdo.", "D": "para o córtex somatossensorial.", "E": "para o córtex occipital."}, "g": "A", "j": "A informacao auditiva do ouvido direito projeta-se para AMBOS os cortices auditivos (direito e esquerdo), com predominio contralateral via vias acusticas centrais - audicao e funcao bilateral, ao contrario das vias visuais (que tem decussacao parcial)."}, {"id": "1297557", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento", "Transtornos Neurocognitivos"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto à dislexia do desenvolvimento, assinale a alternativa \ncorreta.", "alt": {"A": "É caracterizada por deficits centrais nas habilidades de \nleitura de palavras isoladas e compreensão da leitura.", "B": "O diagnóstico é feito, geralmente, durante o primeiro \nano escolar.", "C": "Ao contrário de outros transtornos da aprendizagem, é \ncaracterizada por um perfil neuropsicológico bastante \nhomogêneo.", "D": "É  geralmente  acompanhada  de deficits  de  percepção \nvisual.", "E": "A  literatura  científica  aponta  deficits  nas  habilidades \nfonológicas como principal fator cognitivo associado à \ndislexia."}, "g": "E", "j": "A literatura cientifica aponta deficits nas habilidades FONOLOGICAS como o principal fator cognitivo associado a dislexia do desenvolvimento. A erra ao incluir compreensao da leitura como deficit central; B erra epoca do diagnostico; C nega heterogeneidade; D atribui deficits visuais como regra."}, {"id": "1297556", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Além  do  método  utilizado  para  diagnosticar  os  casos  de \ndificuldade de aprendizagem, outra discussão importante diz \nrespeito  aos  pontos  de  corte  utilizados  para  identificar \nescores  que  reflitam  algum  funcionamento  patológico.  Por \nexemplo,  alguns  autores  preferem  adotar  pontos  de  corte \nmais  rigorosos  (como  percentil  ≤  10),  enquanto  outros  \noptam  por adotar  pontos  de  corte mais  permissivos  (como  \npercentil  ≤  30).  A  respeito  desse  assunto,  assinale  a \nalternativa incorreta.", "alt": {"A": "O  uso  de  um  ponto  de  corte  permissivo  tende  a \nidentificar casos mais heterogêneos entre si.", "B": "Pontos  de  corte  permissivos  tendem  a  produzir mais \ndiagnósticos falso‐positivos.", "C": "Quando  comparado  com  pontos  de  corte  mais \npermissivos,  os  pontos  de  corte  rigorosos  têm  um \nmaior  poder  de  discriminar  uma  população \ngenuinamente sindrômica.", "D": "Pontos de corte rigorosos são mais suscetíveis ao efeito \nde variáveis intervenientes.", "E": "Pontos  de  corte  rigorosos  tendem  a  identificar  casos \nque  apresentem  maior  estabilidade  temporal  das \ndificuldades."}, "g": "D", "j": "Questao pede INCORRETA. Pontos de corte rigorosos sao MENOS (nao mais) suscetiveis a variaveis intervenientes - eles identificam apenas casos extremos, com maior estabilidade. Sao os pontos de corte PERMISSIVOS que tendem a sofrer mais influencia de fatores intervenientes."}, {"id": "1297555", "d": "psicologia", "a": ["Psicopatologia", "Semiologia Psiquiátrica e Critérios de Normalidade"], "ano": "2018", "org": "CFP", "t": "", "e": "O  método  de  discrepância  entre  habilidade  (QI)  e desempenho é um dos mais empregados no diagnóstico dos \ntranstornos  específicos  de  aprendizagem.  A  partir  dessa \ninformação,  assinale  a  alternativa  que  apresenta  uma \nlimitação importante desse método.", "alt": {"A": "Produz  uma  dicotomização  artificial  entre  normal  e \npatológico.", "B": "Negligencia diferenças individuais.", "C": "A  alta  correlação  entre  medidas  de  inteligência  e \ndesempenho  aumenta  a  probabilidade  de  erros  de \ndiagnóstico.", "D": "Ignora  o  efeito  de  variáveis  educacionais  sobre  o \ndesempenho.", "E": "Em  comparação  com  outros  métodos  possíveis, \ndemanda,  necessariamente,  um  intervalo  de  tempo \ndemasiadamente grande entre o início da avaliação e a \nconfirmação do diagnóstico."}, "g": "C", "j": "A alta correlacao entre QI e desempenho academico torna a discrepancia entre as duas medidas pouco confiavel para diagnostico de transtornos especificos de aprendizagem - critica metodologica recorrente na literatura."}, {"id": "1297554", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Apesar  de  a  linguagem  ser  geralmente  atribuída  ao \nfuncionamento  do  hemisfério  cerebral  esquerdo,  existem \nevidências  de  um  envolvimento  do  hemisfério  direito  em \nalgumas  atividades  da  linguagem.  Com  base  nessa \ninformação, é correto afirmar que o hemisfério direito esteja \nenvolvido", "alt": {"A": "no processamento da prosódia e de metáforas.", "B": "no  reconhecimento  do  timbre  da  voz  e  no \nprocessamento da prosódia.", "C": "no  reconhecimento  do  timbre  da  voz  e  no \nprocessamento de metáforas.", "D": "somente no processamento da prosódia.", "E": "somente no processamento de metáforas."}, "g": "A", "j": "O hemisferio cerebral direito participa ativamente do processamento da prosodia (entonacao, ritmo, melodia) e de aspectos figurativos/metaforicos da linguagem - achados consagrados na neuropsicologia da linguagem."}, {"id": "1297553", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta os deficits centrais para \ncritérios diagnósticos do autismo.", "alt": {"A": "deficit na imaginação e na motricidade e ausência total \nde linguagem", "B": "deficits motores e deficiência intelectual", "C": "deficiência intelectual e deficit de integração social", "D": "dificuldade de aprendizagem e deficit de coordenação \nmotora", "E": "deficit de integração social, linguagem, comunicação e \nflexibilidade comportamental"}, "g": "E", "j": "Os deficits centrais para diagnostico de autismo (triade de Wing/DSM): deficit de integracao social, linguagem/comunicacao e flexibilidade comportamental (rigidez/repetitividade). Demais alternativas restringem ou misturam aspectos motores e cognitivos."}, {"id": "1297552", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "O paciente 1 apresenta fala espontânea, mas marcada \npor  repetição  e  quantidade  reduzida  de  palavras,  ao  passo \nque  a  compreensão  da  linguagem  se  mantém  intacta.  O \npaciente  2  consegue  falar  espontaneamente  de  maneira \nbastante  fluente, mas com comprometimento do conteúdo \ndo  discurso.  Apresenta  ainda  dificuldades  acentuadas  na \ncompreensão  da  conversação.  O  paciente  3  consegue \nproduzir  um  discurso  fluente  e  carregado  de  sentido  e \ntambém  consegue  entender  o  que  lhe  é  dito,  no  entanto \napresenta dificuldades marcantes na  repetição de palavras, \nmarcada por erros fonológicos e lexicais. Com base nesse caso hipotético, os pacientes 1, 2 e 3 podem \nser  classificados,  respectivamente,  com  os  diagnósticos  de \nafasia de", "alt": {"A": "Wernicke, de Broca e de condução.", "B": "Broca, de Wernicke e de condução.", "C": "Wernicke, de condução e de Broca.", "D": "Broca, de Wernicke e de Wernicke.", "E": "Broca, de Broca e de condução."}, "g": "B", "j": "Paciente 1 (fala nao fluente, compreensao preservada) = afasia de Broca; paciente 2 (fluencia preservada, compreensao prejudicada) = afasia de Wernicke; paciente 3 (fluencia e compreensao preservadas, deficit na repeticao) = afasia de conducao."}, {"id": "1297551", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas", "CID-10 e DSM"], "ano": "2018", "org": "CFP", "t": "", "e": "No que diz respeito à leitura de palavras isoladas, assinale a \nalternativa correta.", "alt": {"A": "A  área  da  forma  visual  da  palavra,  situada  no  lobo \ntemporal  esquerdo,  tem  papel  fundamental  no \nreconhecimento de símbolos gráficos verbais, mas não \nde símbolos numéricos e faces.", "B": "A especialização cortical para reconhecimento de letras \ne palavras é um produto direto da evolução da espécie \nhumana.", "C": "A  alexia  pura  é  caracterizada  por  incapacidade  de \nreconhecer  palavras  apresentadas  em  qualquer \nmodalidade sensorial (visual, oral ou tátil).", "D": "As  alexias  são  causadas  por  lesões  concentradas  no \ncórtex visual primário.", "E": "O acesso ao conteúdo semântico das palavras escritas \nocorre mesmo antes dos primeiros estágios de análise \nvisual dos símbolos gráficos."}, "g": "A", "j": "A area da forma visual da palavra (VWFA), no lobo temporal esquerdo, e especializada no reconhecimento de simbolos graficos verbais (palavras/letras), nao de simbolos numericos nem de faces (que tem areas dedicadas distintas)."}, {"id": "1297550", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "O estudo das bases neurais da linguagem é considerado como \num dos temas clássicos em neuropsicologia, tendo inclusive \num papel importante no surgimento dessa disciplina. Acerca \ndesse tema, assinale a alternativa correta.", "alt": {"A": "Com o avanço dos modelos conexionistas, não é mais \npossível  destacar  uma  estrutura  neural  específica \nimportante para a linguagem.", "B": "Todo o processamento da linguagem é feito em regiões \nfrontais e parietais.", "C": "As  estruturas  importantes  para  os  processos \nexpressivos  da  linguagem  estão  localizadas \nprincipalmente no lobo frontal.", "D": "As afasias são consequência de lesão no córtex auditivo \nprimário.", "E": "O  hemisfério  cerebral  direito  é  especializado  nos \nprocessos articulatórios da fala."}, "g": "C", "j": "As estruturas centrais para os processos expressivos da linguagem (producao oral, articulacao, sintaxe) localizam-se principalmente no lobo frontal esquerdo (area de Broca e regioes adjacentes). Demais alternativas negam especializacao, generalizam regioes ou invertem hemisferio dominante."}, {"id": "1297547", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  apresenta  uma  vantagem  da \nmagnetoencefalografia (MEG) em relação ao EEG.", "alt": {"A": "resolução temporal elevada", "B": "maior resolução espacial", "C": "originar‐se  de mecanismos  neurais mais  precisos  que \nos captados pelo EEG", "D": "ser uma técnica não invasiva", "E": "captação  de  atividade  neural  mesmo  na  ausência  de \nrespostas motoras"}, "g": "B", "j": "A magnetoencefalografia (MEG) oferece MAIOR resolucao espacial que o EEG, pois capta campos magneticos diretamente das correntes neurais com menor distorcao pelo cranio. Ambos compartilham boa resolucao temporal e nao-invasividade."}, {"id": "1297545", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "A  respeito  dos  principais  métodos  de  estudo  da  atividade \nneural, julgue os próximos itens.  \nI  A  ressonância  magnética  funcional  (fMRI,  do  inglês \nFunctional  Magnetic  Ressonance  Imaging)  mede  a \natividade funcional a partir de variações no fluxo e na \noxigenação do  sangue  que irriga  regiões  de interesse \nno córtex cerebral.  \nII  A  fMRI  apresenta  uma  excelente  resolução  espacial, \nmas baixa resolução temporal. \nIII  O eletroencefalograma (EEG) mede a atividade elétrica \nde  uma  única  sinapse  a  partir  de  eletrodos \nposicionados na superfície escalpo. \nIV  O EEG apresenta resolução temporal bastante precisa, \nmas resolução espacial pobre. \nV  A  fMRI  e  o  EEG  têm,  cada  vez  mais,  se  tornado \nferramentas  indispensáveis  para  o  diagnóstico  de \ntranstornos neuropsiquiátricos e do desenvolvimento, \ncomo  autismo,  dislexia  e  transtorno  de  deficit  de \natenção e hiperatividade. \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I, II e IV estão certos.", "B": "Apenas os itens I, II, III e IV estão certos.", "C": "Apenas os itens I, II, III e V estão certos.", "D": "Apenas os itens I, II, IV e V estão certos.", "E": "Todos os itens estão certos."}, "g": "A", "j": "Itens I, II e IV corretos: fMRI baseada em BOLD (I), alta resolucao espacial e baixa temporal (II), EEG com excelente temporal e pobre espacial (IV). Item III erra ao reduzir EEG a 'uma unica sinapse' (capta atividade de populacoes neurais). Item V e categorico - fMRI/EEG complementam, nao 'diagnosticam' transtornos isolados."}, {"id": "1297544", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca da memória de longo prazo declarativa, julgue os itens \nsubsequentes. \nI  A  memória  semântica  possui  maior  resistência  ao \nesquecimento. \nII  As  memórias  episódicas  são,  muitas  vezes,  formadas \nlogo após o evento. \nIII  Não  existem  evidências  de  dissociação  neural  entre \ndiferentes categorias semânticas. \nIV  As  memórias  episódicas  não  podem  se  tornar \nmemórias semânticas. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e IV estão certos.", "E": "Apenas os itens III e IV estão certos."}, "g": "B", "j": "Itens I (semantica mais resistente ao esquecimento) e II (episodicas formadas logo apos o evento) corretos. Item III nega evidencias de dissociacao neural entre categorias semanticas (existem, p.ex., entre seres vivos e ferramentas). Item IV nega a transformacao episodico-semantica (que ocorre via repeticao e consolidacao)."}, {"id": "1297543", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Um  paciente  apresenta  deficits  importantes  em \ntarefas  que  envolvam  memória  não  declarativa,  mas  os \ndemais  componentes  de  sua  memória  se  apresentam \nintactos.  O  neuropsicólogo  responsável  pela  avaliação \nlevantou  a  hipótese  de  que  quatro  estruturas  neurais \npoderiam  apresentar  comprometimento,  sendo  elas: \namígdalas; cerebelo; hipocampo; e núcleos da base. Com  base  nessa  situação  hipotética,  assinale  a  alternativa \ncorreta.", "alt": {"A": "Todas  essas  estruturas  poderiam  apresentar \ncomprometimento.", "B": "Somente  as  amígdalas  não  poderiam  apresentar \ncomprometimento.", "C": "Somente  o  cerebelo  não  poderia  apresentar \ncomprometimento.", "D": "Somente  o  hipocampo  não  poderia  apresentar \ncomprometimento.", "E": "Somente os núcleos da base não poderiam apresentar \ncomprometimento."}, "g": "D", "j": "Memoria nao declarativa (procedural, condicionamento, priming) depende de cerebelo, nucleos da base e amigdalas. O hipocampo e estrutura central da memoria DECLARATIVA - portanto nao pode ser substrato de deficit isolado em memoria nao declarativa."}, {"id": "1297542", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Os  pacientes  com  problemas  de  memória  para  os  eventos \nque ocorreram antes do início de sua perda de memória estão \nsofrendo de amnésia", "alt": {"A": "proativa.", "B": "retrógrada.", "C": "anterógrada.", "D": "retroativa.", "E": "global."}, "g": "B", "j": "Amnesia RETROGRADA: perda da memoria para eventos ANTERIORES ao inicio da lesao/perda de memoria. Anterograda e perda para eventos posteriores; proativa/retroativa sao tipos de interferencia, nao amnesias; global combina ambas."}, {"id": "1297541", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  não  apresenta  um  avanço  do \nmodelo  de  memória  de  Baddeley  &  Hitch  (memória  de \ntrabalho) em relação ao modelo de Atkinson & Shiffrin.", "alt": {"A": "incorporação de mecanismos de memória dedicados a \ninformações de diferentes modalidades sensoriais", "B": "distinção de diferentes sistemas de memória de longo \nprazo", "C": "definição  de  um  sistema  geral  de  controle  capaz  de \ngerenciar recursos atencionais", "D": "explicação da manipulação ativa da informação contida \nnos sistemas de curto prazo", "E": "proposta  de  um  componente  multimodal  capaz  de \nintegrar  informações  de  diferentes  modalidades  e, \ntambém,  aquelas  armazenadas  no  sistema  de  longo \nprazo"}, "g": "B", "j": "Distinguir diferentes sistemas de MEMORIA DE LONGO PRAZO NAO e avanco do modelo de Baddeley & Hitch (focado na memoria de TRABALHO). Os avancos do modelo de MT incluem componentes modais especificos, executivo central, manipulacao ativa e buffer episodico."}, {"id": "1297540", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Godden e Baddeley (1980) estudaram o efeito do contexto na \nmemória,  realizando experimentos em que os participantes \ndeveriam  aprender  uma  lista  de  palavras  para  depois \nrecordá‐la  em  ambientes  diferentes  (por  exemplo,  debaixo \nd'água). Tais autores descobriram que", "alt": {"A": "a recuperação é beneficiada quando ocorre no mesmo \ncontexto onde aconteceu a memorização, enquanto a \nmemória  por  reconhecimento  não  sofre  efeito  de \ncontexto.", "B": "tanto  a  recuperação  quanto  o  reconhecimento  são \nmelhores  quando  ocorrem  no mesmo  contexto  onde \naconteceu a memorização.", "C": "o  contexto  não  interfere  na  recuperação  nem  no \nreconhecimento.", "D": "somente a memória por  reconhecimento sofre efeito do contexto.", "E": "o  estudo  não  permite  inferências  sobre  o  efeito  do \ncontexto."}, "g": "A", "j": "Godden & Baddeley (1980) demonstraram que a RECUPERACAO (recall livre) e beneficiada no mesmo contexto da memorizacao (efeito do contexto), enquanto o RECONHECIMENTO nao sofre tal efeito - distincao paradigmatica em psicologia da memoria."}, {"id": "1297538", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  a  pacientes  com  lesão  no  córtex  pré‐frontal \ndorsolateral, é correto afirmar que", "alt": {"A": "seja  normalmente  observado  um  prejuízo  na \nsensibilidade  às  contingências,  o  qual  poderá  ser \navaliado por meio do teste de cartas de Wisconsin.", "B": "seja  normalmente  observado  um  prejuízo  na \nsensibilidade  às  contingências,  o  qual  poderá  ser \navaliado por meio do teste de Stroop‐Victoria.", "C": "apresentem  um  quadro  marcante  de  síndrome \ndisexecutiva, que requer somente avaliação clínica.", "D": "seja  comum  observar  sintomas  de  impulsividade,  os \nquais  poderão  ser  avaliados  por  meio  do  teste  de \nStroop‐Victoria.", "E": "apresentem apenas deficits emocionais."}, "g": "A", "j": "Lesoes no cortex pre-frontal DORSOLATERAL causam prejuizo na sensibilidade a contingencias e flexibilidade cognitiva, classicamente avaliados pelo Teste de Cartas de Wisconsin (WCST). Stroop avalia inibicao (mais ligada ao cortex orbitofrontal/cingulado)."}, {"id": "1297537", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Em seu livro O Erro de Descartes, o neuropsicólogo Antônio \nDamásio  relata  casos  de  pacientes  com  lesão  na  porção \norbitofrontal  do  córtex  pré‐frontal.  Considerando  essa \ninformação,  assinale  a  alternativa  que  não  apresenta \ncaracterística(s) observada(s) em tais pacientes.", "alt": {"A": "dificuldade  na  inibição  de  comportamentos \ninapropriados", "B": "alterações de personalidade", "C": "pouca  sensibilidade  às  consequências  dos  próprios \ncomportamentos", "D": "deficits na memória declarativa", "E": "menor sensibilidade às regras sociais"}, "g": "D", "j": "Lesoes no cortex ORBITOFRONTAL (Damasio) causam: dificuldade de inibicao, alteracoes de personalidade, baixa sensibilidade a consequencias e regras sociais. NAO causam deficits primarios em memoria declarativa (preservada apos esse tipo de lesao focal)."}, {"id": "1297536", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Apesar  das  semelhanças  observadas  entre  os  diversos \nmodelos  de  funcionamento  das  funções  executivas  (FE),  é \ncorreto afirmar que eles difiram em relação", "alt": {"A": "à quantidade de construtos que compõem as FE.", "B": "ao papel das FE no controle do comportamento.", "C": "ao papel das diferenças individuais.", "D": "ao padrão de correlações estrutura‐função.", "E": "ao padrão de comprometimento após lesão cerebral."}, "g": "A", "j": "Os modelos de funcoes executivas diferem principalmente na QUANTIDADE de construtos que as compoem (modelo unitario vs multifatorial, com 3 ou mais componentes). Convergem quanto ao papel das FE no controle do comportamento, diferencas individuais e padrao apos lesao."}, {"id": "1297535", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "No que diz respeito aos processos automáticos e controlados, \nassinale a alternativa correta.", "alt": {"A": "Os processos automáticos não podem ser utilizados de \nmaneira flexível em circunstâncias dinâmicas.", "B": "Os  processos  controlados  não  apresentam  limite  de \ncapacidade.", "C": "Quando aprendidos, processos automáticos podem ser \nfacilmente modificados.", "D": "Processos controlados não requerem atenção.", "E": "Processos  automáticos  são  iniciados,  geralmente,  de \nmodo lento e deliberado."}, "g": "A", "j": "Processos automaticos sao rapidos, paralelos, sem demanda atencional, mas rigidos - NAO podem ser utilizados de maneira flexivel em circunstancias dinamicas. Demais alternativas invertem caracteristicas (controlados nao tem limite, automaticos modificaveis, etc.)."}, {"id": "1297534", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "A  memorização  de  uma  lista  de  estímulos  sonoros  é \nprejudicada quando também se recitam sons. Esse fenômeno \né denominado de", "alt": {"A": "articulação fonológica.", "B": "supressão fonológica.", "C": "inibição.", "D": "esquecimento dependente de indício/traço.", "E": "tarefa dual."}, "g": "B", "j": "O fenomeno em que a memorizacao de estimulos auditivos e prejudicada quando o sujeito recita sons simultaneamente e a SUPRESSAO FONOLOGICA (Baddeley) - interfere no loop fonologico da memoria de trabalho."}, {"id": "1297533", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "A  condição  em  que  há  uma  falta  de  consciência  para  os \nestímulos apresentados ao  lado  contralesional  do espaço é \nchamada de", "alt": {"A": "síndrome de Balint.", "B": "agnosia visual.", "C": "heminegligência.", "D": "ataxia.", "E": "anosognosia."}, "g": "C", "j": "A heminegligencia (negligencia hemiespacial) e a falta de consciencia para estimulos apresentados no lado contralesional do espaco, tipica de lesoes parietais direitas. Sindrome de Balint envolve outros sintomas (simultanagnosia, apraxia, ataxia optica); agnosia, ataxia e anosognosia tem outras definicoes."}, {"id": "1297532", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  apresenta  um  desdobramento \nfalso do avanço da ressonância magnética funcional.", "alt": {"A": "maior  precisão  espacial  para  as  correlações  \nestrutura‐função", "B": "uso  de  delineamentos  experimentais  para  a \ninvestigação  das  bases  neurais  dos  processos \ncognitivos", "C": "investigação não invasiva do cérebro", "D": "acompanhamento do desfecho de tratamentos", "E": "possibilidade  de  confirmação  de  diagnósticos  de \ntranstornos do desenvolvimento, como o TDAH"}, "g": "E", "j": "A fMRI NAO confirma diagnostico de transtornos do desenvolvimento como TDAH (que sao clinicos, baseados em DSM/CID) - sua contribuicao e investigativa, nao diagnostica isolada. Demais alternativas (precisao espacial, delineamentos, nao invasividade, acompanhamento de tratamentos) sao desdobramentos legitimos."}, {"id": "1297531", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "O neuropsicólogo  russo Alexander  Luria  organizou  o  córtex \ncerebral em uma hierarquia composta por três grandes áreas \nfuncionais.  A  respeito  dessas  áreas,  assinale  a  alternativa \ncorreta.", "alt": {"A": "As  regiões  primárias  possuem  um  papel \nessencialmente motor.", "B": "As  regiões  terciárias  diferem  das  secundárias, \nprincipalmente,  pela  capacidade  de  integração  de \ninformações.", "C": "O córtex motor primário recebe comandos de regiões \nmotoras associativas.", "D": "Uma  lesão  no  córtex  visual  primário  é  geralmente \nacompanhada  de  deficits  em  outras  modalidades \nsensoriais.", "E": "Lesões  em  regiões  secundárias  geralmente  estão \nassociadas a deficits sensoriais."}, "g": "C", "j": "Em Luria, o cortex motor primario recebe comandos das areas motoras ASSOCIATIVAS (secundarias/pre-motoras), que organizam programas motores. Demais alternativas erram funcao das areas primarias (sensoriais/motoras, nao apenas motoras), das terciarias (integracao multimodal) e dos efeitos das lesoes."}, {"id": "1297530", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere aos trabalhos de Broca e Wernicke, assinale \na alternativa incorreta.", "alt": {"A": "Promoveram a ideia de localização cortical das funções \ncognitivas.", "B": "Forneceram  evidência  empírica  para  a  ideia  de \norganização modular do cérebro.", "C": "Promoveram o estudo de pacientes com lesão cerebral \ncomo  fonte  de  inferências  para  modelos  do \nfuncionamento cognitivo normal.", "D": "Consistiram,  ambos,  em  um  estudo  de  dupla \ndissociação.", "E": "Os  dois  trabalhos,  em  especial  o  de  Wernicke, \ninspiraram a elaboração de modelos de processamento \nda linguagem."}, "g": "D", "j": "Questao pede INCORRETA. Cada trabalho isolado de Broca e de Wernicke constitui uma DISSOCIACAO SIMPLES; JUNTOS, eles formam a logica de DUPLA dissociacao. Afirmar que cada um, por si so, seja 'estudo de dupla dissociacao' contraria a definicao metodologica."}, {"id": "1297529", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas", "Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca  das  duas  principais  abordagens  metodológicas  em \nneuropsicologia:  nomotética  e  idiográfica,  julgue  os  itens  a \nseguir. \nI  A abordagem nomotética é caracterizada por estudos \nem  que  o  desempenho  de  um  grupo  de  pacientes  é \ncomparado com o de um grupo de controle normativo. \nII  Na  abordagem  idiográfica,  o  desempenho  de  um \npaciente  (caso)  é  investigado,  tomando‐o  como \nreferência.  \nIII  As duas abordagens compreendem visões antagônicas, \nirreconciliáveis, a respeito da ciência neuropsicológica. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Itens I (nomotetica = grupo vs controle) e II (idiografica = caso unico) corretos. Item III erra ao afirmar que as abordagens sao 'antagonicas e irreconciliaveis' - na pratica, sao complementares e frequentemente combinadas na neuropsicologia."}, {"id": "1297528", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  ao  método  anatomoclínico,  assinale  a \nalternativa correta.", "alt": {"A": "Baseia‐se em uma visão modular da mente.", "B": "Surgiu  como  uma  tentativa  de  superar  a  visão \nlocalizacionista predominante na neurologia do século \nXIX.", "C": "Entrou em desuso após o surgimento das  técnicas de \nneuroimagem funcional.", "D": "Atualmente  é  utilizado  apenas  em  estudos  de  caso \nisolado.", "E": "Surgiu  com  o  desenvolvimento  dos  exames  de \nneuroimagem."}, "g": "A", "j": "O metodo anatomoclinico baseia-se em uma visao MODULAR da mente - correlaciona lesoes em regioes especificas a alteracoes comportamentais distintas. Demais alternativas confundem com critica ao localizacionismo, desuso pela neuroimagem ou origem com exames modernos."}, {"id": "1297202", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito de imagem corporal, julgue os próximos itens.    I. Refere‐se à imagem ou à representação mental do corpo, que abrange aspectos sociais, afetivos e fisiológicos.  II. Está em constante modificação e sua formação depende de memórias, experiências, aspirações, tendências e intenções.    Assinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "A", "j": "Ambos os itens corretos e relacionados: imagem corporal e representacao mental do corpo que abrange aspectos sociais, afetivos e fisiologicos (I); esta em constante modificacao, dependendo de memorias, experiencias, aspiracoes (II)."}, {"id": "1297201", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação às duas vertentes existentes hoje na psicomotricidade, julgue os itens que se seguem.    I. A vertente funcional prioriza o gesto técnico e os exercícios analíticos para que a criança desenvolva competências motrizes.  II. Na vertente relacional, o foco está na relação simbólica entre o corpo e o meio. Por meio da interação do corpo com o meio, pode‐se expressar, com liberdade e autenticidade, todo o potencial motor, cognitivo, afetivo, social e relacional para que, consequentemente, se possa melhorar o desenvolvimento.  III. A vertente psíquica prioriza a interação do corpo com o meio para que a criança desenvolva competências motrizes.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (vertente funcional - gesto tecnico, exercicios analiticos) e II (vertente relacional - relacao simbolica corpo-meio) corretos. Item III e falso - nao existe 'vertente psiquica' como categorizacao classica em psicomotricidade."}, {"id": "1297200", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca do desenho como recurso, julgue os itens subsequentes.    I. Na terapia psicomotora, pode ser utilizado para favorecer o desenvolvimento das habilidades motoras finas, da aprendizagem em leitura e escrita, da comunicação expressiva e da exteriorização de emoções, sentimentos e sensações.  II. Na terapia psicológica, serve para identificar traços de personalidade e características emocionais dos pacientes.    Assinale a alternativa correta", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "A", "j": "Ambos os itens corretos e relacionados: na terapia psicomotora, o desenho favorece motricidade fina, leitura/escrita, comunicacao e expressao emocional (I); na terapia psicologica, serve para identificar tracos de personalidade e caracteristicas emocionais (II) - dois usos complementares do mesmo recurso."}, {"id": "1297198", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere ao teste gestáltico de Bender, é correto afirmar que", "alt": {"A": "apresente uma forma subjetiva de avaliar a maturação perceptovisual.", "B": "esteja ligado a traços de personalidade, como o inconformismo, a flexibilidade e a curiosidade.", "C": "seja possível identificar traços de personalidade por meio dos desenhos presentes nesse teste.", "D": "tenha por objetivo avaliar a maturação perceptomotora por meio da análise da forma.", "E": "a função gestáltica não esteja associada com funções intelectuais e de aprendizagem."}, "g": "D", "j": "O Teste Gestaltico Visomotor de Bender avalia a maturacao perceptomotora por meio da analise da forma (copia de figuras geometricas). A descreve avaliacao subjetiva; B/C atribuem indevidamente tracos de personalidade; E nega associacao com funcoes cognitivas."}, {"id": "1297195", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito da relação entre psicomotricidade e equoterapia, assinale a alternativa correta.", "alt": {"A": "Há uma busca por uma visão alternativa na prática clínica e a equoterapia pode substituir a psicomotricidade realizada em consultório.", "B": "A equoterapia, como recurso na terapia psicomotora, pode fornecer elementos para que o paciente possa construir seu desenvolvimento global por meio de seu próprio corpo e da relação do corpo com o meio ambiente.", "C": "A estimulação do equilíbrio é a função primordial da equoterapia e da psicomotricidade.", "D": "A privação de participação na equoterapia como parte da terapia psicomotora pode atrasar o desenvolvimento psíquico e motor dos pacientes.", "E": "O cavalo possui a maior responsabilidade pelo desempenho psicomotor do paciente."}, "g": "B", "j": "A equoterapia, como recurso complementar a terapia psicomotora, fornece elementos para o desenvolvimento global do paciente via experiencia corporal e relacao com o ambiente. A erra ao defender substituicao; C reduz funcao; D supervaloriza dependencia; E inverte papel do cavalo."}, {"id": "1297194", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto à relação entre avaliação neuropsicológica e avaliação psicomotora, julgue os próximos itens.    I. Ambas avaliam capacidades que estão diretamente relacionadas às capacidades cognitivas.  II. Baixo quociente de inteligência (QI) avaliado nos testes neuropsicológicos pode revelar quadros associados a alterações psicomotoras.  III. QI de execução abaixo do esperado para a normalidade pode indicar problemas com percepção, processamento, coordenação e execução de tarefas motoras.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: avaliacao neuropsicologica e psicomotora articulam-se a capacidades cognitivas (I); baixo QI pode revelar alteracoes psicomotoras associadas (II); QI de execucao abaixo do esperado pode indicar problemas perceptivos, de processamento e coordenacao motora (III)."}, {"id": "1297193", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Diversos autores afirmam que as habilidades psicomotoras podem interferir nas aquisições escolares. No que diz respeito a esse assunto, julgue os itens que se seguem.    I. O esquema corporal envolve o controle motor do corpo e, em especial, das mãos, interferindo na caligrafia.  II. A orientação espacial e a lateralidade interferem na ordem de disposição do texto na folha de caderno.  III. A definição do lado dominante também contribui para a melhora do tônus das mãos e para o desenvolvimento da noção de direita e esquerda.  IV. A orientação temporal está ligada diretamente ao ritmo da leitura e à ordem dos fatos.    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Todos os quatro itens corretos: esquema corporal e caligrafia (I); orientacao espacial/lateralidade e disposicao do texto (II); definicao do lado dominante e tonus/direita-esquerda (III); orientacao temporal e ritmo de leitura/ordem dos fatos (IV) - relacoes consagradas em psicomotricidade escolar."}, {"id": "1297192", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "As habilidades motoras, desde os movimentos mais amplos até os mais refinados e específicos, como os de escrita, dependem do desenvolvimento de áreas psicomotoras específicas. As áreas psicomotoras são elementos que compõem a atividade psicomotora e podem ser verificados por", "alt": {"A": "coordenação motora, tônus muscular, circunstâncias ambientais, equilíbrio, lateralidade, estruturação espacial e estruturação temporal.", "B": "coordenação motora, equilíbrio, tônus corporal, estruturação espacial, lateralidade, esquema muscular e estruturação temporal.", "C": "coordenação motora, natureza biológica, equilíbrio, tônus muscular, estruturação espacial, lateralidade e estruturação temporal.", "D": "coordenação motora e lateralidade, equilíbrio, tônus muscular, movimentos voluntários, esquema corporal e estruturação temporal.", "E": "coordenação motora, esquema corporal, estruturação \nespacial, lateralidade, equilíbrio, tônus muscular e estruturação temporal."}, "g": "E", "j": "As areas psicomotoras classicas (Le Boulch, Fonseca) sao: coordenacao motora, esquema corporal, estruturacao espacial, lateralidade, equilibrio, tonus muscular e estruturacao temporal. Alternativa E reproduz exatamente o rol. Demais alternativas incluem categorias estranhas (circunstancias ambientais, esquema muscular, natureza biologica)."}, {"id": "1297188", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação à terapia psicomotora, é correto afirmar que", "alt": {"A": "esteja voltada para o desenvolvimento biomecânico.", "B": "conte com técnicas que usem como recursos o corpo e o movimento, bem como suas manifestações psíquicas.", "C": "a observação comportamental e o aconselhamento sejam suas atividades centrais.", "D": "utilize jogos como ferramentas somente com crianças.", "E": "a avaliação para indicação à terapia psicomotora se faça somente por observação."}, "g": "B", "j": "A terapia psicomotora utiliza tecnicas que tem como recursos o corpo, o movimento e suas manifestacoes psiquicas - integracao soma-psique e o eixo da intervencao. Demais alternativas restringem indevidamente (biomecanico, observacao, jogos so para criancas, avaliacao so observacional)."}, {"id": "1297187", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca da percepção visual e de sua importância para a psicomotricidade, assinale a alternativa correta.", "alt": {"A": "É importante Na infância, mas não tanto na adolescência e na vida adulta.", "B": "É a forma de interpretar as informações visuais para direcionar as ações que sofre influência psíquica para dar significado ao que é visto.", "C": "O processamento da informação visual dá‐se por meio de experiências motoras.", "D": "Problemas de percepção visual estão diretamente relacionados à baixa visão, o que prejudica o desenvolvimento psicomotor.", "E": "O grau de percepção visual pode ser avaliado por meio de testes psicomotores."}, "g": "B", "j": "A percepcao visual e a forma de interpretar as informacoes visuais para direcionar acoes, sofrendo influencia psiquica que da significado ao percebido. Demais alternativas restringem fases etarias, invertem direcao do processamento ou reduzem percepcao a baixa visao."}, {"id": "1297186", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "De acordo com a definição de esquema corporal, é correto afirmar que seja", "alt": {"A": "como a pessoa se vê e como seu corpo se apresenta mentalmente, sofrendo influências do que ela vive e do que enfrenta.", "B": "o conhecimento intelectual consciente que uma pessoa tem de seu corpo.", "C": "a consciência do corpo e de suas partes (representação funcional) que permite o relacionamento com pessoas, espaços e objetos.", "D": "a noção de onde se localizam as partes do corpo.", "E": "a ação coordenada de partes do corpo para interagir com o meio."}, "g": "C", "j": "Esquema corporal e a consciencia do corpo e de suas partes (representacao funcional) que permite o relacionamento com pessoas, espacos e objetos. A descreve imagem corporal; B reduz a conhecimento intelectual; D restringe a noção de localizacao; E confunde com coordenacao."}, {"id": "1297185", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto à intervenção psicomotora segundo Le Boulch, julgue os seguintes itens.    I. Deve permitir e garantir que a criança tome consciência de seu corpo e de sua lateralidade.  II. Deve permitir e garantir que a criança se situe no espaço, domine seu tempo e adquira a coordenação de seus gestos e movimentos.  III. Deve ser considerada como educação base para o desenvolvimento infantil e deve ser praticada desde cedo.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos em Le Boulch: tomada de consciencia do corpo e lateralidade (I); situar-se no espaco, dominar tempo e coordenar gestos (II); educacao base do desenvolvimento infantil praticada desde cedo (III)."}, {"id": "1297182", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Na estimulação e na educação psicomotoras, é menos adequado", "alt": {"A": "fazer a transição de um jogo dirigido para um jogo espontâneo.", "B": "pensar sempre no prazer do movimento e na liberdade de criação.", "C": "manter os mesmos estímulos e as mesmas sequências nas atividades para que a criança se sinta segura.", "D": "realizar sempre uma avaliação antes de propor a estimulação para que haja adequação das atividades ao desenvolvimento e às demandas atuais.", "E": "que as colocações espontâneas do sujeito sejam acolhidas mesmo que interrompam as atividades."}, "g": "C", "j": "Manter os MESMOS estimulos e MESMAS sequencias e MENOS adequado - a estimulacao deve ser variada e progressiva para promover desenvolvimento. Demais alternativas (transicao dirigido-espontaneo, prazer/liberdade, avaliacao previa, acolhimento) sao boas praticas."}, {"id": "1297181", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca do movimento e dos ritmos, assinale a alternativa incorreta.", "alt": {"A": "O movimento faz do ser humano um ser único.", "B": "O fluxo de tensão está relacionado às pulsões.", "C": "Esforço e modelagem aparecem, no primeiro ano de vida, de forma rudimentar.", "D": "O sentido cinestésico não se refere às sensações internas e às tensões, mas sim à articulação de grupos musculares. As sensações precisam de um olhar qualitativo mais apurado.", "E": "Os ritmos orais estão presentes no decorrer da vida e servem para a alimentação e a fala."}, "g": "D", "j": "Questao pede INCORRETA. O sentido cinestesico REFERE-SE a sensacoes internas, tensoes e articulacao muscular - a alternativa D nega indevidamente essa dimensao. Demais alternativas descrevem corretamente movimento, fluxo de tensao, esforco/modelagem e ritmos orais."}, {"id": "1297180", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "O teste gestáltico visomotor de Bender consiste em um instrumento de avaliação psicomotora de grande valia. Com relação a esse assunto, julgue os itens que se seguem.   I. Resume‐se em um padrão original espacial (padrão visual) do fator temporal de transformação e do fator pessoal sensório‐motor. Sendo assim, há uma tendência à modificação das estruturas conforme os padrões do sujeito.  II. Como é um teste visomotor, sua relação com o desenvolvimento intelectual é nula, ou seja, não há correlações, o que favorece a avaliação isenta dessa habilidade.  III. As formas oferecidas às crianças são predominantemente arredondadas por serem mais fáceis de serem reproduzidas.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Nenhum item certo. Item I tem redacao confusa e atribuicoes imprecisas; item II nega correlacao do Bender com desenvolvimento intelectual (que existe); item III erra ao descrever as figuras como predominantemente arredondadas (sao variadas geometricamente)."}, {"id": "1297179", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito do reconhecimento de “esquerda‐direita” e lateralidade, é correto firmar que", "alt": {"A": "o reconhecimento de direita e esquerda em si e no outro seja próprio da faixa etária de quatro anos.", "B": "saber identificar esquerda e direita seja sinônimo de definição de lateralidade.", "C": "definir “esquerda‐direita” venha antes da formação da lateralidade.", "D": "seja necessário ter atenção na avaliação em casos de lateralidade cruzada porque a criança poderá se confundir na identificação.", "E": "essa habilidade seja o componente menos importante na avaliação neuropsicomotora."}, "g": "D", "j": "Na lateralidade cruzada, e necessario atencao na avaliacao porque a crianca pode se confundir na identificacao de esquerda/direita. A erra a faixa etaria; B confunde identificacao com lateralidade; C inverte ordem; E nega importancia do componente."}, {"id": "1297175", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere ao HTPF (House – Tree – Person – Family; ou, em português, Casa – Árvore – Pessoa – Família), é correto afirmar que", "alt": {"A": "desenhar uma casa consista em um método projetivo valioso para avaliar, principalmente, a organização espacial da criança.", "B": "a criança, na maioria das vezes, se detenha à aparência visual, o que dificulta a reprodução de histórias passadas e vivências atuais por meio do grafismo.", "C": "desenhar uma casa consista em um método projetivo valioso para verificar a vivência traumática dentro do ambiente físico em que ela resida, sem relação com o ambiente externo, uma vez que a casa é o centro de tudo.", "D": "o desenho seja a concretização de um diálogo entre as memórias e os desejos e permita a expressão daquilo que se organizou até hoje na relação do sujeito com o meio e o outro.", "E": "a análise da casa seja de extrema importância e se deva isolar seus elementos para entender o funcionamento psíquico da criança."}, "g": "D", "j": "O desenho do HTPF e a concretizacao de um dialogo entre memorias e desejos, expressando o que se organizou na relacao do sujeito com o meio e com o outro. A reduz a organizacao espacial; B nega expressividade; C limita ao ambiente fisico; E defende isolamento de elementos."}, {"id": "1297174", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca do jogo simbólico, julgue os itens subsequentes.    I. Até os três anos de idade, a criança está interessada nos aspectos práxicos do movimento, sendo este um dos requisitos para o desenvolvimento da função simbólica.  II. A criança, por meio do jogo expressivo, poderá identificar‐se com personagens sociais marcantes (como professor, bombeiro etc.), processo que favorecerá a socialização.  III. A imitação diferida, ou seja, a imitação de modelos presentes, é de extrema importância para a construção do esquema.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "C", "j": "Itens I (aspectos praxicos como base da funcao simbolica ate 3 anos) e II (identificacao com personagens sociais via jogo expressivo) corretos. Item III erra ao definir imitacao DIFERIDA como imitacao de modelos PRESENTES - diferida e justamente em diferimento (ausencia do modelo)."}, {"id": "1297173", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Em uma pré‐escola, tem‐se observado um comportamento de extrema agitação na classe de crianças de cinco anos de idade. O tempo em sala de aula aumentou e a escola, que apresenta perfil tradicional, acredita que agora seja a hora de permanecer sentado na carteira para o aprendizado da letra cursiva.Com base nessa situação hipotética, assinale a alternativa que apresenta a intervenção menos recomendada pelo psicomotricista.", "alt": {"A": "deslocar as cadeiras de  tempos em tempos e propor, no meio da sala, atividades cantadas e dramatizadas com o objetivo de promover o desenvolvimento do ritmo", "B": "utilizar mais atividades de pintar com lápis de cor e cobrir traçados de letras cursivas para que atinjam mais bem a atenção concentrada antes de entrar com a letra cursiva", "C": "ensinar em paralelo a lavar e secar as mãos, amarrar e desamarrar sapatos, além de abotoar e desabotoar as roupas", "D": "realizar jogos com bola de maneira ritmada e também com alvos a serem atingidos", "E": "incentivar trabalhos de modelagem com o objetivo de descobrir possibilidades e trabalhar a coordenação motora fina"}, "g": "B", "j": "A intervencao menos recomendada e MAIS atividades de pintar e cobrir letras cursivas - mantem a imobilidade e nao responde a agitacao das criancas. As demais (atividades cantadas/dramatizadas, AVDs, jogos com bola, modelagem) integram corpo e aprendizagem de forma adequada."}, {"id": "1297172", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Julgue os itens a seguir.    I. A analogia entre o modelo psiconeurológico de Luria e os fatores psicomotores da BPM (bateria psicomotora) é próxima.  II. Em termos ontogenéticos, há a organização de sete fatores: tonicidade; equilibração; lateralização; noção do corpo; estruturação espaçotemporal; praxia global; e praxia fina.  III. Na BPM, a estruturação espacial inclui funções de recepção, processamento e armazenamento espacial, envolvendo áreas visuais do córtex occipital.    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos sobre a BPM de Fonseca: analogia com Luria (I); sete fatores psicomotores em ordem ontogenetica (II); estruturacao espacial envolvendo cortex occipital e funcoes de recepcao/processamento/armazenamento (III)."}, {"id": "1297168", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "O foco da perspectiva educativa baseia‐se no diálogo corporal entre o Eu da criança, o mundo que a rodeia e o mundo dos outros. Em relação a esse tema, assinale a alternativa incorreta.", "alt": {"A": "A consciência respiratória é um dos elementos básicos para que o indivíduo possa, por meio da atenção plena sobre si, organizar mais bem sua relação com o mundo.", "B": "A ação intencional da criança favorece o conhecimento e o domínio de si mesma.", "C": "O jogo corporal possibilita a interação dinâmica e espontânea da criança com o mundo.", "D": "A utilização do canto consiste em uma atividade que favorece o controle da respiração.", "E": "O equilíbrio corporal precisa de ser estimulado após o domínio do esquema corporal pela criança."}, "g": "E", "j": "Questao pede INCORRETA. O equilibrio corporal NAO depende de domnio previo do esquema corporal para ser estimulado - ambos sao desenvolvidos PARALELAMENTE, em integracao reciproca. Demais alternativas (respiracao, acao intencional, jogo corporal, canto) sao corretas."}, {"id": "1297163", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação à prática atual da psicomotricidade, é correto afirmar que o(a)", "alt": {"A": "primeira reflexão esteja focada na motricidade do ser humano e nas implicações com seu corpo.", "B": "ensino da psicomotricidade se mantenha na fragmentação do sujeito, o que é visto nos cursos de psicologia, pedagogia, fonoaudiologia etc.", "C": "psicomotricidade venha se preocupando em promover práticas integradas a outros saberes, pensando na qualidade de vida do sujeito.", "D": "corpo, apesar de estar separado do ambiente que o cerca, tendo limites estabelecidos, aja em direção a esse ambiente, construindo um jeito de ser que é único.", "E": "corpo do indivíduo, à luz da psicomotricidade, apresente um significante e um significado, com gestos e atitudes desde a infância, que são facilmente entendidos pelos adultos."}, "g": "C", "j": "A pratica atual da psicomotricidade se preocupa em promover praticas INTEGRADAS a outros saberes, pensando na qualidade de vida do sujeito. Demais alternativas restringem a motricidade, defendem fragmentacao do sujeito ou separacao corpo-ambiente."}, {"id": "1297122", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "Refere‐se a uma investigação que teve como objetivo compreender como estava sendo tratada a motricidade das crianças de seis anos de idade que, com a implantação do ensino de nove anos, passaram a frequentar o ensino  fundamental. Apesar de ter focado a motricidade, não se perdeu de vista sua indissociabilidade da cognição e da afetividade. Foram observadas duas turmas de 1.º ano de uma escola municipal da Zona Oeste de São Paulo. As sessões de observação, registradas em diário de campo, foram sintetizadas em episódios. O estudo apontou que a escola ainda não reconhece a importância do ato motor para o desenvolvimento cognitivo e afetivo, oferece poucas oportunidades para que as crianças de seis anos de idade vivenciem o espaço físico, fundamental para a construção do espaço mental, e poucos momentos para brincadeiras de ficção, importantes para o fortalecimento da representação.Fátima Bissoto Medeiros Cintra e Laurinda Ramalho Almeida. Uma  \nleitura do movimento: crianças de seis anos no ensino  \nfundamental. Psicologia Escolar e Educacional. \nv. 21, n.º 2, 2017. p. 205‐214 (com adaptações).", "e": "O referencial teórico que fundamentou a pesquisa descrita no texto acima foi o(a)", "alt": {"A": "perspectiva montessoriana.", "B": "psicogenética de Piaget.", "C": "psicogenética de Wallon.", "D": "psicogenética de Vygotsky.", "E": "das inteligências múltiplas de Gardner."}, "g": "C", "j": "A pesquisa de Cintra e Almeida fundamenta-se na psicogenetica de WALLON, autor que enfatiza a indissociabilidade entre motricidade, cognicao e afetividade no desenvolvimento - linguagem direta do texto-base."}, {"id": "1297120", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "A teoria das inteligências múltiplas propõe que", "alt": {"A": "seja calculado um “QI” para cada uma das inteligências.", "B": "cada tipo de inteligência seja um atributo ou uma faculdade inata do indivíduo.", "C": "inteligência implique a capacidade de resolver problemas ou elaborar produtos que sejam importantes em determinado ambiente ou comunidade cultural.", "D": "as inteligências funcionem de modo isolado, contribuindo para a realização de tarefas especializadas.", "E": "um indivíduo, para ser considerado como superdotado, deva possuir tanto o fator g quanto uma das sete formas de inteligência dois percentis acima da média."}, "g": "C", "j": "Gardner define inteligencia como capacidade de resolver problemas ou elaborar produtos VALORIZADOS em determinado ambiente cultural - definicao centrada na competencia contextual, nao em escores ou genetica isolada."}, {"id": "1297116", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Na avaliação assistida, o examinador utiliza estratégias educacionais, temporárias e ajustáveis ao desempenho da criança que permitem revelar seu desempenho potencial, fazendo‐a alcançar um grau crescente de autonomia em situações de resolução de problemas. Ao utilizá‐las, aumenta‐se a compreensão sobre os processos cognitivos da criança durante a realização de tarefas, complementando informações que  foram  obtidas  com  a  psicometria \ntradicional.Maria Beatriz Martins Linhares. Avaliação assistida em crianças com queixa de dificuldade de aprendizagem. Temas em Psicologia, v. 4, n.º 1, 1996. p. 17‐32 (com adaptações).  É correto afirmar que esse tipo de avaliação se fundamente", "alt": {"A": "nos conceitos de aprendizagem mediada e zona de desenvolvimento proximal ou iminente de Vygotsky.", "B": "nos conceitos de equilibração, assimilação e acomodação de Piaget.", "C": "no conjunto funcional cognitivo que opera por meio de um movimento dialético, ora centrípeto ora centrífugo, proposto por Wallon.", "D": "na construção do conhecimento proposta por Emília Ferreiro.", "E": "no conceito de inteligência cristalizada e fluida do modelo CHC."}, "g": "A", "j": "A avaliacao assistida fundamenta-se nos conceitos de APRENDIZAGEM MEDIADA e ZONA DE DESENVOLVIMENTO PROXIMAL/IMINENTE de Vygotsky - examinador atua como mediador para revelar o desempenho potencial da crianca."}, {"id": "1297115", "d": "psicologia", "a": ["Psicopatologia", "Transtornos do Neurodesenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca dos transtornos do espectro autista, julgue os itens subsequentes.    I. Caracteriza‐se por comprometimentos que se manifestam depois dos três anos de idade.  II. Caracteriza‐se pelo desenvolvimento acentuadamente atípico na interação social.  III. Caracteriza‐se por limitações na comunicação.  IV. Caracteriza‐se pela presença de um repertório marcadamente restrito de atividades e interesses.  V. Caracteriza‐se por comportamentos estereotipados e repetitivos.    A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "D", "j": "Quatro itens corretos (II-V) - TEA caracterizado por atipia na interacao social, limitacoes na comunicacao, repertorio restrito de atividades/interesses e comportamentos estereotipados/repetitivos. Item I errado pois manifesta-se ANTES dos 3 anos (geralmente antes dos 2-3)."}, {"id": "1297114", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Piaget", "Teorias da Personalidade"], "ano": "2018", "org": "CFP", "t": "", "e": "Considerando que um psicólogo especialista em psicopedagogia adote o referencial teórico piagetiano, pretendendo intervir para promover o desenvolvimento moral de estudantes do ensino fundamental, julgue os itens que se seguem.    I. Ao planejar sua intervenção, ele deverá considerar que os estudantes desse nível estão na fase da cooperação nascente e, consequentemente, não conhecem as regras em seus pormenores, cada um tendo uma opinião pessoal a respeito delas.  II. Ao planejar sua intervenção, ele deverá ficar atento às confusões, entre o ponto de vista próprio e o de outra pessoa, típicas do estágio operatório formal, pois os alunos do ensino fundamental não diferenciam seus pensamentos dos pensamentos de outrem, tendo dificuldade para se colocar na perspectiva do outro e agindo como se tudo acontecesse devido à própria vontade.  III. Ao planejar sua intervenção, ele deverá concentrar seus esforços em ações relacionadas ao estágio pós‐convencional, isto é, baseadas em princípios universais éticos, já que o corpo discente do ensino fundamental está nessa etapa do desenvolvimento moral.  IV. Ao planejar sua intervenção, ele deverá identificar as \ncontingências ambientais que reforcem o juízo moral e promover a assimilação delas pelos estudantes.  V. Ao planejar sua intervenção, ele deverá dedicar atenção especial ao egocentrismo, uma vez que, apesar de ser mais característico nos discentes do início desse nível educacional, ele também se manifesta em fases mais avançadas do desenvolvimento moral.    A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "B", "j": "Dois itens corretos (I cooperacao nascente; V egocentrismo persistente em fases mais avancadas). II confunde formal com pre-operatorio; III atribui pos-convencional indevidamente a fundamental; IV mistura behaviorismo com Piaget."}, {"id": "1297113", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto ao modelo dual de leitura, julgue os itens a seguir.    I. Prevê que duas vias, via léxica e via fonológica, interatuem nesse processo.  II. Considera que leitores competentes façam uso do raciocínio verbal e da discriminação visual ao ler, por isso tenha a designação de modelo dual.  III. Propõe que a via fonológica, também chamada de sublexical ou indireta, seja mais utilizada no início da alfabetização e na leitura de palavras desconhecidas, recorrendo à associação entre letras e seus sons.  IV. Estabelece que, na discriminação visual ou identificação direta, o reconhecimento e o acesso ao significado da palavra ocorram simultaneamente, como se a escrita de uma palavra fosse seu desenho.  V. Explica como as funções executivas (Componente 1 – neuropsicológico) e o método de ensino (Componente 2 – ambiental) atuam no comportamento de ler.    A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Tres itens corretos: duas vias lexica/fonologica (I); via fonologica como rota inicial e p/ palavras desconhecidas (III); discriminacao visual = reconhecimento e acesso semantico como 'desenho' da palavra (IV). II confunde raciocinio verbal/discriminacao visual; V descreve outro modelo."}, {"id": "1297112", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta uma relação entre dislexia, oportunidade educacional e QI respaldada pela literatura científica.", "alt": {"A": "Para fins de diagnóstico, um indivíduo com dislexia deve possuir QI igual ou superior a 80 e ter tido condições pedagógicas suficientes.", "B": "A dislexia manifesta‐se em pessoas com rebaixamento intelectual (QI  inferior a  100), mas que não possuem deficiência e tiveram acesso à escolarização adequada.", "C": "A dislexia é característica de pessoas com QI superior a 115, mas que foram alfabetizadas de modo inadequado, ou seja, trata‐se de um problema de “ensinagem”.", "D": "O diagnóstico de dislexia não deve considerar o QI nem as oportunidades educacionais.", "E": "A  dislexia é causada por ensino inadequado (dispedagogia) e, desse modo, o QI nem precisa ser considerado nas avaliações psicopedagógicas."}, "g": "C", "j": "Pela atualizacao do DSM-5 e da literatura, o diagnostico de dislexia NAO depende mais de criterios fixos de QI nem da quantificacao de oportunidades educacionais como exclusao - foca-se em sintomas, persistencia e impacto. Demais alternativas adotam criterios obsoletos ou simplificadores."}, {"id": "1297111", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "No que diz respeito às habilidades metalinguísticas, julgue os itens que se seguem.    I. Podem ser definidas como a capacidade de pensar a própria língua.  II. Abrangem as habilidades sintática, semântica e fonológica.  III. Constituem um importante preditor do sucesso em leitura e escrita.  IV. Abrangem, por exemplo, a consciência fonológica que contribui positivamente para o desempenho em leitura, especialmente para a decodificação de palavras.  V. São inatas.    A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "D", "j": "Quatro itens corretos sobre habilidades metalinguisticas: definicao como capacidade de pensar a propria lingua (I); inclusao de sintatica/semantica/fonologica (II); preditor de sucesso em leitura/escrita (III); consciencia fonologica como contributo a decodificacao (IV). Item V e falso - sao DESENVOLVIDAS, nao inatas."}, {"id": "1297110", "d": "psicologia", "a": ["Psicopatologia", "CID-10 e DSM", "Transtornos do Neurodesenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação ao transtorno de deficit de atenção e hiperatividade (TDAH), julgue os itens seguintes.   I. É caracterizado pela presença de impulsividade.  II. É típico de pessoas com altas habilidades ou superdotação.  III. Decorre de transtornos de personalidade.  IV. Diferentemente do que se afirmava até recentemente, é caracterizado apenas por deficit  significativo de atenção flutuante.  V. É causado estritamente por fatores ambientais, mas os sintomas podem ser revertidos por meio de intervenção psicopedagógica combinada com intervenção medicamentosa. A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "A", "j": "Apenas item I correto - TDAH e caracterizado por impulsividade (alem de desatencao e hiperatividade). II, III, IV, V apresentam afirmacoes incorretas (associacao com superdotacao, etiologia em personalidade, deficit unico de atencao flutuante, etiologia exclusivamente ambiental)."}, {"id": "1297109", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto ao bullying, julgue os próximos itens. I. Os casos de bullying de alunos contra professores têm aumentado.  II. A simetria de poder é uma característica‐chave desse tipo de agressão.  III. O ciberbullying é o bullying cometido por hackers.  IV. O bullying atinge os estudantes indistintamente, ou seja, todos os alunos, independentemente de gênero, presença de necessidades educacionais especiais, origem étnico‐racial e desempenho escolar, são vitimizados do mesmo modo e com a mesma frequência.  V. A idade não é uma variável importante ao se considerar os diferentes tipos de bullying (físico, social etc.), pois todas as formas dessa agressão se manifestam com a mesma frequência nos diferentes momentos da escolarização.    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "B", "j": "Apenas item I correto - aumento de casos de bullying de alunos contra professores. II inverte (e ASSIMETRIA de poder); III confunde ciberbullying com hacking; IV nega variabilidade por genero/raca/deficiencia; V nega importancia da idade."}, {"id": "1297108", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Crianças pequenas (educação infantil) utilizam cada vez mais jogos eletrônicos. Apesar de se tratar de um tema ainda carente de pesquisas no contexto brasileiro, é correto afirmar que", "alt": {"A": "conhecimentos científicos sobre os padrões de use de jogos eletrônicos de estudantes da educação infantil pouco contribuam para a psicopedagogia clínica e institucional.", "B": "haja consenso quanto à necessidade de impedir que crianças pequenas tenham acesso a esse tipo de jogo.", "C": "esteja comprovado que essa atividade lúdica prejudique o desenvolvimento cognitivo de crianças da \neducação infantil.", "D": "se trate de um elemento da cultura infantil atual que não é inócuo para o desenvolvimento das crianças, persistindo controvérsias quanto a seus efeitos positivos e(ou) negativos em crianças de educação infantil.", "E": "haja um acúmulo de evidências empíricas geradas por pesquisas brasileiras que dão suporte para a utilização desses dispositivos na educação infantil."}, "g": "D", "j": "Jogos eletronicos na educacao infantil sao elemento da cultura infantil contemporanea NAO inocuo para o desenvolvimento, com controversias persistentes quanto a efeitos positivos e negativos. Demais alternativas adotam posicoes categoricas (impedir, prejudica, suporte empirico) sem suporte cientifico."}, {"id": "1297104", "d": "psicologia", "a": ["Psicopatologia", "Psicologia da Educação", "Outros Transtornos"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto à terminologia dupla excepcionalidade, julgue os itens a seguir.I. Designa estudantes que apresentem altas habilidades/superdotação e outra necessidade educacional especial caracterizada por algum deficit ou transtorno, como transtorno deficit de atenção e hiperatividade ou síndrome de Asperger. II. Classifica alunos com duas deficiências em áreas distintas, como deficiência física e deficiência intelectual, que se manifestam, por exemplo, em certos tipos de paralisia cerebral.III. Faz menção a discentes com dois diagnósticos psicopedagógicos na área de dificuldades de aprendizagem, como dislexia e discalculia.Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas item I correto - dupla excepcionalidade designa estudantes com altas habilidades/superdotacao E outra necessidade educacional especial (TDAH, Asperger). Item II descreve deficiencia multipla; item III descreve comorbidade entre transtornos de aprendizagem - nao sao dupla excepcionalidade."}, {"id": "1297102", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto à evolução do pensamento infantil, assinale a alternativa incorreta.", "alt": {"A": "Animismo é a atribuição de vida e consciência a todas as coisas que rodeiem a criança, sendo comum até os seis anos de idade.", "B": "Egocentrismo é uma centração da criança em si mesma, que vai diminuindo à medida que a criança passa a ter noção da realidade.", "C": "Imitação é a forma natural com que a criança constrói seu pensamento e origina suas ações.", "D": "Na fase do pensamento egocêntrico, são comuns os conflitos por disputa de brinquedos.", "E": "Artificialismo é a colocação de um agente fabricador na origem de todas as coisas, que vai diminuindo até os oito anos de idade."}, "g": "C", "j": "Questao pede INCORRETA. O animismo em Piaget e tipico da fase pre-operatoria e geralmente persiste ate aproximadamente 7-8 anos (nao 'ate os seis anos' como afirma a alternativa A). Demais alternativas (egocentrismo, imitacao, conflitos de disputa, artificialismo) sao descritas corretamente."}, {"id": "1297101", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação à disortografia, assinale a alternativa correta.", "alt": {"A": "A dificuldade na escrita não implica a diminuição da qualidade do traçado das letras.", "B": "É a dificuldade de copiar informações escritas do quadro.", "C": "As trocas só aparecem a partir do 4.º ano do ensino fundamental.", "D": "Deve ser diagnosticada somente aos nove anos de idade.", "E": "A confusão ocorre somente com fonemas semelhantes."}, "g": "A", "j": "Disortografia e dificuldade especifica na ORTOGRAFIA (regras grafemicas) e NAO implica diminuicao da qualidade do TRACADO das letras - traco e dominio da disgrafia. Demais alternativas confundem disortografia com outras disfuncoes ou impoem criterios indevidos de idade/4. ano."}, {"id": "1297099", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "A abordagem familiar consiste em um desafio para o psicopedagogo. Acerca dessa intervenção, assinale a alternativa incorreta.", "alt": {"A": "Propor o treinamento dos pais é tão importante no processo escolar quanto ensinar conteúdos escolares.", "B": "Apesar das intervenções, percebe‐se que alguns pais e cuidadores não se vinculam afetivamente às crianças.", "C": "Com frequência, há dificuldade de reconhecer os sintomas porque estes, muitas vezes, são gerados pela própria família.", "D": "A anamnese inicial deve ser criteriosa, pois consiste em uma das etapas mais importantes do processo de avaliação psicopedagógica.", "E": "O acompanhamento psicopedagógico clínico deve continuar mesmo que os pais não se vinculem ao processo, pois o foco está no paciente."}, "g": "C", "j": "Questao pede INCORRETA. O treinamento dos pais NAO se equipara em importancia ao ensino de conteudos escolares (cabe ao professor, nao ao psicopedagogo) - sao funcoes complementares mas distintas. Demais alternativas (vinculacao, geracao familiar de sintomas, anamnese, continuidade clinica) sao corretas."}, {"id": "1297093", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Em uma sala de aula, a professora convidou um aluno para refletir sobre seu comportamento de conversar durante a aula. Relatou que ela (a professora) tinha de falar mais alto\nainda para ser ouvida, o que prejudicava sua saúde. Após a intervenção, a criança compreendeu a colocação e disse que percebia que sua voz estava rouca e se comprometeria em tentar modificar seu comportamento.Com base nessa situação hipotética, assinale a alternativa incorreta em relação às habilidades mais estabilizadas nessa criança à luz da teoria de Jean Piaget.", "alt": {"A": "senso de justiça pertinente ao estágio pré‐operatório", "B": "reversibilidade do pensamento", "C": "conservação", "D": "respeito mútuo", "E": "cooperação"}, "g": "A", "j": "Questao pede INCORRETA. Em Piaget, o senso de justica NAO e pertinente ao estagio pre-operatorio (em que predomina o egocentrismo e o realismo moral), mas se desenvolve no operatorio concreto/formal com autonomia e respeito mutuo. Demais habilidades (reversibilidade, conservacao, respeito mutuo, cooperacao) sao do operatorio concreto."}, {"id": "1297092", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere ao desenvolvimento cognitivo e ao processo de escolarização da criança de zero a seis anos de idade, julgue os itens que se seguem.I. Na pré‐escola, o interesse maior da escola deve ser pelo desenvolvimento sensório‐motor, que servirá de base para a aprendizagem da leitura e da escrita.II. A alfabetização no Brasil precisa de ser revista, incluindo o método fônico, mais indicado como estratégia de ensino.III. O desenvolvimento do processo de mielinização tem relação discreta com o aumento do vocabulário aos doze meses de vida.Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Nenhum item correto. Item I confunde fases (sensorio-motor e 0-2 anos, nao da pre-escola); item II e proposicao controversa nao consensual; item III subestima a relacao entre mielinizacao e desenvolvimento da linguagem (que e robusta)."}, {"id": "1297091", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "O hemisfério direito, responsável pela habilidade visuoespacial, precisa de ser estimulado por meio de atividades direcionadas a esse fim. Para se realizar esse estímulo, não é indicado o(a)", "alt": {"A": "reconhecimento de fisionomias.", "B": "desenho de uma planta da escola.", "C": "montagem de quebra‐cabeça.", "D": "trabalho com argila.", "E": "material dourado."}, "g": "E", "j": "O material dourado NAO estimula o hemisferio direito - e instrumento matematico ligado ao processamento numerico (hemisferio esquerdo). Demais alternativas (fisionomias, plantas, quebra-cabeca, argila) estimulam habilidades visuoespaciais do hemisferio direito."}, {"id": "1297087", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação às contribuições de Reuven Fuerstein para o campo da psicopedagogia, julgue os itens a seguir.I. O conceito de “experiência de aprendizagem mediada” trazido por Fuerstein deve ser visto como uma postura que favorece a apropriação do conhecimento pelo sujeito.II. As dificuldades do desenvolvimento cognitivo‐intelectual devem ser atribuídas, principalmente, à pobreza nas mediações construídas nos primeiros anos de vida.III. Uma criança que tenha dificuldade de distinguir entre o que é e o que não é relevante, segundo Fuerstein, necessita de intervenção psicopedagógica na função cognitiva de “análise”.Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos sobre Fuerstein: experiencia de aprendizagem mediada como postura facilitadora (I); dificuldades cognitivas atribuidas a pobreza de mediacoes precoces (II); intervencao na funcao 'analise' para distincao do relevante (III)."}, {"id": "1297084", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Alicia Fernandez traz contribuições significativas para que se possa ampliar a visão sobre o “aprendente” e sua interação com as instâncias que promovem a aprendizagem. No que se refere aos pressupostos teóricos que norteiam seu pensamento, assinale a alternativa incorreta.", "alt": {"A": "O problema de aprendizagem surge, se entrelaça na trama familiar e muitas vezes é reforçado pelo ambiente escolar.", "B": "Muitas vezes apenas um de vários membros da família reflete um problema de aprendizagem, o que leva a questionar os elementos internos desse sujeito para que tenha manifestado o sintoma. Nesse caso, possivelmente a estrutura familiar deve ser menos considerada como geradora do sintoma.", "C": "A criança pode não aprender, respondendo à marginalização de âmbito socioeducativo.", "D": "O aprender se faz na relação inteligência‐desejo e também no equilíbrio imprescindível entre assimilação‐acomodação.", "E": "A criança muitas vezes assume o “medo de aprender” que vem de sua trama familiar, por isso é necessário lutar contra o termo “criança‐problema” e ampliar sempre a investigação sobre o processo."}, "g": "B", "j": "Questao pede INCORRETA. Em Alicia Fernandez, a estrutura familiar deve ser SIGNIFICATIVAMENTE considerada como geradora do sintoma de aprendizagem - a alternativa B inverte essa perspectiva. Demais alternativas (problema na trama familiar, marginalizacao, inteligencia-desejo, medo de aprender) reproduzem corretamente a autora."}, {"id": "1297083", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "CFP", "t": "", "e": "Um ponto de partida importante para a prática psicopedagógica é a investigação. Com relação a esse processo, assinale a alternativa correta.", "alt": {"A": "Nesse contexto, avaliação é sinônimo de investigação e tem como objetivo penetrar nos motivos por que o sujeito não aprende.", "B": "Parte da queixa, que é diferente de sintoma, pois se configura em apenas uma fala superficial sobre o sujeito.", "C": "Mais importante que ouvir o sujeito a ser investigado é ouvir todos os contextos em que esteja inserido.", "D": "A escolha dos instrumentos de avaliação, sendo o profissional de psicopedagogia um psicólogo, é favorecida pela possibilidade de uso de testes psicológicos, que ampliam o olhar sobre o problema.", "E": "Por ser um procedimento meramente empírico, a observação lúdica consiste em um instrumento pouco utilizado na avaliação psicopedagógica."}, "g": "C", "j": "No contexto psicopedagogico, avaliacao e sinonimo de investigacao - tem como objetivo penetrar nos motivos pelos quais o sujeito nao aprende, em uma logica clinica. Demais alternativas separam queixa/sintoma, restringem escuta, supervalorizam testes ou negam a observacao ludica."}, {"id": "1296921", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Terapia familiar"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  relação  à  perspectiva  da  terapia  familiar  em  uma \nabordagem  comportamental  segundo  Ingberman  (1997), \njulgue os itens seguintes. \nI  Liberman  (1972)  afirma  que  as  terapias  de  família \npodem  ser  formas  potentes  de  modificação  de \ncomportamento  porque  o  espaço  interpessoal  que \nembasa  a  mudança  é  o  encontro  do  dia  a  dia.  Há \nsucesso  quando  o  terapeuta  é  hábil  em  guiar  os \nmembros  da  família  para  mudar  seus  modos  de  se \nrelacionar uns com os outros. \nII  Caso  a  família  seja  um  sistema  de  troca  \ne  comportamentos  recíprocos  (inclusive \ncomportamento  afetivo),  a  terapia  de  família  só \nfuncionará  quando  todos  os  membros  atuarem \nsincronicamente. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "C", "j": "Apenas item I correto (Liberman/Ingberman - sucesso da terapia familiar comportamental depende da habilidade do terapeuta em guiar a mudanca dos modos de relacionamento). Item II e categorico (TODOS sincronicamente), incorreto."}, {"id": "1296917", "d": "psicologia", "a": ["Psicanálise", "Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca de transferência e contratransferência em processos \ngrupais segundo Zimerman (1997), julgue os itens a seguir. \nI  É consenso entre os psicoterapeutas que o fenômeno \nessencial  em  que  se  baseia  o  processo  de  qualquer \nterapia  psicanalítica  é  o  da  transferência. \nParticularmente  nas  grupoterapias,  as  transferências \naparecem de forma múltipla e cruzada. \nII  Na  atualidade,  acredita‐se  que,  em  todo  processo \nterápico,  haja  transferência,  mas  nem  tudo  deva  ser \nentendido e trabalhado como sendo transferência. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "C", "j": "Ambos itens corretos e relacionados (Zimerman): transferencia e fenomeno essencial das terapias psicanaliticas (I); o trabalho transferencial e seletivo - ha transferencia em todo processo, mas nao se interpreta tudo como tal (II)."}, {"id": "1296911", "d": "psicologia", "a": ["Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2018", "org": "CFP", "t": "", "e": "Em  relação  ao  processo  de  consentimento  informado,  é \ncorreto afirmar que", "alt": {"A": "ele  só  seja  necessário  em  situações  de  pesquisa  em \nsaúde, devendo ser preenchido em duas vias.", "B": "se trate exclusivamente de uma doutrina legal que se \nrefere à autorização para coleta de dados em situações \nde pesquisa em instituições de saúde.", "C": "se  trate  da  aceitação  pura,  simples e  irrevogável  dos \ntermos propostos pelo pesquisador.", "D": "seja um documento que se associa exclusivamente ao \ndireito de beneficência do potencial participante.", "E": "seja  um  documento  que  explicita  riscos,  benefícios, \ndireitos  e  deveres  do  participante  da  pesquisa  ou \nintervenção,  bem  como  o  caráter  voluntário  dessa \nparticipação."}, "g": "C", "j": "O TCLE e documento que explicita riscos, beneficios, direitos e deveres do participante de pesquisa ou intervencao, bem como o carater voluntario da participacao. Demais alternativas restringem indevidamente o documento a duas vias, saude, irrevogabilidade ou apenas beneficencia."}, {"id": "1296908", "d": "psicologia", "a": ["Psicoterapias", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Labadia  e  Castro  (2008)  referem  que  terapeutas  \ncognitivo‐comportamentais  vêm  utilizando  cada  vez  mais \nintervenções  com  pais  de  crianças  e  adolescentes  que \napresentam  problemas,  visando  obter  resultados  mais \nduradouros no tratamento. A respeito desse assunto, julgue \nos itens que se seguem. \nI  Isso  é  decorrente  do  fato  de  a  terapia  \ncognitivo‐comportamental  considerar  que  os \npensamentos e as crenças parentais possam influenciar \nas condutas dos filhos. \nII  No ciclo das relações entre os membros da família, um \npensamento,  um  comportamento  ou  uma  emoção \ndisfuncional pode levar a uma espiral negativa. \nIII  O  comportamento  disfuncional  da  criança  ou  do \nadolescente  é  resultado  do  comportamento \ndisfuncional dos pais. \nIV  Essa  abordagem  diminui  o  peso  do  papel  de  bode \nexpiatório  do  doente  identificado  e  possibilita  a \naprendizagem de novos papéis e funções parentais. \nV  A  intervenção  com  os  pais  pode  trazer  benefícios \nadicionais  para  o  paciente,  ajudando‐o  a  manter  os \nresultados eventualmente obtidos com o tratamento. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Quatro itens corretos: pensamentos parentais influenciam condutas dos filhos (I); espiral negativa (II); reducao do bode expiatorio (IV); beneficios adicionais para manutencao dos resultados (V). Item III erra ao reducir comportamento disfuncional do filho a uma RESULTANTE direta do dos pais."}, {"id": "1296907", "d": "psicologia", "a": ["Psicopatologia", "CID-10 e DSM", "Esquizofrenia e outros Transtornos Psicóticos", "Outros Transtornos", "Semiologia Psiquiátrica e Critérios de Normalidade"], "ano": "2018", "org": "CFP", "t": "", "e": "De acordo com Dalgalarrondo  (2008), para a construção do \ndelírio, podem contribuir vários fatores e vivências. O delírio\ndeve  ser  pensado  como  uma  construção  inserida  em  um \nprocesso  de  tentativa  de  reorganização  do  funcionamento \nmental.  Considerando  essas  informações,  julgue  os  itens \nseguintes. \nI  O  delírio  de  perseguição  consiste  em  o  indivíduo \nacreditar  que  é  vítima  de  um  complô  ou  está  sendo \nperseguido por pessoas importantes e(ou) poderosas. \nII  O delírio de controle trata‐se de a pessoa acreditar que \nestá  sob  controle  ou  sob  influência  de  uma  força  ou \nentidade externa. \nIII  O  indivíduo  com  delírio  de  influência  acredita  que  \npode  controlar  uma  entidade  poderosa  e  salvar  o \nmundo. \nIV  Em  casos  de  delírio  de  reforma,  o  indivíduo  se  sente \ndestinado  a  salvar  ou  a  revolucionar  o  mundo  ou  a \nsociedade dos contextos sociais. \nV  No delírio de infestação, a pessoa afirma que existem \npequenos animais infestando seu corpo. \nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Quatro itens corretos (I, II, IV, V) descrevem delirios de persecucao, controle, reforma e infestacao em Dalgalarrondo. Item III INVERTE delirio de influencia (que e ser influenciado/controlado por entidade, nao controlar uma)."}, {"id": "1296906", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Ludoterapia"], "ano": "2018", "org": "CFP", "t": "", "e": "Kaye  (1999)  esclarece  que,  no  trabalho  psicoterápico  de \norientação  analítica  com  crianças,  algumas  especificidades \ndevem  ser  consideradas.  Acerca  desse  assunto,  julgue  os \nitens a seguir. \nI  O psicoterapeuta infantil deve considerar que a criança \napresente  menor  capacidade  de  suportar  a  dor \npsíquica.\nII  O psicoterapeuta infantil deve considerar que a criança \npossa  ter  compreensão  limitada  sobre  os motivos  da \nindicação do tratamento e sobre seus benefícios.\nIII  O psicoterapeuta infantil deve considerar que a criança \nirá  transferir  para  o  terapeuta  todos  os  sentimentos \nque tenha em relação aos pais.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Itens I (menor capacidade de suportar dor psiquica) e II (compreensao limitada sobre tratamento) corretos. Item III erra pela categoricidade: 'TODOS os sentimentos' - a transferencia e seletiva, nao integral."}, {"id": "1296905", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Psicologia da Saúde", "Processo Saúde-Doença", "Saúde Coletiva", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Conforme Straub (2005), o comportamento do indivíduo em \nrelação  à  doença  (illness  behavior)  refere‐se  aos \ncomportamentos  da  pessoa  enferma,  buscando  definir  seu \nestado de saúde e identificar opções terapêuticas. A respeito \ndesse  tipo  de  comportamento,  assinale  a  alternativa \nincorreta.", "alt": {"A": "São  muitas  as  razões  que  levam  as  pessoas  a  não \nreconhecer  sintomas  potencialmente  perigosos  de \numa doença, inclusive o medo de que seu sintoma seja \nsinal de uma doença grave.", "B": "Existem  fatores psicológicos, como o  foco de atenção \ndo indivíduo em um dado momento, que interferem no \nreconhecimento dos sintomas existentes.", "C": "Estratégias  de  enfrentamento  de  indivíduos \nrepressores/moderadores, que tendem a estar atentos \nàs  informações  relacionadas  à  própria  saúde, \nfavorecem  um  processo  adaptativo  saudável  de \nautocuidado.", "D": "A representação da doença influencia a forma como os \nindivíduos  percebem  e  reagem  a  seus  sintomas, \npodendo  interferir  na  motivação  de  buscar  cuidado \nmédico.", "E": "Fatores  socioculturais,  perturbações  psicológicas, experiências prévias e perspectiva de vida estão entre os  fatores  que  podem  interferir  na  busca  de diagnóstico e tratamento para sintomas percebidos."}, "g": "C", "j": "Questao pede INCORRETA. Individuos REPRESSORES/MODERADORES tendem a EVITAR informacoes sobre a propria saude (defesa atencional), nao a estar atentos - logo nao favorecem autocuidado adaptativo. A alternativa C inverte o construto. Demais alternativas (medo, foco de atencao, representacao, fatores socioculturais) sao corretas."}, {"id": "1296904", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Saúde Coletiva", "Doenças Crônico-Degenerativas", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2018", "org": "CFP", "t": "", "e": "Em relação à atuação do psicólogo em saúde de acordo com \nStraub (2005), julgue os próximos itens. \nI  É  importante  identificar  os  fatores  psicológicos, \ncomportamentais e sociais associados à ocorrência e à \nmanutenção das doenças, especialmente as de caráter \ncrônico.\nII  A promoção e a manutenção da saúde orientam muitas \ndas  principais  pesquisas  associadas  à  intervenção  do \npsicólogo em saúde. \nIII A  quantidade  e  a  diversidade  de  intervenções  em \npsicologia da saúde têm aumentado nos últimos anos \npara ajudar as pessoas a enfrentar os subprodutos das \ndoenças crônicas, como ansiedade e depressão.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Todos os itens corretos: identificacao de fatores psicossociais associados a doencas cronicas (I); promocao/manutencao da saude como eixo de pesquisas (II); aumento de intervencoes para enfrentamento de subprodutos cronicos como ansiedade/depressao (III)."}, {"id": "1296900", "d": "psicologia", "a": ["Psicoterapias", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "A terapia comportamental na atualidade é reconhecida como \nprática clínica que se preocupa com atestar sua eficiência no \ntratamento de diversas dificuldades psicossociais. A respeito \ndesse tema, julgue os itens que se seguem. \nI Entre as principais correntes terapêuticas vinculadas a \nesse modelo, estão a terapia comportamental clássica, \na terapia cognitivo‐comportamental e a análise clínica \ndo comportamento.\nII  Selecionismo  refere‐se  a  um  aspecto  essencial  dos \noperantes comportamentais.\nIII  O  externalismo  coloca  ênfase  nas  variáveis  do \nambiente para abordar fenômenos comportamentais.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "Todos os itens corretos: correntes terapeuticas (terapia comportamental classica, TCC, analise clinica do comportamento) em I; selecionismo como aspecto dos operantes (II); externalismo com enfase em variaveis ambientais (III)."}, {"id": "1296899", "d": "psicologia", "a": ["Behaviorismo", "Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Terapia familiar", "Grupos Terapêuticos"], "ano": "2018", "org": "CFP", "t": "", "e": "Com  o  acúmulo  de  evidências  a  respeito  da  eficácia  das \ndiferentes  abordagens  e  formas  de  psicoterapia,  foram \nconstruídos  critérios  de  indicação  e  contraindicação  para \nalgumas formas de tratamento psicoterápico. Cordioli (2008) \nsumariza  esses  critérios  em  sua  obra  Psicoterapias  – \nAbordagens Atuais. Sendo assim, assinale a alternativa que \napresenta  conteúdo  que  não  corresponde  à  proposta  do \nautor ao compilar as evidências disponíveis.", "alt": {"A": "A psicoterapia breve de apoio está indicada em crises \nagudas e emergências.", "B": "A terapia comportamental é contraindicada para casos \nde transtorno de personalidade esquizoide e depressão \ngrave.", "C": "A  terapia  de  grupo  é  contraindicada  para  indivíduos \ncom fobia social grave.", "D": "A terapia cognitiva é indicada para depressões leves e \nmoderadas e transtornos de personalidade.", "E": "A  terapia  de  casal  e  de  família  é  contraindicada  em \nsituações de conflitos intergeracionais."}, "g": "C", "j": "A terapia de casal e familia E INDICADA (nao contraindicada) em conflitos intergeracionais - e justamente um de seus contextos clinicos centrais. Demais alternativas (PB de apoio, terapia comportamental, terapia de grupo, terapia cognitiva) reproduzem corretamente as indicacoes/contraindicacoes em Cordioli."}, {"id": "1296898", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Cordioli  (2008)  afirma  que  determinadas  atitudes  do \nterapeuta  facilitam  a  criação  do  vínculo  terapêutico  com  o \npaciente.  Com  base  nessa  informação,  julgue  os  itens \nsubsequentes. \nI  O  terapeuta  deve  ter  disponibilidade  de  tempo  para \nque o paciente possa relatar seus problemas.\nII  O  terapeuta  deve  oferecer  um  ambiente  com \nprivacidade para as sessões.\nIII O  terapeuta  deve  emitir  cuidadosamente  seus \njulgamentos para não ferir os sentimentos do paciente.IV O terapeuta deve ter maturidade para não se perturbar \ncom as revelações do paciente por mais assustadoras \nque sejam.\nV O terapeuta deve disfarçar e procurar mostrar atenção, \ncuriosidade e interesse pelos assuntos abordados pelo \npaciente.\nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Quatro itens corretos (I-IV): disponibilidade, privacidade, cuidado nos julgamentos e maturidade. Item V erra ao defender que o terapeuta deva 'DISFARCAR' atencao/curiosidade - o vinculo demanda autenticidade, nao simulacao."}, {"id": "1296897", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Todas  as  abordagens  psicoterápicas  estabelecem  um \nconjunto de regras, combinações e arranjos para direcionar o \nprocesso  psicoterápico.  Algumas  dessas  regras  variam  de \nacordo  com  a  abordagem,  mas  o  chamado  “contrato \nterapêutico”  normalmente  tem  aspectos  em  comum, \nindependentemente do modelo adotado. Em relação a esses \naspectos comuns na quase totalidade das abordagens, julgue \nos itens que se seguem. I  O contrato é estabelecido de forma explícita no início \ndo processo psicoterápico.\nII  O  contrato  terapêutico  explicita  regras  objetivas  de \nconduta  do  terapeuta  e  do  paciente,  como,  por \nexemplo,  frequência  das  sessões  e  formas  de \ncomunicação com o terapeuta. \nIII  Os objetivos e as metas do processo, assim como sua \nduração  máxima,  são  estabelecidos  pelo  contrato \nterapêutico. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Itens I (contrato explicito no inicio) e II (regras objetivas de conduta - frequencia, comunicacao) corretos. Item III erra ao incluir DURACAO MAXIMA como aspecto universal - apenas algumas modalidades (PB) fixam duracao, e nem sempre se trata de teto rigido."}, {"id": "1296896", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Segundo  Eizeirick,  Liberman  e  Costa  (2008,  apud  Cordioli, \n2008),  o  destino  de  cada  psicoterapia  resulta  das \ncaracterísticas  pessoais  do  paciente  e  do  terapeuta  e  das \nreedições  de  vivências  passadas  que  ambos  trazem  para  a \nsituação atual, única e particular, que eles estabelecem entre \nsi.  Considerando  essa  informação,  é  correto  afirmar  que  o \nveículo  por  meio  do  qual  se  processem  os  tratamentos \npsicoterápicos seja o(a)", "alt": {"A": "aliança terapêutica.", "B": "transferência.", "C": "relação terapêutica.", "D": "contratransferência.", "E": "insight."}, "g": "C", "j": "O veiculo por meio do qual se processam os tratamentos psicoterapicos e a RELACAO TERAPEUTICA - dimensao que abrange aliança, transferencia, contratransferencia e insight como elementos seus, mas e mais ampla."}, {"id": "1296894", "d": "psicologia", "a": ["Psicopatologia", "Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Exames Mentais e Funções Psíquicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Pesquisas  recentes  em  neurociência  trazem  importantes \naportes  para  a  compreensão  de  aspectos  associados  aos \nprocessos  psicoterápicos.  Considerando  essa  informação, \njulgue os próximos itens. I  O  impacto  de  variáveis  ontogenéticas  pode  ficar \narmazenado  sob  a  forma  de  memórias  explícitas  ou \nimplícitas.\nII  Todas  as  formas  de  psicoterapia  têm  como  objetivo \nalterar  processos  relacionados  a  esses  dois  tipos  de \nmemória.\nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "C", "j": "Ambos os itens corretos e relacionados: experiencias ontogeneticas se armazenam como memorias explicitas/implicitas (I); todas as psicoterapias visam alterar processos relacionados a esses dois tipos de memoria (II), constituindo eixo neurocientifico unificador."}, {"id": "1296893", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Para Cordioli (2008), o terapeuta deve avaliar clinicamente a \ncapacidade  do  paciente  de  estabelecer  uma  boa  aliança \nterapêutica.  Considerando  essa  informação,  assinale  a \nalternativa que não apresenta um critério para tal fim.", "alt": {"A": "conseguir estabelecer  um bom  vínculo afetivo  com  o \nterapeuta", "B": "apresentar bom grau de flexibilidade psicológica", "C": "aderir às tarefas terapêuticas propostas", "D": "ter poucas expectativas em relação ao tratamento", "E": "procurar cumprir o contrato terapêutico"}, "g": "D", "j": "Ter POUCAS expectativas em relacao ao tratamento NAO e criterio favoravel para boa alianca - na verdade, sao as expectativas positivas e realistas que sustentam o engajamento. Demais alternativas (vinculo, flexibilidade, adesao a tarefas, contrato) sao criterios validos em Cordioli."}, {"id": "1296892", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Gestalt"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca da Gestalt‐terapia, julgue os itens a seguir. I  O  trabalhar  no  “aqui  e  agora”,  característica  da  \nGestalt‐terapia,  é  resultado  da  influência  da \nfenomenologia.\nII  Na Gestalt‐terapia, o terapeuta observa, mas faz parte \nda  relação,  o  que  é  denominado  de  “implicação  do \nterapeuta”.\nIII  Dá  ao  paciente  a  possibilidade  de  internalizar  seus \nmedos  e  anseios  em  um  processo  de  alternância  de \npercepção de figura e fundo.\nIV  A  cadeira  quente  possibilita  reviver \nexperimentalmente uma situação no setting protegido.\nV  Na  Gestalt‐terapia,  o  experimento  visa  aumentar  a \ncapacidade  do  indivíduo  de  estar  consciente  de  seu \nmomento.\nA quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "C", "j": "Quatro itens corretos sobre Gestalt-terapia: aqui-agora via fenomenologia (I); implicacao do terapeuta (II); cadeira quente como tecnica vivencial (IV); experimento como ampliacao de consciencia (V). Item III adota descricao imprecisa sobre figura-fundo."}, {"id": "1296891", "d": "psicologia", "a": ["Behaviorismo", "Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2018", "org": "CFP", "t": "", "e": "Julgue os itens que se seguem. I  A  análise  funcional  do  comportamento  busca \nidentificar  os  determinantes  da  ocorrência  de \ncomportamentos a partir de paradigmas (respondente \ne operante).\nII  A  análise  funcional  do  comportamento  possibilita \nprever  em  que  circunstâncias  determinados  padrões \nde comportamento tendem a surgir e se repetir.\nIII  A  análise  funcional  do  comportamento  possibilita \npropor  estratégias  de  intervenção  em  relação  aos \ncomportamentos estudados.\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Todos os itens corretos: analise funcional do comportamento identifica determinantes via paradigmas respondente/operante (I); preve circunstancias e repeticoes (II); fundamenta estrategias de intervencao (III)."}, {"id": "1296888", "d": "psicologia", "a": ["Psicoterapias", "Avaliação Psicológica", "Teorias e Técnicas Psicoterápicas", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "No  que  concerne  à  entrevista  devolutiva  no  processo \npsicodiagnóstico  segundo  Arzeno  (2003),  julgue  os  itens \nsubsequentes.     I   O  psicólogo  trabalha  constantemente  com  a \ntransferência e a contratransferência.  II  A  devolução  de  informações  é  o  passo  que  mais \nmanifesta a experiência clínica do profissional.\n  III Em situações de psicodiagnóstico infantil, é o momento \nde  transmitir  os  resultados,  de  forma  organizada  e \ndosada, somente para os responsáveis.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Itens I (transferencia/contratransferencia) e II (devolucao como expressao da experiencia clinica) corretos em Arzeno. Item III erra ao restringir a transmissao SOMENTE aos responsaveis - no psicodiagnostico infantil, a crianca tambem recebe devolutiva adaptada."}, {"id": "1296886", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere à proposta de Arzeno (2003) em relação ao processo psicodiagnóstico, julgue os próximos itens.     I  Por  ser  um  processo  estruturado,  prescinde  de  um enquadre.  II Exige  do  profissional  a  escolha  adequada  dos instrumentos e  das  situações  de  avaliação  de  acordo com as características do consultante e sua queixa.  III Em  instituições,  o  psicodiagnóstico  deve  ter  seu enquadre  e  sua  rotina  estabelecidos  pelas  normas institucionais  para  garantir  uniformidade  nos procedimentos.    Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Apenas os itens I e III estão certos"}, "g": "B", "j": "Apenas item II correto - escolha adequada de instrumentos conforme caracteristicas do consultante e queixa. Item I e falso (psicodiagnostico EXIGE enquadre); item III tambem e falso (enquadre e responsabilidade tecnica do psicologo, nao das normas institucionais)."}, {"id": "1296862", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Estudiosos  da  psicologia  do  esporte  têm  dado  atenção \nespecial  ao  conceito  de  fair  play,  levando  em  conta  as \ntransformações que ocorrem nas regras e condutas para os \npraticantes de diversas modalidades. No que se refere a esse \nassunto, julgue os próximos itens. \nI  O fair play não formal está relacionado diretamente ao \ncumprimento  de  regras  e  regulamentos  pelo \nparticipante  da  competição,  em  princípio,  sendo \nconsiderado como uma “norma/obrigação”. \nII  O  fair  play  formal  relaciona‐se  ao  comportamento \npessoal e aos valores morais do atleta e dos envolvidos \nno mundo esportivo. Possui um caráter subjetivo. \nIII  Rubio  (2001)  aponta  que,  de  acordo  com  os  novos \nvalores  esportivos  (denominado  pós‐olimpismo),  o \namadorismo foi abolido e o fair play tem‐se adequado \nà  necessidade  de  convivência  com  patrocinadores, \nespaço comercial e novas regulamentações.  \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "B", "j": "Apenas item III correto - Rubio (2001) descreve pos-olimpismo com aboliçao do amadorismo e adaptacao do fair play. Itens I e II INVERTEM a distincao: fair play FORMAL e regras/regulamentos; NAO FORMAL e valores morais subjetivos."}, {"id": "1296860", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Quanto  à  relação  entre  técnico  e  atleta,  julgue  os  itens \nseguintes. \nI  Há  uma  única  linha  de  pesquisa,  com  apenas  um \nreferencial  teórico  e  metodológico,  sobre  como \nestudar esse fenômeno e os aspectos relacionados ao \ntema na psicologia esportiva. \nII  O estilo de técnico consultivo diz respeito àquele que \nconsulta  todos ou alguns dos atletas, embora reserve \npara  si  a  decisão  final,  levando  ou  não  em  conta  as \nsugestões recebidas. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "D", "j": "Apenas item II correto - estilo consultivo de tecnico (consulta atletas mas reserva a decisao final). Item I e falso ao afirmar UNICA linha de pesquisa/referencial sobre relacao tecnico-atleta - existem multiplas abordagens."}, {"id": "1296859", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "A  respeito  da  atuação  do  psicólogo  em  projetos  sociais \nesportivos, julgue os seguintes itens. \nI  Na atualidade,  como  característica  do  capitalismo, as \nrelações  humanas  são  competitivas.  Entretanto,  o \nesporte  não  reproduz  valores  do  capitalismo, \nespecialmente  nos  projetos  ofertados  pelo  terceiro \nsetor, que visam apenas à inclusão social. \nII  O  psicólogo  do  esporte,  como  cidadão  que  é,  deve \nprocurar  resgatar  a  dignidade  humana,  com  o \ncompromisso  ético  de  favorecer  a  reflexão  das \nimplicações  da  reprodução  de  valores  capitalistas  e \nhegemônicos no esporte. \nAssinale a alternativa correta.", "alt": {"A": "Os dois itens estão certos e relacionados.", "B": "Os dois itens estão certos, mas não estão relacionados.", "C": "Apenas o item I está certo.", "D": "Apenas o item II está certo.", "E": "Nenhum item está certo."}, "g": "D", "j": "Apenas item II correto - o psicologo do esporte deve atuar com compromisso etico de resgate da dignidade humana. Item I e falso ao afirmar que o esporte NAO reproduz valores capitalistas - o esporte espelha sim e reproduz dinamicas competitivas da sociedade."}, {"id": "1296855", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "É uma preparação fisiológica e psicológica geral, variando de \num continuum de sono profundo a uma intensa agitação o(a)", "alt": {"A": "ansiedade.", "B": "estresse.", "C": "ativação.", "D": "motivação.", "E": "autoconfiança."}, "g": "C", "j": "A ATIVACAO (arousal) e a preparacao fisiologica e psicologica geral, variando em continuum do sono profundo a intensa agitacao - conceito chave em psicologia esportiva. Ansiedade, estresse, motivacao e autoconfianca tem definicoes distintas."}, {"id": "1296854", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação à abordagem sanduíche no ambiente esportivo, \nassinale a alternativa incorreta.", "alt": {"A": "A  abordagem  sanduíche  é  uma  técnica  de  oferecer \nfeedback construtivo de maneira sensível e efetiva.", "B": "O ponto‐chave da abordagem sanduíche é a instrução \norientada  ao  passado  para  que  a  pessoa  a  utilize  da \npróxima vez.", "C": "A  parte  final  do  sanduíche  é  um  cumprimento  para \najudar  a  construir  a  confiança  e  a  harmonia,  mesmo \nque tenha ocorrido um erro.", "D": "Infelizmente  muitas  pessoas  recebem  críticas  como \nameaças e, por isso, tal abordagem faz‐se útil.", "E": "Um  exemplo  de  crítica  realizada  com  base  nessa \nabordagem seria: “Você realmente está se esforçando. \nDa próxima vez, tente ir mais devagar e não se antecipe \npara  pegar  a  bola.  Você  está  indo  bem.  Continue \nassim”."}, "g": "B", "j": "Questao pede INCORRETA. A abordagem sanduiche orienta-se ao FUTURO (proxima vez), nao ao passado - o ponto-chave e instruir para mudancas futuras, intercalando elogio. Demais alternativas descrevem corretamente a tecnica."}, {"id": "1296852", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "De acordo com Weinberg e Gould (2001), algumas razões são \napontadas  pelas  pessoas  para  praticarem  atividade  física. \nSendo assim, assinale a alternativa que não apresenta uma  delas.", "alt": {"A": "controle de peso", "B": "redução no estresse e na depressão", "C": "redução do risco de doenças cardiovasculares", "D": "falta de motivação", "E": "socialização"}, "g": "D", "j": "Falta de motivacao NAO e razao para praticar atividade fisica - e justamente a barreira a pratica. Demais alternativas (controle de peso, reducao de estresse/depressao, prevencao cardiovascular, socializacao) sao motivacoes para a pratica em Weinberg & Gould."}, {"id": "1296851", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Acerca de liderança no ambiente esportivo, é correto afirmar que", "alt": {"A": "o  modelo  multidimensional  de  liderança  no  esporte\nconceitualize a liderança como um processo inato.", "B": "uma das características de bons líderes no esporte seja criar um ambiente de apoio por meio de  práticas coercitivas", "C": "a efetividade do estilo de liderança de um indivíduo seja fruto de sua adaptação às situações.", "D": "exista  um  conjunto  de  traços  de  personalidade  que \nassegurem  que  uma  pessoa  possa  se  tornar  um  bom \nlíder.  Entre  tais  características,  estão  lealdade, \nflexibilidade e franqueza.", "E": "Barrow  (1977),  citado  por Weinberg &  Gould  (2001), \nafirme  que  liderança  possa  ser  definida  como  um \nsentimento  que  é  capaz  de  influenciar  indivíduos  e \ngrupos."}, "g": "C", "j": "A efetividade do estilo de lideranca esportiva e fruto da ADAPTACAO as situacoes (teoria situacional/multidimensional de Chelladurai). A erra ao caracterizar lideranca como inata; B defende coercitividade; D atribui tracos fixos; E confunde lideranca com sentimento."}, {"id": "1296850", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere aos aspectos subjetivos e de identidade no \nesporte de alto rendimento, julgue os próximos itens. \nI  Em  sua  atuação  no  contexto  de  alto  rendimento,  é \nimportante  que  o  psicólogo  pense  nesse  esporte \nassociado à espetacularização e à importância dada a \nele pela mídia. \nII  Culturalmente,  no  esporte  de  alto  rendimento, \nqualquer  outro  resultado  que  não  seja a  vitória  ou  o \ndesempenho máximo tem valor igual.\nIII  A  prática  esportiva  no  alto  rendimento  geralmente \nrelega as virtudes dos sujeitos a um segundo plano.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Itens I (importancia da espetacularizacao e midia) e III (virtudes em segundo plano no alto rendimento) corretos. Item II e falso pela categoricidade ('VALOR IGUAL' a qualquer resultado que nao seja vitoria) - cultura do alto rendimento valoriza assimetricamente vitoria/desempenho maximo."}, {"id": "1296849", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação ao treinamento de habilidades psicológicas (THP), julgue os itens subsequentes. I  Em relação ao THP, não há diferença entre habilidades \npsicológicas e métodos psicológicos. \nII  O THP serve apenas para melhorar o desempenho de \natletas. \nIII  Um  problema  comum  na  implementação  de  um \nprograma  de  THP  é  a  falta  de  tempo  alegada  por \ntécnicos. \nIV  Na fase de educação do THP, o psicólogo deve focar em \nestratégias  e  técnicas  para  aprendizagem  das \ndiferentes habilidades psicológicas. \nV  Para melhores resultados, o ideal é implementar o THP \nfora de temporada, quando há mais tempo para treinar \nas habilidades psicológicas. A quantidade de itens certos é igual a", "alt": {"A": "1.", "B": "2.", "C": "3.", "D": "4.", "E": "5."}, "g": "B", "j": "Dois itens corretos (III falta de tempo dos tecnicos; V implementacao fora de temporada como ideal). Itens I (sem diferenca entre habilidades e metodos), II (apenas para desempenho) e IV (fase educacao focada em tecnicas) sao falsos."}, {"id": "1296848", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "O uso de esteroides anabolizantes por parte dos atletas tem como objetivo", "alt": {"A": "reduzir a fadiga e aumentar o estado de alerta.", "B": "reduzir a dor por conta dos treinamentos.", "C": "bloquear  respostas  estimulatórias  em  modalidades \ncomo tiro, por exemplo.", "D": "perder peso temporariamente.", "E": "melhorar força e resistência."}, "g": "E", "j": "Esteroides anabolizantes sao utilizados por atletas com objetivo de melhorar FORCA e RESISTENCIA (sintese proteica, hipertrofia muscular). Demais alternativas descrevem efeitos de outras substancias (estimulantes, analgesicos, beta-bloqueadores, diureticos)."}, {"id": "1296847", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "O termo agressão pode ser utilizado de diferentes formas no \nesporte e no exercício. Há quatro critérios para um ato  ser \nconsiderado como agressão/violência. Sendo assim, assinale \na alternativa que não apresenta um desses critérios.", "alt": {"A": "ser um comportamento e não um sentimento", "B": "envolver danos ou ferimentos", "C": "envolver intenção", "D": "ser dirigida a outro ser vivo", "E": "envolver somente dano físico"}, "g": "E", "j": "Os quatro criterios para agressao incluem: ser comportamento, envolver danos/ferimentos (fisicos OU psicologicos), envolver intencao e ser dirigida a outro ser vivo. Restringir 'SOMENTE A DANO FISICO' nao integra os criterios classicos."}, {"id": "1296845", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Com relação ao desenvolvimento psicológico das crianças por meio do esporte, assinale a alternativa incorreta.", "alt": {"A": "A afiliação é um motivo importante para que as crianças pratiquem esportes.", "B": "Segundo Weinberg e Gould (2001), os níveis de ansiedade em crianças durante competições esportivas geralmente não são significativamente maiores que os encontrados durante outras atividades  avaliativas da infância. Mesmo assim, algumas crianças podem sentir‐se estressadas ou ansiosas em situações específicas relacionadas ao esporte.", "C": "O burnout é um caso especial de abandono do esporte, no qual um atleta jovem interrompe seu envolvimento na atividade em resposta ao estresse crônico.", "D": "Quando uma criança desiste de uma prática esportiva específica, ela irá interromper seu  envolvimento em todos os esportes e exercícios.", "E": "Uma forma de ajudar crianças muito estressadas a lidar com o problema  seria, por exemplo, fazer exercícios envolvendo estratégias físicas e concretas, como dar a elas uma bolinha dentro da qual possam colocar suas preocupações."}, "g": "D", "j": "Questao pede INCORRETA. Desistir de uma pratica esportiva especifica NAO implica interromper envolvimento em todos os esportes/exercicios - criancas costumam migrar entre modalidades. A alternativa D inverte essa logica."}, {"id": "1296844", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "No que se refere ao exercício e ao bem‐estar psicológico, é correto afirmar que", "alt": {"A": "haja uma relação de causa e efeito entre a prática regular de atividades físicas e a redução na ansiedade e na depressão.", "B": "a melhora na autoestima e no autoconceito seja um mecanismo psicológico apontado como efeito positivo do exercício físico.", "C": "o clímax do corredor seja uma sensação de euforia, geralmente inesperada, e de bem-estar aumentado.", "D": "a maioria dos escritores use o termo vício, na literatura de psicologia do exercício, para se referir  a um envolvimento intenso no exercício.", "E": "um efeito que parece maximizar a efetividade da prática de atividade física sobre a depressão  seja a ausência de competição interpessoal."}, "g": "C", "j": "O 'climax do corredor' (runner's high) e a sensacao de euforia geralmente inesperada e bem-estar aumentado durante exercicio prolongado, associada a endorfinas/endocanabinoides. Demais alternativas formulam afirmacoes categoricas, incorretas ou imprecisas."}, {"id": "1296842", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Entre os motivos de participação em esportes infantojuvenis \napontados por Gould & Horn (1984), citados por Weinberg & \nGould (2001), a maioria das crianças pratica esportes porque \ndeseja, em primeiro lugar,", "alt": {"A": "competir.", "B": "permanecer em forma.", "C": "fazer novas amizades.", "D": "melhoras as habilidades.", "E": "se divertir."}, "g": "E", "j": "Em Gould & Horn (1984), a principal motivacao das criancas para a pratica esportiva e SE DIVERTIR - achado classico da psicologia do esporte infantil. Demais motivacoes (habilidades, amizades, forma, competir) sao secundarias na hierarquia."}, {"id": "1296841", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito da participação de crianças no esporte, assinale a alternativa incorreta.", "alt": {"A": "A  alta  exigência e cobrança  dos  pais na carreira \nesportiva pode promover uma atmosfera de  regras rígidas e expectativas irreais, levando a uma carreira malsucedida.", "B": "A natureza do esporte em que a criança está envolvida \né  definida  por  uma  série  de  relações.  Toda  prática \noferecida às crianças e aos adolescentes é  permeada \npor  ações  adultas  –  dos  pais,  dos  dirigentes,  dos \nprofessores, dos técnicos ou dos árbitros.", "C": "Crianças  com  baixas  percepções  de  suas  capacidades \nesportivas geralmente não desistem e têm a iniciativa \nde praticar algum esporte.", "D": "Embora  a  maioria  das  crianças  desista  do  esporte \ndevido a interesses em outras atividades, há também \naquelas que desistem por razões negativas, como falta \nde diversão, muita pressão ou antipatia pelo técnico.", "E": "Contrariamente  à  crença  popular,  a  participação  em \nesportes organizados não é automaticamente benéfica \npara as crianças."}, "g": "C", "j": "Questao pede INCORRETA. Criancas com BAIXAS percepcoes de capacidade ESPORTIVA tendem a desistir ou nao iniciar a pratica - a alternativa C inverte essa relacao. Demais alternativas descrevem corretamente cobrança parental, natureza relacional do esporte, razoes de desistencia e nao-automaticidade do beneficio."}, {"id": "1296839", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Petitpas e Danish (1995), citados por Weinberg & Gould (2001), identificaram algumas reações psicológicas de má adaptação às lesões esportivas, sendo elas", "alt": {"A": "reação de alarme; fase de resistência; fase de adaptação; e fase de exaustão.", "B": "perfeccionismo; senso de direção; integridade; e disposição.", "C": "apatia; megalomania; euforia; e ansiedade.", "D": "ansiedade; irritabilidade; tranquilidade; e aumento da motivação.", "E": "perda de identidade; medo e ansiedade; falta de confiança; e redução no desempenho."}, "g": "E", "j": "Petitpas e Danish (1995) identificam como reacoes psicologicas de ma adaptacao a lesoes esportivas: perda de identidade, medo e ansiedade, falta de confianca e reducao do desempenho. Demais alternativas confundem com sindrome de adaptacao (Selye) ou listas genericas."}, {"id": "1296838", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta uma atitude que não é esperada de psicólogos que  trabalhem com atletas lesionados.", "alt": {"A": "desenvolver vínculo com o atleta lesionado", "B": "incentivar atitudes do tipo “aja com firmeza e dê 110%” (“no pain, no gain”)", "C": "ensinar habilidades psicológicas específicas de controle emocional e cognitivo", "D": "ensinar a lidar com retrocessos na recuperação", "E": "incentivar o apoio social"}, "g": "B", "j": "Incentivar 'aja com firmeza, no pain no gain' NAO e atitude esperada do psicologo com atletas lesionados - pode agravar a lesao e prejudicar a recuperacao. Demais alternativas (vinculo, controle emocional, lidar com retrocessos, apoio social) sao boas praticas."}, {"id": "1296837", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "A  respeito  dos  fatores  psicológicos  nas  lesões  esportivas, \njulgue os itens seguintes. \nI  As  cinco  fases  emocionais  após  uma  lesão  são: \nnegação;  raiva;  negociação;  depressão;  aceitação;  e \nreorganização. Todos os atletas lesionados passam por \ntodos os estágios na mesma sequência e intensidade.\nII  O  nível  de  estresse  foi  identificado  como  um  dos \nfatores  psicológicos  mais  relacionados  a  lesões \nesportivas  e  deve  ser  entendido  como  uma  resposta \ncomplexa  que  pode estar antes,  durante e depois  de \numa lesão.\nIII  Há  dez  sinais  que  permitem  identificar  um  ajuste \npsicológico  potencialmente  problemático  do  atleta  à \nlesão,  entre  os  quais  estão:  sentimentos  de  raiva  e \nconfusão;  sentimento  de  culpa  por  não  poder \ncolaborar com a equipe; e retorno precoce e repetitivo \nao esporte, levando à reincidência da lesão.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "E", "j": "Itens II (estresse como fator complexo antes/durante/depois) e III (dez sinais de ajuste problematico) corretos. Item I e categorico ('TODOS atletas... mesma sequencia e intensidade') - falso, pois as fases sao individuais e variaveis."}, {"id": "1296836", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Nos casos em que o psicólogo já encontra o atleta com uma  lesão desportiva, há algumas condutas e técnicas que podem  ser adotadas. O discurso interior positivo é uma técnica muito utilizada para", "alt": {"A": "ajudar o atleta a visualizar uma meta de reabilitação a ser atingida.", "B": "aprender a controlar a dor originada pela lesão que provoca reações emocionais no atleta.", "C": "que os atletas aprendam a bloquear pensamentos negativos e substitui‐los por pensamentos  reais e positivos.", "D": "diminuir o estresse que traz o período de recuperação e o nível geral de tensão psicológica.", "E": "tornar o atleta consciente de sua tensão muscular e de reações em outros sistemas nervosos autônomos."}, "g": "C", "j": "O discurso interior positivo (self-talk positivo) e tecnica para que atletas aprendam a BLOQUEAR pensamentos negativos e SUBSTITUI-LOS por pensamentos reais e positivos - reestruturacao cognitiva aplicada ao esporte."}, {"id": "1296835", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "A respeito de grupos e equipes esportivas, julgue os itens que \nse seguem. I Uma  liderança  efetiva  deverá  ser  respaldada  pela admiração e pelo respeito que os atletas têm por seu líder, sendo necessário que este conquiste o  respeito de seus liderados para ter sua autoridade reconhecida \nperante eles, e não apenas o cargo designado. Nesse \nsentido,  o  capitão  de  um  time,  por  exemplo,  nem \nsempre será um líder reconhecido e efetivo.\nII Segundo Weinberg & Gould  (2001),  não há  diferença \nentre dirigente e líder.\nIII Sugere‐se  que  os  treinadores  alternem  seu  estilo  de \nliderança, adaptando‐o conforme a necessidade. \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "Itens I (lideranca efetiva requer respeito/admiração) e III (alternancia de estilos conforme necessidade) corretos. Item II inverte Weinberg & Gould - HA diferenca entre dirigente (papel formal) e lider (influencia/respeito)."}, {"id": "1296833", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "A  respeito  do  comportamento  e  das  responsabilidades  dos \npais no ambiente esportivo, assinale a alternativa incorreta.", "alt": {"A": "De acordo com Weinberg e Gould  (2001), embora os \ncomportamentos negativos dos pais nunca venham a \nser  completamente  eliminados  do  esporte \ninfantojuvenil,  muito  pode  ser  conseguido  \neducando‐os e melhorando as linhas de comunicação \nentre pais, técnicos e organizadores.", "B": "Com relação à conduta dos pais no ambiente esportivo, \né  esperado  e  permitido  que  aconselhem  o  técnico \nsobre como deve ser sua atuação.", "C": "Entre  as  responsabilidades  dos  pais,  é  esperado  que \najudem  seus  filhos  a  estabelecer  metas  realistas  de \ndesempenho.", "D": "Durante  os  jogos  e  treinos,  é  esperado  que  os  pais \ncontrolem  suas  emoções  e  incentivem  emoções \npositivas nos filhos.", "E": "Espera‐se que os pais ajudem os técnicos, em situações \nespecíficas  de  treinamento  ou  partidas,  quando \nsolicitados."}, "g": "B", "j": "Questao pede INCORRETA. NAO se espera que pais aconselhem o tecnico sobre sua atuacao - cada um tem seu papel especifico, e essa interferencia compromete a relacao tecnica. Demais alternativas (educacao, metas realistas, controle emocional, ajuda quando solicitada) sao adequadas."}, {"id": "1296832", "d": "psicologia", "a": ["Psicologia do Esporte"], "ano": "2018", "org": "CFP", "t": "", "e": "Weinberg & Gould  (2001) afirmam que há quatros estágios \npara  que  um  grupo  se  torne  uma  equipe.  Assinale  a \nalternativa que apresenta esses estágios.", "alt": {"A": "proximidade, diferenciação, similaridade e coesão", "B": "apoio pela escuta, apoio emocional, apoio de \nconfirmação de realidade e apoio de reconhecimento da tarefa", "C": "formação, agitação, normalização e atuação", "D": "formação, proximidade, coesão e atuação", "E": "proximidade, formação, apoio de confirmação e atuação"}, "g": "C", "j": "Os quatro estagios para um grupo se tornar equipe (Tuckman, citado por Weinberg & Gould): formacao (forming), agitacao (storming), normalizacao (norming) e atuacao (performing). Demais alternativas misturam categorias de apoio social ou inventam fases."}, {"id": "1278668", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "O bullying é considerado como uma das formas de violência mais acentuadas por causa das mídias sociais. Com relação a esse assunto, assinale a alternativa correta.", "alt": {"A": "É  um  fenômeno  que  pouco  interfere  na  aprendizagem  e  no  desenvolvimento  cognitivo,  sensorial  e  emocional. \ndas crianças e dos adolescentes.", "B": "É um fenômeno natural, que auxilia os alunos a demarcar seu espaço tanto no ambiente escolar quanto na vida.", "C": "É caracterizado quando um aluno mais forte passa a perseguir, excluir e ridicularizar um colega, mesmo que seja uma única \nvez, demonstrando, com essa atitude, comportamento segregacionista.", "D": "Corresponde a um conjunto de atos agressivos e sistemáticos contra criança ou adolescente, sem motivação aparente, mas \nde forma intencional, protagonizado por uma ou mais pessoas.", "E": "É uma produção da sociedade moderna, a qual devemos conceber como própria do seu tempo."}, "g": "D", "j": "Bullying corresponde a conjunto de atos agressivos e SISTEMATICOS contra crianca/adolescente, sem motivacao aparente e de forma INTENCIONAL, por uma ou mais pessoas. C erra ao admitir 'unica vez'; outras alternativas negam impacto, naturalizam ou idealizam o fenomeno."}, {"id": "1278664", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a substâncias"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "O  consumo  de  bebidas  alcoólicas  é  comum  e  considerado como  natural  em  diferentes  situações.  Porém,  enquanto algumas pessoas podem fazer uso recreativo dessas bebidas ao  longo  da  vida, sem  nenhum  indício  de  adoecimento, outras pessoas desenvolvem um transtorno conhecido como dependência  alcoólica  ou  alcoolismo.  Considerando  essas informações, assinale a alternativa que apresenta a resposta comportamental que caracteriza esse transtorno.", "alt": {"A": "uso  de  bebidas  restrito  a  situações  festivas,  em \nquantidades  semelhantes  às  de  quando  o  uso  foi \niniciado, com a obtenção do mesmo efeito", "B": "uso  de  bebida  de  cinco  a  sete  vezes  por  semana, \nmesmo  que a  rotina  habitual  de  trabalho  ou estudos \nseja mantida", "C": "uso  de  bebida  em  quantidade  crescente  para  a obtenção do mesmo efeito de quando o uso foi iniciado", "D": "uso de bebida rotineiro, salvo nas situações em que a bebida  seja  incompatível  com  alguma  atividade desejada", "E": "uso de bebida em situações sociais, na companhia das \nmesmas pessoas"}, "g": "C", "j": "Caracteristica do alcoolismo: uso de bebida em QUANTIDADE CRESCENTE para obter o mesmo efeito - definicao de tolerancia, criterio diagnostico chave. Demais alternativas descrevem padroes recreativos ou sociais, sem o componente de tolerancia/dependencia."}, {"id": "1278663", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Acerca  da  adolescência  e  das  características  do \ndesenvolvimento  psicossocial  do  adolescente,  assinale  a \nalternativa incorreta.", "alt": {"A": "A adolescência é uma  fase evolutiva do indivíduo em \nque  são  identificadas  mudanças  biológicas,  sociais  e \npsicológicas significativas.", "B": "Sendo  essencial  ao  desenvolvimento  humano,  a \nadolescência  é  uma  fase  que  sofre  influência  da \ncultura,  mas  apresenta  aspectos  psicodinâmicos \nimportantes.", "C": "As  transformações  corporais  características  da \nadolescência  exigem  uma  reformulação  do  esquema \ncorporal e a elaboração da perda do corpo infantil.", "D": "De acordo com a teoria psicanalítica, é no período da\nadolescência que se identifica a fase genital.", "E": "A  adolescência  é  uma  fase  que  dura  dos  doze  aos \ndezoito  anos,  independentemente  da  cultura  dos \npovos."}, "g": "E", "j": "Questao pede INCORRETA. A duracao da adolescencia (12-18 anos) VARIA segundo a cultura, contexto socioeconomico e marcos psicossociais - NAO e universal. Demais alternativas (mudancas biopsicossociais, base ao desenvolvimento, esquema corporal, fase genital) sao corretas."}, {"id": "1151318", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Lei n.º 4.119/1962, que dispõe sobre os\ncursos de formação em psicologia e regulamenta a profissão\nde psicólogo, constitui função privativa do psicólogo a\nutilização de métodos e técnicas psicológicas para", "alt": {"A": "elaboração de relatórios.", "B": "diagnóstico psicológico.", "C": "emitir atestado.", "D": "realizar perícia.", "E": "lecionar."}, "g": "B", "j": "Lei 4.119/1962 estabelece como funcao PRIVATIVA do psicologo a utilizacao de metodos e tecnicas psicologicas para DIAGNOSTICO PSICOLOGICO (alem de orientacao, selecao etc.). Demais alternativas listam atividades que nao sao privativas ou nao constam nesse rol especifico."}, {"id": "1141625", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a Lei n.º 5.766/1971, são atribuições dos conselhos regionais de psicologia", "alt": {"A": "elaborar e aprovar o Código de ética profissional do psicólogo e orientar, disciplinar e fiscalizar o exercício da profissão de\npsicólogo.", "B": "elaborar e encaminhar a prestação de contas ao tribunal de contas e aprovar as anuidades e demais contribuições a serem\npagas pelos psicólogos.", "C": "zelar pela observância do Código de ética profissional, impondo sansões por sua violação, e funcionar como tribunal\nregional de ética profissional.", "D": "elaborar a proposta orçamentária anual a ser apreciada pela assembleia dos delegados regionais dentro dos prazos\nregimentais e fixar os critérios para a elaboração das propostas orçamentárias regionais.", "E": "servir de órgão consultivo em matéria de psicologia e publicar, anualmente, o relatório de seus trabalhos e a relação de\ntodos os psicólogos registrados."}, "g": "C", "j": "Lei 5.766/1971 atribui aos CRPs: zelar pela observancia do CEP, impondo sancoes por sua violacao, e funcionar como tribunal regional de etica profissional. Demais alternativas misturam atribuicoes do CFP (codigo, anuidades, regimento) com as dos CRPs."}, {"id": "999928", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Skinner,  Freud,  Piaget,  Vygotsky  e  Wallon  trouxeram contribuições  fundamentais  para  o  arcabouço  teórico  da psicologia da aprendizagem, focando em um elemento básico no  qual  delinearam  seus  campos  de  estudo.  Acerca  desse assunto,  assinale  alternativa  que  apresenta  o  elemento central para o estudo da aprendizagem de Skinner.", "alt": {"A": "comportamento", "B": "inconsciente", "C": "conhecimento", "D": "social", "E": "emoção"}, "g": "A", "j": "Skinner tem o COMPORTAMENTO como elemento central do estudo da aprendizagem (analise experimental do comportamento, condicionamento operante). Freud foca no inconsciente, Piaget no conhecimento, Vygotsky no social, Wallon na emocao/integracao."}, {"id": "999925", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Para estabelecer uma relação efetiva entre pais e escola que \npromova o sucesso acadêmico do aluno, é necessário que", "alt": {"A": "cada  segmento  tenha  clareza  quanto  a  suas \ncompetências, suas responsabilidades e seus poderes, \nsem interferir no espaço e na autonomia do outro.", "B": "a  relação  entre  família  e  escola  esteja  pautada  no \nestabelecimento  de  ações  e  soluções  conjuntas, \nprevistas  no  projeto  pedagógico,  priorizando \nestratégias  e  formas  de  ampliar  essa  relação  e \nconsiderando  o  contexto  cultural,  as  crenças,  os \nvalores e as peculiaridades dos ambientes sociais.", "C": "a  escola  garanta  o  acesso  às  informações,  forneça \noportunidades de inserção multicultural e compense as \nlacunas provenientes da educação familiar.", "D": "os  pais  se  envolvam  com  a  escola,  monitorem  o \ncomportamento  dos  filhos  e  criem  de  ambientes  de \naprendizagem em casa.", "E": "a  família  favoreça  ao  filho  o  desenvolvimento  de \nhabilidades e competências sociais e a capacidade de \nadaptação às situações cotidianas."}, "g": "B", "j": "A relacao pais-escola eficaz se pauta em ACOES e SOLUCOES CONJUNTAS, previstas no projeto pedagogico, com estrategias de ampliacao da relacao e respeito ao contexto cultural. Demais alternativas defendem segregacao de papeis, compensacao familiar ou responsabilizacao unilateral."}, {"id": "999924", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Mitjáns  (2009)  salienta  que,  para  que  o  psicólogo  escolar contribua com a transformação e a melhoria da qualidade da educação brasileira, é  fundamental a mudança nas práticas tradicionais  e  a  emergência  de  novas  práticas científico‐profissionais.  Sendo  assim,  assinale  a  alternativa que  apresenta  atividade(s)  que  não  é(são)  recomendada(s) para um psicólogo escolar.", "alt": {"A": "diagnóstico,  análise  e  intervenção  em  nível \ninstitucional,  especialmente  no  que  diz  respeito  à \nsubjetividade social da escola", "B": "elaboração de relatórios de avaliação psicológica para \nfins  de  encaminhamento  de  alunos  com  dificuldades \nescolares para outros profissionais especializados fora \nda instituição escolar", "C": "participação na construção, no acompanhamento e na \navaliação da proposta pedagógica da escola", "D": "participação no processo de seleção dos membros da \nequipe  pedagógica  e  no  processo  de  avaliação  dos \nresultados do trabalho", "E": "contribuição  para  a  coesão  da  equipe  de  direção \npedagógica e para sua formação técnica"}, "g": "B", "j": "Em Mitjans (2009), a elaboracao de relatorios para ENCAMINHAMENTO de alunos com dificuldades FORA da instituicao escolar NAO e recomendada - a critica da autora e justamente ao papel encaminhador/medicalizante. Demais alternativas (diagnostico institucional, projeto pedagogico, selecao da equipe, coesao da direcao) sao recomendadas."}, {"id": "999922", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Visando  a  contribuir  para  a  formação  de  professores,  o \npsicólogo escolar deve", "alt": {"A": "fornecer  conceitos  de  normalidade  e  legitimar  a \nmanutenção  da  ordem  por meio  da  naturalização  da \ndesigualdade no espaço escolar.", "B": "proporcionar  ao  professor  espaços  de  reflexão, \ndiscussão,  acolhimento  e  desenvolvimento,  em \nconjunto com todas as pessoas envolvidas no processo \neducativo.", "C": "centrar‐se  nas  queixas  dos  professores  sobre  as \ndificuldades de aprendizagem dos alunos, detectar os \nproblemas  e  apresentar  soluções  para  esses \nproblemas.", "D": "priorizar a promoção da competência técnica do corpo \ndocente.", "E": "promover a adaptação das condutas desviantes."}, "g": "B", "j": "Na formacao de professores, o psicologo escolar deve proporcionar ESPACOS DE REFLEXAO, discussao, acolhimento e desenvolvimento, em conjunto com todos os envolvidos. Demais alternativas defendem posturas normativas, queixosas, tecnicas ou adaptativas, contrarias a uma perspectiva critica."}, {"id": "999921", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas", "Psicologia da Educação"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "No que se refere às intervenções da psicanálise em situações de  fracasso  escolar  da  criança,  assinale  a  alternativa incorreta.", "alt": {"A": "Transforma a dificuldade de aprendizagem do sujeito \nem um sintoma.", "B": "Acolhe  e  maneja  as  especificidades  da  demanda  da \nqueixa escolar.", "C": "Realiza  um  diagnóstico  clínico  das  dificuldades  de \naprendizagem da criança.", "D": "Interroga a criança sobre sua dificuldade.", "E": "Identifica  os  conflitos  emocionais  e  os  problemas  de \nafetividade na família."}, "g": "E", "j": "Questao pede INCORRETA. A psicanalise, no fracasso escolar, NAO se ocupa de IDENTIFICAR conflitos da familia como objetivo central - foca na escuta da subjetividade da crianca, transformando dificuldade em sintoma a ser interrogado. As outras (sintoma, acolhimento da queixa, interrogacao, diagnostico psicanalitico) sao adequadas."}, {"id": "999920", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Quanto ao conceito de zona de desenvolvimento proximal de \nVygotsky, assinale a alternativa correta.", "alt": {"A": "Na relação de sala de aula com o educador, o aluno tem \na possibilidade de se desenvolver como um  todo, em \nseus conjuntos cognitivo, motor e afetivo.", "B": "Torna  manifestos  os  sentimentos  profundos  que \ninfluem  e  determinam  as  relações  com  o  outro, \nprincipalmente com aqueles aos quais o indivíduo está \nmais ligado efetivamente.", "C": "Possibilita o aprendizado e ainda uma explicação dos \nmecanismos  e  dos  processos  que  interferem  na \naquisição de conhecimentos novos.", "D": "Abrange  todas  as  funções  e  atividades  que  a  criança  \nou  o  aluno  consegue  desempenhar  com  a  ajuda  de \nalguém.", "E": "Significa  realizar  e  compreender  as  coisas  por  si \nmesmo."}, "g": "D", "j": "A ZDP de Vygotsky abrange as funcoes e atividades que a crianca consegue desempenhar COM AJUDA de alguem mais experiente - distancia entre o nivel real (autonomia) e o potencial (mediado). Demais alternativas confundem com outros conceitos (desenvolvimento integral, afetos, autonomia)."}, {"id": "999917", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Piaget", "Psicologia da Educação", "Teorias da Personalidade"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Segundo Piaget, a aprendizagem é  fruto das relações que o indivíduo estabelece com o mundo. Nesse sentido, assinale a alternativa incorreta.", "alt": {"A": "A  aprendizagem  depende  de  condições  específicas \n(espaço, objetos, meio) e subordina‐se à equilibração e \nà maturação.", "B": "A aprendizagem deve ocupar‐se com a operatividade, \ncom  a  capacidade  de  descobrir,  inventar  e  criar \npossibilidades.", "C": "A  aprendizagem  é  um  processo  de  construção  de \nconhecimento por meio da interação entre o sujeito e \no objeto.", "D": "Aprendizagem  e  desenvolvimento  são  fenômenos \ndistintos,  mas  interdependentes,  isto  é,  que  influem \num no outro reciprocamente.", "E": "A  aprendizagem  é  um  processo  de  busca  e  de \ndescoberta que facilita a aquisição de procedimentos e \nde atitudes de trabalho, estudo e questionamento."}, "g": "D", "j": "Questao pede INCORRETA. Em Piaget, aprendizagem e SUBORDINADA ao desenvolvimento (nao 'distintos mas interdependentes', formulacao mais propria de Vygotsky). A alternativa D embaralha as posicoes dos dois autores. Demais alternativas reproduzem corretamente Piaget."}, {"id": "999915", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "No  âmbito  da  psicologia  da  aprendizagem  e  do \ndesenvolvimento,  a  visão  inatista  concebe  o \ndesenvolvimento como um processo", "alt": {"A": "de construção social que se dá por meio das múltiplas \ninterações estabelecidas entre um indivíduo, desde o \nseu nascimento, e as pessoas com as quais ele mantém \num maior vínculo afetivo.", "B": "de modelagem, ou seja, o indivíduo será moldado pelas \ncontingências  de  reforçamento  ou  punição  providas \npelas pessoas e circunstâncias que o cercam.", "C": "geneticamente determinado, pois o ambiente apenas \nfacilita  ou  dificulta  o  desenvolvimento  cognitivo  ou \nlinguístico,  o  qual  é  regulado  basicamente  pelo \nprocesso de maturação.", "D": "dialético  de  fusão  e  diferenciação  em  uma  busca \ncontínua de sua própria identidade.", "E": "de  aquisição,  de  reestruturação  e  de  mudança  de \nestruturas cognitivas."}, "g": "C", "j": "Visao INATISTA concebe o desenvolvimento como geneticamente determinado, sendo o ambiente apenas facilitador/dificultador, com a maturacao regulando o processo cognitivo/linguistico. Demais alternativas correspondem a outras visoes (interacionista, behaviorista, dialetica, construtivista)."}, {"id": "910858", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2018", "org": "CRP", "t": "", "e": "Segundo o art. 13 da Lei n.° 4.119/1962, constitui função\nprivativa do psicólogo a utilização de métodos e técnicas\npsicológicas com os seguintes objetivos:", "alt": {"A": "diagnóstico psicológico; orientação e seleção\nprofissional; orientação psicopedagógica; e solução de\nproblemas de ajustamento.", "B": "avaliação psicológica; testes psicológicos; orientação\nprofissional; consultoria; e assessoria.", "C": "orientação psicopedagógica; avaliação psicológica;\nrecursos humanos; e avaliação de motoristas.", "D": "orientação e seleção profissional; orientação\npsicopedagógica; solução de problemas de\najustamento; e avaliação psicológica.", "E": "avaliação psicológica; testes psicológicos; orientação\nprofissional; e colaboração em assuntos psicológicos\nligados a outras ciências."}, "g": "A", "j": "Lei 4.119/1962 art. 13 define como funcoes PRIVATIVAS do psicologo: diagnostico psicologico, orientacao e selecao profissional, orientacao psicopedagogica e solucao de problemas de ajustamento. Alternativa A reproduz literalmente o rol."}, {"id": "1363638", "d": "psicologia", "a": ["Qualidade de Vida", "Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Assinale a alternativa que apresenta efeito das práticas de\nassédio moral nas organizações.", "alt": {"A": "diminuição do absentismo e dos acidentes no trabalho", "B": "aumento da eficácia, da eficiência, da produtividade e\nda competitividade organizacional", "C": "deficit da qualidade dos produtos e melhoria dos\nserviços", "D": "deterioração da imagem da empresa", "E": "proteção de sanções econômicas e certificações de\nqualidade"}, "g": "D", "j": "O assedio moral nas organizacoes causa DETERIORACAO DA IMAGEM DA EMPRESA (alem de prejuizos psicossomaticos, processuais e financeiros). Demais alternativas invertem efeitos reais (que sao negativos: absenteismo aumenta, produtividade cai, qualidade piora, sancoes ocorrem)."}, {"id": "1363637", "d": "psicologia", "a": ["Assédio Moral", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "O assédio moral tem sido uma prática recorrente nos\ncontextos de trabalho, especialmente nas empresas públicas.\nCom relação a esse assunto, assinale a alternativa correta.", "alt": {"A": "É uma situação que envolve um conjunto de atitudes e\ncomportamentos visíveis.", "B": "É praticado dentro das organizações e empresas,\ndeliberada e sistematicamente, por uma pessoa ou\ngrupo (chefe, equipes, clientes).", "C": "É causa da patologia da solidão e da sobrecarga.", "D": "Está relacionado ao prazer, estresse e sofrimento do\nassediador.", "E": "Envolve a perversão como elemento psicológico\ncentral para a prática sistemática."}, "g": "B", "j": "Assedio moral e praticado dentro das organizacoes DELIBERADA e SISTEMATICAMENTE, por uma pessoa ou grupo (chefe, equipes, clientes). A erra ao afirmar 'atitudes visiveis' (e frequentemente sutil); C/D/E invertem ou confundem aspectos causais/psicologicos."}, {"id": "1363632", "d": "psicologia", "a": ["Qualidade de Vida", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Assinale a alternativa que apresenta o indicador primário de\nqualidade de vida no trabalho usado pelos estudos\norganizacionais.", "alt": {"A": "satisfação", "B": "organização do trabalho", "C": "avaliação e feedback", "D": "interações socioprofissionais", "E": "estilo de vida"}, "g": "A", "j": "A SATISFACAO no trabalho e o indicador primario classico de QVT nos estudos organizacionais - construto consagrado para mensuracao subjetiva da qualidade de vida laboral. Demais alternativas listam dimensoes secundarias ou correlatas."}, {"id": "1363630", "d": "psicologia", "a": ["Qualidade de Vida", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Assinale a alternativa que apresenta a abordagem\nteórico-metodológica mais usada para fundamentar os\nprogramas de qualidade de vida no trabalho.", "alt": {"A": "abordagem sistêmica, tecnológica e psicodinâmica", "B": "abordagem clínica e da psicodinâmica do trabalho", "C": "abordagem da ergonomia da atividade articulada à\nabordagem humanista", "D": "abordagem comportamental, experimental e\nqualitativa", "E": "modelo de Walton de 1975"}, "g": "E", "j": "O MODELO DE WALTON (1975) e a abordagem teorico-metodologica mais usada para fundamentar programas de QVT, com oito dimensoes (compensacao, condicoes de trabalho, uso de capacidades, oportunidades, integracao, constitucionalismo, espaco vida-trabalho, relevancia social)."}, {"id": "1363627", "d": "psicologia", "a": ["Grupos nas Organizações", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Assinale a alternativa que apresenta a vantagem da\nrealização do grupo focal para as pesquisas organizacionais.", "alt": {"A": "fornece informações detalhadas sobre circunstâncias\nparticulares dos indivíduos e seu comportamento nos\ngrupos", "B": "demonstra facilidades de tempo e de participação", "C": "é limitado ao comportamento verbal", "D": "apresenta muitas observações em pouco tempo", "E": "traduz a artificialidade do grupo por meio das amostras\nheterogênea e diversificada"}, "g": "D", "j": "O grupo focal permite obter MUITAS observacoes em pouco tempo, com sinergia entre participantes - vantagem central para pesquisas organizacionais. Demais alternativas listam limitacoes (verbal, artificialidade) ou caracteristicas erroneas (facilidade, individualizacao)."}, {"id": "1363624", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "O diagnóstico precoce do uso abusivo de drogas lícitas e\nilícitas pode ajudar no tratamento e no prognóstico. É um\ndiagnóstico difícil em função da imprecisão do conceito de\nalcoolismo e de sua existência coabitar com outros\ntranstornos psíquicos, tendo, assim, uma etiologia\ndiversificada. Em relação à atuação do psicólogo diante do\ndiagnóstico diferencial, assinale a alternativa correta.", "alt": {"A": "Deve aplicar o DMS-IV para fazer o diagnóstico, pois é\no método mais confiável.", "B": "Deve aplicar um protocolo para anamnese da história\nfamiliar", "C": "Deve usar o método do psicodiagnóstico e aplicar\ntestes de personalidade.", "D": "Deve diagnosticar a etapa em que a doença se encontra\npara avaliar a gravidade do transtorno e seu\nprognóstico.", "E": "Deve fazer estudo de caso com a equipe\nmultiprofissional."}, "g": "E", "j": "No diagnostico diferencial do uso abusivo de drogas, o psicologo deve realizar ESTUDO DE CASO com a equipe multiprofissional - abordagem integrada que articula multiplas fontes de informacao. Demais alternativas restringem indevidamente o trabalho a um unico metodo (DSM, anamnese, testes, estadiamento)."}, {"id": "1363623", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Considerando as diferentes abordagens teóricas da psicologia\nque podem ser usadas pelo psicólogo para o estudo do\ncomportamento, do comprometimento e da satisfação no\ntrabalho, assinale a alternativa correta.", "alt": {"A": "A abordagem psicodinâmica estuda as dimensões\ninconscientes da satisfação no trabalho.", "B": "A abordagem humanista trabalha com as noções de\nnormal e patológico relacionadas ao comportamento\norganizacional.", "C": "A abordagem comportamental enfatiza modelos\nmultivariados para explicar o comprometimento e a\nsatisfação no trabalho.", "D": "Na abordagem sistêmica, o comprometimento\nindividual é tratado diretamente como manifestação\nda dinâmica dos grupos de trabalho e da\npersonalidade.", "E": "As abordagens psicológicas para estudar a satisfação\nutilizam mais a entrevista clínica como técnica que o\ngrupo focal."}, "g": "C", "j": "A abordagem PSICODINAMICA estuda as dimensoes INCONSCIENTES da satisfacao no trabalho (mobilizacao subjetiva, prazer-sofrimento, defesas). Demais alternativas misturam abordagens (humanista nao trabalha com normal/patologico, comportamental nao prioriza multivariados, etc.)."}, {"id": "1363622", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicologia do Trabalho", "Psicologia e Organizações", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "O trabalho do psicólogo exige uma diversidade de métodos e\ntécnicas de coleta de dados, especialmente para pesquisa e\ndiagnóstico das relações de trabalho no contexto\norganizacional. Assim, deve utilizar prioritariamente como\ninstrumentos", "alt": {"A": "escalas de personalidade com alto grau de\nconfiabilidade.", "B": "testes expressivos de personalidade.", "C": "observações sistemáticas e testes projetivos.", "D": "entrevistas de ajuda, psicossociais e de devolução.", "E": "entrevistas clínicas, grupos focais e observações."}, "g": "E", "j": "Para pesquisa e diagnostico das relacoes de trabalho no contexto organizacional, o psicologo deve usar prioritariamente: ENTREVISTAS CLINICAS, GRUPOS FOCAIS e OBSERVACOES - metodos qualitativos compativeis com a complexidade do objeto. Demais alternativas restringem a instrumentos psicometricos/projetivos."}, {"id": "1363620", "d": "psicologia", "a": ["Qualidade de Vida", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Quanto à saúde mental no trabalho, assinale a alternativa\ncorreta.", "alt": {"A": "A saúde mental depende das estratégias de regulação\npara eliminar a discrepância entre os trabalhos\nprescrito e real.", "B": "As patologias do trabalho têm relação progressiva com\na personalidade e a organização do trabalho,\nimpedindo a nomeação do sofrimento e dos sintomas\ndos trabalhadores.", "C": "O reconhecimento está na base da saúde mental por\nsupor a existência de um espaço público de discussão e\npela equidade quanto ao julgamento do trabalho pelo\noutro.", "D": "O adoecimento mental ocorre quando as recompensas\ne a retribuição simbólica são frequentes, dadas as\ncontribuições à organização do trabalho prescrito.", "E": "Os objetivos da clínica psicodinâmica do trabalho são a\nrelação entre trabalho e saúde mental e a constituição\ndas estruturas de personalidade e da identidade do\nsujeito."}, "g": "A", "j": "A saude mental no trabalho depende das ESTRATEGIAS DE REGULACAO que o sujeito mobiliza para reduzir a discrepancia entre trabalho prescrito e trabalho real (Dejours) - dimensao central da psicodinamica do trabalho."}, {"id": "1363616", "d": "psicologia", "a": ["Psicopatologia do Trabalho", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "No que diz respeito às psicopatologias do trabalho, é correto\nafirmar que ao estresse pós-traumático corresponda a\nseguinte afirmação:", "alt": {"A": "“Pensar no dia seguinte é uma tortura, meu trabalho é\nsem sentido e nada me faz pensar que valha à pena\ncontinuar vivo”.", "B": "“Mesmo sem ganhar horas extras, fico após o\nexpediente, caso contrário, perco a função”.", "C": "“Cada vez mais, o número de atividades a serem\nexecutadas aumenta; 100% não é mais o limite”.", "D": "“Eu não consigo atender às demandas, aquele grito\nnão sai da minha mente”.", "E": "“Só de pensar em vir trabalhar, tenho taquicardia,\nsudorese e crise de choro. Não aguento mais”."}, "g": "D", "j": "A revivescencia intrusiva ('aquele grito nao sai da minha mente') e sintoma classico do TEPT - reexperimentacao involuntaria do evento traumatico. Demais alternativas descrevem ideacao suicida, precariedade, sobrecarga e ansiedade antecipatoria, sem o nucleo do TEPT."}, {"id": "1363612", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Assinale a alternativa correta quanto ao sofrimento no\ntrabalho.", "alt": {"A": "O sofrimento é um resultado direto do confronto entre\no princípio de realidade e organização do trabalho e o\nprincípio de prazer e satisfação das necessidades do\ntrabalhador.", "B": "O sofrimento no trabalho associa-se com as\npsicopatologias.", "C": "O sofrimento é um mediador da relação\nsujeito/organização do trabalho/adoecimento.", "D": "As defesas de negação são mais eficazes que as de\nprojeção e formação reativa para enfrentar o\nsofrimento no trabalho.", "E": "Quanto mais sofrimento menos bem-estar físico,\npsíquico e social."}, "g": "C", "j": "O sofrimento e MEDIADOR da relacao sujeito/organizacao do trabalho/adoecimento - dimensao dialetica em Dejours, podendo ter face criativa ou patogenica. Demais alternativas reducionistas (sofrimento = patologia, hierarquizam defesas, ou estabelecem relacao causal direta)."}, {"id": "1234452", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2017", "org": "CFP", "t": "", "e": "No que se refere às atividades compatíveis com a atuação do  psicólogo na prevenção e intervenção primárias, julgue os  itens subsequentes.       I  O psicólogo deve assistir os pacientes em consultas  primárias, não confundindo essa assistência com a  prática da psicoterapia.    II  O psicólogo deve abordar temas de saúde de acordo  com as demandas psicológicas dos casos individuais  que atenda, não trabalhando no âmbito de dinâmicas  de grupo ou de interconsultas com outros profissionais  de saúde.    III  O psicólogo deve atuar na saúde geral dos coletivos  sociais a serem assistidos, elaborando programas de  promoção e educação para saúde.        Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Todos os itens estão certos."}, "g": "D", "j": "Itens I (consultas primarias distintas de psicoterapia) e III (atuacao em saude geral de coletivos via programas de promocao/educacao) corretos. Item II e falso ao excluir dinamicas de grupo e interconsultas da atuacao primaria."}, {"id": "1233313", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2017", "org": "CFP", "t": "", "e": "Com relação à psicologia comunitária, julgue os seguintes  itens.        I  A partir de meados da década de 1990, aconteceram  importantes  mudanças  no  campo  da  psicologia comunitária. Houve a procura por serviços além da  atuação  tradicional,  como,  por  exemplo,  violência  cotidiana  e  doméstica,  formas  de  intolerância  e  preconceito para com as minorias sociais.  \n    II  Atualmente  é  importante  pensar  nos  resultados  (quantidade e eficiência) dos diferentes projetos, pois  são  sinônimos  de  compromisso.  Os  processos  de  formação e participação têm caráter secundário.      III  A  psicologia  comunitária  assume  uma  ação  pedagógico‐formativa,  já  que  tem  um  caráter  preventivo na perspectiva de implementar projetos  políticos que resultem em mudanças na vida cotidiana  das pessoas.      IV  Quando  os  problemas  já  estão  localizados,  deve  também desenvolver ações pontuais e específicas, pois  os  indivíduos  em  comunidade  necessitam  de  conscientização.        Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e IV estão certos.", "E": "Apenas os itens III e IV estão certos."}, "g": "C", "j": "Itens I (mudancas pos-1990 em psicologia comunitaria) e III (acao pedagogico-formativa de carater preventivo) corretos. Item II inverte logica (resultados quantitativos como sinonimos de compromisso); item IV reduz a acoes pontuais com vies normativo."}, {"id": "1229086", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2017", "org": "CRP 7ª Região RS", "t": "", "e": "Segundo a Resolução CFP n.º 8/2010, que dispõe sobre a atuação do psicólogo como perito e assistente técnico no Poder Judiciário, assinale a alternativa correta quanto à realização da perícia.", "alt": {"A": "A perícia poderá ser realizada em qualquer espaço.", "B": "O psicólogo perito poderá atuar em equipe multiprofissional, desde que preserve sua especificidade e o limite de intervenção, não se subordinando técnica e profissionalmente a outras áreas.", "C": "A presença do psicólogo assistente técnico é obrigatória durante a realização dos procedimentos metodológicos que norteiem o atendimento do psicólogo perito e vice-versa.", "D": "A produção do relatório pelo psicólogo perito apresentará indicativos pertinentes à sua investigação que possam diretamente subsidiar o juiz na solicitação realizada, podendo adentrar nas decisões, que são de atribuição exclusiva dos magistrados.", "E": "Para desenvolver sua função, o assistente técnico não deverá ouvir pessoas envolvidas nem solicitar documentos em poder das partes, entre outros meios."}, "g": "B", "j": "Res CFP 8/2010 - o psicologo perito pode atuar em equipe multiprofissional, preservando sua especificidade e limite de intervencao, sem subordinacao tecnica/profissional a outras areas. Demais alternativas violam disposicoes (espaco livre, presenca do assistente, indicativos juridicos, vedacao de instrucao)."}, {"id": "1226082", "d": "psicologia", "a": ["Psicanálise", "Freud", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2017", "org": "IAMSPE", "t": "", "e": "Segundo Ponciano, o termo libido, força psíquica de natureza sexual, foi introduzido por", "alt": {"A": "Adler", "B": "Jung", "C": "Carl Rogers.", "D": "Maslow", "E": "Freud"}, "g": "E", "j": "Freud introduziu o termo LIBIDO como forca psiquica de natureza sexual - conceito central da teoria pulsional psicanalitica. Adler, Jung, Rogers e Maslow desenvolveram outros referenciais teoricos."}, {"id": "1225980", "d": "psicologia", "a": ["Jung", "Teorias da Personalidade"], "ano": "2017", "org": "IAMSPE", "t": "", "e": "O inconsciente coletivo ou transpessoal formado pelas lembranças próprias da raça humana é um conceito de", "alt": {"A": "Carl Rogers.", "B": "Adler", "C": "Freud", "D": "Jung", "E": "Skinner"}, "g": "D", "j": "O INCONSCIENTE COLETIVO ou transpessoal, formado pelas lembrancas da raca humana (arquetipos), e conceito central de JUNG - distinguindo-o de Freud, que enfatizava o inconsciente pessoal."}, {"id": "1213406", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2017", "org": "CFP", "t": "", "e": "ECA  prevê  que  o  vínculo  da  adoção  se  constitui  por  sentença judicial, que será inscrita no registro civil mediante  mandado do qual não se fornecerá certidão. Acerca desse  assunto, julgue os itens subsequentes.        I  A inscrição consignará o nome dos adotantes como  pais, bem como o nome de seus ascendentes.      II  O mandado judicial, que será arquivado, cancelará o  registro original do adotado.      III  A pedido do adotante, o novo registro poderá ser  lavrado no cartório de registro civil do município de sua  residência.  IV  Nenhuma observação sobre a origem do ato poderá  constar nas certidões do registro.        A quantidade de itens certos é igual a", "alt": {"A": "0", "B": "1", "C": "2", "D": "3", "E": "4"}, "g": "E", "j": "Os quatro itens corretos sobre adocao no ECA: registro consigna adotantes e ascendentes (I); mandado cancela registro original (II); novo registro pode ser lavrado no cartorio da residencia (III); nenhuma observacao sobre origem na certidao (IV)."}, {"id": "1205806", "d": "psicologia", "a": ["Psicodrama", "Teorias e Técnicas Psicoterápicas"], "ano": "2017", "org": "CFP", "t": "", "e": "Franco  (2000)  descreve  as  fases  do  procedimento  de psicodrama na utilização de um jogo dramático e aponta as  contribuições  dessa  abordagem  no  ambiente  esportivo.  Quanto  à  prática  do  psicodrama  no  esporte,  assinale  a  alternativa correta.", "alt": {"A": "Traçando um paralelo entre o psicodrama e o esporte,  o palco (ou cenário), lugar/espaço onde acontece o  “como se”, no ambiente esportivo, seria a quadra, o  campo, a piscina ou as pistas.", "B": "O processo de desenvolvimento de papéis passa por  três fases. No role taking, as pessoas treinam papéis.", "C": "O papel, segundo Moreno, refere‐se ao sentimento e  ao  conhecimento  da  situação  real  das  pessoas  envolvidas em uma situação.", "D": "No jogo dramático, o ego‐auxiliar é aquele que dirige,  produz e analisa os dados que emergem do grupo.", "E": "No jogo dramático, o compartilhar ocorre quando o  grupo se prepara para uma nova situação, desafio ou  reflexão."}, "g": "A", "j": "Em Franco, paralelo psicodrama-esporte: o palco/cenario corresponde a quadra, campo, piscina ou pistas - espaco onde acontece o 'como se' da pratica esportiva. Demais alternativas confundem fases do role/papel ou funcao do ego-auxiliar e do compartilhar."}, {"id": "1205774", "d": "psicologia", "a": ["Behaviorismo", "Teorias e Técnicas Psicoterápicas"], "ano": "2017", "org": "CFP", "t": "", "e": "Suponha‐se que uma ginasta iniciante sofra várias  quedas duras ao treinar um mortal de costas na trave, cada  queda  causando  tanto  sentimento  de  medo  quanto considerável dor. Agora, quando a jovem ginasta está prestes  a treinar o mortal de costas na trave, sente medo e fica tensa.       Martin, 2001 (com adaptações).        Com base nesse caso hipotético, o princípio da aprendizagem  que está evidente é o(a)", "alt": {"A": "reforçamento positivo.", "B": "fuga.", "C": "esquiva.", "D": "punição negativa.", "E": "emparelhamento  de  estímulos  (condicionamento  respondente)."}, "g": "E", "j": "O caso ilustra o EMPARELHAMENTO DE ESTIMULOS (condicionamento respondente classico): a associacao entre o mortal de costas (EN, estimulo neutro) e a dor/queda (ENC, estimulo incondicionado) faz com que o estimulo passe a eliciar medo (RC). Demais alternativas referem-se a operante (reforco, fuga, esquiva, punicao)."}, {"id": "1190818", "d": "psicologia", "a": ["Teorias da Personalidade", "Teorias da Personalidade - Outros Autores"], "ano": "2017", "org": "CFP", "t": "", "e": "Com base no estudo da personalidade no esporte, assinale a  alternativa que apresenta a abordagem que, por definição,  não levava em consideração as situações particulares que  também  poderiam  influenciar  o  comportamento  de  um  indivíduo.", "alt": {"A": "fenomenológica", "B": "de traço", "C": "interacional", "D": "psicodinâmica", "E": "situacional"}, "g": "B", "j": "A abordagem DE TRACO, por definicao, NAO considerava situacoes particulares - assumia que tracos estaveis explicariam o comportamento, em oposicao a abordagem interacional/situacional. Posteriormente foi criticada e complementada por modelos integrativos."}, {"id": "1190675", "d": "psicologia", "a": ["Comportamento Organizacional em Psicologia", "Psicologia e Organizações"], "ano": "2017", "org": "CFP", "t": "", "e": "Morgan (1980) afirma que atletas de elite bem‐sucedidos são caracterizados pelo perfil iceberg. De acordo com esse perfil,    um atleta de alto rendimento possui uma característica acima da média da população. Essa característica é o(a)", "alt": {"A": "vigor", "B": "raiva.", "C": "fadiga.", "D": "confusão.", "E": "depressão."}, "g": "A", "j": "Em Morgan (1980), o perfil iceberg dos atletas de alto rendimento mostra niveis de VIGOR acima da media e niveis abaixo da media em tensao, depressao, raiva, fadiga e confusao (medidos pelo POMS)."}, {"id": "1190649", "d": "psicologia", "a": ["Psicodrama", "Teorias e Técnicas Psicoterápicas"], "ano": "2017", "org": "CFP", "t": "", "e": "Um sociograma é um instrumento usado para medir a coesão  social, entretanto ele não revela o(a)", "alt": {"A": "relação entre coesão e desempenho da equipe", "B": "presença ou a ausência de “panelinhas”.", "C": "isolamento social de membros do grupo.", "D": "escolha de amizades dentro do grupo.", "E": "afiliação e a atração entre os membros."}, "g": "A", "j": "O sociograma mensura coesao, afiliacao, atracao, panelinhas e isolamento social - mas NAO revela diretamente a RELACAO ENTRE COESAO E DESEMPENHO da equipe, que exige outros instrumentos correlacionais."}, {"id": "1190648", "d": "psicologia", "a": ["Psicologia Organizacional", "Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2017", "org": "CFP", "t": "", "e": "Assinale a alternativa que não apresenta atividade que caracterize a atuação do psicólogo do esporte.", "alt": {"A": "suporte na melhora da relação técnico‐atleta", "B": "criação  e  implementação  de  um  programa  de  treinamento de habilidades psicológicas", "C": "avaliação física, técnica e tática de atletas", "D": "orientação de pais e familiares dos atletas", "E": "desenvolvimento e teste de diferentes estratégias que  possam aumentar a adesão ao exercício"}, "g": "C", "j": "Avaliacao FISICA, TECNICA e TATICA de atletas NAO e atribuicao do psicologo do esporte (cabe a tecnicos, preparadores fisicos, fisiologistas). Demais alternativas (suporte tecnico-atleta, THP, orientacao familiar, estrategias de adesao ao exercicio) sao do psicologo."}, {"id": "1190548", "d": "psicologia", "a": ["Motivação", "Psicologia e Organizações"], "ano": "2017", "org": "CFP", "t": "", "e": "No que se refere à motivação, a teoria da necessidade de  realização é uma visão interacional que considera fatores  pessoais  e  situacionais  como  bons  prognosticadores  de  comportamento. De acordo com Weinberg & Gould (2001),  cinco componentes constituem essa teoria. Considerando  essa informação, assinale a alternativa que não apresenta um  dos componentes da teoria mencionada.", "alt": {"A": "aspectos da personalidade", "B": "competitividade", "C": "fatores situacionais", "D": "reações emocionais", "E": "tendências resultantes"}, "g": "B", "j": "COMPETITIVIDADE NAO integra os cinco componentes da teoria da necessidade de realizacao (Atkinson/McClelland em Weinberg & Gould): personalidade, fatores situacionais, tendencias resultantes, reacoes emocionais e comportamentos relacionados ao desempenho."}, {"id": "1190182", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2017", "org": "CFP", "t": "", "e": "Considerando o uso de medidas psicológicas no contexto esportivo e a Resolução n.º 7/2003 do Conselho Federal de  Psicologia (CFP), assinale a alternativa incorreta.", "alt": {"A": "É preciso assegurar o sigilo dos que forem avaliados,  cuidando  das  informações  que  podem  ou  não  ser  divulgadas para a comissão técnica, por exemplo.", "B": "Os  testes  utilizados  para  emissão  de  laudos  e(ou)  pareceres de um atleta precisam estar validados e  aprovados pelo CFP.", "C": "Ao  fazer  a  avaliação  psicológica  de  um  atleta,  é  interessante  usar,  sempre  que  possível,  testes  específicos para o contexto esportivo.", "D": "É importante informar aos atletas e(ou) à comissão  técnica o objetivo da avalição", "E": "Outras fontes de dados e medidas, como observação  da  frequência  de  comportamentos,  uso  do  biofeedback, registro da frequência cardíaca e pressão  arterial,  correlacionadas  com  estados  de  estresse,  ansiedade ou dor devem ser ignoradas e descartadas  da avaliação."}, "g": "E", "j": "Questao pede INCORRETA. Outras fontes de dados (observacao, biofeedback, FC, pressao arterial) NAO devem ser ignoradas/descartadas - integram a avaliacao psicologica esportiva. Demais alternativas reproduzem corretamente principios da Res CFP 7/2003."}, {"id": "1182053", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2017", "org": "CFP", "t": "", "e": "Assinale a alternativa que apresenta princípios da Política  Nacional de Humanização (2003).", "alt": {"A": "transversalidade, indissociabilidade entre a atenção e a  gestão,  protagonismo,  corresponsabilidade  e  autonomia dos sujeitos e coletivos", "B": "transversalidade, equidade e integralidade", "C": "equidade, autonomia dos sujeitos e ambiência", "D": "equidade, gestão compartilhada e transversalidade", "E": "transversalidade, equidade e ambiência"}, "g": "A", "j": "A Politica Nacional de Humanizacao (PNH/2003) tem como principios: TRANSVERSALIDADE, INDISSOCIABILIDADE entre atencao e gestao, PROTAGONISMO, CORRESPONSABILIDADE e AUTONOMIA dos sujeitos e coletivos. Demais alternativas misturam principios e diretrizes do SUS."}, {"id": "2762157", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2016", "org": "CRP", "t": "", "e": "Sigilo profissional, em qualquer código de ética, tem por finalidade proteger a pessoa atendida. Considere as afirmativas sobre a atuação do Psicólogo e assinale a incorreta.", "alt": {"A": "Todo psicólogo, em seu exercício profissional, está obrigado ao sigilo profissional.", "B": "Cabe ao psicólogo criar as condições adequadas para que não haja a violação do sigilo.", "C": "Em se tratando de prontuário que possa interessar a uma Equipe Multidisciplinar, devem ser registradas apenas as informações necessárias ao cumprimento dos objetivos do trabalho.", "D": "Em caso de demissão ou exoneração, o psicólogo não poderá repassar informações e materiais de seus pacientes ao psicólogo que vier a substituí-lo.", "E": "O usuário deve ser informado da existência do prontuário, tendo livre acesso às informações contidas a seu respeito."}, "g": "D", "j": "Questao pede INCORRETA. Em caso de demissao/exoneração, o psicologo DEVE repassar informacoes e materiais ao substituto para garantir continuidade do cuidado - a alternativa D viola essa logica etica. Demais alternativas reproduzem corretamente o CEP sobre sigilo."}, {"id": "2762155", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2016", "org": "CRP", "t": "", "e": "A Epistemologia Genética é uma ciência relativamente nova, inaugurada pelos trabalhos de Piaget, que tem por objetivo revelar os processos pelos quais se constituem os diferentes estados do conhecimento. Assim, a conclusão desse autor é de que o homem aprende assimilando a realidade e acomodando os esquemas e as operações de sua mente para novas assimilações. Assim, “a alteração na própria estrutura mental, seja na criação de novos esquemas ou na modificação de antigos”, refere-se ao conceito de:", "alt": {"A": "assimilação.", "B": "acomodação.", "C": "equilibração.", "D": "esquemas secundários.", "E": "zona de desenvolvimento proximal."}, "g": "B", "j": "ACOMODACAO em Piaget e a alteracao na propria estrutura mental (criacao de novos esquemas ou modificacao dos antigos) para integrar nova informacao. Assimilacao incorpora ao esquema existente; equilibracao e o mecanismo geral; ZDP e de Vygotsky."}, {"id": "2762154", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2016", "org": "CRP", "t": "", "e": "A teoria histórico-cultural, mais conhecida no Brasil como Escola de Vygotsky, constituiu-se como uma vertente da psicologia que se desenvolvia na União Soviética, nas décadas iniciais do século XX. Os autores que autodenominaram sua corrente de pensamento como histórico-cultural tinham razões para isso; partiam do pressuposto de que:", "alt": {"A": "a personalidade do homem é composta por três sistemas resultantes de sua interação com o ambiente.", "B": "as relações indivíduo-ambiente são controladas pelas consequências do cotidiano.", "C": "o homem é um ser de natureza social.", "D": "o homem já traz, ao nascer, um conjunto de aptidões e capacidades definidas e determinadas geneticamente.", "E": "o desenvolvimento humano ocorre por meio de estágios em que a interação da criança evolui seu processo maturacional."}, "g": "C", "j": "O pressuposto fundamental de Vygotsky (Escola de Vygotsky/historico-cultural) e que o HOMEM E SER DE NATUREZA SOCIAL - desenvolvimento se da pela mediacao cultural e historica, nao por estagios maturacionais isolados nem por consequencias comportamentais."}, {"id": "2762153", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2016", "org": "CRP", "t": "", "e": "Bock, Furtado e Teixeira, no livro Psicologias: uma introdução ao estudo de Psicologia (2002), abordam em um dos capítulos o tema “Psicologia como Profissão”. Sobre o assunto, assinale a alternativa incorreta.", "alt": {"A": "A Psicologia, no Brasil, é uma profissão reconhecida desde 1958, pela Lei nº 3.278.", "B": "O psicólogo pode, junto com o paciente, desvendar razões e compreender dificuldades, caracterizando-se assim sua intervenção.", "C": "O psicólogo possui instrumentos adequados para auxiliar o indivíduo a compreender, organizar e aplicar esse saber, permitindo sua transformação e a mudança de sua ação sobre o meio.", "D": "A Psicologia tem seu objeto de estudo marcado pela busca da compreensão do funcionamento da consciência.", "E": "Psicologia e Psiquiatria se aproximam no que diz respeito às intervenções nos processos patológicos da subjetividade humana; os psicólogos têm se dedicado mais à compreensão das patologias para qualificar seus afazeres profissionais."}, "g": "A", "j": "Questao pede INCORRETA. A psicologia no Brasil foi REGULAMENTADA como profissao em 1962 pela LEI 4.119, NAO pela Lei 3.278/1958 (que apenas dispoe sobre psicotecnicos). A alternativa A apresenta data e diploma legal incorretos."}, {"id": "2762152", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas"], "ano": "2016", "org": "CRP", "t": "", "e": "O Behaviorismo, a Gestalt e a Psicanálise são considerados por inúmeros autores as três mais importantes tendências teóricas da Psicologia no século XX. Seguindo cada uma das abordagens, assinale a alternativa que descreve corretamente os aspectos conceituais relacionados.", "alt": {"A": "O pré-consciente é constituído por conteúdos reprimidos que não são acessíveis ao consciente pelas ações de censuras internas.", "B": "A Psicanálise, enquanto método de investigação, caracteriza-se pelo método introspectivo, que busca o significado oculto daquilo que é manifesto por meio de ações e palavras ou pelas produções imaginárias.", "C": "A base do Behaviorismo está na formulação do conceito de comportamento respondente, ou seja, estímulo-reflexo.", "D": "Seguindo as leis do Behaviorismo entre o estímulo dado ao indivíduo e sua resposta, há o processo de percepção – o que ele percebe e como percebe são dados importantes para a compreensão do comportamento humano.", "E": "A Gestalt, que tem seu berço nos Estados Unidos, dedica-se ao estudo das interações entre o indivíduo e o ambiente."}, "g": "B", "j": "A base do BEHAVIORISMO esta na formulacao do conceito de COMPORTAMENTO RESPONDENTE (estimulo-reflexo) - paradigma pavloviano que fundamenta a analise comportamental. A erra ao definir pre-consciente; B confunde Psicanalise com introspectivismo; D inclui percepcao no S-R; E erra origem da Gestalt."}, {"id": "2762151", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2016", "org": "CRP", "t": "D’Oliveira, (1984) registra em seu livro “Ciência e Pesquisa em Psicologia”, que faz parte da coleção “Temas Básicos de Psicologia”, as experiências e inquietações enquanto pesquisadora e professora de Psicologia. Assim, o material fornece subsídios para uma atuação em ciência e pesquisa com o intuito de reconhecê-las e compará-las com outras atividades do conhecimento humano. Com base nesse assunto, responda às questões 43 e 44.", "e": "Um grande marco na história da Psicologia como ciência e pesquisa foi quando Wilhelm Wundt (1832-1920) estabeleceu o primeiro laboratório psicológico do mundo. Wundt acreditava que a maneira mais simples de estudar a mente era através do estudo direto dos eventos mentais, com um método chamado:", "alt": {"A": "introspecção.", "B": "hipnose.", "C": "avaliação funcional.", "D": "diálogo dirigido.", "E": "catarse."}, "g": "A", "j": "Wundt utilizou o metodo da INTROSPECCAO experimental para estudar os eventos mentais no primeiro laboratorio de psicologia (Leipzig, 1879). Hipnose, avaliacao funcional, dialogo dirigido e catarse pertencem a outras tradicoes (Freud, Charcot, etc.)."}, {"id": "2762150", "d": "psicologia", "a": ["Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2016", "org": "CRP", "t": "", "e": "Leia as seguintes afirmativas. I. Fazer pesquisa é umas das etapas da ciência. II. A ciência está em constante interação com a sociedade, podendo ser determinada pela história política e econômica do momento social em que se insere. III. O problema de pesquisa deve ser formulado sob forma de pergunta. Pode-se afirmar que:", "alt": {"A": "somente I está correta.", "B": "somente I está correta.", "C": "somente III está correta.", "D": "I, II e III estão corretas.", "E": "I, II e III estão incorretas."}, "g": "D", "j": "Todas as tres afirmacoes corretas: pesquisa como etapa da ciencia (I); ciencia em interacao com sociedade/historia (II); problema de pesquisa formulado como pergunta (III) - principios metodologicos consensuais."}, {"id": "2762149", "d": "psicologia", "a": ["Psicologia e Organizações"], "ano": "2016", "org": "CRP", "t": "Em seu artigo intitulado “Psicologia Institucional: o exercício da psicologia como instituição”, Guirado (2009) revisa as discussões desenvolvidas pelo tema nos mais de 20 anos de trabalhos contínuos intensos. As questões 41 e 42 estão relacionadas a esse tema.", "e": "Considere as seguintes afirmativas. I. Análise Institucional é o nome dado a um movimento que supõe um modo específico de compreender as relações sociais, um conceito de instituição e um modo de inserção do profissional psicólogo que é de natureza imediatamente política.II. O instituído é uma dimensão ou momento do processo de institucionalização em que os sentidos, as ações ainda estão em movimento e constituição. III. Organização é um nível da realidade social em que as relações são regidas por estatutos e acontecem no interior de estabelecimentos, espaços físicos determinados. IV. A instituição é o nível da Lei ou da Constituição que rege todo o tecido de uma formação social; está acima dos estatutos das organizações. Está correto o que se afirma somente em:", "alt": {"A": "I.", "B": "II.", "C": "III.", "D": "II, III e IV.", "E": "I, III e IV."}, "g": "E", "j": "Apenas I, III e IV corretos. Item I define analise institucional como movimento politico/conceitual; III conceitua organizacao; IV situa instituicao no nivel da lei. Item II inverte o conceito - quem esta em movimento e o INSTITUINTE (e nao o instituido, que e cristalizado)."}, {"id": "2762148", "d": "psicologia", "a": ["Análise Institucional", "Psicologia e Organizações"], "ano": "2016", "org": "CRP", "t": "", "e": "Psicologia Institucional é um termo cunhado por ________, psiquiatra argentino de orientação psicanalítica inglesa, que, a um certo momento, buscou aliar _________ e _________ para pensar a atuação do profissional em psicologia, para além das práticas terapêuticas e consultorias. As lacunas são, correta e respectivamente, preenchidas por:", "alt": {"A": "George Lapassade, sociologia e Gestalt.", "B": "Michel Foucault, funcionalismo e psicanálise.", "C": "José Bleger, psicanálise e marxismo.", "D": "Freud, psicanálise e dialética.", "E": "Pichon-Rivière, psicanálise e estruturalismo."}, "g": "C", "j": "JOSE BLEGER (psiquiatra argentino) cunhou o termo Psicologia Institucional, articulando PSICANALISE e MARXISMO para pensar a atuacao do psicologo alem das praticas terapeuticas tradicionais."}, {"id": "2762147", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2016", "org": "CRP", "t": "O Conselho Federal de Psicologia apresentou à categoria e à sociedade em geral, em 2012, o documento de Referências Técnicas para a Prática de Psicólogas(os) em Programas de Atenção à Mulher em Situação de Violência, produzido a partir da metodologia do Centro de Referência Técnica em Psicologia e Políticas Públicas (Crepop). As questões 39 e 40 estão relacionadas a esse documento que busca contribuir referência sólida para a atuação da Psicologia na área.", "e": "Como um fenômeno complexo e multifacetado, a violência contra a mulher exige compreensão e intervenção multidisciplinares. Portanto, sobre a prática do profissional Psicólogo nesse contexto, podemos afirmar exceto que:", "alt": {"A": "as diretrizes básicas para a atuação das equipes partem de normas provenientes de instituições como Ministério da Saúde, Secretaria de Políticas para Mulheres (SPM) e Ministério do Desenvolvimento Social, que fornecem orientações gerais para a implantação dos serviços.", "B": "as pesquisas da área mostram que há consenso entre o objetivo de trabalho do psicólogo em relação à sua equipe multiprofissional envolvida, estando bem delimitadas a articulação das ações, as metodologias e as questões conceituais.", "C": "dentre as atividades desenvolvidas pelo psicólogo podem-se considerar escuta qualificada, acolhimento, fortalecimento, promoção da autoestima, superação da situação de violência.", "D": "o atendimento à mulher em situação de violência requer discussões a respeito das contextualizações das novas demandas sociais, que exigem da Psicologia uma ampliação de suas práticas e novos campos de atuação.", "E": "considerando que o papel do psicólogo é promover a reflexão nas mulheres em situação de violência, no sentido de que elas possam reconstruir suas vidas e fazer novas escolhas, é fundamental ter acesso à grande variedade de conceitos e teorias a respeito da violência e da especificidade do gênero."}, "g": "B", "j": "Questao pede EXCETO. NAO HA consenso entre o objetivo do psicologo e a equipe multi nos servicos de atencao a mulher em situacao de violencia - a articulacao de acoes, metodologias e conceitos ainda esta em construcao. Demais alternativas reproduzem corretamente o documento Crepop."}, {"id": "2762141", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2016", "org": "CRP", "t": "Chiavenato (2009), em seu livro “Recursos Humanos: o capital humano nas organizações”, menciona que a entrevista de seleção é a técnica de seleção mais utilizada, sendo que em todas as situações a entrevista deve ser feita com habilidade e tato, a fim de que possa produzir os resultados esperados. Responda às questões 33 e 34, relacionadas ao tema.", "e": "Leia as seguintes afirmativas sobre a utilização de testes psicológicos durante o processo de entrevista.I. São utilizados para melhor conhecer as pessoas nas decisões de emprego, orientação profissional, avaliação profissional e mensuração de aptidões.II. Limitam o perfil do candidato identificando apenas seus déficits.III. Não possibilitam um resultado fidedigno por falta de dados normativos.IV. Constituem uma medida objetiva e estandardizada de amostras do comportamento das pessoas.V. Focalizam principalmente as aptidões, procurando avaliar sua presença em cada pessoa, com o intuito de generalizar e prever seu comportamento em determinadas situações de trabalho.Quantas estão corretas?", "alt": {"A": "Uma, somente.", "B": "Duas, somente", "C": "Três, somente.", "D": "Quatro, somente.", "E": "Todas."}, "g": "C", "j": "Tres afirmacoes corretas (I, IV e V): conhecer pessoas para decisoes/orientacao/avaliacao; medida objetiva e estandardizada; focalizar aptidoes para prever comportamento. Itens II (limitar a deficits) e III (sem fidedignidade por falta de normativos) sao falsos."}, {"id": "2762140", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2016", "org": "CRP", "t": "", "e": "Os testes de personalidade servem para analisasr os diversos traços de personalidade, sejam eles determinados pelo caráter, sejam pelo temperamento. Eles são genéricos quando revelam traços gerais de personalidade em uma síntese global e recebem o nome de psicodiagnóstico. Nessa categoria estão os chamados testes expressivos e projetivos. Como exemplo, podemos citar apenas:", "alt": {"A": "WISC IV.", "B": "FIGURAS COMPLEXAS DE REY.", "C": "BGFM.", "D": "RORSCHACH.", "E": "BPR - 5."}, "g": "D", "j": "Entre as alternativas, apenas o Rorschach e um teste projetivo de personalidade. WISC IV avalia inteligencia, Figuras de Rey avalia funcoes executivas/memoria, BGFM (Bender-Gestalt) e visomotor, BPR-5 mede raciocinio."}, {"id": "2762139", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2016", "org": "CRP", "t": "Considerando as informações sobre a Psicologia Social discutidas no livro de Bock, Furtado e Teixeira (2002) “Psicologias: uma introdução ao estudo de Psicologia”, responda às questões 31 e 32.", "e": "“Pequenas organizações de indivíduos que, possuindo objetivos comuns, desenvolvem ações na direção desses objetivos” é o conceito de:", "alt": {"A": "trabalho grupal.", "B": "cultura organizacional.", "C": "grupos operativos.", "D": "grupos sociais.", "E": "equipes de trabalho."}, "g": "D", "j": "Bock, Furtado e Teixeira (2002) definem grupos sociais como pequenas organizacoes de individuos com objetivos comuns que desenvolvem acoes nessa direcao."}, {"id": "2762138", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2016", "org": "CRP", "t": "", "e": "Considere as seguintes afirmativas sobre as principais características da Psicologia Social.I. Procura aprofundar o conhecimento da natureza social do fenômeno psíquico.II. Busca compreender como se dá a construção do psiquismo humano a partir das relações sociais vividas pelo homem.III. Estuda o desenvolvimento afetivo-emocional do ser humano.IV. Estuda o comportamento humano de acordo com suas aprendizagens significativas. V. Interessa-se pela história de reforçamento presente no ambiente do ser humano.Quantas estão corretas?", "alt": {"A": "Uma, somente.", "B": "Duas, somente", "C": "Três, somente.", "D": "Quatro, somente.", "E": "Todas."}, "g": "B", "j": "Caracteristicas da Psicologia Social: I e II corretas (natureza social do psiquismo e construcao via relacoes sociais). III, IV e V referem-se a outras areas (desenvolvimento e behaviorismo). Apenas duas estao corretas."}, {"id": "2762129", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2016", "org": "CRP", "t": "", "e": "Conforme disposto no Código de Ética Profissional do Psicólogo, assinale a alternativa incorreta.", "alt": {"A": "É vedado ao psicólogo induzir a convicções políticas, filosóficas, morais, ideológicas, religiosas, de orientação sexual ou a qualquer tipo de preconceito, quando do exercício de suas funções profissionais.", "B": "É dever do psicólogo a prestação de serviços profissionais em situações de calamidade pública ou de emergência, sem visar a benefício pessoal.", "C": "Ao fixar a remuneração por seu trabalho, o psicólogo levará em conta a justa retribuição aos serviços prestados e as condições do usuário ou beneficiário.", "D": "É vedado ao psicólogo, em qualquer hipótese, intervir na prestação de serviços psicológicos que estejam sendo efetuados por outro profissional.", "E": "O psicólogo, quando participar de greves ou paralisações, garantirá que as atividades de emergência não sejam interrompidas."}, "g": "D", "j": "Codigo de Etica do Psicologo (Res CFP 10/2005) nao veda 'em qualquer hipotese' a intervencao em servicos de outro profissional - ha excecoes previstas em situacoes especiais. Demais alternativas correspondem a deveres e vedacoes do codigo."}, {"id": "1234315", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2016", "org": "CRP - SP", "t": "", "e": "Analise as afirmativas a seguir, relacionadas às infrações disciplinares e às penalidades estabelecidas pelo Decreto                nº 79.822/77.    I. Pratica infração disciplinar aquele que solicita ou recebe de cliente qualquer favor em troca de concessões ilícitas. \n  II. Entre as penalidades estabelecidas pelo referido decreto, encontra-se a suspensão do exercício profissional. \n  III. Para efeito da cominação da pena, serão consideradas especialmente graves as faltas diretamente relacionadas com o exercício profissional. \n  IV. O referido decreto não prevê aplicação de advertência, por tratar-se de sanção demasiadamente branda. Às infrações de menor gravidade aplica-se a pena de censura.     Está correto o que se afirma em:", "alt": {"A": "I, II e III, somente.", "B": "II, III e IV, somente.", "C": "I e II, somente.", "D": "nenhuma.", "E": "todas."}, "g": "A", "j": "Decreto 79.822/77: I, II e III corretas (receber favor por concessao ilicita e infracao; suspensao e penalidade prevista; faltas ligadas ao exercicio sao especialmente graves). IV incorreta: o decreto preve advertencia como penalidade."}, {"id": "1234175", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2016", "org": "CRP - SP", "t": "", "e": "Nos termos do Decreto nº 79.822/77, da imposição de qualquer penalidade caberá recurso, com efeito suspensivo, ao Conselho Federal, no prazo de:", "alt": {"A": "30 dias.", "B": "20 dias.", "C": "15 dias.", "D": "10 dias.", "E": "8 dias."}, "g": "A", "j": "Decreto 79.822/77, art. 32: recurso ao Conselho Federal com efeito suspensivo no prazo de 30 dias."}, {"id": "1136764", "d": "psicologia", "a": ["Trabalho em Equipe", "Grupos e Equipes"], "ano": "2016", "org": "CRO", "t": "", "e": "Katzenbach e Smith são grandes autores da literatura que\ntrata sobre a formação e o desempenho de equipes/\ngrupos de trabalho. Ao analisarem suas características, os\nautores classificaram as equipes de acordo com seu modo\nde funcionamento. Portanto, diante de uma situação em\nque existe intenção de produzir desempenho coletivo, em\nque é necessário assumir compromisso quanto ao resultado\nde grupo e em que os membros precisam de\nesclarecimentos das finalidades, dos objetivos e da\nabordagem de tarefa, os autores indicam as equipes como:", "alt": {"A": "pseudo-equipes.", "B": "grupos de trabalho.", "C": "equipes potenciais.", "D": "equipes reais.", "E": "equipes de elevado desempenho."}, "g": "C", "j": "Katzenbach e Smith classificam como 'equipe potencial' aquela que tem intencao de desempenho coletivo e busca compromisso/objetivos, mas ainda necessita esclarecer finalidades e abordagem."}, {"id": "808824", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2016", "org": "CRO", "t": "", "e": "A avaliação do desempenho é um processo sistemático de\nanálise do desempenho de um funcionário no cargo\nexecutando suas funções, em função do contexto de seu\ntrabalho. A problemática existente no processo de\navaliação de desempenho originou várias soluções que\nficaram conhecidas como métodos tradicionais de avaliação\nde desempenho. O método que consiste em avaliar o\ndesempenho das pessoas por meio de frases descritivas\ncom alternativas de tipos de desempenho individual e em\nque, em cada bloco, existirão algumas frases possíveis para\nque o avaliador analise e escolha, marcando uma ou duas\ncaracterísticas de cada avaliado, é conhecido por:", "alt": {"A": "Método das Escalas Gráficas.", "B": "Método da Escolha Forçada.", "C": "Método dos Incidentes Críticos.", "D": "Método da Pesquisa de Campo.", "E": "Método de Listas de Verificação – checklist."}, "g": "B", "j": "Metodo da Escolha Forcada (Chiavenato): avalia desempenho por meio de blocos de frases descritivas em que o avaliador escolhe forcosamente uma ou duas que caracterizam o avaliado."}, {"id": "801146", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2016", "org": "CFP", "t": "", "e": "As Secretarias do Conselho Federal de Psicologia são\ndenominadas: 5 (cinco) Secretarias Regionais, sendo uma\npara cada região geográfica; Secretaria de Orientação e\nÉtica; e Secretaria de Comunicação.\n  São atribuições do Secretário de Orientação e Ética\nconduzir os processos, responder a consultas e tomar as\nmedidas relacionadas, exceto:", "alt": {"A": "à legislação interna.", "B": "à orientação e fiscalização do exercício profissional.", "C": "à edição das publicações do Conselho Federal de\nPsicologia.", "D": "a processos eleitorais.", "E": "a processos, consultas e medidas relacionadas ao\nCódigo de Ética Profissional do Psicólogo."}, "g": "C", "j": "A edicao das publicacoes do CFP e atribuicao da Secretaria de Comunicacao, nao da Secretaria de Orientacao e Etica."}, {"id": "601639", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2016", "org": "CFP", "t": "", "e": "Assinale a alternativa que contraria a Resolução CFP\nnº 003/2007 (que institui a Consolidação das Resoluções do\nConselho Federal de Psicologia), acerca da inscrição\nsecundária nos Conselhos Regionais.", "alt": {"A": "As atividades que se desenvolvam em tempo inferior a\n90 (noventa) dias por ano, em cada região, serão\nconsideradas de natureza eventual e, por conseguinte,\nnão sujeitarão o psicólogo à inscrição secundária.", "B": "O exercício da profissão, fora da área de jurisdição do\nConselho Regional de Psicologia em que o profissional\ntem inscrição principal, não o obriga à inscrição\nsecundária no Conselho competente.", "C": "Considera-se inscrição secundária o comunicado formal\ndo psicólogo, ao CRP da jurisdição onde o trabalho será\nrealizado, recebendo este um certificado de\nautorização do Conselho.", "D": "A inscrição secundária não acarretará ônus financeiro\nao psicólogo.", "E": "Deverá se inscrever no Conselho Regional de Psicologia\no portador de diploma de psicólogo que exerça\natividades privativas dessa profissão,\nindependentemente do seu enquadramento funcional\nna organização."}, "g": "B", "j": "Res CFP 003/2007: o exercicio profissional fora da jurisdicao do CRP de inscricao principal por periodo superior a 90 dias OBRIGA a inscricao secundaria - a alternativa B contraria a resolucao."}, {"id": "519032", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2015", "org": "CRP", "t": "", "e": "São modalidades de documentos decorrentes da avaliação\npsicológica:", "alt": {"A": "atestado, relatório e estudo psicológico.", "B": "atestado, relatório e laudo psicológico.", "C": "estudo, relatório e laudo psicológico.", "D": "atestado, entrevista e relatório psicológico.", "E": "estudo, entrevista e relatório psicológico."}, "g": "B", "j": "Modalidades de documentos da avaliacao psicologica conforme Res CFP 007/2003 e 006/2019: declaracao, atestado, relatorio/laudo psicologico e parecer. A unica alternativa coerente e B."}, {"id": "519030", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2015", "org": "CRP", "t": "", "e": "O Conselho Regional de Psicologia é composto pelos\nseguintes órgãos, exceto:", "alt": {"A": "Plenário.", "B": "Comissões.", "C": "Tesouraria.", "D": "Congressos.", "E": "Assembléias."}, "g": "C", "j": "Orgaos do CRP: Plenario, Comissoes, Congressos e Assembleias. Tesouraria nao e orgao - integra a Diretoria."}, {"id": "519025", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2015", "org": "CRP", "t": "", "e": "A respeito do exercício profissional do psicólogo, disciplinado\npelo Decreto n° 53.646/1964, assinale a alternativa correta.", "alt": {"A": "A designação profissional de psicólogo pode ser\nlivremente utilizada por qualquer profissional que emita\ndiagnóstico.", "B": "O psicólogo não pode exercer a função de professor.", "C": "O psicólogo é autorizado a dirigir serviços de psicologia\nem órgãos e estabelecimentos públicos, autárquicos,\nparaestatais, de economia mista e particulares.", "D": "É vedado ao psicólogo emitir parecer ou realizar perícia\nsobre qualquer assunto.", "E": "Ao psicólogo é permitido fazer diagnóstico psicológico,\nmas não pode supervisionar alunos em trabalhos teóricos\ne práticos de Psicologia."}, "g": "C", "j": "Decreto 53.464/64 autoriza o psicologo a dirigir servicos de psicologia em orgaos publicos, autarquicos, paraestatais, de economia mista e particulares."}, {"id": "519024", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2015", "org": "CRP", "t": "", "e": "Constitui função privativa do Psicólogo, exceto:", "alt": {"A": "diagnóstico psicológico.", "B": "orientação e seleção profissional.", "C": "orientação psicopedagógica.", "D": "diagnóstico neurológico.", "E": "solução de problemas de ajustamento."}, "g": "D", "j": "Diagnostico neurologico e atribuicao privativa do medico neurologista, nao do psicologo."}, {"id": "1238024", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2014", "org": "CRP - 10ª Região (AP e PA)", "t": "", "e": "Analise as seguintes funções.\n  I- Dirigir serviços de Psicologia em Órgãos e estabelecimentos públicos, autárquicos, paraestatais, de economia mista e particulares    II-  Ensinar as cadeiras ou disciplinas de Psicologia nos vários níveis de ensino, observadas as demais exigências da legislação em vigor.    III- Supervisionar profissionais e alunos em trabalhos teóricos e práticos de Psicologia.\n    Pode-se afirmar que, de acordo com o Decreto nº 53.464/64, são funções do psicólogo:", "alt": {"A": "somente I e II.", "B": "somente I e III.", "C": "somente II e III.", "D": "nenhuma.", "E": "todas."}, "g": "E", "j": "Decreto 53.464/64: as tres funcoes listadas (dirigir servicos, ensinar e supervisionar) sao funcoes do psicologo."}, {"id": "1235176", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2013", "org": "CFP", "t": "", "e": "O teste consiste no desenho de 30 objetos comuns. Cada objeto é apresentado segmentado em duas ou mais partes que são arranjadas aleatoriamente no desenho. O tempo requerido para a aplicação varia entre dez a quinze minutos. A descrição apresentada é compatível com o teste:", "alt": {"A": "Hooper.", "B": "COWA FAS.", "C": "Token Test.", "D": "Finger Tapping.", "E": "Boston Naming."}, "g": "A", "j": "Hooper Visual Organization Test consiste em 30 desenhos de objetos segmentados que devem ser identificados, com aplicacao em 10-15 minutos."}, {"id": "1230724", "d": "psicologia", "a": ["Psicologia do Desenvolvimento"], "ano": "2013", "org": "CFP", "t": "", "e": "Algumas pesquisas desenvolvidas por Hubel e Wiesel (1965) indicaram que o desenvolvimento da dominância ocular depende tanto do input sensorial quanto do tempo em que a experiência ocorre. A identificação de que há uma janela temporal mais suscetível a transformações neurais é denominado:", "alt": {"A": "Período ontogenético.", "B": "Período crítico.", "C": "Período filogenético.", "D": "Janela somática.", "E": "Enriquecimento somático."}, "g": "B", "j": "Pesquisas de Hubel e Wiesel sobre dominancia ocular consolidaram o conceito de 'periodo critico' para a plasticidade neural dependente da experiencia."}, {"id": "1225946", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2013", "org": "CFP", "t": "", "e": "Ao considerar os muitos fatores que constituem a realidade escolar e suas influências na escolarização dos alunos, assinale a alternativa que expressa a concepção contextual errônea por parte do Psicólogo Escolar.", "alt": {"A": "Alunos que são perseguidos ou ridicularizados por seus colegas na escola podem apresentar dificuldades afetivas/de autoestima.", "B": "O Psicólogo Escolar deve ter como ponto de partida a formação familiar do aluno. Famílias desestruturadas promovem invariavelmente alunos com dificuldades.", "C": "A atenção no cotidiano escolar é primordial para compreender as teias de relações que permeiam esse contexto.", "D": "Alunos que apresentam insucesso escolar podem necessitar de um atendimento psicoeducacional mais focado na remediação de sua dificuldade.", "E": "O fracasso do aluno geralmente é produto de uma gama de fatores que devem ser levados em conta, tais como escola/ professores/ família/ interação com os colegas, dentre outros."}, "g": "B", "j": "A concepcao erronea e o determinismo familiar ('familias desestruturadas promovem invariavelmente alunos com dificuldades'), incompativel com a perspectiva critica da Psicologia Escolar contemporanea."}, {"id": "1224447", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2013", "org": "CFP", "t": "", "e": "Ainda tratando do período inicial da Psicologia do Esporte como ciência, podemos afirmar que muitas pesquisas começaram a aparecer. Qual foi o tema que norteou as primeiras pesquisas em Psicologia do Esporte?", "alt": {"A": "Indicadores de perfil de personalidade na escolha de modalidades esportivas.", "B": "Manifestação de comportamento operante e respondente em jogos.", "C": "Criação do modelo de atenção e concentração.", "D": "Motivação e explicação de melhores desempenhos.", "E": "Teoria sobre ativação, estresse e ansiedade."}, "g": "D", "j": "As primeiras pesquisas em Psicologia do Esporte centraram-se na motivacao e na explicacao de melhores desempenhos esportivos."}, {"id": "1221887", "d": "psicologia", "a": ["Foucault", "Psicologia Social"], "ano": "2013", "org": "CFP", "t": "", "e": "Para Foucault:  I. o suplício como punição de crimes apenas migrou do corpo para a alma.    II. o sistema jurídico moderno “julga” também a alma do acusado e, nessa ação, muitas vezes o psicólogo é incluído.    III. quando o psicólogo ou outro profissional assume a incumbência de determinar se uma pessoa deve ou não receber os benefícios da Lei de Execuções Penais, este profissional está participando do sistema de punição.    Está correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente II.", "C": "somente III.", "D": "todas.", "E": "nenhuma."}, "g": "D", "j": "Foucault (Vigiar e Punir): suplicio migra do corpo para a alma (I); sistema juridico moderno julga tambem a alma (II); profissional que avalia beneficios da LEP participa do sistema punitivo (III). Todas corretas."}, {"id": "1220544", "d": "psicologia", "a": ["Psicologia Institucional"], "ano": "2013", "org": "CFP", "t": "", "e": "Para Goffman, instituições totais:  I. despem o interno, assim que este chega, de sua concepção de eu, por meio de ações sistemáticas de humilhação, rebaixamento e padronização de hábitos, comportamentos e vestimentas.    II. são aquelas que se preocupam com a totalidade do indivíduo.    III. muitas vezes provocam reações de silêncio, agressividade e apatia nos internados novatos, comportamentos esses que demonstram a incapacidade desses internados para a vida em sociedade.    Está correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente II.", "C": "somente III.", "D": "nenhuma.", "E": "todas."}, "g": "A", "j": "Goffman (Manicomios, Prisoes e Conventos): apenas I esta correta - instituicoes totais despem o interno via humilhacao, rebaixamento e padronizacao. II e III distorcem o conceito."}, {"id": "1214161", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2013", "org": "CFP", "t": "", "e": "As sequelas decorrentes das lesões devidas a acidentes e a violência no trânsito, quando não levam o paciente diretamente à morte, podem demandar uma internação, às vezes longa, com gastos elevados. Sobre os diferentes aspectos associados aos agravos do trânsito, assinale a alternativa incorreta.", "alt": {"A": "A taxa de mortos por acidentes de moto cresce a taxas elevadíssimas nas principais capitais do Brasil, estando os condutores jovens enquadrados como maiores vítimas desses eventos.", "B": "Os acidentes representam para o país o ônus da perda de valiosos anos de vida produtiva e o custo de um tratamento médico-hospitalar que, em muitos casos, pode prolongar-se por toda a vida.", "C": "A plena implantação do Código de Trânsito Brasileiro (CTB), com especial atenção às normas de caráter preventivo, pode representar um ganho aos aspectos de saúde dos usuários do sistema de trânsito.", "D": "O consumo abusivo de bebidas alcoólicas constitui-se problema de saúde pública e sua repercussão nos segmentos do trânsito, um risco à vida.", "E": "O estudo das variáveis individuais de condutores pouco se mostra preditivo para entendimento dos fatores inerentes ao comportamento de risco no trânsito."}, "g": "E", "j": "E e incorreta: o estudo das variaveis individuais dos condutores e justamente um dos focos preditivos do comportamento de risco no transito."}, {"id": "1212681", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2013", "org": "CFP", "t": "", "e": "Sobre a avaliação de desempenho de funcionários de uma organização, é incorreto afirmar que:", "alt": {"A": "há diferenças entre as percepções dos trabalhadores e dos dirigentes de uma organização sobre a avaliação de desempenho.", "B": "como todas as estratégias de recursos humanos, a avaliação de desempenho é meramente instrumental, sem nenhum caráter político.", "C": "a avaliação de desempenho pode ser, simultaneamente, instrumento de pressão para o trabalhador, e base orientadora do desenvolvimento pessoal e profissional dos trabalhadores para os gestores.", "D": "o feedback é parte central do processo de avaliação de desempenho.", "E": "a avaliação de desempenho é um recurso administrativo e uma estratégia de poder."}, "g": "B", "j": "A avaliacao de desempenho NAO e meramente instrumental - possui dimensao politica e e estrategia de poder, conforme literatura critica de RH."}, {"id": "1200217", "d": "psicologia", "a": ["LER-DORT", "Psicologia e Organizações"], "ano": "2013", "org": "CFP", "t": "", "e": "Com relação às LER-DORT, pode-se afirmar que:", "alt": {"A": "o fator biomecânico é suficiente para a compreensão do fenômeno das LER-DORT.", "B": "as LER-DORT são um fenômeno multifatorial e multidimensional.", "C": "as LER-DORT são uma doença de fácil remissão.", "D": "as LER-DORT dificilmente provocam danos irreversíveis aos trabalhadores.", "E": "a Psicologia Organizacional e do Trabalho tem pouco a contribuir com a compreensão e intervenção das LER-DORT."}, "g": "B", "j": "LER-DORT e fenomeno multifatorial e multidimensional (biomecanico, organizacional, psicossocial), nao se reduzindo a um unico fator."}, {"id": "1196322", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos", "Papéis Sociais e Relações de Gênero"], "ano": "2013", "org": "CFP", "t": "", "e": "Para Uziel:  I. se a filiação é construída pelo Estado, por meio de suas leis, a filiação homossexual faz parte desse universo.    II. as poucas pesquisas sobre o desenvolvimento de crianças em lares homossexuais (homoafetivos) apontam não haver diferenças ao das crianças de lares heterossexuais (heteroafetivos).    III. as identificações formadoras da identidade das crianças sofrem abalos em várias famílias, não havendo relação entre a gravidade desses abalos e a família homoparental.    Está correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente II.", "C": "somente III.", "D": "todas.", "E": "nenhuma."}, "g": "D", "j": "Uziel: todos os tres itens estao corretos sobre filiacao homoafetiva, ausencia de diferencas no desenvolvimento e ausencia de relacao entre abalos identitarios e configuracao familiar."}, {"id": "1190957", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2013", "org": "CFP", "t": "", "e": "A produção de conhecimento na área de Psicologia Escolar aponta, há vários anos, para a “importância, não só de ensinar aos alunos o conteúdo, mas, também, de promover nos estudantes a consciência dos processos pelos quais se aprende (Pfromm Neto, 1987, Pozo, 1996)”    (Boruchovitch, 2001).    A partir da compreensão de que o sujeito tem uma participação ativa e dinâmica na apropriação do conhecimento, reflita sobre as contribuições da atuação em Psicologia Escolar para os processos de aprendizagem da leitura e escrita e, em seguida, responda à questão.    Escolha a alternativa que representa a sequência correta de palavras no trecho a seguir.    As especificidades de cada sujeito são definidas em sua interface com o mundo, mediante uma interação ______ e _________ entre fatores ________ e _________ a ele, constituindo-se __________ e _____________. Nessa perspectiva, ao analisar as dificuldades que se apresentam durante o processo pedagógico, expressas nas ações de _________ e ___________, a atuação do Psicólogo Escolar contribui para a desconstrução de posturas cristalizadas, na medida em que não responsabiliza os indivíduos envolvidos no processo (_________ e _________), mas sim, analisa as ____________ que esses atores estabelecem no contexto escolar.", "alt": {"A": "passiva; pontual; positivos; negativos; individual; isoladamente; aprender; memorizar; aluno; família; dificuldades", "B": "ativa; constante; internos; externos; histórica; subjetivamente; ensinar; aprender; professor; aluno; relações", "C": "ativa; pontual; internos; externos; histórica; comportamentalmente; memorizar; reproduzir; família; aluno; crises", "D": "passiva; penosa; positivos; negativos; individual; constantemente; ensinar; aprender; professor; aluno; dificuldades", "E": "ativa; constante; internos; próprios; individual; subjetivamente; imitar; memorizar; meninos; meninas; relações"}, "g": "B", "j": "A sequencia correta segue a perspectiva critica da Psicologia Escolar: interacao ativa e constante entre fatores internos e externos, constituindo o sujeito historica e subjetivamente, focando relacoes entre professor e aluno."}, {"id": "1186850", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2013", "org": "CFP", "t": "", "e": "Em O Papel do Psicólogo, Ignácio Martín-Baró diz: “Existe uma crescente consciência entre os psicólogos latino-americanos de que, na hora de definir a nossa identidade profissional e o papel que devemos desempenhar em nossas sociedades, é muito mais importante examinar a situação histórica de nossos povos e suas necessidades do que estabelecer o âmbito específico da psicologia como ciência ou como atividade. Percebe-se cada vez com maior clareza que as definições genéricas procedentes de outros lugares trazem uma compreensão de nós mesmos e dos outros muitas vezes míopes diante das realidades que a maioria dos nossos povos enfrenta e são inadequadas para captar sua especificidade social e cultural”. O grande psicólogo hispano-salvadorenho está afirmando que:  I. mais que importar teorias, importa que o desenvolvimento do conhecimento esteja balizado pelas condições culturais e históricas de um povo.    II. nossos povos não têm a capacidade de compreender as definições genéricas procedentes de outros lugares.    Pode-se afirmar que:", "alt": {"A": "somente I está correta.", "B": "somente II está correta.", "C": "tanto I quanto II estão corretas.", "D": "tanto I quanto II estão erradas.", "E": "II está correta, mas não se aplica ao texto."}, "g": "A", "j": "Martin-Baro afirma que mais importa balizar o conhecimento pelas condicoes culturais e historicas (I correta). A afirmativa II e generalizacao indevida."}, {"id": "1186784", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2013", "org": "CFP", "t": "", "e": "O termo “funções executivas” relaciona-se a um conjunto amplo de processos cognitivos complexos, que incluem iniciação, planejamento, flexibilidade, tomada de decisão e geração de hipóteses, dentre outros. Os estudos recentes têm destacado o papel central da alteração de função executiva em alguns quadros clínicos específicos. Dos quadros listados, não está diretamente relacionado à função executiva:", "alt": {"A": "Autismo.", "B": "Agnosia.", "C": "Esquizofrenia.", "D": "Dependência Química a Álcool e Outras Drogas.", "E": "Transtorno de Déficit de Atenção e Hiperatividade."}, "g": "B", "j": "Agnosia e disturbio perceptivo de reconhecimento, nao esta diretamente relacionada a funcoes executivas. Os demais quadros (autismo, esquizofrenia, dependencia, TDAH) tem alteracoes executivas centrais."}, {"id": "1185859", "d": "psicologia", "a": ["Psicopatologia", "Exames Mentais e Funções Psíquicas"], "ano": "2013", "org": "CFP", "t": "", "e": "Um jovem de 30 anos, após um acidente automobilístico, começa a apresentar uma modalidade específica de alteração cognitiva: uma considerável dificuldade de reconhecer faces, que é denominada:", "alt": {"A": "Agnosia.", "B": "Dislexia.", "C": "Amnésia.", "D": "Prosopagnosia.", "E": "Amnésia visual."}, "g": "C", "j": "Prosopagnosia e o termo tecnico para o deficit especifico de reconhecimento de faces, frequentemente apos lesao em regiao temporo-occipital."}, {"id": "1185858", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2013", "org": "CFP", "t": "", "e": "Para a avaliação de nível cognitivo em crianças de quatro anos é adequada a utilização de:", "alt": {"A": "situações lúdicas livres, somente.", "B": "G-36 e Bateria Lourenço Filho.", "C": "Escala de Maturidade Intelectual Columbia e Provas Piagetianas.", "D": "as Escalas Weschler de Inteligência para Crianças (WISC III), somente.", "E": "Escalas Weschler para Crianças IV e Escala de Maturidade Intelectual Columbia."}, "g": "C", "j": "Para criancas de 4 anos sao adequados a Escala de Maturidade Intelectual Columbia e as Provas Piagetianas. WISC III/IV iniciam a partir de 6 anos."}, {"id": "773613", "d": "psicologia", "a": ["Psicanálise", "Freud", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2013", "org": "CFP", "t": "", "e": "Na definição de Freud sobre a Psicanálise, presente em seu\ntrabalho “Dois verbetes de Enciclopédia” (1922), pode-se\nverificar que:", "alt": {"A": "a psicanálise é caracterizada como uma ciência leiga\npara além da medicina que usa um método já\nconsagrado.", "B": "apresenta a psicanálise como um método, um\nprocedimento e uma coleção de informações\npsicológicas.", "C": "limita a extensão da interpretação ao setting\nterapêutico.", "D": "remodela a noção de Inconsciente com o uso dos\nmecanismos de recalque.", "E": "caracteriza o Ego como uma instância de menor\nimportância quanto à expressão dos dinamismos\nmentais."}, "g": "B", "j": "Em 'Dois verbetes de Enciclopedia' (1922), Freud apresenta a psicanalise como um metodo de investigacao, um procedimento terapeutico e uma colecao de informacoes psicologicas."}, {"id": "773612", "d": "psicologia", "a": ["Freud", "Teorias da Personalidade"], "ano": "2013", "org": "CFP", "t": "", "e": "Freud, no seu trabalho “A questão da Análise leiga” (1926),\nidentifica e caracteriza a possibilidade da Psicanálise ser:", "alt": {"A": "uma ciência voltada às necessidades mais cotidianas\ndas pessoas.", "B": "realizada por médicos e por não médicos.", "C": "realizada em quadros clínicos sem se atentar\nà questão\nde diagnósticos definidos por médicos.", "D": "possível de ser realizada fora do meio acadêmico em\natividades clínicas.", "E": "uma ciência que se volta à noção da normalidade\n, mais\nque\nà patologia do cotidiano."}, "g": "B", "j": "Em 'A Questao da Analise Leiga' (1926), Freud defende a possibilidade de a psicanalise ser realizada por medicos e nao medicos (analistas leigos)."}, {"id": "773608", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2013", "org": "CFP", "t": "", "e": "As infrações disciplinares dispostas no Código de Ética\nProfissional do Psicólogo são objeto das seguintes\npenalidades e procedimentos:", "alt": {"A": "Advertência; multa; censura pública; suspensão do\nexercício profissional, por até 30 (trinta) dias, ad\nreferendum do Conselho Federal de Psicologia; cassação\ndo exercício profissional, ad referendum do Conselho\nFederal de Psicologia.", "B": "Advertência escrita; multa; censura pública; suspensão\ndo exercício profissional, por até 30 (trinta) dias, ad\nreferendum do Conselho Regional de Psicologia;\ncassação do exercício profissional, ad referendum do\nConselho Regional de Psicologia.", "C": "Advertência; multa; censura pública; suspensão do\nexercício profissional, por até 20 (vinte) dias, ad\nreferendum do Conselho Regional de Psicologia, e\nposterior denúncia ao Ministério Público Federal.", "D": "Advertência verbal; multa; censura pública; suspensão\ndo exercício profissional, por até 60 (sessenta) dias, ad\nreferendum do Conselho Regional de Psicologia;\ncassação do exercício profissional, ad referendum do\nConselho Federal de Psicologia, e posterior denúncia ao\nMinistério Público Federal.", "E": "Advertência; multa; censura pública; suspensão do\nexercício profissional, por até 10 (dez) dias, ad\nreferendum do Conselho Federal de Psicologia; cassação\ndo exercício profissional, ad referendum do Conselho\nFederal de Psicologia e posterior denúncia ao Ministério\nPúblico do Trabalho."}, "g": "A", "j": "CEP Psicologo (Res 10/2005): penalidades sao advertencia, multa, censura publica, suspensao por ate 30 dias ad referendum do CFP e cassacao ad referendum do CFP."}, {"id": "773607", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2013", "org": "CFP", "t": "", "e": "Sobre a elaboração de uma bateria de testes para um\nprocesso avaliativo, Arzeno caracteriza como aspectos\nimportantes o fato de o psicólogo atentar para:", "alt": {"A": "demanda, frequência de encontros, elementos da\npersonalidade a serem investigados e o sexo do\nexaminando.", "B": "tempo de atendimento, demanda, idade e sexo do\nexaminando e nível cultural dos pais do examinando.", "C": "o solicitante, a idade e o nível cultural do avaliando,\npossíveis deficiências, o momento vital, o contexto\nespaço-temporal da avaliação e elementos da\npersonalidade a investigar.", "D": "base teórica do psicólogo, tempo de atendimento,\nidade e sexo do avaliando, escolaridade da família e\nmotivo do atendimento.", "E": "formação e linha teórica do psicólogo, sexo e idade do\navaliando, demanda do atendimento, aspectos\nculturais e diagnóstico do avaliando."}, "g": "C", "j": "Arzeno: na elaboracao de uma bateria de testes o psicologo deve considerar o solicitante, idade, nivel cultural, deficiencias, momento vital, contexto espaco-temporal e elementos de personalidade."}, {"id": "773606", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Luta Antimanicomial"], "ano": "2013", "org": "CFP", "t": "", "e": "A Resolução nº 251/2002, do Ministério da Saúde, propõe\ncaracterizar e abordar as questões de desenvolvimento:", "alt": {"A": "dos Centros de Atenção Psicossocial que poderão\nconstituir-se nas modalidades de serviços.", "B": "de atividades de assessoramento, internação e\nclassificação de psicopatologias e terapêuticas\nmedicamentosas.", "C": "da estrutura do atendimento psicossocial de pessoas\ncom necessidades especiais.", "D": "de estrutura do atendimento psicossocial de pessoas,\nalém das internações psiquiátricas na rede do SUS.", "E": "da assistência hospitalar em psiquiatria, reclassificando\nos hospitais psiquiátricos, definindo e estruturando a\nporta de entrada para as internações psiquiátricas na\nrede do SUS."}, "g": "E", "j": "Portaria MS 251/2002 trata da assistencia hospitalar em psiquiatria, reclassificando hospitais psiquiatricos e definindo a porta de entrada para internacoes psiquiatricas no SUS."}, {"id": "773605", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2013", "org": "CFP", "t": "", "e": "Para Straub, a definição de saúde é como um estado\npositivo e multidimensional que envolve a presença de três\ndomínios. Quais?", "alt": {"A": "Físico, mental e laboral.", "B": "Assistencialista, curativo e de promoção.", "C": "Imediato, curativo e preventivo.", "D": "Saúde física, saúde psicológica e saúde social.", "E": "Individual, comunitário e social."}, "g": "D", "j": "Straub define saude como estado positivo e multidimensional com tres dominios: saude fisica, saude psicologica e saude social."}, {"id": "773603", "d": "psicologia", "a": ["Grupos Operativos", "Teorias e Técnicas Psicoterápicas"], "ano": "2013", "org": "CFP", "t": "", "e": "O conjunto de experiências, conhecimentos e afetos com os\nquais o indivíduo pensa e atua é definido como:", "alt": {"A": "ensino grupal.", "B": "esquema referencial.", "C": "aprendizagem.", "D": "grupo operativo.", "E": "ações grupais."}, "g": "B", "j": "Esquema referencial (Pichon-Riviere): conjunto de experiencias, conhecimentos e afetos com os quais o individuo pensa e atua."}, {"id": "773602", "d": "psicologia", "a": ["Entrevista Psicológica e Técnicas de Entrevista"], "ano": "2013", "org": "CFP", "t": "", "e": "Segundo Bleger, a regra básica da entrevista consiste em:", "alt": {"A": "obter o encadeamento dos pontos abordados na\nsessão.", "B": "verificar a veracidade das informações prestadas pelo\npaciente.", "C": "realizar diagnóstico estrutural do quadro clínico por\nmeio dos sintomas percebidos.", "D": "possibilitar confronto com as informações\nanteriormente obtidas pelos familiares.", "E": "obter dados completos do comportamento total no\ndecorrer da entrevista."}, "g": "E", "j": "Bleger: regra basica da entrevista psicologica e obter dados completos do comportamento total do entrevistado no decorrer da entrevista."}, {"id": "773601", "d": "psicologia", "a": ["Psicanálise", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas", "Grupos Terapêuticos"], "ano": "2013", "org": "CFP", "t": "", "e": "Características como a presença de objetivos limitados,\nalívio direto de sintomas, reforço de funções de defesa e\nadaptação, visando ao estado dinâmico, se referem à\nterapia de:", "alt": {"A": "Insight.", "B": "TCC.", "C": "Psicanálise lacaniana.", "D": "grupo.", "E": "apoio."}, "g": "E", "j": "As caracteristicas descritas (objetivos limitados, alivio direto de sintomas, reforco de defesas e adaptacao) sao da terapia de apoio."}, {"id": "773600", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2013", "org": "CFP", "t": "", "e": "Segundo Dewald, os objetivos da psicoterapia dirigida ao\ninsight são:", "alt": {"A": "minimização do conflito, manutenção de condições\nadaptativas, reiteração e maturação da personalidade.", "B": "manutenção da personalidade, maximização da\ncomunicação e redução da ansiedade.", "C": "resolução do conflito, maturação da personalidade e\ndesenvolvimento de novos modos de adaptação.", "D": "minimização do conflito, maximização da comunicação\ne reiteração e maturação da personalidade.", "E": "resolução do conflito, maximização da comunicação e\nreiteração e maturação da personalidade."}, "g": "C", "j": "Dewald: objetivos da psicoterapia voltada ao insight sao a resolucao do conflito, a maturacao da personalidade e o desenvolvimento de novos modos de adaptacao."}, {"id": "773598", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2013", "org": "CFP", "t": "", "e": "Tendo em vista o aumento da busca de atendimentos\npsicológicos por idosos, os processos psicoterapêuticos são\ncada vez mais requisitados. Como objetivos da psicoterapia\ncom idosos, podemos citar:", "alt": {"A": "alívio sintomático, adaptação às alterações de vida,\naceitação de uma situação de maior dependência e\nmelhora da autoestima.", "B": "diminuição da dependência, redução de quadros\ndemenciais, ativação cardiorrespiratória e valorização\nde esquemas anteriores de comportamento.", "C": "diminuição do risco de demências, mudanças de\nhumor, incremento da ansiedade situacional e\naumento da autoestima.", "D": "alterações do humor, restrição de ações aversivas,\nadaptação às alterações vitais e aumento da\nlongevidade.", "E": "diminuição do risco de adição, alterações da percepção\nsocial, limitações vitais e diminuição da ansiedade."}, "g": "A", "j": "Objetivos da psicoterapia com idosos: alivio sintomatico, adaptacao as alteracoes vitais, aceitacao da maior dependencia e melhora da autoestima."}, {"id": "773595", "d": "psicologia", "a": ["Psicoterapias", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas", "Grupos Terapêuticos"], "ano": "2013", "org": "CFP", "t": "", "e": "O processo terapêutico que auxilia o paciente a explicitar as\nvariáveis que influenciam seu comportamento, podendo, a\npartir disso, levar a pessoa a modificar seu ambiente para\nque possam ocorrer mudanças no seu comportamento é:", "alt": {"A": "terapia energética.", "B": "terapia cognitivo-comportamental.", "C": "terapia de orientação analítica.", "D": "terapia de suporte.", "E": "terapia de grupo de base analítica."}, "g": "B", "j": "Terapia cognitivo-comportamental: auxilia o paciente a explicitar variaveis que influenciam o comportamento e a modificar seu ambiente para gerar mudancas."}, {"id": "773594", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2013", "org": "CFP", "t": "", "e": "Em terapias de enfoque dinâmico, é papel do paciente:", "alt": {"A": "acatar as explicações e interpretações do terapeuta.", "B": "adotar como fonte de transformação a autoridade\ntécnica e teórica do terapeuta.", "C": "produzir esforços contínuos de autoexploração.", "D": "colaborar com o processo terapêutico por meio de\nleituras complementares.", "E": "falar, expressar-se, responder e se relacionar com o\nterapeuta."}, "g": "E", "j": "Em terapias de enfoque dinamico, cabe ao paciente falar, expressar-se, responder e se relacionar com o terapeuta (associacao livre)."}, {"id": "773593", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2013", "org": "CFP", "t": "", "e": "Quando o psicólogo realiza um psicodiagnóstico utilizando\ntestes:", "alt": {"A": "é desnecessária a preocupação com a questão\ntransferencial.", "B": "pode ocorrer contratransferência.", "C": "pode considerar que projeções de paciente e terapeuta\nsão típicas só nas psicoterapias.", "D": "é preciso ver todos os testes como instrumentos\nmeramente objetivos.", "E": "deve considerar que o período de contato é muito\npequeno para se pensar em processos projetivos."}, "g": "B", "j": "No psicodiagnostico com testes, pode ocorrer contratransferencia, ja que o vinculo testador-testando mobiliza afetos."}, {"id": "773587", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2013", "org": "CFP", "t": "", "e": "Quando se discute a utilização de drogas em concomitância\ncom a psicoterapia, é incorreto afirmar que:", "alt": {"A": "as drogas devem ser vistas como procedimento auxiliar\nà psicoterapia.", "B": "não é adequado juntar os dois procedimentos porque a\ndroga inibe totalmente a capacidade de elaboração do\npaciente.", "C": "o terapeuta precisa estar alerta para não depositar\nconfiança demasiada na eficácia da droga.", "D": "o terapeuta precisa discutir com clareza e firmeza a\nnecessidade da medicação.", "E": "a droga, ao ajudar na melhora do mal-estar do\nsintoma, oferece o fortalecimento da relação com o\nterapeuta."}, "g": "B", "j": "E incorreto afirmar que farmaco e psicoterapia nao podem ser combinados porque a droga inibe totalmente a elaboracao - a literatura indica articulacao possivel e frequentemente proveitosa."}, {"id": "773585", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Terapia familiar"], "ano": "2013", "org": "CFP", "t": "", "e": "Assinale a afirmativa que aponta para indicação de terapia\nfamiliar.", "alt": {"A": "Negação familiar de ocorrência de problemas.", "B": "Tendência irreversível à ruptura familiar.", "C": "Quando os cônjuges têm segredos não reveláveis.", "D": "O problema atual envolve dois ou mais membros da\nfamília.", "E": "Há problemas individuais que necessitam de outros\ntratamentos."}, "g": "D", "j": "A terapia familiar e indicada quando o problema atual envolve dois ou mais membros da familia. As demais alternativas indicam contraindicacoes."}, {"id": "773584", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Grupos Terapêuticos"], "ano": "2013", "org": "CFP", "t": "", "e": "Assinale a opção que não faz parte dos fatores terapêuticos\nda terapia de grupo.", "alt": {"A": "Repertório diminuto de seguimento de normas grupais.", "B": "Compartilhamento de informações.", "C": "Aprendizagem interpessoal.", "D": "Vivências catárticas.", "E": "Instilação de esperança."}, "g": "A", "j": "Repertorio diminuto de seguimento de normas grupais e disfuncao do grupo, nao fator terapeutico. Os demais (compartilhamento, aprendizagem interpessoal, catarse, instilacao de esperanca) sao fatores terapeuticos de Yalom."}, {"id": "773583", "d": "psicologia", "a": ["Freud", "Teorias da Personalidade"], "ano": "2013", "org": "CFP", "t": "", "e": "Num texto de 1926, discorrendo sobre o conteúdo da\nPsicanálise, Freud apresenta várias afirmativas. Aponte a\nafirmativa que não pertence a Freud.", "alt": {"A": "A psicanálise traz aos pacientes benefícios maiores do\nque outras formas de tratamento.", "B": "A psicanálise não se configura como panaceia para\ntodos os transtornos psíquicos.", "C": "Sua influência sobre a demência precoce e a paranoia é\ninquestionável.", "D": "Seu principal setor de aplicação é aquele das neuroses\nmais leves, como a histeria e as fobias.", "E": "No futuro, provavelmente a Psicanálise será vista\nmuito mais como ciência do inconsciente do que como\num método terapêutico."}, "g": "C", "j": "Freud reconheceu limitacoes da psicanalise em psicoses como demencia precoce e paranoia - afirmar que sua influencia nelas e inquestionavel nao pertence a Freud."}, {"id": "773578", "d": "psicologia", "a": ["Psicopatologia", "Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas", "Psicossomática", "Psicologia da Saúde", "Dor, Estresse e Luto", "Transtornos do Neurodesenvolvimento", "Transtornos do Humor", "Transtornos Alimentares", "Esquizofrenia e outros Transtornos Psicóticos"], "ano": "2013", "org": "CFP", "t": "", "e": "A indicação de terapia cognitiva está bem estabelecida:", "alt": {"A": "no retardo mental.", "B": "na psicose aguda.", "C": "nos transtornos alimentares.", "D": "no transtorno bipolar.", "E": "na dor crônica."}, "g": "C", "j": "A indicacao da terapia cognitiva esta bem estabelecida nos transtornos alimentares (anorexia e bulimia nervosa), com vasta literatura de evidencia."}, {"id": "773575", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2013", "org": "CFP", "t": "", "e": "Os estudos e pesquisas em neurociência trazem qual\nperspectiva para as psicoterapias, entre as citadas a seguir?", "alt": {"A": "A substituição das terapias pelos tratamentos\norgânicos.", "B": "A real compreensão do mistério do funcionamento\npsíquico.", "C": "O questionamento severo do fundamento das\nabordagens que adotam o inconsciente.", "D": "As explicações da neurociência para compreensão dos\nefeitos produzidos pela psicoterapia.", "E": "As variáveis biológicas são desnecessárias para a\ncompreensão do fenômeno psicológico."}, "g": "D", "j": "As neurociencias ampliam a compreensao das psicoterapias ao oferecer explicacoes neurobiologicas para os efeitos por elas produzidos."}, {"id": "3005481", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Considerando os avanços da Ciência Psicológica, os quais têm propiciado a emergência de áreas de conhecimento específico para a atuação do profissional de Psicologia, a Resolução CFP nº 013/2007 institui a consolidação das resoluções relativas ao título profissional de especialista em psicologia e dispõe sobre normas e procedimentos para seu registro. Na hipótese de o CFP regulamentar nova especialidade ao profissional autônomo, além dos documentos exigidos, será facultada a obtenção do título por experiência comprovada ao psicólogo que tenha comprovação do exercício profissional durante o período de, pelo menos:", "alt": {"A": "3 (três) anos.", "B": "4 (quatro) anos.", "C": "5 (cinco) anos.", "D": "6 (seis) anos.", "E": "7 (sete) anos."}, "g": "C", "j": "Res CFP 013/2007: para obtencao do titulo de especialista por experiencia comprovada exige-se pelo menos 5 anos de exercicio profissional."}, {"id": "3005478", "d": "psicologia", "a": ["Behaviorismo", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Abordagem de filosofia monista, entende que as relações indivíduo-ambiente, especialmente no que diz respeito ao aspecto sociocultural, são controladas pelas consequências do cotidiano. Trata-se do(a):", "alt": {"A": "Sistêmica.", "B": "Gestalt.", "C": "Piagetiana.", "D": "Psicanálise Lacaniana.", "E": "Behaviorismo Radical."}, "g": "E", "j": "O Behaviorismo Radical (Skinner) parte de filosofia monista e entende as relacoes individuo-ambiente, inclusive socioculturais, como controladas pelas consequencias do cotidiano."}, {"id": "3005477", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Ao estudar o aparelho psíquico do indivíduo, a Psicanálise divide-o em três regiões ou instâncias: id, ego e superego. Com isso, o comportamento humano é resultante da interação desses três sistemas, sendo que cada um deles , tem suas próprias funções. E correto afirmar que:", "alt": {"A": "O ego é a instância original da psique, é a matriz da qual o id e o superego se diferenciam.", "B": "Enquanto o ego conhece apenas a realidade subjetiva da mente, o id é capaz de diferenciar entre ela e a realidade do mundo externo.", "C": "O ego, por ser a parte organizada do id e por possuir a função de realizar os objetivos dessa instância primária, desempenha a difícil tarefa de integrar as exigências antagônicas do id, do meio ambiente e do superego.", "D": "O superego é regido pelo princípio da realidade e opera por meio do processo secundário.", "E": "O ego é o sensor das funções do id e decide se algo é certo ou errado, de modo a garantir que uma pessoa aja em harmonia com os padrões sociais vigentes."}, "g": "C", "j": "Na metapsicologia freudiana, o ego e a parte organizada do id que precisa integrar as exigencias do id, do meio ambiente e do superego."}, {"id": "3005475", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "A Resolução CFP nº 007 /2003 revoga a Resolução CFP nº 030/2001 e Institui o Manual de Elaboração de Documentos Escritos produzidos pelo Psicólogo, decorrentes de avaliação. Essa Resolução, além de revogar a Resolução CFP nº 17 /2002, determina que são modalidades de documentos, exceto:", "alt": {"A": "Declaração e Parecer Psicológico que, apesar de não serem documentos decorrentes da avaliação Psicológica, são importantes constarem no manual em questão a fim de que sejam diferenciados.", "B": "Atestado Psicológico.", "C": "Declaração Obrigatória para o Setor Público .", "D": "Parecer Psicológico.", "E": "Relatório e Laudo Psicológico."}, "g": "C", "j": "A Res CFP 007/2003 elenca como modalidades: Declaracao, Atestado, Relatorio, Laudo e Parecer Psicologico. 'Declaracao Obrigatoria para o Setor Publico' nao existe como modalidade."}, {"id": "3005474", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Conforme análise do Decreto nº 53.464/64, que regulamenta a Lei nº 4.119/62 (dispõe sobre a profissão de Psicólogo), assinale a alternativa correta a respeito das funções do profissional Psicólogo.", "alt": {"A": "Utilizar métodos e técnicas psicológicas com o objetivo de: diagnóstico psicológico, orientação e seleção profissional, orientação psicopedagógica, solução de problemas de ajustamento e encaminhamento  psiquiátrico.", "B": "Dirigir serviços de Psicologia em , órgãos e estabelecimentos públicos, autárquicos, paraestatais, de economia mista, particulares, internacionais e regionais.", "C": "Ensinar as cadeiras ou disciplinas de Psicologia nos vários níveis de ensino, excetuadas as cadeiras de ensino médio e fundamental.", "D": "Supervisionar profissionais e alunos em trabalhos teóricos e práticos da Psicologia em universidades públicas.", "E": "Assessorar, tecnicamente, órgãos e estabelecimentos públicos, autárquicos, paraestatais, de economia mista e particulares."}, "g": "E", "j": "Decreto 53.464/64: o psicologo pode assessorar tecnicamente orgaos publicos, autarquicos, paraestatais, de economia mista e particulares - funcao explicita na regulamentacao."}, {"id": "3005473", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "As transgressões dos preceitos do Código de Ética do profissional Psicólogo constituem infração disciplinar. As infrações disciplinares incorrem nas seguintes penalidades legais e regimentais, exceto:", "alt": {"A": "Advertência.", "B": "Multa.", "C": "Censura Pública.", "D": "Suspensão do exercício profissional por até 6 (seis) meses, ad referendum do Conselho Regional de Psicologia.", "E": "Cassação do exercício profissional, ad referendum do Conselho Federal de Psicologia."}, "g": "D", "j": "A penalidade de suspensao prevista no CEP/Psicologo e de ate 30 dias, e nao 6 meses como afirma a alternativa D."}, {"id": "3005472", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "É permitido ao Psicólogo intervir na prestação de serviços psicológicos que estejam sendo efetuados por outro profissional, na seguinte situação:", "alt": {"A": "A pedido expresso e documentado do profissional responsável pelo serviço.", "B": "Em caso de emergência ou risco ao beneficiário ou usuário do serviço, quando não será necessária imediata ciência ao profissional.", "C": "Quando determinado pelo Conselho Federal de Psicologia, conforme denúncia de outro profissional da área da Psicologia.", "D": "Quando informado expressamente, por qualquer uma das partes, da interrupção voluntária e definitiva do serviço.", "E": "Quando se tratar de trabalho multiprofissional e a intervenção não fizer parte da metodologia adotada."}, "g": "D", "j": "CEP: o psicologo pode intervir em servicos de outro profissional quando informado expressamente da interrupcao voluntaria e definitiva do atendimento."}, {"id": "3005471", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Analise as alternativas acerca das determinações da Resolução CFP nº 010/2005 e legislação correlata sobre o , Código de Ética e as responsabilidades do Psicólogo, e assinale a incorreta a respeito das vedações aos profissionais Psicólogos.", "alt": {"A": "Ser conivente com erros, faltas éticas, violação de direitos, crimes ou contravenções penais praticados por Psicólogos na prestação de serviços profissionais.", "B": "Prestar serviços ou vincular o título de Psicólogo a serviços de atendimento psicológico cujos procedimentos, técnicas e meios não estejam regulamentados ou reconhecidos pela profissão.", "C": "Emitir documentos sem fundamentação e qualidade técnico-científica.", "D": "Interferir na validade e fidedignidade de instrumentos e técnicas psicológicas, adulterar seus resultados ou fazer declarações falsas.", "E": "Assumir responsabilidades profissionais somente por atividades para as quais esteja capacitado pessoal, teórica e tecnicamente."}, "g": "E", "j": "A alternativa E descreve um dever (assumir responsabilidades somente por atividades capacitado), nao uma vedacao - portanto e a incorreta quando se pede vedacoes."}, {"id": "3005470", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Analise as alternativas a respeito das determinações da Resolução CFP nº 010/2005 e legislação correlata sobre o Código de Ética e as responsabilidades do Psicólogo, e assinale a correta.", "alt": {"A": "Informar a todos os resultados decorrentes da prestação de serviços psicológicos, transmitindo todos os dados para a tomada de decisões que afetem o usuário ou beneficiário.", "B": "Orientar a população sobre os encaminhamentos apropriados, a partir da prestação de serviços psicológicos, e fornecer, sempre que solicitado pelo Poder Público, os documentos pertinentes ao bom termo do trabalho.", "C": "Zelar para que a comercialização, aquisição, doação, empréstimo, guarda e forma de divulgação do material privativo do Psicólogo sejam feitos conforme os princípios do Código de Ética e legislação pertinente.", "D": "Ter, para com o trabalho dos Psicólogos e de outros profissionais, respeito, consideração, solidariedade judicia l e, mesmo sem solicitação formal, a colaboração pertinente, salvo impedimento por motivo relevante.", "E": "Indicar, com força de lei, serviços de outros psicólogos, sempre que, por motivos de foro íntimo, não puderem ser continuados pelo profissional que os assumiu inicialmente, fornecendo ao seu substituto as informações completas para a continuidade do trabalho."}, "g": "C", "j": "E dever do psicologo zelar para que comercializacao, aquisicao, doacao, emprestimo, guarda e divulgacao de material privativo sigam o CEP e a legislacao."}, {"id": "3005469", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Sobre as determinações da Resolução CFP nº 010/2005 e legislação correlata, é correto afirmar que:", "alt": {"A": "Códigos de Ética expressam, facultativamente, uma concepção de homem e de sociedade que determina as normas jurídicas alternativas nas relações entre os indivíduos.", "B": "Traduzem os Códigos de Ética princípios e normas, que devem se pautar pelo respeito ao sujeito humano e seus direitos fundamentais.", "C": "Constituem expressão de valores específicos, não regulamentados pela legislação.", "D": "Não refletem a realidade do país, mas o que se pretende como valores que estruturam esse país.", "E": "Podem ser compreendidas como um conjunto fixo de normas morais imutáveis numa sociedade atemporal."}, "g": "B", "j": "Os Codigos de Etica traduzem principios e normas pautados pelo respeito ao sujeito humano e seus direitos fundamentais."}, {"id": "3005468", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Acerca da inscrição de PESSOA JURÍDICA nos Conselhos Regionais de Psicologia, assinale a alternativa incorreta, conforme a Resolução CFP nº 003/2007.", "alt": {"A": "Pessoa jurídica que presta serviços de Psicologia a terceiros ou em razão de sua atividade principal está obrigada a registrar-se no Conselho Federal de Psicologia.", "B": "O registro é obrigatório, inclusive para associações, fundações de direito privado, cooperativas e entidades de caráter filantrópico.", "C": "Empresários individuais estão desobrigados ao registro como pessoa jurídica nos Conselhos competentes.", "D": "A agência, filial ou sucursal de qualquer pessoa jurídica deve proceder ao registro no Conselho Regional de Psicologia devido.", "E": "Quando a agência, filial ou sucursal for na mesma jurisdição do registro, caberá à pessoa jurídica fazer a indicação do Psicólogo responsável naquele loca I e apresentar documentos relativos à constituição da unidade."}, "g": "A", "j": "Res CFP 003/2007: a pessoa juridica que presta servicos de Psicologia deve registrar-se no Conselho REGIONAL competente, e nao no Conselho Federal."}, {"id": "3005467", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "São atribuições dos Conselhos Regionais de Psicologia, conforme determinado na Lei nº 5.766/71, exceto:", "alt": {"A": "Funcionar como Tribunal Superior de Ética Profissional.", "B": "Sugerir ao Conselho Federal as medidas necessárias à orientação e fiscalização do exercício profissional.", "C": "Remeter, anualmente, relatório ao Conselho Federal, nele incluindo relações atualizadas dos profissionais inscritos, cancelados e suspensos.", "D": "Elaborar a proposta orçamentária anual, submetendo-a à aprovação do Conselho Federal.", "E": "Encaminhar a prestação de contas ao Conselho Federal de Psicologia."}, "g": "A", "j": "Funcionar como Tribunal Superior de Etica Profissional e atribuicao do CFP (e nao dos CRPs), conforme Lei 5.766/71."}, {"id": "3005466", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale a alternativa incorreta, de acordo com o Decreto nº 79.822/77 e legislação extravagante, sobre os Conselhos Regionais de Psicologia e as infrações disciplinares.", "alt": {"A": "Transgredir preceito do Código de Ética profissional é considerado infração disciplinar na Lei nº 79.822/77 e legislação correlata.", "B": "E infração disciplinar exercer a profissão quando impedido de fazê-lo, ou facilitar, por qualquer meio, o seu exercício aos não inscritos ou impedidos.", "C": "Solicitar ou receber de cliente qualquer favor em troca de concessões lícitas é infração disciplinar regulamentada pela legislação em tela.", "D": "O descumprimento, no prazo estabelecido na legislação, de determinação emanada de órgão ou autoridade dos Conselhos, em matéria de suas competências, depois de regularmente justificada, é infração disciplinar.", "E": "Considera-se infração disciplinar deixar de pagar aos Conselhos, pontualmente, as contribuições a que esteja obrigado."}, "g": "C", "j": "Decreto 79.822/77: a infracao disciplinar refere-se a receber favor em troca de concessoes ILICITAS - a alternativa C, ao falar em 'licitas', distorce o texto legal."}, {"id": "2895705", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "As atribuições profissionais do psicólogo no Brasil estão descritas na Resolução CFP nº 003/2007, que institui a Consolidação das Resoluções do Conselho Federal de Psicologia. Sobre as inscrições e registros nos Conselhos Regionais, não podemos afirmar que:", "alt": {"A": "Em caso de transferência, a dívida referente ao ano civil em curso e aos exercícios anteriores é devida ao Conselho Regional de origem.", "B": "Poderá ser concedida interrupção temporária do pagamento das anuidades em caso de viagem ao exterior, com permanência superior a seis meses.", "C": "O requerimento de inscrição secundária será acompanhado da carteira de identidade profissional e da indicação do local onde o profissional exercerá as atividades.", "D": "O requerimento de inscrição de pessoa física é instituído apenas com o diploma de psicólogo e o CPF.", "E": "As inscrições realizadas com certificado de colação de grau terão caráter provisório, sendo assim identificadas em todos os documentos."}, "g": "D", "j": "O requerimento de inscricao de pessoa fisica exige documentos alem do diploma e CPF (carteira de identidade, titulo eleitoral, quitacao militar, etc.), tornando a alternativa D incorreta."}, {"id": "2895697", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "O Conselho Federal de Psicologia criou uma comissão de avaliação de testes psicológicos no Brasil em 2001 e se propôs a indicar os instrumentos com melhores qualificações, ao passo que restringiu o uso dos demais. De acordo com o site: http ://www2. pol .org. br / satepsi/sistema/ ad mi n .cfm ?lista 1= sim, assinale a alternativa que contém o teste psicológico aprovado para uso.", "alt": {"A": "PMK.", "B": "TESTE DAS FÁBULAS.", "C": "TESTE DO DESENHO DE SILVER.", "D": "WARTEGG.", "E": "NEUPSILIN."}, "g": "E", "j": "O NEUPSILIN consta como teste psicologico aprovado pelo SATEPSI; PMK, Teste das Fabulas, Teste do Desenho de Silver e Wartegg estavam desaprovados na epoca da prova."}, {"id": "2895694", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Teste destinado a adultos, inicialmente criado para avaliar a inteligência de candidatos a motoristas. Caracteriza-se como uma medida de inteligência não verbal, construída para ser usada principalmente em pessoas com instrução de nível fundamental:", "alt": {"A": "IHS.", "B": "R1.", "C": "WISC III.", "D": "WAIS.", "E": "BTN."}, "g": "B", "j": "O R-1 e teste de inteligencia nao verbal, originalmente desenvolvido para avaliar candidatos a motoristas e indicado a pessoas com escolaridade fundamental."}, {"id": "2895675", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Sobre os deveres fundamentais dos psicólogos, seguindo o Código de Ética Profissional do Psicólogo, é incorreto afirmar que:", "alt": {"A": "Em caso de interrupção do trabalho, por quaisquer motivos, o psicólogo deverá zelar pelo destino dos seus arquivos confidenciais.", "B": "Ao fixar a remuneração pelo seu trabalho, o psicólogo deverá seguir os honorários sugeridos pelo CFP e não as condições do usuário ou beneficiário.", "C": "Nos documentos que embasam as atividades em equipe multiprofissional, o psicólogo registrará apenas as informações necessárias para o cumprimento dos objetivos do trabalho.", "D": "É dever do psicólogo respeitar o sigilo profissional a fim de proteger, por meio da confidencialidade, a intimidade das pessoas.", "E": "O psicólogo não divulgará, ensinará ou venderá a leigos instrumentos e técnicas psicológicas que permitam ou facilitem o exercício ilegal da profissão."}, "g": "B", "j": "O CEP determina que o psicologo, ao fixar honorarios, considere as condicoes do usuario, e nao tabelas sugeridas pelo CFP - logo, a alternativa B contraria o codigo."}, {"id": "2895674", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Toda profissão define-se a partir de práticas que buscam atender a demandas sociais, norteadas por elevados padrões técnicos e pela existência de normas éticas que garantam a adequada relação de cada profissional com seus pares e com a sociedade como um todo. Dessa maneira, o Código de Ética Profissional do Psicólogo oferece diretrizes para sua formação, delineando as responsabilidades e deveres do psicólogo. Analise atentamente as afirmações sobre a prática desse profissional. I. É permitido induzir qualquer pessoa ou organização a recorrer a seus serviços. II. É vedado prolongar, desnecessariamente, a prestação de serviços profissionais. III. Ao participar de greves ou paralisações, deverá garantir que as atividades de emergência não serão interrompidas. IV. No atendimento à criança, não deverá, em hipótese alguma, comunicar aos pais ou responsáveis as informações obtidas. V. Ao promover publicamente seus serviços, poderá utilizar o preço do atendimento como forma de propaganda. Seguindo o Código de Ética Profissional do Psicólogo, está correto o que se afirma em:", "alt": {"A": "apenas II e III.", "B": "apenas III e V.", "C": "apenas II e IV.", "D": "apenas III, IV e V.", "E": "apenas II, III e IV."}, "g": "A", "j": "Apenas II (vedacao a prolongar desnecessariamente servicos) e III (manutencao das atividades de emergencia em greves) sao corretas segundo o CEP. I, IV e V violam o codigo."}, {"id": "2895671", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Constata-se, no exercício profissional dos psicólogos no âmbito judiciário, a predominância das atividades de confecção de laudos, pareceres e relatórios, no pressuposto de que cabe à Psicologia, neste contexto, uma atividade predominantemente avaliativa e de subsídio aos magistrados (Arantes, 2004). ARANTES, E.M.M. Pensando a Psicologia aplicada à justiça. ln: GONÇALVES, H.S.; BRANDÃO, E.P. (orgs.) Psicologia Jurídica no Brasil. Rio de Janeiro: Nau Ed., 2004, p.15-49. De acordo com as informações citadas pela autora, é incorreto afirmar que:", "alt": {"A": "No caso específico da atuação dos psicólogos em Varas de Família, constatou-se o predomínio das atividades de perícia nos casos de separações litigiosas, em que havia disputa pela guarda dos filhos.", "B": "A imagem do psicólogo exercendo uma atividade predominantemente avaliativa tem causado mal-estar entre a nova geração de psicólogos, que preferiria ter de si uma imagem menos comprometida com a manutenção da ordem social vigente, considerada injusta e excludente.", "C": "A perícia tem sido um dos procedimentos mais utilizados na área jurídica, tendo por objetivo fornecer subsídios para a tomada de uma decisão, dentro do que impõe a lei.", "D": "Não há críticas mencionadas na literatura da área sobre o mal-estar vivido pela nova geração de psicólogos no âmbito jurídico, devido ao fato de exercer uma atividade predominantemente avaliativa.", "E": "Ao buscar a objetividade, a Psicologia transformou-se em instrumentalista, esquecendo-se de se situar em relação às circunstâncias nas quais se constituiu."}, "g": "D", "j": "Arantes (2004) cita criticas explicitas ao mal-estar da nova geracao de psicologos pela predominancia da atividade avaliativa - a alternativa D contraria o texto."}, {"id": "2895670", "d": "psicologia", "a": ["Teorias da Personalidade", "Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "\"Frequentemente gostaríamos de ver algumas pessoas em particular mudar para melhor, mas nem sempre temos controle sobre as consequências que são responsáveis por sua conduta. Se o temos, podemos mudar as consequências e ver se a conduta também muda. Ou podemos prover as mesmas consequências para conduta desejável e ver se a nova substitui a antiga\". (Sidman, 1995, p. 104)  SIDMAN, M. Coerção e suas implicações. Campinas: Editorial Psy, 1995. Assim, se quisermos mudar o comportamento, é importante identificar o comportamento e as consequências, alterar as consequências, atuar na relação entre o ato e a consequência e ver se o comportamento muda. Esse é um procedimento ativo e é a essência da:", "alt": {"A": "Motivação.", "B": "Contingência de reforçamento.", "C": "Análise de contingências.", "D": "Linha de base múltipla.", "E": "Avaliação comportamental."}, "g": "C", "j": "O procedimento descrito (identificar comportamento, consequencias, alterar consequencias e observar o comportamento) corresponde a analise de contingencias da Analise do Comportamento."}, {"id": "2895669", "d": "psicologia", "a": ["Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas", "Teorias da Personalidade"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "De modo geral, o termo comportamento refere-se à atividade dos organismos (animais) que mantém intercâmbio com o ambiente. Numa linguagem mais rigorosa, seguindo a abordagem da Teoria Comportamentalista, podemos dizer sobre o comportamento:(A) O termo \"comportamento verbal\" foi proposto para enfatizar que linguagem é um comportamento modelado e mantido por consequências e não é algo ou uma propriedade que alguém possua ou, muito menos, uma entidade interna. (B) O universo de cada sujeito é constituído de uma parte pública e de uma parte privada. (C) A pessoa pode, de forma encoberta, estabelecer estímulos discriminativos para os próprios comportamentos, pode avaliá-los, porém nunca poderá consequenciá-los.(D) Uma consequência importante do comportamento verbal é que o falante se torna também ouvinte e pode reforçar amplamente seu próprio comportamento.Está correto o que se afirma em:", "alt": {"A": "todas as afirmações.", "B": "nenhuma das afirmações.", "C": "apenas uma das afirmações.", "D": "apenas duas das afirmações.", "E": "apenas três das afirmações."}, "g": "E", "j": "Tres afirmacoes estao corretas (A, B, D). A afirmativa C esta incorreta - o sujeito pode consequenciar encobertamente seus proprios comportamentos."}, {"id": "2895668", "d": "psicologia", "a": ["Psicanálise", "Behaviorismo", "Teorias e Técnicas Psicoterápicas", "Gestalt"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "O Behaviorismo, a Gestalt e a Psicanálise são consideradas, por inúmeros autores, as três mais importantes tendências teóricas da Psicologia no século 20. Seguindo cada uma das abordagens, assinale a alternativa correta que descreva os aspectos conceituais relacionados.", "alt": {"A": "A Psicanálise, que nasce com Freud, na Áustria, a partir da prática médica, recupera para a Psicologia a importância da afetividade e postula o inconsciente como objeto de estudo, quebrando a tradição da Psicologia como ciência da consciência e da razão.", "B": "A Gestalt, que tem seu berço nos Estados Unidos, tornou-se importante por ter definido o fato psicológico, de modo concreto, a partir da noção de comportamento.", "C": "O Behaviorismo, que tem seu berço na Europa, surge como uma negação da fragmentação das ações e processos humanos, postulando a necessidade de se compreender o homem como uma totalidade.", "D": "O inconsciente refere-se ao sistema onde permanecem aqueles conteúdos acessíveis à consciência. É aquilo que não está na consciência, neste momento, e no momento seguinte pode estar.", "E": "Sintoma, na teoria psicanalítica, refere-se a um estado de tensão que busca, por meio de um objeto, a supressão desse estado."}, "g": "A", "j": "A Psicanalise nasce com Freud na Austria, a partir da pratica medica, e postula o inconsciente como objeto de estudo - quebrando a tradicao da Psicologia como ciencia da consciencia."}, {"id": "2895666", "d": "psicologia", "a": ["Psicologia Social", "História da Psicologia", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Todo comportamento de um organismo vivo tende a se repetir, se nós recompensarmos o organismo assim que este emitir o comportamento. Por outro lado, o comportamento tenderá a não acontecer, se o organismo for castigado após sua ocorrência. Assim, o organismo irá associar essas situações com outras semelhantes. Formulada por Edward Thorndike, essa lei que foi de grande utilidade para a Psicologia Comportamentalista é denominada:", "alt": {"A": "Lei do Condicionamento Clássico.", "B": "Lei do Estímulo-Reforço.", "C": "Lei do Reforçamento.", "D": "Lei do Efeito.", "E": "Lei do Controle de Estímulos."}, "g": "D", "j": "Edward Thorndike formulou a Lei do Efeito: respostas seguidas de recompensa tendem a se repetir; seguidas de punicao, a desaparecer."}, {"id": "2895665", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "\"A história da construção da Psicologia está ligada, em cada momento histórico, às exigências de conhecimento da humanidade, às demais áreas do conhecimento humano e aos novos desafios colocados pela realidade econômica e social pela insaciável necessidade do homem de compreender a si mesmo\". (Bock, Furtado & Teixeira, 2002, p.31) BOCK, A.M.B.; FURTADO, O.; TEIXEIRA, M.L.T. Psico/agias: uma introdução ao estudo de Psicologia. 13.ed. reform e ampl. São Paulo, Saraiva, 2002.  Para compreender a diversidade com que a Psicologia se apresenta hoje, é indispensável recuperar sua história. Assim, é correto afirmar que:", "alt": {"A": "O funcionalismo é considerado a primeira sistematização genuinamente americana de conhecimentos em Psicologia.", "B": "Edward Titchner, representante do funcionalismo, elege a consciência como o centro de suas preocupações e busca a compreensão de seu funcionamento, na medida em que o homem a usa para adaptar-se ao meio.", "C": "O estruturalismo de Thorndike está preocupado com a compreensão da consciência.", "D": "O termo estruturalismo origina-se da concepção de que a aprendizagem se dá por um processo de associação das ideias.", "E": "William James, representante do associacionismo, elegeu a consciência como centro de suas atenções."}, "g": "A", "j": "O Funcionalismo (William James, Dewey, Angell) e considerado a primeira sistematizacao genuinamente americana da Psicologia."}, {"id": "2895664", "d": "psicologia", "a": ["História da Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Assinale a alternativa que, corretamente, preenche as lacunas a seguir. Um dos grandes marcos da história da Psicologia como ciência e pesquisa foi em _________ com o estabelecimento do primeiro laboratório psicológico do mundo criado por _____________.", "alt": {"A": "1879 / Sigmund Freud", "B": "1879 / Wilhelm Wundt", "C": "1912 / Sigmund Freud", "D": "1912 / Wilhelm Wundt", "E": "1698 / John Locke"}, "g": "B", "j": "O primeiro laboratorio de Psicologia foi criado em 1879 por Wilhelm Wundt em Leipzig, marco da Psicologia como ciencia."}, {"id": "2895662", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Segundo Cotrim (2002), o \"[ ... ] vasto conjunto de concepções geralmente aceitas como verdadeiras em determinado meio social recebe o nome de\": COTRIM. Gilberto. Fundamentos da filosofia: história e grandes temas. 15. ed. São Paulo : Saraiva, 2002.", "alt": {"A": "Ciência.", "B": "Senso comum.", "C": "Variáveis dependentes.", "D": "Variáveis independentes.", "E": "Pensamento científico."}, "g": "B", "j": "Cotrim (2002): o conjunto de concepcoes geralmente aceitas como verdadeiras em determinado meio social recebe o nome de senso comum."}, {"id": "2895661", "d": "psicologia", "a": ["Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Francelin (2004) revisa alguns aspectos da constituição do conhecimento científico e descreve características de eventos que se desenvolveram e ainda se desenvolvem a partir de novos conceitos em torno da própria ciência, como o senso comum. Considere as seguintes afirmações. FRANCELIN, M. M. Ciência, senso comum e revoluções científicas: ressonâncias e paradoxos. Ci. lnf., Brasília, v. 33, n. 3, dez. 2004. Disponível em <http://www.scielo.br/ scielo. ph p ?scri pt=sci _ a rttex t&pid=S0100- 19652004000300004&Ing=pt&nrm=iso>. acessos em 27 jan. 2012. I. A ciência, aparentemente, busca por meio de seu rigor na pesquisa, no debate e crítica de opiniões, afastar-se do senso comum.II. No meio científico, deve haver plena consciência de que uma pesquisa que leva a um novo conhecimento não é definitiva.III. No senso comum, as opiniões obtidas podem ser emitidas como verdadeiras e definitivas.IV. A caracterização do senso comum não passa, necessariamente, por critérios de verdade ou falsidade, mas sim pela \"falta de fundamentação sistemática\".Está correto o que se afirma em:", "alt": {"A": "nenhuma das afirmações.", "B": "apenas uma das afirmações.", "C": "apenas duas das afirmações.", "D": "apenas três das afirmações.", "E": "todas as afirmações."}, "g": "E", "j": "Todas as afirmacoes sobre ciencia x senso comum, conforme Francelin (2004), estao corretas."}, {"id": "2895659", "d": "psicologia", "a": ["Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "D'Oliveira (1984) registra em seu livro as experiências e inquietações enquanto pesquisadora e professora de Psicologia. Assim, o material fornece subsídios para uma atuação em ciência e pesquisa com o intuito de reconhecê-las e compará-las com outras atividades do conhecimento humano. Considerando suas informações, é incorreto afirmar que: D'OLIVEIRA, M.M.H. Ciência e pesquisa em psicologia: uma introdução. São Paulo: EPU, 1984.", "alt": {"A": "Fazer pesquisa é uma das etapas do fazer ciência.", "B": "A ciência é, antes de tudo, um empreendimento humano complexo.", "C": "Ciência é uma atividade padronizada, com todos os cientistas trabalhando a partir de regras semelhantes e estáticas.", "D": "A ciência está em constante interação com a sociedade, sendo determinada pela história política e econômica do momento social em que se insere.", "E": "A ciência mantém um estreito contato com a filosofia."}, "g": "C", "j": "D'Oliveira destaca a ciencia como atividade dinamica e historica, NAO padronizada com regras estaticas - a alternativa C e a incorreta."}, {"id": "2892969", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Documento expedido pelo psicólogo que certifica uma determinada situação ou estado psicológico, tendo como finalidade afirmar sobre as condições psicológicas de quem, por requerimento, o solicita, com fins de: - justificar faltas e/ou impedimentos do solicitante; - justificar estar apto ou não para atividades específicas, após realização de um processo de avaliação psicológica, dentro do rigor técnico e ético. De acordo com a Resolução CFP n5 7/2003, o conceito e finalidades acima transcritos são relativos:", "alt": {"A": "Ao Atestado Psicológico.", "B": "À Declaração.", "C": "Ao Relatório Psicológico.", "D": "Ao Laudo Psicológico.", "E": "Ao Parecer."}, "g": "A", "j": "Res CFP 007/2003: o documento que certifica situacao/estado psicologico para justificar faltas e aptidao apos avaliacao psicologica e o Atestado Psicologico."}, {"id": "2892955", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Sob o prisma da Lei n9 5.766, constituem infrações disciplinares as abaixo descritas, exceto:", "alt": {"A": "Solicitar ou receber de cliente qualquer favor em troca de concessões, ainda que lícitas.", "B": "Não cumprir no prazo estabelecido, determinação emanada do órgão ou autoridade dos Conselhos, em matéria da competência destes, depois de regularmente notificado.", "C": "Exercer a profissão quando impedido de fazê-lo, ou facilitar, por qualquer meio, o seu exercício aos não inscritos ou impedidos.", "D": "Praticar, no exercício da atividade profissional, ato que a lei defina como crime ou contravenção.", "E": "Deixar de pagar aos Conselhos, pontualmente, as contribuições a que esteja obrigado."}, "g": "A", "j": "A Lei 5.766/71 tipifica como infracao receber favor em troca de concessoes ILICITAS - a alternativa A, ao falar em 'licitas', contraria o texto legal."}, {"id": "1234339", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "O direito da criança e adolescente à convivência familiar e comunitária é inviolável. Assim sendo, aponte o tratamento adequado dado pelo ECA.", "alt": {"A": "Para a colocação em família substituta, sempre que possível, a criança ou o adolescente será previamente ouvido por equipe interprofissional, respeitado seu estágio de desenvolvimento e grau de compreensão sobre as implicações da medida, e terá sua opinião devidamente considerada.", "B": "A falta ou a carência de recursos materiais não constitui motivo suficiente para a perda ou a suspensão do poder familiar.", "C": "O poder familiar será exercido, em igualdade de condições, pelo pai e pela mãe, na forma do que dispuser a legislação civil, assegurado a qualquer deles o direito de, em caso de discordância, recorrer à autoridade judiciária competente para a solução da divergência.", "D": "Para a colocação em família substituta, tratando-se de maior de 12 (doze) anos de idade, será necessário seu consentimento, colhido em audiência.", "E": "Os filhos, havidos ou não da relação do casamento, exceto por adoção, que terão tratamento próprio, terão os mesmos direitos e qualificações, proibidas quaisquer designações discriminatórias relativas à filiação."}, "g": "E", "j": "O ECA assegura aos filhos os mesmos direitos e qualificacoes - inclusive os adotivos - sem qualquer designacao discriminatoria. A alternativa E excepciona a adocao, o que e incorreto."}, {"id": "1222515", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale a alternativa que completa a lacuna a seguir.   A avaliação psicológica tem sido considerada uma das principais ferramentas do processo de seleção de pessoal. Dentre os testes habitualmente usados para essa função, temos o _____________ que avalia 15 dimensões da personalidade, abrangendo ainda uma escala de mentira e uma de desejabilidade social, abrangendo, portanto, 17 fatores de personalidade.", "alt": {"A": "EAT", "B": "IFP", "C": "MAPA", "D": "HTP", "E": "G 36"}, "g": "B", "j": "O IFP (Inventario Fatorial de Personalidade) avalia 15 dimensoes de personalidade alem de escalas de mentira e desejabilidade social, totalizando 17 fatores."}, {"id": "1214036", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale a alternativa incorreta em relação às regras recursais segundo o Código de Processamento Disciplinar.", "alt": {"A": "Interposto tempestivamente, o recurso terá efeito suspensivo da execução da pena aplicada.", "B": "Após decorridos os prazos de razões e contrarrazões, o Presidente da Comissão de Ética determinará a subida dos autos ao Conselho Federal, com ou sem as contrarrazões.", "C": "Recebido o recurso, o Presidente da Comissão de Ética mandará intimar a parte contrária para apresentar contrarrazões, no prazo de 30 (trinta) dias.", "D": "Às partes, assiste o direito de recorrer, voluntariamente, de toda decisão resultante de julgamento, adotada pelo Plenário do CRP, no prazo de 15 (quinze) dias, a contar da data da ciência da decisão.", "E": "O recurso será interposto por escrito, formulando o recorrente suas razões, de modo claro e objetivo, devendo ser protocolado no Conselho Regional de Psicologia, que certificará, nos autos, a data de sua entrada e fornecerá ao recorrente comprovante do protocolo."}, "g": "D", "j": "O prazo recursal previsto no Codigo de Processamento Disciplinar e de 30 dias da ciencia da decisao, e nao 15 como afirma a alternativa D."}, {"id": "1214029", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "A instância máxima de deliberação, responsável por estabelecer as diretrizes para a atuação do Conselho Federal e dos Conselhos Regionais de Psicologia no triênio subsequente a sua realização, é o(a):", "alt": {"A": "Maioria absoluta dos Conselhos Regionais de Psicologia, ad referendum do Conselho Federal de Psicologia.", "B": "Plenário do Conselho Federal de Psicologia.", "C": "Congresso Nacional da Psicologia.", "D": "Presidência do Conselho Federal de Psicologia.", "E": "Comissão de Orientação e Fiscalização do Conselho Federal de Psicologia."}, "g": "C", "j": "O Congresso Nacional da Psicologia (CNP) e a instancia maxima deliberativa do Sistema Conselhos, definindo diretrizes para o trienio."}, {"id": "1209634", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Na psicologia, julgamos a qualidade dos nossos dispositivos de mensuração por dois critérios psicométricos: a confiabilidade e a validade. A confiabilidade refere-se à:", "alt": {"A": "Concordância entre especialistas sobre o que os itens de um teste medem sobre um determinado conteúdo.", "B": "Precisão de fazer inferências a respeito dos escores de um teste.", "C": "Fidedignidade de um teste ante o constructo que ele se propõe a medir.", "D": "Coerência e estabilidade da mensuração.", "E": "Medida do quanto um teste prevê um critério ou está estatisticamente relacionado a ele."}, "g": "D", "j": "Confiabilidade (precisao/fidedignidade) refere-se a coerencia e estabilidade da mensuracao do instrumento."}, {"id": "1208459", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "O ato pelo qual se dá conhecimento ao psicólogo processado da instauração do processo disciplinar ético, bem como lhe concede a oportunidade de se defender no prazo que se especifica, recebe o nome de:", "alt": {"A": "Notificação.", "B": "Citação.", "C": "Interpelação", "D": "Intimação.", "E": "Comunicação."}, "g": "B", "j": "O ato que da conhecimento ao psicologo processado da instauracao do processo e lhe abre prazo para defesa denomina-se citacao."}, {"id": "1187028", "d": "psicologia", "a": ["Liderança", "Psicologia e Organizações"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Dentre as várias abordagens teóricas que foram desenvolvidas para explicar a Liderança, podemos citar a Abordagem Comportamental que:", "alt": {"A": "Enfatiza os atributos pessoais dos líderes.", "B": "Enfatiza o que os líderes realmente fazem no trabalho e qual o reflexo de suas atitudes na sua eficácia.", "C": "Concebe que a liderança é mais bem compreendida pelo uso do poder e da influência exercido por uma pessoa em um grupo.", "D": "Enfatiza a importância de os líderes indicarem aos seguidores quais comportamentos eles precisam exibir para alcançar os objetivos desejados.", "E": "Concebe que a liderança é melhor compreendida em termos de fatores situacionais que promovem sua ocorrência."}, "g": "B", "j": "A Abordagem Comportamental da Lideranca enfatiza o que os lideres realmente fazem no trabalho e o reflexo de suas atitudes na sua eficacia."}, {"id": "1184576", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale a alternativa incorreta.", "alt": {"A": "O psicólogo, em sua publicidade, é obrigado a prestar informações que esclareçam a natureza básica dos seus serviços, sendo-lhe vedado fazer previsão taxativa de resultado.", "B": "As regras de controle de publicidade são aplicáveis a toda forma de publicidade ou propaganda, realizada por psicólogo, individual ou coletivamente, com exceção se feita por pessoa jurídica que tenha por objetivo a prestação de serviços psicológicos, que terá regulação própria.", "C": "Sem prejuízo do caráter privativo da atividade profissional, o psicólogo poderá delegar funções a estagiário, como forma de treinamento.", "D": "Em sua publicidade, o psicólogo não poderá utilizar diagnóstico psicológico, análise de caso, aconselhamento ou orientação psicológica que, de alguma forma, identifiquem o sujeito.", "E": "Considera-se estagiário o estudante do ciclo profissional de curso de graduação de psicólogo, em situação regular junto ao MEC e/ou outro órgão competente, seja pela autorização ou reconhecimento, regularmente matriculado, cursando disciplina profissionalizante com atividade prática que agenda 14 legislação pertinente sobre o estágio"}, "g": "B", "j": "As regras de controle de publicidade aplicam-se inclusive a pessoa juridica que preste servicos psicologicos, nao havendo a excecao alegada na alternativa B."}, {"id": "821100", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2012", "org": "CFP", "t": "", "e": "A Resolução 07/2003 do Conselho Federal de Psicologia,\nque instituiu o \"Manual de elaboração de documentos\nescritos produzidos pelo psicólogo\", prevê a possibilidade\nde quatro tipos de documentos. Qual, dentre os listados a\nseguir, não se encontra previsto nessa resolução?", "alt": {"A": "Declaração.", "B": "Parecer psicológico.", "C": "Relatório / laudo psicológico.", "D": "Estudo psicossocial.", "E": "Atestado psicológico."}, "g": "D", "j": "A Res CFP 007/2003 prevê quatro modalidades: declaracao, atestado, relatorio/laudo e parecer psicologico. 'Estudo psicossocial' nao consta na resolucao."}, {"id": "821098", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CFP", "t": "", "e": "Conforme o Estatuto da Criança e do Adolescente (ECA), as\nmedidas sócio-educativas estão previstas para serem\naplicadas aos adolescentes que cometeram ato infracional.\nQual das assertivas abaixo não corresponde às\ndeterminações previstas pelo estatuto?", "alt": {"A": "Em hipótese alguma está previsto o trabalho forçado.", "B": "A medida aplicada ao adolescente levará em conta sua\ncapacidade de cumpri-la, as circunstâncias e a\ngravidade da infração.", "C": "Se o ato infracional tiver reflexos patrimoniais, a\nautoridade poderá determinar que o adolescente\npromova o ressarcimento do dano.", "D": "A prestação de serviço à comunidade está prevista\ncomo uma das possibilidades de medida sócio-educativa.", "E": "A liberdade assistida só poderá ser adotada se um dos\ngenitores do adolescente se responsabilizar por ele."}, "g": "E", "j": "O ECA nao condiciona a liberdade assistida a responsabilizacao por genitor; a medida e aplicada conforme avaliacao do juizo da infancia e juventude."}, {"id": "821097", "d": "psicologia", "a": ["Foucault", "Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Para Foucault (1984), a \"prisão\" como instituição se\ncaracteriza, principalmente, por buscar de forma incessante\no(a):", "alt": {"A": "Tratamento psicológico.", "B": "Reedução psicossocial.", "C": "Controle e disciplina.", "D": "Garantia de direitos durante o cumprimento da pena.", "E": "Nenhuma das alternativas anteriores está correta."}, "g": "C", "j": "Foucault (Vigiar e Punir): a prisao caracteriza-se principalmente pela busca incessante de controle e disciplina dos corpos."}, {"id": "821095", "d": "psicologia", "a": ["Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2012", "org": "CFP", "t": "", "e": "Qual das assertivas não faz parte das diretrizes propostas\npara a atuação e formação dos psicólogos no sistema\nprisional brasileiro (Ministério da Justiça, DEPEN e CFP,\n2007)?", "alt": {"A": "Evitar a participação em organismos de controle social\npara debater as questões de saúde e educação, que\nsão próprias do sistema penal.", "B": "Constituir equipes diferenciadas para o trabalho com o\ndependente químico.", "C": "Contribuir para a construção de modelos substitutivos\nao sistema de encarceramento.", "D": "Criar estratégias e ferramentas que facilitem a\nexpressão do sujeito como protagonista de sua\nhistória.", "E": "Interagir com outros profissionais para construção de\nprojetos interdisciplinares visando à saúde do\ntrabalhador do sistema prisional."}, "g": "A", "j": "As Diretrizes (MJ/DEPEN/CFP, 2007) incentivam a participacao do psicologo em organismos de controle social - logo, 'evitar a participacao' NAO faz parte das diretrizes."}, {"id": "821094", "d": "psicologia", "a": ["Psicologia Jurídica", "Psicologia Criminal e Carcerária"], "ano": "2012", "org": "CFP", "t": "", "e": "Rauter (2003) discute a validade e a função dos laudos que\nsão emitidos por técnicos do sistema penitenciário. Em\nrelação ao diagnóstico do criminoso, diz que sua\nrepercussão no campo penal seria de:", "alt": {"A": "Planejamento do tratamento penal.", "B": "Escolha da instituição para o cumprimento da pena.", "C": "Previsão da conduta após a liberdade.", "D": "Estigmatização.", "E": "Modernização do tratamento penal."}, "g": "D", "j": "Rauter (2003): o efeito principal do diagnostico do criminoso no campo penal e a estigmatizacao."}, {"id": "821092", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "Apesar das determinações legais contidas no Estatuto da\nCriança e do Adolescente (ECA), a subnotificação da\nviolência é uma realidade no Brasil. Gonçalves e Ferreira\n(2002) discutem os inúmeros problemas que entravam o\nprocesso de notificação, considerando os diferentes atores\ne os diferentes níveis estruturais do problema. Identifique a\nresposta que relaciona os principais problemas da\nsubnotificação que podem ser vinculados diretamente ao\nfuncionamento dos profissionais de saúde.", "alt": {"A": "Incapacidade técnica para identificar os casos de maus-tratos\ne os conflitos éticos quanto à quebra de sigilo.", "B": "Incapacidade técnica de identificar os casos e não\nsaber como tratá-los.", "C": "Conflitos éticos quanto ao tipo de encaminhamento a\nser realizado.", "D": "Incapacidade técnica para identificar os casos e os\nconflitos éticos na comunicação entre os demais\nmembros da equipe interdisciplinar de atendimento.", "E": "Dependência da tomada de decisão dos familiares da\nvítima quanto ao encaminhamento da denúncia."}, "g": "A", "j": "Goncalves e Ferreira (2002): os profissionais de saude entravam a notificacao por incapacidade tecnica de identificar maus-tratos e por conflitos eticos quanto a quebra de sigilo."}, {"id": "821089", "d": "psicologia", "a": ["Psicologia Jurídica", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2012", "org": "CFP", "t": "", "e": "Segundo Vargas (1998), são características da adoção\ntardia:\nI. A criança adotada possui mais de dois anos.\nII. Independentemente da idade cronológica, o esperado\né que a criança adotada apresentará em seu processo\nadaptativo condutas regressivas e agressivas. III. Esse tipo de adoção gera maior preconceito tanto nas\npessoas interessadas em adotar crianças como na\nsociedade em geral.\nEstá correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente I e II.", "C": "somente II e III.", "D": "todas.", "E": "nenhuma."}, "g": "D", "j": "Vargas (1998): caracteristicas da adocao tardia incluem crianca com mais de 2 anos, condutas regressivas/agressivas durante a adaptacao e maior preconceito social - todos os itens corretos."}, {"id": "821085", "d": "psicologia", "a": ["Psicologia Jurídica", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2012", "org": "CFP", "t": "", "e": "Conforme Brandão (2004), o contexto adversarial pela\ndisputa da guarda dos filhos favorece o surgimento dos\nseguintes fenômenos:\nI. Atos que visam a denegrir a imagem do ex-cônjuge\ncom o objetivo de mostrar-se mais competente para a\ndetenção da guarda.\nII. Alianças com os filhos para utilizá-los como\ninstrumento de agressão ao ex-cônjuge, reforçando os\nchamados \"vínculos de lealdade\".\nIII. Desenvolvimento de uma boa autoestima nos filhos\npor sentirem-se desejados por ambos os genitores.\nEstá correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente I e II.", "C": "somente I e III.", "D": "todas.", "E": "nenhuma."}, "g": "B", "j": "Brandao (2004): o contexto litigioso favorece a denegracao do ex-conjuge e aliancas de lealdade com os filhos como instrumentos de agressao. A boa autoestima nao e fenomeno tipico."}, {"id": "821084", "d": "psicologia", "a": ["Família", "Psicologia Jurídica", "Perícia Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "Shine (2005) discute as possíveis modalidades de atuação\ndo psicólogo no contexto forense, dependendo de como\nele se posiciona na arena jurídica, quando o foco de seu\ntrabalho é a avaliação psicológica nas Varas de Família.\nQual das alternativas melhor descreveria o papel do\npsicólogo como \"perito imparcial\"?", "alt": {"A": "A maior contribuição do perito será em relatar o que\nviu e ouviu, evitando a interferência de seu\nconhecimento técnico.", "B": "O perito deve atender aos interesses de uma das\npartes, trabalhando com isenção e seguindo os\nreferenciais técnicos e éticos.", "C": "O perito trabalha no sentido de trazer a \"verdade\" que\ninteressa ao seu cliente.", "D": "É o perito que realiza um trabalho conclusivo,\nposicionando-se claramente e de forma categórica ao\nque lhe é perguntado pelo juízo, ou seja, definindo a\nquestão legal.", "E": "É o perito que apresenta as opiniões e previsões de\nforma imparcial e neutra, discriminando os fatores\npsicológicos em jogo, sem adentrar no julgamento da\nquestão legal."}, "g": "E", "j": "O perito imparcial apresenta opinioes e previsoes de forma imparcial e neutra, discriminando os fatores psicologicos, sem adentrar no julgamento da questao legal."}, {"id": "821082", "d": "psicologia", "a": ["Família", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "Szymanski, no livro \"A família contemporânea em debate\"\n(Carvalho, 1995), critica o uso estereotipado do conceito de\nfamília burguesa para valorar as famílias que chegam em\nbusca de auxílio. Propõe, em contraposição, que os\nprofissionais façam o uso do conceito de \"família vivida\".\nQual das ideias não é pertinente a essa concepção?", "alt": {"A": "Pessoas que convivem numa relação afetiva.", "B": "Pessoas que convivem numa relação estruturada.", "C": "Pessoas que possuem um modo próprio de se\ncomunicar.", "D": "Pessoas que possuem, necessariamente, o vínculo de\nconsangüinidade para se relacionar.", "E": "Pessoas que convivem em relações de maior\nestabilidade."}, "g": "D", "j": "Szymanski: o conceito de familia vivida nao exige vinculo de consanguinidade - rompe justamente com a definicao restrita de familia burguesa."}, {"id": "821079", "d": "psicologia", "a": ["Psicologia Jurídica", "Psicologia Social", "Psicologia Criminal e Carcerária"], "ano": "2012", "org": "CFP", "t": "", "e": "A criminalidade, sobretudo nos grandes centros urbanos,\ntem sido objeto diário das páginas de jornais, das emissoras\nde rádio e televisão. Cada vez mais, sobretudo movido pela\nemoção decorrente de crimes de repercussão pública, a\nopinião pública clama e reclama quanto à impunidade, à\nlentidão da Justiça Criminal, à necessidade do agravamento\ndas penas e, seguidamente, propõe o rebaixamento da\nidade de responsabilidade penal. No imaginário social,\npenas cada vez mais longas, regime disciplinar prisional\nmais rigoroso seriam instrumentos eficazes a contribuir\ncom o decréscimo de taxas de incidência criminal. (Carvalho\net al., 2011, p. 72-73)\nAcerca do sistema prisional brasileiro e da atuação da\npsicologia nesse contexto, assinale a alternativa incorreta.", "alt": {"A": "Segundo Kolker (2004), a ideia de periculosidade dita à\nsociedade o perfil dos criminosos e delinqüentes\npotenciais, de tal maneira que não é necessário\ncometer um crime para ser considerado perigoso.\nSegundo essa autora, uma vez que o verdadeiro fim do\ndireito penal positivista é a defesa social, é possível\njustificar a intervenção nas classes consideradas\nperigosas sem esperar pelo delito.", "B": "A profecia autorrealizadora (self-fullfilling profecy) é\num conceito descrito pela Psicologia Social que pode\nser observado no sistema prisional, uma vez que se\nestabelece um mecanismo de autorreprodução da\nviolência pelo reforço da identidade criminosa.", "C": "A \"apreensão por atitude suspeita\" que foi conhecida\nno Brasil no início do século XX tinha como objeto não\numa ação considerada delituosa, mas um indivíduo\nsuspeito por obter sinais de identificação com um\ndeterminado grupo social.", "D": "Segundo os princípios da Psicologia Jurídica afirmados\npor Carvalho (2004), os presidiários devem\nobrigatoriamente ser submetidos a tratamento\npsicológico, uma vez que esse procedimento é\nfundamental para a redução de danos causados pelo\ncárcere.", "E": "De acordo com Carvalho (2004), o conceito de\n\"personalidade voltada para o crime\" tem raízes nas\nideias lombrosianas, assim como o sonho da medição\nda periculosidade é pautada nos modelos positivistas\nde ciência, visando à quantificação do futuro dos\npresidiários."}, "g": "D", "j": "O tratamento psicologico do preso nao e obrigatorio - a alternativa D contraria os principios da Psicologia Juridica, que enfatizam autonomia e consentimento."}, {"id": "821077", "d": "psicologia", "a": ["Foucault", "Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Michel Foucault, \"a prisão é um duplo erro\neconômico: diretamente pelo custo intrínseco de sua\norganização e indiretamente pelo custo da delinqüência\nque não se reprime\". Em relação à obra Vigiar e Punir, de\nautoria desse pensador francês, assinale a alternativa que\nnão está de acordo com as ideias descritas nessa obra.", "alt": {"A": "Entendendo-se que a figura do castigo ao corpo\ninscreve-se em uma relação de demonstração\nconstante de poder, a gradual substituição das práticas\nde castigo e suplício diante das massas para os\nsistemas prisionais estava vinculada principalmente a\num apelo pela humanização e diminuição da crueldade.", "B": "Foucault afirma que a disciplina é uma técnica\ndesenvolvida para controlar corpos e vidas para além\ndo ato infracional/criminal, transformando o infrator\nem delinqüente.", "C": "As prisões, escolas, quartéis e conventos são\ninstituições que visam ao treinamento do corpo social\na partir da disciplina e da correção. Nas instituições\nprisionais, a ação sobre o indivíduo é ininterrupta e\nincessante, recodificando a existência do sujeito ao\nregular e repartindo todo o seu tempo: de vigília e\nsono, repouso, refeições, trabalho, oração, uso da\npalavra e do pensamento.", "D": "Os três princípios prisionais consistem em: trabalho,\nisolamento e duração da pena, que têm como objetivo\nfabricar corpos submissos e exercitados.", "E": "O disciplinamento, inaugurado pelo panoptismo e\nreforçado pelos saberes científicos, passou a ser a base\nde ordenamento social ocidental. Seu poder estendeu-se\npara a otimização de potencialidades e do tempo\nprodutivo e para o regramento e disseminação dos\n\"bons hábitos\", que afastam a \"preguiça e os vícios\"."}, "g": "A", "j": "Em Vigiar e Punir, Foucault destaca que a substituicao do suplicio publico pelas prisoes nao decorre de humanizacao, mas de um novo regime de controle e de economia do poder punitivo."}, {"id": "821076", "d": "psicologia", "a": ["Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "Em 29/11/2010, o Conselho Nacional de Justiça publicou a\nResolução nº125, que dispõe sobre a Política Judiciária\nNacional de tratamento adequado dos conflitos de\ninteresses no âmbito do Poder Judiciário, considerando a\nconciliação e a mediação como instrumentos efetivos de\npacificação social, solução e prevenção de litígios. Acerca\ndo processo de mediação familiar segundo os pressupostos\nteóricos de Haynes e Marodin (1996), assinale a alternativa\nincorreta.", "alt": {"A": "O mediador deve atuar administrando as negociações\ne planejando as questões a serem resolvidas, a fim de\npromover um processo organizado e, dessa forma,\nfavorecer os participantes na busca de soluções que\nlhes sejam adequadas e aceitáveis.", "B": "O mediador deve atuar de maneira a construir um\nambiente colaborativo entre as partes, desconstruir\nimpasses e oferecer opiniões e sugestões de\nalternativas para o acordo que beneficie a todos.", "C": "A mediação é um processo de poder que visa a\noferecer aos participantes o direito e a habilidade de\ndeterminar o que consideram justo para sua situação\nfamiliar, podendo ir além das previsões legais\nformalizadas.", "D": "O processo de mediação consiste em nove estágios:\nIdentificação do problema, Escolha do método, Seleção\ndo mediador, Reunião de dados, Definição do\nproblema, Desenvolvimento das opções, Redefinição\ndas posições, Barganha e Redação do acordo.", "E": "O processo de mediação somente pode ocorrer se\ntodos os envolvidos concordarem voluntariamente em\nparticipar, não sendo obrigatória a chegada a um\nacordo."}, "g": "B", "j": "Para Haynes e Marodin, o mediador nao oferece opinioes nem sugestoes prontas; ele estimula as partes a construirem suas proprias solucoes."}, {"id": "821075", "d": "psicologia", "a": ["Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "A Lei Maria da Penha (Lei n ° 11.340/2006) é uma lei inovadora\nque trata da violência doméstica e familiar contra a mulher.\nSobre essa lei, assinale a alternativa correta.", "alt": {"A": "A Lei Maria da Penha trata apenas da violência\nconjugal.", "B": "São exemplos de medidas protetivas de urgência que\nobrigam o agressor: suspensão da posse ou restrição\ndo porte de armas, afastamento do lar, proibição de\naproximação da ofendida e de seus familiares,\nrestrição ou suspensão de visitas aos dependentes\nmenores e prestação de alimentos provisórios.", "C": "Para ser contemplada pela Lei Maria da Penha, a\nrelação entre vítima e agressor deve ser de coabitação.", "D": "A Lei Maria da Penha impede que a mulher vítima de\nviolência doméstica e familiar renuncie à queixa que foi\nregistrada.", "E": "Segundo a Lei Maria da Penha, são formas de violência\ndoméstica e familiar contra a mulher: física,\npsicológica, verbal, espiritual e virtual."}, "g": "B", "j": "Sao medidas protetivas de urgencia que obrigam o agressor (art. 22 da Lei Maria da Penha): suspensao da posse/restricao de armas, afastamento do lar, proibicao de aproximacao, restricao de visitas e prestacao de alimentos."}, {"id": "821074", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "O fenômeno do abuso sexual acontece em diferentes\npaíses, e os profissionais de diferentes áreas devem estar\ncapacitados para trabalhar com crianças, adolescentes e\nfamílias vítimas de violência sexual. Sobre a violência sexual\ne a atuação do psicólogo, assinale a alternativa incorreta.", "alt": {"A": "O abuso sexual não se limita apenas à atividade do ato\nsexual, mas também pode envolver as interações\nsexualizadas, que também podem ser verbais e\npsicológicas. Nesse sentido, os atos designados como\nabuso sexual podem ou não envolver contato físico\nentre agressor e vítima.", "B": "Conforme Kaplan e Sadock (1990, em AMAZARRAY &\nKOLLER, 1998), a maioria das situações de abuso sexual\ncontra crianças e adolescentes não é revelada.\nSegundo Furniss (1993), um dos motivos dessa não\nrevelação da violência sexual contra a criança e o\nadolescente é a síndrome de segredo, pois a vítima\nfrequentemente recebe ameaças, caso ela revele a\nsituação.", "C": "Segundo o Código de Ética Profissional do Psicólogo, é\ndever do psicólogo respeitar o sigilo profissional a fim\nde proteger a intimidade das pessoas a que atende.\nNesse sentido, se uma criança revelar durante o\natendimento psicológico que está sofrendo violência\nsexual por parte de seu padrasto, o psicólogo deve\nmanter sigilo profissional, uma vez que se refere\napenas a uma suspeita de um crime.", "D": "Quando as vítimas são meninas, a maioria dos casos de\nviolência sexual acontece no contexto familiar e,\nfrequentemente, o agressor é o pai. Segundo\nAmazarray e Koller (1998), as relações familiares em\nque ocorre o incesto normalmente são disfuncionais,\napresentado funcionamento caótico, fronteiras\nnebulosas e inversão de papéis.", "E": "Crianças e adolescentes vítimas de violência sexual\npodem apresentar como sintomas: hiperatividade ou\nretraimento, fobia, vergonha, culpa, depressão,\nansiedade, pesadelos, distorção da imagem corporal,\nenurese, ecoprese, comportamento sexual\ninadequado, entre outros."}, "g": "C", "j": "O CEP nao autoriza manter sigilo quando ha relato de violencia sexual contra crianca - ha o dever de notificacao obrigatoria, protegendo o melhor interesse da crianca."}, {"id": "821073", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia Jurídica", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2012", "org": "CFP", "t": "", "e": "Sobre a adoção de crianças e adolescentes no Brasil,\nestabelecida no Estatuto da Criança e do Adolescente,\nassinale a alternativa correta.", "alt": {"A": "A adoção é uma medida que deve ser excepcional e\nirrevogável, salvo quando da morte dos adotantes e\nmelhor interesse da criança/adolescente em conviver\ncom os pais biológicos.", "B": "O adotante há de ser, pelo menos, quatorze anos mais\nvelho do que o adotando.", "C": "É necessário consentimento da criança e do\nadolescente no processo de adoção.", "D": "O adotado tem direito de conhecer sua origem\nbiológica, bem como de obter acesso irrestrito ao\nprocesso no qual a medida foi aplicada e seus\neventuais incidentes, após completar 18 (dezoito)\nanos.", "E": "Caso a criança ou o adolescente esteja aguardando o\nprocesso de adoção em um abrigo, o dirigente de\nentidade do abrigo é equiparado ao guardião, para\ntodos os efeitos de direito."}, "g": "D", "j": "O ECA assegura ao adotado o direito de conhecer sua origem biologica e acessar o processo de adocao apos completar 18 anos."}, {"id": "821072", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia Jurídica", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Adoção, Guarda e Tutela de Crianças e Adolescentes"], "ano": "2012", "org": "CFP", "t": "", "e": "Segundo o art. 50 § 3o do Estatuto da Criança e do\nAdolescente, a inscrição de postulantes à adoção será\nprecedida de um período de preparação psicossocial e\njurídica, orientado pela equipe técnica da Justiça da\nInfância e da Juventude, preferencialmente com apoio dos\ntécnicos responsáveis pela execução da política municipal\nde garantia do direito à convivência familiar. Segundo\nPilotti (1988, em Weber, 2004), a equipe interprofissional\nde adoção deve não apenas selecionar os adotantes mais\naptos, mas também assessorar, informar e avaliar os\ninteressados. Acerca desses procedimentos, assinale a\nalternativa que não deve constituir um elemento de\nimportância no período de preparação psicossocial e\njurídica.", "alt": {"A": "Capacidade dos adotantes em exercer papéis inerentes\nà maternidade e à paternidade.", "B": "Personalidade e maturidade dos adotantes.", "C": "Capacidade dos adotantes em aceitar a criança como\nela é, sem noções preconceituosas.", "D": "Capacidade dos adotantes de lidar com a infertilidade.", "E": "Posição socioeconômica dos adotantes."}, "g": "E", "j": "A posicao socioeconomica dos adotantes nao constitui elemento determinante na preparacao psicossocial - o foco e em capacidade afetiva, maturidade e abertura."}, {"id": "821069", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia Jurídica", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde", "Crianças e Adolescentes - Menores Infratores"], "ano": "2012", "org": "CFP", "t": "", "e": "Um adolescente de 16 anos confessou à polícia ter matado\na tiros o radialista Laécio de Souza, 40 anos, no dia\n03/01/2012, no município baiano de Simões Filho (22 km\nde Salvador). Souza, que apresentava um programa diário\nna Rádio Sucesso FM de Camaçari, foi assassinado\nenquanto andava num terreno que havia comprado para\nrealizar ações sociais num bairro carente da cidade. O\nadolescente, que havia sido apreendido sob suspeita de\nenvolvimento no caso, disse à polícia que matou Souza por\nvingança. O radialista, segundo o menor, havia feito uma\nreportagem sobre um crime que ele havia cometido.\n(Fonte: Folha de São Paulo, 06/01/2012, com adaptações)\nAcerca do adolescente em conflito com a lei e do Estatuto\nda Criança e do Adolescente, assinale a alternativa correta.", "alt": {"A": "Conforme o Estatuto da Criança e do Adolescente, as\nmedidas socioeducativas devem ser utilizadas em casos\nmais graves de prática de ato infracional por\nadolescentes, visando à sua punição.", "B": "Tendo em vista que os adolescentes participam\nativamente da sociedade e são também responsáveis\npor ela, caso um adolescente desrespeite as regras\ninstituídas legalmente, a ele será aplicada uma medida\nsocioeducativa, uma vez que a responsabilidade pelo\nato infracional é somente dele.", "C": "Caso um adolescente cometa um ato infracional e a ele\nfor aplicada a medida socioeducativa de internação, ele\nficará sob tutela do Estado e deverá permanecer\nincomunicável por no mínimo um mês, a depender da\ngravidade do ato praticado.", "D": "Aos adolescentes que praticaram ato infracional são\naplicadas somente as medidas socioeducativas que\nconsistem em: advertência, obrigação de reparar o\ndano, prestação de serviços à comunidade, liberdade\nassistida, inserção em regime de semiliberdade e\ninternação em estabelecimento educacional.", "E": "No momento anterior à audiência judicial na Justiça da\nInfância e da Juventude, poderá ser realizado estudo\npsicossocial do adolescente, sua família e rede de\napoio devendo fornecer subsídios por escrito,\nmediante laudos, ou verbalmente, na audiência, a fim\nde auxiliar o Juiz em sua tomada de decisão."}, "g": "E", "j": "O estudo psicossocial do adolescente, familia e rede de apoio pode ser realizado antes da audiencia, fornecendo subsidios por escrito ou verbalmente para a tomada de decisao judicial."}, {"id": "821068", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Érika Piedade da Silva Santos (2004), a\ninfância começou a ser definida como objeto de ação e\nintervenção do Estado a partir do advento do capitalismo e\nde suas demandas: a necessidade de um mercado\nconsumidor e de mão de obra barata e disciplinada. Sobre a\ninfância e a intervenção estatal e científica, assinale a\nalternativa incorreta.", "alt": {"A": "Durante o século XX, a expressão \"menor de idade\"\nestava relacionada à necessidade de diferenciar os\nbem-nascidos e os potencialmente perigosos à\nsociedade, ideia que influenciou o imaginário subjetivo,\nsocial e jurídico.", "B": "Influenciadas pelo movimento higienista, a pediatria e\na pedagogia são exemplos de campos do saber-poder\nque visaram a transformar as formas de constituição\nfamiliar, ditando normas e padrões morais a partir de\nmodelos ideais de conduta, definindo os parâmetros\nde \"normalidade\" e \"anormalidade\".", "C": "Diferentemente do Código de Menores de 1927, o\nCódigo de Menores de 1979 baseava-se na Doutrina da\nProteção Integral, que tinha como objetivo a proteção\nintegral dos menores em situação irregular e como\npoder decisório a centralização na figura do Juiz de\nMenores.", "D": "No Brasil, os primórdios da Psicologia Jurídica referem-se\nà elaboração de avaliações e diagnósticos\npsicológicos direcionados ao controle e adaptação da\nmenoridade nos Juizados de Menores e instituições de\nabrigo e correção de menores.", "E": "A partir da análise de obras de arte, Philippe Ariès\n(1978) defende a ideia de que a descoberta da infância\nteve início somente no século XVIII, quando se passou\na admitir que a criança não estivesse madura para a\nvida adulta, sendo necessário submetê-la a uma\nespécie de quarentena em um regime especial."}, "g": "C", "j": "O Codigo de Menores de 1979 baseou-se na Doutrina da Situacao Irregular - a Doutrina da Protecao Integral surge apenas com o ECA (1990). Logo, C esta incorreta."}, {"id": "821067", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Entrevista Psicológica e Técnicas de Entrevista", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "Meloy (1991, em Rovinski, 2007) propõe seis dimensões\ndistintivas da entrevista psicológica no contexto forense.\nSão elas:", "alt": {"A": "Contexto coercitivo, falta parcial ou total de sigilo,\nredação do laudo, distorção consciente das\ninformações, discordância e verificação e papel do\ninvestigador.", "B": "Acolhimento, estabelecimento de rapport, formulação\nde perguntas, respondendo às perguntas, elaboração\ndo laudo e argumentação em audiência.", "C": "Avaliação individual, avaliação da dinâmica familiar,\navaliação do contexto social e cultural, avaliação das\nquestões psicológicas, avaliação das questões jurídicas\ne avaliação das implicações do laudo.", "D": "Perguntas abertas, perguntas fechadas, perguntas\nreflexivas, respostas diretas, respostas indiretas e\nrespostas reflexivas.", "E": "Contexto psicojurídico, contrato com as partes,\natendimento às partes, resposta aos quesitos,\nelaboração de laudo técnico, defesa do documento em\naudiência."}, "g": "A", "j": "Meloy (1991): as seis dimensoes distintivas da entrevista forense sao contexto coercitivo, falta parcial ou total de sigilo, redacao do laudo, distorcao consciente das informacoes, discordancia/verificacao e papel do investigador."}, {"id": "821066", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2012", "org": "CFP", "t": "", "e": "Este tipo de documento psicológico relaciona-se à avaliação\nde uma questão focal do campo psicológico, a fim de\nesclarecer uma questão-problema do ponto de vista da\nPsicologia, podendo apontar resultados indicativos ou\nconclusivos. Possui como estrutura os seguintes itens:\nIdentificação, Exposição de motivos, Análise e Conclusão.\nO documento psicológico descrito acima se refere a:", "alt": {"A": "Declaração.", "B": "Atestado psicológico.", "C": "Relatório psicológico.", "D": "Laudo psicológico.", "E": "Parecer psicológico."}, "g": "E", "j": "O Parecer Psicologico (Res CFP 007/2003) tem estrutura: Identificacao, Exposicao de motivos, Analise e Conclusao, atendendo a uma questao focal do campo psicologico."}, {"id": "821065", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "A Resolução do Conselho Federal de Psicologia nº 007/2003\ninstitui o manual de elaboração de documentos\ndecorrentes de avaliações psicológicas. Sobre essa\nresolução, leia as afirmações a seguir.\nI. Compreende-se por avaliação psicológica o processo\ntécnico-científico de coleta de dados, estudos e\ninterpretação de dados e informações acerca dos\nfenômenos psicológicos, que são resultantes da relação\ndo indivíduo com o social, utilizando-se, para tanto, de\nestratégias psicológicas - métodos, técnicas e\ninstrumentos.\nII. O processo de avaliação psicológica e seu documento\npsicológico devem considerar a natureza dinâmica, não\ndefinitiva e não cristalizada do seu objeto de estudo,\numa vez que possuem determinações históricas,\nsociais, econômicas e políticas, devendo indicar, onde\nfor possível, o prazo de validade do conteúdo emitido\nno documento. III. Sob toda e qualquer condição, o psicólogo deve\nrecusar utilizar-se de instrumentos, técnicas\npsicológicas e da experiência profissional da Psicologia\nna sustentação de modelos institucionais e ideológicos\nque visem à perpetuação da segregação aos diferentes\nmodos de subjetivação.\nIV. É responsabilidade do psicólogo e da instituição em\nque ocorreu a avaliação psicológica guardar, pelo prazo\nmínimo de cinco anos, os documentos escritos\ndecorrentes de avaliação psicológica, bem como todo o\nmaterial que os fundamentou.\nEstá correto o que se afirma em:", "alt": {"A": "somente II e III.", "B": "somente I, II e IV.", "C": "somente I, III e IV.", "D": "todas.", "E": "nenhuma."}, "g": "D", "j": "As quatro afirmacoes correspondem fielmente ao Manual de Documentos Psicologicos (Res CFP 007/2003), incluindo o prazo minimo de cinco anos para guarda dos documentos."}, {"id": "821064", "d": "psicologia", "a": ["Violência Doméstica, Violência Contra a Mulher e Casos de Abuso", "Família", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "O conceito de família foi mudando ao longo da legislação brasileira. Acerca desse processo de transformações, assinale a alternativa incorreta.", "alt": {"A": "No início do século XX, eram visíveis as influências da Igreja Católica nas leis brasileiras, o que pode ser observado na definição de família da Constituição de  1934: família é constituída pelo casamento indissolúvel sob proteção especial do Estado.", "B": "Segundo o Código Civil de 1916, o pátrio poder é exercido pelo marido, cabendo a ele: a chefia da sociedade conjugal, o direito de fixar domicílio da família e o direito de administrar os bens do casal.", "C": "Somente na Constituição Brasileira de 1967 é reconhecida a união estável entre homem e mulher como entidade familiar, suprimindo a expressão \"constituída pelo casamento\".", "D": "A Constituição da República Federativa do Brasil de 1988 garante direitos iguais entre homens e mulheres, eliminando a superioridade hierárquica dos homens nas legislações anteriores.", "E": "Dentre as legislações brasileiras, a Lei Maria da Penha inovou o conceito de família, trazendo a possibilidade\nde contemplar as uniões homoafetivas no âmbito familiar."}, "g": "C", "j": "O reconhecimento da uniao estavel entre homem e mulher como entidade familiar ocorreu apenas na Constituicao de 1988, e nao em 1967."}, {"id": "821063", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica", "Perícia Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia as afirmações que se seguem acerca da atividade do psicólogo assistente técnico.I. Segundo o Código do Processo Civil, não há impedimentos ou suspeição para a atuação do assistente técnico.II. Deve redigir um parecer crítico acerca do laudo psicológico oriundo da perícia.III. O assistente técnico fará sua apreciação técnica durante a realização da perícia psicológica.\nIV. O assistente técnico é indicado por uma das partes em um processo judicial, podendo apresentar quesitos a\nserem respondidos durante a perícia. Está correto o que se afirma em:", "alt": {"A": "somente I e III.", "B": "somente I, II e IV.", "C": "somente II, III e IV.", "D": "todas.", "E": "nenhuma."}, "g": "B", "j": "Estao corretas: I (CPC nao preve impedimento/suspeicao para o assistente tecnico), II (redige parecer critico do laudo) e IV (indicado pelas partes, pode apresentar quesitos). III esta incorreta."}, {"id": "821062", "d": "psicologia", "a": ["Psicologia Jurídica", "Perícia Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "Segundo Shine (2007), a perícia psicológica é uma avaliação\nrealizada no contexto forense. Sobre os aspectos éticos dessa prática psicológica, leia as seguintes afirmações:I. O sigilo profissional no enquadre de uma perícia psicológica é garantido apenas nas questões irrelevantes para a matéria jurídica em apreciação. II. No relacionamento com profissionais do Direito, o psicólogo jurídico deve compartilhar somente informações relevantes para qualificar o serviço prestado.III. É vedado ao profissional psicólogo ser perito em situações nas quais seus vínculos pessoais ou profissionais, atuais ou anteriores, possam afetar a qualidade do trabalho a ser realizado ou a fidelidade aos resultados da avaliação.IV. Caso requisitado, o psicólogo perito de casos de repercussão social deve realizar breves comentários nos meios de comunicação a fim de garantir o princípio da supremacia do interesse coletivo.Está correto o que se afirma em:", "alt": {"A": "somente III.", "B": "somente I e II.", "C": "somente II e III.", "D": "somente I, II e III.", "E": "todas."}, "g": "D", "j": "Estao corretas I, II e III (sigilo nas questoes irrelevantes, compartilhamento de informacoes relevantes e vedacao de pericia com vinculos pessoais). IV contraria o sigilo profissional ao defender comentarios na midia."}, {"id": "821061", "d": "psicologia", "a": ["Psicologia Jurídica: Conceito, Histórico e Atuação", "Psicologia Jurídica"], "ano": "2012", "org": "CFP", "t": "", "e": "A partir das afirmativas a seguir, que tratam da especialidade da Psicologia Jurídica, assinale a alternativa correta.I. É papel do psicólogo jurídico assessorar na formulação, revisão e execução de leis que tratam de seu objeto de estudo. II. A Psicologia no âmbito jurídico deve visar a centralizar-se exclusivamente na elaboração de diagnósticos e laudos periciais.III. São campos da Psicologia Jurídica: as varas cíveis, criminais, Justiça do Trabalho, da família, da criança e do adolescente.IV. O psicólogo desenvolve estudos e pesquisas no campo jurídico, constituindo ou adaptando instrumentos de investigação psicológica.\nEstá correto o que se afirma em:", "alt": {"A": "somente I e III.", "B": "somente II e IV.", "C": "somente I, III e IV.", "D": "todas.", "E": "nenhuma."}, "g": "C", "j": "Estao corretas I (assessoria a leis), III (varas civeis, criminais, do trabalho, da familia, da crianca e adolescente) e IV (pesquisa e instrumentos). II e incorreta - a Psicologia Juridica nao se restringe a laudos periciais."}, {"id": "776188", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Fabiana é professora de ciências em turmas de 8a série/9o ano\ndo Ensino Fundamental. A partir de entrevista realizada com\nFabiana foi possível perceber que, para ela, os baixos\nresultados alcançados pelos alunos nas avaliações decorrem\nda falta de interesse dos estudantes nas aulas, da indisciplina e\nda falta de incentivo dos pais para o estudo. Analise as\nafirmativas e assinale aquela que indica ações desejáveis do\npsicólogo escolar que trabalha na escola de Fabiana, com base\nna perspectiva crítica e preventiva em Psicologia Escolar.I.Contribuir para a reflexão das concepções subjacentes\nque Fabiana tem do ensino, da aprendizagem e da\navaliação, as quais orientam sua maneira de trabalhar e\ncompreender os fenômenos escolares.\nII. Problematizar, junto com Fabiana, os aspectos\nintersubjetivos que são constitutivos do desenvolvimento\ne da aprendizagem humana. III.Oferecer, à professora Fabiana, tratamento psicológico\npara sua descrença no potencial dos alunos.\nIV. Convocar, juntamente com Fabiana, reunião de pais para\ndiscutir os resultados das avaliações dos alunos e orientá-los a incentivar os filhos a estudarem, evidenciando as\nimplicações psicológicas da não participação parental.\nV. Promover, durante as coordenações pedagógicas,\ndiscussões acerca dos fatores intraescolares que também\nparticipam do processo de aprendizagem dos alunos.\nEstá correto o que se afirma em:", "alt": {"A": "III, somente.", "B": "I e IV, somente.", "C": "I, II e V, somente.", "D": "II, III e IV, somente.", "E": "I, II, IV e V , somente."}, "g": "C", "j": "Acoes desejaveis na perspectiva critica: I (reflexao das concepcoes da professora), II (problematizar aspectos intersubjetivos) e V (discutir fatores intraescolares). III e IV nao se adequam."}, {"id": "776187", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Fernando é professor de Física no Ensino Médio há 18 anos\ne queixa-se de que, atualmente, os alunos são mais\ninquietos, agitados e, sobretudo, indisciplinados. Por essa\nrazão, vem modificando suas aulas no sentido de privilegiar\ntrabalhos individuais e proibindo a interação entre os\nalunos, o que, segundo ele, sempre acaba em bagunça.\nHipotetizando que você seja o psicólogo escolar da\ninstituição em que Fernando trabalha, qual argumento não\ndeve orientar a atuação do psicólogo escolar, tendo como\nreferência a perspectiva crítica?", "alt": {"A": "A elaboração de metodologias de ensino que\nvalorizam as relações sociais, estabelecidas em sala de\naula, favorece a construção de conhecimento.", "B": "Partilhamos e transformamos significados com nosso\ngrupo cultural por meio das relações sociais.", "C": "Considerando o papel da mediação no processo de\naprendizagem, a ausência de troca de ideias entre os\nalunos potencializa a construção do conhecimento.", "D": "Os processos psicológicos são potencializados nas\nrelações sociais que são mediadoras de trocas de\nsignificados socialmente partilhados.", "E": "As trocas interativas entre os alunos promovem desafios,\nconflitos e negociações que levam a uma construção\nativa de conhecimentos e ao desenvolvimento de\nautonomia, iniciativa e responsabilidade."}, "g": "C", "j": "A afirmativa C contradiz a perspectiva critica: a ausencia de troca de ideias entre alunos NAO potencializa a construcao do conhecimento - a mediacao social e justamente o que a sustenta."}, {"id": "776186", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Queixas relativas a problemas de aprendizagem,\ndificuldades, distúrbios e transtornos engrossam os\nnúmeros de insucesso escolar. Em relação a tais temáticas,\nassinale a alternativa que expressa atuação coerente por\nparte do psicólogo escolar, com base nas produções\nrecentes em Psicologia Escolar.", "alt": {"A": "O maior foco de intervenção do psicólogo escolar são\nos alunos que não aprendem, pois são as vítimas de um\nsistema educacional falido.", "B": "O psicólogo escolar deve trabalhar pela\nconscientização dos múltiplos fatores envolvidos no\nfracasso escolar, inclusive os intraescolares.", "C": "O modelo de intervenção remediativo é o que melhor\nauxiliará na modificação do quadro de insucesso\nescolar.", "D": "A responsabilização ou culpabilização do aluno pelo\nnão aprender é uma prática importante do psicólogo\nescolar como forma de conscientizar os alunos da sua\nresponsabilidade pelos estudos.", "E": "As dificuldades de aprendizagem têm, evidentemente,\norigem na inabilidade dos pais para ajudarem seus\nfilhos com as tarefas de casa, os trabalhos extraclasse e\na organização da rotina de estudo, aspectos que\ndemandam orientação do psicólogo escolar."}, "g": "B", "j": "A producao recente em Psicologia Escolar critica afirma que o psicologo deve trabalhar pela conscientizacao dos multiplos fatores envolvidos no fracasso escolar, incluindo os intraescolares."}, {"id": "776185", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "A inclusão de diferentes atores na intervenção de um\nproblema escolar favorece a promoção do\ndesenvolvimento e da aprendizagem. Ao se incluir o\nprofessor como coparticipante no processo de atendimento\na seus alunos, por exemplo, emerge um espaço de\ninterlocução que possibilita ao professor refletir sobre sua\nprática e assumir uma postura mais crítica diante das\nqueixas escolares. Com base nas reflexões sobre atuação\ncrítica e preventiva em Psicologia Escolar, analise as\nalternativas e assinale a incorreta.", "alt": {"A": "A participação do professor no entendimento das\nqueixas escolares favorece sua conscientização em\nrelação às concepções de desenvolvimento e\naprendizagem.", "B": "Ao incluir o professor, os psicólogos escolares criam\ncondições para a desmistificação das explicações\npsicologizantes sobre as dificuldades de aprendizagem.", "C": "A participação ativa do professor na busca de\nalternativas para o aprendizado dos alunos lhe\npossibilita apropriar-se de sua função e\nresponsabilidade.", "D": "O psicólogo escolar pode provocar, junto aos\nprofessores, o questionamento das concepções\ndeterministas que, implicitamente e de forma pouco\nlúcida, estão presentes nas práticas pedagógicas.", "E": "O trabalho do psicólogo escolar com os professores é\numa maneira de ensinar-lhes técnicas de ensino mais\nadequadas."}, "g": "E", "j": "A alternativa E adota postura prescritiva ('ensinar tecnicas de ensino mais adequadas'), incompativel com a perspectiva critica de atuacao com professores."}, {"id": "776184", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "As possibilidades de atuação psicológica nos contextos\neducativos têm se ampliado e diversificado\nsignificativamente nas últimas décadas. Dentre as\nalternativas, assinale aquela que não corresponde à\natuação em Psicologia Escolar, conforme as diretrizes\ncontemporâneas que orientam a área.", "alt": {"A": "Consultoria escolar.", "B": "Assessoria à gestão institucional.", "C": "Acompanhamento do processo ensino-aprendizagem.", "D": "Aulas de reforço escolar aos alunos com necessidades\neducativas especiais.", "E": "Planejamento e desenvolvimento de projetos de\ncapacitação para gestores."}, "g": "D", "j": "Aulas de reforco escolar aos alunos com necessidades educativas especiais nao integram as diretrizes contemporaneas de atuacao em Psicologia Escolar - sao funcao do educador."}, {"id": "776182", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "As manifestações de violência estão cada vez mais\nfreqüentes no contexto escolar. A ocorrência do fenômeno\nbullying, por exemplo, tem se intensificado; refere-se a um\nconjunto de atitudes agressivas, intencionais e repetitivas,\nrealizadas por um ou mais alunos contra outro(s), e que\ncausam dor, angústia, mal-estar e sofrimento. Tomando\ncomo referência as possibilidades de atuação crítica e\npreventiva do psicólogo escolar em relação à temática da\nviolência escolar, assinale a alternativa correta.", "alt": {"A": "Os altos índices de agressão escolar têm forte influência\nda desestruturação familiar, indicando a necessidade de o\npsicólogo escolar planejar cursos de orientação aos pais\npara ensinar a necessidade de colocarem limites nos\nfilhos.", "B": "A intervenção do psicólogo escolar deve direcionar-se ao\nfortalecimento da indiferença e da banalização em\nrelação às agressões que ocorrem no contexto educativo.", "C": "Contribuição importante do psicólogo escolar é no\ntratamento terapêutico dos estudantes agressores e na\nconscientização de suas ações, com vistas a adaptá-los às\nregras escolares.", "D": "A construção de espaços de diálogo e de circulação dos\nafetos, sentidos e significados atribuídos à escola e às\nrelações deve ser estimulada pelo psicólogo escolar como\nestratégia à redução dos fenômenos de violência.", "E": "A rotulação de estudantes, o uso de apelidos e as\ngozações entre colegas e, também, insultos e\nridicularizações são práticas associadas ao bullying que\ninterferem no processo de aprendizagem e, por isso, cabe\nao psicólogo escolar fazer avaliação psicológica das\nvítimas e iniciar o tratamento."}, "g": "D", "j": "A construcao de espacos de dialogo e de circulacao dos afetos, sentidos e significados na escola e a estrategia critica e preventiva para reducao da violencia escolar."}, {"id": "776180", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "A relação que se estabelece entre a escola e as famílias dos\nalunos é um dos campos de atuação da Psicologia Escolar.\nFamília e escola são os dois primeiros contextos educativos\nem que a criança vive e servem de referência à vida em\nsociedade. À luz das reflexões sobre atuação crítica em\nPsicologia Escolar, particularmente no que se refere às\npossibilidades de intevenção nas relações entre família e\nescola, analise as alternativas abaixo e assinale a incorreta.", "alt": {"A": "Na concepção dos professores existe um modelo\nfamiliar mais adequado às necessidades educacionais,\no qual, na opinião deles, não é cumprido pelos pais. Ao\npsicólogo escolar cabe planejar e executar cursos e\npalestras informativas que ensinem aos pais o que\nprecisam fazer.", "B": "A escola tem um modelo idealizado de família, todavia,\natualmente, há uma diversidade de famílias no que diz\nrespeito à multiplicidade cultural, orientação sexual e\ncomposições. Sendo assim, uma contribuição dos\npsicólogos escolares é na conscientização dos\nprofissionais da escola acerca da diversidade de\nmodelos familiares.", "C": "Historicamente, o padrão da relação entre família e\nescola baseia-se na ocorrência de problemas (baixo\nrendimento acadêmico, indisciplina, relacionamento\ncom os professores etc). Para modificar esse padrão\nrelacionai, o psicólogo escolar pode oportunizar\nreflexões com a equipe escolar voltadas à construção\nde uma relação diferenciada.", "D": "A definição do que cabe aos pais na escola é um grande\ndesafio, pois não é fácil distinguir os temas que lhes\nsão próprios daqueles nos quais seu papel deve ser\ncomplementar. O psicólogo escolar deve oportunizar\nreflexões sobre esse desafio com os atores escolares e\ncom os pais, para que possam\ncolaborativamente uma relação saudável.", "E": "Um espaço de diálogo e discussão entre a família e a\nescola pode ser proposto pelo psicólogo escolar\nquando se identifica que existem divergências de\nopiniões entre os atores envolvidos na relação,\nbuscando contribuir para o desenvolvimento de uma\nrelação de parceria entre família e escola."}, "g": "A", "j": "A alternativa A adota postura prescritiva e individualizante ('cursos que ensinem aos pais o que precisam fazer'), incompativel com a perspectiva critica de Psicologia Escolar."}, {"id": "776179", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "A formação continuada dos profissionais que trabalham em\numa instituição educativa - incluindo professores,\ncoordenadores, técnico-administrativos e gestores - é um\ndos campos de intervenção da Psicologia Escolar. A respeito\ndessa atuação, assinale a alternativa correta.\nI. A formação continuada da equipe profissional da\nescola, mediada pelo psicólogo escolar, direciona-se\npara o aprofundamento e apropriação das bases\nteórico-conceituais que sustentam a proposta\npedagógica da escola, especificamente quanto às\nconcepções de desenvolvimento humano.\nII. A formação continuada visa, sobretudo, a corrigir\nfalhas e lacunas dos cursos de formação inicial. Dessa\nforma, cabe ao psicólogo escolar fazer um diagnóstico\ndas fragilidades dos profissionais.III . O processo de formação continuada planejado e\nconduzido pela Psicologia Escolar é uma estratégia\npara a conscientização das concepções e das práticas\ndos profissionais, com vistas a potencializar os\nIV.\nprocessos educativos.\nA formação continuada busca modificar os\ncomportamentos inadequados dos profissionais no que\ndiz respeito às regras estabelecidas pela escola.\nV. Ações de formação continuada com os gestores da\ninstituição só se justificam quando eles não conseguem\ndesempenhar satisfatoriamente as suas funções.", "e": "Está correto o que se afirma em:", "alt": {"A": "IV, somente.", "B": "I e III, somente.", "C": "II e V, somente.", "D": "I, III, e IV, somente.", "E": "II,IV e V, somente."}, "g": "B", "j": "Apenas I (aprofundamento das bases teorico-conceituais) e III (conscientizacao das praticas dos profissionais) condizem com a perspectiva critica de formacao continuada."}, {"id": "776178", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Contemporaneamente, as estratégias de caráter institucional\nvêm se configurando como prática entre os psicólogos\nescolares que cada vez mais ampliam a compreensão dos\nfenômenos escolares para além da problemática individual.\nAcerca da intervenção institucional em Psicologia Escolar,\nassinale a alternativa incorreta.", "alt": {"A": "Mapear a instituição cria subsídios para a compreensão\nda realidade, bem como dos processos que são\nconstitutivos de subjetividades.", "B": "O Mapeamento Institucional deve ser feito assim que o\npsicólogo ingressa na escola, ampliando sua compreensão\ndo contexto no qual irá atuar e orientando a definição das\nações. Após esse momento, o Mapeamento torna-se\ndesnecessário, pois o profissional já conhece a escola.", "C": "Em uma perspectiva institucional de atuação, o psicólogo\nescolar pode colaborar com a investigação e\nconscientização das concepções e ideais que sustentam as\nações institucionais.", "D": "Mapear, analisar e refletir sobre os aspectos institucionais\nde forma sistemática e contínua é etapa básica do\nprocesso de intervenção institucional.", "E": "O psicólogo escolar pode assessorar os processos de\ngestão como o planejamento e coordenação das políticas,\nprogramas e ações educacionais que impactam as\nrelações intersubjetivas."}, "g": "B", "j": "O Mapeamento Institucional e processo CONTINUO, nao um diagnostico unico no ingresso. A alternativa B contraria a perspectiva institucional contemporanea."}, {"id": "776177", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "Camila é psicóloga escolar de uma escola pública de\nGoiânia e foi contactada pelo coordenador pedagógico que\npediu que intervisse em um conflito entre alunos do 1o ano\ndo Ensino Médio que se agrediram física e verbalmente em\nsala de aula. O coordenador esclareceu, ainda, que um dos\nalunos é negro e que a turma exigia sua expulsão\n(transferência) da escola. Camila, confusa com o pedido\nque estava recebendo, perguntou sobre as medidas que\nhaviam sido tomadas; o coordenador esclareceu que ele\npróprio conversou com os alunos e que, apoiado pela\nmaioria dos professores, pretendia sugerir a transferência\ndo aluno negro para outro turno. Considerando a\nespecificidade do conhecimento psicológico na promoção\ndo desenvolvimento humano e as reflexões sobre atuação\ncrítica em Psicologia Escolar, assinale a alternativa que\napresenta possibilidades de ações da psicóloga escolar.\nI. Conversar com os dois alunos para se desculparem e\nprometerem não se agredir novamente, sob pena de\nserem transferidos da escola.\nII. Realizar oficinas terapêuticas com toda a turma\nvoltadas para a reflexão sobre o preconceito e a\ndiscriminação racial.III. Propor ao aluno negro um acompanhamento\npsicoterapêutico para amenizar seu sentimento de\ndiscriminação.\nIV. Planejar e desenvolver em conjunto com os\nprofessores um projeto de convívio e respeito à\ndiversidade humana.\nV. Dialogar com o coordenador e professores acerca dos\naspectos relacionais, sociais e institucionais envolvidos\nna configuração do conflito.", "e": "Está correto o que se afirma em:", "alt": {"A": "III, somente.", "B": "I e II, somente", "C": "II e IV, somente.", "D": "I, II e III, somente.", "E": "IV e V, somente."}, "g": "E", "j": "As acoes adequadas sao IV (projeto coletivo de convivio e respeito a diversidade) e V (dialogo com coordenador e professores sobre o conflito). I, II e III adotam respostas individualizantes ou punitivas incompativeis com a perspectiva critica."}, {"id": "776176", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Um campo emergente de atuação da Psicologia Escolar é a\nassessoria na elaboração, implementação e avaliação\npermanente da proposta pedagógica da escola. Entretanto,\na construção de um projeto pedagógico não é uma tarefa\nsimples, pois \"requer coesão em torno dos princípios e\nvalores quanto à função social da educação, da escola e dos\neducadores e a sua tradução em ações e relações regidas\npor direitos e deveres coletivamente estabelecidos\".\nEm relação à atuação do psicólogo escolar na construção de\nprojetos políticos pedagógicos, assinale a alternativa\nincorreta.\nTrecho retirado de: Del Prette, Z. (1999). Psicologia, educação e LDB: novos\ndesafios para velhas questões? Em R. Guzzo (Org.), Psicologia Escolar: LDB\ne educação hoje (pp. 9-26). Campinas: Editora Alínea.", "alt": {"A": "Ao psicólogo escolar compete definir os fundamentos\nconceituais relativos ao desenvolvimento humano e à\naprendizagem a serem assumidos na proposta\npedagógica.", "B": "O projeto político pedagógico da escola deve prever\nsituações e recursos pedagógicos que favoreçam a\npromoção de uma cultura de sucesso escolar, podendo\no psicólogo escolar suscitar essas reflexões e\nconstruções.", "C": "No processo de construção do projeto pedagógico o\npsicólogo pode concentrar sua ação nos aspectos\nrelacionados aos processos  de desenvolvimento humano e de aprendizagem.", "D": "O psicólogo escolar pode participar de atividades de\nsensibilização e de reflexão sobre o que é uma\nproposta pedagógica e a sua função nos trabalhos\ndesenvolvidos na escola.", "E": "No processo de implantação do projeto pedagógico, o\npsicólogo escolar pode mediar as reflexões sobre a\nprática pedagógica à luz dos objetivos e princípios\ncoletivamente estabelecidos."}, "g": "A", "j": "A definicao dos fundamentos conceituais da proposta pedagogica e construcao coletiva da escola, nao competencia exclusiva do psicologo - a alternativa A e a incorreta."}, {"id": "776175", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "Regina, 38 anos, professora das séries iniciais do Ensino\nFundamental em uma escola pública do interior goiano,\nprocurou a psicóloga escolar relatando que dois alunos de\nsua turma da 3a série/4o ano, ambos repetentes, têm bom\ndesempenho na leitura, escrita e interpretação textual;\ncontudo, estão com grande dificuldade de aprendizagem na\nmatemática, especialmente nas operações de divisão.\nA partir da situação fictícia apresentada acima, e com base\nnas diretrizes contemporâneas em Psicologia Escolar, responda a questão a seguir.", "e": "A partir do reconhecimento de que queixas como a de\nRegina são recorrentes na escola, você planejou ações de\nformação continuada para os professores e coordenadores.\nSão objetivos dessa formação:I. Transmitir conhecimentos psicológicos aplicáveis ao\nprocesso de ensino-aprendizagem que permitam aos\nprofessores fazer diagnóstico psicológico dos alunos\ncom dificuldade de aprendizagem.\nII. Criar um espaço de reflexão sobre as concepções dos\nprofessores acerca do processo de ensino-aprendizagem\ne as influências dessas concepções em\nsuas práticas cotidianas. III. Possibilitar a reflexão sobre os aspectos pessoais,\nrelacionais e institucionais envolvidos no processo de\nensino-aprendizagem, de forma a ampliar a\ncompreensão dos problemas que surgem no decorrer\nIV.\ndo processo.\nProblematizar os motivos\nencaminhamento de\nque\nalunos com\njustificam o\ndificuldades,\nconscientizando os professores da origem individual e\nneurológica dos problemas.\nEstá correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "I e III, somente.", "C": "II e III, somente.", "D": "II e IV, somente.", "E": "II, III e IV, somente."}, "g": "C", "j": "Estao corretas II (criar espaco de reflexao sobre concepcoes) e III (reflexao sobre aspectos pessoais, relacionais e institucionais). I e IV adotam abordagens individualizantes incompativeis com a perspectiva critica."}, {"id": "776173", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Hipotetizando que você seja o psicólogo escolar da escola\nem que Regina trabalha, e tendo como referência os\nconhecimentos e reflexões acerca da atuação crítica em\nPsicologia Escolar, analise as afirmativas e assinale a\nalternativa correta.I. Solicitaria aos pais que levem os filhos a um serviço de\ndiagnóstico psicopedagógico, para avaliação\nprofissional específica.\nII. Buscaria aproximação com a professora Regina para\nincentivar e auxiliar a construção de estratégias de\nensino diversificadas.III. Juntamente com a professora Regina, faria um\ndiagnóstico com toda a turma para identificar por que\napenas dois alunos apresentam dificuldade em\nmatemática.\nIV. Faria encontros com a professora para discutir as\nrazões, expectativas e sugestões relativas à queixa e,\neventualmente, chamaria os alunos para avaliação.\nV. Realizaria uma bateria de testes de inteligência - com\nfoco nas habilidades matemáticas - e, na seqüência,\nencaminharia para avaliação médica e psicopedagógica. Está correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "II e IV, somente.", "C": "l e V, somente.", "D": "II, III e IV, somente.", "E": "todas."}, "g": "B", "j": "Estao corretas II (aproximacao com a professora para construir estrategias diversificadas) e IV (encontros para discutir razoes e expectativas). I, III e V adotam respostas patologizantes ou avaliativas isoladas."}, {"id": "776172", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "Com base no texto a seguir e nas reflexões\ncontemporâneas sobre atuação crítica em Psicologia\nEscolar, responda a questão a seguir.\"Mudar paradigma significa olhar diferentemente para toda\na situação, seus determinantes e formas de intervenção. No\ncaso da Psicologia Escolar, há que se preparar o profissional\npara entender o sistema educacional em todas as suas\ndimensões, principalmente a social e política; para estudar\no sucesso acadêmico e as formas de implementá-lo nas\nsalas de aula; para desenvolver e avaliar os efeitos de\nprogramas de prevenção com o envolvimento de pais e\nprofessores, ao invés de atender a casos desviantes em\nestratégia de atendimento individualizado\" (Guzzo, 1999, p.\n113).\nTrecho retirado de: Guzzo, R. S. L. (1999). Novo paradigma para a\nformação e atuação do Psicólogo Escolar no cenário educacional brasileiro.\nEm R. Guzzo (Org.), Psicologia Escolar: LDB e educação hoje (pp. 105-116).\nCampinas: Editora Alínea.", "e": "Analise as afirmativas a seguir e assinale a alternativa\ncorreta. I. Ao encaminhar alunos para avaliação psicológica, o\nprofessor está assumindo de forma inconsciente a\nfragilidade e as limitações do conhecimento\npedagógico.\nII. Incluir o professor no processo de avaliação das\ndificuldades de aprendizagem significa construir novas\nformas de atuação que não se coadunem à perspectiva\ndo fracasso escolar como uma problemática individual.\nIII. O encaminhamento de alunos para avaliação\npsicológica pode ser entendido como uma maneira de\nviabilizar um trabalho coletivo, isto é, como forma de\nestabelecer uma parceria com o psicólogo.\nIV. Ao trabalhar com os professores, o psicólogo escolar\nbusca auxiliá-los na reflexão sobre a sua prática e na\nidentificação dos aspectos pessoais, relacionais e\ninstitucionais envolvidos no processo ensino-aprendizagem.\nEstá correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "I e III, somente.", "C": "I, III e IV, somente.", "D": "II, III e IV, somente.", "E": "nenhuma."}, "g": "D", "j": "Estao corretas II (incluir o professor para superar a logica do fracasso individual), III (parceria via encaminhamento) e IV (auxilio na reflexao sobre a pratica do professor)."}, {"id": "776171", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa correta.", "alt": {"A": "O sucesso escolar é um fenômeno complexo que está\nrelacionado às oportunidades de mediação de\naprendizagens importantes para o aluno, as quais\npossam favorecer o desenvolvimento do seu potencial\npara aprender.", "B": "Almejando a aprendizagem de todos os alunos e a\nmaximização do sucesso escolar, o psicólogo escolar\ndeve trabalhar com base no perfil de aluno ideal.", "C": "Diferentemente do professor que é mediador de\nvariadas aprendizagens, os colegas de turma pouco\noportunizam novas aprendizagens à criança.", "D": "O aluno-problema é portador de um distúrbio\nindividual que revela a necessidade de uma\nintervenção imediata e urgente por parte do psicólogo\nescolar.", "E": "A pobreza das escolas localizadas em regiões de baixa\nrenda é grande responsável pelo fracasso escolar e,\ndiante desse contexto, as possibilidades de intervenção\ndo psicólogo escolar ficam significativamente\nreduzidas."}, "g": "A", "j": "O sucesso escolar e fenomeno complexo relacionado as oportunidades de mediacao de aprendizagens importantes que favorecam o desenvolvimento do potencial do aluno."}, {"id": "776170", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Analise as afirmações e assinale a alternativa correta.I. A atuação preventiva relaciona-se à ação do psicólogo\nescolar de se antecipar a determinado fenômeno\n(problema) com o objetivo de evitar que ele ocorra.\nII. É objetivo do psicólogo escolar possibilitar o\najustamento do comportamento dos estudantes\nproblemáticos a padrões aceitos pela escola. III. Trabalhar de forma preventiva implica desenvolver\nações junto aos profissionais da instituição,\ncontribuindo para a identificação de elementos\nobjetivos, subjetivos e intersubjetivos que dificultam a\nconstrução do conhecimento.\nIV. O desenvolvimento de práticas preventivas pelo\npsicólogo escolar apoia-se em ações de caráter\nremediativo que buscam minimizar um problema\ninstalado.\nV. A mudança de paradigma na atuação em psicologia\nescolar implica modificar a ênfase do fracasso para o\nsucesso, do distúrbio, das dificuldades e das doenças\npara a saúde e a qualidade de vida.Está correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "III e V, somente.", "C": "II, III e IV, somente.", "D": "III, IV e V, somente.", "E": "todas."}, "g": "B", "j": "Estao corretas III (acoes preventivas junto a profissionais para identificar elementos objetivos/subjetivos/intersubjetivos) e V (mudanca do paradigma do fracasso para o sucesso)."}, {"id": "776169", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Uma das inúmeras contribuições da Psicologia Escolar aos\ncontextos educativos refere-se à formação continuada de\nprofessores. Com base na especificidade do conhecimento\npsicológico e nas reflexões sobre atuação crítica em\nPsicologia Escolar, analise as alternativas e assinale a\nincorreta.", "alt": {"A": "O processo de formação continuada de professores,\nmediado pelo psicólogo escolar, deve privilegiar a\napropriação de conhecimentos psicológicos, associada\na análise e reflexão das situações cotidianamente\nvivenciadas pelos professores.", "B": "A apropriação dos conhecimentos científicos\nproduzidos pela Psicologia do Desenvolvimento pode\nlevar os professores a compreender que o aprendizado\né a mola propulsora do desenvolvimento dos alunos\npara, assim, explorarem de maneira diferente o\nconhecimento científico e os conteúdos curriculares.", "C": "A formação de professores deve oportunizar\nmomentos de reflexão acerca dos aspectos que\nconstituem o sujeito e são integrantes de sua\nsubjetividade.", "D": "A atuação da Psicologia Escolar na formação\ncontinuada docente pode ser a de destacar o quanto a\nintervenção do professor pode provocar o\ndesenvolvimento das funções psicológicas dos alunos.", "E": "A modificação do trabalho do professor envolve a\nressignificação do sentido subjetivo que o profissional\natribui ao seu trabalho, sendo função do psicólogo\nescolar definir e estabelecer tal sentido."}, "g": "E", "j": "Nao cabe ao psicologo escolar definir e estabelecer o sentido subjetivo que o professor atribui ao seu trabalho - esse sentido e construido pelo proprio profissional. A alternativa E e a incorreta."}, {"id": "776168", "d": "psicologia", "a": ["Psicologia da Educação", "Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa em que não está correta a compreensão acerca da noção de pesquisa psicoeducacional no ambiente escolar.", "alt": {"A": "A pesquisa psicoeducacional envolve planejamento e\nexecução de estudos voltados aos processos de ensino\ne/ou aprendizagem.", "B": "A pesquisa psicoeducacional busca a compreensão das\nvariáveis envolvidas no processo de ensino e/ou\naprendizagem", "C": "A pesquisa psicoeducacional pode envolver\nintervenção, caso o corte do estudo exija esse tipo de\natividade.", "D": "A pesquisa psicoeducacional pode se voltar para\natender a aspectos psicossociais do professor.", "E": "A pesquisa psicoeducacional não deve ter interface\ncom variáveis associadas à saúde mental, pois perderia\nseu foco por se inserir em outra área de interesse."}, "g": "E", "j": "A pesquisa psicoeducacional pode e deve ter interface com variaveis de saude mental, ja que estas afetam diretamente os processos de ensino-aprendizagem - a alternativa E e a incorreta."}, {"id": "776167", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia da Educação", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "O exercício profissional do psicólogo escolar está fundamentado nos princípios do Código de Ética profissional. I. Embora os princípios sejam gerais da profissão de\npsicólogo e não da especificidade da atuação do\npsicólogo escolar, tais princípios são norteadores e\ndevem ser seguidos.\nII. Os princípios éticos são gerados a partir de dilemas\néticos e específicos de cada atuação profissional,\nportanto, quando se trata da atuação do psicólogo\nescolar, o Código de Ética não atende à demanda dessa\nrealidade. III. Os princípios devem ser atendidos, contudo, por vezes\né preciso usar o bom senso e abrir exceção quanto ao\nuso e à aplicação do Código de Ética no contexto\nescolar.", "e": "Está correto o que se afirma em:", "alt": {"A": "I e III, somente.", "B": "III, somente.", "C": "I, somente.", "D": "II, somente.", "E": "nenhuma."}, "g": "C", "j": "Apenas a afirmativa I esta correta - os principios gerais do Codigo de Etica devem nortear a atuacao do psicologo escolar, mesmo nao sendo especificos da area."}, {"id": "776166", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa em que se pode observar um desvio\nde função do psicólogo escolar.", "alt": {"A": "O psicólogo escolar pode atuar como clínico no\ncontexto escolar, desde que essa atuação não interfira\nno seu fazer enquanto psicólogo escolar.", "B": "O psicólogo escolar pode auxiliar na elaboração do\nprojeto pedagógico da instituição escolar.", "C": "Dentre as atribuições do psicólogo escolar, está a\nmediação do diálogo entre professor e aluno.", "D": "O psicólogo escolar pode disseminar trabalhos\ncientíficos que permitam o diálogo entre a realidade\nacadêmica e a prática escolar.", "E": "Orientar, supervisionar ou executar projetos\ninterventivos junto aos professores."}, "g": "A", "j": "Atuar como clinico no contexto escolar configura desvio de funcao do psicologo escolar, mesmo quando se argumenta nao interferir no fazer principal."}, {"id": "776165", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "O psicólogo escolar assume diversas atribuições\nprofissionais na escola. Sendo assim, assinale aquela que\nnão se caracteriza como papel do psicólogo escolar.", "alt": {"A": "Diagnóstico institucional.", "B": "Planejamento e execução de intervenções\npsicoeducacionais que capacitem a equipe escolar.", "C": "Orientação vocacional/profissional a\nestudantes.", "D": "Avaliação diagnostica de alunos com dificuldades de\naprendizagem.", "E": "Avaliação da saúde mental de professores que\napresentam sintomas de esgotamento no trabalho,\ncomo estresse laborai, depressão, entre outros"}, "g": "E", "j": "A avaliacao da saude mental de professores compete a clinica/saude do trabalhador, nao ao psicologo escolar, que pode no maximo encaminhar."}, {"id": "776164", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "No fazer profissional do psicólogo escolar, deve-se adotar\numa postura crítica. Assinale a alternativa na qual essa\npostura crítica não é respeitada.", "alt": {"A": "A atuação do psicólogo escolar deve ser fundamentada\nno compromisso para a luta por uma escola\ndemocrática.", "B": "O fazer do psicólogo escolar deve ser pela qualidade do\nensino.", "C": "O fazer do psicólogo escolar deve ter compromisso\nhistórico e social com a noção de escola participativa.", "D": "O psicólogo escolar tem o dever de também atender\naos interesses políticos e partidários, pois estes\ninterferem no contexto escolar.", "E": "O psicólogo escolar deve se posicionar de modo a\ndefender os direitos à cidadania dos alunos e dos\nprofissionais da educação."}, "g": "D", "j": "A alternativa D nao respeita a postura critica: o psicologo escolar nao deve servir a interesses politicos e partidarios, mas a valores publicos e ao direito a educacao."}, {"id": "776163", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "Em muitos casos a história familiar e as carências materiais\ndos alunos com insucesso escolar são utilizadas para\nexplicar com exclusividade os problemas escolares.\nLevando em conta essa consideração, leia as afirmações a\nseguir:\nI. O psicólogo escolar deve sempre avaliar o insucesso\nescolar como um todo, no complexo cenário do ensino\ne da aprendizagem do aluno.\nII. Para o psicólogo escolar fica claro que todos os alunos\nque apresentam insucesso escolar são vítimas de\nviolência doméstica. III.O psicólogo escolar deve ter uma preocupação de\narticular a história escolar com a história pessoal do\naluno, e não somente a história familiar. IV. O psicólogo escolar deve estar consciente de que os alunos que apresentam insucesso escolar são\nprovenientes de lares e famílias desestruturados.", "e": "Está correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "II e IV, somente.", "C": "I e III, somente.", "D": "II e III, somente.", "E": "todas."}, "g": "C", "j": "Estao corretas I (avaliar o insucesso como um todo) e III (articular historia escolar com historia pessoal). II e IV generalizam violencia domestica e desestruturacao familiar."}, {"id": "776162", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "Leia as afirmações a seguir:\nI. A motivação para a aprendizagem do aluno depende\nde políticas educacionais efetivas que melhorem as\ncondições de trabalho do professor e\nconsequentemente a qualidade do seu trabalho em\nsala de aula.\nII. A motivação para a aprendizagem do aluno pode ter\ncausas internas (intrínsecas) que não se relacionam\nnecessariamente com a falta de motivação do\nprofessor para ensinar.\nIII. A motivação do professor para ensinar pode ser\nmelhorada por meio de intervenção psicológica\nterapêutica do psicólogo escolar com o professor\ndesmotivado.", "e": "Quanto à motivação voltada ao contexto escolar está\ncorreto o que se afirma em:", "alt": {"A": "I, somente.", "B": "I e II, somente.", "C": "II e III, somente.", "D": "II, somente.", "E": "Todas."}, "g": "D", "j": "Apenas II esta correta - a motivacao para a aprendizagem pode ter causas internas (intrinsecas) independentes da motivacao do professor."}, {"id": "776161", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Sobre o fracasso escolar, é possível afirmar que muitos\npsicólogos escolares apresentam uma visão medicalizante\nacerca desse fenômeno. Com base no que foi exposto,\nresponda o que é a visão medicalizante adotada por muitos\npsicólogos escolares.", "alt": {"A": "Visão que atribui ao fracasso ou dificuldade de\naprendizagem uma relação causai de que o problema\nestá relacionado a algum distúrbio psico-fisiológico do\naluno.", "B": "Trata-se de uma visão mais atual na qual a intervenção\npsicológica é vista como um tipo de remédio clínico\nque poderia ser profilático ao aluno com dificuldade.", "C": "A visão medicalizante é uma visão na qual o psicólogo\nescolar assume o papel de médico, adotando assim\nposturas de cunho mais clínico, especialmente no caso\nde alunos com dificuldades.", "D": "Essa visão defende que o psicólogo também poderia\nprescrever medicamentos específicos que ajudariam\nalunos com dificuldades, como é o caso de alunos com\nDéficits de atenção e/ou Hiperatividade.", "E": "A visão medicalizante tem por foco a atuação\nmultiprofissional entre o psicólogo, a equipe escolar e\nos profissionais da saúde."}, "g": "A", "j": "Visao medicalizante atribui o fracasso/dificuldade de aprendizagem a uma relacao causal com disturbio psico-fisiologico do aluno, reduzindo o fenomeno educacional a uma patologia individual."}, {"id": "776160", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "O fazer profissional do psicólogo no âmbito da escola exige\nque ele tenha conhecimentos que o instrumentalizem em\nsua prática. Torna-se imprescindível que o psicólogo escolar\nseja capaz de compreender os fenômenos próprios desse\ncontexto à luz das legislações e normativas vigentes. Sendo\nassim, assinale a alternativa cuja afirmação está\nequivocada.", "alt": {"A": "Os Parâmetros Curriculares Nacionais são mais\najustados ao conhecimento do pedagogo e, portanto,\nnão são necessários ao trabalho do psicólogo.", "B": "O código de ética profissional invariavelmente deve ser\num norteador para a atuação do psicólogo.", "C": "O Estatuto da Criança e do Adolescente se constitui em\nferramenta importante para o psicólogo.", "D": "As resoluções publicadas pelo Conselho Federal de\nPsicologia devem servir de parâmetro para a atuação\ndo psicólogo, independendo de sua área.", "E": "O conhecimento do projeto pedagógico e do currículo\nda instituição escolar é fundamental para a atuação do\npsicólogo escolar."}, "g": "A", "j": "Os Parametros Curriculares Nacionais sao referencias importantes para o trabalho do psicologo escolar - afirmar que nao sao necessarios e equivocado."}, {"id": "776159", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "A atuação do psicólogo junto à comunidade é uma prática\nque assume importância na melhoria de como esta\ncomunidade enxerga a escola. Com base nessa\nconsideração, assinale a alternativa que não estaria\ncoerente com a atuação do psicólogo escolar.", "alt": {"A": "O trabalho do psicólogo escolar pode promover a\nampliação do diálogo entre escola e comunidade.", "B": "O psicólogo escolar pode desenvolver programas\ninterventivos que permitam levar informações à\ncomunidade.", "C": "Invariavelmente a comunidade é resistente às ações\ninterventivas do psicólogo escolar, mesmo esse\ntrabalho ocorrendo de forma interdisciplinar.", "D": "A atuação do psicólogo escolar com a comunidade\npermite a compreensão da inter-relação\npais/escola/aluno/meio.", "E": "A comunidade pode ser uma parceira da escola e o\npsicólogo escolar pode ser o agente facilitador dessa\nparceria."}, "g": "C", "j": "Generalizar que a comunidade e 'invariavelmente resistente' as acoes do psicologo escolar contraria a perspectiva critica e dialogica de atuacao."}, {"id": "776158", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Cabe ao psicólogo escolar desenvolver atividades de cunho\npreventivo e educativo, tendo inclusive a prevenção como\nfoco de atenção primária. Sendo assim, seria incoerente\nafirmar que:", "alt": {"A": "atuações voltadas à prevenção podem atingir\nprofessores, alunos e comunidade.", "B": "atuar de forma preventiva junto aos alunos pode surtir\nefeitos positivos em sua vida escolar.", "C": "não se deve considerar que a intervenção educativa\nanule a importância da ação remediativa.", "D": "atuações que focam a prevenção no âmbito escolar\npodem ocorrer dentro ou fora da escola.", "E": "o trabalho de remediação é mais relevante do que o\npreventivo, pois permite reparar uma situação\nproblema já instalada."}, "g": "E", "j": "Afirmar que a remediacao e mais relevante que a prevencao e incoerente com a perspectiva critica e preventiva da Psicologia Escolar."}, {"id": "776157", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Ao considerar a família como elemento importante na\nremediação da dificuldade do aluno que apresenta fracasso\nescolar, não é correto afirmar que:", "alt": {"A": "a família pode ser orientada a como lidar de forma\nmenos traumática com essa situação.", "B": "por mais que o psicólogo intervenha, cabe somente à\nfamília fazer com que o aluno supere sua dificuldade.", "C": "o psicólogo poderá mediar o diálogo entre escola,\nfamília e aluno com dificuldade.", "D": "o suporte familiar pode causar impacto positivo no\ncomportamento do aluno com dificuldade.", "E": "o planejamento de ações específicas junto ao aluno\ncom dificuldade se faz necessário."}, "g": "B", "j": "A superacao do fracasso escolar e processo compartilhado entre escola, familia e equipe psicossocial - nao recai 'somente sobre a familia'."}, {"id": "776156", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "A atuação com pessoas com necessidades educativas\nespeciais constitui uma das práticas do psicólogo escolar.\nAssinale a alternativa que não condiz com esse tipo de\natuação.", "alt": {"A": "O psicólogo escolar pode realizar a caracterização ou\ndiagnóstico do aluno com essa necessidade.", "B": "O psicólogo escolar pode desenvolver estratégias de\nintervenção grupal que ofereçam apoio à equipe\npedagógica na lida com o aluno com essa necessidade.", "C": "O psicólogo escolar pode promover ações que\npermitam a melhor socialização do aluno com essa\nnecessidade.", "D": "O psicólogo escolar poderá oferecer assistência\npedagógica adequada às demandas específicas do\naluno com essa necessidade.", "E": "O psicólogo escolar poderá atuar de forma\ninterventiva, oferecendo esclarecimentos às famílias\ndos alunos com essa necessidade."}, "g": "D", "j": "Oferecer assistencia pedagogica e funcao do pedagogo/educador especial, nao do psicologo escolar, que pode apoiar mas nao substituir tal atuacao."}, {"id": "776155", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "A atuação interventiva no fazer do psicólogo escolar pode\nfocar diferentes formas de trabalho e visa sempre à\npromoção de ações mais assertivas na lida de alguma\nsituação. Considere as seguintes propostas interventivas:\nI. Ação focada em remediar as dificuldades de alunos\ncom deficiências na aprendizagem, pois esses\ninvariavelmente acabam por delinquir e a intervenção\nmudaria esse fato.\nII. Ação interventiva com pais, alunos e professores\npoderia ser viabilizada de forma concomitante e\nsurtiria maior resultado.\nIII. Ação direcionada ao trabalho com professores de\nalunos com dificuldades escolares poderia ser benéfica\npara o professor e, de forma indireta, para o aluno.", "e": "Está correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "II e III, somente.", "C": "I e III, somente.", "D": "II, somente.", "E": "todas."}, "g": "B", "j": "Estao corretas II (intervencao concomitante com pais, alunos e professores) e III (trabalho com professores beneficia o aluno de forma indireta). I generaliza ao associar dificuldade a delinquencia."}, {"id": "776154", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Torna-se imprescindível a atuação do psicólogo escolar na\nelaboração de um projeto interventivo que auxilie a equipe\npedagógica dos diferentes níveis da educação formal a\nlidarem de forma mais eficaz com os alunos com altas\nhabilidades/superdotação. Com base nessa consideração,\nassinale a alternativa que não estaria coerente com a\natuação do psicólogo escolar.", "alt": {"A": "Os professores podem ser orientados pelo psicólogo\nescolar a lidarem de forma mais assertiva com as\ndiscrepâncias apresentadas entre o desempenho do\naluno com altas habilidades/superdotação e o\ndesempenho dos alunos considerados típicos.", "B": "Cabe ao psicólogo escolar atuar visando a melhorar a\ninteração entre professores, alunos típicos e aluno com\naltas habilidades/superdotação.", "C": "O psicólogo escolar poderia desenvolver um trabalho\npsicoterapêutico junto ao aluno com altas\nhabilidades/superdotação, de modo a aprimorar ainda\nmais as habilidades desse aluno.", "D": "O psicólogo escolar poderia auxiliar a equipe\npedagógica na elaboração de atividades voltadas ao\naluno com altas habilidades/superdotação.", "E": "O trabalho do psicólogo escolar poderia abranger a\norientação de pais de alunos com altas\nhabilidades/superdotação."}, "g": "C", "j": "Desenvolver trabalho psicoterapeutico individual com o aluno superdotado configura desvio de funcao do psicologo escolar."}, {"id": "776153", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia da Educação", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando o Código de Ética Profissional em seu Artigo 1o, Letra i, pode ser observado que o psicólogo deve \"zelar\npara que a comercialização, aquisição, doação,\nempréstimo, guarda e forma de divulgação do material\nprivativo do psicólogo sejam feitas conforme os princípios\ndo código de ética\". A esse respeito, é correto afirmar que:", "alt": {"A": "o psicólogo, no seu fazer profissional na escola, sabe\nque há outros profissionais que não são psicólogos,\nque poderiam fazer uso de material privativo e que,\nportanto, essa regra não se aplicaria nessas condições.", "B": "é sabido pelo psicólogo escolar que no contexto da\nescola não cabe a ele zelar pela comercialização,\naquisição, doação, empréstimo, guarda e forma de\ndivulgação do material privativo do psicólogo.", "C": "esse princípio do Código de Ética não se aplica ao\npsicólogo escolar, haja vista que, em sua atuação, ele\nnão faz uso de material privativo.", "D": "a direção da escola não deve ser privada do acesso aos\nmateriais privativos do psicólogo, especialmente\nporque a direção deve ter ciência sobre as atividades\ndo psicólogo escolar dentro da instituição.", "E": "o psicólogo escolar que trabalha com material privativo\ndo psicólogo deve em qualquer circunstância zelar para\nque esse item do código seja cumprido."}, "g": "E", "j": "O psicologo que trabalha com material privativo da profissao deve, em qualquer circunstancia, zelar pelo cumprimento desse dispositivo do Codigo de Etica."}, {"id": "776151", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa que indica no que a função do\npsicólogo escolar se diferencia da função do educador.", "alt": {"A": "O psicólogo escolar tem o papel de intervir, visando a\naprimorar/desenvolver ou remediar os fenômenos\ninerentes à interface psicoeducacional.", "B": "O psicólogo escolar terá a função de desenvolver\natividades clínicas, visando à melhora significativa da\nsituação problema.", "C": "O psicólogo escolar tem o dever de atuar de forma\nclínica e pedagógica, tendo por objetivo maior o bem-estar\ndos alunos e da equipe escolar.", "D": "É papel do psicólogo escolar também atuar como\neducador, especialmente na intervenção com alunos\nque apresentam dificuldades de aprendizagem.", "E": "Somente o psicólogo escolar pode atuar de forma\nclínica na escola, o que permite o atendimento da\nequipe pedagógica, aluno e família."}, "g": "A", "j": "A funcao especifica do psicologo escolar e intervir, visando aprimorar/desenvolver ou remediar os fenomenos da interface psicoeducacional - diferenciando-se do educador."}, {"id": "776150", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Considere a seguinte afirmação: \"A não aprendizagem na\nescola é uma das causas do fracasso escolar.\" Com base na\nafirmativa, responda como o psicólogo escolar deve\nencarar esse fato.", "alt": {"A": "Para o psicólogo escolar esse fato deve ser\ncompreendido sob a perspectiva de que a escola é a\núnica responsável pelo êxito escolar de seus alunos.", "B": "Esse fato deve ser encarado pelo psicólogo escolar\ncomo algo inerente a um contexto mais amplo, isto é, a\nrealidade escolar.", "C": "Esse fato deve ser considerado pelo psicólogo escolar\ncomo reflexo de uma dificuldade da estrutura familiar\ndo aluno.", "D": "O psicólogo escolar deve encarar esse fato como algo\nisolado que acontece na vida de alguns alunos.", "E": "O fato deve ser visto como algo que não reflete a\nrealidade, pois a não aprendizagem é a única causa do\nfracasso escolar."}, "g": "B", "j": "A nao aprendizagem deve ser compreendida como fenomeno inerente ao contexto amplo da realidade escolar, em uma perspectiva critica."}, {"id": "776149", "d": "psicologia", "a": ["Psicologia da Educação"], "ano": "2012", "org": "CFP", "t": "", "e": "Nos últimos anos é possível observar em dados oficiais\noferecidos pelo Ministério da Educação que houve uma\nredução do número de alunos repetentes em toda a\neducação básica. Com base nessa constatação, das\nalternativas a seguir, qual não deve ser considerada como\nconcepção predominante para o trabalho de um psicólogo\nescolar?", "alt": {"A": "O psicólogo escolar deve ter a concepção\npredominante de que todas as variáveis envolvidas na\ndificuldade do aluno devem ser investigadas.", "B": "O psicólogo escolar deve ter a visão de que os fatores\ncondicionantes ou estruturantes podem ter relação\ndireta com o fracasso do aluno.", "C": "O psicólogo escolar deve ter a visão de que muitas\nfamílias de alunos que fracassam na escola se\npreocupam e se comprometem de forma positiva com\na educação desse aluno.", "D": "O psicólogo escolar deve ter a\npredominante de que o aluno com\napresenta conflitos internos que são reflexos de sua\ndesestruturação familiar e que resultam em fracasso\nescolar.", "E": "A visão do psicólogo escolar deve ser no sentido de\nvoltar sua atenção para o cotidiano escolar, focando\nnão somente o aluno com dificuldade, mas também a\nrede de relações que permeiam o cenário escolar."}, "g": "D", "j": "Atribuir o fracasso escolar a conflitos internos do aluno decorrentes de 'desestruturacao familiar' e concepcao reducionista incompativel com a perspectiva critica."}, {"id": "773846", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2012", "org": "CFP", "t": "", "e": "Diferentes desafios demandam atenção e pesquisa\ncientífica de instituições internacionais e nacionais, de\ngovernos e de sociedades civis organizadas. Tais desafios\nsão os efeitos negativos do transporte motorizado, do\naumento da frota de veículos, da ausência de vias\nadequadas, entre outros aspectos que influenciam na\nqualidade de vida urbana, gerando alterações ambientais e\nsociais, intensificando a poluição atmosférica e a poluição\nsonora. Assinale a afirmativa correta.", "alt": {"A": "Pesquisadores do campo do trânsito e da mobilidade\nbuscam entender os processos psicológicos que atuam\nna escolha das pessoas pelo modo de transporte, bem\ncomo o impacto e as conseqüências psicológicas das\npolíticas de redução do uso do automóvel.", "B": "As atuais pesquisas no campo do trânsito são pouco\núteis na elaboração de políticas públicas de mobilidade\nurbana.", "C": "No Brasil, o campo de pesquisa sobre comportamento\nhumano e trânsito encontra-se fortemente\ndesenvolvido ao comparar-se com os principais núcleos\nde pesquisa do assunto na Europa.", "D": "Estudiosos do comportamento consideram que os\naprimoramentos das tecnologias dos automóveis são\naspectos suficientes para resolução dos problemas\natuais e futuros no trânsito.", "E": "O desenvolvimento de novos testes psicológicos é o\nrecurso principal para aprimoramento do campo da\npsicologia do trânsito no Brasil."}, "g": "A", "j": "Pesquisadores em transito e mobilidade investigam os processos psicologicos envolvidos na escolha do modo de transporte e o impacto das politicas de reducao do uso do automovel."}, {"id": "773844", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2012", "org": "CFP", "t": "", "e": "No livro sobre Psicologia do Trânsito no Brasil, Rozestraten\n(1988) enuncia que o trânsito é constituído por três fatores:\n(1) a via, (2) o veículo e (3) o homem. Assinale a afirmativa\ncorreta.", "alt": {"A": "A maior causa dos acidentes de trânsito reside nas\nfalhas mecânicas dos veículos e nas más condições das\nvias de tráfego.", "B": "Estatísticas nacionais e internacionais apontam que a\ningestão de bebidas alcoólicas, por parte dos\nmotoristas, não afeta o incremento nos números dos\nacidentes de trânsito.", "C": "A experiência no ato de dirigir refere-se à idade\nsuperior do condutor aos 18 anos para obtenção de\nCNH.", "D": "As condições do motorista são tidas como principais\ncausas dos acidentes de trânsito, compreendidas em\ntrês níveis: (1) estado físico-fisiológico, (2) estado\nmental e emocional e (3) experiência em dirigir.", "E": "Aspectos mentais e cognitivos pouco interferem no\ncomportamento de dirigir."}, "g": "D", "j": "Rozestraten (1988): as condicoes do motorista sao a principal causa dos acidentes, compreendidas em tres niveis - estado fisico-fisiologico, estado mental/emocional e experiencia ao dirigir."}, {"id": "773842", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica", "Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "Numa situação de pesquisa um grupo de cientistas psicólogos construiu um teste de inteligência geral e\nprocurou validá-lo. No processo de desenvolvimento da\nnova medida, o instrumento construído foi aplicado junto\ncom o teste R-1 e encontrou-se coeficiente de correlação\nentre os testes igual a 0,87. Assinale a alternativa correta.", "alt": {"A": "O novo teste psicológico validado não possui\nindicadores de validade concorrente.", "B": "Entre a variável considerada critério e a variável\npreditora não se observa nenhuma relação.", "C": "O indicador de validade de correlação apresenta valor\ninviável, pois só se consideram valores discriminantes\nos reconhecidos pelo SATEPSI superiores a 0,30.", "D": "O instrumento psicológico desenvolvido é validado,\napresentando indicadores concorrentes positivos de\nvalidade.", "E": "Nenhuma das alternativas anteriores está correta."}, "g": "D", "j": "A correlacao de 0,87 entre o novo teste e o R-1 (criterio) configura validade concorrente positiva e elevada do novo instrumento."}, {"id": "773841", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "O Código de Ética de Psicologia prevê infrações disciplinares\ncom aplicação de penalidades. Considere as afirmações a\nseguir e assinale a alternativa correta.", "alt": {"A": "Ao psicólogo é permitido ser conivente com atos que\ncaracterizem negligência, discriminação, exploração,\nviolência, crueldade ou opressão.", "B": "Ao psicólogo é facultado o ato de induzir a convicções\npolíticas, filosóficas, morais, ideológicas, religiosas, de\norientação sexual ou a qualquer tipo de preconceito,\nquando do exercício de suas funções profissionais.", "C": "O psicólogo, quando exercer atividades ocupacionais\nem instituições de recuperação de infratores e sujeitos\nem conflito com a lei, poderá usar de conhecimento e\npráticas psicológicas como instrumentos de castigo ou\ntortura.", "D": "Ao psicólogo é permitido realizar diagnósticos, divulgar\nprocedimentos ou apresentar resultados de serviços\npsicológicos em meios de comunicação, de forma a\nexpor pessoas, grupos ou organizações.", "E": "Ao psicólogo é vedado interferir na validade e\nfidedignidade de instrumentos e técnicas psicológicas,\nbem como adulterar seus resultados ou fazer\ndeclarações falsas."}, "g": "E", "j": "O CEP veda ao psicologo interferir na validade e fidedignidade dos instrumentos e tecnicas psicologicas, bem como adulterar resultados ou fazer declaracoes falsas."}, {"id": "773840", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Sobre os princípios fundamentais do Código de Ética do\nPsicólogo (2005), assinale a alternativa correta.", "alt": {"A": "O código foi construído dentro de espaços acadêmicos\nde discussão sobre a ética e a filosofia da profissão.", "B": "Conforme orientação do código o psicólogo trabalhará\npara a saúde, a qualidade de vida das pessoas e das\ncoletividades, podendo ser negligente em questões de\ndiscriminação e opressão em situações em que tal\npostura for necessária.", "C": "O psicólogo atuará com responsabilidade, por meio do\ncontínuo aprimoramento profissional, contribuindo\npara o desenvolvimento da Psicologia como campo\ncientífico de conhecimento e de prática.", "D": "O psicólogo zelará para que o exercício profissional seja\nefetuado com dignidade, agindo passivamente nas\nsituações em que a Psicologia esteja sendo aviltada.", "E": "O psicólogo atuará sem responsabilidade social,\nanalisando crítica e historicamente a realidade política,\neconômica, social e cultural."}, "g": "C", "j": "O CEP estabelece que o psicologo atuara com responsabilidade, por meio do continuo aprimoramento profissional, contribuindo para o desenvolvimento da Psicologia como campo cientifico e pratico."}, {"id": "773839", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a substâncias", "Psicologia do Trânsito"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Ponce e Leyton (2008), dirigir é uma tarefa\ncomplexa na qual o condutor recebe informação\ncontinuamente, analisa-a e reage a respeito dela. Substâncias\nque têm uma influência em funções cerebrais ou em\nprocessos mentais envolvidos na condução certamente irão\nafetar seu desempenho. Considere as seguintes afirmações:\nI. A cannabis, também conhecida por maconha, é uma\ndroga ilícita que, quando utilizada por motoristas,\ninfluencia percepções,\ncognitiva e funções afetivas.\nperformance psicomotora, cognitiva e funções afetivas.\n\nII. O indivíduo sob efeito de cocaína está mais propenso a\nassumir comportamentos de risco, o que pode levar a um\nenvolvimento maior em acidentes de trânsito, podendo\nser pela perda de concentração e/ou atenção.\nIII. O uso de derivados anfetamínicos (como o ecstasy) pode\naumentar perigosamente a autoconfiança do condutor,\ncom aumento no envolvimento em situações de risco; o\nmotorista poder tornar-se agressivo no início e apático\nquando os efeitos agudos passam.\nIV. Drogas lícitas e medicinais (como os tranquilizantes e\nantidepressivos) possuem também expressiva\nparticipação na ocorrência de acidentes, não raro com\nvítimas fatais.Está correto o que se afirma em:", "alt": {"A": "somente I e III.", "B": "somente II e III.", "C": "somente I, II e III.", "D": "somente II, III e IV.", "E": "todas."}, "g": "E", "j": "Todas as afirmacoes sobre maconha, cocaina, derivados anfetaminicos e drogas licitas/medicinais e seus efeitos no transito sao consistentes com a literatura."}, {"id": "773838", "d": "psicologia", "a": ["Psicopatologia", "Transtornos relacionados a substâncias", "Psicologia do Trânsito", "Psicologia da Saúde", "Redução de Danos"], "ano": "2012", "org": "CFP", "t": "", "e": "Conforme Nascimento e Cols.(2011) \"A associação entre álcool\ne direção tem se tornado foco de discussão em diferentes\nníveis da estrutura social contemporânea, seja no âmbito da\nsaúde coletiva, seja no da epidemiologia, educação,\nfiscalização, legislação\". Sobre os aspectos relativos à\nassociação entre álcool e direção, assinale a afirmativa correta.", "alt": {"A": "Álcool é considerado um companheiro de eventos sociais,\nresponsável pela diminuição das inibições e conseqüente\nrelaxamento, produzindo sensações de bem-estar no\nindivíduo. Quando consumido em doses reduzidas, não\ntraz prejuízos e riscos para o comportamento humano no\ntrânsito.", "B": "Uma das estratégias para superação dos problemas com\ndrogas no trânsito é Política de Redução de Danos, a qual\nconsiste em políticas que promovam uma redução das\nconseqüências biopsicossociais negativas do consumo de\ndrogas exclusivamente para os motoristas.", "C": "O Código de Trânsito Brasileiro (CBT) estabelece punições\npouco claras para motoristas flagrados em estados de\nembriaguez no trânsito.", "D": "Considerando que o consumo de álcool irá continuar e\nque o abuso de álcool também, os princípios e estratégias\nde redução de danos são ilógicos e pouco eficientes\nnesses casos.", "E": "A combinação entre álcool e direção automotiva é\nresponsável por prejuízos na esfera socioeconômica,\nrevelando prejuízos também em âmbitos mais\nespecíficos, como no familiar e individual."}, "g": "E", "j": "A combinacao de alcool e direcao causa prejuizos socioeconomicos amplos, alem de impactos familiares e individuais, conforme literatura sobre seguranca viaria."}, {"id": "773837", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "A nota técnica CFP no 001/2011 faz menção à propriedade\ndo construto Atenção, objeto de procedimentos de\navaliação psicológica no trânsito. Considere as afirmações a\nseguir e assinale a incorreta.", "alt": {"A": "A atenção pode ser definida como o fenômeno pelo\nqual o ser humano processa uma quantidade limitada\nde informações das várias informações disponíveis no\nambiente.", "B": "Atenção refere-se à capacidade e esforço exercido para\nfocalizar e selecionar um estímulo para ser processado.", "C": "A atenção permite que o indivíduo responda a\ndeterminados aspectos do ambiente, em lugar de fazê-lo a outros, possibilitando a ele utilizar seus recursos\ncognitivos para emitir respostas rápidas e adequadas\nmediante estímulos que julgue importantes.", "D": "No Brasil, atualmente, não há testes psicológicos que\nse propõem a avaliar a atenção concentrada, dividida,\nalternada, sustentada, entre outras, cabendo ao\npsicólogo responsável pela avaliação psicológica para\nmotoristas a escolha por outros testes.", "E": "Diferentes nomenclaturas se referem ao constructo da\natenção, sendo verificada a existência dos conceitos de\natenção dividida, concentrada, sustentada, alternada,\ndifusa, vigilância, distribuída, voluntária, entre outras."}, "g": "D", "j": "Existem testes brasileiros aprovados para avaliacao de atencao concentrada, dividida, alternada e sustentada - a alternativa D contraria esta realidade."}, {"id": "773836", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "A resolução CFP no 016/2002 dispõe acerca do trabalho do\npsicólogo na avaliação psicológica de candidatos à Carteira\nNacional de Habilitação e Condutores de veículos\nautomotores. Das sentenças a seguir, assinale a alternativa\ncorreta.", "alt": {"A": "A resolução citada visa a normatizar e qualificar os\nprocedimentos relacionados à prática da avaliação\npsicológica de candidatos à Carteira Nacional de\nHabilitação e condutores de veículos automotores.", "B": "Os locais para a realização das avaliações psicológicas\npara candidatos à Carteira Nacional de Habilitação e\ncondutores de veículos automotores devem ser\nadequados e específicos, salvo exceções de unidades\nlocalizadas em cidade com população inferior a 20 mil\nhabitantes.", "C": "Conforme resolução, a distribuição dos exames de\navaliação psicológica entre as entidades credenciadas\nna área de jurisdição do órgão executivo do trânsito\ndeve obedecer a parâmetros de livre concorrência de\nclientela e mercado.", "D": "Nos locais onde se realizam os procedimentos de\navaliação psicológica não é permitida a realização de\noutras avaliações, tais como exames de sanidade física\ne mental com a finalidade de obtenção da Carteira\nNacional de Habilitação e condutores de veículos\nautomotores.", "E": "Conforme resolução, frente a situações em que não\nhouver peritos ou especialistas em psicologia do\ntrânsito, os procedimentos de avaliação psicológica\npoderão ser realizados por profissionais com prática\nreconhecida no manuseio de testes psicológicos\nsuperior a 5 anos."}, "g": "A", "j": "A Res CFP 016/2002 visa normatizar e qualificar os procedimentos relacionados a pratica da avaliacao psicologica de candidatos a CNH e condutores de veiculos automotores."}, {"id": "773834", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Marín e Queiroz (2000), os estudos sobre\nacidentes de trânsito (AT) no Brasil são escassos, as ações\nde prevenção e controle estão apenas começando. Pouco\nse conhece a respeito do comportamento do motorista e\ndo pedestre, das condições de segurança das vias e\nveículos, da engenharia de tráfego, dos custos humanos e\nambientais do uso de veículos motorizados e das\nconseqüências traumáticas resultantes dos AT. Sobre os\naspectos gerais dessa situação, considere as seguintes\nafirmações:\n  I. Com uma frota de veículos cada vez maior, circulando\nno mundo inteiro, além do crescimento dos AT,\nobserva-se também um aumento significativo na\npoluição do ar, no índice de ruídos e na transformação\ndegradante da paisagem urbana.\n  II. Os traumas oriundos de AT trazem prejuízos de ordem\napenas individual (financeiros e de locomoção).   III. Os países em desenvolvimento, como o Brasil, apesar\ndas preocupações com os problemas gerados pelos\nacidentes de trânsito, não conseguem implantar\npolíticas ou programas eficazes destinados à\ndiminuição da mortalidade ou dos custos dos\nproblemas decorrentes dos AT.   IV. Do ponto de vista individual, os aspectos dos AT não se\nassociam com variáveis como personalidade, exposição\na risco, aspectos de agressividade e hostilidade.\nEstá correto o que se afirma em:", "alt": {"A": "somente I.", "B": "somente II e IV.", "C": "somente I e III.", "D": "todas.", "E": "nenhuma."}, "g": "C", "j": "Estao corretas I (frota cresce, poluicao e ruidos aumentam) e III (paises em desenvolvimento nao conseguem implementar politicas eficazes). II e IV apresentam afirmacoes reducionistas."}, {"id": "773833", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "A avaliação psicológica é uma função privativa do psicólogo,\nsegundo a Lei no 4.119/62. Sobre os aspectos gerais dessa\nprática, considere as seguintes afirmações:\n  I. O processo de avaliação refere-se à obtenção, análise e\ninterpretação de informações psicológicas, oriundas do\nemprego de técnicas e procedimentos confiáveis.\n  II. São considerados testes psicológicos confiáveis de\navaliação aqueles que apresentam alto grau de\nprecisão e validade, aprovados pelo Sistema de\nAvaliação dos Testes Psicológicos.   III. Por validade de um instrumento psicológico entende-se\no grau de precisão gerado a partir dos seus escores.\n  IV. A propriedade da confiabilidade ou precisão de uma\nmedida psicológica associa-se com a capacidade de o\ninstrumento avaliar ou acessar os fenômenos para os\nquais foi construído.\n  Está correto o que se afirma em:", "alt": {"A": "I e III.", "B": "I e II.", "C": "II e III.", "D": "somente IV.", "E": "I e IV."}, "g": "B", "j": "Estao corretas I (avaliacao envolve obtencao/analise/interpretacao via tecnicas confiaveis) e II (testes confiaveis sao aprovados pelo SATEPSI). III confunde validade com precisao e IV confunde precisao com validade."}, {"id": "773831", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2012", "org": "CFP", "t": "", "e": "O Manual de Elaboração de Documentos Escritos\nproduzidos pelo psicólogo é estruturado a partir da\nresolução CFP n° 007/2003. Sobre este manual, assinale a\nalternativa incorreta.", "alt": {"A": "O relatório psicológico apresenta as demandas,\nprocedimentos, métodos e conclusões gerados pelo\nprocesso da avaliação psicológica, podendo descrever\naspectos de diagnóstico e prognóstico psicológico.", "B": "O \"atestado psicológico\" permite ao profissional\npsicólogo realizar registro de informações sobre\nsintomas, situação e condição psicológica, podendo ser\nusado o registro do Código Internacional de Doença\n(CID).", "C": "No \"Parecer\" não é permitido apresentar informações\nde caráter indicativo ou conclusivo do cliente ou\npaciente atendido.", "D": "O documento do tipo \"Declaração\" é destinado\nprincipalmente à prestação de informações sobre as\ncondições do atendimento (tempo de\nacompanhamento, dias ou horários).", "E": "O Parecer psicológico não pode ser um documento\ndecorrente de um processo de avaliação Psicológica."}, "g": "C", "j": "O Parecer Psicologico PODE apresentar resultados indicativos ou conclusivos - a alternativa C contraria a Res CFP 007/2003."}, {"id": "773830", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "A Resolução nº 002/2003 define e regulamenta o uso, a\nelaboração e a comercialização de testes psicológicos.\nSobre a presente resolução, assinale a alternativa incorreta.", "alt": {"A": "Os Testes Psicológicos são instrumentos de avaliação\ne/ou mensuração de características psicológicas,\nconstituindo-se um método ou uma técnica de uso\nprivativo do psicólogo.", "B": "A resolução possui por objetivo garantir serviços com\nqualidade técnica e ética à população usuária desses\nserviços.", "C": "A resolução orienta procedimentos técnicos gerais de\nqualificação dos testes.", "D": "Como produto final a presente resolução cria um\nsistema contínuo de avaliação dos testes psicológicos,\no SATEPSI.", "E": "A partir da presente resolução, instrumentos projetivos\nsão considerados inválidos e banidos de uso pelo seu\ncaráter subjetivo e pouco padronizável."}, "g": "E", "j": "A Res CFP 002/2003 NAO bane os testes projetivos - alguns sao aprovados e a maioria pode ser submetida a avaliacao pelo SATEPSI. A alternativa E e incorreta."}, {"id": "773829", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando as afirmações de Anache e Corrêa (2010), no\ntexto intitulado 'As políticas do Conselho Federal de\nPsicologia para a avaliação psicológica', julgue verdadeiras\n(V) ou falsas (F) as afirmativas a seguir.\n  ( ) No que se refere à Psicologia no contexto do trânsito, o\nConselho Federal de Psicologia entende que a mobilidade\nhumana, por diversos meios e entre eles o automotivo,\nexpressa a relação que os seres humanos estabelecem com\no seu ambiente.\n  ( ) A avaliação psicológica poderá dar importantes\ncontribuições à Psicologia do Trânsito. No entanto, isso implica\nindubitavelmente a urgente revisão do uso da avaliação\npsicológica para habilitação da carteira de motorista, na\nmedida em que tal procedimento encontra-se apoiado em\nmodelos e instrumentos que se repetem há muitos anos.  \n( ) A avaliação psicológica no contexto do trânsito deverá\nseguir um caminho semelhante ao observado na prática\nclínica nas últimas décadas, ou seja, deverá deixar de ser\nexclusivamente uma aplicação de testes para tornar-se um\ncampo da psicologia que entenda os fenômenos\npsicológicos em sua totalidade. Dessa forma, o psicólogo do\ntrânsito poderá, além de fazer sua avaliação nesse\ncontexto, extrapolar o seu conhecimento para a área\nclínica. Da mesma forma, o psicólogo clínico que apresentar\no conhecimento necessário poderá realizar avaliação\npsicológica no contexto do trânsito.\n  ( ) As relações humanas cada vez mais deterioradas pelo\nsistema econômico e social que se instalou no Brasil têm\ncontribuído para que a violência e o caos se instalem em\ndiversos setores. Certamente a 'rua', como espaço público,\ntem sido palco de permanente confronto, de conflito\nhistórico de lutas de classes proveniente do modelo de\nexploração capitalista. Para pautar a discussão sobre o\nassunto em referência, torna-se necessário avançar na\nconstrução de políticas públicas que garantam a segurança\ne o direito do cidadão de ir e vir. Trata-se de um fenômeno\namplo que não deve ser reduzido à avaliação psicológica.\n  Assinale a alternativa que indica corretamente a seqüência\nde respostas.", "alt": {"A": "V,V, F,V", "B": "V, F ,V ,V", "C": "F, F, F, V", "D": "F, V, F, V", "E": "V ,V ,V ,V"}, "g": "A", "j": "Sequencia V-V-F-V: a terceira afirmativa e falsa porque nao basta ao psicologo clinico ter conhecimento para realizar avaliacao no contexto do transito - a area exige formacao especifica."}, {"id": "773827", "d": "psicologia", "a": ["Psicologia do Trânsito"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando o trabalho de Rocha (2005), intitulado\n'Inovações tecnológicas aumentam a segurança no\ntrânsito?', assinale a alternativa incorreta.", "alt": {"A": "...A literatura sobre o trânsito é rica em variados\nassuntos, como por exemplo, a influência de bebidas e\ndrogas, velocidade, desobediência às leis,\ninfraestrutura, etc, que geralmente associam variáveis\nde forma a identificar causas e efeitos. Há um acervo\nrazoável sobre vários assuntos, como erros e violações,\npor exemplo, mas, por outro lado, falta maior\naprofundamento das questões sistêmicas e em torno\nde certos hábitos, práticas e mitos que as autoridades\nparecem negligenciar ou resistir em tratar de maneira\nmais racional, como é o caso da punição, aplicada\nindistintamente, a motoristas que violam\ndeliberadamente as regras de trânsito e àqueles que\nerram por diversos motivos, mas sem intenção de\ncometer infração...", "B": "...Wilde (2005) comenta que acidentes são associados\na tudo, desde deficiência de visão, problemas de\npressão barométrica, tendências antissociais, vias\nestreitas, álcool, idade, condições do tempo, estado\ncivil, etc.. Estes conhecimentos isolados são\ncertamente valiosos, mas poderiam ser mais úteis se\nfossem apreciados dentro de um sistema, onde seriam\nanalisadas causas e conseqüências associadas a outros\nproblemas...", "C": "...Estatísticas citadas por Wilde (2005, p. 106)\nmostram, por exemplo, correlação de - 0,68 entre taxa\nde desemprego e mortes no trânsito no período de\n1948-1987 nos Estados Unidos e correlação de - 0,88\nno período de 1968-1986, referente à Holanda,\nrelacionada aos mesmos fatores. A discrepância entre\nesses números indica a existência de vários problemas\nsubjacentes ao comportamento dos motoristas\ncausadores dos acidentes, o que sugere muito cuidado\nao se avaliar causas isoladas e imediatas, como bebida\ne briga de casal, por exemplo, que podem ser, em\núltima análise, conseqüências da falta de emprego...", "D": "...à primeira vista, atribuir à avaliação de riscos um\npapel preponderante na determinação do grau de\nsegurança no trânsito pode parecer uma proposição\ninconsequente ou inconsistente, porque pode sugerir\nalgum desprezo ou temor pelo avanço ou progresso\ntecnológico...", "E": "...e foi a partir do conceito de homeostase que Wilde\nnegligenciou a teoria de homeostase de risco para o\ntrânsito, na qual dispensa atenção especial ao\nchamado 'nível aceito de risco'. Dessa forma, o nível\naceito de risco é determinado por dois fatores da\nmotivação humana, que não se relacionam com a\nhomeostase proposta por ele: 1) custos existentes\nindependentemente dos riscos, pois o seguro do carro\né pago pelo dono de um veículo, independentemente\nde saber se estará certo ou errado na hora de um\nacidente; 2) benefícios esperados pela utilização do\nveículo automotor, pois essa utilização desperta no\nmotorista um sentimento de prazer que está acima,\ninconscientemente, do perigo oferecido para a\ncomunidade..."}, "g": "E", "j": "A alternativa E afirma que Wilde 'negligenciou' a teoria de homeostase de risco - na verdade ele a PROPOS, e nao a negligenciou."}, {"id": "773818", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Avaliação Psicológica", "Entrevista Psicológica e Técnicas de Entrevista", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "A Resolução nº 007/2009 do Conselho Federal de Psicologia\ninstitui normas e procedimentos para a avaliação\npsicológica no contexto Trânsito. Considerando-a, indique a\nalternativa correta.", "alt": {"A": "Os traços de personalidade avaliados devem ser, no\nmínimo, três, e o psicólogo responsável pela avaliação\npsicológica para CNH poderá considerar, dentre eles, a\nansiedade, a impulsividade, a psicopatia e a cognição.", "B": "O teste psicológico pode ser conceituado como uma\nmedida objetiva e padronizada de uma amostra do\ncomportamento do sujeito, tendo a função\nfundamental de classificar um candidato dentro de\ntabelas normativas específicas para a categoria de CNH\npretendida.", "C": "A entrevista psicológica deve ser utilizada em caráter\ninicial e faz parte do processo de avaliação psicológica.\nÉ durante esse procedimento que o psicólogo tem\ncondições de identificar situações que possam\ninterferir negativamente na avaliação psicológica,\npodendo o avaliador optar por não proceder à\ntestagem naquele momento para não prejudicar o\ncandidato.", "D": "Ao corrigir e avaliar um teste, o profissional deve seguir\nrigorosamente as normas apresentadas no manual,\nconsiderando também as resoluções específicas\npublicadas pelo CONTRAN. Para isso, o psicólogo deve\nmanter-se atualizado com relação às publicações\ncientíficas, testes novos disponíveis no mercado, novas\npesquisas e disposições legais do CONTRAN e DETRANS\ndo estado no qual é credenciado.", "E": "O laudo da avaliação psicológica deverá ser registrado\npelo psicólogo e arquivado junto aos protocolos dos\ntestes para, em seguida, ser emitido um resultado final\nem documento próprio. A conclusão do laudo não é a\nparte mais importante do processo avaliativo, mas ela\nnão pode deixar de ser considerada em hipótese\nalguma."}, "g": "C", "j": "A entrevista psicologica e utilizada em carater inicial no processo de avaliacao e permite identificar situacoes que possam interferir na testagem, autorizando o adiamento."}, {"id": "773817", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicologia do Trânsito", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "No trabalho 'Psicologia do trânsito ou avaliação psicológica\nno trânsito: faz-se distinção no Brasil?', são afirmações de\nRueda (2011):\n  I. ...devemos fazer um parêntese para deixar claro que\nfoi na década de 1980 que as dúvidas sobre o papel do\npsicólogo do trânsito, ou do psicólogo que realiza\navaliação psicológica no trânsito, ou ainda do\n\"psicólogo psicotecnista\", começaram a surgir não\napenas entre os colegas de profissão...\n  II. ...o importante mesmo foi saber que uma categoria\nque consegue se organizar para derrubar um veto\npresidencial, com certeza, consegue se organizar\ntambém para melhorar e argumentar contra todos\naqueles que criticam a prática profissional...   III. ...nosso diferencial está na interpretação que damos\npara o resultado do teste e na junção de todas as\ninformações provenientes dos diferentes instrumentos\ne procedimentos que o psicólogo tem para realizar\numa avaliação psicológica...\n  IV. ...nestes 60 anos de prática profissional: podemos concluir\nque existe a Psicologia do trânsito, ou o que realmente\nexiste é a avaliação psicológica no trânsito? Ou talvez\nambas? Ou até nenhuma? Podemos talvez pensar que o\nque existe é uma mera aplicação de testes psicológicos?\nSe for isso de fato, é feito por todos os psicólogos? Ou há\nmuitos que realizam um trabalho correto?....\n  V. ...O fato é que o SATEPSI existe porque, por ora, os\nprofissionais precisam desse norteador. A questão é:\npor que não nortear também o trabalho do psicólogo\ndo trânsito ou da avaliação psicológica no trânsito? Por\nque deixar que órgãos como DETRANs ou CONTRAN\ndeterminem como deve ser o trabalho do profissional\npsicólogo? Por que, em vez de nós, acadêmicos,\ncontinuarmos apontando problemas e críticas para a\nárea, não começamos a nos apropriar do que o\npsicólogo da área está precisando e começar também a\napresentar soluções?   Estão corretas:", "alt": {"A": "apenas I, II, III e IV.", "B": "apenas I, II, III e V.", "C": "apenas I, III, IV e V.", "D": "apenas II, III, IV e V.", "E": "todas."}, "g": "E", "j": "As cinco afirmacoes de Rueda (2011) refletem posicionamentos consistentes com o debate sobre Psicologia do Transito e Avaliacao Psicologica no Transito."}, {"id": "773811", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando o Código de Ética dos Psicólogos, é possível\nafirmar que:  I. Na sua atuação profissional, o psicólogo não deverá\nconsiderar as relações de poder nos contextos em que\natua e os impactos dessas relações sobre as suas\natividades, mas poderá se posicionar criticamente\nsempre que julgar necessário, mesmo que por vezes\ndeva desconsiderar o Código de Ética Profissional.\n  II. Mesmo participando de greves ou paralisações, o\npsicólogo deve garantir que as atividades de\nemergência não sejam paralisadas.  III. É dever fundamental aos psicólogos prestar serviços\nprofissionais em situações de calamidade pública ou de\nemergência, sem visar ao benefício pessoal.  \nIV. Ao psicólogo é vedado induzir a convicções de\norientação sexual quando do exercício de suas funções\nprofissionais.\n  V. É dever fundamental dos psicólogos estabelecer\nacordos de prestação de serviços que estejam\ncondizentes com as condições econômicas dos\nbeneficiários, bem como garantir o atendimento sem\nônus quando o usuário de serviço de psicologia não\npuder pagar pelo serviço, sob pena de cassação do seu\nRegistro Profissional.  Estão corretos:", "alt": {"A": "apenas I, II e III.", "B": "apenas I, III e IV.", "C": "apenas II, III e IV.", "D": "apenas II, III e V.", "E": "apenas III, IV e V."}, "g": "C", "j": "Estao corretas II (atividades de emergencia em greves), III (servicos em situacoes de calamidade) e IV (vedacao de induzir convicoes sobre orientacao sexual). I e V contradizem o CEP."}, {"id": "689001", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Considere as seguintes afirmações.\n1. Ato pelo qual se dá conhecimento ao representado da\nexistência de representação, bem como lhe dá\noportunidade de prestar esclarecimentos.\n2. Ato pelo qual se dá conhecimento ao psicólogo\nprocessado da instauração do processo disciplinar, bem\ncomo lhe concede a oportunidade de se defender no prazo\nque específica.\n3. Ato pelo qual se dá ciência a alguém dos atos e termos\nda representação ou do processo, para que faça ou deixe\nde fazer alguma coisa.\nOs conceitos acima, de acordo com o Código de\nProcessamento Disciplinar instituído pela Resolução CFP nº 06/2007, correspondem, respectivamente, a:", "alt": {"A": "Notificação; Citação; Intimação.", "B": "Intimação; Notificação; Citação.", "C": "Citação; Intimação; Notificação.", "D": "Notificação; Intimação; Citação.", "E": "Intimação; Citação; Notificação."}, "g": "A", "j": "Res CFP 006/2007 (Codigo de Processamento Disciplinar): 1=Notificacao (representado), 2=Citacao (psicologo processado) e 3=Intimacao (ciencia de atos)."}, {"id": "689000", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Os documentos escritos decorrentes de avaliação\npsicológica, bem como todo o material que os\nfundamentou, deverão ser guardados pelo prazo mínimo\nde _______, observando-se a responsabilidade por eles\ntanto do psicólogo quanto da instituição em que ocorreu a\navaliação psicológica.Assinale a alternativa que corretamente preenche a lacuna,\nde acordo com a Resolução CFP nº 7/2003.", "alt": {"A": "2 anos", "B": "1 ano", "C": "5 anos", "D": "6 meses", "E": "18 meses"}, "g": "C", "j": "A Res CFP 007/2003 estabelece o prazo minimo de 5 anos para guarda dos documentos escritos decorrentes de avaliacao psicologica."}, {"id": "688999", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Documento expedido pelo psicólogo que certifica uma\ndeterminada situação ou estado psicológico, tendo como\nfinalidade afirmar sobre as condições psicológicas de quem,\npor requerimento, o solicita, com fins de:- justificar faltas e/ou impedimentos do solicitante;\n- justificar estar apto ou não para atividades específicas,\napós realização de um processo de avaliação psicológica,\ndentro do rigor técnico e ético.De acordo com a Resolução CFP nº 7/2003, o conceito e\nfinalidades acima transcritos são relativos:", "alt": {"A": "Ao Atestado Psicológico.", "B": "À Declaração.", "C": "Ao Relatório Psicológico.", "D": "Ao Laudo Psicológico.", "E": "Ao Parecer."}, "g": "A", "j": "Res CFP 007/2003: o documento que certifica situacao/estado psicologico para justificar faltas e aptidao apos avaliacao psicologica e o Atestado Psicologico."}, {"id": "688998", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Assinale a alternativa que está em desacordo com o\ndisposto pela Resolução CFP nº 19/2000.", "alt": {"A": "A Secretaria de Orientação e Ética do CFP será\nconstituída pelo Secretário de Orientação e Ética, que a\npresidirá, e pelo menos mais dois membros, indicados\npelo Plenário, podendo ser conselheiros efetivos ou\nsuplentes ou psicólogos convidados.", "B": "Compete à Secretaria de Orientação e Ética apropriar-se\nda legislação interna e externa referente ao\nexercício profissional, bem como das diretrizes\ndefinidas pela autarquia para a área.", "C": "A Comissão de Orientação e Fiscalização dos CRPs será\nconstituída com, no mínimo, três membros indicados\npelo Plenário, presidida por um conselheiro efetivo,\npodendo os demais serem conselheiros, suplentes ou\npsicólogos convidados.", "D": "Antes de iniciarem a atividade de fiscalização, os fiscais\ndeverão ser submetidos a um processo de\ntreinamento, de caráter teórico e prático, visando ao\nconhecimento das leis e resoluções vigentes,\nreguladoras do exercício profissional, bem como das\ndiretrizes da Autarquia.", "E": "Os fiscais desenvolverão apenas atividades de\nfiscalização de acordo com as diretrizes e normas da\nautarquia, não lhes sendo atribuída função de\norientação."}, "g": "E", "j": "Res CFP 19/2000: os fiscais desenvolvem atividades de orientacao E fiscalizacao - a alternativa E e equivocada ao restringir suas funcoes apenas a fiscalizacao."}, {"id": "688997", "d": "psicologia", "a": ["Políticas Públicas no SUS", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Considere as seguintes afirmações.\nI. O conjunto de ações e serviços de saúde, prestados por\nórgãos e instituições públicas federais, estaduais e\nmunicipais, da Administração direta e indireta e das\nfundações mantidas pelo Poder Público, constitui o\nSistema Único de Saúde (SUS).\nII. As ações e serviços de saúde, executados pelo Sistema\nÚnico de Saúde (SUS), seja diretamente ou mediante\nparticipação complementar da iniciativa privada, serão\norganizados de forma regionalizada e hierarquizada em\nníveis de complexidade crescente.\nIII. Os serviços privados de assistência à saúde\ncaracterizam-se pela atuação, por iniciativa própria, de\nprofissionais liberais, legalmente habilitados, e de\npessoas jurídicas de direito privado na promoção,\nproteção e recuperação da saúde.De acordo com a Lei nº 8.080, pode-se afirmar que:", "alt": {"A": "somente I e II são corretas.", "B": "somente I e III são corretas.", "C": "somente II e III são corretas.", "D": "todas são incorretas.", "E": "todas são corretas."}, "g": "E", "j": "Lei 8.080/90: as tres afirmacoes refletem corretamente a estrutura do SUS e o papel dos servicos privados de assistencia a saude."}, {"id": "688996", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "O exercício do mandato de membro do Conselho Federal e\ndos Conselhos Regionais, assim como a respectiva eleição,\nmesmo na condição de suplente, ficarão subordinados ao\npreenchimento dos seguintes requisitos e condições\nbásicas, exceto:", "alt": {"A": "Cidadania brasileira.", "B": "Inscrição principal na jurisdição do Conselho Regional\nrespectivo há mais de 2 (dois) anos.", "C": "Pleno gozo dos direitos profissionais, civis e políticos.", "D": "Inexistência de qualquer condenação em virtude de\nsentença mesmo que ainda não transitada em julgado.", "E": "Inexistência de penalidade por infração ao Código de\nÉtica."}, "g": "D", "j": "A exigencia legal e a inexistencia de condenacao em virtude de sentenca TRANSITADA EM JULGADO - a alternativa D distorce ao incluir condenacoes ainda nao transitadas."}, {"id": "688995", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "O patrimônio dos Conselhos Regionais será constituído de:\nI. doações e legados;\nII. dotações orçamentárias do Poder Público Federal,\nEstadual ou Municipal;\nIII. bens e valores adquiridos;\nIV. ________das anuidades, taxas, emolumentos e multas\narrecadadas.\nAssinale a alternativa que corretamente completa a lacuna.", "alt": {"A": "1/4(um quarto)", "B": "2/3 (dois terços)", "C": "1/2 (metade)", "D": "1/5 (um quinto)", "E": "3/4 (três quartos)"}, "g": "B", "j": "O patrimonio dos CRPs e constituido por 2/3 (dois tercos) das anuidades, taxas, emolumentos e multas arrecadadas."}, {"id": "688994", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Sob o prisma da Lei nº 5.766, constituem infrações\ndisciplinares as abaixo descritas, exceto:", "alt": {"A": "Solicitar ou receber de cliente qualquer favor em troca\nde concessões, ainda que lícitas.", "B": "Não cumprir no prazo estabelecido, determinação\nemanada do órgão ou autoridade dos Conselhos, em\nmatéria da competência destes, depois de\nregularmente notificado.", "C": "Exercer a profissão quando impedido de fazê-lo, ou\nfacilitar, por qualquer meio, o seu exercício aos não\ninscritos ou impedidos.", "D": "Praticar, no exercício da atividade profissional, ato que\na lei defina como crime ou contravenção.", "E": "Deixar de pagar aos Conselhos, pontualmente, as\ncontribuições a que esteja obrigado."}, "g": "A", "j": "A Lei 5.766/71 tipifica como infracao receber favor em troca de concessoes ILICITAS - a alternativa A, ao falar em 'licitas', contraria o texto legal."}, {"id": "688993", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Considere as seguintes funções.\nI. Elaborar e aprovar o Código de Ética Profissional do\nPsicólogo.\nII. Orientar, disciplinar e fiscalizar o exercício da profissão\nde Psicólogo.\nIII. Funcionar como tribunal superior de ética profissional.\nDe acordo com a Lei nº 5.766, as funções competem,\nrespectivamente:", "alt": {"A": "Ao Conselho Federal de Psicologia; ao Conselho\nFederal de Psicologia; ao Conselho Federal de\nPsicologia.", "B": "Ao Conselho Federal de Psicologia; ao Conselho\nFederal de Psicologia; aos Conselhos Regionais de\nPsicologia.", "C": "Aos Conselhos Regionais de Psicologia; aos Conselhos\nRegionais de Psicologia; aos Conselhos Regionais de\nPsicologia.", "D": "Aos Conselhos Regionais de Psicologia; ao Conselho\nFederal de Psicologia; aos Conselhos Regionais de\nPsicologia.", "E": "Aos Conselhos Regionais de Psicologia; aos Conselhos\nRegionais de Psicologia; ao Conselho Federal de\nPsicologia."}, "g": "A", "j": "Lei 5.766/71: elaborar o Codigo de Etica, orientar e fiscalizar o exercicio da profissao e funcionar como tribunal superior de etica sao todas competencias do CFP."}, {"id": "603926", "d": "psicologia", "a": ["Clima e Cultura Organizacional na Psicologia", "Qualidade de Vida", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia as seguintes afirmações:I. A satisfação no trabalho indica o julgamento avaliativo\nindividualizado (positivo ou negativo) que o\ntrabalhador faz de seu trabalho ou ambiente e situação\nde trabalho.\nII. Não há distinção claramente identificável entre clima\norganizacional e satisfação no trabalho. III. A cultura organizacional é baseada, somente, nos\nvalores de seus líderes e dirigentes.\nEstá correto o que se afirma em:", "alt": {"A": "todas as afirmações.", "B": "apenas duas das afirmações, incluindo a I.", "C": "apenas duas das afirmações, incluindo a II.", "D": "apenas uma das afirmações.", "E": "nenhuma das afirmações."}, "g": "D", "j": "Apenas I e correta. II e errada pois ha distincao entre clima e satisfacao. III e errada pois a cultura nao depende apenas dos valores dos lideres."}, {"id": "603925", "d": "psicologia", "a": ["Psicologia Organizacional", "Gestão de Pessoas", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa correta.", "alt": {"A": "O desemprego não é um fenômeno que deve ser\nobjeto de estudo e intervenção da Psicologia\nOrganizacional e do Trabalho.", "B": "A situação de desemprego representa importante fator\nde risco para a saúde mental dos trabalhadores.", "C": "O impacto do desemprego nos processos de gestão de\npessoas numa organização é nulo.", "D": "O desemprego não se constitui numa situação\ngeradora de adoecimento.", "E": "O desemprego não deve ser estudado pela Psicologia\nOrganizacional e do Trabalho, pois os índices de\ndesemprego no Brasil estão baixos."}, "g": "B", "j": "A literatura em POT confirma o desemprego como importante fator de risco para a saude mental dos trabalhadores."}, {"id": "603924", "d": "psicologia", "a": ["Gestão por Competências", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "O modelo das competências tem afetado significativamente\nos processos de gestão de pessoas nas empresas, assim\ncomo o modelo da qualificação o fez durante quase todo o\nséculo XX. É incorreto afirmar que:", "alt": {"A": "Houve uma incorporação do modelo das competências\nnas empresas por conta da adoção de padrões mais\nflexíveis de produção.", "B": "Tanto a qualificação quanto as competências objetivam\nfornecer bases para a organização das funções do\ntrabalho e dos processos de treinamento,\ndesenvolvimento e educação.", "C": "Competência pode ser definida como um conjunto de\nsaberes mobilizados em situação de trabalho.", "D": "Apesar de a utilização do modelo das competências ser\nrecente nas empresas, o conceito de competência é\nantigo.", "E": "O modelo das competências prescinde da qualificação."}, "g": "E", "j": "O modelo das competencias NAO prescinde da qualificacao - integra-se a ela. A alternativa E e incorreta."}, {"id": "603923", "d": "psicologia", "a": ["Conflito nas Organizações", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Sobre a afirmação reproduzida abaixo, e baseada na\natuação profissional dos psicólogos nas empresas, assinale\na alternativa correta.Conflitos são inerentes às relações humanas, embora eles\ndevam ser evitados através da utilização de estratégias\npsicológicas.\nPrimeira parte - Conflitos são inerentes às relações\nhumanas. Segunda parte - Conflitos devem ser evitados através da\nutilização de estratégias psicológicas.", "alt": {"A": "A afirmação é parcialmente verdadeira, pois a primeira\nparte está correta, mas a segunda não.", "B": "A afirmação é parcialmente verdadeira, pois a primeira\nparte da frase não está correta, mas a segunda parte\nestá.", "C": "A afirmação é totalmente verdadeira.", "D": "A afirmação é totalmente falsa, pois estratégias\npsicológicas não são bem aceitas nesse contexto.", "E": "A afirmação é totalmente falsa, pois conflitos não são\nfenômenos sobre os quais a psicologia deva intervir."}, "g": "A", "j": "A primeira parte e verdadeira (conflitos sao inerentes), a segunda e falsa (conflitos nao devem ser apenas evitados, mas gerenciados)."}, {"id": "603922", "d": "psicologia", "a": ["Organizações na Psicologia", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a única alternativa incorreta com relação ao\ncooperativismo.", "alt": {"A": "As cooperativas são organizações do trabalho que,\ndentre outras atividades, são voltadas ao crédito, aos\nserviços e à produção.", "B": "As cooperativas de trabalho seriam as que vendem o\nproduto do trabalho dos membros.", "C": "As assembleias são os espaços formais de tomada de\ndecisão em cooperativas de trabalho.", "D": "As cooperativas são uma boa alternativa jurídica para a\nredução de encargos trabalhistas na contratação e\nmanutenção dos funcionários de uma organização.", "E": "As cooperativas são organizações de trabalho onde há\nsócio-trabalhadores, não empregados assalariados."}, "g": "D", "j": "As cooperativas nao sao uma alternativa juridica para reducao de encargos trabalhistas, sob pena de configurar fraude trabalhista (cooperativismo precario)."}, {"id": "603920", "d": "psicologia", "a": ["Gestão de Pessoas", "Políticas Públicas - Pessoas com Deficiência", "Psicologia e Organizações", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa correta com relação a aspectos\nimportantes a serem considerados para um programa de\ngestão da diversidade nas empresas.", "alt": {"A": "Segundo a OMS (Organização Mundial da Saúde),\ndeficiência, incapacidade e desvantagem são termos\nequivalentes com relação ao seu significado.", "B": "A acessibilidade de locomoção é a única estratégia\nnecessária para um programa de gestão da diversidade\nsignificativo.", "C": "Segundo a OMS (Organização Mundial da Saúde), a\ndeficiência pode ser definida como uma limitação\nfuncional orgânica, que pode gerar incapacidades e\ndesvantagens sociais.", "D": "Segundo a OMS (Organização Mundial da Saúde), a\ndeficiência é definida como conjunto de dificuldades\nadaptativas e relacionais, gerando incapacidades e\ndesvantagens sociais.", "E": "A deficiência não carrega em si a possibilidade de gerar\num estigma, por isso um programa de gestão da\ndiversidade significativo não deve levar em conta esta\nquestão."}, "g": "C", "j": "OMS: a deficiencia e uma limitacao funcional organica que pode gerar incapacidades e desvantagens sociais."}, {"id": "603919", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa incorreta com relação à competência\nprofissional do psicólogo em TD&E (Treinamento,\nDesenvolvimento e Educação).", "alt": {"A": "Análise organizacional e de tarefas.", "B": "Atuação exclusivamente técnica.", "C": "Análise e interpretação de dados de avaliação.", "D": "Gestão de pessoas com qualificações diversificadas.", "E": "Elaboração ou seleção de estratégias instrucionais."}, "g": "B", "j": "A atuacao do psicologo em TD&E nao e exclusivamente tecnica - exige competencias relacionais, gerenciais e politicas alem das tecnicas."}, {"id": "603918", "d": "psicologia", "a": ["Análise do Trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Com relação ao processo de \"análise do trabalho\", François\nGuérin e colaboradores (2001, p. 15), autores do campo da\nErgonomia, afirmam que:\n\"A distância entre o ______ e o _______é a manifestação\nconcreta da contradição sempre presente no ato de\ntrabalho, entre 'o que é pedido' e 'o que a coisa pede'. A\nanálise ergonômica da ______ é a análise das estratégias\nusadas pelo operador para administrar essa distância, ou\nseja, a análise do ______ \".\nPreencha as lacunas e assinale a alternativa que melhor\nreproduz a afirmação original de Guérin e colaboradores.", "alt": {"A": "real, prescrito, atividade, sistema homem/tarefa", "B": "prescrito, trabalho, tarefa, cargo", "C": "real, prescrito, tarefa, trabalho", "D": "prescrito, real, tarefa, sistema homem/tarefa", "E": "prescrito, real, atividade, sistema homem/tarefa"}, "g": "E", "j": "Guerin e colaboradores (2001): a distancia entre prescrito e real e a manifestacao do conflito 'pedido x coisa pede'; a analise ergonomica da atividade e a analise do sistema homem/tarefa."}, {"id": "603917", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa correta com relação às práticas do\npsicólogo organizacional e do trabalho.", "alt": {"A": "Acontecem apenas no interior das empresas.", "B": "Há um movimento de mudança gradativa, ainda em\nprocesso, de um foco de intervenção no indivíduo para\num foco de intervenção sobre as questões\norganizacionais mais amplas.", "C": "Instituições como uma escola, um hospital ou um\npresídio não têm espaço para as práticas do psicólogo\norganizacional e do trabalho.", "D": "Programas de qualidade de vida não entram no escopo de\nintervenção do psicólogo organizacional e do trabalho.", "E": "O nível estratégico deve ser o nível exclusivo de\nintervenção dos administradores, não sendo função do\npsicólogo organizacional e do trabalho contribuir na\nformulação de políticas para as ações organizacionais."}, "g": "B", "j": "A alternativa B mistura as definicoes de Saude Ocupacional e Saude do Trabalhador, tornando-se a incorreta."}, {"id": "603916", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa incorreta com relação às concepções\nde segurança no trabalho e saúde ocupacional,\nrepresentadas pelos campos da Medicina do Trabalho, da\nSaúde Ocupacional e da Saúde do Trabalhador.", "alt": {"A": "A Medicina do Trabalho tem os trabalhadores como\nseu principal foco de intervenção e objetiva garantir o\nmais elevado nível de bem-estar físico e mental dos\nmesmos, enquanto que a Saúde Ocupacional tem\ncaráter multiprofissional e visa a atuar sobre o\nambiente organizacional com a finalidade de controlar\npossíveis riscos ambientais.", "B": "A Saúde Ocupacional busca intervir na relação saúde-trabalho\npor meio da compreensão dos processos, da\norganização e das condições de trabalho, enfatizando a\nimportância da participação dos próprios\ntrabalhadores na concepção e intervenção das relações\nsaúde-trabalho, enquanto que a Saúde do Trabalhador\ntem caráter multiprofissional e visa a atuar sobre o\nambiente organizacional com a finalidade de controlar\npossíveis riscos ambientais.", "C": "A Medicina do Trabalho tem os trabalhadores como\nseu principal foco de intervenção e objetiva garantir o\nmais elevado nível de bem-estar físico e mental dos\nmesmos, enquanto que a Saúde do Trabalhador busca\nintervir na relação saúde-trabalho por meio da\ncompreensão dos processos, da organização e das\ncondições de trabalho, enfatizando a importância da\nparticipação dos próprios trabalhadores na concepção\ne intervenção das relações saúde-trabalho.", "D": "A Saúde do Trabalhador busca intervir na relação\nsaúde-trabalho por meio da compreensão dos\nprocessos, da organização e das condições de trabalho,\nenfatizando a importância da participação dos próprios\ntrabalhadores na concepção e intervenção das relações\nsaúde-trabalho, enquanto que a Saúde Ocupacional\ntem caráter multiprofissional e visa a atuar sobre o\nambiente organizacional com a finalidade de controlar\npossíveis riscos ambientais.", "E": "A Medicina do Trabalho promove intervenções nos\ntrabalhadores, a Saúde Ocupacional nos ambientes de\ntrabalho e a Saúde do Trabalhador nas relações entre\ntrabalhadores e processos e organização do trabalho."}, "g": "B", "j": "A POT vive uma mudanca gradativa do foco de intervencao individual para questoes organizacionais mais amplas."}, {"id": "603915", "d": "psicologia", "a": ["Clima e Cultura Organizacional na Psicologia", "Qualidade de Vida", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia as seguintes afirmações:\nI. A cultura organizacional indica o padrão de referência\n(sistema de normas e valores) criado pelo grupo de\ntrabalhadores que influencia seu modo de perceber,\npensar e sentir, dando origem às políticas e às\natividades da organização e seus modos de ação,\ncomunicação e decisão.\nII. O clima organizacional indica as influências do\nambiente interno de trabalho sobre o comportamento\nhumano, refletindo a dinâmica da vida organizacional.\nIII. A satisfação no trabalho indica o julgamento avaliativo\nindividualizado (positivo ou negativo) que o\ntrabalhador faz de seu trabalho ou ambiente e situação\nde trabalho.\nIV. O poder organizacional é um fator independente da\ndinâmica organizacional que não guarda relação com a\ncultura, o clima e a satisfação organizacionais.\nEstá correto o que se afirma em:", "alt": {"A": "I, II e IV, somente.", "B": "II e III, somente.", "C": "I, II e III, somente.", "D": "I e II, somente.", "E": "todas."}, "g": "C", "j": "Estao corretas I (cultura), II (clima) e III (satisfacao). IV e falsa pois poder organizacional NAO e independente da dinamica organizacional."}, {"id": "603914", "d": "psicologia", "a": ["Dinâmicas de Grupo", "Grupos e Equipes"], "ano": "2012", "org": "CFP", "t": "", "e": "Uma das práticas mais demandadas ao profissional da\nPsicologia Organizacional e do Trabalho é a realização de\ndinâmicas de grupo, principalmente para soluções de\nproblemas de conflitos interpessoais, desmotivação e\naumento de produtividade.\nI. Os manuais de técnicas de dinâmica de grupo se\nconstituem na única e principal fonte de referência\npara os psicólogos que trabalham com grupos\n                                           POR ISSO\nII. deve-se sempre aplicar as técnicas de dinâmica de\ngrupo da forma como estão lá descritas independente\ndo contexto organizacional.\nAssinale a resposta correta sobre as duas afirmações.", "alt": {"A": "A primeira é falsa e a segunda, verdadeira.", "B": "As duas afirmações são verdadeiras e a segunda não\njustifica a primeira.", "C": "As duas afirmações são verdadeiras e a segunda\njustifica a primeira.", "D": "As duas são falsas.", "E": "Apenas uma delas é falsa, embora justifique a outra."}, "g": "D", "j": "Ambas as afirmacoes sao falsas - os manuais nao sao a unica fonte e as tecnicas devem ser adaptadas ao contexto, nao aplicadas de forma rigida."}, {"id": "603913", "d": "psicologia", "a": ["Recrutamento e Seleção", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa correta com relação às práticas de\nrecrutamento, seleção de pessoal e desligamento.", "alt": {"A": "Os testes psicológicos continuam sendo os\ninstrumentos mais utilizados nos processos de\nrecrutamento e seleção.", "B": "A terceirização dos processos de recrutamento e seleção é um movimento ainda incipiente nas\nempresas.", "C": "As transformações organizacionais e a demanda de um\nnovo perfil de trabalhador têm gerado inovações no\nprocesso de seleção.", "D": "O psicólogo não pode realizar mais os processos de\nrecrutamento e seleção que agora são atribuição de\noutros profissionais.", "E": "Em função de um contexto atual de poucas mudanças\norganizacionais, os processos de recrutamento e\nseleção têm diminuído em intensidade, gerando,\ninclusive, um fechamento gradativo de consultorias\nespecializadas."}, "g": "C", "j": "As transformacoes organizacionais e a demanda de um novo perfil de trabalhador tem gerado inovacoes nos processos de selecao de pessoal."}, {"id": "603912", "d": "psicologia", "a": ["Liderança", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Segundo Tamayo e Porto (2005), \"podemos afirmar que o\nprotótipo de líder ideal é dependente da cultura\" (p. 197).\nQue argumento não justificaria tal afirmação?", "alt": {"A": "Pessoas de diferentes ambientes sociais irão endossar\ndiferentes valores.", "B": "Os fatores situacionais são fundamentais, embora os\ntraços de personalidade sejam mais determinantes\npara a definição de um líder ideal.", "C": "Os modelos de liderança são adaptações culturais.", "D": "Modelos culturais distintos são preditores dos estilos\nde liderança predominantes.", "E": "Culturas mais igualitárias costumam aceitar mais a\nliderança participativa como eficaz."}, "g": "B", "j": "O argumento B (tracos de personalidade serem mais determinantes que fatores situacionais) e universalista e nao justifica a dependencia cultural do prototipo de lider ideal."}, {"id": "603911", "d": "psicologia", "a": ["Análise do Trabalho", "Ergonomia na Psicologia", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia as seguintes afirmações\nI. Resultado antecipado fixado em condições\ndeterminadas.\nII. Realização da tarefa. III. Unidade da atividade de trabalho, das condições reais\ne dos resultados efetivos.\nOs itens I, II e III correspondem a três realidades postuladas\npela Ergonomia para análise do trabalho. Faça a correlação\nentre as realidades descritas e as conceituações\ncorrespondentes propostas pela Ergonomia.", "alt": {"A": "Tarefa, atividade de trabalho, trabalho.", "B": "Atividade de trabalho, tarefa, trabalho.", "C": "Trabalho prescrito, trabalho real, tarefa.", "D": "Tarefa, trabalho prescrito, função desempenhada.", "E": "Trabalho real, atividade de trabalho, função\ndesempenhada."}, "g": "A", "j": "Ergonomia: I (resultado antecipado fixado)=Tarefa; II (realizacao da tarefa)=Atividade de trabalho; III (unidade da atividade, condicoes reais e resultados)=Trabalho."}, {"id": "603909", "d": "psicologia", "a": ["Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa que não indique aspectos relevantes\nrelativos à cognição organizacional para a atuação\nprofissional do psicólogo, especificamente voltada à gestão\nde pessoas nas empresas.", "alt": {"A": "Os estudos cognitivos permitem afirmar que o\nindivíduo não se constitui em passivo seguidor de\nregras e princípios definidos externamente.", "B": "Os estudos cognitivos recolocaram as pessoas e os seus\nprocessos psicológicos no centro das atenções dos\nestudos organizacionais.", "C": "Os estudos cognitivos ressaltam a importância do\nengajamento e da participação das pessoas nos\nprocessos de tomada de decisão concernentes a si\npróprios.", "D": "Os estudos cognitivos permitem apontar a\nimpossibilidade de implementação de ideais de\nhomogeneidade, como preconizam, por exemplo, os\nmodelos burocráticos de organização do trabalho.", "E": "Os estudos cognitivos permitem a organização de\nregras sobre como gerenciar cognições no trabalho,\ntão importantes para a prática profissional do\npsicólogo."}, "g": "E", "j": "Os estudos cognitivos nao permitem a producao de regras universais de gerenciamento de cognicoes - a alternativa E contraria a perspectiva nao prescritiva da abordagem cognitiva."}, {"id": "603908", "d": "psicologia", "a": ["Psicologia Organizacional", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicologia e Organizações", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Uma das questões centrais da atuação profissional do\npsicólogo no campo das organizações se define pelas\nimplicações éticas da realização do seu trabalho. Algumas\nde suas ações no contexto das empresas ferem direta ou\nindiretamente o Código de Ética Profissional do psicólogo.\nDentre elas, pode-se citar:", "alt": {"A": "O tecnicismo e a crença na neutralidade da atuação do\npsicólogo.", "B": "Uma visão estratégica da atuação profissional do\npsicólogo nas empresas.", "C": "O diálogo multidisciplinar com os vários atores\norganizacionais.", "D": "A compreensão de que a atuação profissional do\npsicólogo envolve vários âmbitos de análise e\nintervenção.", "E": "A consciência de que a atuação profissional do\npsicólogo tem limites de ação."}, "g": "A", "j": "O tecnicismo e a crenca na neutralidade da atuacao do psicologo nas empresas ferem o CEP, ao desconsiderarem dimensoes politicas e eticas da pratica profissional."}, {"id": "603907", "d": "psicologia", "a": ["Treinamento e Desenvolvimento", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Muitos profissionais que trabalham na área de gestão de\npessoas em empresas não são capazes de distinguir as\nconcepções e ações de desenvolvimento, educação,\ntreinamento, instrução e informação, gerando, muitas\nvezes, esforços que não irão atingir a meta determinada,\nem função dessa confusão conceituai. Com relação aos\nprocessos de desenvolvimento, educação, treinamento,\ninstrução e informação nas empresas, é correto afirmar\nque:", "alt": {"A": "A instrução e a informação são as formas mais amplas\ne complexas de aprendizagem nas organizações.", "B": "O treinamento é determinado por cursos de longa\nduração realizados na própria empresa, com caráter de\nprofissionalização e formação.", "C": "O desenvolvimento pode ser definido como um\nprocesso de aprendizagem mais geral que visa ao\ncrescimento e ao amadurecimento das pessoas de\nforma ampla, sem uma vinculação direta com o cargo\ndesempenhado.", "D": "Desenvolvimento, educação, treinamento, instrução e\ninformação são processos similares que, na prática,\ndefinem formas e tipos semelhantes de ação, sem uma\ndiferenciação clara entre eles.", "E": "Em termos de abrangência dos processos acima\nindicados, pode-se afirmar que o treinamento é o nível\nmais complexo e a instrução o nível mais simples."}, "g": "C", "j": "O desenvolvimento e um processo de aprendizagem amplo voltado ao crescimento e amadurecimento das pessoas, sem vinculacao direta com o cargo desempenhado."}, {"id": "603906", "d": "psicologia", "a": ["Psicologia Organizacional", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "A reconfiguração das práticas do psicólogo organizacional e\ndo trabalho permite concluir que as atividades tradicionais,\nembora continuem sendo desempenhadas, sofreram\nimportantes transições em função do desenvolvimento\ncientífico e das transformações nos contextos de trabalho.\nDentre os movimentos inovadores da área e que ampliam\nas propostas de intervenção, podemos destacar o seguinte:", "alt": {"A": "O conhecimento e a aprendizagem são fatores de\ncompetitividade, assim as ações de treinamento são\ndesenvolvidas com foco no desenvolvimento\norganizacional e na tecnologia do desempenho.", "B": "Do foco no indivíduo há um movimento consistente\npara entender e intervir sobre questões de\ndesenvolvimento gerencial, utilizando técnicas para\neliminar conflitos.", "C": "As ações com foco nas relações de trabalho e as\nmudanças organizacionais se apresentam como\ndesafios, pois dependem dos advogados e\nadministradores.", "D": "O plano da formulação de políticas para as ações\norganizacionais baseado nas aptidões, habilidades,\ncompetências e processos psicossociais básicos.", "E": "Reconhecimento de que a pesquisa é uma prática\nindispensável para fundamentar as intervenções\norganizacionais. Além de propiciar o conhecimento da\nrealidade, funciona como estratégia de participação\ndos empregados."}, "g": "E", "j": "O reconhecimento da pesquisa como pratica indispensavel para fundamentar intervencoes organizacionais e estrategia de participacao dos empregados e movimento inovador da POT."}, {"id": "603905", "d": "psicologia", "a": ["Psicologia do Trabalho", "Gestão de Pessoas", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "A saída do mundo do trabalho quando da aposentadoria\nimplica diversas mudanças na vida do sujeito, pois\nrepresenta, ao mesmo tempo, a perda do lugar no sistema\nde produção, a necessidade de reorganização espacial e\ntemporal (tempo e lugar de trabalho e tempo e lugar não\ntrabalho) e de reestruturação da identidade. A orientação\npsicológica para a aposentadoria indica a necessidade de:", "alt": {"A": "Acompanhamento de carreira realizado durante toda a\nvida dos sujeitos, pois a aposentadoria é acompanhada\nde perdas de estratégias devido ao afastamento de\ncomportamentos habituais e perdas de poder e\nreconhecimento; e perdas da identidade\nsocioprofissional.", "B": "Atividades recreativas, já que a aposentadoria tende a\nser acompanhada por valores negativos como\ninutilidade, incapacidade e envelhecimento.", "C": "Treinamentos para elaboração do luto para lidar com\nperdas e com o conflito de sentir-se produtivo e capaz\ne, por outro lado, com o estigma da não ação cobrado\npela sociedade, onde o aposentado é aquele que não\nprecisa fazer nada.", "D": "Atendimento psicológico para lidar com os limites\nimpostos pelo corpo e pelo processo de exclusão do\nmundo do trabalho.", "E": "Avaliação do mercado de trabalho, pois o aposentado é\nquem não possui mais utilidade para a manutenção do\nsistema produtivo."}, "g": "A", "j": "A orientacao psicologica para a aposentadoria exige acompanhamento de carreira durante toda a vida, dadas as perdas de estrategias, poder, reconhecimento e identidade socioprofissional."}, {"id": "603904", "d": "psicologia", "a": ["Organizações na Psicologia", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "As organizações são sistemas com múltiplos níveis de\ncomplexidades e âmbitos de abrangência. Quaisquer\nresultados podem ser examinados e avaliados como\nafetados por características e processos que ocorrem em\nquatro âmbitos:", "alt": {"A": "Âmbito micro-organizacional, equivalente aos âmbitos\nindividual e grupai, na academia e na economia.", "B": "Individual, grupai, organizacional e contextual ou\nambiental, sendo este último considerado a área que\ninclui os estudos sobre as mudanças tecnológicas,\npolíticas, sociais, culturais e econômicas.", "C": "O ambiente, a organização, as equipes e as pessoas,\ncom ênfase no papel do indivíduo e sua história\nparticular.", "D": "Emergem os processos micro-organizacionais (pessoas\ne equipes) que, por sua vez, constituem o contexto que\nconfigura e afeta os processos estruturais e\nempresariais.", "E": "Aprendizagem, motivação, liderança e comportamento\nintergrupal passam a ser vistos como indispensáveis\npara a compreensão dos processos organizacionais."}, "g": "B", "j": "Os quatro ambitos de analise organizacional sao: individual, grupal, organizacional e contextual/ambiental (com estudos sobre mudancas tecnologicas, politicas, sociais, culturais e economicas)."}, {"id": "603903", "d": "psicologia", "a": ["Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "A identidade tem sido apresentada como um conceito\ndinâmico, adotado frequentemente para compreender a\ninserção do sujeito no mundo e sua relação com o outro. O\natual contexto do mundo do trabalho contribui de forma\ndecisiva para a fragmentação dos sujeitos e, desse modo,\ntende a reforçar a fragilidade e a condição provisória da\nidentidade. Dentre as alternativas a seguir, assinale a que\napresenta as repercussões da precarização do trabalho na\nidentidade profissional.", "alt": {"A": "As mudanças no mundo do trabalho afetaram a forma\nde ser da classe trabalhadora, tornando-a mais\nmobilizada para permanecer no emprego e continuar\nna atividade profissional e/ou empresa escolhida.", "B": "O trabalho apresenta as características como\nprecariedade e fragmentação, impondo dificuldades\npara que se processem as identificações por seu\nintermédio, mas favorecendo empregabilidade do\ntrabalhador.", "C": "A concepção do trabalho como um elemento\nimprescindível para a construção da identidade do\nsujeito é inegável quando há emprego para a classe\ntrabalhadora.", "D": "Nas situações de demissão, o trabalhador deixa de\npertencer a um grupo determinado de profissionais,\numa vez que se desvincula da rotina diária do seu\ntrabalho e perde seu lugar e sua condição de\ntrabalhador daquela empresa específica.", "E": "As novas configurações de tempo e espaço vêm\nafetando cada vez mais os diversos contextos\nprodutivos, diminuindo as jornadas de trabalho."}, "g": "D", "j": "Em situacoes de demissao, o trabalhador deixa de pertencer ao grupo profissional especifico, desvincula-se da rotina e perde seu lugar na empresa, fragilizando a identidade."}, {"id": "603901", "d": "psicologia", "a": ["Assédio Moral", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Os estudos sobre o assédio moral no trabalho referem a\nperda precoce da capacidade de trabalho em determinados\ncontextos organizacionais. Qual, das seguintes alternativas,\nmelhor descreve o terreno fértil para o surgimento do\nassédio moral?", "alt": {"A": "Onipotência da empresa e vigilância constante dos\ntrabalhadores, dos gerentes e supervisores.", "B": "Orientações e treinamentos aos gerentes e\nfuncionários por meio da educação e da informação.", "C": "Comportamentos agressivos e impulsivos da vítima\nmostrando desequilíbrio e perturbando o trabalho dos\ncolegas.", "D": "Cultura e clima permissivo da organização, com\ndesconfiança e competição exacerbada;\nsupervalorização das estruturas hierárquicas;\nprocessos de reestruturação organizacional sem\ntransparência e com ameaças generalizadas;\ndesumanização das relações de trabalho.", "E": "Chefias, o assédio é vertical descendente, sendo a\nhierarquia um elemento inibidor da ação comunicativa."}, "g": "D", "j": "O terreno fertil para o assedio moral envolve cultura/clima permissivos, competicao exacerbada, hierarquia rigida, reestruturacao sem transparencia e desumanizacao das relacoes."}, {"id": "603899", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "As doenças relacionadas ao trabalho vêm se tornando mais\nincidentes num mundo cada vez mais industrializado. Para\nreconhecer e diagnosticar essas doenças diversos autores\napontam a necessidade de perguntar ao\npaciente/trabalhador: qual é a sua ocupação? A questão da\nsaúde do trabalhador tem permitido evidenciar que:", "alt": {"A": "Quando não são tomadas medidas de controle, os\nfatores de risco podem levar a comprometimentos\npara o trabalhador, como as doenças próprias de cada\nexposição.", "B": "A análise das condições de trabalho se faz necessária\nfrente ao acentuado aumento dos benefícios pagos por\ndoenças do trabalho.", "C": "A insatisfação com o conteúdo do trabalho se\nmanifesta nos transtornos mentais.", "D": "As implicações sobre a saúde dos trabalhadores têm\nforte associação com os programas de qualidade de\nvida no trabalho.", "E": "As investigações sobre as doenças relacionadas ao\ntrabalho são recentes e têm grande aceitação."}, "g": "A", "j": "Quando nao sao tomadas medidas de controle, os fatores de risco ocupacionais podem levar a comprometimentos a saude do trabalhador, com doencas proprias de cada exposicao."}, {"id": "603898", "d": "psicologia", "a": ["Análise do Trabalho", "Ergonomia na Psicologia", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "O analista do trabalho sempre se confronta com a\nsingularidade de uma pessoa que, no ato profissional,\nmanifesta sua vida pessoal e social. A dimensão pessoal do\ntrabalho se expressa concretamente nas estratégias usadas\npelos operadores para realizar sua tarefa. Estas são objeto\nreal da análise ergonômica da atividade. Das alternativas a\nseguir, assinale a que melhor define tarefa e atividade.", "alt": {"A": "Tarefa é um conjunto de prescrições e refere-se à\nnecessidade de estabelecer métodos de gestão,\nenquanto a atividade de trabalho é um elemento\ncentral que organiza e estrutura os componentes da\nsituação de trabalho.", "B": "O trabalho prescrito é sempre relativo a um tempo\nmédio socialmente necessário e a atividade de\ntrabalho é o resultado socialmente aceitável.", "C": "A atividade é um princípio que impõe um modo de\ndefinição do trabalho em relação ao tempo, já a tarefa\nidentifica as características da situação de trabalho que\norienta a maneira pela qual o trabalhador realiza o\ntrabalho.", "D": "A dimensão pessoal das condições de trabalho ganha\nsentido em função do itinerário profissional do\ntrabalhador e de sua experiência, portanto a tarefa\nleva em conta as particularidades dos operados e o que\neles pensam sobre as escolha feitas ou impostas.", "E": "Atividade é conjunto de objetivos e prescrições\ndefinidos exteriormente ao trabalhador, enquanto a\ntarefa é a maneira como o trabalhador alcança os\nobjetivos que lhe foram designados."}, "g": "A", "j": "Tarefa = conjunto de prescricoes que define metodos de gestao; Atividade = elemento central que organiza e estrutura os componentes da situacao de trabalho."}, {"id": "603897", "d": "psicologia", "a": ["Ergonomia na Psicologia", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "A ação ergonômica decorre, geralmente, de uma demanda\ne o trabalho de análise e reformulação da demanda\nrepresenta um aspecto essencial da condução do processo.\nOs problemas expressos na demanda refletem em geral\nsomente uma parte dos que se relacionam à situação de\ntrabalho. Desse modo, a análise da demanda deverá\nconsiderar:", "alt": {"A": "os problemas pontuais e circunscritos à formulação\ninicial da queixa.", "B": "qualquer que seja o nível de explicitação da demanda\ndeve-se evitar discernir elementos implícitos e analisar\nos problemas expressos.", "C": "a demanda apresentada por diferentes interlocutores\nevidencia que não há responsáveis pela demanda,\nportanto não poderá ser apresentada uma proposta de\nação.", "D": "as observações abertas são usadas na fase inicial de um\nprocesso de intervenção com o propósito de definir um\ndiagnóstico.", "E": "a análise da situação de trabalho, as fontes e os meios\nde acesso às informações determinam a qualidade\ndessa análise."}, "g": "E", "j": "A analise da demanda ergonomica deve considerar a analise da situacao de trabalho, as fontes e os meios de acesso as informacoes - elementos que determinam a qualidade da analise."}, {"id": "603896", "d": "psicologia", "a": ["Análise do Trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "A análise do trabalho é uma análise da atividade, das\ncondições de trabalho e do resultado da atividade. Nesse\nsentido, há uma multiplicidade de ciências do trabalho que\ncontribuem para realizar uma análise do trabalho e\nninguém pode pretender abordar só com a sua\ncompetência uma realidade tão complexa. Nesse contexto,\npara atender à demanda de intervenção de uma empresa é\ncorreto afirmar que:", "alt": {"A": "o domínio da ação é idêntico ao do conhecimento\nnecessário à ação.", "B": "ter um bom conhecimento das características das\ncondições térmicas de trabalho ou do ambiente sonoro\nparece ser suficiente para agir.", "C": "são indispensáveis a análise do sistema e a do seu\nfuncionamento e o analista do trabalho deve se recusar\na separar as diferentes realidades e ter competência\npara abordá-las.", "D": "Deve-se privilegiar uma abordagem do trabalho com\nênfase nos aspectos econômicos, sociológicos e\nbiológicos e na procura de relações unívocas de causa e\nefeito.", "E": "uma análise do trabalho deve contar com um analista\ndo trabalho que privilegie os aspectos técnicos, pois\nexistem muitas divergências entre os diferentes atores\nque fornecem as informações sobre o trabalho."}, "g": "C", "j": "Sao indispensaveis a analise do sistema e do seu funcionamento; o analista do trabalho deve recusar-se a separar as diferentes realidades e ter competencia para aborda-las."}, {"id": "603893", "d": "psicologia", "a": ["Organizações na Psicologia", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "O crescimento do setor de serviço representa uma\ntransformação da realidade produtiva. As características\nmecânicas, homogêneas, quantitativas, dentre outras, que\nmarcavam o modelo industrial, cederam espaço para a\nemergência de um novo modelo produtivo. Uma das\ncaracterísticas do trabalho no contexto virtual, por\nexemplo, é a impermanência do próprio contexto. Com\nbase no exposto, é possível afirmar que:", "alt": {"A": "As decisões estratégicas privilegiam as novas políticas\nde organização social.", "B": "A flexibilidade é o que vai definir a produtividade e,\nmuitas vezes, chega a constituir-se a estratégia que\npermite e justifica a sobrevivência da organização.", "C": "A informatização e o emprego de alta intensidade de\ninformação substituíram o modelo da linha de\nmontagem.", "D": "Aumenta a participação dos trabalhadores nas lutas\nsindicais e nas negociações coletivas.", "E": "O desempenho é compreendido em ambientes densos\ne fortemente manualizados."}, "g": "B", "j": "No novo modelo produtivo, a flexibilidade define a produtividade e frequentemente constitui-se na estrategia que justifica a sobrevivencia da organizacao."}, {"id": "603892", "d": "psicologia", "a": ["Gestão de Pessoas"], "ano": "2012", "org": "CFP", "t": "", "e": "Os autores divergem sobre o impacto das novas\ntecnologias, causando muitas polêmicas. Para uns, significa\na eliminação dos trabalhos pesados, repetitivos e\nmonótonos, liberando mais tempo para o lazer. Para\noutros, representa a desqualificação e extinção de postos\nde trabalho. Na área de gestão de pessoas, a contratação\nde pessoas passa por diversas mudanças. Assinale a\nalternativa que descreve os impactos observados na área.", "alt": {"A": "As políticas poupadoras de mão de obra reduzem os\nquadros de pessoal, mas enriquecem o conteúdo do\ntrabalho, pois aumentam as horas de trabalho.", "B": "A demanda de um novo perfil de trabalhador fortalece\nos processos de recrutamento e seleção com uso dos\ninstrumentos e técnicas consagradas.", "C": "O desenvolvimento dos meios de comunicação,\nespecialmente a internet, permite em vários setores a\ncontratação de serviços por terceiros ou diretamente a\ndistância e multiplicam-se os contratos temporários.", "D": "As organizações utilizam estratégias para concentrar as\nações em suas atividades fins, eliminando e/ou\nterceirizando setores e/ou atividades, o que favorece a\norganização autônoma dos trabalhadores e o\ndesempenho organizacional.", "E": "A reengenharia tem sido acompanhada na prática pela\naplicação de políticas poupadoras de mão de\nobra que buscam a retribuição justa ao esforço do\ntrabalho."}, "g": "C", "j": "O desenvolvimento dos meios de comunicacao, especialmente a internet, permite a contratacao de servicos a distancia e multiplicacao de contratos temporarios."}, {"id": "603891", "d": "psicologia", "a": ["Saúde no trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "O sofrimento no trabalho pode ser definido como as\nvivências concomitantes de desgaste e insegurança que são\ncapazes de desestabilizar a identidade e a personalidade. A\norigem do sofrimento pode ser verificada:", "alt": {"A": "Nas pressões e nas imposições da organização do\ntrabalho e na incapacidade de enfrentar as exigências\nrelacionadas ao desempenho.", "B": "Nos conflitos intrapsíquicos e nas condições subjetivas\ndo trabalho.", "C": "Nas condições objetivas do trabalho e na história de\nvida.", "D": "Nos aspectos psicossociais do trabalho e nas\ncaracterísticas pessoais: sexo, idade e formação.", "E": "Nas exigências da tarefa e na ausência de programas\nde qualidade de vida."}, "g": "A", "j": "A origem do sofrimento no trabalho reside nas pressoes e imposicoes da organizacao do trabalho e na incapacidade do trabalhador de enfrentar as exigencias de desempenho."}, {"id": "603890", "d": "psicologia", "a": ["Análise do Trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Os estudos organizacionais apontam que há uma\ndiversidade de usos do conceito de qualificação e que este\ntema adquire papel central no processo de implantação de\nnovas tecnologias e técnicas de gestão. As principais\nconcepções sobre o conceito de qualificação consideram:\nI. As características descritas nas rotinas e nos postos de\ntrabalho.\nII. O grau de autonomia do trabalhador. III. O fato de ser uma construção social, complexa,\ncontraditória e multideterminada.\nIV. Relação com a escolaridade, com as exigências do\nposto de trabalho e as habilidades aprendidas.\nV. Análise de como o trabalho é dividido e gerenciado.\nQuanto à concepção de qualificação, pode-se afirmar que:", "alt": {"A": "somente I, II e III estão corretas.", "B": "somente III, IV e V estão corretas.", "C": "somente II, III e IV estão corretas.", "D": "II e III estão incorretas.", "E": "todas estão corretas."}, "g": "E", "j": "Todas as cinco concepcoes de qualificacao apresentadas (rotinas, autonomia, construcao social, escolaridade/habilidades, divisao e gestao do trabalho) estao corretas conforme a literatura organizacional."}, {"id": "603889", "d": "psicologia", "a": ["Psicodinâmica do Trabalho", "Saúde no trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "O trabalho não se reduz à atividade em si, transcende o\nconcreto e instala-se numa subjetividade. O trabalho pode\nser um prazer, dependendo das condições nas quais é\nrealizado, ou poderá resultar num desprazer ao indivíduo.\nO estudo do prazer como um indicador de saúde vem\nsendo desenvolvido pelos estudos na abordagem da\npsicodinâmica do trabalho, segundo a qual é possível\ndefini-lo como:", "alt": {"A": "É um estado emocional que ocorre quando o trabalho\né desafiante, tem recompensas equilibradas, boas\ncondições e suporte dos colegas.", "B": "É uma sensação de bem-estar que pode ser medida e\ndepende da vontade.", "C": "É um sentimento de gratificação, orgulho e\nidentificação com um trabalho que atende às\nnecessidades profissionais.", "D": "É um equilíbrio entre as experiências positivas e\nnegativas e o grau de êxito que o indivíduo tem nas\ndiferentes esferas da vida.", "E": "É uma vivência de realização e liberdade que envolve\nexperiências simbólicas de reconhecimento, está\nrelacionado à identidade social e pessoal."}, "g": "E", "j": "Em psicodinamica do trabalho (Dejours), prazer e a vivencia de realizacao e liberdade que envolve experiencias simbolicas de reconhecimento, relacionada a identidade social e pessoal."}, {"id": "603888", "d": "psicologia", "a": ["Psicologia do Trabalho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Em relação ao campo de aplicação dos conhecimentos da\nciência psicológica a questões pertinentes ao trabalho, que\ncaracteriza a área da Psicologia do Trabalho, uma\ncompreensão mais ampliada do objeto de estudo permite\nafirmar que:", "alt": {"A": "Há três momentos diferentes da constituição da prática\nnesta área, sendo que o caráter instrumental da\nPsicologia Organizacional acabou por supervalorizar as\nteorias psicanalíticas com ênfase na satisfação.", "B": "O ponto central é o estudo e compreensão do trabalho\nhumano em todos os seus significados e\nmanifestações.", "C": "Os profissionais dessa área mesclam instrumentos e\npráticas que privilegiam a psicometria, a\ninterdisciplinaridade e a clínica.", "D": "Os objetivos da área centram-se na busca de eficiência,\ndesempenho, produtividade e rendimento, portanto é\numa atuação de caráter instrumental e orientação\ntecnocrática.", "E": "Atua nos postos de trabalho, na seleção, treinamento,\navaliação de desempenho e não se envolve com a\nestrutura das organizações."}, "g": "B", "j": "A Psicologia do Trabalho, em sua compreensao ampliada, tem como ponto central o estudo e compreensao do trabalho humano em todos os seus significados e manifestacoes."}, {"id": "598058", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Robert M. Farr adota um critério para classificar a\npsicologia social no seu desenvolvimento histórico. Ele\nclassifica determinadas correntes como psicologia social\nsociológica e como psicologia social psicológica. Farr, ao\nfazer essa classificação, está pretendendo:", "alt": {"A": "Separar a contaminação que a sociologia produziu em\nparte da psicologia social e valorizar a vocação\npsicológica da psicologia social moderna.", "B": "Estabelecer um critério que permita ao leitor\nespecializado reconhecer uma psicologia que sabe\nequacionar os problemas relativos aos indivíduos em\nsituação social.", "C": "Na realidade, trata-se apenas de um recurso histórico\npara classificar a psicologia produzida antes de 1930\nnos Estados Unidos, que precede a Psicologia Social\nCognitivista.", "D": "Farr está fazendo a diferenciação em entre George\nHerbert Mead e a Võlkerpsychologie de Wundt.", "E": "Estabelecer critério que permita compreender a\ninfluência da sociologia e da psicologia na produção da\npsicologia social, principalmente a partir do\nconhecimento desenvolvido após a II Guerra Mundial."}, "g": "E", "j": "Farr distingue psicologia social sociologica e psicologia social psicologica para compreender a influencia da sociologia e da psicologia na area, especialmente pos II Guerra."}, {"id": "598055", "d": "psicologia", "a": ["Psicologia Social", "Psicologia e Cultura"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Furtado, O.: \"...O repertório de 'idéias' de\numa determinada cultura, de uma determinada nação, de\num grupo social, tem como base o processo histórico do\ndesenvolvimento das forças produtivas e, ao mesmo\ntempo, acaba influindo no próprio processo econômico, ou\nseja, no desenvolvimento das formas subjetivas de\nexpressão desse processo de desenvolvimento.\" O autor\nestá discutindo:", "alt": {"A": "Que a subjetividade coincide com a noção popular de\n\"ideia\".", "B": "Sobre as \"dimensões subjetivas da realidade\".", "C": "Sobre desenvolvimento humano como foco da análise\npsicológica.", "D": "Que a objetividade é central no estudo da psicologia\nsocial", "E": "Que o repertório de \"ideias\" enquanto ideologia\ninfluencia as forças produtivas."}, "g": "B", "j": "Furtado, ao discutir como o repertorio de ideias se relaciona com o processo economico, esta tratando das 'dimensoes subjetivas da realidade'."}, {"id": "598054", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2012", "org": "CFP", "t": "", "e": "Numa favela da zona norte carioca, visada pelo tráfico,\nestabeleceu-se uma área de pacificação com o ingresso da\npolícia na favela e a instalação de um posto policial\npermanente. Foram instalados novos equipamentos\npúblicos, entre eles uma UPA e um CRAS. Por meio de uma\nONG, psicólogos sociais passaram a fazer um trabalho de\norganização da população, inclusive para discutir as\nconseqüências da ocupação. Do ponto de vista do\nconhecimento acumulado pela psicologia social no Brasil,\npodemos dizer que se trata de:", "alt": {"A": "Um trabalho de mudança de atitudes.", "B": "Um trabalho de base ambientalista.", "C": "Intervenção sociocultural.", "D": "Pesquisa-Ação.", "E": "Intervenção de psicologia social comunitária."}, "g": "E", "j": "O trabalho de organizacao popular em comunidade pacificada com discussao das consequencias da ocupacao configura intervencao tipica da psicologia social comunitaria."}, {"id": "598052", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2012", "org": "CFP", "t": "", "e": "Serge Moscovici, importante psicólogo social francês,\ndesenvolveu, no final do século XX, importante teoria\npsicossocial que deslocou a centralidade psíquica, do ponto\nde vista cognitivo, das atitudes para a construção social do\nsaber cotidiano, como referência para o comportamento de\npessoas, grupos, comunidades. Sua teoria foi fortalecida\npor muitos pesquisadores que aderiram a essa nova forma\nde pensar a psicologia social e que é muito difundida no\nBrasil. Estamos falando da:", "alt": {"A": "Teoria da Representação Social.", "B": "Teoria da Dissonância Cognitiva.", "C": "Teoria Sócio-Histórica.", "D": "Psicossociologia.", "E": "Teoria das Relações Interpessoais."}, "g": "A", "j": "Serge Moscovici desenvolveu a Teoria das Representacoes Sociais, deslocando o foco das atitudes para a construcao social do saber cotidiano."}, {"id": "598051", "d": "psicologia", "a": ["Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde"], "ano": "2012", "org": "CFP", "t": "", "e": "\"A ênfase na promoção de saúde e prevenção da doença\nabre, portanto, uma nova dimensão: a da determinação\nsocial da doença. O social se faz presente não apenas na\nexplicação do processo saúde-doença, como também em\nnível do comportamento, trazendo para a discussão a\nreflexão sobre a cultura de classe\". Spink, M. J., ao\ncomentar a 8ª Conferência Nacional da Saúde, faz\nreferência ao trabalho do psicólogo, que deve ser:", "alt": {"A": "Como profissional que saberá elucidar o componente\nsocial da relação saúde-doença.", "B": "Como detentor do saber clínico (saúde-doença) que\nsaberá fazer a ponte com os profissionais que\nentendem da cultura de classe.", "C": "Como especialista do comportamento humano.", "D": "Como participante da equipe multidisciplinar cujo\npapel central é o da promoção da saúde e prevenção\nda doença.", "E": "Como profissional atuante na determinação social da\ndoença."}, "g": "D", "j": "O psicologo deve atuar como participante da equipe multidisciplinar cujo papel central e a promocao da saude e a prevencao da doenca."}, {"id": "598050", "d": "psicologia", "a": ["Metodologia de Pesquisa e Estatística Aplicada à Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Martins, S. T. F.: \"Entre os autores não há\nconcordância em considerá-las como sinônimo. Thiollent\n(1986), por exemplo, estabelece diferenças entre as duas...\n[uma] tem base empírica e deve estar intrinsicamente\nligada com uma ação ou com a resolução de um problema\ncoletivo. Neste processo, tanto os pesquisadores quanto os\nrepresentantes da situação ou do problema em foco\ndeverão estar envolvidos de modo cooperativo ou\nparticipativo.\" Quando menciona as duas vertentes, ele\nestá se referindo a:", "alt": {"A": "Economia Solidária e Cooperativismo Popular.", "B": "Práxis e Experimentalismo.", "C": "Pesquisa ação e pesquisa participante.", "D": "Saber popular e saber acadêmico.", "E": "Ação permanente."}, "g": "C", "j": "Thiollent (1986) distingue pesquisa-acao de pesquisa participante, sendo a primeira voltada para acao/resolucao de um problema coletivo com envolvimento cooperativo."}, {"id": "598049", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com Neves, S. M & Bernardes, N. M. G., a\npsicologia comunitária:\n\"[É] uma área da psicologia social que estuda a atividade do\npsiquismo decorrente do modo de vida do\nlugar/comunidade; estuda os sistemas de relações e\nrepresentações, identidade, níveis de consciência,\nidentificação e pertinência dos indivíduos ao\nlugar/comunidade e aos grupos comunitários.\" \"Visa ao desenvolvimento da consciência dos moradores\ncomo sujeitos históricos e comunitários, através de um\nesforço interdisciplinar que perpassa o desenvolvimento\ndos grupos e da comunidade.\"", "alt": {"A": "As duas afirmações são verdadeiras, e a segunda é uma\njustificativa correta da primeira.", "B": "As duas afirmações são verdadeiras, mas a segunda\nnão é uma justificativa correta da primeira.", "C": "A primeira afirmação é verdadeira, e a segunda é falsa.", "D": "A primeira afirmação é falsa, e a segunda é verdadeira.", "E": "As duas afirmações são falsas."}, "g": "A", "j": "As duas afirmacoes sao verdadeiras e a segunda justifica a primeira ao explicitar que a psicologia comunitaria visa ao desenvolvimento da consciencia dos moradores como sujeitos historicos."}, {"id": "598048", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Importante psicóloga social brasileira radicada na\nInglaterra, Sandra Jovchelovitch diz em seu livro\nRepresentações Sociais e Esfera Pública: \"A esfera pública,\nportanto, é discutida atualmente em dois níveis: 1) como\num conceito-guia no projeto político de estabelecer uma\ndemocracia radical; e 2) como um fenômeno histórico,\naberto à avaliação e crítica. Ela permanece uma ideia\nparadigmática para pensar a democracia e a possibilidade\nde um espaço para o exercício do diálogo na vida comum.'", "alt": {"A": "O trecho citado faz referência à radicalização da crítica\ncomo método guia para a psicologia social e tem como\nbase o exercício do diálogo na vida comum.", "B": "A noção de esfera pública diz respeito ao campo das\npolíticas públicas e à análise do projeto político nos\ntrês níveis de governança.", "C": "A autora reconhece que sua obra está sujeita à\navaliação e à crítica.", "D": "O projeto político referido pela autora, de democracia\nradical, é o projeto neoliberal que propõe o Estado\nMínimo.", "E": "O espaço para o exercício do diálogo na vida comum é\numa referência à Teoria da Ação Comunicativa, de\nHabermas, também utilizada pela autora para\nfundamentar a noção de esfera pública."}, "g": "E", "j": "Jovchelovitch utiliza a Teoria da Acao Comunicativa de Habermas para fundamentar a nocao de esfera publica como espaco para o exercicio do dialogo na vida comum."}, {"id": "598046", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2012", "org": "CFP", "t": "", "e": "As concepções de representação são bem distintas entre\nMoscovici e Goffman. Considerando a orientação teórica de\ncada um desses teóricos da psicologia social, podemos dizer\nque:", "alt": {"A": "A representação para Moscovici tem caráter de evocar\numa expressão coletiva de um grupo social, e a\nrepresentação para Goffman tem o sentido da\nexpressão do sujeito no plano institucional no sentido\nda teatralização da vida.", "B": "A diferença entre eles é que para Moscovici a\nrepresentação é sempre social, e para Goffman ela é\nsempre individual.", "C": "As equipes descritas por Goffman equivalem aos grupos descritos por Moscovici.", "D": "Quando Moscovici fala em ancoragem das\nrepresentações, ele está fazendo referência a Goffman,\ncujo estudo é bem anterior, no sentido das\nrepresentações idealizadas.", "E": "Goffman constrói sua noção de representação,\ninfluenciado pelo Interacionismo Simbólico, e\nMoscovici o faz a partir da Psicanálise."}, "g": "A", "j": "Moscovici: representacao como expressao coletiva de um grupo social; Goffman: representacao como expressao do sujeito no plano institucional (teatralizacao da vida)."}, {"id": "598044", "d": "psicologia", "a": ["Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2012", "org": "CFP", "t": "", "e": "Bernardes, A. G. & Guareschi, N. M. F., a partir de relato de\npesquisa em hospital psiquiátrico de Porto Alegre, dizem:\n''Ao discutirmos estratégia e situações que decorrem da\nimplantação da Lei de Reforma Psiquiátrica estamos\nproblematizando a constituição de identidades de\ntrabalhadores da saúde mental, não em um âmbito geral\nabstrato, mas referente às interpelações pelas quais\nauxiliares de enfermagem vão fixando outros modos de\npensarem e se perceberem como trabalhadores de um\ncampo institucional no qual são rediscutidas as políticas\ntanto de saúde, quanto administrativas/' Considerando a\nafirmação das autoras, podemos dizer que:", "alt": {"A": "As autoras estão interessadas em focar a identidade de\ntrabalhadores de saúde mental, considerando que a\nformação dos auxiliares de enfermagem produz um\nviés que consolida modos de pensarem e de se\nperceberem como trabalhadores.", "B": "As autoras pretendem discutir sobre o modo como\numa política de saúde produz efeitos sobre a\nconstituição de novas identidades do trabalhador dos\nsistemas de saúde.", "C": "Políticas de saúde e políticas administrativas são\nproduções discursivas que se chocam e, algumas vezes,\nse anulam. O gestor público de saúde deveria priorizar\nas políticas de saúde em detrimento das políticas\nadministrativas.", "D": "A constituição das identidades de trabalhadores da\nsaúde mental não ocorre no âmbito geral abstrato,\nmas são específicas do modo como trabalham e\nconsolidam uma identidade estritamente profissional.", "E": "A rediscussão das políticas de saúde e administrativas\nocorre a partir da constituição da identidade\nprofissional da auxiliares de enfermagem."}, "g": "B", "j": "Bernardes e Guareschi discutem como uma politica de saude (Reforma Psiquiatrica) produz efeitos sobre a constituicao de novas identidades dos trabalhadores dos sistemas de saude."}, {"id": "598043", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2012", "org": "CFP", "t": "", "e": "Em uma comunidade extrativista instalada em zona de\nproteção e que vive da coleta de castanha da Amazônia,\numa família está sendo forçada a abandonar sua casa. O\ngrupo que produz a pressão é ligado a uma madeireira\nclandestina que tem interesse no abandono dessa área\npara poder realizar o comércio ilegal de madeira sem\ntestemunhas. A pressão é realizada com violência, e um dos\nfilhos mais velhos dessa família foi encontrado morto em\num igarapé no meio da floresta. No momento, a família\ndiscute se o melhor não seria ir morar em condições mais\nprecárias numa favela na periferia de Manaus e abandonar\nos benefícios obtidos por eles nesse projeto de inclusão\nsocial. Assinale a alternativa correta.", "alt": {"A": "Trata-se de uma violência endêmica no norte do país, e\nas condições inóspitas da floresta impedem a ação da\nPolícia Federal. A única alternativa dessa família será a\nde abandonar o projeto e buscar salvaguardar a vida\ndos demais membros da família.", "B": "É sabido que esse tipo de projeto não oferece bons\nresultados, e que colocar famílias, como a do caso\ncitado, em situação de risco é uma irresponsabilidade\ndos técnicos que elaboram esse tipo de projeto.", "C": "A agressão aos direitos humanos é flagrante nesse caso\ne trata-se de um evidente caso de violação que cabe\nação imediata e contundente das forças policiais.\nSomente depois do enfrentamento, será possível a\nintervenção da psicologia social.", "D": "Trata-se de uma ação de defesa dos direitos humanos,\ne uma equipe multidisciplinar deve ser a responsável\npor intervir nessa situação. Deve contar com o\nMinistério Público, agentes da Polícia Federal e\nmembros da Comissão Especial de Direitos Humanos;\nentre eles, o psicólogo que poderá utilizar a referência\ndo sofrimento ético-político como instrumento para\nanalisar o sofrimento psíquico das vítimas da violência.", "E": "Não se trata de ação relativa aos direitos humanos,\nmas de disputa de propriedade em local de terrar\ndevolutas, e somente a justiça pode arbitrar sobre a\nposse real do terreno. Não há ação possível da\npsicologia social nesse caso."}, "g": "D", "j": "A situacao demanda intervencao de equipe multidisciplinar (MP, PF, Comissao de DH) com o psicologo utilizando a referencia do sofrimento etico-politico para analisar o sofrimento psiquico das vitimas."}, {"id": "598042", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Em um estudo atitudinal, realizado em um grande centro\nmetropolitano, psicólogos sociais buscaram a mudança de\natitude de usuários do metrô quanto ao uso e conservação\ndos veículos durante o transporte da população. Para tanto,\norientaram uma campanha publicitária que versou sobre o\ncomportamento esperado e, de certa forma, ridicularizava\no personagem cujo comportamento era inadequado. Nessa\ncircunstância podemos dizer que:", "alt": {"A": "A estratégia central da campanha foi centrada no\ncomponente afetivo da atitude (por meio do humor) de\nconservação do transporte público pelo seu usuário,\nconsiderando que seria essa a melhor estratégia para a\nalteração do comportamento do usuário, já que seria\ndifícil focar apenas no componente cognitivo e quase\nimpossível tratar do componente conativo das atitudes,\ndado que se trata de controle de vasta população.", "B": "A mudança de comportamento, no caso das atitudes,\ndepende de como será feito o controle do reforço,\nconsiderando que, no caso, as variáveis dependentes são\nresponsáveis pelo maior efeito de mudança atitudinal.", "C": "Em casos como esse, de um transporte de massa com\nmilhares de pessoas utilizando o serviço, não há\ncondições viáveis de controle e, portanto, será\nimpossível a implantação de programas atitudinais,\nconsiderando que essa referência é aplicada somente a\npequenos grupos.", "D": "O componente comportamental ou conativo das\natitudes é o que mais garante mudança de\ncomportamento, quando adequadamente controlado.\nEntão, o procedimento correto será o de estabelecer\nnormas mais rígidas com aplicação de multa aos\ninfratores. Assim, teremos uma mudança rápida do\ncomportamento, e será possível garantir a manutenção\npor meio de campanha publicitária.", "E": "Ridicularizar pessoas em uma campanha publicitária,\nmesmo no caso de comportamento socialmente\ninadequado, corresponde à infração do Código de Ética\ndo Psicólogo e não deve ser estratégia que um psicólogo\nsocial possa utilizar em uma campanha publicitária."}, "g": "A", "j": "A campanha que ridiculariza comportamentos inadequados foca o componente afetivo da atitude (humor) para alterar comportamentos em massa."}, {"id": "598041", "d": "psicologia", "a": ["Saúde Mental", "Psicologia Social", "Psicologia da Saúde", "Luta Antimanicomial", "Psicologia Comunitária"], "ano": "2012", "org": "CFP", "t": "", "e": "Um CAPS II planejou atividade de geração de renda para os\nseus usuários interessados em sua autonomia financeira. A\natividade, além de colaborar na inserção desses usuários na\ncomunidade, acaba resultando em estruturação pessoal\ndos envolvidos no projeto. Uma das atividades implicou a\nqualificação de um grupo de homens e mulheres adultos,\ncomo garçons e quituteiras, para realização de festas e\ncoffee-breaks. A formação dos usuários envolveu a\naquisição de conhecimento relativo à organização de\ncooperativa popular, obedecendo ao princípio de\nautonomia e socialização do resultado do trabalho\nexecutado. Podemos afirmar que, numa experiência desse\ntipo, a psicologia social:", "alt": {"A": "Fornece instrumental de análise a partir de estudos\natitudinais realizados in loco e fartamente publicados\nem periódicos nacionais e internacionais, considerando\nque a Economia Solidária é teoria de base cognitiva.", "B": "A discussão sobre trabalho e alienação, do ponto de\nvista da psicologia crítica do trabalho, é um importante\nreferencial para considerarmos a inserção ou reinserção dos usuários, em situação de\nvulnerabilidade, no mundo do trabalho, levando em\nconta que o trabalho cooperativado poderá reverter a\ncondição de trabalho estranhado que ocorre nas\nrelações capitalistas de trabalho.", "C": "A psicologia social tem muito pouco a oferecer numa\nsituação desestruturada como a mencionada, já que\ndependemos da existência de uma clientela bem\ndefinida e institucionalizada que nos permita o\ntrabalho de organização de grupos e da avaliação\nconstante de sua dinâmica.", "D": "A utilização do referencial da psicologia organizacional\nserá extremamente útil no estabelecimento de um\nplanejamento de avaliação de cargos e salários no\nmomento da divisão dos usuários pelos cargos\nexistentes na cooperativa e o real valor do trabalho\nexecutado por eles conforme a função exercida.", "E": "A psicologia social não tem aplicação em uma atividade\nclaramente econômica."}, "g": "B", "j": "A discussao sobre trabalho e alienacao (psicologia critica do trabalho) e o referencial central para a insercao de usuarios em economia solidaria como CAPS, revertendo o trabalho estranhado."}, {"id": "598040", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2012", "org": "CFP", "t": "", "e": "Numa comunidade ribeirinha, uma grande obra irá\ndesalojar um grupo de pescadores. Uma ONG ambientalista\ncontratou psicólogos sociais para ajudar a organizar a\npopulação a fim de resistir à desocupação, com o objetivo\nde obter melhores condições de transferência para a\npopulação atingida. Os psicólogos contratados resolveram\ntrabalhar com a noção de processo grupai de Silvia Lane,\nque supõe: I. Que a população atingida deve formar barricadas e\nocupar a área da obra como estratégia de resistência.\nII. Ser importante a análise do processo de organização\ndo grupo atingido, considerando a análise da atividade\ncomo forma de identificar relações de poder e\nsignificado social.III. Ser necessário conhecer os interesses envolvidos para\numa análise das condições objetivas e subjetivas que\nnos forneça possibilidade de avaliação das\ncontradições existentes. Está correto o que se afirma em:", "alt": {"A": "apenas I.", "B": "apenas I e III.", "C": "apenas II e III.", "D": "apenas III.", "E": "nenhuma."}, "g": "C", "j": "Estao corretas II (analise da atividade para identificar relacoes de poder e significado social) e III (analise das condicoes objetivas e subjetivas e contradicoes), conforme Silvia Lane."}, {"id": "598038", "d": "psicologia", "a": ["Psicologia Social", "Psicologia da Saúde", "Promoção, Prevenção e Reabilitação em Saúde", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Na interface da Psicologia Social e a Saúde, podemos\nafirmar que: I. As práticas em saúde ainda sustentam uma concepção\nfragmentada de saúde e o caráter impositivo e\nnormatizador da visão positivista de ciência.\nII. As práticas em saúde mostram ainda uma tendência a\ncontinuarem concentradas numa biotecnologia\naplicada, fortalecendo a indústria farmacêutica e a de\nequipamentos médicos muito sofisticados.III. É necessário cobrarmos as responsabilidades de cada\npessoa pelas doenças e sofrimentos, tanto pelos estilos\nde vida inadequados quanto pelos aspectos\npatológicos de personalidade.\nIV. A consolidação do Sistema Único de Saúde (SUS) é o\ngrande desafio para todos os trabalhadores da saúde e,\nem particular, para os psicólogos.Diante das considerações acima, assinale a alternativa\ncorreta.", "alt": {"A": "Todas afirmações estão corretas.", "B": "Apenas a afirmação IV está correta.", "C": "Apenas as afirmações I, II e IV estão corretas.", "D": "Todas afirmações estão incorretas.", "E": "Apenas a afirmação III está correta."}, "g": "C", "j": "I, II e IV estao corretas. III esta incorreta porque transfere a responsabilidade pelas doencas para o individuo, ignorando determinantes sociais."}, {"id": "598037", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Papéis Sociais e Relações de Gênero"], "ano": "2012", "org": "CFP", "t": "", "e": "Considere as assertivas a seguir\nI. A Psicologia Social Sócio-Histórica não privilegia a\ndescrição do discurso (representações), mas a sua\nprodução.\nII. O pequeno grupo e as relações interpessoais são o\nobjeto de estudo privilegiado da Psicologia Social\nSócio-Histórica.\nIII. Na teoria dos papeis sociais, a abordagem da\nhistoricidade é considerada fundamental.\nIV. Entre os recursos metodológicos utilizados pela\nabordagem sócio-histórica, encontramos a pesquisa\nparticipante e a pesquisa-ação.\nPode-se afirmar que:", "alt": {"A": "apenas I e III estão corretas", "B": "apenas I e IV estão corretas.", "C": "todas estão corretas.", "D": "apenas IV está correta.", "E": "todas estão incorretas."}, "g": "B", "j": "I (Psicologia Socio-Historica privilegia a producao do discurso) e IV (utiliza pesquisa participante e pesquisa-acao) estao corretas. II e III sao incorretas."}, {"id": "598036", "d": "psicologia", "a": ["Foucault", "Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Na perspectiva dos estudos de Michel Foucault, analise as\nfrases a seguir. I. A lógica discursiva que define a obsessão das\nsociedades contemporâneas pela juventude está ligada\na uma concepção de sexualidade que faz referência à\nbeleza e à atividade sexual.\nII. Ainda hoje, em nossa sociedade, podemos observar a\narticulação da medicina, da demografia e da pedagogia\nna administração da conduta sexual da população. III. A partir do século 18, os dispositivos de saber e poder\ndeixam de incidir sobre o sexo da criança, permitindo a\nexpressão livre de seus comportamentos.\nIV. O dispositivo da \"sexualidade\" tem sua origem na\nseparação do sexo do dispositivo da aliança que\narticulava as obrigações religiosas ou legais do\ncasamento com a transmissão da propriedade e dos\nlaços de sangue, constituindo o sistema social.\nPode-se afirmar que:", "alt": {"A": "apenas I, II e IV estão corretas.", "B": "todas estão corretas.", "C": "apenas I e II estão corretas.", "D": "apenas I e IV estão corretas.", "E": "todas estão incorretas."}, "g": "A", "j": "I, II e IV estao corretas na perspectiva foucaultiana. III esta incorreta - os dispositivos de saber-poder INTENSIFICAM o controle sobre a sexualidade infantil a partir do seculo 18."}, {"id": "598035", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a afirmação incorreta.", "alt": {"A": "Os meios de comunicação possuem instrumentos\npersuasivos por meio dos quais podem exercer\ncontrole absoluto sobre nossa subjetividade.", "B": "Os norte-americanos usaram e usam a linguagem\ncinematográfica para convencer o mundo de que seu\nmodo de vida era (é) o melhor.", "C": "É na forma discursiva que o poder escancara suas\nformas de dominação.", "D": "A persuasão é um mecanismo de convencimento usado\nna propaganda que pode ou não ultrapassar as bases\nracionais de difusão de uma mensagem.", "E": "O jornalista e o publicitário podem apropriar-se do\nconhecimento da Psicologia e utilizá-lo com\ncompetência na sua atividade profissional junto à\nmídia."}, "g": "A", "j": "A alternativa A esta incorreta ao afirmar 'controle absoluto sobre nossa subjetividade' - os meios de comunicacao influenciam, mas nao controlam absolutamente."}, {"id": "598034", "d": "psicologia", "a": ["Dinâmicas de Grupo", "Kurt Lewin", "Teorias da Personalidade", "Grupos e Equipes"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando os estudos dos grupos, assinale a alternativa\nincorreta.", "alt": {"A": "Kurt Lewin foi o primeiro estudioso a desenvolver uma\nteoria consistente sobre os grupos.", "B": "A coesão é a forma encontrada pelos grupos para que\nseus membros sigam as regras estabelecidas.", "C": "Na solidariedade mecânica, a afiliação a um grupo\ndepende da nossa vontade no que diz respeito à\nescolha dos seus integrantes.", "D": "O grupo operativo se caracteriza por estar centrado, de\nforma explícita, em uma tarefa que pode ser o\naprendizado, a cura, o diagnóstico etc.", "E": "Não existe um grupo abstrato, mas sim um processo\ngrupal que se reconfigura a cada momento."}, "g": "C", "j": "A alternativa C inverte o conceito durkheimiano - a solidariedade mecanica e involuntaria, baseada em semelhanca, nao em escolha voluntaria de membros."}, {"id": "598033", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "As seguintes afirmações apresentam características da\nPsicologia Social de orientação positivista, inspirada no\nmodelo norte-americano pós-guerra. I. Propõe-se a descrever os processos observáveis dos\nencontros sociais.\nII. Seus objetivos estão voltados para a procura de formas\nadequadas de ajustamento de comportamentos\nindividuais ao contexto social.\nIII. O social é entendido apenas como a relação entre\npessoas e não como um conjunto de produções\nhumanas que constroem a realidade social e, ao\nmesmo tempo, o indivíduo.\nIV. É uma Psicologia Social comprometida com a\ntransformação das condições de desigualdade e\ninjustiça social.Pode-se afirmar que:", "alt": {"A": "apenas I e III estão corretas.", "B": "apenas I, II e III estão corretas.", "C": "todas estão incorretas.", "D": "todas estão corretas.", "E": "apenas II, III e IV estão corretas."}, "g": "B", "j": "I, II e III caracterizam a Psicologia Social positivista (descritiva, ajustamento, social como mera interacao). IV e incorreta - a perspectiva positivista nao se compromete com transformacao social."}, {"id": "598032", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Analise as afirmações, considerando o pensamento de\nMartin-Baró, ao refletir sobre o papel do psicólogo na\nsociedade e assinale a alternativa incorreta.", "alt": {"A": "A psicologia não tem uma especificidade enquanto\nárea de conhecimento científico e prático.", "B": "O trabalho do psicólogo deve buscar a desalienação\ndas pessoas e grupos, para que isso os ajude a chegar a\num saber crítico sobre si próprios e sobre a realidade.", "C": "A conscientização constitui-se no horizonte primordial\ndo \"que fazer\" psicológico.", "D": "O psicólogo deve transformar sua prática profissional\ndespojando-a de pressupostos teóricos adaptacionistas\ne de suas formas de intervenção a partir de posições de\npoder.", "E": "O psicólogo deve preocupar-se com as conseqüências\nhistóricas concretas que sua atividade esteja\nproduzindo."}, "g": "A", "j": "A alternativa A contraria Martin-Baro, que defende uma psicologia especifica enquanto area cientifica e pratica voltada para a libertacao."}, {"id": "598030", "d": "psicologia", "a": ["Psicologia Social", "Psicologia Comunitária"], "ano": "2012", "org": "CFP", "t": "", "e": "Em relação às contribuições da Psicologia Social\nComunitária, no Brasil e na América Latina, analise as\nafirmações e assinale a que está incorreta.", "alt": {"A": "A Comunidade é considerada como categoria central\nde análise e de possibilidade de ação.", "B": "A vida cotidiana constitui-se em matéria-prima para\nanálise dos processos de conscientização e\nparticipação.", "C": "Provocou um incremento na \"vontade de ajudar\" de\ngrupos e segmentos da sociedade civil o que, por si,\ngera uma diminuição dos problemas concretos,\neliminando os determinantes das situações de\nopressão e exploração.", "D": "Contribuiu para a defesa do fortalecimento de rede de\nsolidariedade, para que possa ser construído um\nprojeto de sociedade digna e justa.", "E": "Vem aglutinando trabalhos e experiências de\ndiferentes campos disciplinares."}, "g": "C", "j": "A alternativa C esta incorreta - 'vontade de ajudar' nao elimina por si os determinantes da opressao e exploracao; a Psicologia Social Comunitaria critica o assistencialismo."}, {"id": "598029", "d": "psicologia", "a": ["Intervenção Psicossocial", "Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Tendo como referência a Intervenção Psicossocial, assinale\na afirmação que está incorreta.", "alt": {"A": "O objetivo do trabalho do facilitador/interventor é\npossibilitar melhores condições humanas e qualidade\nde vida.", "B": "A intervenção psicossocial é uma prática que será mais\nefetiva e competente quanto mais independente for\ndos valores e posturas do profissional interventor.", "C": "A participação do grupo-alvo do trabalho de\nintervenção é imprescindível para o desenvolvimento\ndo grupo.", "D": "São os grupos sociais que podem, a partir da\nintervenção psicossocial, promover ações\ntransformadoras da realidade.", "E": "A avaliação deve estar presente em todos os níveis do\nprocesso de intervenção social, do diagnóstico até a\nfase dos resultados e seus efeitos."}, "g": "B", "j": "A alternativa B contraria a intervencao psicossocial: a pratica nao se torna mais efetiva por ser independente dos valores - os valores e postura do profissional sao constitutivos."}, {"id": "598028", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia Jurídica", "Crianças e Adolescentes - Menores Infratores"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia, com atenção, as seguintes assertivas:I. A construção da noção de \"periculosidade\" associada\nao comportamento dos jovens serve como legitimação\ndo tratamento violento, a eles dirigido, pelos agentes\ndo Estado.\nII. É necessária a atuação psiquiátrica/psicológica para\ntratar dos problemas e conflitos que setores da\njuventude vêm trazendo para o campo social.\nIII. É necessário desnaturalizar quaisquer noções totalizantes sobre a adolescência que se pretenda permanente e universal. IV. Devemos, numa perspectiva discursiva, questionar a\nvisão instituída por um pensamento psicológico\ndesenvolvimentista que estabelece características\ninerentes para cada uma das etapas da vida.\nPode-se afirmar que:", "alt": {"A": "todas estão corretas.", "B": "apenas II está incorreta.", "C": "apenas II e IV estão incorretas.", "D": "apenas IV está incorreta.", "E": "apenas I está incorreta."}, "g": "B", "j": "Apenas II esta incorreta - a 'atuacao psiquiatrica/psicologica' como solucao patologiza demandas sociais, contrariando perspectivas criticas sobre juventude."}, {"id": "598026", "d": "psicologia", "a": ["Teorias da Personalidade", "Teorias da Personalidade - Outros Autores"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia, com atenção, as assertivas a seguir.I. A emoção e o sentimento não são entidades absolutas\nou lógicas do nosso psiquismo.\nII. Por serem sociais, as emoções são fenômenos\nhistóricos, cujo conteúdo e qualidade estão sempre em\nconstituição.\nIII. Os avanços da neurociência e das técnicas biológicas,\nque buscam ampliar o tempo de vida e a felicidade\nhumana, demonstram claramente a determinação\ngenética das nossas maiores angústias. Pode-se afirmar que:", "alt": {"A": "apenas I está correta.", "B": "apenas II e III estão corretas.", "C": "todas estão corretas.", "D": "apenas III está correta.", "E": "apenas I e II estão corretas."}, "g": "E", "j": "I e II estao corretas (emocoes nao sao absolutas/logicas e sao construcoes historico-sociais). III esta incorreta ao reduzir as angustias a determinacao genetica."}, {"id": "598025", "d": "psicologia", "a": ["Psicologia Social", "Papéis Sociais e Relações de Gênero"], "ano": "2012", "org": "CFP", "t": "", "e": "A \"Humilhação Social\" discutida por Gonçalves Filho, J.M.\nem seu trabalho com mulheres pobres de São Paulo:", "alt": {"A": "É um conceito não relacionado às determinações\neconômicas e inconscientes.", "B": "Modalidade de angústia disparada pelo enigma da\ndesigualdade de classes.", "C": "Inadequação social das classes populares por falta de\numa boa formação familiar e escolar.", "D": "O sentir-se humilhado decorre de uma percepção ou imaginação das pessoas pobres.", "E": "Nenhuma das alternativas anteriores está correta."}, "g": "B", "j": "Goncalves Filho: a Humilhacao Social e modalidade de angustia disparada pelo enigma da desigualdade de classes, atravessando corpo, gesto, imaginacao e voz do humilhado."}, {"id": "598024", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "Para a Psicologia Sócio-Histórica: I. As funções psíquicas superiores do ser humano foram\ndesenvolvidas a partir da atividade consciente de\ntransformação do mundo.\nII. A consciência pode ser considerada como elemento\ncentral da constituição do psiquismo humano.\nIII. É necessário romper com as leituras normatizadoras da\nsubjetividade e do campo psicológico.IV. A compreensão crítica da realidade requer a\nidentificação da gênese e do curso dos fenômenos que\na constituem.Pode-se afirmar que:", "alt": {"A": "apenas I, II e IV estão corretas.", "B": "todas estão incorretas.", "C": "todas estão corretas.", "D": "apenas II, III e IV estão corretas.", "E": "apenas II e III estão corretas."}, "g": "C", "j": "As quatro afirmacoes correspondem corretamente aos pressupostos da Psicologia Socio-Historica (funcoes psiquicas superiores, consciencia, critica as normatizacoes e analise genetica)."}, {"id": "598023", "d": "psicologia", "a": ["Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social"], "ano": "2012", "org": "CFP", "t": "", "e": "No contexto da pesquisa em Psicologia Social, podemos\ndefinir os grupos focais como:", "alt": {"A": "Grupos de pessoas ligadas a uma mesma perspectiva\npolítico-ideológica.", "B": "Uma forma de entrevista grupal, típica da pesquisa\nqualitativa.", "C": "Uma forma de coleta de dados, utilizando\nquestionários com um foco temático único.", "D": "Uma técnica de análise de dados da pesquisa\nqualitativa com grupos de discussão.", "E": "Todas as alternativas anteriores estão corretas."}, "g": "B", "j": "Os grupos focais sao uma forma de entrevista grupal, tipica da pesquisa qualitativa, que reune participantes em torno de um tema para discussao orientada."}, {"id": "598022", "d": "psicologia", "a": ["Psicologia Social", "Representações Sociais, Atitudes, Comportamento, Estereótipos e Preconceitos"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando a teoria das representações sociais, assinale\na alternativa incorreta.", "alt": {"A": "As representações sociais são sempre a representação\nde um objeto, ou seja, elas ocupam o lugar de alguma\ncoisa.", "B": "As pesquisas sobre os conteúdos da mídia têm sido\nutilizadas pelos estudos de representações sociais.", "C": "As representações sociais possuem um caráter\nprodutor de imagens e significante, expressando o\ntrabalho do psiquismo.", "D": "As representações sociais são fenômenos simbólicos\nproduzidos na esfera pública.", "E": "Uma das características das representações sociais é o\nseu caráter de permanência e imutabilidade."}, "g": "E", "j": "As representacoes sociais NAO sao permanentes e imutaveis - sao dinamicas, processuais e mudam com transformacoes historico-sociais."}, {"id": "598021", "d": "psicologia", "a": ["Psicologia Social", "Papéis Sociais e Relações de Gênero"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia as afirmativas a seguir. I. O conhecimento psicológico sempre considerou, em\nsuas teorias e práticas, a dimensão de gênero.\nII. Gênero é entendido como elemento constitutivo das\nrelações sociais percebidas entre os sexos. III. As pesquisas na área de saúde da mulher têm\ndemonstrado que a menopausa é uma experiência\nfisiológica que se apresenta de forma semelhante em\ntodas as culturas.\nIV. Está ainda presente, no imaginário social brasileiro, a\nrepresentação da fidelidade feminina como\nfundamental para a valorização da mulher, sob a óptica\nmasculina.Pode-se afirmar que:", "alt": {"A": "todas estão incorretas.", "B": "apenas II e IV estão corretas.", "C": "apenas IV está correta.", "D": "todas estão corretas.", "E": "apenas I está incorreta."}, "g": "B", "j": "II (genero como elemento constitutivo das relacoes sociais) e IV (representacao da fidelidade feminina no imaginario) estao corretas. I e III sao falsas."}, {"id": "598020", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2012", "org": "CFP", "t": "", "e": "Tendo em vista as concepções atuais do processo de saúde-doença,\nassinale a afirmação incorreta.", "alt": {"A": "Tanto o comportamento da pessoa saudável quanto o\nda pessoa doente devem ser compreendidos dentro do\nseu contexto social.", "B": "A prevenção da saúde é um conceito relacionado com\na doença, enquanto que a promoção é um conceito\nrelacionado com a saúde.", "C": "Não há um limite claro entre saúde e doença, senão\ngraus e expressões diversas que se misturam.", "D": "A promoção da saúde é uma tarefa interdisciplinar,\nmas cabe ao médico o papel principal na condução do\nprocesso de diagnóstico e tratamento.", "E": "A saúde deve ser entendida num sentido mais amplo,\ncomo componente da qualidade de vida e, assim, não é\num bem de troca, mas um bem comum."}, "g": "D", "j": "A promocao da saude e tarefa INTERDISCIPLINAR sem hierarquia entre profissionais - reduzir o papel a centralizacao medica contraria a perspectiva contemporanea."}, {"id": "598019", "d": "psicologia", "a": ["Psicologia do Desenvolvimento", "Psicologia Social", "Conceito, Histórico, Atuação e Objetos de Estudo da Psicologia Social", "Movimentos Sociais e de Massa"], "ano": "2012", "org": "CFP", "t": "", "e": "Analise as afirmativas a seguir. I. O mito da natureza violenta dos excluídos tem\nimplicações nas práticas cotidianas que configuram as\nrelações entre as classes sociais.\nII. Os meios de comunicação fornecem informações\ncorretas que nos permitem avaliar adequadamente o\nquadro de violência que vem sempre aumentando nas\ngrandes cidades brasileiras. III. A causa da violência, associada ao comportamento dos\njovens, deve ser buscada na falta de limites impostos\npelos seus pais.\nIV. Podemos dizer que, ao longo da história recente da\nadolescência, a ciência e o pensamento social\nconstruíram a ideia de \"idade do perigo\", que marca a\ntransição da infância para a vida adulta.Pode-se afirmar que:", "alt": {"A": "todas estão corretas.", "B": "apenas I está correta.", "C": "todas estão incorretas.", "D": "apenas I e IV estão corretas.", "E": "apenas IV está correta."}, "g": "D", "j": "I (mito da natureza violenta dos excluidos) e IV ('idade do perigo' como construcao historica) estao corretas. II (informacoes corretas da midia) e III (falta de limites parentais) sao reducoes."}, {"id": "594797", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia atentamente as afirmações e, em seguida, assinale a resposta cuja alternativa não condiz com os primeiros cuidados recomendados por Chiavenato (2009) para implantar a avaliação do desempenho.", "alt": {"A": "Assegurar um clima de trabalho de respeito e confiança entre as pessoas.", "B": "Desenvolver um estilo de administração que seja democrático, participativo e consultivo.", "C": "Criar um propósito de direção, futuro e melhoria contínua entre as pessoas.", "D": "Gerar uma expectativa permanente de aprendizagem, inovação, desenvolvimento pessoal e profissional.", "E": "Desencorajar as pessoas a assumirem responsabilidades e a definirem metas de trabalho."}, "g": "E", "j": "Chiavenato (2009) recomenda ENCORAJAR as pessoas a assumirem responsabilidades e definirem metas - a alternativa E inverte essa orientacao."}, {"id": "594796", "d": "psicologia", "a": ["Avaliação de Desempenho", "Psicologia e Organizações"], "ano": "2012", "org": "CFP", "t": "", "e": "As práticas de avaliação de desempenho não são novas. Desde que uma pessoa deu emprego a outra, seu trabalho passou a ser avaliado em termos de custo e benefício. Considere as afirmações sobre o assunto e assinale a incorreta.", "alt": {"A": "A avaliação de desempenho é uma apreciação do desempenho de cada pessoa no cargo e o seu potencial de desenvolvimento futuro.", "B": "Nem toda avaliação de desempenho é um processo para estimular ou julgar o valor, a excelência, as qualidades de alguma pessoa.", "C": "A avaliação de desempenho é um conceito dinâmico, pois os empregados sempre são avaliados, seja formal ou informalmente.", "D": "A avaliação de desempenho constitui uma técnica de direção imprescindível na atividade administrativa.", "E": "A avaliação de desempenho pode colaborar na determinação e no desenvolvimento de uma política adequada de recursos humanos às necessidades da organização."}, "g": "B", "j": "A alternativa B esta incorreta - toda avaliacao de desempenho e um processo para estimular ou julgar valor, excelencia e qualidades de alguma pessoa."}, {"id": "594792", "d": "psicologia", "a": ["Avaliação Psicológica", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "O documento referente às Normas e Procedimentos para Avaliação Psicológica de Candidatos à Carteira Nacional de Habilitação (CNH) e Condutores de Veículos Automotores regulamenta a prática da avaliação psicológica junto aos Órgãos Executivos estaduais de Trânsito dos Estados e do Distrito Federal (DETRAN's - Departamentos de Trânsito). Sobre esse documento, é incorreto afirmar que:", "alt": {"A": "o laudo da avaliação psicológica poderá apresentar apenas dois resultados possíveis ao candidato: apto ou inapto.", "B": "fica o psicólogo obrigado a realizar a entrevista devolutiva, apresentando de forma clara e objetiva o resultado de sua avaliação.", "C": "para proceder à mensuração e avaliação de um teste, o profissional deve seguir rigorosamente as determinações do manual, os indicadores e escalas apresentadas nos manuais de cada instrumento.", "D": "a entrevista psicológica deve ser utilizada em caráter inicial e faz parte do processo de avaliação psicológica.", "E": "a sala de atendimento coletivo deve ter, no mínimo, as dimensões descritas pela Resolução do CONTRAN."}, "g": "A", "j": "O laudo da avaliacao psicologica para CNH pode apresentar quatro resultados: apto, apto com restricoes, inapto temporariamente e inapto - nao apenas dois como afirma a alternativa A."}, {"id": "594791", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "No tocante à Resolução CFP n° 006/2007, que institui o Código de Processamento Disciplinar, analise as seguintes afirmações referentes ao Capítulo V - das penalidades.I. As penalidades aplicáveis são as seguintes: advertência, multa, censura pública, suspensão ou cassação do registro para o exercício profissional.II. A censura pública, a suspensão e a cassação do exercício profissional serão publicadas em Diário Oficial, jornais ou boletins do Conselho regional e afixados na sua sede onde estiver inscrito o psicólogo processado e nas suas Seções.III. Para efeito de análise de reincidência do psicólogo no cometimento de infração ética que envolve mesma matéria, deverá ser considerada a existência de processos éticos já julgados no período de 2 (dois) anos anteriores, contados a partir do cumprimento da pena imposta.", "e": "Está correto o que se afirma em:", "alt": {"A": "somente I e II.", "B": "somente II e III.", "C": "somente I e III.", "D": "todas.", "E": "nenhuma."}, "g": "D", "j": "Res CFP 006/2007: as tres afirmacoes correspondem corretamente as disposicoes sobre penalidades, publicidade e periodo de reincidencia (2 anos)."}, {"id": "594790", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "O psicólogo, em sua prática profissional, é frequentemente interpelado por questões ligadas à sexualidade. Assim, a Psicologia pode e deve contribuir com seu conhecimento para o esclarecimento sobre questões da sexualidade, permitindo a superação de preconceitos e discriminações.Considere as afirmações a seguir, de acordo com as Resoluções CFP n° 001/1999 e 014/2011.I. Os psicólogos poderão colaborar com eventos e serviços que proponham tratamento e cura das homossexualidades.II. Os psicólogos não exercerão qualquer ação que favoreça a patologização de comportamentos ou práticas homoeróticas.III. Os psicólogos transexuais e travestis terão direito à escolha de tratamento nominal a ser inserido no campo \"observação\" da Carteira de Identidade Profissional do Psicólogo, por meio da indicação do nome social.", "e": "Está correto o que se afirma em:", "alt": {"A": "somente II.", "B": "somente II e III.", "C": "somente I e III.", "D": "todas.", "E": "nenhuma."}, "g": "B", "j": "Res CFP 001/1999 e 014/2011: II (vedacao a patologizacao) e III (direito ao nome social na carteira profissional) estao corretas. I e vedada pelas resolucoes."}, {"id": "594789", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "Algumas das especialidades que estão contidas na Resolução CFP n° 013/2007 e as quais podem ser concedidas o título profissional de Especialista em Psicologia são:I. Psicomotricidade.II. Psicopedagogia.III. Neuropsicologia.IV. Psicologia Hospitalar.V. Psicologia do Trânsito.", "e": "Está correto o que se afirma em:", "alt": {"A": "somente III e V.", "B": "somente III e IV.", "C": "somente I, III e V.", "D": "somente II, III, IV e V.", "E": "I, II, III, IV e V."}, "g": "E", "j": "As cinco especialidades (Psicomotricidade, Psicopedagogia, Neuropsicologia, Psicologia Hospitalar e Psicologia do Transito) constam na Res CFP 013/2007."}, {"id": "594786", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Psicodiagnóstico e Avaliação Psicológica", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "Considerando a necessidade de aprimorar os instrumentos e procedimentos técnicos de trabalho dos psicólogos e de revisão periódica das condições dos métodos e técnicas utilizadas na avaliação psicológica, a Resolução CFP n° 002/2003 define e regulamenta o uso, a elaboração e a comercialização de testes psicológicos. Assinale a afirmação correta sobre o tema.", "alt": {"A": "Será considerado teste psicológico em condições de uso, seja ele comercializado ou disponibilizado, aquele que, após receber Parecer da Comissão Consultiva em Avaliação Psicológica, for aprovado pelo CRP.", "B": "Os testes com avaliação final desfavorável, por não atenderem às condições mínimas, não poderão ser reapresentados.", "C": "Na comercialização de testes psicológicos, as editoras, por meio de seus responsáveis técnicos, manterão procedimento de controle em que constem somente o nome do psicólogo que os adquiriu e o(s) número(s) de série dos testes adquiridos.", "D": "Os Conselhos Regionais de Psicologia adotarão as providências para o cumprimento desta Resolução, em suas respectivas jurisdições, podendo apreender lote de testes psicológicos não autorizados para o uso.", "E": "A Comissão Consultiva em Avaliação Psicológica será composta por, no mínimo, três membros, podendo valer-se da colaboração de pareceristas Ad hoc."}, "g": "D", "j": "Os CRPs adotam providencias para o cumprimento da Res 002/2003 em suas jurisdicoes, podendo apreender lotes de testes psicologicos nao autorizados."}, {"id": "594785", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resolução CFP n° 006/2019 - Manual de Elaboração de Documentos Escritos - Informes e Documentos Psicológicos"], "ano": "2012", "org": "CFP", "t": "A Resolução CFP n° 007/2003 institui o Manual de Elaboração de Documentos Escritos produzidos pelo psicólogo, decorrentes de Avaliações Psicológicas que tem por objetivos orientar o profissional na confecção de documentos e fornecer subsídios éticos e técnicos necessários para a elaboração qualificada da comunicação escrita. Conforme os princípios Éticos e Técnicos, considere as seguintes afirmações:\nI. A linguagem do documento deve ser extensa, sem restringir informações que fizerem parte da história de vida do atendido.II. Não é necessário rubricar as laudas, apenas a última deverá ser assinada em qualquer modalidade de documento.III. Na elaboração do documento, o psicólogo deverá basear suas informações na observância dos princípios da Declaração Universal dos Direitos Humanos.IV. O processo de avaliação psicológica deve ignorar que as questões de ordem psicológica possuem determinações históricas, sociais e políticas.", "e": "Está correto o que se afirma em:", "alt": {"A": "nenhuma das afirmações.", "B": "apenas uma das afirmações.", "C": "apenas duas das afirmações.", "D": "apenas três das afirmações.", "E": "todas as afirmações."}, "g": "A", "j": "Nenhuma das quatro afirmacoes esta correta - todas contrariam a Res CFP 007/2003 sobre linguagem, rubrica de laudas, principios eticos e dimensoes historico-sociais da avaliacao."}, {"id": "594784", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "A Resolução CFP n° 012/2005 regulamenta o atendimento psicoterapêutico e outros serviços psicológicos mediados por computador. Porém, o atendimento psicoterapêutico, por ser uma prática ainda não reconhecida pela Psicologia, pode ser utilizado em caráter experimental, desde que sejam garantidas as seguintes condições, exceto que:", "alt": {"A": "faça parte de projeto de pesquisa conforme critérios dispostos na Resolução 196/96, do Conselho Nacional de Saúde do Ministério da Saúde, e resoluções específicas do Conselho Federal de Psicologia para pesquisas com seres humanos em Psicologia.", "B": "haja cobrança de honorários seguindo os valores de referência nacional de honorários dos psicólogos em (R$) atualizados pelo INPC (índice Nacional de Preços ao Consumidor).", "C": "esteja garantido que o usuário possa, a qualquer momento, desistir de participar da pesquisa.", "D": "quando da publicação de resultados da pesquisa, seja mantido o sigilo sobre a identidade do usuário.", "E": "o psicólogo pesquisador se comprometa a seguir as recomendações técnicas e aquelas relativas à segurança e criptografia reconhecidas internacionalmente."}, "g": "B", "j": "Res CFP 012/2005: o atendimento psicoterapeutico em carater experimental NAO pode envolver cobranca de honorarios - a alternativa B contraria essa exigencia."}, {"id": "594774", "d": "psicologia", "a": ["Políticas Públicas no ECA", "Psicologia e Políticas Públicas de Proteção e Promoção à Saúde"], "ano": "2012", "org": "CFP", "t": "", "e": "De acordo com a Lei n° 8.069/90, que dispõe sobre o Estatuto da Criança e do Adolescente (ECA) e dá outras providências:", "alt": {"A": "Tendo em vista que é dever do Estado e dos pais de cuidado para com a criança e o adolescente, a referida lei dispõe sobre a proteção parcial à criança e ao adolescente - fato este muito discutido quando da tramitação do projeto de lei na Câmara dos Deputados e Senado Federal.", "B": "Considera-se criança, para os efeitos da referida lei, a pessoa até doze anos de idade completos, e adolescente aquela entre doze e vinte e um anos de idade.", "C": "Nos casos expressos em lei, aplica-se excepcionalmente este estatuto às pessoas entredezoito e vinte e um anos de idade.", "D": "Considera-se criança, para os efeitos da referida lei, a pessoa até quatorze anos de idade incompletos, e adolescente aquela entre quatorze e dezoito anos de idade.", "E": "Nos casos expressos em lei, aplica-se excepcionalmente este estatuto às pessoas entre até vinte e cinco anos de idade, idade aproximada em que a pessoa se gradua em curso superior."}, "g": "C", "j": "ECA: nos casos expressos em lei, aplica-se excepcionalmente o estatuto as pessoas entre dezoito e vinte e um anos de idade (art. 2 paragrafo unico)."}, {"id": "578532", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "O Conselho Federal e os Conselhos Regionais de Psicologia\nsão:", "alt": {"A": "dotados de personalidade jurídica de direito privado,\nautonomia administrativa, constituindo, em seu\nconjunto, uma sociedade sem fins lucrativos,\ndestinados a orientar, disciplinar e fiscalizar o exercício\nda profissão de Psicólogo e zelar pela fiel observância\ndos princípios de ética e disciplina da classe.", "B": "dotados de personalidade jurídica de direito público,\nautonomia administrativa, e dependentes\nfinanceiramente dos Ministérios federais, constituindo,\nem seu conjunto, autarquias, destinados a orientar,\ndisciplinar e fiscalizar o exercício da profissão de\nPsicólogo e profissões correlatas.", "C": "dotados de personalidade jurídica de direito privado,\ndependente dos Ministérios Federais administrativa e\nfinanceiramente, constituindo, em seu conjunto, uma\nautarquia, destinados a orientar, disciplinar e fiscalizar\no exercício da profissão de Psicólogo.", "D": "dotados de personalidade jurídica de direito público,\nautonomia administrativa e financeira, constituindo,\nem seu conjunto, uma sociedade sem fins lucrativos.", "E": "dotados de personalidade jurídica de direito público,\nautonomia administrativa e financeira, constituindo,\nem seu conjunto, uma autarquia, destinados a\norientar, disciplinar e fiscalizar o exercício da profissão\nde Psicólogo e zelar pela fiel observância dos princípios\nde ética e disciplina da classe."}, "g": "E", "j": "CFP e CRPs sao dotados de personalidade juridica de direito publico, autonomia administrativa e financeira, constituindo, em seu conjunto, uma autarquia."}, {"id": "577185", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "É condição de elegibilidade para o Conselho Federal de\nPsicologia:", "alt": {"A": "Não ter sido condenado criminalmente a pena superior\na 4 (quatro) anos, em virtude de sentença judicial\ntransitada em julgado, salvo reabilitação legal.", "B": "O pleno gozo dos direitos profissionais e civis, salvo\ndireitos políticos.", "C": "A cidadania brasileira ou estrangeira de língua\nportuguesa.", "D": "Não ser candidato a cargo de Conselheiro em Conselho\nRegional, ou ocupar cargo na Diretoria do Conselho\nFederal de Psicologia ou do Conselho Regional, no\nperíodo de 3 (três) meses que anteceder à realização\ndo pleito.", "E": "Não ter sofrido penalidade por infração ao Código de\nÉtica Profissional nos últimos 2 (dois) anos."}, "g": "D", "j": "Lei 5.766/71: condicao de elegibilidade para o CFP inclui nao ser candidato a cargo no CRP ou ocupar cargo na Diretoria no periodo que antecede o pleito."}, {"id": "577183", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "Leia os enunciados abaixo. I. Aos não inscritos nos Conselhos que, mediante\nqualquer forma de publicidade, se propuserem ao\nexercício da profissão de psicólogo, serão aplicadas as\npenalidades cabíveis pelo exercício ilegal da profissão.\nII. O regime jurídico do pessoal dos Conselhos será o da\nlegislação trabalhista.\nIII. O Conselho Federal será constituído de 15 (quinze)\nmembros efetivos e 15 (quinze) suplentes, brasileiros,\neleitos por maioria de votos, em escrutínio secreto, na\nAssembleia dos Delegados Regionais.\nIV. Os presidentes do Conselho Federal e dos Conselhos\nRegionais têm qualidade para agir, mesmo\ncriminalmente, contra qualquer pessoa que infringir as\ndisposições da Lei Federal n° 5.766/71, que criou o\nConselho Federal e os Conselhos Regionais de\nPsicologia e deu outras providências e, em geral, em\ntodos os casos que digam respeito às prerrogativas, à\ndignidade e ao prestígio da profissão de psicólogo.\nAgora, aponte a alternativa correta.", "alt": {"A": "Existem apenas dois enunciados corretos.", "B": "Existe apenas um enunciado correto.", "C": "Todos os enunciados estão corretos.", "D": "Apenas um enunciado está incorreto.", "E": "Nenhum enunciado está totalmente correto."}, "g": "D", "j": "Apenas o enunciado III esta incorreto - o CFP e constituido por 9 membros efetivos e 9 suplentes, nao 15 como afirma o enunciado."}, {"id": "577182", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "À Assembleia Geral não compete:", "alt": {"A": "Por deliberação de, pelo menos 2/3 (dois terços) dos\nmembros presentes, em reunião previamente\nconvocada para esse fim, destituir o Conselho Regional\nou qualquer de seus membros, por motivo de alta\ngravidade, que atinja o prestígio, o decoro ou o bom\nnome da classe.", "B": "Eleger os membros do Conselho Regional e respectivos\nsuplentes.", "C": "Elaborar a proposta orçamentária anual, submetendo-a\nà aprovação do Conselho Federal.", "D": "Deliberar sobre questões e consultas submetidas à sua\napreciação.", "E": "Propor ao Conselho Federal anualmente a tabela de\ntaxas, anuidades e multas, bem como de quaisquer\noutras contribuições."}, "g": "C", "j": "A elaboracao da proposta orcamentaria anual e atribuicao da Diretoria/Plenario do CRP, nao da Assembleia Geral."}, {"id": "577181", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a descrição incorreta da competência ou da\nconstituição do órgão.", "alt": {"A": "O Plenário, constituído pelo conjunto dos Conselheiros,\né órgão deliberativo do Conselho Federal de Psicologia.", "B": "A Diretoria, órgão responsável pela operacionalização\nde diretrizes e decisões do Plenário, é constituída de\nPresidente, Vice-Presidente, Secretário-Geral e\nTesoureiro, eleitos pelo Plenário, na primeira reunião\nordinária de cada ano.", "C": "A Assembleia das Políticas Administrativas e\nFinanceiras (APAF) é a instância deliberativa abaixo do\nCongresso Nacional da Psicologia.", "D": "O Congresso Nacional da Psicologia (CNP) é a instância\nmáxima de deliberação, responsável por estabelecer as\ndiretrizes para a atuação do Conselho Federal e dos\nConselhos Regionais de Psicologia no triênio\nsubsequente à sua realização.", "E": "As Gerências são os órgãos deliberativos subordinados\ne imediatamente abaixo das Diretorias, auxiliando-as\nnas decisões de maior grau de importância aos\nConselhos."}, "g": "E", "j": "As Gerencias NAO sao orgaos deliberativos - sao orgaos administrativos/executivos subordinados as Diretorias."}, {"id": "575566", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "Aponte a alternativa incorreta.", "alt": {"A": "Para o bom desempenho de suas atribuições, o\nConselho Federal de Psicologia contará com assessorias\nde caráter permanente ou transitório, exercidas por\nprofissionais legalmente habilitados, escolhidos em\nfunção de sua competência e idoneidade, sendo a\nAssessoria Jurídica exemplo de caráter transitório.", "B": "Toda matéria encaminhada à apreciação do Conselho\nFederal de Psicologia é passível de transformação em\nprocesso, o que ocorrerá em decorrência de\ndeliberação de qualquer dos seus órgãos.", "C": "De qualquer decisão dos Conselhos Regionais de\nPsicologia caberá recurso para o Plenário do Conselho\nFederal de Psicologia, no prazo de 30 (trinta) dias, a\ncontar da notificação dos interessados, salvo os\nrecursos em processos eleitorais e éticos que são\nregidos por disposições próprias.", "D": "O Conselho Federal de Psicologia manterá órgãos de\ndivulgação com o objetivo de divulgar os seus atos e a\nPsicologia, como ciência e profissão, bem como os\nfatos que afetam a saúde mental da população.", "E": "É vedado ao Conselho Federal de Psicologia realizar\nmanifestações e pronunciamentos de caráter religioso."}, "g": "A", "j": "A Assessoria Juridica do CFP e de carater PERMANENTE, nao transitorio, dada a complexidade e continuidade das demandas juridicas."}, {"id": "575565", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "O Plenário, constituído pelo conjunto dos Conselheiros, é\nórgão deliberativo do Conselho Federal de Psicologia.\nCompete, dentre outras competências, privativamente ao\nPlenário:", "alt": {"A": "acompanhar e supervisionar as atividades da\nCoordenadoria Técnica.", "B": "aprovar a realização de diligências, inquéritos ou\nverificações sobre o funcionamento dos Conselhos\nRegionais de Psicologia, bem como a adoção das\nmedidas necessárias para a sua regularidade e\neficiência.", "C": "receber regularmente e avaliar os relatórios, bem\ncomo orientar as atividades desenvolvidas pelos\ndiretores, secretários e demais conselheiros em suas\nrespectivas áreas de atuação.", "D": "instituir as instruções necessárias ao funcionamento do\nConselho Federal de Psicologia e dos Conselhos\nRegionais de Psicologia.", "E": "decidir sobre a aquisição de materiais, bens e serviços,\nbem como os respectivos fornecedores, dentro dos\nlimites legais e orçamentários."}, "g": "B", "j": "Compete privativamente ao Plenario do CFP aprovar a realizacao de diligencias, inqueritos ou verificacoes sobre o funcionamento dos CRPs e medidas de regularidade."}, {"id": "575563", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale a alternativa que preenche corretamente as\nlacunas a seguir. \"Os bens imóveis do Conselho Federal de Psicologia serão\nadquiridos em qualquer parte do território nacional, por\ndeliberação de __________________ e com a aprovação\n_______________ e a Assembleia dos Delegados Regionais,\ne poderão ser cedidos sob empréstimo e exclusivamente\npara uso _______________.\"", "alt": {"A": "1/2 (metade) do Plenário; da Diretoria; de Conselho\nRegional de Psicologia", "B": "2/3 (dois terços) do Plenário; da Assembleia das\nPolíticas Administrativas e Financeiras; de Conselho\nRegional de Psicologia", "C": "2/3 (dois terços) do\nconselheiro federal", "D": "1/3 (um terço) do Plenário; da Assembleia das Políticas\nAdministrativas e Financeiras; de conselheiro federal", "E": "1/2 (metade) da Assembleia Geral; da Assembleia das\nPolíticas Administrativas e Financeiras; de Conselho\nFederal de Psicologia"}, "g": "B", "j": "Aquisicao de bens imoveis do CFP exige deliberacao de 2/3 do Plenario, aprovacao da APAF e da Assembleia dos Delegados Regionais; emprestimos somente para uso de CRP."}, {"id": "575561", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "O Conselho Federal de Psicologia é composto pelos\nseguintes órgãos abaixo, com exceção de um. Assinale-o.", "alt": {"A": "Gerências.", "B": "Plenário.", "C": "Diretoria.", "D": "Assembleia das Políticas Administrativas e Financeiras.", "E": "Congresso Nacional da Psicologia."}, "g": "A", "j": "As Gerencias nao compoem os orgaos do CFP - sao orgaos administrativos/executivos. Os orgaos sao Plenario, Diretoria, APAF e CNP."}, {"id": "512029", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Julgue  os  itens  a  seguir  sobre  a  promoção  pública  dos serviços de psicologia, e assinale a  alternativa  correta.", "alt": {"A": "O  Psicólogo  deverá  informar  publicamente:  nome  completo,  CRP,  número  de  registro,  CPF  e  Cédula  de  Identidade.", "B": "Divulgará  qualificações e  recursos  relativos  a  técnicas e  práticas  reconhecidas  ou  em  curso  de  regulamentação  pela  profissão.", "C": "Não  utilizará  o  preço  do  serviço  como  forma  de  propaganda.", "D": "Poderá  realizar  uma  previsão  taxativa  de  resultados,  se  comprovados.", "E": "Proporá atividades que sejam atribuições privativas de outras categorias profissionais do caso de clínica multidisciplinar."}, "g": "C", "j": "CEP: e vedado utilizar o preco do servico como forma de propaganda na promocao publica dos servicos psicologicos."}, {"id": "512028", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Acerca  da  atuação do  profissional  Psicólogo  em  pesquisas  e atividades  voltadas  para  a  produção  de  conhecimento  e desenvolvimento, é  incorreto afirmar que:", "alt": {"A": "Avaliará  os  riscos  envolvidos,  tanto  pelos  procedimentos  como  pela  divulgação  dos  resultados,  com  o  objetivo  de  proteger  as  pessoas,  grupos,  organizações e  comunidades envolvidas.", "B": "Garantirá  o  caráter  voluntário  da  participação  dos  envolvidos.", "C": "Os  envolvidos  participarão  das  pesquisas  e  atividades  voltadas  para  a  produção  de  conhecimento  mediante  livre consentimento.", "D": "O  anonimato  de  pessoas  e  grupos  deve  ser  garantido,  salvo  interesse manifesto destes.", "E": "Garantirá o acesso das pessoas, grupos ou organizações aos resultados das pesquisas ou estudos durante o procedimento, mas não após o encerramento."}, "g": "E", "j": "O psicologo deve garantir o acesso aos resultados das pesquisas DURANTE E APOS o encerramento - a alternativa E restringe esse direito."}, {"id": "512027", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "A  respeito  da  atuação  do  profissional  Psicólogo  no  atendimento  de  crianças,  assinale  a  alternativa  correta,  conforme  expressamente  determinado  pela  legislação  que  rege a  atuação profissional do  Psicólogo.", "alt": {"A": "Para  realizar  atendimento  eventual  de  criança,  o  Psicólogo deverá obter autorização.", "B": "Para  realizar  atendimento  não  eventual  de  criança,  adolescente  ou  interdito,  o  Psicólogo  deverá  obter  autorização  de  ao  menos  um  de  seus  responsáveis,  observadas as determinações da  legislação vigente.", "C": "O  atendimento  da  criança  exige,  necessariamente,  a  presença  dos  pais  ou  responsáveis  com  autorização  expressa  de próprio  punho.", "D": "No  caso  de  não  se  apresentar  um  responsável  legal,  o  atendimento  somente poderá  ser efetuado  se  presente  um membro do Conselho Regional de Psicologia.", "E": "O Psicólogo não se responsabilizará pelos encaminhamentos que se fizerem necessários para garantir a proteção integral da criança atendida."}, "g": "B", "j": "Para atendimento nao eventual de crianca, adolescente ou interdito, o psicologo deve obter autorizacao de pelo menos um dos responsaveis, conforme o CEP."}, {"id": "512026", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "São  vedações  expressamente  aplicadas  aos  profissionais Psicólogos, exceto:", "alt": {"A": "Praticar  ou  ser  conivente  com  quaisquer  atos  que  caracterizam  negligência,  discriminação,  exploração,  violência,  crueldade ou opressão.", "B": "Induzir  a  convicções  políticas,  filosóficas,  morais,  ideológicas,  religiosas,  de  orientação  sexual  ou  a  qualquer  tipo  de  preconceito,  quando  do  exercício  de  suas funções profissionais.", "C": "Utilizar  ou  favorecer  o  uso  de  conhecimento  e  a  utilização  de  práticas  psicológicas  como  instrumentos  de castigo,  tortura ou qualquer forma de violência.", "D": "Ter,  para  com  o  trabalho  dos  Psicólogos  e  de  outros  profissionais,  respeito,  consideração e  solidariedade,  e,  quando  solicitado,  colaborar  com  estes,  salvo  impedimento  por motivo  relevante.", "E": "Acumpliciar-se com pessoas ou organizações que exerçam ou favoreçam o exercício ilegal da profissão de Psicólogo ou de qualquer outra atividade profissional."}, "g": "D", "j": "A alternativa D descreve um DEVER (respeito, consideracao, solidariedade aos colegas), nao uma vedacao - sendo a excecao ao rol de vedacoes."}, {"id": "512025", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "É  incorreto  afirmar  que  são  deveres  dos  Psicólogos, conforme a  legislação sobre Código de  Ética:", "alt": {"A": "Assumir  responsabilidades  profissionais  somente  por  atividades  para  as  quais  esteja  capacitado  pessoal,  teórica e tecnicamente.", "B": "Prestar  serviços  psicológicos  de  qualidade,  especialmente  pro  bono,  em  condições  de  trabalho  dignas  e  apropriadas  à  natureza  desses  serviços,  utilizando  princípios,  conhecimentos  e  técnicas  reconhecidamente  fundamentados  na  ciência  psicológica,  na ética  e na  legislação  profissional.", "C": "Prestar  serviços  profissionais  em  situações  de  calamidade  pública  ou  de  emergência,  sem  visar  ao  benefício pessoal.", "D": "Estabelecer  acordos  de  prestação  de  serviços  que  respeitem  os  direitos  do  usuário  ou  beneficiário  de  serviços de  Psicologia.", "E": "Fornecer, a quem de direito, na prestação de serviços psicológicos, informações concernentes ao trabalho a ser realizado e ao seu objetivo profissional."}, "g": "B", "j": "A alternativa B esta incorreta - o CEP fala em prestar servicos de qualidade em condicoes dignas, sem especificar 'especialmente pro bono'."}, {"id": "512024", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "São  princípios  fundamentais  presentes  no  Código  de  Ética do  profissional  Psicólogo,  conforme  a  CFP  n°  10/2005  e legislação correlata, exceto:", "alt": {"A": "O  Psicólogo  baseará  seu  trabalho  no  respeito  e  na  promoção  da  liberdade,  dignidade,  igualdade,  integridade  do  ser  humano,  apoiado  nos  valores  que  embasam  a  Constituição  da  República  Federativa  do  Brasil do ano de  1988.", "B": "O  Psicólogo  trabalhará  visando  promover  a  saúde  e  a  qualidade  de  vida  das  pessoas  e  das  coletividades  e  contribuirá  para  a  eliminação  de  quaisquer  formas  de  negligência,  discriminação,  exploração,  violência,  crueldade e opressão.", "C": "O  Psicólogo  atuará  com  responsabilidade  social,  analisando  crítica  e  historicamente  a  realidade  política,  econômica,  social e cultural.", "D": "O  Psicólogo  atuará  com  responsabilidade,  por meio  do  contínuo  aprimoramento  profissional,  contribuindo  para  o  desenvolvimento  da  Psicologia  como  campo  científico de conhecimento e de prática.", "E": "O Psicólogo contribuirá para promover a universalização do acesso da população às informações, ao conhecimento da ciência psicológica, aos serviços e aos padrões éticos da profissão."}, "g": "A", "j": "Os principios fundamentais do CEP referenciam-se a Declaracao Universal dos Direitos Humanos, e nao a Constituicao de 1988 como afirma a alternativa A."}, {"id": "512023", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "A documentação  abaixo  é  indispensável  para  a  inscrição  de  pessoa  física  no  Conselho  Regional  de  Psicologia,  conforme  Resolução CFP  n° 003/2007,  exceto:", "alt": {"A": "Diploma de Psicólogo.", "B": "Certidão  de  colação  de  grau  de  curso  autorizado  pelo  órgão ministerial  competente.", "C": "Cédula de  Identidade e CPF.", "D": "Comprovantes  de  votação  da  última  eleição  ou  justificativas.", "E": "Certidão de antecedentes criminais."}, "g": "E", "j": "A Res CFP 003/2007 nao exige certidao de antecedentes criminais para a inscricao de pessoa fisica - os demais documentos sao exigidos."}, {"id": "512022", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "São  atribuições  dos  Conselhos  Regionais  de  Psicologia, conforme determinado na  Lei  n° 5.766/71, exceto:", "alt": {"A": "Organizar  seu  regimento,  submetendo-o  à  aprovação  do  Conselho  Regional  de  Psicologia,  em  Assembleia  Geral.", "B": "Orientar,  disciplinar e  fiscalizar o  exercício  da  profissão  em  sua  área  de  competência.", "C": "Zelar  pela  observância  do  Código  de  Ética  profissional,  impondo sanções pela  sua violação.", "D": "Funcionar como tribunal  regional  de ética  profissional.", "E": "Sugerir ao Conselho Federal as medidas necessárias à orientação e fiscalização do exercício profissional."}, "g": "A", "j": "Os CRPs submetem o regimento a aprovacao do CFP (e nao a propria Assembleia Geral), conforme Lei 5.766/71."}, {"id": "512021", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale  a  alternativa  em  que  não  consta  uma  das  funções da  Assembleia  Geral  de  cada  Conselho  Regional  de Psicologia,  conforme  o  Decreto  n°  79.822/77  e  legislação sobre o tema.", "alt": {"A": "Eleger os membros do  Conselho  Regional  e  respectivos  suplentes.", "B": "Aprovar  a  aquisição  e  alienação  de  bens,  cujo  valor  ultrapasse  5  (cinco)  vezes  o  valor  de  referência  da  legislação afeta.", "C": "Propor ao Conselho  Regional, semestralmente, a  tabela  de  anuidades,  taxas,  emolumentos  e  multas,  bem  como quaisquer outras contribuições.", "D": "Deliberar  sobre  questões  e  consultas  submetidas  à  sua  apreciação  pelos  Presidentes  do  Conselho  Federal  ou  Presidente do  respectivo Conselho Regional.", "E": "Destituir o Conselho Regional ou qualquer de seus membros, por motivo de alta gravidade, que atinja o decoro ou o bom nome da classe."}, "g": "C", "j": "A Assembleia Geral propoe ANUALMENTE (e nao semestralmente) a tabela de anuidades, taxas, emolumentos e multas - a alternativa C distorce a periodicidade."}, {"id": "512020", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Assinale  a  alternativa  correta  de  acordo  com  o  Decreto  n° 79.822/77  e  legislação  extravagante,  a  respeito  dos Conselhos Regionais de Psicologia.", "alt": {"A": "Os Conselhos  Federais de  Psicologia  têm  por  finalidade  orientar,  disciplinar  e  fiscalizar o  exercício  da  profissão  de  Psicólogo  e  zelar pela  fiel  observância  dos  princípios  de ética e disciplina da  classe.", "B": "Os  Conselhos  Regionais  terão  sede  e  foro  na  capital  do  Estado,  ou  de  um  dos  Estados  ou  Territórios,  a  seu  critério e conforme o número de Psicólogos da  região.", "C": "O  Conselho  Federal  será  composto  de  membros  efetivos  e  suplentes,  em  número  fixado  pelos  Conselhos Regionais de Psicologia.", "D": "O  mandato  dos  membros  dos  Conselhos  Regionais  de  Psicologia  será de 3  (três) anos.", "E": "Permite-se a reeleição dos membros dos Conselhos Regionais de Psicologia, por 2 (duas) vezes apenas."}, "g": "D", "j": "Decreto 79.822/77: o mandato dos membros dos Conselhos Regionais de Psicologia e de 3 anos."}, {"id": "509068", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "A  inscrição  no  Conselho  Regional  de  Psicologia  -  9ª Região  será  requerida  com  a  apresentação  dos  documentos  exigidos  por  Lei.  Homologada  a  inscrição  pelo  Plenário,  a  Secretaria  expedirá  a  Carteira  de  Identidade  Profissional,  que  será  entregue  ao  interessado,  em  uma  reunião  específica  para  essa  finalidade.  Em  caso  de  indeferimento,  poderá  o  interessado  recorrer  ao  Conselho  Federal  de  Psicologia  no  prazo de:", "alt": {"A": "15 dias.", "B": "7 dias.", "C": "30 dias.", "D": "45 dias.", "E": "60 dias."}, "g": "C", "j": "O prazo para recurso ao CFP em caso de indeferimento da inscricao no CRP e de 30 dias."}, {"id": "509066", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "De  acordo  com  seu  regimento  interno,  o  Conselho  Regional  de  Psicologia  da 9ª  Região  compõe-se dos  seguintes órgãos,  exceto:", "alt": {"A": "Plenário.", "B": "Comitê de  Ética  em  Pesquisa.", "C": "Diretoria.", "D": "Assembléias.", "E": "Congresso."}, "g": "B", "j": "O Comite de Etica em Pesquisa nao compoe os orgaos do CRP-09. Os orgaos sao Plenario, Diretoria, Assembleias e Congresso (regional)."}, {"id": "509065", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "De  acordo  com  a  Lei  nº  5.766,  dentre  as  penas  aplicáveis  por  infrações  disciplinares,  está  prevista  suspensão  do  exercício profissional  por até:", "alt": {"A": "30  (trinta)  dias.", "B": "60  (sessenta) dias.", "C": "90  (noventa) dias.", "D": "120  (cento e vinte) dias.", "E": "180 (cento e oitenta) dias"}, "g": "A", "j": "A Lei 5.766/71 estabelece a pena de suspensao do exercicio profissional por ate 30 (trinta) dias."}, {"id": "509064", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Considere as seguintes afirmações.I.      A Assembleia  Geral  do  Conselho  Regional  de  Psicologia  da  9ª Região é  órgão  deliberativo,  sendo  composta  por  psicólogos  com  inscrição  principal  nesta  regional  e  em  pleno gozo de seus direitos. II.     As  deliberações  da  Assembleia  Geral  do  Conselho  Regional  de  Psicologia  da 9 ª Região  serão  tomadas  por  maioria  simples de votos.III.  A Assembleia  Geral  do  Conselho  Regional  de  Psicologia  da  9ª Região  reunir-se-á,  na  primeira  convocação,  com  maioria  absoluta  de  seus  integrantes,  e,  nas  convocações  subsequentes,  com  qualquer  número  de  integrantes.Levando  em  conta  o  que  dispõe  o  texto  do  Regimento  Interno  do  Conselho  Regional  de  Psicologia  da  9ª Região,  é  correto afirmar que:", "alt": {"A": "somente  I  e  II  são corretas.", "B": "somente  I  e  III  são corretas.", "C": "somente  II  e  III  são corretas.", "D": "todas são  incorretas.", "E": "todas são corretas."}, "g": "E", "j": "As tres afirmacoes sobre a Assembleia Geral do CRP-09 estao corretas conforme seu Regimento Interno (deliberativa, maioria simples, primeira convocacao com maioria absoluta)."}, {"id": "509063", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "De  acordo  com  a  Lei  nº  5.766,  o  patrimônio  do  Conselho Federal  e  dos  Conselhos  Regionais  será  constituído,  exceto por:", "alt": {"A": "Doações e  legados.", "B": "Dotações  orçamentárias  do  Poder  Público  Federal, Estadual e Municipal.", "C": "Bens e valores adquiridos.", "D": "Taxas,  anuidades,  multas  e outras  contribuições  a serem  pagas pelos profissionais.", "E": "Taxas, anuidades, multas e outras contribuições a serem pagas pelos usuários dos serviços dos Conselhos."}, "g": "E", "j": "As taxas, anuidades, multas e contribuicoes que integram o patrimonio dos Conselhos sao pagas pelos PROFISSIONAIS, e nao pelos usuarios dos servicos - a alternativa E e a excecao."}, {"id": "509061", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Assinale  a  alternativa  incorreta  de  acordo  com  o  Decreto  nº 79.888.", "alt": {"A": "Os  Conselhos  Regionais  de  Psicologia  têm  por  finalidade orientar,  disciplinar e  fiscalizar o  exercício da  profissão  de  Psicólogo  e  zelar  pela  fiel  observância  dos  princípios de ética  e disciplina  da  classe.", "B": "Os Conselhos  Regionais  terão  sede  e  foro  na  Capital  do  Estado,  ou  de  um  dos  Estados  ou  Territórios,  a  critério  do Conselho Federal.", "C": "Conselhos  Regionais  serão  compostos  de  membros  efetivos  e  suplentes,  em  número  fixado  pelo  Conselho  Federal.", "D": "Os  Conselhos  Regionais deliberarão  com  a  presença  da  maioria  simples de seus membros.", "E": "Compete aos Conselhos Regionais expedir Carteira de Identidade de Profissional."}, "g": "D", "j": "Os CRPs deliberam com a presenca da MAIORIA ABSOLUTA de seus membros, nao maioria simples como afirma a alternativa D."}, {"id": "509060", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Compete ao Conselho  Federal de Psicologia:I.      Aprovar os Regimentos dos Conselhos Regionais. II.     Exercer  função  normativa  e  baixar  atos  necessários  à  execução  da  legislação  reguladora  do  exercício  da  profissão. III.    Definir  o  limite  de  competência  do  exercício  profissional,  conforme  os  cursos  realizados  ou  provas  de  especialização  prestadas  em  escolas  ou  institutos  profissionais  reconhecidos.IV.    Elaborar  e  aprovar  o  Código  de  Ética  Profissional  do  Psicólogo.É  correto o que se afirma  em:", "alt": {"A": "todas.", "B": "somente  I,  II  e  III.", "C": "somente  II,  III  e  IV.", "D": "somente  I,  II  e  IV.", "E": "somente I e II."}, "g": "A", "j": "Todas as quatro atribuicoes (aprovar regimentos dos CRPs, exercer funcao normativa, definir limite de competencia, elaborar Codigo de Etica) sao do CFP conforme Lei 5.766/71."}, {"id": "509059", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CRP 9ª Região (GO e TO)", "t": "", "e": "Assinale  a  alternativa  que  contraria  o  disposto  pelo Decreto  nº 79.822.", "alt": {"A": "O  Conselho  Federal  e  os  Conselhos  Regionais  de  Psicologia  constituem,  em  seu  conjunto,  uma  autarquia  Federal  dotada  de  personalidade  jurídica  de  direito  público,  com  autonomia  administrativa  e  financeira,  vinculada  ao Ministério do Trabalho.", "B": "O  Conselho  Federal  de  Psicologia  tem  por  finalidade  orientar,  supervisionar  e  disciplinar  o  exercício  da  profissão de  Psicólogo,  em todo o território nacional.", "C": "O  Conselho  Federal  é  o  órgão  supremo  dos  Conselhos  Regionais,  com  jurisdição  em  todo  o  território  nacional  e sede no Distrito  Federal.", "D": "O  Conselho  Federal  será  constituído  de  9  (nove)  membros efetivos e 9  (nove)  suplentes.", "E": "O mandato dos membros do Conselho Federal será de 2 (dois) anos, permitida a reeleição por duas vezes."}, "g": "E", "j": "Decreto 79.822/77 estabelece mandato de 3 anos para membros do CFP - a alternativa E afirma 2 anos, contrariando a norma."}, {"id": "505051", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Um  paciente  de  16  anos  procura  atendimento  sem  a  autorização  de  seus  responsáveis,  que  são  contra  o  tratamento. Nesse caso, o  psicólogo deve:", "alt": {"A": "Negar-se a  atender.", "B": "Combinar  com  o  paciente  que  mais  tarde  conversará  com os  responsáveis.", "C": "Delatar os  responsáveis ao conselho tutelar.", "D": "Avisar os  responsáveis à  revelia  do  paciente.", "E": "Atender o paciente, desde que alguma autoridade competente seja comunicada."}, "g": "E", "j": "Adolescente de 16 anos pode ser atendido sem autorizacao dos responsaveis, desde que autoridade competente (Conselho Tutelar/MP) seja comunicada para garantir protecao integral."}, {"id": "505050", "d": "psicologia", "a": ["Behaviorismo", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "No  setting  terapêutico  comportamental,  o  ato  da  fala envolve:", "alt": {"A": "A história  de vida do paciente.", "B": "O núcleo ansiógeno do paciente.", "C": "A capacidade de expressão verbal.", "D": "Eventos que precedem e que seguem  a  própria  fala.", "E": "Condições ambientais"}, "g": "D", "j": "Na perspectiva comportamental (Skinner - comportamento verbal), o ato da fala envolve eventos que precedem (antecedentes) e que seguem (consequentes) a propria fala."}, {"id": "505048", "d": "psicologia", "a": ["Freud", "Teorias da Personalidade"], "ano": "2012", "org": "CFP", "t": "", "e": "Em  1937,  Freud  referia-se  ao  término  da  análise.  As seguintes  frases  são  compatíveis  com  o  pensamento  do autor, exceto:", "alt": {"A": "É  melhor  falar  em  análise  incompleta  do  que  falar  em  análise  inacabada.", "B": "A  análise  termina  quando  o  psicanalista  e  o  paciente  deixam de  reunir-se  para  as sessões de análise.", "C": "É  possível  obter,  por  intermédio  da  psicanálise,  um  meio estável de normalidade", "D": "Há  dúvidas  sobre  a  possibilidade  de  se  levar  a  análise  até o final.", "E": "Final de análise é uma questão ambígua."}, "g": "C", "j": "Em 'Analise terminavel e interminavel' (1937), Freud expressa duvidas sobre a possibilidade de obter, pela psicanalise, um meio estavel de normalidade."}, {"id": "505046", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "A  mãe  superprotetora  desenvolve  um  mecanismo  de  defesa  caracterizado como:", "alt": {"A": "Racionalização", "B": "Formação  reativa.", "C": "Sublimação.", "D": "Repressão.", "E": "Negação."}, "g": "B", "j": "A mae superprotetora desenvolve o mecanismo de defesa de formacao reativa: investe na superprotecao para mascarar impulsos hostis em relacao ao filho."}, {"id": "505045", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "As  terapias  de  insight  tendem  a  ser  mais  demoradas  e, portanto, mais caras. Nesse  caso,  convém:", "alt": {"A": "cobrar  enquanto  for  possível  e  depois  atender  sem  custos", "B": "não  começar  um  tratamento  que  o  paciente  não  terá  como continuar", "C": "esperar para ver se o  paciente  suporta os custos.", "D": "encaminhar para  um  tratamento mais barato.", "E": "orientar o paciente a buscar outros recursos econômicos."}, "g": "B", "j": "Eticamente, nao se deve comecar um tratamento de insight que o paciente nao tera condicoes financeiras de continuar - evita-se interromper processo iniciado."}, {"id": "505044", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "Quanto ao ato de o terapeuta  tomar nota  durante a  sessão, avalie as afirmativas a  seguir.I.  O  paciente  pensa  que  o  terapeuta  lhe  dá menor atenção.II.  O  paciente  pode  sentir  persecutoriedade  em  função  das anotações.III.  Caso  não  tome  nota,  o  paciente  pode  crer  que  o  terapeuta  não  está  interessado  e  não  presta  atenção  ao que é dito.IV.  O  paciente  pode  ficar  mais tranqüilo  quando  a anotação é combinada  no contrato  inicial.Pode-se afirmar que:", "alt": {"A": "somente  II  e  III  são corretas", "B": "somente  III é correta.", "C": "somente  III e  IV são corretas.", "D": "todas são  incorretas.", "E": "todas são correta"}, "g": "E", "j": "Todas as quatro afirmacoes sobre o impacto da anotacao na sessao terapeutica sao consistentes (menor atencao percebida, persecutoriedade, interesse, tranquilidade quando combinada)."}, {"id": "505043", "d": "psicologia", "a": ["Psicoterapias", "Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Teorias e Técnicas Psicoterápicas", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Um  paciente  procura  o  psicólogo  e  lhe  solicita  uma  regressão a  vidas passadas. O  psicólogo, então:", "alt": {"A": "encaminha  o  paciente  a  um  profissional  que  acredita  em vidas passadas.", "B": "convence o paciente a  tratar da vida  presente.", "C": "aceita o atendimento para ver o que pode acontecer.", "D": "avisa  o  paciente  que  não  atenderá  por  não  acreditar  em vidas passadas.", "E": "informa ao paciente que não se trata de técnica fundamentada na ciência psicológica."}, "g": "E", "j": "Conforme o CEP, o psicologo deve informar ao paciente que a regressao a vidas passadas nao e tecnica fundamentada na ciencia psicologica."}, {"id": "505040", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "São manifestações de contratransferência, exceto:", "alt": {"A": "Tentativa  de  moldar  o  paciente  a  partir  de  uma  imagem  idealizada.", "B": "Incapacidade  do  terapeuta  de  atuar  como  instrumento  perceptivo.", "C": "Comentar os atrasos do paciente.", "D": "Juntar seus próprios  conflitos ao material  trazido  pelo  paciente", "E": "Manifestação de admiração por qualidades do paciente."}, "g": "C", "j": "Comentar os atrasos do paciente e tecnica adequada (interpretacao), nao manifestacao de contratransferencia. As demais sao manifestacoes contratransferenciais."}, {"id": "505039", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas", "Psicologia da Saúde", "Doenças Crônico-Degenerativas"], "ano": "2012", "org": "CFP", "t": "", "e": "É  função  do  psicólogo  no  tratamento  de  paciente  com  HIV  na  fase terminal de tratamento:", "alt": {"A": "Evitar  informações técnicas sobre o desenlace", "B": "Buscar manter o astral do paciente.", "C": "Oferecer  ao  paciente  informações  necessárias  para  a  solução de problemas posteriores", "D": "Deixar aos familiares o manejo da  situação terminal.", "E": "Abster-se de manifestação quanto à ajuda religiosa"}, "g": "C", "j": "E funcao do psicologo no tratamento de paciente com HIV terminal oferecer informacoes necessarias para a solucao de problemas posteriores (preparacao da familia, decisoes, etc.)."}, {"id": "505034", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "Na  condução  do  contrato  terapêutico,  em  abordagem  com enfoque dinâmico, o terapeuta  não deve:", "alt": {"A": "Avaliar  a  necessidade  e  a  dor  do  paciente  que  o  procura.", "B": "Já  no  telefonema,  fazer  uma  pesquisa  ampla  sobre  a  vida do paciente.", "C": "Procurar atendê-lo o mais  rápido  possível.", "D": "Ser  claro  quanto  á  disponibilidade  de  horário  para  atendê-lo.", "E": "Ficar atento ao movimento transferenciai do paciente."}, "g": "B", "j": "Na conducao do contrato terapeutico em abordagem dinamica, o terapeuta NAO deve fazer pesquisa ampla sobre a vida do paciente ja no telefonema - tal aproximacao deve ocorrer no setting."}, {"id": "505032", "d": "psicologia", "a": ["Freud", "Teorias da Personalidade"], "ano": "2012", "org": "CFP", "t": "", "e": "No trabalho Algumas  lições elementares de psicanálise,  Freud descreve a  consciência  como  sendo apenas:", "alt": {"A": "Quantidade de energia mental, e  inconstante.", "B": "A forma do psíquico e,  além  do mais,  numa manifestação  inconstante", "C": "Uma  característica  do  que  é  psíquico  e,  além  do  mais,  como uma qualidade  inconstante.", "D": "A  quantidade  do  atributo  do  que  é  psíquico  e,  além  do  mais,  uma  quantidade  inconsistente.", "E": "Uma qualidade ou atributo do que é psíquico e, além do mais, uma qualidade inconstante."}, "g": "E", "j": "Freud (Algumas licoes elementares de psicanalise): descreve a consciencia como uma qualidade ou atributo do que e psiquico e, alem disso, uma qualidade inconstante."}, {"id": "505030", "d": "psicologia", "a": ["Saúde Mental", "Psicologia da Saúde", "Luta Antimanicomial"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  preenche  correta  e  respectivamente  as  lacunas  a  seguir  referente  a  afirmação  apresentada  na  III  Conferência  de Saúde Mental.Os ____________   infanto-juvenis  ou  outros  dispositivos  de base  territorial  devem  ter  como  uma  de  suas  prioridades  de ação  os  projetos  de  ________________  de  crianças  e adolescentes  internados em manicômios ou  abrigos  públicos,  filantrópicos ou  privados.", "alt": {"A": "CAPS,  desinstitucionalização", "B": "núcleos escolares,  inserção ao trabalho", "C": "órgãos públicos,  não  inserção", "D": "modos de ação, desinstitucionalização", "E": "Representantes, não inserção"}, "g": "A", "j": "III Conferencia de Saude Mental: os CAPS infanto-juvenis devem priorizar projetos de desinstitucionalizacao de criancas e adolescentes internados."}, {"id": "505028", "d": "psicologia", "a": ["Psicologia da Saúde", "Processo Saúde-Doença"], "ano": "2012", "org": "CFP", "t": "", "e": "Foram  observados  cinco  estágios  no  processo  de  decisão  e procrastinação  na  busca  por  tratamento.  Assinale  a alternativa  correta que descreve tais estágios.", "alt": {"A": "Demora  na  avaliação,  demora  na  aceitação  da  doença,  demora  comportamental,  demora  na  marcação  de  consulta e demora  no tratamento.", "B": "Percepção  inadequada  dos  sintomas,  avaliação  superficial,  dificuldades  no  relacionamento,  atenção  focalizada e análise  inadequada  dos sintomas.", "C": "Avaliação  superficial,  demora  comportamental,  percepção  inadequada  dos  sintomas,  demora  no  tratamento e atenção focalizada.", "D": "Negação,  cólera,  negociação, depressão e aceitação", "E": "Percepção superficial do problema, atenção focalizada, motivação inadequada, demora na marcação de consulta e aceitação"}, "g": "A", "j": "Os cinco estagios do processo de decisao e procrastinacao na busca por tratamento sao: demora na avaliacao, aceitacao da doenca, comportamental, marcacao de consulta e tratamento."}, {"id": "505026", "d": "psicologia", "a": ["Terapia Cognitivo Comportamental", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  preenche  correta  e  respectivamente  as  lacunas  a  seguir,  quanto  aos  fatores  do  contrato na  terapia  cognitiva.Participação______ nas  sessões,  na  avaliação  d o ______,  no estabelecimento  d a _____,  na  escolha  das  tarefas  de  casa  e na  avaliação da_____.", "alt": {"A": "ativa,  humor,  agenda  e sessão", "B": "presente,  afeto,  cognição e afetividade", "C": "adequada,  afeto,  agenda,  afetividade", "D": "neutra,  humor,  cognição e sessão", "E": "constante, afeto, cognição e sessão"}, "g": "A", "j": "Terapia cognitiva (Beck): participacao ATIVA do paciente nas sessoes, avaliacao do HUMOR, estabelecimento da AGENDA, escolha das tarefas e avaliacao da SESSAO."}, {"id": "505025", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Teoria Familiar Sistêmica"], "ano": "2012", "org": "CFP", "t": "", "e": "Em  relação  ao  atendimento  psicoterapêutico  de  famílias,  o psicólogo  deve  ficar  atento  às  principais  indicações  e contraindicações. Trata-se de  uma  contraindicação quando:", "alt": {"A": "O  problema  atual  envolve  dois  ou  mais  membros  da  família", "B": "Uma  criança ou  adolescente for o problema  presente", "C": "Há  ruptura  da  harmonia  familiar  devido  a  conflitos  interpessoais", "D": "A  família  passa  por  uma  situação  de  crise  de  transição  que pode  levá-la  à  ruptura.", "E": "Existem problemas individuais que necessitam previamente de atendimento."}, "g": "E", "j": "E contraindicacao para terapia familiar quando existem problemas individuais que necessitam previamente de atendimento - a alternativa E descreve essa contraindicacao."}, {"id": "505020", "d": "psicologia", "a": ["Psicoterapias", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "Como  critérios  de  seleção  de  pacientes  para  tratamento focal,  temos:", "alt": {"A": "Transtornos  de  início  recente,  patologia  de  caráter  leve,  força  e  plasticidade  do  ego  em  bom  estado,  alta  motivação  para  o  tratamento,  capacidade  de  insight,  determinação e boa  delimitação focal desde o  início.", "B": "Ausência  de  alterações  de  caráter,  condições  de  flexibilidade  superegóica,  alta  escolaridade,  empatia,  motivação  para  desafios,  baixa  aderência  a  tratamento  psicofarmacológico e tolerância  à  frustração.", "C": "Condições  de  flexibilidade  superegóica,  alta  escolaridade,  motivação  para  o  tratamento,  capacidade  de  insight,  determinação e  boa  delimitação  focal  desde o  início e apresentar sofrimento neurótico", "D": "Sofrimento  psíquico  intenso,  histórico  de  dificuldades  interpessoais  freqüentes,  patologia  de  caráter  leve,  generalização  das  dificuldades  em  distintos  contextos,  motivação  moderada  e  alterações  na  expressão  de  afetos.", "E": "Força e plasticidade do ego em bom estado, empatia, motivação para desafios, baixa aderência a tratamento grupai, moderada tolerância à frustração, labilidade afetiva, flexibilidade superegóica e escolaridade superior à média."}, "g": "A", "j": "Criterios para tratamento focal: transtornos de inicio recente, patologia de carater leve, ego em bom estado, alta motivacao, capacidade de insight e boa delimitacao focal."}, {"id": "505019", "d": "psicologia", "a": ["Teorias e Técnicas Psicoterápicas", "Grupos Terapêuticos"], "ano": "2012", "org": "CFP", "t": "", "e": "São  contraindicações  para  a  realização  de  psicoterapia  de grupo  para  alcoolistas:", "alt": {"A": "Intoxicados  ou  pouco  convictos  quanto  à  abstinência,  pessoa  de  reconhecimento  público  e  funcionamento  psicótico.", "B": "Com  histórico  de  abandono  de  tratamento,  pouco  convictos ou  intoxicados e funcionamento borderline.", "C": "Com  funcionamento  neurótico,  sem  histórico  de  abandono  de  tratamento  e  alcoolista  há  mais  de  quinze  anos.", "D": "Histórico  de  alcoolismo  recente,  sem  relações  afetivas  estáveis e baixa escolaridade.", "E": "Com funcionamento psicótico, ausência de abandono de tratamento e com histórico de dificuldades de relacionamento afetivo"}, "g": "A", "j": "Contraindicacoes para grupo de alcoolistas: intoxicados ou pouco convictos quanto a abstinencia, pessoa com reconhecimento publico e funcionamento psicotico."}, {"id": "505018", "d": "psicologia", "a": ["Avaliação Psicológica", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "Segundo  Arzeno,  um  psicodiagnóstico  clínico  completo  e corretamente administrado permite:", "alt": {"A": "Caracterizar  a(s)  psicopatologia(s)  mais  expressiva(s)  identificadas no examinando.", "B": "Estimar  o  prognóstico  do  caso  e  a  estratégia  mais  adequada de atendimento", "C": "Entender  a  dinâmica  do  funcionamento  mental  inconsciente.", "D": "Obter dados com objetivo de um diagnóstico nosológico.", "E": "Identificar os sintomas que o examinando apresenta"}, "g": "B", "j": "Arzeno: o psicodiagnostico clinico completo permite estimar o prognostico do caso e definir a estrategia mais adequada de atendimento."}, {"id": "505017", "d": "psicologia", "a": ["Testes Psicológicos - Testes Psicométricos e Testes Projetivos", "Psicodiagnóstico e Avaliação Psicológica"], "ano": "2012", "org": "CFP", "t": "", "e": "Para  a  composição  de  uma  bateria  de  testes  num  psicodiagnóstico  clínico,  diversos  fatores  são  determinantes.  Segundo Arzeno, quais são esses fatores?", "alt": {"A": "O  solicitante,  a  idade  do  examinando,  o  nível  cultural  do  avaliando,  a  existência  de  possíveis  deficiências,  o  momento vital,  o  contexto  espaço  temporal  da  avaliação  e os elementos a  investigar da  personalidade.", "B": "Os  dados  pregressos  do  avaliando,  as  dificuldades identificadas,  as  características do  grupo  familiar,  o tempo  disponível  para  avaliação,  a  idade  e  sexo,  o  momento vital e a escolaridade do examinando.", "C": "A  idade  e  sexo  do  examinando,  a  disponibilidade  de instrumentos  projetivos,  o  tempo disponível  para  a avaliação,  os  elementos  da  personalidade  a  serem  investigados,  os  dados  pregressos  do  avaliando  e  as  características do grupo familiar.", "D": "O  solicitante,  a  disponibilidade  de  instrumentos projetivos,  o  tempo  disponível para  a  avaliação,  os elementos  da  personalidade  a  serem  investigados,  a  idade e  sexo,  o momento vital  e  a  existência  de  possíveis  deficiências.", "E": "As normas estabelecidas pelos CFP, as dificuldades identificadas, as características do grupo familiar, o tempo disponível para avaliação, a experiência do profissional com as técnicas, a idade e a escolaridade do examinando."}, "g": "A", "j": "Arzeno: na elaboracao de uma bateria de testes deve-se considerar o solicitante, idade, nivel cultural, deficiencias, momento vital, contexto espaco-temporal e elementos de personalidade."}, {"id": "505015", "d": "psicologia", "a": ["Psicanálise", "Teorias e Técnicas Psicoterápicas"], "ano": "2012", "org": "CFP", "t": "", "e": "Assinale  a  alternativa  que  preenche  correta  e  respectivamente as  lacunas a  seguir. Enquanto  mecanismo  de  defesa,  o(a) manifesta- se  pela  separação  dos  processos  mentais  nas  partes  que  os  compõem,  cuja  conexão entre essas  partes e o  conhecimento  ________ está  bloqueada.", "alt": {"A": "sublimação,  inconsciente", "B": "isolamento,  inconsciente", "C": "projeção,  consciente", "D": "isolamento,  consciente", "E": "deslocamento, inconsciente"}, "g": "D", "j": "O isolamento e o mecanismo de defesa que separa processos mentais, bloqueando a conexao consciente entre as partes (afeto separado da representacao)."}, {"id": "360757", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "De  acordo  com  o  Decreto  Federal  nº  79.822/77,  a  extinção ou  perda  do  mandato  de  membro  do  Conselho  Federal  e dos Conselhos Regionais não ocorrerá:", "alt": {"A": "pelo  comprovado  exaurimento  de  suas  atividades  e  funções como conselheiro.", "B": "por destituição da Assembleia  dos Delegados  Regionais  ou  da Assembleia Geral do Conselho Regional.", "C": "por  condenação  a  pena  superior  a  2  (dois)  anos  em  virtude de sentença  transitada  em julgado.", "D": "por  ausência,  sem  motivo  justificado,  a  5  (cinco)  reuniões,  consecutivas ou  intercaladas, em  cada  ano.", "E": "por superveniência de causa de que resulte o cancelamento da inscrição."}, "g": "A", "j": "Decreto 79.822/77: 'exaurimento de suas atividades' nao e causa prevista de extincao/perda de mandato. As demais alternativas listam causas previstas."}, {"id": "360756", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "Os membros dos  Conselhos  Regionais,  efetivos e  suplentes,  serão  brasileiros,  eleitos  pelos  profissionais  inscritos  na  respectiva  área  de  ação,  em  escrutínio  secreto  pela  forma  estabelecida  em  Regimento.  Sobre  esse  assunto,  assinale  a  alternativa  correta.", "alt": {"A": "O mandato dos membros dos Conselhos  Regionais  será  de 2  (dois) anos,  permitida  a  reeleição  uma vez.", "B": "Em  cada  ano,  na  primeira  reunião,  cada  Conselho  Regional  elegerá  seu  Presidente  e  Vice-Presidente,  Secretário  e Tesoureiro,  cujas  atribuições  serão  fixadas  no  respectivo Regimento.", "C": "Apenas  pessoas  ou  entidades  comprovadamente  ligadas  à  psicologia  poderão  representar  ao  Conselho  Regional  contra o  registro de  um  candidato.", "D": "Se  o  Conselho  Regional  indeferir o  pedido  de  inscrição,  o  candidato  terá  direito  de  recorrer  ao  próprio  Conselho  Regional  dentro  do  prazo  fixado  em  Regimento.", "E": "Aceita a inscrição, ser-lhe-á expedida pelo Conselho Federal a Carteira de Identidade Profissional, onde serão feitas anotações relativas à atividade do portador."}, "g": "B", "j": "Em cada ano, na primeira reuniao, cada Conselho Regional elegera seu Presidente, Vice-Presidente, Secretario e Tesoureiro, conforme o Decreto 79.822/77."}, {"id": "360755", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Resoluções do Conselho Federal de Psicologia"], "ano": "2012", "org": "CFP", "t": "", "e": "Constituem  a  Assembleia  Geral  de  cada  Conselho  Regional  os  psicólogos  nele  inscritos,  em  pleno  gozo  de  seus direitos  e  que  tenham,  na  respectiva  jurisdição,  a  sede  principal  de  sua  atividade  profissional.  Assim  sendo,  leia  as  proposições  a  seguir que tratam do assunto. I.  À  Assembleia  Geral  compete  propor  ao  Conselho  Federal  anualmente  a  tabela  de  taxas,  anuidades  e  multas,  bem  como de quaisquer outras contribuições. II.  A  Assembleia  Geral  deverá  reunir-se  ordinariamente,  pelo menos,  uma vez por ano, exigindo-se,  em  primeira  convocação  o  quórum  da  maioria  absoluta  de  seus  membros. III.  A  Assembleia  Geral  poderá  reunir-se  extraordinariamente  a  pedido  justificado  de,  pelo  menos,  1/3  (um  terço)  de  seus  membros  ou  por  iniciativa  do  Presidente  do  Conselho  Regional  respectivo. IV.  À  Assembleia  Geral  compete  eleger  os  membros  do  Conselho Regional e  respectivos suplentes. V.  À  Assembleia  Geral  compete  por  deliberação  de,  pelo  menos,  2/3  (dois  terços)  dos  membros  presentes,  em  reunião  previamente  convocada  para  esse  fim,  destituir  o  Conselho  Regional  ou  qualquer  de  seus  membros,  por  motivo  de  alta  gravidade,  que  atinja  o  prestígio, o decoro ou  o  bom  nome da  classe. Está  correto o que se afirma  em:", "alt": {"A": "apenas um  inciso.", "B": "apenas dois  incisos.", "C": "apenas três  incisos.", "D": "apenas quatro  incisos.", "E": "todos os incisos."}, "g": "E", "j": "Todos os cinco incisos correspondem corretamente as competencias e regras da Assembleia Geral do CRP previstas no Decreto 79.822/77."}, {"id": "360753", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "Aponte  a  assertiva  incorreta  a  respeito  dos  processos disciplinares.", "alt": {"A": "O  processo  disciplinar  ordinário  apurará  infringência  a  resoluções de natureza  administrativa  e cível.", "B": "A  pena  a  ser  aplicada  nos  processos  disciplinares  ordinários  no  processamento  de  infração  cometida  por  pessoa  física  inscrita  no  Conselho  Regional  de  Psicologia  será  de  advertência,  multa  no  valor  de  0,5  (meia)  a  5  (cinco)  anuidades,  tendo  como  referência  a  anuidade  praticada  pelo  Conselho  Regional  no  exercício  em  que  esta  vier  a  ser  imposta,  ou  censura  pública.", "C": "Na  aplicação  da  pena,  o  Plenário  do  Conselho  Regional  de  Psicologia  considerará  em  cada  caso,  dentre  outros  fatores,  a  individualidade da  pena.", "D": "Em  caso  de  reincidência,  o  valor  da  multa  será  dobrado,  sem  prejuízo  das  demais  penas  previstas  em  lei.", "E": "A pena a ser aplicada nos processos disciplinares ordinários no processamento de infração cometida por pessoa jurídica será de multa, no valor de 0,5 (meia) a 5 (cinco) anuidades, tendo como referência a anuidade praticada pelo Conselho Regional, no exercício em que esta vier a ser imposta, suspensão temporária das atividades, ou cassação do registro ou cadastramento."}, "g": "A", "j": "O processo disciplinar ordinario apura infringencia ao Codigo de Etica - nao a resolucoes de natureza administrativa e civel. A alternativa A esta incorreta."}, {"id": "360752", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Legislação de Psicologia - Outras Normas"], "ano": "2012", "org": "CFP", "t": "", "e": "Segundo  o  transcrito  na  Lei  Federal  nº  5.766/71,  não  constitui  infração disciplinar:", "alt": {"A": "Transgredir preceito do Código de  Ética  Profissional.", "B": "Exercer  a  profissão  quando  impedido  de  fazê-lo,  ou  facilitar,  por  qualquer  meio,  o  seu  exercício  aos  não  inscritos ou  impedidos.", "C": "Praticar,  no  exercício  da  atividade  profissional  ou  fora  dela,  ato que a  lei defina  como  ilícito civil.", "D": "Não  cumprir  no  prazo  estabelecido,  determinação  emanada  do  órgão  ou  autoridade  dos  Conselhos,  em  matéria  da  competência  destes,  depois  de  regularmente notificado.", "E": "Deixar de pagar aos Conselhos, pontualmente, as contribuições a que esteja obrigado."}, "g": "C", "j": "A Lei 5.766/71 nao tipifica como infracao disciplinar a pratica de ilicito civil fora do exercicio profissional - a alternativa C extrapola o ambito da norma."}, {"id": "360750", "d": "psicologia", "a": ["Legislação de Psicologia e Resoluções do Conselho Federal de Psicologia", "Código de Ética Profissional do Psicólogo (Resolução CFP Nº 10/05)"], "ano": "2012", "org": "CFP", "t": "", "e": "O  psicólogo  poderá  intervir  na  prestação  de  serviços psicológicos  que  estejam  sendo  efetuados  por  outro profissional  nas seguintes situações, exceto:", "alt": {"A": "a  pedido do profissional  responsável  pelo serviço.", "B": "quando  se  tratar  de  trabalho  multiprofissional  e  a  intervenção fizer parte da metodologia  adotada.", "C": "quando  informado  expressamente,  por  qualquer  uma  das  partes,  da  interrupção  voluntária  e  definitiva  do  serviço.", "D": "quando  detectar  e  entender,  em  função  do  espírito  de  solidariedade,  e  de  modo  construtivo,  que  deverá  agir  para  melhorar  a  situação  do  paciente  pertencente  ao  profissional  responsável.", "E": "em caso de emergência ou risco ao beneficiário ou usuário do serviço, quando dará imediata ciência ao profissional."}, "g": "D", "j": "O CEP nao autoriza intervir em servico de outro profissional por mero 'espirito de solidariedade' - as hipoteses sao taxativas (pedido do responsavel, multiprofissional, interrupcao informada, emergencia/risco)."}, {"id": "3756353", "d": "servico_social", "a": ["Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A análise das relações sociais, orientada pela perspectiva\nda totalidade, exige compreender que a exploração de\nclasse se articula de forma indissociável às determinações\nétnico‑raciais. A partir dessa informação, assinale a opção\ncorreta, no que diz respeito aos estudos sobre raça e etnia\nno serviço social.", "alt": {"A": "A raça é uma condição biológica, validada pelas\nciências naturais, que indica uma origem comum.", "B": "Para os movimentos negros e antirracistas, a supressão\nda categoria raça é imprescindível para a superação\ndo racismo e do preconceito racial.", "C": "O conceito de etnia é sinônimo do conceito de raça.", "D": "É fundamental que conste nos formulários e nos\ndocumentos dos serviços públicos e de atendimento\nà população o quesito cor, e que este seja preenchido\na partir da percepção visual do atendente sobre o\nfenótipo do cidadão.", "E": "A dinâmica de reprodução do capitalismo\nfrequentemente apoia‑se na reconfiguração\ndo racismo, que assume novas formas, como a\nsubstituição da segregação institucionalizada e do\nracismo oficial por uma postura de indiferença em\nface da igualdade racial sob o manto da democracia."}, "g": "E", "j": "A dinamica de reproducao do capitalismo apoia-se na reconfiguracao do racismo, substituindo a segregacao oficial por indiferenca em face da igualdade racial sob o manto da democracia."}, {"id": "3756352", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Saúde"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "O Caderno Parâmetros para a Atuação de Assistentes\nSociais na Saúde (2009) tem como objetivo apresentar\ndiretrizes para a atuação dos profissionais de serviço social\nna área de saúde. Com base nessa informação, assinale a\nopção que apresenta uma atribuição do assistente social na\nárea da saúde, conforme as diretrizes desse documento.", "alt": {"A": "identificar a situação socioeconômica e familiar\ndos usuários com vistas à construção do perfil\nsocioeconômico para possibilitar a formulação de\nestratégias de intervenção", "B": "solicitação e regulação de ambulância para remoção\ne alta", "C": "identificação de vagas em outras unidades nas\nsituações de necessidade de transferência hospitalar", "D": "convocação do responsável para informar sobre alta\ne óbito", "E": "montagem de processo e preenchimento de\nformulários para viabilização de tratamento fora\nde domicílio (TFD), medicação de alto custo e\nfornecimento de equipamentos (órteses, próteses e\nmeios auxiliares de locomoção)"}, "g": "A", "j": "Conforme Parametros para Atuacao de Assistentes Sociais na Saude (2009): identificar a situacao socioeconomica e familiar dos usuarios para formular estrategias de intervencao e atribuicao do assistente social."}, {"id": "3756351", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "No que diz respeito à história e aos fundamentos\nteórico‑metodológicos do serviço social, assinale a\nopção correta.", "alt": {"A": "O IV Congresso Brasileiro de Assistentes Sociais,\nconhecido como Congresso da Ruptura, foi um marco\nfundamental na recusa do conservadorismo e a favor\nda renovação histórico‑crítica da profissão.", "B": "Os seminários de Araxá e de Teresópolis são\nimportantes marcos na tentativa de rompimento com\no serviço social tradicional e conservador.", "C": "A Escola de Serviço Social da Universidade Católica\nde Minas Gerais diverge dos rumos do movimento de\nreconceituação latino‑americano e constrói o projeto\nacadêmico Método BH, com o objetivo de fortalecer o\nserviço social tradicional.", "D": "A necessidade de atribuir um estatuto científico ao\nserviço social e a politização da ação profissional,\nsolidária com a libertação dos oprimidos e\ncomprometida com a transformação social são\nalguns dos eixos fundamentais do movimento\nde reconceituação.", "E": "O movimento de reconceituação do serviço social no\nBrasil representou uma reafirmação dos rumos da\nprofissão, consolidando‑se por meio de uma vertente\nhegemônica marcada pelo pragmatismo e pelo\nracionalismo instrumental."}, "g": "D", "j": "O movimento de reconceituacao do servico social tem como eixos fundamentais a atribuicao de estatuto cientifico, a politizacao da acao e a solidariedade com a libertacao dos oprimidos."}, {"id": "3756350", "d": "servico_social", "a": ["Saúde"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "A respeito da Política de Saúde no Brasil, assinale a\nopção que apresenta o princípio do Sistema Único\nde Saúde (SUS) que expressa que os serviços de\nsaúde devem ser estruturados de maneira que haja\numa ordenação da prestação de acordo com as\ndemandas apresentadas.", "alt": {"A": "universalidade", "B": "descentralização", "C": "hierarquização", "D": "integralidade", "E": "regionalização"}, "g": "C", "j": "O principio da hierarquizacao do SUS estrutura os servicos de saude por niveis de complexidade, ordenando a prestacao conforme as demandas apresentadas."}, {"id": "3756348", "d": "servico_social", "a": ["Trabalho e Serviço Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção correta no que se refere à temática\nquestão social, segundo a perspectiva crítica do serviço\nsocial.", "alt": {"A": "No modo de produção capitalista, a pobreza,\nenquanto expressão da questão social, resulta da má\ndistribuição da riqueza socialmente produzida.", "B": "O desenvolvimento do capitalismo e das forças\nprodutivas impulsiona a criação de postos de trabalho\ne a incorporação da força de trabalho disponível,\nresultando na redução do desemprego e da\namenização da questão social.", "C": "A questão social é concebida como a marginalização\ndos indivíduos que permanecem fora do mercado de\ntrabalho, constituindo‑se, portanto, em um fenômeno\nde exclusão social.", "D": "As desigualdades sociais são fenômenos naturais ao\ndesenvolvimento das relações sociais, o que implica\nafirmar que a questão social esteve presente em\noutros modos de produção.", "E": "Historicamente, as lutas sociais deslocaram a questão\nsocial do âmbito privado das relações capital‑trabalho\npara a esfera pública, exigindo a intervenção estatal\npara o reconhecimento e a legalização de direitos e\ndeveres dos sujeitos envolvidos."}, "g": "E", "j": "Historicamente, as lutas sociais deslocaram a questao social do ambito privado das relacoes capital-trabalho para a esfera publica, exigindo intervencao estatal e legalizacao de direitos."}, {"id": "3748446", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Quanto à elaboração e à execução de projetos sociais,\nassinale a opção correta.", "alt": {"A": "O primeiro passo para elaborar um projeto social\né assegurar a existência de recursos ou fontes de\nfinanciamento para a sua concretização.", "B": "O projeto é uma setorização do plano, sendo\nrecomendado que tenha um ciclo de vida de cinco a\noito anos.", "C": "Os objetivos específicos apontam a direção do\nprojeto, devem ser qualitativos e indicar as ações e as\natividades para serem alcançados.", "D": "As metas são unidades de medida – quantitativas\nou qualitativas – que servem para informar em qual\nmedida os objetivos de um projeto foram alcançados,\ndentro de um prazo delimitado de tempo.", "E": "Os resultados esperados são essenciais na estrutura\nmetodológica de um projeto social, porque explicitam\no estado em que se espera chegar a partir do\nproblema posto inicialmente, após a estratégia de\nintervenção proposta."}, "g": "E", "j": "Os resultados esperados sao essenciais na estrutura metodologica de um projeto social, pois explicitam o estado em que se espera chegar a partir do problema posto inicialmente."}, {"id": "3748444", "d": "servico_social", "a": ["Políticas Sociais", "Saúde"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Conforme Correia (2018), a efetivação do controle social\nna área de saúde é limitada. A partir dessa informação,\nassinale a opção que apresenta corretamente os motivos\ndessa limitação.", "alt": {"A": "pela não transparência das informações e pela\nmanipulação de dados epidemiológicos", "B": "pela composição bipartite do conselho e pela\nrepresentatividade política das entidades\nrepresentadas pelos usuários", "C": "pelo desconhecimento do papel a ser desempenhado\npelo conselheiro e por o conselho ser um órgão\ndeliberativo", "D": "pelo uso de artifícios contábeis no manuseio dos\nrecursos do Fundo da Saúde e pela imparcialidade e\nneutralidade desse espaço político", "E": "pelo corporativismo dos conselheiros e pela defesa\ndos interesses coletivos dos usuários da saúde"}, "g": "A", "j": "Correia (2018): a efetivacao do controle social na saude e limitada pela nao transparencia das informacoes e pela manipulacao de dados epidemiologicos."}, {"id": "3748436", "d": "servico_social", "a": ["Saúde"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Em relação ao processo de trabalho do assistente social na\nárea da saúde, assinale a opção correta.", "alt": {"A": "O plantão é realizado pelos assistentes sociais na\natenção terciária, em hospitais, e é caraterizado como\numa atividade pensada, planejada e organizada que\nbusca atender, de forma humanizada, aos problemas\napresentados pelos usuários.", "B": "O assistente social é o trabalhador da assistência\nsocial na saúde.", "C": "O serviço social tem a sua legitimidade na área da\nsaúde a partir das contradições da política de saúde. É\njustamente nas lacunas resultantes da não efetivação\ndo SUS que o assistente social tem sido requisitado\na intervir.", "D": "São demandas legítimas do serviço social na área de\nsaúde resolver os problemas dos usuários com alta\nmédica que apresentam dificuldade de autonomia, a\nexemplo: idosos sem acompanhantes; população em\nsituação de rua; e pacientes psiquiátricos em situação\nde abandono.", "E": "O assistente social deve priorizar ações focais\nindividuais, sem prejuízo das ações coletivas, para\npotencializar a autonomia, o empoderamento e a\ncidadania dos usuários."}, "g": "C", "j": "O servico social tem legitimidade na area da saude a partir das contradicoes da politica de saude e das lacunas resultantes da nao efetivacao do SUS."}, {"id": "3748433", "d": "servico_social", "a": ["Pensamento Social"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção correta acerca da concepção de família,\nconsiderando a perspectiva crítica marxista.", "alt": {"A": "A família é compreendida como um complexo social\nque deverá assumir os impactos advindos das\ndeterminações da lei geral da acumulação capitalista.", "B": "A família é compreendida como objeto de intervenção\nprofissional do assistente social, sendo o exercício\nprofissional direcionado às relações familiares, com\nvistas à sua transformação por meio de orientação e\nsocialização de informações.", "C": "A família é concebida como a base da sociedade,\nsendo compreendida como núcleo central para\na formação social dos sujeitos. Dessa forma, as\npráticas profissionais devem ser direcionadas para o\nfortalecimento dos vínculos familiares.", "D": "As expressões da questão social vivenciadas pelas\nfamílias são interpretadas como decorrentes\nda desestruturação familiar e de problemas\ncomportamentais de seus membros.", "E": "A categoria trabalho possibilita compreender as\nmediações que explicam os fundamentos da família\ne de sua particularidade no capitalismo, pois foi o\ntrabalho que, historicamente, determinou as relações\nsociais entre os indivíduos."}, "g": "E", "j": "Perspectiva marxista: a categoria trabalho possibilita compreender as mediacoes que explicam os fundamentos da familia e sua particularidade no capitalismo."}, {"id": "2397461", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais", "Pensamento Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa que apresenta a concepção teórica que concebe as políticas sociais enquanto processo e resultado de relações complexas e contraditórias que ocorrem entre sociedade civil e Estado, na arena da luta  de classes.", "alt": {"A": "idealismo", "B": "funcionalismo", "C": "fenomenologia", "D": "marxismo", "E": "positivismo"}, "g": "D", "j": "O marxismo concebe as politicas sociais como processo e resultado de relacoes contraditorias entre sociedade civil e Estado, na arena da luta de classes."}, {"id": "2397459", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa que apresenta um princípio do Welfare State.", "alt": {"A": "meritocracia", "B": "universalidade dos serviços sociais", "C": "livre concorrência", "D": "desregulamentação das relações econômicas e sociais pelo Estado", "E": "Estado mínimo"}, "g": "B", "j": "A universalidade dos servicos sociais e principio caracteristico do Welfare State (Estado de Bem-Estar Social)."}, {"id": "2397457", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal"], "ano": "2024", "org": "CRESS", "t": "", "e": "A respeito da temática de política social, assinale a alternativa correta, segundo o debate crítico do serviço social realizado por Behring e Boschetti (2007).", "alt": {"A": "As políticas sociais, no ideário neoliberal, são caracterizadas pelo trinômio: privatização; focalização; e desconcentração.", "B": "A privatização na seara das políticas públicas compõe um movimento de transferências monetárias para a esfera privada, sendo uma medida necessária e positiva, pois promove a geração de empregos e a circulação do capital.", "C": "A seletividade associada à focalização das políticas sociais assegura acesso apenas aos usuários que comprovem a extrema pobreza.", "D": "A refilantropização das políticas sociais, conceito cunhado por Yazbek, refere‑se à parceria realizada entre o Estado e o terceiro setor, para garantir o acesso da população aos direitos sociais.", "E": "Historicamente, as políticas econômicas são subordinadas e submissas às políticas sociais."}, "g": "C", "j": "Behring e Boschetti (2007): as politicas sociais no ideario neoliberal sao caracterizadas pelo trinomio privatizacao, focalizacao e desconcentracao."}, {"id": "2397446", "d": "servico_social", "a": ["Instrumentalidade do Serviço Social", "Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta quanto ao debate do serviço social a respeito da autonomia profissional.", "alt": {"A": "Tanto a autonomia profissional quanto a autonomia técnica são relativas, pois ambas estão submetidas às imposições e às determinações do trabalho e da correlação de forças institucionais.", "B": "O assistente social – na condição de empregado, servidor, contratado – deve sujeitar‑se às normativas administrativas, burocráticas e estruturais que interferem em sua opinião técnica e na escolha dos instrumentais, das técnicas e dos métodos no exercício profissional.", "C": "O domínio das dimensões teórico‑metodológica, ético‑política, técnico‑operativa, somado ao conhecimento de legislações trabalhistas e que regulamentam e normatizam a profissão são elementos fundamentais para a ampliação da autonomia no espaço de trabalho.", "D": "No Brasil, o serviço social é regulamentado como profissão liberal, o que indica que o assistente social é um profissional autônomo, com autonomia plena no exercício de suas atividades e dispõe do total controle das condições materiais, organizacionais e técnicas necessárias para o exercício profissional.", "E": "O assistente social, por estar inserido em uma relação de compra e venda de sua força de trabalho, não possui autonomia profissional."}, "g": "C", "j": "O dominio das dimensoes teorico-metodologica, etico-politica e tecnico-operativa, somado ao conhecimento de legislacoes, e fundamental para ampliar a autonomia profissional."}, {"id": "2397445", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Instrumentalidade do Serviço Social"], "ano": "2024", "org": "CRESS", "t": "", "e": "No processo de formação do assistente social é necessária a capacitação teórico‑metodológica, ético‑política e técnico‑operativa. Considerando essa informação, assinale a alternativa que apresenta um propósito que esse profissional deve alcançar com o desenvolvimento dessas capacidades profissionais.", "alt": {"A": "descrever a formação histórica e os processos sociais contemporâneos que conformam a sociedade brasileira", "B": "conhecer o desenvolvimento do capitalismo no País", "C": "memorizar o processo histórico de desenvolvimento do serviço social no Brasil", "D": "apreender criticamente o processo histórico  como totalidade", "E": "reproduzir as formas de intervenção já consolidadas na profissão"}, "g": "D", "j": "A capacitacao teorico-metodologica, etico-politica e tecnico-operativa visa a apreender criticamente o processo historico como totalidade."}, {"id": "2397438", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2024", "org": "CRESS", "t": "", "e": "Horst, Araújo e Costa (2023) afirmam que as requisições indevidas se apresentam por meio de atividades, práticas e serviços que não se relacionam com as normativas da profissão. Considerando essa informação, assinale a alternativa que apresenta as requisições indevidas, de acordo com os autores supracitados.", "alt": {"A": "São exemplos de requisições indevidas: declaração de hipossuficiência; agendamento de consultas e exames; atividades administrativas; intermediação de visitas do Poder Judiciário e orientação aos usuários sobre os direitos sociais.", "B": "As requisições indevidas encaminhadas ao serviço social são um fenômeno novo e que surgiu com o agravamento das expressões da questão social devido à pandemia da covid‑19.", "C": "Foram identificados três perfis de profissionais perante as requisições indevidas: o primeiro que, ciente dos princípios ético‑políticos da profissão, recusa o atendimento de tais demandas; o segundo que, por desconhecimento dos princípios ético‑políticos, realiza o atendimento das demandas sem questionar, e o terceiro que, ciente do Código de Ética, atende qualquer demanda encaminhada para agradar o patronato.", "D": "Toda requisição indevida remete, necessariamente, a uma infração dos princípios fundamentais expressos no Código de Ética.", "E": "A elaboração do projeto de trabalho profissional e sua divulgação, juntamente à instituição, à equipe de trabalho e à população usuária do serviço social, é uma importante estratégia para minimizar as requisições indevidas."}, "g": "E", "j": "Horst, Araujo e Costa (2023): a elaboracao do projeto de trabalho profissional e sua divulgacao a instituicao, equipe e usuarios e estrategia para minimizar requisicoes indevidas."}, {"id": "2397428", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2024", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta a respeito da elaboração do projeto de trabalho profissional do assistente social.", "alt": {"A": "O projeto de trabalho deve ser fiel ao projeto institucional, uma vez que deve contemplar o atendimento irrestrito às demandas e requisições da instituição empregadora.", "B": "A identificação, a delimitação e a justificativa do objetivo institucional é um elemento do projeto  de trabalho.", "C": "O projeto de trabalho é um instrumento norteador da ação profissional, visto ser um manual que contém os objetivos institucionais, as estratégias metodológicas para o alcance desses objetivos e os recursos necessários para a intervenção profissional.", "D": "O projeto de trabalho deve apontar como o assistente social se coloca ante as demandas da população, como pretende atendê‑las e como a população pode exercer o controle do trabalho a ser executado.", "E": "O contrato de trabalho é o instrumento jurídico‑legal primordial para subsidiar a elaboração do projeto  de trabalho."}, "g": "D", "j": "O projeto de trabalho do assistente social deve apontar como ele se coloca ante as demandas da populacao, como pretende atende-las e como a populacao pode exercer o controle do trabalho."}, {"id": "2363738", "d": "servico_social", "a": ["Saúde", "Serviço Social e Atenção Básica e Secundária"], "ano": "2023", "org": "FSNH", "t": "", "e": "Assinale a alternativa que constitui uma das prioridades\nbásicas do pacto pela saúde.", "alt": {"A": "fortalecimento da atenção básica", "B": "fortalecimento da atenção secundária", "C": "fortalecimento da atenção terciária", "D": "controle do câncer colorretal", "E": "controle do câncer de tireoide"}, "g": "A", "j": "Uma das prioridades basicas do Pacto pela Saude e o fortalecimento da atencao basica, conforme as diretrizes do SUS."}, {"id": "2081323", "d": "servico_social", "a": ["Serviço Social na Educação", "Política Educacional"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Considerando o contexto social e as relações que são estabelecidas no ambiente escolar, assinale a alternativa correta.", "alt": {"A": "A fim de disseminar o respeito às diferenças culturais nas relações, todos os profissionais da comunidade escolar devem pautar suas ações na valorização da diversidade, como princípio do Estado brasileiro democrático e laico, independentemente de suas crenças pessoais.", "B": "Atitudes de intolerância e violência nas relações são sempre facilmente identificáveis. Sendo assim, a formação continuada dos profissionais da instituição de ensino, relacionada a temas como diversidade cultural, gênero e raça, não se faz indispensável para que eles identifiquem e atuem de maneira ética diante de tais atitudes.", "C": "O profissional que tiver conhecimento da ocorrência de violência física deverá comunicar a autoridade escolar para que sejam tomadas as providências cabíveis. No entanto, outras formas de violência, como psicológica, sexual, moral ou simbólica, não são passíveis de tal comunicação.", "D": "O bullying é a agressão física ou psicológica que ocorre repetitiva e intencionalmente, de modo a ridicularizar, humilhar e intimidar a vítima. É importante que os profissionais da escola reconheçam o bullying como forma de violência, pois isso simboliza um marco no respeito às diferenças. Não obstante a identificação do bullying pela escola, os pais ou responsáveis dos alunos são os únicos que possuem legitimidade para tomar as medidas necessárias contra esse tipo de violência.", "E": "O fenômeno da violência nas escolas, amplamente divulgado pelas mídias, atesta a crescente falência da autoridade da instituição escolar. Esse contexto demanda que o assunto seja tratado, exclusivamente, pela inserção policialesca no âmbito escolar, de modo prioritário e urgente, a fim de coibir a violência."}, "g": "A", "j": "Os profissionais da comunidade escolar devem pautar suas acoes na valorizacao da diversidade, principio do Estado democratico e laico, independentemente de suas crencas pessoais."}, {"id": "2081322", "d": "servico_social", "a": ["Serviço Social na Educação", "Educação e Serviço Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Quanto aos preconceitos e às práticas discriminatórias no \nâmbito escolar, assinale a alternativa correta.", "alt": {"A": "O debate sobre questões de gênero na escola, embora possa contribuir para o combate ao sexismo e ao machismo na sociedade, não guarda consonância com os princípios constitucionais da igualdade.", "B": "As correlações entre as mídias sociais, a violência urbana e o uso de drogas ilícitas ou lícitas devem ser debatidas no âmbito escolar, a fim de estimular a consciência crítica e o protagonismo dos estudantes para promover mudanças positivas na sociedade.", "C": "Embora a escola possa tomar conhecimento da ocorrência de violência doméstica na família de alunos, tal problema não diz respeito à instituição de ensino e seus profissionais não devem adotar nenhum tipo de providência nesses casos, pois a questão da violência doméstica é de responsabilidade exclusiva dos pais ou responsáveis.", "D": "A diversidade cultural não se mostra como tema a ser tratado no âmbito escolar. Por exemplo, diferenças culturais relacionadas a religião não devem ser consideradas pelos profissionais da comunidade escolar em suas relações cotidianas com os estudantes.", "E": "A homofobia, o sexismo, o racismo e a intolerância religiosa são temas controversos que dizem respeito a crenças individuais, isto é, não são construídos social e historicamente. Diante disso, a escola não deve debatê-los nem considerá-los nas relações sociais do ambiente escolar, de modo a respeitar as diferenças nesse sentido."}, "g": "B", "j": "As correlacoes entre midias sociais, violencia urbana e uso de drogas devem ser debatidas na escola para estimular consciencia critica e protagonismo dos estudantes."}, {"id": "2081316", "d": "servico_social", "a": ["Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A respeito da Constituição da República Federativa do Brasil \nde 1988, assinale a alternativa incorreta.", "alt": {"A": "A educação, a saúde, a alimentação, o trabalho, a moradia, o transporte, o lazer, a segurança, a previdência social, a proteção à maternidade e à infância e a assistência aos desamparados são direitos sociais estabelecidos pela Constituição.", "B": "O salário mínimo é estabelecido pela Constituição Federal de 1988 como direito dos trabalhadores urbanos e rurais, com o intuito de atender às suas necessidades vitais básicas e às de sua família (moradia, alimentação, educação, saúde, lazer, vestuário, higiene, transporte e previdência social), e terá reajustes periódicos que lhe preservem o poder aquisitivo.", "C": "Como forma de proteger os direitos dos trabalhadores, é facultativa a participação dos sindicatos nas negociações coletivas de trabalho.", "D": "Todos os trabalhadores brasileiros têm direito à assistência gratuita, em creches e pré-escolas, para seus filhos e dependentes, desde o nascimento até cinco anos de idade.", "E": "A educação, direito de todos, visa à qualificação da pessoa para o trabalho, para o exercício da cidadania e para seu pleno desenvolvimento. É dever do Estado e da família e será promovida e incentivada por toda a sociedade."}, "g": "C", "j": "A CF/1988 estabelece a participacao OBRIGATORIA dos sindicatos nas negociacoes coletivas de trabalho - a alternativa C diz facultativa, contrariando a Constituicao."}, {"id": "2069802", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Acerca da Política de Seguridade Social, assinale a alternativa\ncorreta.", "alt": {"A": "No Brasil, a Política de Seguridade Social foi\ninfluenciada pelo modelo norueguês bismarckiano e\npelo modelo inglês keynesiano.", "B": "A seguridade social brasileira, instituída com a\nConstituição brasileira de 1988, restringiu a\nprevidência aos trabalhadores contribuintes,\nuniversalizou a saúde e ampliou a educação,\ntornando-a pública e gratuita.", "C": "Quanto mais a Política de Seguridade Social se\naproxima da lógica do seguro social, maior é a\nacessibilidade de direitos e benefícios da população\nbrasileira.", "D": "Algumas das diretrizes constitucionais da Política de\nSeguridade Social são: a universalidade da cobertura e\ndo atendimento; a uniformidade e a equivalência dos\nbenefícios e serviços às populações urbanas e rurais; e\na seletividade e a distributividade na prestação dos\nbenefícios e serviços.", "E": "Um dos marcos da instauração da Política de\nSeguridade Social no Brasil foi a Lei Estácio de Sá, em\n1930, que previa o acesso às políticas de previdência e\nde saúde apenas para os contribuintes da previdência\nsocial."}, "g": "D", "j": "As diretrizes constitucionais da Seguridade Social incluem universalidade da cobertura, uniformidade/equivalencia entre populacoes urbanas e rurais, e seletividade/distributividade na prestacao."}, {"id": "2069793", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Serviço Social na América Latina"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A respeito da formação profissional dos assistentes sociais no\nBrasil e na América Latina, assinale a alternativa correta.", "alt": {"A": "Os anos 1940 foram um marco histórico no que se\nrefere ao debate sobre os fundamentos do serviço\nsocial no Brasil. A teoria social crítica (de tradição\nmajoritariamente marxista) norteou o projeto\nacadêmico-profissional da profissão no País desde\nentão, tendo como núcleo a compreensão da história a\npartir da luta das classes sociais.", "B": "A trajetória do serviço social latino-americano é\ncaracterizada pela absoluta carência de críticas teóricas\nsubstantivas ao serviço social clássico e a seus\nprincipais formuladores e por seus vínculos teóricos e\npráticos com o conservadorismo. Não obstante esse\nhistórico, percebe-se que, na atualidade, a crítica aos\nfundamentos do serviço social de caso, do serviço\nsocial de grupo e do serviço social de comunidade não\nse faz necessária, tendo em vista a total superação\ndesses fundamentos na prática profissional.", "C": "O nascimento do serviço social no Brasil foi marcado\npela interlocução privilegiada com o pensamento social\ncatólico e conservador europeu, em estreita\naproximação com as concepções estruturais e\nfuncionalistas difundidas nas ciências sociais e\nhumanas norte-americanas, incorporando rudimentos\nda psicanálise.", "D": "A construção coletiva da formação acadêmica no\nserviço social brasileiro não foi permeada pela defesa\nda universidade pública, gratuita e de qualidade, nem\nbaseada na realidade regional e nacional ou\ndirecionada aos interesses da coletividade. Assim, as\ndiretrizes curriculares visam à função pública da\nuniversidade, priorizando a ampliação do acesso ao\nensino em instituições particulares e a modalidade de\nensino a distância.", "E": "As diretrizes curriculares atualmente vigentes no Brasil\ndefinem a capacitação teórico-metodológica e\nético-política como formalidade opcional para o\nexercício das atividades técnico-operativas da\nprofissão."}, "g": "C", "j": "O nascimento do servico social no Brasil foi marcado pela interlocucao com o pensamento social catolico e conservador europeu, em aproximacao com concepcoes funcionalistas e rudimentos da psicanalise."}, {"id": "2053918", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2023", "org": "IIER", "t": "", "e": "Na área de planejamento, o documento mais abrangente e\ngeral, que contém estudos, análises situacionais ou\ndiagnósticos, é denominado", "alt": {"A": "plano.", "B": "programa.", "C": "planificação.", "D": "projeto.", "E": "projeto de intervenção."}, "g": "A", "j": "Na area de planejamento, o plano e o documento mais abrangente e geral, contendo estudos, analises situacionais ou diagnosticos."}, {"id": "2053917", "d": "servico_social", "a": ["Serviço Social e Equipe Multi e Interdisciplinar"], "ano": "2023", "org": "IIER", "t": "", "e": "A interdisciplinaridade é um elemento que pode estar\npresente na atuação em equipe interprofissional.\nConsiderando as características de uma prática interdisciplinar,\nassinale a alternativa correta.", "alt": {"A": "Trata-se de interações superficiais, sem aprofundamento\npara o desenvolvimento de um objetivo ou finalidade.", "B": "Há uma horizontalização das relações entre as\ndisciplinas e a existência de um diálogo mais próximo e\nminucioso entre as profissões.", "C": "Não existe avanço de fronteiras disciplinares: cada\ndisciplina permanece isolada.", "D": "A prática interdisciplinar cria um novo campo teórico\nde disciplinas mais amplas.", "E": "Há uma quebra de todas as barreiras do conhecimento\nque irá fundir as disciplinas em algo que transcenda a\ntodas, uma fusão."}, "g": "B", "j": "A pratica interdisciplinar caracteriza-se pela horizontalizacao das relacoes entre as disciplinas e por um dialogo mais proximo e minucioso entre as profissoes."}, {"id": "2053916", "d": "servico_social", "a": ["Pesquisa em Serviço Social"], "ano": "2023", "org": "IIER", "t": "", "e": "Acerca da pesquisa em processos de investigação social,\nassinale a alternativa correta.", "alt": {"A": "A hipótese é um elemento obrigatório na construção\nde um projeto de pesquisa.", "B": "O questionário é um instrumento que, necessariamente,\nexige o contato pesquisador-entrevistado, no\nmomento de sua aplicação.", "C": "A pesquisa qualitativa visa a coletar informações\nquantificáveis, que expressem concepções e o universo\nde significados e valores, convertendo-os em variáveis\noperacionalizadas.", "D": "A ordenação dos dados, a classificação e a posterior\nanálise são etapas importantes do tratamento dos\ndados coletados em uma pesquisa.", "E": "Toda investigação inicia-se com uma justificativa."}, "g": "D", "j": "A ordenacao dos dados, a classificacao e a posterior analise sao etapas importantes do tratamento dos dados coletados em uma pesquisa."}, {"id": "2053913", "d": "servico_social", "a": ["Previdência Social"], "ano": "2023", "org": "IIER", "t": "", "e": "A previdência social é uma política de caráter contributivo.\nPara ter acesso aos benefícios e aos direitos expressos pela\npolítica de previdência social, é necessário que o trabalhador", "alt": {"A": "contribua com, pelo menos, um mês de pagamento\npara o Fundo de Garantia por Tempo de Serviço.", "B": "esteja vinculado a um trabalho formal.", "C": "contribua com, no mínimo, dezoito parcelas para o\nInstituto Nacional do Seguro Social (INSS).", "D": "mantenha a qualidade de segurado.", "E": "mantenha-se apto para o trabalho."}, "g": "D", "j": "Para acessar os beneficios da previdencia social, o trabalhador deve manter a qualidade de segurado."}, {"id": "2053911", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2023", "org": "IIER", "t": "", "e": "Boschetti (2009), no artigo intitulado Avaliação de políticas, programas e projetos sociais, evidencia a importância de se\nrealizar a avaliação das políticas sociais, situando-a e\ncompreendo-a enquanto um fenômeno social complexo e\ncontraditório, imerso no processo de produção e reprodução\nsocial. A autora destaca a importância de se conhecer o\nquadro institucional que conforma essa política e, para isso,\napresenta três elementos de análise, que são", "alt": {"A": "o financiamento, a relação custo-benefício e a\ndiversidade regional.", "B": "a gestão, os interesses político-partidários e os\nobjetivos propostos.", "C": "o público-alvo, o financiamento e a correlação de\nforças.", "D": "os direitos e benefícios estabelecidos e assegurados, o\nfinanciamento e a gestão e o controle social\ndemocrático.", "E": "as relações de poder, os direitos e benefícios\nestabelecidos e a governabilidade."}, "g": "D", "j": "Boschetti (2009): os tres elementos de analise sao direitos e beneficios estabelecidos/assegurados, financiamento e gestao, e controle social democratico."}, {"id": "2053910", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal"], "ano": "2023", "org": "IIER", "t": "", "e": "Com base na perspectiva crítica, assinale a alternativa correta\nquanto aos estudos sobre política social no serviço social.", "alt": {"A": "A política social é vista exclusivamente como\nmecanismo de favorecimento do capital, tanto do\nponto de vista econômico quanto do ponto de vista\npolítico.", "B": "Na perspectiva fenomenológica, a política social é\ncompreendida como resultado de contradições\nestruturais engendradas pela luta de classes e\ndelimitadas pelos processos de valorização do capital.", "C": "Segundo o keynesianismo, a política social é residual e\nsoluciona apenas o que não pode ser enfrentado pela\nvia do mercado, da comunidade e da família.", "D": "Uma das tendências da política social na\ncontemporaneidade é o desdobramento do sistema de\nproteção social, de forma que, para os segmentos\npopulacionais que dispõem de alguma renda, haja a\nprivatização e a mercantilização dos serviços a que\npodem recorrer; para os segmentos mais\npauperizados, há serviços públicos de baixa qualidade.", "E": "Os ciclos econômicos, considerados como um\nmovimento natural e previsível da economia, ditam as\npossibilidades e os limites da política social."}, "g": "D", "j": "Tendencia da politica social contemporanea: para segmentos com renda, privatizacao e mercantilizacao; para os mais pauperizados, servicos publicos de baixa qualidade."}, {"id": "2053909", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social"], "ano": "2023", "org": "IIER", "t": "", "e": "Em relação às características do início do serviço social no\nBrasil, assinale a alternativa correta.", "alt": {"A": "A profissão apresenta um caráter de apostolado\nfundado em uma abordagem da “questão social” como\nproblema moral e religioso e em uma intervenção que\nprioriza a formação da família e do indivíduo para a\nsolução dos problemas e o atendimento de suas\nnecessidades materiais, morais e sociais.", "B": "Os referenciais orientadores do pensamento e da ação\ndo emergente serviço social tem sua fonte na Doutrina\nSocial da Igreja e na filosofia teocrática de Santo\nAgostinho.", "C": "O serviço social formula os primeiros objetivos políticos\ne sociais, orientando‐se por posicionamentos de cunho\nhumanista fundamentados na teoria conservadora e\nno ideário liberal.", "D": "Os princípios filosóficos que orientam o serviço social\nem seus primórdios são a noção de dignidade da\npessoa humana, sua imperfectibilidade, a natural\ninteligência do homem e a igualdade.", "E": "No início dos anos 1930, o serviço social começa a ser\ntecnificado, a partir do contato com o serviço social\nnorte-americano, fundamentado pela teoria social\nfuncionalista."}, "g": "A", "j": "O servico social no Brasil inicia com caracter de apostolado, abordando a 'questao social' como problema moral e religioso, priorizando a formacao da familia e do individuo."}, {"id": "2053905", "d": "servico_social", "a": ["Instrumentalidade do Serviço Social", "Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2023", "org": "IIER", "t": "", "e": "O exercício profissional configura-se pela articulação das\ndimensões ético-política, teórico-metodológica, técnico-operativa\ne crítico-investigativa, que capacitam o assistente social a dar\nrespostas às demandas da sociedade. Quanto a essas\ndimensões, assinale a alternativa correta.", "alt": {"A": "A dimensão teórica refere-se à capacidade do\nassistente social de criar estratégias e táticas de\nintervenção.", "B": "Existem instrumentos e técnicas próprios a cada\ndireção teórica, ou seja, existe uma relação direta entre\ninstrumentos e teorias.", "C": "A dimensão investigativa remete às competências\ninstrumentais e responde a questões como “Para que\nfazer?”, “Para quem fazer?”, “O que fazer?” e “Como\nfazer?”.", "D": "A dimensão ético-política envolve projetar a ação em\nfunção dos valores e das finalidades do profissional, da\ninstituição e da população.", "E": "O agir profissional deve ser sucedido de reflexões sobre\no direcionamento e a intencionalidade da intervenção\ne sobre os valores que impregnam as ações do serviço\nsocial."}, "g": "D", "j": "A dimensao etico-politica envolve projetar a acao em funcao dos valores e das finalidades do profissional, da instituicao e da populacao."}, {"id": "2053904", "d": "servico_social", "a": ["Serviço Social no campo sócio jurídico"], "ano": "2023", "org": "IIER", "t": "", "e": "A seara denominada resolução apropriada de disputas é\nconstituída por uma série de métodos capazes de solucionar\nconflitos, entre os quais se destacam a mediação e a\nconciliação. No que se refere a esses métodos, assinale a\nalternativa correta", "alt": {"A": "A mediação visa à resolução do conflito, ao passo que\na conciliação busca apenas o acordo entre as partes.", "B": "A conciliação é um processo autocompositivo simples\ne direto, com uma comunicação voltada à persuasão.", "C": "A conciliação é um processo com a participação\nfacultativa ou voluntária dos envolvidos, ao passo que,\nna mediação, a participação é obrigatória.", "D": "A mediação é um processo autocompositivo, segundo\no qual as partes em disputa são auxiliadas por uma\nterceira parte, denominada árbitro, que tem a função\nde estudar os argumentos e influenciar o processo\ndecisório.", "E": "A decisão final, tanto na mediação quanto na\nconciliação, é dada pelo conciliador e(ou) mediador,\nque, ao verificar a impossibilidade de composição entre\nas partes, poderá decretar o fim da atividade."}, "g": "A", "j": "A mediacao visa a resolucao do conflito (transformacao da relacao), enquanto a conciliacao busca apenas o acordo entre as partes."}, {"id": "2053900", "d": "servico_social", "a": ["Saúde", "Serviço Social e Saúde do Trabalhador"], "ano": "2023", "org": "IIER", "t": "", "e": "É atribuição dos centros de referência em saúde do\ntrabalhador (CEREST)", "alt": {"A": "desempenhar as funções de suporte técnico, de\neducação permanente e de coordenação de projetos\nde promoção, vigilância e assistência à saúde dos\ntrabalhadores, no âmbito da sua área de abrangência.", "B": "executar as ações de saúde do trabalhador na atenção\nprimária em saúde, nos serviços especializados e nos\nserviços de urgência e emergência.", "C": "alocar recursos orçamentários e financeiros para a\nimplementação da Política Nacional do Trabalhador e\nda Trabalhadora.", "D": "realizar fóruns nacionais de saúde do trabalhador, com\nperiodicidade quadrienal.", "E": "aplicar advertência e multa para as organizações que\ninfringirem os dispositivos da Política Nacional do\nTrabalhador e da Trabalhadora."}, "g": "A", "j": "E atribuicao dos CEREST desempenhar funcoes de suporte tecnico, educacao permanente e coordenacao de projetos de promocao, vigilancia e assistencia a saude dos trabalhadores."}, {"id": "2053899", "d": "servico_social", "a": ["Saúde", "Trabalho e Serviço Social", "Transformações Societárias, mundo do trabalho e Estado capitalista", "Serviço Social e Saúde do Trabalhador", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2023", "org": "IIER", "t": "", "e": "Segundo Lourenço, [p]ensar a saúde do trabalhador exige um\nesforço intelectual e político para compreender as relações\nsociais de trabalho, bem como a especificidade do processo e\nda organização e gestão do trabalho na atual conjuntura. Em\nrelação à saúde do trabalhador diante das mudanças na\nprodução, na organização e na gestão do trabalho, assinale a\nalternativa correta.", "alt": {"A": "A individualização do trabalho configura um fator\nprotetivo ao adoecimento no mundo do trabalho.", "B": "Um dos fatores que contribuem para a maior incidência\ndo processo de adoecimento no trabalho é a\nprogressiva diminuição ou ausência de controle dos\ntrabalhadores sobre o processo de trabalho.", "C": "A expansão da terceirização diminuiu a incidência de\ncasos de lesões por esforços repetitivos/distúrbios\nosteomuscularesrelacionados ao trabalho (LER/Dort) e\nde transtornos mentais.", "D": "As doenças relacionadas ao trabalho, como LER/Dort, e\nos agravos relacionados à saúde mental apresentam\nsintomas e expressões fáceis de serem mensurados e\nquantificados.", "E": "A saúde do trabalhador é o campo de conhecimento\nque objetiva estudar o processo saúde/doença no\ntrabalho, abarcando apenas os trabalhadores que\nadquirem doenças nesse processo."}, "g": "B", "j": "Um dos fatores que contribuem para o adoecimento no trabalho e a progressiva diminuicao ou ausencia de controle dos trabalhadores sobre o processo de trabalho."}, {"id": "2053898", "d": "servico_social", "a": ["Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal", "Trabalho e Serviço Social", "Transformações Societárias, mundo do trabalho e Estado capitalista"], "ano": "2023", "org": "IIER", "t": "", "e": "A reestruturação produtiva e a mundialização do capital\ntrouxeram profundas alterações no mundo do trabalho. A\nrespeito desse assunto, assinale a alternativa correta.", "alt": {"A": "Quanto mais forte a legislação protetora do trabalho e\na organização sindical, maior será o grau de\nprecarização das condições de trabalho.", "B": "A nova gestão do trabalho, advinda com as inovações\nda reestruturação produtiva, propõe metas\nalcançáveis, com a preservação da qualidade de vida do\ntrabalhador, e propicia um envolvimento espontâneo e\nvoluntário dos trabalhadores com os ideais das\nempresas.", "C": "Os trabalhadores pertencentes ao núcleo que atua com\no maquinário mais avançado, dotado de maior\ntecnologia, são menos expostos à flexibilização e à\nintensificação do ritmo de suas atividades.", "D": "O liberalismo, associado aos fenômenos do fordismo e\nda financeirização do capital, deu origem à\nreestruturação produtiva.", "E": "A expansão da reestruturação produtiva tem como\nconsequências a flexibilização, a informalidade e a\nprofunda precarização das condições de trabalho e de\nvida da classe trabalhadora brasileira."}, "g": "E", "j": "A reestruturacao produtiva tem como consequencias a flexibilizacao, a informalidade e a profunda precarizacao das condicoes de trabalho e de vida da classe trabalhadora."}, {"id": "2053896", "d": "servico_social", "a": ["Assessoria e Consultoria em Serviço Social"], "ano": "2023", "org": "IIER", "t": "", "e": "No que se refere à assessoria e à consultoria em serviço\nsocial, com fundamento nos estudos realizados por Matos,\nassinale a alternativa correta.", "alt": {"A": "A supervisão é considerada como um exemplo de\nassessoria em serviço social.", "B": "Uma das frentes de assessoria em serviço social é a\norganização política dos usuários.", "C": "A prática intervencionista é a principal característica da\nassessoria.", "D": "Toda contratação de assistente social, sem vínculo\nempregatício, para a prestação de serviços, por tempo\ndeterminado, em organizações empregadoras,\npúblicas e privadas, é considerada como assessoria em\nserviço social.", "E": "O primeiro ponto a ser tratado pelo assessor é a\noperacionalização das demandas iniciais dos\nassessorandos."}, "g": "B", "j": "Segundo Matos, uma das frentes de assessoria em servico social e a organizacao politica dos usuarios."}, {"id": "2053895", "d": "servico_social", "a": ["Saúde", "Serviço Social e Saúde do Trabalhador"], "ano": "2023", "org": "IIER", "t": "", "e": "Quanto à Política Nacional de Saúde do Trabalhador e da\nTrabalhadora, assinale a alternativa correta.", "alt": {"A": "Um dos princípios e das diretrizes da Política Nacional\nde Saúde do Trabalhador e da Trabalhadora é a\nprecaução.", "B": "Para ter acesso aos direitos assegurados pela Política\nNacional de Saúde do Trabalhador e da Trabalhadora,\né necessário que o trabalhador possua vínculo\nempregatício formal.", "C": "A Política Nacional de Saúde do Trabalhador e da\nTrabalhadora tem como finalidade a execução das\nações de saúde do trabalhador, com ênfase na\nrecuperação dos agravos advindos do trabalho.", "D": "Um dos objetivos da Política Nacional de Saúde do\nTrabalhador e da Trabalhadora é a revisão periódica da\nlista de doenças relacionadas ao trabalho.", "E": "Cabe ao Conselho Tripartite de Saúde do Trabalhador e\nda Trabalhadora desempenhar as funções de suporte\ntécnico, de educação permanente e de coordenação de\nprojetos de promoção, vigilância e assistência à saúde\ndos trabalhadores, no âmbito nacional."}, "g": "A", "j": "A precaucao e um dos principios e diretrizes da Politica Nacional de Saude do Trabalhador e da Trabalhadora (Portaria 1.823/2012)."}, {"id": "1979312", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Em relação aos fundamentos teóricos-metodológicos do\nserviço social, assinale a alternativa correta.", "alt": {"A": "As fontes dos referenciais orientadores do pensamento\ne da ação emergente do serviço social são a doutrina\nsocial da Igreja Católica, o Iluminismo e o pensamento\nde Santo Agostinho.", "B": "A gênese do serviço social no Brasil é marcada por uma\nabordagem da questão social como problema moral e\nreligioso, assim como é baseada em uma intervenção\nque prioriza a formação da família e do indivíduo para\na solução dos problemas.", "C": "O doutrinarismo e o conservadorismo foram teorias\nsociais hegemônicas no serviço social até a década de\n70, quando se iniciou o movimento de reconceituação.", "D": "O primeiro suporte teórico-metodológico necessário à\nqualificação técnica e à prática dos assistentes sociais\nadveio da matriz fenomenológica.", "E": "Os documentos de Araxá, de Petrópolis e de Guaxupé\nsão os principais instrumentos que direcionam o\nserviço social para a ruptura com o conservadorismo."}, "g": "B", "j": "A genese do servico social no Brasil e marcada pela abordagem da questao social como problema moral e religioso, com intervencao centrada na formacao da familia e do individuo."}, {"id": "1979311", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Condições e Mercado de Trabalho do Assistente Social", "Transformações Societárias, mundo do trabalho e Estado capitalista", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2022", "org": "PRODAM", "t": "", "e": "As análises sobre a categoria trabalho no serviço social\nrevelam como ocorrem as relações entre capital e trabalho\nna sociedade capitalista e oferece ao assistente social\nsubsídios para realizar a leitura da conjuntura e direcionar as\nações profissionais para a materialização do projeto ético político da profissão. A partir dessa informação, assinale a\nalternativa correta, referente ao debate sobre serviço social\ne trabalho.", "alt": {"A": "O fato de existir muita força de trabalho disponível\ncoloca os trabalhadores em uma condição defensiva e\nsubordinada em relação ao capital.", "B": "O neoliberalismo foi o responsável por conceber e criar\na reestruturação produtiva com o objetivo de controlar\nos mercados financeiros e a classe trabalhadora.", "C": "O trabalho flexível gera mais oportunidades de\nemprego para a classe trabalhadora e fortalece a forma\ncontratual de trabalho com carteira assinada e\nproteção social.", "D": "A acumulação flexível é fundamentada nos princípios\ndo fordismo e tem o objetivo de expandir a\nprodutividade capitalista.", "E": "Baixa rotatividade de funcionários, salários atrativos e\nestabilidade contratual são as características das\nrelações de trabalho no terceiro setor."}, "g": "A", "j": "A existencia de excedente de forca de trabalho (exercito industrial de reserva) coloca os trabalhadores em condicao defensiva e subordinada em relacao ao capital."}, {"id": "1979309", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2022", "org": "PRODAM", "t": "", "e": "No planejamento, é necessário produzir documentos que irão\ndirecionar as ações planejadas. O documento elaborado mais\npróximo da execução, o qual deverá apresentar as atividades\na serem desenvolvidas, determinar os prazos, identificar os\nrecursos humanos e materiais e estruturar as receitas e os\ncustos, é o", "alt": {"A": "plano.", "B": "projeto.", "C": "programa.", "D": "projeto de pesquisa.", "E": "plano de execução."}, "g": "B", "j": "O projeto e o documento de planejamento mais proximo da execucao, contendo atividades, prazos, recursos humanos/materiais, receitas e custos."}, {"id": "1979307", "d": "servico_social", "a": ["Saúde", "Sistema Único de Saúde - SUS: Lei Orgânica da Saúde - LOS - Lei nº 8.080 de 1990 e Lei  nº 8.142 de 1990"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Assinale a alternativa correta a respeito do Sistema Único de\nSaúde (SUS).", "alt": {"A": "Um dos objetivos do SUS consiste na identificação e na\ndivulgação dos fatores condicionantes e determinantes\nda saúde.", "B": "É vedada a participação da iniciativa privada no SUS.", "C": "A vigilância sanitária, a vigilância epidemiológica e a\nvigilância socioassistencial estão incluídas nas ações\nprevistas pelo SUS.", "D": "Constitui um princípio do SUS a prevalência da ótica\nmédica na preservação da vida das pessoas.", "E": "A rede de serviços de saúde funciona de forma\nhorizontalizada, descentralizada e universalizada."}, "g": "A", "j": "Lei 8.080/90: e objetivo do SUS a identificacao e divulgacao dos fatores condicionantes e determinantes da saude."}, {"id": "1979303", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais", "Trabalho e Serviço Social", "Transformações Societárias, mundo do trabalho e Estado capitalista"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Em relação às questões teóricas e históricas do Estado,\nassinale a alternativa correta.", "alt": {"A": "Na perspectiva liberal, cabe ao Estado o papel de\nrestabelecer o equilíbrio econômico, por meio de uma\npolítica fiscal, creditícia e de gastos, realizando\ninvestimentos ou inversões reais nos períodos de\ndepressão econômica.", "B": "Os direitos civis foram a primeira categoria de direitos\nde cidadania, com o objetivo de impor limites ao\ndomínio do Estado absolutista.", "C": "Na perspectiva de Keynes, os indivíduos são\nconduzidos por uma mão invisível — o mercado — que\npromove o equilíbrio entre a oferta e a procura e entre\no trabalho e o salário.", "D": "O Estado absolutista prevê o Estado mínimo, com\napenas três funções: a defesa contra os inimigos\nexternos; a proteção de todo o indivíduo; e o\nprovimento de obras públicas.", "E": "A ideologia socialista democrática apoia-se no princípio\nde que o bem-estar individual maximiza o bem-estar\ncoletivo e no princípio da naturalização da miséria."}, "g": "B", "j": "Os direitos civis foram a primeira categoria de direitos de cidadania, com o objetivo de impor limites ao dominio do Estado absolutista (Marshall)."}, {"id": "1903388", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social", "Trabalho e Serviço Social", "Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2021", "org": "CRESS", "t": "", "e": "O profissional de serviço social concretiza um trabalho\nfundamentalmente socioeducativo e atua nas diversas áreas\nligadas à condução das políticas sociais, públicas e privadas.\nA campanha acima encerrou-se em 2020. Acerca da atuação\ndo profissional de serviço social, assinale a alternativa\ncorreta.", "alt": {"A": "A campanha fere diretamente o Código de Ética do\nAssistente Social, pois há um privilégio para\ndeterminado grupo populacional.", "B": "Assistentes sociais devem ter atuação limitada aos\nserviços públicos, como, por exemplo, os de saúde,\neducação, habitação e assistência social.", "C": "O trabalho dos assistentes sociais não pode ter foco nas\ndemandas da população definidas por gênero, cor ou\nraça nem relação direta com elas.", "D": "Atualmente, há um elevado conflito entre os campos\nde atuação dos profissionais de assistência social e dos\npsicólogos.", "E": "Campanhas como essa visam a incentivar a promoção\nde ações de combate ao racismo no cotidiano\nprofissional de assistentes sociais."}, "g": "E", "j": "Campanhas como a referida buscam incentivar a promocao de acoes de combate ao racismo no cotidiano profissional dos assistentes sociais."}, {"id": "1903387", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "O Conselho Federal de Serviço Social tem a atribuição de\norientar, disciplinar, normatizar, fiscalizar e defender o\nexercício profissional do assistente social no Brasil.\nConsiderando essa informação, julgue os próximos itens.    \nI O serviço social foi uma das primeiras profissões da área\nsocial a ter aprovada sua lei de regulamentação\nprofissional.\n    II O Conselho Federal de Serviço Social é uma autarquia\nprivada federal, mas sem autonomia administrativa ou\nfinanceira.\n    III Atualmente, a fiscalização pelo Conselho Federal de\nServiço Social restringe-se à exigência da inscrição do\nprofissional e ao pagamento do tributo devido.\n      Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas I esta correto - o servico social foi uma das primeiras profissoes da area social a ter aprovada sua lei de regulamentacao (1957). II e III contem incorrecoes."}, {"id": "1903386", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Segundo o Código de Ética do Assistente Social, assinale a\nalternativa incorreta.", "alt": {"A": "Constitui direito do assistente social o desagravo\npúblico por ofensa que atinja sua honra profissional.", "B": "É vedado ao assistente social substituir profissional que\ntenha sido exonerado, demitido ou transferido por\ndefender os princípios da ética profissional, enquanto\nperdurar o motivo da exoneração, demissão ou\ntransferência.", "C": "Compete ao Conselho Regional de Serviço Social atuar\ncomo Tribunal Superior de Ética Profissional e firmar\njurisprudência na observância do Código de Ética da\nprofissão.", "D": "É infração disciplinar deixar de pagar, regularmente, as\nanuidades e as contribuições devidas ao respectivo\nConselho Regional de Serviço Social.", "E": "A cassação do registro profissional é uma das\npenalidades aplicáveis pelo Código de Ética."}, "g": "C", "j": "Atuar como Tribunal Superior de Etica Profissional e firmar jurisprudencia e atribuicao do CFESS (Conselho Federal), nao do CRESS (Conselho Regional)."}, {"id": "1875978", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Instrumentos e Técnicas de Intervenção"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Acerca dos instrumentos e das técnicas do serviço social,\nassinale a alternativa correta.", "alt": {"A": "Durante a entrevista, quando ocorre o silêncio do\nusuário, o entrevistador deve interrompê-lo\nimediatamente, realizando outra pergunta sobre\nassunto ainda não abordado, uma vez que o silêncio é\nindicativo de recusa do entrevistado a responder à\nquestão realizada pelo entrevistador.", "B": "A entrevista é um processo unidirecional, no qual o\nassistente social é o condutor que transmite\nconhecimento e informações ao usuário.", "C": "Ao fazer uso dos instrumentos junto aos usuários, o\nassistente social deve esclarecer, no início do\natendimento, o objetivo e a amplitude do trabalho\nprofissional.", "D": "A visita domiciliar proporciona observar as relações\nsociais e a forma como se estabelecem as relações\nfamiliares e deve ser realizada com o objetivo de\naveriguar a fidedignidade das informações prestadas\npelo usuário.", "E": "No manuseio dos instrumentos do serviço social,\ndeve-se preponderar a dimensão técnico-operativa,\npois o conhecimento sobre a aplicação das técnicas por\nsi só garante a competência profissional."}, "g": "C", "j": "O assistente social deve esclarecer no inicio do atendimento o objetivo e a amplitude do trabalho profissional, garantindo a transparencia e o consentimento do usuario."}, {"id": "1875977", "d": "servico_social", "a": ["Saúde", "Sistema Único de Saúde - SUS: Lei Orgânica da Saúde - LOS - Lei nº 8.080 de 1990 e Lei  nº 8.142 de 1990", "Serviço Social e Saúde do Trabalhador"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "No que se refere à Política Nacional de Saúde do Trabalhador,\nassinale a alternativa correta.", "alt": {"A": "A Política Nacional de Saúde do Trabalhador tem como\nfinalidade definir os princípios, as diretrizes e as\nestratégias a serem observados pela gestão nacional\ndo Sistema Único de Saúde (SUS) e pelos\nempregadores, para o desenvolvimento da atenção\nintegral à saúde do trabalhador, com ênfase na\nsegurança do trabalho.", "B": "A condição necessária para que o cidadão seja assistido\npela Política Nacional de Saúde do Trabalhador é que\nesteja inserido no mercado formal de trabalho e exerça\natividade remunerada, urbana ou rural.", "C": "Uma das estratégias da Política Nacional de Saúde do\nTrabalhador é alocar recursos orçamentários e\nfinanceiros para a implementação e a efetivação dessa\nPolítica.", "D": "A descentralização, a hierarquização, a equidade e a\nprecaução são alguns dos princípios e das diretrizes da\nPolítica Nacional de Saúde do Trabalhador.", "E": "Fortalecer a rede terciária de saúde e fiscalizar o\ncumprimento dos protocolos de segurança do trabalho\nconstituem objetivos da Política Nacional de Saúde do\nTrabalhador."}, "g": "D", "j": "PNSST: a descentralizacao, a hierarquizacao, a equidade e a precaucao sao alguns dos principios e diretrizes da Politica Nacional de Saude do Trabalhador."}, {"id": "1875976", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "O Código de Ética de 1993 é resultado de um processo de\namadurecimento e renovação do serviço social. Nesse\ndocumento, estão expressos os princípios, as normativas e as\ndiretrizes da profissão. Com base no Código de Ética do\nAssistente Social, assinale a alternativa correta.", "alt": {"A": "Constitui direito do assistente social o desagravo\nindividual, com a presença de um conselheiro como\ntestemunha, por ofensa que atinja a sua honra\nprofissional.", "B": "É direito do assistente social depor como testemunha\nsobre situação sigilosa de usuário de que tenha\nconhecimento no exercício profissional, quando\nautorizado.", "C": "As penalidades previstas no Código de Ética são: multa;\nadvertência reservada; advertência pública; suspensão\ndo exercício profissional; e cassação do registro\nprofissional.", "D": "A quebra do sigilo profissional só é admissível quando\nse tratar de situação cuja gravidade envolva fato\ndelituoso e traga prejuízo a coletividade.", "E": "É vedado ao assistente social realizar crítica pública a\ncolega e a outros profissionais."}, "g": "C", "j": "As penalidades previstas no Codigo de Etica de 1993 sao: multa; advertencia reservada; advertencia publica; suspensao do exercicio profissional; e cassacao do registro profissional."}, {"id": "1875975", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Proteção Social ao Idoso"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "O Estatuto do Idoso veio ampliar e assegurar direitos para a\npopulação idosa e se configura como um importante\ninstrumento na defesa da cidadania desse público. No que diz\nrespeito ao Estatuto do Idoso, assinale a alternativa correta.", "alt": {"A": "O idoso enfermo que for notificado a comparecer\nperante os órgãos públicos deverá apresentar atestado\nmédico justificando sua ausência do ato. Após o\nrestabelecimento, terá o prazo de trinta dias para\ncomparecer pessoalmente ao órgão solicitador.", "B": "O Estatuto do Idoso visa regular os direitos assegurados\nàs pessoas com idade igual ou superior a 65 anos.", "C": "Ao idoso internado ou em observação é obrigatória a\npresença de um acompanhante, devendo o órgão de\nsaúde proporcionar as condições adequadas para a sua\npermanência em tempo integral.", "D": "É assegurada prioridade especial aos idosos maiores de\noitenta anos de idade, atendendo-se suas necessidades\npreferencialmente em relação aos demais idosos.", "E": "É obrigação da família, da comunidade, da sociedade e\ndo Estado garantir à pessoa idosa a proteção à vida e à\nsaúde, mediante a efetivação de políticas sociais\npúblicas que permitam um envelhecimento saudável."}, "g": "D", "j": "Estatuto do Idoso: e obrigacao da familia, comunidade, sociedade e Estado garantir a pessoa idosa a protecao a vida e a saude por politicas sociais publicas."}, {"id": "1875974", "d": "servico_social", "a": ["Serviço Social na Empresa, Responsabilidade Social, Terceiro Setor, ONGs, Entidades Sociais, Recursos Humanos e Gestão de Pessoas", "Trabalho e Serviço Social", "Condições e Mercado de Trabalho do Assistente Social", "Transformações Societárias, mundo do trabalho e Estado capitalista"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Nas últimas décadas, as inovações tecnológicas e os avanços\ntécnico-científicos e informacionais vêm proporcionando\nvárias transformações no mundo do trabalho, na organização\nda produção e nos processos de trabalho das empresas.\nSendo assim, assinale a alternativa correta quanto ao\ntrabalho do serviço social nas empresas.", "alt": {"A": "No Brasil, é a partir dos anos 1940, momento em que a\nconjuntura nacional apresentava uma ampliação do\nmercado de trabalho devido à reestruturação\nprodutiva, que se identifica uma presença maciça de\nassistentes sociais atuando em empresas.", "B": "Uma das demandas atuais e emergentes da atuação do\nassistente social no âmbito empresarial é realizar\npráticas educativas, com o objetivo de favorecer\nmudanças de hábitos, atitudes e comportamentos do\ntrabalhador, visando promover uma maior adequação\nao processo produtivo.", "C": "Apesar de o assistente social, na sua atuação em\nempresas, não interferir na reprodução social, esse\nprofissional atua na contradição entre capital e\ntrabalho, com o foco voltado a atender as demandas\ndos empregadores.", "D": "O serviço social no campo empresarial é considerado\ncomo um espaço permeado por tensões e dissensos,\nno qual é inviável a articulação de estratégias que se\nvinculem ao projeto ético-profissional.", "E": "Algumas das frentes de trabalho para o assistente\nsocial nas empresas são: a gestão de recursos\nhumanos; o desenvolvimento de equipes; a ação\ncomunitária; a certificação social; e a educação\nambiental."}, "g": "E", "j": "Frentes de trabalho do assistente social nas empresas: gestao de RH, desenvolvimento de equipes, acao comunitaria, certificacao social e educacao ambiental."}, {"id": "1875973", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Quanto à história do serviço social no Brasil, assinale a\nalternativa correta.", "alt": {"A": "A prática profissional realizada pelas primeiras\nassistentes sociais era voltada principalmente para a\norganização da assistência e para a educação popular,\ncom o objetivo de promover a adaptação e o\najustamento das classes populares à ordem vigente.", "B": "As primeiras assistentes sociais embasavam suas ações\nnas legislações sociais, na teoria liberal, nas encíclicas\npapais e nas orientações doutrinárias.", "C": "A primeira escola de serviço social no Brasil foi fundada\nem 1934, na cidade do Rio de Janeiro, e foi resultado\nde uma iniciativa do Movimento Cristão Laico.", "D": "Na década de 1930, o serviço social no Brasil foi\nmarcado pela influência do serviço social americano,\ncom uma forte base filosófica e idealista, porém\ndesprovido de técnicas e metodologias.", "E": "As primeiras assistentes sociais atuavam sobre a\nquestão social e, de forma crítica, consideravam e\nanalisavam as transformações econômicas e sociais e\nseus impactos na vida dos clientes."}, "g": "A", "j": "A pratica das primeiras assistentes sociais brasileiras voltava-se para a organizacao da assistencia e educacao popular, com objetivo de promover a adaptacao das classes populares a ordem vigente."}, {"id": "1875972", "d": "servico_social", "a": ["Serviço Social na Empresa, Responsabilidade Social, Terceiro Setor, ONGs, Entidades Sociais, Recursos Humanos e Gestão de Pessoas"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "César e Amaral abordam o tema do trabalho do assistente\nsocial nas empresas capitalistas. As autoras afirmam que os\nassistentes sociais são solicitados a atuar no programa que\ncomporta os fatores do “ambiente de trabalho”, que\ninfluenciam o comportamento e a produtividade dos\ntrabalhadores, e que avalia aspectos relacionais existentes\nentre a organização do trabalho, a satisfação e o\ndesempenho. Conforme César e Amaral, esse programa é\ndenominado Programa", "alt": {"A": "Participativo.", "B": "de Qualidade de Vida.", "C": "de Clima ou Ambiência Organizacional.", "D": "de Treinamento e Desenvolvimento.", "E": "de Círculos de Controle e Qualidade."}, "g": "C", "j": "Cesar e Amaral: o programa que comporta os fatores do 'ambiente de trabalho' e denominado Programa de Clima ou Ambiencia Organizacional."}, {"id": "1875971", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Com relação ao debate contemporâneo sobre a Política\nSocial, fundamentado na teoria social crítica, assinale a\nalternativa correta.", "alt": {"A": "As políticas sociais devem ser analisadas a partir de\nfatos sociais presentes na morfologia da sociedade.", "B": "A política social é fruto da iniciativa natural do Estado\npara responder às demandas da sociedade e garantir\nsua hegemonia.", "C": "Do ponto de vista histórico, é preciso relacionar o\nsurgimento da política social a uma dimensão racional\ne instrumental que busca a amenização dos problemas\nsociais da sociedade.", "D": "As principais funções da política social são evitar o\nestado de anomia, patologização e desequilíbrio da\nsociedade e promover a coesão social.", "E": "A partir da perspectiva econômica, faz-se necessário\nestabelecer relações entre a política social e as\nquestões estruturais da economia e seus efeitos para\nas condições de produção e reprodução da vida da\nclasse trabalhadora."}, "g": "E", "j": "Na perspectiva critica, e necessario relacionar a politica social com as questoes estruturais da economia e seus efeitos para as condicoes de producao e reproducao da vida da classe trabalhadora."}, {"id": "1875970", "d": "servico_social", "a": ["Assessoria e Consultoria em Serviço Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "A respeito da assessoria e da consultoria em serviço social,\nassinale a alternativa correta.", "alt": {"A": "Um dos atributos necessários ao assessor é a\nneutralidade, qualidade que possibilitará a\nobjetividade e a racionalidade do trabalho realizado.", "B": "Uma das atividades de assessoria realizadas pelo\nassistente social é a assessoria à organização política\ndos usuários, por meio da qual o profissional poderá\nrefletir, junto aos usuários, quanto à necessidade de\nsua organização política tanto dentro da instituição\nquanto em movimentos sociais e em entidades\nrepresentativas da sociedade civil.", "C": "A assessoria é uma atividade que requer contínua\ncapacitação e conhecimento aprofundado sobre\ndeterminada área de conhecimento. Assim, para se\nexercer a atividade de assessor, é necessário ter, no\nmínimo, a titulação de mestrado na área de atuação.", "D": "A assessoria em serviço social é a competência\nprofissional de supervisionar e transmitir seus\nconhecimentos ao assessorando, visando adaptá-lo à\nnecessária atuação competente.", "E": "O assessor deve instruir, desenvolver ações de\naconselhamento e expressar opinião ou parecer\ntécnico sobre assunto de sua especialidade."}, "g": "B", "j": "Uma das atividades de assessoria realizadas pelo assistente social e a assessoria a organizacao politica dos usuarios, refletindo sobre sua atuacao em movimentos sociais e entidades."}, {"id": "1875969", "d": "servico_social", "a": ["Saúde", "Sistema Único de Saúde - SUS: Lei Orgânica da Saúde - LOS - Lei nº 8.080 de 1990 e Lei  nº 8.142 de 1990", "Serviço Social na Saúde", "Serviço Social e Saúde do Trabalhador"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Um dos campos de trabalho do assistente social é a saúde do\ntrabalhador. Segundo Lourenço, a compreensão da saúde do\ntrabalhador exige a associação das relações sociais do\ntrabalho com a particularidade do processo, da organização e\nda gestão do trabalho na conjuntura nacional. Considerando\nessa informação, assinale a alternativa correta acerca da\nsaúde do trabalhador.", "alt": {"A": "Ao atuar na área de saúde do trabalhador, o assistente\nsocial deve conhecer os índices de afastamento\nrelacionados às diversas morbidades, aos acidentes e\nàs mortes no trabalho, pois os dados notificados\nrepresentam a real ocorrência de acidentes de trabalho\ne refletem a realidade em que a totalidade dos\ntrabalhadores está inserida.", "B": "Os agravos à saúde do trabalhador são ocorrências\nimprevisíveis e inevitáveis, que se originam de\nsituações que envolvem uma multicausalidade de\nfatores relacionados ao trabalho.", "C": "O adoecimento mental do trabalhador está\nessencialmente relacionado à sua subjetividade, à sua\nfragilidade psíquica e à sua predisposição de\ndesenvolver distúrbios mentais.", "D": "Os acidentes de trabalho podem ser compreendidos\ncomo uma forma de exclusão social, visto que podem\nexpor o trabalhador a condições de vulnerabilidade\nsocial.", "E": "As definições e as classificações das doenças laborais\nsão claras e objetivas e contemplam todo o espectro de\ndoenças relacionadas ao trabalho, o que garante a\ntodos os trabalhadores o reconhecimento do problema\nde saúde originário do trabalho e a acessibilidade aos\ndireitos previstos nas legislações."}, "g": "D", "j": "Os acidentes de trabalho podem ser compreendidos como forma de exclusao social, expondo o trabalhador a condicoes de vulnerabilidade social."}, {"id": "1875968", "d": "servico_social", "a": ["Saúde", "Sistema Único de Saúde - SUS: Lei Orgânica da Saúde - LOS - Lei nº 8.080 de 1990 e Lei  nº 8.142 de 1990", "Serviço Social e Saúde do Trabalhador"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "O órgão público que visa prestar assistência aos\ntrabalhadores que desenvolveram doenças e(ou) agravos\nrelacionados ao trabalho, bem como realizar ações relativas\nà promoção, à proteção e à recuperação da saúde dos\ntrabalhadores denomina-se", "alt": {"A": "Rede de Atendimento à Saúde do Trabalhador (REAST).", "B": "Unidade de Atendimento à Saúde do Trabalhador (UAST).", "C": "Rede Integrada de Promoção à Saúde do\nTrabalhador (RIPST).", "D": "Centro Integrado de Atenção ao Trabalhador (CIAT).", "E": "Centro de Referência em Saúde do Trabalhador (CEREST)."}, "g": "E", "j": "O orgao publico que visa prestar assistencia aos trabalhadores com doencas/agravos relacionados ao trabalho e realizar acoes de promocao, protecao e recuperacao da saude e o Centro de Referencia em Saude do Trabalhador (CEREST)."}, {"id": "1875967", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Proteção Social às Pessoas com Deficiência"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Com relação à Política Nacional para a Integração da Pessoa\nPortadora de Deficiência, assinale a alternativa correta.", "alt": {"A": "A deficiência múltipla é definida quando ocorre a\nassociação de três ou mais deficiências.", "B": "A colocação seletiva é uma das modalidades de\ninserção laboral da pessoa com deficiência.", "C": "Para fins de concessão de benefícios, a deficiência ou\nincapacidade deve ser diagnosticada e caracterizada\npor equipe médica.", "D": "A habilitação profissional é um processo que possui\nduração limitada e apresenta o objetivo de permitir\nque a pessoa com deficiência desenvolva, ao máximo,\no nível físico, mental ou social.", "E": "A fiscalização do cumprimento da legislação pertinente\nà pessoa com deficiência é um dos objetivos dessa\nPolítica."}, "g": "B", "j": "A colocacao seletiva e uma das modalidades de insercao laboral da pessoa com deficiencia, conforme a Politica Nacional para a Integracao da Pessoa Portadora de Deficiencia."}, {"id": "1875966", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "No que concerne à Lei de regulamentação da profissão de\nassistente social, assinale a alternativa correta.", "alt": {"A": "As organizações que se registrarem nos Conselhos\nRegionais de Serviço Social receberão um certificado\nque as habilitará a atuar na área de serviço social.", "B": "São atribuições privativas do assistente social as de\nplanejar, executar e avaliar pesquisas que possam\ncontribuir para a análise da realidade social e para\nsubsidiar ações profissionais.", "C": "É competência privativa do Conselho Federal de\nServiço Social representar, em juízo e fora dele, os\ninteresses gerais e individuais dos assistentes sociais.", "D": "Compete ao Conselho Federal de Serviço Social expedir\nas carteiras profissionais dos assistentes sociais,\nfixando a respectiva taxa.", "E": "A supervisão de estágio é uma competência do\nassistente social."}, "g": "A", "j": "Lei 8.662/93: as organizacoes que se registrarem nos CRESS receberao um certificado que as habilitara a atuar na area de servico social."}, {"id": "1875965", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "A produção teórica de Boschetti apresenta importantes\ncontribuições para a realização da avaliação de programas e\npolíticas sociais. De acordo com a concepção dessa autora,\nassinale a alternativa correta quanto à avaliação de\nprogramas e políticas sociais.", "alt": {"A": "A análise de programas e políticas sociais é realizada\npor meio de uma abordagem sequencial e linear de\nações compostas das seguintes etapas: identificação\ndo problema; formulação de objetivos; tomada de\ndecisão; implementação/execução; avaliação; e\nextinção ou manutenção da política.", "B": "A análise e a avaliação de políticas sociais são\natividades que utilizam métodos e técnicas racionais e\noperativos, com o objetivo de obter o melhor\ncusto-benefício.", "C": "Alguns elementos importantes para a análise dos\nprogramas ou das políticas sociais são: os direitos e os\nbenefícios estabelecidos e assegurados; o\nfinanciamento; a gestão; e o controle social\ndemocrático.", "D": "Para a avaliação de programas e políticas sociais,\nexige-se que o assistente social conheça, com\nprofundidade, todos os aspectos da realidade social, de\nmodo a compor um quadro total e completo sobre a\neficiência da política social.", "E": "O foco da análise das políticas sociais é a avaliação da\nsua implementação, visando à maximização de sua\neficiência e eficácia."}, "g": "C", "j": "Boschetti: os elementos importantes para a analise de programas e politicas sociais sao direitos e beneficios estabelecidos/assegurados, financiamento, gestao e controle social democratico."}, {"id": "1875964", "d": "servico_social", "a": ["Pesquisa em Serviço Social", "Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "A pesquisa e a aplicação de métodos e técnicas qualitativas e\nquantitativas constituem importantes instrumentos no\nexercício profissional do assistente social. No que se refere a\nesse tema, assinale a alternativa correta.", "alt": {"A": "Os elementos obrigatórios de um projeto de pesquisa\nsão: o tema; a justificativa; o problema; as hipóteses;\nos objetivos gerais; os objetivos específicos; e a\nmetodologia.", "B": "O projeto de pesquisa é o registro que materializa o\nplanejamento da pesquisa. Após a conclusão da\nelaboração desse projeto, ele não poderá sofrer\nalterações, uma vez que qualquer modificação\nacarretará em prejuízos à pesquisa.", "C": "O problema e a hipótese da pesquisa devem expressar,\ncom clareza e precisão, a finalidade da pesquisa e a\nmeta a ser alcançada.", "D": "Entre as vantagens da escolha do questionário como\ninstrumento de coleta de dados, destacam-se a\nversatilidade, pois ele pode ser utilizado com todos os\nsegmentos da população, e a flexibilidade, pois permite\nque o entrevistador repita ou esclareça as perguntas.", "E": "Para a escolha do tema de pesquisa, é recomendado\nque o pesquisador utilize os critérios de originalidade,\nviabilidade e relevância."}, "g": "E", "j": "Para a escolha do tema de pesquisa, recomenda-se utilizar os criterios de originalidade, viabilidade e relevancia."}, {"id": "1875963", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Conforme Baptista, no planejamento, o processo que se\nrealiza após as tomadas de decisões e que se configura no\ntrabalho de sistematização das atividades e dos\nprocedimentos necessários para o alcance das metas e dos\nresultados traçados denomina-se", "alt": {"A": "monitoramento.", "B": "execução.", "C": "planificação.", "D": "avaliação.", "E": "implementação."}, "g": "C", "j": "Baptista: a planificacao e o processo realizado apos as tomadas de decisao, configurando a sistematizacao das atividades e procedimentos para alcance das metas."}, {"id": "1875962", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Uma das principais demandas do assistente social é realizar\nações de enfrentamento à questão social. A respeito dessa\ndemanda, assinale a alternativa correta.", "alt": {"A": "O assistente social, no enfrentamento da questão\nsocial, deve realizar ações voltadas ao fortalecimento\ndos sujeitos coletivos e dos direitos sociais e reassumir\no trabalho de base, de educação, mobilização e\norganização popular.", "B": "A questão social é avessa à sociabilidade capitalista e\ntem como principal expressão a pobreza,\ncompreendida enquanto um fenômeno histórico e\nnatural da sociedade.", "C": "A questão social pode ser compreendida enquanto\nproblema social e individual que é vivenciado pelas\nfamílias demandatárias da ação do serviço social.", "D": "A questão social é o mesmo que desigualdade\neconômica.", "E": "O assistente social é o único profissional habilitado a\ntrabalhar com as expressões da questão social."}, "g": "A", "j": "O assistente social, no enfrentamento da questao social, deve realizar acoes voltadas ao fortalecimento dos sujeitos coletivos e dos direitos sociais e reassumir o trabalho de base."}, {"id": "1875961", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Estudo Social, Pareceres, Perícia Social, Relatório Social e Laudo Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Com base nos estudos de Fávero sobre o estudo social, o\nrelatório social, o laudo social e o parecer social, assinale a\nalternativa correta.", "alt": {"A": "O estudo social é uma técnica de investigação centrada\nno indivíduo e nos problemas sociais que o circundam.", "B": "O parecer social é uma manifestação sucinta e\nfundamentada, que apresenta esclarecimentos e\nanálises sobre a questão ou situação social analisada,\npodendo ter um caráter conclusivo ou indicativo.", "C": "O relatório social é um instrumento meramente\ndescritivo, que possui a finalidade de retratar\ninformações relativas ao contexto socioeconômico\nfamiliar.", "D": "O laudo deve necessariamente expressar o\ndetalhamento de todos os conteúdos obtidos durante\no estudo social, de modo a assegurar a fidedignidade e\na confiabilidade do processo.", "E": "O estudo social, a perícia social, o laudo social e o\nparecer social são instrumentos utilizados por\ndiferentes profissões que trabalham na área social."}, "g": "B", "j": "Favero: o parecer social e uma manifestacao sucinta e fundamentada que apresenta esclarecimentos e analises sobre a questao social analisada, com carater conclusivo ou indicativo."}, {"id": "1875959", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Assinale a alternativa que apresenta os elementos\nconstitutivos do projeto ético-político do serviço social,\nsegundo Teixeira e Braz.", "alt": {"A": "princípios e valores ético-políticos e a trama social", "B": "lutas e posicionamentos políticos acumulados pela\ncategoria na trajetória histórica da profissão e a crítica\nà ordem social vigente", "C": "expressões da questão social e a matriz\nteórico-metodológica marxista", "D": "idealismo, instrumentalidade e dimensão técnica\noperativa", "E": "razão instrumental e projeto societário"}, "g": "B", "j": "Teixeira e Braz: os elementos constitutivos do projeto etico-politico do servico social sao as lutas e posicionamentos politicos acumulados pela categoria e a critica a ordem social vigente."}, {"id": "1834860", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Resolução CFESS n.o 582/2010 apresenta a Consolidação\ndas Resoluções do Conselho Federal de Serviço Social que\nestá em vigor e cujas disposições devem ser observadas por\ntodos os Conselhos Regionais de Serviço Social e por todos os\nprofissionais inscritos. Considerando essa informação,\nassinale a alternativa incorreta.", "alt": {"A": "As obrigações pecuniárias decorrentes da vinculação\ndo profissional ao Conselho Regional de Serviço Social\ncompreendem anuidades, taxas e multas.", "B": "Qualquer profissional poderá requerer o cancelamento\nde sua inscrição, desde que declare o não exercício de\nqualquer atividade, função ou cargo que envolva o\nexercício profissional de assistente social.", "C": "Será concedida a interrupção do pagamento das\nanuidades ao profissional que requerer a interrupção\ntemporária do efetivo exercício profissional nos casos\nprevistos na Consolidação.", "D": "No caso de falecimento do profissional inscrito, o\ncancelamento será automático, ficando seus familiares\nresponsáveis por todos os seus eventuais débitos,\ndecorrentes de anuidades, taxas e multas, até a data\ndo falecimento.", "E": "É facultado ao assistente social que deixar de exercer\nsuas atividades profissionais, por aposentadoria ou por\nqualquer outro motivo, permanecer registrado no\nConselho Regional de Serviço Social, com todos os\ndireitos e deveres, inclusive com o ônus financeiro."}, "g": "D", "j": "No caso de falecimento do profissional inscrito, o cancelamento e automatico e ficam extintos todos os eventuais debitos - nao ha responsabilizacao dos familiares como afirma a alternativa D."}, {"id": "1834858", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Competências e Atribuições Privativas do Assistente Social", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Julgue os itens a seguir.\nI O Conselho Federal de Serviço Social poderá intervir nos\nConselhos Regionais de Serviço Social, por deliberação\ndo Conselho Pleno do Conselho Federal, para assegurar\no cumprimento das leis, do Código de Ética, do Estatuto,\ndos regulamentos e das resoluções e acatar as decisões\njudiciais.\nII O Conselho Federal de Serviço Social poderá intervir nos\nConselhos Regionais de Serviço Social, por deliberação\ndo Conselho Pleno do Conselho Federal, para\nrestabelecer a normalidade administrativa e(ou)\nfinanceira e a lisura de atos administrativos e financeiros\npraticados pelos Conselhos Regionais de Serviço Social,\numa vez comprovada a existência de irregularidade.\nIII O Conselho Federal de Serviço Social poderá intervir nos\nConselhos Regionais de Serviço Social, por deliberação\ndo Conselho Pleno do Conselho Federal, para sanar\ndesequilíbrio financeiro grave, insolvência ou má gestão\ndos recursos.\nAssinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas o item III está certo.", "D": "Apenas os itens I e II estão certos.", "E": "Todos os itens estão certos."}, "g": "E", "j": "O CFESS pode intervir nos CRESS por deliberacao do Conselho Pleno: para assegurar cumprimento de normas (I), restabelecer normalidade administrativa/financeira (II) e sanar desequilibrio financeiro grave (III)."}, {"id": "1834855", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais"], "ano": "2021", "org": "CRESS", "t": "", "e": "A cidadania é uma espécie de igualdade humana\nbásica, associada com o conceito de participação integral na\ncomunidade, o qual não é inconsistente com as\ndesigualdades que diferenciam os vários níveis econômicos\nna sociedade. Em outras palavras, a desigualdade do sistema\nde classes sociais pode ser aceitável, desde que a igualdade\nde cidadania seja reconhecida.\nT. H. Marshall. Cidadania, classe social e\nstatus. Rio de Janeiro: Zahar, 1967, p. 62.\nSegundo T. H. Marshall, na obra citada, a expansão da\ncidadania levaria à diminuição das desigualdades econômicas\ngeradas pelo capitalismo. Ainda que não se obtivesse a\nigualdade absoluta, seria possível remover as desigualdades\ntidas como injustas, chegando-se, em certas situações,\na anulá-las. No que se refere a esse tema, julgue os itens\nsubsequentes.\nI São direitos que fazem parte do conceito de cidadania os\ndireitos civis (liberdades individuais, de movimento, de\nimprensa, de pensamento e de fé e o direito à\npropriedade, à consecução de contratos válidos e ao\nacesso individual à justiça).\nII São direitos que fazem parte do conceito de cidadania\nos direitos políticos (direito ao voto e direito de\nparticipação nas estruturas de poder).\nIII São direitos que fazem parte do conceito de cidadania\nos direitos sociais (um mínimo de bem-estar econômico\ne a possibilidade de levar a vida de acordo com\nos padrões reconhecidos pela sociedade, notadamente\nassegurando-se o direito de acesso à educação e à\nsaúde).\nAssinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "E", "j": "Conforme T. H. Marshall, sao direitos da cidadania: civis (I), politicos (II) e sociais (III) - os tres itens estao corretos."}, {"id": "1830088", "d": "servico_social", "a": ["Instrumentos Técnicos-Operativos do Serviço Social", "Instrumentos e Técnicas de Intervenção", "Instrumentalidade do Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Para além de um conjunto de instrumentos e técnicas, a\ninstrumentalidade no exercício profissional refere-se a uma\npropriedade constitutiva da profissão, construída e\nreconstruída no processo sócio-histórico, nas relações sociais e\nno confronto entre as condições objetivas e subjetivas de tal\nexercício. No que se refere à instrumentalidade do trabalho do\nassistente social, assinale a alternativa correta.", "alt": {"A": "Os profissionais de serviço social dão\ninstrumentalidade às suas ações ao alterarem o\ncotidiano profissional e o cotidiano das classes sociais\nque demandam sua intervenção, modificando as\ncondições, os meios e os instrumentos existentes para\no alcance dos objetivos profissionais.", "B": "O processo de trabalho pode ser definido como um\nconjunto de atividades práticas voltadas integralmente\npara o alcance das finalidades da instituição na qual o\nassistente social está inserido.", "C": "O serviço social de casos surgiu no âmbito da\ninstitucionalização do serviço social no Brasil como\numa abordagem predominantemente emancipatória\ndos sujeitos, no sentido de abandonar influências\npsicologizantes e moralizantes.", "D": "O instrumental técnico-operativo da profissão diz\nrespeito somente a aspectos técnicos do fazer\nprofissional, não sendo relacionado às implicações\nsociopolíticas provenientes de sua aplicação.", "E": "São exemplos de instrumentais técnico-operativos da\nprofissão: reuniões; visitas institucionais e domiciliares;\nrelatórios e pareceres sociais; avaliações; e entrevistas."}, "g": "A", "j": "Os profissionais dao instrumentalidade as suas acoes ao alterarem o cotidiano profissional e o das classes que demandam intervencao, modificando condicoes, meios e instrumentos."}, {"id": "1830087", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Política Nacional de Estágio (PNE) é um documento que\napresenta a concepção de estágio adotada pelo serviço social,\nreforça a supervisão direta do estágio, define as atribuições\ndos sujeitos envolvidos no processo de estágio e aponta\nestratégias para a construção das políticas de estágio nas\nunidades de ensino. Quanto à PNE e às regulamentações\nsobre o estágio supervisionado em serviço social, assinale a\nalternativa correta.", "alt": {"A": "A PNE define que o estágio supervisionado é\ndestinado ao aprendizado da prática e dos aspectos\ntécnico-operativos da profissão, sendo os\nconhecimentos teórico-metodológicos atribuição\nprivativa das unidades de formação acadêmica.", "B": "A responsabilidade ética e técnica da supervisão direta\né do supervisor de campo, cabendo apenas a este\navaliar a pertinência da abertura e do encerramento do\nestágio.", "C": "Cabe ao Conselho Federal de Serviço Social o\nrecebimento de comunicação formal e escrita, por\nparte das unidades de ensino, que informe os campos\nde estágio credenciados e a identificação dos\nprofissionais responsáveis pela supervisão dos\nestagiários. O prazo para envio dessa comunicação é de\ntrinta dias, a partir do início de cada semestre letivo.", "D": "Para que o estágio se constitua como atividade\npedagógica do processo de formação profissional,\nfaz-se necessária a elaboração de um projeto de\ntrabalho, de um plano de estágio e de relatórios – estes\núltimos a serem realizados pelos estudantes.", "E": "Cabe ao estudante manter cópia do plano de estágio\nno local de sua realização, sendo tal documento\nsubscrito pelos estagiários e pelos servidores."}, "g": "D", "j": "PNE: para que o estagio se constitua como atividade pedagogica, faz-se necessaria a elaboracao de projeto de trabalho, plano de estagio e relatorios - estes ultimos pelos estudantes."}, {"id": "1830086", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Os projetos profissionais apresentam a autoimagem\nde uma profissão, elegem os valores que a legitimam\nsocialmente, delimitam e priorizam os seus objetivos e as\nsuas funções, formulam os requisitos (teóricos, institucionais\ne práticos) para o seu exercício, prescrevem normas para o\ncomportamento dos profissionais e estabelecem as balizas da\nsua relação com os usuários de seus serviços, com as outras\nprofissões e com as organizações e instituições sociais,\nprivadas e públicas.   \n José Paulo Netto. A construção do projeto ético-político do serviço social.\n \n \nIn: Serviço Social e Saúde. Formação e trabalho profissional.\n \n São Paulo: Cortez, 2006 (com adaptações).  \n Acerca do projeto ético-político do serviço social brasileiro,\nassinale a alternativa incorreta.", "alt": {"A": "Os princípios ético-políticos e a matriz\nteórico-metodológica em que o serviço social se baseia\nsão os elementos constitutivos de seu projeto\nético-político, que o materializam no processo\nsócio-histórico da profissão.", "B": "A busca de ruptura com o histórico conservadorismo\nno âmbito da profissão, o avanço na produção de\nconhecimentos, a partir da interlocução e do diálogo\ncom diferentes áreas do saber e entre diferentes\nparadigmas, e o debate sobre a formação profissional\ne a reforma curricular foram alguns fatores que\nimpulsionaram a construção do atual projeto\nético-político profissional.", "C": "Os princípios que fazem parte do projeto ético-político\nda profissão têm como valor central a liberdade,\nrelacionada à autonomia, à emancipação e à plena\nexpansão dos indivíduos sociais.", "D": "Os projetos constantes do projeto ético-político da\nprofissão afirmam a defesa dos direitos humanos, da\nequidade e da justiça social, na perspectiva da\nfocalização do acesso a bens e serviços relativos aos\nprogramas e às políticas sociais, firmando, assim, o\ncompromisso com a competência e a qualidade dos\nserviços prestados à população.", "E": "A prática profissional nessa perspectiva pressupõe\ncompetências teóricas, técnico-operativas e\nético-políticas."}, "g": "D", "j": "O projeto etico-politico do servico social brasileiro defende a UNIVERSALIZACAO do acesso a bens e servicos (e nao focalizacao como afirma a alternativa D)."}, {"id": "1830085", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993"], "ano": "2021", "org": "CRESS", "t": "", "e": "Segundo a Lei n.° 8.662/1993, que dispõe sobre a profissão\nde assistente social e dá outras providências, assinale a\nalternativa correta.", "alt": {"A": "A coordenação de seminários e congressos na área de\nserviço social não é atribuição privativa de assistentes\nsociais, podendo também ser realizada por\nprofissionais das ciências sociais.", "B": "O Conselho Federal de Serviço Social será mantido\nexclusivamente por contribuições e taxas arrecadadas\npelos Conselhos Regionais de Serviço Social.", "C": "São atribuições privativas do assistente social elaborar,\ncoordenar, executar e avaliar planos, programas e\nprojetos que sejam do âmbito de atuação do serviço\nsocial com participação da sociedade civil.", "D": "O planejamento, a organização e a administração de\nprojetos em unidades de serviço social somente\npoderão ser exercidos por assistentes sociais.", "E": "Os Conselhos Regionais de Serviço Social são\nresponsáveis pela aprovação dos respectivos\nregimentos internos no fórum máximo de deliberação\ndo conjunto CFESS/CRESS."}, "g": "D", "j": "Lei 8.662/93: o planejamento, organizacao e administracao de projetos em unidades de servico social somente podem ser exercidos por assistentes sociais (atribuicao privativa)."}, {"id": "1830084", "d": "servico_social", "a": ["Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal", "Assistência Social no Serviço Social", "Lei Orgânica da Assistência Social – LOAS – Lei 8.742 de 1993 e Lei nº 12.435 de 2011", "Política Nacional de Assistência Social – PNAS"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Constituição Federal de 1988 trouxe uma nova concepção\nà assistência social brasileira, no sentido de passar a\nconsiderá-la como parte do campo dos direitos, da\nuniversalização dos acessos e da responsabilidade estatal.\nAssim, a assistência social foi incluída no âmbito da\nseguridade social e regulamentada pela Lei Orgânica da\nAssistência Social (LOAS). A respeito da Política Nacional de\nAssistência Social (PNAS) e da LOAS, assinale a alternativa\nincorreta.", "alt": {"A": "A proteção social básica é a modalidade de\natendimento assistencial que se destina a famílias e\nindivíduos em situação de risco pessoal e social.", "B": "A proteção social deve garantir os seguintes tipos de\nsegurança à população: segurança de sobrevivência (de\nrendimento e de autonomia); segurança de acolhida; e\nsegurança da vivência familiar ou do convívio.", "C": "O conceito de proteção social adotado pela PNAS\nabrange as formas seletivas de distribuição e de\nredistribuição de bens materiais e culturais, assim\ncomo os princípios reguladores e as normas que fazem\nparte da vida das coletividades.", "D": "O conceito de família adotado pela PNAS considera a\nunião de pessoas que se dê por meio de laços\nconsanguíneos, afetivos e(ou) de solidariedade.", "E": "Os serviços, os programas, os projetos e os benefícios\ndo Sistema Único de Assistência Social (SUAS) têm foco\nprioritário na atenção às famílias, a seus membros e\naos indivíduos. O território, por sua vez, constitui-se\ncomo base de sua organização."}, "g": "A", "j": "A proteção social BÁSICA destina-se a famílias e indivíduos em situação de VULNERABILIDADE (não de risco). É a proteção social ESPECIAL que atende risco pessoal e social. Erro na letra A."}, {"id": "1830082", "d": "servico_social", "a": ["Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua", "Violência e Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "A LGBTfobia é caracterizada pelas violações de direitos e\npelas diversas formas de violência cometidas contra pessoas\nlésbicas, gays, bissexuais, travestis e transexuais em diversos\nespaços sociais. A respeito dessa discussão, assinale a\nalternativa correta.", "alt": {"A": "A sigla LGBT (lésbicas, gays, bissexuais, travestis e\ntransexuais) foi popularizada na última década, a partir\ndas discussões nos movimentos sociais e nas políticas\npúblicas. Embora esteja relacionada à diversidade\nsexual e de gênero e agrupe diversas identidades\nsociais, conforma expressões semelhantes de\npreconceito, que possuem as mesmas características,\nhistórias e demandas por direitos.", "B": "O Brasil está entre os países com menores índices de\ncrimes por LGBTfobia no mundo. Isso porque se\nobserva o respeito aos direitos humanos e à\ndiversidade expresso nas políticas públicas e na\nlegislação específica, implementadas logo após a\npromulgação da Constituição Federal de 1988.", "C": "O binarismo de gênero é uma ideologia que questiona\na imutabilidade da distinção radical entre homens e\nmulheres, fundada unicamente nos corpos biológicos.\nAssim, propõe o desvelamento da realidade social e da\nprodução das relações sociais.", "D": "As pessoas transexuais são aquelas que inserem em\nseus corpos símbolos socialmente associados com o\nfeminino, apesar de terem sido registradas, ao\nnascerem, como sendo do sexo masculino. As travestis\nsão todas as pessoas que se identificam com um gênero\ndistinto do que foi registrado ao nascerem.", "E": "O nome social é aquele que a pessoa deseja ouvir ao\nser abordada. Diversas regulamentações têm\nreconhecido o direito ao uso do nome social, inclusive\nno âmbito do serviço social. Assim, assistentes sociais\ntravestis e transexuais podem utilizar seus nomes\nsociais nos documentos da profissão."}, "g": "E", "j": "Res. CFESS 615/2011 reconhece o uso do nome social no exercício profissional. Demais alternativas têm erros conceituais (binarismo, definição de travesti, Brasil supostamente seguro)."}, {"id": "1830081", "d": "servico_social", "a": ["Serviço Social e Minorias: grupos étnicos/raciais, movimentos sociais, questão agrária e ambiental, questão habitacional, questão de gênero e população de rua"], "ano": "2021", "org": "CRESS", "t": "", "e": "Com relação à discussão sobre gênero no âmbito do serviço\nsocial, julgue os itens que se seguem.\n  I Os estudos sobre gênero surgiram no final do século XX,\nnotadamente nas décadas de 1970 e 1980, sob a\ninfluência das feministas acadêmicas. Todavia, ainda que\nà época não se utilizasse o termo “gênero”, tal\nconcepção já se mostrava presente nos movimentos\nfeministas anteriormente.\n  II O patriarcado, a divisão sexual do trabalho e o feminismo\nsão categorias teóricas que analisam a construção social\ndo masculino e do feminino em uma perspectiva\nhistórica.\n  III A categoria analítica “relações sociais de sexo” não\ncorresponde a uma perspectiva crítica e materialista,\ntendo em vista que não pode ser relacionada às\ncategorias classe social e raça.\n  Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas o item I está certo.", "C": "Apenas o item II está certo.", "D": "Apenas o item III está certo.", "E": "Todos os itens estão certos."}, "g": "B", "j": "Apenas I correto. II equivoca-se ao classificar feminismo como categoria teórica (é movimento social/perspectiva). III nega caráter materialista das relações sociais de sexo (Kergoat)."}, {"id": "1830080", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993"], "ano": "2021", "org": "CRESS", "t": "", "e": "O atual Código de Ética do Assistente Social foi instituído em\n1993, a partir da necessidade de se estabelecer, no âmbito da\ncategoria profissional, novos valores éticos, fundamentados\nem uma definição mais abrangente de compromisso com os\nusuários. Conforme o Código de Ética de 1993, assinale a\nalternativa incorreta.", "alt": {"A": "A violação do sigilo profissional é permitida em\ndeterminadas situações.", "B": "É proibido ao assistente social substituir profissional\nque tenha sido exonerado, demitido ou transferido por\ndefender os princípios da ética profissional, enquanto\nainda existirem os motivos da exoneração, da demissão\nou da transferência.", "C": "O assistente social tem como dever denunciar aos\nórgãos competentes toda forma de censura,\ncerceamento da liberdade ou policiamento de\ncomportamentos, salvo se sofrer algum tipo de\nameaça.", "D": "Quando ocupante de cargo de chefia, o assistente\nsocial tem o dever de liberar subordinados que\ndesejem participar de estudos e pesquisas, com o\nobjetivo de aprimorar-se profissionalmente.", "E": "Caso receba a pena de suspensão, o profissional terá o\nexercício interditado, em todos os estados brasileiros,\npor, no máximo, dois anos."}, "g": "C", "j": "O dever de denunciar (art. 5º do Código de Ética) é incondicional, não há ressalva por ameaça. Erro na letra C."}, {"id": "1830079", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Desde seu surgimento até os dias atuais, a profissão de\nassistente social no Brasil está intimamente relacionada ao\nenfrentamento da chamada questão social. No que se refere\na esse assunto, assinale a alternativa incorreta.", "alt": {"A": "A questão social pode ser definida como o conjunto de\nmanifestações da desigualdade social engendrada e\nconstitutiva da sociedade capitalista.", "B": "A primeira escola de serviço social, criada na capital\npaulista em 1936, adotou uma abordagem da questão\nsocial com enfoque individualista, psicologizante e\nmoralizador. As diversas manifestações da questão\nsocial eram então vistas como problemas advindos dos\ncomportamentos e valores dos “clientes”, que\ndeveriam ser integrados às relações sociais vigentes.", "C": "A visão da categoria profissional acerca da questão\nsocial adquiriu perspectiva crítica ao longo das\ndécadas, com especial contribuição das ciências sociais\ne da criação e da expansão da pós-graduação na\nárea (com seus cursos de mestrado e doutorado) na\ndécada de 1970.", "D": "As décadas de 1980 e 1990 foram adversas para as\npolíticas sociais, a partir do avanço neoliberal que\nerodiu as bases do sistema de proteção social no País.\nEssa tendência teve continuidade no advento dos anos\n2000, por meio dos processos de globalização, da\nvalorização crescente do capital financeiro e de suas\ngrandes corporações transnacionais, das mídias e das\nestruturas mundiais de poder.", "E": "Apesar das metamorfoses no mundo do trabalho,\nadvindas dos processos de reestruturação\nprodutiva capitalista observados no início do\nmilênio (especialmente após a crise econômica de\n2008), é correto afirmar que a questão social\npermanece com as mesmas características dos anos\n1930. Isso porque a precarização, a insegurança e a\nvulnerabilidade do trabalho e das condições de vida\ndos trabalhadores também permanecem com o\nmesmo perfil."}, "g": "E", "j": "E é falsa: a questão social passa por metamorfoses contemporâneas (Iamamoto), não permanece com 'as mesmas características dos anos 1930'."}, {"id": "1830078", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Política Nacional de Fiscalização, base estruturante da\nfiscalização do exercício profissional, é constituída por um\nconjunto de instrumentos legais: as resoluções do Conselho\nFederal de Serviço Social; a Lei de Regulamentação; o Código\nde Ética; o Estatuto do Conjunto CFESS/CRESS; os regimentos\ninternos; o Código Processual de Ética; e o Código Eleitoral,\nentre outros. Acerca da Política Nacional de Fiscalização,\nassinale a alternativa incorreta.", "alt": {"A": "Caracteriza-se como infração à Lei n.° 8.662/1993 o\nexercício de atividade, tarefa ou função de atribuição\nprivativa do assistente social. Nesse caso, poderá ou\nnão ser aplicada multa, a depender das medidas\nadministrativas, criminais ou cíveis adotadas.", "B": "Somente profissionais inscritos no respectivo Conselho\nRegional de Serviço Social poderão ser designados\ncomo assistentes sociais. Tal inscrição é obrigatória\npara profissionais que ocupem cargo ou tenham\ncontrato ou registro sob a denominação de assistente\nsocial – mesmo que estejam em “desvio de função”.", "C": "Poderá ser utilizado instrumento público de\nprocuração para requerer a inscrição junto ao Conselho\nRegional de Serviço Social. Entretanto, somente o\nprofissional poderá receber a cédula ou carteira de\nidentidade profissional.", "D": "O setor administrativo do Conselho Regional de Serviço\nSocial é responsável por instruir os pedidos de inscrição\ndos profissionais, que serão posteriormente\nsubmetidos a parecer da comissão de inscrição e à\naprovação da diretoria. No ato do pedido de inscrição,\no funcionário do setor administrativo deverá entregar\nà pessoa que solicita o registro profissional, se\nsolicitada, uma cópia da Consolidação das Resoluções\ndo Conselho Federal de Serviço Social e esclarecer os\nparâmetros estabelecidos nessa regulamentação.", "E": "Qualquer indício de violação disciplinar cometida por\nassistente social inscrito deverá ser encaminhado pelo\nConselho Regional à respectiva presidência, por meio\nde documentação comprobatória, ainda que tenha\ntomado conhecimento da irregularidade por meio da\nimprensa."}, "g": "A", "j": "A PNF prevê aplicação automática de multa por exercício de atribuição privativa, independentemente de medidas administrativas/criminais/cíveis. Erro na letra A."}, {"id": "1830076", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Códigos de Ética de 1947-1975 e de 1986", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993"], "ano": "2021", "org": "CRESS", "t": "", "e": "No bojo da luta da sociedade brasileira pela\nredemocratização do País na década de 1980, parte da\ncategoria profissional de assistentes sociais, alinhada com os\nmovimentos sindicais e outros movimentos sociais, passou a\nintegrar o Conselho Federal de Serviço Social e os Conselhos\nRegionais de Serviço Social. Como consequência, a partir de\n1983, começou a ocorrer um amplo debate, promovido pelo\nconjunto CFESS/CRESS junto à categoria, no sentido de se\ndiscutir a reformulação das legislações de regulamentação da\nprofissão. Quanto aos resultados desse processo de discussão\nno âmbito do serviço social brasileiro, assinale a alternativa\ncorreta.", "alt": {"A": "O Código de Ética de 1986, embora tenha sido fruto de\ndiscussão do conjunto CFESS/CRESS junto à categoria\nde profissionais, não avançou no que diz respeito a\nromper com o enfoque individualista, psicologizante e\nmoralizador adotado pelo Código de Ética de 1975.", "B": "O debate foi reaberto entre os anos 1991 e 1993, sob a\ncoordenação do Conselho Federal de Serviço Social, em\ndiversos eventos: Seminários Nacionais de Ética;\nENESS; VII CBAS; e Encontros Nacionais CFESS/CRESS.\nO resultado foi a aprovação do Código de Ética\nProfissional, no dia 13 de março de 1993, que expressa\no acúmulo do debate profissional nos últimos vinte\nanos do serviço social brasileiro.", "C": "A Lei n.° 8.662/1993, fruto de amplo debate no âmbito\nda categoria, possibilitou melhores condições de\nfiscalização profissional, embora não defina com\nprecisão competências e atribuições privativas dos\nassistentes sociais. Tal Lei também reconheceu\nformalmente o Conselho Federal de Serviço Social, a\nAssociação Brasileira de Ensino e Pesquisa em Serviço\nSocial (ABEPSS) e a Executiva Nacional de Estudantes\nde Serviço Social (ENESSO) como fóruns máximos de\ndeliberação da profissão.", "D": "A ABEPSS é uma entidade de amplitude nacional que\npossui como associados apenas instituições de ensino,\nquais sejam, as unidades de formação acadêmica de\nserviço social presenciais e de ensino a distância.", "E": "O Movimento Estudantil de Serviço Social organizou-se\na partir da década de 1960, sendo que, em 1963, foi\nfundada a ENESSO, entidade máxima de representação\ndos estudantes da área no País. Por ser subordinada\nadministrativamente à ABEPSS, a ENESSO não possui\nestatuto próprio."}, "g": "B", "j": "Código de Ética de 1993 aprovado em 13/03/1993 após debate entre 1991-1993 sob coordenação do CFESS. As demais têm imprecisões factuais sobre ABEPSS, ENESSO, CE-1986 e Lei 8.662/93."}, {"id": "1770340", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Política Nacional de Estágio da Associação Brasileira de\nEnsino e Pesquisa em Serviço Social afirma que a\nmaterialização do estágio curricular supervisionado deve\nocorrer em consonância como os princípios ético-políticos\nexplicitados no Código de Ética dos assistentes sociais, que se\nconstituem como os valores norteadores do projeto\nprofissional do serviço social brasileiro. Além desses valores,\noutros princípios devem nortear a realização do estágio em\nserviço social. Sendo assim, assinale a alternativa que não\napresenta um desses princípios.", "alt": {"A": "intersetorialidade", "B": "interdisciplinaridade", "C": "unidade teoria-prática", "D": "articulação entre formação e exercício profissional", "E": "articulação entre universidade e sociedade"}, "g": "A", "j": "Política Nacional de Estágio (ABEPSS, 2010) lista: indissociabilidade ensino-pesquisa-extensão, interdisciplinaridade, unidade teoria-prática, articulação formação-exercício profissional, articulação universidade-sociedade. Intersetorialidade não consta."}, {"id": "1770339", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Proteção Social ao Idoso"], "ano": "2021", "org": "CRESS", "t": "", "e": "De acordo com o Estatuto do Idoso, é assegurada a\natenção integral à saúde do idoso, por intermédio do SUS,\ngarantindo-lhe o acesso universal e igualitário, em conjunto\narticulado e contínuo das ações e dos serviços para a\nprevenção, promoção, proteção e recuperação da saúde,\nincluindo a atenção especial às doenças que afetam\npreferencialmente os idosos. Com base nesse Estatuto,\nassinale a alternativa incorreta.", "alt": {"A": "O idoso internado ou em observação tem direito à\nacompanhante familiar, devendo o órgão de saúde\nproporcionar as condições adequadas para a sua\npermanência em tempo integral, segundo o critério\nmédico.", "B": "É assegurado ao idoso enfermo o atendimento\ndomiciliar pela perícia médica do Instituto Nacional do\nSeguro Social (INSS), pelo serviço público de saúde ou\npelo serviço privado de saúde, contratado\nou conveniado, que integre o SUS, para a expedição do\nlaudo de saúde necessário ao exercício de seus direitos\nsociais e de isenção tributária.", "C": "Em todo atendimento de saúde, os maiores de oitenta\nanos de idade terão preferência especial sobre os\ndemais idosos, exceto em caso de emergência.", "D": "Os casos de suspeita ou confirmação de violência\npraticada contra idosos serão objeto de notificação\ncompulsória pelos serviços de saúde públicos e\nprivados à autoridade sanitária, bem como serão\nobrigatoriamente comunicados por eles a quaisquer\ndos seguintes órgãos: autoridade policial; Ministério\nPúblico; e Conselhos Municipal, Estadual e Nacional do\nIdoso.", "E": "É vedada a discriminação do idoso nos planos de saúde,\ncom a cobrança de valores diferenciados em razão da\nidade."}, "g": "A", "j": "Art. 16 Estatuto do Idoso assegura direito a 'acompanhante', sem restringir a 'familiar'. A questão adiciona 'familiar' que não consta na lei, tornando A incorreta."}, {"id": "1770338", "d": "servico_social", "a": ["Saúde", "Sistema Único de Saúde - SUS: Lei Orgânica da Saúde - LOS - Lei nº 8.080 de 1990 e Lei  nº 8.142 de 1990", "Serviço Social e Saúde do Trabalhador"], "ano": "2021", "org": "CRESS", "t": "", "e": "De acordo com a Lei n.o\n 8.080/1990, um conjunto de ações\nque proporcionam o conhecimento, a detecção ou a\nprevenção de qualquer mudança nos fatores determinantes\ne condicionantes da saúde individual ou coletiva, com a\nfinalidade de recomendar e adotar as medidas de prevenção\ne controle das doenças ou agravos, diz respeito à", "alt": {"A": "vigilância nutricional.", "B": "vigilância sanitária.", "C": "vigilância epidemiológica.", "D": "saúde do trabalhador.", "E": "assistência terapêutica integral."}, "g": "C", "j": "Art. 6º §2º Lei 8.080/90 define exatamente vigilância epidemiológica: conjunto de ações que proporcionam o conhecimento, detecção ou prevenção de mudanças nos fatores determinantes/condicionantes da saúde."}, {"id": "1770337", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Serviço Social no campo sócio jurídico", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família"], "ano": "2021", "org": "CRESS", "t": "", "e": "O Estatuto da Criança e do Adolescente afirma, no que diz\nrespeito às medidas socioeducativas, que a internação\nconstitui medida privativa da liberdade, sujeita aos princípios\nde brevidade, excepcionalidade e respeito à condição\npeculiar de pessoa em desenvolvimento. Quanto à\ninternação, assinale a alternativa correta.", "alt": {"A": "A medida comporta prazo determinado, podendo ser\nreavaliada, mediante decisão fundamentada, no\nmínimo, a cada seis meses.", "B": "A internação, antes da sentença, pode ser determinada\npelo prazo máximo de 45 dias.", "C": "Em hipótese alguma, o período de internação excederá\ndois anos.", "D": "Atingido o limite máximo de internação, o adolescente\nserá liberado, colocado em liberdade assistida ou para\na prestação de serviços à comunidade.", "E": "Não é permitida a realização de atividades externas."}, "g": "B", "j": "Art. 108 ECA: internação antes da sentença, prazo máximo de 45 dias. A: reavaliação no máximo (não mínimo) a cada 6 meses. C: período não excede 3 anos (não 2). D: liberado, semiliberdade OU liberdade assistida. E: atividades externas permitidas."}, {"id": "1770336", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Serviço Social no campo sócio jurídico", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família"], "ano": "2021", "org": "CRESS", "t": "", "e": "De acordo com o Estatuto da Criança e do Adolescente,\nnenhum adolescente será privado de sua liberdade senão em\nflagrante de ato infracional ou por ordem escrita e\nfundamentada da autoridade judiciária competente, tendo\ndireito à identificação dos responsáveis por sua apreensão e\ndevendo ser informado acerca de seus direitos. No que diz\nrespeito à prestação de serviços à comunidade, julgue os\nitens subsequentes.\n    I A prestação de serviços à comunidade não deve se\nrealizar por período excedente a seis meses.  \nII As tarefas serão atribuídas conforme as aptidões do\nadolescente e deverão ser cumpridas durante jornada\nmáxima de seis horas semanais.  \nIII As tarefas não poderão ser realizadas aos sábados,\ndomingos e feriados.  \nIV A prestação de serviços à comunidade deve se realizar\njunto a entidades assistenciais, hospitais, escolas e\noutros estabelecimentos congêneres.\n    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "C", "j": "Art. 117 ECA: I correto (não excederá 6 meses); II falso (8h semanais, não 6); III falso (pode aos sábados/domingos); IV correto (entidades assistenciais, hospitais, escolas). Total: 2 itens."}, {"id": "1770334", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Serviço Social no campo sócio jurídico", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família"], "ano": "2021", "org": "CRESS", "t": "", "e": "O Estatuto da Criança e do Adolescente afirma que o\nafastamento da criança ou do adolescente do convívio\nfamiliar é de competência exclusiva da autoridade judiciária\ne importará na deflagração, a pedido do Ministério Público ou\nde quem tenha legítimo interesse, de procedimento judicial\ncontencioso, no qual se garanta aos pais ou ao responsável\nlegal o exercício do contraditório e da ampla defesa. Crianças\ne adolescentes somente poderão ser encaminhados às\ninstituições que executam programas de acolhimento\ninstitucional, governamentais ou não, por meio de uma", "alt": {"A": "certidão de encaminhamento.", "B": "certidão de acolhimento.", "C": "guia de acolhimento.", "D": "guia de abrigamento.", "E": "guia de encaminhamento."}, "g": "C", "j": "Art. 101 §3º ECA estabelece a Guia de Acolhimento como instrumento obrigatório para encaminhamento a programas de acolhimento institucional."}, {"id": "1770332", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Quanto ao projeto ético-político do serviço social, julgue os\nitens seguintes.    \nI Não cabem, no projeto ético-político contemporâneo do\nserviço social, posturas teóricas conservadoras,\nvinculadas a pressupostos filosóficos que vislumbrem a\nmanutenção da ordem.\n  II O projeto ético-político do serviço social pressupõe, em\nsi mesmo, um espaço democrático de construção\ncoletiva permanentemente em disputa. Essa afirmação\nindica a presença do pluralismo de ideias em seu interior.\n  III O projeto ético-político do serviço social é expressão das\ncontradições que particularizam a profissão.\n  IV Os projetos societários estão presentes na dinâmica de\ntodo e qualquer projeto coletivo, inclusive no projeto\nético-político do serviço social.\n    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Todos os 4 itens corretos. Netto: projeto ético-político é incompatível com conservadorismo (I), é espaço democrático plural (II), expressa contradições da profissão (III), e dialoga com projetos societários (IV)."}, {"id": "1770331", "d": "servico_social", "a": ["Saúde", "Serviço Social na Saúde", "Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "As atribuições e as competências dos assistentes sociais são\norientadas e norteadas por direitos e deveres constantes no\nCódigo de Ética Profissional e na Lei de Regulamentação da\nProfissão, que devem ser observados e respeitados. De\nacordo com os parâmetros para a atuação de assistentes\nsociais na Política de Saúde, assinale a alternativa incorreta.", "alt": {"A": "A saúde do trabalhador vem se apresentando como\numa importante área de atuação do assistente social\nnas últimas décadas.", "B": "O movimento de reforma sanitária salientou a\nimportância da determinação social sustentada nas\ncategorias de trabalho e na reprodução da vida. Nessa\nperspectiva, são fundamentais o contexto e as\ncondições sociais que impactam o processo\nsaúde-doença.", "C": "Os assistentes sociais na saúde atuam em quatro\ngrandes eixos, sendo um deles o de investigação,\nplanejamento e gestão.", "D": "Nas equipes de saúde mental, o assistente social deve\ncontribuir para que a reforma psiquiátrica alcance seu\nprojeto ético-político.", "E": "O atendimento direto aos usuários acontece em\ndiversos espaços de atuação profissional na saúde,\nsendo menos frequente (no atendimento direto) a\npresença das ações socioeducativas."}, "g": "E", "j": "Os Parâmetros para Atuação do AS na Saúde (CFESS, 2010) elegem as ações socioeducativas como uma das mais frequentes no atendimento direto, não menos frequente. Erro na letra E."}, {"id": "1770329", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2021", "org": "CRESS", "t": "", "e": "Com base nas contribuições de Marilda Villela Iamamoto\nacerca da relação entre trabalho e serviço social, julgue os\nitens subsequentes.\n    I O serviço social, ainda que regulamentado como uma\nprofissão liberal, não tem tal tradição na sociedade\nbrasileira em sua alocação no mercado de trabalho.\n  II Os assistentes sociais são proprietários de sua força de\ntrabalho qualificada, mas não dispõem de todos os meios\nnecessários para a efetivação de seu trabalho, pois parte\ndesses meios lhes é fornecida pelas entidades\nempregadoras.\n  III O assistente social tem como instrumento básico de\ntrabalho a linguagem.\n  IV A atividade do assistente social depende\nfundamentalmente do profissional, que dispõe de\nautonomia para direcionar sua prática conforme suas\nnecessidades e exigências.    \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "D", "j": "Iamamoto: I, II e III corretos. IV falso — a autonomia do AS é RELATIVA, condicionada pelas instituições empregadoras. Total: 3 itens."}, {"id": "1770328", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social", "Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Marilda Villela Iamamoto afirma que o serviço social tem na\nquestão social a base de sua fundação como especialização\ndo trabalho. A respeito da questão social, assinale a\nalternativa incorreta.", "alt": {"A": "Os assistentes sociais trabalham na tensão entre a\nprodução da desigualdade e a produção da rebeldia e\nda resistência.", "B": "A desigualdade que preside o processo de\ndesenvolvimento do País tem sido uma de suas\nparticularidades históricas. O moderno se constrói por\nmeio do arcaico, o que atribui um ritmo histórico\nparticular ao processo de mudanças. Essa coexistência\nde temporalidades históricas desiguais faz com que a\nquestão social apresente, na atualidade, tanto\nmarcas do passado quanto marcas do presente,\nequilibrando-a e amenizando-a.", "C": "Decifrar as novas mediações por meio das quais se\nexpressa a questão social na atualidade é fundamental\npara o serviço social em uma dupla perspectiva: tanto\nem apreender as diversas expressões que as\ndesigualdades sociais assumem, quanto em vislumbrar\nformas de resistência e de defesa da vida.", "D": "É necessário, atualmente, repensar a questão social,\nvisto que as bases de sua produção sofrem uma\nprofunda transformação com as inflexões verificadas\nno padrão de acumulação.", "E": "Apreender a questão social é também captar as\ndiversas formas de pressão social, de invenção e de\nreinvenção da vida."}, "g": "B", "j": "B é falsa: a coexistência de temporalidades desiguais APROFUNDA a questão social, não a equilibra/ameniza (Iamamoto)."}, {"id": "1770327", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Considerado como um marco histórico e político, que\npossibilitou a transição para um serviço social renovado, o\nCongresso que ficou conhecido como o “Congresso da\nVirada” foi o", "alt": {"A": "III Congresso Nacional de Assistentes Sociais, em 1979.", "B": "III Congresso Nacional de Assistentes Sociais, em 1978.", "C": "III Congresso Nacional de Assistentes Sociais, em 1976.", "D": "II Congresso Nacional de Assistentes Sociais, em 1979.", "E": "II Congresso Nacional de Assistentes Sociais, em 1978."}, "g": "A", "j": "III CBAS de 1979 é conhecido como Congresso da Virada — marco da transição do conservadorismo ao SS renovado."}, {"id": "1770326", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Em Ditadura e Serviço Social: Uma análise do Serviço Social\nno Brasil pós-64, José Paulo Netto afirma que é inconteste\nque o serviço social no Brasil, até a primeira metade da\ndécada de 1960, não apresentava polêmicas de relevo,\nmostrava uma relativa homogeneidade nas suas projeções\ninterventivas, sugeria uma grande unidade nas suas\npropostas profissionais e carecia de uma elaboração teórica\nsignificativa. A ruptura com esse cenário tem suas bases\nno(na)", "alt": {"A": "radicalização do conservadorismo.", "B": "laicização do serviço social.", "C": "messianismo profissional.", "D": "filantropização do serviço social.", "E": "militantismo."}, "g": "B", "j": "J. P. Netto: a ruptura com o conservadorismo tem suas bases na laicização do SS (autonomização frente à Igreja/conservadorismo)."}, {"id": "1770325", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "Conforme o Estatuto do Conjunto CFESS/CRESS, julgue os\nitens que se seguem.    \nI O fórum máximo de deliberação da profissão é o\nEncontro Nacional CFESS/CRESS, que será convocado\nanualmente, na forma estabelecida pelo Estatuto.  \nII O Conselho Federal de Serviço Social poderá homologar\na criação e a extinção ou determinar a alteração da\njurisdição de qualquer Conselho Regional existente,\nmediante a aprovação do Encontro Nacional\nCFESS/CRESS e o atendimento dos critérios estabelecidos\npela Consolidação das Resoluções do Conselho Federal\nde Serviço Social.\n  III O Conselho Federal e os Conselhos Regionais de Serviço\nSocial mantêm com os órgãos de Administração Pública\nvínculo funcional ou hierárquico.    \nAssinale a alternativa correta.", "alt": {"A": "Apenas o item II está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "I e II corretos (Estatuto CFESS/CRESS). III falso: CFESS e CRESS são autarquias e NÃO mantêm vínculo funcional/hierárquico com a Administração Pública."}, {"id": "1770324", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "No que se refere à fiscalização do exercício profissional do\nassistente social, julgue os próximos itens.\n    I Os agentes fiscais serão contratados, mediante concurso\npúblico, pelos Conselhos Regionais de Serviço Social, por\nmeio de processo seletivo, devendo ser,\nnecessariamente, assistentes sociais em pleno gozo de\nseus direitos e sendo vedada a contratação daquele que\nesteja respondendo a processo disciplinar e(ou) ético.  \nII Os agentes fiscais portarão identificação fornecida pelo\nConselho Regional de Serviço Social competente, que\nserá obrigatoriamente exibida no ato da fiscalização ou\nde qualquer outra ação.\n  III Os membros do serviço de fiscalização (agentes fiscais,\nfuncionários administrativos etc.) serão contratados na\nforma da legislação vigente, estando impedidos de\nintegrá-lo: os conselheiros do Conselho Federal e dos\nConselhos Regionais de Serviço Social ou membros de\nseccionais, efetivos ou suplentes; e os profissionais que\nestejam respondendo a processo ético ou disciplinar.\n  IV Compete aos agentes fiscais remeter todos os relatórios\nde fiscalização com constatação de irregularidades à\napreciação da COFI, para as providências cabíveis.    \nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "E", "j": "Res. CFESS 512/2007: todos os 4 itens corretos (concurso público para agentes fiscais; identificação obrigatória; impedimentos para conselheiros; encaminhamento à COFI)."}, {"id": "1770322", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "De acordo com a Resolução CFESS n.o\n 512/2007, para a\nrealização da função de fiscalização do exercício da profissão\ndo assistente social, os Conselhos Regionais deverão manter,\nem caráter permanente, uma Comissão de Orientação e\nFiscalização (COFI). A respeito desse assunto, assinale a\nalternativa incorreta.", "alt": {"A": "A comissão é formada, no mínimo, por três membros,\nsendo constituída por: um conselheiro, a quem caberá\na coordenação; agentes fiscais concursados; e\nassistentes sociais inscritos no Conselho Regional de\nServiço Social, em pleno gozo de seus direitos, a convite\nda direção do Conselho.", "B": "As ações referentes à fiscalização serão executadas por\nconselheiros, membros das seccionais e(ou) agentes\nfiscais. Os conselheiros e os coordenadores seccionais\nsão fiscais natos.", "C": "Para a atuação da COFI, os Conselhos Regionais de\nServiço Social deverão garantir uma estrutura\nadequada aos requisitos técnicos e operacionais\nnecessários à viabilização da PNF.", "D": "Para a execução e a concretização da atuação\ntécnico-política da COFI, os Conselhos Regionais de\nServiço Social deverão priorizar ações que viabilizem\nmeios e recursos financeiros para a estruturação de um\nserviço de orientação e fiscalização, integrado por\nagente fiscal e funcionários administrativos, que\nresponderão pelas demandas rotineiras do setor, em\ncumprimento do plano de ação definido pela COFI e\npor sua organização administrativa, sempre sob a\ndireção dessa Comissão.", "E": "As atividades exercidas por todos os integrantes da\nCOFI terão caráter voluntário e, portanto, sempre sem\nremuneração."}, "g": "E", "j": "E falso: agentes fiscais são profissionais contratados e remunerados, não voluntários. A Res. CFESS 512/2007 não impõe gratuidade às atividades."}, {"id": "1770321", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993"], "ano": "2021", "org": "CRESS", "t": "", "e": "Considerando o disposto na Lei n.o\n 8.662/1993, assinale e\nalternativa incorreta.", "alt": {"A": "A duração do trabalho do assistente social é de trinta\nhoras semanais.", "B": "O Conselho Federal de Serviço Social e os Conselhos\nRegionais de Serviço Social constituem, em seu\nconjunto, uma entidade com personalidade jurídica e\nforma federativa, com o objetivo básico de disciplinar\ne defender o exercício da profissão de assistente social\nem todo o território nacional.", "C": "Cabe ao Conselho Federal de Serviço Social e aos\nConselhos Regionais de Serviço Social representar, em\njuízo e fora dele, os interesses gerais e individuais dos\nassistentes sociais, no cumprimento desta Lei.", "D": "Os Conselhos Regionais de Serviço Social são dotados\nde autonomia administrativa, estando financeiramente\ndependentes de sua vinculação ao Conselho Federal.", "E": "Compete ao Conselho Federal de Serviço Social, na\nqualidade de órgão normativo de grau superior,\nfuncionar como Tribunal Superior de Ética Profissional,\nentre outras atribuições."}, "g": "D", "j": "Art. 11 da Lei 8.662/93: CRESS têm autonomia administrativa E financeira, sem prejuízo de sua vinculação ao CFESS. D inverte ao dizer 'financeiramente dependentes'."}, {"id": "1770319", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2021", "org": "CRESS", "t": "", "e": "Em conformidade com a Lei n.o\n 8.662/1993, que dispõe sobre\na profissão de assistente social, assinale a alternativa que não\napresenta atribuição(ões) privativa(s) desse profissional.", "alt": {"A": "orientar indivíduos e grupos de diferentes segmentos\nsociais no sentido de identificar recursos e de fazer uso\ndeles no atendimento e na defesa de seus direitos", "B": "realizar vistorias, perícias técnicas, laudos periciais e\npareceres sobre a matéria de serviço social", "C": "treinamento, avaliação e supervisão direta de\nestagiários de serviço social", "D": "elaborar provas, presidir e compor bancas de exames e\ncomissões julgadoras de concursos ou outras formas\nde seleção para assistentes sociais ou em que sejam\naferidos conhecimentos inerentes ao serviço social", "E": "coordenar seminários, encontros, congressos e\neventos assemelhados sobre assuntos de serviço social"}, "g": "A", "j": "Art. 5º Lei 8.662/93 (atribuições privativas) não inclui 'orientar indivíduos e grupos' — esta é competência do art. 4º (não privativa). As demais (vistorias, supervisão de estágio, bancas, coordenar eventos) estão no art. 5º."}, {"id": "1764653", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2021", "org": "CRESS", "t": "", "e": "A Administração Federal compreende a administração direta,\nque se constitui dos serviços integrados na estrutura\nadministrativa da presidência da República e dos ministérios,\ne a administração indireta, que compreende as seguintes\ncategorias de entidades, dotadas de personalidade jurídica\nprópria: autarquias; empresas públicas; sociedades de\neconomia mista; e fundações públicas. Entre as autarquias,\nhá o Conselho Federal de Serviço Social e os Conselhos\nRegionais de Serviço Social, que constituem, em seu\nconjunto, uma entidade com personalidade jurídica e forma\nfederativa, com o objetivo básico de disciplinar e defender o\nexercício da profissão de assistente social em todo o território\nnacional. Os Conselhos Regionais de Serviço Social são\ndotados de autonomia administrativa e financeira, sem\nprejuízo de sua vinculação ao Conselho Federal, nos termos\nda legislação em vigor. Cabe ao Conselho Federal de Serviço\nSocial e aos Conselhos Regionais de Serviço Social\nrepresentar, em juízo e fora dele, os interesses gerais e\nindividuais dos assistentes sociais, nos termos da legislação\nem vigor. Considerando essas informações, assinale a\nalternativa que apresenta atribuição que está fora da\ncompetência dos Conselhos Regionais de Serviço Social.", "alt": {"A": "organizar o registro profissional dos assistentes sociais\ne o cadastro das instituições e obras sociais, públicas e\nprivadas, ou de fins filantrópicos", "B": "fiscalizar o exercício da profissão de assistente social na\nrespectiva região e expedir carteiras profissionais de\nassistentes sociais, fixando a respectiva taxa", "C": "zelar pela observância do Código de Ética Profissional,\nfuncionando como Tribunais Regionais de Ética\nProfissional", "D": "julgar, em última instância, os recursos contra as\nsanções impostas pelos próprios Conselhos Regionais", "E": "aplicar as sanções previstas no Código de Ética\nProfissional"}, "g": "D", "j": "Julgar em última instância os recursos contra sanções dos CRESS é competência do CFESS (Tribunal Superior de Ética), não dos CRESS."}, {"id": "1111252", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "As  Resoluções  do  Conselho  Federal  do  Serviço  Social \norientam  a  prática  profissional  na  direção  da  ética \nprofissional. Considerando a Resolução CFESS n.º 489/2006, \nque estabelece normas que vedam condutas discriminatórias \nou preconceituosas, por orientação e expressão sexual entre \npessoas do mesmo sexo, na prática institucional, o assistente \nsocial deverá denunciar", "alt": {"A": "ao  Conselho  Regional  de  Serviço  Social  as  pessoas \njurídicas,  desde  que  tenham  natureza  pública,  ou  as \npessoas  físicas,  somente  quando exercerem a  função \nde  assistentes  sociais,  que  forem  coniventes  ou \npraticarem  atos  ou  manifestarem  qualquer  conduta \nrelativa a preconceito e à discriminação por orientação \nsexual entre pessoas do mesmo sexo.", "B": "ao  Conselho  Regional  de  Serviço  Social  somente as\npessoas  físicas,  quando  exercerem  a  função  de\nassistentes  sociais,  que  forem  coniventes  ou \npraticarem  atos  ou  manifestarem  qualquer  conduta \nrelativa a preconceito e à discriminação por orientação \nsexual  entre  pessoas  do  mesmo  sexo.  O  Conselho \nRegional  de  Serviço  Social  não  pode  tomar \nprovidências diante de denúncias de pessoas jurídicas.", "C": "ao Conselho Regional de Serviço Social de sua área de \nação as pessoas jurídicas, privadas ou públicas, ou as \npessoas  físicas,  sejam assistentes  sociais  ou  não,  que \nforem coniventes ou praticarem atos ou manifestarem \nqualquer  conduta  relativa  a  preconceito  e  à \ndiscriminação por orientação sexual entre pessoas do \nmesmo sexo.", "D": "ao  Conselho  Regional  de  Serviço  Social  as  pessoas\nfísicas,  sejam assistentes  sociais  ou  não, e denunciar, \nna delegacia de polícia, as pessoas jurídicas, privadas \nou públicas, que forem coniventes ou praticarem atos \nou  manifestarem  qualquer  conduta  relativa  a \npreconceito  e  à  discriminação  por  orientação  sexual \nentre pessoas do mesmo sexo.", "E": "as  pessoas  jurídicas,  privadas  ou  públicas,  ou  as \npessoas  físicas,  sejam assistentes  sociais  ou  não,  que \nforem coniventes ou praticarem atos ou manifestarem \nqualquer  conduta  relativa  a  preconceito  e  à \ndiscriminação por orientação sexual entre pessoas do \nmesmo sexo na delegacia de polícia e enviar cópia do \nboletim de ocorrência ao Conselho Federal de Serviço \nSocial,  para  que  tome  as  providências  cabíveis  em \nrelação à prática discriminatória realizada."}, "g": "C", "j": "Res. CFESS 489/2006: AS deve denunciar ao CRESS de sua área pessoas jurídicas (privadas/públicas) ou físicas (AS ou não) que pratiquem discriminação por orientação sexual."}, {"id": "1111249", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "Para  realizar  o  exercício  profissional  nas  instituições, de \nforma a atender os princípios expressos no Código de Ética, e \nter  atitudes  que  possibilitem  uma  prática  profissional \ndinâmica e  crítica,  faz‐se  necessário  que  o assistente  social \nrealize  uma  análise  de  conjuntura.  Considerando  essa \ninformação,  assinale  a  alternativa  que  não  apresenta  uma \ncompetência que permite que o profissional realize a análise \ncrítica da realidade.", "alt": {"A": "a partir de uma perspectiva de totalidade, realizar a \napreensão crítica dos processos sociais de produção e \nreprodução das relações sociais", "B": "realizar a análise da trajetória histórica da sociedade \nbrasileira,  apreendendo  as  particularidades  do \ndesenvolvimento do capitalismo no Brasil", "C": "adotar uma postura eclética e pluralista, no  sentido \nde analisar a sociedade sobre os diferentes prismas e \nas diferentes correntes teóricas", "D": "desvelar as possibilidades de intervenção profissional \nna realidade, a partir das análises sobre o significado \nsocial  da  profissão  e  de  seu  desenvolvimento  \nsócio‐histórico", "E": "reconhecer  as  demandas  expressas  na  sociedade, \nobjetivando  formular  respostas  profissionais  para  o \nenfrentamento das expressões da questão social"}, "g": "C", "j": "Postura eclética e pluralista é incompatível com análise crítica da realidade. O pluralismo do Código de Ética não significa ecletismo teórico."}, {"id": "1111248", "d": "servico_social", "a": ["Políticas Sociais", "Políticas Sociais pós Constituição Federal de 1988 e no contexto neoliberal", "Serviço Social na Empresa, Responsabilidade Social, Terceiro Setor, ONGs, Entidades Sociais, Recursos Humanos e Gestão de Pessoas", "Trabalho e Serviço Social", "Transformações Societárias, mundo do trabalho e Estado capitalista", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A  formação  profissional  do  assistente  social  na  sociedade \nbrasileira  contempla  a  necessidade  de  acompanhar  as \ntransformações societárias. Com base na perspectiva crítica \nreferente  às  transformações  societárias  contemporâneas, \nassinale a alternativa correta.", "alt": {"A": "A  reestruturação  produtiva,  caracterizada  pela \nmodernização  da  economia  e  pela  globalização  das \nrelações  sociais,  contribui  para  a  estagnação  da \nquestão social na sociedade contemporânea.", "B": "A  partir  dos  anos  1990,  houve  um  aumento  das \nparcerias  entre  o  Estado  e  a  sociedade  civil,  com \ncompartilhamento e  repasse  das  funções  estatais  no \natendimento  das  necessidades  sociais  da  população \npara o terceiro setor. Esse fenômeno não traz impactos \nnegativos para o cidadão nem para a sociedade, uma vez que o indivíduo continuará a ser assistido em suas \nnecessidades.", "C": "Na  esfera  estatal,  constata‐se  que  o  Estado  realiza  a \nredução  dos  gastos  sociais,  o  que  contribui  para  o \nprocesso  de  desresponsabilização  na  oferta  das \npolíticas sociais, caracterizando o Estado Mínimo.", "D": "As  políticas  sociais  na  sociedade  capitalista  são \nconcebidas como concessões do Estado e incorporam\no  atendimento  integral  das  demandas  da  classe \ntrabalhadora e das classes populares.", "E": "O  aumento  das  organizações  não governamentais  na \noferta  das  políticas  sociais  está  diretamente \nrelacionado  com  o  fortalecimento  da  sociedade  civil, \ncom  o  aumento  do  controle  social  por  parte  da \npopulação e com a conquista de direitos sociais."}, "g": "C", "j": "Perspectiva crítica reconhece o Estado neoliberal como Estado Mínimo, com redução dos gastos sociais e desresponsabilização. As demais são falsas (estagnação da questão social, ausência de impactos negativos do terceiro setor, etc)."}, {"id": "1105627", "d": "servico_social", "a": ["Planejamento, Monitoramento e Avaliação de Planos, Programas e Projetos"], "ano": "2019", "org": "Prefeitura de Cristalina", "t": "", "e": "Myriam Veras Baptista caracteriza o planejamento como um processo  técnico‐político.  Com  base  na  concepção  de planejamento  da  referida  autora,  assinale  a  alternativa correta.", "alt": {"A": "É  um  método  empírico  composto  por  ações rigidamente encadeadas e ordenadas.", "B": "Tem  como  objeto  um  recorte  da  realidade  social totalmente definido e imutável.", "C": "Possui como uma de suas etapas a avaliação, que deve estar presente dialeticamente em todo o seu processo.", "D": "Apresenta  uma  dimensão  política  decorrente  da necessidade  de  sistematização  das  informações  a serem coletadas para o estudo da situação‐problema.", "E": "Prevê  a  elaboração  do  plano,  do  programa  e  do projeto,  sendo  que  o  primeiro  apresenta  um  maior nível de detalhamento e o último delineia as decisões de caráter geral do processo."}, "g": "C", "j": "Baptista: avaliação é etapa do planejamento e deve estar presente dialeticamente em todo o processo (não apenas ao final)."}, {"id": "1105619", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2019", "org": "Prefeitura de Cristalina", "t": "", "e": "Não são elementos constitutivos do Projeto Ético‐Político do Serviço Social", "alt": {"A": "os princípios e valores ético‐políticos.", "B": "as matrizes teórico‐metodológicas críticas.", "C": "as questões sociais.", "D": "as críticas radicais à ordem social vigente.", "E": "os históricos de luta e os posicionamentos políticos da \ncategoria profissional."}, "g": "C", "j": "PEP responde à questão social, mas 'as questões sociais' (no plural, como apresentado) não são elementos constitutivos do projeto. Os demais (princípios, matrizes críticas, crítica à ordem, histórico de luta) são elementos clássicos."}, {"id": "1105616", "d": "servico_social", "a": ["Proteção Social à Criança, ao Adolescente e à Família", "Serviço Social no campo sócio jurídico", "Proteção à Mulher, à Criança e ao Adolescente - Proteção a Família"], "ano": "2019", "org": "Prefeitura de Cristalina", "t": "", "e": "O  Estatuto  da  Criança  e  do  Adolescente  (ECA)  é  uma conquista derivada da luta e da articulação dos movimentos sociais e da sociedade civil na defesa e garantia dos direitos da criança e do adolescente no Brasil. Com relação ao ECA e à legislação brasileira  referente à criança e ao adolescente, assinale a alternativa correta.", "alt": {"A": "O ECA adota a doutrina da proteção plena e assegura a prioridade absoluta e a condição de sujeito de direitos às crianças e aos adolescentes.", "B": "A  criança e  o adolescente  têm  direito  à  liberdade  de opinião  e  expressão,  a  brincar,  a  praticar  esportes,  a divertir‐se, a trabalhar e a participar da vida política, na forma da lei.", "C": "A  guarda  confere  à  criança  ou  ao  adolescente  a condição de dependente para todos os fins e efeitos de direito, inclusive os previdenciários.", "D": "Casais que iniciaram o estágio de convivência a fim de realizar a adoção da criança e(ou) do adolescente, mas decidiram se separar, se divorciar ou dissolver a união estável, não poderão adotar conjuntamente.", "E": "Ao adolescente aprendiz, maior de treze anos de idade, são  assegurados  os  direitos  trabalhistas  e previdenciários."}, "g": "C", "j": "Art. 33 §3º ECA: a guarda confere à criança/adolescente a condição de dependente para todos os fins e efeitos de direito, inclusive previdenciários. A: doutrina é da proteção INTEGRAL (não 'plena'). B: ECA não inclui direito a trabalhar. D: podem adotar. E: aprendiz a partir de 14 anos."}, {"id": "1104838", "d": "servico_social", "a": ["Saúde", "Sistema Único de Saúde - SUS: Lei Orgânica da Saúde - LOS - Lei nº 8.080 de 1990 e Lei  nº 8.142 de 1990"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "Segundo a Lei Orgânica da Saúde, o conjunto de ações capaz \nde eliminar, diminuir ou prevenir riscos à saúde e de intervir \nnos problemas sanitários decorrentes do meio ambiente, da \nprodução e da circulação de bens e da prestação de serviços \nde interesse da saúde é denominado vigilância", "alt": {"A": "preventiva da saúde pública.", "B": "epidemiológica.", "C": "sanitária.", "D": "farmacoepidemiológica.", "E": "primária."}, "g": "C", "j": "Art. 6º §1º Lei 8.080/90: vigilância sanitária é o conjunto de ações capaz de eliminar/diminuir/prevenir riscos à saúde decorrentes do meio ambiente, produção, circulação de bens e prestação de serviços."}, {"id": "1104825", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "No título IV do Código de Ética, encontram‐se os dispositivos   que  tratam  “Da  Observância,  Penalidades,  Aplicação  e   Cumprimento deste Código”. Considerando essa informação,   assinale  a  alternativa  que  não  apresenta  uma  penalidade   aplicada  ao  assistente  social  que  descumpra  as  normativas   expressas  no  Código  de  Ética,  conforme  o  expresso  no    artigo 24.", "alt": {"A": "multa", "B": "advertência reservada", "C": "desagravo público", "D": "advertência pública", "E": "cassação do registro profissional"}, "g": "C", "j": "Art. 24 CE/1993 prevê: multa, advertência reservada, advertência pública, suspensão e cassação. Desagravo público NÃO é penalidade (é instrumento de defesa do profissional)."}, {"id": "1104822", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Princípios Fundamentais, Sigilo Profissional, Direitos, Deveres, Vedações e Responsabilidades Gerais do Assistente Social"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "Clarice  é  assistente  social e  moradora  da  cidade  de \nTupi.  No  mês  de  outubro,  devido  às  chuvas  intermitentes, \nocorreram  alagamentos  e  enchentes  na  região,  sendo \ndecretada  situação  de  calamidade  pública.  Os  assistentes \nsociais da cidade de Tupi foram convocados para trabalhar no \natendimento  à  população  desabrigada.  Clarice,  por  estar \ndesempregada  há  dois  meses,  decidiu  não  participar  das \nações emergenciais de atendimento à população.  \nCom base nessa situação hipotética e no Código de Ética do \nAssistente Social, assinale a alternativa correta.", "alt": {"A": "A  atitude  de  Clarice está  correta,  pois,  por  não estar   exercendo a atividade de assistente social pelo motivo   de  desemprego,  não  possui  o  dever  de  atender  a   convocação.", "B": "A atitude de Clarice está correta, uma vez que, segundo   o Código de Ética, participar de programas de socorro   à população é um direito do assistente social, e não um   dever profissional.", "C": "A atitude de Clarice está incorreta, pois é um dever do   assistente social participar de programas de socorro à   população em situação de calamidade pública.", "D": "A  atitude  de  Clarice  está  correta,  pois  é  vedado  ao   assistente social exercer a atividade profissional se não   estiver vinculado a uma instituição por meio de vínculo   formal de trabalho ou, de  forma voluntária, por meio   de emissão de termo institucional de voluntariado.", "E": "A atitude de Clarice está incorreta, pois é um direito do   assistente social participar de programas de socorro à   população em situação de calamidade pública."}, "g": "C", "j": "Art. 3º, alínea 'e' do CE: é DEVER do AS participar de programas de socorro à população em calamidade pública. A recusa de Clarice é incorreta."}, {"id": "1104811", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Trabalho e Serviço Social: perfil, demanda, prática e competências profissionais"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "As  relações  que  configuram  a  prática  profissional  \nsão  complexas.  Por  um  lado,  expressam  determinado  tipo  \nde  intervenção  no  âmbito  das  práticas  sociais;  por  outro, \nresultam  de  uma  especialização  do  trabalho  coletivo  no \ncontexto  da  sociedade,  determinada  pela  divisão \nsociotécnica do trabalho.      \n \nMyrian Veras Baptista. Prática social/prática profissional: a natureza \n \n \ncomplexa das relações profissionais cotidianas. In: Myrian Veras  \n \n \nBaptista e Odária Battini. A prática profissional do Assistente Social:  \n \n \nteoria, ação, construção do conhecimento. São Paulo: Veras, 2009. \n \n   \n O  texto  acima  aponta  a  complexidade  das  relações  que \nconfiguram  o  exercício  profissional  do  assistente  social. \nConsiderando  a  perspectiva  crítica,  assinale  a  alternativa \ncorreta acerca da prática profissional do assistente social.", "alt": {"A": "No  espaço  sócio‐ocupacional,  o  assistente  social   possui plena autonomia sobre as condições objetivas   e subjetivas do trabalho.", "B": "A prática profissional do assistente social situa‐se no   âmbito singular e particular das relações estabelecidas   pelos  sujeitos  sociais,  que  se  manifestam   concretamente em problemas pessoais.", "C": "As  ações  profissionais  do  assistente  social  possuem   uma  temporalidade  histórica,  pois  são  influenciadas   pela conjuntura social, econômica e política.", "D": "A prática profissional do assistente social visa a operar   mudanças  culturais,  ideológicas  e  comportamentais   na  vida  dos  sujeitos,  por  meio  do  diálogo  e  do   aconselhamento,  de  modo  que  eles  consigam,  pelo   seu esforço, superar a problemática vivenciada.", "E": "O  sentido e a  direcionalidade  da  prática  profissional   do  assistente  social  devem  estar  orientados  para   materializar o projeto ético‐político, que é um projeto   societário compactuado por todos os profissionais de   serviço social."}, "g": "C", "j": "As ações profissionais possuem temporalidade histórica e são influenciadas pela conjuntura. Outras alternativas têm imprecisões críticas (autonomia plena, individualismo, PEP compactuado por todos)."}, {"id": "2826214", "d": "servico_social", "a": ["Serviço Social na Empresa, Responsabilidade Social, Terceiro Setor, ONGs, Entidades Sociais, Recursos Humanos e Gestão de Pessoas"], "ano": "2018", "org": "SESC", "t": "", "e": "Quanto ao Serviço Social do Comércio (Sesc), assinale a alternativa correta.", "alt": {"A": "A ação do Sesc abrange o trabalhador no comércio e em atividades assemelhadas e seus dependentes e os diversos meios ambientes que condicionam a vida do trabalhador e de sua família.", "B": "O Sesc desempenhará suas atribuições de forma independente dos órgãos do Ministério do Trabalho e Previdência Social e de quaisquer outras entidades públicas ou privadas de serviço social.", "C": "Para a consecução de seus fins, incumbe ao Sesc, entre outros, servir‐se dos recursos audiovisuais e dos instrumentos de formação da opinião pública para interpretar e realizar a sua obra educativa e divulgar princípios, métodos e técnicas de serviço social, mas não promover, por processos racionais e práticos, a aproximação entre empregados e empregadores.", "D": "Um dos valores do Sesc é a atuação em rede, que visa a uniformizar o pensamento sistêmico e da unidade institucional, em detrimento da identidade regional.", "E": "A missão do Sesc consiste em promover ações educativas que contribuam para o bem‐estar e a qualidade de vida dos trabalhadores do comércio de bens, serviços e turismo, não abrangendo seus familiares e a comunidade."}, "g": "A", "j": "Dec.-Lei 9.853/1946 (Sesc): ação alcança trabalhador no comércio e dependentes e os diversos meios ambientes que condicionam sua vida e da família."}, {"id": "566878", "d": "servico_social", "a": ["Surgimento e Institucionalização do Serviço Social", "Fundamentos históricos e teórico-metodológicos do Serviço Social"], "ano": "2015", "org": "CRESS", "t": "", "e": "O Serviço Social surge como parte de um movimento social mais amplo, de bases confessionais, articulado à necessidade de formação doutrinária e social do laicato, para uma presença mais ativa da Igreja Católica no chamado mundo temporal, no:", "alt": {"A": "início da década de 1920.", "B": "final da década de 1920.", "C": "início da década de 1930.", "D": "final da década de 1930.", "E": "início da década de 1940."}, "g": "C", "j": "SS no Brasil surge no início dos anos 1930 (CEAS-SP, 1932) sob bases confessionais católicas."}, {"id": "566877", "d": "servico_social", "a": ["Políticas Sociais", "Noções Gerais de Políticas Sociais"], "ano": "2015", "org": "CRESS", "t": "Com base nas questões teóricas e históricas que perpassam a relação entre Estado e políticas sociais, leia atentamente as afirmativas a seguir.I. O Estado liberal predominante no século XIX e o Estado social capitalista do século XX têm em comum o fato de terem reconhecido direitos sem colocar em xeque os fundamentos do capitalismo.II. A generalização dos direitos políticos é resultado da luta da classe trabalhadora e contribuiu, de forma significativa, para ampliar os direitos sociais e para tencionar, questionar e mudar o papel do Estado no âmbito do capitalismo a partir do final do século XIX e início do século XX.III. O surgimento das políticas sociais foi gradual e diferenciado entre os países.IV. Os autores que discorrem acerca da origem das políticas sociais são unânimes em situar o início do século XX como o período em que o Estado capitalista passa a assumir e a realizar ações sociais de forma mais ampla, planejada, sistematizada e com caráter de obrigatoriedade.", "e": "É correto o que se afirma em:", "alt": {"A": "todas.", "B": "I, II e III, somente.", "C": "I, II e IV, somente.", "D": "III e IV, somente.", "E": "I e II, somente."}, "g": "B", "j": "I, II e III corretos. IV falso: autores NÃO são unânimes sobre o início no século XX (há controvérsia historiográfica)."}, {"id": "566876", "d": "servico_social", "a": ["Trabalho e Serviço Social", "Questão Social e Serviço Social"], "ano": "2015", "org": "CRESS", "t": "", "e": "Marilda Villela Iamamoto afirma que a matéria-prima do trabalho do assistente social encontra-se no âmbito da questão social em suas múltiplas manifestações, tal como vivenciadas pelos indivíduos sociais em suas relações sociais quotidianas, às quais respondem com ações, pensamentos e sentimentos (IAMAMOTO, 2003). Sobre o debate contemporâneo da profissão de assistente social e sua interface com a questão social, assinale a alternativa incorreta.", "alt": {"A": "Dar conta da questão social, hoje, é decifrar as desigualdades sociais – de classes – em seus recortes de gênero, raça, etnia, religião, nacionalidade, meio ambiente, entre outros. É também decifrar as formas de resistência e rebeldia com que são vivenciadas pelos sujeitos sociais.", "B": "Um dos aspectos centrais da questão social, hoje, é a ampliação do desemprego e da precarização das relações de trabalho.", "C": "A coexistência de temporalidades históricas desiguais faz com que a questão social apresente, hoje, tanto marcas do passado quanto do presente, radicalizando-as.", "D": "É necessário hoje repensar a questão social, não porque as bases de sua produção sofrem uma transformação, mas porque, na atualidade, suas expressões sofrem uma profunda transformação com as inflexões verificadas no padrão de acumulação. Suas bases permanecem imutáveis.", "E": "As alterações no padrão de acumulação capitalista, sob a hegemonia do capital financeiro, introduzem novas mediações históricas nas formas de enfrentamento da questão social, seja por parte da sociedade civil organizada ou do Estado."}, "g": "D", "j": "D contradiz Iamamoto ao afirmar que 'as bases permanecem imutáveis' — para a autora, as bases da questão social sofrem profunda transformação no novo padrão de acumulação."}, {"id": "566875", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Projeto Ético-Político do Serviço Social e Diretrizes Curriculares do Serviço Social"], "ano": "2015", "org": "CRESS", "t": "", "e": "Assinale a alternativa incorreta acerca do Projeto Ético-Político do Serviço Social.", "alt": {"A": "O Projeto Ético-Político do Serviço Social tem em seu núcleo o reconhecimento da liberdade como valor ético central.", "B": "O Projeto Ético-Político do Serviço Social está vinculado a um projeto de transformação da sociedade. Essa vinculação se dá pela própria exigência que a dimensão política da intervenção profissional impõe.", "C": "Os(as) assistentes sociais não podem, individualmente, operar o Projeto Ético-Político através de modalidades interventivas da profissão.", "D": "O Projeto Ético-Político do Serviço Social tem um compromisso com a autonomia, a emancipação e a plena expansão dos indivíduos sociais.", "E": "O Projeto Ético-Político do Serviço Social articula em si mesmo alguns elementos constitutivos, uma imagem ideal da profissão, os valores que a legitima, sua função social e seus objetivos, conhecimentos teóricos, saberes interventivos, normas, práticas, entre outros."}, "g": "C", "j": "O PEP pode e deve ser operado individualmente por cada AS via modalidades interventivas. C inverte essa premissa."}, {"id": "566874", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2015", "org": "CRESS", "t": "", "e": "O art. 22 do Código de Ética Profissional dos(as) Assistentes Sociais apresenta cinco infrações disciplinares. Dentre essas cinco infrações, o Código Processual Disciplinar afirma que somente quatro delas são passíveis de serem apuradas pelos procedimentos estabelecidos na Regulamentação que o institui. Assinale a alternativa que apresenta a única infração disciplinar do Código de Ética Profissional dos(as) Assistentes Sociais que não é passível de ser apurada pelo Código Processual Disciplinar.", "alt": {"A": "Exercer a Profissão quando impedido(a) de fazê-lo, ou facilitar, por qualquer meio, o seu exercício ao(às) não inscritos(as) ou impedidos(as).", "B": "Não cumprir, no prazo estabelecido, determinação emanada do órgão ou autoridade dos Conselhos, em matéria destes, depois de regularmente notificado(a).", "C": "Deixar de pagar, regularmente, as anuidades e contribuições devidas ao Conselho Regional de Serviço Social a que esteja obrigado(a).", "D": "Participar de instituição que, tendo por matéria o Serviço Social, não esteja inscrita no Conselho Regional de Serviço Social.", "E": "Fazer ou apresentar declaração, documento falso ou adulterado, perante o Conselho Regional ou Federal de Serviço Social."}, "g": "C", "j": "O Código Processual Disciplinar não apura inadimplência (anuidades) — esta é tratada por procedimento administrativo de cobrança, não por processo ético-disciplinar."}, {"id": "566871", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Competências e Atribuições Privativas do Assistente Social"], "ano": "2015", "org": "CRESS", "t": "", "e": "De acordo com a Lei nº 8.662/1993, que dispõe sobre a profissão de assistente social e dá outras providências, compete aos Conselhos Regionais de Serviço Social (CRESS), em suas respectivas áreas de jurisdição, o exercício de algumas atribuições. São algumas dessas atribuições, exceto:", "alt": {"A": "organizar e manter o registro profissional dos(as) assistentes sociais e o cadastro das instituições e obras sociais públicas e privadas, ou de fins filantrópicos.", "B": "expedir carteiras profissionais de assistentes sociais.", "C": "fixar, em assembleia da categoria, as anuidades que devem ser pagas pelos(as) assistentes sociais.", "D": "prestar assessoria técnico-consultiva aos organismos públicos ou privados, em matéria de serviço social.", "E": "elaborar o respectivo Regimento Interno e submetê-lo a exame para a aprovação do fórum máximo de deliberação do conjunto CFESS/CRESS."}, "g": "D", "j": "Art. 10 Lei 8.662/93 não inclui 'prestar assessoria técnico-consultiva' entre as atribuições dos CRESS. Esta é competência do CFESS (art. 8º)."}, {"id": "566869", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS", "Infrações Disciplinares e Penalidades no Serviço Social"], "ano": "2015", "org": "CRESS", "t": "", "e": "De acordo com o Código de Ética Profissional dos(as) Assistentes Sociais, as infrações ao Código acarretarão penalidades, na forma dos dispositivos legais ou regimentais. Sobre as penalidades previstas no Código de Ética Profissional dos(as) Assistentes Sociais, não é correto afirmar que:", "alt": {"A": "a pena de suspensão acarreta ao(à) assistente social a interdição do exercício profissional em todo território nacional pelo prazo de 30 (trinta) dias a 2 (dois) anos.", "B": "a suspensão por falta de pagamento de anuidades e taxas só cessará com satisfação do débito, podendo ser cassada a inscrição profissional após decorridos 3 (três) anos da suspensão.", "C": "a pena de multa variará entre o mínimo correspondente ao valor de uma anuidade e o máximo de seu décuplo.", "D": "da imposição de qualquer penalidade, caberá recurso com efeito suspensivo ao CRESS.", "E": "na execução da advertência reservada, não sendo encontrado o(a) penalizado(a) ou se este(a), após duas convocações, não comparecer no prazo fixado para receber a penalidade, será ela tornada pública."}, "g": "D", "j": "Da imposição de penalidades cabe recurso ao CFESS (Tribunal Superior de Ética) — não ao CRESS. Erro em D."}, {"id": "566865", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Código de Ética de 1993 - Lei de Regulamentação da Profissão – Lei nº 8.662 de 1993", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "", "e": "A Resolução nº 588/2010 do Conselho Federal de Serviço Social resolve que a inscrição no CRESS deverá ser solicitada através de requerimento instruído e apresenta a documentação necessária para essa solicitação. Sobre essa resolução, indique a alternativa incorreta.", "alt": {"A": "Na solicitação de inscrição no CRESS, será admitida Certidão de Colação de Grau em substituição ao diploma, a qual deverá ser substituída pelo diploma no prazo de 1 (um) ano, prorrogável por mais 1 (um) ano.", "B": "O comprovante de pagamento das taxas devidas e o do pagamento da anuidade (integral ou proporcional) ou da primeira parcela são documentos necessários para solicitar inscrição no CRESS.", "C": "A declaração de que não há inscrição principal em outro CRESS é um dos documentos necessários para a solicitação de inscrição no CRESS.", "D": "No caso de assistente social diplomado em país estrangeiro, o diploma deverá estar devidamente revalidado e registrado em órgão competente no Brasil.", "E": "A inscrição no CRESS poderá ser requerida por instrumento público e o procurador constituído terá poderes para o recebimento da Carteira e/ou da Cédula de Identidade Profissional."}, "g": "E", "j": "Res. 588/2010: a Carteira/Cédula só pode ser recebida pelo próprio profissional, ainda que a inscrição tenha sido requerida por procurador. Erro em E."}, {"id": "566860", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "Com base na Resolução nº 493/2006 do Conselho Federal de Serviço Social (CFESS), que dispõe sobre as condições éticas e técnicas do exercício profissional do(a) assistente social, leia atentamente as afirmativas a seguir.I. O local de atendimento destinado ao assistente social deve ser dotado de espaço suficiente, para abordagens individuais ou coletivas, conforme as características dos serviços prestados, e deve possuir e garantir algumas características físicas, como ventilação adequada a atendimentos breves ou demorados e com portas fechadas.II. Na constatação de inadequações quanto às condições éticas, físicas e técnicas do exercício profissional, o assistente social deve informar por escrito a entidade, instituição ou órgão que trabalha ou presta serviços, sugerindo alternativas para a melhoria dos serviços prestados.III. É atribuição dos Conselhos Regionais de Serviço Social orientar e fiscalizar as condições éticas e técnicas estabelecidas na Resolução, bem como em outros instrumentos normativos expedidos pelo CFESS, em relação aos assistentes sociais e pessoas jurídicas que prestam serviços sociais. Essa atribuição se realiza através exclusivamente dos agentes fiscais dos Conselhos Regionais de Serviço Social.IV. Os casos omissos e aqueles concernentes à interpretação abstrata geral da norma serão resolvidos e dirimidos pelo Conselho Pleno do CFESS.", "e": "É correto o que se afirma em:", "alt": {"A": "todas.", "B": "I, II e III, somente.", "C": "I, II e IV, somente.", "D": "III e IV, somente.", "E": "I e II, somente."}, "g": "C", "j": "Res. 493/2006: I, II e IV corretos. III falso: a fiscalização não é exclusivamente realizada por agentes fiscais (conselheiros também atuam como fiscais natos)."}, {"id": "566859", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "A Resolução nº 533/2008 do Conselho Federal de Serviço Social afirma que a supervisão direta de estágio em Serviço Social é atividade privativa do assistente social, em pleno gozo dos seus direitos profissionais, devidamente inscrito no CRESS de sua área de ação, sendo denominado supervisor de campo o assistente social da instituição campo de estágio e supervisor acadêmico o assistente social professor da instituição de ensino.", "e": "Essa mesma Resolução afirma que a definição do número de estagiários a serem supervisionados deve levar em conta a carga horária do supervisor de campo, as peculiaridades do campo de estágio e a complexidade das atividades profissionais, sendo que o limite máximo não deverá exceder:", "alt": {"A": "1 (um) estagiário para cada 6 (seis) horas semanais de trabalho.", "B": "1 (um) estagiário para cada 10 (dez) horas semanais de trabalho.", "C": "1 (um) estagiário para cada 15 (quinze) horas semanais de trabalho.", "D": "2 (dois) estagiários para cada 15 (quinze) horas semanais de trabalho.", "E": "2 (dois) estagiários para cada 10 (dez) horas semanais de trabalho."}, "g": "B", "j": "Res. 533/2008: limite máximo de 1 estagiário para cada 10 horas semanais de trabalho do supervisor de campo."}, {"id": "566858", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "Sobre os processos administrativos e os recursos estabelecidos no Estatuto do Conjunto CFESS/CRESS, analise as seguintes afirmativas.I. Os processos que tramitam perante os Conselhos Regionais de Serviço Social são processos administrativos, devendo sempre ser garantido o amplo e irrestrito direito de defesa aos envolvidos, independentemente, de sua natureza e espécie.II. Os processos disciplinares éticos são regulados pelo Código Processual de Ética, instituído através de Resolução do CFESS, devendo os procedimentos ali prescritos ser rigorosamente cumpridos pelos CFESS, pelo CRESS e pela Comissão Permanente de Ética e de Instrução.III. Das decisões do Conselho Pleno do Conselho Regional de Serviço Social caberá recurso ao Conselho Federal apenas no caso de ocorrência de cerceamento de defesa.IV. Os recursos terão efeito devolutivo apenas.", "e": "Está correto o que se afirma em:", "alt": {"A": "todas.", "B": "II e III, somente.", "C": "I e IV, somente.", "D": "IV, somente.", "E": "I e II, somente."}, "g": "E", "j": "I e II corretos. III falso (recurso ao CFESS não se limita a cerceamento). IV falso (recursos podem ter efeito suspensivo)."}, {"id": "566857", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "", "e": "Conforme o estabelecido pelo Estatuto do Conjunto CFESS/CRESS, não cabe a perda de mandato de Conselheiro Federal ou Regional de Serviço Social, ou membros das Seccionais, no caso de:", "alt": {"A": "renúncia.", "B": "superveniência de causa de que resulte a inabilitação para o exercício da profissão.", "C": "ausência a 2 (duas) reuniões consecutivas ou 3 (três) alternadas no período de 1 (um) ano, sem motivo justificado.", "D": "ausência a mais de 3 (três) reuniões consecutivas ou 5 (cinco) alternadas no período de 1 (um) ano, sem motivo justificado.", "E": "penalização em processo disciplinar e/ou ético, após decisão transitada em julgado."}, "g": "C", "j": "O Estatuto CFESS/CRESS prevê perda de mandato por 3 ausências consecutivas ou 5 alternadas em 1 ano (alternativa D) — os números de C (2/3) não correspondem ao Estatuto, tornando essa hipótese inválida."}, {"id": "566853", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "", "e": "Assinale a alternativa incorreta, conforme o disposto no Estatuto do Conjunto CFESS/CRESS.", "alt": {"A": "A competência dos Conselheiros Federais e Regionais de Serviço Social, efetivos e suplentes, é cumprir rigorosamente e fazer cumprir o previsto em Leis, Estatuto, Regimentos Internos, Resoluções e demais instrumentos legais, atinentes ao órgão.", "B": "No exercício de seu mandato, o conselheiro tem direitos e obrigações e se sujeita a sanções e penalidades, em conformidade com as disposições contidas no Estatuto.", "C": "Os membros do Conselho Federal de Serviço Social (CFESS) e dos Conselhos Regionais (CRESS) exercerão seus mandatos pessoalmente, não sendo permitida a representação por procuração, seja a que título for.", "D": "Os conselheiros farão jus apenas às despesas de transporte, diárias ou ajudas de custo, na forma regulamentar estabelecida pelo Conselho Pleno, para participação em reuniões, atividades administrativas e de representação do Conselho.", "E": "Os membros do Conselho Federal de Serviço Social (CFESS) e dos Conselhos Regionais (CRESS) poderão receber remuneração pelo exercício de seus mandatos, sendo facultada a relação de emprego com o CFESS ou CRESS."}, "g": "E", "j": "O mandato de conselheiro do CFESS/CRESS é GRATUITO. Conselheiros não podem ser remunerados nem manter relação de emprego com o Conselho. Erro em E."}, {"id": "566848", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "", "e": "Assinale a alternativa correta, conforme o Estatuto do Conjunto CFESS/CRESS.", "alt": {"A": "O Fórum máximo de deliberação da profissão de Assistente Social é o Encontro Nacional CFESS/CRESS, que será convocado a cada biênio, na forma estabelecida pelo presente Estatuto.", "B": "O Conselho Federal de Serviço Social poderá homologar a criação, extinção ou determinar a alteração da jurisdição de qualquer Conselho Regional existente, independentemente de aprovação do Encontro Nacional CFESS/CRESS, atendendo-se, contudo, aos critérios estabelecidos pela Consolidação das Resoluções do CFESS.", "C": "O Conselho Federal de Serviço Social é o órgão normativo de grau superior e central do Conjunto CFESS/CRESS, tendo como competência, na forma da Lei de Regulamentação da Profissão – Lei nº 8.662/93 – e do interesse público, fiscalizar, orientar, supervisionar, defender, normatizar e disciplinar o exercício e as atividades da profissão do assistente social, em todo o território nacional.", "D": "O Conselho Federal e os Conselhos Regionais de Serviço Social mantêm com os órgãos de administração pública vínculo hierárquico.", "E": "O Encontro Nacional CFESS/CRESS é a instância máxima de deliberação deste Conjunto, composto de delegados do CFESS e dos CRESS, com direito a voz e voto, assim como por observadores e convidados com direito a voz e voto."}, "g": "C", "j": "C descreve corretamente o CFESS como órgão normativo central. A falso (Encontro é anual, não bienal); B falso (depende de aprovação); D falso (não há vínculo hierárquico); E falso (observadores e convidados têm apenas voz)."}, {"id": "566846", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "Constituem receitas do CRESS da 11ª Região:I. anuidades de pessoas físicas e jurídicas, taxas e emolumentos arrecadados pelo CRESS, a serem fixados na assembleia geral da categoria, respeitados os limites estabelecidos pelo Encontro Nacional CFESS/CRESS.II. receitas oriundas de mutações patrimoniais e locações de bens de qualquer natureza.III. doações e legados.IV. outras receitas.", "e": "Está correto o que se afirma em:", "alt": {"A": "todas.", "B": "III e IV, somente.", "C": "I e III, somente.", "D": "I, somente.", "E": "I e II, somente."}, "g": "A", "j": "Todas as receitas listadas (I-IV) constam do Regimento Interno do CRESS: anuidades/taxas, mutações patrimoniais/locações, doações/legados e outras receitas."}, {"id": "566845", "d": "servico_social", "a": ["Profissão do Assistente Social e o Código de Ética do Serviço Social", "Órgãos de Fiscalização da Profissão - CFESS/CRESS - e Resoluções do CFESS"], "ano": "2015", "org": "CRESS", "t": "", "e": "Segundo o Regimento Interno do CRESS, da 11ª Região, os Conselhos Regionais de Serviço Social são competentes para as seguintes atividades, exceto:", "alt": {"A": "manifestar-se ética, política e tecnicamente perante os organismos públicos e privados em matéria de Serviço Social.", "B": "representar a profissão de Assistente Social, perante os órgãos da administração pública e privada, podendo delegar tal encargo aos membros da Seccional de sua jurisdição.", "C": "disciplinar, fiscalizar e normatizar as atividades de pessoas jurídicas que tenham como objetivo prestar serviços em assessoria, consultoria, planejamento e capacitação em Serviço Social.", "D": "zelar pelo livre-exercício, pela dignidade e pela autonomia da profissão.", "E": "aplicar as sanções previstas no Código de Ética profissional, independentemente da instauração de processo administrativo-disciplinar e direito de defesa."}, "g": "E", "j": "Aplicação de sanções exige instauração de processo administrativo-disciplinar com amplo direito de defesa (garantia constitucional do contraditório). Erro em E."}, {"id": "3785382", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2025", "org": "CRA", "t": "", "e": "O art. 37 da Constituição Federal de 1988 estabelece os\nprincípios que orientam a Administração Pública, buscando\ngarantir que os agentes públicos ajam de forma ética,\neficiente e voltada ao interesse coletivo. Considerando\nessa informação, assinale a opção que apresenta um dos\nprincípios constitucionais da Administração Pública.", "alt": {"A": "Eficiência: o serviço público deve buscar melhores\nresultados com o uso racional dos recursos disponíveis.", "B": "Eficácia: refere‑se apenas ao alcance de metas,\nsem considerar a economicidade e a qualidade na\nexecução.", "C": "Pessoalidade: o servidor público deve agir conforme\nseus interesses pessoais e particulares.", "D": "Proteção da informação: as informações públicas\nnão devem ser divulgadas para preservar o sigilo\nadministrativo.", "E": "Legalismo: o servidor público pode agir conforme\nsua própria interpretação da lei, sem necessidade de\nobservá‑la integralmente."}, "g": "A", "j": "Art. 37 CF/88 inclui eficiência como princípio expresso da Administração Pública (LIMPE). Pessoalidade não é princípio (o é IMpessoalidade); 'legalismo' e 'proteção da informação' são distorções dos princípios reais."}, {"id": "3748949", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2025", "org": "CORE", "t": "", "e": "A Constituição Federal de 1988, em seu art. 22, estabelece\nque compete privativamente à União legislar a respeito de\ndeterminadas matérias, relacionadas à estrutura jurídica,\npolítica e econômica do Estado brasileiro.\n      Assinale a opção que apresenta apenas matérias de\ncompetência legislativa privativas da União.", "alt": {"A": "direito civil, comercial e penal", "B": "direito ambiental, tributário e urbanístico", "C": "direito agrário, financeiro e de consumo", "D": "direito eleitoral, previdenciário e trabalhista", "E": "direito administrativo, econômico e do consumidor"}, "g": "A", "j": "Art. 22, I CF/88: compete privativamente à União legislar sobre direito civil, comercial, penal, processual, eleitoral, agrário, marítimo, aeronáutico, espacial e do trabalho. As demais alternativas misturam competências concorrentes (art. 24) e privativas."}, {"id": "3748932", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira"], "ano": "2025", "org": "CORE", "t": "", "e": "A ordem econômica, fundada na valorização do trabalho\nhumano e na livre iniciativa, tem por fim assegurar a todos\nexistência digna, conforme os ditames da justiça social.\nConsiderando essa informação e as regras constitucionais\npara atuação do Estado na economia, inclusive para fins de\nproteção ambiental, assinale a opção correta.", "alt": {"A": "É constitucional lei municipal que obriga à substituição\nde sacos e sacolas plásticos por sacos e sacolas\nbiodegradáveis.", "B": "A Constituição Federal de 1988 proíbe o uso de\ntributos como instrumento de proteção ambiental.", "C": "A exploração mineral em terras indígenas independe\nde autorização legislativa.", "D": "A exploração direta de atividade econômica pelo\nEstado só será permitida quando necessária à defesa\nnacional.", "E": "Dependerá de autorização legislativa ou de concessão\npara se realizar o aproveitamento do potencial de\nenergia renovável de capacidade reduzida."}, "g": "A", "j": "STF (RE 732.686, RG Tema 970): é constitucional lei municipal obrigando substituição de sacolas plásticas por biodegradáveis (competência local em meio ambiente urbano)."}, {"id": "3748931", "d": "direito_constitucional", "a": ["Poder Legislativo"], "ano": "2025", "org": "CORE", "t": "", "e": "O Poder Legislativo é exercido pelo Congresso Nacional,\ncomposto da Câmara dos Deputados e do Senado Federal.\nA partir dessa informação e acerca das imunidades\nparlamentares e das competências do Poder Legislativo,\nassinale a opção correta, à luz do texto da Constituição\nFederal de 1988.", "alt": {"A": "A Câmara dos Deputados julga o Presidente da\nRepública nos crimes de responsabilidade.", "B": "As comissões permanentes do Congresso Nacional\nnão possuem competência deliberativa, apenas\nconsultiva.", "C": "A imunidade parlamentar impede que deputados e\nsenadores sejam investigados por fatos ocorridos fora\ndo exercício do mandato.", "D": "O Congresso Nacional pode sustar atos normativos do\nExecutivo que exorbitem do poder regulamentar", "E": "O Congresso Nacional pode revogar decisões\ndo TCU que envolvam julgamento de contas de\nadministradores públicos."}, "g": "D", "j": "Art. 49, V CF/88: compete ao Congresso Nacional sustar atos normativos do Executivo que exorbitem do poder regulamentar."}, {"id": "3748930", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2025", "org": "CORE", "t": "", "e": "A Constituição Federal de 1988 dedica dispositivos\nespecíficos ao Distrito Federal, reconhecendo sua\nnatureza jurídica singular. Com base nessa informação e\nconsiderando a Constituição Federal de 1988, assinale a\nopção correta, acerca do Distrito Federal.", "alt": {"A": "O Distrito Federal possui autonomia limitada, estando\nsubordinado diretamente ao governo federal em\ntodas as matérias administrativas.", "B": "O Distrito Federal pode ser dividido em municípios,\ndesde que haja autorização por lei complementar\nfederal.", "C": "O Distrito Federal rege‑se por lei orgânica, aprovada\npela Câmara Legislativa por dois terços e em dois\nturnos, e não por Constituição própria.", "D": "O Distrito Federal não possui Tribunal de Contas\npróprio, sendo fiscalizado exclusivamente pelo\nTribunal de Contas da União.", "E": "O Distrito Federal está impedido de instituir taxas,\npois não possui competência municipal."}, "g": "C", "j": "Art. 32 CF/88: DF rege-se por lei orgânica, aprovada pela Câmara Legislativa em dois turnos, com interstício mínimo de 10 dias e por 2/3 dos votos."}, {"id": "3748928", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República"], "ano": "2025", "org": "CORE", "t": "", "e": "“Ainda que nos documentos internacionais assumam\na forma das primeiras declarações, nos ordenamentos\nnacionais integram as constituições, adquirindo o caráter\nconcreto de normas jurídicas positivas constitucionais, por\nisso, subjetivando‑se em direito particular de cada povo.”\nCom base na doutrina e na Constituição Federal de 1988,\nassinale a opção correta, a respeito dos princípios que\nregem as relações internacionais do Estado brasileiro.", "alt": {"A": "A supremacia do interesse nacional sobre os direitos\nhumanos é um princípio constitucional das relações\ninternacionais do Brasil.", "B": "A concessão de asilo político é vedada pela\nConstituição Federal de 1988, por representar\ningerência em assuntos internos de outros Estados.", "C": "A Constituição Federal de 1988 determina que o\nBrasil deve manter neutralidade absoluta em conflitos\ninternacionais, independentemente de sua natureza.", "D": "A Constituição Federal de 1988 prevê que o Brasil\ndeve buscar a integração econômica, política, social e\ncultural dos povos de todo o continente americano.", "E": "A cooperação entre os povos para o progresso\nda humanidade, prevista na Constituição Federal\nde 1988, impõe ao Brasil o dever de atuar em\nfóruns internacionais com vistas à promoção do\ndesenvolvimento sustentável e à redução das\ndesigualdades globais."}, "g": "E", "j": "Art. 4º, IX CF/88: cooperação entre os povos para o progresso da humanidade — princípio das relações internacionais. D é falso pois a CF fala em integração da América Latina, não 'todo continente americano'."}, {"id": "3748440", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Assinale a opção que apresenta corretamente os direitos\nsociais previstos na Constituição Federal de 1988.", "alt": {"A": "o transporte, o lazer e o direito ao voto", "B": "a nacionalidade, a segurança e a educação", "C": "a liberdade, a alimentação e a moradia", "D": "a saúde, o trabalho e a previdência social", "E": "a proteção social, a defesa da vida e a filiação\npartidária"}, "g": "D", "j": "Art. 6º CF/88: saúde, trabalho e previdência social são direitos sociais. Voto, nacionalidade, liberdade e filiação partidária pertencem a outras categorias (políticos/individuais)."}, {"id": "3621694", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2025", "org": "CRM", "t": "", "e": "Em relação aos direitos e às garantias fundamentais,\nassinale a opção correta.", "alt": {"A": "Todos são iguais perante a lei, sem distinção de\nqualquer natureza, garantindo‑se apenas aos\nbrasileiros a inviolabilidade do direito à vida, à\nliberdade, à igualdade, à segurança e à propriedade.", "B": "É livre a manifestação do pensamento, sendo\npermitido o anonimato.", "C": "É assegurado o direito de resposta, proporcional\nao agravo, sendo vedada a indenização por dano\nmaterial, moral ou à imagem.", "D": "É inviolável o sigilo da correspondência e das\ncomunicações telegráficas, de dados e das\ncomunicações telefônicas, salvo, no último caso, por\nordem do Ministério Público, nas hipóteses e na forma\nque a lei estabelecer para fins de investigação criminal\nou instrução processual penal.", "E": "É livre a locomoção no território nacional em tempo\nde paz, podendo qualquer pessoa, nos termos da lei,\nnele entrar, permanecer ou dele sair com seus bens."}, "g": "E", "j": "Art. 5º, XV CF/88: livre locomoção no território nacional em tempo de paz. Demais alternativas distorcem dispositivos (anonimato é vedado; sigilo telefônico só por ordem JUDICIAL; brasileiros E estrangeiros residentes)."}, {"id": "3536614", "d": "direito_constitucional", "a": ["Direitos Sociais", "Ordem Social"], "ano": "2025", "org": "CREMAM", "t": "", "e": "A saúde, como direito, é um dos pilares do SUS e está\ngarantida na Constituição Federal de 1988. Considerando\nessa informação, é correto afirmar que", "alt": {"A": "apenas contribuintes do INSS têm acesso à saúde.", "B": "a saúde é responsabilidade exclusiva do médico\nassistente.", "C": "o Estado deve promover políticas públicas que\ngarantam acesso universal.", "D": "é um privilégio de funcionários públicos em atividade.", "E": "somente os serviços de emergência são garantidos\npelo Estado."}, "g": "C", "j": "Art. 196 CF/88: saúde é direito de todos e dever do Estado, garantida mediante políticas que visem acesso universal e igualitário."}, {"id": "3536492", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais"], "ano": "2025", "org": "CREMAM", "t": "", "e": "Das decisões em mandado de segurança proferidas em\núnica instância pelos tribunais cabe", "alt": {"A": "recurso especial, apenas.", "B": "recurso extraordinário, apenas.", "C": "recurso especial ou extraordinário, apenas.", "D": "recurso especial e extraordinário, nos casos\nlegalmente previstos, e recurso ordinário, quando a\nordem for denegada.", "E": "recurso especial e extraordinário, nos casos\nlegalmente previstos, e recurso ordinário, quando a\nordem for concedida."}, "g": "D", "j": "Lei 12.016/2009 + arts. 102, II, 'a' e 105, II, 'b' CF/88: cabe recurso ordinário quando a ordem for denegada, REsp e RE nos casos legalmente previstos."}, {"id": "3536491", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais"], "ano": "2025", "org": "CREMAM", "t": "", "e": "O direito de requerer mandado de segurança extinguir‑se‑á,\ncontados da ciência, pelo interessado, do ato impugnado,\nno prazo de", "alt": {"A": "30 dias.", "B": "60 dias.", "C": "90 dias.", "D": "120 dias.", "E": "150 dias."}, "g": "D", "j": "Art. 23 Lei 12.016/2009: direito de requerer MS extingue-se em 120 dias da ciência do ato impugnado."}, {"id": "3438441", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira"], "ano": "2025", "org": "CRO", "t": "", "e": "Com base na Constituição Federal de 1988, assinale a opção\ncorreta, em relação à receita pública.", "alt": {"A": "É vedada a vinculação de receita de impostos a órgão,\nfundo ou despesa, salvo nos casos expressamente\nautorizados pela Constituição Federal de 1988.", "B": "As receitas derivadas da exploração de atividades\neconômicas pelo Estado não se submetem às regras\nda Constituição Federal de 1988 sobre vinculação de\nreceita.", "C": "A criação ou a majoração de tributos pode ocorrer\npor meio de decreto do Poder Executivo, desde\nque haja previsão orçamentária na lei de diretrizes\norçamentárias (LDO).", "D": "A repartição das receitas tributárias entre os entes\nfederativos é facultativa, podendo ser estabelecida\npor lei ordinária de iniciativa do Senado Federal.", "E": "As contribuições de melhoria não integram a receita\npública por possuírem natureza indenizatória, e não\ntributária."}, "g": "A", "j": "Art. 167, IV CF/88: vedada a vinculação de receita de impostos a órgão, fundo ou despesa, salvo nos casos expressamente previstos na Constituição."}, {"id": "3438436", "d": "direito_constitucional", "a": ["Poder Legislativo"], "ano": "2025", "org": "CRO", "t": "", "e": "Com base na Constituição Federal de 1988, assinale a\nopção correta, acerca da fiscalização contábil, financeira e\norçamentária.", "alt": {"A": "A fiscalização contábil e financeira da Administração\nPública é exercida exclusivamente pelo Congresso\nNacional, sem participação de outros órgãos.", "B": "Os tribunais de contas possuem competência apenas\npara julgar as contas do presidente da República.", "C": "O controle externo é exercido pelo Poder Judiciário,\ncom o auxílio do Ministério Público e da Receita\nFederal.", "D": "Compete ao tribunal de contas emitir parecer prévio\nsobre as contas prestadas anualmente pelo chefe do\nPoder Executivo.", "E": "A fiscalização orçamentária limita‑se ao exame da\nlegalidade formal da despesa pública, sem considerar\naspectos de economicidade ou legitimidade."}, "g": "D", "j": "Art. 71, I CF/88: compete ao TCU emitir parecer prévio sobre as contas prestadas anualmente pelo Presidente da República (e analogamente nos demais entes)."}, {"id": "3437615", "d": "direito_constitucional", "a": ["Poder Legislativo"], "ano": "2025", "org": "CRO", "t": "", "e": "Considerando a Constituição Federal de 1988, a respeito do\nPoder Legislativo, cada legislatura terá a duração de", "alt": {"A": "1 ano.", "B": "2 anos.", "C": "4 anos.", "D": "8 anos.", "E": "10 anos."}, "g": "C", "j": "Art. 44, parágrafo único CF/88: cada legislatura terá a duração de quatro anos."}, {"id": "3437614", "d": "direito_constitucional", "a": ["Processo Legislativo", "Organização Político-Administrativa do Estado"], "ano": "2025", "org": "CRO", "t": "", "e": "À luz da Constituição Federal de 1988, os territórios federais\ndevem ser criados ou transformados em estados por meio\nde", "alt": {"A": "lei complementar.", "B": "lei ordinária.", "C": "medida provisória.", "D": "decreto‑lei.", "E": "emenda constitucional."}, "g": "A", "j": "Art. 18, §3º CF/88: territórios federais podem ser criados, transformados em Estados ou reintegrados ao Estado de origem mediante lei complementar."}, {"id": "3437613", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2025", "org": "CRO", "t": "", "e": "A respeito da soberania popular, a Constituição Federal de\n1988 estabelece que ela será exercida pelo sufrágio", "alt": {"A": "universal e pelo voto direto e público, com valor igual\npara todos.", "B": "universal e pelo voto direto e secreto, com valor igual\npara todos.", "C": "universal e pelo voto indireto e secreto, com valor\nigual para todos.", "D": "universal e pelo voto direto e secreto, com valor\ndobrado para os portadores de diploma de nível\nsuperior.", "E": "censitário e pelo voto direto e secreto, com valor igual\npara todos."}, "g": "B", "j": "Art. 14 caput CF/88: soberania popular exercida pelo sufrágio universal e voto direto e secreto, com valor igual para todos."}, {"id": "3437612", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2025", "org": "CRO", "t": "", "e": "À luz da Constituição Federal de 1988, assinale a opção que\napresenta um cargo que pode ser ocupado por brasileiro\nnaturalizado.", "alt": {"A": "vice‑presidente da República", "B": "presidente da Câmara dos Deputados", "C": "presidente do Senado Federal", "D": "ministro do Superior Tribunal de Justiça", "E": "ministro do Supremo Tribunal Federal"}, "g": "D", "j": "Art. 12, §3º CF/88: cargos privativos de brasileiro nato são Presidente/VP, Pres. Câmara, Pres. Senado, Min. STF, carreira diplomática, oficial das FA, Min. Defesa. STJ admite naturalizado."}, {"id": "3437611", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2025", "org": "CRO", "t": "", "e": "Considerando a Constituição Federal de 1988, assinale a\nopção que apresenta um dos direitos dos trabalhadores\nurbanos e rurais.", "alt": {"A": "seguro‑desemprego, em caso de desemprego\nvoluntário", "B": "irredutibilidade do salário, salvo o disposto em lei ou\nmedida provisória", "C": "décimo terceiro e décimo quartos salários, com base\nna remuneração integral ou no valor da aposentadoria", "D": "remuneração do trabalho noturno igual à do diurno", "E": "repouso semanal remunerado, preferencialmente aos\ndomingos"}, "g": "E", "j": "Art. 7º, XV CF/88: repouso semanal remunerado, preferencialmente aos domingos. As demais alteram dispositivos (seguro só em desemprego involuntário; convenção/acordo coletivo; só 13º; noturno superior ao diurno)."}, {"id": "3364080", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira"], "ano": "2025", "org": "CORE", "t": "", "e": "Em relação à ordem econômica e financeira, ressalvados\nos casos previstos na Constituição Federal de 1988, a\nexploração direta de atividade econômica pelo Estado só\nserá permitida quando for", "alt": {"A": "necessária aos imperativos da economia nacional ou\na relevante interesse estatal, conforme definidos em\nmedida provisória.", "B": "autorizada pelo Ministério da Fazenda e pelo\nMinistério da Economia, por meio de portaria\nconjunta.", "C": "necessária à defesa da segurança e da soberania\nnacional, conforme definidos em Lei.", "D": "autorizada pelo presidente da República, conforme\ndecreto específico.", "E": "necessária aos imperativos da segurança nacional ou\na relevante interesse coletivo, conforme definidos\nem Lei."}, "g": "E", "j": "Art. 173 CF/88: exploração direta de atividade econômica pelo Estado só permitida quando necessária aos imperativos da segurança nacional ou a relevante interesse coletivo, conforme definidos em lei."}, {"id": "3364079", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Organização Político-Administrativa do Estado"], "ano": "2025", "org": "CORE", "t": "", "e": "De acordo com a Constituição Federal de 1988, assinale\na opção que apresenta apenas impostos de competência\nda União.", "alt": {"A": "sobre a importação de produtos estrangeiros, sobre as\ngrandes fortunas, sobre a transmissão causa mortis, e\nsobre a doação de quaisquer bens ou direitos", "B": "sobre a propriedade de veículos automotores, sobre\nos produtos industrializados e sobre a propriedade\nterritorial rural", "C": "sobre a propriedade predial e territorial urbana,\nsobre os serviços de qualquer natureza e sobre a\npropriedade territorial rural", "D": "sobre a importação de produtos estrangeiros, sobre a\nrenda e os proventos de qualquer natureza e sobre a\npropriedade territorial rural", "E": "sobre a transmissão inter vivos de bens imóveis, sobre\nas operações relativas à circulação de mercadorias e\nsobre a propriedade de veículos automotores"}, "g": "D", "j": "Art. 153 CF/88: II (importação), III (renda), VI (ITR) são impostos da União. ITCMD e IPVA são estaduais; ITBI e ISS são municipais."}, {"id": "3364078", "d": "direito_constitucional", "a": ["Poder Executivo", "Defesa do Estado e das Instituições Democráticas"], "ano": "2025", "org": "CORE", "t": "", "e": "Com base na Constituição Federal de 1988, o estado de\ndefesa pode ser decretado pelo", "alt": {"A": "Senado Federal, ouvidos o presidente da República e o\nConselho de Defesa Nacional.", "B": "ministro da Defesa, ouvidos o chefe das Forças\nArmadas e o Congresso Nacional.", "C": "presidente da República, ouvidos o Conselho da\nRepública e o Conselho de Defesa Nacional.", "D": "Supremo Tribunal Federal, ouvidos o ministro da\nDefesa e o procurador‑geral da República.", "E": "Conselho de Defesa Nacional, ouvidos o Senado\nFederal e a Câmara dos Deputados."}, "g": "C", "j": "Art. 136 CF/88: o estado de defesa é decretado pelo Presidente da República, ouvidos o Conselho da República e o Conselho de Defesa Nacional."}, {"id": "3364077", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça"], "ano": "2025", "org": "CORE", "t": "", "e": "Considerando a Constituição Federal de 1988, assinale a\nopção correta, a respeito do Ministério Público.", "alt": {"A": "São princípios institucionais do Ministério Público\na unidade, a indivisibilidade e a independência\nfuncional.", "B": "O Ministério Público é uma instituição permanente,\nessencial à função jurisdicional do Estado,\nincumbindo‑lhe a defesa da ordem jurídica, do\nregime democrático e dos interesses sociais e\nindividuais disponíveis.", "C": "O Ministério Público elaborará sua proposta\norçamentária independentemente dos limites\nestabelecidos na lei de diretrizes orçamentárias.", "D": "A destituição do procurador‑geral da República,\npor iniciativa do presidente da República, deverá\nser precedida de autorização do Supremo\nTribunal Federal.", "E": "Os Ministérios Públicos dos estados e o do Distrito\nFederal e Territórios formarão lista tríplice entre\nintegrantes da carreira, na forma da lei respectiva, para\nescolha de seu procurador‑geral, que será nomeado\npelo chefe do Poder Executivo, para mandato de cinco\nanos, permitidas duas reconduções."}, "g": "A", "j": "Art. 127, §1º CF/88: princípios institucionais do MP são unidade, indivisibilidade e independência funcional."}, {"id": "3364058", "d": "direito_constitucional", "a": ["Poder Legislativo"], "ano": "2025", "org": "CORE", "t": "", "e": "O município de Feira de Santana aprovou um\norçamento anual com previsão de investimentos em\ninfraestrutura e educação. No entanto, denúncias sobre\nirregularidades nos gastos levaram a câmara municipal a\niniciar uma investigação sobre a execução orçamentária do\nPoder Executivo local. Diante desse cenário, os vereadores\nquestionaram quais órgãos são responsáveis pela\nfiscalização contábil, financeira e orçamentária, conforme\nprevisto na Constituição Federal de 1988.\n    Com base nessa situação hipotética, assinale a opção\ncorreta, no que se refere à Seção IX do Capítulo I do Título\nIV da Constituição Federal de 1988.", "alt": {"A": "A fiscalização contábil, financeira e orçamentária é\ncompetência exclusiva dos tribunais de contas, que\ntêm autonomia para aplicar sanções diretamente aos\ngestores públicos.", "B": "A fiscalização contábil, financeira e orçamentária é\nexercida pelo Poder Judiciário, que tem a prerrogativa\nde anular atos administrativos que desrespeitem a\nlegalidade orçamentária.", "C": "O Tribunal de Contas da União e os tribunais de\ncontas estaduais são os únicos órgãos que exercem a\nfiscalização orçamentária, sem qualquer envolvimento\ndo Poder Legislativo.", "D": "O Ministério Público é o órgão responsável pela\nfiscalização contábil e orçamentária, podendo\ninterferir diretamente na execução do orçamento\npúblico.", "E": "A fiscalização contábil, financeira e orçamentária dos\nentes públicos é realizada pelo Poder Legislativo, com\no auxílio dos tribunais de contas."}, "g": "E", "j": "Art. 70 CF/88: fiscalização contábil, financeira e orçamentária é exercida pelo Poder Legislativo, com o auxílio dos Tribunais de Contas."}, {"id": "3324757", "d": "direito_constitucional", "a": ["Direitos Individuais", "Teoria dos Direitos Fundamentais"], "ano": "2025", "org": "CRF", "t": "", "e": "No que concerne à Constituição Federal de 1988, assinale a\nopção correta.", "alt": {"A": "É livre a expressão da atividade intelectual, artística,\ncientífica e de comunicação, mediante autorização\nestatal.", "B": "Ninguém será privado de direitos por motivo de\ncrença religiosa ou de convicção filosófica ou política,\nsalvo se as invocar para eximir‑se de obrigação legal\na todos imposta e recusar‑se a cumprir prestação\nalternativa, fixada em Lei.", "C": "O exercício de qualquer trabalho, ofício ou\nprofissão depende de autorização prévia estatal,\nindependentemente das qualificações exigidas por\nLei.", "D": "O direito de utilização, publicação ou reprodução\ndas obras não pode ser transmitido aos herdeiros,\nextinguindo‑se com a morte do autor.", "E": "A Lei punirá qualquer discriminação atentatória dos\ndireitos e das liberdades fundamentais, mas apenas\nquando cometida contra brasileiro nato."}, "g": "B", "j": "Art. 5º, VIII CF/88: ninguém será privado de direitos por crença religiosa/convicção filosófica/política, salvo se as invocar para eximir-se de obrigação legal e recusar prestação alternativa."}, {"id": "3324752", "d": "direito_constitucional", "a": ["Direitos Individuais", "Teoria dos Direitos Fundamentais"], "ano": "2025", "org": "CRF", "t": "", "e": "De acordo com a Constituição Federal de 1988, assinale a\nopção correta.", "alt": {"A": "A manifestação do pensamento é livre, sendo\npermitido o anonimato para garantir a liberdade de\nexpressão.", "B": "Ninguém será privado de seus bens sem o devido\nprocesso legal, exceto em casos de interesse público,\nindependentemente de indenização.", "C": "A prática do racismo constitui crime inafiançável e\nimprescritível, sujeito à pena de reclusão, nos termos\nda Lei.", "D": "É assegurado a todos, mediante o pagamento de taxa,\na obtenção de certidões em repartições públicas,\npara a defesa de direitos e para o esclarecimento de\nsituações de interesse pessoal.", "E": "As entidades associativas têm legitimidade para\nrepresentar seus filiados judicial ou extrajudicialmente,\nindependentemente de autorização expressa."}, "g": "C", "j": "Art. 5º, XLII CF/88: a prática do racismo constitui crime inafiançável e imprescritível, sujeito à pena de reclusão."}, {"id": "3324751", "d": "direito_constitucional", "a": ["Direitos Individuais"], "ano": "2025", "org": "CRF", "t": "", "e": "Conforme a Constituição Federal de 1988, assinale a opção\ncorreta.", "alt": {"A": "É plena a liberdade de associação para fins lícitos,\ninclusive a de caráter paramilitar.", "B": "No caso de iminente perigo público, a autoridade\ncompetente não poderá usar de propriedade\nparticular, tendo em vista a inviolabilidade do direito\nà propriedade.", "C": "A Lei estabelecerá o procedimento para\ndesapropriação por necessidade ou utilidade pública,\nou por interesse social, sem necessidade de justa e\nprévia indenização em dinheiro.", "D": "É assegurado a todos o acesso à informação e é\nresguardado o sigilo da fonte, quando for necessário\nao exercício profissional.", "E": "Todos têm direito a receber dos órgãos públicos\ninformações de seu interesse particular, ou de\ninteresse coletivo ou geral, que serão prestadas no\nprazo de 15 dias, sob pena de responsabilidade,\nressalvadas aquelas cujo sigilo seja imprescindível à\nsegurança da sociedade e do Estado."}, "g": "D", "j": "Art. 5º, XIV CF/88: é assegurado a todos o acesso à informação e resguardado o sigilo da fonte, quando necessário ao exercício profissional."}, {"id": "3324682", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos"], "ano": "2025", "org": "CRF", "t": "", "e": "Em relação à Administração Pública em geral, nos termos\nconstitucionais, é correto afirmar que", "alt": {"A": "as nomeações para cargo em comissão declarado em\nlei de livre nomeação e exoneração independem de\naprovação prévia em concurso público.", "B": "o prazo de validade do concurso público será\nprorrogado por até dois anos ou até a realização do\nconcurso subsequente.", "C": "a contratação por tempo indeterminado se destina a\natender a necessidade permanente, quando houver\nconveniência, a critério da Administração, de pessoal\ncom excepcional qualificação.", "D": "os vencimentos dos cargos do Poder Executivo\npoderão ser inferiores aos pagos pelos demais Poderes\ne pelo Ministério Público.", "E": "os acréscimos pecuniários percebidos por servidor\npúblico serão computados ou acumulados para fins de\nconcessão de acréscimos ulteriores."}, "g": "A", "j": "Art. 37, II CF/88: nomeações para cargos em comissão declarados em lei de livre nomeação e exoneração não exigem concurso público."}, {"id": "3324681", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2025", "org": "CRF", "t": "", "e": "Entre os direitos assegurados pela Constituição Federal de\n1988, inclui‑se o(a)", "alt": {"A": "livre expressão da atividade de comunicação,\ncondicionada a licença.", "B": "livre o exercício de qualquer trabalho, ofício ou\nprofissão, atendidas as qualificações profissionais que\na lei estabelecer.", "C": "acesso de todos à informação, independentemente\ndo sigilo da fonte, quando necessário ao exercício\nprofissional.", "D": "plena a liberdade de associação para quaisquer fins.", "E": "criação de associações, o que depende de autorização,\nadmitida a interferência estatal nos termos da lei."}, "g": "B", "j": "Art. 5º, XIII CF/88: é livre o exercício de qualquer trabalho, ofício ou profissão, atendidas as qualificações profissionais que a lei estabelecer."}, {"id": "3324375", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade"], "ano": "2025", "org": "CRF", "t": "", "e": "Acerca da reclamação constitucional, assinale a opção\ncorreta.", "alt": {"A": "A reclamação poderá ser ajuizada exclusivamente pelo\nMinistério Público para preservar a competência do\ntribunal.", "B": "A reclamação somente pode ser proposta perante os\nTribunais Superiores.", "C": "É inadmissível a reclamação proposta após o trânsito\nem julgado da decisão reclamada.", "D": "Compete ao Supremo Tribunal Federal processar e\njulgar a reclamação destinada a garantir a autoridade\ndas decisões do Tribunal Superior do Trabalho.", "E": "É inadmissível a reclamação proposta para garantir\na observância de acórdão de recurso extraordinário\ncom repercussão geral reconhecida quando estiverem\nesgotadas as instâncias ordinárias."}, "g": "C", "j": "Súmula 734 STF: 'não cabe reclamação quando já houver transitado em julgado o ato judicial que se alega tenha desrespeitado decisão do STF'."}, {"id": "3324373", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2025", "org": "CRF", "t": "", "e": "De acordo com a Constituição Federal de 1988, assinale a\nopção que apresenta uma competência comum da União,\ndos estados, do Distrito Federal e dos municípios.", "alt": {"A": "preservar as florestas, a fauna e a flora", "B": "legislar sobre direito civil, comercial, penal, processual,\neleitoral, agrário, marítimo, aeronáutico, espacial e do\ntrabalho", "C": "planejar e promover a defesa permanente contra as\ncalamidades públicas, especialmente as secas e as\ninundações", "D": "organizar, manter e executar a inspeção do trabalho", "E": "explorar, diretamente ou mediante autorização,\nconcessão ou permissão, os serviços de radiodifusão\nsonora e de sons e imagens"}, "g": "A", "j": "Art. 23, VII CF/88: é competência COMUM preservar as florestas, a fauna e a flora. As demais são competências exclusivas/privativas da União (arts. 21 e 22)."}, {"id": "3324372", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais"], "ano": "2025", "org": "CRF", "t": "", "e": "Em relação ao mandado de segurança, assinale a opção\ncorreta.", "alt": {"A": "O mandado de segurança coletivo pode ser impetrado\npor partido político sem representação no Congresso\nNacional.", "B": "O mandado de segurança será concedido para\nimpugnar decisão judicial da qual caiba recurso com\nefeito suspensivo.", "C": "O mandado de segurança será concedido para a\nretificação de dados, salvo quando for possível\nrealizá‑la por meio de processo sigiloso, judicial ou\nadministrativo.", "D": "O mandado de segurança será concedido sempre que\na falta de norma regulamentadora torne inviável o\nexercício dos direitos e das liberdades constitucionais\ne das prerrogativas inerentes à nacionalidade, à\nsoberania e à cidadania.", "E": "O mandado de segurança não será concedido quando\nhouver ato passível de recurso administrativo com\nefeito suspensivo, mesmo que não haja exigência de\ncaução."}, "g": "E", "j": "Lei 12.016/2009 art. 5º, I: não cabe MS quando se tratar de ato do qual caiba recurso administrativo com efeito suspensivo, independentemente de caução."}, {"id": "3324371", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2025", "org": "CRF", "t": "", "e": "Acerca dos direitos políticos, assinale a opção correta.", "alt": {"A": "Conforme a Constituição Federal de 1988, apenas os\nanalfabetos são inelegíveis.", "B": "O pleno exercício dos direitos políticos é a única\ncondição de elegibilidade.", "C": "Para concorrer a outros cargos, o governador de\nestado deverá renunciar ao respectivo mandato até\n90 dias antes do pleito.", "D": "Com base na Constituição Federal de 1988, é vedada a\nsuspensão dos direitos políticos.", "E": "O alistamento eleitoral e o voto são facultativos para\nos analfabetos, para os maiores de 70 anos de idade e\npara os maiores de 16 e menores de 18 anos de idade."}, "g": "E", "j": "Art. 14, §1º, II CF/88: alistamento e voto são facultativos para analfabetos, maiores de 70 anos, e maiores de 16 e menores de 18 anos."}, {"id": "3177283", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2025", "org": "CORE", "t": "", "e": "No que concerne ao Sistema Tributário Nacional, compete\nà União instituir impostos sobre", "alt": {"A": "transmissão causa mortis e doação, de quaisquer bens\nou direitos.", "B": "propriedade de veículos automotores.", "C": "propriedade predial e territorial urbana.", "D": "erviços de qualquer natureza.", "E": "produtos industrializados."}, "g": "E", "j": "Art. 153, IV CF/88: compete à União instituir imposto sobre produtos industrializados (IPI). As demais são estaduais (ITCMD, IPVA) ou municipais (IPTU, ISS)."}, {"id": "3177282", "d": "direito_constitucional", "a": ["Poder Legislativo", "Congresso Nacional"], "ano": "2025", "org": "CORE", "t": "", "e": "Em relação ao Poder Legislativo, cada legislatura terá\nduração de", "alt": {"A": "1 ano.", "B": "2 anos.", "C": "3 anos.", "D": "4 anos.", "E": "5 anos."}, "g": "D", "j": "Art. 44, parágrafo único CF/88: cada legislatura tem duração de quatro anos."}, {"id": "3177281", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2025", "org": "CORE", "t": "", "e": "Assinale a opção que corresponde a um cargo privativo de\nbrasileiros natos.", "alt": {"A": "ministro do Tribunal de Contas da União", "B": "deputado federal", "C": "presidente do Senado Federal", "D": "ministro do Superior Tribunal de Justiça", "E": "governador de estado"}, "g": "C", "j": "Art. 12, §3º CF/88: o cargo de Presidente do Senado Federal é privativo de brasileiro nato."}, {"id": "3177280", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Injunção"], "ano": "2025", "org": "CORE", "t": "", "e": "O remédio jurídico para os casos em que a falta de norma\nregulamentadora torna inviável o exercício dos direitos e\nliberdades constitucionais e das prerrogativas inerentes à\nnacionalidade, à soberania e à cidadania é o(a)", "alt": {"A": "mandado de segurança.", "B": "mandado de injunção.", "C": "habeas corpus.", "D": "recurso extraordinário.", "E": "ação direta de inconstitucionalidade."}, "g": "B", "j": "Art. 5º, LXXI CF/88: mandado de injunção é o remédio para falta de norma regulamentadora que torne inviável o exercício de direitos e liberdades constitucionais."}, {"id": "3177279", "d": "direito_constitucional", "a": ["Supremo Tribunal Federal", "Organização do Poder Judiciário"], "ano": "2025", "org": "CORE", "t": "", "e": "O habeas data impetrado contra ato do presidente daRepública será julgado, originariamente, pelo(a)", "alt": {"A": "Supremo Tribunal Federal.", "B": "Superior Tribunal de Justiça.", "C": "Senado Federal.", "D": "Câmara dos Deputados.", "E": "Tribunal de Contas da União."}, "g": "A", "j": "Art. 102, I, 'd' CF/88: compete ao STF processar e julgar originariamente o habeas data contra atos do Presidente da República."}, {"id": "3174872", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2025", "org": "CORE", "t": "", "e": "As eleições municipais de 2024 expressam, mais uma\nvez, a normalidade institucional vivida pelo Brasil desde a\nredemocratização (1985) e consagrada pela Constituição\nFederal de 1988. A respeito do atual sistema eleitoral\nbrasileiro, assinale a opção correta.", "alt": {"A": "O voto é obrigatório para o brasileiro de qualquer\nidade.", "B": "A eleição é indireta, ou seja, realizada por meio de um\ncolégio eleitoral.", "C": "Os municípios elegem prefeitos, vice‑prefeitos e\nvereadores.", "D": "O mandato de deputado federal e de senador é de\noito anos.", "E": "Os estados elegem governadores, mas não deputados\nestaduais."}, "g": "C", "j": "Art. 29, I CF/88: nos municípios elegem-se prefeito, vice-prefeito e vereadores."}, {"id": "3159639", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade"], "ano": "2025", "org": "CORE", "t": "", "e": "Em relação aos direitos e deveres individuais e coletivos, a\nConstituição Brasileira de 1988 estabelece que", "alt": {"A": "é livre a manifestação do pensamento, preservado o\nanonimato.", "B": "é inviolável o sigilo da correspondência e das\ncomunicações telegráficas, salvo por ordem judicial.", "C": "é livre o exercício de qualquer trabalho, ofício ou\nprofissão, atendidas as qualificações profissionais que\na lei estabelecer.", "D": "a criação de associações depende de autorização,\nsendo vedada a interferência estatal em seu\nfuncionamento.", "E": "ninguém poderá ser compelido a associar‑se, a não\nser no interesse da coletividade."}, "g": "C", "j": "Art. 5º, XIII CF/88: livre o exercício de qualquer trabalho, ofício ou profissão, atendidas as qualificações profissionais que a lei estabelecer."}, {"id": "3159621", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Injunção"], "ano": "2025", "org": "CORE", "t": "", "e": "A respeito dos remédios constitucionais, assinale a opção\ncorreta.", "alt": {"A": "O habeas corpus será concedido para assegurar o\nconhecimento de informações relativas à pessoa do\nimpetrante, constantes de registros ou de bancos de\ndados de entidades governamentais ou de caráter\npúblico.", "B": "O mandado de segurança será concedido contra\ndecisão judicial da qual caiba recurso com efeito\nsuspensivo.", "C": "O habeas data será concedido sempre que a falta de\nnorma regulamentadora torne inviável o exercício\ndos direitos e das liberdades constitucionais e das\nprerrogativas inerentes à nacionalidade, à soberania e\nà cidadania.", "D": "O mandado de injunção coletivo pode ser promovido\npela defensoria pública quando a tutela requerida for\nespecialmente relevante para a promoção dos direitos\nhumanos e a defesa dos direitos individuais e coletivos\ndos necessitados, na forma da Constituição Federal de\n1988.", "E": "O mandado de segurança coletivo pode ser impetrado\npor todos os partidos políticos, mesmo sem\nrepresentação no Congresso Nacional."}, "g": "D", "j": "Lei 13.300/2016 art. 12, IV: a Defensoria Pública pode promover mandado de injunção coletivo quando a tutela for relevante para a promoção dos direitos humanos e defesa dos direitos individuais e coletivos dos necessitados."}, {"id": "3159620", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado", "O Federalismo Brasileiro"], "ano": "2025", "org": "CORE", "t": "", "e": "Acerca das características essenciais do Estado Federal,\nassinale a opção correta.", "alt": {"A": "Os estados federados têm o direito de secessão, sendo\neste um atributo inerente à sua autonomia política.", "B": "No Estado Federal, não há previsão de intervenção\nfederal, pois a unidade física e jurídica é assegurada\nexclusivamente pela soberania dos estados federados.", "C": "O Estado Federal é uma forma de Estado caracterizada\npela descentralização política e administrativa, com\nrepartição de competências entre União e entes\nfederados, consagrada na Constituição Federal 1988.", "D": "A Suprema Corte, em um Estado Federal, possui\njurisdição limitada aos conflitos entre os entes\nfederados, sem jurisdição nacional.", "E": "A organização do Estado Federal dispensa a\nparticipação dos estados federados nas deliberações\nda União, sendo estas atribuídas exclusivamente ao\ngoverno central."}, "g": "C", "j": "Estado Federal caracteriza-se pela descentralização política e administrativa com repartição constitucional de competências entre União e entes federados."}, {"id": "3159619", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado", "O Federalismo Brasileiro"], "ano": "2025", "org": "CORE", "t": "", "e": "Com base no conceito de soberania e autonomia no\nfederalismo, assinale a opção que apresenta a relação entre\no Estado Federal e os estados‑membros no Brasil.", "alt": {"A": "A autonomia dos estados‑membros no Brasil\nrestringe‑se à execução de leis, não abrangendo a\nelaboração de suas constituições estaduais próprias.", "B": "A descentralização administrativa no federalismo\nbrasileiro confere soberania aos estados‑membros no\nâmbito de sua competência territorial.", "C": "A União pode restringir, a seu critério, a autonomia\ndos estados‑membros em matéria legislativa.", "D": "A autonomia dos estados‑membros permite‑lhes\nexercer a soberania em seus territórios, desde que em\nharmonia com a União.", "E": "A soberania é atributo exclusivo do Estado Federal,\nenquanto os estados‑membros possuem autonomia\npara legislar e se autoconstituir, observando os limites\nimpostos pela Constituição Federal de 1988."}, "g": "E", "j": "A soberania é atributo exclusivo do Estado Federal (União); os Estados-membros possuem autonomia (auto-organização, autogoverno, autolegislação e autoadministração) nos limites da CF/88."}, {"id": "3268727", "d": "direito_constitucional", "a": ["Disposições Gerais no Poder Judiciário", "Conselho Nacional de Justiça", "Supremo Tribunal Federal", "Poder Judiciário", "Organização do Poder Judiciário"], "ano": "2024", "org": "CREF", "t": "", "e": "Com base nas normas constitucionais, que tratam sobre o\nPoder Judiciário, assinale a alternativa correta.", "alt": {"A": "O Conselho Nacional de Justiça tem sede no estado de\nSão Paulo.", "B": "O Conselho Nacional de Justiça julgará,\noriginariamente, os recursos interpostos contra\ndecisão de ministro do Supremo Tribunal Federal.", "C": "O Ministério Público é uma instituição permanente\nsubordinada ao presidente da República.", "D": "O Supremo Tribunal Federal tem jurisdição em todo o\nterritório nacional.", "E": "O Conselho Nacional de Justiça é composto de 15\nmembros com mandato de 2 anos, todos indicados\npelo presidente da República."}, "g": "D", "j": "Art. 92, §2º CF/88: o Supremo Tribunal Federal e os Tribunais Superiores têm sede na Capital Federal e jurisdição em todo o território nacional."}, {"id": "3268726", "d": "direito_constitucional", "a": ["Poder Legislativo", "Câmara dos Deputados"], "ano": "2024", "org": "CREF", "t": "", "e": "Considerando a CF/1988, assinale a alternativa que\napresenta uma competência privativa à Câmara\ndos Deputados.", "alt": {"A": "Os deputados deverão aprovar previamente, por\nvoto secreto, a escolha de ministro do Supremo\nTribunal Federal.", "B": "Compete à Câmara dos Deputados autorizar, por dois\nterços de seus membros, a instauração de processo\ncontra o presidente e o vice‑presidente da República e\nos ministros de Estado.", "C": "A autorização das operações externas de natureza\nfinanceira, de interesse da União, dos estados, do\nDistrito Federal, dos territórios e dos municípios\ncompete à Câmara dos Deputados.", "D": "A aprovação do procurador‑geral da República deverá\nser submetida previamente à Câmara dos Deputados.", "E": "Os deputados deverão fixar, por proposta do\npresidente da República, limites globais para o\nmontante da dívida consolidada da União, dos\nestados, do Distrito Federal e dos municípios."}, "g": "B", "j": "Art. 51, I CF/88: compete privativamente à Câmara dos Deputados autorizar, por 2/3 de seus membros, a instauração de processo contra o Presidente, VP e Ministros de Estado."}, {"id": "3268725", "d": "direito_constitucional", "a": ["Organização do Estado - União", "Organização Político-Administrativa do Estado", "Repartição de Competências Constitucionais"], "ano": "2024", "org": "CREF", "t": "", "e": "Conforme a CF/1988, assinale a alternativa que apresenta\numa competência privativa da União.", "alt": {"A": "Compete à União legislar, privativamente, sobre\nsistemas de consórcios e sorteios.", "B": "É de competência privativa da União a regulamentação\ndos serviços de transporte municipal.", "C": "É de competência privativa da União legislar sobre a\ncriação e a organização dos municípios.", "D": "Compete privativamente à União legislar sobre o\ndireito à saúde e à educação básica.", "E": "A União poderá, mediante lei ordinária federal, criar e\nextinguir cargos públicos estaduais e municipais."}, "g": "A", "j": "Art. 22, XX CF/88: compete privativamente à União legislar sobre sistemas de consórcios e sorteios."}, {"id": "3268724", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2024", "org": "CREF", "t": "", "e": "Considerando as questões relativas à nacionalidade na\nCF/1988, assinale a alternativa correta.", "alt": {"A": "A pessoa nascida em território brasileiro não\npode ser considerada brasileira nata se seus pais\nforem estrangeiros.", "B": "Os portugueses com residência temporária no Brasil\nterão os direitos inerentes ao brasileiro naturalizado.", "C": "A lei não poderá estabelecer distinção entre brasileiros\nnatos e naturalizados, salvo nos casos previstos\nna CF/1988.", "D": "A CF/1988 permite que qualquer estrangeiro solicite\na nacionalidade brasileira imediatamente após o\ncasamento com um cidadão brasileiro.", "E": "Os filhos de pais brasileiros nascidos no exterior\nprecisam, necessariamente, retornar ao Brasil\nantes dos 18 anos de idade para manter sua\nnacionalidade brasileira."}, "g": "C", "j": "Art. 12, §2º CF/88: a lei não poderá estabelecer distinção entre brasileiros natos e naturalizados, salvo nos casos previstos na própria Constituição."}, {"id": "3268723", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Segurança", "Habeas Corpus"], "ano": "2024", "org": "CREF", "t": "", "e": "A respeito dos remédios constitucionais previstos no bojo\nda CF/1988, assinale a alternativa correta.", "alt": {"A": "O mandado de segurança só pode ser utilizado para\nproteger os direitos que já estão amparados pelo\nhabeas corpus ou habeas data e não pode ser aplicado\npara garantir outros direitos líquidos e certos.", "B": "A legitimidade para impetrar o mandado de segurança\ncoletivo é exclusiva dos partidos políticos com\nrepresentação no Congresso Nacional.", "C": "O habeas data poderá ser utilizado em substituição ao\nmandado de segurança.", "D": "O mandado de segurança é um recurso que poderá\nser interposto contra a decisão das entidades privadas\nque contrariem os direitos do cidadão.", "E": "O habeas corpus será concedido sempre que alguém\nsofrer ou se achar ameaçado de sofrer violência\nou coação em sua liberdade de locomoção, por\nilegalidade ou abuso de poder."}, "g": "E", "j": "Art. 5º, LXVIII CF/88: concede-se HC sempre que alguém sofrer ou se achar ameaçado de sofrer violência ou coação em sua liberdade de locomoção, por ilegalidade ou abuso de poder."}, {"id": "3268722", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Igualdade"], "ano": "2024", "org": "CREF", "t": "", "e": "A CF/1988 estabelece os crimes imprescritíveis,\ninafiançáveis, insuscetíveis de graça ou anistia. Com base\nnessa informação, assinale a alternativa que apresenta um\ncrime imprescritível.", "alt": {"A": "tráfico ilícito de entorpecentes e drogas afins", "B": "prática do racismo", "C": "crimes hediondos e assemelhados", "D": "prática do homicídio qualificado", "E": "terrorismo e os definidos em lei como crimes\nhediondos"}, "g": "B", "j": "Art. 5º, XLII CF/88: a prática do racismo é o único crime imprescritível dentre os listados. Os demais (XLIII e XLIV) são inafiançáveis mas prescritíveis, exceto ação de grupos armados (não listada)."}, {"id": "3268721", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito de Propriedade e Função Social da Propriedade"], "ano": "2024", "org": "CREF", "t": "", "e": "À luz da CF/1988, é garantido ao cidadão o direito à\npropriedade. Com base nessa informação, assinale a\nalternativa correta.", "alt": {"A": "O direito à propriedade não é absoluto, razão pela\nqual as propriedades rurais podem ser expropriadas\nsem compensação se o proprietário não estiver\ncultivando plantações comerciais.", "B": "A garantia do direito de propriedade é relativa,\npodendo o Poder Público adotar medidas contra o\nproprietário para assegurar que o imóvel atenda à sua\nfunção social.", "C": "No caso de iminente perigo público, a autoridade\ncompetente poderá utilizar de propriedade particular,\nsendo assegurado ao proprietário o depósito\nantecipado da quantia relativa a 5% do valor do imóvel\npara cobrir eventuais danos que, eventualmente,\nocorram no imóvel.", "D": "A pequena propriedade rural, assim definida em lei,\ndesde que trabalhada pela família, somente poderá\nser penhora para pagamento de débitos decorrentes\nde sua atividade produtiva.", "E": "A expropriação de um imóvel, por qualquer que seja\no motivo, somente poderá ocorrer mediante justa e\nprévia indenização em dinheiro."}, "g": "B", "j": "Art. 5º, XXIII CF/88: a propriedade atenderá a sua função social — o Poder Público pode adotar medidas para garantir essa função (desapropriação por descumprimento, etc.)."}, {"id": "3268720", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Privacidade"], "ano": "2024", "org": "CREF", "t": "", "e": "De acordo com a CF/1988, a casa é asilo inviolável\ndo indivíduo, ninguém nela podendo adentrar sem\nconsentimento do morador. Contudo, o próprio texto\nconstitucional prevê algumas exceções a essa regra.\nCom base nessas informações, assinale a alternativa que\napresenta a possibilidade de ingresso no domicílio de uma\npessoa sem seu consentimento.", "alt": {"A": "Havendo determinação judicial, um oficial de justiça\npoderá, durante a noite, ingressar na casa de um\nindivíduo sem o consentimento.", "B": "A polícia pode ingressar em qualquer residência,\nindependentemente do horário, sem a necessidade\nde autorização do morador, se houver suspeita de\natividades ilícitas.", "C": "A inviolabilidade de domicílio poderá ser relativizada\nna hipótese em que houver autorização de um vizinho,\ncaso ele resida no mesmo condomínio.", "D": "A inviolabilidade de domicílio poderá ser mitigada em\ncaso de flagrante delito.", "E": "O ingresso em uma casa abandonada dependerá de\nautorização de quem esteja lá, mesmo que a pessoa\nnão seja o legítimo proprietário ou possuidor, bem\ncomo daquele que esteja se escondendo no local."}, "g": "D", "j": "Art. 5º, XI CF/88: a casa é asilo inviolável, ninguém nela podendo penetrar sem consentimento do morador, salvo em caso de flagrante delito ou desastre, ou para prestar socorro, ou, durante o dia, por determinação judicial."}, {"id": "3268719", "d": "direito_constitucional", "a": ["Poder Legislativo", "Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo", "Funções Típicas e Atípicas"], "ano": "2024", "org": "CREF", "t": "", "e": "Os Poderes Legislativo, Executivo e Judiciário exercem tanto\nfunções típicas quanto atípicas. Com base nesse contexto,\nassinale a alternativa correta.", "alt": {"A": "A elaboração dos regimentos internos pelos tribunais\nde justiça é uma função típica do Poder Judiciário, pois\né indispensável ao seu funcionamento.", "B": "As funções atípicas dos Poderes da União somente\npoderão ser desempenhadas mediante delegação do\nrespectivo poder.", "C": "A edição de medidas provisórias pelo presidente da\nRepública é uma forma de exercício da função típica\ndo Poder Executivo.", "D": "As funções atípicas dos Poderes da União não\npossuem previsão legal. Assim, os Poderes Legislativo,\nExecutivo e Judiciário terão a faculdade de exercê‑las,\nconforme sua conveniência e oportunidade.", "E": "O julgamento de autoridades em processos de\nimpeachment constitui uma função atípica do\nPoder Legislativo."}, "g": "E", "j": "O julgamento de autoridades em processo de impeachment (art. 52, I e II CF/88) é função atípica do Poder Legislativo (jurisdicional)."}, {"id": "3268718", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Princípios de Direito Constitucional Internacional"], "ano": "2024", "org": "CREF", "t": "", "e": "Em relação aos princípios que regem a República Federativa\ndo Brasil em relações internacionais, assinale a alternativa\nque apresenta um desses princípios.", "alt": {"A": "concessão de asilo político", "B": "soberania e a dignidade da pessoa humana", "C": "cidadania e construção de uma sociedade livre, justa\ne solidária", "D": "repúdio ao terrorismo e à soberania", "E": "erradicação da pobreza e da marginalização e a\nredução das desigualdades sociais e regionais"}, "g": "A", "j": "Art. 4º, X CF/88: concessão de asilo político é princípio das relações internacionais. Os demais são fundamentos (art. 1º) ou objetivos (art. 3º)."}, {"id": "3268717", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Fundamentos da República"], "ano": "2024", "org": "CREF", "t": "", "e": "À luz da Constituição Federal de 1988 (CF/1988), assinale\na alternativa que apresenta um fundamento da República\nFederativa do Brasil.", "alt": {"A": "prevalência dos direitos humanos", "B": "pluralismo político", "C": "concessão de asilo político", "D": "igualdade entre os estados", "E": "construção de uma sociedade livre, justa e solidária"}, "g": "B", "j": "Art. 1º, V CF/88: pluralismo político é um dos fundamentos da República Federativa do Brasil."}, {"id": "3268676", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade", "Direito à Igualdade", "Teoria dos Direitos Fundamentais"], "ano": "2024", "org": "CREF", "t": "", "e": "À luz da Constituição Federal de 1988 (CF/1988), assinale\na alternativa correta, acerca dos direitos e das garantias\nfundamentais (Título II, Capítulo I).", "alt": {"A": "Ninguém será obrigado a fazer ou deixar de fazer\nalguma coisa senão em virtude de ordem judicial.", "B": "Em hipótese alguma o cidadão poderá ser privado de\ndireitos por motivo de crença religiosa ou de convicção\nfilosófica ou política.", "C": "É livre a manifestação do pensamento e de expressão,\nsendo garantido o anonimato.", "D": "É livre a locomoção no território nacional em tempo\nde paz, podendo qualquer pessoa, nos termos da lei,\nnele entrar, permanecer ou dele sair com seus bens.", "E": "É garantida a obtenção de certidões em repartições\npúblicas, para defesa de direitos e esclarecimento\nde situações de interesse pessoal, desde que haja o\nprévio pagamento da taxa devida em favor do ente\nda Federação."}, "g": "D", "j": "Art. 5º, XV CF/88: é livre a locomoção no território nacional em tempo de paz, podendo qualquer pessoa, nos termos da lei, nele entrar, permanecer ou dele sair com seus bens."}, {"id": "3268601", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Supremo Tribunal Federal", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Poder Judiciário", "Organização do Poder Judiciário", "Garantias do Poder Judiciário e de seus Membros"], "ano": "2024", "org": "CREF", "t": "", "e": "Acerca da reclamação constitucional, assinale a alternativa\ncorreta.", "alt": {"A": "A reclamação pode ser proposta, apenas, perante os\ntribunais superiores.", "B": "Caberá reclamação da parte interessada ou do\nMinistério Público para garantir a observância de\nacórdão de recurso extraordinário com repercussão\ngeral reconhecida ou de acórdão proferido\nem julgamento de recursos extraordinário ou\nespecial repetitivos, quando não esgotadas as\ninstâncias ordinárias.", "C": "É inadmissível a reclamação proposta após o trânsito\nem julgado da decisão reclamada.", "D": "Caberá reclamação da parte interessada ou do\nMinistério Público para garantir a autoridade dos\ndespachos do tribunal.", "E": "É inadmissível a reclamação proposta para preservar a\ncompetência do tribunal."}, "g": "C", "j": "Súmula 734 STF: é inadmissível reclamação após o trânsito em julgado da decisão reclamada."}, {"id": "3268588", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2024", "org": "CREF", "t": "", "e": "Conforme a Constituição Federal de 1988, assinale a\nalterativa que apresenta uma condição de elegibilidade.", "alt": {"A": "idade mínima de 30 anos para presidente e\nvice‑presidente da República e senador", "B": "formação em curso superior", "C": "alistamento eleitoral", "D": "idoneidade moral e reputação ilibada", "E": "notórios conhecimentos jurídicos, contábeis,\neconômicos e financeiros ou de Administração Pública"}, "g": "C", "j": "Art. 14, §3º, III CF/88: o alistamento eleitoral é condição de elegibilidade. As demais são incompatíveis com o texto constitucional ou são requisitos para outros cargos."}, {"id": "3268587", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Habeas Data"], "ano": "2024", "org": "CREF", "t": "", "e": "Assinale a alternativa que apresenta o remédio\nconstitucional que visa assegurar o conhecimento de\ninformações relativas à pessoa do impetrante, constantes\nde registros ou de bancos de dados de entidades\ngovernamentais ou de caráter público.", "alt": {"A": "mandado de injunção", "B": "ação popular", "C": "mandado de segurança", "D": "habeas data", "E": "habeas corpus"}, "g": "D", "j": "Art. 5º, LXXII CF/88: habeas data garante o conhecimento de informações relativas ao impetrante, constantes de registros ou bancos de dados de entidades governamentais ou de caráter público."}, {"id": "3268586", "d": "direito_constitucional", "a": ["Classificação das Constituições", "Teoria da Constituição"], "ano": "2024", "org": "CREF", "t": "", "e": "Assinale a alternativa que apresenta a classificação da\nConstituição Federal de 1988 quanto à origem.", "alt": {"A": "outorgada", "B": "cesarista", "C": "pactuada", "D": "bonapartista", "E": "promulgada"}, "g": "E", "j": "CF/88 é classificada quanto à origem como promulgada (democrática) — elaborada pela Assembleia Nacional Constituinte de 1987-1988."}, {"id": "3231002", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2024", "org": "CONFERE", "t": "", "e": "De acordo com o Sistema Tributário Nacional, julgue os\nitens a seguir, à luz do vigente regramento.    \nI Determina a CF/1988 que a competência para\ninstituição de empréstimos compulsórios é\nexclusiva da União, que deverá fazê‑lo, se for o\ncaso, por meio de medida provisória.\n    II De acordo com a doutrina do Código Tributário\nNacional, os tributos são os impostos, as taxas,\nas contribuições de melhoria, os emolumentos e\nas custas.\n    III O Sistema Tributário Nacional deverá observar,\ntambém, os princípios da simplicidade, da\ntransparência e da justiça tributária.\n      Assinale a alternativa correta.", "alt": {"A": "Somente o item I está certo.", "B": "Somente os itens I e II estão certos.", "C": "Somente os itens I e III estão certos.", "D": "Somente os itens II e III estão certos.", "E": "Somente o item III está certo."}, "g": "E", "j": "I falso (empréstimos compulsórios exigem LC, não MP); II falso (emolumentos e custas não são tributos no CTN); III correto (EC 132/2023 incluiu simplicidade, transparência e justiça tributária no art. 145, §3º CF)."}, {"id": "3230996", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade", "Administração Pública – Disposições Gerais e Servidores Públicos", "Disposições Gerais na Administração Pública"], "ano": "2024", "org": "CONFERE", "t": "", "e": "De acordo com a Constituição Federal de 1988 (CF/1988),\njulgue os itens a seguir, no que se refere à\nAdministração Pública Federal.\n    I Regra geral, a CF/1988 veda o acúmulo\nremunerado de cargos públicos. Contudo,\nalgumas exceções são admitidas, em caso de\ncompatibilidade de horários, como a ocupação de\ndois cargos de professor.    \nII A CF/1988 veda, em qualquer hipótese, que\nbrasileiros naturalizados ou estrangeiros venham\na ocupar cargos ou empregos públicos, em função\ndo princípio da soberania nacional.    \nIII A estabilidade em cargos de provimento\nefetivo é adquirida após três anos de efetivo\nexercício, sujeita, contudo, à avaliação especial\nde desempenho por comissão instituída para\nessa finalidade.      \nAssinale a alternativa correta.", "alt": {"A": "Somente o item I está certo.", "B": "Somente os itens I e II estão certos.", "C": "Somente os itens I e III estão certos.", "D": "Somente os itens II e III estão certos.", "E": "Somente o item III está certo."}, "g": "C", "j": "I correto (art. 37, XVI permite acumular dois cargos de professor); II falso (estrangeiros e naturalizados podem ocupar cargos públicos, salvo restrições específicas); III correto (estabilidade após 3 anos com avaliação especial — art. 41)."}, {"id": "3230919", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Advocacia"], "ano": "2024", "org": "CONFERE", "t": "", "e": "Conforme a Constituição Federal de 1988, a instituição que,\ndiretamente ou por meio de órgão vinculado, representa\na União, judicial e extrajudicialmente, cabendo‑lhe as\natividades de consultoria e assessoramento jurídico do\nPoder Executivo, é o(a)", "alt": {"A": "Ministério da Justiça.", "B": "advocacia privada.", "C": "Ministério Público.", "D": "Advocacia‑Geral da União.", "E": "Poder Judiciário."}, "g": "D", "j": "Art. 131 CF/88: a Advocacia-Geral da União representa a União judicial e extrajudicialmente e exerce atividades de consultoria e assessoramento jurídico do Poder Executivo."}, {"id": "3230918", "d": "direito_constitucional", "a": ["Supremo Tribunal Federal", "Organização do Poder Judiciário"], "ano": "2024", "org": "CONFERE", "t": "", "e": "De acordo com a Constituição Federal de 1988, assinale a\nalternativa correta, em relação aos ministros do Supremo\nTribunal Federal.", "alt": {"A": "Serão nomeados pelo presidente da República, depois\nde aprovada a escolha pela maioria qualificada do\nCongresso Nacional.", "B": "Serão nomeados pelo ministro da Justiça, depois\nde aprovada a escolha pela maioria absoluta do\nCongresso Nacional.", "C": "Serão nomeados pelo presidente da República, depois\nde aprovada a escolha pela maioria absoluta da\nCâmara dos Deputados.", "D": "Serão nomeados pelo vice‑presidente da República,\ndepois de aprovada a escolha pela maioria absoluta\ndo Senado Federal.", "E": "Serão nomeados pelo presidente da República, depois\nde aprovada a escolha pela maioria absoluta do\nSenado Federal."}, "g": "E", "j": "Art. 101, §único CF/88: ministros do STF são nomeados pelo Presidente da República, depois de aprovada a escolha pela maioria absoluta do Senado Federal."}, {"id": "3230917", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2024", "org": "CONFERE", "t": "", "e": "Considerando a Constituição Federal de 1988, assinale\na alternativa correta, acerca dos direitos e das\ngarantias fundamentais.", "alt": {"A": "Ninguém será obrigado a fazer ou deixar de fazer\nalguma coisa, senão em virtude de lei ou ordem\nexpressa da autoridade policial.", "B": "É livre a manifestação do pensamento, sendo vedado\no anonimato.", "C": "É assegurado o direito de resposta, proporcional ao\nagravo, compreendendo apenas a indenização por\ndano material.", "D": "São invioláveis a intimidade, a vida privada, a honra e\na imagem das pessoas, mas não é assegurado o direito\nà indenização pelo dano material ou moral decorrente\nde sua violação.", "E": "É plena a liberdade de associação para fins lícitos,\ninclusive a de caráter paramilitar."}, "g": "B", "j": "Art. 5º, IV CF/88: livre manifestação do pensamento, sendo vedado o anonimato."}, {"id": "3230916", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Princípios de Direito Constitucional Internacional"], "ano": "2024", "org": "CONFERE", "t": "", "e": "Quanto à Constituição Federal de 1988, assinale a\nalternativa correta, acerca das relações internacionais\ndo Brasil.", "alt": {"A": "A República Federativa do Brasil buscará a integração\neconômica, política, social e cultural dos povos\nda América Latina, visando à formação de uma\ncomunidade latino‑americana de nações.", "B": "A República Federativa do Brasil buscará a integração\neconômica, política, social e cultural dos povos do\ncontinente americano, visando à formação de uma\ncomunidade americana de nações.", "C": "A República Federativa do Brasil buscará a integração\neconômica, política, social e cultural dos povos da\nAmérica Latina e da Europa, visando à formação de\numa comunidade euro‑latino‑americana de nações.", "D": "A República Federativa do Brasil buscará a integração\neconômica, política, social e cultural dos povos de\ntodos os continentes, visando à formação de uma\ncomunidade mundial de nações.", "E": "A República Federativa do Brasil buscará a integração\neconômica, política e social dos povos da América,\nmas sem promover qualquer tipo de mescla cultural."}, "g": "A", "j": "Art. 4º, parágrafo único CF/88: o Brasil buscará a integração econômica, política, social e cultural dos povos da América Latina, visando à formação de uma comunidade latino-americana de nações."}, {"id": "3179869", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2024", "org": "CORE", "t": "", "e": "Com base na Constituição Federal de 1988 (CF/1988),\nassinale a alternativa correta no que diz respeito aos\nprincípios fundamentais que regem a República.", "alt": {"A": "A República Federativa do Brasil é formada pela\nunião indissolúvel dos estados, dos territórios, dos\nmunicípios e do Distrito Federal.", "B": "O Estado brasileiro não concede asilo político em\nnenhuma circunstância.", "C": "A República Federativa do Brasil buscará a integração\neconômica, política, social e cultural dos povos\nda América Latina, visando à formação de uma\ncomunidade latino‑americana de nações.", "D": "Nas suas relações internacionais, a República\nFederativa do Brasil é regida pelo princípio da\nintervenção em estados não democráticos.", "E": "Diminuir a pobreza para um nível aceitável é um dos\nobjetivos da República Federativa do Brasil."}, "g": "C", "j": "Art. 4º, parágrafo único CF/88: integração latino-americana visando comunidade latino-americana de nações."}, {"id": "3115563", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Disposições Gerais na Administração Pública"], "ano": "2024", "org": "CORE", "t": "", "e": "De acordo com a Constituição Federal de 1988, é\npossível acumular", "alt": {"A": "dois ou mais cargos de professor.", "B": "dois ou mais cargos ou empregos privativos\nde profissionais de saúde, com profissões\nregulamentadas.", "C": "um cargo de advogado com outro em empresa\npública.", "D": "um cargo de professor com outro técnico ou científico.", "E": "um cargo de magistrado com outro técnico ou científico em uma sociedade de economia mista."}, "g": "D", "j": "Art. 37, XVI, 'b' CF/88: acumulação permitida de um cargo de professor com outro técnico ou científico, havendo compatibilidade de horários."}, {"id": "2660433", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2024", "org": "CRF", "t": "", "e": "Conforme a Constituição Federal de 1988, a instituição do imposto sobre grandes fortunas é de competência", "alt": {"A": "dos municípios.", "B": "dos estados.", "C": "do Distrito Federal.", "D": "da União.", "E": "de todos os entes federativos, em conjunto."}, "g": "D", "j": "Art. 153, VII CF/88: compete à União instituir imposto sobre grandes fortunas, nos termos de lei complementar."}, {"id": "2660432", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2024", "org": "CRF", "t": "", "e": "Considerando a Constituição Federal de 1988, é permitido à União, aos estados, ao Distrito Federal e aos municípios", "alt": {"A": "exigir ou aumentar tributo sem lei que o estabeleça.", "B": "instituir contribuição de melhoria, decorrente de obras públicas.", "C": "utilizar tributo com efeito de confisco.", "D": "estabelecer limitações ao tráfego de pessoas ou bens, por meio de tributos interestaduais ou intermunicipais, ressalvada a cobrança de pedágio pela utilização de vias conservadas pelo poder público.", "E": "cobrar tributos em relação a fatos geradores ocorridos antes do início da vigência da lei que os houver instituído ou aumentado."}, "g": "B", "j": "Art. 145, III CF/88: é permitido aos entes federativos instituir contribuição de melhoria, decorrente de obras públicas."}, {"id": "2660431", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2024", "org": "CRF", "t": "", "e": "De acordo com a Constituição Federal de 1988, a regulação das limitações constitucionais ao poder de tributar deverá ser realizada por", "alt": {"A": "lei complementar.", "B": "lei ordinária.", "C": "medida provisória.", "D": "decreto legislativo.", "E": "emenda constitucional."}, "g": "A", "j": "Art. 146, II CF/88: cabe à lei complementar regular as limitações constitucionais ao poder de tributar."}, {"id": "2660430", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Advocacia Pública"], "ano": "2024", "org": "CRF", "t": "", "e": "Conforme a Constituição Federal de 1988, o cargo de advogado‑geral da União é de livre nomeação pelo", "alt": {"A": "presidente da República, entre cidadãos maiores de 21 anos de idade, de notável saber jurídico e de reputação ilibada.", "B": "presidente do Supremo Tribunal Federal, entre cidadãos maiores de 35 anos de idade, de notável saber jurídico e de reputação ilibada.", "C": "vice‑presidente da República, entre cidadãos maiores de 35 anos de idade, de notável saber jurídico e de reputação ilibada.", "D": "presidente do Senado Federal, entre cidadãos maiores de 21 anos de idade, de notável saber jurídico e de reputação ilibada.", "E": "presidente da República, entre cidadãos maiores de 35 de anos idade, de notável saber jurídico e de reputação ilibada."}, "g": "E", "j": "Art. 131, §1º CF/88: o AGU é de livre nomeação pelo Presidente da República dentre cidadãos maiores de 35 anos, de notável saber jurídico e reputação ilibada."}, {"id": "2660428", "d": "direito_constitucional", "a": ["Poder Legislativo"], "ano": "2024", "org": "CRF", "t": "", "e": "Acerca da Constituição Federal de 1988, assinale a alternativa correta, a respeito do Poder Legislativo.", "alt": {"A": "O Poder Legislativo é exercido pelo Senado Federal, que se compõe da Câmara dos Deputados e do Congresso Nacional.", "B": "Cada legislatura terá a duração de oito anos.", "C": "Cada território elegerá oito deputados federais.", "D": "O Senado Federal compõe‑se de representantes dos estados e do Distrito Federal, eleitos segundo o princípio majoritário.", "E": "Cada senador será eleito com três suplentes."}, "g": "D", "j": "Art. 46 CF/88: o Senado Federal compõe-se de representantes dos Estados e do DF, eleitos pelo princípio majoritário."}, {"id": "2660427", "d": "direito_constitucional", "a": ["Organização do Estado - União", "Organização Político-Administrativa do Estado"], "ano": "2024", "org": "CRF", "t": "", "e": "Quanto à Constituição Federal de 1988, é correto afirmar que as terras tradicionalmente ocupadas pelos índios são consideradas bens", "alt": {"A": "das comunidades indígenas que as ocuparem.", "B": "do Ministério da Justiça.", "C": "dos municípios em que se encontrarem.", "D": "dos estados em que se encontrarem.", "E": "da União."}, "g": "E", "j": "Art. 20, XI CF/88: as terras tradicionalmente ocupadas pelos índios são bens da União."}, {"id": "2660426", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2024", "org": "CRF", "t": "", "e": "De acordo com a Constituição Federal de 1988, os territórios federais integram a União, e sua criação, transformação em estado ou reintegração ao estado de origem serão reguladas em", "alt": {"A": "emenda constitucional.", "B": "decreto presidencial.", "C": "lei complementar.", "D": "lei ordinária.", "E": "medida provisória."}, "g": "C", "j": "Art. 18, §3º CF/88: territórios federais integram a União; sua criação, transformação em Estado ou reintegração ao Estado de origem serão reguladas em lei complementar."}, {"id": "2660425", "d": "direito_constitucional", "a": ["Partidos Políticos", "Noção geral"], "ano": "2024", "org": "CRF", "t": "", "e": "Considerando a Constituição Federal de 1988, os partidos políticos, após adquirirem personalidade jurídica, na forma da lei civil, registrarão seus estatutos no", "alt": {"A": "Supremo Tribunal Federal.", "B": "Tribunal Superior Eleitoral.", "C": "Senado Federal.", "D": "Tribunal Regional Eleitoral de sua sede.", "E": "Congresso Nacional."}, "g": "B", "j": "Art. 17, §2º CF/88: os partidos políticos, após adquirirem personalidade jurídica na forma da lei civil, registrarão seus estatutos no Tribunal Superior Eleitoral."}, {"id": "2660424", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2024", "org": "CRF", "t": "", "e": "Acerca da Constituição Federal de 1988, sobre os direitos políticos, assinale a alternativa correta.", "alt": {"A": "Não podem alistar‑se como eleitores os estrangeiros e, durante o período do serviço militar obrigatório, os conscritos.", "B": "O presidente da República, os governadores de estado e do Distrito Federal, os prefeitos e quem os houver sucedido, ou substituído no curso dos mandatos, não poderão ser reeleitos.", "C": "Para concorrerem a outros cargos, o presidente da República, os governadores de estado e do Distrito Federal e os prefeitos devem renunciar aos respectivos mandatos até seis semanas antes do pleito.", "D": "É permitida a cassação de direitos políticos no direito brasileiro.", "E": "A lei que alterar o processo eleitoral entrará em vigor na data de sua publicação, aplicando‑se imediatamente a todas as eleições subsequentes."}, "g": "A", "j": "Art. 14, §2º CF/88: não podem alistar-se como eleitores os estrangeiros e, durante o período do serviço militar obrigatório, os conscritos."}, {"id": "2660423", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2024", "org": "CRF", "t": "", "e": "Segundo a Constituição Federal de 1988, a soberania popular será exercida pelo sufrágio", "alt": {"A": "universal e pelo voto direto e público, com valor igual para todos.", "B": "universal e pelo voto direto e secreto, com valor em dobro para aqueles que estiverem em situação de vulnerabilidade.", "C": "capacitário e pelo voto direto e secreto, com valor igual para todos.", "D": "universal e pelo voto indireto e secreto, com valor igual para todos.", "E": "universal e pelo voto direto e secreto, com valor igual para todos."}, "g": "E", "j": "Art. 14 caput CF/88: soberania popular pelo sufrágio universal e voto direto e secreto, com valor igual para todos."}, {"id": "2660422", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2024", "org": "CRF", "t": "", "e": "Quanto à Constituição Federal de 1988, é correto afirmar que são símbolos da República Federativa do Brasil a", "alt": {"A": "bandeira, o hino, as armas e o selo nacionais.", "B": "bandeira, o hino, as armas e o território nacionais.", "C": "bandeira, o hino, o povo e o selo nacionais.", "D": "bandeira, o hino, a cultura e o selo nacionais.", "E": "bandeira, o hino, a moeda e o selo nacionais."}, "g": "A", "j": "Art. 13, §1º CF/88: são símbolos da República Federativa do Brasil a bandeira, o hino, as armas e o selo nacionais."}, {"id": "2660421", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2024", "org": "CRF", "t": "", "e": "Acerca da Constituição Federal de 1988, assinale a alternativa que apresenta o cargo que pode ser ocupado por brasileiro naturalizado.", "alt": {"A": "ministro de Estado da Defesa", "B": "ministro de Estado da Economia", "C": "ministro do Supremo Tribunal Federal", "D": "oficial das Forças Armadas", "E": "presidente da Câmara dos Deputados"}, "g": "B", "j": "Art. 12, §3º CF/88: o cargo de Ministro da Economia NÃO está entre os privativos de brasileiro nato (apenas Min. Defesa entre os ministros listados)."}, {"id": "2660420", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2024", "org": "CRF", "t": "", "e": "Considerando a Constituição Federal de 1988, assinale a alternativa correta, a respeito dos direitos sociais.", "alt": {"A": "O trabalho e a moradia não são considerados direitos sociais.", "B": "Apenas os brasileiros natos que estiverem em situação de vulnerabilidade social terão direito a uma renda básica familiar, garantida pelo poder público em programa permanente de transferência de renda.", "C": "Os trabalhadores rurais e urbanos possuem direito à irredutibilidade do salário, salvo o disposto em convenção ou acordo coletivo.", "D": "O salário mínimo é uma garantia exclusiva dos trabalhadores urbanos, e não será aplicável aos trabalhadores rurais.", "E": "Os trabalhadores rurais e urbanos possuem direito a seguro‑desemprego, em caso de desemprego voluntário ou involuntário."}, "g": "C", "j": "Art. 7º, VI CF/88: irredutibilidade do salário, salvo o disposto em convenção ou acordo coletivo."}, {"id": "2658910", "d": "direito_constitucional", "a": [], "ano": "2024", "org": "CRF", "t": "", "e": "A respeito dos direitos e deveres individuais e coletivos, julgue os itens a seguir.I É assegurado o direito de resposta proporcional ao agravo, hipótese em que o ofendido não fará jus a qualquer tipo de indenização.Il  A casa é asilo inviolável do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, exceto por determinação judicial, a qualquer hora do dia ou da noite.III É assegurado a todos o acesso à informação e resguardado do sigilo da fonte, quando necessário ao exercício profissional.Assinale a alternativa correta.", "alt": {"A": "Somente os itens l e Il estão certos.", "B": "Somente os itens l e Ill estão certos.", "C": "Somente o item Il está certo.", "D": "Somente os itens Il e Ill estão certos.", "E": "Somente o item III está certo."}, "g": "E", "j": "III correto (acesso à informação e sigilo da fonte). I falso (direito de resposta + indenização). II falso (entrada por determinação judicial só durante o DIA, não a qualquer hora)."}, {"id": "2658908", "d": "direito_constitucional", "a": [], "ano": "2024", "org": "CRF", "t": "", "e": "De acordo com a Constituição Federal de 1988, existem exceções à vedação do acúmulo remunerado de cargos públicos, desde que haja compatibilidade de horários. Uma dessas exceções é a possibilidade de acúmulo", "alt": {"A": "de dois cargos de natureza técnica ou científica.", "B": "de dois cargos em comissão, declarados em lei de livre nomeação e exoneração.", "C": "do cargo de prefeito com um cargo de vereador no mesmo município.", "D": "de dois cargos ou empregos privativos de profissionais de saúde, com profissões regulamentadas.", "E": "de dois cargos de vereador em municípios diferentes."}, "g": "D", "j": "Art. 37, XVI, 'c' CF/88: a acumulação de dois cargos ou empregos privativos de profissionais de saúde, com profissões regulamentadas, é permitida com compatibilidade de horários."}, {"id": "2526929", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2024", "org": "CRMV", "t": "", "e": "Em relação aos princípios da Administração Pública, julgue\nos itens a seguirI        Em razão do princípio da legalidade, somente é\nconsiderada legítima a atuação do agente público\nou da Administração Pública, se for permitida\npor lei.II        A Administração Pública tem o dever de\ndar publicidade, ou seja, de conduzir ao\nconhecimento de terceiros o conteúdo e a\nexata dimensão do ato administrativo, a fim de\nfacilitar o controle dos atos da Administração, em\nqualquer hipótese.III        Segundo o princípio da eficiência, o ordenamento\njurídico censura a atuação amadorística do agente\npúblico, que, no exercício de sua função, deve\nimprimir incansável esforço pela consecução do\nmelhor resultado possível e o máximo proveito\ncom o mínimo de recursos humanos e financeiros.Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "C", "j": "I e III corretos. II falso: a publicidade comporta exceções (sigilo imprescindível à segurança do Estado, intimidade etc.), não 'em qualquer hipótese'."}, {"id": "2526928", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2024", "org": "CRMV", "t": "", "e": "O princípio da Administração Pública que exige que\na atuação do administrador público seja voltada ao\natendimento geral, ainda que venha a interessar a\npessoas determinadas, não sendo a atuação atribuída ao\nagente público, mas à entidade estatal a que se vincula,\né denominado", "alt": {"A": "legalidade.", "B": "impessoalidade.", "C": "moralidade.", "D": "publicidade.", "E": "eficiência."}, "g": "B", "j": "O princípio da impessoalidade exige atuação voltada ao atendimento geral, atribuindo o ato à entidade estatal e não ao agente público."}, {"id": "2526832", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Disposições Gerais na Administração Pública"], "ano": "2024", "org": "CRMV", "t": "", "e": "Considerando a Constituição Federal de 1988, assinale\na alternativa correta, no que diz respeito à disciplina da\nAdministração Pública.", "alt": {"A": "É vedado ao servidor público exercer direito de greve.", "B": "Os cargos em comissão destinam‑se apenas às\natribuições de direção, de chefia e de assessoramento.", "C": "A Constituição Federal de 1988 não admite que\nestrangeiros ocupem cargos públicos no Brasil.", "D": "A criação e a extinção de cargos públicos podem ser\nlevadas a efeito por meio de decreto do chefe do\nPoder Executivo.", "E": "É expressamente vedado, em qualquer hipótese, o\nacúmulo remunerado de cargos públicos."}, "g": "B", "j": "Art. 37, V CF/88: cargos em comissão destinam-se às atribuições de direção, chefia e assessoramento."}, {"id": "2522730", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira"], "ano": "2024", "org": "CRMV", "t": "", "e": "No que se refere à Constituição Federal de 1988, a\ncompetência para instituir impostos sobre a propriedade\nterritorial rural foi atribuída", "alt": {"A": "ao Instituto Nacional de Colonização e Reforma\nAgrária.", "B": "aos municípios.", "C": "aos estados.", "D": "ao Distrito Federal.", "E": "à União."}, "g": "E", "j": "Art. 153, VI CF/88: o ITR (imposto sobre propriedade territorial rural) é da competência da União."}, {"id": "2522729", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2024", "org": "CRMV", "t": "", "e": "Quanto à Constituição Federal de 1988, a respeito dos\nprincípios gerais do Sistema a Tributário Nacional, a\nregulamentação das limitações constitucionais ao poder de\ntributar será feita mediante", "alt": {"A": "medida provisória.", "B": "decreto.", "C": "lei ordinária.", "D": "lei complementar.", "E": "emenda constitucional."}, "g": "D", "j": "Art. 146, II CF/88: cabe à lei complementar regular as limitações constitucionais ao poder de tributar."}, {"id": "2522728", "d": "direito_constitucional", "a": ["Poder Executivo"], "ano": "2024", "org": "CRMV", "t": "", "e": "Considerando‑se a Constituição Federal de 1988, antes de\ndecretar o estado de defesa, o presidente da República\ndeve escutar o(a)", "alt": {"A": "ministro da Justiça e o advogado‑geral da União.", "B": "presidente do Supremo Tribunal Federal e o presidente\ndo Senado Federal.", "C": "Conselho da República e o Conselho de Defesa\nNacional.", "D": "Câmara dos Deputados e o Senado Federal.", "E": "Procuradoria‑Geral da República e as Forças Armadas."}, "g": "C", "j": "Art. 136 CF/88: o Presidente decreta o estado de defesa após ouvir o Conselho da República e o Conselho de Defesa Nacional."}, {"id": "2522727", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Organização Político-Administrativa do Estado"], "ano": "2024", "org": "CRMV", "t": "", "e": "Conforme a Constituição Federal de 1988, a instituição\npermanente, essencial à função jurisdicional do Estado,\nà qual compete a defesa da ordem jurídica, do regime\ndemocrático e dos interesses sociais e individuais\nindisponíveis é o(a)", "alt": {"A": "advocacia privada.", "B": "Advocacia‑Geral da União.", "C": "Ministério Público.", "D": "Defensoria Pública.", "E": "Procuradoria da Fazenda Nacional."}, "g": "C", "j": "Art. 127 CF/88: o Ministério Público é instituição permanente, essencial à função jurisdicional do Estado, incumbindo-lhe a defesa da ordem jurídica, do regime democrático e dos interesses sociais e individuais indisponíveis."}, {"id": "2522726", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2024", "org": "CRMV", "t": "", "e": "Segundo a Constituição Federal de 1988, a respeito da\norganização do Estado brasileiro, a competência para\nmanter relações com Estados estrangeiros e participar de\norganizações internacionais é", "alt": {"A": "do Distrito Federal.", "B": "da União.", "C": "dos estados.", "D": "dos municípios.", "E": "do Mercosul."}, "g": "B", "j": "Art. 21, I CF/88: compete à União manter relações com Estados estrangeiros e participar de organizações internacionais."}, {"id": "2522725", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2024", "org": "CRMV", "t": "", "e": "Acerca da Constituição Federal de 1988, assinale a\nalternativa correta, a respeito dos direitos de nacionalidade.", "alt": {"A": "São brasileiros natos os nascidos na República\nFederativa do Brasil, ainda que de pais estrangeiros,\ndesde que estes não estejam a serviço de seu país.", "B": "São brasileiros naturalizados os nascidos na República\nFederativa do Brasil, ainda que de pais estrangeiros,\ndesde que estes não estejam a serviço de seu país.", "C": "São brasileiros natos os nascidos na República\nFederativa do Brasil, exceto quando de pais\nestrangeiros.", "D": "São brasileiros natos os nascidos na República\nFederativa do Brasil, ainda que de pais estrangeiros,\ninclusive se estiverem a serviço de seu país.", "E": "São brasileiros naturalizados os nascidos na República\nFederativa do Brasil, ainda que de pais estrangeiros,\ninclusive se estiverem a serviço de seu país."}, "g": "A", "j": "Art. 12, I, 'a' CF/88: são brasileiros natos os nascidos no Brasil, ainda que de pais estrangeiros, desde que estes não estejam a serviço de seu país."}, {"id": "2522724", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2024", "org": "CRMV", "t": "", "e": "No que concerne à Constituição Federal de 1988, assinale a\nalternativa correta, quanto aos direitos sociais.", "alt": {"A": "É vedada a dispensa do empregado sindicalizado a\npartir do registro da candidatura a cargo de direção\nou de representação sindical e, se eleito, ainda\nque suplente, até um ano após o final do mandato,\ninclusive se este cometer falta grave.", "B": "É assegurado o direito de greve, competindo aos\nempregadores decidir sobre a oportunidade de\nexercê‑lo e sobre os interesses que devam por meio\ndele defender.", "C": "É assegurada apenas a participação dos trabalhadores\nnos colegiados dos órgãos públicos em que seus\ninteresses profissionais ou previdenciários sejam\nobjeto de discussão e deliberação.", "D": "Nas empresas de mais de duzentos empregados, é\nassegurada a eleição de um representante destes\ncom a finalidade exclusiva de promover‑lhes o\nentendimento direto com os empregadores.", "E": "A lei poderá exigir autorização do Estado para a\nfundação de sindicato, inclusive com o registro no\nórgão competente, sendo lícita ao poder público a\ninterferência e a intervenção na organização sindical."}, "g": "D", "j": "Art. 11 CF/88: nas empresas de mais de 200 empregados é assegurada a eleição de um representante para entendimento direto com os empregadores."}, {"id": "2522723", "d": "direito_constitucional", "a": ["Direitos Individuais"], "ano": "2024", "org": "CRMV", "t": "", "e": "Quanto à Constituição Federal de 1988, assinale a\nalternativa correta, a respeito dos direitos e deveres\nindividuais e coletivos.", "alt": {"A": "É livre a manifestação do pensamento, sendo\npermitido o anonimato.", "B": "É inviolável a liberdade de consciência e de\ncrença, mas não é garantido o livre exercício dos\ncultos religiosos.", "C": "São invioláveis a intimidade, a vida privada, a honra\ne a imagem das pessoas, assegurado o direito à\nindenização apenas pelo dano material decorrente de\nsua violação.", "D": "É assegurado a todos o acesso à informação, sem se\nresguardar o sigilo da fonte.", "E": "Todos podem reunir‑se pacificamente, sem armas,\nem locais abertos ao público, independentemente de\nautorização, desde que não frustrem outra reunião\nanteriormente convocada para o mesmo local, sendo\napenas exigido prévio aviso à autoridade competente."}, "g": "E", "j": "Art. 5º, XVI CF/88: todos podem reunir-se pacificamente, sem armas, em locais abertos ao público, independentemente de autorização, com prévio aviso à autoridade."}, {"id": "2391968", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2024", "org": "CAU", "t": "", "e": "Acerca da Constituição Federal de 1988, quantos aos\ndireitos políticos, assinale a alternativa correta.", "alt": {"A": "O alistamento eleitoral e o voto são obrigatórios para\nos maiores de quatorze anos de idade.", "B": "Podem alistar‑se como eleitores os estrangeiros e,\ndurante o período do serviço militar obrigatório,\nos conscritos.", "C": "Os analfabetos são elegíveis, mas inalistáveis para\nfins eleitorais.", "D": "A soberania popular será exercida pelo sufrágio\nuniversal e pelo voto direto e secreto, com valor igual\npara todos.", "E": "O presidente da República, os governadores de\nestado e do Distrito Federal, os prefeitos e quem\nos houver sucedido, ou substituído no curso dos\nmandatos, poderão ser reeleitos para até três\nperíodos subsequentes."}, "g": "D", "j": "Art. 14 caput CF/88: soberania popular pelo sufrágio universal e voto direto e secreto, com valor igual para todos."}, {"id": "2391967", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2024", "org": "CAU", "t": "", "e": "De acordo com a Constituição Federal de 1988, são\nbrasileiro natos os", "alt": {"A": "nascidos na República Federativa do Brasil, salvo se de\npais estrangeiros.", "B": "que, na forma da lei, adquiram a nacionalidade\nbrasileira, exigidas aos originários de países de língua\nportuguesa apenas residência por um ano ininterrupto\ne idoneidade moral.", "C": "estrangeiros de qualquer nacionalidade, residentes na\nRepública Federativa do Brasil há mais de quinze anos\nininterruptos e sem condenação penal, desde que\nrequeiram a nacionalidade brasileira.", "D": "portugueses com residência fixa na República\nFederativa do Brasil há mais de 15 anos.", "E": "nascidos na República Federativa do Brasil, ainda que\nde pais estrangeiros, desde que estes não estejam a\nserviço de seu país."}, "g": "E", "j": "Art. 12, I, 'a' CF/88: são brasileiros natos os nascidos no Brasil, ainda que de pais estrangeiros, desde que estes não estejam a serviço de seu país."}, {"id": "2391848", "d": "direito_constitucional", "a": ["Organização do Estado - União", "Organização Político-Administrativa do Estado"], "ano": "2024", "org": "CAU", "t": "", "e": "Segundo a Constituição Federal de 1988, legislar sobre\ndireito civil e eleitoral é uma competência atribuída", "alt": {"A": "à União, exclusivamente.", "B": "aos estados, exclusivamente.", "C": "à União, privativamente.", "D": "à União e aos estados, concorrentemente.", "E": "aos municípios, residualmente."}, "g": "C", "j": "Art. 22, I CF/88: compete privativamente à União legislar sobre direito civil e eleitoral."}, {"id": "2391847", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2024", "org": "CAU", "t": "", "e": "Considerando as disposições da Constituição Federal\nde 1988, assinale a alternativa que apresenta um cargo\nprivativo de brasileiro nato.", "alt": {"A": "ministro do Superior Tribunal de Justiça", "B": "ministro do Supremo Tribunal Federal", "C": "ministro do Tribunal Superior Eleitoral", "D": "ministro da Educação", "E": "ministro da Justiça"}, "g": "B", "j": "Art. 12, §3º CF/88: o cargo de Ministro do STF é privativo de brasileiro nato."}, {"id": "2363547", "d": "direito_constitucional", "a": ["Direitos Políticos", "Poder Legislativo", "Poder Judiciário", "Congresso Nacional"], "ano": "2023", "org": "FSNH", "t": "", "e": "Quanto ao atual sistema político‑eleitoral brasileiro, é\ncorreto afirmar que", "alt": {"A": "o voto é censitário, ou seja, a renda, tal como no\nImpério, era o fator determinante para votar e\nser votado.", "B": "inexiste idade mínima para se candidatar a\ndeterminados cargos, como, por exemplo, o de\npresidente da República.", "C": "não há mais necessidade de se filiar a um partido\npolítico, para se candidatar a qualquer cargo público.", "D": "os ministros do Supremo Tribunal Federal, a mais\nalta corte do Judiciário brasileiro, são eleitos pelo\nvoto popular.", "E": "o Poder Legislativo é exercido pelo Congresso\nNacional (Câmara dos Deputados e Senado Federal)."}, "g": "E", "j": "Art. 44 CF/88: o Poder Legislativo é exercido pelo Congresso Nacional, composto pela Câmara dos Deputados e pelo Senado Federal."}, {"id": "2288315", "d": "direito_constitucional", "a": ["Ordem Social", "Saúde"], "ano": "2023", "org": "CREFITO", "t": "", "e": "Nos termos da Constituição Federal de 1988, com relação à \nassistência à saúde, a destinação de recursos públicos para \nauxílios ou subvenções é permitida às", "alt": {"A": "entidades que prestem serviços fora do âmbito do \nSistema Único de Saúde (SUS).", "B": "empresas que realizem pesquisas sobre tratamentos \nfisioterápicos.", "C": "instituições privadas sem fins lucrativos.", "D": "instituições que tratem de doenças raras.", "E": "entidades religiosas que prestem serviços a seus \nfiliados."}, "g": "C", "j": "Art. 199, §2º CF/88: é vedada destinação de recursos públicos para auxílios ou subvenções a instituições privadas com fins lucrativos. Apenas as sem fins lucrativos podem receber."}, {"id": "2288306", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2023", "org": "CREFITO", "t": "", "e": "As terras devolutas, indispensáveis à defesa das fronteiras, \ndas fortificações e construções militares, das vias \nfederais de comunicação e à preservação ambiental, são \nbens da(do)", "alt": {"A": "União.", "B": "estado da Federação no qual estão localizadas.", "C": "território no qual estão localizadas.", "D": "Distrito Federal.", "E": "município no qual estão localizadas."}, "g": "A", "j": "Art. 20, II CF/88: as terras devolutas indispensáveis à defesa das fronteiras, fortificações, vias federais e à preservação ambiental são bens da União."}, {"id": "2287480", "d": "direito_constitucional", "a": ["Organização dos Poderes", "Princípio da Separação dos Poderes"], "ano": "2023", "org": "CREFITO", "t": "", "e": "Com base na Constituição Federal de 1988, assinale a \nalternativa correta, em relação à organização dos poderes \nno Estado.", "alt": {"A": "O Poder Legislativo é exercido pelo Congresso \nNacional, que se compõe da Câmara dos Deputados e \ndas assembleias legislativas.", "B": "O Senado Federal compõe‑se de representantes do \npovo, eleitos, pelo sistema proporcional, em cada \nestado, em cada território e no Distrito Federal.", "C": "Cada estado e o Distrito Federal elegerão três \nsenadores, com mandato de quatro anos.", "D": "Cada senador será eleito com dois suplentes.", "E": "Somente a Câmara dos Deputados poderá convocar \nministro de Estado ou quaisquer titulares de órgãos \ndiretamente subordinados à presidência da República \npara prestarem, pessoalmente, informações sobre \nassunto previamente determinado, importando \ncrime de responsabilidade à ausência sem \njustificação adequada."}, "g": "D", "j": "Art. 46, §3º CF/88: cada senador será eleito com dois suplentes."}, {"id": "2287479", "d": "direito_constitucional", "a": ["Ordem Social"], "ano": "2023", "org": "CREFITO", "t": "", "e": "De acordo com a Constituição Federal de 1988, assinale a \nalternativa correta, a respeito da ordem social.", "alt": {"A": "A ordem social tem como base a propriedade privada \ne tem, como objetivo, o bem‑estar e a justiça sociais.", "B": "A seguridade social compreende um conjunto \nintegrado de ações de iniciativa dos poderes públicos \ne da sociedade, destinadas a assegurar os direitos \nrelativos à saúde, à previdência e à assistência social.", "C": "A saúde é direito de todos e dever do Estado, garantido \nmediante políticas sociais e econômicas que visem \nà redução do risco de doença e de outros agravos e \nao acesso universal e não igualitário às ações e aos \nserviços para sua promoção, proteção e recuperação.", "D": "É vedada à lei complementar disciplinar a cobertura de \nbenefícios não programados, inclusive os decorrentes \nde acidente do trabalho.", "E": "As universidades gozam de autonomia \ndidático‑científica, mas são administrativamente \nvinculadas e subordinadas ao Ministério da \nEducação (MEC)."}, "g": "B", "j": "Art. 194 CF/88: seguridade social compreende conjunto integrado de ações dos Poderes Públicos e da sociedade destinadas a saúde, previdência e assistência social."}, {"id": "2287478", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Ministério Público"], "ano": "2023", "org": "CREFITO", "t": "", "e": "Quanto à Constituição Federal de 1988, assinale a \nalternativa correta, quanto ao Ministério Público.", "alt": {"A": "O Ministério Público é uma instituição temporária, \nessencial à função jurisdicional do Estado, \nincumbindo‑lhe a defesa da ordem jurídica, do \nregime democrático e dos interesses sociais e \nindividuais indisponíveis.", "B": "O Ministério Público é uma instituição permanente, \nessencial à função jurisdicional do Estado, \nincumbindo‑lhe a defesa da ordem jurídica, do \nregime democrático e dos interesses sociais e \nindividuais disponíveis.", "C": "O Ministério Público é uma instituição permanente, \nessencial à função jurisdicional do Estado, \nincumbindo‑lhe a defesa da ordem jurídica, do \nregime democrático e dos interesses sociais e \nindividuais indisponíveis.", "D": "O Ministério Público é uma instituição permanente, \nnão essencial à função jurisdicional do Estado, \nincumbindo‑lhe a defesa da ordem jurídica, do \nregime democrático e dos interesses sociais e \nindividuais indisponíveis.", "E": "O Ministério Público é uma instituição permanente, \nessencial à função jurisdicional do Estado, \nincumbindo‑lhe, exclusivamente, a defesa do interesse \npúblico primário."}, "g": "C", "j": "Art. 127 CF/88: MP é instituição permanente, essencial à função jurisdicional, incumbido da defesa da ordem jurídica, regime democrático e interesses sociais e individuais indisponíveis."}, {"id": "2287477", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Princípios Gerais da Atividade Econômica"], "ano": "2023", "org": "CREFITO", "t": "", "e": "Considerando a Constituição Federal de 1988, assinale a \nalternativa correta, com relação aos princípios gerais da \natividade econômica.", "alt": {"A": "É assegurado a todos o livre exercício de qualquer \natividade econômica, independentemente de \nautorização de órgãos públicos, sendo vedado à lei \ndispor em sentido contrário.", "B": "Como agente normativo e regulador da atividade \neconômica, o Estado não poderá exercer as funções \nde fiscalização, incentivo e planejamento.", "C": "Incumbe ao poder público, conforme liberalidade da \nautoridade competente, diretamente ou sob regime \nde concessão ou permissão, sendo dispensável a \nlicitação, a prestação de serviços públicos.", "D": "As jazidas, em lavra ou não, e os demais recursos \nminerais e os potenciais de energia hidráulica \nconstituem propriedade distinta da do solo, para \nefeito de exploração ou aproveitamento, e pertencem \naos municípios, garantida ao concessionário a \npropriedade do produto da lavra.", "E": "O atendimento de requisição de documento \nou informação de natureza comercial, feita por \nautoridade administrativa ou judiciária estrangeira à \npessoa física ou jurídica residente ou domiciliada no \nPaís, dependerá de autorização do Poder competente."}, "g": "E", "j": "Art. 181 CF/88: o atendimento de requisição estrangeira de documento/informação comercial dirigida a pessoa no Brasil depende de autorização do Poder competente."}, {"id": "2287476", "d": "direito_constitucional", "a": ["Defesa do Estado e das Instituições Democráticas"], "ano": "2023", "org": "CREFITO", "t": "", "e": "Com base na Constituição Federal de 1988, assinale a \nalternativa correta, acerca da defesa do Estado e das \ninstituições democráticas.", "alt": {"A": "O presidente da República pode, ouvidos o Conselho \nda República e o Conselho de Defesa Nacional, decretar \nestado de defesa para preservar ou, prontamente, \nrestabelecer, em locais restritos e determinados, a \nordem pública ou a paz social ameaçadas por grave e \niminente instabilidade institucional ou atingidas por \ncalamidades de grandes proporções na natureza.", "B": "O decreto que instituir o estado de defesa terá, \nobrigatoriamente, tempo indeterminado, especificará \nas áreas a serem abrangidas e indicará as medidas \ncoercitivas a vigorarem.", "C": "O tempo de duração do estado de defesa não será \nsuperior a noventa dias, podendo ser prorrogado uma \nvez, por igual período, se persistirem as razões que \njustificaram sua decretação.", "D": "Decretado o estado de defesa ou sua prorrogação, \no presidente da República, dentro de vinte e \nquatro horas, submeterá o ato com a respectiva \njustificação ao Congresso Nacional, que decidirá por \nmaioria simples.", "E": "O Congresso Nacional apreciará o decreto de \nestado de defesa dentro de cinco dias contados de \nseu recebimento."}, "g": "A", "j": "Art. 136 CF/88: o Presidente decreta estado de defesa, ouvidos Conselho da República e CDN, para restabelecer ordem pública/paz social em locais restritos e determinados."}, {"id": "2249598", "d": "direito_constitucional", "a": ["Poder Legislativo", "Comissões Parlamentares e Comissões Parlamentares de Inquérito (CPIs)"], "ano": "2023", "org": "FSNH", "t": "", "e": "Atualmente, no Brasil, o Poder Legislativo dispõe de\ninstrumentos de investigação acerca de fatos determinados,\nalguns dos quais geraram, inclusive, o afastamento do poder\nde presidentes da República. Esse instrumento de atuação do\nparlamento denomina-se", "alt": {"A": "Corregedoria-Geral da União (CGU).", "B": "Comissão Parlamentar de Inquérito (CPI).", "C": "Supremo Tribunal Federal (STF).", "D": "Superior Tribunal de Justiça (STJ).", "E": "Secretaria da Receita Federal (SRF)."}, "g": "B", "j": "Art. 58, §3º CF/88: CPIs têm poderes investigatórios próprios das autoridades judiciais; são instrumento do Legislativo para investigação de fatos determinados."}, {"id": "2200002", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Arguição de Descumprimento de Preceito Fundamental - ADPF"], "ano": "2023", "org": "CRM", "t": "", "e": "Quanto à arguição de descumprimento de preceito\nfundamental, assinale a alternativa correta.", "alt": {"A": "Como típico instrumento do modelo difuso de controle\nde constitucionalidade, a arguição de descumprimento\nde preceito fundamental tanto pode dar ensejo à\nimpugnação ou ao questionamento direto de lei ou de\nato normativo federal, estadual ou municipal quanto\npode acarretar uma provocação a partir de situações\nconcretas, que levem à impugnação de lei ou de\nato normativo.", "B": "Qualquer cidadão tem legitimidade para a\npropositura de arguição de descumprimento de\npreceito fundamental.", "C": "As confederações sindicais, as entidades de classe de\nâmbito nacional e os partidos políticos possuem\ncapacidade postulatória especial na arguição de\ndescumprimento de preceito fundamental.", "D": "Diferentemente do que se verifica no âmbito do\ncontrole abstrato de normas, a arguição de\ndescumprimento de preceito fundamental poderá ser\nproposta contra ato normativo já revogado, tendo em\nvista o interesse jurídico da solução quanto à\nlegitimidade de sua aplicação no passado.", "E": "Por ser processo de caráter subjetivo, a arguição de\ndescumprimento de preceito fundamental não admite\na intervenção de amicus curiae."}, "g": "D", "j": "Jurisprudência STF (ADPF 33, 54): a ADPF pode ser proposta contra ato normativo já revogado quando subsistir interesse jurídico na solução quanto a sua aplicação no passado."}, {"id": "2200001", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Declaratória de Constitucionalidade - ADC"], "ano": "2023", "org": "CRM", "t": "", "e": "No que se refere à ação declaratória de constitucionalidade,\nassinale a alternativa correta.", "alt": {"A": "Somente o presidente da República possui legitimidade\npara propor ação declaratória de constitucionalidade.", "B": "Não se afigura admissível a propositura de ação\ndeclaratória de constitucionalidade se não houver\ncontrovérsia ou dúvida relevante quanto à legitimidade\nda norma.", "C": "O objeto da ação declaratória de constitucionalidade\ncorresponde ao do recurso extraordinário, havendo\nfungibilidade entre as medidas.", "D": "As regras destinadas à disciplina da ação direta de\ninconstitucionalidade estão previstas no texto\nconstitucional, sendo vedado ao Regimento Interno do\nSupremo Tribunal Federal (STF) dispor sobre a matéria.", "E": "A ação declaratória de constitucionalidade deve ser\nproposta no prazo de um ano, contado da publicação\ndo ato normativo questionado."}, "g": "B", "j": "Lei 9.868/99 art. 14, III: a petição inicial da ADC deve indicar a existência de controvérsia judicial relevante. Sem dúvida quanto à constitucionalidade, a ADC é inadmissível."}, {"id": "2200000", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2023", "org": "CRM", "t": "", "e": "A respeito da ação direta de inconstitucionalidade, assinale a\nalternativa correta.", "alt": {"A": "A reduzida lista de legitimados presentes no texto\nconstitucional fortalece a impressão de que o\nconstituinte pretendeu enfraquecer o controle\nabstrato de normas no ordenamento jurídico\nbrasileiro, como peculiar instrumento de correção do\nsistema geral incidente.", "B": "Exige-se que o objeto da ação de inconstitucionalidade\nguarde relação de pertinência com a atividade de\nrepresentação da confederação sindical ou da entidade\nde classe de âmbito nacional que a ajuizar.", "C": "É vedado ao governador firmar a petição inicial, isolada\nou juntamente, com o procurador-geral do estado ou\ncom outro advogado.", "D": "Podem ser impugnadas, por ação direta de\ninconstitucionalidade, as portarias expedidas por\nautarquias federais.", "E": "É inadmissível a propositura de ação direta de\ninconstitucionalidade contra atos de efeito concreto."}, "g": "E", "j": "Jurisprudência consolidada do STF: não cabe ADI contra atos de efeito concreto, somente contra atos normativos primários, gerais e abstratos."}, {"id": "2199999", "d": "direito_constitucional", "a": ["Classificação das Constituições", "Teoria da Constituição"], "ano": "2023", "org": "CRM", "t": "", "e": "Acerca da classificação das constituições, assinale a\nalternativa correta.", "alt": {"A": "As constituições escritas dão-se a conhecimento em\num documento único, que sistematiza o direito\nconstitucional da comunidade política.", "B": "A rigidez ou flexibilidade da constituição é apurada de\nacordo com a quantidade de vezes que o documento\nfoi ou pode ser alterado.", "C": "As constituições programáticas tendem a concentrar\nsua atenção normativa nos aspectos de estrutura do\npoder, cercando as atividades políticas das condições\nnecessárias para seu correto desempenho.", "D": "Conforme sua origem, as constituições distinguem-se\nem históricas e políticas.", "E": "As constituições semânticas são as que logram ser\nlealmente cumpridas por todos os interessados,\nlimitando, efetivamente, o poder."}, "g": "A", "j": "Constituições escritas (codificadas) são apresentadas em um documento único que sistematiza o direito constitucional. As esparsas/legais seriam em múltiplos diplomas."}, {"id": "2199998", "d": "direito_constitucional", "a": ["Classificação das Constituições", "Teoria da Constituição"], "ano": "2023", "org": "CRM", "t": "", "e": "Consiste em um documento escrito e solene que positiva as\nnormas jurídicas superiores da comunidade do Estado,\nelaboradas por um processo constituinte específico. Trata-se\ndo conceito de constituição em sentido", "alt": {"A": "material.", "B": "objetivo.", "C": "formal.", "D": "subjetivo.", "E": "amplo."}, "g": "C", "j": "Constituição em sentido formal: documento escrito e solene contendo normas jurídicas superiores elaboradas por processo constituinte específico (Kelsen, Canotilho)."}, {"id": "2081381", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Marcos nasceu na Argentina, durante viagem que \nos pais brasileiros faziam a serviço do Brasil.\nCom base nesse caso hipotético e na Constituição Federal de \n1998, Marcos", "alt": {"A": "é brasileiro nato.", "B": "é brasileiro naturalizado.", "C": "será brasileiro naturalizado após um ano de residência ininterrupta no Brasil.", "D": "será brasileiro nato após um ano de residência ininterrupta no Brasil.", "E": "é argentino, sem qualquer possibilidade de naturalizar-se brasileiro."}, "g": "A", "j": "Art. 12, I, 'b' CF/88: são natos os nascidos no estrangeiro de pai/mãe brasileiros, desde que qualquer deles esteja a serviço da República Federativa do Brasil."}, {"id": "2081380", "d": "direito_constitucional", "a": ["Poder Judiciário"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A respeito do Poder Judiciário, assinale a alternativa correta.", "alt": {"A": "Os juízes gozam das garantias constitucionais de vitaliciedade e inamovibilidade, adquiridas após três anos de exercício.", "B": "Segundo o texto constitucional, apenas os ministros do Supremo Tribunal Federal gozam de vitaliciedade.", "C": "Conforme a Constituição, aos juízes é vedado dedicar-se à atividade político-partidária.", "D": "Os juízes podem exercer qualquer outro cargo ou função pública remunerada, desde que haja disponibilidade e compatibilidade de horários.", "E": "Os tribunais e juízes militares, embora exerçam função jurisdicional, não são órgãos do Poder Judiciário."}, "g": "C", "j": "Art. 95, §único, III CF/88: é vedado aos juízes dedicar-se à atividade político-partidária."}, {"id": "2081379", "d": "direito_constitucional", "a": ["Supremo Tribunal Federal", "Organização do Poder Judiciário"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Segundo a Constituição Federal de 1988, a competência para \nprocessar e julgar, originariamente, o presidente da \nRepública nas infrações penais comuns é do", "alt": {"A": "Senado Federal.", "B": "Superior Tribunal de Justiça.", "C": "Congresso Nacional.", "D": "Supremo Tribunal Federal.", "E": "Conselho Nacional de Justiça."}, "g": "D", "j": "Art. 102, I, 'b' CF/88: compete ao STF processar e julgar originariamente o Presidente da República nas infrações penais comuns."}, {"id": "2081377", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Com relação aos direitos políticos, assinale a alternativa \ncorreta.", "alt": {"A": "Entre as condições de elegibilidade impostas pelo texto constitucional, está a filiação partidária.", "B": "Para ocupar o cargo de presidente da República, exige-se nacionalidade brasileira e idade mínima de 21 anos.", "C": "O voto será sempre facultativo para o estrangeiro e para os maiores de sessenta anos de idade.", "D": "O estrangeiro pode ocupar os cargos de vereador e de deputado estadual, desde que comprove domicílio no Brasil e idade mínima de dezoito anos.", "E": "Um prefeito pode concorrer aos cargos de presidente da República e governador de estado sem renunciar a seu mandato."}, "g": "A", "j": "Art. 14, §3º, V CF/88: filiação partidária é condição de elegibilidade."}, {"id": "2081376", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Acerca dos direitos e das garantias fundamentais expressos \nno texto constitucional, assinale a alternativa correta.", "alt": {"A": "A casa é asilo inviolável do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo por determinação judicial, em qualquer horário do dia ou da noite.", "B": "Todos podem reunir-se pacificamente, com ou sem armas, em locais abertos ao público, desde que previamente autorizados pela autoridade competente.", "C": "O exercício do direito constitucional de reunião em locais públicos está condicionado ao agendamento e à prévia autorização da autoridade competente.", "D": "Segundo o texto constitucional, é livre a expressão da atividade intelectual, artística, científica e de comunicação, independentemente de censura ou licença.", "E": "O acesso ao domicílio, mesmo sem consentimento do morador, pode ocorrer, durante o dia, com simples autorização da autoridade policial."}, "g": "D", "j": "Art. 5º, IX CF/88: livre a expressão da atividade intelectual, artística, científica e de comunicação, independentemente de censura ou licença."}, {"id": "2076266", "d": "direito_constitucional", "a": ["Educação, Cultura e Desporto", "Ordem Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Internet: <http://comolidarcomalunosespecias.blogspot.com>.\nA Constituição Federal de 1988 estabelece o direito dos\nportadores de deficiência ao atendimento educacional\nespecializado, preferencialmente na rede regular de ensino.\nSendo assim, julgue os itens seguintes, considerando a charge\ne os princípios da educação inclusiva.\nI O acesso ao ensino é obrigatório e gratuito.\nII O Estado deve garantir a permanência física dos alunos\ncom deficiência nas escolas.\nIII Cabe ao professor tratar a todos igualmente, pois todos\n(com ou sem deficiência) têm direito à aprendizagem.\nIV Deve-se priorizar o caráter classificatório da avaliação\nescolar, por meio de provas e notas, sem deixar de\noferecer outras práticas avaliativas.\nA quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "C", "j": "I e II corretos (acesso obrigatório/gratuito; permanência garantida). III falso (princípio inclusivo exige tratamento diferenciado, não igual). IV falso (avaliação formativa, não classificatória). Total: 2 itens."}, {"id": "2069788", "d": "direito_constitucional", "a": ["Previdência Social", "Ordem Social", "Saúde", "Assistência Social"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "De acordo com a Constituição Federal de 1988, a seguridade\nsocial compreende", "alt": {"A": "um conjunto de ações de iniciativa exclusiva dos\nPoderes Públicos, destinadas a assegurar os direitos\nrelativos à saúde, à previdência e à assistência social,\ntendo como objetivo, entre outros, a universalidade da\ncobertura e do atendimento.", "B": "um conjunto integrado de ações de iniciativa dos\nPoderes Públicos e da sociedade, destinadas a\nassegurar os direitos relativos à saúde, à previdência e\nà assistência social, tendo como objetivo, entre outros,\na uniformidade e equivalência dos benefícios e serviços\nexclusivamente às populações urbanas.", "C": "um conjunto integrado de ações de iniciativa dos\nPoderes Públicos e da sociedade, destinadas a\nassegurar os direitos relativos à saúde, à previdência e\nà assistência social, tendo como objetivo, entre outros,\na irredutibilidade do valor dos benefícios.", "D": "um conjunto de ações de iniciativa exclusiva dos\nPoderes Públicos, destinadas a assegurar os direitos\nrelativos à saúde, à previdência e à assistência social,\ntendo como objetivo, entre outros, a equidade na\nforma de participação no custeio.", "E": "um conjunto de ações de iniciativa exclusiva dos\nPoderes Públicos, destinadas a assegurar os direitos\nrelativos à saúde, à previdência e à assistência social,\ntendo como objetivo, entre outros, a seletividade e a\ndistributividade na prestação dos benefícios e serviços."}, "g": "C", "j": "Art. 194 CF/88: seguridade social = ações dos Poderes Públicos E da sociedade. Entre os objetivos, irredutibilidade do valor dos benefícios (inciso IV)."}, {"id": "2069615", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Controle Preventivo: Comissões de Constituição e Justiça e Veto Jurídico", "Controle Repressivo do Poder Legislativo", "Controle Repressivo do Poder Judiciário: o Controle Difuso ou Aberto"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Quanto ao controle legislativo e judicial da Administração\nPública, julgue os itens que se seguem.\n      I O Poder Judiciário pode examinar os atos da\nAdministração Pública, vinculados ou discricionários,\nmas sempre sob o aspecto da legalidade.\n  II O controle judicial da Administração Pública pode\nocorrer por iniciativa do próprio Poder Judiciário ou\nmediante provocação dos administrados por meio de\nrecursos administrativos.\n  III A competência do Congresso Nacional para sustar os atos\nnormativos do Poder Executivo que exorbitem do poder\nregulamentar ou dos limites de delegação legislativa é\nexemplo de controle legislativo da Administração.\n      Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item III está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "D", "j": "I correto (controle judicial é de legalidade); III correto (art. 49, V — sustação de atos do Executivo); II falso (controle judicial não ocorre por iniciativa do próprio Judiciário nem por recursos administrativos)."}, {"id": "2069614", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Com relação aos direitos políticos, assinale a alternativa\ncorreta.", "alt": {"A": "São inelegíveis e inalistáveis os analfabetos e, durante\no período de serviço militar obrigatório, os conscritos.", "B": "O mandato eletivo poderá ser impugnado ante a\nJustiça Eleitoral no prazo de 120 dias, contados de sua\ndiplomação, instruída a ação com provas de abuso do\npoder econômico, corrupção ou fraude.", "C": "A lei que alterar o processo eleitoral entrará em vigor\num ano após sua publicação.", "D": "Entre as condições de elegibilidade impostas pelo texto\nconstitucional, estão a nacionalidade brasileira e a\nidade mínima de 21 anos para os cargos de deputado\nestadual e governador de estado.", "E": "A ação de impugnação de mandato tramitará em\nsegredo de justiça, respondendo o autor, na forma da\nlei, se temerária ou de manifesta má-fé."}, "g": "E", "j": "Art. 14, §11 CF/88: a ação de impugnação de mandato tramitará em segredo de justiça, respondendo o autor, na forma da lei, se temerária ou de manifesta má-fé."}, {"id": "2069613", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "Acerca da possibilidade de alteração do texto constitucional,\nassinale a alternativa incorreta.", "alt": {"A": "No direito brasileiro, a doutrina majoritária rejeita a\nexistência de limites materiais implícitos ao poder de\nreforma constitucional.", "B": "É plenamente possível a incidência do controle de\nconstitucionalidade, difuso ou concentrado, sobre\nemendas constitucionais.", "C": "Não haverá participação do presidente da República na\nfase constitutiva do processo legislativo de uma\nemenda constitucional, uma vez que o titular do poder\nconstituinte derivado reformador é o Poder Legislativo.", "D": "A matéria constante de proposta de emenda rejeitada\nou havida por prejudicada não poderá ser objeto de\nnova proposta na mesma sessão legislativa.", "E": "Não será objeto de deliberação a proposta de emenda\ntendente a abolir a forma federativa de Estado."}, "g": "A", "j": "A é incorreta: a doutrina majoritária ACEITA limites materiais implícitos ao poder de reforma constitucional (forma federativa, separação dos Poderes, etc., além dos expressos no art. 60 §4º)."}, {"id": "2069612", "d": "direito_constitucional", "a": ["Classificação das Constituições", "Teoria da Constituição"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "A respeito dos conceitos, dos elementos e das classificações\ndas constituições, julgue os itens seguintes.\n      I No sentido sociológico, segundo Ferdinand Lassalle, a\nconstituição deve ser entendida como uma decisão\npolítica fundamental, tomada pelo titular do poder\nconstituinte.\n  II Com relação ao modo de elaboração, a constituição\ndogmática se apresenta como produto da lenta e\ncontínua síntese da história e das tradições de um\ndeterminado povo.\n  III As disposições constitucionais transitórias são exemplos\nde elementos formais de aplicabilidade da constituição.\n  IV O legislador constituinte de 1988, ao prever a\npossibilidade de alteração das normas constitucionais\npor meio de um processo legislativo especial e mais\ndificultoso que o ordinário, definiu a Constituição da\nRepública Federativa do Brasil como rígida.\n      A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "C", "j": "III e IV corretos. I falso (Lassalle = soma dos fatores reais de poder; 'decisão política fundamental' é Schmitt). II falso (a contínua síntese da história é da constituição HISTÓRICA, não dogmática)."}, {"id": "2069610", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Habeas Corpus"], "ano": "2023", "org": "Prefeitura de Alto Paraíso de Goiás", "t": "", "e": "No que se refere à tutela constitucional das liberdades e ao\nhabeas corpus, assinale a alternativa correta.", "alt": {"A": "O habeas corpus é uma ação constitucional de caráter\npenal e de procedimento comum, sujeita ao\npagamento de custas e que visa a evitar ou cessar\nviolência ou ameaça na liberdade de locomoção, por\nilegalidade ou abuso de poder.", "B": "A legitimidade para ajuizamento do habeas corpus\nsomente se verifica quando a parte possui capacidade\nde estar em juízo.", "C": "O habeas corpus somente poderá ser impetrado contra\nato coator praticado por autoridade pública, não sendo\nadmitida sua impetração contra atos praticados por\nparticulares.", "D": "O habeas corpus poderá ser utilizado como meio\nprocessual adequado para cessar constrangimento\nilegal à liberdade de locomoção do acusado-preso,\ndecorrente de abusivo excesso de prazo para o\nencerramento da instrução processual penal.", "E": "As decisões de qualquer das Turmas do Supremo\nTribunal Federal são atacáveis por habeas corpus, o\nqual será julgado pelo Plenário."}, "g": "D", "j": "HC pode ser utilizado para cessar constrangimento ilegal por excesso de prazo na instrução processual penal (jurisprudência STF/STJ consolidada)."}, {"id": "2068731", "d": "direito_constitucional", "a": ["Ordem Social", "Saúde"], "ano": "2023", "org": "IIER", "t": "", "e": "A Constituição Federal de 1988 (CF), por meio de seus\nprincípios fundamentais, visa a construir uma sociedade livre,\njusta e solidária. No contexto da pandemia instaurada em\ndecorrência da covid-19 e considerando o descrito no artigo\n200 da CF, assinale a alternativa correta.", "alt": {"A": "O Sistema Único de Saúde (SUS) deve promover a\nharmonia entre as atividades dos três Poderes, com\nvistas à determinação das medidas coletivas de\nenfrentamento da pandemia de covid-19 e de seus\nimpactos.", "B": "Cabe ao SUS executar as ações de vigilância sanitária e\nepidemiológica, bem como as de saúde do trabalhador.", "C": "Cabe ao Poder Executivo promover a livre escolha dos\ncidadãos quanto à adesão às medidas de proteção\ncoletiva.", "D": "O Poder Legislativo deve estabelecer percentual de\nrecursos a ser repassado aos hospitais públicos e\nprivados.", "E": "É de responsabilidade da vigilância sanitária fiscalizar e\nemitir notas técnicas sobre as doenças potencialmente\ntransmissíveis."}, "g": "B", "j": "Art. 200, II CF/88: ao SUS compete executar as ações de vigilância sanitária e epidemiológica, bem como as de saúde do trabalhador."}, {"id": "2018106", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2022", "org": "Câmara de Goianésia", "t": "", "e": "O atributo dos direitos fundamentais que os amplia para\nnortear e limitar a elaboração de leis pelo Poder Legislativo e\no governo pela Administração é conhecido como eficácia", "alt": {"A": "horizontal.", "B": "limitada.", "C": "imediata.", "D": "transversal.", "E": "irradiante."}, "g": "E", "j": "Eficácia irradiante dos direitos fundamentais: amplia o alcance dos direitos fundamentais para nortear a atuação legislativa e administrativa (Sarlet, Mendes)."}, {"id": "2018104", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2022", "org": "Câmara de Goianésia", "t": "", "e": "Conforme a CF, em um município com setenta mil habitantes,\na respectiva câmara municipal será composta por, no\nmáximo,", "alt": {"A": "nove vereadores.", "B": "onze vereadores.", "C": "quinze vereadores.", "D": "vinte vereadores.", "E": "trinta vereadores."}, "g": "C", "j": "Art. 29, IV CF/88: municípios entre 30.001 e 80.000 habitantes têm no máximo 15 vereadores."}, {"id": "1996487", "d": "direito_constitucional", "a": ["Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo"], "ano": "2022", "org": "Prefeitura de Barreiras", "t": "", "e": "Com relação à organização dos poderes do Estado, assinale a\nalternativa correta.", "alt": {"A": "O presidente da República é a autoridade competente\npara sancionar ou vetar as emendas à CF.", "B": "O presidente da República, na vigência do mandato,\nnão pode ser responsabilizado por atos estranhos ao\nexercício de suas funções.", "C": "A competência do presidente para conceder indulto e\ncomutar penas é indelegável.", "D": "Os atos do presidente da República contra a probidade na\nAdministração configuram crime de responsabilidade,\ndevendo ser julgados pelo Supremo Tribunal Federal."}, "g": "B", "j": "Art. 86, §4º CF/88: o Presidente da República, na vigência do mandato, não pode ser responsabilizado por atos estranhos ao exercício de suas funções."}, {"id": "1996486", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2022", "org": "Prefeitura de Barreiras", "t": "", "e": "Com relação aos direitos políticos e às normas previstas na\nCF, assinale a alternativa correta.", "alt": {"A": "O alistamento eleitoral e o voto são facultativos para os\nanalfabetos e os maiores de 65 anos de idade.", "B": "Os estrangeiros podem alistar-se como eleitores, desde\nque comprovem quatro anos de residência fixa no\nBrasil.", "C": "Os analfabetos são inalistáveis.", "D": "A nacionalidade brasileira e a filiação partidária estão\nentre as condições de elegibilidade estabelecidas pelo\ntexto constitucional."}, "g": "D", "j": "Art. 14, §3º CF/88: nacionalidade brasileira (I) e filiação partidária (V) são condições de elegibilidade."}, {"id": "1996485", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2022", "org": "Prefeitura de Barreiras", "t": "", "e": "John, de nacionalidade americana, reside\nregularmente no Brasil há 18 anos ininterruptos.\nConsiderando essa situação hipotética, assinale alternativa\ncorreta, de acordo com a CF.", "alt": {"A": "Ao completar vinte anos residindo no Brasil, John\nadquirirá tacitamente a nacionalidade brasileira.", "B": "Caso não obtenha nacionalidade brasileira, John\npoderá ser extraditado se ficar comprovado o\nenvolvimento em crimes políticos e de opinião.", "C": "Caso obtenha nacionalidade brasileira, John poderá\nseguir carreira política no Brasil e ocupar os cargos de\npresidente e vice-presidente da República.", "D": "Mesmo sem nacionalidade brasileira, John será\nbeneficiário dos direitos e das garantias individuais\nprevistos na CF."}, "g": "D", "j": "Art. 5º caput CF/88: brasileiros e estrangeiros residentes no País são titulares dos direitos e garantias individuais."}, {"id": "1996483", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2022", "org": "Prefeitura de Barreiras", "t": "", "e": "Acerca dos direitos e deveres individuais e coletivos, previstos\nna Constituição Federal de 1988 (CF), assinale a alternativa\ncorreta.", "alt": {"A": "Todos podem reunir-se pacificamente em locais\nabertos ao público, desde que obtenham previamente\nautorização da autoridade competente.", "B": "Não viola o texto constitucional a ordem judicial que\ndetermina escuta telefônica do réu em processo civil\nde reparação de danos.", "C": "A CF veda o arbitramento de fiança para os crimes de\ntortura e tráfico ilícito de entorpecentes.", "D": "Segundo o texto constitucional, o preso não pode ter\nacesso à identificação dos responsáveis por sua prisão\nou por seu interrogatório policial."}, "g": "C", "j": "Art. 5º, XLIII CF/88: a tortura, o tráfico ilícito de entorpecentes e drogas afins, o terrorismo e os crimes hediondos são inafiançáveis."}, {"id": "1980813", "d": "direito_constitucional", "a": ["Poder Legislativo", "Funções Essenciais à Justiça", "Organização dos Poderes", "Princípio da Separação dos Poderes", "Funções Típicas e Atípicas", "Ministério Público"], "ano": "2022", "org": "PRODAM", "t": "", "e": "Com relação aos elementos do Estado e às suas funções,\nassinale a alternativa correta.", "alt": {"A": "Os poderes da União desempenham exclusivamente as\nfunções típicas expressas na Constituição Federal de\n1988 (CF).", "B": "O Ministério Público integra tacitamente o rol de\npoderes da União.", "C": "O julgamento do presidente da República pelo Senado\nFederal, no caso de crime de responsabilidade,\nconstitui função atípica do Poder Legislativo.", "D": "A harmonia e a independência dos poderes da União\nimpede, de forma absoluta, a interferência de um sobre\no outro, quando o ato for praticado no exercício de suas\nfunções típicas.", "E": "A edição de medidas provisórias pelo chefe do Poder\nExecutivo é corolário de sua função típica, uma vez que\ntem como fundamento o texto constitucional."}, "g": "C", "j": "Art. 52, I CF/88: o julgamento do Presidente por crime de responsabilidade pelo Senado é função atípica jurisdicional do Poder Legislativo."}, {"id": "1972188", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Segurança"], "ano": "2022", "org": "CRA", "t": "", "e": "Considerando o mandado de segurança, assinale a alternativa\ncorreta.", "alt": {"A": "Quando o direito ameaçado ou violado couber a várias\npessoas, qualquer uma delas poderá requerer o\nmandado de segurança.", "B": "Conceder-se-á mandado de segurança para proteger\ndireito ilíquido e certo, não amparado por habeas\ncorpus ou habeas data, sempre que, ilegalmente ou\ncom abuso de poder, qualquer pessoa física ou jurídica\nsofrer violação ou houver justo receio de sofrê-la por\nparte de autoridade, seja de que categoria for e sejam\nquais forem as funções que exerça.", "C": "É incabível a impetração de mandado de segurança\ncontra decisão judicial.", "D": "O direito de requerer mandado de segurança\nextinguir-se-á decorridos 180 dias, contados da ciência,\npelo interessado, do ato impugnado.", "E": "Das decisões em mandado de segurança proferidas em\núnica instância pelos tribunais cabe recurso ordinário,\nnos casos legalmente previstos, e recurso especial ou\nextraordinário, quando a ordem for denegada."}, "g": "A", "j": "Lei 12.016/2009 art. 1º, §3º: quando o direito ameaçado ou violado couber a várias pessoas, qualquer delas poderá requerer mandado de segurança."}, {"id": "1972177", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Advocacia"], "ano": "2022", "org": "CRA", "t": "", "e": "No que se refere às funções essenciais à justiça, assinale a\nalternativa correta.", "alt": {"A": "O Ministério Público é uma instituição temporária,\nessencial à função jurisdicional do Estado,\nincumbindo-lhe a defesa da ordem jurídica, do regime\ndemocrático e dos interesses sociais e individuais\nindisponíveis.", "B": "A Advocacia-Geral da União é a instituição que,\ndiretamente ou por meio de órgão vinculado,\nrepresenta a União, judicial e extrajudicialmente,\ncabendo-lhe, nos termos da lei complementar que\ndispuser sobre sua organização e funcionamento, as\natividades de consultoria e assessoramento jurídico do\nPoder Legislativo.", "C": "A Advocacia-Geral da União tem por chefe o\nadvogado-geral da União, de livre nomeação pelo\npresidente do Supremo Tribunal Federal, dentre\ncidadãos maiores de 35 anos de idade, de notável saber\njurídico e reputação ilibada.", "D": "O advogado é indispensável à administração da justiça,\nsendo inviolável por seus atos e suas manifestações no\nexercício da profissão, nos limites da lei.", "E": "A Defensoria Pública é uma instituição permanente,\nessencial à função jurisdicional do Estado,\nincumbindo-lhe a defesa da ordem jurídica, do regime\ndemocrático e dos interesses sociais e individuais\nindisponíveis."}, "g": "D", "j": "Art. 133 CF/88: o advogado é indispensável à administração da justiça, sendo inviolável por seus atos e manifestações no exercício da profissão, nos limites da lei."}, {"id": "1972176", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2022", "org": "CRA", "t": "", "e": "Com relação às suas características básicas, o poder\nconstituinte originário é", "alt": {"A": "inicial, limitado e incondicionado.", "B": "inicial, autônomo e incondicionado.", "C": "permanente, autônomo e condicionado.", "D": "inicial, autônomo e condicionado.", "E": "inicial, permanente e incondicionado."}, "g": "B", "j": "Poder constituinte originário: inicial, autônomo, incondicionado, ilimitado e permanente (doutrina clássica de Sieyès/Bonavides)."}, {"id": "1972175", "d": "direito_constitucional", "a": ["Princípios de Interpretação Constitucional", "Teoria da Constituição"], "ano": "2022", "org": "CRA", "t": "", "e": "O princípio segundo o qual não se deve considerar uma\nnorma da Constituição fora do sistema em que esta se integra\ndenomina-se princípio da", "alt": {"A": "força normativa da Constituição.", "B": "eficácia integradora.", "C": "correção funcional.", "D": "concordância prática.", "E": "unicidade da Constituição."}, "g": "E", "j": "Princípio da unidade da Constituição: a Constituição deve ser interpretada como um todo sistêmico, sem dissociar uma norma do sistema em que se insere."}, {"id": "1972174", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Métodos de Interpretação Constitucional"], "ano": "2022", "org": "CRA", "t": "", "e": "A respeito da interpretação das normas constitucionais,\nassinale a alternativa correta.", "alt": {"A": "A interpretação das normas constitucionais em nada\ndifere daquela típica dos demais ramos do direito.", "B": "A interpretação constitucional tende a não acarretar\nimpacto sobre o direito positivo do Estado.", "C": "Para que a norma constitucional possa atuar na solução\nde problemas concretos e seja aplicada, seu conteúdo\nsemântico deve ser averiguado, em coordenação com\no exame das singularidades da situação real que a\nnorma pretende reger.", "D": "Existindo lacunas do texto constitucional, o intérprete\ndeverá abster-se de interpretar a norma.", "E": "O método hermenêutico clássico preconiza que a\nConstituição seja interpretada com os mesmos\nrecursos interpretativos das demais leis, segundo as\nfórmulas desenvolvidas por Hans Kelson: a\ninterpretação sistemática; histórica; lógica; e\ngramatical."}, "g": "C", "j": "Para que a norma constitucional atue na solução de problemas concretos, seu conteúdo semântico deve ser averiguado em coordenação com a situação real (concretização — Müller, Hesse)."}, {"id": "1972173", "d": "direito_constitucional", "a": ["Classificação das Constituições", "Teoria da Constituição"], "ano": "2022", "org": "CRA", "t": "", "e": "Quanto às classificações das constituições, assinale a\nalternativa correta.", "alt": {"A": "As constituições não escritas são compostas por\ncostumes, pela jurisprudência e também por\ninstrumentos escritos, mas dispersos, inclusive no\ntempo.", "B": "A distinção entre normas formalmente constitucionais\ne materialmente constitucionais é apurada segundo o\ncritério do grau de formalidade do procedimento\nrequerido para a mudança da Lei Maior.", "C": "As constituições programáticas tendem a concentrar a\nsua atenção normativa nos aspectos de estrutura do\npoder, cercando as atividades políticas das condições\nnecessárias para o seu correto desempenho.", "D": "As constituições-garantia traçam metas, programas de\nação e objetivos para as atividades do Estado nos\ndomínios social, cultural e econômico.", "E": "Chama-se Constituição outorgada aquela em que\nocorre a participação popular, sendo, por isso, também\nchamada de Constituição democrática."}, "g": "A", "j": "Constituições não escritas (consuetudinárias) são compostas por costumes, jurisprudência e instrumentos escritos esparsos no tempo (ex.: Reino Unido)."}, {"id": "1969786", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2022", "org": "CRO", "t": "", "e": "Em relação à ação direta de inconstitucionalidade e à ação\ndeclaratória de constitucionalidade, assinale a alternativa\ncorreta.", "alt": {"A": "O procurador-geral da República defenderá o ato ou o\ntexto impugnado na ação de inconstitucionalidade.", "B": "O advogado-geral da União deverá ser previamente\nouvido nas ações de inconstitucionalidade por\nomissão.", "C": "Declarada a inconstitucionalidade por omissão, será\ndada ciência ao órgão administrativo para fazê-lo em\ntrinta dias.", "D": "As decisões de mérito proferidas pelo STF produzirão\nefeito vinculante restrito ao ente federado que editou\no ato normativo impugnado.", "E": "Compete à Câmara dos Deputados suspender a\nexecução de lei declarada inconstitucional por decisão\ndefinitiva do STF."}, "g": "C", "j": "Art. 103, §2º CF/88: declarada a inconstitucionalidade por omissão, será dada ciência ao Poder competente para adoção de providências necessárias e, em se tratando de órgão administrativo, no prazo de 30 dias."}, {"id": "1969785", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2022", "org": "CRO", "t": "", "e": "Os membros de um partido político que não possui\nrepresentação no Congresso Nacional desejam impugnar a\nconstitucionalidade de determinada lei federal.\n    Considerando-se essa situação hipotética e o disposto na CF,\né correto afirmar que podem propor ação direta\nde inconstitucionalidade perante o Supremo Tribunal\nFederal (STF) o(a)", "alt": {"A": "presidente da República e os prefeitos.", "B": "Confederação Sindical e a União de Associações Civis.", "C": "procurador-geral da República e o governador de\nEstado.", "D": "mesa do Congresso Nacional e a Assembleia\nLegislativa.", "E": "Conselho Federal da Ordem dos Advogados do\nBrasil (OAB) e o Conselho Seccional da OAB."}, "g": "C", "j": "Art. 103, V e VI CF/88: o PGR e os Governadores de Estado/DF são legitimados para propor ADI perante o STF (não há exigência de representação)."}, {"id": "1969783", "d": "direito_constitucional", "a": ["Previdência Social", "Ordem Social", "Saúde", "Assistência Social"], "ano": "2022", "org": "CRO", "t": "", "e": "À luz do disposto na CF sobre a ordem social, assinale a\nalternativa correta.", "alt": {"A": "Compete ao poder público organizar a seguridade\nsocial com base na seletividade da cobertura e do\natendimento.", "B": "É permitida a filiação ao regime geral de previdência\nsocial, na qualidade de segurado facultativo, de pessoa\nparticipante de regime próprio de previdência.", "C": "As instituições privadas poderão participar de forma\nsuplementar do Sistema Único de Saúde, desde que\nsejam entidades filantrópicas e sem fins lucrativos.", "D": "Nenhum benefício da seguridade social poderá ser\ncriado ou majorado sem a correspondente fonte de\ncusteio total.", "E": "A ordem social tem como base o bem-estar e visa ao\ntrabalho e à justiça social."}, "g": "D", "j": "Art. 195, §5º CF/88: nenhum benefício ou serviço da seguridade social poderá ser criado, majorado ou estendido sem a correspondente fonte de custeio total."}, {"id": "1969782", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade", "Direito à Privacidade", "Direito de Propriedade e Função Social da Propriedade"], "ano": "2022", "org": "CRO", "t": "", "e": "Com base na CF, assinale a alternativa correta.", "alt": {"A": "As associações podem ser compulsoriamente\ndissolvidas por decisão administrativa.", "B": "As entidades associativas têm legitimidade estatutária\npara representar judicialmente seus filiados.", "C": "É permitida a reunião em locais públicos,\nindependentemente de autorização, sem prévio aviso\nà autoridade.", "D": "Todo cidadão é inocente até que se prove o contrário\nno processo judicial ou administrativo.", "E": "São invioláveis a intimidade, a vida privada, a honra e a\nimagem das pessoas, sendo assegurada a indenização\nem caso de dano material ou moral."}, "g": "E", "j": "Art. 5º, X CF/88: são invioláveis a intimidade, a vida privada, a honra e a imagem das pessoas, assegurado o direito a indenização pelo dano material ou moral decorrente de sua violação."}, {"id": "1969781", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2022", "org": "CRO", "t": "", "e": "Quanto aos direitos dos trabalhadores urbanos e rurais, a\nConstituição Federal de 1988 (CF) permite", "alt": {"A": "diferença de exercício de funções por motivo de sexo.", "B": "diferença de critério de admissão por motivo de idade.", "C": "menor aprendiz a partir dos doze anos de idade.", "D": "trabalho noturno a menores de dezoito anos de idade\ne maiores de dezesseis anos de idade.", "E": "remuneração do trabalho noturno superior à do\ndiurno."}, "g": "E", "j": "Art. 7º, IX CF/88: remuneração do trabalho noturno superior à do diurno."}, {"id": "1943967", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Finanças Públicas – Orçamento"], "ano": "2022", "org": "CAU", "t": "", "e": "À luz das disposições da Constituição Federal de 1988 (CF)\nacerca da lei orçamentária anual, assinale a alternativa\ncorreta.", "alt": {"A": "A CF admite que a lei orçamentária anual contenha\ndispositivos estranhos à previsão da receita e à fixação\nda despesa, a exemplo de alterações no zoneamento\nurbano dos municípios, a fim de agilizar o processo\nlegislativo.", "B": "A lei orçamentária anual será única para cada ente da\nFederação, sendo subdividida em orçamento fiscal das\nestatais, orçamento dos investimentos públicos e\norçamento do regime geral de previdência social.", "C": "Na União, o prazo regulamentar para envio do projeto\nde lei orçamentária anual ao Congresso Nacional se\nencerra no dia 31 de agosto de cada exercício\nfinanceiro.", "D": "Por conter as despesas de todos os poderes, de todos\nos órgãos e de todas as entidades, a iniciativa de\nencaminhamento do projeto de lei será compartilhada\nentre o chefe do Poder Executivo, o chefe do Poder\nLegislativo e o chefe do Poder Judiciário.", "E": "Na lei orçamentária anual, o montante previsto com\nreceitas de operação de crédito poderá ser superior ao\nmontante previsto com despesas de capital, sendo\ndesnecessária a autorização legislativa para tanto."}, "g": "C", "j": "ADCT art. 35, §2º, III: na União, o PLOA deve ser encaminhado até 31 de agosto de cada exercício financeiro (4 meses antes do encerramento)."}, {"id": "1941182", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2022", "org": "CAU", "t": "", "e": "Em relação às espécies tributárias, assinale a alternativa\ncorreta.", "alt": {"A": "São cinco as espécies tributárias estabelecidas pela CF:\nimposto; taxa; contribuição de melhoria; empréstimo\ncompulsório; e contribuição especial.", "B": "As taxas são tributos que incidem necessariamente\nsobre revelações de riqueza do contribuinte.", "C": "Os impostos são tributos que têm como fato gerador o\nexercício regular do poder de polícia, ou a utilização,\nefetiva ou potencial, de serviço público específico e\ndivisível, prestado ao contribuinte ou posto à sua\ndisposição.", "D": "As contribuições de melhoria pressupõem apenas a\nrealização de obras públicas pelo Estado, dispensando\no enriquecimento do contribuinte.", "E": "O empréstimo compulsório é espécie tributária que\nexige a configuração de um fato gerador vinculado."}, "g": "A", "j": "Teoria pentapartida adotada pelo STF: impostos, taxas, contribuições de melhoria, empréstimos compulsórios e contribuições especiais (parafiscais/sociais)."}, {"id": "1941171", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado", "Formas de Estado - Estado Unitário, Confederação e Federação"], "ano": "2022", "org": "CAU", "t": "", "e": "No que se refere à organização político-administrativa do\nBrasil, assinale a alternativa correta.", "alt": {"A": "A CF adotou, como forma de Estado, o federalismo, que\né uma aliança ou união de estados, baseada em uma\nConstituição, de modo que os entes que ingressam na\nfederação mantêm sua soberania no momento do\ningresso, embora percam sua autonomia política.", "B": "O princípio da indissolubilidade no Estado federal\nbrasileiro foi consagrado nas constituições\nrepublicanas do País, desde 1891, e tem duas\nfinalidades básicas: a unidade nacional e a necessidade\ncentralizadora.", "C": "A União consiste em uma entidade federativa\nautônoma em relação aos estados-membros e\nmunicípios, constituindo uma pessoa jurídica de direito\npúblico interno, cabendo-lhe exercer as atribuições da\nsoberania do Estado brasileiro.", "D": "A União, por se confundir com o Estado federal, pode\nagir em nome de toda a Federação, quando se\nrelacionar internacionalmente com os demais países.", "E": "Os municípios reger-se-ão por constituições\nmunicipais, votadas em turno único e aprovadas por\ndois terços dos membros da Câmara Municipal, que as\noutorgará."}, "g": "C", "j": "A União é pessoa jurídica de direito público interno, autônoma em relação aos demais entes federativos, exercendo as atribuições da soberania do Estado brasileiro nas relações exteriores."}, {"id": "1941170", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2022", "org": "CAU", "t": "", "e": "Em relação ao direito de nacionalidade, assinale a alternativa\ncorreta.", "alt": {"A": "A nacionalidade secundária resulta do nascimento a\npartir do qual, mediante critérios sanguíneos,\nterritoriais ou mistos, ela será estabelecida.", "B": "A CF adota o critério do jure matrimonii.", "C": "Pelo critério do ius sanguinis, adotado como regra na\nCF, será nacional todo o descendente de nacionais,\nindependentemente do local de nascimento.", "D": "O brasileiro naturalizado é aquele que adquire a\nnacionalidade brasileira de forma secundária, ou seja,\npela ocorrência de um fato natural.", "E": "A naturalização é o único meio derivado de aquisição\nde nacionalidade, permitindo-se ao estrangeiro ou ao\nheimatlos assumir a nacionalidade do país em que se\nencontra, mediante a satisfação de requisitos\nconstitucionais e legais."}, "g": "E", "j": "A naturalização é o único meio derivado de aquisição de nacionalidade, permitindo a estrangeiro ou apátrida (heimatlos) assumir a nacionalidade brasileira mediante requisitos constitucionais e legais."}, {"id": "1941169", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2022", "org": "CAU", "t": "", "e": "Direitos sociais são direitos fundamentais do homem, de\nobservância obrigatória em um Estado Social de Direito,\ncaracterizando-se como verdadeiras liberdades", "alt": {"A": "positivas, tendo por finalidade a melhoria das\ncondições de vida dos hipossuficientes, visando à\nconcretização da igualdade social e sendo consagrados\ncomo fundamentos do Estado democrático.", "B": "negativas, tendo por finalidade a melhoria das\ncondições de vida dos hipossuficientes, visando à\nconcretização da igualdade social e sendo consagrados\ncomo fundamentos do Estado democrático.", "C": "positivas, tendo por finalidade a melhoria das\ncondições de vida dos hipossuficientes, visando à\nconcretização da paz mundial e sendo consagrados\ncomo fundamentos do Estado democrático.", "D": "negativas, tendo por finalidade a melhoria das\ncondições de vida dos hipossuficientes, visando à\nconcretização da igualdade social, mas não\nconstituindo fundamentos do Estado democrático.", "E": "positivas, tendo por finalidade a melhoria das\ncondições econômicas do Estado, visando à\nconcretização de políticas públicas de redistribuição de\nrenda."}, "g": "A", "j": "Direitos sociais são liberdades positivas (prestacionais) que exigem atuação do Estado para concretizar a igualdade social — fundamentos do Estado Democrático (Silva, Bonavides)."}, {"id": "1941168", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2022", "org": "CAU", "t": "", "e": "Quanto ao poder constituinte, assinale a alternativa correta.", "alt": {"A": "O poder constituinte derivado estabelece a\nconstituição de um novo Estado, organizando-o e\ncriando os poderes destinados a reger os interesses de\numa comunidade.", "B": "O poder constituinte originário caracteriza-se por ser\ninicial, ilimitado, autônomo e incondicionado.", "C": "A assembleia nacional constituinte é o\nestabelecimento da constituição por declaração\nunilateral do agente revolucionário, que autolimita seu\npoder.", "D": "A outorga nasce da deliberação da representação\npopular, devidamente convocada pelo agente\nrevolucionário, para estabelecer o texto organizatório\ne limitativo de poder.", "E": "O poder constituinte derivado reformador consiste na\npossibilidade que os estados-membros têm, em\nvirtude de sua autonomia político-administrativa, de se\nauto-organizarem por meio de suas respectivas\nconstituições estaduais, sempre respeitando as regras\nlimitativas estabelecidas pela Constituição Federal."}, "g": "B", "j": "Poder constituinte originário: inicial, ilimitado (juridicamente), autônomo e incondicionado."}, {"id": "1941167", "d": "direito_constitucional", "a": ["Classificação das Constituições", "Teoria da Constituição"], "ano": "2022", "org": "CAU", "t": "", "e": "Considerando-se as classificações das constituições, é correto\nafirmar que a Constituição Federal de 1988 (CF) classifica-se\ncomo", "alt": {"A": "formal, escrita, legal, dogmática, promulgada, rígida e\nsintética.", "B": "material, escrita, legal, dogmática, promulgada, rígida\ne analítica.", "C": "formal, escrita, legal, dogmática, promulgada, imutável\ne analítica.", "D": "formal, escrita, legal, dogmática, promulgada, rígida e\nanalítica.", "E": "formal, escrita, legal, dogmática, outorgada, rígida e\nanalítica."}, "g": "D", "j": "CF/88 é formal, escrita, legal (não codificada), dogmática, promulgada (democrática), rígida e analítica/prolixa."}, {"id": "1941158", "d": "direito_constitucional", "a": ["Poder Legislativo", "Congresso Nacional", "Câmara dos Deputados"], "ano": "2022", "org": "CAU", "t": "", "e": "Relativamente à organização dos poderes disciplinada na CF,\nassinale a alternativa correta.", "alt": {"A": "Autorizar o presidente e o vice-presidente da República\na se ausentarem do País, quando a ausência exceder a\nquinze dias, é de competência exclusiva da Câmara de\nDeputados.", "B": "Compete privativamente ao Senado Federal autorizar,\npor dois terços de seus membros, a instauração de\nprocesso contra o presidente da República.", "C": "Os deputados e senadores não serão obrigados a\ntestemunhar sobre informações recebidas ou\nprestadas em razão do exercício do mandato, nem\nsobre as pessoas que lhes confiaram ou deles\nreceberam informações.", "D": "Os deputados e senadores não poderão, desde a\nexpedição do diploma, ser titulares de mais de um\ncargo ou mandato público eletivo.", "E": "A Mesa do Congresso Nacional será presidida pelo\npresidente da Câmara dos Deputados, e os demais\ncargos serão exercidos pelos ocupantes de cargos\nequivalentes no Senado Federal."}, "g": "C", "j": "Art. 53, §6º CF/88: deputados e senadores não serão obrigados a testemunhar sobre informações recebidas/prestadas em razão do mandato, nem sobre as pessoas que lhes confiaram informações."}, {"id": "1939763", "d": "direito_constitucional", "a": ["Disposições Gerais no Poder Judiciário", "Poder Judiciário"], "ano": "2022", "org": "CAU", "t": "", "e": "A respeito dos poderes e elementos do Estado, assinale a\nalternativa correta.", "alt": {"A": "Legislar constitui função atípica do Poder Legislativo.", "B": "O território não constitui um elemento essencial do\nEstado.", "C": "O Poder Legislativo e o Poder Judiciário são poderes da\nUnião que se sobrepõem ao Poder Executivo.", "D": "A independência dos poderes da União é absoluta,\nmotivo pelo qual o Poder Legislativo não pode sustar\nos atos do Poder Executivo, ainda que estes exorbitem\ndo poder regulamentar.", "E": "A edição de normas regimentais constitui exercício da\nfunção atípica do Poder Judiciário, destinada ao seu\nfuncionamento."}, "g": "E", "j": "A edição de normas regimentais (atividade legislativa/normativa) constitui função atípica do Poder Judiciário (sua função típica é jurisdicional)."}, {"id": "1939754", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2022", "org": "CAU", "t": "", "e": "Relativamente à nacionalidade e aos direitos políticos\nestabelecidos na CF, assinale a alternativa correta.", "alt": {"A": "Os nascidos no estrangeiro, de pai brasileiro ou mãe\nbrasileira, desde que qualquer deles esteja a serviço da\nRepública Federativa do Brasil, são brasileiros\nnaturalizados.", "B": "A lei poderá estabelecer distinção entre brasileiros\nnatos e naturalizados.", "C": "Será declarada a perda da nacionalidade do brasileiro\nque, em qualquer caso, adquirir outra nacionalidade.", "D": "O alistamento eleitoral e o voto são facultativos para os\nmaiores de setenta anos de idade.", "E": "A idade mínima para concorrer ao cargo de senador é\ntrinta anos."}, "g": "D", "j": "Art. 14, §1º, II, 'b' CF/88: alistamento e voto facultativos para maiores de 70 anos."}, {"id": "1939753", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2022", "org": "CAU", "t": "", "e": "No que se refere aos direitos sociais fixados na CF, assinale a\nalternativa correta.", "alt": {"A": "A assistência gratuita aos filhos e dependentes, desde\no nascimento até cinco anos de idade, em creches e\npré-escolas constitui um direito dos trabalhadores\nurbanos e dos trabalhadores rurais.", "B": "O seguro-desemprego, em caso de desemprego\ninvoluntário, constitui direito apenas dos\ntrabalhadores urbanos.", "C": "A irredutibilidade do salário constitui um direito\nabsoluto dos trabalhadores urbanos, não podendo ser\nreduzido, mesmo na hipótese de convenção ou acordo\ncoletivo.", "D": "Será assegurada aos trabalhadores urbanos e rurais a\nremuneração do serviço extraordinário superior, no\nmínimo, em 75% à do normal.", "E": "Não haverá igualdade de direitos entre o trabalhador\ncom vínculo empregatício permanente e o trabalhador\navulso."}, "g": "A", "j": "Art. 7º, XXV CF/88: assistência gratuita aos filhos e dependentes desde o nascimento até 5 anos de idade em creches e pré-escolas — direito dos trabalhadores urbanos e rurais."}, {"id": "1939752", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade"], "ano": "2022", "org": "CAU", "t": "", "e": "Quanto aos direitos e aos deveres individuais e coletivos\nprevistos na Constituição Federal de 1988 (CF), assinale a\nalternativa correta.", "alt": {"A": "O direito de resposta impede a possibilidade de\nindenização por dano material, moral ou à imagem.", "B": "É vedada a liberdade de consciência e de crença,\npodendo a lei conceder autorização especial para o seu\nexercício.", "C": "Ninguém será privado de direitos por motivo de crença\nreligiosa ou de convicção filosófica ou política, salvo se\nas invocar para eximir-se de obrigação legal a todos\nimposta e recusar-se a cumprir prestação alternativa,\nfixada em lei.", "D": "A casa é asilo inviolável do indivíduo, ninguém nela\npodendo penetrar sem consentimento do morador,\nsalvo por determinação judicial, durante qualquer hora\ndo dia ou da noite.", "E": "As associações poderão ser compulsoriamente\ndissolvidas ou ter suas atividades suspensas por\ndeterminação do presidente da República."}, "g": "C", "j": "Art. 5º, VIII CF/88: ninguém será privado de direitos por motivo de crença religiosa/convicção filosófica ou política, salvo se as invocar para se eximir de obrigação legal e recusar prestação alternativa."}, {"id": "1897844", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Constitucionalismo"], "ano": "2022", "org": "CRMV", "t": "", "e": "Quanto ao chamado “neoconstitucionalismo”, assinale a\nalternativa correta.", "alt": {"A": "Possui como premissa a ideia de Estado Constitucional\nde Direito, em que a Constituição passa a ter papel\ncentral, colorindo com seu espírito a interpretação de\ntodas as demais normas.", "B": "A Constituição se despe de opções políticas e passa a\ncongregar, essencialmente, questões jurídicas\nrelevantes.", "C": "Rejeitam-se as condições mínimas de dignidade e de\ndireito e somente se consideram como resguardados\nos direitos que alcancem máxima efetividade.", "D": "Há uma guinada teórica que sai do positivismo rumo a\numa revisita ao jusnaturalismo.", "E": "É pregado um maior protagonismo e uma maior\nliberdade do Legislativo em relação ao Executivo e à\njurisdição constitucional."}, "g": "A", "j": "Neoconstitucionalismo: Estado Constitucional de Direito com a Constituição no centro do ordenamento, irradiando seus princípios para todas as normas (Barroso, Sarmento)."}, {"id": "1897843", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2022", "org": "CRMV", "t": "", "e": "Em um dado caso, o Supremo Tribunal Federal (STF),\nem meio a julgamento de ação direta de\ninconstitucionalidade, julgou procedente o pedido com\nrelação ao dispositivo impugnado “x”. Acontece que, por\nocasião dos debates, os ministros notaram que o dispositivo\n“y”, embora não impugnado pela petição inicial, seria\ninstrumental do artigo “x”, guardando com ele relação\nnormativa próxima.\nCom base nessa situação hipotética, assinale a alternativa\ncorreta, de modo a solucionar o impasse.", "alt": {"A": "O STF deverá aplicar a teoria da transcendência dos\nefeitos dos motivos determinantes para, em processo\nfuturo, declarar também a inconstitucionalidade do\ndispositivo “y”.", "B": "O STF adotará a técnica da inconstitucionalidade por\natração e declarará também a inconstitucionalidade do\ndispositivo “y”, mesmo ele não tendo sido objeto de\nimpugnação.", "C": "O STF adotará a técnica da inconstitucionalidade\nprogressiva, sujeitando à nulidade o dispositivo “y”\ncom o passar do tempo e conforme for sendo\nassimilada a nulidade do dispositivo “x”.", "D": "O STF adotará a técnica da inconstitucionalidade\ncircunstancial, no sentido de que o dispositivo “y”\nsomente será inconstitucional naquilo que não puder\nser lido sem conexão com o artigo “x”.", "E": "O STF limitará sua decisão ao artigo “x”, em prestígio\nao princípio da congruência, somente discutindo sobre\na validade do dispositivo “y” em processo em que a\nreferida norma venha a ser impugnada."}, "g": "B", "j": "Técnica da inconstitucionalidade por arrastamento (ou por atração): o STF declara inconstitucional dispositivo não impugnado, mas que guarde relação normativa estreita com o impugnado."}, {"id": "1876373", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito de Propriedade e Função Social da Propriedade"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Em relação aos direitos e às garantias fundamentais, assinale\na alternativa correta.", "alt": {"A": "A expressão da atividade intelectual, artística e\ncientífica depende de autorização.", "B": "A imagem das pessoas não está resguardada pela\ncláusula de inviolabilidade.", "C": "A reunião pacífica, em locais abertos ao público,\ndepende de autorização.", "D": "Os autores de inventos industriais têm privilégio\nvitalício para sua utilização.", "E": "Os autores têm direito exclusivo de utilização de suas\nobras, transmissível aos herdeiros."}, "g": "E", "j": "Art. 5º, XXVII CF/88: aos autores pertence o direito exclusivo de utilização, publicação ou reprodução de suas obras, transmissível aos herdeiros pelo tempo que a lei fixar."}, {"id": "1875954", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Disposições Gerais na Administração Pública"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Com base na Constituição Federal de 1988, é correto afirmar,\nem relação à Administração Pública, que", "alt": {"A": "a filiação sindical é obrigatória para o servidor público\ncivil e militar.", "B": "é expressamente vedado aos servidores públicos em\ngeral exercer o direito de greve.", "C": "o percentual mínimo de portadores de deficiência\nexercendo cargos em comissão é previsto em decreto.", "D": "a contratação por tempo determinado é\nperemptoriamente vedada.", "E": "a remuneração dos servidores públicos somente pode\nser fixada ou alterada por lei específica."}, "g": "E", "j": "Art. 37, X CF/88: a remuneração dos servidores públicos somente poderá ser fixada ou alterada por lei específica, observada a iniciativa privativa em cada caso."}, {"id": "1875953", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Constitucionais-Penais e Garantias Constitucionais do Processo", "Direitos Individuais", "Direito de Propriedade e Função Social da Propriedade", "Teoria dos Direitos Fundamentais", "Mandado de Segurança", "Habeas Corpus"], "ano": "2021", "org": "Prefeitura de Canaã dos Carajás", "t": "", "e": "Em relação aos direitos e às garantias fundamentais, assinale\na alternativa correta.", "alt": {"A": "O direito de propriedade impede de forma absoluta a\nprivação dos bens do indivíduo.", "B": "Ninguém poderá ser considerado como culpado até\nque se prove o contrário.", "C": "Os direitos e as garantias fundamentais previstos na\nConstituição são um rol taxativo.", "D": "As normas definidoras dos direitos e das garantias\nfundamentais têm aplicação imediata.", "E": "O habeas corpus e o mandado de segurança são ações\nconstitucionais gratuitas."}, "g": "D", "j": "Art. 5º, §1º CF/88: as normas definidoras dos direitos e garantias fundamentais têm aplicação imediata."}, {"id": "1860605", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Servidores Públicos"], "ano": "2021", "org": "CRBio", "t": "", "e": "Acerca das normas de conduta dos servidores públicos civis\nda União, das autarquias e das fundações públicas, assinale a\nalternativa correta.", "alt": {"A": "Servidor público é a pessoa legalmente investida em\ncargo ou em emprego público na administração direta,\nnas autarquias ou nas fundações públicas.", "B": "Considera-se como servidor público apenas a pessoa\nlegalmente investida em cargo público na\nadministração direta.", "C": "Aquele que está legalmente investido em emprego\npúblico nas fundações públicas não é servidor público.", "D": "Servidores públicos são somente aqueles que estão\ninvestidos em cargos públicos na administração\nindireta.", "E": "Aquele que está legalmente investido em cargo público\nnas autarquias não é servidor público."}, "g": "A", "j": "Lei 8.112/90 art. 2º: servidor público é a pessoa legalmente investida em cargo público. Em sentido amplo, abrange cargo OU emprego público na adm. direta, autarquias e fundações públicas."}, {"id": "1860604", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2021", "org": "CRBio", "t": "", "e": "A respeito dos direitos e das garantias fundamentais, assinale\na alternativa correta.", "alt": {"A": "Os direitos fundamentais de primeira geração\nenglobam o direito a um meio ambiente equilibrado.", "B": "Os direitos fundamentais de segunda geração são os\ndireitos sociais, econômicos e culturais.", "C": "Os direitos fundamentais de terceira geração estão\nrelacionados às liberdades públicas.", "D": "A Constituição Federal de 1988 não estabelece direitos\ne garantias fundamentais.", "E": "A classificação dos direitos e das garantias\nfundamentais em gerações baseia-se em critérios\npuramente culturais."}, "g": "B", "j": "Classificação clássica (Bonavides/Vasak): 1ª geração = direitos civis e políticos (liberdades públicas); 2ª geração = sociais, econômicos e culturais; 3ª geração = direitos coletivos/difusos (meio ambiente, paz)."}, {"id": "1837104", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Controle Repressivo do Poder Judiciário: o Controle Difuso ou Aberto"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Assinale a alternativa correta a respeito do controle difuso de\nconstitucionalidade no âmbito dos tribunais.", "alt": {"A": "O incidente de arguição de inconstitucionalidade\ndepende de provocação das partes ou do Ministério\nPúblico, não admitindo suscitação judicial de ofício.", "B": "Suscitado incidente de arguição de\ninconstitucionalidade, cabe ao órgão fracionário a\npronta remessa ao órgão especial, a quem competirá o\njuízo de admissibilidade e, eventualmente, de mérito.", "C": "O incidente de arguição de inconstitucionalidade deve\nser suscitado até o início do julgamento, sob pena de\npreclusão temporal.", "D": "Não viola a cláusula de reserva de plenário a decisão\nturmária que aplicar dispositivo por julgá-lo\nconstitucional, a despeito da arguição incidental de sua\ninconstitucionalidade por uma das partes.", "E": "Admitido o incidente e julgado o seu mérito, o órgão\nespecial decidirá o caso concreto."}, "g": "D", "j": "A cláusula de reserva de plenário (art. 97 CF/88) só se aplica quando se afasta a aplicação da norma por inconstitucionalidade. Decisão turmária que aplica o dispositivo por considerá-lo constitucional não viola a reserva."}, {"id": "1837101", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Constitucionalismo"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "No que se refere à tese da constitucionalização simbólica,\nassinale a alternativa correta.", "alt": {"A": "Trata de evidenciar a lacuna por vezes existente entre\no que é normatizado constitucionalmente e o deficit de\nsua concretização real.", "B": "Consiste em divisar a Constituição como símbolo e\nápice de uma conquista democrática.", "C": "Expõe a Constituição como alegoria a na verdade\nchancela os desejos da elite dominante de seu tempo.", "D": "Busca situar a Constituição como uma carta dirigente a\nrespeito dos objetivos ambicionados por uma nação.", "E": "Aponta a Constituição como o resultado das tensões\nsociais que buscam um denominador normativo\ncomum."}, "g": "A", "j": "Marcelo Neves: a constitucionalização simbólica evidencia o descompasso entre o texto constitucional e seu efetivo cumprimento na realidade social (déficit de concretização)."}, {"id": "1837100", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Constitucionalismo", "Teoria dos Direitos Fundamentais"], "ano": "2021", "org": "CRP 4ª Região (MG)", "t": "", "e": "Acerca do fenômeno conhecido como “constitucionalização\ndo direito privado”, assinale a alternativa correta.", "alt": {"A": "Trata-se de uma falácia teórica, restando admitida\nainda, atualmente, uma cisão rígida entre os ramos dos\ndireitos público e privado.", "B": "Favoreceu uma releitura que colocou os distintos\ndireitos privatísticos como microssistemas submetidos\nà dignidade da pessoa humana e à Constituição.", "C": "Contaminou positivamente o direito civil para\nfortalecer sua codificação como uma unidade\nsistemática de normatividade.", "D": "Reforçou a patrimonialidade e o direito de propriedade\ncomo elementos de liberdade individual.", "E": "Consistiu, essencialmente, na introdução da eficácia\nhorizontal dos direitos fundamentais como algo a se\nobservar nas searas empresarial e de consumo."}, "g": "B", "j": "A constitucionalização do direito privado promoveu releitura dos direitos privatísticos como microssistemas submetidos à dignidade da pessoa humana e ao filtro constitucional (eficácia horizontal dos direitos fundamentais)."}, {"id": "1834838", "d": "direito_constitucional", "a": ["Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo"], "ano": "2021", "org": "CRESS", "t": "", "e": "Os ministérios do Brasil são órgãos do Poder Executivo Federal\nbrasileiro. Cada ministério é responsável por uma área específica\ne é liderado por um ministro ou ministro-chefe. A escolha do\ntitular de cada ministério é atribuição do(s)", "alt": {"A": "funcionários efetivos concursados do ministério, por\nmeio de uma lista tríplice.", "B": "presidente do Supremo Tribunal Federal (STF).", "C": "presidente do Congresso Nacional e do Senado\nFederal.", "D": "presidente da Câmara dos Deputados.", "E": "presidente da República."}, "g": "E", "j": "Art. 84, I CF/88: compete privativamente ao Presidente da República nomear e exonerar os Ministros de Estado."}, {"id": "1834835", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2021", "org": "CRESS", "t": "", "e": "Segundo o art. 37 da Constituição Federal de 1988, a\nadministração pública direta e indireta de qualquer dos\nPoderes da União, dos estados, do Distrito Federal e dos\nmunicípios obedecerá aos princípios de legalidade,\nimpessoalidade, moralidade, publicidade e eficiência. Com\nbase nessa informação, assinale a alternativa incorreta.", "alt": {"A": "Os princípios revelam o conjunto de regras ou preceitos\nque se fixam para servir de norma à toda espécie de\nação jurídica, traçando, assim, a conduta a ser adotada\nem qualquer operação jurídica.", "B": "Os princípios mostram a própria razão fundamental de\nser das coisas jurídicas, convertendo-se na verdade\nexistente por si mesma.", "C": "Os princípios se diferenciam das regras por possuírem\nconteúdo abstrato e incidem sobre inúmeras situações.", "D": "Ao se analisar os princípios enumerados, pode-se\nobservar, do ponto de vista estritamente jurídico, que\nhá uma hierarquia entre eles.", "E": "Os princípios prevalecem em relação às demais normas\nconstitucionais e atuam como fonte de direito e\ngarantia individual. Servem como critérios de\ninterpretação e aplicação do direito e espalham sua\nforça normativa às demais espécies jurídicas. Além\ndisso, consagram diretrizes e orientações aos poderes\npúblicos e impõem limites à sua atuação."}, "g": "D", "j": "Não há hierarquia jurídica entre os princípios da Administração Pública (LIMPE) — todos têm igual estatura constitucional. A afirmação D é incorreta."}, {"id": "1829370", "d": "direito_constitucional", "a": ["Poder Legislativo", "Funções Típicas e Atípicas"], "ano": "2021", "org": "CRT", "t": "", "e": "O Estado consiste em uma instituição dotada de\npersonalidade jurídica própria de direito público. Acerca do\nEstado (conceito, elementos, poderes e organização),\nassinale a alternativa incorreta.", "alt": {"A": "O Brasil adotou a teoria de tripartição de funções do\nEstado. Nesse sentido, a Constituição Federal definiu o\nfuncionamento de três poderes: Executivo; Legislativo;\ne Judiciário; todos independentes e harmônicos entre si.", "B": "Estado e governo possuem conceitos distintos, sendo\neste último um elemento formador do primeiro, sem\ncom ele se confundir.", "C": "Cada Poder do Estado exerce funções típicas, mas\ntambém, em caráter excepcional, a fim de garantir a\nharmonia entre eles, desempenha funções atípicas.", "D": "O Estado é um povo situado em determinado território\ne sujeito a um governo. Assim, são elementos do\nEstado: povo; território; e governo.", "E": "É função típica do Poder Legislativo a realização de\nprocedimento licitatório para a contratação de\nserviços, desde que necessários ao órgão."}, "g": "E", "j": "A realização de licitação é função ATÍPICA (administrativa) do Poder Legislativo, não típica. A função típica é legislar."}, {"id": "1829369", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Injunção"], "ano": "2021", "org": "CRT", "t": "", "e": "Conforme a Constituição Federal de 1988, sempre que a falta\nde norma regulamentadora torne inviável o exercício dos\ndireitos e das liberdades constitucionais e das prerrogativas\ninerentes à nacionalidade, à soberania e à cidadania, caberá", "alt": {"A": "mandado de injunção.", "B": "mandado de segurança.", "C": "habeas corpus.", "D": "habeas data.", "E": "ação popular."}, "g": "A", "j": "Art. 5º, LXXI CF/88: cabe mandado de injunção sempre que a falta de norma regulamentadora torne inviável o exercício dos direitos e liberdades constitucionais."}, {"id": "1829368", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2021", "org": "CRT", "t": "", "e": "À luz do que dispõe a Constituição Federal de 1988 sobre a\nAdministração Pública, assinale a alternativa correta.", "alt": {"A": "Deve observar os princípios da legalidade, moralidade,\npublicação, individualidade e eficácia.", "B": "Estrangeiros também podem ter acesso a cargos,\nempregos e funções públicas, na forma da lei.", "C": "É vedada a contratação por tempo determinado, por\nviolar a moralidade e o interesse público.", "D": "O prazo de validade do concurso público será de dois\nanos, improrrogáveis.", "E": "Não há direito de greve no âmbito do serviço público,\npor prevalecer o interesse público."}, "g": "B", "j": "Art. 37, I CF/88: os cargos, empregos e funções públicas são acessíveis aos brasileiros que preencham os requisitos e aos estrangeiros, na forma da lei."}, {"id": "1829367", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2021", "org": "CRT", "t": "", "e": "Com base na Constituição Federal de 1988, é direito dos\ntrabalhadores o(a)", "alt": {"A": "seguro-desemprego, em caso de desemprego\nvoluntário ou involuntário.", "B": "remuneração do trabalho noturno equivalente à do\ndiurno.", "C": "gozo de férias anuais remuneradas, com um terço a\nmais do salário normal.", "D": "repouso semanal remunerado, obrigatoriamente aos\ndomingos.", "E": "jornada de oito horas para o trabalho em turnos\nininterruptos de revezamento."}, "g": "C", "j": "Art. 7º, XVII CF/88: gozo de férias anuais remuneradas com, pelo menos, um terço a mais do que o salário normal."}, {"id": "1829366", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais"], "ano": "2021", "org": "CRT", "t": "", "e": "Quanto aos direitos e deveres individuais e coletivos\nprevistos na Constituição Federal de 1988, assinale a\nalternativa correta.", "alt": {"A": "O anonimato garante a liberdade na manifestação do\npensamento.", "B": "A liberdade intelectual, artística e científica depende\nde licença obtida junto ao órgão competente.", "C": "O exercício profissional e laboral não pode ser limitado\nou restringido pela lei.", "D": "Ninguém poderá ser compelido a associar-se ou a\npermanecer associado.", "E": "Os autores de inventos industriais e marcas têm\nprivilégio permanente para sua utilização."}, "g": "D", "j": "Art. 5º, XX CF/88: ninguém poderá ser compelido a associar-se ou a permanecer associado."}, {"id": "1794069", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Habeas Data"], "ano": "2021", "org": "CRF", "t": "", "e": "O art. 5.°\n da Carta Magna, em seu inciso LXXII, traz uma\nimportante ferramenta de controle judicial ao cidadão: o\nhabeas data. A respeito desse remédio constitucional,\nassinale a alternativa correta.", "alt": {"A": "É possível o ajuizamento de habeas data contra\nentidades privadas, desde que as informações do\ninteressado contidas em seus bancos de dados sejam\ndestinadas ao conhecimento de terceiros.", "B": "O ajuizamento de habeas data será isento de custas\nprocessuais somente àqueles que forem\nhipossuficientes, nos moldes do inciso LXXIV do\nart. 5.°\n da Constituição Federal, que prevê a gratuidade\nde justiça.", "C": "O cidadão poderá impetrar ação de habeas data\nsolicitando a retificação de seus dados pessoais assim\nque tiver conhecimento dos erros na base de dados do\nPoder Público.", "D": "O Supremo Tribunal Federal será competente para\nprocessar e julgar o pedido de habeas data quando se\ntratar de ato praticado por ministro de Estado.", "E": "A ação de habeas data é o remédio cabível contra a\nautoridade que se nega a divulgar informações de\ninteresse coletivo."}, "g": "A", "j": "Lei 9.507/97 art. 1º, §único: cabe HD contra registros ou bancos de dados de entidades governamentais ou de caráter público (incluídas entidades privadas cujos dados sejam destinados a terceiros, como SPC/Serasa)."}, {"id": "1785088", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2021", "org": "CREF", "t": "", "e": "No que diz respeito aos direitos políticos assegurados na\nConstituição Federal de 1988, assinale a alternativa correta.", "alt": {"A": "O referendo não é considerado como uma forma de\nexercício direto da soberania popular.", "B": "Em todas as hipóteses, no Brasil, o alistamento e o voto\nserão obrigatórios, inclusive para os maiores de\nsetenta anos de idade.", "C": "Os conscritos, durante o período do serviço militar\nobrigatório, são alistáveis e elegíveis.", "D": "São inelegíveis, no território de jurisdição do titular, o\ncônjuge e os parentes consanguíneos ou afins, até o\nsegundo grau ou por adoção, do presidente da\nRepública, de governador de estado, de Território ou\ndo Distrito Federal, de prefeito ou de quem os haja\nsubstituído dentro dos seis meses anteriores ao pleito,\nsalvo se já titular de mandato eletivo e candidato à\nreeleição.", "E": "A condenação criminal transitada em julgado não\nrestringe os direitos políticos do cidadão condenado,\nindependentemente do que tenha praticado."}, "g": "D", "j": "Art. 14, §7º CF/88: inelegibilidade reflexa de cônjuge e parentes até 2º grau ou por adoção, no território de jurisdição do titular, salvo se já titular de mandato eletivo e candidato à reeleição."}, {"id": "1785086", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2021", "org": "CREF", "t": "", "e": "Com relação aos direitos sociais assegurados na Constituição\nFederal de 1988, assinale a alternativa correta.", "alt": {"A": "O seguro-desemprego será assegurado,\nindependentemente de o desemprego ser voluntário\nou involuntário.", "B": "A irredutibilidade do salário, prevista na Constituição,\nimpede, sob quaisquer hipóteses, a redução salarial.", "C": "A garantia de salário nunca inferior ao mínimo para os\nque percebem remuneração variável é um direito dos\ntrabalhadores.", "D": "O salário-família será pago, em razão de dependentes,\na todos os trabalhadores, independentemente da\nrenda, nos termos da lei.", "E": "O aviso prévio a ser pago não se vincula ao tempo de\nserviço, sendo, no máximo, de trinta dias."}, "g": "C", "j": "Art. 7º, VII CF/88: garantia de salário, nunca inferior ao mínimo, para os que percebem remuneração variável."}, {"id": "1785085", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade"], "ano": "2021", "org": "CREF", "t": "", "e": "No que concerne aos direitos e às garantias fundamentais\nprevistos na Constituição Federal de 1988, assinale a\nalternativa correta.", "alt": {"A": "A proteção às participações individuais em obras\ncoletivas e à reprodução da imagem e da voz humanas,\ninclusive nas atividades desportivas, são asseguradas\nna forma da lei.", "B": "É livre a manifestação do pensamento e permitido o\nanonimato, de modo a garantir a liberdade de\nexpressão.", "C": "O direito de petição aos Poderes Públicos, em defesa\nde direitos ou contra ilegalidades ou abusos de poder,\né assegurado, desde que o interessado realize o\npagamento das taxas correspondentes ao ato\nsolicitado.", "D": "É reconhecida a instituição do júri para o julgamento de\ncrimes dolosos contra a vida, sendo obrigatória a\npublicidade das votações dos jurados.", "E": "Em nenhuma hipótese, será admitida a pena de morte\nno Brasil."}, "g": "A", "j": "Art. 5º, XXVIII CF/88: são assegurados, nos termos da lei, a proteção às participações individuais em obras coletivas e à reprodução da imagem e voz humanas, inclusive nas atividades desportivas."}, {"id": "1785084", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Princípios de Direito Constitucional Internacional"], "ano": "2021", "org": "CREF", "t": "", "e": "Quanto aos princípios fundamentais da Constituição Federal\nde 1988, assinale a alternativa correta.", "alt": {"A": "A soberania e a cidadania não constituem fundamentos\nda República Federativa do Brasil.", "B": "O Legislativo, o Executivo e o Judiciário são Poderes da\nUnião e o Poder Legislativo é subordinado ao Poder\nExecutivo.", "C": "Em suas relações internacionais, a República\nFederativa do Brasil rege-se por diversos princípios,\nentre os quais destaca-se o da proibição de concessão\nde asilo político e de intervenção.", "D": "A República Federativa do Brasil buscará a integração\neconômica, política, social e cultural dos povos da\nAmérica Latina, visando à formação de uma\ncomunidade latino-americana de nações.", "E": "A garantia do desenvolvimento nacional não compõe o\nrol dos objetivos fundamentais da República Federativa\ndo Brasil."}, "g": "D", "j": "Art. 4º, parágrafo único CF/88: o Brasil buscará a integração econômica, política, social e cultural dos povos da América Latina, visando à formação de uma comunidade latino-americana de nações."}, {"id": "1784693", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2021", "org": "CREF", "t": "", "e": "Relativamente à nacionalidade, sabe-se que a lei não pode\nestabelecer distinção entre brasileiros natos e naturalizados,\nexceto nos casos previstos na Constituição Federal de 1988.\nSendo assim, assinale a alternativa que apresenta cargo que\npode ser exercido por brasileiro naturalizado.", "alt": {"A": "ministro do Supremo Tribunal Federal", "B": "deputado estadual", "C": "carreira diplomática", "D": "oficial das Forças Armadas", "E": "presidente da Câmara dos Deputados"}, "g": "B", "j": "Art. 12, §3º CF/88: cargos privativos de brasileiros natos são PR/VP, Pres. Câmara/Senado, Min. STF, carreira diplomática, oficial das FA e Min. Estado da Defesa. Deputado estadual NÃO é privativo de nato."}, {"id": "1784692", "d": "direito_constitucional", "a": ["Disposições Gerais no Poder Judiciário", "Poder Judiciário"], "ano": "2021", "org": "CREF", "t": "", "e": "Com base na Constituição Federal de 1988, assinale a\nalternativa correta quanto aos Poderes da União.", "alt": {"A": "O Poder Executivo tem como função típica administrar,\nenquanto o Ministério Público, que também é\nconsiderado como um dos Poderes da União, tem a\nfunção de preservar os direitos do cidadão.", "B": "O Poder Legislativo tem como função típica legislar,\nsendo-lhe vedado exercer a função atípica de\nadministrar.", "C": "O Poder Judiciário tem a função típica de julgar,\nsendo-lhe vedado legislar e administrar seus órgãos e\nsuas secretarias, mesmo que atipicamente.", "D": "O Poder Judiciário tem como função típica julgar,\nexercendo, atipicamente, as funções de legislar e\nadministrar.", "E": "O Poder Judiciário e o Poder Executivo exercem a\nfunção típica de administrar e estão subordinados ao\nPoder Legislativo."}, "g": "D", "j": "Função típica do Judiciário é julgar; atipicamente exerce funções de legislar (regimentos) e administrar (gestão de seus órgãos e servidores)."}, {"id": "1764650", "d": "direito_constitucional", "a": ["Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo"], "ano": "2021", "org": "CRESS", "t": "", "e": "Os ministérios são constituídos para auxiliar e assessorar a\npresidência da República na realização de suas atividades.\nPara isso, devem trabalhar planejando e executando, no\nâmbito de suas atribuições, ações e medidas que coloquem\nem prática as políticas do governo federal. Cada um dos\nministérios é responsável por uma área específica de\natividades, possuindo funções próprias. As sedes de todos os\nórgãos estão localizadas em Brasília, na Esplanada dos\nMinistérios. Para que um ministério seja criado ou extinto, é\nnecessária a aprovação de uma lei com esse objetivo. A\ncompetência para propor um projeto de lei que crie ou\nextinga um ministério é do presidente do(da)", "alt": {"A": "República.", "B": "Senado.", "C": "Câmara dos Deputados.", "D": "Supremo Tribunal Federal.", "E": "Tribunal de Contas da União."}, "g": "A", "j": "Art. 61, §1º, II, 'e' CF/88: iniciativa privativa do Presidente da República para leis que disponham sobre criação e extinção de Ministérios e órgãos da Administração Pública."}, {"id": "1710761", "d": "direito_constitucional", "a": ["Poder Legislativo", "Tribunal de Contas da União (TCU) e Fiscalização Contábil, Financeira e Orçamentária da União"], "ano": "2021", "org": "CRM", "t": "", "e": "O art. 70 da Constituição Federal de 1988 estabelece que a\nfiscalização contábil, financeira, orçamentária, operacional e\npatrimonial da União e das entidades da administração direta\ne indireta, quanto à legalidade, à legitimidade, à\neconomicidade, à aplicação das subvenções e à renúncia de\nreceitas, será exercida pelo Congresso Nacional, mediante\ncontrole externo, e pelo sistema de controle interno de cada\nPoder. Firma-se, cada vez mais, que as entidades objeto da\nfiscalização governamental passem a ser instrumentalizadas\ncom o sistema de controle interno, que, além de subsidiar o\ncontrole externo, assegura a existência de um controle na\nextensão proposta pela lei, exercido, preferencialmente, de\nforma preventiva e concomitante aos atos de gestão. Além da\nobediência aos princípios constitucionais, o exercício do\ncontrole interno, em termos de gestão, deve avaliar a\nobediência a princípios próprios de controle interno. Deverá\nhaver uma separação entre as funções de autorização e\naprovação de operações, de execução, de controle e de\ncontabilização. Esse princípio de controle é conhecido como", "alt": {"A": "controle sobre as transações", "B": "instrução devidamente formalizada.", "C": "segregação de funções.", "D": "relação custo-benefício.", "E": "aderência às diretrizes e às normas legais."}, "g": "C", "j": "Segregação de funções: princípio de controle interno que exige a separação entre funções de autorização, execução, controle e contabilização, evitando concentração de poder."}, {"id": "1710759", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Finanças Públicas – Orçamento"], "ano": "2021", "org": "CRM", "t": "", "e": "O sistema orçamentário do Brasil, conforme o art. 165 da\nConstituição Federal de 1988, é composto por três leis\nbásicas: lei do plano plurianual; lei de diretrizes\norçamentárias; e lei orçamentária anual. A lei de diretrizes\norçamentárias compreenderá as metas e prioridades da\nAdministração Pública Federal, incluindo as despesas de\ncapital para o exercício financeiro subsequente, orientará a\nelaboração da lei orçamentária anual, disporá sobre as\nalterações na legislação tributária e estabelecerá a política de\naplicação das agências financeiras oficiais de fomento. Sua\nelaboração é de iniciativa do(da)", "alt": {"A": "tribunal de contas.", "B": "Senado.", "C": "Câmara dos Deputados e do Senado.", "D": "Câmara dos Deputados.", "E": "Poder Executivo."}, "g": "E", "j": "Art. 165 CF/88: as leis do PPA, LDO e LOA são de iniciativa do Poder Executivo."}, {"id": "1710707", "d": "direito_constitucional", "a": ["Processo Legislativo", "Espécies Normativas: Medida Provisória, Lei Delegada, Decreto Legislativo e Resolução"], "ano": "2021", "org": "CRM", "t": "", "e": "Segundo a Constituição Federal, em caso de relevância e\nurgência, será possível a edição de medida provisória sobre\nmatéria relativa", "alt": {"A": "à nacionalidade.", "B": "à cidadania.", "C": "aos partidos políticos.", "D": "ao direito penal.", "E": "ao direito tributário."}, "g": "E", "j": "Art. 62 §1º CF/88: MP é vedada sobre nacionalidade, cidadania, partidos políticos, direito penal, processo penal e civil. Sobre direito tributário, é permitida (art. 62 §2º com observância da anterioridade na conversão)."}, {"id": "1710706", "d": "direito_constitucional", "a": ["Processo Legislativo", "Processo Legislativo Ordinário"], "ano": "2021", "org": "CRM", "t": "", "e": "A respeito do processo legislativo, assinale a alternativa\ncorreta.", "alt": {"A": "Não será objeto de deliberação a proposta de emenda\nconstitucional tendente a abolir o voto obrigatório, por\nse tratar de cláusula pétrea.", "B": "A matéria constante de projeto de lei rejeitado\nsomente poderá constituir objeto de novo projeto, na\nmesma sessão legislativa, mediante proposta da\nmaioria absoluta dos membros de qualquer das Casas\ndo Congresso Nacional.", "C": "O veto presidencial pode ser parcial, abrangendo\napenas palavras e expressões do projeto de lei.", "D": "Segundo o texto constitucional, é possível a reedição,\nna mesma sessão legislativa, de medida provisória que\ntenha perdido sua eficácia por decurso de prazo.", "E": "Se o veto presidencial for rejeitado pelo Congresso\nNacional, o projeto de lei será enviado diretamente ao\npresidente do Senado Federal para promulgação."}, "g": "B", "j": "Art. 67 CF/88: matéria constante de projeto de lei rejeitado só pode constituir objeto de novo projeto na mesma sessão legislativa mediante proposta da maioria absoluta dos membros de qualquer das Casas."}, {"id": "1710705", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Controle Repressivo do Poder Legislativo", "Controle Repressivo do Poder Judiciário: o Controle Difuso ou Aberto", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2021", "org": "CRM", "t": "", "e": "Considerando o sistema constitucional brasileiro, assinale a\nalternativa correta.", "alt": {"A": "O decreto legislativo com a finalidade de sustar os atos\ndo Poder Executivo que exorbitem do poder\nregulamentar representa hipótese de controle\nrepressivo de constitucionalidade.", "B": "O controle exercido pelo presidente da República,\nmediante veto jurídico, constitui hipótese de controle\nrepressivo de constitucionalidade.", "C": "Somente pela maioria relativa de seus membros ou dos\nmembros do respectivo órgão especial poderão os\ntribunais declarar a inconstitucionalidade de lei ou ato\nnormativo do Poder Público.", "D": "O Poder Judiciário realiza controle preventivo de\nconstitucionalidade em via mandamental ou em ação\ndireta de inconstitucionalidade.", "E": "De acordo com a jurisprudência, é possível utilizar o\nmandado de segurança para impedir a tramitação de\nproposta de emenda constitucional que contenha vício\nde constitucionalidade material ou formal."}, "g": "A", "j": "Art. 49, V CF/88: o decreto legislativo que susta atos do Executivo que exorbitem do poder regulamentar é hipótese de controle repressivo de constitucionalidade exercido pelo Legislativo."}, {"id": "1697360", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade"], "ano": "2020", "org": "CREMERS", "t": "", "e": "Com relação a direitos e garantias fundamentais, assinale a\nalternativa correta.", "alt": {"A": "O exercício do direito constitucional de reunião em\nlocais públicos depende de prévia autorização da\nautoridade competente.", "B": "A associação inicialmente criada para finalidade lícita e\nposteriormente desvirtuada será compulsoriamente\ndissolvida por decisão da autoridade policial.", "C": "Segundo o texto constitucional, é livre a manifestação\ndo pensamento, sendo vedado o anonimato.", "D": "A ação de grupos armados contra a ordem\nconstitucional e o Estado democrático constitui crime\ninafiançável e insuscetível de graça ou anistia.", "E": "O sigilo das comunicações telefônicas será violado\nsomente por decisão da autoridade policial para os\ncasos de investigação criminal."}, "g": "C", "j": "Art. 5º, IV CF/88: livre manifestação do pensamento, sendo vedado o anonimato."}, {"id": "1252620", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2019", "org": "CRO", "t": "", "e": "Acerca dos direitos sociais e políticos na Constituição Federal de 1988, assinale a alternativa correta.", "alt": {"A": "Estando os direitos políticos previstos na Constituição Federal,  somente  a  própria  Constituição  poderá estabelecer  hipóteses  de  inelegibilidade,  absoluta  ou relativa.", "B": "Todo inelegível é inalistável, mas nem todo inalistável é inelegível.", "C": "Somente  a  Constituição  pode  prever  as  situações  de perda ou suspensão de direitos políticos.", "D": "Os  direitos  sociais  são  amplamente  passíveis  de disposição  contratual  pelas  partes  envolvidas  na relação  trabalhista, a bem do princípio da autonomia da vontade.", "E": "Todas  as  pessoas  são  beneficiárias  dos  direitos  sociais, inclusive os empresários, os empreendedores, os  servidores  públicos,  os  desempregados  e  os aprendizes."}, "g": "C", "j": "Art. 15 CF/88: as hipóteses de perda ou suspensão dos direitos políticos são taxativas na Constituição, sendo vedada a cassação."}, {"id": "1252619", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2019", "org": "CRO", "t": "", "e": "De  acordo  com  a  Constituição  Federal  de  1988,  assinale  a alternativa correta a respeito da nacionalidade.", "alt": {"A": "As hipóteses de aquisição originária de nacionalidade estão previstas, de modo não taxativo, na Constituição, podendo a lei estabelecer situações adicionais.", "B": "Muito embora a regra adotada pela Constituição para aquisição originária de nacionalidade seja o critério jus sanguinis, há hipóteses em que se admite o critério jus soli,  aliado  ao  atendimento  de  outros  requisitos previstos na Carta.", "C": "A  chamada  nacionalidade  potestativa  consiste  na aquisição  originária  por  aquele  que,  nascido  no estrangeiro, de pai brasileiro ou mãe brasileira, venha a residir na República Federativa do Brasil, optando, no prazo  máximo  de  um  ano  após  o  atingimento  da maioridade, pela nacionalidade brasileira.", "D": "Não perde a nacionalidade brasileira aquele que tenha, em  virtude  do  critério  jus  sanguinis,  nacionalidade originária reconhecida por Estado estrangeiro.", "E": "Somente  aos  portugueses  naturalizados  são reconhecidos os mesmos direitos dos brasileiros."}, "g": "D", "j": "Art. 12, §4º, II, 'a' CF/88: não perde a nacionalidade brasileira aquele cujo reconhecimento se dê por outro Estado em razão do critério jus sanguinis (nacionalidade originária)."}, {"id": "1252615", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2019", "org": "CRO", "t": "", "e": "Quanto  aos  municípios  na  Constituição  Federal  de  1988, assinale a alternativa correta.", "alt": {"A": "É vedada a criação de tribunais, conselhos ou órgãos de contas municipais.", "B": "A  lei  orgânica  dos  municípios  preverá  a  iniciativa popular de projetos de lei, ficando a cargo de cada ente a  definição  sobre  o  percentual  mínimo  de  eleitores exigidos para a manifestação.", "C": "O  controle  externo  da  Câmara  Municipal  é  realizado  pelo  Poder  Executivo,  por  meio  de  sua  Controladoria‐Geral.", "D": "O  controle  externo  municipal  é  desempenhado  pelo Ministério Público e pelo tribunal de contas do estado.", "E": "Compete  aos  municípios  organizar  e  prestar, diretamente ou sob regime de concessão, os serviços públicos locais, exceto o de transporte, de competência estadual."}, "g": "A", "j": "Art. 31, §4º CF/88: é vedada a criação de tribunais, conselhos ou órgãos de contas municipais (mantidos apenas os já existentes ao tempo da CF — São Paulo e Rio de Janeiro)."}, {"id": "1252613", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2019", "org": "CRO", "t": "", "e": "Assinale a alternativa correta a respeito da nacionalidade na Constituição Federal de 1988.", "alt": {"A": "A  legislação  infraconstitucional  poderá  estabelecer distinções  entre  brasileiros  natos  e  naturalizados, desde que atendido o pressuposto da razoabilidade.", "B": "Há  perda  da  nacionalidade  brasileira  sempre  que houver a aquisição de nacionalidade diversa.", "C": "O cargo de ministro de Estado é privativo de brasileiro nato.", "D": "Os  símbolos  não  são  uma  prerrogativa  exclusiva  da República Federativa do Brasil, podendo os estados, o Distrito Federal e os municípios adotar bandeira, hino, armas e selos próprios.", "E": "O  cargo  de  senador  da  República  é  privativo  de brasileiro nato."}, "g": "D", "j": "Art. 13, §2º CF/88: os Estados, DF e Municípios poderão ter símbolos próprios — não são prerrogativa exclusiva da União."}, {"id": "1252612", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2019", "org": "CRO", "t": "", "e": "Com  relação  aos  direitos  sociais  na  Constituição  Federal  de 1988, assinale a alternativa correta.", "alt": {"A": "É vedada a redução salarial por acordo ou convenção coletiva de trabalho.", "B": "A  remuneração  por  serviço  extraordinário  deve superar a comum em exatos cinquenta porcento.", "C": "O  seguro  contra  acidentes  de  trabalho  não  exclui  a indenização devida pelo empregador quando incorrer em dolo ou culpa.", "D": "O adicional de férias deve corresponder a, exatamente, um terço do salário normal.", "E": "O décimo terceiro salário deve ser estimado com base no valor do último vencimento."}, "g": "C", "j": "Art. 7º, XXVIII CF/88: seguro contra acidentes de trabalho a cargo do empregador, sem excluir a indenização a que está obrigado quando incorrer em dolo ou culpa."}, {"id": "1252611", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Constitucionais-Penais e Garantias Constitucionais do Processo", "Direitos Individuais", "Direito à Liberdade", "Direito de Propriedade e Função Social da Propriedade"], "ano": "2019", "org": "CRO", "t": "", "e": "No que concerne aos direitos e às garantias fundamentais na Constituição Federal de 1988, assinale a alternativa correta.", "alt": {"A": "A escusa  de consciência  não  pode ensejar punição, a não  ser  quando  invocada  como  fundamento  para  a negativa  de  cumprimento  de  obrigação  imposta  a todos  e,  adicionalmente,  quando  houver  recusa  do cumprimento de prestação alternativa.", "B": "A propriedade rural produtiva não poderá ser objeto de penhora  para  pagamento  de  débitos  decorrentes  de sua atividade.", "C": "O  racismo  é  crime  imprescritível,  inafiançável  e insuscetível de graça ou anistia.", "D": "O  princípio  da  individualização  da  pena  é,  em  certa medida, relativizado pela possibilidade de a reparação de  dano  e  o  perdimento  de  bens  poderem  ser transferidos aos herdeiros, até sua integral satisfação.", "E": "É  absoluta  a  vedação  a que  o  civilmente  identificado seja criminalmente identificado."}, "g": "A", "j": "Art. 5º, VIII CF/88: ninguém será privado de direitos por motivo de crença ou convicção, salvo se as invocar para se eximir de obrigação legal e recusar prestação alternativa fixada em lei."}, {"id": "1252542", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2019", "org": "CRO", "t": "", "e": "É condição de elegibilidade a idade mínima de", "alt": {"A": "35 anos para governador.", "B": "30 anos para deputado federal.", "C": "21 anos para prefeito.", "D": "18 anos para deputado estadual.", "E": "18 anos para juiz de paz."}, "g": "C", "j": "Art. 14, §3º, VI, 'c' CF/88: idade mínima de 21 anos para prefeito, vice-prefeito e juiz de paz."}, {"id": "1252541", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2019", "org": "CRO", "t": "", "e": "O município reger‐se‐á por lei orgânica votada em", "alt": {"A": "primeiro  turno,  se  aprovada  por  dois  terços  dos membros da Câmara Municipal.", "B": "dois  turnos,  com  o  interstício  mínimo  de  dez  dias,  e aprovada  por  dois  terços  dos  membros  da  Câmara Municipal.", "C": "dois turnos, com o interstício mínimo de trinta dias, e aprovada  por  um  terço  dos  membros  da  Câmara Municipal.", "D": "dois  turnos,  com  o  interstício  mínimo  de  dez  dias,  e aprovada  por  maioria  dos  membros  da  Câmara Municipal.", "E": "dois turnos, com o interstício mínimo de trinta dias, e aprovada  por  maioria  dos  membros  da  Câmara Municipal."}, "g": "B", "j": "Art. 29 CF/88: município reger-se-á por Lei Orgânica votada em dois turnos, com interstício mínimo de 10 dias, e aprovada por 2/3 dos membros da Câmara Municipal."}, {"id": "1252540", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2019", "org": "CRO", "t": "", "e": "É brasileiro", "alt": {"A": "nato o nascido no estrangeiro de pai ou mãe brasileira que esteja a serviço da República Federativa do Brasil.", "B": "nato  o  originário  de  país  de  língua  portuguesa  que venha residir no Brasil, tenha idoneidade moral e faça essa opção.", "C": "naturalizado  o  nascido  no  Brasil  de  pais  estrangeiros que não estejam a serviço de seu país.", "D": "naturalizado  o  nascido  no  estrangeiro,  de  pai  ou  de mãe  brasileira,  que  seja  registrado  em  repartição brasileira competente.", "E": "naturalizado  o  nascido  no  estrangeiro,  de  pai  ou  de mãe brasileira, que venha a residir no Brasil e opte pela nacionalidade brasileira."}, "g": "A", "j": "Art. 12, I, 'b' CF/88: são natos os nascidos no estrangeiro de pai ou mãe brasileira, desde que qualquer deles esteja a serviço da República Federativa do Brasil."}, {"id": "1252539", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2019", "org": "CRO", "t": "", "e": "De acordo com a CF, é direito social o(a)", "alt": {"A": "repouso  semanal  remunerado,  preferencialmente  no \nfinal de semana.", "B": "adicional  de  um  terço,  em  relação  à  remuneração  do  serviço  normal,  à  remuneração  do  serviço extraordinário.", "C": "remuneração  superior,  no  mínimo,  em  setenta porcento, à normal para atividades tóxicas, insalubres ou perigosas.", "D": "proteção  do  salário,  constituindo‐se  crime  sua retenção dolosa.", "E": "seguro  contra  acidentes  de  trabalho,  a  cargo  do empregado,  sem  excluir  a  indenização  pelo empregador."}, "g": "D", "j": "Art. 7º, X CF/88: proteção do salário na forma da lei, constituindo crime sua retenção dolosa."}, {"id": "1252538", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2019", "org": "CRO", "t": "", "e": "A criação, a incorporação, a fusão e o desmembramento de municípios serão feitos por meio de lei", "alt": {"A": "federal,  dentro  do  período  determinado  por  lei complementar  federal  e  dependendo  de  consulta mediante plebiscito.", "B": "federal,  dentro  do  período  determinado  por  lei complementar  federal  e  dependendo  de  consulta mediante referendo.", "C": "estadual,  dentro  do  período  determinado  por  lei complementar  estadual  e  dependendo  de  consulta prévia, mediante referendo.", "D": "estadual,  dentro  do  período  determinado  por  lei complementar  federal  e  dependendo  de  consulta prévia, mediante plebiscito.", "E": "complementar  federal,  dentro  do  período determinado  por  lei  estadual  e  dependendo  de consulta mediante referendo."}, "g": "D", "j": "Art. 18, §4º CF/88: a criação/incorporação/fusão/desmembramento de municípios faz-se por lei estadual, dentro do período determinado por lei complementar federal, dependendo de consulta prévia, mediante plebiscito."}, {"id": "1252536", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Teoria dos Direitos Fundamentais"], "ano": "2019", "org": "CRO", "t": "", "e": "Quanto aos direitos e às garantias fundamentais previstos na Constituição  Federal  de  1988  (CF),  assinale  a  alternativa correta.", "alt": {"A": "Ninguém  será  obrigado  a  fazer  ou  a  deixar  de  fazer alguma coisa senão em virtude de decisão judicial.", "B": "A  casa  é  inviolável,  ninguém  nela  podendo  penetrar sem o consentimento do morador, salvo durante o dia, para prestar socorro ou por determinação judicial.", "C": "É  livre  o  exercício  de  qualquer  trabalho,  ofício  ou profissão, sendo vedadas as restrições para sua prática.", "D": "A criação de associações e de cooperativas independe de  autorização,  sendo  vedada  a  interferência  estatal em seu funcionamento.", "E": "São obrigatórias a filiação a entidades associativas e a permanência mínima estabelecida no estatuto social."}, "g": "D", "j": "Art. 5º, XVIII CF/88: a criação de associações e, na forma da lei, a de cooperativas independem de autorização, sendo vedada a interferência estatal em seu funcionamento."}, {"id": "1105095", "d": "direito_constitucional", "a": ["Ato das Disposições Constitucionais Transitórias - ADCT"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "De acordo com a Constituição Federal, no Ato das Disposições Constitucionais Transitórias, enquanto não for aprovada a Lei de  que  trata  o  art.  165,  §  9.º,  I  e  II,  os  prazos  para encaminhamento  e  para  devolução  da  lei  de  diretrizes orçamentárias da União serão, respectivamente, de", "alt": {"A": "quatro  meses antes  do  encerramento  do  exercício financeiro e até o encerramento da sessão legislativa.", "B": "quatro  meses  antes  do  encerramento  do  exercício financeiro e até o encerramento do primeiro período da sessão legislativa.", "C": "oito meses e meio antes do encerramento do exercício financeiro e até o encerramento do primeiro período da sessão legislativa.", "D": "oito meses e meio antes do encerramento do exercício financeiro e até o encerramento da sessão legislativa.", "E": "nove  meses  e  meio antes  do  encerramento  do exercício financeiro e até o encerramento do primeiro período da sessão legislativa."}, "g": "C", "j": "ADCT art. 35, §2º, II: a LDO da União será encaminhada até 8 meses e meio antes do encerramento do exercício financeiro e devolvida até o encerramento do primeiro período da sessão legislativa."}, {"id": "1104806", "d": "direito_constitucional", "a": ["Previdência Social", "Ordem Social"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "O  custeio  da  seguridade  social  é  proveniente  de  diversas fontes.  Assim,  crises  em  determinados  setores  não comprometem exorbitantemente a arrecadação. Segundo a Constituição Federal de 1988, assinale a alternativa correta a respeito do custeio da seguridade social.", "alt": {"A": "A  seguridade  social  será  financiada  exclusivamente mediante recursos provenientes da União, não sendo responsabilidade dos estados, do Distrito Federal e dos municípios.", "B": "As contribuições sociais sobre a receita de concurso de prognósticos, como loterias,  não podem  ser  fonte de custeio  para  a  seguridade  social,  já  que  tais  eventos envolvem recursos exclusivos da União.", "C": "A  seguridade  social  será  financiada  por  toda  a \nsociedade,  de  forma  direta e  indireta,  nos  termos  da \nlei,  mediante  recursos  provenientes  dos  orçamentos \nda  União,  dos  estados,  do  Distrito  Federal  e  dos \nmunicípios e de outras contribuições sociais.", "D": "A União, os estados, o Distrito Federal e os municípios, \nserão responsáveis pelo  financiamento da seguridade \nsocial, mas não a sociedade.", "E": "A  seguridade  social  será  financiada  exclusivamente pela sociedade, de forma direta, não sendo possível de forma indireta."}, "g": "C", "j": "Art. 195 CF/88: a seguridade social será financiada por toda a sociedade, de forma direta e indireta, com recursos dos orçamentos da União, Estados, DF e Municípios, e contribuições sociais."}, {"id": "1104799", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "O Estado, soberano, possui o poder de tributar, isto é, obter  dos  cidadãos  os  tributos  que  desejar.  Contudo,  este poder não é irrestrito, a própria Constituição Federal de 1988 estabelece  as  limitações  do  poder  de  tributar  atribuído  à União,  aos  estados‐membros,  ao  Distrito  Federal  e  aos municípios.", "e": "Acerca do poder de tributar da União, assinale a alternativa \ncorreta.", "alt": {"A": "É vedado instituir tributo que seja uniforme em todo o \nterritório nacional.", "B": "É  vedado  conceder  incentivos  fiscais  destinados  a promover  o  equilíbrio  do  desenvolvimento socioeconômico entre as diferentes regiões do País.", "C": "É vedado instituir isenções de tributos de competência dos estados, do Distrito Federal ou dos municípios.", "D": "Deve tributar a renda das obrigações da dívida pública dos estados, do Distrito Federal e dos municípios.", "E": "Deve  tributar  a  remuneração  e  os  proventos  dos respectivos agentes públicos, em níveis superiores aos que fixar para suas obrigações e para seus agentes."}, "g": "C", "j": "Art. 151, III CF/88: vedação à isenção heterônoma — é vedado à União instituir isenções de tributos de competência dos Estados, DF ou Municípios."}, {"id": "1104794", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Disposições Gerais na Administração Pública"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A  tutela  constitucional  da  moralidade  na  Administração \nPública dá‐se por meio do(da)", "alt": {"A": "improbidade  administrativa  para  infrações  menos \ngraves, hipóteses  em que  fica prejudicada a persecução \npenal.", "B": "tipificação dos crimes de responsabilidade, passíveis de serem cometidos por qualquer pessoa.", "C": "possibilidade  de  a  ofensa  ao  princípio  resultar  em inelegibilidade.", "D": "estabelecimento  dos  crimes  contra  a  Administração Pública como inafiançáveis e imprescritíveis.", "E": "ação  popular,  passível  de  ajuizamento  por  qualquer pessoa."}, "g": "C", "j": "Art. 14, §9º CF/88 + LC 64/90: a violação do princípio da moralidade pode resultar em inelegibilidade. Tutela constitucional ampla da moralidade administrativa."}, {"id": "1104786", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Conceito de Constituição"], "ano": "2019", "org": "Prefeitura de Jataí", "t": "", "e": "A  Constituição  representa  o  resultado  de  uma  vontade política fundamental externada pelo Constituinte originário a respeito de temas ligados à estrutura do Estado. Essa acepção do conceito de Constituição está ligada", "alt": {"A": "a um sentido sociológico.", "B": "a um sentido cultural.", "C": "a um sentido político.", "D": "ao conceito formal de Constituição.", "E": "ao conceito material de Constituição."}, "g": "C", "j": "Sentido político (Carl Schmitt): a Constituição é a decisão política fundamental do titular do poder constituinte sobre a estrutura do Estado."}, {"id": "1078210", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2019", "org": "CRF", "t": "", "e": "Quanto  aos  limites  territoriais  da  inelegibilidade  reflexa \nprevistos  na  Constituição  Federal  de  1988,  assinale  a \nalternativa correta.", "alt": {"A": "Cônjuge do atual prefeito não pode se candidatar, pela primeira vez, à vice‐prefeitura do mesmo município.", "B": "Irmão  por  adoção  do  atual  prefeito  não  pode  se candidatar,  pela  primeira  vez,  a  vereador  no  mesmo município.", "C": "Pai  do  atual  presidente  da  República  não  pode  se candidatar, pela primeira vez, a nenhum cargo eletivo no País.", "D": "Filho  do  atual  governador  de  estado  não  pode  se candidatar, pela primeira vez, a deputado estadual no mesmo estado.", "E": "Cônjuge  de  secretário  de  estado  não  pode  se candidatar, pela primeira vez, a prefeito de município que pertença àquele mesmo estado."}, "g": "C", "j": "Art. 14, §7º CF/88: inelegibilidade reflexa do PR alcança parentes consanguíneos/afins até 2º grau em TODO o território nacional. Pai do PR é inelegível para qualquer cargo no país."}, {"id": "1063086", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Intervenção do Estado no Domínio Econômico"], "ano": "2019", "org": "CORECON", "t": "", "e": "O exercício  de  atividades econômicas e  profissionais \npor particulares deve ser protegido da  coerção arbitrária por \nparte do Estado, competindo ao Judiciário, à luz do sistema \nde  freios  e  contrapesos  estabelecidos na Constituição brasileira, invalidar atos normativos que estabeleçam \nrestrições  desproporcionais  à  livre  iniciativa  e  à  liberdade \nprofissional. \n                                                                             Internet: <www.stf.jus.br> (com adaptações). \nTendo o texto acima apenas como referência inicial, assinale \na alternativa correta,  de acordo  com a Constituição Federal \nde 1988, no que se refere à ordem  econômica e financeira.", "alt": {"A": "Não é permitida, em nenhuma hipótese, a exploração \ndireta  de  atividade  econômica  pelo  Estado,  uma  vez \nque seria concorrência desleal com os particulares.", "B": "As  empresas  públicas  e  as  sociedades  de  economia \nmista  poderão  gozar  de  privilégios  fiscais  não \nextensivos aos do setor privado.", "C": "O  Estado  favorecerá  a  organização  da  atividade \ngarimpeira em cooperativas,  considerando a proteção \ndo meio ambiente e a promoção econômico‐social dos \ngarimpeiros.", "D": "Os  estados,  o  Distrito  Federal  e  os  municípios  não \npoderão conceder às microempresas  e às empresas de \npequeno  porte,  assim  definidas  em  lei,  tratamento \njurídico diferenciado.", "E": "A  refinação  do  petróleo  nacional  ou  estrangeiro \nconstitui  monopólio  da  União,  não  sendo  possível  a \ncontratação  de  empresas  estatais  para  a  realização \ndessa atividade."}, "g": "C", "j": "Art. 174, §3º CF/88: o Estado favorecerá a organização da atividade garimpeira em cooperativas, levando em conta a proteção do meio ambiente e a promoção econômico-social dos garimpeiros."}, {"id": "1037797", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2019", "org": "FHGV", "t": "", "e": "Segundo a  CF, é  direito  dos  trabalhadores  rurais e  urbanos \no(a)", "alt": {"A": "remuneração do trabalho noturno majorada em dobro \nem relação à do diurno.", "B": "remuneração  do  serviço  extraordinário  superior,  no \nmáximo, em 50% à do normal.", "C": "assistência gratuita aos  filhos e dependentes desde o \nnascimento  até  cinco  anos  de  idade  em  creches  e  \npré‐escolas.", "D": "gozo de  férias anuais  remuneradas com, pelo menos, um quarto a mais que o salário normal do período.", "E": "adicional  de  um  terço  na  remuneração  para  as atividades penosas, insalubres ou perigosas."}, "g": "C", "j": "Art. 7º, XXV CF/88: assistência gratuita aos filhos e dependentes desde o nascimento até 5 anos de idade em creches e pré-escolas."}, {"id": "1278660", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "A  respeito  dos  direitos  sociais  previstos  na  Constituição  da República Federativa do Brasil de 1988, é correto afirmar que é direito do trabalhador o(a)", "alt": {"A": "seguro‐desemprego  em  caso  de  desemprego \nvoluntário.", "B": "recebimento  de  remuneração  igual  para  trabalhos \nexecutados nos turnos diurno e noturno.", "C": "repouso semanal remunerado, sempre aos domingos.", "D": "desigualdade  de  direitos  entre  o  trabalhador  com \nvínculo  empregatício  permanente  e  o  trabalhador \navulso.", "E": "salário‐família,  pago  em  razão  de  dependente  do \ntrabalhador de baixa renda, nos termos da lei."}, "g": "E", "j": "Art. 7º, XII CF/88: salário-família pago em razão de dependente do trabalhador de baixa renda, nos termos da lei."}, {"id": "1278657", "d": "direito_constitucional", "a": ["Família, Criança, Adolescente e Idoso", "Ordem Social"], "ano": "2018", "org": "Prefeitura de Cristalina", "t": "", "e": "Acerca da família, da criança, do adolescente, do jovem e do idoso, de acordo com a Constituição da República Federativa do Brasil de 1988, assinale a alternativa correta.", "alt": {"A": "O  planejamento  familiar  cabe  ao  Estado,  sendo  de \nresponsabilidade  do  casal  propiciar  recursos \neducacionais.", "B": "O Estado garantirá a assistência à família na pessoa de cada um dos que a integram, criando mecanismos para coibir a violência no âmbito de suas relações.", "C": "A  família  tem  especial  proteção  do  Estado,  mas  não \nreconhece  a  união  estável  entre  homem  e  mulher \ncomo entidade familiar.", "D": "A  participação  de  entidades  não  governamentais  em \nprogramas  de  assistência  integral  à  saúde  da  criança \nnão é permitida, cabendo ao Estado.", "E": "Aos  maiores  de  45  anos  de  idade  é  garantida  a \ngratuidade dos transportes coletivos urbanos."}, "g": "B", "j": "Art. 226, §8º CF/88: o Estado assegurará a assistência à família na pessoa de cada um dos que a integram, criando mecanismos para coibir a violência no âmbito de suas relações."}, {"id": "1141637", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2018", "org": "CRP", "t": "", "e": "Com relação aos direitos sociais na CF, assinale a alternativa\ncorreta.", "alt": {"A": "É dever do Estado e direito subjetivo das crianças com\nidade entre zero e sete anos o acesso à educação\ninfantil, de forma gratuita, em creche e pré-escola.", "B": "O princípio da isonomia previsto no texto\nconstitucional deve ser aplicado como norma\ninstituidora de garantia ao tratamento isonômico, ou\nseja, projeta-se, por meio de norma de eficácia\nlimitada, para assegurar a todos, indistintamente,\nindependentemente de raça, cor, sexo, classe social,\nsituação econômica, orientação sexual e convicções\npolíticas e religiosas, igual tratamento perante a lei.", "C": "Muito embora o legislador ordinário tenha uma\nconsiderável liberdade de conformação quanto ao\nconteúdo das elaborações normativas ou\nrelativamente ao modo de organizar a concretização\ndesses direitos, é inegável que os direitos\nfundamentais sociais sejam dotados de vinculatividade\nnormativo-constitucional.", "D": "De acordo com o Supremo Tribunal Federal (STF), a\ngarantia constitucional de acesso da criança à\neducação pode ser obstada por razões orçamentárias,\na despeito do princípio da dignidade da pessoa\nhumana.", "E": "A licença-gestante, com duração de cento e vinte dias,\né exclusiva para as mulheres investidas em cargo\nefetivo, via concurso público, não se aplicando aos\ncargos em comissão, de livre nomeação e exoneração."}, "g": "C", "j": "Os direitos fundamentais sociais são dotados de vinculatividade normativo-constitucional, ainda que o legislador disponha de margem de conformação quanto à concretização (Sarlet, Mendes)."}, {"id": "1083377", "d": "direito_constitucional", "a": ["Poder Legislativo", "Comissões Parlamentares e Comissões Parlamentares de Inquérito (CPIs)"], "ano": "2018", "org": "COREN", "t": "", "e": "A respeito das Comissões Parlamentares de Inquérito, assinale a alternativa correta.", "alt": {"A": "Diferentemente do que ocorre com os órgãos judiciais, as Comissões Parlamentares de Inquérito, no desempenho de seus poderes de investigação, não estão sujeitas às prerrogativas legais conferidas aos advogados.", "B": "As Comissões Parlamentares de Inquérito não detêm a atribuição de investigar atos praticados em âmbito privado, ainda que revestidos de potencial interesse público e cujo objeto esteja inserido, em tese, entre as competências da Casa Legislativa que lhe dá origem.", "C": "A Comissão Parlamentar de Inquérito, desde que por meio de decisão fundamentada e motivada, poderá quebrar o sigilo bancário do investigado, sem a necessidade de intervenção do Poder Judiciário.", "D": "De forma excepcional, as Comissões Parlamentares de Inquérito poderão ser criadas por prazo certo e para investigar fatos indeterminados, desde que haja expressa autorização do Poder Judiciário e a respectiva Casa Legislativa fundamente sua decisão.", "E": "Nas investigações realizadas pelas Comissões Parlamentares de Inquérito, não tem incidência a garantia constitucional da não autoincriminação do investigado ou indiciado."}, "g": "C", "j": "Jurisprudência STF (MS 23.452): CPI pode determinar a quebra de sigilo bancário do investigado por decisão fundamentada, sem necessidade de intervenção judicial prévia."}, {"id": "1082692", "d": "direito_constitucional", "a": ["Família, Criança, Adolescente e Idoso"], "ano": "2018", "org": "COREN", "t": "", "e": "O  planejamento  familiar  é  livre  decisão  do  casal, \nfundamentando‐se no princípio da", "alt": {"A": "igualdade.", "B": "fraternidade.", "C": "dignidade da pessoa humana.", "D": "proporcionalidade ou razoabilidade.", "E": "responsabilidade social."}, "g": "C", "j": "Art. 226, §7º CF/88: o planejamento familiar é livre decisão do casal, fundado nos princípios da dignidade da pessoa humana e da paternidade responsável."}, {"id": "1081051", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Injunção"], "ano": "2018", "org": "CRMV", "t": "", "e": "Nos termos da CF, quando a falta de norma regulamentadora   tornar  inviável  o  exercício  dos  direitos  e  das  liberdades   constitucionais e das prerrogativas inerentes à nacionalidade,   à soberania e à cidadania, será possível impetrar", "alt": {"A": "habeas corpus.", "B": "habeas data.", "C": "mandado de injunção.", "D": "ação popular.", "E": "ação civil pública."}, "g": "C", "j": "Art. 5º, LXXI CF/88: cabe mandado de injunção sempre que a falta de norma regulamentadora torne inviável o exercício dos direitos e liberdades constitucionais e das prerrogativas inerentes à nacionalidade, soberania e cidadania."}, {"id": "1033300", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2018", "org": "CRMV", "t": "", "e": "Segundo  a  CF,  é  direito  dos  trabalhadores  urbanos  e  \nrurais o(a)", "alt": {"A": "seguro‐desemprego  em  caso  de  desemprego \nvoluntário ou despedida arbitrária.", "B": "remuneração  do  trabalho  diurno  superior  à  do \nnoturno.", "C": "remuneração  do  serviço  extraordinário  superior,  no \nmínimo, em 50% à do normal.", "D": "gozo de  férias anuais  remuneradas com, pelo menos, um quarto a mais que o salário normal.", "E": "jornada  de  oito  horas  para  o  trabalho  realizado  em turnos ininterruptos de revezamento."}, "g": "C", "j": "Art. 7º, XVI CF/88: remuneração do serviço extraordinário superior, no mínimo, em 50% à do normal."}, {"id": "994982", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Constitucionais-Penais e Garantias Constitucionais do Processo"], "ano": "2018", "org": "CRB 8º Região", "t": "", "e": "No  que  se  refere  aos  direitos  e  às  garantias  individuais, \nassinale a alternativa correta.", "alt": {"A": "Segundo  o  texto  constitucional,  ninguém  será \nsubmetido  à  tortura  nem  a  tratamento  desumano, \nsalvo em caso de guerra declarada.", "B": "A prática de  terrorismo constitui crime inafiançável e \nimprescritível, sujeito à pena de reclusão, nos termos \nda lei.", "C": "É possível impetrar habeas corpus quando alguém  se \nachar ameaçado de sofrer violência em sua liberdade \nde locomoção, por ilegalidade ou abuso de poder.", "D": "A  Constituição  Federal  de  1988  (CF)  assegura, \nmediante pagamento de taxa, a obtenção de certidões \nem repartições públicas para defesa de direitos.", "E": "São gratuitas as ações de habeas corpus e mandado de \nsegurança."}, "g": "C", "j": "Art. 5º, LXVIII CF/88: conceder-se-á HC sempre que alguém sofrer ou se achar AMEAÇADO de sofrer violência ou coação em sua liberdade de locomoção, por ilegalidade ou abuso de poder."}, {"id": "994981", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2018", "org": "CRB 8º Região", "t": "", "e": "É privativo de brasileiro nato o cargo de", "alt": {"A": "presidente do Senado Federal.", "B": "ministro de Estado.", "C": "deputado federal.", "D": "senador.", "E": "ministro do Superior Tribunal de Justiça (STJ)."}, "g": "A", "j": "Art. 12, §3º CF/88: o cargo de Presidente do Senado Federal é privativo de brasileiro nato."}, {"id": "994980", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2018", "org": "CRB 8º Região", "t": "", "e": "Quanto a direitos políticos, assinale a alternativa correta.", "alt": {"A": "O alistamento eleitoral e o voto são  facultativos para \nos estrangeiros e para os conscritos durante o período \nde serviço militar obrigatório.", "B": "A cassação dos direitos políticos é permitida somente \nnos casos de improbidade administrativa e condenação \ncriminal transitada em julgado.", "C": "Para  concorrer  a  outro  cargo,  o  prefeito  deverá \nrenunciar ao mandato até seis meses antes do pleito.", "D": "Brasileiros  e  estrangeiros  analfabetos  não  podem  se \nalistar como eleitores.", "E": "Para concorrer aos cargos de presidente da República e governador de estado, o candidato deverá ter idade mínima de 35 anos."}, "g": "C", "j": "Art. 14, §6º CF/88: para concorrerem a outros cargos, o Presidente, Governadores e Prefeitos devem renunciar aos respectivos mandatos até 6 meses antes do pleito."}, {"id": "994979", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República"], "ano": "2018", "org": "CRB 8º Região", "t": "", "e": "A respeito dos princípios fundamentais da República, julgue os itens a seguir. I  Todo o poder emana do povo, que o exerce por meio de representantes eleitos ou diretamente, nos termos da Constituição Federal. II  A  cidadania  é  mencionada  no  texto  constitucional como um dos objetivos fundamentais da República. III  O  texto  constitucional  adota  expressamente  a República como forma de Estado. Assinale a alternativa correta.", "alt": {"A": "Apenas o item I está certo.", "B": "Apenas o item II está certo.", "C": "Apenas os itens I e II estão certos.", "D": "Apenas os itens I e III estão certos.", "E": "Apenas os itens II e III estão certos."}, "g": "A", "j": "I correto (art. 1º §único — todo poder emana do povo). II falso (cidadania é FUNDAMENTO art. 1º II, não objetivo). III falso (República é forma de GOVERNO; Federação é forma de Estado)."}, {"id": "910846", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Servidores Públicos"], "ano": "2018", "org": "CRP", "t": "", "e": "Acerca dos servidores públicos, julgue os itens que se\nseguem.\n    I O membro de Poder será remunerado exclusivamente\npor subsídio fixado em parcela única, com acréscimo\nde gratificação e verbas de representação.\n  II A CF assegura aos servidores ocupantes de cargo\npúblico o direito à participação em lucros e resultados.\n  III Os cargos públicos são acessíveis somente aos\nbrasileiros que preencham requisitos legalmente\nestabelecidos, sendo vedada, em qualquer hipótese, a\ncontratação de estrangeiros.\n  IV A CF assegura ao servidor público civil o direito à livre\nassociação sindical.\n    A quantidade de itens certos é igual a", "alt": {"A": "0.", "B": "1.", "C": "2.", "D": "3.", "E": "4."}, "g": "B", "j": "Apenas IV correto (art. 37, VI: direito à livre associação sindical). I falso (subsídio é parcela única, vedado acréscimo); II falso (PLR não para cargo efetivo); III falso (estrangeiros têm acesso na forma da lei). Total: 1."}, {"id": "910845", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2018", "org": "CRP", "t": "", "e": "Maria, brasileira nata, mudou-se para a França em\nrazão do trabalho. Alguns anos depois, casou-se com Pierre\n(francês), com quem teve o filho Pedro (nascido em solo\nfrancês).\n    Considerando esse caso hipotético e as regras constitucionais\nsobre nacionalidade, assinale a alternativa correta.", "alt": {"A": "Não há previsão constitucional para que Pedro alcance\nstatus de brasileiro nato.", "B": "Pedro será brasileiro naturalizado se for\nimediatamente registrado em repartição brasileira\ncompetente.", "C": "Mesmo que Maria estivesse a serviço do Brasil, Pedro\nnão seria brasileiro nato, uma vez que nasceu em\nterritório francês.", "D": "Mesmo nascendo em território estrangeiro e sendo\nfilho de pai francês, Pedro será brasileiro nato caso\nMaria esteja a serviço do Brasil.", "E": "Pedro será brasileiro naturalizado caso se mude para o\nBrasil e escolha, depois de atingida a maioridade, a\nnacionalidade brasileira."}, "g": "D", "j": "Art. 12, I, 'b' CF/88: são natos os nascidos no estrangeiro de pai/mãe brasileira, desde que qualquer deles esteja a serviço da República — independentemente da nacionalidade do outro cônjuge."}, {"id": "910844", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade"], "ano": "2018", "org": "CRP", "t": "", "e": "Com relação à nacionalidade, assinale a alternativa correta.", "alt": {"A": "Com exceção dos casos previstos na CF, a lei não pode\nestabelecer distinção entre brasileiros natos e\nnaturalizados.", "B": "O estrangeiro residente no Brasil há mais de\nquinze anos, sem condenação penal, adquire\nautomaticamente a nacionalidade brasileira.", "C": "O brasileiro naturalizado será extraditado somente na\nhipótese de crime político ou de responsabilidade\npraticado antes da naturalização.", "D": "Embora não conste expressamente da CF, considera-se\na língua portuguesa como idioma oficial da República\nFederativa do Brasil.", "E": "Aos portugueses com residência fixa no País e sem\ncondenação penal serão atribuídos direitos inerentes\nao brasileiro nato."}, "g": "A", "j": "Art. 12, §2º CF/88: a lei não poderá estabelecer distinção entre brasileiros natos e naturalizados, salvo nos casos previstos na própria Constituição."}, {"id": "910843", "d": "direito_constitucional", "a": ["Direitos Políticos", "Direitos da Nacionalidade"], "ano": "2018", "org": "CRP", "t": "", "e": "Nos termos da CF, são privativos de brasileiro nato os cargos\nde", "alt": {"A": "deputado federal.", "B": "senador.", "C": "procurador-geral da República.", "D": "juiz de direito.", "E": "carreira diplomática."}, "g": "E", "j": "Art. 12, §3º, V CF/88: a carreira diplomática é privativa de brasileiro nato."}, {"id": "910842", "d": "direito_constitucional", "a": ["Direitos Sociais"], "ano": "2018", "org": "CRP", "t": "", "e": "No que se refere aos direitos sociais, julgue os itens que se\nseguem.\n    I A moradia e o lazer são direitos sociais expressamente\nprevistos na CF.\n  II A CF assegura à categoria dos trabalhadores\ndomésticos o direito ao décimo terceiro salário, com\nbase na remuneração integral ou no valor da\naposentadoria.\n  III Nos termos da CF, é obrigatória a participação dos\nsindicatos nas negociações coletivas de trabalho.\n  IV O transporte e a assistência aos necessitados são\ndireitos sociais, mas não estão expressamente\nprevistos na CF.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens I, II e III estão certos.", "D": "Apenas os itens I, II e IV estão certos.", "E": "Apenas os itens II, III e IV estão certos."}, "g": "C", "j": "I correto (moradia/lazer no art. 6º). II correto (13º para domésticos após EC 72/2013). III correto (art. 8º, VI). IV falso (transporte foi incluído pela EC 90/2015 e assistência aos desamparados consta no art. 6º)."}, {"id": "910841", "d": "direito_constitucional", "a": ["Direitos Políticos"], "ano": "2018", "org": "CRP", "t": "", "e": "Acerca dos direitos políticos, assinale a alternativa correta.", "alt": {"A": "Podem alistar-se como eleitores os estrangeiros e os\nconscritos, mesmo durante período de serviço militar\nobrigatório.", "B": "Para concorrerem a outros cargos, os prefeitos devem\nrenunciar aos respectivos mandatos até seis meses\nantes do pleito.", "C": "Com provas de corrupção e fraude, pode-se impugnar\no mandato eletivo ante a Justiça Eleitoral no prazo de\n120 dias, contados da diplomação.", "D": "A CF autoriza cassação dos direitos políticos somente\nem hipóteses de condenação criminal e improbidade\nadministrativa.", "E": "Eventual cancelamento da naturalização, ainda que por\nsentença transitada em julgado, não autoriza perda ou\nsuspensão dos direitos políticos."}, "g": "B", "j": "Art. 14, §6º CF/88: para concorrer a outros cargos, prefeitos devem renunciar aos respectivos mandatos até 6 meses antes do pleito."}, {"id": "910840", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Segurança", "Habeas Corpus"], "ano": "2018", "org": "CRP", "t": "", "e": "A respeito de habeas corpus e de mandado de segurança,\njulgue os itens subsequentes.\n    I É possível impetrar habeas corpus quando alguém se\nachar ameaçado de sofrer violência em sua liberdade\nde locomoção, por ilegalidade ou abuso de poder.\n  II O partido político com representação no Congresso\nNacional pode impetrar mandado de segurança\ncoletivo.\n  III O mandado de segurança garante acesso a\ninformações relativas à pessoa do impetrante,\nconstantes de registros ou bancos de dados de\nentidades governamentais.\n  IV São gratuitas as ações de mandado de segurança.\n    Assinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens II e III estão certos.", "C": "Apenas os itens II e IV estão certos.", "D": "Apenas os itens I, II e III estão certos.", "E": "Apenas os itens II, III e IV estão certos."}, "g": "A", "j": "I correto (HC art. 5º LXVIII). II correto (MS coletivo por partido com representação — art. 5º LXX 'a'). III falso (é função do habeas data). IV falso (MS não é gratuito; gratuito é HC e ação popular)."}, {"id": "910839", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2018", "org": "CRP", "t": "", "e": "Com relação aos direitos e às garantias fundamentais,\nassinale a alternativa correta.", "alt": {"A": "Todos podem reunir-se pacificamente em locais\nabertos ao público, desde que autorizados\npreviamente pela autoridade competente.", "B": "A CF proíbe a prestação de assistência religiosa em\nentidades militares de internação coletiva, pois\nconsidera o Estado brasileiro como laico.", "C": "O texto constitucional assegura o direito de petição aos\nPoderes Públicos, com isenção do pagamento de taxa\naos que comprovarem insuficiência de recursos.", "D": "Nos termos da CF, não haverá pena de morte nem de\ncaráter perpétuo, salvo em situações de guerra\ndeclarada.", "E": "Segundo o texto constitucional, o racismo constitui\ncrime inafiançável e imprescritível, sujeito à pena de\nreclusão, nos termos da lei."}, "g": "E", "j": "Art. 5º, XLII CF/88: a prática do racismo constitui crime inafiançável e imprescritível, sujeito à pena de reclusão, nos termos da lei."}, {"id": "910838", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Objetivos Fundamentais da República"], "ano": "2018", "org": "CRP", "t": "", "e": "Nos termos da Constituição Federal de 1988 (CF), a República\nFederativa do Brasil constitui-se em Estado Democrático de\nDireito e tem como fundamento o(a)", "alt": {"A": "cidadania.", "B": "repúdio ao terrorismo.", "C": "defesa da paz.", "D": "autodeterminação dos povos.", "E": "erradicação da pobreza."}, "g": "A", "j": "Art. 1º, II CF/88: a cidadania é fundamento da República. As demais são princípios das relações internacionais (art. 4º) ou objetivos fundamentais (art. 3º)."}, {"id": "910821", "d": "direito_constitucional", "a": ["Processo Legislativo", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Processo Legislativo Ordinário", "Fase Introdutória – Iniciativa de Lei por Parlamentar e Extra-Parlamentar", "Ação Popular"], "ano": "2018", "org": "CRP", "t": "", "e": "De acordo com a CF, julgue os itens subsequentes.\n    I Qualquer cidadão é parte legítima para propor ação\npopular que vise a anular ato lesivo ao patrimônio\npúblico ou de entidade de que o Estado participe, à\nmoralidade administrativa, ao meio ambiente e ao\npatrimônio histórico e cultural, ficando o autor, salvo\ncomprovada má-fé, isento de custas judiciais e do ônus\nda sucumbência.\n  II Qualquer cidadão, partido político, associação ou\nsindicato é parte legítima para, na forma da lei,\ndenunciar irregularidades ou ilegalidades perante o\nTribunal de Contas da União (TCU).\n  III A iniciativa das leis complementares e ordinárias não\ncabe a nenhum cidadão, seja ele brasileiro ou não; ela\né função exclusiva da Câmara dos Deputados, do\nSenado e do presidente da República.\n    Assinale a alternativa correta.", "alt": {"A": "Nenhum item está certo.", "B": "Apenas os itens I e II estão certos.", "C": "Apenas os itens I e III estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Todos os itens estão certos."}, "g": "B", "j": "I correto (art. 5º, LXXIII — ação popular). II correto (art. 74, §2º — qualquer cidadão, partido, associação ou sindicato pode denunciar ao TCU). III falso (art. 61 §2º admite iniciativa popular)."}, {"id": "2815327", "d": "direito_constitucional", "a": ["Organização do Estado – Estados", "Organização Político-Administrativa do Estado"], "ano": "2017", "org": "CONTER", "t": "", "e": "De acordo com a Constituição Federal de 1988 (CF), assinale a alternativa correta no que se refere à competência tributária.", "alt": {"A": "Compete aos municípios instituir impostos sobre importação de produtos estrangeiros.", "B": "Compete aos estados instituir impostos sobre transmissão causa mortis e doação de quaisquer bens ou direitos.", "C": "Compete aos estados instituir impostos sobre propriedade predial e territorial urbana.", "D": "Compete à União instituir impostos sobre propriedade de veículos automotores.", "E": "Compete aos estados instituir impostos sobre propriedade territorial rural."}, "g": "B", "j": "Art. 155, I CF/88: compete aos Estados e ao DF instituir impostos sobre transmissão causa mortis e doação (ITCMD)."}, {"id": "2740654", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2017", "org": "CONTER", "t": "", "e": "O Sistema Tributário é a distribuição da competência\ntributária entre os vários planos do Estado. No Brasil temos\no Sistema Federativo, isto é, a competência tributária está\ndistribuída entre os vários planos de governo: União;\nEstados e Municípios. Entende-se como Competência\nTributária a capacidade, outorgada pelas Fontes\nLegislativas, de legislar sobre tributos. A Constituição\nBrasileira de 1988 estabelece, em seu artigo 145, quais\ntipos de tributos a União, os Estados, o Distrito Federal e os\nMunicípios poderão instituir. O fato é que a realidade\ntributária brasileira é notoriamente complexa, sendo um\ndos componentes do chamado “custo Brasil”. O excesso de\ntributação inviabiliza muitas operações e cabe ao\nadministrador tornar possível, em termos de custos, a\ncontinuidade de determinados produtos e serviços, num\npreço compatível com o que o mercado consumidor deseja\ne pode pagar. Os tributos afetam as empresas das mais\ndiversas formas, variando de acordo com o setor em que\natua e com seu porte. Considerando a incidência tributária\ne seu impacto nas operações da empresa, quais dos\nseguintes itens devem ser considerados na formação de\npreços e margem de lucro? I. O peso dos tributos incidentes sobre as receitas de\nvenda de produtos e serviços.\nII. O peso dos tributos incidentes sobre as importações de\nbens, serviços e tecnologia.\nIII. O peso dos tributos incidentes sobre a folha de\nsalários.\nIV. O peso dos tributos incidentes sobre os bens\npatrimoniais.\nV. O peso dos tributos incidentes sobre o exercício de\ncertas atividades reguladas.\nVI. O peso dos tributos incidentes sobre o lucro.\nVII. A variação da carga tributária em função do local em\nque a empresa estiver instalada.\nEstão corretos:", "alt": {"A": "todos.", "B": "somente seis.", "C": "somente cinco.", "D": "somente quatro.", "E": "somente três."}, "g": "A", "j": "Todos os 7 itens listados (tributos sobre receita, importação, folha, patrimônio, atividades reguladas, lucro e variação geográfica) integram a carga tributária a ser considerada na formação de preços e margens."}, {"id": "2718917", "d": "direito_constitucional", "a": ["Família, Criança, Adolescente e Idoso", "Ordem Social"], "ano": "2017", "org": "CONTER", "t": "", "e": "Com base na CF, assinale a alternativa correta a respeito da família, da criança, do adolescente e do idoso.", "alt": {"A": "Para efeito da proteção do Estado, não é reconhecida a união estável entre o homem e a mulher como entidade familiar.", "B": "Entende-se como entidade familiar a comunidade formada por qualquer dos pais e seus descendentes.", "C": "São penalmente inimputáveis os menores de dezesseis anos de idade.", "D": "Os pais têm o dever de assistir, criar e educar os filhos menores de idade, mas os filhos maiores de idade não têm o dever de ajudar e amparar os pais na velhice, carência ou enfermidade.", "E": "Os programas de amparo aos idosos serão executados preferencialmente em hospitais."}, "g": "B", "j": "Art. 226, §4º CF/88: entende-se também como entidade familiar a comunidade formada por qualquer dos pais e seus descendentes (família monoparental)."}, {"id": "2718916", "d": "direito_constitucional", "a": ["Meio Ambiente", "Ordem Social"], "ano": "2017", "org": "CONTER", "t": "", "e": "No que diz respeito à previsão constitucional do Capítulo VI – do Meio Ambiente, assinale a alternativa correta.", "alt": {"A": "O dever de defender o meio ambiente e preservá-lo cabe ao Poder Público, não cabendo à coletividade essa obrigação.", "B": "Incumbe ao Poder Público definir, em todas as unidades da Federação, espaços territoriais e seus componentes a serem especialmente protegidos, sendo a alteração e a supressão permitidas por meio de portarias e vedada qualquer utilização que comprometa a integridade dos atributos que justifiquem sua proteção.", "C": "As condutas e atividades consideradas como lesivas ao meio ambiente sujeitarão os infratores, pessoas físicas ou jurídicas, apenas a sanções penais, independentemente da obrigação de reparar os danos causados.", "D": "As usinas que operem com reator nuclear deverão ter sua localização definida em lei do Distrito Federal, sem o que não poderão ser instaladas.", "E": "São indisponíveis as terras devolutas ou arrecadadas pelos estados por ações discriminatórias necessárias à proteção dos ecossistemas naturais."}, "g": "E", "j": "Art. 225, §5º CF/88: são indisponíveis as terras devolutas ou arrecadadas pelos Estados, por ações discriminatórias, necessárias à proteção dos ecossistemas naturais."}, {"id": "2718914", "d": "direito_constitucional", "a": ["Ciência, Tecnologia e Comunicação Social", "Ordem Social"], "ano": "2017", "org": "CONTER", "t": "", "e": "A manifestação do pensamento, a criação, a expressão e a informação, sob qualquer forma, processo ou veículo, não sofrerão qualquer restrição (art. 220 da CF). Acerca da comunicação social, assinale a alternativa correta de acordo com a CF.", "alt": {"A": "É permitida toda e qualquer censura de natureza política, ideológica e artística.", "B": "Compete à lei municipal regular as diversões e os espetáculos públicos, cabendo ao Poder Público informar sobre a natureza deles, as faixas etárias a que não se recomendem e os locais e horários em que suas apresentações se mostrem inadequadas.", "C": "A propaganda comercial de tabaco, bebidas alcoólicas, agrotóxicos, medicamentos e terapias estará sujeita a restrições legais, contendo, sempre que necessário, advertência sobre os malefícios decorrentes de seu uso.", "D": "A publicação de veículo impresso de comunicação depende de licença de autoridade.", "E": "Os meios de comunicação social podem, direta ou indiretamente, ser objeto de monopólio ou oligopólio."}, "g": "C", "j": "Art. 220, §4º CF/88: propaganda comercial de tabaco, bebidas alcoólicas, agrotóxicos, medicamentos e terapias está sujeita a restrições legais, com advertência sobre os malefícios."}, {"id": "2718913", "d": "direito_constitucional", "a": ["Ciência, Tecnologia e Comunicação Social", "Ordem Social"], "ano": "2017", "org": "CONTER", "t": "", "e": "A respeito de ciência e tecnologia, assinale a alternativa correta conforme a CF.", "alt": {"A": "A pesquisa tecnológica voltar-se-á preponderantemente para a solução dos problemas brasileiros e para o desenvolvimento do sistema produtivo internacional.", "B": "É obrigatório aos estados e ao Distrito Federal vincular parcela de sua receita orçamentária a entidades públicas de fomento ao ensino e à pesquisa científica e tecnológica.", "C": "Lei municipal disporá sobre as normas gerais do Sistema Nacional de Ciência, Tecnologia e Inovação.", "D": "O mercado interno integra o patrimônio nacional e será incentivado de modo a viabilizar o desenvolvimento cultural e socioeconômico, o bem-estar da população e a autonomia tecnológica do País, nos termos de lei federal.", "E": "O Estado não promoverá e não incentivará o desenvolvimento científico, a pesquisa, a capacitação científica e tecnológica e a inovação."}, "g": "D", "j": "Art. 219 CF/88: o mercado interno integra o patrimônio nacional e será incentivado para viabilizar o desenvolvimento cultural e socioeconômico, o bem-estar e a autonomia tecnológica."}, {"id": "2718912", "d": "direito_constitucional", "a": ["Educação, Cultura e Desporto", "Ordem Social"], "ano": "2017", "org": "CONTER", "t": "", "e": "À luz da CF, assinale a alternativa correta acerca da educação.", "alt": {"A": "As universidades gozam de autonomia didático-científica, administrativa e de gestão financeira e patrimonial e obedecem ao princípio de indissociabilidade entre ensino, pesquisa e extensão.", "B": "O não oferecimento do ensino obrigatório pelo Poder Público, ou sua oferta irregular, não importa responsabilidade da autoridade competente.", "C": "O dever do Estado com a educação é efetivado mediante a garantia de educação infantil, em creche e pré-escola, às crianças de até dez anos de idade.", "D": "O Estado não tem o dever de ofertar ensino noturno regular.", "E": "Não é dever do Estado com a educação a garantia de acesso aos níveis mais elevados do ensino, da pesquisa e da criação artística, segundo a capacidade de cada um."}, "g": "A", "j": "Art. 207 CF/88: as universidades gozam de autonomia didático-científica, administrativa e de gestão financeira/patrimonial, e obedecem ao princípio da indissociabilidade entre ensino, pesquisa e extensão."}, {"id": "2718910", "d": "direito_constitucional", "a": ["Previdência Social", "Ordem Social"], "ano": "2017", "org": "CONTER", "t": "", "e": "De acordo com a CF, compete ao Poder Público, nos termos da lei, organizar a seguridade social, com base no(na)", "alt": {"A": "desigualdade na forma de participação no custeio.", "B": "redutibilidade do valor dos benefícios.", "C": "financiamento de apenas uma fonte.", "D": "caráter democrático e descentralizado da Administração, mediante gestão quadripartite.", "E": "gestão sem a participação dos empregadores."}, "g": "D", "j": "Art. 194, §único, VII CF/88: caráter democrático e descentralizado da administração, mediante gestão quadripartite, com participação de trabalhadores, empregadores, aposentados e Governo."}, {"id": "2718909", "d": "direito_constitucional", "a": ["Partidos Políticos", "Direitos Individuais"], "ano": "2017", "org": "CONTER", "t": "", "e": "Com base na CF, é correto afirmar que", "alt": {"A": "seja proibida a extinção de partidos políticos.", "B": "seja proibido o recebimento de recursos financeiros de entidade ou governo estrangeiros pelos partidos políticos.", "C": "seja permitida a criação de partidos de caráter regional.", "D": "o acesso ao rádio e à televisão pelos partidos políticos devam ser pagos, sem previsão de acesso gratuito.", "E": "os partidos políticos, após adquirirem personalidade jurídica, na forma da lei civil, registrem seus estatutos no Congresso Nacional."}, "g": "B", "j": "Art. 17, II CF/88: é vedado aos partidos políticos o recebimento de recursos financeiros de entidade ou governo estrangeiros, ou subordinação a estes."}, {"id": "2718908", "d": "direito_constitucional", "a": ["Direitos Políticos", "Direitos Individuais"], "ano": "2017", "org": "CONTER", "t": "", "e": "A respeito dos direitos políticos previstos na CF, assinale a alternativa correta.", "alt": {"A": "O alistamento eleitoral e o voto são obrigatórios para os maiores de setenta anos de idade.", "B": "Os conscritos devem, durante o período de serviço militar, alistar-se como eleitores.", "C": "É condição de elegibilidade a idade mínima de trinta anos para senador.", "D": "Para concorrerem a outros cargos, o presidente da República, os governadores de estado e do Distrito Federal e os prefeitos devem renunciar aos respectivos mandatos até seis meses antes do pleito.", "E": "São inelegíveis, no território de jurisdição do titular, o cônjuge e os parentes consanguíneos ou afins, até o terceiro grau ou por adoção, do presidente da República, de governador de estado ou Território, do Distrito Federal, de prefeito ou de quem os haja substituído dentro dos seis meses anteriores ao pleito, salvo se já titular de mandato eletivo e candidato à reeleição."}, "g": "D", "j": "Art. 14, §6º CF/88: para concorrer a outros cargos, PR, Governadores e Prefeitos devem renunciar aos respectivos mandatos até 6 meses antes do pleito."}, {"id": "2718907", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade", "Direitos Individuais"], "ano": "2017", "org": "CONTER", "t": "", "e": "Mia e Vanderlei, ambos de nacionalidade holandesa, estavam de férias, passeando como turistas no Brasil. Nesse período, Mia, que estava grávida, veio a ter um parto em território brasileiro, onde nasceu Anelise. Com base nessa situação hipotética, assinale a alternativa correta.", "alt": {"A": "Anelise será considerada como brasileira naturalizada.", "B": "Anelise não poderá ser considerada como brasileira nata nem naturalizada.", "C": "Anelise será considerada como brasileira nata.", "D": "Anelise só poderia ser considerada como brasileira nata se seus pais estivessem a serviço.", "E": "Anelise só seria considerada como brasileira nata se seus pais fossem portugueses."}, "g": "C", "j": "Art. 12, I, 'a' CF/88: são natos os nascidos no Brasil, ainda que de pais estrangeiros, desde que estes não estejam a serviço de seu país. Anelise nasceu no Brasil de pais holandeses turistas — é nata."}, {"id": "2718906", "d": "direito_constitucional", "a": ["Direitos Individuais"], "ano": "2017", "org": "CONTER", "t": "", "e": "João, proprietário de uma área particular no Brasil, possui algumas dúvidas a respeito do assunto. Nesse caso hipotético, de acordo com o disposto no Capítulo I – Dos Direitos e Deveres Individuais e Coletivos da CF, é correto afirmar que", "alt": {"A": "o direito de João à propriedade seja previsto em leis infraconstitucionais, mas não na CF.", "B": "a propriedade de João não precise de atender sua função social.", "C": "a propriedade de João, caso seja uma pequena propriedade rural, assim definida em lei, trabalhada pela família, poderá ser objeto de penhora para pagamento de débitos decorrentes de sua atividade produtiva.", "D": "a autoridade competente não poderá usar a propriedade de João no caso de iminente perigo público.", "E": "seja previsto na CF que a lei estabelecerá o procedimento para desapropriação da propriedade de João por necessidade ou utilidade pública."}, "g": "E", "j": "Art. 5º, XXIV CF/88: a lei estabelecerá o procedimento para desapropriação por necessidade ou utilidade pública, ou por interesse social, mediante justa e prévia indenização em dinheiro."}, {"id": "2718905", "d": "direito_constitucional", "a": ["Direitos Individuais"], "ano": "2017", "org": "CONTER", "t": "", "e": "Acerca dos direitos e deveres individuais e coletivos previstos na Constituição Federal de 1988 (CF), assinale a alternativa correta.", "alt": {"A": "Ninguém será obrigado a fazer ou deixar de fazer alguma coisa senão em virtude de lei.", "B": "É assegurado direito de resposta superior ao agravo, além de indenização por dano material, moral ou à imagem.", "C": "É livre a manifestação anônima do pensamento.", "D": "É livre a expressão da atividade intelectual, artística, científica e de comunicação, mediante licença.", "E": "Não é assegurada a prestação de assistência religiosa nas entidades civis e militares de internação coletiva."}, "g": "A", "j": "Art. 5º, II CF/88: ninguém será obrigado a fazer ou deixar de fazer alguma coisa senão em virtude de lei (princípio da legalidade)."}, {"id": "1702307", "d": "direito_constitucional", "a": ["Previdência Social", "Ordem Social"], "ano": "2017", "org": "CRF", "t": "", "e": "A respeito das normas constitucionais sobre o regime geral\nde previdência, analise as afirmativas a seguir.\n    I. A gratificação natalina dos aposentados e pensionistas\nterá por base o valor dos proventos do mês de\ndezembro de cada ano.    \nII. É vedada a filiação ao regime geral de previdência\nsocial, na qualidade de segurado facultativo, de pessoa\nparticipante de regime próprio de previdência.\n    III. Todos os salários de contribuição considerados para o\ncálculo de benefício serão devidamente atualizados, na\nforma da lei.\n    IV. É vedada a adoção de requisitos e critérios\ndiferenciados para a concessão de aposentadoria,\nmesmo nos casos de atividades exercidas sob\ncondições especiais que prejudiquem a saúde ou a\nintegridade física.\n    Está correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "II e III, somente.", "C": "II, III e IV, somente.", "D": "I, II, e III, somente.", "E": "todas."}, "g": "D", "j": "I, II e III corretos (arts. 201 §6º, §5º e §3º CF/88). IV falso: o art. 201 §1º admite requisitos diferenciados para atividades em condições especiais que prejudiquem a saúde/integridade física."}, {"id": "1702300", "d": "direito_constitucional", "a": ["Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo"], "ano": "2017", "org": "CRF", "t": "", "e": "Sobre o Presidente da República, assinale a alternativa\nincorreta.", "alt": {"A": "O Presidente será submetido a julgamento perante o\nSTF, nas infrações penais comuns, ou perante o Senado\nFederal, nos crimes de responsabilidade.", "B": "Enquanto não sobrevier sentença condenatória, nas\ninfrações penais comuns, o Presidente da República\nnão estará sujeito a prisão.", "C": "O Presidente ficará suspenso de suas funções, nas\ninfrações penais comuns, se recebida a denúncia pelo\nSupremo Tribunal Federal.", "D": "O Presidente não pode delegar o provimento e a\nextinção de cargos públicos federais a seus Ministros,\npois são atos de competência exclusiva.", "E": "Nos termos da Constituição, compete privativamente\nao Presidente nomear e exonerar Ministros de Estados."}, "g": "D", "j": "D é incorreta: o art. 84 §único CF/88 permite que o PR DELEGUE a Ministros e ao PGR atribuições do art. 84 incisos VI, XII e XXV (primeira parte) — incluindo o provimento de cargos públicos federais conforme regulamento."}, {"id": "1702298", "d": "direito_constitucional", "a": ["Poder Legislativo", "Comissões Parlamentares e Comissões Parlamentares de Inquérito (CPIs)"], "ano": "2017", "org": "CRF", "t": "", "e": "Relativamente às Comissões Parlamentares de Inquérito,\nassinale a alternativa incorreta.", "alt": {"A": "Segundo texto constitucional, as comissões\nparlamentares de inquérito terão poderes de\ninvestigação próprios das autoridades judiciais, além\nde outros previstos nos regimentos das respectivas\nCasas.", "B": "As comissões parlamentares de inquérito podem\nordenar a quebra do sigilo bancário, sempre com\nindicação concreta de fatos específicos e necessidade\nda medida.", "C": "Segundo jurisprudência do Supremo, o investigado\nintimado para depor perante CPI pode permanecer em\nsilêncio, evitando-se a autoincriminação.", "D": "A comissão parlamentar de inquérito é competente\npara expedir decreto de indisponibilidade de bens de\nparticular, consoante jurisprudência do STF.", "E": "De acordo com o STF, há impossibilidade jurídica de CPI\npraticar atos sobre os quais incida a cláusula\nconstitucional de reserva de jurisdição, como a busca e\napreensão domiciliar."}, "g": "D", "j": "D é incorreta: jurisprudência STF veda CPI de decretar indisponibilidade de bens (matéria sujeita à reserva de jurisdição). CPI pode quebrar sigilos bancário/fiscal/dados, mas medidas constritivas patrimoniais são privativas do Judiciário."}, {"id": "1702297", "d": "direito_constitucional", "a": ["Poder Judiciário", "Garantias do Poder Judiciário e de seus Membros"], "ano": "2017", "org": "CRF", "t": "", "e": "Sobre o Poder Judiciário, assinale a alternativa correta.", "alt": {"A": "O CNJ e o Tribunal de Contas da União são órgãos do\nPoder Judiciário, segundo disposição expressa do texto\nconstitucional.", "B": "Aos juízes é vedado exercer advocacia no Juízo ou\nTribunal do qual se afastou, antes de decorridos cinco\nanos do afastamento do cargo por aposentadoria ou\nexoneração.", "C": "Os advogados que ingressam nos tribunais superiores\npelo quinto constitucional adquirem vitaliciedade dois\nanos após efetivo exercício da carreira.", "D": "O Juiz goza de inamovibilidade; contudo, em casos de\ninteresse público, pode ser removido por decisão da\nmaioria absoluta do respectivo Tribunal ou do\nConselho Nacional de Justiça.", "E": "De acordo com o texto constitucional, o STJ é o órgão\ncompetente para processar e julgar, originariamente,\nação direta de inconstitucionalidade de lei ou ato\nnormativo estadual"}, "g": "D", "j": "Art. 95, II CF/88: o juiz goza de inamovibilidade, salvo por motivo de interesse público, pelo voto da maioria absoluta do respectivo tribunal ou do CNJ."}, {"id": "1702296", "d": "direito_constitucional", "a": ["Direitos da Nacionalidade", "Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Individuais", "Direito à Liberdade"], "ano": "2017", "org": "CRF", "t": "", "e": "Com relação aos direitos e garantias fundamentais, analise\nas afirmativas a seguir.    \nI. Segundo texto constitucional, a prática do terrorismo\nconstitui crime inafiançável e imprescritível, sujeito à\npena de reclusão.\n    II. Ao estabelecer que “é livre o exercício de qualquer\ntrabalho ou profissão, atendidas as qualificações\nprofissionais que a lei estabelecer”, a Constituição\ncontempla norma de eficácia limitada.    III. Segundo disposição constitucional, compete ao\nSupremo Tribunal Federal processar e julgar\noriginariamente as ações populares propostas em face\ndo Presidente da República.    \nIV. De acordo com a Constituição, o brasileiro naturalizado\npode ser extraditado em caso de crime comum\npraticado antes da naturalização.    \nEstá correto o que se afirma em:", "alt": {"A": "II e IV, somente.", "B": "II e III, somente.", "C": "I, III e IV, somente.", "D": "II, somente.", "E": "IV, somente."}, "g": "E", "j": "Somente IV correto (art. 5º, LI: naturalizado extraditável por crime comum praticado antes da naturalização). I falso (terrorismo é inafiançável mas não imprescritível); II falso (norma de eficácia CONTIDA); III falso (AP contra PR é da JF de 1ª instância)."}, {"id": "1197925", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República"], "ano": "2017", "org": "IAMSPE", "t": "", "e": "À luz da CF, assinale a alternativa correta a respeito da República Federativa do Brasil.", "alt": {"A": "Todo o poder emana do povo, que o exercerá diretamente, sendo vedado, pela CF, qualquer exercício do poder por meio de representantes.", "B": "O pluralismo político constitui objetivo fundamental da República Federativa do Brasil.", "C": "A República Federativa do Brasil é formada pela união dissolúvel entre os estados, os municípios e o Distrito Federal.", "D": "A República Federativa do Brasil buscará a integração econômica, política, social e cultural dos povos da América Latina, visando à formação de uma comunidade latino-americana de nações.", "E": "A concessão de asilo político constitui objetivo fundamental da República Federativa do Brasil."}, "g": "D", "j": "Art. 4º, parágrafo único CF/88: o Brasil buscará a integração econômica, política, social e cultural dos povos da América Latina, visando à comunidade latino-americana de nações."}, {"id": "1069161", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Ministério Público", "Advocacia Pública", "Advocacia", "Defensoria Pública no Direito Constitucional"], "ano": "2017", "org": "Procon", "t": "", "e": "São funções essenciais à justiça o Ministério Público, a\nAdvocacia e a Defensoria Públicas. Com relação a esse\nassunto, assinale a alternativa correta.", "alt": {"A": "É uma função institucional do Ministério Público\ndefender os interesses das populações indígenas,\nrestando privativamente à Defensoria Pública o dever\nde promover a ação penal pública.", "B": "É exclusiva a legitimação do Ministério Público para\npromover ação civil e penal públicas, visando à\nproteção dos direitos dos consumidores.", "C": "Cabe ao Ministério Público, como instituição\npermanente, a defesa dos interesses sociais, nos quais\nse incluem os direitos difusos e coletivos.", "D": "A Defensoria Pública é responsável pela assistência\njudiciária da União e pela consultoria jurídica dos entes\nfederados, de forma integral e gratuita, em defesa dos\ndireitos humanos.", "E": "A União é representada extrajudicialmente pela\nAdvocacia-Geral da União e judicialmente pela\nDefensoria Pública dos estados, tanto nas causas cíveis\nquanto nas criminais."}, "g": "C", "j": "Art. 127 CF/88: cabe ao MP, instituição permanente, a defesa dos interesses sociais, incluindo direitos difusos e coletivos (art. 129, III: ação civil pública para proteção desses interesses)."}, {"id": "961223", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Fundamentos da República", "Objetivos Fundamentais da República", "Princípios de Direito Constitucional Internacional"], "ano": "2017", "org": "CRBio", "t": "", "e": "Com relação aos Princípios Fundamentais estabelecidos na\nConstituição Federal, assinale a alternativa correta.", "alt": {"A": "Os valores sociais do trabalho e da livre-iniciativa são\nprincípios que regem as relações internacionais do\nBrasil.", "B": "Segundo o texto constitucional, o repúdio ao\nterrorismo é um dos objetivos fundamentais da\nRepública.", "C": "Nos termos da Constituição, os Poderes Executivo e\nLegislativo são autônomos, mas dependentes entre si.", "D": "O Brasil buscará a integração econômica, política,\nsocial e cultural dos povos da América Latina, visando à\nformação de uma comunidade latino-americana de\nnações.", "E": "São poderes da União, independentes e harmônicos\nentre si, o Legislativo, o Executivo, o Judiciário e o\nModerador."}, "g": "D", "j": "Art. 4º, parágrafo único CF/88: integração latino-americana visando à formação de comunidade latino-americana de nações."}, {"id": "961221", "d": "direito_constitucional", "a": ["Poder Legislativo", "Congresso Nacional", "Câmara dos Deputados", "Senado Federal"], "ano": "2017", "org": "CRBio", "t": "", "e": "Sobre o Poder Legislativo, assinale a alternativa correta.", "alt": {"A": "Nos termos da Constituição, a Câmara dos Deputados\ncompõe-se de representantes do povo, eleitos em cada\nEstado pelo princípio majoritário.", "B": "O Senado Federal é composto por representantes do\npovo, assim como a Câmara dos Deputados é\ncomposta por representantes dos Estados.", "C": "De acordo com o texto constitucional, cada Estado e o\nDistrito Federal elegerão três Senadores, com mandato\nde quatro anos.", "D": "Compete privativamente ao Congresso Nacional, por\ndois terços de seus membros, autorizar a instauração\nde processo contra o Presidente e o Vice-Presidente da\nRepública.", "E": "Salvo disposição constitucional em contrário, as\ndeliberações de cada Casa do Congresso Nacional\nserão tomadas por maioria dos votos, presente a\nmaioria absoluta de seus membros."}, "g": "E", "j": "Art. 47 CF/88: salvo disposição constitucional em contrário, as deliberações de cada Casa e suas Comissões serão tomadas por maioria dos votos, presente a maioria absoluta de seus membros."}, {"id": "961220", "d": "direito_constitucional", "a": ["Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo"], "ano": "2017", "org": "CRBio", "t": "", "e": "Considere situação hipotética em que o Presidente da\nRepública renuncia ao cargo no início do mandato.\nAssumindo o Vice-Presidente, há processo de impeachment\nque reconhece a existência de crime de responsabilidade.\nConsiderando que a vacância de ambos os cargos ocorreu\nno primeiro ano do período presidencial, assinale a\nalternativa correta.", "alt": {"A": "Na hipótese do enunciado, haverá eleição indireta para\nambos os cargos no prazo de 30 dias depois de aberta\na última vaga.", "B": "Na hipótese do enunciado, competirá ao Congresso\nNacional eleger o Presidente da República, no prazo de\n30 dias.", "C": "Vagando os cargos de Presidente e Vice-Presidente da\nRepública, haverá eleição 90 dias depois de aberta a\núltima vaga.", "D": "Na situação narrada, assumirá o Presidente do Senado\nFederal até o final do mandato.", "E": "Diante da hipótese narrada, assumirá definitivamente\no Presidente da Câmara dos Deputados."}, "g": "C", "j": "Art. 81, §1º CF/88: vagando os cargos de PR e VP nos dois primeiros anos do mandato, far-se-á eleição direta 90 dias depois de aberta a última vaga."}, {"id": "961219", "d": "direito_constitucional", "a": ["Organização do Estado – Estados", "Organização do Estado – Municípios", "Organização Político-Administrativa do Estado", "O Federalismo Brasileiro"], "ano": "2017", "org": "CRBio", "t": "", "e": "Considerando as disposições da Constituição Federal sobre\norganização político-administrativa, assinale a alternativa\nincorreta.", "alt": {"A": "De acordo com o texto constitucional, é vedado à\nUnião criar distinções entre brasileiros ou preferências\nentre eles.", "B": "Os Estados podem desmembrar-se para formação de\nnovos Estados ou Territórios Federais mediante\naprovação da população interessada e do Congresso\nNacional.", "C": "A criação e o desmembramento de Municípios\ndemandam edição de lei estadual e elaboração de\nEstudos de Viabilidade Municipal, mas dispensam\nconsulta à população.", "D": "É vedado à União estabelecer cultos religiosos ou\nmanter com eles e seus representantes relações de\ndependência ou aliança, ressalvada, na forma da lei, a\ncolaboração de interesse público.", "E": "Nos termos da Constituição, é defeso à União e aos\nEstados recusar fé aos documentos públicos."}, "g": "C", "j": "C é incorreta: o art. 18 §4º CF/88 exige consulta prévia mediante plebiscito para criação, fusão, desmembramento ou incorporação de Municípios."}, {"id": "961218", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Habeas Corpus"], "ano": "2017", "org": "CRBio", "t": "", "e": "Nos termos da Constituição Federal, sempre que alguém\nsofrer ou se achar ameaçado de sofrer violência ou coação\nem sua liberdade de locomoção, por ilegalidade, poderá\nimpetrar:", "alt": {"A": "habeas data.", "B": "mandado de segurança.", "C": "habeas corpus.", "D": "mandado de injunção.", "E": "ação popular."}, "g": "C", "j": "Art. 5º, LXVIII CF/88: conceder-se-á HC sempre que alguém sofrer ou se achar ameaçado de sofrer violência ou coação em sua liberdade de locomoção, por ilegalidade ou abuso de poder."}, {"id": "961217", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Constitucionais-Penais e Garantias Constitucionais do Processo", "Direitos Individuais", "Direito à Liberdade"], "ano": "2017", "org": "CRBio", "t": "", "e": "Com relação aos direitos e às garantias fundamentais\nprevistos na Constituição Federal, analise as afirmativas a\nseguir.\nI. A todos é assegurado, após o pagamento das taxas\npertinentes, o direito de petição aos Poderes Públicos\nem defesa de direitos ou contra abuso de Poder.\nII. Segundo previsão expressa do texto constitucional,\npodem ser extraditados os brasileiros e os estrangeiros\nque cometerem crimes políticos ou de opinião.\nIII. De acordo com a literalidade da Constituição, são\nvedadas, em qualquer hipótese, penas de morte ou de\ntrabalho forçado.\nIV. Todos podem reunir-se pacificamente em locais\nabertos ao público, desde que não frustrem outra\nreunião anteriormente convocada para o mesmo local,\nsendo apenas exigido prévio aviso à autoridade\ncompetente.\nEstá correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "I e III, somente.", "C": "II e IV, somente.", "D": "IV, somente.", "E": "I, III e IV, somente."}, "g": "D", "j": "Somente IV correto (art. 5º, XVI — reunião pacífica com prévio aviso). I falso (direito de petição é gratuito); II falso (brasileiros natos não são extraditáveis); III falso (admite-se pena de morte em caso de guerra declarada)."}, {"id": "961216", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Fundamentos da República"], "ano": "2017", "org": "CRBio", "t": "", "e": "Segundo o texto constitucional, a República Federativa do\nBrasil constitui-se em Estado Democrático de Direito e tem\ncomo um de seus fundamentos:", "alt": {"A": "o pluralismo político.", "B": "a autodeterminação dos povos.", "C": "a redução das desigualdades sociais.", "D": "a erradicação da pobreza.", "E": "a defesa da paz."}, "g": "A", "j": "Art. 1º, V CF/88: o pluralismo político é fundamento da República Federativa do Brasil."}, {"id": "959820", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Disposições Gerais na Administração Pública"], "ano": "2017", "org": "CRF", "t": "", "e": "Tendo em vista o disposto no art. 37 da Constituição\nFederal de 1988, analise as afirmativas a seguir.\nI. Os atos de improbidade administrativa importarão a\nsuspensão dos direitos políticos, a perda da função\npública, a indisponibilidade dos bens e o ressarcimento\nao erário, na forma e gradação previstas em lei, sem\nprejuízo da ação penal cabível.II. A lei estabelecerá os prazos de prescrição para ilícitos\npraticados por qualquer agente, servidor ou não, que\ncausem prejuízos ao erário, ressalvadas as respectivas\nações de ressarcimento.\nIII. As pessoas jurídicas de direito público e as de direito\nprivado prestadoras de serviços públicos responderão\npelos danos que seus agentes, nessa qualidade,\ncausarem a terceiros, assegurado o direito de regresso\ncontra o responsável nos casos de dolo ou culpa.\nIV. A lei disporá sobre os requisitos e as restrições ao\nocupante de cargo ou emprego da administração\ndireta e indireta que possibilite o acesso a informações\nprivilegiadas.\nPode-se afirmar que:", "alt": {"A": "todas estão corretas.", "B": "somente uma está correta.", "C": "somente duas estão corretas", "D": "somente três estão corretas.", "E": "todas estão incorretas."}, "g": "A", "j": "Todas as 4 afirmativas estão corretas (art. 37 §§ 4º, 5º, 6º e 7º CF/88 — improbidade, prescrição, responsabilidade civil objetiva e restrições a acesso a informações privilegiadas)."}, {"id": "865507", "d": "direito_constitucional", "a": ["Poder Legislativo", "Supremo Tribunal Federal", "Poder Executivo", "Organização do Poder Judiciário", "Senado Federal", "Imunidade, Crimes Comuns, Crimes de Responsabilidade (Lei nº 1.079 de 1950) e Impeachment"], "ano": "2017", "org": "CONTER", "t": "", "e": "Nos termos da Constituição, os Ministros do Supremo\nTribunal Federal, nos casos de crime de responsabilidade,\nserão julgados pelo(a):", "alt": {"A": "Conselho Nacional de Justiça.", "B": "Plenário do Supremo Tribunal Federal.", "C": "Câmara dos Deputados.", "D": "Senado Federal.", "E": "Superior Tribunal de Justiça."}, "g": "D", "j": "Art. 52, II CF/88: compete privativamente ao Senado Federal processar e julgar os Ministros do STF, membros do CNJ/CNMP, PGR e AGU nos crimes de responsabilidade."}, {"id": "865506", "d": "direito_constitucional", "a": ["Conselho Nacional de Justiça", "Organização do Poder Judiciário"], "ano": "2017", "org": "CONTER", "t": "", "e": "Sobre o Conselho Nacional de Justiça, analise as afirmativas\na seguir.\nI. O Conselho Nacional de Justiça pode rever, de ofício ou\nmediante provocação, os processos disciplinares de\njuízes e membros de tribunais julgados há menos de\num ano.\nII. Compete ao Conselho Nacional de Justiça o controle da\natuação administrativa e financeira do Poder Judiciário\ne do cumprimento dos deveres funcionais dos juízes.\nIII. O Conselho Nacional de Justiça tem em sua\ncomposição dois advogados, indicados pelo Conselho\nFederal da Ordem dos Advogados do Brasil.\nIV. Compete ao Conselho Nacional de Justiça, entre outras\natribuições, apreciar a legalidade dos atos\nadministrativos e jurisdicionais praticados por\nmembros do Poder Judiciário, podendo desconstituí-\nlos para exato cumprimento da lei.\nEstá correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "I, II e III, somente.", "C": "III e IV, somente.", "D": "II, III e IV, somente.", "E": "todas."}, "g": "B", "j": "I, II e III corretos (art. 103-B). IV falso: o CNJ pode rever atos administrativos do Judiciário, mas NÃO atos jurisdicionais (Súmula 568 STJ / jurisprudência STF)."}, {"id": "865505", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2017", "org": "CONTER", "t": "", "e": "Com relação ao Controle de Constitucionalidade, assinale a\nalternativa correta.", "alt": {"A": "O controle de constitucionalidade preventivo será\nexercido exclusivamente pelo Congresso Nacional por\nmeio de Comissões de Constituição e Justiça.", "B": "Mesmo com prévia declaração de\ninconstitucionalidade da lei pelo Pleno do STF, os\ntribunais locais devem obedecer à cláusula de reserva\nde plenário no exercício de controle de difuso.", "C": "O controle preventivo não pode ser realizado pelo\nPoder Judiciário. Deve ser feito apenas pelos Poderes\nExecutivo e Legislativo durante a fase de elaboração da\nlei.", "D": "Órgão fracionário de Tribunal não pode declarar a\ninconstitucionalidade de lei, mas pode afastar a sua\nincidência, sem violar a cláusula de reserva de plenário.", "E": "Nos termos da jurisprudência do STF, não há\nnecessidade de pedido das partes para que haja o\ndescolamento do incidente de inconstitucionalidade\npara o Pleno do tribunal."}, "g": "E", "j": "Jurisprudência STF: o órgão fracionário pode suscitar de ofício o incidente de inconstitucionalidade, encaminhando ao Pleno/órgão especial, sem necessidade de pedido das partes."}, {"id": "865467", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Finanças Públicas – Orçamento"], "ano": "2017", "org": "CONTER", "t": "", "e": "Nos termos das disposições orçamentárias constantes da\nConstituição Federal de 1988 (CF), é vedado", "alt": {"A": "contrair empréstimos que excedam o montante dos\ninvestimentos.", "B": "abrir créditos extraordinários sem indicação dos\nrecursos correspondentes.", "C": "vincular contribuição a órgão, a fundo ou à despesa.", "D": "iniciar investimento circunscrito ao exercício financeiro\nsem prévia inclusão no plano plurianual (PPA).", "E": "transferir recursos de uma modalidade de aplicação\npara outra sem prévia autorização legislativa."}, "g": "A", "j": "Art. 167, III CF/88: é vedada a realização de operações de crédito que excedam o montante das despesas de capital (regra de ouro orçamentária)."}, {"id": "2826339", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Individuais"], "ano": "2016", "org": "CREMAM", "t": "", "e": "Nos termos da Constituição Federal de 1988, conceder-se-á mandado de injunção sempre que a falta de norma regulamentadora tornar inviável o exercício de direitos e liberdades constitucionais e das prerrogativas inerentes à nacionalidade, à soberania e à cidadania. Com relação ao tema, nos termos do próprio texto constitucional e da jurisprudência do Supremo Tribunal Federal, assinale a alternativa que não está correta.", "alt": {"A": "O mandado de injunção poderá ser ajuizado por qualquer pessoa cujo exercício de um direito, liberdade ou prerrogativa constitucional esteja sendo inviabilizado por falta de norma reguladora da Constituição Federal.", "B": "Apesar da ausência de previsão expressa da Constituição Federal, o Supremo Tribunal Federal já se manifestou pela possibilidade de mandado de injunção coletivo.", "C": "O sujeito passivo no mandado de injunção será somente a pessoa estatal. Os particulares não possuem legitimidade passiva ad causam, pois não lhes compete o dever de emanar as normas reputadas essenciais ao exercício do direito vindicado pelos impetrantes.", "D": "Se a omissão for legislativa federal, o mandado de injunção deverá ser ajuizado em face do Congresso Nacional, mesmo se a iniciativa da lei for privativa do Presidente da República.", "E": "Compete ao Supremo Tribunal Federal processar e julgar, originariamente, o mandado de injunção, quando a elaboração da norma regulamentadora for atribuição do Tribunal de Contas da União."}, "g": "D", "j": "D é incorreta: quando a omissão recair sobre lei de iniciativa privativa do PR, o MI deve ser ajuizado contra o PR — autor da iniciativa — e não contra o Congresso Nacional."}, {"id": "2826336", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Individuais"], "ano": "2016", "org": "CREMAM", "t": "", "e": "Nos termos da Constituição Federal de 1988, podem impetrar mandado de segurança coletivo: I. Partido político com representação no Congresso Nacional. II. Entidade de classe ou associação legalmente constituída e em funcionamento há pelo menos um ano. III. Governador de Estado ou do Distrito Federal. IV. Procurador-Geral da República. Está correto o que se afirma em:", "alt": {"A": "II e III, somente.", "B": "III e IV, somente.", "C": "I e II, somente.", "D": "I e III, somente.", "E": "II e IV, somente."}, "g": "C", "j": "Art. 5º, LXX CF/88: MS coletivo pode ser impetrado por partido político com representação no Congresso Nacional (I) e por organização sindical/entidade de classe/associação >1 ano (II)."}, {"id": "2826335", "d": "direito_constitucional", "a": ["Disposições Gerais no Poder Judiciário", "Organização dos Poderes", "Poder Judiciário"], "ano": "2016", "org": "CREMAM", "t": "", "e": "“Para exercício de tão importantes missões constitucionais, faz-se necessária a existência de certas garantias, que possibilitem a aplicação dos princípios basilares do Direito Constitucional [...]. As garantias conferidas aos membros do Poder Judiciário têm assim como condão conferir à instituição a necessária independência para o exercício da Jurisdição, resguardando-a das pressões do Legislativo e do Executivo”. (Alexandre de Moraes. Direito Constitucional, p. 498.) Considerando o texto apresentado, sobre as garantias do Poder Judiciário, assinale a alternativa que não está correta.", "alt": {"A": "Os juízes gozam de vitaliciedade, que, no primeiro grau, só será adquirida após o chamado estágio probatório, ou seja, após dois anos de efetivo exercício da carreira.", "B": "Os advogados e membros do Ministério Público que ingressam nos Tribunais Estaduais e Federais pelo quinto constitucional adquirem vitaliciedade imediatamente no momento da posse.", "C": "A despeito da garantia da vitaliciedade, a própria Constituição Federal prevê a responsabilização política dos Ministros do Supremo Tribunal Federal em caso de infração político-administrativa (impeachment).", "D": "O juiz somente poderá ser removido ou promovido por iniciativa própria, salvo por motivo de interesse público, pelo voto da maioria absoluta do respectivo tribunal ou do Conselho Nacional de Justiça, assegurada ampla defesa.", "E": "Os juízes militares não gozam da garantia da inamovibilidade."}, "g": "E", "j": "E é incorreta: juízes militares (togados da Justiça Militar) gozam da garantia de inamovibilidade como qualquer outro magistrado (art. 95, II CF/88)."}, {"id": "2826334", "d": "direito_constitucional", "a": ["Poder Legislativo", "Organização dos Poderes"], "ano": "2016", "org": "CREMAM", "t": "", "e": "Considere a proposição I e a razão II a seguir. I. Uma lei ordinária, decorrente de projeto de lei apresentado por deputado federal, aprovada para majoração do salário do funcionalismo público federal, apresentará vício formal subjetivo de inconstitucionalidade. PORQUE II. Nos termos da Constituição Federal, as leis que disponham sobre criação de cargos públicos na administração direta e autárquica ou aumento de sua remuneração, são de iniciativa privativa do Presidente da República. Assinale a alternativa correta.", "alt": {"A": "A proposição é verdadeira, mas a razão é falsa.", "B": "A proposição é falsa, mas a razão é verdadeira.", "C": "A proposição e a razão são falsas.", "D": "A proposição e a razão são verdadeiras, e a razão justifica a proposição.", "E": "A proposição e razão são verdadeiras, mas a razão não justifica a proposição."}, "g": "D", "j": "Proposição e razão verdadeiras, com a razão justificando a proposição. Art. 61, §1º, II, 'a' CF/88: iniciativa privativa do PR sobre criação de cargos públicos e aumento de remuneração — projeto de deputado padece de vício formal subjetivo."}, {"id": "2826333", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade"], "ano": "2016", "org": "CREMAM", "t": "", "e": "Analise as afirmativas a seguir, relacionadas ao controle de constitucionalidade. I. O Presidente da República poderá vetar o projeto de emenda constitucional aprovado pelo Congresso Nacional, realizando verdadeiro controle preventivo de constitucionalidade. II. O Congresso Nacional pode rejeitar medida provisória, com base em inconstitucionalidade apontada no parecer da comissão temporária mista, exercendo, assim, controle repressivo de constitucionalidade. III. Com relação à legitimidade para propositura de ação direta de inconstitucionalidade, enquanto se presume de forma absoluta a pertinência temática para o Presidente da República, exige-se prova da pertinência por parte do Conselho Federal da Ordem dos Advogados do Brasil. Está correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "II e III, somente.", "C": "II, somente.", "D": "todas.", "E": "nenhuma."}, "g": "C", "j": "Somente II correto. I falso (PEC não está sujeita a sanção/veto do PR). III falso (Conselho Federal da OAB é legitimado universal — presunção absoluta de pertinência temática)."}, {"id": "2826284", "d": "direito_constitucional", "a": ["Organização dos Poderes", "Poder Executivo"], "ano": "2016", "org": "CREMAM", "t": "", "e": "No campo do Direito Constitucional, no capítulo referente ao Poder Executivo, a doutrina e jurisprudência tem entendido o seguinte (assinale a alternativa correta):", "alt": {"A": "a Constituição Federal exige alguns requisitos para a candidatura aos cargos de Presidente e Vice-presidente da República, dentre os quais, ser brasileiro nato ou naturalizado e ter mais de 38 anos.", "B": "com relação ao processo dos crimes de responsabilidade, a Constituição Federal estabelece que, admitida a acusação contra o Presidente da República, por dois terços da Câmara, será ele submetido a julgamento perante o Supremo Tribunal Federal.", "C": "nos crimes comuns e nos crimes de responsabilidade, o Presidente da República será processado e julgado pelo Supremo Tribunal Federal depois que a Câmara dos Deputados declarar procedente a acusação.", "D": "o Presidente do Senado Federal sucederá definitivamente o Presidente da República em caso de vacância permanente do cargo.", "E": "o Presidente da República ficará suspenso de suas funções, nos crimes de responsabilidade, após a instauração do processo pelo Senado Federal."}, "g": "E", "j": "Art. 86, §1º, II CF/88: o PR ficará suspenso de suas funções nos crimes de responsabilidade após a instauração do processo pelo Senado Federal."}, {"id": "2826282", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2016", "org": "CREMAM", "t": "", "e": "Sobre o arranjo do federalismo brasileiro na Constituição de 1988, assinale a alternativa incorreta.", "alt": {"A": "A organização político-administrativa da República Federativa do Brasil compreende a União, os Estados, o Distrito Federal e os Municípios.", "B": "O ordenamento jurídico brasileiro não contempla o direito de secessão. Qualquer tentativa de secessão do Estado-membro permitirá a decretação de intervenção federal.", "C": "De acordo com a doutrina majoritária, a Constituição Federal de 1988 alçou o município a entidade federativa, tratamento que não dispõe de correspondência em nenhuma das constituições anteriores.", "D": "Nos termos da Constituição de 1988, não é possível a criação de novo Estado ou modificação territorial de Estado existente.", "E": "Os territórios Federais integram a União, e sua criação; transformação em Estado ou reintegração ao Estado de origem serão reguladas em lei complementar."}, "g": "D", "j": "D é incorreta: o art. 18, §3º CF/88 expressamente permite a criação de novos Estados ou modificação territorial mediante consulta plebiscitária e aprovação por lei complementar."}, {"id": "2762145", "d": "direito_constitucional", "a": [], "ano": "2016", "org": "CRP", "t": "As questões 37 e 38 referem-se ao Estatuto da Criança e do Adolescente (ECA).", "e": "É proibida a venda à criança ou ao adolescente (Capítulo II, Seção II – Dos Produtos e Serviços, art. 81) de: I. armas e munições; II. bebidas alcoólicas; III. produtos cujos componentes possam causar dependência física ou psíquica ainda por utilização indevida; IV. bilhetes lotéricos e equivalentes; V. explosivos. Está correto o que se apresenta em:", "alt": {"A": "somente uma um item.", "B": "somente dois dos itens.", "C": "somente três dos itens.", "D": "somente quatro dos itens.", "E": "todos os itens."}, "g": "E", "j": "Art. 81 ECA: são proibidos para criança/adolescente armas/munições, bebidas alcoólicas, produtos que causem dependência, bilhetes lotéricos e fogos de estampido/artifício, fitas/revistas inadequadas. Todos os 5 itens estão proibidos."}, {"id": "2762144", "d": "direito_constitucional", "a": [], "ano": "2016", "org": "CRP", "t": "", "e": "São medidas aplicáveis aos pais ou ao responsável (Capítulo V, Título IV, art. 129), exceto:", "alt": {"A": "pagamento de multa no valor de 30% do salário mínimo brasileiro.", "B": "encaminhamento a tratamento psicológico.", "C": "advertência.", "D": "perda da guarda.", "E": "destituição da tutela."}, "g": "A", "j": "Art. 129 ECA lista: encaminhamento a programas oficiais, inclusão em programas de auxílio à família, encaminhamento a tratamento, obrigação de matricular o filho, advertência, perda da guarda, destituição da tutela, suspensão/destituição do poder familiar. Multa de 30% não consta."}, {"id": "1144009", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Princípios da Administração Pública"], "ano": "2016", "org": "CRO", "t": "", "e": "As Avaliações Periódicas de Desempenho, que geram a\nestabilidade flexível do servidor, e o Contrato de Gestão\nsão exemplos de instrumentos utilizados pela\nAdministração Pública Gerencial que surgiu com o\nacréscimo de mais um princípio à CF/88 (não previsto no\ntexto original) através da Emenda Constitucional nº 19/98,\ntratando da Reforma Administrativa do Estado. Implantava-se, então, uma nova cultura no âmbito interno da\nAdministração Pública. A que princípio nos referimos?", "alt": {"A": "Princípio da Razoabilidade", "B": "Princípio da Licitação.", "C": "Princípio da Eficiência.", "D": "Princípio da Responsabilidade da Administração.", "E": "Princípio da Participação."}, "g": "C", "j": "EC 19/1998 (Reforma Administrativa): acrescentou o princípio da EFICIÊNCIA ao art. 37 caput da CF/88, originando os instrumentos da Administração Pública Gerencial."}, {"id": "808836", "d": "direito_constitucional", "a": ["Administração Pública – Disposições Gerais e Servidores Públicos", "Servidores Públicos"], "ano": "2016", "org": "CRO", "t": "", "e": "O artigo 40 da Constituição da República dispõe que “aos\nservidores titulares de cargos efetivos da União, dos\nEstados, do Distrito Federal e dos Municípios, incluídas suas\nautarquias e fundações, é assegurado regime de\nprevidência de caráter contributivo e solidário, mediante\ncontribuição do respectivo ente público, dos servidores\nativos e inativos e dos pensionistas, observados critérios\nque preservem o equilíbrio financeiro e atuarial e o\ndisposto neste artigo”.\nAssinale a alternativa incorreta.", "alt": {"A": "A concessão da aposentadoria é materializada por\nmeio de um ato administrativo vinculado, emanado\npelo Estado no exercício de suas funções, tendo por\nfinalidade reconhecer uma situação jurídica subjetiva\ndo servidor. No contexto do Estado Social, é ato que\nemana do Poder Público em sua função típica, de\nforma vinculada, reconhecendo o direito do\nbeneficiário.", "B": "O ato de aposentadoria, em verdade, não é uma\nconcessão do Estado, mas um direito que é assegurado\nao agente público, formalizado através de um processo\nde reconhecimento de sua aquisição pelo interessado.\nSob esse prisma, a aposentadoria visa garantir os\nrecursos financeiros indispensáveis ao beneficiário, de\nnatureza alimentar, quando este já não tenha\ncondições de obtê-los por conta própria.", "C": "A aposentadoria é compulsória em razão do\nimplemento da idade limite, ou seja, setenta anos, sem\ndistinção entre homem e mulher.", "D": "A aposentadoria é voluntária desde que cumprido o\ntempo mínimo de dez anos de efetivo exercício no\nserviço público e cinco anos no cargo efetivo em que se\ndará a aposentadoria, observada a legislação existente\nà época da aposentadoria, quanto aos limites mínimos\nde idade e de contribuição, tanto para homem quanto\npara mulher.", "E": "É vedada a percepção simultânea de proventos de\naposentadoria com remuneração de cargo, emprego\nou função pública, excetos os provenientes de cargos\nacumuláveis na forma da Constituição, os cargos\neletivos e os cargos em comissão declarados em lei de\nlivre nomeação e exoneração."}, "g": "C", "j": "C é incorreta: a aposentadoria compulsória dos servidores ocorre aos 75 anos (LC 152/2015), não aos 70."}, {"id": "695592", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2016", "org": "CRO", "t": "", "e": "[...] Tudo indica, portanto, que a jurisprudência do Supremo\nTribunal Federal, sem sombra de dúvidas, tem de ser\nrevisitada criticamente. [...] assim, a premente necessidade\nde se dar efetividade à proteção dos direitos humanos nos\nplanos interno e internacional torna imperiosa uma\nmudança de posição quanto ao papel dos tratados\ninternacionais sobre direitos na ordem jurídica nacional.\n  (Supremo Tribunal Federal, RE 466.343)\n  Considerando o texto acima indicado, bem como o\nposicionamento jurisprudencial do Supremo Tribunal\nFederal sobre os tratados internacionais de Direitos\nHumanos, analise as afirmativas a seguir.   I. Todos os tratados internacionais de direitos humanos,\nindependentemente do quórum de aprovação, são\nmaterialmente e formalmente constitucionais e\nintegram o bloco de constitucionalidade.\n  II. Os tratados internacionais sobre direitos humanos\nratificados anteriormente à Emenda Constitucional\nnº 45/2004 têm hierarquia infraconstitucional, mas\nsupralegal.\n  III. Os tratados internacionais sobre direitos humanos,\naprovados nas duas Casas do Congresso Nacional, em\ndois turnos, por três quintos dos votos dos respectivos\nmembros, são equivalentes à emenda constitucional.  \nIV. Os tratados internacionais sobre direitos humanos\nratificados pelo Brasil antes da Emenda Constitucional\napresentam a mesma hierarquia de lei federal.\n  É correto o que se afirma em:", "alt": {"A": "II e III, somente.", "B": "I e IV, somente.", "C": "I e II, somente.", "D": "III, somente.", "E": "II, somente."}, "g": "A", "j": "II correto (tratados pré-EC 45 = supralegais infraconstitucionais, conforme STF RE 466.343). III correto (art. 5º §3º — equivalência à EC). I e IV falsos."}, {"id": "695591", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Mandado de Segurança"], "ano": "2016", "org": "CRO", "t": "", "e": "[...] conceder-se-á mandado de segurança para proteger\ndireito líquido e certo, não amparado por habeas corpus ou\nhabeas data, quando o responsável pela ilegalidade ou\nabuso de poder for autoridade pública ou agente de pessoa\njurídica no exercício de atribuições do Poder Público.\n  (Constituição Federal de 1988)  \n\nConsiderando o texto constitucional acima indicado, bem\ncomo as considerações doutrinárias sobre o aludido\nremédio constitucional, assinale a alternativa incorreta.", "alt": {"A": "O mandado de segurança poderá ser repressivo de\numa ilegalidade já cometida; ou preventivo, quando o\nimpetrante demonstrar justo receio de sofrer uma\nviolação de direito líquido e certo por parte da\nautoridade impetrada.", "B": "O particular não está obrigado a exaurir a via\nadministrativa para utilizar-se do mandado de\nsegurança, afinal o Judiciário não pode se furtar do\nexame de qualquer lesão de direito.", "C": "Nos termos da jurisprudência do Supremo Tribunal\nFederal, o pedido de reconsideração na via\nadministrativa interrompe o prazo para o mandado de\nsegurança.", "D": "De acordo com a doutrina majoritária, e jurisprudência\ndo Supremo Tribunal Federal, o mandado de segurança\nobserva prazo decadencial de 120 dias, contados a\npartir da data em que o interessado tiver\nconhecimento do ato a ser impugnado.", "E": "Nos termos da jurisprudência do Superior Tribunal de\nJustiça, não cabe condenação em honorários de\nadvogado na ação de mandado de segurança."}, "g": "C", "j": "C é incorreta: jurisprudência STF é firme no sentido de que pedido de reconsideração na via administrativa NÃO interrompe nem suspende o prazo decadencial do mandado de segurança (Súmula 430 STF)."}, {"id": "695590", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2016", "org": "CRO", "t": "", "e": "Considerando o procedimento previsto na Constituição\nFederal para alteração das normas constitucionais, assinale\na alternativa incorreta.", "alt": {"A": "O legislador constituinte de 1988 consignou a\npossibilidade de alteração das normas constitucionais,\nestabelecendo um processo legislativo especial e mais\ndificultoso que o ordinário. Ele o fez com os olhos\nvoltados para a ideia de supremacia da ordem\nconstitucional.", "B": "Nos termos da Constituição Federal de 1988, a\nproposta tendente a abolir direitos e garantias\nindividuais não pode ser objeto de deliberação. A\naludida determinação constitucional, como não se\nrefere apenas ao rol do artigo 5º, resguarda um\nconjunto mais amplo de direitos constitucionais de\ncaráter individual.", "C": "Atualmente, para limitar direitos inerentes ao exercício\nda democracia representativa, necessária seria a\nedição de emenda constitucional revogando um dos\nincisos do § 4º, do artigo 60 da Constituição Federal\n(dispositivo constitucional que estabelece cláusulas\npétreas).", "D": "A emenda à Constituição será promulgada pelas Mesas\nda Câmara dos Deputados e do Senado Federal, com o\nrespectivo número de ordem.", "E": "A matéria constante de proposta de emenda rejeitada\nou havida por prejudicada não pode ser objeto de nova\nproposta na mesma sessão legislativa."}, "g": "C", "j": "C é incorreta: cláusulas pétreas do art. 60 §4º não podem ser objeto de emenda tendente a aboli-las — incluindo a impossibilidade de revogar o próprio dispositivo (limite material implícito ao poder constituinte derivado)."}, {"id": "695589", "d": "direito_constitucional", "a": ["Processo Legislativo", "Espécies Normativas: Lei Complementar e Lei Ordinária"], "ano": "2016", "org": "CRO", "t": "", "e": "Considere a proposição I e a razão II a seguir  I. Um projeto de lei complementar aprovado por maioria\nsimples na Câmara dos Deputados e no Senado\nFederal, sancionado, promulgado e publicado,\napresenta vício formal objetivo de\nInconstitucionalidade.\n  PORQUE\n  II. Nos termos da Constituição Federal, as leis\ncomplementares devem ser aprovadas por maioria\nqualificada de 3/5.\n  Assinale a alternativa correta.", "alt": {"A": "A proposição é falsa, mas a razão é verdadeira.", "B": "A proposição é verdadeira, mas a razão é falsa.", "C": "A proposição e a razão são falsas.", "D": "A proposição e a razão são verdadeiras e a razão\njustifica a proposição.", "E": "A proposição e a razão são verdadeiras, mas a razão\nnão justifica a proposição."}, "g": "B", "j": "Proposição verdadeira (aprovação por maioria simples gera vício formal objetivo). Razão falsa: LC exige maioria ABSOLUTA (art. 69 CF/88), não 3/5 (quórum esse das emendas constitucionais)."}, {"id": "695588", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Controle Preventivo: Comissões de Constituição e Justiça e Veto Jurídico", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2016", "org": "CRO", "t": "", "e": "No campo do Direito Constitucional, no capítulo referente\nao Controle de Constitucionalidade, assinale a alternativa\ncorreta quanto ao que a doutrina e jurisprudência tem\nentendido.", "alt": {"A": "O controle concentrado de constitucionalidade,\ntambém conhecido como controle por via de ação,\ncaracteriza-se pela permissão a todo e qualquer juiz ou\ntribunal de realizar no caso concreto a análise sobre a\ncompatibilidade do ordenamento jurídico com a\nConstituição.", "B": "O Presidente da República poderá vetar o projeto de\nemenda constitucional aprovado pelo Congresso\nNacional, realizando verdadeiro controle preventivo de\nconstitucionalidade.", "C": "O Congresso Nacional pode rejeitar medida provisória,\ncom base em inconstitucionalidade apontada no\nparecer da comissão temporária mista, exercendo,\nassim, controle preventivo de constitucionalidade.", "D": "De acordo com a jurisprudência do Supremo Tribunal\nFederal, a medida provisória pode ser objeto de ação\ndireta de inconstitucionalidade, pois trata-se de ato\nnormativo perfeito e acabado, apesar do caráter\ntemporário.", "E": "A inobservância das normas constitucionais de\nprocesso legislativo tem como consequência a\ninconstitucionalidade formal da lei ou do ato\nnormativo produzido, possibilitando controle\nrepressivo de constitucionalidade pelo Poder\nJudiciário, neste caso, apenas pelo método\nconcentrado."}, "g": "D", "j": "Jurisprudência STF (ADI 2.084): medida provisória pode ser objeto de ADI, pois é ato normativo com força de lei."}, {"id": "695587", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Classificação das Normas Constitucionais"], "ano": "2016", "org": "CRO", "t": "", "e": "Considerando a tradicional classificação das normas\nconstitucionais, preponderantemente a teoria de José\nAfonso da Silva, analise as afirmativas a seguir.  \nI. Normas constitucionais de eficácia plena são aquelas\nque apresentam aplicabilidade indireta, mediata e\nreduzida, pois somente incidem sobre determinado\ninteresse após uma normatividade ulterior.\n  II. Normas constitucionais de eficácia contida são aquelas\nem que o legislador constituinte regulou\nsuficientemente os interesses relativos à determinada\nmatéria, mas deixou margem à atuação restritiva por\nparte da competência discricionária do poder público.  \nIII. Os remédios constitucionais são exemplos de normas\nconstitucionais de eficácia limitada.\n  É correto o que se afirma em:", "alt": {"A": "I e II, somente.", "B": "II e III, somente.", "C": "I e III, somente.", "D": "II, somente.", "E": "III, somente."}, "g": "D", "j": "Somente II correto. I falso (eficácia plena tem aplicabilidade direta, imediata e integral — quem tem aplicabilidade indireta/mediata/reduzida é a eficácia limitada). III falso (remédios constitucionais são normas de eficácia plena)."}, {"id": "686350", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Ação Popular", "Mandado de Segurança", "Habeas Data", "Habeas Corpus"], "ano": "2016", "org": "CFB", "t": "", "e": "A publicidade dos atos administrativos é feita tanto na\nesfera federal (por meio do Diário Oficial Federal) como na\nestadual (por meio do Diário Oficial Estadual) ou municipal\n(por meio do Diário Oficial do Município). A Publicidade\ndeve ter objetivo educativo, informativo e de interesse\nsocial, não podendo ser utilizados símbolos, imagens etc.\nque caracterizem a promoção pessoal do Agente\nAdministrativo. A Publicidade, ao mesmo tempo que inicia\nos atos, também possibilita àqueles que deles tomam\nconhecimento, utilizarem os remédios constitucionais\ncontra eles. Assim, com base em diversos incisos do art. 5°\nda CF, o interessado poderá usar o(a):  \n   I. Direito de Petição.\n  II. Mandado de Segurança.  III. Ação Popular.  IV. Habeas Data.  V. Habeas Corpus.    Pode-se afirmar que:", "alt": {"A": "todas estão corretas.", "B": "somente I, II e III estão corretas.", "C": "somente I e II estão corretas.", "D": "somente II e III estão corretas.", "E": "somente III, IV e V estão corretas."}, "g": "A", "j": "Todos os 5 instrumentos (direito de petição, MS, ação popular, HD e HC) são remédios constitucionais utilizáveis contra atos administrativos abusivos ou ilegais, conforme o art. 5º CF/88."}, {"id": "679197", "d": "direito_constitucional", "a": ["Poder Judiciário", "Garantias do Poder Judiciário e de seus Membros"], "ano": "2016", "org": "CRQ 18° Região", "t": "", "e": "Por certo, os predicamentos da magistratura não se\ncaracterizam como privilégios dos magistrados, mas sim\ncomo meio de assegurar o seu livre desempenho, e revelar\na independência e autonomia do Poder Judiciário. Com\nrelação ao tema, considerando as garantias do Poder\nJudiciário, assinale a alternativa incorreta.", "alt": {"A": "A garantia constitucional da vitaliciedade só será\nadquirida após dois anos de exercício da carreira,\ndependendo a perda do cargo, nesse período, apenas\nde deliberação do tribunal a que o juiz estiver\nvinculado.", "B": "Os advogados que ingressam nos tribunais estaduais\nou federais pelo quinto constitucional adquirem\nvitaliciedade após dois anos de efetivo exercício da\ncarreira.", "C": "Excepcionalmente, a Constituição Federal prevê\nabrandamento da vitaliciedade dos membros do\nSupremo Tribunal Federal ao consagrar em seu artigo\n52 a competência privativa do Senado Federal para\nprocessar e julgar os Ministros nos crimes de\nresponsabilidade.", "D": "Nos termos da Constituição Federal, aos juízes é\nvedado exercer, ainda que em disponibilidade, outro\ncargo ou função, salvo uma de magistério.", "E": "O salário, vencimentos ou o subsídio do magistrado\nnão podem ser reduzidos como forma de pressão,\ngarantindo-lhe assim o livre exercício de suas\natribuições."}, "g": "B", "j": "B é incorreta: advogados/MP que ingressam pelo quinto constitucional em tribunais adquirem vitaliciedade IMEDIATAMENTE na posse (não após 2 anos). A regra de 2 anos vale apenas para juízes de primeiro grau."}, {"id": "679196", "d": "direito_constitucional", "a": ["Processo Legislativo", "Espécies Normativas: Medida Provisória, Lei Delegada, Decreto Legislativo e Resolução"], "ano": "2016", "org": "CRQ 18° Região", "t": "", "e": "Com relação ao procedimento legislativo especial das medidas\nprovisórias, previsto na Constituição Federal de 1988, analise\nas afirmativas a seguir.\nI. É vedada a reedição, na mesma sessão legislativa, de\nmedida provisória que tenha sido rejeitada ou que tenha\nperdido sua eficácia por decurso de prazo.\nII. Uma vez rejeitada expressamente pelo Legislativo, a\nmedida provisória perderá seus efeitos retroativamente,\ncabendo ao Congresso Nacional disciplinar as relações\njurídicas dela decorrentes, no prazo de 60 dias.\nIII. A medida provisória convertida em lei não tem o condão\nde revogar legislação anterior que versava a mesma\nmatéria.\nIV. De acordo com a Constituição Federal, é vedada a edição\nde medidas provisórias sobre matéria reservada à lei\ncomplementar.\nEstá correto o que se afirma em:", "alt": {"A": "I, II e III, somente.", "B": "I, II e IV, somente.", "C": "I e II, somente.", "D": "II e IV, somente.", "E": "todas as afirmativas."}, "g": "B", "j": "I correto (art. 62 §10). II correto (art. 62 §3º e §11). IV correto (art. 62 §1º, III). III falso: MP convertida em lei revoga legislação anterior incompatível, como qualquer outra lei."}, {"id": "679195", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2016", "org": "CRQ 18° Região", "t": "", "e": "Considerando o posicionamento jurisprudencial do\nSupremo Tribunal Federal sobre os tratados internacionais\nde Direitos Humanos, assinale a alternativa correta.", "alt": {"A": "Todos os tratados internacionais de direitos humanos,\nindependentemente do quórum de aprovação, são\nmaterialmente e formalmente constitucionais e integram\no bloco de constitucionalidade.", "B": "Apenas os tratados internacionais sobre direitos humanos\nratificados pelo Brasil antes da Emenda Constitucional n°\n45/2004 são materialmente e formalmente\nconstitucionais, contudo não integram o bloco de\nconstitucionalidade.", "C": "Os tratados internacionais sobre direitos humanos,\naprovados nas duas Casas do Congresso Nacional, em dois\nturnos, por três quintos dos votos dos respectivos\nmembros, apresentam hierarquia de norma\nsupraconstitucional.", "D": "Os tratados internacionais sobre direitos humanos\nratificados pelo Brasil após a Emenda Constitucional nº\n45/2004 apresentam a mesma hierarquia de lei federal.", "E": "Os tratados internacionais sobre direitos humanos\nratificados anteriormente à Emenda Constitucional nº\n45/2004 têm hierarquia infraconstitucional, mas\nsupralegal."}, "g": "E", "j": "Jurisprudência STF (RE 466.343 e HC 87.585): tratados sobre direitos humanos ratificados antes da EC 45/2004 têm status supralegal e infraconstitucional."}, {"id": "679194", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2016", "org": "CRQ 18° Região", "t": "", "e": "Considere a proposição I e a razão II a seguir.I. Nos termos da jurisprudência do Supremo Tribunal\nFederal, não é possível subtrair a garantia\nconstitucional assegurada ao cidadão no artigo 150,\ninciso III, alínea b, da Constituição de 1988 (princípio da\nanterioridade tributária) por meio de emenda\nconstitucional.\n                                                        Porque\nII. A tentativa de limitação ao princípio da anterioridade\ntributária esbarra em obstáculo previsto pelo artigo 60,\n§ 4º, inciso IV, da Constituição – impossibilidade de\nproposta de emenda tendente a abolir os direitos e\ngarantias individuais, que, de acordo com a Suprema\nCorte, não estão restritos ao rol do artigo 5º da Carta\nde 1988. Assinale a alternativa correta.", "alt": {"A": "A proposição é falsa, mas a razão é verdadeira.", "B": "A proposição é verdadeira, mas a razão é falsa.", "C": "A proposição e a razão são falsas.", "D": "A proposição e a razão são verdadeiras, mas a razão\nnão justifica a proposição.", "E": "A proposição e a razão são verdadeiras e a razão\njustifica a proposição"}, "g": "E", "j": "Proposição e razão verdadeiras, e a razão justifica a proposição: o STF (ADI 939) reconheceu o princípio da anterioridade tributária como direito/garantia individual e, portanto, cláusula pétrea protegida pelo art. 60 §4º IV."}, {"id": "679193", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2016", "org": "CRQ 18° Região", "t": "", "e": "No campo do Direito Constitucional, no capítulo referente\nàs emendas constitucionais, a doutrina e jurisprudência\ntem entendido o seguinte:", "alt": {"A": "o legislador constituinte de 1988, ao prever a\npossibilidade de alteração das normas constitucionais\natravés de processo legislativo semelhante ao\nordinário, definiu nossa Constiuição Federal como\nflexivél.", "B": "se qualquer das limitações impostas pela Constituição\nFederal for desrespeitada, a emenda constitucional\nserá inconstitucional, devendo ser retirada do\nordenamento jurídico por meio das regras de controle\nde constitucionalidade.", "C": "é possível a alteração do texto constitucional durante a\nvigência do estado de sítio, Estado de defesa ou de\nIntervenção Federal, desde que a emenda não limite\ndireitos inerentes ao exercício da democracia.", "D": "o Presidente da República poderá vetar o projeto de\nemenda constitucional aprovado pelo Congresso\nNacional, realizando verdadeiro controle preventivo de\nconstitucionalidade.", "E": "não é possível a incidência de controle difuso de\nconstitucionalidade sobre emendas constitucionais."}, "g": "B", "j": "Emenda constitucional que desrespeita limites (formais, circunstanciais ou materiais) é inconstitucional e pode ser objeto de controle de constitucionalidade (jurisprudência STF, ADI 939)."}, {"id": "601627", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Fundamentos da República"], "ano": "2016", "org": "CFP", "t": "", "e": "O Estado Democrático de Direito baseia-se em uma\nsociedade livre, justa e solidária, como afirma nossa\nConstituição, na qual o poder deve emanar do povo, sendo\nexercido em seu proveito, diretamente, ou por meio de\nrepresentantes eleitos. Deve ser um Estado promotor de\njustiça social, tendo a legalidade como princípio basilar.\nPorém, a lei não deve ficar adstrita em uma esfera\npuramente normativa e abstrata, mas, sim, deve influir na\nrealidade social do povo. Os princípios que alicerçam o\nEstado Democrático de Direito são, exceto:", "alt": {"A": "princípio da constitucionalidade.", "B": "sistema de direitos fundamentais.", "C": "igualdade.", "D": "unificação de poderes.", "E": "segurança jurídica."}, "g": "D", "j": "Estado Democrático de Direito pressupõe separação de poderes (não unificação). A unificação de poderes é incompatível com o constitucionalismo democrático."}, {"id": "2770937", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado"], "ano": "2015", "org": "CRMV", "t": "", "e": "Assinale, a seguir, V (verdadeiro) ou F (falso) para os princípios norteadores da atividade administrativa, previstos no artigo 37 da Constituição Federal.( ) Disponibilidade da função pública.( ) Isonomia.( ) Eficiência.( ) Anualidade.( ) Impessoalidade.A sequência correta está em:", "alt": {"A": "V, V, V, F, F.", "B": "V, V, F, F, V.", "C": "F, V, F, F, V.", "D": "F, F, V, F, F.", "E": "F, F, V, F, V."}, "g": "E", "j": "Art. 37 caput CF/88: LIMPE (legalidade, impessoalidade, moralidade, publicidade, eficiência). Sequência F (disponibilidade não é princípio), F (isonomia não está no caput), V (eficiência), F (anualidade), V (impessoalidade)."}, {"id": "446300", "d": "direito_constitucional", "a": ["Princípios Fundamentais da República", "Fundamentos da República"], "ano": "2014", "org": "CRN", "t": "", "e": "Segundo  a  Constituição  Federal,  a  República  Federativa  do  Brasil  é  formada  pela  união  indissolúvel  dos  Estados  e  Municípios  e  do  Distrito  Federal,  constituindo-se  em  Estado  Democrático de Direito,  e tem  como fundamentos: I.  a  soberania. II.  a  cidadania. III.  a  dignidade da  pessoa  humana. IV.  a  representatividade  política  independentemente  de  partidos. V.  os valores  sociais do trabalho e da  livre  iniciativa.Está  incorreto o que  se afirma  em:", "alt": {"A": "I", "B": "II", "C": "III", "D": "IV", "E": "V"}, "g": "D", "j": "Art. 1º CF/88: fundamentos = soberania, cidadania, dignidade, valores sociais do trabalho/livre iniciativa, pluralismo político. 'Representatividade política independente de partidos' não consta — IV é incorreta."}, {"id": "407578", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2014", "org": "CREF", "t": "", "e": "Assinale  a  alternativa  que  é  incorreta  no  que  diz  respeito  à  função do chefe do poder executivo municipal.", "alt": {"A": "Administração  do  município,  incluindo  a  realização  de  obras  e  a  prestação  de  serviços  públicos,  tais  como  saúde e educação.", "B": "Fiscalização  do  cumprimento  das  leis  aprovadas  pelos  vereadores.", "C": "Prestar  contas de  seu  trabalho  à  Câmara  de Vereadores  e aos cidadãos.", "D": "Execução  de  ações  que  beneficiem  a  comunidade,  tais  como abastecimento de água  e  limpeza  das  ruas.", "E": "Responsabilizar-se pela segurança pública comandando as políticas civil e militar."}, "g": "E", "j": "Art. 144 CF/88: segurança pública não é atribuição de prefeito; cabe à PRF, PF, polícias civis/militares (estaduais) e guardas municipais (com função limitada). Prefeito não comanda polícias civil/militar."}, {"id": "407380", "d": "direito_constitucional", "a": ["Processo Legislativo", "Fase Introdutória – Iniciativa de Lei por Parlamentar e Extra-Parlamentar"], "ano": "2014", "org": "CRM", "t": "", "e": "Segundo  a  Constituição  Federal,  não  são  de  iniciativa privativa  do  Presidente da  República  as  leis que:", "alt": {"A": "disponham  sobre  servidores  públicos  da  União  e  Territórios,  seu  regime  jurídico,  provimento  de  cargos,  estabilidade e aposentadoria.", "B": "disponham  sobre  organização  do  Ministério  Público  e  da  Defensoria  Pública  da  União,  bem  como  normas  gerais  para  a  organização  do  Ministério  Público  e  da  Defensoria  Pública  dos  Estados,  do  Distrito  Federal  e  dos Territórios.", "C": "disponham  sobre  militares  das  Forças  Armadas,  seu  regime  jurídico,  provimento  de  cargos,  promoções,  estabilidade,  remuneração,  reforma  e  transferência  para  a  reserva.", "D": "fixem ou modifiquem os efetivos das  Forças Armadas.", "E": "disponham sobre a criação de cargos, funções ou empregos públicos na administração direta e indireta ou aumento de sua remuneração."}, "g": "E", "j": "Art. 61, §1º, II, 'a' CF/88: iniciativa privativa do PR alcança 'administração direta e AUTÁRQUICA' — a inclusão de toda 'administração indireta' (incluindo empresas públicas/SEM) extrapola o dispositivo."}, {"id": "389511", "d": "direito_constitucional", "a": ["Poder Constituinte Originário, Derivado e Decorrente - Reforma (Emendas e Revisão) e Mutação da Constituição", "Teoria da Constituição"], "ano": "2014", "org": "CRN", "t": "", "e": "Assinale  a  alternativa  incorreta  sob o  prisma  da  Constituição Federal,  no tocante às suas Emendas.", "alt": {"A": "A  Constituição  poderá  ser  emendada  mediante  proposta  de  um  terço,  no  mínimo,  dos  membros  da  Câmara  dos Deputados ou  do Senado  Federal.", "B": "A  Constituição  poderá  ser  emendada  na  vigência  de  intervenção  federal  e  de  estado  de  defesa,  mas  não  na  vigência de estado de sítio.", "C": "A  emenda  à  Constituição  será  promulgada  pelas Mesas  da  Câmara  dos  Deputados  e  do  Senado  Federal,  com  o  respectivo número de ordem.", "D": "Não  será  objeto  de  deliberação  a  proposta  de  emenda  tendente a  abolir a  forma  federativa  de Estado.", "E": "A matéria constante de proposta de emenda rejeitada ou havida por prejudicada não pode ser objeto de nova proposta na mesma sessão legislativa."}, "g": "B", "j": "B é incorreta: art. 60 §1º CF/88 veda emenda à Constituição na vigência de intervenção federal, estado de defesa OU estado de sítio — não há permissão para emenda em qualquer dessas hipóteses."}, {"id": "389509", "d": "direito_constitucional", "a": ["Poder Legislativo", "Congresso Nacional"], "ano": "2014", "org": "CRN", "t": "", "e": "O  artigo  49  da  Constituição  Federal  elenca  as  atribuições  que  são  da  competência  exclusiva  do  Congresso  Nacional.  Assinale  a  alternativa  que  não  se  inclui  nas  atribuições  previstas pelo  referido artigo.", "alt": {"A": "Resolver  definitivamente  sobre  tratados,  acordos  ou  atos  internacionais  que  acarretem  encargos  ou  compromissos gravosos ao patrimônio nacional.", "B": "Autorizar,  por  dois  terços  de  seus  membros,  a  instauração  de  processo  contra  o  Presidente  e  o  Vice-  Presidente da  República  e os Ministros de Estado.", "C": "Autorizar o  Presidente  da  República  a  declarar guerra,  a  celebrar  a  paz,  a  permitir  que  forças  estrangeiras  transitem  pelo  território  nacional  ou  nele  permaneçam  temporariamente,  ressalvados  os  casos  previstos  em  lei  complementar.", "D": "Autorizar o  Presidente  e  o Vice-Presidente  da  República  a  se  ausentarem  do  País,  quando  a  ausência  exceder  a  quinze dias.", "E": "Aprovar o estado de defesa e a intervenção federal, autorizar o estado de sítio, ou suspender qualquer uma dessas medidas."}, "g": "B", "j": "Autorizar instauração de processo contra PR/VP/Ministros (2/3) é competência privativa da CÂMARA DOS DEPUTADOS (art. 51, I), não atribuição do art. 49 (competência exclusiva do Congresso Nacional)."}, {"id": "2928003", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado", "Repartição de Competências Constitucionais"], "ano": "2013", "org": "ABDI", "t": "", "e": "A Competência de legislar sobre normas específicas de Licitação cabe:", "alt": {"A": "A todos os entes da Federação.", "B": "Exclusivamente à União.", "C": "Apenas e tão somente aos Estados.", "D": "Apenas e tão somente aos Municípios.", "E": "Apenas e tão somente ao Território Federal."}, "g": "A", "j": "Art. 22, XXVII CF/88: compete privativamente à União legislar sobre NORMAS GERAIS de licitação. Normas ESPECÍFICAS cabem a todos os entes da Federação no exercício de suas competências."}, {"id": "747615", "d": "direito_constitucional", "a": ["Teoria dos Direitos Fundamentais"], "ano": "2013", "org": "CRBio", "t": "", "e": "De acordo com a Constituição Federal, as normas definidoras dos direitos e garantias fundamentais têm aplicação imediata. Assim sendo, encontre a única regra que não está de acordo com a ideal defesa desses direitos.", "alt": {"A": "O Estado prestará assistência jurídica integral e gratuita aos que comprovarem insuficiência de recursos.", "B": "Os direitos e garantias expressos na Constituição Federal não excluem outros decorrentes do regime e dos princípios por ela adotados, mas tão somente dos tratados internacionais em que a República Federativa do Brasil seja parte.", "C": "Os tratados e convenções internacionais sobre direitos humanos que forem aprovados, em cada Casa do Congresso Nacional, em dois turnos, por três quintos dos votos dos respectivos membros, serão equivalentes às emendas constitucionais.", "D": "São gratuitas as ações de \"habeas-corpus\" e \"habeas-data\", e, na forma da lei, os atos necessários ao exercício da cidadania.", "E": "Qualquer cidadão é parte legítima para propor ação popular que vise a anular ato lesivo ao patrimônio público ou de entidade de que o Estado participe, à moralidade administrativa, ao meio ambiente e ao patrimônio histórico e cultural, ficando o autor, salvo comprovada má-fé, isento de custas judiciais e do ônus da sucumbência."}, "g": "B", "j": "B é incorreta: art. 5º §2º CF/88 — os direitos e garantias expressos não excluem outros decorrentes do regime, dos princípios E dos tratados internacionais (não apenas dos tratados, como afirma B)."}, {"id": "747614", "d": "direito_constitucional", "a": ["Organização dos Poderes"], "ano": "2013", "org": "CRBio", "t": "", "e": "Tenha atenção nos incisos a seguir.    I. O Poder Legislativo Federal é exercido pelo Congresso Nacional, que se compõe da Câmara dos Deputados, do Senado Federal e das Assembléias Legislativas.  II. O Senado Federal compõe-se de representantes do povo, eleitos, pelo sistema proporcional, em cada Estado, em cada Território e no Distrito Federal.  III. O Poder Executivo é exercido pelo Presidente da República, auxiliado pelos Ministros de Estado. A eleição do Presidente da República importará a do Vice- Presidente com ele registrado.  IV. O Supremo Tribunal Federal, o Conselho Nacional de Justiça e os Tribunais Superiores têm sede na Capital Federal. O Supremo Tribunal Federal e os Tribunais  Superiores têm jurisdição em todo o território nacional.    Quantos deles estão corretos?", "alt": {"A": "Nenhum.", "B": "Todos.", "C": "Somente três.", "D": "Somente dois.", "E": "Somente um."}, "g": "D", "j": "III e IV corretos. I falso (Legislativo Federal é exercido pelo Congresso = Câmara + Senado, sem Assembleias Legislativas). II falso (Senado representa Estados/DF pelo princípio majoritário). Total: 2."}, {"id": "747613", "d": "direito_constitucional", "a": ["Direitos Individuais", "Direito à Liberdade", "Direito à Privacidade"], "ano": "2013", "org": "CRBio", "t": "", "e": "Assinale a alternativa incorreta a respeito dos direitos e garantias fundamentais existentes na Constituição Federal.", "alt": {"A": "Todos podem reunir-se pacificamente, sem armas, em locais abertos ao público, independentemente de autorização, desde que não frustrem outra reunião anteriormente convocada para o mesmo local, sendo apenas exigido prévio aviso à autoridade competente.", "B": "É inviolável a liberdade de consciência e de crença, sendo assegurado o livre exercício dos cultos religiosos e garantida, na forma da lei, a proteção aos locais de culto e a suas liturgias.", "C": "É livre a manifestação do pensamento, sendo preservado o anonimato.", "D": "É inviolável o sigilo da correspondência e das comunicações telegráficas, de dados e das comunicações telefônicas, salvo, no último caso, por ordem judicial, nas hipóteses e na forma que a lei estabelecer para fins de investigação criminal ou instrução processual penal.", "E": "Ninguém poderá ser compelido a associar-se ou a permanecer associado."}, "g": "C", "j": "C é incorreta: art. 5º, IV CF/88 — livre manifestação do pensamento, sendo VEDADO o anonimato (não preservado)."}, {"id": "598733", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN", "Ação Declaratória de Constitucionalidade - ADC"], "ano": "2013", "org": "CRF", "t": "", "e": "Ainda sobre controle de constitucionalidade, assinale a alternativa incorreta.", "alt": {"A": "A declaração de constitucionalidade ou de inconstitucionalidade, inclusive a interpretação conforme a Constituição e a declaração parcial de inconstitucionalidade sem redução de texto, têm eficácia contra todos e efeito vinculante em relação aos órgãos do Poder Judiciário e à Administração Pública federal, estadual e municipal.", "B": "Se não for alcançada a maioria necessária à declaração de constitucionalidade ou de inconstitucionalidade, estando ausentes Ministros em número que possa influir no julgamento, este será suspenso a fim de aguardar-se o comparecimento dos Ministros ausentes, até que se atinja o número necessário para prolação da decisão num ou noutro sentido.", "C": "A decisão que declara a constitucionalidade ou a inconstitucionalidade da lei ou do ato normativo em ação direta ou em ação declaratória é irrecorrível, ressalvada a interposição de embargos declaratórios e ação rescisória.", "D": "A decisão sobre a constitucionalidade ou a inconstitucionalidade da lei ou do ato normativo somente será tomada se presentes na sessão, pelo menos, oito Ministros.", "E": "Proclamada constitucionalidade, julgar-se-á improcedente a ação direta ou procedente eventual ação declaratória; e, proclamada inconstitucionalidade, julgar-se-á procedente a ação direta ou improcedente eventual ação declaratória."}, "g": "C", "j": "C é incorreta: art. 26 Lei 9.868/99 — decisão em ADI/ADC é irrecorrível, ressalvada interposição de embargos declaratórios, NÃO admitindo ação rescisória."}, {"id": "598732", "d": "direito_constitucional", "a": ["Controle de Constitucionalidade", "Ação Direta de Inconstitucionalidade Genérica - ADI ou ADIN"], "ano": "2013", "org": "CRF", "t": "As afirmações tratam das regras relativas à ação direta de inconstitucionalidade prevista em nosso ordenamento jurídico.I. Proposta a ação direta, somente se admitirá desistência até a citação do(s) órgão(s) envolvido(s).II. A petição inicial inepta, não fundamentada e a manifestamente improcedente serão liminarmente indeferidas pelo relator, cabendo agravo da decisão que indeferir a petição inicial.III. Não se admitirá intervenção de terceiros no processo de ação direta de inconstitucionalidade.IV. Em caso de excepcional urgência, o Tribunal poderá deferir a medida cautelar sem a audiência dos órgãos ou das autoridades das quais emanou a lei ou o ato normativo impugnado.", "e": "Quantas alternativas são consideradas condizentes com o tratamento legal dado à matéria?", "alt": {"A": "Todas.", "B": "Três.", "C": "Duas.", "D": "Uma.", "E": "Nenhuma."}, "g": "B", "j": "II, III e IV corretos (Lei 9.868/99 arts. 4º, 7º e 10). I falso: art. 5º Lei 9.868/99 dispõe que 'proposta a ação direta, NÃO se admitirá desistência' — sem ressalva temporal."}, {"id": "598731", "d": "direito_constitucional", "a": ["Presidente da República, Vice-Presidente da República e Ministros de Estado.", "Poder Executivo"], "ano": "2013", "org": "CRF", "t": "", "e": "Qual, das seguintes atribuições, o Presidente da República poderá delegar aos Ministros de Estado, ao Procurador- Geral da República ou ao Advogado-Geral da União?", "alt": {"A": "Celebrar tratados, convenções e atos internacionais, sujeitos a referendo do Congresso Nacional.", "B": "Conceder indulto e comutar penas, com audiência, se necessário, dos órgãos instituídos em lei.", "C": "Conferir condecorações e distinções honoríficas.", "D": "Manter relações com Estados estrangeiros e acreditar seus representantes diplomáticos.", "E": "Remeter mensagem e plano de governo ao Congresso Nacional por ocasião da abertura da sessão legislativa, expondo a situação do País e solicitando as providências que julgar necessárias."}, "g": "B", "j": "Art. 84, §único CF/88: o PR pode delegar a Ministros/PGR/AGU as atribuições do inciso VI (organização da administração), XII (conceder indulto e comutar penas) e XXV primeira parte (prover cargos)."}, {"id": "511879", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Política Urbana"], "ano": "2013", "org": "COREN", "t": "", "e": "A  política  de  desenvolvimento  urbano,  executada  pelo  Poder  Público  municipal,  conforme  diretrizes  gerais  fixadas  em  lei,  tem  por  objetivo  ordenar  o  pleno  desenvolvimento  das  funções  sociais  da  cidade  e  garantir  o  bem-  estar  de  seus  habitantes.  Assinale  a  alternativa  que  contraria  as  disposições  da  Constituição  Federal  acerca  da  Política  Urbana.", "alt": {"A": "O  plano  diretor,  aprovado  pela  Câmara  Municipal,  obrigatório  para  cidades  com  mais  de  cem  mil  habitantes,  é  o  instrumento  básico  da  política  de  desenvolvimento e de expansão  urbana.", "B": "Aquele  que  possuir  como  sua  área  urbana  de  até  duzentos  e  cinqüenta  metros  quadrados,  por  cinco  anos,  ininterruptamente  e  sem  oposição,  utilizando-a  para  sua  moradia  ou  de  sua  família,  adquirir-lhe-á  o  domínio,  desde  que  não  seja  proprietário  de  outro  imóvel  urbano ou  rural.", "C": "É  facultado  ao  Poder  Público  municipal,  mediante  lei  específica  para  área  incluída  no  plano  diretor,  exigir,  nos  termos  da  lei  federal,  do  proprietário  do  solo  urbano  não  edificado,  subutilizado  ou  não  utilizado,  que promova  seu  adequado aproveitamento", "D": "Os  imóveis  públicos  não  serão  adquiridos  por  usucapião.", "E": "A propriedade urbana cumpre sua função social quando atende às exigências fundamentais de ordenação da cidade expressas no plano diretor"}, "g": "A", "j": "A é incorreta: art. 182 §1º CF/88 exige plano diretor para cidades com mais de 20.000 habitantes (não 100.000)."}, {"id": "511878", "d": "direito_constitucional", "a": ["Ordem Econômica e Financeira", "Sistema Tributário Nacional"], "ano": "2013", "org": "COREN", "t": "", "e": "Segundo  a  Constituição  Federal,  pertencem  aos  Estados  e ao Distrito  Federal:", "alt": {"A": "O  produto  da  arrecadação  do  imposto  da  União  sobre  renda  e  proventos  de  qualquer  natureza,  incidente  na  fonte,  sobre  rendimentos  pagos,  a  qualquer  título,  por  eles,  suas  autarquias  e  pelas  fundações que  instituírem  e mantiverem", "B": "Cinqüenta  por  cento  do  produto  da  arrecadação  do  imposto  do  Estado  sobre  a  propriedade  de  veículos  automotores  licenciados em  seus territórios.", "C": "Vinte  e  cinco  por  cento  do  produto  da arrecadação do imposto  do  Estado  sobre  operações  relativas  à circulação de mercadorias.", "D": "Vinte  e  cinco  por  cento  do  produto  da arrecadação do imposto  do  Estado  sobre  prestações  de  serviços de transporte  interestadual  e  intermunicipal  e  de  comunicação.", "E": "Cinqüenta por cento do produto da arrecadação do imposto da União sobre a propriedade territorial rural, relativamente aos imóveis neles situados, cabendo a totalidade em determinadas situações."}, "g": "A", "j": "Art. 157, I CF/88: pertence aos Estados e ao DF o produto da arrecadação do imposto da União sobre renda e proventos incidente na fonte sobre rendimentos pagos por eles, suas autarquias e fundações."}, {"id": "511877", "d": "direito_constitucional", "a": ["Poder Legislativo", "Câmara dos Deputados", "Senado Federal"], "ano": "2013", "org": "COREN", "t": "", "e": "Considere as seguintes atribuições:I. Proceder à  tomada de contas do  Presidente da  República,  quando  não  apresentadas  ao  Congresso  Nacional  dentro  de sessenta dias após a abertura da sessão  legislativa.II.  Processar  e  julgar  o  Presidente  e  o  Vice-Presidente  da  República  nos  crimes  de  responsabilidade,  bem  como  os  Ministros  de  Estado  e  os  Comandantes  da  Marinha,  do  Exército e da Aeronáutica, nos crimes da mesma  natureza  conexos com aqueles.III. Dispor  sobre  sua  organização,  funcionamento,  polícia,  criação,  transformação ou  extinção dos  cargos,  empregos  e funções de seus serviços, e a  iniciativa de  lei para fixação  da  respectiva  remuneração,  observados  os  parâmetros  estabelecidos na  lei de diretrizes orçamentárias.As  funções  citadas,  de  acordo  com  a  Constituição  Federal, competem privativa e respectivamente:", "alt": {"A": "À  Câmara  dos  Deputados;  ao  Senado  Federal;  à  Câmara  dos Deputados.", "B": "Ao  Senado  Federal;  à  Câmara  dos  Deputados;  à  Câmara  dos Deputados.", "C": "Ao  Senado  Federal;  ao  Senado  Federal;  ao  Senado  Federal", "D": "À  Câmara  dos  Deputados;  à  Câmara  dos  Deputados;  à  Câmara dos Deputados.", "E": "Ao Senado Federal; à Câmara dos Deputados; ao Senado Federal"}, "g": "A", "j": "I — Câmara dos Deputados (art. 51, II). II — Senado Federal (art. 52, I). III — Câmara dos Deputados (art. 51, IV). Sequência: Câmara; Senado; Câmara."}, {"id": "511876", "d": "direito_constitucional", "a": ["Previdência Social", "Ordem Social", "Saúde"], "ano": "2013", "org": "COREN", "t": "", "e": "Leia as seguintes afirmações:I. A  seguridade  social  compreende  um  conjunto  integrado  de  ações  de  iniciativa  dos  Poderes  Públicos  e  da  sociedade,  destinadas  a  assegurar  os  direitos  relativos  à  saúde, à previdência e à assistência social. II.  A  proposta  de  orçamento  da  seguridade  social  será  elaborada  de  forma  integrada  pelos  órgãos  responsáveis  pela  saúde,  previdência  social  e  assistência  social,  tendo  em  vista  as  metas  e  prioridades  estabelecidas  na  lei  de  diretrizes orçamentárias,  assegurada  a  cada  área  a gestão  de seus recursos.III.São  de  relevância  pública  as  ações  e  serviços  de  saúde,  cabendo ao Poder Público dispor, nos termos da  lei,  sobre  sua  regulamentação,  fiscalização  e  controle,  devendo  sua  execução  ser  feita  diretamente  ou  por meio  de  terceiros  e,  também,  por  pessoa  física  ou  jurídica  de  direito  privado.IV.  As  instituições  privadas  poderão  participar  de  forma  complementar  do  sistema  único  de  saúde,  segundo  diretrizes  deste,  mediante  contrato  de  direito  público  ou  convênio,  tendo  preferência  as  entidades  filantrópicas  e  as sem fins  lucrativos.Em  relação  aos  dispositivos  constitucionais  pertinentes  à  Ordem Social, é correto o que se afirma em:", "alt": {"A": "todas", "B": "somente  I,  II e III", "C": "somente  II,  III e  IV.", "D": "somente  I,  II e  IV", "E": "somente l e II."}, "g": "A", "j": "Todos os 4 itens estão corretos (arts. 194, 195 §2º, 197 e 199 §1º CF/88)."}, {"id": "511875", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado", "Repartição de Competências Constitucionais"], "ano": "2013", "org": "COREN", "t": "", "e": "Assinale  a  alternativa  que  contempla  assunto  cuja  competência  para  legislar  não  é  atribuída  privativamente  à  União,  por força do artigo 22 da Constituição  Federal.", "alt": {"A": "Serviço  postal", "B": "Trânsito e transporte.", "C": "Proteção  ao  patrimônio  histórico,  cultural,  artístico,  turístico e paisagístico", "D": "Sistema  estatístico,  sistema  cartográfico  e  de  geologia  nacionais", "E": "Sistemas de consórcios e sorteios."}, "g": "C", "j": "Art. 23, III CF/88: proteção ao patrimônio histórico, cultural, artístico, turístico e paisagístico é competência COMUM da União, Estados, DF e Municípios (não privativa da União)."}, {"id": "500354", "d": "direito_constitucional", "a": ["Disposições Constitucionais Gerais"], "ano": "2013", "org": "CRQ 4ª Região", "t": "", "e": "O serviço de  lavrar procurações, escrituras de todas as naturezas,  reconhecimento  de  assinaturas  e  autenticação  de  documentos,  são realizados em cartórios de serviços de:", "alt": {"A": "Contratos Marítimos e Serviços de Registros de Distribuição.", "B": "Notas", "C": "Protestos de Titulos.", "D": "Registro Civil das Pessoas Naturais.", "E": "Registro de Imóveis."}, "g": "B", "j": "Lei 8.935/94 (Lei dos Cartórios) art. 7º: os serviços de notas (Tabelionato de Notas) compreendem lavrar procurações, escrituras, reconhecimento de firmas e autenticação de documentos."}, {"id": "500352", "d": "direito_constitucional", "a": ["Supremo Tribunal Federal", "Organização do Poder Judiciário"], "ano": "2013", "org": "CRQ 4ª Região", "t": "", "e": "Analise a  noticia  a  seguir.\"O  Plenário  do  Supremo  Tribunal  Federal  (STF)  declarou  a  inconstitucionalidade  do  artigo  59  da  Lei  12.034/2009,  que  cria  o  voto  impresso  a  partir  das  eleições  2014.  Na  sessão  plenária  realizada,  os  ministros  confirmaram,  em  definitivo,  liminar  concedida  pela  Corte  em  outubro  de  2011,  na  qual  foram  suspensos  os  efeitos  do  dispositivo  questionado  pela  Procuradoria  Geral  da  República  (PGR)  na  Ação  Direta  de  Inconstitucionalidade  (ADI) 4543/'                                                (www.stf.jus.br/portal/cms/verNoticiaDetalhe.asp?idConteudo=252858)Sobre a  notícia  acima,  assinale a  alternativa  correta.", "alt": {"A": "Indiferente à constitucionalidade,  o  presidente  da  república  tem o  poder  de  vetar  o  STF  e  tornar  a  lei  constitucional.", "B": "O  STF  faz  parte  do  poder  Judiciário  e  deve  garantir  os  direitos  individuais,  coletivos  e  sociais  e  resolver  os  conflitos entre cidadãos,  entidades e  Estado.", "C": "O  poder  Legislativo  deverá  dar  o  voto  final  nesse  caso,  pois  e  o  grande  responsável  pela  elaboração  e  aprovação das  leis.", "D": "O  STF é subordinado  ao  poder  Executivo,  portanto,  a  decisão  final  deverá  ser  do  Presidente  da  República,  juntamente com o poder Legislativo.", "E": "A declaração de inconstitucionalidade somente poderá ser revertida se submetida ao plebiscito popular."}, "g": "B", "j": "Art. 102 CF/88: o STF integra o Poder Judiciário e é guardião da Constituição, garantindo os direitos individuais, coletivos e sociais e resolvendo conflitos entre entes."}, {"id": "485981", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2013", "org": "CRF", "t": "", "e": "De  acordo  com  a  Constituição  Federal,  assinale  a  alternativa incorreta.", "alt": {"A": "É vedada  a  criação de Tribunals,  Conselhos ou  órgãos de  Contas Municipals.", "B": "Compete  aos  Municípios  manter,  com  a  cooperação  técnica  e financeira  da  União e do  Estado,  programas de  educação  infantil e de ensino fundamental.", "C": "As  contas dos Municípios  ficarão,  durante  sessenta  dias,  anualmente,  a  disposição  de  qualquer  contribuinte,  para  exame e apreciação,  o qual  poderá  questionar-lhes  a  legitimidade,  nos termos da  lei.", "D": "As  leis  orgânicas  dos  Municípios  serão  modificadas  por  meio  de  votação  favorável  da  maioria  absoluta  dos  integrantes das  respectivas Câmaras Municipals.", "E": "Para a composição das Câmaras Municipals, seraá observado o limite minimo de 9 (nove) Vereadores e máximo de 55 (cinquenta e cinco)."}, "g": "A", "j": "Banca apontou A como incorreta, mas A é CORRETA (art. 31 §4º veda criação de TCs municipais). A real incorreta é D: art. 29 CF/88 exige que a Lei Orgânica seja aprovada por DOIS TERÇOS dos membros (não maioria absoluta)."}, {"id": "455424", "d": "direito_constitucional", "a": ["Teoria da Constituição", "Classificação das Normas Constitucionais"], "ano": "2013", "org": "CREF", "t": "", "e": "Aponte  a  única  alternativa  que  contenha  uma  norma constitucional de eficácia  limitada.", "alt": {"A": "Todos  têm  direito  a  receber  dos  órgãos  públicos  nformações de  seu  interesse particular, ou de  interesse  coletivo  ou  geral,  que  serão  prestadas  no  prazo  da  lei,  sob  pena  de  responsabilidade,  ressalvadas  aquelas  cujo  sigilo  seja  imprescindível  à  segurança  da  sociedade e do  Estado.", "B": "A  lei  estabelecerá  o  procedimento  para  desapropriação  por  necessidade  ou  utilidade  pública,  ou  por  interesse  social, mediante justa  e prévia  indenização em dinheiro,  ressalvados os casos previstos na Constituição.", "C": "É  livre  a  locomoção  no  território  nacional  em  tempo  de  paz,  podendo  qualquer  pessoa,  nos  termos  da  lei,  nele  entrar, permanecer ou dele sair com seus bens.", "D": "A  lei  estadual  poderá  criar,  mediante  proposta  do  Tribunal  de  Justiça,  a  Justiça  Militar  estadual,  constituída,  em  primeiro  grau,  pelos  juizes  de  direito  e  pelos  Conselhos  de  Justiça  e,  em  segundo  grau,  pelo  próprio  Tribunal  de  Justiça,  ou  por  Tribunal  de  Justiça  Militar  nos  Estados  em  que  o  efetivo  militar  seja  superior a vinte mil  integrantes.", "E": "É assegurado a todos o livre exercício de qualquer atividade econômica, independentemente de autorização de órgãos públicos, salvo nos casos previstos em lei."}, "g": "D", "j": "Norma de eficácia limitada: art. 125 §3º CF/88 — criação da Justiça Militar estadual depende de lei estadual (depende de regulamentação ulterior). As demais são de eficácia plena ou contida."}, {"id": "455423", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais"], "ano": "2013", "org": "CREF", "t": "", "e": "Assinale  a  alternativa  errônea  a  respeito  do  tratamento constitucional do  habeas corpus.", "alt": {"A": "Compete  ao  Superior  Tribunal  de  Justiça  julgar,  em  recurso ordinário,  todos os habeas corpus decididos em  única  ou  última  instância  pelos  Tribunais  Regionais  Federais  ou  pelos  tribunais  dos  Estados,  do  Distrito  Federal e Territórios.", "B": "A ação de habeas corpus é gratuita.", "C": "Compete  ao Supremo Tribunal  Federal,  precipuamente,  a  guarda  da  Constituição,  cabendo-lhe  processar  e  julgar,  originariamente  o  habeas  corpus,  quando  o  coator  for  Tribunal  Superior  ou  quando  o  coator  ou  o  paciente  for  autoridade  ou  funcionário  cujos  atos  estejam  sujeitos  diretamente  à  jurisdição  do  Supremo  Tribunal  Federal,  ou  se  trate  de  crime  sujeito  à  mesma  jurisdição em uma única  instância.", "D": "Não  caberá  \"habeas-corpus\"  em  relação  a  punições  disciplinares militares.", "E": "Compete aos Tribunais Regionais Federais processar e julgar, originariamente, os habeas corpus, quando a autoridade coatora for juiz federal."}, "g": "A", "j": "A é incorreta: art. 105, II, 'c' CF/88 — o STJ julga em recurso ordinário apenas os HCs cuja decisão for DENEGATÓRIA, não 'todos' os decididos em única ou última instância pelos TRFs/TJs."}, {"id": "2939674", "d": "direito_constitucional", "a": ["Organização Político-Administrativa do Estado", "Repartição de Competências Constitucionais"], "ano": "2012", "org": "CRBio", "t": "", "e": "Assinale a alternativa que traga uma função à qual não é atribuída competência comum à União, aos Estados, ao Distrito Federal e aos Municípios.", "alt": {"A": "Zelar pela guarda da Constituição, das leis e das instituições democráticas e conservar o patrimônio público.", "B": "Cuidar da saúde e assistência pública, da proteção e garantia das pessoas portadoras de deficiência.", "C": "Elaborar e executar planos nacionais e regionais de ordenação do território e de desenvolvimento econômico e social.", "D": "Proteger os documentos, as obras e outros bens de valor histórico, artístico e cultural, os monumentos, as paisagens naturais notáveis e os sítios arqueológicos.", "E": "Promover programas de construção de moradias e a melhoria das condições habitacionais e de saneamento básico."}, "g": "C", "j": "Art. 21, IX CF/88: elaborar e executar planos nacionais e regionais de ordenação do território e desenvolvimento econômico/social é competência EXCLUSIVA da União, não comum."}, {"id": "2939672", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Individuais"], "ano": "2012", "org": "CRBio", "t": "", "e": "De acordo com a Constituição Federal de 1988, para assegurar o conhecimento de informações relativas à pessoa do impetrante, constantes de registros ou bancos de dados de entidades governamentais ou de caráter público, conceder-se-á:", "alt": {"A": "Habeas Corpus.", "B": "Habeas Data.", "C": "Mandado de lnjunção.", "D": "Mandado de Segurança.", "E": "Habeas Corpus Preventivo."}, "g": "B", "j": "Art. 5º, LXXII CF/88: habeas data assegura o conhecimento de informações relativas à pessoa do impetrante constantes de registros ou bancos de dados de entidades governamentais ou de caráter público."}, {"id": "2939659", "d": "direito_constitucional", "a": ["Remédios e Garantias Constitucionais", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Individuais"], "ano": "2012", "org": "CRBio", "t": "", "e": "Considere as seguintes afirmações relativas à \"Ação Popular\" prevista no inciso LXXIII da Constituição Federal. I. Qualquer cidadão é parte legítima para propor ação popular. lI. Vise a anular ato lesivo ao patrimônio público ou de entidade de que o Estado participe, à moralidade administrativa, ao meio ambiente e ao patrimônio histórico e cultural. IlI. O autor, salvo comprovada má-fé, fica isento de custas judiciais e do ônus da sucumbência. Pode-se afirmar que:", "alt": {"A": "somente I e lI são corretas.", "B": "somente I e IlI são corretas.", "C": "somente II e IlI são corretas.", "D": "todas são incorretas.", "E": "todas são corretas."}, "g": "E", "j": "Art. 5º, LXXIII CF/88: todos os 3 itens correspondem ao texto do inciso sobre ação popular."}, {"id": "1231085", "d": "direito_constitucional", "a": ["Poder Legislativo", "Tribunal de Contas da União (TCU) e Fiscalização Contábil, Financeira e Orçamentária da União"], "ano": "2012", "org": "CRO - PR", "t": "", "e": "Os Ministros do Tribunal de Contas da União serão nomeados dentre brasileiros\n que satisfaçam especificamente os seguintes requisitos:    I. Mais de trinta e menos de cinquenta e cinco anos de\n idade.     II. Idoneidade moral e reputação ilibada.     III. Notorios conhecimentos jurídicos.    IV. Mais de dez anos de exercício de função ou de efetiva atividade profissional que exija os conhecimentos jurídicos, contábeis, econômicos e financeiros ou de administração pública.      Estão incorretos os incisos:", "alt": {"A": "II e IV.", "B": "I e III.", "C": "III e IV.", "D": "I e IV.", "E": "II e III."}, "g": "B", "j": "Art. 73, §1º CF/88: Min. TCU deve ter mais de 35 e menos de 65 anos (I incorreto — diz 30-55) e notórios conhecimentos jurídicos, CONTÁBEIS, econômicos e financeiros OU de adm pública (III incorreto — restringe a 'jurídicos')."}, {"id": "1213651", "d": "direito_constitucional", "a": ["Processo Legislativo", "Processo Legislativo Ordinário"], "ano": "2012", "org": "CRP 18ª Região MT", "t": "", "e": "Dos princípios do Processo Legislativo, pode-se destacar o princípio da publicidade, que é observado sobre os seguintes aspectos:  I. Possibilidade efetiva de o público poder assistir às deliberações das Câmaras.     II. Disponibilidade ao público em geral de atas das sessões e reuniões aprovadas pela própria Câmara e suas comissões.     III. Publicação pela imprensa de resumos ou extratos de suas atas e da livre informação do ocorrido em suas sessões e reuniões.     Está correto o que se afirma em:", "alt": {"A": "I, II e III.", "B": "somente l e lll.", "C": "somente l e ll.", "D": "Somente II e III.", "E": "somente II."}, "g": "A", "j": "Todos os 3 itens são aspectos do princípio da publicidade no processo legislativo: acesso público às deliberações, atas disponíveis e publicação pela imprensa de resumos."}, {"id": "1195555", "d": "direito_constitucional", "a": ["Educação, Cultura e Desporto", "Ordem Social"], "ano": "2012", "org": "DATAPREV", "t": "", "e": "O tema agora é \"da Ordem Social\" - Título XIII da Constituição Federal. Dentre as afirmações, apenas uma está de acordo com as normas constitucionais. Encontre-a.", "alt": {"A": "O Poder Judiciário só admitirá ações relativas à disciplina e ás competições desportivas após esgotarem-se as instâncias da justiça desportiva, regulada em lei.", "B": "O casamento é civil, gratuita a celebração e o casamento religioso tem efeito civil, nos termos da lei. O casamento civil pode ser dissolvido pelo divórcio, após comprovação da separação de fato e, desde a Emenda Constitucional no 66/2010, não há mais prazo mínimo.", "C": "Ficam tombados todos os documentos e os sítios detentores de reminiscências históricas dos antigos quilombos.", "D": "É facultado aos Estados e ao Distrito Federal vincular parcela de sua receita orçamentária a entidades públicas de fomento ao ensino e à pesquisa científica e tecnológica.", "E": "As condutas e atividades consideradas lesivas ao meio ambiente sujeitarão os infratores, pessoas físicas ou jurídicas, a sanções penais e administrativas, independentemente da obrigação de reparar os danos causados."}, "g": "B", "j": "Art. 226 §§1º, 2º e 6º CF/88 (com redação da EC 66/2010): casamento civil/gratuito, casamento religioso com efeito civil, divórcio sem prazo mínimo após EC 66/2010."}, {"id": "766765", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Ação Popular", "Mandado de Injunção", "Mandado de Segurança", "Habeas Data", "Habeas Corpus"], "ano": "2012", "org": "CRBio", "t": "", "e": "Assinale a alternativa que corretamente completa a lacuna.\n  Conceder-se-á _________________ para proteger direito\nlíquido e certo, não amparado por \"habeas-corpus\" ou\n\"habeas-data\", quando o responsável pela ilegalidade ou\nabuso de poder for autoridade pública ou agente de pessoa\njurídica no exercício de atribuições do Poder Público.", "alt": {"A": "Mandado de Segurança", "B": "Habeas Corpus", "C": "Habeas Data", "D": "Ação Popular", "E": "Ação Civil Pública"}, "g": "A", "j": "Art. 5º, LXIX CF/88: conceder-se-á mandado de segurança para proteger direito líquido e certo, não amparado por HC ou HD, quando o responsável pela ilegalidade for autoridade pública."}, {"id": "766763", "d": "direito_constitucional", "a": ["Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Constitucionais-Penais e Garantias Constitucionais do Processo"], "ano": "2012", "org": "CRBio", "t": "", "e": "Considere as seguintes afirmações:\n  I. Todos têm direito a receber dos órgãos públicos\ninformações de seu interesse particular ou de interesse\ncoletivo ou geral, que serão prestadas no prazo da lei,\nsob pena de responsabilidade, ressalvadas aquelas cujo\nsigilo seja imprescindível à segurança da sociedade e\ndo Estado.\n  II. A lei considerará crimes inafiançáveis e insuscetíveis de\ngraça ou anistia a prática da tortura, o tráfico ilícito de\nentorpecentes e drogas afins, o terrorismo e os\ndefinidos como crimes hediondos, por eles\nrespondendo os mandantes, os executores e os que,\npodendo evitá-los, se omitirem.  \nIII. Ninguém será preso senão em flagrante delito ou por\nordem escrita e fundamentada de autoridade judiciária\ncompetente, salvo nos casos de transgressão militar ou\ncrime propriamente militar, definidos em lei.\n  Pode-se afirmar que:", "alt": {"A": "somente I e II são corretas.", "B": "somente I e III são corretas.", "C": "somente II e III são corretas.", "D": "todas são incorretas.", "E": "todas são corretas."}, "g": "E", "j": "Os três itens correspondem ao texto literal do art. 5º CF/88: incisos XXXIII (informação), XLIII (crimes inafiançáveis) e LXI (prisão)."}, {"id": "575682", "d": "direito_constitucional", "a": ["Previdência Social", "Direitos Sociais", "Ordem Social", "Saúde"], "ano": "2012", "org": "CFP", "t": "", "e": "São responsabilidades estatais, segundo a Constituição da República de 1988:\n    \n \nI. A instituição da Seguridade Social como sistema básico de proteção social. \n \n II. Reconhecimento da obrigação do Estado em prestar de forma universal, pública e gratuita, atendimento na área de saúde em todos os níveis de complexidade.\n \n \n \nIII. Reconhecimento da assistência social como política pública, garantindo direito de acesso a serviços por parte de populações necessitadas, e direito a uma renda de solidariedade por parte de idoso e portadores de deficiência em situação de extrema pobreza. \n  IV. Reconhecimento do seguro-desemprego como direito social do trabalhador a uma provisão temporária de renda em situação de perda circunstancial de emprego.\n  \n  \n Estão corretas:", "alt": {"A": "somente I, II e III.", "B": "somente I e IV.", "C": "somente III e IV.", "D": "somente II, III e IV.", "E": "I, II, III e IV."}, "g": "E", "j": "Todos os 4 itens são responsabilidades do Estado: instituição da seguridade social (art. 194), saúde universal (art. 196), assistência social com BPC (art. 203 V) e seguro-desemprego (art. 7º II)."}, {"id": "443158", "d": "direito_constitucional", "a": ["Funções Essenciais à Justiça", "Ministério Público", "Advocacia Pública", "Defensoria Pública no Direito Constitucional"], "ano": "2012", "org": "DATAPREV", "t": "", "e": "A  respeito  das  funções  essenciais  à  justiça,  assinale  a alternativa  equivocada.", "alt": {"A": "Os  Procuradores-Gerais  dos  Ministérios  Públicos  nos  Estados  e  no  Distrito  Federal  e  Territórios  poderão  ser  destituídos  por  deliberação  da  maioria  absoluta  do  Poder  Legislativo,  na  forma  da  lei  complementar  respectiva.", "B": "A  Advocacia-Geral  da  União  tem  por  chefe  o  Advogado-Geral  da  União,  de  livre  nomeação  pelo  Presidente  da  República  dentre  cidadãos  maiores  de  trinta  e  cinco  anos,  de  notável  saber  jurídico  e  reputação  ilibada.", "C": "Os  Procuradores  dos  Estados  e  do  Distrito  Federal,  organizados em  carreira,  na  qual  o  ingresso  dependerá  de  concurso  público  de  provas  e  títulos,  com  a  participação  da  Ordem  dos  Advogados  do  Brasil  em  todas  as  suas  fases,  exercerão  a  representação  judicial  e  a  consultoria  jurídica  das  respectivas  unidades  federadas,  sendo  assegurada  estabilidade  após  dois  anos  de  efetivo  exercício,  mediante  avaliação  de  desempenho  perante  os  órgãos  próprios,  após  relatório circunstanciado das  corregedorias.", "D": "O  Conselho  Nacional  do  Ministério  Público  compõe-se  de  quatorze  membros  nomeados  pelo  Presidente  da  República,  depois  de  aprovada  a  escolha  pela  maioria  absoluta  do  Senado  Federal,  para  um mandato  de  dois  anos, admitida  uma  recondução.", "E": "A Defensoria Pública é instituição essencial à função jurisdicional do Estado, incumbindo-lhe a orientação jurídica e a defesa, em todos os graus, dos necessitados, na forma do art. 5º, LXXIV da Constituição Federal: o Estado prestará assistência jurídica integral e gratuita aos que comprovarem insuficiência de recursos."}, "g": "C", "j": "C é incorreta: art. 132, §único CF/88 (com redação da EC 19/98) — Procuradores dos Estados/DF têm estabilidade após TRÊS anos de efetivo exercício, não dois."}, {"id": "443157", "d": "direito_constitucional", "a": ["Direitos Sociais", "Administração Pública – Disposições Gerais e Servidores Públicos", "Direitos Individuais - Remédios Constitucionais e Garantias Processuais", "Direitos Constitucionais-Penais e Garantias Constitucionais do Processo", "Princípios da Administração Pública", "Direitos Individuais", "Direito à Liberdade"], "ano": "2012", "org": "DATAPREV", "t": "", "e": "Aponte  a  única  súmula  de  Tribunal  Superior  que  está integralmente correta.", "alt": {"A": "Não  é  válida  a  jornada  de  doze  horas  de  trabalho  por  trinta  e  seis  de  descanso,  ajustada  mediante  acordo  coletivo  de  trabalho  ou  convenção  coletiva  de  trabalho,  mesmo  que  assegurada  a  remuneração  em  dobro dos feriados trabalhados.", "B": "Incide  imposto de  renda  sobre a  indenização  por danos  morais.", "C": "É  admissível  a  fixação  de  pena  substitutiva  como  condição especial  ao  regime aberto.", "D": "É  ilícita  a  prisão  civil  de  depositário  infiel,  qualquer que  seja  a modalidade do depósito.", "E": "A nomeação de cônjuge ou parente em linha reta, colateral ou por afinidade, até o quarto grau, inclusive, da autoridade nomeante ou de servidor da mesma pessoa jurídica investido em cargo de direção, chefia ou assessoramento, para o exercício de cargo em comissão ou de confiança ou, ainda, de função gratificada na administração pública direta e indireta em qualquer dos poderes da União, dos Estados, do Distrito Federal e dos Municípios, não compreendido o ajuste mediante designações recíprocas, viola a Constituição Federal."}, "g": "D", "j": "Súmula Vinculante 25 STF: 'É ilícita a prisão civil de depositário infiel, qualquer que seja a modalidade do depósito.' Decorre da adesão do Brasil ao Pacto de San José da Costa Rica."}, {"id": "443156", "d": "direito_constitucional", "a": ["Organização do Estado – Municípios", "Organização Político-Administrativa do Estado"], "ano": "2012", "org": "DATAPREV", "t": "", "e": "Os  incisos  a  seguir  tratam  da  organização  do  Estado  e  dos Poderes,  de  acordo  com  o  estabelecido  pela  Constituição Federal.I.  A  eleição  do  Prefeito  e  do  Vice-Prefeito  realizar-se-á,  simultaneamente,  no  primeiro  domingo  de  outubro,  em  primeiro  turno,  e  no  último  domingo  de  outubro,  em  segundo  turno,  se  houver,  do  ano  anterior  ao  do  término  do  mandato  presidencial  vigente,  no  caso  de  Municípios com mais de duzentos mil  habitantes.II.  As Câmaras Municipais  terão  no mínimo  11  (onze)  e  no  máximo 53  (cinqüenta  e três) vereadores. III.  É  vedada  a  criação  de  Tribunais,  Conselhos  ou  órgãos  de Contas Municipais.IV.  O  controle  externo  da  Câmara  Municipal  será  exercido  com  o  auxílio  dos  Tribunais  de  Contas  dos  Estados  ou  do Município  ou  dos  Conselhos  ou  Tribunais  de  Contas  dos  Municípios,  onde  houver.  O  parecer  prévio,  emitido  pelo  órgão  competente  sobre  as  contas  que  o  Prefeito  deve  anualmente  prestar,  só  deixará  de  prevalecer  por  decisão  de  dois  terços  dos membros  da  Câmara Municipal.Os  incisos  incorretos são:", "alt": {"A": "I  e  II.", "B": "II e  III.", "C": "III  e  IV.", "D": "I  e  IV.", "E": "II e IV."}, "g": "A", "j": "I incorreto (descreve incorretamente datas e ciclo eleitoral municipal). II incorreto (art. 29, IV CF/88 — mínimo de 9 e máximo de 55 vereadores, não 11/53). III e IV corretos."}, {"id": "3843562", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2026", "org": "SES - SP", "t": "", "e": "Com base no texto e na análise das sequências textuais, \nassinale a opção correta.", "alt": {"A": "Contém, predominantemente, sequência textual \ninjuntiva e utiliza argumentação por dados concretos \ne por exemplificação, o que garante impessoalidade \nao texto.", "B": "Ao citar as falas de outrem, o texto define‑se \ncomo narrativo por apresentar discurso direto dos \nentrevistados.", "C": "A utilização de pesquisas realizadas confere \npessoalidade ao texto, pois a sequência textual \ndescritiva faz uso de adjetivações para compor a \ndescrição.", "D": "Apresenta caráter expositivo‑argumentativo, com uso \nde argumentos de autoridade e de dados concretos, \nque visam persuadir o leitor e a defender um ponto \nde vista.", "E": "O autor optou por utilizar as sequências textuais \nargumentativa e narrativa, para que a estrutura se \nadeque ao gênero artigo de opinião."}, "g": "D"}, {"id": "3754368", "d": "portugues", "a": ["Morfologia"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Na oração “os dois termos têm diferenças conceituais”, a\npalavra “dois” é um", "alt": {"A": "verbo.", "B": "artigo.", "C": "numeral.", "D": "advérbio.", "E": "substantivo."}, "g": "C"}, {"id": "3748788", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2025", "org": "CORE-SP", "t": "", "e": "Considerando os aspectos de forma e conteúdo, assinale a\nopção que apresenta o gênero desse texto.", "alt": {"A": "Auto ou esquete, pois traz um texto próprio das\ncomédias de costumes escritas para dramaturgia.", "B": "Solilóquio ou acróstico, pois é uma composição\npoética introspectiva.", "C": "Infográfico ou mapa mental, porque congrega\ninformações de diferentes naturezas com o objetivo\nprecípuo de informar", "D": "Notícia ou reportagem, por possuir estrutura de título,\nlide, corpo e referência e ter o objetivo principal de\ninformar.", "E": "Editorial ou artigo de opinião, pois tem como objetivo\nargumentar a favor ou contra um determinado ponto\nde vista."}, "g": "D"}, {"id": "3748101", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2025", "org": "Fundação do ABC", "t": "", "e": "Do trecho “Entre as doenças imunopreveníveis por essas\nvacinas, estão a poliomielite, o sarampo, a rubéola, o\ntétano, a coqueluche e outras doenças graves e, muitas\nvezes, fatais”, deduz‑se que as doenças citadas", "alt": {"A": "já foram erradicadas do Brasil e, por isso, dispensam\nvacinação.", "B": "não figuram como ameaças à população brasileira.", "C": "são raras e não prejudiciais à saúde.", "D": "podem matar quem as contrai.", "E": "nunca existiram no País."}, "g": "D"}, {"id": "3325135", "d": "portugues", "a": ["Morfologia - Pronomes"], "ano": "2025", "org": "CRF-MS", "t": "", "e": "No trecho “‘Tivemos mais de 24 milhões de pessoas\nbeneficiadas em 2024 e vamos aumentar ainda mais esse\nalcance principalmente nas áreas mais remotas desse país’,\ndisse a ministra.”, é correto afirmar que o uso do vocábulo\n“desse” está", "alt": {"A": "incorreto, e o correto seria “deste”.", "B": "correto, porque “esse” sempre se refere a algo\npróximo do ouvinte.", "C": "correto, porém tanto “esse” quanto “este” poderiam\nser utilizados sem alteração de sentido.", "D": "correto, pois a ministra quis enfatizar que falava de\nmaneira geral sobre o País.", "E": "correto, porque “deste” só se aplica a objetos físicos\nque o falante pode tocar."}, "g": "A"}, {"id": "3324351", "d": "portugues", "a": ["Sintaxe"], "ano": "2025", "org": "CRF-MS", "t": "", "e": "Em relação ao período “A Justiça determinou que apenas\nfarmacêuticos façam a entrega de medicamentos\nantibióticos e controlados em toda a rede municipal de\nsaúde de Aracaju.”, é possível afirmar que ele é composto\nde", "alt": {"A": "duas orações, sendo que uma exerce função de objeto\ndireto da outra.", "B": "três orações, sendo que, pelo menos, uma delas\nexerce função de adjunto adnominal.", "C": "uma oração absoluta com sujeito oculto.", "D": "duas orações, sendo que ambas são coordenadas\nentre si.", "E": "três orações, sendo que duas delas exercem função de\ncomplemento nominal em relação às anteriores."}, "g": "A"}, {"id": "3465835", "d": "portugues", "a": ["Sintaxe"], "ano": "2024", "org": "CRP - 23ª Região (TO)", "t": "", "e": "No último parágrafo, a palavra “quando” (linha 20) introduz\numa oração", "alt": {"A": "coordenada aditiva.", "B": "coordenada adversativa.", "C": "subordinada substantiva.", "D": "subordinada adjetiva.", "E": "subordinada adverbial."}, "g": "E"}, {"id": "3459174", "d": "portugues", "a": ["Sintaxe"], "ano": "2024", "org": "CRP - 23ª Região (TO)", "t": "", "e": "O termo “secretário” (linha 4) funciona como núcleo de um", "alt": {"A": "sujeito.", "B": "objeto direto.", "C": "objeto indireto.", "D": "agente da passiva.", "E": "aposto especificativo."}, "g": "D"}, {"id": "3232108", "d": "portugues", "a": ["Morfologia - Pronomes", "Pronomes demonstrativos"], "ano": "2024", "org": "CRESS - 1ª Região (PA)", "t": "", "e": "Em relação ao pronome “esta”, que inicia o segundo\nperíodo do primeiro parágrafo, assinale a alternativa que o\ndescreve e o analisa corretamente.", "alt": {"A": "Trata‑se de pronome demonstrativo de uso catafórico\nque, porém, no exemplo, foi usado em uma\nreferenciação anafórica.", "B": "Trata‑se de pronome possessivo utilizado para indicar\npertencimento, referindo‑se à medida de proteção\nmencionada anteriormente no texto.", "C": "Trata‑se de pronome pessoal de uso exclusivo na\nlíngua escrita, com a função de substituir o sujeito da\noração anterior", "D": "Trata‑se de pronome relativo que introduz uma oração\nsubordinada adjetiva explicativa, referindo‑se ao\nantecedente “medida de proteção”.", "E": "Trata‑se de pronome indefinido de uso anafórico\nque faz referência a uma ideia subsequente no texto,\nantecipando informações."}, "g": "A"}, {"id": "3230859", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2024", "org": "CONFERE", "t": "", "e": "O período “O conceito surgiu em 1994, quando Jeff Bezos,\nfundador da Amazon, deu espaço para os clientes avaliarem\nos seus produtos.” (linhas de 7 a 9) poderia ser reescrito,\ncom manutenção do sentido original e da correção\ngramatical, da seguinte forma:", "alt": {"A": "Quando o conceito surgiu, em 1994, Jeff Bezos,\nfundador da Amazon, deu espaço para os clientes\navaliarem os seus produtos.", "B": "O conceito foi surgido em 1994, quando o fundador\nda Amazon Jeff Bezos deu espaço para os clientes\navaliarem os seus produtos.", "C": "Quando Jeff Bezos, fundador da Amazon, deu espaço\npara os clientes avaliarem os seus produtos, em\n1994, o conceito surgiu.", "D": "O conceito surgiu em 1994, quando Jeff Bezos,\nfundador da Amazon, deu espaço para os seus\nprodutos ser avaliados pelos clientes.", "E": "Em 1994, quando o conceito surgiu, Jeff Bezos,\nfundador da Amazon, deu espaço para os clientes\navaliarem os seus produtos."}, "g": "C"}, {"id": "2590803", "d": "portugues", "a": ["Interpretação de Textos", "Coesão e coerência", "Morfologia - Pronomes", "Pronomes pessoais retos"], "ano": "2024", "org": "CRF-AC", "t": "", "e": "O referente do pronome “eles” (linha 5) no texto é", "alt": {"A": "“séculos” (linha 1).", "B": "“seguidores” (linha 2).", "C": "“acontecimentos” (linha 4).", "D": "“valores” (linha 6).", "E": "“pecados” (linha 8)."}, "g": "C"}, {"id": "2590800", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2024", "org": "CRF-AC", "t": "", "e": "Segundo as ideias do texto, a dor", "alt": {"A": "consiste em uma forma de redimir os pecados intrínsecos à espécie humana.", "B": "tornou-se mais intensa e incômoda para o ser humano com o passar dos séculos.", "C": "é/era proporcional aos erros cometidos, segundo os valores da cultura judaico-cristã.", "D": "foi, durante muito tempo, encarada com resignação.", "E": "é uma das maiores causas de súplicas e a inspiração de muitos poetas."}, "g": "D"}, {"id": "2522688", "d": "portugues", "a": ["Sintaxe", "Regência"], "ano": "2024", "org": "CRMV-SE", "t": "Texto para a questão.\nVeterinária responsável por “virada esotérica” de Milei\ndiz que tem dom de conversar com animais mortosInternet: <www.g1.globo.com> (com adaptações).", "e": "O trecho “Um dos clones logo morreu. Dos cinco restantes,\ncães enormes com os quais dividia um apartamento\nde 100 m², Milei se convenceu de que um deles era a\nreencarnação de Conan” (linhas de 36 a 39) demonstra que\na regência do verbo “convencer” é da preposição", "alt": {"A": "de.", "B": "se.", "C": "que.", "D": "de que.", "E": "um."}, "g": "A"}, {"id": "2495747", "d": "portugues", "a": ["Sintaxe", "Análise sintática"], "ano": "2024", "org": "CIS-AMURES - SC", "t": "", "e": "Assinale a alternativa em que o termo selecionado de um\ntrecho da tira tem a mesma função sintática que o termo\n“sempre” (primeiro quadrinho).", "alt": {"A": "“o hábito” em “Criar o hábito de lavar sempre as\nmãos!”", "B": "“bem” em “Tentar comer bem e descansar”.", "C": "“a imunidade” em “Pra não baixar a imunidade!”.", "D": "“SUS” em “Defender o SUS”.", "E": "“pública” em “E a pesquisa da universidade pública!”."}, "g": "B"}, {"id": "2363593", "d": "portugues", "a": ["Morfologia", "Interpretação de Textos", "Redação - Reescritura de texto", "Conjunções: Relação de causa e consequência"], "ano": "2023", "org": "FSNH - RS", "t": "", "e": "A expressão “à medida que” (linha 9) poderia ser substituída\nno texto, mantendo‑se seu sentido original e sua correção\ngramatical, por", "alt": {"A": "a partir do momento em que.", "B": "na medida em que.", "C": "contanto que.", "D": "já que.", "E": "como."}, "g": "B"}, {"id": "2198526", "d": "portugues", "a": ["Interpretação de Textos", "Coesão e coerência", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2023", "org": "CRM-MG", "t": "", "e": "O vocábulo “que” (linha 14) refere-se ao termo", "alt": {"A": "“pacientes” (linha 15).", "B": "“necessidades” (linha 15).", "C": "“atendimento médico” (linha 14).", "D": "“proposta” (linha 14).", "E": "“medicina humanizada” (linha 13)."}, "g": "E"}, {"id": "2019834", "d": "portugues", "a": ["Pontuação"], "ano": "2022", "org": "CRF-PR", "t": "", "e": "Com relação aos aspectos linguísticos do texto,\nparticularmente quanto à pontuação, assinale a alternativa\ncorreta.", "alt": {"A": "O sinal de dois-pontos empregado após “ela” (linha 22)\ne “novidade” (linha 30) introduz, em ambas as\nocorrências, uma explicação a respeito de um trecho\ndo texto.", "B": "As aspas empregadas em ‘carocinhos mágicos’ (linha\n48) indicam que essa expressão é uma citação.", "C": "Na linha 31, a vírgula utilizada logo após “confiança”\nisola uma expressão que qualifica o sujeito de “corro”.", "D": "As reticências logo após “desaparecido!” (linha 29)\nforam empregadas para indicar que o narrador se\nmostra hesitante.", "E": "No trecho “O meu Edgarzinho apareceu com uma\ndoença no nariz. Isso na fazenda. Ele tinha 2 anos.\nCorro a Taubaté. Consulto os médicos locais.” (linhas\nde 5 a 8), o emprego reiterado de ponto final\ndemonstra rispidez por parte do narrador."}, "g": "C"}, {"id": "2019120", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2022", "org": "Câmara de Goianésia - GO", "t": "Texto para a questão.", "e": "De acordo com o texto, uma forma de limitar o contato\nhumano com animais selvagens é", "alt": {"A": "evitar futuras pandemias.", "B": "estimar a existência de milhares de vírus.", "C": "reprimir o comércio ilegal de animais silvestres.", "D": "manter intocada a política de utilização da terra.", "E": "promover uma política de proteção dos rebanhos."}, "g": "C"}, {"id": "1974670", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2022", "org": "PRODAM-AM", "t": "", "e": "No texto, a palavra “obsoleto” (linha 7) está empregada com\no mesmo sentido de", "alt": {"A": "ultrapassado.", "B": "difícil.", "C": "inutilizado.", "D": "inoperante.", "E": "desengonçado."}, "g": "A"}, {"id": "1972706", "d": "portugues", "a": ["Sintaxe", "Orações coordenadas sindéticas: Aditivas, Adversativas, Alternativas, Conclusivas...", "Uso dos conectivos"], "ano": "2022", "org": "CRO - RS", "t": "Texto para a questão.", "e": "O conectivo “Porém” (linha 45) poderia ser substituído, sem\nprejuízo da coerência e dos sentidos do texto, por", "alt": {"A": "Porquanto, pois seu sentido é explicativo.", "B": "Embora, dado o seu sentido concessivo.", "C": "Assim, em razão de seu sentido conclusivo.", "D": "Entretanto, pois tem sentido adversativo.", "E": "Ainda, porque tem sentido aditivo."}, "g": "D"}, {"id": "1972207", "d": "portugues", "a": ["Interpretação de Textos", "Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos."], "ano": "2022", "org": "Prefeitura de Barreiras - BA", "t": "", "e": "Na sentença “Os reclamantes pleiteiam melhores salários.”, a\nforma verbal “pleiteiam” significa o mesmo que", "alt": {"A": "reivindicam.", "B": "merecem.", "C": "conquistam.", "D": "perguntam."}, "g": "A"}, {"id": "1972205", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2022", "org": "Prefeitura de Barreiras - BA", "t": "", "e": "Depreende-se do texto que César, Augusto, Nero e\nMassinissa são nomes de", "alt": {"A": "políticos brasileiros contemporâneos à publicação da\nobra.", "B": "pessoas importantes em tempos passados.", "C": "estrangeiros que se tornaram célebres por suas\ninvenções.", "D": "indivíduos que trabalharam na decoração da casa do\nnarrador."}, "g": "B"}, {"id": "1861454", "d": "portugues", "a": ["Interpretação de Textos", "Tipologia Textual"], "ano": "2021", "org": "CRBio-6ª Região", "t": "", "e": "Essa tipologia possui ações prescritivas, de forma que os\nprocedimentos para a realização de algo sejam indicados.\nTrata-se da", "alt": {"A": "exposição.", "B": "injunção.", "C": "dissertação.", "D": "descrição.", "E": "argumentação."}, "g": "B"}, {"id": "1785040", "d": "portugues", "a": ["Interpretação de Textos", "Morfologia - Verbos", "Flexão verbal de tempo (presente, pretérito, futuro)", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2021", "org": "CREF - 21ª Região (MA)", "t": "", "e": "No primeiro parágrafo do texto, o autor apresenta uma\nnarrativa, empregando, majoritariamente, verbos\nflexionados no tempo", "alt": {"A": "pretérito perfeito, para indicar que aqueles\nacontecimentos transcorreram em um passado\nrecente.", "B": "pretérito imperfeito, para deixar claro que aqueles\nacontecimentos transcorreram anos atrás.", "C": "pretérito mais-que-perfeito, para que o leitor entenda\nque aqueles acontecimentos transcorreram antes de\n2014.", "D": "presente, para que o leitor se sinta próximo daqueles\nacontecimentos enquanto lê.", "E": "futuro do pretérito, para sugerir que aquela\nexperiência pode ser novamente replicada no futuro."}, "g": "D"}, {"id": "1740421", "d": "portugues", "a": ["Ortografia"], "ano": "2021", "org": "CRC-AP", "t": "", "e": "O emprego de “z” em “imunizados” (linha 39) está", "alt": {"A": "correto, como em baze.", "B": "correto, como em braza.", "C": "correto, como em bazar.", "D": "incorreto, como em baliza.", "E": "incorreto, como em banalizar."}, "g": "C"}, {"id": "1686652", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2020", "org": "CREMERS", "t": "", "e": "Na última cena, fica claro que o", "alt": {"A": "colchão, de fato, está em ótimo estado de conservação.", "B": "personagem tem razão ao não querer trocar de\ncolchão.", "C": "personagem compreendeu a posição do ortopedista", "D": "ortopedista pode ter razão sobre o colchão.", "E": "ortopedista errou em sua previsão com relação ao\ncolchão."}, "g": "D"}, {"id": "1252593", "d": "portugues", "a": ["Pontuação", "Uso da Vírgula"], "ano": "2019", "org": "CRO - RS", "t": "", "e": "No  que  diz  respeito  à  pontuação  no  texto,  assinale  a alternativa correta.", "alt": {"A": "Estaria mantida a correção gramatical do texto caso o nome  “W. D. Miller”  (linha  1) estivesse  isolado entre vírgulas.", "B": "O  emprego  da  vírgula  após  “bucal”  (linha  10)  é optativo, ou seja, o  referido sinal de pontuação pode ser  suprimido  do  período  sem  prejuízo  da  correção gramatical do texto.", "C": "Estaria mantida a correção gramatical do texto caso a vírgula empregada após o termo “proteica” (linha 13) fosse substituída por ponto final, feito o devido ajuste de minúscula  para maiúscula  na  letra  inicial  do  novo período.", "D": "Estaria  mantida  a  correção  gramatical  do  texto  caso fosse  inserida  uma  vírgula  após  a  palavra  “gorduras” (linha 14).", "E": "O  emprego  de  vírgula  após  “dentário”  (linha  29) justifica‐se por isolar oração com sentido restritivo."}, "g": "B"}, {"id": "1252524", "d": "portugues", "a": ["Interpretação de Textos", "Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos."], "ano": "2019", "org": "CRO - RS", "t": "", "e": "Estariam  mantidas  a  correção  gramatical  e  a  coerência  do texto caso se substituísse", "alt": {"A": "“Segundo” (linha 1) por A despeito da.", "B": "“Faz parte” (linha 5) por Fazem parte.", "C": "“visa” (linha 9) por valida.", "D": "“caro” (linha 17) por dispendioso.", "E": "“logo” (linha 18) por entretanto."}, "g": "D"}, {"id": "1178007", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2019", "org": "CREMERS", "t": "", "e": "Assinale a alternativa correta em relação ao texto.", "alt": {"A": "No texto, pressupõe-se a intenção do emissor da mensagem de persuadir o receptor de que o acompanhamento psicológico \nevita o aparecimento de doenças.", "B": "A ideia central, apresentada no primeiro período do texto, é comprovada por meio da menção a trabalhos acadêmicos de \nprofissionais da área da saúde.", "C": "A  mensagem  central  do  texto  consiste  na  crítica  à  medicina  de  concepção  materialista,  focada  exclusivamente  em \nfenômenos biológicos.", "D": "Infere‐se da leitura do  texto que o emissor da mensagem é um pesquisador da área das ciências humanas com amplo \nconhecimento da relação entre saúde e processos psicossomáticos.", "E": "O  entendimento  da  mensagem  transmitida  no  texto  requer  do  receptor  conhecimento  especializado  do  sistema \nimunológico humano."}, "g": "B"}, {"id": "1078172", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2019", "org": "CRF-PR", "t": "", "e": "Assinale a alternativa que apresenta a ideia central do texto.", "alt": {"A": "medicamentos como agentes de cura", "B": "atribuição de conteúdo mágico aos medicamentos", "C": "efeitos adversos causados pelos medicamentos", "D": "utilização racional de medicamentos", "E": "uso inadequado dos medicamentos"}, "g": "C"}, {"id": "2799612", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2018", "org": "CRMV - MA", "t": "", "e": "Depreende]se da leitura do texto que", "alt": {"A": "as poças de água da chuva são os maiores focos de\nreprodução do mosquito Aedes aegypti.", "B": "os ovos do Aedes aegypti demoram um ano para se\ndesenvolverem em larvas que se transformam em\nmosquitos.", "C": "reservatórios com água devidamente clorada podem\npermanecer destampados, sem risco de reprodução do\nmosquito Aedes aegypti.", "D": "os casos de transmissão de microcefalia pelo mosquito\nAedes aegypti motivaram a atuação das forças de\nsegurança nacionais.", "E": "experimentos com peixes geneticamente modificados\nmostraram‐se eficazes no controle da proliferação do\nmosquito Aedes aegypti."}, "g": "C"}, {"id": "2044745", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2018", "org": "CRB 8º Região - SP", "t": "", "e": "Acerca do quadrinho apresentado, julgue os itens a seguir.     \nI  O humor é gerado a partir da leitura do último balão. \n  II  A  sequência  de  ações  serve  para  criticar,  ampla  e \ngeneralizadamente, aqueles que leem jornal.   III  Nos  quatro  primeiros  balões,  aparecem  falas  que  se \nsomam  umas  às  outras  –  o  que  é  marcado  pela \npresença do conector “e”. \n  IV  O  conteúdo  sensacionalista  do  jornal  é  a  principal \ncausa geradora de reflexão para aqueles que leem os \nquadrinhos, que não apresentam humor.     \nAssinale a alternativa correta.", "alt": {"A": "Apenas os itens I e II estão certos.", "B": "Apenas os itens I e III estão certos.", "C": "Apenas os itens I e IV estão certos.", "D": "Apenas os itens II e III estão certos.", "E": "Apenas os itens III e IV estão certos."}, "g": "B"}, {"id": "1295774", "d": "portugues", "a": ["Interpretação de Textos", "Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos."], "ano": "2018", "org": "SESC-DF", "t": "", "e": "Assinale  a  alternativa  que  apresenta  frase  cujo  verbo \ndestacado,  quanto  ao  significado,  equivale  ao  verbo \n“persuadir”  no  trecho  “Certas  pessoas  são  facilmente \ncontaminadas pelo mal e se deixam persuadir sem perceber” \n(linhas 10 e 11).", "alt": {"A": "A pessoa foi incitada a praticar as referidas ações.", "B": "As demais pessoas acolheram as ações com respeito.", "C": "Depois  de  três  horas  de espera,  todos seguiram  com \ncalma para o local.", "D": "As  atitudes  tomadas  deveriam  ser  acatadas  com \nrespeito.", "E": "Ninguém considerou a atitude inadequada."}, "g": "A"}, {"id": "1295397", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2018", "org": "SESC-DF", "t": "", "e": "O texto tem como objetivo", "alt": {"A": "argumentar  em  favor  do  aumento  de  investimentos \npúblicos na área da engenharia genética.", "B": "defender a tese de que pesquisas com cobaias animais \nsão fundamentais na área médica.", "C": "propor uma reflexão crítica a respeito dos limites éticos \ndos avanços científicos na área da saúde.", "D": "divulgar  os  avanços  científicos  no  âmbito  da \nodontologia,  que envolvem uma  técnica  regenerativa \nque poderá revolucionar a área da saúde.", "E": "narrar  fatos  que  comprovam  que  os  implantes \ndentários  são,  na  atualidade,  a  melhor  alternativa \nterapêutica na odontologia."}, "g": "D"}, {"id": "1293131", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2018", "org": "SESC-DF", "t": "", "e": "Quando nasci, um anjo torto   desses que vivem na sombra   disse: Vai, Carlos! ser gauche na vida.    Carlos Drummond de Andrade. Poema de Sete Faces. In:    Alguma Poesia. Belo Horizonte: Pindorama, 1930, p. 15.     Quando nasci veio um anjo safado   O chato dum querubim   E decretou que eu tava predestinado   A ser errado assim   Já de saída a minha estrada entortou   Mas vou até o fim     Francisco Buarque de Holanda. Até o fim. In: Chico Buarque.    Rio de Janeiro: Marola Edições Musicais, 1978.    Internet: <www.chicobuarque.com.br>.     Assinale a alternativa correta quanto às  relações existentes  entre  o  trecho  do  poema  de  Drummond  e  o  da  letra  da  canção de Chico Buarque de Holanda.", "alt": {"A": "Ambos  os  textos  fazem  referência  a  um  mesmo  contexto: o período da ditadura militar no Brasil.", "B": "A aproximação entre os  textos indica a superioridade \ndo  texto  original  –  o  poema  –  sobre  a  canção  nele \ninspirada.", "C": "Embora  produzidos  em  um  mesmo  contexto,  o \nemprego  da  linguagem  informal  confere  maior \nrealismo à canção que ao poema.", "D": "A relação entre os textos supera a simples repetição de \ntemas  e  palavras  para  alcançar  a  dimensão \nintertextual:  o  diálogo  criativo  produtor  de  novos \nsentidos.", "E": "O diálogo intertextual revela que, no texto da canção,  prevalece uma perspectiva determinista, enquanto, no  poema, o eu‐lírico autodetermina o seu destino diante  de um contexto adverso."}, "g": "D"}, {"id": "1289308", "d": "portugues", "a": ["Sintaxe", "Termos essenciais da oração: Sujeito e Predicado"], "ano": "2018", "org": "SESC-DF", "t": "", "e": "No trecho \"A acreditarmos na pesquisa\" (linha 38), o sujeito\nda oração admite a mesma classificação do sujeito da oração", "alt": {"A": "Eramos meu pai e eu.", "B": "Gosto de chuva, Pedro.", "C": "Como podia haver tantos interessados em mentiras?", "D": "Anunciaram um fato indevido.", "E": "Pede-se silêncio a partir de agora."}, "g": "B"}, {"id": "994967", "d": "portugues", "a": ["Morfologia", "Advérbios"], "ano": "2018", "org": "CRB 8º Região - SP", "t": "", "e": "Há  dois  adjuntos  adverbiais,  no  segundo  período  do  balão, que indicam, respectivamente, circunstâncias de", "alt": {"A": "afirmação e dúvida.", "B": "intensidade e causa.", "C": "negação e tempo.", "D": "lugar e modo.", "E": "causa e dúvida."}, "g": "D"}, {"id": "2792280", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2017", "org": "TERRACAP", "t": "", "e": "Assinale a alternativa correta de acordo com o exposto no texto.", "alt": {"A": "O sonho dos fundadores de Brasília foi frustrado pelo Poder Público, que não controla o êxodo rural.", "B": "O crescimento populacional em Brasília superou muito o previsto no plano original da cidade.", "C": "O surgimento de loteamentos irregulares em Brasília deve-se às falhas na lei que regulamenta o parcelamento do solo no DF.", "D": "Os problemas sociais enfrentados hoje no DF resultam da ganância dos grandes proprietários de terra.", "E": "É equivocada a ideia de que o combate aos loteamentos irregulares vise à preservação dos interesses coletivos."}, "g": "B"}, {"id": "2740601", "d": "portugues", "a": ["Funções morfossintáticas da palavra QUE"], "ano": "2017", "org": "CONTER", "t": "Para responder às questões de 6 a 10, leia os quadrinhos a seguir.(http://unasp-ec.com/fisica/index.php/questoes-de-vestibular-fisica/ufabc-fisica/)", "e": "No trecho “Você acha que nós queremos ver isso?”, o “que”:", "alt": {"A": "deveria, obrigatoriamente, ser substituído por “o qual”.", "B": "deveria, obrigatoriamente, ser substituído por “nos\nquais”.", "C": "é um pronome relativo.", "D": "introduz uma oração subordinada substantiva.", "E": "é uma preposição, já que une termos de mesma\nclassificação morfológica."}, "g": "D"}, {"id": "1702272", "d": "portugues", "a": ["Morfologia", "Preposições", "Artigos", "Interpretação de Textos", "Coesão e coerência", "Redação - Reescritura de texto"], "ano": "2017", "org": "CRF-RS", "t": "", "e": "Observe as afirmativas a respeito de passagens do quarto\nparágrafo do texto.I. A palavra \"dos\", em \"apesar dos problemas de saúde da\nmaioria dos brasileiros pobres\", deveria ser substituída\npor \"de os\".\nII. A palavra \"mal\", em \"mal conseguem ter acesso a\nalimentos básicos\", poderia ser substituída por \"nem\nbem\".\nIII. Na passagem \"mais que o dobro do recomendado pela\nOrganização Mundial de Saúde\", seria possível escrever\n\"mais do que o dobro\".\nEstá correto o que se afirma em:", "alt": {"A": "I, somente.", "B": "II, somente.", "C": "III, somente.", "D": "I e III, somente.", "E": "II e III, somente."}, "g": "E"}, {"id": "1363645", "d": "portugues", "a": ["Morfologia", "Pontuação", "Uso da Vírgula", "Interpretação de Textos", "Coesão e coerência", "Conjunções: Relação de causa e consequência", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2017", "org": "CAESB-DF", "t": "Yuval Noah Harari. Sapiens – uma breve história da humanidade.\nTrad. Janaína Marcoantonio. 22.ª ed. Porto Alegre: L&PM,\n2017, p. 286-287 (com adaptações).", "e": "Assinale a alternativa correta com relação aos mecanismos de\ncoesão no texto.", "alt": {"A": "Em “que partiam para terras distantes” (linha 4), o\nvocábulo “que” refere-se à “tripulação” (linha 3).", "B": "No segmento “Ninguém sabia o que o causava”\n(linhas 13 e 14), “o”, em “o causava”, retoma o termo\n“Ninguém”.", "C": "Na linha 16, sem prejuízo da correção gramatical e dos\nsentidos do texto, a conjunção “quando” poderia ser\ndeslocada para o início do período, feitos os devidos\najustes de maiúsculas e minúsculas – Quando a\nsituação mudou.", "D": "À linha 30, estariam mantidas a correção gramatical e\na coerência das ideias do texto caso o ponto final que\nfecha o período fosse substituído por vírgula e o\npronome “Ele” fosse substituído pela conjunção e.", "E": "Sem prejuízo da correção gramatical e da coerência das\nideias do texto, o período iniciado à linha 31 poderia\nser assim introduzido: Não obstante, carregou um\nbarco."}, "g": "D"}, {"id": "958578", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2017", "org": "CRF - AL", "t": "", "e": "Quanto aos quadrinhos como um todo, mãe e filho\nconversarem, como sugerido no terceiro quadrinho, seria\nmomento posterior àquele em que:", "alt": {"A": "o filho ingerisse um remédio para dor de cabeça", "B": "a mãe começasse a sentir dor de cabeça.", "C": "o filho contasse à mãe o que desejasse.", "D": "a mãe ingerisse um remédio para dor de cabeça.", "E": "os dois personagens se encontrassem fora de casa."}, "g": "D"}, {"id": "2807968", "d": "portugues", "a": ["Interpretação de Textos", "Tipologia Textual", "Vícios da linguagem"], "ano": "2016", "org": "CRB 4° Região - PE", "t": "", "e": "A palavra \"BLAM\", que aparece no segundo quadrinho, apresenta um processo de formação especial, que é a:", "alt": {"A": "onomatopeia.", "B": "parassíntese.", "C": "redução.", "D": "aglutinação.", "E": "abreviação."}, "g": "A"}, {"id": "1701311", "d": "portugues", "a": ["Funções morfossintáticas da palavra QUE"], "ano": "2016", "org": "CRMV-MT", "t": "Espetáculos públicos e exibição de animais\n    Desde que se tem notícia da existência do homem\nsobre a terra, está ele, de uma forma ou de outra,\ninteragindo com os animais. Das arenas romanas até nossos\ndias, vê-se que o homem pouco evoluiu, vez que ainda se\nregozija com o sofrimento alheio. Com o monoteísmo,\ndifundiu-se a ideia de que o homem deveria dominar a\nnatureza e as criaturas que nela habitavam, dogma que tem\nsido levado a efeito de forma irracional e irresponsável.    É relativamente recente a consciência da finitude\ndos recursos naturais. Do mesmo modo a ideia acerca da\ndignidade animal e, como decorrência, a visão de que os\nanimais são, por si mesmos, detentores de direitos em face\ndo homem.         A questão é posta, por outro lado, dentro do\nconceito amplo de dignidade humana e, especificamente,\nem comparação com as diretrizes traçadas pela União no\nrespeitante à política de educação ambiental.    Analisa-se a questão, ainda, sob a ótica da ciência,\nda ética e da medicina veterinária.    Todas essas considerações são contrapostas aos\npreceitos e princípios constitucionais ambientais, focando,\ndepois, a análise sobre a constitucionalidade da legislação\nespecífica infraconstitucional, propondo, ao final, adoção\nde medidas práticas visando a mais ampla e efetiva defesa\nda vida animal.    O Ministério Público fundamenta sua atuação\nprotetiva da fauna no disposto nos artigos 129, inciso III e\n225, § 1º, inciso VII, da Constituição da República e no\nartigo 5º, da Lei nº 7347/85    Ressalte-se, ainda, que o Brasil é subscritor de um\ntratado internacional denominado “Declaração Universal\ndos Direitos dos Animais”, firmado em Bruxelas, na Bélgica,\nem 27/01/78, em Assembleia da UNESCO, no qual é\nconferido a todos os bichos o direito à vida e à existência, à\nconsideração e ao respeito, à cura e à proteção do homem.    Declara o repúdio à tortura para com os animais,\nimpedindo a destruição ou violação da integridade de um\nser vivo e prevê no artigo 3º que nenhum animal será\nsubmetido a maus tratos e a atos cruéis e no artigo 5º que\ncada animal pertencente a uma espécie que vive\nhabitualmente no ambiente do homem, tem o direito de\nviver e crescer segundo o ritmo e as condições de vida e de\nliberdade que são próprias da sua espécie, sendo que toda\nmodificação desse ritmo e dessas condições, imposta pelo\nhomem para fins mercantis, é contrária a esse direito.    Deve ressaltar-se, por fim, que o artigo 10 prevê\nque nenhum animal deve ser usado para divertimento do\nhomem e que a exibição deles e os espetáculos que deles\nse utilizam são incompatíveis com a sua dignidade.\n(Adaptado de http://www.portalseer.ufba.br)", "e": "Sobre as cinco ocorrências de “que” em destaque no\npenúltimo parágrafo do texto, pode-se afirmar\ncorretamente que:", "alt": {"A": "nenhuma delas é exemplo de pronome.", "B": "três delas são exemplos de conjunções subordinativas\nadverbiais.", "C": "todas são exemplos de pronomes oblíquos.", "D": "a primeira e a segunda são conjunções integrantes; a\nterceira e a quarta são pronomes relativos.", "E": "apenas a primeira e a última são pronomes."}, "g": "D"}, {"id": "1358165", "d": "portugues", "a": ["Interpretação de Textos", "Sintaxe", "Uso dos conectivos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2016", "org": "CREMAM", "t": "", "e": "Veja:\n\"Isso não só seria uma oportunidade única para os\ncientistas brasileiros (pois o mecanismo de ação do vírus é\nainda desconhecido), como permitiria que o governo\ninvestisse em soluções definitivas (ao invés de investir em\nevitar mosquitos).\"Considerando que a expressão “ao invés de” só pode ser\nutilizada para indicar termos ou expressões de ideias\ndiametralmente opostas entre si e considerando, ainda,\nque ela foi corretamente utilizada na passagem acima,\npode-se concluir, pela interpretação do texto, que:", "alt": {"A": "“investir em evitar mosquitos” é considerada, pelo\nautor, uma solução não definitiva.", "B": "“investir em evitar mosquitos” é considerada, pelo\nautor, uma solução inútil.", "C": "“investir em evitar mosquitos” é considerada, pelo\nautor, uma solução mais útil do que qualquer outra.", "D": "“investir em evitar mosquitos” é considerado, pelo\nautor, um sinônimo de “solução definitiva”.", "E": "“investir em evitar mosquitos” é considerada, pelo\nautor, uma solução criativa e definitiva para a solução\ndo problema."}, "g": "A"}, {"id": "1255218", "d": "portugues", "a": ["Sintaxe", "Termos integrantes da oração: Objeto direto, Objeto indireto, Complemento nominal, Agente da Passiva"], "ano": "2016", "org": "CREF - 10ª Região (PB)", "t": "", "e": "A palavra \"me\", que aparece no último balão do terceiro\nquadrinho, exerce função sintática de:", "alt": {"A": "objeto direto.", "B": "sujeito.", "C": "objeto indireto.", "D": "preposição.", "E": "adjunto adnominal."}, "g": "C"}, {"id": "1136725", "d": "portugues", "a": ["Interpretação de Textos", "Coesão e coerência", "Sintaxe", "Análise sintática", "Morfologia - Pronomes", "Pronomes relativos"], "ano": "2016", "org": "CRO - PE", "t": "", "e": "O primeiro parágrafo do texto é composto por dois\nperíodos sintaticamente desconectados entre si, mas que\npoderiam ser ligados pelo emprego de um pronome\nrelativo, formando apenas um único período. Agora,\nassinale a alternativa que assim os conecte, adequada e\ncorretamente.", "alt": {"A": "De 2014 até maio de 2015, o Conselho Regional de\nOdontologia do Amazonas (CRO-AM) emitiu 361\nnotificações por diversos tipos de irregularidades na área\nde odontologia, dentre que o Exercício Ilegal da profissão.", "B": "De 2014 até maio de 2015, o Conselho Regional de\nOdontologia do Amazonas (CRO-AM) emitiu 361\nnotificações pelos quais diversos tipos de irregularidades\nna área de odontologia, dentre elas o Exercício Ilegal da\nprofissão.", "C": "De 2014 até maio de 2015, o Conselho Regional de\nOdontologia do Amazonas (CRO-AM) emitiu 361\nnotificações por diversos tipos de irregularidades na área\nde odontologia, dentre as quais o Exercício Ilegal da\nprofissão.", "D": "De 2014 até maio de 2015, o Conselho Regional de\nOdontologia do Amazonas (CRO-AM) emitiu 361\nnotificações que diversos tipos de irregularidades na área\nde odontologia, dentre elas o Exercício Ilegal da profissão.", "E": "De 2014 até maio de 2015, o qual Conselho Regional de\nOdontologia do Amazonas (CRO-AM) emitiu 361\nnotificações por diversos tipos de irregularidades na área\nde odontologia, dentre elas o Exercício Ilegal da profissão."}, "g": "C"}, {"id": "1096428", "d": "portugues", "a": ["Morfologia", "Substantivos", "Adjetivos", "Conjunções: Relação de causa e consequência", "Morfologia - Verbos", "Classificação dos verbos (Regulares, Irregulares, Defectivos, Abundantes, Unipessoais, Pronominais)"], "ano": "2016", "org": "CRA-AC", "t": "Para responder à questão, leia o texto abaixo. Investigação da Fifa vê indícios de irregularidades cometidas por BlatterEm outubro de 2011, funcionários foram premiados com US$ 14 milhões em bônus para a Copa do Mundo 2014\n    Investigação interna feita pela Federação Internacional de Futebol informa ter encontrado evidências de violações cometidas pelo ex-presidente da entidade, Joseph Blatter, e pelos ex-secretários gerais Jérôme Valckee e Markus Kattner. Segundo a Fifa, por meio de aumentos salariais, bônus e incentivos, os três enriqueceram em mais de US$ 79 milhões em apenas cinco anos.    Por meio de nota, a Fifa divulgou os resultados, que são ainda preliminares. De acordo com um dos investigadores do caso, Quinn Emanuel, foram aprovadas alterações contratuais problemáticas em favor de Blatter, Kattner e Valcke. \"Essas alterações resultaram em pagamentos maciços, no valor de dezenas de milhões de dólares, para os ex-funcionários na forma de salários e bônus entre os anos de 2011 e 2015\", disse Emanuel, por meio de nota. Enriquecimento      Segundo ele, há documentos e provas revelando \"um esforço coordenado por três altos funcionários da Fifa para enriquecer através de aumentos anuais de salário e bônus da Copa do Mundo, bem como o pagamento de indenizações indevidas.\" Em apenas uma das operações citadas pelos investigadores, os três teriam recebido, em 2010, US$ 23 milhões em bônus especiais para a Copa daquele ano, realizada na África do Sul. De acordo com a nota da Fifa, foram atribuídos efeitos retroativos a esses prêmios quatro meses após a conclusão da Copa, \"aparentemente, sem uma cláusula contratual subjacente estipulando tais bônus\".    Em outubro de 2011, Valcke e Kattner foram premiados novamente com um combinado de US$ 14 milhões em bônus para a Copa do Mundo 2014 e em junho de 2014 receberam outros US$ 15,5 milhões em bônus para a Copa do Mundo de 2018, na Rússia.\n(http://www.administradores.com.br/)", "e": "Veja:\n    “Em apenas uma das operações citadas pelos\ninvestigadores, os três teriam recebido, em 2010, US$ 23\nmilhões em bônus especiais para a Copa daquele ano,\nrealizada na África do Sul.”\n    Sobre o trecho, assinale a afirmação correta.", "alt": {"A": "A palavra “operações” está flexionada no feminino e\nno plural.", "B": "A palavra “ano” não tem gênero definido.", "C": "Há problemas de flexão de gênero, já que existe um\npar de substantivo e adjetivo que não combinam em\ngênero entre si.", "D": "A palavra “em” classifica-se como conjunção.", "E": "A palavra “três” é uma forma verbal flexionada de\nmaneira equivocada, já que se trata de verbo irregular."}, "g": "A"}, {"id": "961142", "d": "portugues", "a": ["Interpretação de Textos", "Coesão e coerência", "Redação - Reescritura de texto"], "ano": "2016", "org": "CRA-GO", "t": "", "e": "Assinale a alternativa em que o trecho \"esse é o mesmo\npedido que você me mostrou ontem\" tenha sido\ncorretamente reescrito, em total respeito à Norma Culta\nescrita da Língua Portuguesa, mantendo-se o sentido\noriginal.", "alt": {"A": "Este é o mesmo pedido que ontem foi mostrado por\nmim.", "B": "Este é o mesmo pedido que me é mostrado por você.", "C": "Este é o mesmo pedido que ontem me foi mostrado\npor você.", "D": "Este é o mesmo pedido que ontem se mostrou a você.", "E": "Este é o mesmo pedido que ontem você se mostrou a\nmim."}, "g": "C"}, {"id": "748022", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2016", "org": "CRQ 18° Região - PI", "t": "", "e": "Pode-se afirmar que, no segundo quadrinho:", "alt": {"A": "aparece, no alto, exatamente o que a professora leu,\nem voz alta, para o aluno.", "B": "aparece, no alto, o que a professora pensou quando\nouviu o questionamento do aluno.", "C": "aparece, no alto, o enunciado da questão, como a\nprofessora o vê na prova, o que é imprescindível para a\ncompreensão dos quadrinhos.", "D": "aparece, no alto, o enunciado da questão, como a\nprofessora o vê na prova, o que é prescindível para a\ncompreensão dos quadrinhos.", "E": "aparece, por escrito, qual foi a observação registrada\npela professora na prova do aluno para mostrar que a\nquestão estava errada."}, "g": "C"}, {"id": "717569", "d": "portugues", "a": ["Morfologia - Pronomes", "Pronomes pessoais retos", "Pronomes demonstrativos", "Pronomes pessoais oblíquos", "Colocação Pronominal"], "ano": "2016", "org": "CRQ 18° Região - PI", "t": "As 12 substâncias químicasque causam mais problemas hormonais       Uma organização americana1 dedicada a estudar\nos efeitos ambientais sobre a saúde das pessoas e animais\ndivulgou uma lista com as substâncias químicas2 que mais\ncausam danos ao corpo por provocar alterações hormonais.\nEsses compostos são os chamados desreguladores\nendócrinos – uma vez em contato com o organismo, eles\nimitam a ação de hormônios naturais3\n, alterando a ação ou\na quantidade deles no corpo.\n               “Nós estamos rotineiramente expostos a esses\ndesreguladores endócrinos e isso tem um potencial de\nprejudicar de forma significativa a saúde dos jovens. É\nimportante fazermos o que estiver ao nosso alcance para\nevitá-los”, diz Renee Sharp, diretor de pesquisa do\nEnvironmental Working Group (EWG), que elaborou a lista.          Para fazer a lista, os pesquisadores do EWG\nreuniram uma série de artigos científicos4\nsobre os efeitos\ndessas substâncias na saúde das pessoas. Segundo os\nespecialistas do grupo, os desreguladores endócrinos\npodem ser muitas vezes encontrados em alimentos, água,\nembalagens e produtos de consumo, como os de limpeza e\ncosméticos. A exposição a esses compostos já foi associada\na diversos5 problemas: entre eles danos à fertilidade e à\ncognição e um maior risco de câncer.           Entre os itens da lista do EWG, está o bisfenol A\n(BPA), um composto químico presente6 principalmente em\nalguns objetos de plástico e latas de alumínio. A substância\nvem sendo alvo de uma série de pesquisas científicas, que\njá encontraram uma relação entre o BPA e problemas de\nfertilidade, obesidade, câncer, entre outras condições.\nEstudos como esses fizeram com que a Agência Nacional de\nVigilância Sanitária (Anvisa) proibisse, em setembro de\n2011, a comercialização de mamadeiras com a presença do\ncomposto.\n(veja.abril.com.br)", "e": "No segundo parágrafo, está destacada a forma \"evitá-los\".\nAnalise o contexto em que ela aparece e assinale a\nalternativa que contenha uma análise totalmente correta.", "alt": {"A": "Trata-se de uma forma conjugada do verbo \"evitar\"\nunida a uma variação do pronome oblíquo \"os\".", "B": "Trata-se da forma infinitiva do verbo \"evitar\" unida a\numa variação do pronome do caso oblíquo \"os\".", "C": "Trata-se da forma infinitiva do verbo \"evitar\" unida à\nforma de um pronome demonstrativo.", "D": "Trata-se da forma infinitiva de um verbo da segunda\nconjunção unida a um pronome do caso reto.", "E": "A forma \"evitá-los\" está incorreta: o mais correto seria\nescrever \"evitar-os\"."}, "g": "B"}, {"id": "697618", "d": "portugues", "a": ["Interpretação de Textos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2016", "org": "CRA-AC", "t": "", "e": "A abreviatura é um recurso convencional da língua escrita\nque consiste em representar de forma reduzida certas\npalavras ou expressões. É utilizada em pareceres,\ncomunicados, relatórios. Quantos dos conjuntos de\nabreviaturas elencados a seguir estão corretos?  I. dipl. = diploma / adm.= administração / comp. =\n(companhia)  \nII. rel., relat. = relatório / rem.te = remetente / sec., secr.\n= secretaria, secretário, secretária  \nIII. séc., sécs. = século, séculos / secç. = seção / s.d. = sem\ndata\n  IV. leg., legisl. = legislação / l., liv., livr. = livro / jur. =\njurídico\n  V. dec. = decreto / dep., deps. = departamento,\ndepartamentos / fl.; fls. = folha; folhas", "alt": {"A": "Quatro, somente.", "B": "Três, somente.", "C": "Cinco.", "D": "Dois, somente.", "E": "Um, somente."}, "g": "B"}, {"id": "686322", "d": "portugues", "a": ["Interpretação de Textos", "Morfologia - Pronomes", "Pronomes demonstrativos", "Noções Gerais de Compreensão e Interpretação de Texto"], "ano": "2016", "org": "CFB", "t": "", "e": "Analise o emprego do pronome \"este\" no primeiro\nquadrinho e assinale a alternativa correta sobre ele.", "alt": {"A": "O pronome não foi corretamente empregado, já que\nestá se referindo ao livro que está nas mãos do\ninterlocutor, o personagem Pateta.", "B": "De acordo com a Norma Culta Padrão, não há qualquer\ndiferença de uso entre os pronomes \"este\" e \"esse\".\nAmbos, portanto, estariam corretamente empregados\nno contexto da tirinha.", "C": "O mais correto teria sido empregar o pronome\n\"aquele\", no contexto da tirinha, por se referir a um\nlivro que não está presente no momento do discurso.", "D": "O emprego do pronome \"este\", no lugar de \"esse\", já\nindica que a intenção do personagem Pateta é\nemprestar o livro ao personagem Mickey.", "E": "O pronome foi corretamente empregado por estar se\nreferindo ao livro que está nas mãos do próprio\nemissor, o personagem Pateta."}, "g": "E"}, {"id": "686238", "d": "portugues", "a": ["Interpretação de Textos", "Tipologia Textual"], "ano": "2016", "org": "CRMV-RR", "t": "[...]\n                                                                    NO BRASIL\nCom a chegada da família real ao Brasil, em 1808,\nnossa cultura científica e literária recebeu novo alento, pois\naté então não havia bibliotecas, imprensa e ensino superior\nno Brasil Colônia. São fundadas, inicialmente, as Faculdades\nde Medicina (1815), Direito (1827) e a de Engenharia\nPolitécnica (1874).Quanto ao ensino das Ciências Agrárias, seu\ninteresse só foi despertado quando o Imperador D. Pedro II,\nao viajar para a França, em 1875, visitou a Escola\nVeterinária de Alfort, impressionou-se com uma\nConferência ministrada pelo Veterinário e Fisiologista\nCollin. Ao regressar ao Brasil, tentou propiciar condições\npara a criação de entidade semelhante no País. Entretanto, somente no início deste século, já sob\nregime republicano, nossas autoridades decretaram a\ncriação das duas primeiras instituições de ensino de\nVeterinária no Brasil, a Escola de Veterinária do Exército,\npelo Dec. nº 2.232, de 06 de janeiro de 1910 (aberta em\n17/07/1914), e a Escola Superior de Agricultura e Medicina\nVeterinária, através do Dec. nº 8.919 de 20/10/1910\n(aberta em 04/07/1913), ambas na cidade do Rio de\nJaneiro. Em 1911, em Olinda, Pernambuco, a Congregação\nBeneditina Brasileira do Mosteiro de São Bento, através do\nAbade D. Pedro Roeser, sugere a criação de uma instituição\ndestinada ao ensino das ciências agrárias, ou seja,\nAgronomia e Veterinária. As escolas teriam como padrão de\nensino as clássicas escolas agrícolas da Alemanha, as\n\"Landwirschaf Hochschule\". No dia 1º de julho de 1914, eram inaugurados,\noficialmente, os cursos de Agronomia e Veterinária.\nTodavia, por ocasião da realização da terceira sessão da\nCongregação, em 15/12/1913, ou seja antes da abertura\noficial do curso de Medicina Veterinária, um Farmacêutico\nformado pela Faculdade de Medicina e Farmácia da Bahia\nsolicitava matrícula no curso de Veterinária, na condição de\n\"portador de outro diploma do curso superior\". A\nCongregação, acatando a solicitação do postulante, além de\naceitar dispensa das matérias já cursadas indica um\nprofessor particular, para lhe transmitir os conhecimentos\nnecessários para a obtenção do diploma antes dos (quatro)\nanos regimentares. Assim, no dia 13/11/1915, durante a\n24ª sessão da Congregação, recebia o grau de Médico\nVeterinário o senhor DIONYSIO MEILLI, primeiro Médico\nVeterinário formado e diplomado no Brasil. Desde o início de suas atividades até o ano de 1925,\nforam diplomados 24 Veterinários. Em 29 de janeiro, após\n13 anos de funcionamento, a Escola foi fechada por ordem\ndo Abade D. Pedro Roeser.A primeira mulher diplomada em Medicina\nVeterinária no Brasil foi a DRA. NAIR EUGENIA LOBO, na\nturma de 1929 pela Escola Superior de Agricultura e\nVeterinária, hoje Universidade Federal Rural do Rio de\nJaneiro.No Brasil, os primeiros trabalhos científicos\nabrangendo a patologia comparada (animal e humana) foram realizados pelo Capitão-Médico JOÃO MONIZ\nBARRETO DE ARAGÃO, fundador da Escola de Veterinária\ndo Exército, em 1917, no Rio de Janeiro, e cognominado\nPATRONO DA VETERINÁRIA MILITAR BRASILEIRA, cuja\ncomemoração se dá no dia 17 de junho, data oficial de\ninauguração da Escola de Veterinária do Exército\n(17/06/1914). ,(http://www.portaleducacao.com.br/veterinaria/artigos/4043/historia-da-medicina-veterinaria-e-do-medico-veterinario)", "e": "Após a leitura do excerto reproduzido, é possível afirmar\nque as características textuais permitem caracterizá-lo\ncomo:", "alt": {"A": "um projeto.", "B": "um texto informativo.", "C": "um texto narrativo ficcional.", "D": "um texto descritivo-argumentativo.", "E": "um planejamento."}, "g": "B"}, {"id": "677675", "d": "portugues", "a": ["Morfologia", "Numerais"], "ano": "2016", "org": "CRM-PI", "t": "", "e": "No que diz respeito à classificação morfológica, os\nelementos destacados no texto pertencem ao grupo dos\nnumerais:", "alt": {"A": "ordinais.", "B": "cardinais", "C": "multiplicativos.", "D": "fracionários.", "E": "racionais."}, "g": "B"}, {"id": "676483", "d": "portugues", "a": ["Interpretação de Textos", "Coesão e coerência"], "ano": "2016", "org": "CRA-AC", "t": "", "e": "Sobre o texto, pode-se afirmar adequadamente que:", "alt": {"A": "não há qualquer referência ao leitor do texto por meio\nde segunda ou de terceira pessoa do singular, seja em\nformas verbais, seja em pronomes.", "B": "o título promete indicar as cinco melhores formas de\ninvestimento e faz isso numerando-as uma a uma com\nnumerais ordinais.", "C": "a linguagem do texto é absolutamente coloquial, com\ntrechos de obscuridade e arcaísmos.", "D": "não há referências anafóricas no texto.", "E": "a expressão “além disso”, que abre o último parágrafo,\nindica que informações serão adicionadas àquelas que\njá foram apresentadas anteriormente no texto."}, "g": "E"}, {"id": "601618", "d": "portugues", "a": ["Sintaxe", "Análise sintática", "Termos essenciais da oração: Sujeito e Predicado", "Termos integrantes da oração: Objeto direto, Objeto indireto, Complemento nominal, Agente da Passiva", "Vocativo e Termos Acessórios da Oração: Adjunto Adnominal, Diferença entre Adjunto Adnominal e Complemento Nominal, Adjunto Adverbial e Aposto", "Termos integrantes da oração: predicativo do sujeito e predicativo do objeto"], "ano": "2016", "org": "CFP", "t": "", "e": "Compare estas orações retiradas da letra da música: \"Pra\nvocê parar em casa\"; \"Pra poder me sustentar\"; \"Pra\nagradar meu coração\". Levando em consideração a forma\ncomo elas se relacionam, sintaticamente, com outras\norações a que se ligam, assinale a alternativa que destaque\na função sintática de cada uma delas.", "alt": {"A": "Complemento nominal.", "B": "Adjunto adnominal.", "C": "Aposto explicativo.", "D": "Adjunto adverbial.", "E": "Predicativo do sujeito."}, "g": "D"}, {"id": "601612", "d": "portugues", "a": ["Morfologia - Verbos"], "ano": "2016", "org": "CFP", "t": "", "e": "Releia o primeiro parágrafo do texto e analise\nespecialmente a frase que ali está em destaque, para então\nassinalar a seguir a alternativa que contenha comentários\nmorfossintáticos corretos em relação à frase.", "alt": {"A": "Na frase, podemos afirmar com absoluta certeza que o\nverbo \"perguntar\", no contexto em que aparece, é\ncomplementado apenas por objetos diretos.", "B": "Na frase, a palavra \"que\" classifica-se,\nmorfologicamente, como conjunção integrante e,\nportanto, não tem função sintática.", "C": "Na frase, os dois verbos que aparecem estão\nconjugados no mesmo modo (indicativo) e no mesmo\ntempo (pretérito perfeito).", "D": "Na frase, embora haja dois verbos, existe apenas uma\noração, já que um deles é uma forma nominal\ndenominada infinitivo.", "E": "Na frase, o termo \"o\" que antecede a palavra \"que\"\nclassifica-se, morfologicamente, como pronome\ndemonstrativo e, sintaticamente, como objeto direto."}, "g": "E"}, {"id": "566830", "d": "portugues", "a": ["Morfologia - Pronomes", "Pronomes relativos"], "ano": "2015", "org": "CRESS-PR", "t": "", "e": "Sabe-se que o pronome relativo exerce determinadas funções sintáticas, de acordo com a construção de que participa. Pode-se afirmar que o pronome relativo destacado no primeiro parágrafo do texto exerce a mesma função sintática do termo destacado em:", "alt": {"A": "Famílias com crianças estão no grupo que conseguiu entrar nos trens.", "B": "Centenas também embarcaram na Macedônia em direção à Servia.", "C": "A polícia austríaca informou que quem pediu asilo à Hungria não pode prosseguir viagem.", "D": "Já aqueles que querem pedir refúgio à Áustria podem se mover por duas semanas no país.", "E": "Depois disso, eles podem ser devolvidos para o último país de trânsito."}, "g": "E"}, {"id": "553104", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2015", "org": "COBRA Tecnologia S/A (BB)", "t": "", "e": "Quanto aos quadrinhos como um todo, pode-se afirmar que:", "alt": {"A": "a linguagem verbal e a linguagem não verbal de tal\nmaneira contribuem para o entendimento da tirinha,\nque as imagens não podem ser plenamente\ncompreendidas sem o texto.", "B": "a linguagem não verbal poderia, sozinha, dar conta dos\nsentidos pretendidos pelo autor dos quadrinhos,\ndispensáveis que são os textos apresentados nos\nbalões.", "C": "não há recurso algum, nem verbal nem simbólico, que\ndê conta de caracterizar a presença de duas\npersonagens que interagem entre si com o auxílio do\ntelefone.", "D": "a linguagem verbal absolutamente técnica dificulta o\nentendimento da tirinha para um leitor que não seja\ncapaz de compreender o contexto em que se\ndesenvolve o episódio apresentado.", "E": "as informações do primeiro quadrinho são\nfundamentais para a construção do humor da tirinha, já\nque, se os quadrinhos não fossem baseados em uma\nhistória real, o final humorístico e, de certa forma,\ninesperado, estaria gravemente prejudicado."}, "g": "A"}, {"id": "553100", "d": "portugues", "a": ["Ortografia", "Acentuação Gráfica: Proparoxítonas, Paroxítonas, Oxítonas e Hiatos"], "ano": "2015", "org": "COBRA Tecnologia S/A (BB)", "t": "", "e": "Assinale a alternativa que contenha uma afirmação correta a\nrespeito da ortografia ou da acentuação, considerando as\npalavras utilizadas no texto.", "alt": {"A": "No título da notícia, há um equívoco na grafia de\n“hebraico\", já que essa palavra não se inicia por h.", "B": "No trecho “15 séculos de idade\", não se deveria\nacentuar a palavra “séculos\", já que se trata de\nvocábulo paroxítono.", "C": "A palavra “cinzas\" deveria ter sido grafada com s, assim\ncomo “razão\".", "D": "No penúltimo parágrafo, as palavras “centímetros\",\n“versículos\" e “bíblico\" são acentuadas pelo mesmo\nmotivo.", "E": "Na frase “A instituição desenvolveu um programa de\nimagem digital\", há dois erros de ortografia."}, "g": "D"}, {"id": "511330", "d": "portugues", "a": ["Sintaxe", "Análise sintática"], "ano": "2014", "org": "CRB - 6ª Região (MG-ES)", "t": "", "e": "Observe: \n\n\"Acompanhe,  a  seguir,  como  o  de uma onça-pintada,  \no maior felino do Brasil''\n\nO termo em destaque exerce a  função sintática  de:", "alt": {"A": "complemento  nominal.", "B": "adjunto adnominal.", "C": "sujeito", "D": "vocativo.", "E": "aposto."}, "g": "E"}, {"id": "506786", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2014", "org": "CRB - 6ª Região (MG-ES)", "t": "", "e": "Analise as possibilidades de  interpretação dos quadrinhos.I.  O  dono  do  gato  Garfield  fica  satisfeito  pelo  fato  de  o  gato  ter  quebrado  a  janela,  mas  não  por  perceber  que  pequenos animais  invadiram  a  sua  sala. II.  O  gato  Garfield  está  surpreso,  nos  dois  primeiros  quadrinhos,  por  perceber  que  não  está  mais  preso  em  casa, mas,  sim,  livre na  natureza. III.  Garfield  e  o  coelho,  que  aparecem  no  primeiro  quadrinho, agiram  juntos na  ação de quebrar a janela.Está  correto o que  se afirma em:", "alt": {"A": "I,  somente.", "B": "II,  somente", "C": "III,  somente", "D": "duas das afirmações,  somente.", "E": "nenhuma das afirmações."}, "g": "E"}, {"id": "495749", "d": "portugues", "a": ["Interpretação de Textos"], "ano": "2014", "org": "CREF - 11ª Região (MS-MT)", "t": "", "e": "Para responder a  questão, observe o anúncio abaixo. O texto verbal  do anúncio,  em  sua  segunda  oração,  pode ser  reescrito,  explicitando-se  os  termos  ocultos,  da  seguinte  maneira:", "alt": {"A": "Nós fazemos  [notícia]  por amor a  ele  [= Brasil].", "B": "Nós fazemos  [notícia]  por amor a  ele  [= esporte].", "C": "Nós fazemos  [esporte]  por amor a  ele  [= Brasil].", "D": "Nós fazemos  [esporte]  por amor a  ele  [= esporte].", "E": "Nós fazemos [jornalismo] por amor a ele [= esporte]"}, "g": "B"}, {"id": "450279", "d": "portugues", "a": ["Interpretação de Textos", "Significação Contextual de Palavras e Expressões. Sinônimos e Antônimos.", "Sintaxe", "Uso dos conectivos"], "ano": "2014", "org": "CRB - 6ª Região (MG-ES)", "t": "(http://www.gompy.com.br/tirinhas/a-natureza-i/)", "e": "A  conjunção  \"e\",  que  aparece  no  segundo  quadrinho,  estabelece uma  relação entre os termos de:", "alt": {"A": "exclusão.", "B": "adição.", "C": "oposição.", "D": "incompatibilidade.", "E": "impossibilidade."}, "g": "B"}, {"id": "2759269", "d": "portugues", "a": ["Fonologia"], "ano": "2013", "org": "CREFONO - 6ª Região", "t": "", "e": "Sobre a palavra ''dente'', assinale a alternativa correta .", "alt": {"A": "Há mais letras que fonemas.", "B": "Há mais fonemas que letras.", "C": "Há o mesmo número de letras e de fonemas.", "D": "É trissílaba.", "E": "É oxítona ."}, "g": "A"}, {"id": "827896", "d": "portugues", "a": ["Ortografia", "Acentuação Gráfica: Proparoxítonas, Paroxítonas, Oxítonas e Hiatos"], "ano": "2013", "org": "CREF - 12ª Região (PE)", "t": "", "e": "Em relação à posição da sílaba tônica, a palavra \"medo\" tem\na mesma classificação de:", "alt": {"A": "Você.", "B": "Aí.", "C": "Mandar.", "D": "Só.", "E": "Molenga."}, "g": "E"}, {"id": "699575", "d": "portugues", "a": ["Sintaxe", "Orações coordenadas assindéticas", "Orações coordenadas sindéticas: Aditivas, Adversativas, Alternativas, Conclusivas...", "Orações subordinadas substantivas: Subjetivas, Objetivas diretas, Objetivas indiretas...", "Orações subordinadas adjetivas: Restritivas, Explicativas"], "ano": "2013", "org": "CRMV-SP", "t": "", "e": "A oração que está sublinhada em \"A Mãe, que viera\ncorrendo\" é classificada como:", "alt": {"A": "Oração Subordinada Substantiva Subjetiva.", "B": "Oração Subordinada Adjetiva Restritiva.", "C": "Oração Subordinada Adjetiva Explicativa.", "D": "Oração Coordenada Sindética Explicativa.", "E": "Oração Coordenada Assindética."}, "g": "C"}, {"id": "517922", "d": "portugues", "a": ["Sintaxe"], "ano": "2013", "org": "CREF - 3ª Região (SC)", "t": "", "e": "Releia o terceiro parágrafo e, em seguida, assinale a opção em que as relações sintáticas entre seus termos estejam analisadas corretamente.", "alt": {"A": "O trecho \"executiva global da Nike\" é um vocativo.", "B": "A locução verbal \"são sentidos\" participa de uma construção de voz passiva.", "C": "A palavra \"décadas\" é núcleo de um sujeito.", "D": "A expressão \"pelos países mais desenvolvidos\" funciona como objeto indireto.", "E": "O termo \"queda\", na última linha do parágrafo, é uma forma verbal que apresenta complemento direto."}, "g": "B"}, {"id": "688972", "d": "portugues", "a": ["Sintaxe", "Orações subordinadas adverbiais: Causal, Comparativa, Consecutiva, Concessiva, Condicional...", "Uso dos conectivos"], "ano": "2012", "org": "CRP - 9ª Região (GO)", "t": "", "e": "Leia o trecho abaixo, que abre o primeiro parágrafo:\"Para enfrentar a violência nas escolas brasileiras...\" Por meio, especialmente, do conectivo \"para\", o trecho\nacima introduz uma circunstância de:", "alt": {"A": "Causa.", "B": "Consequência.", "C": "Finalidade.", "D": "Comparação.", "E": "Concessão."}, "g": "C"}, {"id": "577168", "d": "portugues", "a": ["Morfologia", "Substantivos", "Adjetivos", "Advérbios", "Preposições", "Morfologia - Pronomes"], "ano": "2012", "org": "CFP", "t": "", "e": "A palavra “não”, que está em destaque também na\nsegunda estrofe, pode ser classificada morfologicamente\ncomo:", "alt": {"A": "um substantivo.", "B": "um advérbio.", "C": "um adjetivo.", "D": "um pronome.", "E": "uma preposição."}, "g": "B"}]}